-- ---------------------------------------------------------------
-- _arabic_month_name(p_month integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public._arabic_month_name(p_month integer)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE p_month
    WHEN 1  THEN 'يناير'
    WHEN 2  THEN 'فبراير'
    WHEN 3  THEN 'مارس'
    WHEN 4  THEN 'أبريل'
    WHEN 5  THEN 'مايو'
    WHEN 6  THEN 'يونيو'
    WHEN 7  THEN 'يوليو'
    WHEN 8  THEN 'أغسطس'
    WHEN 9  THEN 'سبتمبر'
    WHEN 10 THEN 'أكتوبر'
    WHEN 11 THEN 'نوفمبر'
    WHEN 12 THEN 'ديسمبر'
    ELSE p_month::text
  END;
$function$
;

-- ---------------------------------------------------------------
-- _production_get_or_create_je(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_reference_type text, p_reference_id uuid, p_entry_date date, p_description text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public._production_get_or_create_je(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_reference_type text, p_reference_id uuid, p_entry_date date, p_description text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_je_id uuid;
BEGIN
  SELECT id INTO v_je_id
  FROM journal_entries
  WHERE company_id = p_company_id
    AND reference_type = p_reference_type
    AND reference_id = p_reference_id
  LIMIT 1;

  IF v_je_id IS NOT NULL THEN RETURN v_je_id; END IF;

  PERFORM set_config('app.allow_direct_post', 'true', true);
  INSERT INTO journal_entries (
    company_id, branch_id, cost_center_id,
    reference_type, reference_id,
    entry_date, description, status
  ) VALUES (
    p_company_id, p_branch_id, p_cost_center_id,
    p_reference_type, p_reference_id,
    p_entry_date, p_description, 'posted'
  ) RETURNING id INTO v_je_id;
  PERFORM set_config('app.allow_direct_post', 'false', true);
  RETURN v_je_id;
END;
$function$
;

