-- ---------------------------------------------------------------
-- accrual_accounting_engine()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.accrual_accounting_engine()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_inventory_id UUID;
  v_purchases_id UUID;
  v_ap_id UUID;
  v_cash_id UUID;
  v_sales_id UUID;
  v_ar_id UUID;
  v_cogs_id UUID;
  v_journal_id UUID;
BEGIN
  -- إيقاف تشغيل التريجرز الأخرى مؤقتاً لتجنب التداخل العودي أو قيود التعديل (enforce_je_integrity)
  PERFORM set_config('app.allow_direct_post', 'true', true);

  -- جلب حسابات الشركة من شجرة الحسابات (chart_of_accounts)
  SELECT id INTO v_ar_id FROM chart_of_accounts WHERE company_id = NEW.company_id AND sub_type = 'accounts_receivable' LIMIT 1;
  SELECT id INTO v_ap_id FROM chart_of_accounts WHERE company_id = NEW.company_id AND sub_type = 'accounts_payable' LIMIT 1;
  SELECT id INTO v_sales_id FROM chart_of_accounts WHERE company_id = NEW.company_id AND account_type = 'income' LIMIT 1;
  SELECT id INTO v_inventory_id FROM chart_of_accounts WHERE company_id = NEW.company_id AND sub_type = 'inventory' LIMIT 1;
  SELECT id INTO v_cogs_id FROM chart_of_accounts WHERE company_id = NEW.company_id AND (sub_type = 'cost_of_goods_sold' OR account_code = '5000') LIMIT 1;
  SELECT id INTO v_cash_id FROM chart_of_accounts WHERE company_id = NEW.company_id AND (sub_type = 'cash' OR sub_type = 'bank' OR account_type = 'asset') LIMIT 1;

  IF v_ap_id IS NULL OR v_inventory_id IS NULL THEN
    RAISE LOG 'Accounting settings missing for company_id: %', NEW.company_id;
    -- Instead of crashing or doing nothing, we'll gracefully exit the trigger.
    RETURN NEW;
  END IF;

  ------------------------------------------------------------------------------------------------
  -- ✅ 1. Soft-Delete Journals when Bill/Invoice is REVERTED (Draft / Cancelled)
  ------------------------------------------------------------------------------------------------

  -- الفواتير (Bills): إذا تم إرجاع حالة الفاتورة إلى مسودة أو إلغاؤها من حالة نشطة
  IF TG_TABLE_NAME = 'bills' AND OLD.status IN ('sent', 'received', 'paid', 'partially_paid') AND NEW.status IN ('draft', 'cancelled', 'pending_approval') THEN
    UPDATE journal_entries 
       SET is_deleted = TRUE, 
           deleted_at = NOW()
     WHERE reference_type = 'bill' 
       AND reference_id = NEW.id 
       AND (is_deleted IS NULL OR is_deleted = FALSE);
    RETURN NEW;
  END IF;

  -- فواتير المبيعات (Invoices): إذا تم إرجاع حالة الفاتورة أو إلغاؤها
  IF TG_TABLE_NAME = 'invoices' AND OLD.status IN ('sent', 'paid', 'partially_paid') AND NEW.status IN ('draft', 'cancelled', 'pending_approval') THEN
    UPDATE journal_entries 
       SET is_deleted = TRUE, 
           deleted_at = NOW()
     WHERE reference_type IN ('invoice', 'invoice_cogs') 
       AND reference_id = NEW.id 
       AND (is_deleted IS NULL OR is_deleted = FALSE);
    RETURN NEW;
  END IF;

  ------------------------------------------------------------------------------------------------
  -- ✅ 2. Create Journals on Status Activations (Sent / Received)
  ------------------------------------------------------------------------------------------------

  -- فواتير الشراء: الدخول في حالة مرسلة/مستلمة
  IF TG_TABLE_NAME = 'bills' AND OLD.status NOT IN ('sent', 'received', 'paid', 'partially_paid') AND NEW.status IN ('sent', 'received') THEN
    INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description, status)
    VALUES (NEW.company_id, 'bill', NEW.id, NEW.bill_date, 'Purchase - ' || NEW.bill_number, 'draft')
    RETURNING id INTO v_journal_id;

    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
    (v_journal_id, v_inventory_id, NEW.total_amount, 0, 'Inventory'),
    (v_journal_id, v_ap_id, 0, NEW.total_amount, 'Accounts Payable');

    UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_id;
  END IF;

  -- فواتير البيع: الدخول في حالة مرسلة
  IF TG_TABLE_NAME = 'invoices' AND OLD.status NOT IN ('sent', 'paid', 'partially_paid') AND NEW.status = 'sent' THEN
    -- A. Revenue Entry
    INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description, status)
    VALUES (NEW.company_id, 'invoice', NEW.id, NEW.invoice_date, 'Sales - ' || NEW.invoice_number, 'draft')
    RETURNING id INTO v_journal_id;

    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
    (v_journal_id, v_ar_id, NEW.total_amount, 0, 'Accounts Receivable'),
    (v_journal_id, v_sales_id, 0, NEW.total_amount, 'Sales Revenue');

    UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_id;

    -- B. COGS Entry (if total_cost > 0)
    IF NEW.total_cost > 0 THEN
      INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description, status)
      VALUES (NEW.company_id, 'invoice_cogs', NEW.id, NEW.invoice_date, 'COGS - ' || NEW.invoice_number, 'draft')
      RETURNING id INTO v_journal_id;

      INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
      (v_journal_id, v_cogs_id, NEW.total_cost, 0, 'Cost of Goods Sold'),
      (v_journal_id, v_inventory_id, 0, NEW.total_cost, 'Inventory');

      UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_id;
    END IF;
  END IF;

  -- المدفوعات (Payments): الدخول في حالة منتهية
  IF TG_TABLE_NAME = 'payments' AND NEW.status = 'completed' AND OLD.status != 'completed' THEN
    INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description, status)
    VALUES (NEW.company_id, 'payment', NEW.id, NEW.payment_date, 'Payment - ' || NEW.reference_number, 'draft')
    RETURNING id INTO v_journal_id;

    IF NEW.payment_type = 'incoming' THEN
      INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
      (v_journal_id, v_cash_id, NEW.amount, 0, 'Cash In'),
      (v_journal_id, v_ar_id, 0, NEW.amount, 'Accounts Receivable Reduction');
    ELSIF NEW.payment_type = 'outgoing' THEN
      INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
      (v_journal_id, v_ap_id, NEW.amount, 0, 'Accounts Payable Reduction'),
      (v_journal_id, v_cash_id, 0, NEW.amount, 'Cash Out');
    END IF;

    UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_id;
  END IF;

  ------------------------------------------------------------------------------------------------
  -- ✅ التأكد من تنظيف السياق للمنعقدين الآخرين
  ------------------------------------------------------------------------------------------------
  PERFORM set_config('app.allow_direct_post', 'false', true);

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- accrual_invoice_accounting()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.accrual_invoice_accounting()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company_id UUID;
  v_ar_account_id UUID;
  v_revenue_account_id UUID;
  v_inventory_account_id UUID;
  v_cogs_account_id UUID;
  v_journal_entry_id UUID;
  v_cogs_amount NUMERIC := 0;
BEGIN
  -- فقط عند تغيير الحالة إلى sent
  IF OLD.status = 'draft' AND NEW.status = 'sent' THEN
    
    -- الحصول على الحسابات
    SELECT id INTO v_ar_account_id FROM chart_of_accounts 
    WHERE company_id = NEW.company_id AND sub_type = 'accounts_receivable' LIMIT 1;
    
    SELECT id INTO v_revenue_account_id FROM chart_of_accounts 
    WHERE company_id = NEW.company_id AND account_type = 'income' LIMIT 1;
    
    SELECT id INTO v_inventory_account_id FROM chart_of_accounts 
    WHERE company_id = NEW.company_id AND sub_type = 'inventory' LIMIT 1;
    
    SELECT id INTO v_cogs_account_id FROM chart_of_accounts 
    WHERE company_id = NEW.company_id AND (sub_type = 'cogs' OR account_code = '5000') LIMIT 1;

    -- حساب COGS
    SELECT SUM(ii.quantity * COALESCE(p.cost_price, 0)) INTO v_cogs_amount
    FROM invoice_items ii
    JOIN products p ON ii.product_id = p.id
    WHERE ii.invoice_id = NEW.id AND p.item_type != 'service';

    -- 1️⃣ قيد الإيراد
    INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description)
    VALUES (NEW.company_id, 'invoice', NEW.id, NEW.invoice_date, 'Revenue - ' || NEW.invoice_number)
    RETURNING id INTO v_journal_entry_id;

    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
    (v_journal_entry_id, v_ar_account_id, NEW.total_amount, 0, 'Accounts Receivable'),
    (v_journal_entry_id, v_revenue_account_id, 0, NEW.total_amount, 'Sales Revenue');

    -- 2️⃣ قيد COGS (إذا كان > 0)
    IF v_cogs_amount > 0 AND v_inventory_account_id IS NOT NULL AND v_cogs_account_id IS NOT NULL THEN
      INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description)
      VALUES (NEW.company_id, 'invoice_cogs', NEW.id, NEW.invoice_date, 'COGS - ' || NEW.invoice_number)
      RETURNING id INTO v_journal_entry_id;

      INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
      (v_journal_entry_id, v_cogs_account_id, v_cogs_amount, 0, 'Cost of Goods Sold'),
      (v_journal_entry_id, v_inventory_account_id, 0, v_cogs_amount, 'Inventory');
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- activate_booking_atomic(p_company_id uuid, p_booking_id uuid, p_activated_by uuid, p_invoice_date date, p_due_date date, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.activate_booking_atomic(p_company_id uuid, p_booking_id uuid, p_activated_by uuid, p_invoice_date date DEFAULT CURRENT_DATE, p_due_date date DEFAULT CURRENT_DATE, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_status text; v_discount_amt numeric; v_invoice_id uuid;
  v_approval_state text; v_approval_id uuid;
  v_inv_check jsonb; v_shortages jsonb; v_short_msg text;
  v_result jsonb;
BEGIN
  SELECT status, discount_amount, invoice_id INTO v_status, v_discount_amt, v_invoice_id
    FROM public.bookings WHERE id = p_booking_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Booking not found. booking_id=%', p_booking_id USING ERRCODE = 'P0001';
  END IF;
  IF v_status IN ('completed', 'cancelled', 'no_show') THEN
    RAISE EXCEPTION 'Cannot activate a % booking. booking_id=%', v_status, p_booking_id USING ERRCODE = 'P0001';
  END IF;

  IF v_discount_amt IS NOT NULL AND v_discount_amt > 0 THEN
    SELECT id, status INTO v_approval_id, v_approval_state
      FROM public.discount_approvals
     WHERE document_type = 'booking' AND document_id = p_booking_id
       AND discount_value = v_discount_amt
     ORDER BY requested_at DESC LIMIT 1;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'الخصم المطبق على الحجز يتطلب اعتماد المالك / المدير العام قبل التنفيذ. اطلب الاعتماد من صندوق الموافقات.'
        USING ERRCODE = 'P0001';
    END IF;
    IF v_approval_state <> 'approved' THEN
      RAISE EXCEPTION 'الخصم بقيمة % منتظر اعتماد الإدارة (الحالة الحالية: %). لا يمكن تنفيذ الحجز قبل الاعتماد.',
        v_discount_amt, v_approval_state USING ERRCODE = 'P0001';
    END IF;
  END IF;

  -- v3.74.387 inventory gate
  v_inv_check := public.check_booking_service_inventory(p_booking_id);
  IF (v_inv_check->>'ok')::boolean = false THEN
    v_shortages := v_inv_check->'shortages';
    SELECT string_agg(
      (item->>'product_name') || ' (مطلوب ' || (item->>'needed') || '، متاح ' || (item->>'available') || ')',
      E'، ')
      INTO v_short_msg FROM jsonb_array_elements(v_shortages) item;
    RAISE EXCEPTION 'لا يمكن تنفيذ الخدمة — المخزون فى الفرع غير كافٍ للمنتجات التالية: %.', v_short_msg
      USING ERRCODE = 'P0001';
  END IF;

  IF v_status = 'draft' THEN
    UPDATE public.bookings
       SET status = 'confirmed', confirmed_by = COALESCE(confirmed_by, p_activated_by),
           confirmed_at = COALESCE(confirmed_at, NOW())
     WHERE id = p_booking_id;
    v_status := 'confirmed';
  END IF;
  IF v_status = 'confirmed' THEN
    UPDATE public.bookings
       SET status = 'in_progress', started_by = COALESCE(started_by, p_activated_by),
           started_at = COALESCE(started_at, NOW())
     WHERE id = p_booking_id;
    v_status := 'in_progress';
  END IF;

  v_result := public.complete_booking_atomic(
    p_company_id => p_company_id, p_booking_id => p_booking_id,
    p_completed_by => p_activated_by, p_invoice_date => p_invoice_date,
    p_due_date => p_due_date, p_notes => p_notes
  );

  UPDATE public.bookings
     SET current_responsible_user_id = COALESCE(current_responsible_user_id, staff_user_id, p_activated_by)
   WHERE id = p_booking_id;

  RETURN v_result || jsonb_build_object(
    'activated_by', p_activated_by, 'activated_at', NOW(), 'inventory_check', v_inv_check
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- activate_manufacturing_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_updated_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.activate_manufacturing_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_updated_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version RECORD;
  v_previous_active UUID;
  v_operation_count INTEGER;
BEGIN
  SELECT *
    INTO v_version
    FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing routing version not found or not in company. routing_version_id=%', p_routing_version_id;
  END IF;

  IF v_version.status NOT IN ('draft', 'inactive', 'active') THEN
    RAISE EXCEPTION 'Only draft, inactive, or active routing versions can be activated. routing_version_id=%, status=%',
      p_routing_version_id, v_version.status;
  END IF;

  SELECT COUNT(*)
    INTO v_operation_count
    FROM public.manufacturing_routing_operations
   WHERE routing_version_id = p_routing_version_id;

  IF v_operation_count <= 0 THEN
    RAISE EXCEPTION 'Routing version must contain at least one operation before activation. routing_version_id=%', p_routing_version_id;
  END IF;

  PERFORM 1
    FROM public.manufacturing_routing_versions
   WHERE routing_id = v_version.routing_id
   FOR UPDATE;

  SELECT id
    INTO v_previous_active
    FROM public.manufacturing_routing_versions
   WHERE routing_id = v_version.routing_id
     AND status = 'active'
     AND id <> p_routing_version_id
   ORDER BY version_no DESC
   LIMIT 1;

  UPDATE public.manufacturing_routing_versions
     SET status = 'inactive',
         updated_by = p_updated_by
   WHERE routing_id = v_version.routing_id
     AND status = 'active'
     AND id <> p_routing_version_id;

  UPDATE public.manufacturing_routing_versions
     SET status = 'active',
         updated_by = p_updated_by
   WHERE id = p_routing_version_id;

  RETURN jsonb_build_object(
    'success', true,
    'routing_version_id', p_routing_version_id,
    'previous_active_version_id', v_previous_active,
    'status', 'active'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- activate_seat(p_company_id uuid, p_invite_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.activate_seat(p_company_id uuid, p_invite_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_seat_number INTEGER;
  v_member_id   UUID;
  v_user_id     UUID;
BEGIN
  PERFORM pg_advisory_xact_lock(hashtext(p_company_id::TEXT));

  SELECT seat_number INTO v_seat_number
  FROM company_invitations
  WHERE id = p_invite_id AND company_id = p_company_id;

  IF v_seat_number IS NOT NULL THEN
    UPDATE company_members cm
    SET seat_number = v_seat_number
    WHERE cm.company_id = p_company_id
      AND cm.seat_number IS NULL
      AND cm.id = (
        SELECT id FROM company_members
        WHERE company_id = p_company_id AND seat_number IS NULL
        ORDER BY created_at DESC NULLS LAST LIMIT 1
      )
    RETURNING cm.id, cm.user_id INTO v_member_id, v_user_id;

    IF v_user_id IS NOT NULL THEN
      UPDATE public.company_seat_licenses
         SET assigned_user_id = v_user_id,
             assigned_at      = NOW(),
             updated_at       = NOW()
       WHERE company_id  = p_company_id
         AND seat_number = v_seat_number
         AND assigned_user_id IS NULL;
    END IF;
  END IF;

  UPDATE company_invitations
  SET accepted = TRUE, status = 'accepted', accepted_at = now()
  WHERE id = p_invite_id AND company_id = p_company_id;

  INSERT INTO seat_transactions(company_id, transaction_type, seats_delta, metadata)
  VALUES (
    p_company_id, 'activate', 0,
    json_build_object('invite_id', p_invite_id, 'seat_number', v_seat_number, 'user_id', v_user_id)
  );

  RETURN json_build_object('success', TRUE, 'seat_number', v_seat_number, 'user_id', v_user_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- add_booking_bundle_selection(p_company_id uuid, p_booking_id uuid, p_bundle_item_id uuid, p_selected_by uuid, p_quantity_override numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.add_booking_bundle_selection(p_company_id uuid, p_booking_id uuid, p_bundle_item_id uuid, p_selected_by uuid, p_quantity_override numeric DEFAULT NULL::numeric)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_id uuid;
BEGIN
  PERFORM public.assert_booking_editable_for_bundle(p_booking_id);
  PERFORM public.assert_booking_addons_permission(p_company_id, p_booking_id);
  IF NOT EXISTS (
    SELECT 1 FROM public.product_bundle_items pbi
     WHERE pbi.id = p_bundle_item_id AND pbi.company_id = p_company_id
       AND pbi.is_optional = true
  ) THEN
    RAISE EXCEPTION 'BUNDLE_ITEM_NOT_OPTIONAL_OR_NOT_FOUND';
  END IF;
  INSERT INTO public.booking_bundle_selections
    (company_id, booking_id, bundle_item_id, quantity_override, selected_by)
  VALUES (p_company_id, p_booking_id, p_bundle_item_id, p_quantity_override,
          COALESCE(auth.uid(), p_selected_by))
  ON CONFLICT (booking_id, bundle_item_id) DO UPDATE
     SET quantity_override = EXCLUDED.quantity_override,
         selected_by = EXCLUDED.selected_by,
         selected_at = NOW()
  RETURNING id INTO v_id;
  IF EXISTS (SELECT 1 FROM public.bookings WHERE id = p_booking_id AND status = 'completed') THEN
    PERFORM public.resync_booking_invoice(p_company_id, p_booking_id, COALESCE(auth.uid(), p_selected_by));
  END IF;
  RETURN v_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- add_booking_extra_item(p_company_id uuid, p_booking_id uuid, p_product_id uuid, p_quantity numeric, p_unit_price numeric, p_added_by uuid, p_discount_percent numeric, p_tax_rate numeric, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.add_booking_extra_item(p_company_id uuid, p_booking_id uuid, p_product_id uuid, p_quantity numeric, p_unit_price numeric, p_added_by uuid, p_discount_percent numeric DEFAULT 0, p_tax_rate numeric DEFAULT 0, p_notes text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_id uuid;
BEGIN
  PERFORM public.assert_booking_editable_for_bundle(p_booking_id);
  PERFORM public.assert_booking_addons_permission(p_company_id, p_booking_id);
  IF p_quantity IS NULL OR p_quantity <= 0 THEN RAISE EXCEPTION 'QTY_MUST_BE_POSITIVE'; END IF;
  IF p_unit_price IS NULL OR p_unit_price < 0 THEN RAISE EXCEPTION 'PRICE_MUST_BE_NON_NEGATIVE'; END IF;
  INSERT INTO public.booking_extra_items
    (company_id, booking_id, product_id, quantity, unit_price,
     discount_percent, tax_rate, notes, added_by)
  VALUES
    (p_company_id, p_booking_id, p_product_id, p_quantity, p_unit_price,
     COALESCE(p_discount_percent,0), COALESCE(p_tax_rate,0), p_notes,
     COALESCE(auth.uid(), p_added_by))
  RETURNING id INTO v_id;
  IF EXISTS (SELECT 1 FROM public.bookings WHERE id = p_booking_id AND status = 'completed') THEN
    PERFORM public.resync_booking_invoice(p_company_id, p_booking_id, COALESCE(auth.uid(), p_added_by));
  END IF;
  RETURN v_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- add_booking_payment_atomic(p_company_id uuid, p_booking_id uuid, p_created_by uuid, p_amount numeric, p_payment_method text, p_payment_date date, p_reference_no text, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.add_booking_payment_atomic(p_company_id uuid, p_booking_id uuid, p_created_by uuid, p_amount numeric, p_payment_method text DEFAULT 'cash'::text, p_payment_date date DEFAULT NULL::date, p_reference_no text DEFAULT NULL::text, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  RAISE EXCEPTION 'BOOKING_PAYMENTS_DISABLED: الدفعات لا تُسجل من صفحة الحجز — بعد تنفيذ أمر الحجز تُنشأ فاتورة بيع مرتبطة ويستكمل محاسب الفرع التحصيل منها عبر دورة المدفوعات'
    USING ERRCODE = 'P0001';
END;
$function$
;

-- ---------------------------------------------------------------
-- ai_current_user_allowed_resources()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ai_current_user_allowed_resources()
 RETURNS text[]
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public'
AS $function$
DECLARE
  v_set        TEXT[] := ARRAY[]::TEXT[];
  v_row        RECORD;
  v_default    TEXT[];
  v_has_config BOOLEAN;
BEGIN
  -- Walk each (company, role) pair the user belongs to.
  FOR v_row IN
    SELECT company_id, LOWER(TRIM(role)) AS role
    FROM public.company_members
    WHERE user_id = auth.uid()
  LOOP
    -- Does the admin have ANY explicit configuration for this (role, company)?
    SELECT EXISTS (
      SELECT 1 FROM public.company_role_permissions crp
      WHERE crp.company_id = v_row.company_id
        AND LOWER(TRIM(crp.role)) = v_row.role
    ) INTO v_has_config;

    IF v_has_config THEN
      -- Configured: use only what the admin explicitly granted.
      FOR v_row IN
        SELECT crp.resource
        FROM public.company_role_permissions crp
        WHERE crp.company_id = v_row.company_id
          AND LOWER(TRIM(crp.role)) = v_row.role
          AND (
            crp.can_access IS TRUE
            OR crp.can_read IS TRUE
            OR crp.all_access IS TRUE
          )
          AND crp.resource IS NOT NULL
      LOOP
        v_set := v_set || ARRAY[v_row.resource];
      END LOOP;
    ELSE
      -- Not configured: fall back to role defaults so the user is not locked out.
      v_default := CASE v_row.role
        WHEN 'manager' THEN ARRAY[
          'dashboard','reports','invoices','customers','estimates',
          'sales_orders','sales_returns','sent_invoice_returns',
          'customer_debit_notes','bills','suppliers','purchase_orders',
          'purchase_returns','vendor_credits','manufacturing_boms',
          'products','inventory','inventory_transfers','write_offs',
          'third_party_inventory','product_availability',
          'inventory_goods_receipt','payments','expenses','drawings',
          'journal_entries','banking','chart_of_accounts','fixed_assets',
          'asset_categories','fixed_assets_reports','annual_closing',
          'hr','employees','attendance','payroll','instant_payouts',
          'branches','cost_centers','warehouses']
        WHEN 'accountant' THEN ARRAY[
          'dashboard','reports','invoices','customers','sales_returns',
          'customer_debit_notes','bills','suppliers','purchase_returns',
          'vendor_credits','payments','expenses','drawings',
          'journal_entries','chart_of_accounts','banking','annual_closing',
          'accounting_periods','shareholders','fixed_assets',
          'asset_categories','fixed_assets_reports','taxes',
          'exchange_rates','accounting_maintenance','products','inventory',
          'inventory_transfers','write_offs','third_party_inventory',
          'product_availability','inventory_goods_receipt']
        WHEN 'store_manager' THEN ARRAY[
          'dashboard','manufacturing_boms','products','inventory',
          'product_availability','inventory_transfers',
          'third_party_inventory','write_offs','inventory_goods_receipt',
          'purchase_orders','sales_orders','shipping']
        WHEN 'manufacturing_officer' THEN ARRAY[
          'dashboard','manufacturing_boms','products','inventory',
          'product_availability','reports']
        WHEN 'booking_officer' THEN ARRAY[
          'dashboard','bookings','services','customers','payments','reports']
        WHEN 'purchasing_officer' THEN ARRAY[
          'dashboard','reports','bills','suppliers','purchase_orders',
          'purchase_returns','vendor_credits','payments','expenses',
          'drawings','journal_entries','chart_of_accounts','banking',
          'annual_closing','accounting_periods','shareholders',
          'fixed_assets','asset_categories','fixed_assets_reports',
          'taxes','exchange_rates','accounting_maintenance','products',
          'inventory','inventory_transfers','inventory_goods_receipt',
          'product_availability','write_offs','third_party_inventory']
        WHEN 'staff' THEN ARRAY[
          'dashboard','customers','estimates','sales_orders','invoices',
          'inventory','product_availability','attendance']
        WHEN 'sales' THEN ARRAY[
          'dashboard','customers','estimates','sales_orders','invoices',
          'product_availability']
        WHEN 'employee' THEN ARRAY['dashboard','attendance']
        WHEN 'viewer' THEN ARRAY['dashboard','reports']
        ELSE ARRAY[]::TEXT[]
      END;
      v_set := v_set || v_default;
    END IF;
  END LOOP;

  -- Dashboard is always allowed (matches sidebar behaviour).
  v_set := v_set || ARRAY['dashboard'];

  RETURN ARRAY(SELECT DISTINCT x FROM unnest(v_set) AS x WHERE x IS NOT NULL);
END;
$function$
;

-- ---------------------------------------------------------------
-- ai_current_user_is_full_access()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ai_current_user_is_full_access()
 RETURNS boolean
 LANGUAGE sql
 STABLE
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1
    FROM public.company_members cm
    WHERE cm.user_id = auth.uid()
      AND LOWER(TRIM(cm.role)) IN ('owner', 'admin', 'general_manager')
  );
$function$
;

-- ---------------------------------------------------------------
-- ai_get_proactive_alerts(p_language text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ai_get_proactive_alerts(p_language text DEFAULT 'ar'::text)
 RETURNS TABLE(alert_key text, alert_type text, severity text, resource text, title text, message text, action_url text, count_value integer, total_amount numeric, metadata jsonb)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public'
AS $function$
DECLARE
  v_allowed text[];
  v_lang    text := CASE WHEN LOWER(COALESCE(p_language, 'ar')) = 'en' THEN 'en' ELSE 'ar' END;
  v_today   date := CURRENT_DATE;
  v_soon    date := CURRENT_DATE + INTERVAL '7 days';
  v_stale   timestamptz := NOW() - INTERVAL '7 days';
BEGIN
  SELECT public.ai_current_user_allowed_resources() INTO v_allowed;

  -- 1. Overdue customer invoices
  IF 'invoices' = ANY(v_allowed) THEN
    RETURN QUERY
    WITH base AS (
      SELECT i.id, i.invoice_number, i.due_date,
             GREATEST(COALESCE(i.total_amount, 0) - COALESCE(i.paid_amount, 0) - COALESCE(i.returned_amount, 0), 0) AS outstanding,
             c.name AS party_name
      FROM public.invoices i
      LEFT JOIN public.customers c ON c.id = i.customer_id
      WHERE i.status IN ('sent', 'partially_paid')
        AND i.due_date IS NOT NULL AND i.due_date < v_today
        AND GREATEST(COALESCE(i.total_amount, 0) - COALESCE(i.paid_amount, 0) - COALESCE(i.returned_amount, 0), 0) > 0.01
    ), samples AS (
      SELECT jsonb_agg(jsonb_build_object('id', id, 'number', invoice_number, 'party', party_name, 'due_date', due_date, 'outstanding', outstanding) ORDER BY due_date ASC) AS items
      FROM (SELECT * FROM base ORDER BY due_date ASC LIMIT 5) s
    )
    SELECT 'overdue_invoices'::text, 'overdue'::text, 'critical'::text, 'invoices'::text,
      CASE v_lang WHEN 'en' THEN 'Overdue customer invoices' ELSE 'فواتير مبيعات مُتأخّرة' END,
      CASE v_lang WHEN 'en' THEN (SELECT COUNT(*) FROM base)::text || ' invoice(s) past due — outstanding ' || TO_CHAR((SELECT COALESCE(SUM(outstanding), 0) FROM base), 'FM999,999,990.00')
                  ELSE (SELECT COUNT(*) FROM base)::text || ' فاتورة تجاوزت تاريخ الاستحقاق — المتبقّى ' || TO_CHAR((SELECT COALESCE(SUM(outstanding), 0) FROM base), 'FM999,999,990.00') END,
      '/invoices'::text, (SELECT COUNT(*) FROM base)::int, (SELECT COALESCE(SUM(outstanding), 0) FROM base),
      jsonb_build_object('window_days_past_due', GREATEST(0, v_today - (SELECT MIN(due_date) FROM base)), 'samples', COALESCE((SELECT items FROM samples), '[]'::jsonb))
    FROM (SELECT 1) _ WHERE (SELECT COUNT(*) FROM base) > 0;
  END IF;

  -- 2. Invoices due soon
  IF 'invoices' = ANY(v_allowed) THEN
    RETURN QUERY
    WITH base AS (
      SELECT i.id, i.invoice_number, i.due_date,
             GREATEST(COALESCE(i.total_amount, 0) - COALESCE(i.paid_amount, 0) - COALESCE(i.returned_amount, 0), 0) AS outstanding,
             c.name AS party_name
      FROM public.invoices i LEFT JOIN public.customers c ON c.id = i.customer_id
      WHERE i.status IN ('sent','partially_paid') AND i.due_date IS NOT NULL
        AND i.due_date BETWEEN v_today AND v_soon
        AND GREATEST(COALESCE(i.total_amount, 0) - COALESCE(i.paid_amount, 0) - COALESCE(i.returned_amount, 0), 0) > 0.01
    ), samples AS (
      SELECT jsonb_agg(jsonb_build_object('id', id, 'number', invoice_number, 'party', party_name, 'due_date', due_date, 'outstanding', outstanding) ORDER BY due_date ASC) AS items
      FROM (SELECT * FROM base ORDER BY due_date ASC LIMIT 5) s
    )
    SELECT 'due_soon_invoices'::text, 'due_soon'::text, 'warning'::text, 'invoices'::text,
      CASE v_lang WHEN 'en' THEN 'Invoices due in the next 7 days' ELSE 'فواتير تستحق خلال 7 أيام' END,
      CASE v_lang WHEN 'en' THEN (SELECT COUNT(*) FROM base)::text || ' invoice(s) coming due — outstanding ' || TO_CHAR((SELECT COALESCE(SUM(outstanding), 0) FROM base), 'FM999,999,990.00')
                  ELSE (SELECT COUNT(*) FROM base)::text || ' فاتورة تقترب من الاستحقاق — المتبقّى ' || TO_CHAR((SELECT COALESCE(SUM(outstanding), 0) FROM base), 'FM999,999,990.00') END,
      '/invoices'::text, (SELECT COUNT(*) FROM base)::int, (SELECT COALESCE(SUM(outstanding), 0) FROM base),
      jsonb_build_object('window_days', 7, 'samples', COALESCE((SELECT items FROM samples), '[]'::jsonb))
    FROM (SELECT 1) _ WHERE (SELECT COUNT(*) FROM base) > 0;
  END IF;

  -- 3. Overdue supplier bills
  IF 'bills' = ANY(v_allowed) THEN
    RETURN QUERY
    WITH base AS (
      SELECT b.id, b.bill_number, b.due_date,
             GREATEST(COALESCE(b.total_amount, 0) - COALESCE(b.paid_amount, 0) - COALESCE(b.returned_amount, 0), 0) AS outstanding,
             s.name AS party_name
      FROM public.bills b LEFT JOIN public.suppliers s ON s.id = b.supplier_id
      WHERE b.status IN ('sent','partially_paid') AND b.due_date IS NOT NULL AND b.due_date < v_today
        AND GREATEST(COALESCE(b.total_amount, 0) - COALESCE(b.paid_amount, 0) - COALESCE(b.returned_amount, 0), 0) > 0.01
    ), samples AS (
      SELECT jsonb_agg(jsonb_build_object('id', id, 'number', bill_number, 'party', party_name, 'due_date', due_date, 'outstanding', outstanding) ORDER BY due_date ASC) AS items
      FROM (SELECT * FROM base ORDER BY due_date ASC LIMIT 5) s
    )
    SELECT 'overdue_bills'::text, 'overdue'::text, 'critical'::text, 'bills'::text,
      CASE v_lang WHEN 'en' THEN 'Overdue supplier bills' ELSE 'فواتير موردين مُتأخّرة' END,
      CASE v_lang WHEN 'en' THEN (SELECT COUNT(*) FROM base)::text || ' bill(s) past due — outstanding ' || TO_CHAR((SELECT COALESCE(SUM(outstanding), 0) FROM base), 'FM999,999,990.00')
                  ELSE (SELECT COUNT(*) FROM base)::text || ' فاتورة شراء تجاوزت الاستحقاق — المتبقّى ' || TO_CHAR((SELECT COALESCE(SUM(outstanding), 0) FROM base), 'FM999,999,990.00') END,
      '/bills'::text, (SELECT COUNT(*) FROM base)::int, (SELECT COALESCE(SUM(outstanding), 0) FROM base),
      jsonb_build_object('window_days_past_due', GREATEST(0, v_today - (SELECT MIN(due_date) FROM base)), 'samples', COALESCE((SELECT items FROM samples), '[]'::jsonb))
    FROM (SELECT 1) _ WHERE (SELECT COUNT(*) FROM base) > 0;
  END IF;

  -- 4. Stale draft sales orders
  IF 'sales_orders' = ANY(v_allowed) THEN
    RETURN QUERY
    SELECT 'stale_draft_sales_orders'::text, 'stale'::text, 'info'::text, 'sales_orders'::text,
      CASE v_lang WHEN 'en' THEN 'Old draft sales orders' ELSE 'أوامر بيع قديمة فى المُسودَّة' END,
      CASE v_lang WHEN 'en' THEN COUNT(*)::text || ' draft sales order(s) older than 7 days — review or remove'
                  ELSE           COUNT(*)::text || ' أمر بيع فى المُسودَّة لأكثر من 7 أيام — راجِعها أو احذِفها' END,
      '/sales-orders'::text, COUNT(*)::int, COALESCE(SUM(s.total), 0), jsonb_build_object('idle_days', 7)
    FROM public.sales_orders s
    WHERE LOWER(COALESCE(s.status, '')) = 'draft' AND s.created_at IS NOT NULL AND s.created_at < v_stale
    HAVING COUNT(*) > 0;
  END IF;

  -- 5. v3.74.560 — pending payment approvals older than 7 days
  IF 'payments' = ANY(v_allowed) OR 'bills' = ANY(v_allowed) THEN
    RETURN QUERY
    SELECT 'stuck_pending_payments'::text, 'stale'::text, 'warning'::text, 'payments'::text,
      CASE v_lang WHEN 'en' THEN 'Payments stuck awaiting approval' ELSE 'دَفعات مُعلَّقة بانتِظار الاعتِماد' END,
      CASE v_lang WHEN 'en' THEN COUNT(*)::text || ' payment(s) waiting > 7 days — total '  || TO_CHAR(COALESCE(SUM(p.base_currency_amount), 0), 'FM999,999,990.00')
                  ELSE           COUNT(*)::text || ' دَفعَة مُعلَّقة أَكثَر مِن 7 أيام — الإِجمالى ' || TO_CHAR(COALESCE(SUM(p.base_currency_amount), 0), 'FM999,999,990.00') END,
      '/approvals'::text, COUNT(*)::int, COALESCE(SUM(p.base_currency_amount), 0),
      jsonb_build_object('idle_days', 7)
    FROM public.payments p
    WHERE p.status = 'pending_approval'
      AND p.voided_at IS NULL AND p.voids_payment_id IS NULL
      AND p.created_at < v_stale
    HAVING COUNT(*) > 0;
  END IF;

  -- 6. v3.74.560 — stale purchase returns waiting for warehouse dispatch
  IF 'bills' = ANY(v_allowed) THEN
    RETURN QUERY
    SELECT 'stuck_purchase_returns'::text, 'stale'::text, 'warning'::text, 'purchase_returns'::text,
      CASE v_lang WHEN 'en' THEN 'Purchase returns stuck in workflow' ELSE 'مَرتَجَعات مُشتَريات مُعلَّقة فى الاعتِماد' END,
      CASE v_lang WHEN 'en' THEN COUNT(*)::text || ' return(s) pending > 7 days — value ' || TO_CHAR(COALESCE(SUM(pr.total_amount), 0), 'FM999,999,990.00')
                  ELSE           COUNT(*)::text || ' مَرتَجَع بانتِظار الاعتِماد أَكثَر مِن 7 أيام — القيمَة ' || TO_CHAR(COALESCE(SUM(pr.total_amount), 0), 'FM999,999,990.00') END,
      '/approvals'::text, COUNT(*)::int, COALESCE(SUM(pr.total_amount), 0),
      jsonb_build_object('idle_days', 7)
    FROM public.purchase_returns pr
    WHERE pr.workflow_status IN ('pending_admin_approval','pending_approval','pending_warehouse','partial_approval')
      AND pr.created_at < v_stale
    HAVING COUNT(*) > 0;
  END IF;

  -- 7. v3.74.560 — stale correction/refund requests
  IF 'payments' = ANY(v_allowed) THEN
    RETURN QUERY
    SELECT 'stuck_correction_requests'::text, 'stale'::text, 'warning'::text, 'corrections'::text,
      CASE v_lang WHEN 'en' THEN 'Payment corrections stuck' ELSE 'طَلَبات تَصحيح دَفعات مُعلَّقة' END,
      CASE v_lang WHEN 'en' THEN COUNT(*)::text || ' correction request(s) idle > 7 days'
                  ELSE           COUNT(*)::text || ' طَلَب تَصحيح مُعلَّق أَكثَر مِن 7 أيام' END,
      '/approvals'::text, COUNT(*)::int, 0::numeric,
      jsonb_build_object('idle_days', 7)
    FROM (
      SELECT id, created_at FROM public.vendor_payment_correction_requests
       WHERE status IN ('pending','approved') AND created_at < v_stale
      UNION ALL
      SELECT id, created_at FROM public.customer_refund_requests
       WHERE LOWER(COALESCE(status,'')) IN ('pending','approved') AND created_at < v_stale
    ) u
    HAVING COUNT(*) > 0;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- ai_knowledge_chunks_touch_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ai_knowledge_chunks_touch_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ai_normalize_for_fts(input text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ai_normalize_for_fts(input text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE PARALLEL SAFE
AS $function$
  SELECT regexp_replace(
    regexp_replace(
      -- drop diacritics, tatweel, superscript alef
      regexp_replace(
        COALESCE(input, ''),
        '[ؐ-ًؚ-ْٰـۖ-ۭ]',
        '',
        'g'
      ),
      -- drop common Arabic prefixes at the start of every word
      -- (longest first so "وال" is captured before "و" / "ال")
      '\m(وال|بال|كال|فال|لل|ال)',
      '',
      'g'
    ),
    -- collapse extra whitespace
    '\s+',
    ' ',
    'g'
  );
$function$
;

-- ---------------------------------------------------------------
-- ai_reindex_page_guides()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ai_reindex_page_guides()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_count   INTEGER := 0;
  v_guide   RECORD;
  v_max     INTEGER;
  v_i       INTEGER;
  v_txt_ar  TEXT;
  v_txt_en  TEXT;
  v_res     TEXT;
BEGIN
  DELETE FROM public.ai_knowledge_chunks
  WHERE source_type LIKE 'page_guide%'
    AND company_id IS NULL;

  FOR v_guide IN
    SELECT page_key,
           COALESCE(title_ar, '')              AS title_ar,
           COALESCE(title_en, '')              AS title_en,
           COALESCE(description_ar, '')        AS description_ar,
           COALESCE(description_en, '')        AS description_en,
           COALESCE(steps_ar, '[]'::jsonb)     AS steps_ar,
           COALESCE(steps_en, '[]'::jsonb)     AS steps_en,
           COALESCE(tips_ar, ARRAY[]::text[])  AS tips_ar,
           COALESCE(tips_en, ARRAY[]::text[])  AS tips_en
    FROM public.page_guides
    WHERE is_active = TRUE
  LOOP
    v_res := public.ai_resource_for_page_key(v_guide.page_key);

    -- Title
    INSERT INTO public.ai_knowledge_chunks (
      source_type, source_key, source_field,
      content_ar, content_en, resource, company_id, metadata
    ) VALUES (
      'page_guide_title', v_guide.page_key, NULL,
      v_guide.title_ar, v_guide.title_en,
      v_res, NULL,
      jsonb_build_object('page_key', v_guide.page_key)
    );
    v_count := v_count + 1;

    -- Description
    IF length(v_guide.description_ar) > 0 OR length(v_guide.description_en) > 0 THEN
      INSERT INTO public.ai_knowledge_chunks (
        source_type, source_key, source_field,
        content_ar, content_en, resource, company_id, metadata
      ) VALUES (
        'page_guide_description', v_guide.page_key, NULL,
        v_guide.description_ar, v_guide.description_en,
        v_res, NULL,
        jsonb_build_object('page_key', v_guide.page_key)
      );
      v_count := v_count + 1;
    END IF;

    -- Steps
    v_max := GREATEST(jsonb_array_length(v_guide.steps_ar), jsonb_array_length(v_guide.steps_en));
    FOR v_i IN 0..(v_max - 1) LOOP
      v_txt_ar := COALESCE(v_guide.steps_ar ->> v_i, '');
      v_txt_en := COALESCE(v_guide.steps_en ->> v_i, '');
      IF length(v_txt_ar) > 0 OR length(v_txt_en) > 0 THEN
        INSERT INTO public.ai_knowledge_chunks (
          source_type, source_key, source_field,
          content_ar, content_en, resource, company_id, metadata
        ) VALUES (
          'page_guide_step', v_guide.page_key,
          'step:' || v_i::TEXT,
          v_txt_ar, v_txt_en,
          v_res, NULL,
          jsonb_build_object('page_key', v_guide.page_key, 'index', v_i)
        );
        v_count := v_count + 1;
      END IF;
    END LOOP;

    -- Tips
    v_max := GREATEST(
      COALESCE(array_length(v_guide.tips_ar, 1), 0),
      COALESCE(array_length(v_guide.tips_en, 1), 0)
    );
    FOR v_i IN 1..v_max LOOP
      v_txt_ar := COALESCE(v_guide.tips_ar[v_i], '');
      v_txt_en := COALESCE(v_guide.tips_en[v_i], '');
      IF length(v_txt_ar) > 0 OR length(v_txt_en) > 0 THEN
        INSERT INTO public.ai_knowledge_chunks (
          source_type, source_key, source_field,
          content_ar, content_en, resource, company_id, metadata
        ) VALUES (
          'page_guide_tip', v_guide.page_key,
          'tip:' || (v_i - 1)::TEXT,
          v_txt_ar, v_txt_en,
          v_res, NULL,
          jsonb_build_object('page_key', v_guide.page_key, 'index', v_i - 1)
        );
        v_count := v_count + 1;
      END IF;
    END LOOP;
  END LOOP;

  RETURN v_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- ai_resource_for_page_key(p_page_key text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ai_resource_for_page_key(p_page_key text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE PARALLEL SAFE
