-- ---------------------------------------------------------------
-- ai_search_pages(p_query text, p_lang text, p_exclude_page_key text, p_limit integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ai_search_pages(p_query text, p_lang text DEFAULT 'ar'::text, p_exclude_page_key text DEFAULT NULL::text, p_limit integer DEFAULT 20)
 RETURNS TABLE(page_key text, title text, description text, best_snippet text, score real, match_count integer)
 LANGUAGE plpgsql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_clean    TEXT;
  v_or_text  TEXT;
  v_tsquery  tsquery;
BEGIN
  v_clean := COALESCE(p_query, '');
  v_clean := regexp_replace(v_clean, '[&|!():*<>=]', ' ', 'g');
  -- Apply the same Arabic normalizer used for the stored tsvector,
  -- so user-typed "شحن" matches stored "الشَحن" / "وال شحن" / etc.
  v_clean := public.ai_normalize_for_fts(v_clean);
  v_clean := regexp_replace(v_clean, '\s+', ' ', 'g');
  v_clean := TRIM(v_clean);

  IF v_clean = '' THEN
    RETURN;
  END IF;

  v_or_text := regexp_replace(v_clean, '\s+', ' | ', 'g');

  BEGIN
    v_tsquery := to_tsquery('simple', v_or_text);
  EXCEPTION WHEN OTHERS THEN
    RETURN;
  END;

  IF p_lang = 'en' THEN
    RETURN QUERY
    WITH matched AS (
      SELECT
        (c.metadata->>'page_key')::TEXT AS pk,
        c.source_type, c.source_field,
        c.content_en AS content,
        ts_rank(c.tsv_en, v_tsquery) AS chunk_rank
      FROM public.ai_knowledge_chunks c
      WHERE c.company_id IS NULL
        AND c.tsv_en @@ v_tsquery
        AND (p_exclude_page_key IS NULL OR (c.metadata->>'page_key') <> p_exclude_page_key)
    ),
    aggregated AS (
      SELECT
        pk AS page_key,
        SUM(chunk_rank * CASE source_type
              WHEN 'page_guide_title'       THEN 5.0
              WHEN 'page_guide_description' THEN 2.5
              WHEN 'page_guide_step'        THEN 1.5
              WHEN 'page_guide_tip'         THEN 1.0
              ELSE 1.0
            END)::REAL AS score,
        COUNT(*)::INTEGER AS match_count,
        (ARRAY_AGG(content ORDER BY chunk_rank DESC, source_type))[1] AS best_snippet
      FROM matched
      GROUP BY pk
    )
    SELECT
      a.page_key,
      COALESCE((SELECT t.content_en FROM public.ai_knowledge_chunks t
        WHERE t.source_type = 'page_guide_title' AND t.source_key = a.page_key
          AND t.company_id IS NULL LIMIT 1), '') AS title,
      COALESCE((SELECT d.content_en FROM public.ai_knowledge_chunks d
        WHERE d.source_type = 'page_guide_description' AND d.source_key = a.page_key
          AND d.company_id IS NULL LIMIT 1), '') AS description,
      a.best_snippet, a.score, a.match_count
    FROM aggregated a
    WHERE EXISTS (
      SELECT 1 FROM public.ai_knowledge_chunks t2
      WHERE t2.source_type = 'page_guide_title' AND t2.source_key = a.page_key
        AND t2.company_id IS NULL AND LENGTH(t2.content_en) > 0
    )
    ORDER BY a.score DESC LIMIT p_limit;
  ELSE
    RETURN QUERY
    WITH matched AS (
      SELECT
        (c.metadata->>'page_key')::TEXT AS pk,
        c.source_type, c.source_field,
        c.content_ar AS content,
        ts_rank(c.tsv_ar, v_tsquery) AS chunk_rank
      FROM public.ai_knowledge_chunks c
      WHERE c.company_id IS NULL
        AND c.tsv_ar @@ v_tsquery
        AND (p_exclude_page_key IS NULL OR (c.metadata->>'page_key') <> p_exclude_page_key)
    ),
    aggregated AS (
      SELECT
        pk AS page_key,
        SUM(chunk_rank * CASE source_type
              WHEN 'page_guide_title'       THEN 5.0
              WHEN 'page_guide_description' THEN 2.5
              WHEN 'page_guide_step'        THEN 1.5
              WHEN 'page_guide_tip'         THEN 1.0
              ELSE 1.0
            END)::REAL AS score,
        COUNT(*)::INTEGER AS match_count,
        (ARRAY_AGG(content ORDER BY chunk_rank DESC, source_type))[1] AS best_snippet
      FROM matched
      GROUP BY pk
    )
    SELECT
      a.page_key,
      COALESCE((SELECT t.content_ar FROM public.ai_knowledge_chunks t
        WHERE t.source_type = 'page_guide_title' AND t.source_key = a.page_key
          AND t.company_id IS NULL LIMIT 1), '') AS title,
      COALESCE((SELECT d.content_ar FROM public.ai_knowledge_chunks d
        WHERE d.source_type = 'page_guide_description' AND d.source_key = a.page_key
          AND d.company_id IS NULL LIMIT 1), '') AS description,
      a.best_snippet, a.score, a.match_count
    FROM aggregated a
    WHERE EXISTS (
      SELECT 1 FROM public.ai_knowledge_chunks t2
      WHERE t2.source_type = 'page_guide_title' AND t2.source_key = a.page_key
        AND t2.company_id IS NULL AND LENGTH(t2.content_ar) > 0
    )
    ORDER BY a.score DESC LIMIT p_limit;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- append_financial_audit_flag(p_transaction_id uuid, p_audit_flag text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.append_financial_audit_flag(p_transaction_id uuid, p_audit_flag text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_exists BOOLEAN := FALSE;
BEGIN
  IF p_transaction_id IS NULL OR p_audit_flag IS NULL OR btrim(p_audit_flag) = '' THEN
    RETURN;
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.financial_operation_traces fot,
         LATERAL jsonb_array_elements_text(COALESCE(fot.audit_flags, '[]'::JSONB)) AS flag(value)
    WHERE fot.transaction_id = p_transaction_id
      AND flag.value = p_audit_flag
  )
  INTO v_exists;

  IF NOT v_exists THEN
    UPDATE public.financial_operation_traces
    SET audit_flags = COALESCE(audit_flags, '[]'::JSONB) || to_jsonb(p_audit_flag)
    WHERE transaction_id = p_transaction_id;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- apply_customer_credit_to_invoice(p_company_id uuid, p_customer_id uuid, p_invoice_id uuid, p_amount numeric, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.apply_customer_credit_to_invoice(p_company_id uuid, p_customer_id uuid, p_invoice_id uuid, p_amount numeric, p_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_available_credit         numeric;
  v_invoice                  record;
  v_ar_account_id            uuid;
  v_customer_credit_acc_id   uuid;
  v_branch_id                uuid;
  v_journal_id               uuid;
  v_journal_ref_id           uuid := gen_random_uuid();  -- v3.74.205
  v_credit_ledger_id         uuid;
  v_payment_id               uuid;
  v_apply_amount             numeric;
  v_remaining_to_apply       numeric;
  v_credit_lot               record;
  v_consume_from_lot         numeric;
  v_company_base_ccy         text;
BEGIN
  v_available_credit := public.get_customer_credit_balance(p_company_id, p_customer_id);
  IF v_available_credit < 0.01 THEN
    RAISE EXCEPTION 'NO_CREDIT_AVAILABLE: Customer has no available credit balance';
  END IF;

  SELECT * INTO v_invoice FROM invoices WHERE id = p_invoice_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'INVOICE_NOT_FOUND: Invoice % not found', p_invoice_id;
  END IF;

  v_apply_amount := LEAST(
    p_amount,
    v_available_credit,
    GREATEST(0, v_invoice.total_amount - COALESCE(v_invoice.paid_amount, 0) - COALESCE(v_invoice.returned_amount, 0))
  );
  IF v_apply_amount < 0.01 THEN
    RAISE EXCEPTION 'NOTHING_TO_APPLY: Invoice is already fully paid or amount is zero';
  END IF;

  SELECT id INTO v_ar_account_id FROM chart_of_accounts
  WHERE company_id = p_company_id AND is_active = true
    AND (sub_type = 'accounts_receivable' OR account_name ILIKE '%receivable%' OR account_name ILIKE '%الذمم المدينة%')
  ORDER BY CASE WHEN sub_type = 'accounts_receivable' THEN 0 ELSE 1 END LIMIT 1;
  IF v_ar_account_id IS NULL THEN
    RAISE EXCEPTION 'AR_ACCOUNT_MISSING';
  END IF;

  SELECT id INTO v_customer_credit_acc_id FROM chart_of_accounts
  WHERE company_id = p_company_id AND is_active = true
    AND (sub_type IN ('customer_credit', 'customer_advance') OR account_code = '2155'
         OR account_name ILIKE '%رصيد العملاء الدائن%' OR account_name ILIKE '%customer credit%')
  ORDER BY CASE WHEN sub_type = 'customer_credit' THEN 0 WHEN sub_type = 'customer_advance' THEN 1
                WHEN account_code = '2155' THEN 2 ELSE 3 END LIMIT 1;
  IF v_customer_credit_acc_id IS NULL THEN
    RAISE EXCEPTION 'CUSTOMER_CREDIT_ACCOUNT_MISSING';
  END IF;

  v_branch_id := v_invoice.branch_id;
  IF v_branch_id IS NULL THEN
    SELECT id INTO v_branch_id FROM branches WHERE company_id = p_company_id AND is_active = true
    ORDER BY is_main DESC NULLS LAST, name LIMIT 1;
  END IF;

  SELECT base_currency INTO v_company_base_ccy FROM companies WHERE id = p_company_id;
  v_company_base_ccy := COALESCE(v_company_base_ccy, 'EGP');

  -- v3.74.205 — reference_id is a per-call UUID, not p_invoice_id, so a
  -- second application against the same invoice does not collide with the
  -- prevent_duplicate_journal_entry_v2 unique guard. Invoice traceability
  -- stays in the description + customer_credit_ledger.source_id + the
  -- payment row's invoice_id.
  INSERT INTO journal_entries (
    company_id, branch_id, reference_type, reference_id,
    entry_date, description, status
  ) VALUES (
    p_company_id, v_branch_id, 'credit_applied', v_journal_ref_id,
    CURRENT_DATE,
    'تطبيق رصيد دائن على الفاتورة ' || COALESCE(v_invoice.invoice_number, p_invoice_id::text),
    'draft'
  ) RETURNING id INTO v_journal_id;

  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id) VALUES
    (v_journal_id, v_customer_credit_acc_id, v_apply_amount, 0, 'تَسوية رَصيد العَميل الدائن مُقابِل الفاتورة', v_branch_id),
    (v_journal_id, v_ar_account_id, 0, v_apply_amount, 'تَخفيض الذِّمَم المَدينَة للفاتورة', v_branch_id);

  UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_id;

  -- v3.74.205 — FIFO consumption now includes 'partially_used' rows.
  -- Same bug class as v3.74.121/v3.74.199 — once any credit lot's status
  -- had ever been touched (trigger flips it to partially_used), the
  -- executor was skipping it and remaining_to_apply could not drain.
  v_remaining_to_apply := v_apply_amount;
  FOR v_credit_lot IN
    SELECT id, (amount - COALESCE(used_amount, 0) - COALESCE(applied_amount, 0)) AS available
    FROM customer_credits
    WHERE company_id = p_company_id AND customer_id = p_customer_id
      AND status IN ('active', 'partially_used')
      AND (amount - COALESCE(used_amount, 0) - COALESCE(applied_amount, 0)) > 0.01
    ORDER BY credit_date ASC, created_at ASC FOR UPDATE
  LOOP
    EXIT WHEN v_remaining_to_apply <= 0.001;
    v_consume_from_lot := LEAST(v_credit_lot.available, v_remaining_to_apply);
    UPDATE customer_credits
    SET applied_amount = COALESCE(applied_amount, 0) + v_consume_from_lot,
        status = CASE
                   WHEN (amount - COALESCE(used_amount, 0) - COALESCE(applied_amount, 0) - v_consume_from_lot) < 0.01
                     THEN 'used'
                   ELSE 'partially_used'
                 END,
        updated_at = NOW()
    WHERE id = v_credit_lot.id;
    v_remaining_to_apply := v_remaining_to_apply - v_consume_from_lot;
  END LOOP;

  -- Credit ledger entry — source_id still points at the invoice for traceability.
  INSERT INTO customer_credit_ledger (
    company_id, customer_id, source_type, source_id, journal_entry_id, amount, description, created_by
  ) VALUES (
    p_company_id, p_customer_id, 'credit_applied', p_invoice_id, v_journal_id, -v_apply_amount,
    'تطبيق رصيد دائن على الفاتورة ' || COALESCE(v_invoice.invoice_number, p_invoice_id::text), p_user_id
  ) RETURNING id INTO v_credit_ledger_id;

  -- v3.74.102 — Payment row so /payments shows the application alongside cash/bank payments
  INSERT INTO payments (
    company_id, customer_id, invoice_id, payment_date, amount, payment_method,
    reference_number, notes, account_id, journal_entry_id, branch_id, cost_center_id,
    currency_code, exchange_rate, base_currency_amount, original_currency, original_amount,
    status, created_by, created_by_user_id, unallocated_amount
  ) VALUES (
    p_company_id, p_customer_id, p_invoice_id, CURRENT_DATE, v_apply_amount, 'customer_credit',
    'CRED-' || COALESCE(v_invoice.invoice_number, SUBSTRING(p_invoice_id::text FROM 1 FOR 8)),
    'تطبيق رصيد دائن على الفاتورة ' || COALESCE(v_invoice.invoice_number, p_invoice_id::text),
    v_customer_credit_acc_id, v_journal_id, v_branch_id, v_invoice.cost_center_id,
    v_company_base_ccy, 1, v_apply_amount, v_company_base_ccy, v_apply_amount,
    'approved', p_user_id, p_user_id, 0
  ) RETURNING id INTO v_payment_id;

  UPDATE invoices SET
    paid_amount = COALESCE(paid_amount, 0) + v_apply_amount,
    status = CASE WHEN COALESCE(paid_amount, 0) + v_apply_amount
                       >= GREATEST(0, total_amount - COALESCE(returned_amount, 0))
                  THEN 'paid' ELSE 'partially_paid' END,
    updated_at = NOW()
  WHERE id = p_invoice_id;

  RETURN jsonb_build_object(
    'success', true,
    'applied_amount', v_apply_amount,
    'journal_entry_id', v_journal_id,
    'credit_ledger_id', v_credit_ledger_id,
    'payment_id', v_payment_id,
    'remaining_credit', v_available_credit - v_apply_amount,
    'ar_account_id', v_ar_account_id,
    'customer_credit_account', v_customer_credit_acc_id
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- apply_customer_debit_note(p_debit_note_id uuid, p_applied_to_type character varying, p_applied_to_id uuid, p_amount_to_apply numeric, p_applied_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.apply_customer_debit_note(p_debit_note_id uuid, p_applied_to_type character varying, p_applied_to_id uuid, p_amount_to_apply numeric, p_applied_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS TABLE(success boolean, message text, application_id uuid, journal_entry_id uuid)
 LANGUAGE plpgsql
AS $function$ DECLARE v_debit_note RECORD; v_remaining_amount DECIMAL(15,2); v_application_id UUID; v_journal_id UUID; v_invoice RECORD; v_ar_account_id UUID; v_revenue_account_id UUID; BEGIN SELECT * INTO v_debit_note FROM customer_debit_notes WHERE id = p_debit_note_id; IF NOT FOUND THEN RETURN QUERY SELECT FALSE, 'Debit note not found', NULL::UUID, NULL::UUID; RETURN; END IF; IF v_debit_note.approval_status != 'approved' THEN RETURN QUERY SELECT FALSE, 'Debit note must be approved before application (current status: ' || v_debit_note.approval_status || ')', NULL::UUID, NULL::UUID; RETURN; END IF; IF v_debit_note.created_by = p_applied_by THEN RETURN QUERY SELECT FALSE, 'Creator cannot apply their own debit note (separation of duties)', NULL::UUID, NULL::UUID; RETURN; END IF; v_remaining_amount := v_debit_note.total_amount - v_debit_note.applied_amount; IF p_amount_to_apply > v_remaining_amount THEN RETURN QUERY SELECT FALSE, 'Amount exceeds remaining balance (' || v_remaining_amount::TEXT || ')', NULL::UUID, NULL::UUID; RETURN; END IF; IF p_applied_to_type = 'invoice' THEN SELECT * INTO v_invoice FROM invoices WHERE id = p_applied_to_id; IF NOT FOUND THEN RETURN QUERY SELECT FALSE, 'Invoice not found', NULL::UUID, NULL::UUID; RETURN; END IF; IF v_invoice.company_id != v_debit_note.company_id THEN RETURN QUERY SELECT FALSE, 'Company mismatch between debit note and invoice', NULL::UUID, NULL::UUID; RETURN; END IF; IF v_debit_note.branch_id IS NOT NULL AND v_invoice.branch_id != v_debit_note.branch_id THEN RETURN QUERY SELECT FALSE, 'Branch mismatch between debit note and invoice', NULL::UUID, NULL::UUID; RETURN; END IF; IF v_invoice.customer_id != v_debit_note.customer_id THEN RETURN QUERY SELECT FALSE, 'Customer mismatch between debit note and invoice', NULL::UUID, NULL::UUID; RETURN; END IF; END IF; SELECT id INTO v_ar_account_id FROM chart_of_accounts WHERE company_id = v_debit_note.company_id AND account_type = 'accounts_receivable' AND is_active = TRUE LIMIT 1; SELECT ca.id INTO v_revenue_account_id FROM customer_debit_note_items dni LEFT JOIN products p ON dni.product_id = p.id LEFT JOIN chart_of_accounts ca ON p.revenue_account_id = ca.id WHERE dni.customer_debit_note_id = p_debit_note_id LIMIT 1; IF v_revenue_account_id IS NULL THEN SELECT id INTO v_revenue_account_id FROM chart_of_accounts WHERE company_id = v_debit_note.company_id AND account_type = 'revenue' AND is_active = TRUE LIMIT 1; END IF; IF v_ar_account_id IS NULL OR v_revenue_account_id IS NULL THEN RETURN QUERY SELECT FALSE, 'Required accounts not found', NULL::UUID, NULL::UUID; RETURN; END IF; INSERT INTO customer_debit_note_applications (company_id, branch_id, customer_debit_note_id, applied_to_type, applied_to_id, applied_date, amount_applied, notes, application_method, applied_by) VALUES (v_debit_note.company_id, v_debit_note.branch_id, p_debit_note_id, p_applied_to_type, p_applied_to_id, CURRENT_DATE, p_amount_to_apply, p_notes, 'manual', p_applied_by) RETURNING id INTO v_application_id; INSERT INTO journal_entries (company_id, branch_id, cost_center_id, reference_type, reference_id, entry_date, description, status, created_by) VALUES (v_debit_note.company_id, v_debit_note.branch_id, v_debit_note.cost_center_id, 'customer_debit_application', v_application_id, CURRENT_DATE, 'Customer Debit Note Applied - ' || v_debit_note.debit_note_number, 'posted', p_applied_by) RETURNING id INTO v_journal_id; INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES (v_journal_id, v_ar_account_id, p_amount_to_apply, 0, 'AR - Customer Debit Note Applied'); INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES (v_journal_id, v_revenue_account_id, 0, p_amount_to_apply, 'Revenue - Customer Debit Note Applied'); UPDATE customer_debit_note_applications SET journal_entry_id = v_journal_id WHERE id = v_application_id; UPDATE customer_debit_notes SET applied_amount = applied_amount + p_amount_to_apply, status = CASE WHEN (applied_amount + p_amount_to_apply) >= total_amount THEN 'applied' ELSE 'partially_applied' END WHERE id = p_debit_note_id; IF p_applied_to_type = 'invoice' THEN UPDATE invoices SET total_amount = total_amount + p_amount_to_apply, balance_due = balance_due + p_amount_to_apply WHERE id = p_applied_to_id; END IF; RETURN QUERY SELECT TRUE, 'Debit note applied successfully - journal entry created', v_application_id, v_journal_id; END; $function$
;

-- ---------------------------------------------------------------
-- apply_inventory_soft_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.apply_inventory_soft_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF COALESCE(OLD.is_deleted, FALSE) = FALSE AND NEW.is_deleted = TRUE THEN
    IF OLD.product_id IS NOT NULL THEN
      UPDATE products
        SET quantity_on_hand = COALESCE(quantity_on_hand, 0) - COALESCE(OLD.quantity_change, 0)
        WHERE id = OLD.product_id;
    END IF;
  ELSIF COALESCE(OLD.is_deleted, FALSE) = TRUE AND NEW.is_deleted = FALSE THEN
    IF NEW.product_id IS NOT NULL THEN
      UPDATE products
        SET quantity_on_hand = COALESCE(quantity_on_hand, 0) + COALESCE(NEW.quantity_change, 0)
        WHERE id = NEW.product_id;
    END IF;
  END IF;
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- apply_inventory_to_product_qty()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.apply_inventory_to_product_qty()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  prod_item_type TEXT;
BEGIN
  IF TG_OP = 'INSERT' THEN
    IF NEW.product_id IS NULL THEN
      RETURN NEW;
    END IF;
    -- Check if product is a service (skip inventory for services)
    SELECT item_type INTO prod_item_type FROM products WHERE id = NEW.product_id;
    IF prod_item_type = 'service' THEN
      RETURN NEW;
    END IF;
    UPDATE products
      SET quantity_on_hand = COALESCE(quantity_on_hand, 0) + COALESCE(NEW.quantity_change, 0)
      WHERE id = NEW.product_id;
    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    -- If product changed, revert old then apply new; else apply the delta
    IF NEW.product_id IS DISTINCT FROM OLD.product_id THEN
      IF OLD.product_id IS NOT NULL THEN
        SELECT item_type INTO prod_item_type FROM products WHERE id = OLD.product_id;
        IF prod_item_type IS NULL OR prod_item_type != 'service' THEN
          UPDATE products
            SET quantity_on_hand = COALESCE(quantity_on_hand, 0) - COALESCE(OLD.quantity_change, 0)
            WHERE id = OLD.product_id;
        END IF;
      END IF;
      IF NEW.product_id IS NOT NULL THEN
        SELECT item_type INTO prod_item_type FROM products WHERE id = NEW.product_id;
        IF prod_item_type IS NULL OR prod_item_type != 'service' THEN
          UPDATE products
            SET quantity_on_hand = COALESCE(quantity_on_hand, 0) + COALESCE(NEW.quantity_change, 0)
            WHERE id = NEW.product_id;
        END IF;
      END IF;
    ELSE
      SELECT item_type INTO prod_item_type FROM products WHERE id = NEW.product_id;
      IF prod_item_type IS NULL OR prod_item_type != 'service' THEN
        UPDATE products
          SET quantity_on_hand = COALESCE(quantity_on_hand, 0) + (COALESCE(NEW.quantity_change, 0) - COALESCE(OLD.quantity_change, 0))
          WHERE id = NEW.product_id;
      END IF;
    END IF;
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    IF OLD.product_id IS NULL THEN
      RETURN NULL;
    END IF;
    SELECT item_type INTO prod_item_type FROM products WHERE id = OLD.product_id;
    IF prod_item_type = 'service' THEN
      RETURN NULL;
    END IF;
    UPDATE products
      SET quantity_on_hand = COALESCE(quantity_on_hand, 0) - COALESCE(OLD.quantity_change, 0)
      WHERE id = OLD.product_id;
    RETURN NULL;
  END IF;
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_bank_voucher(p_request_id uuid, p_approved_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_bank_voucher(p_request_id uuid, p_approved_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_req RECORD;
BEGIN
    SELECT * INTO v_req FROM public.bank_voucher_requests WHERE id = p_request_id FOR UPDATE;

    IF v_req IS NULL THEN
        RAISE EXCEPTION 'Request not found';
    END IF;

    IF v_req.status != 'pending' THEN
        RAISE EXCEPTION 'Request is already %', v_req.status;
    END IF;

    -- Only update status to approved
    UPDATE public.bank_voucher_requests SET
        status = 'approved',
        reviewed_by = p_approved_by,
        reviewed_at = NOW()
    WHERE id = p_request_id;

    RETURN jsonb_build_object('success', true);
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_customer_debit_note(p_debit_note_id uuid, p_approved_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_customer_debit_note(p_debit_note_id uuid, p_approved_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS TABLE(success boolean, message text, debit_note_id uuid)
 LANGUAGE plpgsql
AS $function$ DECLARE v_debit_note RECORD; BEGIN SELECT * INTO v_debit_note FROM customer_debit_notes WHERE id = p_debit_note_id; IF NOT FOUND THEN RETURN QUERY SELECT FALSE, 'Debit note not found', NULL::UUID; RETURN; END IF; IF v_debit_note.approval_status = 'approved' THEN RETURN QUERY SELECT FALSE, 'Debit note is already approved', NULL::UUID; RETURN; END IF; IF v_debit_note.approval_status = 'rejected' THEN RETURN QUERY SELECT FALSE, 'Cannot approve rejected debit note', NULL::UUID; RETURN; END IF; IF v_debit_note.created_by = p_approved_by THEN RETURN QUERY SELECT FALSE, 'Creator cannot approve their own debit note (separation of duties)', NULL::UUID; RETURN; END IF; UPDATE customer_debit_notes SET approval_status = 'approved', approved_by = p_approved_by, approved_at = NOW(), notes = CASE WHEN p_notes IS NOT NULL THEN COALESCE(notes, '') || E'\n[APPROVAL] ' || p_notes ELSE notes END, updated_at = NOW() WHERE id = p_debit_note_id; RETURN QUERY SELECT TRUE, 'Debit note approved successfully', p_debit_note_id; END; $function$
;

-- ---------------------------------------------------------------
-- approve_manufacturing_bom_version_atomic(p_company_id uuid, p_bom_version_id uuid, p_approved_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_manufacturing_bom_version_atomic(p_company_id uuid, p_bom_version_id uuid, p_approved_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version RECORD;
BEGIN
  SELECT * INTO v_version
    FROM public.manufacturing_bom_versions
   WHERE id = p_bom_version_id AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'BOM version not found. bom_version_id=%', p_bom_version_id;
  END IF;

  IF v_version.status <> 'pending_approval' THEN
    RAISE EXCEPTION 'Only pending_approval versions can be approved. status=%', v_version.status;
  END IF;

  UPDATE public.manufacturing_bom_versions
     SET status           = 'approved',
         approved_by      = p_approved_by,
         approved_at      = NOW(),
         -- effective_from: keep existing or default to now
         effective_from   = COALESCE(v_version.effective_from, NOW()),
         rejected_by      = NULL,
         rejected_at      = NULL,
         rejection_reason = NULL,
         updated_by       = p_approved_by
   WHERE id = p_bom_version_id;

  RETURN jsonb_build_object(
    'success',        true,
    'bom_version_id', p_bom_version_id,
    'status',         'approved'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_approved_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_approved_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_po record;
BEGIN
  SELECT role INTO v_role FROM public.company_members
   WHERE company_id = p_company_id AND user_id = p_approved_by;
  IF NOT FOUND OR v_role NOT IN ('owner', 'general_manager') THEN
    RETURN jsonb_build_object('success', false,
      'error', 'صلاحية اعتماد أوامر الإنتاج محصورة بالمالك والمدير العام');
  END IF;

  SELECT * INTO v_po FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'أمر الإنتاج غير موجود');
  END IF;
  IF v_po.approval_status <> 'pending_approval' THEN
    RETURN jsonb_build_object('success', false, 'error', 'الأمر ليس بانتظار الاعتماد');
  END IF;

  UPDATE public.manufacturing_production_orders
     SET approval_status = 'approved',
         approved_by     = p_approved_by,
         approved_at     = NOW()
   WHERE id = p_production_order_id;

  RETURN jsonb_build_object('success', true, 'approval_status', 'approved');
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_purchase_order_atomic(p_po_id uuid, p_user_id uuid, p_company_id uuid, p_action text, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_purchase_order_atomic(p_po_id uuid, p_user_id uuid, p_company_id uuid, p_action text, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_po RECORD;
    v_user_role TEXT;
    v_user_branch UUID;
    v_new_status TEXT;
    v_audit_action TEXT;
    v_new_bill_id UUID;
    v_bill_number TEXT;
    v_next_bill_num INTEGER;
    v_item RECORD;
    v_last_disc_status TEXT;
BEGIN
    SELECT role, branch_id INTO v_user_role, v_user_branch
    FROM public.company_members WHERE company_id = p_company_id AND user_id = p_user_id;
    IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'User is not a member of this company'); END IF;
    IF v_user_role NOT IN ('owner', 'general_manager') THEN
         RETURN jsonb_build_object('success', false, 'error', 'صَلاحية اعتماد أَوامِر الشراء مَحصورَة بالمالِك والمُدير العام فَقَط');
    END IF;
    SELECT * INTO v_po FROM public.purchase_orders WHERE id = p_po_id AND company_id = p_company_id FOR UPDATE;
    IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Purchase order not found'); END IF;
    IF v_po.status != 'pending_approval' THEN
        RETURN jsonb_build_object('success', false, 'error', 'PO is not in a pending_approval state');
    END IF;

    IF p_action = 'approve' THEN
        IF COALESCE(v_po.discount_value, 0) > 0 THEN
            SELECT status INTO v_last_disc_status
              FROM public.discount_approvals
             WHERE document_type='purchase_order' AND document_id=p_po_id
             ORDER BY requested_at DESC LIMIT 1;

            IF v_last_disc_status = 'pending' THEN
              RETURN jsonb_build_object('success', false,
                'error', 'لا يمكن اعتماد أمر الشراء قبل اعتماد الخصم. افتح صندوق الموافقات واعتمد الخصم أولاً.');
            ELSIF v_last_disc_status = 'rejected' THEN
              RETURN jsonb_build_object('success', false,
                'error', 'تم رفض الخصم. عدّل أمر الشراء (احذف الخصم أو غيّر قيمته) لتفتح دورة موافقة جديدة.');
            ELSIF v_last_disc_status IS NULL THEN
              RETURN jsonb_build_object('success', false,
                'error', 'لا يوجد طلب موافقة على الخصم. أعد إنشاء الأمر أو عدّله لفتح دورة موافقة.');
            END IF;
        END IF;

        v_new_status := 'approved';
        v_audit_action := 'APPROVE';

        UPDATE public.purchase_orders
        SET status = v_new_status, approved_by = p_user_id, approved_at = NOW()
        WHERE id = p_po_id;

        v_new_bill_id := gen_random_uuid();
        SELECT COALESCE(MAX(CAST(SUBSTRING(bill_number FROM 'BILL-([0-9]+)') AS INTEGER)), 0) + 1 INTO v_next_bill_num
        FROM public.bills WHERE company_id = p_company_id AND bill_number ~ '^BILL-[0-9]+$';
        v_bill_number := 'BILL-' || LPAD(v_next_bill_num::TEXT, 4, '0');

        PERFORM set_config('app.skip_discount_approval', 'po', true);

        INSERT INTO public.bills (
            id, company_id, supplier_id, bill_number,
            bill_date, due_date,
            subtotal, tax_amount, total_amount,
            status, approval_status, approved_by, approved_at,
            created_at, is_deleted,
            purchase_order_id, branch_id, cost_center_id, warehouse_id,
            created_by_user_id, currency_code,
            discount_type, discount_value, shipping, adjustment,
            shipping_tax_rate, discount_position, tax_inclusive, exchange_rate,
            original_currency, original_total,
            display_currency, display_total, display_subtotal,
            original_subtotal, original_tax_amount
        ) VALUES (
            v_new_bill_id, v_po.company_id, v_po.supplier_id, v_bill_number,
            CURRENT_DATE, v_po.due_date,
            v_po.subtotal, v_po.tax_amount, v_po.total_amount,
            'draft', 'pending', NULL, NULL,
            NOW(), false,
            v_po.id, v_po.branch_id, v_po.cost_center_id, v_po.warehouse_id,
            p_user_id, v_po.currency,
            v_po.discount_type, v_po.discount_value, v_po.shipping, v_po.adjustment,
            COALESCE(v_po.shipping_tax_rate, 0),
            COALESCE(v_po.discount_position, 'before_tax'),
            COALESCE(v_po.tax_inclusive, false),
            COALESCE(v_po.exchange_rate, 1),
            v_po.currency, v_po.total_amount,
            v_po.currency, v_po.total_amount, v_po.subtotal,
            v_po.subtotal, v_po.tax_amount
        );

        UPDATE public.purchase_orders SET bill_id = v_new_bill_id WHERE id = p_po_id;

        FOR v_item IN (SELECT * FROM public.purchase_order_items WHERE purchase_order_id = p_po_id) LOOP
            INSERT INTO public.bill_items (
                id, bill_id, product_id, description, quantity, unit_price,
                tax_rate, tax_code_id, discount_percent, line_total
            ) VALUES (
                gen_random_uuid(), v_new_bill_id, v_item.product_id, v_item.description,
                v_item.quantity, v_item.unit_price, v_item.tax_rate, v_item.tax_code_id,
                v_item.discount_percent, v_item.line_total
            );
        END LOOP;

        PERFORM set_config('app.skip_discount_approval', '', true);

    ELSIF p_action = 'reject' THEN
        IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
            RETURN jsonb_build_object('success', false, 'error', 'Rejection reason is required');
        END IF;
        v_new_status := 'rejected';
        v_audit_action := 'UPDATE';
        UPDATE public.purchase_orders
        SET status = v_new_status, rejection_reason = p_reason, rejected_by = p_user_id, rejected_at = NOW()
        WHERE id = p_po_id;
    ELSE
        RETURN jsonb_build_object('success', false, 'error', 'Invalid action');
    END IF;

    INSERT INTO public.audit_logs (
        company_id, user_id, action, target_table, record_id, old_data, new_data, created_at, reason, branch_id
    ) VALUES (
        p_company_id, p_user_id, v_audit_action, 'purchase_orders', p_po_id,
        jsonb_build_object('status', v_po.status),
        jsonb_build_object('status', v_new_status, 'reason', p_reason),
        NOW(), p_reason, v_po.branch_id
    );

    RETURN jsonb_build_object(
        'success', true, 'po_id', p_po_id, 'status', v_new_status,
        'bill_id', v_new_bill_id, 'creator_id', v_po.created_by_user_id
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_purchase_return_atomic(p_pr_id uuid, p_user_id uuid, p_company_id uuid, p_action text, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_purchase_return_atomic(p_pr_id uuid, p_user_id uuid, p_company_id uuid, p_action text, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_pr          RECORD;
  v_user_role   TEXT;
  v_user_branch UUID;
  v_new_status  TEXT;
  v_new_wf      TEXT;
  v_audit_action TEXT;
BEGIN
  SELECT role, branch_id INTO v_user_role, v_user_branch
  FROM public.company_members
  WHERE company_id = p_company_id AND user_id = p_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User is not a member of this company');
  END IF;

  IF v_user_role NOT IN ('admin', 'owner', 'general_manager') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Insufficient permissions to approve purchase returns');
  END IF;

  SELECT * INTO v_pr
  FROM public.purchase_returns
  WHERE id = p_pr_id AND company_id = p_company_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Purchase return not found');
  END IF;

  IF v_user_role NOT IN ('owner', 'admin') THEN
    IF v_user_branch IS NOT NULL AND v_pr.branch_id IS NOT NULL AND v_user_branch != v_pr.branch_id THEN
      RETURN jsonb_build_object('success', false, 'error', 'Branch isolation violation');
    END IF;
  END IF;

  IF v_pr.workflow_status NOT IN ('pending_admin_approval', 'pending_approval') THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', format(
        'Purchase return is not pending admin approval. Current workflow_status: %s',
        v_pr.workflow_status
      )
    );
  END IF;

  IF p_action = 'approve' THEN
    v_new_status   := 'approved';
    v_new_wf       := 'pending_warehouse';
    v_audit_action := 'APPROVE';

    UPDATE public.purchase_returns
    SET
      status          = v_new_status,
      workflow_status = v_new_wf,
      approved_by     = p_user_id,
      approved_at     = NOW(),
      is_locked       = true,
      updated_at      = NOW()
    WHERE id = p_pr_id;

  ELSIF p_action = 'reject' THEN
    IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
      RETURN jsonb_build_object('success', false, 'error', 'Rejection reason is required');
    END IF;

    v_new_status   := 'rejected';
    v_new_wf       := 'rejected';
    v_audit_action := 'REJECT';

    UPDATE public.purchase_returns
    SET
      status           = v_new_status,
      workflow_status  = v_new_wf,
      rejected_by      = p_user_id,
      rejected_at      = NOW(),
      rejection_reason = p_reason,
      is_locked        = false,
      updated_at       = NOW()
    WHERE id = p_pr_id;

  ELSE
    RETURN jsonb_build_object('success', false, 'error', 'Invalid action. Must be approve or reject');
  END IF;

  INSERT INTO public.audit_logs (
    company_id, user_id, action, target_table, record_id, old_data, new_data, created_at
  ) VALUES (
    p_company_id, p_user_id,
    v_audit_action,
    'purchase_returns',
    p_pr_id,
    jsonb_build_object('status', v_pr.status, 'workflow_status', v_pr.workflow_status),
    jsonb_build_object('status', v_new_status, 'workflow_status', v_new_wf, 'reason', p_reason),
    NOW()
  );

  RETURN jsonb_build_object(
    'success',          true,
    'pr_id',            p_pr_id,
    'status',           v_new_status,
    'workflow_status',  v_new_wf,
    'created_by',       v_pr.created_by
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_approved_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_approved_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_rv record;
BEGIN
  SELECT role INTO v_role FROM public.company_members
   WHERE company_id = p_company_id AND user_id = p_approved_by;
  IF NOT FOUND OR v_role NOT IN ('owner', 'general_manager') THEN
    RETURN jsonb_build_object('success', false,
      'error', 'صلاحية اعتماد مسارات التصنيع محصورة بالمالك والمدير العام');
  END IF;

  SELECT * INTO v_rv FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'النسخة غير موجودة');
  END IF;
  IF v_rv.approval_status <> 'pending_approval' THEN
    RETURN jsonb_build_object('success', false, 'error', 'النسخة ليست بانتظار الاعتماد');
  END IF;

  UPDATE public.manufacturing_routing_versions
     SET approval_status = 'approved',
         approved_by     = p_approved_by,
         approved_at     = NOW()
   WHERE id = p_routing_version_id;

  RETURN jsonb_build_object('success', true, 'approval_status', 'approved');
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_sales_delivery(p_invoice_id uuid, p_confirmed_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_sales_delivery(p_invoice_id uuid, p_confirmed_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_invoice RECORD;
  v_item RECORD;
  v_decision_at TIMESTAMPTZ := NOW();
BEGIN
  SELECT i.*, s.warehouse_id, s.branch_id, s.cost_center_id, s.shipping_provider_id
  INTO v_invoice
  FROM public.invoices i
  JOIN public.sales_orders s ON s.id = i.sales_order_id
  WHERE i.id = p_invoice_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invoice not found');
  END IF;

  IF v_invoice.warehouse_status != 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Delivery already processed');
  END IF;

  IF v_invoice.status NOT IN ('sent', 'paid', 'partially_paid') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invoice must be posted (sent/paid) before warehouse dispatch');
  END IF;

  FOR v_item IN
    SELECT ii.*, p.name AS product_name
    FROM public.invoice_items ii
    JOIN public.products p ON p.id = ii.product_id
    WHERE ii.invoice_id = p_invoice_id
  LOOP
    INSERT INTO public.inventory_transactions (
      company_id, product_id, transaction_type, quantity_change,
      reference_id, reference_type, notes,
      branch_id, cost_center_id, warehouse_id,
      from_location_type, from_location_id,
      to_location_type, to_location_id,
      unit_cost, total_cost
    ) VALUES (
      v_invoice.company_id, v_item.product_id, 'sale_dispatch', -v_item.quantity,
      p_invoice_id, 'invoice', COALESCE(p_notes, 'إخراج بضاعة - فاتورة مبيعات'),
      v_invoice.branch_id, v_invoice.cost_center_id, v_invoice.warehouse_id,
      'warehouse', v_invoice.warehouse_id,
      'third_party', v_invoice.shipping_provider_id,
      v_item.unit_price, v_item.line_total
    );

    INSERT INTO public.third_party_inventory (
      company_id, shipping_provider_id, product_id, invoice_id,
      quantity, unit_cost, total_cost, status,
      branch_id, cost_center_id, warehouse_id,
      customer_id, sales_order_id
    ) VALUES (
      v_invoice.company_id, v_invoice.shipping_provider_id, v_item.product_id, p_invoice_id,
      v_item.quantity, v_item.unit_price, v_item.line_total, 'open',
      v_invoice.branch_id, v_invoice.cost_center_id, v_invoice.warehouse_id,
      v_invoice.customer_id, v_invoice.sales_order_id
    );
  END LOOP;

  UPDATE public.invoices
  SET
    warehouse_status = 'approved',
    approval_status = 'approved',
    approval_reason = NULLIF(p_notes, ''),
    approved_by = p_confirmed_by,
    approval_date = v_decision_at,
    rejected_by = NULL,
    rejected_at = NULL,
    warehouse_rejection_reason = NULL,
    warehouse_rejected_at = NULL
  WHERE id = p_invoice_id;

  RETURN jsonb_build_object('success', true, 'message', 'Inventory dispatched successfully');
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_sales_delivery_v2(p_company_id uuid, p_invoice_id uuid, p_confirmed_by uuid, p_inventory_transactions jsonb, p_cogs_transactions jsonb, p_fifo_consumptions jsonb, p_journal_entries jsonb, p_third_party_inventory_records jsonb, p_effective_date date, p_notes text, p_idempotency_key text, p_request_hash text, p_trace_metadata jsonb, p_audit_flags jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_sales_delivery_v2(p_company_id uuid, p_invoice_id uuid, p_confirmed_by uuid, p_inventory_transactions jsonb DEFAULT NULL::jsonb, p_cogs_transactions jsonb DEFAULT NULL::jsonb, p_fifo_consumptions jsonb DEFAULT NULL::jsonb, p_journal_entries jsonb DEFAULT NULL::jsonb, p_third_party_inventory_records jsonb DEFAULT NULL::jsonb, p_effective_date date DEFAULT NULL::date, p_notes text DEFAULT NULL::text, p_idempotency_key text DEFAULT NULL::text, p_request_hash text DEFAULT NULL::text, p_trace_metadata jsonb DEFAULT '{}'::jsonb, p_audit_flags jsonb DEFAULT '[]'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result JSONB;
  v_decision_at TIMESTAMPTZ := NOW();
BEGIN
  -- v3.74.83 — يُسَمِّح للـ trigger enforce_je_integrity بقبول INSERT/UPDATE
  -- على journal_entries بحالَة 'posted' من هذا الـ RPC المَوثوق. مَحَلى
  -- لِلـ transaction فَقَط (التَّعديل الثالث=true).
  PERFORM set_config('app.allow_direct_post', 'true', true);

  v_result := public.post_accounting_event_v2(
    p_event_type                    => 'warehouse_approval',
    p_company_id                    => p_company_id,
    p_inventory_transactions        => p_inventory_transactions,
    p_cogs_transactions             => p_cogs_transactions,
    p_fifo_consumptions             => p_fifo_consumptions,
    p_journal_entries               => p_journal_entries,
    p_update_source                 => jsonb_build_object(
      'invoice_id', p_invoice_id,
      'warehouse_status', 'approved'
    ),
    p_source_entity                 => 'invoice',
    p_source_id                     => p_invoice_id,
    p_effective_date                => p_effective_date,
    p_actor_id                      => p_confirmed_by,
    p_idempotency_key               => p_idempotency_key,
    p_request_hash                  => p_request_hash,
    p_third_party_inventory_records => p_third_party_inventory_records,
    p_trace_metadata                => COALESCE(p_trace_metadata, '{}'::JSONB) || jsonb_build_object('notes', p_notes),
    p_audit_flags                   => p_audit_flags
  );

  UPDATE public.invoices
  SET
    approval_status = 'approved',
    approval_reason = NULLIF(p_notes, ''),
    approved_by = p_confirmed_by,
    approval_date = v_decision_at,
    rejected_by = NULL,
    rejected_at = NULL,
    warehouse_rejection_reason = NULL,
    warehouse_rejected_at = NULL
  WHERE id = p_invoice_id
    AND company_id = p_company_id;

  RETURN v_result;
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_sales_return_atomic(p_return_id uuid, p_user_id uuid, p_company_id uuid, p_action text, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_sales_return_atomic(p_return_id uuid, p_user_id uuid, p_company_id uuid, p_action text, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_sr record;
BEGIN
  SELECT role INTO v_role FROM public.company_members
   WHERE company_id = p_company_id AND user_id = p_user_id;
  IF NOT FOUND OR v_role NOT IN ('owner', 'general_manager') THEN
    RETURN jsonb_build_object('success', false,
      'error', 'صلاحية اعتماد مرتجع المبيعات محصورة بالمالك والمدير العام فقط.');
  END IF;

  SELECT * INTO v_sr FROM public.sales_returns
   WHERE id = p_return_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'المرتجع غير موجود.');
  END IF;
  IF v_sr.status <> 'pending_approval' THEN
    RETURN jsonb_build_object('success', false,
      'error', 'المرتجع ليس بحالة "بانتظار الاعتماد".');
  END IF;

  IF p_action = 'approve' THEN
    UPDATE public.sales_returns
       SET status='approved', approved_by=p_user_id, approved_at=NOW()
     WHERE id=p_return_id;
    RETURN jsonb_build_object('success', true, 'status', 'approved');
  ELSIF p_action = 'reject' THEN
    IF p_reason IS NULL OR TRIM(p_reason)='' THEN
      RETURN jsonb_build_object('success', false, 'error', 'سبب الرفض مطلوب.');
    END IF;
    UPDATE public.sales_returns
       SET status='rejected', rejected_by=p_user_id, rejected_at=NOW(),
           rejection_reason=p_reason
     WHERE id=p_return_id;
    RETURN jsonb_build_object('success', true, 'status', 'rejected');
  ELSE
    RETURN jsonb_build_object('success', false, 'error', 'Invalid action');
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_shareholder_drawing(p_drawing_id uuid, p_approved_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_shareholder_drawing(p_drawing_id uuid, p_approved_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_drawing RECORD;
  v_journal_id UUID;
  v_branch_id UUID;
  v_cost_center_id UUID;
  v_amount_gl NUMERIC(15,2);
  v_approver_role TEXT;
BEGIN
  -- Idempotency & lock: select with FOR UPDATE so we own the row until commit
  SELECT * INTO v_drawing
  FROM public.shareholder_drawings
  WHERE id = p_drawing_id
  FOR UPDATE;

  IF v_drawing IS NULL THEN
    RAISE EXCEPTION 'Drawing not found: %', p_drawing_id;
  END IF;

  -- Status guard: only pending_approval can be approved
  IF v_drawing.status <> 'pending_approval' THEN
    RAISE EXCEPTION 'Drawing is not pending approval. Current status: %.', v_drawing.status;
  END IF;

  -- Company isolation: approver must be member of the same company
  IF p_approved_by IS NOT NULL THEN
    SELECT role INTO v_approver_role
    FROM public.company_members
    WHERE company_id = v_drawing.company_id AND user_id = p_approved_by
    LIMIT 1;
    IF v_approver_role IS NULL THEN
      RAISE EXCEPTION 'User is not a member of this company. Cannot approve drawing.';
    END IF;
    -- Role check: only owner, admin, general_manager can approve
    IF v_approver_role NOT IN ('owner', 'admin', 'general_manager') THEN
      RAISE EXCEPTION 'Insufficient role to approve drawings. Required: owner, admin, or general_manager.';
    END IF;
  END IF;

  IF v_drawing.payment_account_id IS NULL OR v_drawing.drawings_account_id IS NULL THEN
    RAISE EXCEPTION 'Drawing missing payment_account_id or drawings_account_id.';
  END IF;

  PERFORM validate_transaction_period(v_drawing.company_id, v_drawing.drawing_date);

  -- Amount for GL: use base_amount when set (multi-currency), else amount
  v_amount_gl := COALESCE(v_drawing.base_amount, v_drawing.amount);

  v_branch_id := v_drawing.branch_id;
  IF v_branch_id IS NULL THEN
    SELECT id INTO v_branch_id
    FROM branches
    WHERE company_id = v_drawing.company_id AND is_active = TRUE
    ORDER BY is_main DESC NULLS LAST, name
    LIMIT 1;
  END IF;
  IF v_branch_id IS NULL THEN
    RAISE EXCEPTION 'No branch found for company.';
  END IF;

  v_cost_center_id := v_drawing.cost_center_id;

  INSERT INTO public.journal_entries (
    company_id, branch_id, entry_date, description, reference_type, reference_id,
    status, cost_center_id
  ) VALUES (
    v_drawing.company_id, v_branch_id, v_drawing.drawing_date,
    'Shareholder Drawing - ' || v_drawing.drawing_date::TEXT,
    'shareholder_drawing', p_drawing_id,
    'posted', v_cost_center_id
  ) RETURNING id INTO v_journal_id;

  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount, branch_id, cost_center_id
  ) VALUES (
    v_journal_id, v_drawing.drawings_account_id, 'Shareholder Withdrawal', v_amount_gl, 0, v_branch_id, v_cost_center_id
  );

  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount, branch_id, cost_center_id
  ) VALUES (
    v_journal_id, v_drawing.payment_account_id, 'Cash Outflow', 0, v_amount_gl, v_branch_id, v_cost_center_id
  );

  UPDATE public.shareholder_drawings
  SET
    status = 'posted',
    approval_status = 'approved',
    approved_by = p_approved_by,
    approved_at = NOW(),
    last_status_changed_at = NOW(),
    journal_entry_id = v_journal_id,
    rejected_by = NULL,
    rejected_at = NULL,
    rejection_reason = NULL
  WHERE id = p_drawing_id;

  RETURN jsonb_build_object('drawing_id', p_drawing_id, 'journal_entry_id', v_journal_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_supplier_payment(p_payment_id uuid, p_approver_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_supplier_payment(p_payment_id uuid, p_approver_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_payment RECORD;
  v_bill    RECORD;
  v_mapping RECORD;
  v_member  RECORD;
BEGIN
  -- 1. Validate payment exists and is pending
  SELECT * INTO v_payment FROM payments WHERE id = p_payment_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Payment not found'; END IF;
  IF v_payment.status != 'pending_approval' THEN
    RAISE EXCEPTION 'Payment is not pending approval. Current status: %', v_payment.status;
  END IF;

  -- 2. Validate approver role
  SELECT role INTO v_member
  FROM company_members
  WHERE user_id = p_approver_id AND company_id = v_payment.company_id;
  IF NOT FOUND OR v_member.role NOT IN ('owner', 'admin', 'general_manager') THEN
    RAISE EXCEPTION 'UNAUTHORIZED: Only owner/admin/general_manager can approve payments';
  END IF;

  -- 3. Prevent self-approval
  IF v_payment.created_by = p_approver_id THEN
    RAISE EXCEPTION 'SELF_APPROVAL_BLOCKED: Cannot approve your own payment request';
  END IF;

  -- 4. Approve the payment
  UPDATE payments SET
    status = 'approved',
    approved_by = p_approver_id,
    approved_at = NOW(),
    updated_at = NOW()
  WHERE id = p_payment_id;

  -- 5. Notify creator
  IF v_payment.created_by IS NOT NULL THEN
    INSERT INTO notifications (
      company_id, branch_id, reference_type, reference_id,
      created_by, assigned_to_user,
      title, message, priority, status, event_key
    ) VALUES (
      v_payment.company_id, v_payment.branch_id,
      'supplier_payment_approved', p_payment_id,
      p_approver_id, v_payment.created_by,
      'تمت الموافقة على طلب الدفع',
      'تمت الموافقة على دفعة المورد بمبلغ ' || v_payment.amount || ' بواسطة المدير.',
      'high', 'unread',
      'payment_approved_' || p_payment_id::text
    );
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'payment_id', p_payment_id,
    'status', 'approved',
    'approved_by', p_approver_id,
    'approved_at', NOW()
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_supplier_payment_atomic(p_payment_id uuid, p_user_id uuid, p_company_id uuid, p_action text, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_supplier_payment_atomic(p_payment_id uuid, p_user_id uuid, p_company_id uuid, p_action text, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_payment record;
BEGIN
  SELECT role INTO v_role
    FROM public.company_members
   WHERE company_id = p_company_id AND user_id = p_user_id;
  IF NOT FOUND OR v_role NOT IN ('owner', 'general_manager') THEN
    RETURN jsonb_build_object('success', false,
      'error', 'صلاحية اعتماد دفع المورد محصورة بالمالك والمدير العام فقط.');
  END IF;

  SELECT * INTO v_payment FROM public.payments
   WHERE id = p_payment_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'الدفعة غير موجودة.');
  END IF;
  IF v_payment.supplier_id IS NULL AND v_payment.bill_id IS NULL THEN
    RETURN jsonb_build_object('success', false,
      'error', 'هذه ليست دفعة مورد.');
  END IF;
  IF v_payment.status <> 'pending_approval' THEN
    RETURN jsonb_build_object('success', false,
      'error', 'الدفعة ليست بحالة "بانتظار الاعتماد".');
  END IF;

  IF p_action = 'approve' THEN
    UPDATE public.payments
       SET status      = 'approved',
           approved_by = p_user_id,
           approved_at = NOW()
     WHERE id = p_payment_id;
    RETURN jsonb_build_object('success', true, 'status', 'approved');
  ELSIF p_action = 'reject' THEN
    IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
      RETURN jsonb_build_object('success', false, 'error', 'سبب الرفض مطلوب.');
    END IF;
    UPDATE public.payments
       SET status            = 'rejected',
           rejected_by       = p_user_id,
           rejected_at       = NOW(),
           rejection_reason  = p_reason
     WHERE id = p_payment_id;
    RETURN jsonb_build_object('success', true, 'status', 'rejected');
  ELSE
    RETURN jsonb_build_object('success', false, 'error', 'Invalid action');
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_vendor_refund_request(p_request_id uuid, p_company_id uuid, p_action text, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_vendor_refund_request(p_request_id uuid, p_company_id uuid, p_action text, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id       UUID := auth.uid();
  v_user_role     TEXT;
  v_req           RECORD;
  v_je_id         UUID;
  v_supplier_debit UUID;
  v_je_ref_id     UUID := gen_random_uuid();
  v_branch_id     UUID;
BEGIN
  SELECT role INTO v_user_role
  FROM public.company_members
  WHERE company_id = p_company_id AND user_id = v_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User is not a member of this company');
  END IF;

  IF v_user_role NOT IN ('owner', 'admin', 'general_manager', 'manager') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Insufficient permissions. Only admin/owner/manager can approve.');
  END IF;

  SELECT * INTO v_req
  FROM public.vendor_refund_requests
  WHERE id = p_request_id AND company_id = p_company_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Request not found');
  END IF;

  IF v_req.status != 'pending_approval' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Request is not in pending_approval state. Current status: ' || v_req.status);
  END IF;

  -- ===== Reject =====
  IF p_action = 'reject' THEN
    IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
      RETURN jsonb_build_object('success', false, 'error', 'Rejection reason is required');
    END IF;

    UPDATE public.vendor_refund_requests
    SET status = 'rejected', rejected_by = v_user_id, rejected_at = NOW(),
        rejection_reason = p_reason, updated_at = NOW()
    WHERE id = p_request_id;

    INSERT INTO public.audit_logs (company_id, user_id, action, target_table, record_id, old_data, new_data, created_at)
    VALUES (p_company_id, v_user_id, 'UPDATE', 'vendor_refund_requests', p_request_id,
            jsonb_build_object('status', 'pending_approval'),
            jsonb_build_object('status', 'rejected', 'rejection_reason', p_reason), NOW());

    RETURN jsonb_build_object('success', true, 'action', 'rejected', 'request_id', p_request_id);
  END IF;

  -- ===== Approve =====
  IF p_action != 'approve' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid action. Must be approve or reject.');
  END IF;

  -- Look up the Vendor Advances asset account, in priority order:
  --   1. By sub_type (the cleanest contract)
  --   2. By account_code (1180 / 1230 / 1240 are the conventional codes)
  --   3. By name pattern — broadened so it matches the Egyptian-Arabic
  --      "سلف ومقدمات للموردين" variants and the English equivalents.
  -- The previous AP fallback is GONE — silently turning a Vendor Advance
  -- settlement into an AP entry is exactly what produced the -3 EGP drift
  -- in JE-000031. If the chart of accounts is misconfigured we now fail
  -- loudly instead of corrupting the AP ledger.
  SELECT id INTO v_supplier_debit
  FROM public.chart_of_accounts
  WHERE company_id = p_company_id
    AND sub_type IN ('vendor_debit', 'supplier_advance', 'vendor_advance')
    AND is_active = TRUE
  ORDER BY created_at
  LIMIT 1;

  IF v_supplier_debit IS NULL THEN
    SELECT id INTO v_supplier_debit
    FROM public.chart_of_accounts
    WHERE company_id = p_company_id
      AND account_code IN ('1180', '1230', '1240')
      AND is_active = TRUE
    ORDER BY account_code
    LIMIT 1;
  END IF;

  IF v_supplier_debit IS NULL THEN
    SELECT id INTO v_supplier_debit
    FROM public.chart_of_accounts
    WHERE company_id = p_company_id
      AND (
        account_name ILIKE '%سلف%مورد%'        -- "سلف الموردين" / "سلف ومقدمات للموردين"
        OR account_name ILIKE '%مقدمات%مورد%'  -- "مقدمات للموردين"
        OR account_name ILIKE '%رصيد%مورد%مدين%'
        OR account_name ILIKE '%vendor advance%'
        OR account_name ILIKE '%supplier advance%'
        OR account_name ILIKE '%prepaid%vendor%'
        OR account_name ILIKE '%prepaid%supplier%'
      )
      AND is_active = TRUE
    ORDER BY created_at
    LIMIT 1;
  END IF;

  IF v_supplier_debit IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'لم يتم العثور على حساب «سلف ومقدمات للموردين». أضف الحساب فى الدليل المحاسبى (كود 1180) أو ضع sub_type = vendor_advance قبل إعادة المحاولة. لن يتم الترحيل على حساب الموردين الدائن.'
    );
  END IF;

  v_branch_id := COALESCE(
    v_req.branch_id,
    (SELECT b.id FROM branches b WHERE b.company_id = p_company_id AND COALESCE(b.is_active, true) ORDER BY b.is_main DESC NULLS LAST, b.name LIMIT 1)
  );

  IF v_branch_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'لم يتم العثور على فرع فعال للقيام بالعملية.');
  END IF;

  PERFORM set_config('app.allow_direct_post', 'true', true);

  INSERT INTO public.journal_entries (
    company_id, reference_type, reference_id,
    entry_date, description, branch_id, cost_center_id, status
  )
  VALUES (
    p_company_id,
    'vendor_refund',
    v_je_ref_id,
    v_req.receipt_date,
    COALESCE(v_req.notes, 'استرداد نقدي من المورد - اعتمد بواسطة النظام'),
    v_branch_id,
    v_req.cost_center_id,
    'draft'
  )
  RETURNING id INTO v_je_id;

  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id,
    debit_amount, credit_amount, description,
    original_currency, original_debit, original_credit,
    exchange_rate_used, branch_id, cost_center_id
  )
  VALUES (
    v_je_id,
    v_req.receipt_account_id,
    v_req.base_amount, 0,
    'استقبال نقدي/بنكي من المورد',
    v_req.currency, v_req.amount, 0,
    v_req.exchange_rate,
    v_branch_id, v_req.cost_center_id
  );

  INSERT INTO public.journal_entry_lines (
      journal_entry_id, account_id,
      debit_amount, credit_amount, description,
      original_currency, original_debit, original_credit,
      exchange_rate_used, branch_id, cost_center_id
  )
  VALUES (
      v_je_id,
      v_supplier_debit,
      0, v_req.base_amount,
      'تسوية سلفة المورد - استرداد',
      v_req.currency, 0, v_req.amount,
      v_req.exchange_rate,
      v_branch_id, v_req.cost_center_id
  );

  UPDATE public.journal_entries
  SET status = 'posted', updated_at = NOW()
  WHERE id = v_je_id;

  PERFORM set_config('app.allow_direct_post', 'false', true);

  -- Apply against vendor_credits (unchanged from previous version).
  DECLARE
    v_remaining   NUMERIC := v_req.amount;
    v_credit      RECORD;
    v_available   NUMERIC;
    v_deduct      NUMERIC;
    v_new_applied NUMERIC;
    v_new_status  TEXT;
  BEGIN
    FOR v_credit IN (
      SELECT id, total_amount, applied_amount
      FROM public.vendor_credits
      WHERE company_id = p_company_id
        AND supplier_id = v_req.supplier_id
        AND status IN ('open', 'partially_applied')
      ORDER BY credit_date ASC
      FOR UPDATE
    ) LOOP
      EXIT WHEN v_remaining <= 0;
      v_available := COALESCE(v_credit.total_amount, 0) - COALESCE(v_credit.applied_amount, 0);
      CONTINUE WHEN v_available <= 0;
      v_deduct := LEAST(v_available, v_remaining);
      v_new_applied := COALESCE(v_credit.applied_amount, 0) + v_deduct;
      v_new_status := CASE WHEN v_new_applied >= COALESCE(v_credit.total_amount, 0) THEN 'applied' ELSE 'partially_applied' END;
      UPDATE public.vendor_credits
      SET applied_amount = v_new_applied, status = v_new_status, updated_at = NOW()
      WHERE id = v_credit.id;
      v_remaining := v_remaining - v_deduct;
    END LOOP;
  END;

  UPDATE public.vendor_refund_requests
  SET status = 'approved', approved_by = v_user_id, approved_at = NOW(),
      journal_entry_id = v_je_id, updated_at = NOW()
  WHERE id = p_request_id;

  INSERT INTO public.audit_logs (company_id, user_id, action, target_table, record_id, old_data, new_data, created_at)
  VALUES (p_company_id, v_user_id, 'UPDATE', 'vendor_refund_requests', p_request_id,
          jsonb_build_object('status', 'pending_approval'),
          jsonb_build_object('status', 'approved', 'journal_entry_id', v_je_id), NOW());

  RETURN jsonb_build_object(
    'success', true,
    'action', 'approved',
    'request_id', p_request_id,
    'journal_entry_id', v_je_id,
    'created_by', v_req.created_by
  );

EXCEPTION WHEN OTHERS THEN
  PERFORM set_config('app.allow_direct_post', 'false', true);
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- approve_write_off(p_write_off_id uuid, p_approved_by uuid, p_expense_account_id uuid, p_inventory_account_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.approve_write_off(p_write_off_id uuid, p_approved_by uuid, p_expense_account_id uuid, p_inventory_account_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_write_off RECORD;
  v_item RECORD;
  v_journal_id UUID;
  v_product RECORD;
  v_available_qty INTEGER;
BEGIN
  -- جلب بيانات الإهلاك
  SELECT * INTO v_write_off FROM inventory_write_offs WHERE id = p_write_off_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'لم يتم العثور على الإهلاك');
  END IF;

  IF v_write_off.status != 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'الإهلاك ليس في حالة انتظار');
  END IF;

  -- التحقق من توفر الكميات
  FOR v_item IN SELECT * FROM inventory_write_off_items WHERE write_off_id = p_write_off_id LOOP
    SELECT quantity_on_hand INTO v_available_qty FROM products WHERE id = v_item.product_id;
    IF v_available_qty < v_item.quantity THEN
      SELECT name INTO v_product FROM products WHERE id = v_item.product_id;
      RETURN jsonb_build_object(
        'success', false,
        'error', 'الكمية المتاحة غير كافية للمنتج: ' || v_product.name ||
                 ' (متاح: ' || v_available_qty || ', مطلوب: ' || v_item.quantity || ')'
      );
    END IF;
  END LOOP;

  -- إنشاء القيد المحاسبي
  INSERT INTO journal_entries (
    company_id, reference_type, reference_id, entry_date, description
  ) VALUES (
    v_write_off.company_id,
    'write_off',
    p_write_off_id,
    v_write_off.write_off_date,
    'إهلاك مخزون - ' || v_write_off.write_off_number
  ) RETURNING id INTO v_journal_id;

  -- إدراج كلا السطرين (المدين والدائن) في نفس الأمر لضمان التوازن
  INSERT INTO journal_entry_lines (
    journal_entry_id, account_id, debit_amount, credit_amount, description
  ) VALUES 
    -- خصم حساب مصروف الإهلاك
    (
      v_journal_id, p_expense_account_id, v_write_off.total_cost, 0,
      'مصروف إهلاك مخزون - ' || v_write_off.write_off_number
    ),
    -- دائن حساب المخزون
    (
      v_journal_id, p_inventory_account_id, 0, v_write_off.total_cost,
      'تخفيض المخزون - ' || v_write_off.write_off_number
    );

  -- إنشاء حركات المخزون
  FOR v_item IN SELECT * FROM inventory_write_off_items WHERE write_off_id = p_write_off_id LOOP
    INSERT INTO inventory_transactions (
      company_id, product_id, transaction_type, quantity_change,
      reference_id, journal_entry_id, notes
    ) VALUES (
      v_write_off.company_id,
      v_item.product_id,
      'write_off',
      -v_item.quantity,
      p_write_off_id,
      v_journal_id,
      'إهلاك - ' || v_write_off.write_off_number
    );
  END LOOP;

  -- تحديث حالة الإهلاك
  UPDATE inventory_write_offs SET
    status = 'approved',
    approved_by = p_approved_by,
    approved_at = now(),
    journal_entry_id = v_journal_id,
    updated_at = now()
  WHERE id = p_write_off_id;

  RETURN jsonb_build_object(
    'success', true,
    'journal_entry_id', v_journal_id,
    'message', 'تم اعتماد الإهلاك بنجاح'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- archive_approval_notifications_for_record(p_company_id uuid, p_reference_type character varying, p_reference_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.archive_approval_notifications_for_record(p_company_id uuid, p_reference_type character varying, p_reference_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_count int;
BEGIN
  IF p_company_id IS NULL OR p_reference_type IS NULL OR p_reference_id IS NULL THEN
    RETURN 0;
  END IF;

  UPDATE notifications
     SET status = 'archived'
   WHERE company_id     = p_company_id
     AND reference_type = p_reference_type
     AND reference_id   = p_reference_id
     AND category       = 'approvals'
     AND status IN ('unread', 'read');

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- archive_manufacturing_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_updated_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.archive_manufacturing_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_updated_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version RECORD;
BEGIN
  SELECT *
    INTO v_version
    FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing routing version not found or not in company. routing_version_id=%', p_routing_version_id;
  END IF;

  IF v_version.status NOT IN ('draft', 'active', 'inactive') THEN
    RAISE EXCEPTION 'Only draft, active, or inactive routing versions can be archived. routing_version_id=%, status=%',
      p_routing_version_id, v_version.status;
  END IF;

  PERFORM 1
    FROM public.manufacturing_routing_versions
   WHERE routing_id = v_version.routing_id
   FOR UPDATE;

  UPDATE public.manufacturing_routing_versions
     SET status = 'archived',
         updated_by = p_updated_by
   WHERE id = p_routing_version_id;

  RETURN jsonb_build_object(
    'success', true,
    'routing_version_id', p_routing_version_id,
    'previous_status', v_version.status,
    'status', 'archived'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- archive_service_atomic(p_company_id uuid, p_service_id uuid, p_updated_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.archive_service_atomic(p_company_id uuid, p_service_id uuid, p_updated_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_active_booking_count INTEGER;
BEGIN
  PERFORM id FROM public.services WHERE id = p_service_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Service not found. service_id=%', p_service_id USING ERRCODE = 'P0001'; END IF;
  SELECT COUNT(*) INTO v_active_booking_count FROM public.bookings
   WHERE service_id = p_service_id AND company_id = p_company_id AND status NOT IN ('completed','cancelled','no_show');
  IF v_active_booking_count > 0 THEN
    RAISE EXCEPTION 'Cannot archive service with % active booking(s). Complete or cancel them first. service_id=%', v_active_booking_count, p_service_id USING ERRCODE = 'P0001';
  END IF;
  UPDATE public.services SET is_active = false, is_bookable = false, updated_by = p_updated_by WHERE id = p_service_id;
  RETURN jsonb_build_object('success', true, 'service_id', p_service_id);
END; $function$
;

