-- ---------------------------------------------------------------
-- assert_baseline()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assert_baseline()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_name text; v_company record; v_error record; v_drift record;
  v_errors int := 0; v_drift_cnt int := 0;
  v_approve_def text; v_void_def text; v_void_inv_def text; v_inv_trg_def text;
  v_dashboard_def text; v_opts text;
  v_po_eval_def text; v_so_eval_def text;
  v_po_cancel_def text; v_so_cancel_def text;
  v_bill_req_def text; v_bill_post_def text;
  v_po_protect_def text; v_po_item_protect_def text;
  v_bill_protect_def text; v_bill_item_protect_def text;
  v_pay_ins_def text; v_pay_upd_def text; v_pay_notify_def text;
  v_pr_ins_def text; v_pr_upd_def text; v_pr_notify_def text;
BEGIN
  FOR v_name IN SELECT unnest(ARRAY['can_modify_data','can_manage_supplier_row','complete_booking_atomic',
                                     'execute_sales_invoice_accounting','check_booking_service_inventory','run_all_integrity_checks',
                                     'void_bill_atomic','void_invoice_atomic','notify_discount_decision_trg',
                                     'po_evaluate_discount_approval','so_evaluate_discount_approval',
                                     'po_cancel_discount_on_status_trg','so_cancel_discount_on_status_trg',
                                     'po_protect_approved_trg','po_item_protect_approved_trg',
                                     'bill_protect_posted_trg','bill_item_protect_posted_trg',
                                     'payment_supplier_approval_insert_trg','payment_supplier_approval_update_trg',
                                     'payment_supplier_notify_approval_trg','approve_supplier_payment_atomic',
                                     'purchase_return_approval_insert_trg','purchase_return_approval_update_trg',
                                     'purchase_return_notify_approval_trg','approve_purchase_return_atomic'])
  LOOP IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = v_name) THEN
      RAISE EXCEPTION 'BASELINE FAIL: function missing: %', v_name;
  END IF; END LOOP;

  FOR v_name IN SELECT unnest(ARRAY['discount_approvals','company_seat_licenses','service_products'])
  LOOP IF NOT EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name=v_name) THEN
      RAISE EXCEPTION 'BASELINE FAIL: table missing: %', v_name;
  END IF; END LOOP;

  FOR v_name IN SELECT unnest(ARRAY['bkg_request_discount_approval','inv_request_discount_approval','inv_block_post_unapproved_discount',
                                     'bill_request_discount_approval','bill_block_post_unapproved_discount',
                                     'sync_employee_user_id_ins','sync_employee_user_id_upd','sync_employee_user_id_del',
                                     'po_request_discount_approval','so_request_discount_approval',
                                     'discount_approval_notify_decision',
                                     'po_item_request_discount_approval','so_item_request_discount_approval',
                                     'po_cancel_discount_on_status','so_cancel_discount_on_status',
                                     'po_protect_approved','po_item_protect_approved',
                                     'bill_protect_posted','bill_item_protect_posted',
                                     'payment_supplier_approval_insert','payment_supplier_approval_update',
                                     'payment_supplier_notify_approval',
                                     'trg_auto_create_payment_journal_ins','trg_auto_create_payment_journal_upd',
                                     'purchase_return_approval_insert','purchase_return_approval_update',
                                     'purchase_return_notify_approval'])
  LOOP IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname=v_name AND NOT tgisinternal) THEN
      RAISE EXCEPTION 'BASELINE FAIL: trigger missing: %', v_name;
  END IF; END LOOP;

  IF EXISTS (SELECT 1 FROM pg_trigger WHERE tgname='trg_auto_create_payment_journal' AND NOT tgisinternal) THEN
    RAISE EXCEPTION 'BASELINE FAIL: legacy trg_auto_create_payment_journal still present (v3.74.426)';
  END IF;

  FOR v_name IN SELECT unnest(ARRAY['suppliers_insert','suppliers_update','suppliers_delete'])
  LOOP IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE schemaname='public' AND tablename='suppliers' AND policyname=v_name) THEN
      RAISE EXCEPTION 'BASELINE FAIL: policy missing on suppliers: %', v_name;
  END IF; END LOOP;

  FOR v_name IN SELECT unnest(ARRAY['booking','sales_invoice','purchase_invoice','purchase_order','sales_order'])
  LOOP IF NOT EXISTS (SELECT 1 FROM pg_enum WHERE enumtypid='discount_document_type'::regtype AND enumlabel=v_name) THEN
      RAISE EXCEPTION 'BASELINE FAIL: discount_document_type enum missing value "%"', v_name;
  END IF; END LOOP;

  IF NOT EXISTS (SELECT 1 FROM pg_proc p WHERE p.proname='can_modify_data'
    AND pg_get_functiondef(p.oid) LIKE '%purchasing_officer%'
    AND pg_get_functiondef(p.oid) LIKE '%general_manager%') THEN
    RAISE EXCEPTION 'BASELINE FAIL: can_modify_data is missing modern operational roles';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc p WHERE p.proname='can_manage_supplier_row'
    AND pg_get_functiondef(p.oid) LIKE '%p_row_branch_id = v_user_branch_id%') THEN
    RAISE EXCEPTION 'BASELINE FAIL: can_manage_supplier_row no longer enforces branch-scope';
  END IF;

  FOR v_company IN SELECT id, name FROM companies LOOP
    FOR v_error IN SELECT check_code, name_ar, severity, detail FROM run_all_integrity_checks(v_company.id) WHERE severity='error'
    LOOP v_errors := v_errors + 1; END LOOP;
  END LOOP;
  IF v_errors > 0 THEN RAISE EXCEPTION 'BASELINE FAIL: % integrity error(s)', v_errors; END IF;

  FOR v_drift IN
    SELECT pr.id AS product_id
      FROM products pr
     WHERE coalesce(pr.product_type, pr.item_type, 'physical') NOT IN ('service','خدمة')
       AND pr.quantity_on_hand IS DISTINCT FROM coalesce((SELECT sum(quantity_change) FROM inventory_transactions WHERE product_id = pr.id), 0)
  LOOP v_drift_cnt := v_drift_cnt + 1; END LOOP;
  IF v_drift_cnt > 0 THEN RAISE EXCEPTION 'BASELINE FAIL: % product(s) inventory drift', v_drift_cnt; END IF;

  FOR v_name IN SELECT unnest(ARRAY['purchase_order_items','bill_items','invoice_items','sales_order_items',
                                     'vendor_credit_items','estimate_items','customer_debit_note_items'])
  LOOP IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                       WHERE table_schema='public' AND table_name=v_name AND column_name='tax_code_id') THEN
      RAISE EXCEPTION 'BASELINE FAIL: %.tax_code_id column missing', v_name;
  END IF; END LOOP;

  SELECT pg_get_functiondef(p.oid) INTO v_approve_def FROM pg_proc p WHERE p.proname='approve_purchase_order_atomic' LIMIT 1;
  IF v_approve_def NOT LIKE '%v_last_disc_status = ''rejected''%'
     OR v_approve_def NOT LIKE '%''owner'', ''general_manager''%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: approve_purchase_order_atomic invariants';
  END IF;

  SELECT pg_get_functiondef(p.oid) INTO v_void_def FROM pg_proc p WHERE p.proname='void_bill_atomic' LIMIT 1;
  IF v_void_def NOT LIKE '%discount_approvals%' OR v_void_def NOT LIKE '%status = ''voided''%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: void_bill_atomic invariants';
  END IF;

  SELECT pg_get_functiondef(p.oid) INTO v_inv_trg_def FROM pg_proc p WHERE p.proname='inv_request_discount_approval_trg' LIMIT 1;
