  END IF;
  SELECT pg_get_functiondef(p.oid) INTO v_bill_protect_def FROM pg_proc p WHERE p.proname='bill_protect_posted_trg' LIMIT 1;
  IF v_bill_protect_def NOT LIKE '%discount_value%' OR v_bill_protect_def NOT LIKE '%''draft''%' THEN
