  END IF;
  SELECT pg_get_functiondef(p.oid) INTO v_bill_item_protect_def FROM pg_proc p WHERE p.proname='bill_item_protect_posted_trg' LIMIT 1;
  IF v_bill_item_protect_def NOT LIKE '%''draft''%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: bill_item_protect_posted_trg invariants (v3.74.425)';
  END IF;

  SELECT pg_get_functiondef(p.oid) INTO v_pay_ins_def FROM pg_proc p WHERE p.proname='payment_supplier_approval_insert_trg' LIMIT 1;
  IF v_pay_ins_def NOT LIKE '%''owner'', ''general_manager''%' OR v_pay_ins_def NOT LIKE '%supplier_id%' OR v_pay_ins_def NOT LIKE '%bill_id%' THEN
