  PERFORM public.assert_baseline_v3_74_451_check();
  PERFORM public.assert_baseline_v3_74_452_check();
  PERFORM public.assert_baseline_v3_74_454_check();
  RAISE NOTICE 'BASELINE OK: all contracts intact';
END;
$function$
;

-- ---------------------------------------------------------------
-- assert_baseline_v3_74_428_check()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assert_baseline_v3_74_428_check()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_def text;
BEGIN
  -- All four trigger functions must exist
  FOR v_def IN SELECT unnest(ARRAY[
        'notify_branch_manager',
        'po_branch_manager_notify_trg',
        'bill_branch_manager_notify_trg',
        'payment_branch_manager_notify_trg',
        'purchase_return_branch_manager_notify_trg'])
  LOOP
    IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = v_def) THEN
      RAISE EXCEPTION 'BASELINE FAIL: function missing: % (v3.74.428)', v_def;
    END IF;
  END LOOP;

  -- All four triggers must be installed
  FOR v_def IN SELECT unnest(ARRAY[
        'po_branch_manager_notify',
        'bill_branch_manager_notify',
        'payment_branch_manager_notify',
        'purchase_return_branch_manager_notify'])
  LOOP
    IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname = v_def AND NOT tgisinternal) THEN
      RAISE EXCEPTION 'BASELINE FAIL: trigger missing: % (v3.74.428)', v_def;
    END IF;
  END LOOP;

  -- Helper must filter by role='manager' AND branch_id
  SELECT pg_get_functiondef(oid) INTO v_def FROM pg_proc WHERE proname = 'notify_branch_manager';
  IF v_def NOT LIKE '%role%=%''manager''%' AND v_def NOT LIKE '%role = ''manager''%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: notify_branch_manager does not target role=manager (v3.74.428)';
  END IF;
  IF v_def NOT LIKE '%branch_id%=%p_branch_id%' AND v_def NOT LIKE '%branch_id  = p_branch_id%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: notify_branch_manager does not filter by branch (v3.74.428)';
  END IF;
  IF v_def NOT LIKE '%''branch_activity''%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: notify_branch_manager does not use branch_activity category (v3.74.428)';
  END IF;
END;
$function$
;

