-- ---------------------------------------------------------------
-- assert_baseline_v3_74_430_check()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assert_baseline_v3_74_430_check()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_def text;
BEGIN
  -- Schema: sales_returns must have all 5 approval columns
  FOR v_def IN SELECT unnest(ARRAY['approved_by','approved_at','rejected_by','rejected_at','rejection_reason'])
  LOOP
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                    WHERE table_schema='public' AND table_name='sales_returns' AND column_name=v_def) THEN
      RAISE EXCEPTION 'BASELINE FAIL: sales_returns.% missing (v3.74.430)', v_def;
    END IF;
  END LOOP;

  -- Functions
  FOR v_def IN SELECT unnest(ARRAY[
        'sales_return_approval_insert_trg','sales_return_approval_update_trg',
        'sales_return_notify_approval_trg','approve_sales_return_atomic',
        'so_branch_manager_notify_trg','invoice_branch_manager_notify_trg',
        'payment_customer_branch_manager_notify_trg',
        'sales_return_branch_manager_notify_trg','invoice_notify_accountant_trg'])
  LOOP
    IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname=v_def) THEN
      RAISE EXCEPTION 'BASELINE FAIL: function missing: % (v3.74.430)', v_def;
    END IF;
  END LOOP;

  -- Triggers
  FOR v_def IN SELECT unnest(ARRAY[
        'sales_return_approval_insert','sales_return_approval_update',
        'sales_return_notify_approval','so_branch_manager_notify',
        'invoice_branch_manager_notify','payment_customer_branch_manager_notify',
        'sales_return_branch_manager_notify','invoice_notify_accountant'])
  LOOP
    IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname=v_def AND NOT tgisinternal) THEN
      RAISE EXCEPTION 'BASELINE FAIL: trigger missing: % (v3.74.430)', v_def;
    END IF;
  END LOOP;

  -- Contract invariants
  SELECT pg_get_functiondef(oid) INTO v_def FROM pg_proc WHERE proname='sales_return_approval_insert_trg';
  IF v_def NOT LIKE '%''owner'', ''general_manager''%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: sales_return_approval_insert_trg missing role gate (v3.74.430)';
  END IF;
  SELECT pg_get_functiondef(oid) INTO v_def FROM pg_proc WHERE proname='invoice_notify_accountant_trg';
  IF v_def NOT LIKE '%''accountant''%' OR v_def NOT LIKE '%''accountant_action''%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: invoice_notify_accountant_trg invariants (v3.74.430)';
  END IF;
END;
$function$
;

