;

-- ---------------------------------------------------------------
-- assert_baseline_v3_74_443_check()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assert_baseline_v3_74_443_check()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_def text;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname='reactivate_company_subscription') THEN
    RAISE EXCEPTION 'BASELINE FAIL: reactivate_company_subscription missing (v3.74.443)';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname='company_seat_license_auto_reactivate_trg') THEN
    RAISE EXCEPTION 'BASELINE FAIL: company_seat_license_auto_reactivate_trg missing (v3.74.443)';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname='company_seat_license_auto_reactivate' AND NOT tgisinternal) THEN
    RAISE EXCEPTION 'BASELINE FAIL: company_seat_license_auto_reactivate trigger missing (v3.74.443)';
  END IF;
  -- The RPC body must reactivate + notify
  SELECT pg_get_functiondef(oid) INTO v_def FROM pg_proc WHERE proname='reactivate_company_subscription';
  IF v_def NOT LIKE '%no_active_seats%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: reactivate_company_subscription must check for active seats (v3.74.443)';
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
