-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assert_baseline_v3_74_444_check()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_table text; v_def text;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname='can_write_to_company') THEN
    RAISE EXCEPTION 'BASELINE FAIL: can_write_to_company missing (v3.74.444)';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname='subscription_write_gate_trg') THEN
    RAISE EXCEPTION 'BASELINE FAIL: subscription_write_gate_trg missing (v3.74.444)';
  END IF;
  SELECT pg_get_functiondef(oid) INTO v_def FROM pg_proc WHERE proname='can_write_to_company';
  IF v_def NOT LIKE '%''payment_failed''%' OR v_def NOT LIKE '%''cancelled''%' THEN
    RAISE EXCEPTION 'BASELINE FAIL: can_write_to_company must gate payment_failed and cancelled (v3.74.444)';
  END IF;
  FOR v_table IN SELECT unnest(ARRAY[
        'purchase_orders','sales_orders','bills','invoices','payments',
        'purchase_returns','sales_returns',
        'manufacturing_production_orders','manufacturing_bom_versions',
        'manufacturing_routing_versions','manufacturing_material_issue_approvals',
        'manufacturing_product_receive_approvals'])
  LOOP
    IF NOT EXISTS (
      SELECT 1 FROM pg_trigger t JOIN pg_class c ON c.oid = t.tgrelid
       WHERE c.relname = v_table AND t.tgname = 'subscription_write_gate' AND NOT t.tgisinternal
    ) THEN
      RAISE EXCEPTION 'BASELINE FAIL: subscription_write_gate trigger missing on % (v3.74.444)', v_table;
    END IF;
  END LOOP;
END;
$function$
;

