-- ---------------------------------------------------------------
-- assert_booking_addons_permission(p_company_id uuid, p_booking_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assert_booking_addons_permission(p_company_id uuid, p_booking_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_role text;
  v_member_branch uuid;
  v_booking public.bookings;
BEGIN
  IF v_uid IS NULL THEN RETURN; END IF;

  SELECT cm.role, cm.branch_id INTO v_role, v_member_branch
  FROM public.company_members cm
  WHERE cm.company_id = p_company_id AND cm.user_id = v_uid
  LIMIT 1;

  IF v_role IS NULL THEN
    RAISE EXCEPTION 'ADDONS_FORBIDDEN: لست عضواً فى هذه الشركة';
  END IF;

  IF v_role IN ('owner','admin','general_manager') THEN RETURN; END IF;

  SELECT * INTO v_booking FROM public.bookings b
  WHERE b.id = p_booking_id AND b.company_id = p_company_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'BOOKING_NOT_FOUND'; END IF;

  -- Booking officer: branch scope, and ONLY until execution.
  IF v_role = 'booking_officer'
     AND (v_member_branch IS NULL OR v_member_branch = v_booking.branch_id) THEN
    IF v_booking.status = 'completed' THEN
      RAISE EXCEPTION 'ADDONS_FORBIDDEN: بعد تنفيذ أمر الحجز يقتصر التعديل على الموظف المنفذ (ما دامت الفاتورة مسودة)';
    END IF;
    RETURN;
  END IF;

  -- The assigned executor: before AND after execution (draft window is
  -- enforced by assert_booking_editable_for_bundle).
  IF v_booking.staff_user_id = v_uid
     OR EXISTS (
       SELECT 1 FROM public.booking_staff_assignments bsa
       WHERE bsa.booking_id = p_booking_id AND bsa.user_id = v_uid
     ) THEN
    RETURN;
  END IF;

  RAISE EXCEPTION 'ADDONS_FORBIDDEN: تعديل إضافات الحجز متاح فقط للمالك/الإدارة، مسئول الحجز فى فرعه (قبل التنفيذ)، والموظف المكلف بهذا الحجز';
END;
$function$
;

-- ---------------------------------------------------------------
-- assert_booking_editable_for_bundle(p_booking_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assert_booking_editable_for_bundle(p_booking_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE v_status text; v_inv_status text;
BEGIN
  SELECT b.status, i.status INTO v_status, v_inv_status
  FROM public.bookings b
  LEFT JOIN public.invoices i ON i.id = b.invoice_id
  WHERE b.id = p_booking_id;

  IF v_status IS NULL THEN RAISE EXCEPTION 'BOOKING_NOT_FOUND'; END IF;
  IF v_status IN ('cancelled','no_show') THEN
    RAISE EXCEPTION 'BOOKING_LOCKED: cannot modify addons after status=%', v_status;
  END IF;
  IF v_status = 'completed' AND v_inv_status IS DISTINCT FROM 'draft' THEN
    RAISE EXCEPTION 'BOOKING_LOCKED: الفاتورة معتمدة — أى تعديل بعد الاعتماد يتم عبر مرتجع المبيعات';
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- assert_journal_entries_balanced_v2(p_journal_entries jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assert_journal_entries_balanced_v2(p_journal_entries jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_je            JSONB;
  v_line          JSONB;
  v_debit_total   NUMERIC;
  v_credit_total  NUMERIC;
  v_reference     TEXT;
BEGIN
  IF p_journal_entries IS NULL OR jsonb_typeof(p_journal_entries) <> 'array' OR jsonb_array_length(p_journal_entries) = 0 THEN
    RETURN;
  END IF;

  FOR v_je IN SELECT * FROM jsonb_array_elements(p_journal_entries)
  LOOP
    v_debit_total := 0;
    v_credit_total := 0;
    v_reference := COALESCE(v_je->>'reference_type', 'unknown') || ':' || COALESCE(v_je->>'reference_id', 'unknown');

    IF v_je->'lines' IS NULL OR jsonb_typeof(v_je->'lines') <> 'array' OR jsonb_array_length(v_je->'lines') = 0 THEN
      RAISE EXCEPTION 'UNBALANCED_JOURNAL_PAYLOAD: Journal payload [%] has no lines', v_reference
        USING ERRCODE = 'P0001';
    END IF;

    FOR v_line IN SELECT * FROM jsonb_array_elements(v_je->'lines')
    LOOP
      v_debit_total := v_debit_total + COALESCE((v_line->>'debit_amount')::NUMERIC, 0);
      v_credit_total := v_credit_total + COALESCE((v_line->>'credit_amount')::NUMERIC, 0);
    END LOOP;

    IF ABS(v_debit_total - v_credit_total) > 0.01 THEN
      RAISE EXCEPTION
        'UNBALANCED_JOURNAL_PAYLOAD: Journal [%] is not balanced. Debit=% Credit=%',
        v_reference, v_debit_total, v_credit_total
        USING ERRCODE = 'P0001';
    END IF;
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- assign_default_member_branch()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assign_default_member_branch()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ DECLARE v_main_branch_id UUID; v_main_cost_center_id UUID; v_main_warehouse_id UUID; BEGIN IF NEW.branch_id IS NULL THEN SELECT id INTO v_main_branch_id FROM branches WHERE company_id = NEW.company_id AND is_main = true LIMIT 1; NEW.branch_id := v_main_branch_id; END IF; IF NEW.cost_center_id IS NULL AND NEW.branch_id IS NOT NULL THEN SELECT id INTO v_main_cost_center_id FROM cost_centers WHERE branch_id = NEW.branch_id AND is_main = true LIMIT 1; IF v_main_cost_center_id IS NULL THEN SELECT id INTO v_main_cost_center_id FROM cost_centers WHERE branch_id = NEW.branch_id LIMIT 1; END IF; NEW.cost_center_id := v_main_cost_center_id; END IF; IF NEW.warehouse_id IS NULL AND NEW.branch_id IS NOT NULL THEN SELECT id INTO v_main_warehouse_id FROM warehouses WHERE branch_id = NEW.branch_id AND is_main = true LIMIT 1; IF v_main_warehouse_id IS NULL THEN SELECT id INTO v_main_warehouse_id FROM warehouses WHERE branch_id = NEW.branch_id LIMIT 1; END IF; NEW.warehouse_id := v_main_warehouse_id; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- assign_next_seat_number(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.assign_next_seat_number(p_company_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_seat_number int;
  v_license_count int;
BEGIN
  SELECT COUNT(*) INTO v_license_count
    FROM public.company_seat_licenses WHERE company_id = p_company_id;

  IF v_license_count > 0 THEN
    SELECT csl.seat_number INTO v_seat_number
      FROM public.company_seat_licenses csl
     WHERE csl.company_id = p_company_id
       AND csl.assigned_user_id IS NULL
       AND csl.expires_at > NOW()
       AND NOT EXISTS (
         SELECT 1 FROM public.company_invitations ci
          WHERE ci.company_id = p_company_id
            AND ci.seat_number = csl.seat_number
            AND ci.accepted = false
            AND COALESCE(ci.status, 'pending') = 'pending'
       )
     ORDER BY csl.seat_number LIMIT 1;
    IF v_seat_number IS NOT NULL THEN RETURN v_seat_number; END IF;
  END IF;

  SELECT COALESCE(MAX(seat_number), 0) + 1 INTO v_seat_number
    FROM company_members WHERE company_id = p_company_id;
  RETURN v_seat_number;
END;
$function$
;

-- ---------------------------------------------------------------
-- audit_customer_changes()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.audit_customer_changes()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company_id UUID;
  v_user_id UUID;
  v_old_data JSONB;
  v_new_data JSONB;
  v_has_non_address_changes BOOLEAN := FALSE;
BEGIN
  v_user_id := auth.uid();
  v_company_id := NEW.company_id;

  -- التحقق من وجود تغييرات في حقول غير العنوان
  IF (
    OLD.name IS DISTINCT FROM NEW.name OR
    OLD.email IS DISTINCT FROM NEW.email OR
    OLD.phone IS DISTINCT FROM NEW.phone OR
    OLD.tax_id IS DISTINCT FROM NEW.tax_id OR
    OLD.credit_limit IS DISTINCT FROM NEW.credit_limit OR
    OLD.payment_terms IS DISTINCT FROM NEW.payment_terms OR
    OLD.is_active IS DISTINCT FROM NEW.is_active
  ) THEN
    v_has_non_address_changes := TRUE;
  END IF;

  -- تسجيل فقط إذا كانت هناك تغييرات في حقول غير العنوان
  IF v_has_non_address_changes THEN
    v_old_data := jsonb_build_object(
      'name', OLD.name,
      'email', OLD.email,
      'phone', OLD.phone,
      'tax_id', OLD.tax_id,
      'credit_limit', OLD.credit_limit,
      'payment_terms', OLD.payment_terms,
      'is_active', OLD.is_active
    );

    v_new_data := jsonb_build_object(
      'name', NEW.name,
      'email', NEW.email,
      'phone', NEW.phone,
      'tax_id', NEW.tax_id,
      'credit_limit', NEW.credit_limit,
      'payment_terms', NEW.payment_terms,
      'is_active', NEW.is_active
    );

    -- تسجيل في audit_logs
    PERFORM create_audit_log(
      v_company_id,
      v_user_id,
      'UPDATE',
      'customers',
      NEW.id,
      'customer_' || COALESCE(NEW.name, NEW.id::TEXT) || ' - تعديل بيانات',
      v_old_data,
      v_new_data
    );
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- audit_journal_entries_integrity()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.audit_journal_entries_integrity()
 RETURNS TABLE(issue_type text, journal_entry_id uuid, reference_type text, description text, severity text)
 LANGUAGE plpgsql
AS $function$ BEGIN RETURN QUERY SELECT 'UNBALANCED_ENTRY'::TEXT, je.id, je.reference_type, 'المدين: ' || COALESCE(SUM(jel.debit_amount), 0)::TEXT || ' - الدائن: ' || COALESCE(SUM(jel.credit_amount), 0)::TEXT, 'CRITICAL'::TEXT FROM journal_entries je LEFT JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id GROUP BY je.id, je.reference_type HAVING ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) > 0.01; RETURN QUERY SELECT 'EMPTY_ENTRY'::TEXT, je.id, je.reference_type, je.description, 'WARNING'::TEXT FROM journal_entries je WHERE NOT EXISTS ( SELECT 1 FROM journal_entry_lines jel WHERE jel.journal_entry_id = je.id ); RETURN QUERY SELECT 'RETURN_WITHOUT_ENTRY'::TEXT, sr.id, 'sales_return'::TEXT, 'مرتجع ' || sr.return_number || ' بمبلغ ' || sr.total_amount::TEXT, 'HIGH'::TEXT FROM sales_returns sr WHERE sr.status = 'completed' AND sr.journal_entry_id IS NULL; END; $function$
;

-- ---------------------------------------------------------------
-- audit_journal_entry_lines_func()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.audit_journal_entry_lines_func()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_entry_id UUID; v_company_id UUID;
BEGIN
  IF TG_OP='DELETE' THEN v_entry_id:=OLD.journal_entry_id; ELSE v_entry_id:=NEW.journal_entry_id; END IF;
  SELECT company_id INTO v_company_id FROM public.journal_entries WHERE id=v_entry_id;
  BEGIN
    PERFORM create_audit_log(v_company_id, auth.uid(), TG_OP, 'journal_entry_lines', COALESCE(NEW.id,OLD.id), 'JE:'||v_entry_id::TEXT,
      CASE WHEN TG_OP IN ('UPDATE','DELETE') THEN to_jsonb(OLD) ELSE NULL END,
      CASE WHEN TG_OP IN ('INSERT','UPDATE') THEN to_jsonb(NEW) ELSE NULL END);
  EXCEPTION WHEN OTHERS THEN
    RAISE WARNING 'audit_journal_entry_lines_func failed for entry [%]: %', v_entry_id, SQLERRM;
  END;
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- audit_payment_changes()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.audit_payment_changes()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_action VARCHAR(50);
  v_changed_by UUID := auth.uid();
  v_company_id UUID;
BEGIN
  IF TG_OP = 'INSERT' THEN
    v_action := 'CREATE';
    v_company_id := NEW.company_id;
    INSERT INTO public.payment_audit_logs (payment_id, company_id, action, new_values, changed_by)
    VALUES (NEW.id, v_company_id, v_action, to_jsonb(NEW), v_changed_by);
    RETURN NEW;
    
  ELSIF TG_OP = 'UPDATE' THEN
    IF OLD.status != NEW.status THEN
      IF NEW.status = 'approved' THEN
        v_action := 'APPROVE_FINAL';
      ELSIF NEW.status = 'rejected' THEN
        v_action := 'REJECT';
      ELSIF NEW.status LIKE 'pending_%' THEN
        v_action := 'APPROVE_STAGE';
      ELSE
        v_action := 'STATUS_CHANGE';
      END IF;
    ELSE
      v_action := 'UPDATE';
    END IF;
    
    v_company_id := NEW.company_id;
    
    -- Log full old and new rows. Discarding huge arrays if any, but payments row is flat.
    INSERT INTO public.payment_audit_logs (payment_id, company_id, action, old_values, new_values, changed_by)
    VALUES (NEW.id, v_company_id, v_action, to_jsonb(OLD), to_jsonb(NEW), v_changed_by);
    
    RETURN NEW;
    
  ELSIF TG_OP = 'DELETE' THEN
    v_action := 'DELETE';
    v_company_id := OLD.company_id;
    INSERT INTO public.payment_audit_logs (payment_id, company_id, action, old_values, changed_by)
    VALUES (OLD.id, v_company_id, v_action, to_jsonb(OLD), v_changed_by);
    RETURN OLD;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- audit_payments_without_invoice_entries()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.audit_payments_without_invoice_entries()
 RETURNS TABLE(payment_journal_id uuid, invoice_id uuid, invoice_number text, payment_date date, payment_amount numeric, issue text)
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    je.id as payment_journal_id,
    je.reference_id as invoice_id,
    i.invoice_number,
    je.entry_date as payment_date,
    COALESCE(
      (SELECT SUM(jel.credit_amount) FROM journal_entry_lines jel WHERE jel.journal_entry_id = je.id),
      0
    ) as payment_amount,
    'دفعة بدون قيد فاتورة'::TEXT as issue
  FROM journal_entries je
  LEFT JOIN invoices i ON i.id = je.reference_id
  WHERE je.reference_type = 'invoice_payment'
  AND NOT EXISTS (
    SELECT 1 FROM journal_entries inv_je
    WHERE inv_je.reference_type = 'invoice'
    AND inv_je.reference_id = je.reference_id
    AND inv_je.company_id = je.company_id
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- audit_price_changes()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.audit_price_changes()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company_id UUID;
  v_user_id UUID;
  v_old_data JSONB;
  v_new_data JSONB;
BEGIN
  v_user_id := auth.uid();
  v_company_id := NEW.company_id;

  -- التحقق من تغيير السعر
  IF OLD.unit_price IS DISTINCT FROM NEW.unit_price OR
     OLD.cost_price IS DISTINCT FROM NEW.cost_price THEN
    
    v_old_data := jsonb_build_object(
      'unit_price', OLD.unit_price,
      'cost_price', OLD.cost_price,
      'product_id', OLD.id,
      'product_name', OLD.name
    );

    v_new_data := jsonb_build_object(
      'unit_price', NEW.unit_price,
      'cost_price', NEW.cost_price,
      'product_id', NEW.id,
      'product_name', NEW.name
    );

    -- تسجيل في audit_logs
    PERFORM create_audit_log(
      v_company_id,
      v_user_id,
      'UPDATE',
      'products',
      NEW.id,
      'product_' || NEW.id::TEXT || ' - تغيير سعر',
      v_old_data,
      v_new_data
    );
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- audit_status_changes()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.audit_status_changes()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company_id UUID;
  v_user_id UUID;
  v_old_data JSONB;
  v_new_data JSONB;
  v_record_identifier TEXT;
  v_branch_id UUID;
  v_cost_center_id UUID;
BEGIN
  v_user_id := auth.uid();
  v_company_id := NEW.company_id;
  
  -- Get branch_id and cost_center_id if they exist
  v_branch_id := CASE WHEN TG_TABLE_NAME IN ('invoices', 'bills') THEN NEW.branch_id ELSE NULL END;
  v_cost_center_id := CASE WHEN TG_TABLE_NAME IN ('invoices', 'bills') THEN NEW.cost_center_id ELSE NULL END;

  IF OLD.status IS DISTINCT FROM NEW.status THEN
    
    IF TG_TABLE_NAME = 'invoices' THEN
      v_record_identifier := 'invoice_' || COALESCE(NEW.invoice_number, NEW.id::TEXT);
    ELSIF TG_TABLE_NAME = 'bills' THEN
      v_record_identifier := 'bill_' || COALESCE(NEW.bill_number, NEW.id::TEXT);
    ELSIF TG_TABLE_NAME = 'purchase_orders' THEN
      v_record_identifier := 'po_' || COALESCE(NEW.po_number, NEW.id::TEXT);
    ELSE
      v_record_identifier := TG_TABLE_NAME || '_' || NEW.id::TEXT;
    END IF;

    v_old_data := jsonb_build_object('status', OLD.status, 'id', OLD.id);
    v_new_data := jsonb_build_object('status', NEW.status, 'id', NEW.id);

    -- Call 10-parameter version
    PERFORM create_audit_log(
      v_company_id,
      v_user_id,
      'UPDATE'::text,
      TG_TABLE_NAME::text,
      NEW.id,
      v_record_identifier || ' - تغيير حالة: ' || OLD.status || ' → ' || NEW.status,
      v_old_data,
      v_new_data,
      v_branch_id,
      v_cost_center_id
    );
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- audit_trigger_function()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.audit_trigger_function()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company_id UUID;
  v_record_id UUID;
  v_record_identifier TEXT;
  v_old_data JSONB;
  v_new_data JSONB;
  v_user_id UUID;
  v_branch_id UUID;
  v_cost_center_id UUID;
BEGIN
  v_user_id := auth.uid();

  IF TG_OP = 'DELETE' THEN
    v_company_id := OLD.company_id;
    v_record_id := OLD.id;
    v_branch_id := CASE WHEN TG_TABLE_NAME IN ('invoices', 'bills', 'payments', 'journal_entries', 'sales_orders', 'purchase_orders', 'customers', 'inventory_transactions') 
                        THEN OLD.branch_id ELSE NULL END;
    v_cost_center_id := CASE WHEN TG_TABLE_NAME IN ('invoices', 'bills', 'payments', 'journal_entries', 'sales_orders', 'purchase_orders', 'customers', 'inventory_transactions') 
                             THEN OLD.cost_center_id ELSE NULL END;
  ELSE
    v_company_id := NEW.company_id;
    v_record_id := NEW.id;
    v_branch_id := CASE WHEN TG_TABLE_NAME IN ('invoices', 'bills', 'payments', 'journal_entries', 'sales_orders', 'purchase_orders', 'customers', 'inventory_transactions') 
                        THEN NEW.branch_id ELSE NULL END;
    v_cost_center_id := CASE WHEN TG_TABLE_NAME IN ('invoices', 'bills', 'payments', 'journal_entries', 'sales_orders', 'purchase_orders', 'customers', 'inventory_transactions') 
                             THEN NEW.cost_center_id ELSE NULL END;
  END IF;

  v_record_identifier := TG_TABLE_NAME || '_' || COALESCE(v_record_id::TEXT, 'unknown');

  IF TG_OP = 'DELETE' THEN
    v_old_data := to_jsonb(OLD);
    v_new_data := NULL;
  ELSIF TG_OP = 'INSERT' THEN
    v_old_data := NULL;
    v_new_data := to_jsonb(NEW);
  ELSE
    v_old_data := to_jsonb(OLD);
    v_new_data := to_jsonb(NEW);
  END IF;

  PERFORM create_audit_log(
    v_company_id,
    v_user_id,
    TG_OP,
    TG_TABLE_NAME,
    v_record_id,
    v_record_identifier,
    v_old_data,
    v_new_data,
    v_branch_id,
    v_cost_center_id
  );

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
EXCEPTION
  WHEN OTHERS THEN
    RAISE WARNING 'Audit log failed: %', SQLERRM;
    IF TG_OP = 'DELETE' THEN
      RETURN OLD;
    ELSE
      RETURN NEW;
    END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_approve_service_only_invoice_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_approve_service_only_invoice_trg()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_goods_lines integer;
BEGIN
  -- Only touch when we still have a pending dispatch — once approved
  -- or explicitly rejected, leave alone.
  IF COALESCE(NEW.warehouse_status, '') <> 'pending' THEN RETURN NEW; END IF;

  SELECT COUNT(*) INTO v_goods_lines
    FROM public.invoice_items
   WHERE invoice_id = NEW.id
     AND COALESCE(item_type, 'product') NOT IN ('service');

  IF v_goods_lines = 0 THEN
    UPDATE public.invoices
       SET warehouse_status = 'approved',
           updated_at = NOW()
     WHERE id = NEW.id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_create_bill_inventory_transaction()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_create_bill_inventory_transaction()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_bill_status TEXT;
  v_receipt_status TEXT;
  v_company_id UUID;
  v_journal_entry_id UUID;
  v_branch_id UUID;
  v_warehouse_id UUID;
  v_cost_center_id UUID;
BEGIN
  -- Get bill status, receipt_status, and company
  SELECT status, receipt_status, company_id, branch_id, warehouse_id, cost_center_id 
  INTO v_bill_status, v_receipt_status, v_company_id, v_branch_id, v_warehouse_id, v_cost_center_id
  FROM bills
  WHERE id = NEW.bill_id;
  
  -- ✅ Only create transaction if bill is received or paid AND not rejected
  IF v_bill_status NOT IN ('received', 'paid') THEN
    RETURN NEW;
  END IF;
  
  -- ✅ Do not create inventory transactions for rejected bills
  IF v_receipt_status = 'rejected' THEN
    RETURN NEW;
  END IF;
  
  -- Get journal entry for this bill
  SELECT id INTO v_journal_entry_id
  FROM journal_entries
  WHERE reference_type = 'bill'
    AND reference_id = NEW.bill_id
    AND is_deleted = false
  LIMIT 1;
  
  -- Create inventory transaction if it doesn't exist
  -- ✅ استخدام reference_id بدلاً من bill_id
  IF NOT EXISTS (
    SELECT 1 FROM inventory_transactions
    WHERE reference_id = NEW.bill_id
      AND product_id = NEW.product_id
      AND transaction_type = 'purchase'
  ) THEN
    INSERT INTO inventory_transactions (
      company_id,
      branch_id,
      warehouse_id,
      cost_center_id,
      product_id,
      transaction_type,
      quantity_change,
      reference_id,
      journal_entry_id,
      notes
    ) VALUES (
      v_company_id,
      v_branch_id,
      v_warehouse_id,
      v_cost_center_id,
      NEW.product_id,
      'purchase',
      NEW.quantity,
      NEW.bill_id,
      v_journal_entry_id,
      'Auto-created from bill_item'
    );
    
    RAISE NOTICE 'Auto-created inventory transaction for bill_item %', NEW.id;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_create_cogs_journal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_create_cogs_journal()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company_id UUID;
  v_product_cost NUMERIC;
  v_cogs_amount NUMERIC;
  v_inventory_account_id UUID;
  v_cogs_account_id UUID;
  v_journal_entry_id UUID;
  v_invoice_number TEXT;
  v_invoice_date DATE;
  v_product_item_type TEXT;
BEGIN
  IF NEW.transaction_type != 'sale' THEN RETURN NEW; END IF;

  SELECT item_type INTO v_product_item_type FROM products WHERE id = NEW.product_id;
  IF v_product_item_type = 'service' THEN RETURN NEW; END IF;

  SELECT company_id INTO v_company_id FROM products WHERE id = NEW.product_id;
  SELECT cost_price INTO v_product_cost FROM products WHERE id = NEW.product_id;
  
  v_cogs_amount := ABS(NEW.quantity_change) * COALESCE(v_product_cost, 0);
  IF v_cogs_amount = 0 THEN RETURN NEW; END IF;

  SELECT coa.id INTO v_inventory_account_id FROM chart_of_accounts coa
  WHERE coa.company_id = v_company_id AND coa.sub_type = 'inventory' 
  AND (coa.parent_id IS NOT NULL OR coa.level > 1) LIMIT 1;

  SELECT coa.id INTO v_cogs_account_id FROM chart_of_accounts coa
  WHERE coa.company_id = v_company_id 
  AND (coa.sub_type = 'cost_of_goods_sold' OR coa.sub_type = 'cogs' OR coa.account_code = '5000')
  AND (coa.parent_id IS NOT NULL OR coa.level > 1) LIMIT 1;

  IF v_inventory_account_id IS NULL OR v_cogs_account_id IS NULL THEN RETURN NEW; END IF;

  SELECT invoice_number, invoice_date INTO v_invoice_number, v_invoice_date
  FROM invoices WHERE id = NEW.reference_id;

  INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description, branch_id, cost_center_id) 
  VALUES (v_company_id, 'invoice_cogs', NEW.reference_id, COALESCE(v_invoice_date, CURRENT_DATE),
  'COGS - ' || COALESCE(v_invoice_number, 'Invoice'), NEW.branch_id, NEW.cost_center_id) 
  RETURNING id INTO v_journal_entry_id;

  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
  (v_journal_entry_id, v_cogs_account_id, v_cogs_amount, 0, 'COGS'),
  (v_journal_entry_id, v_inventory_account_id, 0, v_cogs_amount, 'Inventory');

  NEW.journal_entry_id := v_journal_entry_id;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_create_cogs_on_invoice_status_change()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_create_cogs_on_invoice_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ BEGIN IF (OLD.status IN ('draft', 'pending') AND NEW.status IN ('sent', 'paid')) THEN PERFORM create_cogs_journal_for_invoice(NEW.id); END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- auto_create_company_defaults()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_create_company_defaults()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  INSERT INTO company_dashboard_alert_limits (company_id, branch_id, min_daily_cash, max_daily_expense)
  VALUES (NEW.id, NULL, NULL, NULL)
  ON CONFLICT DO NOTHING;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_create_credit_from_invoice_overpay()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_create_credit_from_invoice_overpay()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_overpay         numeric;
  v_credit_number   text;
  v_ar_account_id   uuid;
  v_cc_account_id   uuid;
  v_journal_id      uuid;
  v_existing_credit_id uuid;
BEGIN
  v_overpay := COALESCE(NEW.paid_amount, 0) - COALESCE(NEW.total_amount, 0);

  IF v_overpay <= 0.01
     OR NEW.customer_id IS NULL
     OR NEW.status IN ('cancelled', 'draft')
     OR COALESCE(NEW.returned_amount, 0) > 0.01 THEN
    RETURN NEW;
  END IF;

  SELECT id INTO v_existing_credit_id
  FROM public.customer_credits
  WHERE company_id = NEW.company_id
    AND customer_id = NEW.customer_id
    AND reference_type = 'invoice_overpayment'
    AND reference_id   = NEW.id;

  IF v_existing_credit_id IS NOT NULL THEN
    UPDATE public.customer_credits
    SET amount = v_overpay,
        notes = format('فائض دَفعَة على الفاتورة %s (تَحديث) — overpay=%s',
                       COALESCE(NEW.invoice_number, NEW.id::text), v_overpay),
        updated_at = NOW()
    WHERE id = v_existing_credit_id
      AND status = 'active'
      AND COALESCE(used_amount, 0) + COALESCE(applied_amount, 0) <= 0.01;
    RETURN NEW;
  END IF;

  -- Resolve accounts.
  SELECT id INTO v_ar_account_id
  FROM chart_of_accounts
  WHERE company_id = NEW.company_id AND is_active = true
    AND (sub_type = 'accounts_receivable'
         OR account_code = '1130'
         OR account_name ILIKE '%receivable%'
         OR account_name ILIKE '%الذمم المدينة%')
  ORDER BY CASE WHEN sub_type = 'accounts_receivable' THEN 0 ELSE 1 END LIMIT 1;

  SELECT id INTO v_cc_account_id
  FROM chart_of_accounts
  WHERE company_id = NEW.company_id AND is_active = true
    AND (sub_type IN ('customer_credit', 'customer_advance')
         OR account_code = '2155'
         OR account_name ILIKE '%رصيد العملاء الدائن%'
         OR account_name ILIKE '%customer credit%')
  ORDER BY CASE WHEN sub_type='customer_credit' THEN 0
                WHEN sub_type='customer_advance' THEN 1
                WHEN account_code='2155' THEN 2
                ELSE 3 END LIMIT 1;

  v_credit_number := 'CR-INV-OP-' || extract(epoch from now())::bigint::text;

  -- 1) Insert customer_credits row.
  INSERT INTO public.customer_credits (
    company_id, customer_id, credit_number, credit_date,
    amount, used_amount, applied_amount, status,
    reference_type, reference_id, branch_id, cost_center_id, notes
  ) VALUES (
    NEW.company_id, NEW.customer_id, v_credit_number, CURRENT_DATE,
    v_overpay, 0, 0, 'active',
    'invoice_overpayment', NEW.id, NEW.branch_id, NEW.cost_center_id,
    format('فائض دَفعَة عَلى الفاتورة %s — المَدفوع %s وَالقيمَة %s',
           COALESCE(NEW.invoice_number, NEW.id::text),
           NEW.paid_amount, NEW.total_amount)
  );

  -- 2) Post journal: Dr AR / Cr 2155 — reclassifies surplus from AR to customer-credit liability.
  IF v_ar_account_id IS NOT NULL AND v_cc_account_id IS NOT NULL THEN
    PERFORM set_config('app.allow_direct_post', 'true', true);

    INSERT INTO journal_entries (
      company_id, branch_id, reference_type, reference_id,
      entry_date, description, status
    ) VALUES (
      NEW.company_id, NEW.branch_id,
      'credit_from_overpayment', NEW.id,
      CURRENT_DATE,
      format('رَصيد دائن من فائض على الفاتورة %s — تَصنيف من AR إلى 2155',
             COALESCE(NEW.invoice_number, NEW.id::text)),
      'draft'
    ) RETURNING id INTO v_journal_id;

    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id
    ) VALUES
      (v_journal_id, v_ar_account_id, v_overpay, 0,
       'تَصحيح: تَخفيض AR المُتَجاوَزَة', NEW.branch_id),
      (v_journal_id, v_cc_account_id, 0, v_overpay,
       'فائض دَفعَة → رَصيد عَميل دائن', NEW.branch_id);

    UPDATE journal_entries SET status='posted' WHERE id = v_journal_id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_create_credit_from_overpayment()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_create_credit_from_overpayment()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_unallocated     numeric;
  v_credit_number   text;
  v_ar_account_id   uuid;
  v_cc_account_id   uuid;
  v_journal_id      uuid;
  v_branch_id       uuid;
  v_existing_credit_id uuid;
BEGIN
  v_unallocated := COALESCE(NEW.unallocated_amount, 0);

  -- Same eligibility check as before.
  IF v_unallocated <= 0.01
     OR NEW.customer_id IS NULL
     OR COALESCE(NEW.amount, 0) <= 0 THEN
    RETURN NEW;
  END IF;

  -- De-dup: if a customer_credits row for this payment already exists,
  -- just update the amount (if untouched) and return. Don't post duplicate journals.
  SELECT id INTO v_existing_credit_id
  FROM public.customer_credits
  WHERE company_id = NEW.company_id
    AND customer_id = NEW.customer_id
    AND reference_type = 'overpayment'
    AND reference_id   = NEW.id;

  IF v_existing_credit_id IS NOT NULL THEN
    UPDATE public.customer_credits
    SET amount     = v_unallocated,
        notes      = format('فائض دَفعَة (تَحديث): unallocated_amount=%s', v_unallocated),
        updated_at = NOW()
    WHERE id = v_existing_credit_id
      AND status = 'active'
      AND COALESCE(used_amount, 0) + COALESCE(applied_amount, 0) <= 0.01;
    RETURN NEW;
  END IF;

  -- Resolve accounts.
  SELECT id INTO v_ar_account_id
  FROM chart_of_accounts
  WHERE company_id = NEW.company_id AND is_active = true
    AND (sub_type = 'accounts_receivable'
         OR account_name ILIKE '%receivable%'
         OR account_name ILIKE '%الذمم المدينة%'
         OR account_code = '1130')
  ORDER BY CASE WHEN sub_type = 'accounts_receivable' THEN 0 ELSE 1 END
  LIMIT 1;

  SELECT id INTO v_cc_account_id
  FROM chart_of_accounts
  WHERE company_id = NEW.company_id AND is_active = true
    AND (sub_type IN ('customer_credit', 'customer_advance')
         OR account_code = '2155'
         OR account_name ILIKE '%رصيد العملاء الدائن%'
         OR account_name ILIKE '%customer credit%')
  ORDER BY
    CASE WHEN sub_type = 'customer_credit' THEN 0
         WHEN sub_type = 'customer_advance' THEN 1
         WHEN account_code = '2155' THEN 2
         ELSE 3 END
  LIMIT 1;

  v_branch_id := NEW.branch_id;
  v_credit_number := 'CR-OP-' || extract(epoch from now())::bigint::text;

  -- 1) Insert customer_credits row (the v3.74.76 trigger will mirror it into the ledger).
  INSERT INTO public.customer_credits (
    company_id, customer_id, credit_number, credit_date,
    amount, used_amount, applied_amount, status,
    reference_type, reference_id,
    branch_id, cost_center_id, notes
  ) VALUES (
    NEW.company_id, NEW.customer_id, v_credit_number,
    COALESCE(NEW.payment_date::date, CURRENT_DATE),
    v_unallocated, 0, 0, 'active',
    'overpayment', NEW.id,
    v_branch_id, NULL,
    format('رَصيد دائن من فائض دَفعَة #%s', COALESCE(NEW.reference_number, NEW.id::text))
  );

  -- 2) Post the accounting correction: Dr AR / Cr 2155, only if both accounts resolved.
  --    This re-classifies the surplus from AR (which the payment over-credited)
  --    to the customer-credit liability account. Now every report reading from
  --    chart_of_accounts agrees with customer_credits.
  IF v_ar_account_id IS NOT NULL AND v_cc_account_id IS NOT NULL THEN
    PERFORM set_config('app.allow_direct_post', 'true', true);

    INSERT INTO journal_entries (
      company_id, branch_id, reference_type, reference_id,
      entry_date, description, status
    ) VALUES (
      NEW.company_id, v_branch_id,
      'credit_from_overpayment', NEW.id,
      COALESCE(NEW.payment_date::date, CURRENT_DATE),
      format('رَصيد دائن من فائض دَفعَة #%s — تَصنيف من AR إلى 2155',
             COALESCE(NEW.reference_number, NEW.id::text)),
      'draft'
    )
    RETURNING id INTO v_journal_id;

    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id
    ) VALUES
      (v_journal_id, v_ar_account_id, v_unallocated, 0,
       'تَصحيح: تَخفيض الذِّمَم المَدينَة المُتَجاوَزَة', v_branch_id),
      (v_journal_id, v_cc_account_id, 0, v_unallocated,
       'فائض دَفعَة → رَصيد عَميل دائن', v_branch_id);

    UPDATE journal_entries SET status='posted' WHERE id = v_journal_id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_create_payment_journal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_create_payment_journal()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_journal_entry_id UUID;
  v_ar_account_id    UUID;
  v_ap_account_id    UUID;
  v_account_id       UUID;
  v_branch_id        UUID;
  v_pay_ccy          TEXT;
  v_pay_rate         NUMERIC;
  v_pay_orig_amount  NUMERIC;
  v_pay_base_amount  NUMERIC;
  v_pay_rate_id      UUID;
  v_base_ccy         TEXT;
  v_cash_acc_ccy     TEXT;
  v_cash_native      NUMERIC;
  v_cash_rate        NUMERIC;
  v_cash_rate_id     UUID;
BEGIN
  IF NEW.amount < 0 THEN
    RETURN NEW;
  END IF;

  v_branch_id := NULL;
  IF NEW.invoice_id IS NOT NULL THEN
    SELECT branch_id INTO v_branch_id FROM invoices WHERE id = NEW.invoice_id LIMIT 1;
  END IF;
  IF v_branch_id IS NULL AND NEW.bill_id IS NOT NULL THEN
    SELECT branch_id INTO v_branch_id FROM bills WHERE id = NEW.bill_id LIMIT 1;
  END IF;
  IF v_branch_id IS NULL THEN
    SELECT id INTO v_branch_id FROM branches
    WHERE company_id = NEW.company_id AND is_active = TRUE
    ORDER BY is_main DESC NULLS LAST, name LIMIT 1;
  END IF;
  IF v_branch_id IS NULL THEN
    RAISE EXCEPTION 'No branch found for company. Create at least one branch.';
  END IF;

  -- v3.74.219 — Resolve the payment FX context from the row.
  SELECT base_currency INTO v_base_ccy FROM companies WHERE id = NEW.company_id;
  v_base_ccy := UPPER(COALESCE(v_base_ccy, 'EGP'));
  v_pay_ccy := UPPER(COALESCE(NEW.currency_code, v_base_ccy));
  v_pay_rate := COALESCE(NULLIF(NEW.exchange_rate_used, 0), NULLIF(NEW.exchange_rate, 0), 1);
  v_pay_orig_amount := COALESCE(NEW.original_amount,
    CASE WHEN v_pay_ccy = v_base_ccy THEN NEW.amount ELSE NEW.amount / NULLIF(v_pay_rate, 0) END);
  v_pay_base_amount := COALESCE(NEW.base_currency_amount, NEW.amount);
  v_pay_rate_id := NEW.exchange_rate_id;

  IF NEW.invoice_id IS NOT NULL THEN
    SELECT id INTO v_ar_account_id FROM chart_of_accounts
    WHERE company_id = NEW.company_id
      AND (sub_type = 'accounts_receivable' OR account_name ILIKE '%receivable%')
    LIMIT 1;

    v_account_id := COALESCE(NEW.account_id, NULL);
    IF v_account_id IS NULL THEN
      SELECT id INTO v_account_id FROM chart_of_accounts
      WHERE company_id = NEW.company_id AND (sub_type = 'cash' OR sub_type = 'bank')
      LIMIT 1;
    END IF;

    IF v_ar_account_id IS NULL OR v_account_id IS NULL THEN
      RAISE WARNING 'الحسابات المطلوبة غير موجودة للدفعة';
      RETURN NEW;
    END IF;

    -- v3.74.219 — resolve the cash account's native currency so the line
    -- gets stamped with the right original_debit + rate.
    SELECT UPPER(COALESCE(original_currency, v_base_ccy))
      INTO v_cash_acc_ccy FROM chart_of_accounts WHERE id = v_account_id;
    IF v_cash_acc_ccy = v_pay_ccy THEN
      v_cash_native := v_pay_orig_amount;
      v_cash_rate := v_pay_rate;
      v_cash_rate_id := v_pay_rate_id;
    ELSIF v_cash_acc_ccy = v_base_ccy THEN
      v_cash_native := v_pay_base_amount;
      v_cash_rate := 1;
      v_cash_rate_id := NULL;
    ELSE
      v_cash_native := v_pay_base_amount;  -- best-effort; cross-currency between two non-base currencies is rare
      v_cash_rate := 1;
      v_cash_rate_id := NULL;
    END IF;

    PERFORM set_config('app.allow_direct_post', 'true', true);

    INSERT INTO journal_entries (
      company_id, branch_id, reference_type, reference_id, entry_date, description, status
    ) VALUES (
      NEW.company_id, v_branch_id, 'invoice_payment', NEW.invoice_id, NEW.payment_date, 'دفعة فاتورة', 'draft'
    ) RETURNING id INTO v_journal_entry_id;

    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount, description,
      original_debit, original_credit, original_currency, exchange_rate_used, exchange_rate_id
    ) VALUES
    (v_journal_entry_id, v_account_id, v_pay_base_amount, 0, 'نقد/بنك',
     v_cash_native, 0, v_cash_acc_ccy, v_cash_rate, v_cash_rate_id),
    (v_journal_entry_id, v_ar_account_id, 0, v_pay_base_amount, 'الذمم المدينة',
     0, v_pay_base_amount, v_base_ccy, 1, NULL);

    UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_entry_id;
    UPDATE payments SET journal_entry_id = v_journal_entry_id WHERE id = NEW.id;

    PERFORM set_config('app.allow_direct_post', 'false', true);
  END IF;

  IF NEW.bill_id IS NOT NULL THEN
    SELECT id INTO v_ap_account_id FROM chart_of_accounts
    WHERE company_id = NEW.company_id
      AND (sub_type = 'accounts_payable' OR account_name ILIKE '%payable%')
    LIMIT 1;

    v_account_id := COALESCE(NEW.account_id, NULL);
    IF v_account_id IS NULL THEN
      SELECT id INTO v_account_id FROM chart_of_accounts
      WHERE company_id = NEW.company_id AND (sub_type = 'cash' OR sub_type = 'bank')
      LIMIT 1;
    END IF;
    IF v_ap_account_id IS NULL OR v_account_id IS NULL THEN
      RAISE WARNING 'الحسابات المطلوبة غير موجودة للدفعة';
      RETURN NEW;
    END IF;

    SELECT UPPER(COALESCE(original_currency, v_base_ccy))
      INTO v_cash_acc_ccy FROM chart_of_accounts WHERE id = v_account_id;
    IF v_cash_acc_ccy = v_pay_ccy THEN
      v_cash_native := v_pay_orig_amount;
      v_cash_rate := v_pay_rate;
      v_cash_rate_id := v_pay_rate_id;
    ELSIF v_cash_acc_ccy = v_base_ccy THEN
      v_cash_native := v_pay_base_amount;
      v_cash_rate := 1;
      v_cash_rate_id := NULL;
    ELSE
      v_cash_native := v_pay_base_amount;
      v_cash_rate := 1;
      v_cash_rate_id := NULL;
    END IF;

    PERFORM set_config('app.allow_direct_post', 'true', true);
    INSERT INTO journal_entries (
      company_id, branch_id, reference_type, reference_id, entry_date, description, status
    ) VALUES (
      NEW.company_id, v_branch_id, 'bill_payment', NEW.bill_id, NEW.payment_date, 'دفعة فاتورة شراء', 'draft'
    ) RETURNING id INTO v_journal_entry_id;

    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount, description,
      original_debit, original_credit, original_currency, exchange_rate_used, exchange_rate_id
    ) VALUES
    (v_journal_entry_id, v_ap_account_id, v_pay_base_amount, 0, 'الذمم الدائنة',
     v_pay_base_amount, 0, v_base_ccy, 1, NULL),
    (v_journal_entry_id, v_account_id, 0, v_pay_base_amount, 'نقد/بنك',
     0, v_cash_native, v_cash_acc_ccy, v_cash_rate, v_cash_rate_id);

    UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_entry_id;
    UPDATE payments SET journal_entry_id = v_journal_entry_id WHERE id = NEW.id;
    PERFORM set_config('app.allow_direct_post', 'false', true);
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  PERFORM set_config('app.allow_direct_post', 'false', true);
  RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_generate_bill_number()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_generate_bill_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_lock_key BIGINT; v_max_number INTEGER; v_number TEXT; BEGIN IF NEW.bill_number IS NULL OR NEW.bill_number = '' THEN v_lock_key := hashtext('bill_' || NEW.company_id::TEXT); PERFORM pg_advisory_xact_lock(v_lock_key); SELECT COALESCE(MAX(CAST(SUBSTRING(bill_number FROM 'BILL-([0-9]+)') AS INTEGER)), 0) INTO v_max_number FROM bills WHERE company_id = NEW.company_id AND bill_number ~ '^BILL-[0-9]+$'; v_number := 'BILL-' || LPAD((v_max_number + 1)::TEXT, 4, '0'); NEW.bill_number := v_number; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- auto_generate_entry_number()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_generate_entry_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_lock_key BIGINT; v_max_number INTEGER; v_number TEXT; BEGIN IF NEW.entry_number IS NULL OR NEW.entry_number = '' THEN v_lock_key := hashtext('je_' || NEW.company_id::TEXT); PERFORM pg_advisory_xact_lock(v_lock_key); SELECT COALESCE(MAX(CAST(SUBSTRING(entry_number FROM 'JE-([0-9]+)') AS INTEGER)), 0) INTO v_max_number FROM journal_entries WHERE company_id = NEW.company_id AND entry_number ~ '^JE-[0-9]+$'; v_number := 'JE-' || LPAD((v_max_number + 1)::TEXT, 6, '0'); NEW.entry_number := v_number; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- auto_generate_expense_number()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_generate_expense_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_lock_key BIGINT;
  v_max_number INTEGER;
  v_number TEXT;
BEGIN
  IF NEW.expense_number IS NULL OR NEW.expense_number = '' THEN
    v_lock_key := hashtext(NEW.company_id::TEXT);
    PERFORM pg_advisory_xact_lock(v_lock_key);
    
    SELECT COALESCE(
      MAX(
        CAST(
          SUBSTRING(expense_number FROM 'EXP-([0-9]+)') AS INTEGER
        )
      ),
      0
    ) INTO v_max_number
    FROM expenses
    WHERE company_id = NEW.company_id
      AND expense_number ~ '^EXP-[0-9]+$';
    
    v_number := 'EXP-' || LPAD((v_max_number + 1)::TEXT, 4, '0');
    NEW.expense_number := v_number;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_generate_grn_number()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_generate_grn_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_lock_key BIGINT;
  v_company_prefix TEXT;
  v_next_number INTEGER;
  v_new_number TEXT;
BEGIN
  IF NEW.grn_number IS NULL OR NEW.grn_number = '' THEN
    v_lock_key := hashtext('grn_' || NEW.company_id::TEXT);
    PERFORM pg_advisory_xact_lock(v_lock_key);
    
    SELECT COALESCE(settings->>'grn_prefix', 'GRN-')
    INTO v_company_prefix
    FROM companies
    WHERE id = NEW.company_id;
    
    SELECT COALESCE(MAX(CAST(SUBSTRING(grn_number FROM '[0-9]+$') AS INTEGER)), 0) + 1
    INTO v_next_number
    FROM goods_receipts
    WHERE company_id = NEW.company_id
      AND grn_number ~ ('^' || v_company_prefix || '[0-9]+$');
    
    v_new_number := v_company_prefix || LPAD(v_next_number::TEXT, 6, '0');
    NEW.grn_number := v_new_number;
  END IF;
  RETURN NEW;
END;
$function$
;

