;

-- ---------------------------------------------------------------
-- auto_inventory_for_vendor_credit()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_inventory_for_vendor_credit()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  vc_record RECORD;
BEGIN
  -- Get vendor credit info
  SELECT company_id, journal_entry_id, credit_number, source_purchase_return_id 
  INTO vc_record
  FROM vendor_credits WHERE id = NEW.vendor_credit_id;

  -- Skip if linked to purchase return — inventory transactions are already created
  -- by confirm_warehouse_allocation to avoid duplicates and missing branch_id issues
  IF vc_record.source_purchase_return_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Create inventory transaction (return to supplier = negative quantity)
  IF NEW.product_id IS NOT NULL AND vc_record.journal_entry_id IS NOT NULL THEN
    INSERT INTO inventory_transactions (
      company_id, product_id, transaction_type, quantity_change,
      reference_id, journal_entry_id, notes
    ) VALUES (
      vc_record.company_id, NEW.product_id, 'purchase_return',
      -NEW.quantity, NEW.vendor_credit_id, vc_record.journal_entry_id,
      'مرتجع مشتريات - إشعار دائن ' || vc_record.credit_number
    );
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_journal_for_vendor_credit()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_journal_for_vendor_credit()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  ap_account UUID;
  inventory_account UUID;
  vat_account UUID;
  je_id UUID;
BEGIN
  -- Skip if journal already linked
  IF NEW.journal_entry_id IS NOT NULL THEN
    RETURN NEW;
  END IF;
  
  -- Find AP account
  SELECT id INTO ap_account FROM chart_of_accounts 
  WHERE company_id = NEW.company_id 
    AND (sub_type = 'accounts_payable' OR account_name ILIKE '%payable%' OR account_name LIKE '%دائن%')
  LIMIT 1;
  
  -- Find Inventory account
  SELECT id INTO inventory_account FROM chart_of_accounts 
  WHERE company_id = NEW.company_id 
    AND (sub_type = 'inventory' OR account_name ILIKE '%inventory%' OR account_name LIKE '%مخزون%')
  LIMIT 1;
  
  IF ap_account IS NULL OR inventory_account IS NULL THEN
    RETURN NEW;
  END IF;
  
  -- Find VAT account (optional)
  SELECT id INTO vat_account FROM chart_of_accounts
  WHERE company_id = NEW.company_id
    AND (sub_type = 'vat_input' OR account_name ILIKE '%vat%' OR account_name LIKE '%ضريب%')
  LIMIT 1;

  -- Create journal entry for vendor credit
  INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description)
  VALUES (NEW.company_id, 'vendor_credit', NEW.id, NEW.credit_date,
    'إشعار دائن مورد رقم ' || NEW.credit_number)
  RETURNING id INTO je_id;

  -- Debit: Accounts Payable (reduce liability)
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
  VALUES (je_id, ap_account, NEW.subtotal + COALESCE(NEW.tax_amount, 0), 0, 'تخفيض ذمم دائنة');

  -- Credit: Inventory (reduce inventory value)
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
  VALUES (je_id, inventory_account, 0, NEW.subtotal, 'مردودات مشتريات');

  -- Credit: VAT (if applicable)
  IF vat_account IS NOT NULL AND NEW.tax_amount > 0 THEN
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
    VALUES (je_id, vat_account, 0, NEW.tax_amount, 'تعديل ضريبة المشتريات');
  END IF;

  -- Link journal entry to vendor credit
  NEW.journal_entry_id := je_id;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_link_inventory_to_journal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_link_inventory_to_journal()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  je_id UUID;
BEGIN
  -- If journal_entry_id already provided, keep it
  IF NEW.journal_entry_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Ensure we have a reference_id to match
  IF NEW.reference_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Resolve journal entry based on transaction_type
  IF NEW.transaction_type = 'sale' THEN
    SELECT id INTO je_id FROM journal_entries
    WHERE company_id = NEW.company_id AND reference_type = 'invoice_cogs' AND reference_id = NEW.reference_id
    LIMIT 1;
  ELSIF NEW.transaction_type = 'sale_reversal' THEN
    SELECT id INTO je_id FROM journal_entries
    WHERE company_id = NEW.company_id AND reference_type = 'invoice_cogs_reversal' AND reference_id = NEW.reference_id
    LIMIT 1;
  ELSIF NEW.transaction_type = 'purchase' THEN
    SELECT id INTO je_id FROM journal_entries
    WHERE company_id = NEW.company_id AND reference_type = 'bill' AND reference_id = NEW.reference_id
    LIMIT 1;
  ELSIF NEW.transaction_type = 'purchase_reversal' THEN
    SELECT id INTO je_id FROM journal_entries
    WHERE company_id = NEW.company_id AND reference_type = 'bill_reversal' AND reference_id = NEW.reference_id
    LIMIT 1;
  ELSE
    je_id := NULL;
  END IF;

  IF je_id IS NOT NULL THEN
    NEW.journal_entry_id := je_id;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_link_payment_to_journal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_link_payment_to_journal()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  je_id UUID;
BEGIN
  IF NEW.journal_entry_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Invoice payment
  IF NEW.invoice_id IS NOT NULL THEN
    SELECT id INTO je_id FROM public.journal_entries
    WHERE company_id = NEW.company_id AND reference_type = 'invoice_payment' AND reference_id = NEW.invoice_id
    LIMIT 1;

  -- Bill payment
  ELSIF NEW.bill_id IS NOT NULL THEN
    SELECT id INTO je_id FROM public.journal_entries
    WHERE company_id = NEW.company_id AND reference_type = 'bill_payment' AND reference_id = NEW.bill_id
    LIMIT 1;

  -- General customer payment (no invoice)
  ELSIF NEW.customer_id IS NOT NULL AND NEW.invoice_id IS NULL THEN
    SELECT id INTO je_id FROM public.journal_entries
    WHERE company_id = NEW.company_id AND reference_type = 'customer_payment' AND reference_id = NEW.customer_id
    ORDER BY entry_date DESC
    LIMIT 1;

  -- General supplier payment (no bill)
  ELSIF NEW.supplier_id IS NOT NULL AND NEW.bill_id IS NULL THEN
    SELECT id INTO je_id FROM public.journal_entries
    WHERE company_id = NEW.company_id AND reference_type = 'supplier_payment' AND reference_id = NEW.supplier_id
    ORDER BY entry_date DESC
    LIMIT 1;

  -- Internal transfer (bank/cash transfer)
  ELSIF COALESCE(LOWER(NEW.payment_method),'') IN ('bank_transfer','internal_transfer') THEN
    IF NEW.reference_number IS NOT NULL THEN
      SELECT id INTO je_id FROM public.journal_entries
      WHERE company_id = NEW.company_id AND reference_type = 'internal_transfer' AND description ILIKE '%'||NEW.reference_number||'%'
      ORDER BY entry_date DESC
      LIMIT 1;
    END IF;

    IF je_id IS NULL THEN
      SELECT id INTO je_id FROM public.journal_entries
      WHERE company_id = NEW.company_id AND reference_type = 'internal_transfer'
      ORDER BY entry_date DESC
      LIMIT 1;
    END IF;
  ELSE
    je_id := NULL;
  END IF;

  IF je_id IS NOT NULL THEN
    NEW.journal_entry_id := je_id;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_post_monthly_depreciation(p_company_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_post_monthly_depreciation(p_company_id uuid, p_user_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(posted_count integer, total_depreciation numeric, errors text[])
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_schedule RECORD;
  v_posted_count INTEGER := 0;
  v_total_depreciation DECIMAL(15, 2) := 0;
  v_errors TEXT[] := ARRAY[]::TEXT[];
  v_journal_id UUID;
  v_current_month_start DATE;
  v_current_month_end DATE;
BEGIN
  -- تحديد بداية ونهاية الشهر الحالي
  v_current_month_start := DATE_TRUNC('month', CURRENT_DATE)::DATE;
  v_current_month_end := (DATE_TRUNC('month', CURRENT_DATE) + INTERVAL '1 month' - INTERVAL '1 day')::DATE;

  -- جلب جميع فترات الإهلاك المستحقة للشهر الحالي
  FOR v_schedule IN
    SELECT ds.id, ds.asset_id, ds.period_number, ds.period_date,
           ds.depreciation_amount, ds.accumulated_depreciation, ds.book_value,
           fa.company_id, fa.name as asset_name,
           fa.depreciation_expense_account_id,
           fa.accumulated_depreciation_account_id,
           fa.salvage_value
    FROM depreciation_schedules ds
    INNER JOIN fixed_assets fa ON ds.asset_id = fa.id
    WHERE ds.company_id = p_company_id
      AND ds.status = 'approved'  -- فقط الفترات المعتمدة
      AND ds.period_date >= v_current_month_start
      AND ds.period_date <= v_current_month_end
      AND fa.status = 'active'  -- فقط الأصول النشطة
    ORDER BY ds.period_date, ds.period_number
  LOOP
    BEGIN
      -- ترحيل الإهلاك
      SELECT post_depreciation(v_schedule.id, COALESCE(p_user_id, auth.uid())) INTO v_journal_id;
      
      v_posted_count := v_posted_count + 1;
      v_total_depreciation := v_total_depreciation + v_schedule.depreciation_amount;
    EXCEPTION
      WHEN OTHERS THEN
        -- تسجيل الخطأ والمتابعة
        v_errors := array_append(v_errors, 
          format('Error posting schedule %s for asset %s: %s', 
            v_schedule.id, v_schedule.asset_name, SQLERRM));
    END;
  END LOOP;

  RETURN QUERY SELECT v_posted_count, v_total_depreciation, v_errors;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_reverse_cogs_on_sale_return()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_reverse_cogs_on_sale_return()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_company_id           UUID;
  v_product_cost         NUMERIC;
  v_cogs_reversal_amount NUMERIC;
  v_inventory_account_id UUID;
  v_cogs_account_id      UUID;
  v_journal_entry_id     UUID;
  v_product_item_type    TEXT;
  v_existing_reversal    UUID;
  v_branch_id            UUID;
BEGIN
  -- Only for sale_return transactions
  IF NEW.transaction_type != 'sale_return' THEN
    RETURN NEW;
  END IF;

  -- Skip services
  SELECT item_type INTO v_product_item_type
  FROM products WHERE id = NEW.product_id;
  IF v_product_item_type = 'service' THEN
    RETURN NEW;
  END IF;

  -- Get company and cost
  SELECT it.company_id, p.cost_price
  INTO v_company_id, v_product_cost
  FROM inventory_transactions it
  JOIN products p ON p.id = NEW.product_id
  WHERE it.id = NEW.id
  LIMIT 1;

  -- Fallback: get company from warehouse
  IF v_company_id IS NULL THEN
    SELECT w.company_id INTO v_company_id
    FROM warehouses w WHERE w.id = NEW.warehouse_id LIMIT 1;
  END IF;

  IF v_company_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Skip if reversal already exists for this reference
  IF NEW.reference_id IS NOT NULL THEN
    SELECT id INTO v_existing_reversal
    FROM journal_entries
    WHERE company_id = v_company_id
      AND reference_type = 'cogs_return'
      AND reference_id = NEW.reference_id
      AND (is_deleted IS NULL OR is_deleted = false)
    LIMIT 1;
    IF v_existing_reversal IS NOT NULL THEN
      RETURN NEW;
    END IF;
  END IF;

  -- Get accounts
  SELECT id INTO v_inventory_account_id FROM chart_of_accounts
  WHERE company_id = v_company_id AND is_active = true
    AND sub_type = 'inventory' LIMIT 1;

  SELECT id INTO v_cogs_account_id FROM chart_of_accounts
  WHERE company_id = v_company_id AND is_active = true
    AND sub_type IN ('cost_of_goods_sold','cogs') LIMIT 1;

  IF v_inventory_account_id IS NULL OR v_cogs_account_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Calculate COGS reversal amount
  v_cogs_reversal_amount := ABS(COALESCE(NEW.quantity_change, 0)) * COALESCE(v_product_cost, 0);

  IF v_cogs_reversal_amount <= 0 THEN
    RETURN NEW;
  END IF;

  -- Resolve branch
  v_branch_id := COALESCE(NEW.branch_id, NULL);
  IF v_branch_id IS NULL THEN
    SELECT id INTO v_branch_id FROM branches
    WHERE company_id = v_company_id AND is_active = true
    ORDER BY is_main DESC NULLS LAST LIMIT 1;
  END IF;

  PERFORM set_config('app.allow_direct_post', 'true', true);

  BEGIN
    -- ✅ FIX: Create JE as DRAFT first
    INSERT INTO journal_entries (
      company_id, branch_id, reference_type, reference_id,
      entry_date, description, status
    ) VALUES (
      v_company_id, v_branch_id,
      'cogs_return',
      COALESCE(NEW.reference_id, NEW.id),
      COALESCE(NEW.transaction_date, CURRENT_DATE),
      'عكس تكلفة مرتجع مبيعات',
      'draft'   -- ← DRAFT first
    ) RETURNING id INTO v_journal_entry_id;

    -- Add reversal lines:
    -- Line 1: DR Inventory (reversed: inventory comes back)
    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount, description
    ) VALUES (
      v_journal_entry_id, v_inventory_account_id,
      v_cogs_reversal_amount, 0,
      'عكس المخزون - مرتجع'
    );

    -- Line 2: CR COGS (balanced at count=2)
    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount, description
    ) VALUES (
      v_journal_entry_id, v_cogs_account_id,
      0, v_cogs_reversal_amount,
      'عكس تكلفة البضاعة'
    );

    -- ✅ Post the JE
    UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_entry_id;
  EXCEPTION WHEN OTHERS THEN
    PERFORM set_config('app.allow_direct_post', 'false', true);
    RAISE WARNING 'COGS reversal JE failed: %', SQLERRM;
    -- Don't block the inventory transaction
  END;

  PERFORM set_config('app.allow_direct_post', 'false', true);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_set_created_by_user_id()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_set_created_by_user_id()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
BEGIN
  IF NEW.created_by_user_id IS NULL THEN
    NEW.created_by_user_id := auth.uid();
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_set_invoice_branch()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_set_invoice_branch()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.branch_id IS NULL THEN
    -- من أمر البيع المرتبط
    IF NEW.sales_order_id IS NOT NULL THEN
      SELECT branch_id INTO NEW.branch_id
      FROM sales_orders WHERE id = NEW.sales_order_id;
    END IF;
    
    -- من المستخدم المنشئ
    IF NEW.branch_id IS NULL AND NEW.created_by_user_id IS NOT NULL THEN
      SELECT branch_id INTO NEW.branch_id
      FROM company_members
      WHERE user_id = NEW.created_by_user_id 
        AND company_id = NEW.company_id
      LIMIT 1;
    END IF;
    
    -- الفرع الرئيسي كخيار احتياطي
    IF NEW.branch_id IS NULL THEN
      SELECT id INTO NEW.branch_id
      FROM branches
      WHERE company_id = NEW.company_id AND is_main = true
      LIMIT 1;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_set_sales_order_branch()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_set_sales_order_branch()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.branch_id IS NULL THEN
    -- من المستخدم المنشئ
    SELECT branch_id INTO NEW.branch_id
    FROM company_members
    WHERE user_id = NEW.created_by_user_id 
      AND company_id = NEW.company_id
    LIMIT 1;
    
    -- الفرع الرئيسي كخيار احتياطي
    IF NEW.branch_id IS NULL THEN
      SELECT id INTO NEW.branch_id
      FROM branches
      WHERE company_id = NEW.company_id AND is_main = true
      LIMIT 1;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_stamp_lot_expiry()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_stamp_lot_expiry()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE v_days integer;
BEGIN
  IF NEW.expiry_date IS NULL THEN
    SELECT shelf_life_days INTO v_days FROM public.products WHERE id = NEW.product_id;
    IF v_days IS NOT NULL AND v_days > 0 THEN
      NEW.expiry_date := COALESCE(NEW.lot_date, CURRENT_DATE) + v_days;
    END IF;
  END IF;
  -- v3.74.586 — human-writable lot code for the physical carton
  IF NEW.lot_number IS NULL THEN
    NEW.lot_number := public.next_lot_number(NEW.company_id);
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- auto_update_document_status()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.auto_update_document_status()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_TABLE_NAME = 'bills' THEN
    IF NEW.paid_amount >= NEW.total_amount - 0.01 THEN
      NEW.status := 'paid';
    ELSIF NEW.paid_amount > 0 THEN
      NEW.status := 'partially_paid';
    END IF;
  ELSIF TG_TABLE_NAME = 'invoices' THEN
    IF NEW.paid_amount >= NEW.total_amount - 0.01 AND NEW.status NOT IN ('cancelled','fully_returned') THEN
      NEW.status := 'paid';
    ELSIF NEW.paid_amount > 0 AND NEW.status NOT IN ('cancelled','fully_returned') THEN
      NEW.status := 'partially_paid';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- backfill_company_seat_licenses()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.backfill_company_seat_licenses()
 RETURNS TABLE(company_id uuid, seats_created integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  c               RECORD;
  v_total         int;
  v_purchased_at  timestamptz;
  v_expires_at    timestamptz;
  v_billing       text;
  v_invoice_id    uuid;
  v_created       int;
  n               int;
  v_assignee      uuid;
  v_assigned_at   timestamptz;
BEGIN
  FOR c IN
    SELECT
      cmp.id                            AS company_id,
      cmp.current_period_start,
      cmp.current_period_end,
      COALESCE(cs.total_paid_seats, 0)  AS total_paid_seats,
      cs.billing_cycle
    FROM public.companies cmp
    LEFT JOIN public.company_seats cs ON cs.company_id = cmp.id
    WHERE COALESCE(cs.total_paid_seats, 0) > 0
  LOOP
    v_total       := c.total_paid_seats;
    v_expires_at  := COALESCE(c.current_period_end, NOW() + INTERVAL '30 days');
    v_purchased_at := COALESCE(c.current_period_start, v_expires_at - INTERVAL '30 days');
    v_billing     := CASE
                       WHEN c.billing_cycle = 'annual' THEN 'annual'
                       ELSE 'monthly'
                     END;

    SELECT id INTO v_invoice_id
      FROM public.billing_invoices
     WHERE billing_invoices.company_id = c.company_id
       AND status = 'paid'
     ORDER BY created_at DESC
     LIMIT 1;

    v_created := 0;
    FOR n IN 1..v_total LOOP
      IF NOT EXISTS (
        SELECT 1 FROM public.company_seat_licenses
         WHERE company_seat_licenses.company_id = c.company_id
           AND company_seat_licenses.seat_number = n
      ) THEN
        SELECT cm.user_id, cm.created_at
          INTO v_assignee, v_assigned_at
          FROM public.company_members cm
         WHERE cm.company_id = c.company_id
           AND cm.seat_number = n
         LIMIT 1;

        INSERT INTO public.company_seat_licenses (
          company_id, seat_number, billing_period,
          purchased_at, expires_at,
          billing_invoice_id, assigned_user_id, assigned_at
        ) VALUES (
          c.company_id, n, v_billing,
          v_purchased_at, v_expires_at,
          v_invoice_id, v_assignee, v_assigned_at
        );
        v_created := v_created + 1;
      END IF;
    END LOOP;

    RETURN QUERY SELECT c.company_id, v_created;
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- bank_voucher_sod_guard()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bank_voucher_sod_guard()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- reviewer must not be the creator
  IF NEW.reviewed_by IS NOT NULL
     AND NEW.created_by IS NOT NULL
     AND NEW.reviewed_by = NEW.created_by THEN
    RAISE EXCEPTION 'SoD violation: مُعتَمِد السَّنَد لا يَجوز أَن يَكون هو نَفسه مُنشِئ السَّنَد.'
      USING ERRCODE = 'check_violation';
  END IF;
  -- poster must not be the reviewer
  IF NEW.posted_by IS NOT NULL
     AND NEW.reviewed_by IS NOT NULL
     AND NEW.posted_by = NEW.reviewed_by THEN
    RAISE EXCEPTION 'SoD violation: مُنَفِّذ السَّنَد لا يَجوز أَن يَكون هو نَفسه مُعتَمِد السَّنَد.'
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- baseline_report()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.baseline_report()
 RETURNS TABLE(section text, item text, status text, detail text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_approve_def text;
BEGIN
  RETURN QUERY SELECT 'function'::text, fn::text,
    CASE WHEN EXISTS (SELECT 1 FROM pg_proc WHERE proname = fn) THEN 'OK' ELSE 'MISSING' END, NULL::text
    FROM unnest(ARRAY['can_modify_data','can_manage_supplier_row','complete_booking_atomic',
                      'execute_sales_invoice_accounting','check_booking_service_inventory','run_all_integrity_checks']) AS fn;

  RETURN QUERY SELECT 'table'::text, tbl::text,
    CASE WHEN EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name = tbl) THEN 'OK' ELSE 'MISSING' END, NULL::text
    FROM unnest(ARRAY['discount_approvals','company_seat_licenses','service_products']) AS tbl;

  RETURN QUERY SELECT 'trigger'::text, trg::text,
    CASE WHEN EXISTS (SELECT 1 FROM pg_trigger WHERE tgname = trg AND NOT tgisinternal) THEN 'OK' ELSE 'MISSING' END, NULL::text
    FROM unnest(ARRAY['bkg_request_discount_approval','inv_request_discount_approval','inv_block_post_unapproved_discount',
                      'bill_request_discount_approval','bill_block_post_unapproved_discount',
                      'sync_employee_user_id_ins','sync_employee_user_id_upd','sync_employee_user_id_del']) AS trg;

  RETURN QUERY SELECT 'policy'::text, ('suppliers.' || pol)::text,
    CASE WHEN EXISTS (SELECT 1 FROM pg_policies WHERE schemaname='public' AND tablename='suppliers' AND policyname = pol) THEN 'OK' ELSE 'MISSING' END, NULL::text
    FROM unnest(ARRAY['suppliers_insert','suppliers_update','suppliers_delete']) AS pol;

  RETURN QUERY SELECT 'fingerprint'::text, 'can_modify_data references modern roles (v3.74.390)'::text,
    CASE WHEN EXISTS (SELECT 1 FROM pg_proc p WHERE p.proname='can_modify_data'
      AND pg_get_functiondef(p.oid) LIKE '%purchasing_officer%'
      AND pg_get_functiondef(p.oid) LIKE '%general_manager%'
      AND pg_get_functiondef(p.oid) LIKE '%booking_officer%'
      AND pg_get_functiondef(p.oid) LIKE '%manufacturing_officer%'
      AND pg_get_functiondef(p.oid) LIKE '%hr_officer%'
      AND pg_get_functiondef(p.oid) LIKE '%store_manager%')
    THEN 'OK' ELSE 'BROKEN' END, NULL::text;

  RETURN QUERY SELECT 'fingerprint'::text, 'can_manage_supplier_row enforces branch-scope (v3.74.391)'::text,
    CASE WHEN EXISTS (SELECT 1 FROM pg_proc p WHERE p.proname='can_manage_supplier_row'
      AND pg_get_functiondef(p.oid) LIKE '%p_row_branch_id = v_user_branch_id%')
    THEN 'OK' ELSE 'BROKEN' END, NULL::text;

  RETURN QUERY SELECT 'integrity'::text, (c.name || ' / ' || r.check_code)::text,
    CASE r.severity WHEN 'error' THEN 'ERROR' WHEN 'warning' THEN 'WARN' ELSE upper(r.severity) END,
    r.detail::text
    FROM companies c CROSS JOIN LATERAL run_all_integrity_checks(c.id) r WHERE r.severity IN ('error','warning');

  RETURN QUERY SELECT 'inventory_drift'::text, (c.name || ' / ' || pr.name)::text, 'ERROR'::text,
    ('col=' || pr.quantity_on_hand || ' ledger=' || coalesce((SELECT sum(quantity_change) FROM inventory_transactions WHERE product_id = pr.id), 0)::text)::text
    FROM products pr JOIN companies c ON c.id = pr.company_id
   WHERE coalesce(pr.product_type, pr.item_type, 'physical') NOT IN ('service','خدمة')
     AND pr.quantity_on_hand IS DISTINCT FROM coalesce((SELECT sum(quantity_change) FROM inventory_transactions WHERE product_id = pr.id), 0);

  RETURN QUERY SELECT 'tax_column'::text, ('purchase_order_items.tax_code_id')::text,
    CASE WHEN EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='purchase_order_items' AND column_name='tax_code_id')
    THEN 'OK' ELSE 'MISSING' END, NULL::text;

  RETURN QUERY SELECT 'tax_column'::text, ('bill_items.tax_code_id')::text,
    CASE WHEN EXISTS (SELECT 1 FROM information_schema.columns WHERE table_schema='public' AND table_name='bill_items' AND column_name='tax_code_id')
    THEN 'OK' ELSE 'MISSING' END, NULL::text;

  RETURN QUERY SELECT 'tax_mismatch'::text, (tbl || '.' || row_id::text)::text, 'ERROR'::text,
    ('rate=' || tax_rate::text || ' expected=' || expected_rate::text)::text
    FROM (
      SELECT 'purchase_order_items' AS tbl, poi.id AS row_id, poi.tax_rate, tc.rate AS expected_rate
        FROM purchase_order_items poi JOIN tax_codes tc ON tc.id = poi.tax_code_id
       WHERE poi.tax_code_id IS NOT NULL AND coalesce(poi.tax_rate, 0) <> coalesce(tc.rate, 0)
      UNION ALL
      SELECT 'bill_items', bi.id, bi.tax_rate, tc.rate
        FROM bill_items bi JOIN tax_codes tc ON tc.id = bi.tax_code_id
       WHERE bi.tax_code_id IS NOT NULL AND coalesce(bi.tax_rate, 0) <> coalesce(tc.rate, 0)
    ) x;

  -- Section K (v3.74.398)
  SELECT pg_get_functiondef(p.oid) INTO v_approve_def FROM pg_proc p WHERE p.proname='approve_purchase_order_atomic' LIMIT 1;
  RETURN QUERY SELECT 'po_bill_carryover'::text, ('approve_purchase_order_atomic.' || col)::text,
    CASE WHEN v_approve_def IS NULL THEN 'MISSING'
         WHEN v_approve_def LIKE ('%' || col || '%') THEN 'OK'
         ELSE 'BROKEN' END,
    NULL::text
    FROM unnest(ARRAY['shipping_tax_rate','discount_position','tax_inclusive','exchange_rate','tax_code_id']) AS col;
END;
$function$
;

-- ---------------------------------------------------------------
-- batch_mark_notifications_as_read(p_notification_ids uuid[], p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.batch_mark_notifications_as_read(p_notification_ids uuid[], p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- إدراج حالة جديدة أو تحديث الحالة الحالية للمستخدم
  INSERT INTO notification_user_states (notification_id, user_id, status, read_at, updated_at)
  SELECT 
    unnest(p_notification_ids), 
    p_user_id, 
    'read', 
    NOW(), 
    NOW()
  ON CONFLICT (notification_id, user_id)
  DO UPDATE SET 
    status = CASE WHEN notification_user_states.status = 'unread' THEN 'read' ELSE notification_user_states.status END,
    read_at = COALESCE(notification_user_states.read_at, NOW()),
    updated_at = NOW();

  RETURN TRUE;
END;
$function$
;

-- ---------------------------------------------------------------
-- batch_update_notification_status(p_notification_ids uuid[], p_status character varying, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.batch_update_notification_status(p_notification_ids uuid[], p_status character varying, p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- إدراج حالة جديدة أو تحديث الحالة الحالية للمستخدم
  INSERT INTO notification_user_states (notification_id, user_id, status, read_at, actioned_at, updated_at)
  SELECT 
    unnest(p_notification_ids), 
    p_user_id, 
    p_status,
    CASE WHEN p_status IN ('read', 'archived', 'actioned') THEN NOW() ELSE NULL END,
    CASE WHEN p_status = 'actioned' THEN NOW() ELSE NULL END,
    NOW()
  ON CONFLICT (notification_id, user_id)
  DO UPDATE SET 
    status = p_status,
    read_at = CASE WHEN p_status IN ('read', 'archived', 'actioned') THEN COALESCE(notification_user_states.read_at, NOW()) ELSE notification_user_states.read_at END,
    actioned_at = CASE WHEN p_status = 'actioned' THEN COALESCE(notification_user_states.actioned_at, NOW()) ELSE notification_user_states.actioned_at END,
    updated_at = NOW();

  RETURN TRUE;
END;
$function$
;

-- ---------------------------------------------------------------
-- bdl_expand_product_bundle(p_product_id uuid, p_parent_qty numeric, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bdl_expand_product_bundle(p_product_id uuid, p_parent_qty numeric DEFAULT 1, p_company_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_parent_name TEXT; v_result jsonb;
BEGIN
  IF p_parent_qty IS NULL OR p_parent_qty <= 0 THEN p_parent_qty := 1; END IF;
  SELECT name INTO v_parent_name FROM public.products
    WHERE id = p_product_id AND (p_company_id IS NULL OR company_id = p_company_id);
  IF v_parent_name IS NULL THEN RETURN jsonb_build_array(); END IF;
  SELECT COALESCE(jsonb_agg(row ORDER BY display_order, is_optional, child_name), '[]'::jsonb)
    INTO v_result
    FROM (
      SELECT
        b.display_order, b.is_optional, cp.name AS child_name,
        jsonb_build_object(
          'child_product_id', b.child_product_id,
          'parent_product_id', b.parent_product_id,
          'parent_name', v_parent_name,
          'name', cp.name, 'sku', cp.sku,
          'quantity', (b.quantity * p_parent_qty),
          'unit_price', COALESCE(cp.unit_price, 0),
          'effective_unit_price',
            CASE b.price_handling WHEN 'add_to_total' THEN COALESCE(cp.unit_price, 0) ELSE 0 END,
          'cost_price', COALESCE(cp.cost_price, 0),
          'is_optional', b.is_optional,
          'auto_deduct_inventory', b.auto_deduct_inventory,
          'price_handling', b.price_handling,
          'income_account_id', cp.income_account_id,
          'expense_account_id', cp.expense_account_id,
          'display_order', b.display_order,
          'description_hint', cp.name || ' (مرفق مع: ' || v_parent_name || ')'
        ) AS row
      FROM public.product_bundle_items b
      JOIN public.products cp ON cp.id = b.child_product_id
      WHERE b.parent_product_id = p_product_id
        AND (p_company_id IS NULL OR b.company_id = p_company_id)
    ) AS expanded;
  RETURN COALESCE(v_result, '[]'::jsonb);
END;
$function$
;

-- ---------------------------------------------------------------
-- bdl_no_recursion()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bdl_no_recursion()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF EXISTS (
    SELECT 1 FROM public.product_bundle_items
     WHERE child_product_id = NEW.parent_product_id
       AND (TG_OP = 'INSERT' OR id <> NEW.id)
  ) THEN
    RAISE EXCEPTION 'Recursive bundles are not allowed: product % is already a bundle child, it cannot be a parent.',
      NEW.parent_product_id USING ERRCODE='P0001';
  END IF;
  IF EXISTS (
    SELECT 1 FROM public.product_bundle_items
     WHERE parent_product_id = NEW.child_product_id
       AND (TG_OP = 'INSERT' OR id <> NEW.id)
  ) THEN
    RAISE EXCEPTION 'Recursive bundles are not allowed: product % already has its own bundle children, it cannot be a bundle child.',
      NEW.child_product_id USING ERRCODE='P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bdl_set_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bdl_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN NEW.updated_at := NOW(); RETURN NEW; END;
$function$
;

-- ---------------------------------------------------------------
-- bdl_validate_bundle_completeness(p_items jsonb, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bdl_validate_bundle_completeness(p_items jsonb, p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_missing jsonb := '[]'::jsonb;
BEGIN
  IF p_items IS NULL OR jsonb_typeof(p_items) <> 'array' OR jsonb_array_length(p_items) = 0 THEN
    RETURN jsonb_build_object('complete', true, 'missing', '[]'::jsonb);
  END IF;
  WITH item_qty AS (
    SELECT (e->>'product_id')::uuid AS product_id,
           SUM(COALESCE((e->>'quantity')::numeric, 0)) AS qty
    FROM jsonb_array_elements(p_items) e
    WHERE e ? 'product_id'
    GROUP BY (e->>'product_id')::uuid
  ), required AS (
    SELECT b.parent_product_id, pp.name AS parent_name,
           b.child_product_id, cp.name AS child_name,
           (b.quantity * iq.qty) AS required_quantity
    FROM item_qty iq
    JOIN public.product_bundle_items b
      ON b.parent_product_id = iq.product_id
     AND b.company_id        = p_company_id
     AND b.is_optional       = false
    JOIN public.products pp ON pp.id = b.parent_product_id
    JOIN public.products cp ON cp.id = b.child_product_id
  )
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'parent_product_id', r.parent_product_id, 'parent_name', r.parent_name,
    'child_product_id', r.child_product_id, 'child_name', r.child_name,
    'required_quantity', r.required_quantity
  )), '[]'::jsonb)
  INTO v_missing
  FROM required r
  LEFT JOIN item_qty have ON have.product_id = r.child_product_id
  WHERE COALESCE(have.qty, 0) < r.required_quantity;
  RETURN jsonb_build_object(
    'complete', jsonb_array_length(v_missing) = 0,
    'missing', v_missing
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- bdl_validate_company_match()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bdl_validate_company_match()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_parent_company UUID; v_child_company UUID;
BEGIN
  SELECT company_id INTO v_parent_company FROM public.products WHERE id = NEW.parent_product_id;
  SELECT company_id INTO v_child_company  FROM public.products WHERE id = NEW.child_product_id;
  IF v_parent_company IS NULL THEN
    RAISE EXCEPTION 'parent_product_id (%) does not exist', NEW.parent_product_id USING ERRCODE='P0001';
  END IF;
  IF v_child_company IS NULL THEN
    RAISE EXCEPTION 'child_product_id (%) does not exist', NEW.child_product_id USING ERRCODE='P0001';
  END IF;
  IF v_parent_company <> NEW.company_id OR v_child_company <> NEW.company_id THEN
    RAISE EXCEPTION 'Bundle items must all belong to the same company (row=%, parent=%, child=%)',
      NEW.company_id, v_parent_company, v_child_company USING ERRCODE='P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bill_amendment_reset_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bill_amendment_reset_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_material_change boolean := false;
  v_baseline_id uuid; v_baseline_type text;
  v_party_name text; v_requester uuid; v_items_snap jsonb;
BEGIN
  IF NEW.status <> 'draft' AND NEW.status <> 'pending_approval' THEN RETURN NEW; END IF;
  IF COALESCE(current_setting('app.skip_discount_approval', true), '') <> '' THEN RETURN NEW; END IF;

  IF   COALESCE(OLD.shipping, 0)          IS DISTINCT FROM COALESCE(NEW.shipping, 0)
    OR COALESCE(OLD.shipping_tax_rate, 0) IS DISTINCT FROM COALESCE(NEW.shipping_tax_rate, 0)
    OR COALESCE(OLD.adjustment, 0)        IS DISTINCT FROM COALESCE(NEW.adjustment, 0)
    OR COALESCE(OLD.tax_amount, 0)        IS DISTINCT FROM COALESCE(NEW.tax_amount, 0)
    OR COALESCE(OLD.subtotal, 0)          IS DISTINCT FROM COALESCE(NEW.subtotal, 0)
    OR COALESCE(OLD.total_amount, 0)      IS DISTINCT FROM COALESCE(NEW.total_amount, 0)
    OR COALESCE(OLD.currency_code, '')    IS DISTINCT FROM COALESCE(NEW.currency_code, '')
    OR COALESCE(OLD.exchange_rate, 1)     IS DISTINCT FROM COALESCE(NEW.exchange_rate, 1)
    OR COALESCE(OLD.discount_position,'') IS DISTINCT FROM COALESCE(NEW.discount_position,'')
    OR COALESCE(OLD.tax_inclusive, false) IS DISTINCT FROM COALESCE(NEW.tax_inclusive, false)
    OR COALESCE(OLD.discount_value, 0)    IS DISTINCT FROM COALESCE(NEW.discount_value, 0)
    OR COALESCE(OLD.discount_type, '')    IS DISTINCT FROM COALESCE(NEW.discount_type, '')
    OR COALESCE(OLD.supplier_id::text, '')IS DISTINCT FROM COALESCE(NEW.supplier_id::text, '') THEN
    v_material_change := true;
  END IF;
  IF NOT v_material_change THEN RETURN NEW; END IF;

  SELECT id, 'purchase_invoice' INTO v_baseline_id, v_baseline_type
    FROM public.discount_approvals
   WHERE document_type='purchase_invoice' AND document_id=NEW.id
     AND status IN ('approved','pending','rejected')
   ORDER BY requested_at DESC LIMIT 1;
  IF v_baseline_id IS NULL AND NEW.purchase_order_id IS NOT NULL THEN
    SELECT id, 'purchase_order' INTO v_baseline_id, v_baseline_type
      FROM public.discount_approvals
     WHERE document_type='purchase_order' AND document_id=NEW.purchase_order_id
       AND status='approved'
     ORDER BY requested_at DESC LIMIT 1;
  END IF;

  UPDATE public.discount_approvals
     SET status='cancelled',
         decision_note = COALESCE(decision_note,
           'Superseded by material amendment on the purchase invoice.'),
         updated_at = NOW()
   WHERE document_type='purchase_invoice' AND document_id=NEW.id
     AND status IN ('approved','pending');

  BEGIN
    SELECT name INTO v_party_name FROM public.suppliers WHERE id = NEW.supplier_id;
  EXCEPTION WHEN OTHERS THEN v_party_name := NULL; END;
  v_requester := COALESCE(NEW.last_edited_by_user_id, NEW.created_by_user_id, NEW.created_by);

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'product_id', bi.product_id,
    'product_name', COALESCE(p.name, bi.description),
    'description', bi.description,
    'item_type', bi.item_type,
    'quantity', bi.quantity, 'unit_price', bi.unit_price,
    'discount_percent', bi.discount_percent,
    'tax_rate', bi.tax_rate, 'total', bi.line_total
  )), '[]'::jsonb) INTO v_items_snap
    FROM public.bill_items bi
    LEFT JOIN public.products p ON p.id = bi.product_id
   WHERE bi.bill_id = NEW.id;

  IF v_requester IS NOT NULL THEN
    INSERT INTO public.discount_approvals (
      company_id, document_type, document_id, document_no,
      discount_value, discount_type, document_total, party_name,
      reason, status, requested_by, requested_at,
      supersedes_approval_id, items_snapshot,
      shipping_snapshot, adjustment_snapshot,
      tax_amount_snapshot, subtotal_snapshot,
      shipping_tax_rate_snapshot, discount_position_snapshot,
      tax_inclusive_snapshot, supplier_name_snapshot
    ) VALUES (
      NEW.company_id, 'purchase_invoice', NEW.id, NEW.bill_number,
      COALESCE(NEW.discount_value, 0), COALESCE(NEW.discount_type, 'amount'),
      NEW.total_amount, v_party_name,
      'تعديل على الفاتورة يستدعى إعادة اعتماد', 'pending', v_requester, NOW(),
      v_baseline_id, v_items_snap,
      NEW.shipping, NEW.adjustment,
      NEW.tax_amount, NEW.subtotal,
      NEW.shipping_tax_rate, NEW.discount_position,
      NEW.tax_inclusive, v_party_name
    );
    PERFORM set_config('app.amendment_inserted', '1', true);
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bill_block_post_unapproved_discount_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bill_block_post_unapproved_discount_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_approval_state text;
  v_po_disc_status text; v_po_disc_value numeric; v_po_disc_type text;
BEGIN
  IF current_setting('app.skip_discount_approval', true) = 'booking' THEN RETURN NEW; END IF;
  IF COALESCE(OLD.status, '') <> 'draft' THEN RETURN NEW; END IF;
  IF NEW.status NOT IN ('sent', 'approved', 'posted', 'paid', 'partially_paid') THEN RETURN NEW; END IF;
  IF NEW.discount_value IS NULL OR NEW.discount_value <= 0 THEN RETURN NEW; END IF;

  -- v3.74.424 — accept linked PO approval as coverage.
  IF NEW.purchase_order_id IS NOT NULL THEN
    SELECT status, discount_value, discount_type
      INTO v_po_disc_status, v_po_disc_value, v_po_disc_type
      FROM public.discount_approvals
     WHERE document_type = 'purchase_order'
       AND document_id   = NEW.purchase_order_id
     ORDER BY requested_at DESC LIMIT 1;
    IF FOUND AND v_po_disc_status = 'rejected' THEN
      RAISE EXCEPTION 'تم رفض اعتماد خصم أمر الشراء — لا يمكن ترحيل الفاتورة بنفس الخصم.'
        USING ERRCODE = 'P0001';
    END IF;
    IF FOUND
       AND v_po_disc_status = 'approved'
       AND v_po_disc_value  = NEW.discount_value
       AND COALESCE(v_po_disc_type, 'amount') = COALESCE(NEW.discount_type, 'amount') THEN
      RETURN NEW;
    END IF;
  END IF;

  SELECT status INTO v_approval_state
    FROM public.discount_approvals
   WHERE document_type = 'purchase_invoice'
     AND document_id   = NEW.id
     AND discount_value = NEW.discount_value
     AND COALESCE(discount_type, 'amount') = COALESCE(NEW.discount_type, 'amount')
   ORDER BY requested_at DESC LIMIT 1;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'الخصم المطبق على فاتورة المورد يتطلب اعتماد المالك / المدير العام قبل الترحيل. اطلب الاعتماد من صندوق الموافقات.'
      USING ERRCODE = 'P0001';
  END IF;
  IF v_approval_state <> 'approved' THEN
    RAISE EXCEPTION 'الخصم على فاتورة المورد منتظر اعتماد الإدارة (الحالة الحالية: %). لا يمكن ترحيل الفاتورة قبل الاعتماد.',
      v_approval_state USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bill_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bill_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_supplier_name text;
  v_currency text;
  v_actor uuid;
BEGIN
  v_currency := COALESCE(NEW.currency_code, 'EGP');
  BEGIN
    SELECT name INTO v_supplier_name FROM public.suppliers WHERE id = NEW.supplier_id;
  EXCEPTION WHEN OTHERS THEN v_supplier_name := NULL; END;

  v_actor := COALESCE(
    auth.uid(),
    NEW.last_edited_by_user_id,
    NEW.created_by_user_id,
    NEW.created_by
  );

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'bill', NEW.id, v_actor,
      'نشاط فرعك: تم إنشاء فاتورة مشتريات',
      'تم إنشاء فاتورة ' || NEW.bill_number ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' من المورد ' || v_supplier_name ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency || ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status IN ('paid', 'partially_paid', 'voided') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'bill', NEW.id, v_actor,
      'نشاط فرعك: تغيّرت حالة فاتورة المورد',
      'فاتورة ' || NEW.bill_number ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' من المورد ' || v_supplier_name ELSE '' END ||
      ' أصبحت الحالة "' || NEW.status || '".'
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bill_item_amendment_reset_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bill_item_amendment_reset_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_bill_id uuid; v_items jsonb; v_bill RECORD; v_supplier text;
BEGIN
  v_bill_id := COALESCE(NEW.bill_id, OLD.bill_id);
  SELECT * INTO v_bill FROM public.bills WHERE id = v_bill_id;
  IF NOT FOUND THEN RETURN COALESCE(NEW, OLD); END IF;
  IF v_bill.status NOT IN ('draft','pending_approval') THEN RETURN COALESCE(NEW, OLD); END IF;
  IF COALESCE(current_setting('app.skip_discount_approval', true), '') <> '' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'product_id', bi.product_id,
    'product_name', COALESCE(p.name, bi.description),
    'description', bi.description,
    'item_type', bi.item_type,
    'quantity', bi.quantity, 'unit_price', bi.unit_price,
    'discount_percent', bi.discount_percent,
    'tax_rate', bi.tax_rate, 'total', bi.line_total
  )), '[]'::jsonb) INTO v_items
    FROM public.bill_items bi LEFT JOIN public.products p ON p.id=bi.product_id
   WHERE bi.bill_id = v_bill_id;
  SELECT name INTO v_supplier FROM public.suppliers WHERE id = v_bill.supplier_id;

  UPDATE public.discount_approvals
     SET items_snapshot            = v_items,
         document_total            = v_bill.total_amount,
         subtotal_snapshot         = v_bill.subtotal,
         shipping_snapshot         = v_bill.shipping,
         adjustment_snapshot       = v_bill.adjustment,
         tax_amount_snapshot       = v_bill.tax_amount,
         shipping_tax_rate_snapshot= v_bill.shipping_tax_rate,
         discount_position_snapshot= v_bill.discount_position,
         tax_inclusive_snapshot    = v_bill.tax_inclusive,
         supplier_name_snapshot    = v_supplier,
         discount_value            = COALESCE(v_bill.discount_value, 0),
         discount_type             = COALESCE(v_bill.discount_type, 'amount'),
         updated_at                = NOW()
   WHERE document_type='purchase_invoice' AND document_id=v_bill_id AND status='pending';
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- bill_item_protect_posted_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bill_item_protect_posted_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_bill_status text;
  v_bill_id uuid;
BEGIN
  v_bill_id := COALESCE(NEW.bill_id, OLD.bill_id);
  SELECT status INTO v_bill_status FROM public.bills WHERE id = v_bill_id;
  IF NOT FOUND THEN RETURN COALESCE(NEW, OLD); END IF;
  IF v_bill_status IN ('draft', 'voided', 'pending_approval', 'rejected') THEN
    RETURN COALESCE(NEW, OLD);
  END IF;
  IF COALESCE(current_setting('app.skip_po_lock', true), '') <> '' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;
  -- v3.74.514: returned_quantity bookkeeping from the returns workflow
  IF TG_OP = 'UPDATE'
     AND (to_jsonb(NEW) - 'returned_quantity' - 'updated_at')
       = (to_jsonb(OLD) - 'returned_quantity' - 'updated_at') THEN
    RETURN NEW;
  END IF;
  RAISE EXCEPTION 'لا يمكن تعديل بنود فاتورة منشورة. اعمل void للفاتورة أولاً.'
    USING ERRCODE = 'P0001';
END;
$function$
;

-- ---------------------------------------------------------------
-- bill_notify_accountant_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bill_notify_accountant_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_supplier_name text;
  v_currency text;
  v_actor uuid;
  v_accountant uuid;
  v_branch_count int;
  v_po_no text;
BEGIN
  v_actor    := COALESCE(NEW.created_by_user_id, NEW.created_by);
  v_currency := COALESCE(NEW.currency_code, 'EGP');

  BEGIN
    SELECT name INTO v_supplier_name FROM public.suppliers WHERE id = NEW.supplier_id;
  EXCEPTION WHEN OTHERS THEN v_supplier_name := NULL; END;

  BEGIN
    IF NEW.purchase_order_id IS NOT NULL THEN
      SELECT po_number INTO v_po_no FROM public.purchase_orders WHERE id = NEW.purchase_order_id;
    END IF;
  EXCEPTION WHEN OTHERS THEN v_po_no := NULL; END;

  -- Count branch-scoped accountants first.
  SELECT COUNT(*) INTO v_branch_count
    FROM public.company_members
   WHERE company_id = NEW.company_id
     AND role       = 'accountant'
     AND branch_id  = NEW.branch_id
     AND user_id    IS NOT NULL;

  FOR v_accountant IN
    SELECT user_id FROM public.company_members
     WHERE company_id = NEW.company_id
       AND role       = 'accountant'
       AND user_id    IS NOT NULL
       AND (
         -- Branch-scoped accountants when available, otherwise fall back
         -- to company-wide accountants.
         (v_branch_count > 0 AND branch_id = NEW.branch_id)
         OR
         (v_branch_count = 0)
       )
       AND (v_actor IS NULL OR user_id <> v_actor)
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      NEW.company_id, 'bill', NEW.id, v_actor,
      v_accountant,
      'فاتورة مشتريات جديدة تحتاج إجراء',
      'فاتورة ' || NEW.bill_number ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' من المورد ' || v_supplier_name ELSE '' END ||
      CASE WHEN v_po_no IS NOT NULL THEN ' (من أمر شراء ' || v_po_no || ')' ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency ||
      ' — راجع الفاتورة وحضّر دورة الدفع.',
      'high', 'info', 'accountant_action', 'in_app', NOW()
    );
  END LOOP;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bill_protect_posted_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bill_protect_posted_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF COALESCE(OLD.status, '') IN ('draft', 'voided', 'pending_approval', 'rejected') THEN
    RETURN NEW;
  END IF;
  IF NEW.status IS DISTINCT FROM OLD.status THEN RETURN NEW; END IF;
  IF NEW.discount_value    IS DISTINCT FROM OLD.discount_value
     OR NEW.discount_type     IS DISTINCT FROM OLD.discount_type
     OR NEW.discount_position IS DISTINCT FROM OLD.discount_position
     OR NEW.tax_inclusive     IS DISTINCT FROM OLD.tax_inclusive
     OR NEW.exchange_rate     IS DISTINCT FROM OLD.exchange_rate
     OR NEW.subtotal          IS DISTINCT FROM OLD.subtotal
     OR NEW.total_amount      IS DISTINCT FROM OLD.total_amount
     OR NEW.tax_amount        IS DISTINCT FROM OLD.tax_amount
     OR NEW.shipping          IS DISTINCT FROM OLD.shipping THEN
    RAISE EXCEPTION 'لا يمكن تعديل الخصم أو الإجماليات على فاتورة منشورة. اعمل void للفاتورة أولاً.'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bill_request_discount_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bill_request_discount_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_last_id uuid; v_last_status text; v_last_value numeric; v_last_type text;
  v_party_name text; v_requester uuid;
  v_po_disc_status text; v_po_disc_value numeric; v_po_disc_type text;
  v_supersedes uuid; v_items_snap jsonb;
BEGIN
  IF COALESCE(current_setting('app.skip_discount_approval', true), '') <> '' THEN RETURN NEW; END IF;
  IF COALESCE(current_setting('app.amendment_inserted', true), '') = '1' THEN
    PERFORM set_config('app.amendment_inserted', '', true); RETURN NEW;
  END IF;
  IF NEW.discount_value IS NULL OR NEW.discount_value <= 0 THEN RETURN NEW; END IF;
  IF NEW.status <> 'draft' THEN RETURN NEW; END IF;
  IF TG_OP='UPDATE'
     AND COALESCE(OLD.discount_value, 0) = NEW.discount_value
     AND COALESCE(OLD.discount_type, '') = COALESCE(NEW.discount_type, '')
     AND COALESCE(OLD.discount_position, '') = COALESCE(NEW.discount_position, '')
     AND COALESCE(OLD.tax_inclusive, false) = COALESCE(NEW.tax_inclusive, false) THEN
    RETURN NEW;
  END IF;
  IF NEW.purchase_order_id IS NOT NULL THEN
    SELECT status, discount_value, discount_type INTO v_po_disc_status, v_po_disc_value, v_po_disc_type
      FROM public.discount_approvals
     WHERE document_type='purchase_order' AND document_id=NEW.purchase_order_id
     ORDER BY requested_at DESC LIMIT 1;
    IF FOUND THEN
      IF v_po_disc_status='rejected' THEN
        RAISE EXCEPTION 'تم رفض اعتماد خصم أمر الشراء المرتبط — لا يمكن حفظ فاتورة بنفس الخصم.' USING ERRCODE='P0001';
      END IF;
      IF TG_OP='INSERT' AND v_po_disc_status='approved'
         AND v_po_disc_value = NEW.discount_value
         AND COALESCE(v_po_disc_type,'amount') = COALESCE(NEW.discount_type,'amount') THEN
        RETURN NEW;
      END IF;
    END IF;
  END IF;
  SELECT id, status, discount_value, discount_type INTO v_last_id, v_last_status, v_last_value, v_last_type
    FROM public.discount_approvals
   WHERE document_type='purchase_invoice' AND document_id=NEW.id
   ORDER BY requested_at DESC LIMIT 1;
  IF FOUND AND v_last_status IN ('pending','approved')
     AND v_last_value = NEW.discount_value
     AND COALESCE(v_last_type,'') = COALESCE(NEW.discount_type,'amount') THEN
    RETURN NEW;
  END IF;
  IF FOUND AND v_last_status='pending' THEN
    UPDATE public.discount_approvals
       SET status='cancelled',
           decision_note = COALESCE(decision_note, 'Superseded by amended discount on the purchase invoice.'),
           updated_at = NOW()
     WHERE id = v_last_id;
  END IF;
  BEGIN SELECT name INTO v_party_name FROM public.suppliers WHERE id = NEW.supplier_id;
  EXCEPTION WHEN OTHERS THEN v_party_name := NULL; END;
  v_requester := COALESCE(NEW.last_edited_by_user_id, NEW.created_by_user_id, NEW.created_by);
  IF v_requester IS NULL THEN
    RAISE EXCEPTION 'Cannot open discount approval — no requester recorded on bill %.', NEW.id USING ERRCODE='P0001';
  END IF;
  BEGIN v_supersedes := NULLIF(current_setting('app.superseded_approval_id', true), '')::uuid;
  EXCEPTION WHEN OTHERS THEN v_supersedes := NULL; END;
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'product_id', bi.product_id, 'product_name', p.name,
    'quantity', bi.quantity, 'unit_price', bi.unit_price,
    'discount_percent', bi.discount_percent,
    'tax_rate', bi.tax_rate, 'total', bi.line_total
  )), '[]'::jsonb) INTO v_items_snap
    FROM public.bill_items bi LEFT JOIN public.products p ON p.id = bi.product_id
   WHERE bi.bill_id = NEW.id;
  INSERT INTO public.discount_approvals (
    company_id, document_type, document_id, document_no,
    discount_value, discount_type, document_total, party_name,
    reason, status, requested_by, requested_at,
    supersedes_approval_id, items_snapshot,
    shipping_snapshot, adjustment_snapshot,
    tax_amount_snapshot, subtotal_snapshot
  ) VALUES (
    NEW.company_id, 'purchase_invoice', NEW.id, NEW.bill_number,
    NEW.discount_value, COALESCE(NEW.discount_type, 'amount'),
    NEW.total_amount, v_party_name,
    NULL, 'pending', v_requester, NOW(),
    v_supersedes, v_items_snap,
    NEW.shipping, NEW.adjustment,
    NEW.tax_amount, NEW.subtotal
  );
  PERFORM set_config('app.superseded_approval_id', '', true);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bills_force_reapproval_on_edit()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bills_force_reapproval_on_edit()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_changed boolean := false;
BEGIN
  -- Skip if status is already pending_approval / rejected / final states;
  -- we only intercept the draft → re-edit path.
  IF OLD.status NOT IN ('draft', 'approved') THEN
    RETURN NEW;
  END IF;

  -- Only enforce when the bill came from a PO. Manual bills (purchase_order_id NULL)
  -- still go through the normal approveBill path.
  IF NEW.purchase_order_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Detect monetary changes vs the snapshot taken at PO conversion time.
  IF NEW.original_total IS NOT NULL THEN
    IF ABS(COALESCE(NEW.total_amount, 0) - COALESCE(NEW.original_total, 0)) > 0.001 THEN
      v_changed := true;
    END IF;
  END IF;

  IF NEW.original_subtotal IS NOT NULL AND NOT v_changed THEN
    IF ABS(COALESCE(NEW.subtotal, 0) - COALESCE(NEW.original_subtotal, 0)) > 0.001 THEN
      v_changed := true;
    END IF;
  END IF;

  IF NEW.original_tax_amount IS NOT NULL AND NOT v_changed THEN
    IF ABS(COALESCE(NEW.tax_amount, 0) - COALESCE(NEW.original_tax_amount, 0)) > 0.001 THEN
      v_changed := true;
    END IF;
  END IF;

  IF v_changed THEN
    -- Force re-approval. Notification is dispatched by the API layer when
    -- it detects this transition on the returned row.
    NEW.status := 'pending_approval';
    NEW.approval_status := 'pending';
    NEW.approved_by := NULL;
    NEW.approved_at := NULL;
    NEW.rejection_reason := NULL;
    NEW.rejected_by := NULL;
    NEW.rejected_at := NULL;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- binary_quantize(vector)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.binary_quantize(vector)
 RETURNS bit
 LANGUAGE c
 IMMUTABLE PARALLEL SAFE STRICT
AS '$libdir/vector', $function$binary_quantize$function$
;

-- ---------------------------------------------------------------
-- binary_quantize(halfvec)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.binary_quantize(halfvec)
 RETURNS bit
 LANGUAGE c
 IMMUTABLE PARALLEL SAFE STRICT
AS '$libdir/vector', $function$halfvec_binary_quantize$function$
;

-- ---------------------------------------------------------------
-- bkg_assert_booking_accessible(p_booking_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_assert_booking_accessible(p_booking_id uuid, p_company_id uuid)
 RETURNS bookings
 LANGUAGE plpgsql
AS $function$
DECLARE v_booking public.bookings;
BEGIN
  SELECT * INTO v_booking FROM public.bookings WHERE id = p_booking_id AND company_id = p_company_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Booking not found or not accessible. booking_id=%, company_id=%', p_booking_id, p_company_id USING ERRCODE = 'P0001';
  END IF;
  RETURN v_booking;
END; $function$
;

-- ---------------------------------------------------------------
-- bkg_check_service_capacity(p_service_id uuid, p_booking_date date, p_start_time time without time zone, p_end_time time without time zone, p_exclude_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_check_service_capacity(p_service_id uuid, p_booking_date date, p_start_time time without time zone, p_end_time time without time zone, p_exclude_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(active_count integer, capacity integer, is_available boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE v_capacity INTEGER; v_active_count INTEGER;
BEGIN
  SELECT s.capacity INTO v_capacity FROM public.services s WHERE s.id = p_service_id;
  SELECT COUNT(*)::INTEGER INTO v_active_count FROM public.bookings b
   WHERE b.service_id = p_service_id AND b.booking_date = p_booking_date
     AND b.id IS DISTINCT FROM p_exclude_id AND b.status NOT IN ('cancelled','no_show')
     AND (b.start_time,b.end_time) OVERLAPS (p_start_time,p_end_time);
  RETURN QUERY SELECT v_active_count, COALESCE(v_capacity,1), v_active_count < COALESCE(v_capacity,1);
END; $function$
;

-- ---------------------------------------------------------------
-- bkg_check_staff_conflict(p_staff_user_id uuid, p_booking_date date, p_start_time time without time zone, p_end_time time without time zone, p_exclude_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_check_staff_conflict(p_staff_user_id uuid, p_booking_date date, p_start_time time without time zone, p_end_time time without time zone, p_exclude_id uuid DEFAULT NULL::uuid)
 RETURNS integer
 LANGUAGE sql
AS $function$
  SELECT COUNT(*)::INTEGER FROM public.bookings
   WHERE staff_user_id = p_staff_user_id AND booking_date = p_booking_date
     AND id IS DISTINCT FROM p_exclude_id AND status NOT IN ('cancelled','no_show')
     AND (start_time,end_time) OVERLAPS (p_start_time,p_end_time); $function$
;

-- ---------------------------------------------------------------
-- bkg_compute_totals(p_unit_price numeric, p_quantity numeric, p_discount_amt numeric, p_tax_rate numeric, p_commission_rate numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_compute_totals(p_unit_price numeric, p_quantity numeric, p_discount_amt numeric, p_tax_rate numeric, p_commission_rate numeric)
 RETURNS TABLE(subtotal numeric, tax_amount numeric, total_amount numeric, commission_amount numeric)
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT
    ROUND((p_unit_price*p_quantity)-COALESCE(p_discount_amt,0),4),
    ROUND(((p_unit_price*p_quantity)-COALESCE(p_discount_amt,0))*COALESCE(p_tax_rate,0)/100.0,4),
    ROUND(((p_unit_price*p_quantity)-COALESCE(p_discount_amt,0))*(1+COALESCE(p_tax_rate,0)/100.0),4),
    ROUND(((p_unit_price*p_quantity)-COALESCE(p_discount_amt,0))*COALESCE(p_commission_rate,0)/100.0,4); $function$
;

-- ---------------------------------------------------------------
-- bkg_generate_booking_no(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_generate_booking_no(p_company_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year   TEXT    := TO_CHAR(NOW(), 'YYYY');
  v_next   INTEGER;
  v_prefix TEXT;
BEGIN
  v_prefix := 'BKG-' || v_year || '-';

  SELECT COALESCE(
    MAX(
      CASE
        WHEN booking_no LIKE v_prefix || '%'
          AND REGEXP_REPLACE(booking_no, '^BKG-[0-9]{4}-', '') ~ '^[0-9]+$'
        THEN CAST(REGEXP_REPLACE(booking_no, '^BKG-[0-9]{4}-', '') AS INTEGER)
        ELSE 0
      END
    ), 0
  ) + 1
  INTO v_next
  FROM public.bookings
  WHERE company_id = p_company_id;

  RETURN v_prefix || LPAD(v_next::TEXT, 5, '0');
END;
$function$
;

-- ---------------------------------------------------------------
-- bkg_is_active_status(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_is_active_status(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status,'') NOT IN ('cancelled','no_show'); $function$
;

-- ---------------------------------------------------------------
-- bkg_is_status_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_is_status_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_old_status,'')
    WHEN 'draft'       THEN COALESCE(p_new_status,'') IN ('draft','confirmed','cancelled')
    WHEN 'confirmed'   THEN COALESCE(p_new_status,'') IN ('confirmed','in_progress','cancelled','no_show')
    WHEN 'in_progress' THEN COALESCE(p_new_status,'') IN ('in_progress','completed')
    WHEN 'completed'   THEN COALESCE(p_new_status,'') IN ('completed')
    WHEN 'cancelled'   THEN COALESCE(p_new_status,'') IN ('cancelled')
    WHEN 'no_show'     THEN COALESCE(p_new_status,'') IN ('no_show')
    ELSE false
  END; $function$
;

-- ---------------------------------------------------------------
-- bkg_is_terminal_status(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_is_terminal_status(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status,'') IN ('completed','cancelled','no_show'); $function$
;

-- ---------------------------------------------------------------
-- bkg_request_discount_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_request_discount_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_last_id     uuid;
  v_last_status text;
  v_last_value  numeric;
  v_party_name  text;
  v_requester   uuid;
BEGIN
  IF NEW.discount_amount IS NULL OR NEW.discount_amount <= 0 THEN
    RETURN NEW;
  END IF;
  IF TG_OP = 'UPDATE' AND COALESCE(OLD.discount_amount, 0) = NEW.discount_amount THEN
    RETURN NEW;
  END IF;

  IF NEW.status NOT IN ('draft', 'confirmed') OR NEW.invoice_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  SELECT id, status, discount_value
    INTO v_last_id, v_last_status, v_last_value
    FROM public.discount_approvals
   WHERE document_type = 'booking' AND document_id = NEW.id
   ORDER BY requested_at DESC
   LIMIT 1;

  IF FOUND AND v_last_status IN ('pending', 'approved') AND v_last_value = NEW.discount_amount THEN
    RETURN NEW;
  END IF;

  IF FOUND AND v_last_status = 'pending' THEN
    UPDATE public.discount_approvals
       SET status = 'cancelled',
           decision_note = COALESCE(decision_note, 'Superseded by amended discount on the booking.'),
           updated_at = NOW()
     WHERE id = v_last_id;
  END IF;

  BEGIN
    SELECT name INTO v_party_name
      FROM public.customers
     WHERE id = NEW.customer_id;
  EXCEPTION WHEN OTHERS THEN
    v_party_name := NULL;
  END;

  v_requester := COALESCE(NEW.updated_by, NEW.created_by);
  IF v_requester IS NULL THEN
    RAISE EXCEPTION
      'Cannot open discount approval — no requester recorded on booking %.', NEW.id
      USING ERRCODE = 'P0001';
  END IF;

  INSERT INTO public.discount_approvals (
    company_id, document_type, document_id, document_no,
    discount_value, discount_type, document_total, party_name,
    reason, status, requested_by, requested_at
  ) VALUES (
    NEW.company_id, 'booking', NEW.id, NEW.booking_no,
    NEW.discount_amount, 'amount', NEW.total_amount, v_party_name,
    NULL, 'pending', v_requester, NOW()
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- bkg_sync_payment_status(p_booking_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_sync_payment_status(p_booking_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE v_total_paid NUMERIC; v_total_amount NUMERIC; v_pstatus TEXT;
BEGIN
  SELECT COALESCE(SUM(amount),0) INTO v_total_paid FROM public.booking_payments WHERE booking_id = p_booking_id;
  SELECT total_amount INTO v_total_amount FROM public.bookings WHERE id = p_booking_id;
  IF v_total_paid <= 0 THEN v_pstatus := 'unpaid';
  ELSIF v_total_paid >= v_total_amount THEN v_pstatus := 'paid';
  ELSE v_pstatus := 'partial'; END IF;
  UPDATE public.bookings SET paid_amount = v_total_paid, payment_status = v_pstatus WHERE id = p_booking_id;
END; $function$
;

-- ---------------------------------------------------------------
-- bkg_trg_record_status_history()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_trg_record_status_history()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.booking_status_history (company_id, booking_id, old_status, new_status, changed_by, reason)
    VALUES (NEW.company_id, NEW.id, NULL, NEW.status, NEW.created_by, 'Booking created');
    RETURN NEW;
  END IF;
  IF TG_OP = 'UPDATE' AND OLD.status IS DISTINCT FROM NEW.status THEN
    INSERT INTO public.booking_status_history (company_id, booking_id, old_status, new_status, changed_by, reason)
    VALUES (NEW.company_id, NEW.id, OLD.status, NEW.status, NEW.updated_by,
      CASE NEW.status WHEN 'confirmed' THEN 'Booking confirmed' WHEN 'in_progress' THEN 'Service started'
        WHEN 'completed' THEN 'Service completed' WHEN 'cancelled' THEN COALESCE(NEW.cancellation_reason,'Booking cancelled')
        WHEN 'no_show' THEN 'Customer no-show' ELSE 'Status updated' END);
  END IF;
  RETURN NEW;
END; $function$
;

-- ---------------------------------------------------------------
-- bkg_trg_sync_payment_status()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_trg_sync_payment_status()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE v_booking_id UUID;
BEGIN
  v_booking_id := COALESCE(NEW.booking_id, OLD.booking_id);
  PERFORM public.bkg_sync_payment_status(v_booking_id);
  RETURN COALESCE(NEW, OLD);
END; $function$
;

-- ---------------------------------------------------------------
-- bkg_trg_validate_booking()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_trg_validate_booking()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE v_capacity_row RECORD; v_staff_conflicts INTEGER;
BEGIN
  IF TG_OP = 'UPDATE' THEN
    IF NOT public.bkg_is_status_transition_allowed(OLD.status, NEW.status) THEN
      RAISE EXCEPTION 'Invalid booking status transition: % → %. booking_id=%', OLD.status, NEW.status, OLD.id USING ERRCODE = 'P0001';
    END IF;
    IF public.bkg_is_terminal_status(OLD.status) THEN
      IF OLD.status = 'completed' THEN
        NEW.status := OLD.status; NEW.service_id := OLD.service_id; NEW.customer_id := OLD.customer_id;
        NEW.booking_date := OLD.booking_date; NEW.start_time := OLD.start_time; NEW.end_time := OLD.end_time;
        NEW.total_amount := OLD.total_amount; RETURN NEW;
      END IF;
      RAISE EXCEPTION 'Cannot modify a % booking. booking_id=%', OLD.status, OLD.id USING ERRCODE = 'P0001';
    END IF;
  END IF;
  IF TG_OP = 'INSERT' OR OLD.booking_date IS DISTINCT FROM NEW.booking_date OR OLD.start_time IS DISTINCT FROM NEW.start_time
     OR OLD.end_time IS DISTINCT FROM NEW.end_time OR OLD.staff_user_id IS DISTINCT FROM NEW.staff_user_id OR OLD.service_id IS DISTINCT FROM NEW.service_id THEN
    IF NOT public.bkg_is_terminal_status(NEW.status) THEN
      IF NEW.staff_user_id IS NOT NULL THEN
        v_staff_conflicts := public.bkg_check_staff_conflict(NEW.staff_user_id, NEW.booking_date, NEW.start_time, NEW.end_time, CASE WHEN TG_OP='UPDATE' THEN OLD.id ELSE NULL END);
        IF v_staff_conflicts > 0 THEN
          RAISE EXCEPTION 'Staff member already has % overlapping booking(s) at this time. staff_user_id=%, date=%, time=%--%', v_staff_conflicts, NEW.staff_user_id, NEW.booking_date, NEW.start_time, NEW.end_time USING ERRCODE = 'P0001';
        END IF;
      END IF;
      SELECT * INTO v_capacity_row FROM public.bkg_check_service_capacity(NEW.service_id, NEW.booking_date, NEW.start_time, NEW.end_time, CASE WHEN TG_OP='UPDATE' THEN OLD.id ELSE NULL END);
      IF NOT v_capacity_row.is_available THEN
        RAISE EXCEPTION 'Service capacity exceeded. % of % slot(s) already booked at this time. service_id=%, date=%, time=%--%', v_capacity_row.active_count, v_capacity_row.capacity, NEW.service_id, NEW.booking_date, NEW.start_time, NEW.end_time USING ERRCODE = 'P0001';
      END IF;
      IF EXISTS (SELECT 1 FROM public.service_schedules WHERE service_id = NEW.service_id AND is_active = true) THEN
        PERFORM public.bkg_validate_working_hours(NEW.service_id, NEW.booking_date, NEW.start_time, NEW.end_time);
      END IF;
    END IF;
  END IF;
  RETURN NEW;
END; $function$
;

-- ---------------------------------------------------------------
-- bkg_validate_advance_booking(p_service_id uuid, p_booking_date date, p_start_time time without time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_validate_advance_booking(p_service_id uuid, p_booking_date date, p_start_time time without time zone)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE v_service public.services; v_booking_datetime TIMESTAMPTZ; v_max_future_datetime TIMESTAMPTZ; v_min_booking_datetime TIMESTAMPTZ;
BEGIN
  SELECT * INTO v_service FROM public.services WHERE id = p_service_id;
  IF NOT FOUND THEN RETURN; END IF;
  v_booking_datetime     := (p_booking_date::TEXT||' '||p_start_time::TEXT)::TIMESTAMPTZ;
  v_min_booking_datetime := NOW()+(v_service.min_advance_hours||' hours')::INTERVAL;
  v_max_future_datetime  := NOW()+(v_service.advance_booking_days||' days')::INTERVAL;
  IF v_booking_datetime < v_min_booking_datetime THEN
    RAISE EXCEPTION 'Booking must be at least % hour(s) in advance. Earliest allowed: %', v_service.min_advance_hours, v_min_booking_datetime USING ERRCODE = 'P0001';
  END IF;
  IF v_booking_datetime > v_max_future_datetime THEN
    RAISE EXCEPTION 'Booking cannot be more than % day(s) in advance. Latest allowed: %', v_service.advance_booking_days, v_max_future_datetime USING ERRCODE = 'P0001';
  END IF;
END; $function$
;

-- ---------------------------------------------------------------
-- bkg_validate_working_hours(p_service_id uuid, p_booking_date date, p_start_time time without time zone, p_end_time time without time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.bkg_validate_working_hours(p_service_id uuid, p_booking_date date, p_start_time time without time zone, p_end_time time without time zone)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_day_of_week INTEGER;
  v_book_start  INTEGER;
  v_book_end    INTEGER;
  v_schedule_id UUID;
BEGIN
  v_day_of_week := EXTRACT(DOW FROM p_booking_date)::INTEGER;

  -- Minutes-since-midnight. "00:00:00" on the END side means
  -- "midnight at the close of the day" (i.e. 24:00 = 1440).
  v_book_start := EXTRACT(HOUR FROM p_start_time) * 60
                + EXTRACT(MINUTE FROM p_start_time);
  v_book_end := CASE
    WHEN p_end_time = '00:00:00'::time THEN 24 * 60
    ELSE EXTRACT(HOUR FROM p_end_time) * 60
       + EXTRACT(MINUTE FROM p_end_time)
  END;

  SELECT id INTO v_schedule_id
    FROM public.service_schedules
   WHERE service_id  = p_service_id
     AND day_of_week = v_day_of_week
     AND is_active   = true
     AND ( EXTRACT(HOUR FROM start_time) * 60
         + EXTRACT(MINUTE FROM start_time) ) <= v_book_start
     AND ( CASE
             WHEN end_time = '00:00:00'::time THEN 24 * 60
             ELSE EXTRACT(HOUR FROM end_time) * 60
                + EXTRACT(MINUTE FROM end_time)
           END ) >= v_book_end
   LIMIT 1;

  IF v_schedule_id IS NULL THEN
    RAISE EXCEPTION 'Booking time % - % on day % is outside service working hours. service_id=%',
      p_start_time, p_end_time, v_day_of_week, p_service_id
      USING ERRCODE = 'P0001';
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- block_bank_voucher_delete_after_post()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.block_bank_voucher_delete_after_post()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.status IN ('posted','approved') OR OLD.journal_entry_id IS NOT NULL THEN
    RAISE EXCEPTION
      'لا يُمكِن حَذف سَنَد بَنكى بَعد الاعتِماد أَو التَّرحيل. استَخدِم مَسار الإِلغاء المُعتَمَد.'
      USING ERRCODE = 'foreign_key_violation';
  END IF;
  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- block_bank_voucher_immutable_edits()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.block_bank_voucher_immutable_edits()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.status IN ('draft','pending') THEN
    RETURN NEW;
  END IF;

  IF NEW.amount        IS DISTINCT FROM OLD.amount        OR
     NEW.base_amount   IS DISTINCT FROM OLD.base_amount   OR
     NEW.currency      IS DISTINCT FROM OLD.currency      OR
     NEW.exchange_rate IS DISTINCT FROM OLD.exchange_rate OR
     NEW.account_id    IS DISTINCT FROM OLD.account_id    OR
     NEW.counter_id    IS DISTINCT FROM OLD.counter_id    OR
     NEW.voucher_type  IS DISTINCT FROM OLD.voucher_type  OR
     NEW.entry_date    IS DISTINCT FROM OLD.entry_date THEN
    RAISE EXCEPTION
      'لا يُمكِن تَعديل هذا الحَقل بَعد اعتِماد السَّنَد البَنكى.'
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- block_bill_delete_with_pending()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.block_bill_delete_with_pending()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_pending_pr    integer := 0;
  v_pending_pay   integer := 0;
  v_pending_corr  integer := 0;
BEGIN
  SELECT COUNT(*) INTO v_pending_pr
    FROM public.purchase_returns
   WHERE bill_id = OLD.id
     AND workflow_status IN (
       'pending_admin_approval','pending_approval',
       'pending_warehouse','partial_approval'
     );

  SELECT COUNT(*) INTO v_pending_pay
    FROM public.payments
   WHERE (bill_id = OLD.id
          OR EXISTS (SELECT 1 FROM public.payment_allocations pa
                      WHERE pa.payment_id = payments.id AND pa.bill_id = OLD.id))
     AND status = 'pending_approval'
     AND voided_at IS NULL
     AND voids_payment_id IS NULL;

  SELECT COUNT(*) INTO v_pending_corr
    FROM public.vendor_payment_correction_requests vpcr
    JOIN public.payments p ON p.id = vpcr.original_payment_id
   WHERE p.bill_id = OLD.id
     AND vpcr.status IN ('pending','approved');

  IF v_pending_pr + v_pending_pay + v_pending_corr > 0 THEN
    RAISE EXCEPTION
      'لا يُمكِن حَذف الفاتورة قَبل الانتِهاء مِن جَميع الطَّلَبات المُعلَّقة. مَرتَجَعات مَعلَّقة: %، دَفعات بانتظار الاعتِماد: %، طَلَبات تَصحيح دَفعات: %.',
      v_pending_pr, v_pending_pay, v_pending_corr
      USING ERRCODE = 'foreign_key_violation';
  END IF;

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- block_bill_immutable_edits()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.block_bill_immutable_edits()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_locked boolean := false;
BEGIN
  -- Locked once ANY payment, allocation, or return references it
  IF COALESCE(NEW.paid_amount, 0) > 0
     OR COALESCE(NEW.returned_amount, 0) > 0
     OR EXISTS (SELECT 1 FROM public.payments p
                 WHERE (p.bill_id = NEW.id)
                   AND p.status IN ('approved','pending_approval')
                   AND p.voided_at IS NULL AND p.voids_payment_id IS NULL)
     OR EXISTS (SELECT 1 FROM public.payment_allocations pa
                 WHERE pa.bill_id = NEW.id)
     OR EXISTS (SELECT 1 FROM public.purchase_returns pr
                 WHERE pr.bill_id = NEW.id
                   AND pr.workflow_status IN (
                     'pending_admin_approval','pending_approval',
                     'pending_warehouse','partial_approval','completed'
                   )) THEN
    v_locked := true;
  END IF;

  IF NOT v_locked THEN RETURN NEW; END IF;

  IF NEW.total_amount   IS DISTINCT FROM OLD.total_amount   OR
     NEW.currency_code  IS DISTINCT FROM OLD.currency_code  OR
     NEW.exchange_rate  IS DISTINCT FROM OLD.exchange_rate  OR
     NEW.supplier_id    IS DISTINCT FROM OLD.supplier_id    OR
     NEW.bill_date      IS DISTINCT FROM OLD.bill_date THEN
    RAISE EXCEPTION
      'لا يُمكِن تَعديل هذا الحَقل بَعد وُجود دَفعات أَو مَرتَجَعات على الفاتورة. استَخدِم مَسار التَّصحيح المُعتَمَد.'
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- block_expense_delete_after_post()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.block_expense_delete_after_post()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.journal_entry_id IS NOT NULL
     OR OLD.status IN ('approved','paid') THEN
    RAISE EXCEPTION
      'لا يُمكِن حَذف مَصروف بَعد الاعتِماد أَو التَّرحيل. استَخدِم مَسار الإِلغاء المُعتَمَد.'
      USING ERRCODE = 'foreign_key_violation';
  END IF;
  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- block_expense_immutable_edits()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.block_expense_immutable_edits()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.status IN ('draft','pending_approval','rejected') THEN
    RETURN NEW;
  END IF;

  IF NEW.amount               IS DISTINCT FROM OLD.amount               OR
     NEW.base_currency_amount IS DISTINCT FROM OLD.base_currency_amount OR
     NEW.currency_code        IS DISTINCT FROM OLD.currency_code        OR
     NEW.exchange_rate        IS DISTINCT FROM OLD.exchange_rate        OR
     NEW.expense_account_id   IS DISTINCT FROM OLD.expense_account_id   OR
     NEW.payment_account_id   IS DISTINCT FROM OLD.payment_account_id   OR
     NEW.expense_date         IS DISTINCT FROM OLD.expense_date THEN
    RAISE EXCEPTION
      'لا يُمكِن تَعديل هذا الحَقل بَعد اعتِماد المَصروف.'
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- block_invoice_delete_with_pending()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.block_invoice_delete_with_pending()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_pending_sr    integer := 0;
  v_pending_pay   integer := 0;
  v_pending_ref   integer := 0;
BEGIN
  BEGIN
    SELECT COUNT(*) INTO v_pending_sr
      FROM public.sales_return_requests
     WHERE invoice_id = OLD.id
       AND LOWER(COALESCE(status,'')) IN (
         'pending','approved','partial_approval','pending_warehouse'
       );
  EXCEPTION WHEN undefined_table THEN v_pending_sr := 0; END;

  SELECT COUNT(*) INTO v_pending_pay
    FROM public.payments
   WHERE (invoice_id = OLD.id
          OR EXISTS (SELECT 1 FROM public.payment_allocations pa
                      WHERE pa.payment_id = payments.id AND pa.invoice_id = OLD.id))
     AND status = 'pending_approval'
     AND voided_at IS NULL
     AND voids_payment_id IS NULL;

  BEGIN
    SELECT COUNT(*) INTO v_pending_ref
      FROM public.customer_refund_requests
     WHERE invoice_id = OLD.id
       AND LOWER(COALESCE(status,'')) IN ('pending','approved');
  EXCEPTION WHEN undefined_table THEN v_pending_ref := 0; END;

  IF v_pending_sr + v_pending_pay + v_pending_ref > 0 THEN
    RAISE EXCEPTION
      'لا يُمكِن حَذف الفاتورة قَبل الانتِهاء مِن جَميع الطَّلَبات المُعلَّقة. مَرتَجَعات مبيعات مَعلَّقة: %، دَفعات بانتظار الاعتِماد: %، طَلَبات استِرداد/تَصحيح: %.',
      v_pending_sr, v_pending_pay, v_pending_ref
      USING ERRCODE = 'foreign_key_violation';
  END IF;

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- block_invoice_immutable_edits()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.block_invoice_immutable_edits()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_locked boolean := false;
BEGIN
  IF COALESCE(NEW.paid_amount, 0) > 0
     OR COALESCE(NEW.returned_amount, 0) > 0
     OR EXISTS (SELECT 1 FROM public.payments p
                 WHERE (p.invoice_id = NEW.id)
                   AND p.status IN ('approved','pending_approval')
                   AND p.voided_at IS NULL AND p.voids_payment_id IS NULL)
     OR EXISTS (SELECT 1 FROM public.payment_allocations pa
                 WHERE pa.invoice_id = NEW.id) THEN
    v_locked := true;
  END IF;

  BEGIN
    IF NOT v_locked AND EXISTS (
      SELECT 1 FROM public.sales_return_requests
       WHERE invoice_id = NEW.id
         AND LOWER(COALESCE(status,'')) IN (
           'pending','approved','partial_approval','pending_warehouse','completed'
         )
    ) THEN
      v_locked := true;
    END IF;
  EXCEPTION WHEN undefined_table THEN NULL; END;

  IF NOT v_locked THEN RETURN NEW; END IF;

  IF NEW.total_amount   IS DISTINCT FROM OLD.total_amount   OR
     NEW.currency_code  IS DISTINCT FROM OLD.currency_code  OR
     NEW.exchange_rate  IS DISTINCT FROM OLD.exchange_rate  OR
     NEW.customer_id    IS DISTINCT FROM OLD.customer_id    OR
     NEW.invoice_date   IS DISTINCT FROM OLD.invoice_date THEN
    RAISE EXCEPTION
      'لا يُمكِن تَعديل هذا الحَقل بَعد وُجود دَفعات أَو مَرتَجَعات على الفاتورة. استَخدِم مَسار التَّصحيح المُعتَمَد.'
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$function$
;

