;

-- ---------------------------------------------------------------
-- branch_outlet_lifecycle()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.branch_outlet_lifecycle()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_id uuid;
BEGIN
  IF TG_OP = 'INSERT' THEN
    PERFORM public.ensure_branch_outlet(NEW.id);
    RETURN NEW;
  END IF;

  -- UPDATE: sync outlet name + active flag
  SELECT sp.id INTO v_id
  FROM public.shipping_providers sp
  JOIN public.branch_shipping_providers bsp ON bsp.shipping_provider_id = sp.id
  WHERE sp.company_id = NEW.company_id
    AND sp.provider_code = 'branch_outlet'
    AND bsp.branch_id = NEW.id
  LIMIT 1;

  IF v_id IS NOT NULL THEN
    UPDATE public.shipping_providers
       SET provider_name = 'منفذ بيع ' || NEW.name,
           is_active = COALESCE(NEW.is_active, true)
     WHERE id = v_id;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- calc_declining_balance_depreciation(p_book_value numeric, p_salvage_value numeric, p_rate numeric, p_useful_life_months integer, p_period_number integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.calc_declining_balance_depreciation(p_book_value numeric, p_salvage_value numeric, p_rate numeric, p_useful_life_months integer, p_period_number integer)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_depreciation DECIMAL;
  v_annual_rate DECIMAL;
BEGIN
  -- تحويل المعدل السنوي إلى شهري
  v_annual_rate := p_rate / 12;
  v_depreciation := ROUND(p_book_value * v_annual_rate, 2);

  -- التأكد من عدم تجاوز القيمة المتبقية
  IF (p_book_value - v_depreciation) < p_salvage_value THEN
    v_depreciation := p_book_value - p_salvage_value;
  END IF;

  RETURN GREATEST(v_depreciation, 0);
END;
$function$
;

-- ---------------------------------------------------------------
-- calc_straight_line_depreciation(p_purchase_cost numeric, p_salvage_value numeric, p_useful_life_months integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.calc_straight_line_depreciation(p_purchase_cost numeric, p_salvage_value numeric, p_useful_life_months integer)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  IF p_useful_life_months <= 0 THEN
    RETURN 0;
  END IF;
  RETURN ROUND((p_purchase_cost - p_salvage_value) / p_useful_life_months, 2);
END;
$function$
;

-- ---------------------------------------------------------------
-- calculate_bonus_amount(p_invoice_total numeric, p_bonus_type text, p_bonus_percentage numeric, p_bonus_fixed numeric, p_bonus_points_per_value numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.calculate_bonus_amount(p_invoice_total numeric, p_bonus_type text, p_bonus_percentage numeric, p_bonus_fixed numeric, p_bonus_points_per_value numeric)
 RETURNS numeric
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$ BEGIN CASE p_bonus_type WHEN 'percentage' THEN RETURN ROUND(p_invoice_total * (p_bonus_percentage / 100), 2); WHEN 'fixed' THEN RETURN p_bonus_fixed; WHEN 'points' THEN RETURN FLOOR(p_invoice_total / NULLIF(p_bonus_points_per_value, 0)); ELSE RETURN 0; END CASE; END; $function$
;

-- ---------------------------------------------------------------
-- calculate_cogs_total(p_company_id uuid, p_from_date date, p_to_date date, p_branch_id uuid, p_cost_center_id uuid, p_warehouse_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.calculate_cogs_total(p_company_id uuid, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT NULL::date, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_total NUMERIC := 0;
BEGIN
  SELECT COALESCE(SUM(total_cost), 0)
  INTO v_total
  FROM cogs_transactions
  WHERE company_id = p_company_id
    AND (p_from_date IS NULL OR transaction_date >= p_from_date)
    AND (p_to_date IS NULL OR transaction_date <= p_to_date)
    AND (p_branch_id IS NULL OR branch_id = p_branch_id)
    AND (p_cost_center_id IS NULL OR cost_center_id = p_cost_center_id)
    AND (p_warehouse_id IS NULL OR warehouse_id = p_warehouse_id);
  
  RETURN v_total;
END;
$function$
;

-- ---------------------------------------------------------------
-- calculate_customer_debit_note_totals()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.calculate_customer_debit_note_totals()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_subtotal DECIMAL(15,2); v_tax_amount DECIMAL(15,2); v_total_amount DECIMAL(15,2); BEGIN SELECT COALESCE(SUM(line_total), 0), COALESCE(SUM(line_total * tax_rate / 100), 0) INTO v_subtotal, v_tax_amount FROM customer_debit_note_items WHERE customer_debit_note_id = COALESCE(NEW.customer_debit_note_id, OLD.customer_debit_note_id); v_total_amount := v_subtotal + v_tax_amount; UPDATE customer_debit_notes SET subtotal = v_subtotal, tax_amount = v_tax_amount, total_amount = v_total_amount, updated_at = NOW() WHERE id = COALESCE(NEW.customer_debit_note_id, OLD.customer_debit_note_id); RETURN COALESCE(NEW, OLD); END; $function$
;

-- ---------------------------------------------------------------
-- calculate_fifo_cogs(p_product_id uuid, p_quantity numeric, OUT total_cogs numeric, OUT lots_used jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.calculate_fifo_cogs(p_product_id uuid, p_quantity numeric, OUT total_cogs numeric, OUT lots_used jsonb)
 RETURNS record
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_lot RECORD;
  v_remaining_qty NUMERIC := p_quantity;
  v_qty_from_lot NUMERIC;
  v_cost_from_lot NUMERIC;
  v_lots_array JSONB := '[]'::JSONB;
BEGIN
  total_cogs := 0;

  -- الحصول على الدفعات بترتيب FIFO (الأقدم أولاً)
  FOR v_lot IN
    SELECT id, remaining_quantity, unit_cost, lot_date
    FROM fifo_cost_lots
    WHERE product_id = p_product_id
      AND remaining_quantity > 0
    ORDER BY lot_date ASC, created_at ASC
  LOOP
    -- إذا استهلكنا الكمية المطلوبة، نتوقف
    EXIT WHEN v_remaining_qty <= 0;

    -- الكمية التي سنأخذها من هذه الدفعة
    v_qty_from_lot := LEAST(v_lot.remaining_quantity, v_remaining_qty);
    v_cost_from_lot := v_qty_from_lot * v_lot.unit_cost;

    -- إضافة للتكلفة الإجمالية
    total_cogs := total_cogs + v_cost_from_lot;

    -- تسجيل الدفعة المستخدمة
    v_lots_array := v_lots_array || jsonb_build_object(
      'lot_id', v_lot.id,
      'quantity', v_qty_from_lot,
      'unit_cost', v_lot.unit_cost,
      'total_cost', v_cost_from_lot,
      'lot_date', v_lot.lot_date
    );

    -- تقليل الكمية المتبقية
    v_remaining_qty := v_remaining_qty - v_qty_from_lot;
  END LOOP;

  lots_used := v_lots_array;

  -- إذا لم نجد دفعات كافية، نرجع خطأ
  IF v_remaining_qty > 0 THEN
    RAISE WARNING 'Insufficient FIFO lots for product %. Missing quantity: %', p_product_id, v_remaining_qty;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- calculate_fifo_cost(p_product_id uuid, p_warehouse_id uuid, p_quantity numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.calculate_fifo_cost(p_product_id uuid, p_warehouse_id uuid, p_quantity numeric)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total_cost NUMERIC := 0;
  v_remaining_qty NUMERIC := p_quantity;
  v_lot RECORD;
BEGIN
  -- جلب اللوتات حسب FIFO (الأقدم أولاً)
  -- استخدام COALESCE للتعامل مع purchase_date إذا كان موجوداً
  FOR v_lot IN 
    SELECT id, remaining_quantity, unit_cost
    FROM fifo_cost_lots
    WHERE product_id = p_product_id
      AND (warehouse_id = p_warehouse_id OR warehouse_id IS NULL)
      AND remaining_quantity > 0
    ORDER BY COALESCE(purchase_date, created_at::DATE) ASC, created_at ASC
  LOOP
    IF v_remaining_qty <= 0 THEN
      EXIT;
    END IF;
    
    DECLARE
      v_qty_from_lot NUMERIC := LEAST(v_lot.remaining_quantity, v_remaining_qty);
    BEGIN
      v_total_cost := v_total_cost + (v_qty_from_lot * v_lot.unit_cost);
      v_remaining_qty := v_remaining_qty - v_qty_from_lot;
    END;
  END LOOP;
  
  RETURN v_total_cost;
END;
$function$
;

-- ---------------------------------------------------------------
-- calculate_invoice_net_amount(p_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.calculate_invoice_net_amount(p_invoice_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_total_amount NUMERIC;
  v_returned_amount NUMERIC;
  v_net_amount NUMERIC;
BEGIN
  SELECT 
    COALESCE(total_amount, 0),
    COALESCE(returned_amount, 0)
  INTO v_total_amount, v_returned_amount
  FROM invoices
  WHERE id = p_invoice_id;

  IF NOT FOUND THEN
    RETURN 0;
  END IF;

  v_net_amount := v_total_amount - v_returned_amount;
  
  RETURN GREATEST(v_net_amount, 0);
END;
$function$
;

