-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.can_approve_discount(p_company_id uuid, p_user_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.company_members cm
     WHERE cm.company_id = p_company_id AND cm.user_id = p_user_id
       AND cm.role IN ('owner', 'admin', 'general_manager')
  ) OR EXISTS (
    SELECT 1 FROM public.companies c WHERE c.id = p_company_id AND c.user_id = p_user_id
  );
$function$
;

-- ---------------------------------------------------------------
-- can_close_accounting_year(p_company_id uuid, p_year integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.can_close_accounting_year(p_company_id uuid, p_year integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_unbalanced_count   INT := 0;
  v_duplicate_count    INT := 0;
  v_open_periods_count INT := 0;
  v_blocking_issues    JSONB[] := '{}';
BEGIN
  -- اختبار 1: قيود غير متوازنة
  SELECT COUNT(*) INTO v_unbalanced_count FROM (
    SELECT je.id FROM public.journal_entries je
    LEFT JOIN public.journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE je.company_id = p_company_id AND je.status = 'posted'
      AND (je.is_deleted IS NULL OR je.is_deleted = FALSE) AND je.deleted_at IS NULL
      AND EXTRACT(YEAR FROM je.entry_date) = p_year
    GROUP BY je.id
    HAVING ABS(COALESCE(SUM(jel.debit_amount),0) - COALESCE(SUM(jel.credit_amount),0)) > 0.01
  ) u;

  IF v_unbalanced_count > 0 THEN
    v_blocking_issues := array_append(v_blocking_issues, jsonb_build_object(
      'code','UNBALANCED_ENTRIES',
      'message', format('يوجد %s قيد غير متوازن في %s', v_unbalanced_count, p_year),
      'count', v_unbalanced_count));
  END IF;

  -- اختبار 2: قيود مكررة
  SELECT COUNT(*) INTO v_duplicate_count FROM (
    SELECT reference_type, reference_id FROM public.journal_entries
    WHERE company_id = p_company_id AND reference_type IS NOT NULL AND reference_id IS NOT NULL
      AND (is_deleted IS NULL OR is_deleted = FALSE) AND deleted_at IS NULL
      AND EXTRACT(YEAR FROM entry_date) = p_year
    GROUP BY reference_type, reference_id HAVING COUNT(*) > 1
  ) d;

  IF v_duplicate_count > 0 THEN
    v_blocking_issues := array_append(v_blocking_issues, jsonb_build_object(
      'code','DUPLICATE_ENTRIES',
      'message', format('يوجد %s مجموعة قيود مكررة في %s', v_duplicate_count, p_year),
      'count', v_duplicate_count));
  END IF;

  -- اختبار 3: فترات مفتوحة
  SELECT COUNT(*) INTO v_open_periods_count FROM public.accounting_periods
  WHERE company_id = p_company_id AND EXTRACT(YEAR FROM period_start) = p_year
    AND status NOT IN ('closed','locked');

  IF v_open_periods_count > 0 THEN
    v_blocking_issues := array_append(v_blocking_issues, jsonb_build_object(
      'code','OPEN_PERIODS',
      'message', format('يوجد %s فترة مفتوحة في %s', v_open_periods_count, p_year),
      'count', v_open_periods_count));
  END IF;

  IF array_length(v_blocking_issues, 1) > 0 THEN
    RETURN jsonb_build_object('can_close', FALSE, 'year', p_year,
      'blocking_issues', to_jsonb(v_blocking_issues),
      'message', format('لا يمكن الإقفال: %s مشكلة حرجة', array_length(v_blocking_issues, 1)));
  END IF;

  RETURN jsonb_build_object('can_close', TRUE, 'year', p_year,
    'blocking_issues', '[]'::JSONB, 'message', format('يمكن إقفال سنة %s', p_year));
END; $function$
;

-- ---------------------------------------------------------------
-- can_close_period_with_integrity(p_company_id uuid, p_period_year integer, p_period_month integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.can_close_period_with_integrity(p_company_id uuid, p_period_year integer, p_period_month integer DEFAULT NULL::integer)
 RETURNS TABLE(can_close boolean, blocking_issues jsonb, warnings jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_recon_row RECORD; v_blocks JSONB := '[]'::JSONB; v_warns JSONB := '[]'::JSONB;
  v_unbalanced INTEGER;
BEGIN
  PERFORM public.run_daily_reconciliation(p_company_id);
  FOR v_recon_row IN
    SELECT * FROM daily_reconciliation_log
    WHERE company_id = p_company_id AND run_date = CURRENT_DATE AND NOT is_ok
    ORDER BY severity DESC
  LOOP
    IF v_recon_row.severity = 'critical' THEN
      v_blocks := v_blocks || jsonb_build_object('check', v_recon_row.check_name, 'message', v_recon_row.message, 'difference', v_recon_row.difference);
    ELSE
      v_warns := v_warns || jsonb_build_object('check', v_recon_row.check_name, 'message', v_recon_row.message);
    END IF;
  END LOOP;
  SELECT COUNT(*) INTO v_unbalanced FROM (
    SELECT je.id FROM journal_entries je
    JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE je.company_id = p_company_id AND je.status = 'posted'
      AND EXTRACT(YEAR FROM je.entry_date) = p_period_year
    GROUP BY je.id HAVING ABS(SUM(jel.debit_amount) - SUM(jel.credit_amount)) > 0.01
  ) sub;
  IF v_unbalanced > 0 THEN
    v_blocks := v_blocks || jsonb_build_object('check','UNBALANCED_ENTRIES','message', v_unbalanced||' قيود غير متوازنة','count',v_unbalanced);
  END IF;
  RETURN QUERY VALUES (jsonb_array_length(v_blocks) = 0, v_blocks, v_warns);
END; $function$
;

-- ---------------------------------------------------------------
-- can_delete_data(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.can_delete_data(p_company_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  -- المالك يمكنه الحذف دائماً
  IF EXISTS (
    SELECT 1 FROM companies c WHERE c.id = p_company_id AND c.user_id = auth.uid()
  ) THEN
    RETURN TRUE;
  END IF;
  
  -- التحقق من صلاحية الحذف من جدول الصلاحيات
  RETURN EXISTS (
    SELECT 1 
    FROM company_members cm
    JOIN company_role_permissions crp ON crp.company_id = cm.company_id AND crp.role = cm.role
    WHERE cm.company_id = p_company_id
    AND cm.user_id = auth.uid()
    AND crp.resource = 'customers'
    AND crp.can_delete = true
  );
END;
$function$
;

