-- ---------------------------------------------------------------
-- can_manage_supplier_row(p_company_id uuid, p_row_branch_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.can_manage_supplier_row(p_company_id uuid, p_row_branch_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_role text; v_user_branch_id uuid;
BEGIN
  IF EXISTS (SELECT 1 FROM companies c WHERE c.id = p_company_id AND c.user_id = auth.uid()) THEN
    RETURN true;
  END IF;
  SELECT role, branch_id INTO v_role, v_user_branch_id
    FROM company_members WHERE company_id = p_company_id AND user_id = auth.uid() LIMIT 1;
  IF v_role IS NULL THEN RETURN false; END IF;
  IF v_role IN ('owner','admin','general_manager') THEN RETURN true; END IF;
  IF v_role IN ('manager','accountant','purchasing_officer') THEN
    IF v_user_branch_id IS NULL THEN RETURN false; END IF;
    IF p_row_branch_id IS NULL THEN RETURN false; END IF;
    RETURN p_row_branch_id = v_user_branch_id;
  END IF;
  RETURN false;
END;
$function$
;

