-- ---------------------------------------------------------------
-- can_modify_transaction(p_company_id uuid, p_transaction_date date, p_table_name text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.can_modify_transaction(p_company_id uuid, p_transaction_date date, p_table_name text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_is_locked BOOLEAN;
BEGIN
  -- التحقق من حالة الفترة
  v_is_locked := check_period_lock(p_company_id, p_transaction_date);

  IF v_is_locked THEN
    RAISE EXCEPTION 'الفترة المحاسبية مغلقة. لا يمكن % في التاريخ %', 
      p_table_name, p_transaction_date;
  END IF;

  RETURN TRUE;
END;
$function$
;

