-- ---------------------------------------------------------------
-- cancel_approved_write_off(p_write_off_id uuid, p_cancelled_by uuid, p_cancellation_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cancel_approved_write_off(p_write_off_id uuid, p_cancelled_by uuid, p_cancellation_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_write_off RECORD;
  v_item RECORD;
  v_reversal_journal_id UUID;
BEGIN
  SELECT * INTO v_write_off FROM public.inventory_write_offs WHERE id = p_write_off_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'لم يتم العثور على الإهلاك');
  END IF;

  IF v_write_off.status != 'approved' THEN
    RETURN jsonb_build_object('success', false, 'error', 'لا يمكن إلغاء إهلاك غير معتمد');
  END IF;

  INSERT INTO public.journal_entries (
    company_id, reference_type, reference_id, entry_date, description,
    branch_id, cost_center_id
  ) VALUES (
    v_write_off.company_id,
    'write_off_reversal',
    p_write_off_id,
    CURRENT_DATE,
    'إلغاء إهلاك - ' || v_write_off.write_off_number,
    v_write_off.branch_id,
    v_write_off.cost_center_id
  ) RETURNING id INTO v_reversal_journal_id;

  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, debit_amount, credit_amount, description
  )
  SELECT
    v_reversal_journal_id,
    account_id,
    credit_amount,
    debit_amount,
    'عكس: ' || COALESCE(description, '')
  FROM public.journal_entry_lines
  WHERE journal_entry_id = v_write_off.journal_entry_id;

  FOR v_item IN SELECT * FROM public.inventory_write_off_items WHERE write_off_id = p_write_off_id LOOP
    INSERT INTO public.inventory_transactions (
      company_id, product_id, transaction_type, quantity_change,
      reference_id, journal_entry_id, notes,
      branch_id, cost_center_id, warehouse_id
    ) VALUES (
      v_write_off.company_id,
      v_item.product_id,
      'write_off_reversal',
      v_item.quantity,
      p_write_off_id,
      v_reversal_journal_id,
      'إلغاء إهلاك - ' || v_write_off.write_off_number,
      v_write_off.branch_id,
      v_write_off.cost_center_id,
      v_write_off.warehouse_id
    );
  END LOOP;

  UPDATE public.inventory_write_offs SET
    status = 'cancelled',
    cancelled_by = p_cancelled_by,
    cancelled_at = now(),
    cancellation_reason = p_cancellation_reason,
    last_status_changed_at = now(),
    updated_at = now()
  WHERE id = p_write_off_id;

  RETURN jsonb_build_object(
    'success', true,
    'reversal_journal_id', v_reversal_journal_id,
    'message', 'تم إلغاء الإهلاك بنجاح'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- cancel_booking_atomic(p_company_id uuid, p_booking_id uuid, p_cancelled_by uuid, p_cancellation_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cancel_booking_atomic(p_company_id uuid, p_booking_id uuid, p_cancelled_by uuid, p_cancellation_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_booking public.bookings;
BEGIN
  SELECT * INTO v_booking FROM public.bookings WHERE id = p_booking_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Booking not found. booking_id=%', p_booking_id USING ERRCODE='P0001'; END IF;
  IF public.bkg_is_terminal_status(v_booking.status) THEN RAISE EXCEPTION 'Cannot cancel a % booking. booking_id=%', v_booking.status, p_booking_id USING ERRCODE='P0001'; END IF;
  UPDATE public.bookings SET status='cancelled', cancellation_reason=p_cancellation_reason, cancelled_by=p_cancelled_by, cancelled_at=NOW(), updated_by=p_cancelled_by WHERE id=p_booking_id;
  RETURN jsonb_build_object('success',true,'booking_id',p_booking_id,'status','cancelled');
END; $function$
;

-- ---------------------------------------------------------------
-- cancel_discount_approval(p_approval_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cancel_discount_approval(p_approval_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_approval public.discount_approvals;
BEGIN
  SELECT * INTO v_approval FROM public.discount_approvals WHERE id = p_approval_id FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Approval not found' USING ERRCODE = 'P0001';
  END IF;

  IF v_approval.requested_by <> auth.uid() AND NOT public.can_approve_discount(v_approval.company_id, auth.uid()) THEN
    RAISE EXCEPTION 'Not authorized to cancel this approval' USING ERRCODE = 'P0001';
  END IF;

  IF v_approval.status <> 'pending' THEN
    RAISE EXCEPTION 'Cannot cancel a % approval', v_approval.status USING ERRCODE = 'P0001';
  END IF;

  UPDATE public.discount_approvals SET status = 'cancelled', decided_by = auth.uid(), decided_at = NOW()
  WHERE id = p_approval_id;

  RETURN jsonb_build_object('success', true, 'approval_id', p_approval_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- cancel_manufacturing_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_cancelled_by uuid, p_cancellation_reason text, p_cancelled_at timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cancel_manufacturing_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_cancelled_by uuid, p_cancellation_reason text, p_cancelled_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order RECORD;
  v_cancelled_at TIMESTAMPTZ := COALESCE(p_cancelled_at, NOW());
  v_blocking_operation_count INTEGER := 0;
  v_deleted_operation_count INTEGER := 0;
  v_cancelled_operation_count INTEGER := 0;
BEGIN
  IF p_cancellation_reason IS NULL OR BTRIM(p_cancellation_reason) = '' THEN
    RAISE EXCEPTION 'cancellation_reason is required.';
  END IF;

  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order not found or not in company. production_order_id=%', p_production_order_id;
  END IF;

  IF v_order.status = 'cancelled' THEN
    RETURN jsonb_build_object(
      'success', true,
      'production_order_id', p_production_order_id,
      'previous_status', v_order.status,
      'status', 'cancelled'
    );
  END IF;

  IF v_order.status NOT IN ('draft', 'released') THEN
    RAISE EXCEPTION 'Only draft or released production orders can be cancelled in v1. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  END IF;

  IF v_order.status = 'released' THEN
    SELECT COUNT(*)
      INTO v_blocking_operation_count
      FROM public.manufacturing_production_order_operations
     WHERE production_order_id = p_production_order_id
       AND (
         status NOT IN ('pending', 'ready', 'cancelled')
         OR completed_quantity > 0
         OR actual_start_at IS NOT NULL
         OR actual_end_at IS NOT NULL
       );

    IF v_blocking_operation_count > 0 THEN
      RAISE EXCEPTION 'Released production order cannot be cancelled after execution has started. production_order_id=%, blocking_operation_count=%',
        p_production_order_id, v_blocking_operation_count;
    END IF;

    UPDATE public.manufacturing_production_order_operations
       SET status = 'cancelled',
           updated_by = p_cancelled_by
     WHERE production_order_id = p_production_order_id
       AND status IN ('pending', 'ready');

    GET DIAGNOSTICS v_cancelled_operation_count = ROW_COUNT;
  ELSE
    DELETE FROM public.manufacturing_production_order_operations
     WHERE production_order_id = p_production_order_id;

    GET DIAGNOSTICS v_deleted_operation_count = ROW_COUNT;
  END IF;

  UPDATE public.manufacturing_production_orders
     SET status = 'cancelled',
         cancelled_at = v_cancelled_at,
         cancelled_by = p_cancelled_by,
         cancellation_reason = p_cancellation_reason,
         updated_by = p_cancelled_by
   WHERE id = p_production_order_id;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', p_production_order_id,
    'previous_status', v_order.status,
    'status', 'cancelled',
    'cancelled_at', v_cancelled_at,
    'deleted_operation_count', v_deleted_operation_count,
    'cancelled_operation_count', v_cancelled_operation_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- cancel_refund_requests_on_invoice_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cancel_refund_requests_on_invoice_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE public.customer_refund_requests
     SET status = 'cancelled',
         cancelled_at = NOW(),
         rejection_reason = COALESCE(rejection_reason,'') ||
           CASE WHEN COALESCE(rejection_reason,'')='' THEN '' ELSE ' | ' END ||
           'إلغاء آلى: حُذفت الفاتورة المصدر ' || COALESCE(OLD.invoice_number, OLD.id::text),
         updated_at = NOW()
   WHERE invoice_id = OLD.id
     AND status IN ('pending','approved')
     AND reversal_payment_id IS NULL;
  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- cancel_requests_on_payment_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cancel_requests_on_payment_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE public.customer_refund_requests
     SET status = 'cancelled',
         cancelled_at = NOW(),
         rejection_reason = COALESCE(rejection_reason,'') ||
           CASE WHEN COALESCE(rejection_reason,'')='' THEN '' ELSE ' | ' END ||
           'إلغاء آلى: حُذفت الدفعة المصدر',
         updated_at = NOW()
   WHERE original_payment_id = OLD.id
     AND status IN ('pending','approved')
     AND reversal_payment_id IS NULL;

  UPDATE public.vendor_payment_correction_requests
     SET status = 'cancelled',
         cancelled_at = NOW(),
         rejection_reason = COALESCE(rejection_reason,'') ||
           CASE WHEN COALESCE(rejection_reason,'')='' THEN '' ELSE ' | ' END ||
           'إلغاء آلى: حُذفت الدفعة المصدر',
         updated_at = NOW()
   WHERE original_payment_id = OLD.id
     AND status IN ('pending','approved')
     AND reversal_payment_id IS NULL;

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- cb_validate_consolidation_run_contract()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cb_validate_consolidation_run_contract()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.execution_mode = 'commit_run' AND NEW.run_type = 'dry_run' THEN
    RAISE EXCEPTION 'CONSOLIDATION_COMMIT_REQUIRES_NON_DRY_RUN_TYPE';
  END IF;

  IF OLD.status = 'completed' THEN
    RAISE EXCEPTION 'CONSOLIDATION_RUN_IMMUTABLE_AFTER_COMPLETION';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- cb_validate_elimination_trace_link()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cb_validate_elimination_trace_link()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.entry_type = 'elimination'
     AND NEW.candidate_id IS NULL
     AND NEW.source_intercompany_transaction_id IS NULL
     AND NEW.source_reconciliation_result_id IS NULL THEN
    RAISE EXCEPTION 'ELIMINATION_TRACE_LINK_REQUIRED';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- cb_validate_statement_run_version()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cb_validate_statement_run_version()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_run_version INTEGER;
BEGIN
  SELECT run_version
    INTO v_run_version
  FROM public.consolidation_runs
  WHERE id = NEW.consolidation_run_id;

  IF v_run_version IS NULL THEN
    RAISE EXCEPTION 'CONSOLIDATION_RUN_MISSING_FOR_STATEMENT';
  END IF;

  IF NEW.run_version <> v_run_version THEN
    RAISE EXCEPTION 'CONSOLIDATED_STATEMENT_RUN_VERSION_MISMATCH';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_account_cycle()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_account_cycle()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.parent_id IS NULL THEN RETURN NEW; END IF;
  IF NEW.parent_id = NEW.id THEN RAISE EXCEPTION 'Account cannot be its own parent.'; END IF;
  IF EXISTS (
    WITH RECURSIVE ancestry AS (
      SELECT id, parent_id FROM chart_of_accounts WHERE id = NEW.parent_id
      UNION ALL
      SELECT c.id, c.parent_id FROM chart_of_accounts c JOIN ancestry a ON c.id = a.parent_id
    )
    SELECT 1 FROM ancestry WHERE id = NEW.id
  ) THEN
    RAISE EXCEPTION 'Cyclic dependency detected.';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_accounting_integrity(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_accounting_integrity(p_company_id uuid)
 RETURNS TABLE(check_name text, status text, details text)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_unbalanced_count INTEGER;
  v_missing_cogs_count INTEGER;
  v_duplicate_cogs_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_unbalanced_count
  FROM (SELECT * FROM check_all_journal_entries_balance(p_company_id)) t;
  
  check_name := 'Unbalanced Entries';
  IF v_unbalanced_count = 0 THEN
    status := 'PASS';
    details := 'All entries are balanced';
  ELSE
    status := 'FAIL';
    details := v_unbalanced_count || ' unbalanced entries';
  END IF;
  RETURN NEXT;

  SELECT COUNT(*) INTO v_missing_cogs_count
  FROM invoices i
  WHERE i.company_id = p_company_id
    AND i.status NOT IN ('draft', 'cancelled')
    AND NOT EXISTS(
      SELECT 1 FROM journal_entries je 
      WHERE je.reference_type = 'invoice_cogs' AND je.reference_id = i.id
    )
    AND EXISTS(
      SELECT 1 FROM invoice_items ii
      JOIN products p ON ii.product_id = p.id
      WHERE ii.invoice_id = i.id AND p.item_type != 'service' AND p.cost_price > 0
    );
  
  check_name := 'Missing COGS Entries';
  IF v_missing_cogs_count = 0 THEN
    status := 'PASS';
    details := 'All invoices have COGS entries';
  ELSE
    status := 'FAIL';
    details := v_missing_cogs_count || ' invoices without COGS';
  END IF;
  RETURN NEXT;

  SELECT COUNT(*) INTO v_duplicate_cogs_count
  FROM (
    SELECT reference_id, COUNT(*) as cnt
    FROM journal_entries
    WHERE company_id = p_company_id AND reference_type = 'invoice_cogs'
    GROUP BY reference_id
    HAVING COUNT(*) > 1
  ) t;
  
  check_name := 'Duplicate COGS Entries';
  IF v_duplicate_cogs_count = 0 THEN
    status := 'PASS';
    details := 'No duplicate COGS entries';
  ELSE
    status := 'FAIL';
    details := v_duplicate_cogs_count || ' invoices with duplicate COGS';
  END IF;
  RETURN NEXT;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_all_journal_entries_balance(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_all_journal_entries_balance(p_company_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(journal_entry_id uuid, entry_date date, description text, total_debit numeric, total_credit numeric, difference numeric, is_balanced boolean)
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    je.id,
    je.entry_date,
    je.description,
    COALESCE(SUM(jel.debit_amount), 0) as total_debit,
    COALESCE(SUM(jel.credit_amount), 0) as total_credit,
    ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) as difference,
    ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) < 0.01 as is_balanced
  FROM journal_entries je
  LEFT JOIN journal_entry_lines jel ON je.id = jel.journal_entry_id
  WHERE (p_company_id IS NULL OR je.company_id = p_company_id)
  GROUP BY je.id, je.entry_date, je.description
  HAVING ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) > 0.01
  ORDER BY je.entry_date DESC;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_and_claim_idempotency_key(p_idempotency_key text, p_company_id uuid, p_operation_type text, p_request_hash text, p_created_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_and_claim_idempotency_key(p_idempotency_key text, p_company_id uuid, p_operation_type text, p_request_hash text DEFAULT NULL::text, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_existing RECORD;
  v_new_id   UUID;
BEGIN
  SELECT id, status, response_data, created_at, request_hash
  INTO v_existing
  FROM public.idempotency_keys
  WHERE idempotency_key = p_idempotency_key
    AND company_id = p_company_id
    AND operation_type = p_operation_type
  LIMIT 1;

  IF FOUND THEN
    IF v_existing.status = 'completed' THEN
      RETURN jsonb_build_object(
        'cached', TRUE,
        'status', 'completed',
        'response', v_existing.response_data,
        'original_at', v_existing.created_at
      );
    END IF;

    IF v_existing.status = 'processing' THEN
      IF v_existing.created_at < NOW() - INTERVAL '5 minutes' THEN
        -- FIX: حذف مباشر بدلاً من UPDATE ثم شرط على المتغير المحلي الذي لا يتحدث
        DELETE FROM public.idempotency_keys WHERE id = v_existing.id;
        -- الخروج من الـ IF والمتابعة لإنشاء مفتاح جديد
      ELSE
        RAISE EXCEPTION 'IDEMPOTENCY_IN_FLIGHT: العملية جارية بالفعل. انتظر اكتمالها. Key: %', p_idempotency_key
          USING ERRCODE = 'P0001';
      END IF;
    -- FIX: ELSIF بدلاً من IF منفصل — يعمل سواء جاء من 'failed' مباشرة أو بعد الحذف أعلاه
    ELSIF v_existing.status = 'failed' THEN
      DELETE FROM public.idempotency_keys WHERE id = v_existing.id;
    END IF;
  END IF;

  INSERT INTO public.idempotency_keys
    (idempotency_key, company_id, operation_type, status, request_hash, created_by)
  VALUES
    (p_idempotency_key, p_company_id, p_operation_type, 'processing', p_request_hash, p_created_by)
  RETURNING id INTO v_new_id;

  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_and_increment_rate_limit(p_identifier text, p_route text, p_max_requests integer, p_window_seconds integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_and_increment_rate_limit(p_identifier text, p_route text, p_max_requests integer, p_window_seconds integer DEFAULT 60)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_window_start timestamptz;
  v_request_count int;
  v_allowed boolean;
  v_blocked_until timestamptz;
BEGIN
  v_window_start := date_trunc('minute', now());

  -- Atomic upsert: insert new window or increment existing
  INSERT INTO api_rate_limits
    (identifier, route, request_count, window_start, window_seconds, max_requests)
  VALUES
    (p_identifier, p_route, 1, v_window_start, p_window_seconds, p_max_requests)
  ON CONFLICT (identifier, route)
  DO UPDATE SET
    request_count = CASE
      -- New window: reset counter
      WHEN api_rate_limits.window_start < v_window_start
      THEN 1
      -- Same window: increment
      ELSE api_rate_limits.request_count + 1
    END,
    window_start = CASE
      WHEN api_rate_limits.window_start < v_window_start
      THEN v_window_start
      ELSE api_rate_limits.window_start
    END,
    blocked_until = CASE
      WHEN api_rate_limits.request_count + 1 > p_max_requests
        AND api_rate_limits.window_start >= v_window_start
      THEN now() + (p_window_seconds || ' seconds')::interval
      ELSE api_rate_limits.blocked_until
    END
  RETURNING request_count, window_start, blocked_until
  INTO v_request_count, v_window_start, v_blocked_until;

  -- Determine if request is allowed
  v_allowed := (
    v_request_count <= p_max_requests
    AND (v_blocked_until IS NULL OR v_blocked_until <= now())
  );

  RETURN jsonb_build_object(
    'allowed', v_allowed,
    'request_count', v_request_count,
    'window_start', v_window_start,
    'blocked_until', v_blocked_until
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- check_bill_item_returned_quantity()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_bill_item_returned_quantity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.returned_quantity IS NOT NULL AND NEW.returned_quantity > NEW.quantity THEN
    RAISE EXCEPTION 
      'returned_quantity (%) cannot exceed quantity (%) for bill_item %',
      NEW.returned_quantity, NEW.quantity, NEW.id;
  END IF;
  IF NEW.returned_quantity IS NOT NULL AND NEW.returned_quantity < 0 THEN
    RAISE EXCEPTION 
      'returned_quantity cannot be negative for bill_item %', NEW.id;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_bill_quantities(p_bill_id uuid, p_grn_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_bill_quantities(p_bill_id uuid, p_grn_id uuid, p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_bill_item RECORD;
  v_grn_item RECORD;
  v_mismatches JSONB := '[]'::JSONB;
  v_mismatch JSONB;
  v_valid BOOLEAN := true;
BEGIN
  FOR v_bill_item IN 
    SELECT bi.*, p.name as product_name
    FROM bill_items bi
    LEFT JOIN products p ON p.id = bi.product_id
    WHERE bi.bill_id = p_bill_id AND bi.product_id IS NOT NULL
  LOOP
    SELECT * INTO v_grn_item FROM goods_receipt_items
    WHERE goods_receipt_id = p_grn_id AND product_id = v_bill_item.product_id LIMIT 1;
    
    IF v_grn_item IS NULL THEN
      v_valid := false;
      v_mismatch := jsonb_build_object(
        'product_id', v_bill_item.product_id, 'product_name', v_bill_item.product_name,
        'bill_qty', v_bill_item.quantity, 'grn_qty', 0, 'difference', v_bill_item.quantity,
        'message', 'Product not found in GRN'
      );
      v_mismatches := v_mismatches || v_mismatch;
    ELSIF v_bill_item.quantity > v_grn_item.quantity_accepted THEN
      v_valid := false;
      v_mismatch := jsonb_build_object(
        'product_id', v_bill_item.product_id, 'product_name', v_bill_item.product_name,
        'bill_qty', v_bill_item.quantity, 'grn_qty', v_grn_item.quantity_accepted,
        'difference', v_bill_item.quantity - v_grn_item.quantity_accepted,
        'message', 'Bill quantity exceeds GRN accepted quantity'
      );
      v_mismatches := v_mismatches || v_mismatch;
    END IF;
  END LOOP;
  
  RETURN jsonb_build_object(
    'valid', v_valid,
    'mismatches', v_mismatches,
    'mismatch_count', jsonb_array_length(v_mismatches)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- check_bill_returned_amount()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_bill_returned_amount()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- نتحقق فقط عند وجود قيمة للـ returned_amount
  IF NEW.returned_amount IS NOT NULL AND NEW.total_amount IS NOT NULL THEN
    -- نسمح بتجاوز total_amount في حالة المرتجع الكامل مع تعديل total_amount
    -- لكن returned_amount يجب أن لا تكون سالبة
    IF NEW.returned_amount < 0 THEN
      RAISE EXCEPTION
        'bills.returned_amount cannot be negative for bill %', NEW.id;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_booking_service_inventory(p_booking_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_booking_service_inventory(p_booking_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_booking         public.bookings;
  v_warehouse_id    uuid;
  v_branch_id       uuid;
  v_shortages       jsonb := '[]'::jsonb;
  v_count_short     int := 0;
  v_count_checked   int := 0;
  rec               RECORD;
BEGIN
  SELECT b.* INTO v_booking FROM public.bookings b WHERE b.id = p_booking_id LIMIT 1;
  IF NOT FOUND THEN RETURN jsonb_build_object('ok', false, 'error', 'booking_not_found'); END IF;
  v_branch_id := v_booking.branch_id;

  SELECT br.default_warehouse_id INTO v_warehouse_id FROM public.branches br WHERE br.id = v_branch_id;
  IF v_warehouse_id IS NULL THEN
    SELECT id INTO v_warehouse_id FROM public.warehouses WHERE company_id = v_booking.company_id LIMIT 1;
  END IF;
  IF v_warehouse_id IS NULL THEN
    RETURN jsonb_build_object('ok', true, 'warehouse_id', null, 'note', 'no_warehouse_to_check');
  END IF;

  FOR rec IN
    SELECT sc.product_id, sc.product_name, sc.qty_needed, sc.track_inventory
      FROM public.get_service_consumables(v_booking.service_id, v_booking.quantity) sc
  LOOP
    IF NOT rec.track_inventory THEN CONTINUE; END IF;
    v_count_checked := v_count_checked + 1;
    DECLARE v_available numeric := 0;
    BEGIN
      SELECT COALESCE(available_quantity, 0) INTO v_available
        FROM public.inventory_available_balance
       WHERE company_id = v_booking.company_id
         AND warehouse_id = v_warehouse_id
         AND product_id = rec.product_id
       LIMIT 1;
      IF v_available IS NULL THEN v_available := 0; END IF;
      IF v_available < rec.qty_needed THEN
        v_count_short := v_count_short + 1;
        v_shortages := v_shortages || jsonb_build_object(
          'product_id', rec.product_id, 'product_name', rec.product_name,
          'needed', rec.qty_needed, 'available', v_available,
          'short_by', (rec.qty_needed - v_available)
        );
      END IF;
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'ok', (v_count_short = 0), 'warehouse_id', v_warehouse_id, 'branch_id', v_branch_id,
    'checked_count', v_count_checked, 'short_count', v_count_short, 'shortages', v_shortages
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- check_branch_shipping_provider_same_company()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_branch_shipping_provider_same_company()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_branch_company_id UUID; v_provider_company_id UUID;
BEGIN
  SELECT company_id INTO v_branch_company_id FROM public.branches WHERE id = NEW.branch_id;
  SELECT company_id INTO v_provider_company_id FROM public.shipping_providers WHERE id = NEW.shipping_provider_id;
  IF v_branch_company_id IS DISTINCT FROM v_provider_company_id THEN
    RAISE EXCEPTION 'BRANCH_SHIPPING_PROVIDER_COMPANY: الفرع وشركة الشحن يجب أن يكونا تابعين لنفس الشركة';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_branch_warehouse_stock(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_items jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_branch_warehouse_stock(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_items jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_shortages   jsonb := '[]'::jsonb;
  v_item        jsonb;
  v_product_id  uuid;
  v_requested   numeric;
  v_available   numeric;
  v_name        text;
  v_unit        text;
  v_tracked     boolean;
BEGIN
  IF p_items IS NULL OR jsonb_typeof(p_items) <> 'array' THEN
    RETURN jsonb_build_object('shortages', v_shortages);
  END IF;

  FOR v_item IN SELECT value FROM jsonb_array_elements(p_items) AS t(value)
  LOOP
    v_product_id := NULLIF(v_item->>'product_id', '')::uuid;
    v_requested  := COALESCE((v_item->>'quantity')::numeric, 0);

    IF v_product_id IS NULL OR v_requested <= 0 THEN
      CONTINUE;
    END IF;

    SELECT track_inventory, name, unit
      INTO v_tracked, v_name, v_unit
      FROM public.products
     WHERE id = v_product_id;

    IF NOT COALESCE(v_tracked, false) THEN
      CONTINUE;
    END IF;

    SELECT COALESCE(SUM(quantity_change), 0)
      INTO v_available
      FROM public.inventory_transactions
     WHERE company_id = p_company_id
       AND product_id = v_product_id
       AND branch_id  = p_branch_id
       AND COALESCE(warehouse_id::text, '') = COALESCE(p_warehouse_id::text, '')
       AND COALESCE(is_deleted, false) = false;

    IF v_available < v_requested THEN
      v_shortages := v_shortages || jsonb_build_object(
        'product_id',   v_product_id,
        'product_name', v_name,
        'uom',          COALESCE(v_unit, ''),
        'requested',    v_requested,
        'available',    v_available,
        'missing',      v_requested - v_available
      );
    END IF;
  END LOOP;

  RETURN jsonb_build_object('shortages', v_shortages);
END;
$function$
;

-- ---------------------------------------------------------------
-- check_cancelled_invoice_transactions(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_cancelled_invoice_transactions(p_company_id uuid)
 RETURNS TABLE(transaction_id uuid, invoice_id uuid, invoice_number text, transaction_type text, quantity_change integer, product_name text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ BEGIN RETURN QUERY SELECT it.id, i.id, i.invoice_number, it.transaction_type, it.quantity_change, p.name FROM inventory_transactions it JOIN invoices i ON it.reference_id = i.id JOIN products p ON it.product_id = p.id WHERE it.company_id = p_company_id AND i.status = 'cancelled' AND i.return_status = 'full' AND it.transaction_type = 'sale' AND (it.is_deleted IS NULL OR it.is_deleted = false); END; $function$
;

-- ---------------------------------------------------------------
-- check_chart_of_accounts_drift(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_chart_of_accounts_drift(p_company_id uuid)
 RETURNS TABLE(account_code text, account_name text, sub_type text, drift_reason text)
 LANGUAGE sql
AS $function$
  -- Rows in template that the company doesn't have at all.
  SELECT t.account_code, t.account_name, t.sub_type,
         'missing'::text AS drift_reason
    FROM public.chart_of_accounts_template t
   WHERE NOT EXISTS (
     SELECT 1 FROM public.chart_of_accounts coa
      WHERE coa.company_id = p_company_id
        AND coa.account_code = t.account_code
   )
  UNION ALL
  -- Rows where the company's sub_type drifted from the template
  -- (e.g., legacy hand-edit by an admin). Flag for review; the row
  -- is not auto-corrected because changing sub_type can affect how
  -- existing journal entries are categorised in reports.
  SELECT t.account_code, t.account_name, t.sub_type,
         'sub_type_drift: company=' || COALESCE(coa.sub_type,'NULL') ||
         ' template=' || COALESCE(t.sub_type,'NULL')
    FROM public.chart_of_accounts_template t
    JOIN public.chart_of_accounts coa
      ON coa.company_id = p_company_id
     AND coa.account_code = t.account_code
   WHERE COALESCE(coa.sub_type,'') <> COALESCE(t.sub_type,'');
$function$
;

-- ---------------------------------------------------------------
-- check_cogs_has_revenue(p_company_id uuid, p_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_cogs_has_revenue(p_company_id uuid, p_invoice_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$ DECLARE v_has_revenue BOOLEAN; BEGIN SELECT EXISTS (SELECT 1 FROM journal_entries WHERE company_id = p_company_id AND reference_type = 'invoice' AND reference_id = p_invoice_id AND (is_deleted IS NULL OR is_deleted = false)) INTO v_has_revenue; RETURN v_has_revenue; END; $function$
;

-- ---------------------------------------------------------------
-- check_customer_credit_integrity(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_customer_credit_integrity(p_company_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(cmp_id uuid, severity text, check_name text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company RECORD;
  v_cc_net   numeric;
  v_acct_net numeric;
  v_diff     numeric;
  r          RECORD;
BEGIN
  FOR v_company IN
    SELECT id, name FROM companies
    WHERE (p_company_id IS NULL OR id = p_company_id)
  LOOP
    -- CHECK 1: customer_credits net  vs  account 2155 net (per company)
    SELECT COALESCE(SUM(cc.amount - COALESCE(cc.used_amount,0) - COALESCE(cc.applied_amount,0)), 0)
    INTO v_cc_net
    FROM customer_credits cc
    WHERE cc.company_id = v_company.id AND cc.status = 'active';

    SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount), 0)
    INTO v_acct_net
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.journal_entry_id AND je.status = 'posted'
    JOIN chart_of_accounts coa ON coa.id = jel.account_id
    WHERE coa.company_id = v_company.id
      AND (coa.account_code = '2155'
           OR coa.sub_type IN ('customer_credit','customer_advance'));

    v_diff := ROUND(v_cc_net - v_acct_net, 4);
    IF ABS(v_diff) > 0.01 THEN
      cmp_id     := v_company.id;
      severity   := CASE WHEN ABS(v_diff) > 1 THEN 'high' ELSE 'medium' END;
      check_name := 'cc_vs_2155_mismatch';
      detail     := jsonb_build_object(
        'company_name',     v_company.name,
        'customer_credits', v_cc_net,
        'account_2155',     v_acct_net,
        'difference',       v_diff,
        'hint',             'A customer_credits row exists without its matching accounting journal, or vice-versa.'
      );
      RETURN NEXT;
    END IF;

    -- CHECK 2: overpaid invoices without customer_credit
    FOR r IN
      SELECT i.id, i.invoice_number, i.total_amount, i.paid_amount, i.customer_id
      FROM invoices i
      WHERE i.company_id = v_company.id
        AND i.status NOT IN ('draft','cancelled')
        AND COALESCE(i.returned_amount, 0) < 0.01
        AND COALESCE(i.paid_amount, 0) > COALESCE(i.total_amount, 0) + 0.01
        AND NOT EXISTS (
          SELECT 1 FROM customer_credits cc
          WHERE cc.company_id = i.company_id
            AND cc.customer_id = i.customer_id
            AND cc.reference_type IN ('invoice_overpayment','overpayment')
            AND (cc.reference_id = i.id
                 OR cc.reference_id IN (SELECT p.id FROM payments p WHERE p.invoice_id = i.id))
        )
    LOOP
      cmp_id     := v_company.id;
      severity   := 'high';
      check_name := 'overpaid_invoice_without_credit';
      detail     := jsonb_build_object(
        'invoice_id',     r.id,
        'invoice_number', r.invoice_number,
        'total',          r.total_amount,
        'paid',           r.paid_amount,
        'overpay',        ROUND(r.paid_amount - r.total_amount, 4),
        'customer_id',    r.customer_id,
        'hint',           'Overpaid invoice has no customer_credit row — overpayment trigger did not fire.'
      );
      RETURN NEXT;
    END LOOP;

    -- CHECK 3: customer_credit rows that originated from overpayments must have a posted journal
    FOR r IN
      SELECT cc.id, cc.credit_number, cc.amount, cc.reference_type, cc.reference_id, cc.customer_id
      FROM customer_credits cc
      WHERE cc.company_id = v_company.id
        AND cc.status = 'active'
        AND cc.reference_type IN ('invoice_overpayment','overpayment')
        AND NOT EXISTS (
          SELECT 1 FROM journal_entries je
          WHERE je.company_id = cc.company_id
            AND je.status = 'posted'
            AND je.reference_type = 'credit_from_overpayment'
            AND je.reference_id = cc.reference_id
        )
    LOOP
      cmp_id     := v_company.id;
      severity   := 'high';
      check_name := 'customer_credit_without_journal';
      detail     := jsonb_build_object(
        'credit_id',      r.id,
        'credit_number',  r.credit_number,
        'amount',         r.amount,
        'reference_type', r.reference_type,
        'reference_id',   r.reference_id,
        'customer_id',    r.customer_id,
        'hint',           'customer_credit row exists but no matching credit_from_overpayment journal posted.'
      );
      RETURN NEXT;
    END LOOP;
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_customer_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_customer_delete()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    blocking_invoice_count INTEGER;
    draft_invoice_count INTEGER;
    payment_count INTEGER;
    active_sales_order_count INTEGER;
BEGIN
    -- التحقق من الفواتير بحالات تمنع الحذف (sent, partially_paid, paid)
    SELECT COUNT(*) INTO blocking_invoice_count
    FROM invoices
    WHERE customer_id = OLD.id
    AND LOWER(status) IN ('sent', 'partially_paid', 'paid');

    IF blocking_invoice_count > 0 THEN
        RAISE EXCEPTION 'CUSTOMER_DELETE_BLOCKED: لا يمكن حذف هذا العميل لوجود % فاتورة مرسلة أو مدفوعة مرتبطة به. برجاء مراجعة الفواتير أولاً.', blocking_invoice_count;
    END IF;

    -- التحقق من الفواتير المسودة
    SELECT COUNT(*) INTO draft_invoice_count
    FROM invoices
    WHERE customer_id = OLD.id
    AND LOWER(status) = 'draft';

    IF draft_invoice_count > 0 THEN
        RAISE EXCEPTION 'CUSTOMER_DELETE_BLOCKED: العميل لديه % فاتورة مسودة. يرجى حذفها أولاً قبل حذف العميل.', draft_invoice_count;
    END IF;

    -- التحقق من المدفوعات
    SELECT COUNT(*) INTO payment_count
    FROM payments
    WHERE customer_id = OLD.id;

    IF payment_count > 0 THEN
        RAISE EXCEPTION 'CUSTOMER_DELETE_BLOCKED: العميل لديه % سجل مدفوعات. لا يمكن الحذف.', payment_count;
    END IF;

    -- التحقق من أوامر البيع النشطة (غير مسودة)
    SELECT COUNT(*) INTO active_sales_order_count
    FROM sales_orders
    WHERE customer_id = OLD.id
    AND LOWER(status) != 'draft';

    IF active_sales_order_count > 0 THEN
        RAISE EXCEPTION 'CUSTOMER_DELETE_BLOCKED: العميل لديه % أمر بيع نشط. يرجى إلغاءها أولاً.', active_sales_order_count;
    END IF;

    -- إذا وصلنا هنا، يمكن الحذف
    RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_fiscal_period_locked(p_company_id uuid, p_entry_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_fiscal_period_locked(p_company_id uuid, p_entry_date date)
 RETURNS boolean
 LANGUAGE sql
 STABLE
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.fiscal_periods fp
    WHERE fp.company_id = p_company_id
      AND fp.year = EXTRACT(YEAR FROM p_entry_date)::SMALLINT
      AND fp.month = EXTRACT(MONTH FROM p_entry_date)::SMALLINT
      AND fp.status IN ('closed', 'locked')
  );
$function$
;

-- ---------------------------------------------------------------
-- check_gl_balance_integrity(p_company_id uuid, p_from_date date, p_to_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_gl_balance_integrity(p_company_id uuid, p_from_date date DEFAULT NULL::date, p_to_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(check_name text, result text, total_debit numeric, total_credit numeric, difference numeric, unbalanced_count bigint, status text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  WITH posted_entries AS (
    SELECT je.id, je.entry_date
    FROM journal_entries je
    WHERE je.company_id = p_company_id
      AND je.status     = 'posted'
      AND (je.is_deleted IS NULL OR je.is_deleted = false)
      AND je.deleted_at IS NULL
      AND (p_from_date IS NULL OR je.entry_date >= p_from_date)
      AND je.entry_date <= p_to_date
  ),
  line_totals AS (
    SELECT
      jel.journal_entry_id,
      SUM(jel.debit_amount)  AS total_dr,
      SUM(jel.credit_amount) AS total_cr
    FROM journal_entry_lines jel
    WHERE jel.journal_entry_id IN (SELECT id FROM posted_entries)
    GROUP BY jel.journal_entry_id
  ),
  company_totals AS (
    SELECT
      SUM(total_dr)  AS grand_dr,
      SUM(total_cr)  AS grand_cr,
      COUNT(*) FILTER (WHERE ABS(total_dr - total_cr) > 0.01) AS unbalanced_entries
    FROM line_totals
  )
  SELECT
    'GL Balance Check'::TEXT                         AS check_name,
    CASE WHEN ABS(grand_dr - grand_cr) < 0.01
         THEN 'PASSED' ELSE 'FAILED' END             AS result,
    ROUND(COALESCE(grand_dr, 0), 2)                  AS total_debit,
    ROUND(COALESCE(grand_cr, 0), 2)                  AS total_credit,
    ROUND(ABS(COALESCE(grand_dr, 0) - COALESCE(grand_cr, 0)), 2) AS difference,
    COALESCE(unbalanced_entries, 0)                  AS unbalanced_count,
    CASE WHEN ABS(grand_dr - grand_cr) < 0.01
         THEN 'GL متوازن - جميع القيود صحيحة'
         ELSE 'GL غير متوازن - يوجد خطأ في القيود المحاسبية'
    END                                              AS status
  FROM company_totals;
$function$
;

-- ---------------------------------------------------------------
-- check_governance_scope()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_governance_scope()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- التحقق من أن الفرع ينتمي للشركة
  IF NOT EXISTS (
    SELECT 1 FROM branches 
    WHERE id = NEW.branch_id 
    AND company_id = NEW.company_id
  ) THEN
    RAISE EXCEPTION 'Branch does not belong to company';
  END IF;

  -- التحقق من أن المستودع ينتمي للشركة
  IF NOT EXISTS (
    SELECT 1 FROM warehouses 
    WHERE id = NEW.warehouse_id 
    AND company_id = NEW.company_id
  ) THEN
    RAISE EXCEPTION 'Warehouse does not belong to company';
  END IF;

  -- التحقق من أن مركز التكلفة ينتمي للشركة
  IF NOT EXISTS (
    SELECT 1 FROM cost_centers 
    WHERE id = NEW.cost_center_id 
    AND company_id = NEW.company_id
  ) THEN
    RAISE EXCEPTION 'Cost center does not belong to company';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_inventory_balance_sync()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_inventory_balance_sync()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_company_id UUID;
  v_inventory_account_id UUID;
  v_accounting_balance NUMERIC;
  v_inventory_value NUMERIC;
  v_difference NUMERIC;
BEGIN
  -- Get company_id from the affected record
  IF TG_TABLE_NAME = 'journal_entry_lines' THEN
    SELECT company_id INTO v_company_id
    FROM journal_entries
    WHERE id = NEW.journal_entry_id;
  ELSIF TG_TABLE_NAME = 'products' THEN
    v_company_id := NEW.company_id;
  END IF;
  
  -- Get inventory account for this company
  SELECT id INTO v_inventory_account_id
  FROM chart_of_accounts
  WHERE company_id = v_company_id
    AND sub_type = 'inventory'
  LIMIT 1;
  
  IF v_inventory_account_id IS NULL THEN
    RETURN NEW;
  END IF;
  
  -- Calculate accounting balance
  SELECT COALESCE(SUM(debit_amount - credit_amount), 0)
  INTO v_accounting_balance
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id
  WHERE jel.account_id = v_inventory_account_id
    AND je.is_deleted = false;
  
  -- Calculate inventory value from products
  SELECT COALESCE(SUM(quantity_on_hand * cost_price), 0)
  INTO v_inventory_value
  FROM products
  WHERE company_id = v_company_id
    AND (item_type IS NULL OR item_type = 'product');
  
  -- Calculate difference
  v_difference := ABS(v_inventory_value - v_accounting_balance);
  
  -- Log warning if difference is significant (> 1000)
  IF v_difference > 1000 THEN
    RAISE WARNING 'Inventory value mismatch for company %: Accounting=%, Products=%, Diff=%',
      v_company_id, v_accounting_balance, v_inventory_value, v_difference;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_invoice_entry_before_payment()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_invoice_entry_before_payment()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  invoice_entry_exists BOOLEAN;
  invoice_id UUID;
BEGIN
  IF NEW.reference_type != 'invoice_payment' THEN
    RETURN NEW;
  END IF;
  
  IF NEW.reference_id IS NULL THEN
    RETURN NEW;
  END IF;
  
  invoice_id := NEW.reference_id;
  
  SELECT EXISTS (
    SELECT 1 FROM journal_entries 
    WHERE reference_type = 'invoice' 
    AND reference_id = invoice_id
    AND company_id = NEW.company_id
  ) INTO invoice_entry_exists;
  
  IF NOT invoice_entry_exists THEN
    RAISE WARNING 'تحذير: يتم تسجيل دفعة للفاتورة % بدون قيد فاتورة مسبق', invoice_id;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_invoice_time_lock()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_invoice_time_lock()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_invoice_date DATE; v_time_lock_days INTEGER := 90; v_days_old INTEGER; BEGIN SELECT invoice_date INTO v_invoice_date FROM invoices WHERE id = NEW.source_invoice_id; v_days_old := CURRENT_DATE - v_invoice_date; IF v_days_old > v_time_lock_days THEN RAISE EXCEPTION 'Cannot create debit note for invoice older than % days (invoice is % days old). Contact administrator for override.', v_time_lock_days, v_days_old; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- check_journal_entry_balance()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_journal_entry_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  total_debit DECIMAL(15, 2);
  total_credit DECIMAL(15, 2);
  entry_id UUID;
  line_count INTEGER;
BEGIN
  -- v3.74.263: allow temporary imbalance during an audited RPC. The RPC
  -- explicitly re-checks balance at the end, so this bypass is safe.
  IF coalesce(current_setting('app.allow_direct_post', true), '') = 'true' THEN
    IF TG_OP = 'DELETE' THEN RETURN OLD; END IF;
    RETURN NEW;
  END IF;

  IF TG_OP = 'INSERT' OR TG_OP = 'UPDATE' THEN
    entry_id := NEW.journal_entry_id;
  ELSE
    entry_id := OLD.journal_entry_id;
  END IF;

  SELECT COUNT(*) INTO line_count
  FROM journal_entry_lines
  WHERE journal_entry_id = entry_id;

  IF line_count <= 1 THEN
    IF TG_OP = 'DELETE' THEN RETURN OLD; END IF;
    RETURN NEW;
  END IF;

  SELECT
    COALESCE(SUM(debit_amount), 0),
    COALESCE(SUM(credit_amount), 0)
  INTO total_debit, total_credit
  FROM journal_entry_lines
  WHERE journal_entry_id = entry_id;

  IF ABS(total_debit - total_credit) > 0.01 THEN
    RAISE EXCEPTION 'القيد غير متوازن: المدين = %, الدائن = %. الفرق = %',
      total_debit, total_credit, ABS(total_debit - total_credit);
  END IF;

  IF TG_OP = 'DELETE' THEN RETURN OLD; END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_journal_entry_exists(p_company_id uuid, p_reference_type text, p_reference_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_journal_entry_exists(p_company_id uuid, p_reference_type text, p_reference_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$ DECLARE v_exists BOOLEAN; BEGIN SELECT EXISTS (SELECT 1 FROM journal_entries WHERE company_id = p_company_id AND reference_type = p_reference_type AND reference_id = p_reference_id AND (is_deleted IS NULL OR is_deleted = false)) INTO v_exists; RETURN v_exists; END; $function$
;

-- ---------------------------------------------------------------
-- check_no_overlapping_periods()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_no_overlapping_periods()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_overlapping_count INTEGER;
BEGIN
  -- التحقق من وجود فترات متداخلة لنفس الشركة
  SELECT COUNT(*) INTO v_overlapping_count
  FROM accounting_periods
  WHERE company_id = NEW.company_id
    AND id != COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::UUID)
    AND daterange(period_start, period_end, '[]') && daterange(NEW.period_start, NEW.period_end, '[]');

  IF v_overlapping_count > 0 THEN
    RAISE EXCEPTION 'لا يمكن إنشاء فترة متداخلة مع فترة موجودة لنفس الشركة';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_notification_exists(p_company_id uuid, p_event_key text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_notification_exists(p_company_id uuid, p_event_key text)
 RETURNS TABLE(notification_exists boolean, notification_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_notification_id UUID;
BEGIN
  SELECT id INTO v_notification_id
  FROM notifications
  WHERE company_id = p_company_id
    AND event_key = p_event_key
    AND status != 'archived'
  LIMIT 1;

  IF v_notification_id IS NOT NULL THEN
    RETURN QUERY SELECT TRUE, v_notification_id;
  ELSE
    RETURN QUERY SELECT FALSE, NULL::UUID;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_page_access(p_company_id uuid, p_role text, p_resource text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_page_access(p_company_id uuid, p_role text, p_resource text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ DECLARE v_can_access BOOLEAN; BEGIN SELECT COALESCE(can_access, TRUE) INTO v_can_access FROM company_role_permissions WHERE company_id = p_company_id AND role = p_role AND resource = p_resource; IF NOT FOUND THEN RETURN TRUE; END IF; RETURN v_can_access; END; $function$
;

-- ---------------------------------------------------------------
-- check_page_access(p_user_id uuid, p_company_id uuid, p_resource text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_page_access(p_user_id uuid, p_company_id uuid, p_resource text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_role TEXT;
  v_can_access BOOLEAN := FALSE;
BEGIN
  -- الحصول على دور المستخدم
  SELECT role INTO v_role
  FROM company_members
  WHERE user_id = p_user_id AND company_id = p_company_id;

  IF v_role IS NULL THEN
    RETURN FALSE;
  END IF;

  -- owner و admin لديهم وصول لكل الصفحات
  IF v_role IN ('owner', 'admin') THEN
    RETURN TRUE;
  END IF;

  -- التحقق من can_access
  SELECT COALESCE(crp.can_access, TRUE) INTO v_can_access
  FROM company_role_permissions crp
  WHERE crp.company_id = p_company_id
    AND crp.role = v_role
    AND crp.resource = p_resource;

  -- إذا لم يوجد سجل، نفترض أن الوصول مسموح
  RETURN COALESCE(v_can_access, TRUE);
END;
$function$
;

-- ---------------------------------------------------------------
-- check_paid_invoices_without_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_paid_invoices_without_entries(p_company_id uuid)
 RETURNS TABLE(invoice_id uuid, invoice_number text, status text, total_amount numeric, paid_amount numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ BEGIN RETURN QUERY SELECT i.id, i.invoice_number, i.status, i.total_amount, i.paid_amount FROM invoices i WHERE i.company_id = p_company_id AND i.status IN ('paid', 'partially_paid') AND (i.is_deleted IS NULL OR i.is_deleted = false) AND NOT EXISTS (SELECT 1 FROM journal_entries je WHERE je.reference_id = i.id AND je.reference_type = 'invoice'); END; $function$
;

-- ---------------------------------------------------------------
-- check_period_lock(p_company_id uuid, p_transaction_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_period_lock(p_company_id uuid, p_transaction_date date)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_period_status TEXT;
BEGIN
  -- البحث عن الفترة التي تحتوي على التاريخ
  SELECT status INTO v_period_status
  FROM accounting_periods
  WHERE company_id = p_company_id
    AND p_transaction_date >= period_start
    AND p_transaction_date <= period_end
    AND status IN ('closed', 'locked')
  LIMIT 1;

  -- إذا كانت الفترة مغلقة أو مقفلة، نرجع true (ممنوع)
  RETURN v_period_status IS NOT NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_period_lock_for_date(p_company_id uuid, p_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_period_lock_for_date(p_company_id uuid, p_date date)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_period RECORD;
BEGIN
  SELECT id, period_name, period_start, period_end, status, is_locked INTO v_period
  FROM public.accounting_periods
  WHERE company_id = p_company_id AND p_date BETWEEN period_start AND period_end
    AND (is_locked = TRUE OR status IN ('closed', 'locked')) LIMIT 1;
  IF FOUND THEN
    RETURN jsonb_build_object('is_locked', TRUE, 'period_id', v_period.id,
      'period_name', v_period.period_name, 'period_start', v_period.period_start,
      'period_end', v_period.period_end, 'status', v_period.status);
  END IF;
  RETURN jsonb_build_object('is_locked', FALSE);
END; $function$
;

-- ---------------------------------------------------------------
-- check_permission(p_company_id uuid, p_role text, p_resource text, p_action text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_permission(p_company_id uuid, p_role text, p_resource text, p_action text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ DECLARE v_has_permission BOOLEAN := FALSE; v_perm RECORD; BEGIN SELECT * INTO v_perm FROM company_role_permissions WHERE company_id = p_company_id AND role = p_role AND resource = p_resource LIMIT 1; IF NOT FOUND THEN RETURN FALSE; END IF; IF v_perm.all_access = TRUE THEN RETURN TRUE; END IF; CASE p_action WHEN 'access' THEN v_has_permission := COALESCE(v_perm.can_access, TRUE); WHEN 'read' THEN v_has_permission := v_perm.can_read; WHEN 'write', 'create' THEN v_has_permission := v_perm.can_write; WHEN 'update' THEN v_has_permission := v_perm.can_update; WHEN 'delete' THEN v_has_permission := v_perm.can_delete; ELSE v_has_permission := p_action = ANY(COALESCE(v_perm.allowed_actions, '{}')); END CASE; RETURN COALESCE(v_has_permission, FALSE); END; $function$
;

-- ---------------------------------------------------------------
-- check_permission(p_user_id uuid, p_company_id uuid, p_action text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_permission(p_user_id uuid, p_company_id uuid, p_action text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_role TEXT;
  v_resource TEXT;
  v_has_permission BOOLEAN := FALSE;
BEGIN
  -- الحصول على دور المستخدم في الشركة
  SELECT role INTO v_role
  FROM company_members
  WHERE user_id = p_user_id AND company_id = p_company_id;

  IF v_role IS NULL THEN
    RETURN FALSE;
  END IF;

  -- owner و admin لديهم كل الصلاحيات
  IF v_role IN ('owner', 'admin') THEN
    RETURN TRUE;
  END IF;

  -- استخراج المورد من الـ action
  v_resource := split_part(p_action, ':', 1);

  -- التحقق من الصلاحية
  SELECT EXISTS (
    SELECT 1 FROM company_role_permissions crp
    WHERE crp.company_id = p_company_id
      AND crp.role = v_role
      AND crp.resource = v_resource
      AND (
        crp.all_access = TRUE
        OR p_action = ANY(crp.allowed_actions)
        OR (p_action LIKE '%:read' AND crp.can_read = TRUE)
        OR (p_action LIKE '%:create' AND crp.can_write = TRUE)
        OR (p_action LIKE '%:update' AND crp.can_update = TRUE)
        OR (p_action LIKE '%:delete' AND crp.can_delete = TRUE)
      )
  ) INTO v_has_permission;

  RETURN v_has_permission;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_product_expiry_notifications()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_product_expiry_notifications()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  rec RECORD;
  v_owner uuid;
  v_stage text;
  v_title text;
  v_msg text;
  v_sent int := 0;
  v_role text;
BEGIN
  FOR rec IN
    SELECT l.id AS lot_id, l.company_id, l.branch_id, l.warehouse_id,
           l.expiry_date, l.remaining_quantity,
           p.name AS product_name, p.sku,
           b.name AS branch_name
    FROM public.fifo_cost_lots l
    JOIN public.products p ON p.id = l.product_id
    LEFT JOIN public.branches b ON b.id = l.branch_id
    WHERE l.expiry_date IS NOT NULL
      AND l.remaining_quantity > 0
      AND l.expiry_date <= CURRENT_DATE + 30
  LOOP
    v_stage := CASE WHEN rec.expiry_date < CURRENT_DATE THEN 'expired' ELSE 'expiring' END;

    IF v_stage = 'expired' THEN
      v_title := '⛔ انتهت صلاحية دفعة: ' || rec.product_name;
      v_msg := 'انتهت صلاحية دفعة من «' || rec.product_name || '» (' || COALESCE(rec.sku,'') || ') فى '
        || TO_CHAR(rec.expiry_date, 'YYYY-MM-DD')
        || ' — الكمية المتبقية: ' || rec.remaining_quantity
        || COALESCE(' · الفرع: ' || rec.branch_name, '')
        || '. يُنصح بحصرها وإهلاكها عبر دورة إهلاك المخزون.';
    ELSE
      v_title := '⚠️ اقتراب انتهاء صلاحية: ' || rec.product_name;
      v_msg := 'دفعة من «' || rec.product_name || '» (' || COALESCE(rec.sku,'') || ') تنتهى صلاحيتها فى '
        || TO_CHAR(rec.expiry_date, 'YYYY-MM-DD')
        || ' (خلال ' || (rec.expiry_date - CURRENT_DATE) || ' يوم)'
        || ' — الكمية المتبقية: ' || rec.remaining_quantity
        || COALESCE(' · الفرع: ' || rec.branch_name, '')
        || '. يُنصح بتصريفها أولاً.';
    END IF;

    SELECT user_id INTO v_owner FROM public.company_members
    WHERE company_id = rec.company_id AND role = 'owner' LIMIT 1;

    FOREACH v_role IN ARRAY ARRAY['store_manager','warehouse_manager','manager','owner'] LOOP
      BEGIN
        PERFORM public.create_notification(
          rec.company_id, 'inventory', rec.lot_id,
          v_title, v_msg,
          v_owner, rec.branch_id, NULL, rec.warehouse_id,
          v_role, NULL,
          CASE WHEN v_stage = 'expired' THEN 'high' ELSE 'normal' END,
          'lot_expiry:' || rec.lot_id || ':' || v_stage || ':' || v_role,
          CASE WHEN v_stage = 'expired' THEN 'error' ELSE 'warning' END,
          'inventory');
        v_sent := v_sent + 1;
      EXCEPTION WHEN OTHERS THEN
        -- notification failures must never kill the sweep
        NULL;
      END;
    END LOOP;
  END LOOP;

  RETURN jsonb_build_object('success', true, 'notifications_attempted', v_sent, 'ran_at', NOW());
END;
$function$
;

-- ---------------------------------------------------------------
-- check_purchase_return_item_quantity()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_purchase_return_item_quantity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_bill_item_qty NUMERIC;
  v_active_sum    NUMERIC;
  v_self_pr_id    UUID := NEW.purchase_return_id;
BEGIN
  -- No bill_item → can't validate against a specific line; let it through.
  IF NEW.bill_item_id IS NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.quantity IS NULL OR NEW.quantity <= 0 THEN
    RETURN NEW;
  END IF;

  -- Serialize concurrent return-item inserts on this bill_item so two
  -- transactions can't both pass the check before either commits.
  PERFORM pg_advisory_xact_lock(
    hashtext('purchase_return_item_qty_check:' || NEW.bill_item_id::text)
  );

  -- Lock the bill_item too — both for the quantity read and because the
  -- existing trigger pipeline expects rows to be reservable.
  SELECT quantity INTO v_bill_item_qty
  FROM bill_items
  WHERE id = NEW.bill_item_id
  FOR UPDATE;

  IF NOT FOUND THEN
    -- Don't block: the FK will fail elsewhere with a clearer error.
    RETURN NEW;
  END IF;

  -- Sum the quantity of every *other* active purchase_return_item on this
  -- bill_item. "Active" = parent return is not rejected/cancelled.
  -- On UPDATE, exclude the row being updated (by id).
  SELECT COALESCE(SUM(pri.quantity), 0)
  INTO v_active_sum
  FROM purchase_return_items pri
  JOIN purchase_returns pr ON pr.id = pri.purchase_return_id
  WHERE pri.bill_item_id = NEW.bill_item_id
    AND pr.workflow_status NOT IN ('rejected', 'warehouse_rejected', 'cancelled')
    AND pri.id IS DISTINCT FROM NEW.id;

  IF (v_active_sum + NEW.quantity) > v_bill_item_qty THEN
    RAISE EXCEPTION
      'لا يُمكِن إِنشاء مَرتَجَع بكَمية % لِهَذا الصِّنف. كَمية الفاتورَة: %، وَمَجموع المَرتَجَعات السَّابِقَة (المُعتَمَدَة وَالتى قَيد الاعتماد): %. الكَمية المُتاحَة لِلمَرتَجَع: %.',
      NEW.quantity, v_bill_item_qty, v_active_sum,
      GREATEST(v_bill_item_qty - v_active_sum, 0)
      USING ERRCODE = 'check_violation';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_purchase_return_item_warehouse_stock()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_purchase_return_item_warehouse_stock()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_warehouse_id  UUID; v_company_id UUID; v_current_stock NUMERIC;
  v_pending_pr NUMERIC; v_pending_inv NUMERIC; v_pending_xfer NUMERIC;
  v_pending_mmia NUMERIC; v_reserved NUMERIC; v_available NUMERIC;
BEGIN
  IF NEW.product_id IS NULL OR NEW.quantity IS NULL OR NEW.quantity <= 0 THEN
    RETURN NEW;
  END IF;
  v_warehouse_id := NEW.warehouse_id;
  IF v_warehouse_id IS NULL THEN
    SELECT warehouse_id, company_id INTO v_warehouse_id, v_company_id
    FROM purchase_returns WHERE id = NEW.purchase_return_id;
  ELSE
    SELECT company_id INTO v_company_id FROM purchase_returns WHERE id = NEW.purchase_return_id;
  END IF;
  IF v_warehouse_id IS NULL OR v_company_id IS NULL THEN RETURN NEW; END IF;

  PERFORM pg_advisory_xact_lock(
    hashtext('purchase_return_warehouse_stock:' || v_warehouse_id::text || ':' || NEW.product_id::text)
  );

  SELECT COALESCE(SUM(quantity_change), 0) INTO v_current_stock
    FROM inventory_transactions
   WHERE company_id = v_company_id AND product_id = NEW.product_id
     AND warehouse_id = v_warehouse_id AND COALESCE(is_deleted, false) = false;

  SELECT COALESCE(SUM(pri.quantity), 0) INTO v_pending_pr
    FROM purchase_return_items pri JOIN purchase_returns pr ON pr.id = pri.purchase_return_id
   WHERE pri.product_id = NEW.product_id
     AND COALESCE(pri.warehouse_id, pr.warehouse_id) = v_warehouse_id
     AND pr.workflow_status IN ('pending_admin_approval','pending_approval','pending_warehouse','partial_approval')
     AND pri.id IS DISTINCT FROM NEW.id;

  SELECT COALESCE(SUM(ii.quantity), 0) INTO v_pending_inv
    FROM invoice_items ii JOIN invoices i ON i.id = ii.invoice_id
   WHERE i.company_id = v_company_id AND ii.product_id = NEW.product_id
     AND i.warehouse_id = v_warehouse_id
     AND i.warehouse_status = 'pending' AND i.status IN ('sent','partially_paid','paid');

  SELECT COALESCE(SUM(iti.quantity_sent), 0) INTO v_pending_xfer
    FROM inventory_transfer_items iti JOIN inventory_transfers it ON it.id = iti.transfer_id
   WHERE it.company_id = v_company_id AND iti.product_id = NEW.product_id
     AND it.source_warehouse_id = v_warehouse_id AND (it.deleted_at IS NULL)
     AND LOWER(COALESCE(it.status, '')) IN ('pending','approved','in_transit');

  SELECT COALESCE(SUM(po.planned_quantity * bl.quantity_per * (1 + COALESCE(bl.scrap_percent, 0) / 100.0)), 0)
    INTO v_pending_mmia
    FROM manufacturing_material_issue_approvals mmia
    JOIN manufacturing_production_orders po ON po.id = mmia.production_order_id
    JOIN manufacturing_bom_lines bl ON bl.bom_version_id = po.bom_version_id
   WHERE mmia.company_id = v_company_id
     AND mmia.warehouse_id = v_warehouse_id
     AND bl.component_product_id = NEW.product_id
     AND LOWER(COALESCE(mmia.status, '')) IN (
       'pending_admin_approval','pending_approval','pending_warehouse','partial_approval','partially_approved'
     );

  v_reserved  := v_pending_pr + v_pending_inv + v_pending_xfer + v_pending_mmia;
  v_available := v_current_stock - v_reserved;

  IF NEW.quantity > v_available THEN
    RAISE EXCEPTION
      'لا يَكفى المَخزون. المُتَوَفِّر: %، مَحجوز لمرتجعات: %، مَحجوز لفواتير: %، مَحجوز لتحويلات: %، مَحجوز لطَلَبات صَرف تصنيع: %، المُتاح: %، المَطلوب: %.',
      v_current_stock, v_pending_pr, v_pending_inv, v_pending_xfer, v_pending_mmia,
      GREATEST(v_available, 0), NEW.quantity
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_sales_return_request_quantity()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_sales_return_request_quantity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_item             JSONB;
  v_invoice_item_id  UUID;
  v_new_qty          NUMERIC;
  v_invoice_item_qty NUMERIC;
  v_committed_sum    NUMERIC;
  v_pending_sum      NUMERIC;
  v_total            NUMERIC;
BEGIN
  -- Only validate when the items JSONB or status actually changed.
  -- (BEFORE INSERT always passes through; this matters for UPDATEs.)
  IF TG_OP = 'UPDATE'
     AND OLD.items IS NOT DISTINCT FROM NEW.items
     AND OLD.status IS NOT DISTINCT FROM NEW.status
  THEN
    RETURN NEW;
  END IF;

  -- Skip the check when the request is being moved into a terminal /
  -- non-reserving state. Items in this state no longer compete for
  -- invoice quantity: posted ones live in sales_return_items, rejected
  -- ones are released.
  IF NEW.status NOT IN ('pending', 'pending_approval_level_1', 'pending_warehouse_approval') THEN
    RETURN NEW;
  END IF;

  -- Nothing to check if items is empty or malformed.
  IF NEW.items IS NULL OR jsonb_typeof(NEW.items) <> 'array' THEN
    RETURN NEW;
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(NEW.items) LOOP
    v_invoice_item_id := NULLIF(v_item->>'id', '')::UUID;
    v_new_qty := COALESCE((v_item->>'qtyToReturn')::NUMERIC, 0)
               + COALESCE((v_item->>'qtyCreditOnly')::NUMERIC, 0);

    IF v_invoice_item_id IS NULL OR v_new_qty <= 0 THEN
      CONTINUE;
    END IF;

    -- Serialize concurrent requests on the same invoice line.
    PERFORM pg_advisory_xact_lock(
      hashtext('sales_return_request_qty_check:' || v_invoice_item_id::text)
    );

    -- Read the invoice line's quantity.
    SELECT quantity INTO v_invoice_item_qty
    FROM invoice_items
    WHERE id = v_invoice_item_id
    FOR UPDATE;

    IF NOT FOUND THEN
      -- Unknown line; let the downstream FK / executor handle it.
      CONTINUE;
    END IF;

    -- Committed: every sales_return_items row already posted for this
    -- invoice line.
    SELECT COALESCE(SUM(sri.quantity), 0)
    INTO v_committed_sum
    FROM sales_return_items sri
    WHERE sri.invoice_item_id = v_invoice_item_id;

    -- Pending: JSONB items across all OTHER active requests on this
    -- invoice line. Excludes self (NEW.id), rejected_* statuses and
    -- approved_completed (already in v_committed_sum).
    SELECT COALESCE(SUM(
      COALESCE((other_item->>'qtyToReturn')::NUMERIC, 0)
      + COALESCE((other_item->>'qtyCreditOnly')::NUMERIC, 0)
    ), 0)
    INTO v_pending_sum
    FROM sales_return_requests r,
         jsonb_array_elements(r.items) AS other_item
    WHERE r.id IS DISTINCT FROM NEW.id
      AND r.status IN ('pending', 'pending_approval_level_1', 'pending_warehouse_approval')
      AND NULLIF(other_item->>'id', '')::UUID = v_invoice_item_id;

    v_total := v_committed_sum + v_pending_sum + v_new_qty;

    IF v_total > v_invoice_item_qty THEN
      RAISE EXCEPTION
        'لا يُمكِن إِنشاء مَرتَجَع بَيع بكَمية % لِهَذا الصِّنف. كَمية الفاتورَة: %، المَرتَجَعات المُعتَمَدَة: %، المَرتَجَعات قَيد الاعتماد: %. الكَمية المُتاحَة لِلمَرتَجَع: %.',
        v_new_qty, v_invoice_item_qty, v_committed_sum, v_pending_sum,
        GREATEST(v_invoice_item_qty - v_committed_sum - v_pending_sum, 0)
        USING ERRCODE = 'check_violation';
    END IF;
  END LOOP;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_shipping_provider_branch()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_shipping_provider_branch()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NEW.shipping_provider_id IS NULL THEN RETURN NEW; END IF;
  IF NEW.branch_id IS NULL THEN RAISE EXCEPTION 'SHIPPING_PROVIDER_BRANCH: branch_id مطلوب عند تحديد شركة الشحن'; END IF;
  IF NOT public.is_shipping_provider_allowed_for_branch(NEW.branch_id, NEW.shipping_provider_id, NEW.company_id) THEN
    RAISE EXCEPTION 'SHIPPING_PROVIDER_BRANCH: شركة الشحن المختارة غير مرتبطة بهذا الفرع';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_stock_mismatch(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_stock_mismatch(p_company_id uuid)
 RETURNS TABLE(product_id uuid, product_name text, recorded_qty integer, calculated_qty bigint, difference bigint)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ BEGIN RETURN QUERY SELECT p.id, p.name, p.quantity_on_hand, COALESCE(SUM(it.quantity_change), 0)::BIGINT as calc_qty, (p.quantity_on_hand - COALESCE(SUM(it.quantity_change), 0))::BIGINT as diff FROM products p LEFT JOIN inventory_transactions it ON it.product_id = p.id AND (it.is_deleted IS NULL OR it.is_deleted = false) WHERE p.company_id = p_company_id GROUP BY p.id, p.name, p.quantity_on_hand HAVING p.quantity_on_hand != COALESCE(SUM(it.quantity_change), 0); END; $function$
;

-- ---------------------------------------------------------------
-- check_unbalanced_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_unbalanced_entries(p_company_id uuid)
 RETURNS TABLE(journal_entry_id uuid, entry_date date, description text, total_debit numeric, total_credit numeric, difference numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ BEGIN RETURN QUERY SELECT je.id, je.entry_date, je.description, COALESCE(SUM(jel.debit_amount), 0) as t_debit, COALESCE(SUM(jel.credit_amount), 0) as t_credit, ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) as diff FROM journal_entries je LEFT JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id WHERE je.company_id = p_company_id GROUP BY je.id, je.entry_date, je.description HAVING ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) > 0.01; END; $function$
;

-- ---------------------------------------------------------------
-- check_user_access_to_record(p_user_id uuid, p_company_id uuid, p_resource_type text, p_record_created_by uuid, p_record_branch_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_user_access_to_record(p_user_id uuid, p_company_id uuid, p_resource_type text, p_record_created_by uuid, p_record_branch_id uuid DEFAULT NULL::uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user_role TEXT;
  v_user_branch_id UUID;
  v_has_sharing BOOLEAN;
  v_has_branch_access BOOLEAN;
BEGIN
  SELECT role, branch_id INTO v_user_role, v_user_branch_id
  FROM company_members
  WHERE company_id = p_company_id AND user_id = p_user_id;

  IF v_user_role IN ('owner', 'admin') THEN
    RETURN TRUE;
  END IF;

  IF p_record_created_by = p_user_id THEN
    RETURN TRUE;
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM permission_sharing ps
    WHERE ps.company_id = p_company_id
    AND ps.grantee_user_id = p_user_id
    AND ps.grantor_user_id = p_record_created_by
    AND (ps.resource_type = p_resource_type OR ps.resource_type = 'all')
    AND ps.is_active = TRUE
    AND (ps.expires_at IS NULL OR ps.expires_at > NOW())
  ) INTO v_has_sharing;

  IF v_has_sharing THEN
    RETURN TRUE;
  END IF;

  IF p_record_branch_id IS NOT NULL THEN
    SELECT EXISTS (
      SELECT 1 FROM user_branch_access uba
      WHERE uba.company_id = p_company_id
      AND uba.user_id = p_user_id
      AND uba.branch_id = p_record_branch_id
      AND uba.is_active = TRUE
      AND (
        (p_resource_type = 'customers' AND uba.can_view_customers = TRUE) OR
        (p_resource_type = 'sales_orders' AND uba.can_view_orders = TRUE) OR
        (p_resource_type = 'invoices' AND uba.can_view_invoices = TRUE)
      )
    ) INTO v_has_branch_access;

    IF v_has_branch_access THEN
      RETURN TRUE;
    END IF;
  END IF;

  IF v_user_role = 'manager' AND p_record_branch_id = v_user_branch_id THEN
    RETURN TRUE;
  END IF;

  RETURN FALSE;
END;
$function$
;

-- ---------------------------------------------------------------
-- check_user_access_to_record(p_user_id uuid, p_company_id uuid, p_resource_type text, p_record_owner_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_user_access_to_record(p_user_id uuid, p_company_id uuid, p_resource_type text, p_record_owner_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_member RECORD;
  v_sharing RECORD;
  v_result JSONB;
BEGIN
  -- الحصول على معلومات العضوية
  SELECT * INTO v_member FROM company_members 
  WHERE company_id = p_company_id AND user_id = p_user_id;
  
  -- إذا كان مالك أو مدير
  IF v_member.role IN ('owner', 'admin', 'manager') THEN
    RETURN jsonb_build_object('has_access', TRUE, 'can_view', TRUE, 'can_edit', TRUE, 'can_delete', TRUE, 'source', 'role');
  END IF;
  
  -- إذا كان صاحب السجل
  IF p_user_id = p_record_owner_id THEN
    RETURN jsonb_build_object('has_access', TRUE, 'can_view', TRUE, 'can_edit', TRUE, 'can_delete', TRUE, 'source', 'owner');
  END IF;
  
  -- التحقق من الصلاحيات المشتركة
  SELECT * INTO v_sharing FROM permission_sharing 
  WHERE company_id = p_company_id 
    AND grantor_user_id = p_record_owner_id 
    AND grantee_user_id = p_user_id
    AND (resource_type = p_resource_type OR resource_type = 'all')
    AND is_active = TRUE
    AND (expires_at IS NULL OR expires_at > NOW());
    
  IF FOUND THEN
    RETURN jsonb_build_object(
      'has_access', TRUE, 
      'can_view', v_sharing.can_view, 
      'can_edit', v_sharing.can_edit, 
      'can_delete', v_sharing.can_delete,
      'source', 'sharing'
    );
  END IF;
  
  -- لا توجد صلاحية
  RETURN jsonb_build_object('has_access', FALSE, 'can_view', FALSE, 'can_edit', FALSE, 'can_delete', FALSE, 'source', 'none');
END;
$function$
;

-- ---------------------------------------------------------------
-- check_user_role(p_company_id uuid, p_user_id uuid, p_required_roles text[])
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_user_role(p_company_id uuid, p_user_id uuid, p_required_roles text[])
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN EXISTS (
    SELECT 1 FROM company_members cm
    WHERE cm.company_id = p_company_id
    AND cm.user_id = p_user_id
    AND cm.role = ANY(p_required_roles)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- check_username_available(p_username text, p_exclude_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_username_available(p_username text, p_exclude_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_clean TEXT;
  v_exists BOOLEAN;
BEGIN
  v_clean := LOWER(TRIM(p_username));
  IF LENGTH(v_clean) < 3 THEN
    RETURN jsonb_build_object('available', false, 'error', 'اسم المستخدم قصير جداً');
  END IF;
  IF LENGTH(v_clean) > 30 THEN
    RETURN jsonb_build_object('available', false, 'error', 'اسم المستخدم طويل جداً');
  END IF;
  IF v_clean !~ '^[a-z0-9_]+$' THEN
    RETURN jsonb_build_object('available', false, 'error', 'يُسمح فقط بالأحرف الإنجليزية الصغيرة والأرقام');
  END IF;
  SELECT EXISTS (
    SELECT 1 FROM user_profiles
    WHERE username = v_clean
    AND (p_exclude_user_id IS NULL OR user_id != p_exclude_user_id)
  ) INTO v_exists;
  IF v_exists THEN
    RETURN jsonb_build_object('available', false, 'error', 'اسم المستخدم مستخدم بالفعل');
  END IF;
  RETURN jsonb_build_object('available', true, 'username', v_clean);
END;
$function$
;

-- ---------------------------------------------------------------
-- check_wrong_return_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.check_wrong_return_entries(p_company_id uuid)
 RETURNS TABLE(journal_entry_id uuid, invoice_id uuid, invoice_number text, invoice_status text, wrong_account_name text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ BEGIN RETURN QUERY SELECT je.id, i.id, i.invoice_number, i.status, ca.account_name FROM journal_entries je JOIN invoices i ON je.reference_id = i.id JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id JOIN chart_of_accounts ca ON jel.account_id = ca.id WHERE je.company_id = p_company_id AND je.reference_type = 'sales_return' AND i.paid_amount = 0 AND ca.sub_type = 'customer_credit' AND jel.credit_amount > 0; END; $function$
;

-- ---------------------------------------------------------------
-- claim_next_job(p_job_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.claim_next_job(p_job_type text DEFAULT NULL::text)
 RETURNS SETOF jobs_queue
 LANGUAGE sql
AS $function$
  UPDATE jobs_queue
  SET status = 'processing', started_at = now()
  WHERE id = (
    SELECT id FROM jobs_queue
    WHERE status IN ('pending')
      AND scheduled_at <= now()
      AND (p_job_type IS NULL OR job_type = p_job_type)
    ORDER BY priority ASC, scheduled_at ASC
    LIMIT 1
    FOR UPDATE SKIP LOCKED
  )
  RETURNING *;
$function$
;

-- ---------------------------------------------------------------
-- cleanup_expired_idempotency_keys()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cleanup_expired_idempotency_keys()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_deleted INT;
BEGIN
  DELETE FROM public.idempotency_keys WHERE expires_at < NOW() AND status IN ('completed', 'failed');
  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END; $function$
;

-- ---------------------------------------------------------------
-- cleanup_inventory_on_journal_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cleanup_inventory_on_journal_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  DELETE FROM inventory_transactions WHERE journal_entry_id = OLD.id;
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- cleanup_inventory_on_journal_soft_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cleanup_inventory_on_journal_soft_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NEW.is_deleted = TRUE AND COALESCE(OLD.is_deleted, FALSE) = FALSE THEN
    UPDATE inventory_transactions
      SET is_deleted = TRUE,
          deleted_at = NOW()
    WHERE journal_entry_id = NEW.id;
  END IF;
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- cleanup_old_security_events(days_to_keep integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cleanup_old_security_events(days_to_keep integer DEFAULT 7)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_deleted_count INTEGER;
BEGIN
  -- ✅ حذف الأحداث الأقدم من days_to_keep أيام
  DELETE FROM user_security_events
  WHERE created_at < NOW() - (days_to_keep || ' days')::INTERVAL;
  
  GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
  
  RETURN v_deleted_count;
END;
$function$
;

