-- ---------------------------------------------------------------
-- cleanup_permission_sharing_on_member_leave()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cleanup_permission_sharing_on_member_leave()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE public.permission_sharing
  SET is_active = false,
      notes = COALESCE(notes, '') ||
              CASE WHEN COALESCE(notes,'') = '' THEN '' ELSE E'\n' END ||
              '[auto-deactivated v3.70.0: member left company on ' ||
              to_char(now(), 'YYYY-MM-DD HH24:MI:SS') || ']'
  WHERE company_id = OLD.company_id
    AND is_active = true
    AND (grantor_user_id = OLD.user_id OR grantee_user_id = OLD.user_id);

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- close_accounting_period(p_period_id uuid, p_user_id uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.close_accounting_period(p_period_id uuid, p_user_id uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_period RECORD;
  v_result JSONB;
BEGIN
  -- جلب بيانات الفترة
  SELECT * INTO v_period
  FROM accounting_periods
  WHERE id = p_period_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'الفترة غير موجودة'
    );
  END IF;

  -- التحقق من أن الفترة ليست مغلقة بالفعل
  IF v_period.status IN ('closed', 'locked') THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'الفترة مغلقة بالفعل'
    );
  END IF;

  -- إغلاق الفترة
  UPDATE accounting_periods
  SET
    status = 'closed',
    closed_by = p_user_id,
    closed_at = NOW(),
    notes = COALESCE(p_notes, notes),
    updated_at = NOW()
  WHERE id = p_period_id;

  RETURN jsonb_build_object(
    'success', true,
    'message', 'تم إغلاق الفترة بنجاح',
    'period_id', p_period_id
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- close_accounting_period(p_period_id uuid, p_closed_by uuid, p_retained_earnings_account_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.close_accounting_period(p_period_id uuid, p_closed_by uuid, p_retained_earnings_account_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_period RECORD;
  v_company_id UUID;
  v_je_id UUID;
  v_total_revenue NUMERIC := 0;
  v_total_expense NUMERIC := 0;
  v_net_income NUMERIC := 0;
  v_account_balance RECORD;
  v_lines_to_insert JSONB[] := ARRAY[]::JSONB[];
BEGIN
  SELECT * INTO v_period FROM accounting_periods WHERE id = p_period_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Accounting period not found.'; END IF;
  
  v_company_id := v_period.company_id;

  IF v_period.status = 'closed' THEN RAISE EXCEPTION 'Period is already closed.'; END IF;

  IF p_retained_earnings_account_id IS NOT NULL THEN
    
    -- Create Header for Closing Entry
    INSERT INTO journal_entries (
      company_id,
      entry_date, 
      description,
      reference_type,
      status,
      is_closing_entry
    ) VALUES (
      v_company_id,
      v_period.period_end,
      'Closing Entry - ' || v_period.period_name,
      'closing_entry',
      'posted',
      TRUE
    ) RETURNING id INTO v_je_id;

    -- Collect all closing lines (Revenue)
    FOR v_account_balance IN 
      SELECT 
        jel.account_id, 
        SUM(COALESCE(jel.credit_amount, 0) - COALESCE(jel.debit_amount, 0)) as balance
      FROM journal_entry_lines jel
      JOIN journal_entries je ON jel.journal_entry_id = je.id
      JOIN chart_of_accounts coa ON jel.account_id = coa.id
      WHERE je.company_id = v_company_id
        AND je.status = 'posted'
        AND je.is_closing_entry = FALSE
        AND je.entry_date BETWEEN v_period.period_start AND v_period.period_end
        AND coa.account_type = 'income'
      GROUP BY jel.account_id
      HAVING SUM(COALESCE(jel.credit_amount, 0) - COALESCE(jel.debit_amount, 0)) <> 0
    LOOP
      v_lines_to_insert := array_append(v_lines_to_insert, jsonb_build_object(
        'account_id', v_account_balance.account_id,
        'debit_amount', COALESCE(v_account_balance.balance, 0),
        'credit_amount', 0,
        'description', 'Closing Revenue: ' || v_period.period_name
      ));
      v_total_revenue := v_total_revenue + COALESCE(v_account_balance.balance, 0);
    END LOOP;

    -- Collect all closing lines (Expense)
    FOR v_account_balance IN 
      SELECT 
        jel.account_id, 
        SUM(COALESCE(jel.debit_amount, 0) - COALESCE(jel.credit_amount, 0)) as balance
      FROM journal_entry_lines jel
      JOIN journal_entries je ON jel.journal_entry_id = je.id
      JOIN chart_of_accounts coa ON jel.account_id = coa.id
      WHERE je.company_id = v_company_id
        AND je.status = 'posted'
        AND je.is_closing_entry = FALSE
        AND je.entry_date BETWEEN v_period.period_start AND v_period.period_end
        AND coa.account_type = 'expense'
      GROUP BY jel.account_id
      HAVING SUM(COALESCE(jel.debit_amount, 0) - COALESCE(jel.credit_amount, 0)) <> 0
    LOOP
      v_lines_to_insert := array_append(v_lines_to_insert, jsonb_build_object(
        'account_id', v_account_balance.account_id,
        'debit_amount', 0,
        'credit_amount', COALESCE(v_account_balance.balance, 0),
        'description', 'Closing Expense: ' || v_period.period_name
      ));
      v_total_expense := v_total_expense + COALESCE(v_account_balance.balance, 0);
    END LOOP;

    -- Calculate Net Income and add RE line
    v_net_income := v_total_revenue - v_total_expense;

    IF v_net_income > 0 THEN
      v_lines_to_insert := array_append(v_lines_to_insert, jsonb_build_object(
        'account_id', p_retained_earnings_account_id,
        'debit_amount', 0,
        'credit_amount', v_net_income,
        'description', 'Net Income Allocation'
      ));
    ELSIF v_net_income < 0 THEN
      v_lines_to_insert := array_append(v_lines_to_insert, jsonb_build_object(
        'account_id', p_retained_earnings_account_id,
        'debit_amount', ABS(v_net_income),
        'credit_amount', 0,
        'description', 'Net Loss Allocation'
      ));
    END IF;

    -- Insert all lines at once
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
    SELECT 
      v_je_id,
      (line->>'account_id')::uuid,
      (line->>'debit_amount')::numeric,
      (line->>'credit_amount')::numeric,
      line->>'description'
    FROM unnest(v_lines_to_insert) AS line;

  END IF;

  -- Implement Locking
  UPDATE accounting_periods 
  SET 
    status = 'closed', 
    is_locked = TRUE, 
    closed_by = p_closed_by, 
    closed_at = NOW(),
    journal_entry_id = v_je_id
  WHERE id = p_period_id;

  RETURN jsonb_build_object(
    'success', true, 
    'journal_entry_id', v_je_id,
    'net_income', v_net_income
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- close_fiscal_period(p_company_id uuid, p_year smallint, p_month smallint, p_closed_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.close_fiscal_period(p_company_id uuid, p_year smallint, p_month smallint, p_closed_by uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_id UUID;
  v_old RECORD;
BEGIN
  INSERT INTO public.fiscal_periods (company_id, year, month, status, closed_at, closed_by, updated_at)
  VALUES (p_company_id, p_year, p_month, 'closed', NOW(), p_closed_by, NOW())
  ON CONFLICT (company_id, year, month)
  DO UPDATE SET status = 'closed', closed_at = NOW(), closed_by = p_closed_by, updated_at = NOW()
  RETURNING id INTO v_id;

  SELECT * INTO v_old FROM public.fiscal_periods WHERE id = v_id;
  PERFORM public.system_audit_log_insert(
    p_closed_by, p_company_id, 'close_period', 'fiscal_period', v_id::TEXT,
    NULL, to_jsonb(v_old), jsonb_build_object('year', p_year, 'month', p_month)
  );
  RETURN v_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- close_manufacturing_production_order_reservations_atomic(p_company_id uuid, p_production_order_id uuid, p_updated_by uuid, p_mode text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.close_manufacturing_production_order_reservations_atomic(p_company_id uuid, p_production_order_id uuid, p_updated_by uuid, p_mode text DEFAULT 'auto'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order RECORD;
  v_reservation RECORD;
  v_mode TEXT := COALESCE(NULLIF(BTRIM(COALESCE(p_mode, '')), ''), 'auto');
  v_released_allocation_count INTEGER := 0;
  v_requested_qty NUMERIC(18,4);
  v_reserved_qty NUMERIC(18,4);
  v_consumed_qty NUMERIC(18,4);
  v_released_qty NUMERIC(18,4);
  v_new_status TEXT;
  v_close_reason TEXT;
BEGIN
  IF v_mode NOT IN ('auto', 'complete', 'cancel') THEN
    RAISE EXCEPTION 'Unsupported close-reservations mode. mode=%', v_mode;
  END IF;

  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order not found or not in company. production_order_id=%', p_production_order_id;
  END IF;

  IF v_mode = 'auto' THEN
    CASE v_order.status
      WHEN 'completed' THEN v_mode := 'complete';
      WHEN 'cancelled' THEN v_mode := 'cancel';
      ELSE
        RAISE EXCEPTION 'Reservations can be auto-closed only when the production order is completed or cancelled. production_order_id=%, status=%',
          p_production_order_id, v_order.status;
    END CASE;
  ELSIF v_mode = 'complete' AND v_order.status <> 'completed' THEN
    RAISE EXCEPTION 'Complete-mode reservation close requires a completed production order. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  ELSIF v_mode = 'cancel' AND v_order.status <> 'cancelled' THEN
    RAISE EXCEPTION 'Cancel-mode reservation close requires a cancelled production order. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  END IF;

  SELECT *
    INTO v_reservation
    FROM public.inventory_reservations
   WHERE company_id = p_company_id
     AND source_type = 'production_order'
     AND source_id = p_production_order_id
     AND status NOT IN ('consumed', 'released', 'cancelled', 'expired', 'closed')
   ORDER BY created_at DESC
   LIMIT 1
   FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', true,
      'production_order_id', p_production_order_id,
      'noop', true,
      'mode', v_mode
    );
  END IF;

  UPDATE public.inventory_reservation_allocations
     SET released_qty = released_qty + GREATEST(allocated_qty - consumed_qty - released_qty, 0),
         status = CASE
           WHEN GREATEST(allocated_qty - consumed_qty - released_qty, 0) > 0
             THEN CASE WHEN consumed_qty > 0 THEN 'consumed' ELSE 'released' END
           WHEN consumed_qty > 0 THEN 'consumed'
           ELSE status
         END,
         updated_by = p_updated_by
   WHERE reservation_id = v_reservation.id
     AND GREATEST(allocated_qty - consumed_qty - released_qty, 0) > 0;

  GET DIAGNOSTICS v_released_allocation_count = ROW_COUNT;

  SELECT
    requested_qty,
    reserved_qty,
    consumed_qty,
    released_qty
    INTO v_requested_qty,
         v_reserved_qty,
         v_consumed_qty,
         v_released_qty
    FROM public.inventory_reservations
   WHERE id = v_reservation.id
   FOR UPDATE;

  IF v_mode = 'cancel' THEN
    v_new_status := 'cancelled';
    v_close_reason := 'source_cancelled';
  ELSE
    IF COALESCE(v_requested_qty, 0) > 0
       AND COALESCE(v_consumed_qty, 0) >= COALESCE(v_requested_qty, 0)
       AND COALESCE(v_released_qty, 0) = 0 THEN
      v_new_status := 'consumed';
      v_close_reason := NULL;
    ELSE
      v_new_status := 'closed';
      v_close_reason := CASE
        WHEN COALESCE(v_released_qty, 0) > 0 THEN 'mixed'
        ELSE NULL
      END;
    END IF;
  END IF;

  UPDATE public.inventory_reservations
     SET status = v_new_status,
         close_reason = v_close_reason,
         updated_by = p_updated_by,
         last_status_changed_by = p_updated_by,
         last_status_changed_at = NOW()
   WHERE id = v_reservation.id;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', p_production_order_id,
    'reservation_id', v_reservation.id,
    'mode', v_mode,
    'reservation_status', v_new_status,
    'close_reason', v_close_reason,
    'released_allocation_count', v_released_allocation_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- companies_subscription_status_transitions_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.companies_subscription_status_transitions_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.subscription_status IS DISTINCT FROM OLD.subscription_status THEN
    IF NEW.subscription_status = 'past_due' AND NEW.past_due_at IS NULL THEN
      NEW.past_due_at := NOW();
    END IF;
    IF NEW.subscription_status = 'payment_failed' AND NEW.suspended_at IS NULL THEN
      NEW.suspended_at := NOW();
    END IF;
    IF NEW.subscription_status = 'active' THEN
      NEW.past_due_at    := NULL;
      NEW.suspended_at   := NULL;
      IF NEW.reactivated_at IS NULL OR NEW.reactivated_at < COALESCE(OLD.suspended_at, OLD.past_due_at, NOW() - interval '1 minute') THEN
        NEW.reactivated_at := NOW();
      END IF;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- company_seat_license_auto_reactivate_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.company_seat_license_auto_reactivate_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_status text;
BEGIN
  IF NEW.expires_at IS NOT NULL
     AND NEW.expires_at > NOW()
     AND NEW.expires_at > COALESCE(OLD.expires_at, NEW.expires_at - interval '1 second') THEN
    SELECT subscription_status INTO v_status FROM public.companies WHERE id = NEW.company_id;
    IF v_status IN ('past_due', 'payment_failed') THEN
      PERFORM public.reactivate_company_subscription(NEW.company_id, NULL);
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- company_seat_licenses_set_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.company_seat_licenses_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- complete_booking_atomic(p_company_id uuid, p_booking_id uuid, p_completed_by uuid, p_invoice_date date, p_due_date date, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.complete_booking_atomic(p_company_id uuid, p_booking_id uuid, p_completed_by uuid, p_invoice_date date DEFAULT CURRENT_DATE, p_due_date date DEFAULT CURRENT_DATE, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_booking public.bookings; v_service public.services; v_branch public.branches;
  v_invoice_id UUID; v_invoice_number TEXT; v_year TEXT := TO_CHAR(NOW(), 'YYYY');
  v_invoice_seq INTEGER; v_service_subtotal NUMERIC; v_addon_total NUMERIC := 0;
  v_new_total NUMERIC; v_warehouse_id UUID; v_cost_center_id UUID;
  v_deducted int := 0; v_lines_added int := 0;
  v_has_sale_products boolean := false;
  v_delivery_provider uuid;
  con RECORD;
BEGIN
  PERFORM set_config('app.skip_discount_approval', 'booking', true);

  SELECT * INTO v_booking FROM public.bookings WHERE id = p_booking_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Booking not found. booking_id=%', p_booking_id USING ERRCODE='P0001'; END IF;
  IF v_booking.status <> 'in_progress' THEN
    RAISE EXCEPTION 'Booking must be in_progress to complete. Current: %. booking_id=%',
      v_booking.status, p_booking_id USING ERRCODE='P0001';
  END IF;
  IF v_booking.invoice_id IS NOT NULL THEN
    RAISE EXCEPTION 'Booking already has invoice_id=%.', v_booking.invoice_id USING ERRCODE='P0001';
  END IF;

  SELECT * INTO v_service FROM public.services WHERE id = v_booking.service_id;
  SELECT * INTO v_branch  FROM public.branches WHERE id = v_booking.branch_id;

  v_warehouse_id := v_branch.default_warehouse_id;
  IF v_warehouse_id IS NULL THEN
    SELECT id INTO v_warehouse_id FROM public.warehouses WHERE company_id = p_company_id LIMIT 1;
  END IF;
  IF v_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'No warehouse found for company. company_id=%', p_company_id USING ERRCODE='P0001';
  END IF;

  v_cost_center_id := COALESCE(v_booking.cost_center_id, v_service.cost_center_id, v_branch.default_cost_center_id);
  IF v_cost_center_id IS NULL THEN
    SELECT id INTO v_cost_center_id FROM public.cost_centers WHERE company_id = p_company_id LIMIT 1;
  END IF;

  -- v3.74.597 — طريقة التسليم: منفذ بيع فرع الحجز (يُنشأ إن لم يوجد)
  v_delivery_provider := public.get_branch_outlet(v_booking.branch_id);
  IF v_delivery_provider IS NULL THEN
    v_delivery_provider := public.ensure_branch_outlet(v_booking.branch_id);
  END IF;

  SELECT COALESCE(MAX(
    CASE WHEN invoice_number LIKE 'INV-' || v_year || '-%'
          AND REGEXP_REPLACE(invoice_number, '^INV-[0-9]{4}-', '') ~ '^[0-9]+$'
         THEN CAST(REGEXP_REPLACE(invoice_number, '^INV-[0-9]{4}-', '') AS INTEGER)
         ELSE 0 END), 0) + 1
  INTO v_invoice_seq FROM public.invoices WHERE company_id = p_company_id;
  v_invoice_number := 'INV-' || v_year || '-' || LPAD(v_invoice_seq::TEXT, 5, '0');

  v_service_subtotal := COALESCE(v_booking.unit_price, 0) * COALESCE(v_booking.quantity, 1);

  v_has_sale_products := EXISTS (
    SELECT 1 FROM public.booking_extra_items
    WHERE booking_id = p_booking_id AND company_id = p_company_id
  );

  SELECT COALESCE(SUM(
           (unit_price * quantity) * (1 - COALESCE(discount_percent,0)/100)
         ), 0)
    INTO v_addon_total
    FROM public.get_booking_line_additions(p_booking_id)
   WHERE unit_price > 0;

  v_new_total := v_service_subtotal + v_addon_total
               - COALESCE(v_booking.discount_amount, 0)
               + COALESCE(v_booking.tax_amount, 0);

  INSERT INTO public.invoices (
    company_id, customer_id, invoice_number, invoice_date, due_date,
    subtotal, tax_amount, discount_value, discount_type, total_amount, paid_amount,
    status, notes, branch_id, warehouse_id, cost_center_id, shipping_provider_id
  ) VALUES (
    p_company_id, v_booking.customer_id, v_invoice_number, p_invoice_date, p_due_date,
    v_service_subtotal + v_addon_total, v_booking.tax_amount, COALESCE(v_booking.discount_amount,0),
    'amount', v_new_total, v_booking.paid_amount, 'draft',
    COALESCE(p_notes, 'فاتورة خدمة: ' || v_service.service_name || ' — حجز ' || v_booking.booking_no),
    v_booking.branch_id, v_warehouse_id, v_cost_center_id, v_delivery_provider
  ) RETURNING id INTO v_invoice_id;

  IF v_service.product_catalog_id IS NOT NULL THEN
    INSERT INTO public.invoice_items (
      invoice_id, product_id, quantity, unit_price, tax_rate,
      discount_percent, line_total, returned_quantity, item_type
    ) VALUES (
      v_invoice_id, v_service.product_catalog_id, v_booking.quantity, v_booking.unit_price,
      COALESCE(v_service.tax_rate, 0), 0, v_service_subtotal, 0, 'service'
    );
    v_lines_added := v_lines_added + 1;
  END IF;

  FOR con IN SELECT * FROM public.get_booking_line_additions(p_booking_id) LOOP
    INSERT INTO public.invoice_items (
      invoice_id, product_id, quantity, unit_price, tax_rate,
      discount_percent, line_total, returned_quantity, item_type
    ) VALUES (
      v_invoice_id, con.product_id, con.quantity, con.unit_price,
      con.tax_rate, con.discount_percent,
      con.unit_price * con.quantity * (1 - COALESCE(con.discount_percent,0)/100),
      0,
      CASE WHEN con.kind = 'extra' THEN 'product' ELSE 'service' END
    );
    v_lines_added := v_lines_added + 1;

    IF con.kind <> 'extra' AND con.auto_deduct_inventory AND con.quantity > 0 THEN
      INSERT INTO public.inventory_transactions (
        company_id, branch_id, warehouse_id, cost_center_id,
        product_id, transaction_type, quantity_change,
        reference_type, reference_id, notes
      ) VALUES (
        p_company_id, v_booking.branch_id, v_warehouse_id, v_cost_center_id,
        con.product_id, 'service_consumption', -(CEIL(con.quantity)::int),
        'booking_invoice', v_invoice_id,
        con.kind || ' — ' || COALESCE(con.description,'') || ' — حجز ' || v_booking.booking_no
      );
      v_deducted := v_deducted + 1;
    END IF;
  END LOOP;

  IF v_has_sale_products THEN
    UPDATE public.invoices
       SET warehouse_status = 'pending'
     WHERE id = v_invoice_id;
  ELSE
    IF v_service.product_catalog_id IS NOT NULL THEN
      PERFORM public.execute_sales_invoice_accounting(v_invoice_id);
    END IF;
    UPDATE public.invoices
       SET status = CASE WHEN v_booking.paid_amount >= v_new_total THEN 'paid' ELSE 'sent' END,
           warehouse_status = 'approved'
     WHERE id = v_invoice_id;
  END IF;

  UPDATE public.booking_payments SET invoice_id = v_invoice_id
   WHERE booking_id = p_booking_id AND invoice_id IS NULL;

  UPDATE public.bookings SET
    total_amount = v_new_total,
    status = 'completed', invoice_id = v_invoice_id,
    payment_status = CASE WHEN v_booking.paid_amount >= v_new_total THEN 'paid'
                          WHEN v_booking.paid_amount > 0 THEN 'partially_paid'
                          ELSE COALESCE(v_booking.payment_status,'unpaid') END,
    completed_by = p_completed_by, completed_at = NOW(), updated_by = p_completed_by
   WHERE id = p_booking_id;

  RETURN jsonb_build_object(
    'success', true, 'booking_id', p_booking_id, 'status', 'completed',
    'invoice_id', v_invoice_id, 'invoice_no', v_invoice_number,
    'service_subtotal', v_service_subtotal,
    'addon_total', v_addon_total,
    'new_total', v_new_total,
    'invoice_lines', v_lines_added,
    'inventory_deductions', v_deducted,
    'has_sale_products', v_has_sale_products,
    'invoice_status', CASE WHEN v_has_sale_products THEN 'draft'
                           WHEN v_booking.paid_amount >= v_new_total THEN 'paid'
                           ELSE 'sent' END
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- complete_idempotency_key(p_idempotency_key text, p_company_id uuid, p_operation_type text, p_response_data jsonb, p_success boolean)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.complete_idempotency_key(p_idempotency_key text, p_company_id uuid, p_operation_type text, p_response_data jsonb, p_success boolean DEFAULT true)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  UPDATE public.idempotency_keys
  SET status = CASE WHEN p_success THEN 'completed' ELSE 'failed' END,
      response_data = p_response_data, completed_at = NOW()
  WHERE idempotency_key = p_idempotency_key AND company_id = p_company_id
    AND operation_type = p_operation_type AND status = 'processing';
END; $function$
;

-- ---------------------------------------------------------------
-- complete_manufacturing_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_completed_by uuid, p_completed_quantity numeric, p_completed_at timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.complete_manufacturing_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_completed_by uuid, p_completed_quantity numeric, p_completed_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order RECORD;
  v_completed_at TIMESTAMPTZ := COALESCE(p_completed_at, NOW());
  v_blocking_operation_count INTEGER;
BEGIN
  IF p_completed_quantity IS NULL OR p_completed_quantity <= 0 THEN
    RAISE EXCEPTION 'completed_quantity must be greater than zero.';
  END IF;

  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order not found or not in company. production_order_id=%', p_production_order_id;
  END IF;

  IF v_order.status <> 'in_progress' THEN
    RAISE EXCEPTION 'Only in-progress production orders can be completed. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  END IF;

  SELECT COUNT(*)
    INTO v_blocking_operation_count
    FROM public.manufacturing_production_order_operations
   WHERE production_order_id = p_production_order_id
     AND status <> 'completed';

  IF v_blocking_operation_count > 0 THEN
    RAISE EXCEPTION 'All production order operations must be completed before completing the order. production_order_id=%, blocking_operation_count=%',
      p_production_order_id, v_blocking_operation_count;
  END IF;

  UPDATE public.manufacturing_production_orders
     SET status = 'completed',
         completed_quantity = p_completed_quantity,
         completed_at = v_completed_at,
         completed_by = p_completed_by,
         updated_by = p_completed_by
   WHERE id = p_production_order_id;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', p_production_order_id,
    'previous_status', v_order.status,
    'status', 'completed',
    'completed_quantity', p_completed_quantity,
    'completed_at', v_completed_at
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- confirm_booking_atomic(p_company_id uuid, p_booking_id uuid, p_confirmed_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.confirm_booking_atomic(p_company_id uuid, p_booking_id uuid, p_confirmed_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_booking public.bookings;
BEGIN
  SELECT * INTO v_booking
    FROM public.bookings
   WHERE id = p_booking_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Booking not found. booking_id=%', p_booking_id
      USING ERRCODE = 'P0001';
  END IF;

  IF v_booking.status <> 'draft' THEN
    RAISE EXCEPTION 'Booking must be in draft to confirm. Current status: %. booking_id=%',
      v_booking.status, p_booking_id
      USING ERRCODE = 'P0001';
  END IF;

  -- Idempotent: second click is a no-op except for refreshing updated_by.
  IF v_booking.confirmed_at IS NOT NULL THEN
    RETURN jsonb_build_object(
      'success', true,
      'booking_id', p_booking_id,
      'confirmed_at', v_booking.confirmed_at,
      'already_confirmed', true
    );
  END IF;

  UPDATE public.bookings
     SET confirmed_at = NOW(),
         confirmed_by = p_confirmed_by,
         updated_by   = p_confirmed_by,
         updated_at   = NOW()
   WHERE id = p_booking_id;

  RETURN jsonb_build_object(
    'success', true,
    'booking_id', p_booking_id,
    'confirmed_at', NOW(),
    'already_confirmed', false
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- confirm_purchase_return_delivery(p_purchase_return_id uuid, p_confirmed_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.confirm_purchase_return_delivery(p_purchase_return_id uuid, p_confirmed_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_pr            RECORD;
  v_item          RECORD;
  v_bill_item     RECORD;
  v_current_stock NUMERIC;
  v_new_returned  NUMERIC;
  v_bill_total    NUMERIC;
  v_bill_st       TEXT;
  v_vc_id         UUID;
  v_result        JSONB := '{}';
BEGIN
  SELECT pr.* INTO v_pr FROM purchase_returns pr WHERE pr.id = p_purchase_return_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Purchase return not found: %', p_purchase_return_id; END IF;
  IF v_pr.workflow_status != 'pending_approval' THEN
    RAISE EXCEPTION 'Return is not pending approval. Current status: %', v_pr.workflow_status;
  END IF;

  FOR v_item IN SELECT pri.* FROM purchase_return_items pri WHERE pri.purchase_return_id = p_purchase_return_id AND pri.quantity > 0 LOOP
    IF v_item.bill_item_id IS NOT NULL THEN
      SELECT id, quantity, COALESCE(returned_quantity, 0) AS returned_quantity INTO v_bill_item
      FROM bill_items WHERE id = v_item.bill_item_id FOR UPDATE;
      IF (v_bill_item.returned_quantity + v_item.quantity) > v_bill_item.quantity THEN
        RAISE EXCEPTION 'Return quantity exceeds bill item quantity for item %', v_item.bill_item_id;
      END IF;
    END IF;
    IF v_item.product_id IS NOT NULL AND v_pr.warehouse_id IS NOT NULL THEN
      PERFORM pg_advisory_xact_lock(hashtext(v_pr.company_id::text || v_item.product_id::text || v_pr.warehouse_id::text));
      SELECT COALESCE(SUM(quantity_change), 0) INTO v_current_stock
      FROM inventory_transactions
      WHERE company_id = v_pr.company_id AND product_id = v_item.product_id AND warehouse_id = v_pr.warehouse_id AND COALESCE(is_deleted, false) = false;
      IF v_current_stock < v_item.quantity THEN
        RAISE EXCEPTION 'Insufficient stock for product %. Available: %, Required: %', v_item.product_id, v_current_stock, v_item.quantity;
      END IF;
    END IF;
  END LOOP;

  FOR v_item IN SELECT pri.* FROM purchase_return_items pri WHERE pri.purchase_return_id = p_purchase_return_id AND pri.quantity > 0 LOOP
    IF v_item.product_id IS NOT NULL THEN
      INSERT INTO inventory_transactions (company_id, product_id, transaction_type, quantity_change, reference_id, reference_type, journal_entry_id, notes, branch_id, cost_center_id, warehouse_id, transaction_date)
      VALUES (v_pr.company_id, v_item.product_id, 'purchase_return', -v_item.quantity, v_pr.id, 'purchase_return', v_pr.journal_entry_id,
        'مرتجع مشتريات ' || v_pr.return_number, v_pr.branch_id, v_pr.cost_center_id, v_pr.warehouse_id, v_pr.return_date);
    END IF;
    IF v_item.bill_item_id IS NOT NULL THEN
      UPDATE bill_items SET returned_quantity = COALESCE(returned_quantity, 0) + v_item.quantity WHERE id = v_item.bill_item_id;
    END IF;
  END LOOP;

  IF v_pr.bill_id IS NOT NULL THEN
    SELECT returned_amount, total_amount, status INTO v_new_returned, v_bill_total, v_bill_st FROM bills WHERE id = v_pr.bill_id;
    v_new_returned := COALESCE(v_new_returned, 0) + v_pr.total_amount;
    IF v_bill_st IN ('paid', 'partially_paid') THEN
      UPDATE bills SET returned_amount = v_new_returned,
        return_status = CASE WHEN v_new_returned >= v_bill_total THEN 'full' ELSE 'partial' END, updated_at = NOW()
      WHERE id = v_pr.bill_id;
    ELSE
      UPDATE bills SET returned_amount = v_new_returned,
        return_status = CASE WHEN v_new_returned >= v_bill_total THEN 'full' ELSE 'partial' END,
        status = CASE WHEN (v_bill_total - v_pr.total_amount) <= 0 THEN 'fully_returned' ELSE v_bill_st END,
        total_amount = GREATEST(v_bill_total - v_pr.total_amount, 0), updated_at = NOW()
      WHERE id = v_pr.bill_id;
    END IF;
  END IF;

  IF v_pr.journal_entry_id IS NOT NULL THEN
    UPDATE journal_entries SET status = 'posted', validation_status = 'valid', updated_at = NOW()
    WHERE id = v_pr.journal_entry_id AND status = 'draft';
  END IF;

  IF v_pr.settlement_method = 'debit_note' AND v_pr.total_amount > 0 THEN
    IF NOT EXISTS (SELECT 1 FROM vendor_credits WHERE source_purchase_return_id = v_pr.id) THEN
      INSERT INTO vendor_credits (company_id, supplier_id, bill_id, source_purchase_return_id, source_purchase_invoice_id, journal_entry_id, credit_number, credit_date, status, subtotal, tax_amount, total_amount, applied_amount, branch_id, cost_center_id, warehouse_id, notes, original_currency, exchange_rate_used)
      VALUES (v_pr.company_id, v_pr.supplier_id, v_pr.bill_id, v_pr.id, v_pr.bill_id, v_pr.journal_entry_id,
        'VC-' || REPLACE(v_pr.return_number, 'PRET-', ''), v_pr.return_date, 'open',
        v_pr.subtotal, v_pr.tax_amount, v_pr.total_amount, 0,
        v_pr.branch_id, v_pr.cost_center_id, v_pr.warehouse_id,
        'إشعار دائن - اعتماد مرتجع ' || v_pr.return_number,
        COALESCE(v_pr.original_currency, 'EGP'), COALESCE(v_pr.exchange_rate_used, 1))
      RETURNING id INTO v_vc_id;
      INSERT INTO vendor_credit_items (vendor_credit_id, product_id, description, quantity, unit_price, tax_rate, discount_percent, line_total)
      SELECT v_vc_id, pri.product_id, pri.description, pri.quantity, pri.unit_price, pri.tax_rate, pri.discount_percent, pri.line_total
      FROM purchase_return_items pri WHERE pri.purchase_return_id = v_pr.id;
    END IF;
  END IF;

  UPDATE purchase_returns SET workflow_status = 'confirmed', confirmed_by = p_confirmed_by, confirmed_at = NOW(), confirmation_notes = p_notes
  WHERE id = p_purchase_return_id;

  v_result := jsonb_build_object('purchase_return_id', p_purchase_return_id, 'workflow_status', 'confirmed');
  RETURN v_result;
EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'Confirm delivery failed (rolled back): %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- confirm_purchase_return_delivery_v2(p_purchase_return_id uuid, p_confirmed_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.confirm_purchase_return_delivery_v2(p_purchase_return_id uuid, p_confirmed_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_pr RECORD;
  v_company_id UUID;
  v_supplier_id UUID;
  v_bill_id UUID;
  v_transition JSONB;
  v_item RECORD;
  v_inventory_account_id UUID;
  v_vat_account_id UUID;
  v_ap_account_id UUID;
  v_vc_liability_account_id UUID;
  v_fallback_liability_id UUID;
  v_je_id UUID;
  v_credit_id UUID;
  v_branch_id UUID;
  v_cc_id UUID;
  v_bill_total NUMERIC(18, 4);
  v_bill_paid NUMERIC(18, 4);
  v_remaining_ap NUMERIC(18, 4);
  v_return_total NUMERIC(18, 4);
  v_ap_reduction NUMERIC(18, 4);
  v_vc_debit NUMERIC(18, 4);
  v_vc_sub NUMERIC(18, 4);
  v_vc_tax NUMERIC(18, 4);
  v_round_fix NUMERIC(18, 4);
  v_bill_returned NUMERIC(18, 4);
  v_vc_ratio NUMERIC(18, 8);
  v_je_existed BOOLEAN := false;
  v_lot RECORD;
  v_remaining_to_return NUMERIC;
  v_take NUMERIC;
  v_is_cash_refund BOOLEAN := false;
  v_refund_executed BOOLEAN := false;
BEGIN
  SELECT * INTO v_pr FROM purchase_returns WHERE id = p_purchase_return_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Purchase return not found'; END IF;

  v_company_id := v_pr.company_id;
  v_supplier_id := v_pr.supplier_id;
  v_bill_id := v_pr.bill_id;

  IF v_pr.workflow_status NOT IN ('pending_warehouse', 'pending_approval') THEN
    RAISE EXCEPTION 'Return is not pending warehouse confirmation. Current workflow_status: %', v_pr.workflow_status;
  END IF;

  v_branch_id := COALESCE(
    v_pr.branch_id,
    (SELECT b.id FROM branches b
     WHERE b.company_id = v_company_id AND COALESCE(b.is_active, true)
     ORDER BY b.is_main DESC NULLS LAST, b.name LIMIT 1)
  );
  v_cc_id := v_pr.cost_center_id;

  IF v_branch_id IS NULL THEN
    RAISE EXCEPTION 'Cannot confirm return: no branch on purchase return and no active branch for company';
  END IF;

  v_transition := transition_purchase_return_state(
    p_purchase_return_id, v_company_id, p_confirmed_by, 'completed', p_notes
  );

  IF (v_transition->>'success')::boolean IS DISTINCT FROM TRUE THEN
    RAISE EXCEPTION 'State transition failed: %', v_transition;
  END IF;

  v_bill_total := 0; v_bill_paid := 0; v_bill_returned := 0;
  IF v_bill_id IS NOT NULL THEN
    SELECT COALESCE(b.total_amount, 0), COALESCE(b.paid_amount, 0), COALESCE(b.returned_amount, 0)
    INTO v_bill_total, v_bill_paid, v_bill_returned
    FROM bills b WHERE b.id = v_bill_id AND b.company_id = v_company_id;
    IF NOT FOUND THEN
      v_bill_id := NULL; v_bill_total := 0; v_bill_paid := 0; v_bill_returned := 0;
    END IF;
  END IF;

  v_remaining_ap := GREATEST(COALESCE(v_bill_total, 0) - COALESCE(v_bill_paid, 0) - COALESCE(v_bill_returned, 0), 0);
  v_return_total := COALESCE(v_pr.total_amount, 0);

  IF v_bill_id IS NULL THEN
    v_ap_reduction := 0;
    v_vc_debit := v_return_total;
  ELSE
    v_ap_reduction := LEAST(v_return_total, v_remaining_ap);
    v_vc_debit := GREATEST(v_return_total - v_ap_reduction, 0);
  END IF;

  -- v3.74.173 — cash/bank refund mode kicks in when settlement_method is
  -- cash or bank_transfer AND the refund account is specified. The vc_debit
  -- portion goes straight to the chosen cash account; no vendor_credit row
  -- is needed, and the return seals to closed/refund_recorded.
  v_is_cash_refund :=
       COALESCE(v_pr.settlement_method, '') IN ('cash', 'bank_transfer')
   AND v_pr.refund_account_id IS NOT NULL
   AND v_vc_debit > 0;

  PERFORM set_config('app.allow_direct_post', 'true', true);

  SELECT id INTO v_inventory_account_id FROM chart_of_accounts
   WHERE company_id = v_company_id AND sub_type = 'inventory' AND COALESCE(is_active, true) LIMIT 1;
  SELECT id INTO v_vat_account_id FROM chart_of_accounts
   WHERE company_id = v_company_id AND sub_type = 'vat_input' AND COALESCE(is_active, true) LIMIT 1;
  SELECT id INTO v_ap_account_id FROM chart_of_accounts
   WHERE company_id = v_company_id AND (sub_type = 'accounts_payable' OR sub_type = 'ap') AND COALESCE(is_active, true)
   ORDER BY CASE WHEN sub_type = 'accounts_payable' THEN 0 ELSE 1 END LIMIT 1;
  SELECT id INTO v_vc_liability_account_id FROM chart_of_accounts
   WHERE company_id = v_company_id AND sub_type = 'vendor_credit_liability' AND COALESCE(is_active, true) LIMIT 1;
  SELECT id INTO v_fallback_liability_id FROM chart_of_accounts
   WHERE company_id = v_company_id AND COALESCE(is_active, true)
     AND (sub_type = 'vendor_credit_liability' OR sub_type = 'accounts_payable' OR sub_type = 'ap') LIMIT 1;

  IF v_ap_reduction > 0 AND v_ap_account_id IS NULL THEN
    v_vc_debit := v_vc_debit + v_ap_reduction; v_ap_reduction := 0;
  END IF;
  IF NOT v_is_cash_refund AND v_vc_debit > 0
     AND v_vc_liability_account_id IS NULL AND v_ap_account_id IS NOT NULL THEN
    v_ap_reduction := v_ap_reduction + v_vc_debit; v_vc_debit := 0;
  END IF;

  v_je_id := v_pr.journal_entry_id;

  IF v_je_id IS NOT NULL THEN
    DELETE FROM journal_entry_lines WHERE journal_entry_id = v_je_id;
    UPDATE journal_entries
       SET status = 'posted',
           branch_id = COALESCE(branch_id, v_branch_id),
           cost_center_id = COALESCE(cost_center_id, v_cc_id),
           entry_date = COALESCE(v_pr.return_date, CURRENT_DATE),
           description = 'مرتجع مشتريات ' || COALESCE(v_pr.return_number, ''),
           updated_at = NOW()
     WHERE id = v_je_id;
    v_je_existed := true;
  ELSE
    INSERT INTO journal_entries (
      company_id, branch_id, cost_center_id,
      reference_type, reference_id, entry_date, description, status
    ) VALUES (
      v_company_id, v_branch_id, v_cc_id,
      'purchase_return', p_purchase_return_id,
      COALESCE(v_pr.return_date, CURRENT_DATE),
      'مرتجع مشتريات ' || COALESCE(v_pr.return_number, ''),
      'posted'
    ) RETURNING id INTO v_je_id;
    UPDATE purchase_returns SET journal_entry_id = v_je_id WHERE id = p_purchase_return_id;
  END IF;

  IF v_return_total > 0 THEN
    IF v_ap_reduction > 0 AND v_ap_account_id IS NOT NULL THEN
      INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
      VALUES (v_je_id, v_ap_account_id, v_ap_reduction, 0,
              'تخفيض ذمم دائنة (AP) — مرتجع مشتريات', v_branch_id, v_cc_id);
    END IF;

    IF v_vc_debit > 0 THEN
      IF v_is_cash_refund THEN
        -- Cash/bank refund: debit the chosen cash account directly.
        INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
        VALUES (v_je_id, v_pr.refund_account_id, v_vc_debit, 0,
                CASE WHEN v_pr.settlement_method = 'cash'
                     THEN 'استرداد نقدي من المورد'
                     ELSE 'استرداد بنكي من المورد' END,
                v_branch_id, v_cc_id);
        v_refund_executed := true;
      ELSIF v_vc_liability_account_id IS NOT NULL THEN
        INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
        VALUES (v_je_id, v_vc_liability_account_id, v_vc_debit, 0,
                'إشعار دائن مورد — جزء يتجاوز الرصيد المفتوح على الفاتورة', v_branch_id, v_cc_id);
      ELSIF v_fallback_liability_id IS NOT NULL THEN
        INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
        VALUES (v_je_id, v_fallback_liability_id, v_vc_debit, 0,
                'تسوية مرتجع مشتريات (حساب احتياطي)', v_branch_id, v_cc_id);
      ELSE
        RAISE EXCEPTION 'No liability account (AP / vendor credit) found for company %', v_company_id;
      END IF;
    END IF;
  END IF;

  IF v_inventory_account_id IS NOT NULL AND COALESCE(v_pr.subtotal, 0) > 0 THEN
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
    VALUES (v_je_id, v_inventory_account_id, 0, v_pr.subtotal, 'مخزون مرتجع للمورد', v_branch_id, v_cc_id);
  END IF;

  IF v_vat_account_id IS NOT NULL AND COALESCE(v_pr.tax_amount, 0) > 0 THEN
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
    VALUES (v_je_id, v_vat_account_id, 0, v_pr.tax_amount, 'عكس ضريبة المشتريات', v_branch_id, v_cc_id);
  END IF;

  PERFORM set_config('app.allow_direct_post', 'false', true);

  UPDATE purchase_return_items SET is_deducted = true
   WHERE purchase_return_id = p_purchase_return_id
     AND COALESCE(is_deducted, false) = false;

  FOR v_item IN
    SELECT * FROM purchase_return_items WHERE purchase_return_id = p_purchase_return_id
  LOOP
    IF v_item.product_id IS NOT NULL THEN
      INSERT INTO inventory_transactions (
        company_id, product_id, transaction_type, quantity_change,
        reference_id, reference_type, journal_entry_id, notes,
        branch_id, cost_center_id, warehouse_id
      ) VALUES (
        v_company_id, v_item.product_id, 'purchase_return', -(v_item.quantity),
        p_purchase_return_id, 'purchase_return', v_je_id,
        'مرتجع مشتريات للمورد'
          || CASE WHEN v_pr.return_date IS NOT NULL
                  THEN ' — تاريخ المرتجع: ' || v_pr.return_date::text ELSE '' END,
        v_branch_id, v_cc_id, v_pr.warehouse_id
      );

      v_remaining_to_return := v_item.quantity;
      IF v_bill_id IS NOT NULL AND v_remaining_to_return > 0 THEN
        FOR v_lot IN
          SELECT id, remaining_quantity, unit_cost
          FROM fifo_cost_lots
          WHERE company_id = v_company_id
            AND product_id = v_item.product_id
            AND reference_type = 'bill'
            AND reference_id = v_bill_id
            AND remaining_quantity > 0
          ORDER BY purchase_date, created_at
          FOR UPDATE
        LOOP
          EXIT WHEN v_remaining_to_return <= 0;
          v_take := LEAST(v_lot.remaining_quantity, v_remaining_to_return);
          IF v_take > 0 THEN
            UPDATE fifo_cost_lots
               SET remaining_quantity = remaining_quantity - v_take, updated_at = NOW()
             WHERE id = v_lot.id;
            INSERT INTO fifo_lot_consumptions (
              company_id, lot_id, product_id, consumption_type,
              reference_type, reference_id,
              quantity_consumed, unit_cost, total_cost, consumption_date, notes
            ) VALUES (
              v_company_id, v_lot.id, v_item.product_id, 'purchase_return',
              'purchase_return', p_purchase_return_id,
              v_take, v_lot.unit_cost, v_take * v_lot.unit_cost,
              COALESCE(v_pr.return_date, CURRENT_DATE),
              'عكس FIFO — مرتجع للمورد ' || COALESCE(v_pr.return_number, '')
            );
            v_remaining_to_return := v_remaining_to_return - v_take;
          END IF;
        END LOOP;
      END IF;
    END IF;

    IF v_item.bill_item_id IS NOT NULL THEN
      UPDATE bill_items
         SET returned_quantity = COALESCE(returned_quantity, 0) + v_item.quantity
       WHERE id = v_item.bill_item_id;
    END IF;
  END LOOP;

  IF v_bill_id IS NOT NULL THEN
    UPDATE bills
       SET returned_amount = COALESCE(returned_amount, 0) + v_pr.total_amount,
           return_status = CASE
             WHEN (COALESCE(returned_amount, 0) + v_pr.total_amount) >= COALESCE(total_amount, 0)
             THEN 'fully_returned' ELSE 'partially_returned' END,
           updated_at = NOW()
     WHERE id = v_bill_id;
  END IF;

  -- vendor_credit only when we did NOT auto-execute a cash/bank refund.
  IF NOT v_is_cash_refund AND v_vc_debit > 0 AND COALESCE(v_pr.total_amount, 0) > 0 THEN
    IF NOT EXISTS (SELECT 1 FROM vendor_credits vc WHERE vc.source_purchase_return_id = p_purchase_return_id) THEN
      v_vc_ratio := v_vc_debit / NULLIF(v_return_total, 0);
      IF v_vc_ratio IS NULL THEN v_vc_ratio := 0; END IF;

      v_vc_sub := ROUND(COALESCE(v_pr.subtotal, 0) * v_vc_ratio, 2);
      v_vc_tax := ROUND(COALESCE(v_pr.tax_amount, 0) * v_vc_ratio, 2);
      v_round_fix := v_vc_debit - (v_vc_sub + v_vc_tax);
      v_vc_tax := v_vc_tax + v_round_fix;

      INSERT INTO vendor_credits (
        company_id, supplier_id, bill_id,
        source_purchase_return_id, source_purchase_invoice_id, journal_entry_id,
        credit_number, credit_date, status,
        subtotal, tax_amount, total_amount, applied_amount,
        branch_id, cost_center_id, notes
      ) VALUES (
        v_company_id, v_supplier_id, v_bill_id,
        p_purchase_return_id, v_bill_id, v_je_id,
        'VC-' || REPLACE(COALESCE(v_pr.return_number, 'PR'), 'PRET-', ''),
        COALESCE(v_pr.return_date, CURRENT_DATE), 'open',
        v_vc_sub, v_vc_tax, v_vc_debit, 0,
        v_branch_id, v_cc_id,
        'إشعار دائن — جزء المرتجع فوق رصيد AP المفتوح ' || COALESCE(v_pr.return_number, '')
      ) RETURNING id INTO v_credit_id;

      INSERT INTO vendor_credit_items (
        vendor_credit_id, product_id, description,
        quantity, unit_price, tax_rate, discount_percent, line_total
      )
      SELECT v_credit_id, pri.product_id, pri.description,
        pri.quantity, pri.unit_price, pri.tax_rate, pri.discount_percent,
        ROUND(COALESCE(pri.line_total, 0) * v_vc_ratio, 2)
      FROM purchase_return_items pri
      WHERE pri.purchase_return_id = p_purchase_return_id;
    END IF;
  END IF;

  -- Seal the return.
  IF v_refund_executed THEN
    UPDATE purchase_returns
       SET workflow_status = 'closed',
           status = 'closed',
           financial_status = 'refund_recorded',
           updated_at = NOW()
     WHERE id = p_purchase_return_id;
  ELSE
    UPDATE purchase_returns
       SET workflow_status = 'completed', updated_at = NOW()
     WHERE id = p_purchase_return_id;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'purchase_return_id', p_purchase_return_id,
    'journal_entry_id', v_je_id,
    'vendor_credit_id', v_credit_id,
    'open_ap_before_return', v_remaining_ap,
    'ap_reduction_amount', v_ap_reduction,
    'vendor_credit_accounting_amount', v_vc_debit,
    'je_lines_rebuilt', v_je_existed,
    'cash_refund_executed', v_refund_executed
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- confirm_purchase_return_delivery_v3(p_purchase_return_id uuid, p_confirmed_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.confirm_purchase_return_delivery_v3(p_purchase_return_id uuid, p_confirmed_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_pr                RECORD;
    v_company_id        UUID;
    v_supplier_id       UUID;
    v_bill_id           UUID;
    v_transition_result JSONB;
    v_item              RECORD;
    v_je_id             UUID;
    v_credit_id         UUID;
    v_draft_data        JSONB;
    v_journal_entry     JSONB;
    v_journal_lines     JSONB;
    v_vendor_credit     JSONB;
    v_vendor_credit_items JSONB;
    v_bill_update       JSONB;
    v_bill_total        NUMERIC;
    v_bill_returned     NUMERIC;
    v_current_paid      NUMERIC;
    v_net_after_return  NUMERIC;
    v_overpayment       NUMERIC;
BEGIN
    PERFORM set_config('app.allow_direct_post', 'true', true);

    SELECT * INTO v_pr FROM purchase_returns WHERE id = p_purchase_return_id FOR UPDATE;
    IF NOT FOUND THEN RAISE EXCEPTION 'Purchase return not found'; END IF;

    v_company_id  := v_pr.company_id;
    v_supplier_id := v_pr.supplier_id;
    v_bill_id     := v_pr.bill_id;
    v_draft_data  := v_pr.draft_financial_data;

    IF v_bill_id IS NOT NULL THEN
        SELECT
            COALESCE(b.total_amount, 0),
            COALESCE(b.returned_amount, 0)
        INTO v_bill_total, v_bill_returned
        FROM bills b WHERE id = v_bill_id;

        SELECT COALESCE(SUM(pa.allocated_amount), 0)
        INTO v_current_paid
        FROM payment_allocations pa
        JOIN payments p ON p.id = pa.payment_id
        WHERE pa.bill_id = v_bill_id
          AND p.status = 'approved'
          AND COALESCE(p.is_deleted, false) = false
          AND p.voided_at IS NULL
          AND p.voids_payment_id IS NULL;

        v_net_after_return := GREATEST(v_bill_total - v_bill_returned - v_pr.total_amount, 0);

        IF v_current_paid > v_net_after_return THEN
            v_overpayment := v_current_paid - v_net_after_return;
            RAISE EXCEPTION 'RETURN_BLOCKED_OVERPAYMENT: Approving this return of % would cause an overpayment of % on bill (total=%, already_returned=%, paid=%). Please adjust or reverse the payment first.',
                v_pr.total_amount,
                v_overpayment,
                v_bill_total,
                v_bill_returned,
                v_current_paid
            USING ERRCODE = 'P0002';
        END IF;
    END IF;

    v_transition_result := transition_purchase_return_state(p_purchase_return_id, v_company_id, p_confirmed_by, 'completed', p_notes);

    UPDATE purchase_return_items SET is_deducted = true WHERE purchase_return_id = p_purchase_return_id AND is_deducted = false;

    FOR v_item IN (SELECT * FROM purchase_return_items WHERE purchase_return_id = p_purchase_return_id) LOOP
        INSERT INTO inventory_transactions (
            company_id, branch_id, warehouse_id, product_id,
            transaction_type, reference_type, reference_id,
            quantity_change, unit_cost, total_cost,
            transaction_date, notes, is_deleted
        ) VALUES (
            v_company_id, v_pr.branch_id, v_pr.warehouse_id, v_item.product_id,
            'purchase_return', 'purchase_return', p_purchase_return_id,
            -(v_item.quantity), v_item.unit_price, -(v_item.quantity * v_item.unit_price),
            NOW(), 'مرتجع مشتريات ' || v_pr.return_number, false
        );

        UPDATE bill_items SET returned_quantity = COALESCE(returned_quantity, 0) + v_item.quantity WHERE id = v_item.bill_item_id;
    END LOOP;

    IF v_draft_data IS NOT NULL THEN
        v_journal_entry       := v_draft_data->'journal_entry';
        v_journal_lines       := v_draft_data->'journal_lines';
        v_vendor_credit       := v_draft_data->'vendor_credit';
        v_vendor_credit_items := v_draft_data->'vendor_credit_items';
        v_bill_update         := v_draft_data->'bill_update';

        IF v_journal_entry IS NOT NULL THEN
            INSERT INTO journal_entries (company_id, branch_id, cost_center_id, reference_type, reference_id, entry_date, description, status, created_by)
            VALUES (v_company_id, v_pr.branch_id, v_pr.cost_center_id, 'purchase_return', p_purchase_return_id, (v_journal_entry->>'entry_date')::DATE, v_journal_entry->>'description', 'draft', p_confirmed_by) RETURNING id INTO v_je_id;

            IF v_journal_lines IS NOT NULL THEN
                INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
                SELECT v_je_id, (l->>'account_id')::UUID, COALESCE((l->>'debit_amount')::NUMERIC, 0), COALESCE((l->>'credit_amount')::NUMERIC, 0), l->>'description', v_pr.branch_id, v_pr.cost_center_id
                FROM jsonb_array_elements(v_journal_lines) AS l;
            END IF;

            UPDATE journal_entries SET status = 'posted' WHERE id = v_je_id;
            UPDATE purchase_returns SET journal_entry_id = v_je_id WHERE id = p_purchase_return_id;
        END IF;

        IF v_vendor_credit IS NOT NULL THEN
            INSERT INTO vendor_credits (company_id, supplier_id, bill_id, source_purchase_return_id, source_purchase_invoice_id, journal_entry_id, credit_number, credit_date, status, subtotal, tax_amount, total_amount, applied_amount, branch_id, cost_center_id, notes, created_by)
            VALUES (v_company_id, v_supplier_id, v_bill_id, p_purchase_return_id, v_bill_id, v_je_id, v_vendor_credit->>'credit_number', COALESCE((v_vendor_credit->>'credit_date')::DATE, CURRENT_DATE), 'open', COALESCE((v_vendor_credit->>'subtotal')::NUMERIC, 0), COALESCE((v_vendor_credit->>'tax_amount')::NUMERIC, 0), COALESCE((v_vendor_credit->>'total_amount')::NUMERIC, 0), 0, v_pr.branch_id, v_pr.cost_center_id, v_vendor_credit->>'notes', p_confirmed_by) RETURNING id INTO v_credit_id;

            IF v_vendor_credit_items IS NOT NULL THEN
                INSERT INTO vendor_credit_items (vendor_credit_id, product_id, description, quantity, unit_price, tax_rate, discount_percent, line_total)
                SELECT v_credit_id, NULLIF(vci->>'product_id', '')::UUID, vci->>'description', COALESCE((vci->>'quantity')::NUMERIC, 0), COALESCE((vci->>'unit_price')::NUMERIC, 0), COALESCE((vci->>'tax_rate')::NUMERIC, 0), COALESCE((vci->>'discount_percent')::NUMERIC, 0), COALESCE((vci->>'line_total')::NUMERIC, 0)
                FROM jsonb_array_elements(v_vendor_credit_items) AS vci;
            END IF;

            INSERT INTO system_events (company_id, event_type, reference_type, reference_id, payload, user_id, event_key)
            VALUES (v_company_id, 'vendor_credit.created', 'vendor_credit', v_credit_id, jsonb_build_object('return_id', p_purchase_return_id, 'amount', v_pr.total_amount), p_confirmed_by, 'vendor_credit.created.' || v_credit_id::text) ON CONFLICT DO NOTHING;
        END IF;

        IF v_bill_update IS NOT NULL THEN
            UPDATE bills SET
                returned_amount = COALESCE(NULLIF(v_bill_update->>'returned_amount', '')::NUMERIC, returned_amount),
                return_status   = COALESCE(NULLIF(v_bill_update->>'return_status', ''), return_status),
                status          = COALESCE(NULLIF(v_bill_update->>'status', ''), status),
                updated_at = NOW()
            WHERE id = v_bill_id;
        END IF;

        UPDATE purchase_returns SET draft_financial_data = NULL WHERE id = p_purchase_return_id;

    ELSE
        UPDATE bills SET
            returned_amount = COALESCE(returned_amount, 0) + v_pr.total_amount,
            return_status = CASE WHEN (COALESCE(returned_amount, 0) + v_pr.total_amount) >= total_amount THEN 'fully_returned' ELSE 'partially_returned' END
        WHERE id = v_bill_id;
    END IF;

    RETURN jsonb_build_object('success', true, 'purchase_return_id', p_purchase_return_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- confirm_warehouse_allocation(p_allocation_id uuid, p_confirmed_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.confirm_warehouse_allocation(p_allocation_id uuid, p_confirmed_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_alloc          RECORD;
  v_pr             RECORD;
  v_item           RECORD;
  v_bill_item      RECORD;
  v_current_stock  NUMERIC;
  v_vc_id          UUID;
  v_pending_count  INT;
  v_new_status     TEXT;
  v_new_returned   NUMERIC;
  v_bill_total     NUMERIC;
  v_bill_st        TEXT;
  v_result         JSONB := '{}';
BEGIN
  SELECT * INTO v_alloc
  FROM purchase_return_warehouse_allocations
  WHERE id = p_allocation_id FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Warehouse allocation not found: %', p_allocation_id;
  END IF;

  IF v_alloc.workflow_status != 'pending_approval' THEN
    RAISE EXCEPTION 'Allocation is not pending approval. Current status: %', v_alloc.workflow_status;
  END IF;

  SELECT * INTO v_pr
  FROM purchase_returns
  WHERE id = v_alloc.purchase_return_id FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Purchase return not found: %', v_alloc.purchase_return_id;
  END IF;

  FOR v_item IN
    SELECT pri.* FROM purchase_return_items pri
    WHERE pri.warehouse_allocation_id = p_allocation_id AND pri.quantity > 0
  LOOP
    IF v_item.bill_item_id IS NOT NULL THEN
      SELECT id, quantity, COALESCE(returned_quantity, 0) AS returned_quantity
      INTO v_bill_item FROM bill_items WHERE id = v_item.bill_item_id FOR UPDATE;
      IF (v_bill_item.returned_quantity + v_item.quantity) > v_bill_item.quantity THEN
        RAISE EXCEPTION 'Return quantity exceeds available for bill item %', v_item.bill_item_id;
      END IF;
    END IF;

    IF v_item.product_id IS NOT NULL AND v_alloc.warehouse_id IS NOT NULL THEN
      PERFORM pg_advisory_xact_lock(
        hashtext(v_pr.company_id::text || v_item.product_id::text || v_alloc.warehouse_id::text)
      );
      SELECT COALESCE(SUM(quantity_change), 0) INTO v_current_stock
      FROM inventory_transactions
      WHERE company_id = v_pr.company_id AND product_id = v_item.product_id
        AND warehouse_id = v_alloc.warehouse_id AND COALESCE(is_deleted, false) = false;
      IF v_current_stock < v_item.quantity THEN
        RAISE EXCEPTION 'Insufficient stock for product %. Available: %, Required: %',
          v_item.product_id, v_current_stock, v_item.quantity;
      END IF;
    END IF;
  END LOOP;

  FOR v_item IN
    SELECT pri.* FROM purchase_return_items pri
    WHERE pri.warehouse_allocation_id = p_allocation_id AND pri.quantity > 0
  LOOP
    IF v_item.product_id IS NOT NULL THEN
      INSERT INTO inventory_transactions (
        company_id, product_id, transaction_type, quantity_change,
        reference_id, reference_type, journal_entry_id, notes,
        branch_id, cost_center_id, warehouse_id
      ) VALUES (
        v_pr.company_id, v_item.product_id, 'purchase_return', -v_item.quantity,
        v_pr.id, 'purchase_return', v_alloc.journal_entry_id,
        'مرتجع مشتريات ' || v_pr.return_number || ' — ' || v_alloc.warehouse_id::text,
        v_alloc.branch_id, v_alloc.cost_center_id, v_alloc.warehouse_id
      );
    END IF;
    IF v_item.bill_item_id IS NOT NULL THEN
      UPDATE bill_items
      SET returned_quantity = COALESCE(returned_quantity, 0) + v_item.quantity
      WHERE id = v_item.bill_item_id;
    END IF;
  END LOOP;

  IF v_alloc.journal_entry_id IS NOT NULL THEN
    UPDATE journal_entries SET status = 'posted', updated_at = NOW()
    WHERE id = v_alloc.journal_entry_id AND status = 'draft';
  END IF;

  -- إنشاء/تحديث Vendor Credit (إشعار دائن واحد لكل مرتجع)
  IF v_pr.settlement_method = 'debit_note' AND v_alloc.total_amount > 0 THEN
    SELECT id INTO v_vc_id FROM vendor_credits
    WHERE source_purchase_return_id = v_pr.id;

    IF v_vc_id IS NULL THEN
      INSERT INTO vendor_credits (
        company_id, supplier_id, bill_id,
        source_purchase_return_id, source_purchase_invoice_id, journal_entry_id,
        credit_number, credit_date, status,
        subtotal, tax_amount, total_amount, applied_amount,
        branch_id, cost_center_id, notes
      ) VALUES (
        v_pr.company_id, v_pr.supplier_id, v_pr.bill_id,
        v_pr.id, v_pr.bill_id, v_alloc.journal_entry_id,
        'VC-' || REPLACE(v_pr.return_number, 'PRET-', ''),
        v_pr.return_date, 'open',
        v_alloc.subtotal, v_alloc.tax_amount, v_alloc.total_amount, 0,
        v_alloc.branch_id, v_alloc.cost_center_id,
        'إشعار دائن تلقائي — مرتجع ' || v_pr.return_number
      ) RETURNING id INTO v_vc_id;
    ELSE
      UPDATE vendor_credits SET
        subtotal     = subtotal + v_alloc.subtotal,
        tax_amount   = tax_amount + v_alloc.tax_amount,
        total_amount = total_amount + v_alloc.total_amount
      WHERE id = v_vc_id;
    END IF;

    INSERT INTO vendor_credit_items (
      vendor_credit_id, product_id, description,
      quantity, unit_price, tax_rate, discount_percent, line_total
    )
    SELECT v_vc_id, pri.product_id, pri.description,
      pri.quantity, pri.unit_price, pri.tax_rate, pri.discount_percent, pri.line_total
    FROM purchase_return_items pri
    WHERE pri.warehouse_allocation_id = p_allocation_id;
  END IF;

  UPDATE purchase_return_warehouse_allocations SET
    workflow_status = 'confirmed',
    confirmed_by    = p_confirmed_by,
    confirmed_at    = NOW(),
    notes           = p_notes
  WHERE id = p_allocation_id;

  SELECT COUNT(*) INTO v_pending_count
  FROM purchase_return_warehouse_allocations
  WHERE purchase_return_id = v_alloc.purchase_return_id
    AND workflow_status = 'pending_approval';

  v_new_status := CASE WHEN v_pending_count = 0 THEN 'confirmed' ELSE 'partial_approval' END;

  UPDATE purchase_returns SET workflow_status = v_new_status, updated_at = NOW()
  WHERE id = v_alloc.purchase_return_id;

  IF v_pending_count = 0 AND v_pr.bill_id IS NOT NULL THEN
    SELECT returned_amount, total_amount, status
    INTO v_new_returned, v_bill_total, v_bill_st
    FROM bills WHERE id = v_pr.bill_id;
    v_new_returned := COALESCE(v_new_returned, 0) + v_pr.total_amount;

    IF v_bill_st IN ('paid', 'partially_paid') THEN
      UPDATE bills SET
        returned_amount = v_new_returned,
        return_status = CASE WHEN v_new_returned >= v_bill_total THEN 'full' ELSE 'partial' END,
        updated_at = NOW()
      WHERE id = v_pr.bill_id;
    ELSE
      UPDATE bills SET
        returned_amount = v_new_returned,
        return_status = CASE WHEN v_new_returned >= v_bill_total THEN 'full' ELSE 'partial' END,
        status = CASE WHEN (v_bill_total - v_pr.total_amount) <= 0 THEN 'fully_returned' ELSE v_bill_st END,
        total_amount = GREATEST(v_bill_total - v_pr.total_amount, 0),
        updated_at = NOW()
      WHERE id = v_pr.bill_id;
    END IF;
  END IF;

  v_result := jsonb_build_object(
    'allocation_id',       p_allocation_id,
    'purchase_return_id',  v_alloc.purchase_return_id,
    'allocation_status',   'confirmed',
    'overall_status',      v_new_status,
    'pending_allocations', v_pending_count
  );

  RETURN v_result;

EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'Confirm warehouse allocation failed (rolled back): %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- consume_fifo_lots(p_company_id uuid, p_product_id uuid, p_quantity numeric, p_consumption_type text, p_reference_type text, p_reference_id uuid, p_consumption_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.consume_fifo_lots(p_company_id uuid, p_product_id uuid, p_quantity numeric, p_consumption_type text, p_reference_type text, p_reference_id uuid, p_consumption_date date DEFAULT CURRENT_DATE)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_lot RECORD;
  v_remaining_qty NUMERIC := p_quantity;
  v_qty_from_lot NUMERIC;
  v_cost_from_lot NUMERIC;
  v_total_cogs NUMERIC := 0;
BEGIN
  -- الحصول على الدفعات بترتيب FIFO
  FOR v_lot IN
    SELECT id, remaining_quantity, unit_cost
    FROM fifo_cost_lots
    WHERE product_id = p_product_id
      AND company_id = p_company_id
      AND remaining_quantity > 0
    ORDER BY lot_date ASC, created_at ASC
    FOR UPDATE -- قفل الصفوف لتجنب race conditions
  LOOP
    EXIT WHEN v_remaining_qty <= 0;

    -- الكمية من هذه الدفعة
    v_qty_from_lot := LEAST(v_lot.remaining_quantity, v_remaining_qty);
    v_cost_from_lot := v_qty_from_lot * v_lot.unit_cost;

    -- تسجيل الاستهلاك
    INSERT INTO fifo_lot_consumptions (
      company_id,
      lot_id,
      product_id,
      consumption_type,
      reference_type,
      reference_id,
      quantity_consumed,
      unit_cost,
      total_cost,
      consumption_date
    ) VALUES (
      p_company_id,
      v_lot.id,
      p_product_id,
      p_consumption_type,
      p_reference_type,
      p_reference_id,
      v_qty_from_lot,
      v_lot.unit_cost,
      v_cost_from_lot,
      p_consumption_date
    );

    -- تحديث الكمية المتبقية في الدفعة
    UPDATE fifo_cost_lots
    SET remaining_quantity = remaining_quantity - v_qty_from_lot,
        updated_at = CURRENT_TIMESTAMP
    WHERE id = v_lot.id;

    -- إضافة للتكلفة الإجمالية
    v_total_cogs := v_total_cogs + v_cost_from_lot;
    v_remaining_qty := v_remaining_qty - v_qty_from_lot;
  END LOOP;

  -- إذا لم نجد دفعات كافية
  IF v_remaining_qty > 0 THEN
    RAISE WARNING 'Insufficient FIFO lots for product %. Missing quantity: %', p_product_id, v_remaining_qty;
  END IF;

  RETURN v_total_cogs;
END;
$function$
;

-- ---------------------------------------------------------------
-- convert_purchase_request_to_po(p_request_id uuid, p_user_id uuid, p_company_id uuid, p_supplier_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.convert_purchase_request_to_po(p_request_id uuid, p_user_id uuid, p_company_id uuid, p_supplier_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_request RECORD;
  v_user_role TEXT;
  v_user_branch UUID;
  v_po_id UUID;
  v_po_number TEXT;
  v_item RECORD;
  v_subtotal NUMERIC(12,2) := 0;
  v_tax_amount NUMERIC(12,2) := 0;
  v_total NUMERIC(12,2) := 0;
BEGIN
  SELECT role, branch_id INTO v_user_role, v_user_branch
  FROM company_members
  WHERE company_id = p_company_id AND user_id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User is not a member of this company');
  END IF;
  
  SELECT * INTO v_request
  FROM purchase_requests
  WHERE id = p_request_id 
    AND company_id = p_company_id
    AND status = 'approved'
  FOR UPDATE;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Purchase request not found or not approved');
  END IF;
  
  IF v_user_branch IS NOT NULL AND v_request.branch_id IS NOT NULL 
     AND v_user_branch != v_request.branch_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'Branch isolation violation');
  END IF;
  
  SELECT 
    COALESCE(SUM(estimated_total), 0),
    COALESCE(SUM(estimated_total * 0.15), 0)
  INTO v_subtotal, v_tax_amount
  FROM purchase_request_items
  WHERE purchase_request_id = p_request_id
    AND quantity_approved > 0;
  
  v_total := v_subtotal + v_tax_amount;
  
  INSERT INTO purchase_orders (
    company_id, supplier_id, po_date, due_date, status, currency, exchange_rate,
    subtotal, tax_amount, total, total_amount, branch_id, cost_center_id, warehouse_id,
    notes, created_by_user_id
  )
  VALUES (
    p_company_id, p_supplier_id, CURRENT_DATE, v_request.required_date, 'draft',
    v_request.currency, v_request.exchange_rate, v_subtotal, v_tax_amount, v_total, v_total,
    v_request.branch_id, v_request.cost_center_id, v_request.warehouse_id,
    COALESCE(v_request.notes, '') || ' (Converted from PR: ' || v_request.request_number || ')',
    p_user_id
  )
  RETURNING id, po_number INTO v_po_id, v_po_number;
  
  FOR v_item IN 
    SELECT * FROM purchase_request_items
    WHERE purchase_request_id = p_request_id
      AND quantity_approved > 0
  LOOP
    INSERT INTO purchase_order_items (
      purchase_order_id, product_id, description, quantity, unit_price, tax_rate, line_total, item_type
    )
    VALUES (
      v_po_id, v_item.product_id, v_item.description, v_item.quantity_approved,
      v_item.estimated_unit_price, 15.0, v_item.estimated_total, v_item.item_type
    );
  END LOOP;
  
  UPDATE purchase_requests
  SET 
    status = 'converted_to_po',
    converted_to_po_id = v_po_id,
    converted_at = NOW(),
    converted_by = p_user_id,
    updated_at = NOW()
  WHERE id = p_request_id;
  
  INSERT INTO audit_logs (
    company_id, user_id, action, entity_type, entity_id, old_values, new_values, created_at
  )
  VALUES (
    p_company_id, p_user_id, 'purchase_request_converted', 'purchase_request', p_request_id,
    jsonb_build_object('status', 'approved'),
    jsonb_build_object('status', 'converted_to_po', 'po_id', v_po_id, 'po_number', v_po_number),
    NOW()
  );
  
  RETURN jsonb_build_object('success', true, 'po_id', v_po_id, 'po_number', v_po_number, 'request_id', p_request_id);
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- copy_default_permissions_for_company(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.copy_default_permissions_for_company(p_company_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_role TEXT;
  v_resource TEXT;
  v_actions TEXT[];
  v_can_read BOOLEAN;
  v_can_write BOOLEAN;
  v_can_update BOOLEAN;
  v_can_delete BOOLEAN;
  v_all_access BOOLEAN;
  v_can_access BOOLEAN;
BEGIN
  -- لكل دور
  FOR v_role IN SELECT name FROM roles LOOP
    -- لكل مورد فريد
    FOR v_resource IN
      SELECT DISTINCT p.resource
      FROM permissions p
      JOIN role_default_permissions rdp ON rdp.permission_action = p.action
      WHERE rdp.role_name = v_role
    LOOP
      -- جمع الـ actions لهذا المورد
      SELECT ARRAY_AGG(p.action)
      INTO v_actions
      FROM permissions p
      JOIN role_default_permissions rdp ON rdp.permission_action = p.action
      WHERE rdp.role_name = v_role AND p.resource = v_resource;

      -- تحديد الصلاحيات الأساسية
      v_can_access := EXISTS (
        SELECT 1 FROM role_default_permissions rdp
        JOIN permissions p ON p.action = rdp.permission_action
        WHERE rdp.role_name = v_role AND p.resource = v_resource AND p.action LIKE '%:access'
      );

      v_can_read := EXISTS (
        SELECT 1 FROM role_default_permissions rdp
        JOIN permissions p ON p.action = rdp.permission_action
        WHERE rdp.role_name = v_role AND p.resource = v_resource AND p.action LIKE '%:read'
      );

      v_can_write := EXISTS (
        SELECT 1 FROM role_default_permissions rdp
        JOIN permissions p ON p.action = rdp.permission_action
        WHERE rdp.role_name = v_role AND p.resource = v_resource AND p.action LIKE '%:create'
      );

      v_can_update := EXISTS (
        SELECT 1 FROM role_default_permissions rdp
        JOIN permissions p ON p.action = rdp.permission_action
        WHERE rdp.role_name = v_role AND p.resource = v_resource AND p.action LIKE '%:update'
      );

      v_can_delete := EXISTS (
        SELECT 1 FROM role_default_permissions rdp
        JOIN permissions p ON p.action = rdp.permission_action
        WHERE rdp.role_name = v_role AND p.resource = v_resource AND p.action LIKE '%:delete'
      );

      -- owner و admin لديهم كل الصلاحيات
      v_all_access := v_role IN ('owner', 'admin');

      -- إدراج أو تحديث الصلاحية
      INSERT INTO company_role_permissions (
        company_id, role, resource,
        can_read, can_write, can_update, can_delete, all_access, can_access,
        allowed_actions
      ) VALUES (
        p_company_id, v_role, v_resource,
        v_can_read, v_can_write, v_can_update, v_can_delete, v_all_access, v_can_access,
        v_actions
      )
      ON CONFLICT (company_id, role, resource) DO UPDATE SET
        can_read = EXCLUDED.can_read,
        can_write = EXCLUDED.can_write,
        can_update = EXCLUDED.can_update,
        can_delete = EXCLUDED.can_delete,
        all_access = EXCLUDED.all_access,
        can_access = EXCLUDED.can_access,
        allowed_actions = EXCLUDED.allowed_actions;
    END LOOP;
  END LOOP;
END;
$function$
;

