-- ---------------------------------------------------------------
-- count_unbalanced_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.count_unbalanced_entries(p_company_id uuid DEFAULT NULL::uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_count
  FROM (
    SELECT je.id
    FROM journal_entries je
    LEFT JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE (p_company_id IS NULL OR je.company_id = p_company_id)
    GROUP BY je.id
    HAVING ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) > 0.01
    LIMIT 1000 -- حد أقصى للأمان
  ) AS unbalanced;
  
  RETURN v_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_audit_log(p_company_id uuid, p_user_id uuid, p_action text, p_target_table text, p_record_id uuid, p_record_identifier text, p_old_data jsonb, p_new_data jsonb, p_branch_id uuid, p_cost_center_id uuid, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_audit_log(p_company_id uuid, p_user_id uuid, p_action text, p_target_table text, p_record_id uuid, p_record_identifier text, p_old_data jsonb, p_new_data jsonb, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_reason text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_user_email TEXT;
  v_user_name TEXT;
  v_changed_fields TEXT[];
  v_log_id UUID;
  v_branch_id UUID;
  v_cost_center_id UUID;
BEGIN
  -- جلب بيانات المستخدم
  IF p_user_id IS NOT NULL THEN
    SELECT email, raw_user_meta_data->>'full_name'
    INTO v_user_email, v_user_name
    FROM auth.users WHERE id = p_user_id;
  END IF;

  -- حساب الحقول التي تغيرت
  IF p_action = 'UPDATE' AND p_old_data IS NOT NULL AND p_new_data IS NOT NULL THEN
    SELECT array_agg(key)
    INTO v_changed_fields
    FROM (
      SELECT key FROM jsonb_each(p_new_data)
      EXCEPT
      SELECT key FROM jsonb_each(p_old_data) WHERE p_old_data->key = p_new_data->key
    ) changed;
  END IF;

  -- استخراج branch_id و cost_center_id من البيانات إذا لم يتم تمريرها
  v_branch_id := COALESCE(p_branch_id, (p_new_data->>'branch_id')::UUID, (p_old_data->>'branch_id')::UUID);
  v_cost_center_id := COALESCE(p_cost_center_id, (p_new_data->>'cost_center_id')::UUID, (p_old_data->>'cost_center_id')::UUID);

  -- إدراج السجل
  INSERT INTO audit_logs (
    company_id, user_id, user_email, user_name,
    action, target_table, record_id, record_identifier,
    old_data, new_data, changed_fields,
    branch_id, cost_center_id, reason
  ) VALUES (
    p_company_id, p_user_id, v_user_email, COALESCE(v_user_name, v_user_email),
    p_action, p_target_table, p_record_id, p_record_identifier,
    p_old_data, p_new_data, v_changed_fields,
    v_branch_id, v_cost_center_id, p_reason
  ) RETURNING id INTO v_log_id;

  RETURN v_log_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_auto_invoice_from_sales_order(p_sales_order_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_auto_invoice_from_sales_order(p_sales_order_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_so RECORD;
  v_invoice_id UUID;
  v_item RECORD;
  v_invoice_number TEXT;
  v_seq INTEGER;
BEGIN
  -- 1. جلب أمر البيع
  SELECT * INTO v_so FROM sales_orders WHERE id = p_sales_order_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'SALES_ORDER_NOT_FOUND: %', p_sales_order_id;
  END IF;

  -- 2. التحقق من أنه لا توجد فاتورة مرتبطة بالفعل
  IF v_so.invoice_id IS NOT NULL THEN
    RETURN jsonb_build_object(
      'success', true,
      'invoice_id', v_so.invoice_id,
      'already_exists', true,
      'message', 'فاتورة مسودة موجودة بالفعل لهذا الأمر'
    );
  END IF;

  -- 3. توليد رقم الفاتورة
  SELECT COALESCE(MAX(CAST(REGEXP_REPLACE(invoice_number, '[^0-9]', '', 'g') AS INTEGER)), 0) + 1
  INTO v_seq
  FROM invoices
  WHERE company_id = v_so.company_id
    AND invoice_number ~ '^[A-Z]+-[0-9]+$';

  v_invoice_number := 'INV-' || LPAD(v_seq::TEXT, 5, '0');

  -- 4. إنشاء الفاتورة Draft
  INSERT INTO invoices (
    company_id, customer_id, invoice_date, due_date,
    subtotal, tax_amount, total_amount,
    discount_type, discount_value, discount_position,
    tax_inclusive, shipping, shipping_provider_id,
    status, sales_order_id,
    branch_id, cost_center_id, warehouse_id,
    created_by_user_id, currency_code,
    original_total, invoice_number
  ) VALUES (
    v_so.company_id,
    v_so.customer_id,
    CURRENT_DATE,
    v_so.due_date,
    COALESCE(v_so.subtotal, v_so.total_amount, 0),
    COALESCE(v_so.tax_amount, 0),
    COALESCE(v_so.total_amount, v_so.total, 0),
    COALESCE(v_so.discount_type, 'percent'),
    COALESCE(v_so.discount_value, 0),
    COALESCE(v_so.discount_position, 'before_tax'),
    COALESCE(v_so.tax_inclusive, false),
    COALESCE(v_so.shipping, v_so.shipping_charge, 0),
    v_so.shipping_provider_id,
    'draft',
    v_so.id,
    v_so.branch_id,
    v_so.cost_center_id,
    v_so.warehouse_id,
    v_so.created_by_user_id,
    COALESCE(v_so.currency, 'EGP'),
    COALESCE(v_so.total_amount, v_so.total, 0),
    v_invoice_number
  )
  RETURNING id INTO v_invoice_id;

  -- 5. نسخ بنود أمر البيع إلى الفاتورة
  FOR v_item IN (
    SELECT * FROM sales_order_items 
    WHERE sales_order_id = p_sales_order_id
  )
  LOOP
    INSERT INTO invoice_items (
      invoice_id, product_id, description,
      quantity, unit_price, tax_rate,
      discount_percent, line_total, item_type,
      returned_quantity
    ) VALUES (
      v_invoice_id,
      v_item.product_id,
      v_item.description,
      v_item.quantity,
      v_item.unit_price,
      COALESCE(v_item.tax_rate, 0),
      COALESCE(v_item.discount_percent, 0),
      v_item.line_total,
      COALESCE(v_item.item_type, 'product'),
      0
    );
  END LOOP;

  -- 6. ربط الفاتورة بأمر البيع
  UPDATE sales_orders
  SET invoice_id = v_invoice_id,
      status = 'invoiced',
      updated_at = NOW()
  WHERE id = p_sales_order_id;

  RETURN jsonb_build_object(
    'success', true,
    'invoice_id', v_invoice_id,
    'invoice_number', v_invoice_number,
    'already_exists', false
  );
EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'AUTO_INVOICE_CREATION_FAILED: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_bill_ap_expense_entry(p_bill_id uuid, p_company_id uuid, p_entry_date date, p_description text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_bill_ap_expense_entry(p_bill_id uuid, p_company_id uuid, p_entry_date date, p_description text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_entry_id UUID;
  v_accounts RECORD;
  v_bill RECORD;
  v_subtotal DECIMAL(15, 2);
  v_tax_amount DECIMAL(15, 2);
  v_total DECIMAL(15, 2);
BEGIN
  -- جلب بيانات فاتورة الشراء
  SELECT 
    subtotal, tax_amount, total_amount, bill_number
  INTO v_bill
  FROM bills
  WHERE id = p_bill_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'فاتورة الشراء غير موجودة: %', p_bill_id;
  END IF;
  
  v_subtotal := COALESCE(v_bill.subtotal, 0);
  v_tax_amount := COALESCE(v_bill.tax_amount, 0);
  v_total := COALESCE(v_bill.total_amount, 0);
  
  -- إيجاد الحسابات المطلوبة
  SELECT * INTO v_accounts FROM find_company_accounts(p_company_id);
  
  IF v_accounts.ap_account_id IS NULL OR v_accounts.expense_account_id IS NULL THEN
    RAISE EXCEPTION 'حسابات AP أو Expense غير موجودة للشركة: %', p_company_id;
  END IF;
  
  -- إنشاء القيد
  INSERT INTO journal_entries (
    company_id,
    reference_type,
    reference_id,
    entry_date,
    description,
    status
  ) VALUES (
    p_company_id,
    'bill',
    p_bill_id,
    p_entry_date,
    COALESCE(p_description, 'قيد فاتورة شراء: ' || v_bill.bill_number),
    'posted'
  ) RETURNING id INTO v_entry_id;
  
  -- إنشاء سطور القيد
  -- 1. Expense (Debit)
  INSERT INTO journal_entry_lines (
    journal_entry_id,
    account_id,
    debit_amount,
    credit_amount,
    description
  ) VALUES (
    v_entry_id,
    v_accounts.expense_account_id,
    v_subtotal,
    0,
    'المصروفات/التكاليف'
  );
  
  -- 2. VAT Payable (Debit) - إن وجد
  IF v_tax_amount > 0 AND v_accounts.vat_payable_account_id IS NOT NULL THEN
    INSERT INTO journal_entry_lines (
      journal_entry_id,
      account_id,
      debit_amount,
      credit_amount,
      description
    ) VALUES (
      v_entry_id,
      v_accounts.vat_payable_account_id,
      v_tax_amount,
      0,
      'ضريبة القيمة المضافة (مدخلات)'
    );
  END IF;
  
  -- 3. AP (Credit)
  INSERT INTO journal_entry_lines (
    journal_entry_id,
    account_id,
    debit_amount,
    credit_amount,
    description
  ) VALUES (
    v_entry_id,
    v_accounts.ap_account_id,
    0,
    v_total,
    'الذمم الدائنة'
  );
  
  -- إذا لم يكن هناك حساب VAT، نضيف الفرق إلى Expense
  IF v_tax_amount > 0 AND v_accounts.vat_payable_account_id IS NULL THEN
    UPDATE journal_entry_lines
    SET debit_amount = debit_amount + v_tax_amount
    WHERE journal_entry_id = v_entry_id
    AND account_id = v_accounts.expense_account_id;
  END IF;
  
  RETURN v_entry_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_bill_payment_entry(p_bill_id uuid, p_payment_id uuid, p_company_id uuid, p_entry_date date, p_amount numeric, p_payment_method text, p_description text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_bill_payment_entry(p_bill_id uuid, p_payment_id uuid, p_company_id uuid, p_entry_date date, p_amount numeric, p_payment_method text, p_description text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_entry_id UUID;
  v_accounts RECORD;
  v_bill RECORD;
  v_cash_bank_account_id UUID;
BEGIN
  -- جلب بيانات فاتورة الشراء
  SELECT bill_number INTO v_bill
  FROM bills
  WHERE id = p_bill_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'فاتورة الشراء غير موجودة: %', p_bill_id;
  END IF;
  
  -- إيجاد الحسابات المطلوبة
  SELECT * INTO v_accounts FROM find_company_accounts(p_company_id);
  
  IF v_accounts.ap_account_id IS NULL THEN
    RAISE EXCEPTION 'حساب AP غير موجود للشركة: %', p_company_id;
  END IF;
  
  -- تحديد حساب النقد/البنك
  IF p_payment_method ILIKE '%bank%' OR p_payment_method ILIKE '%بنك%' OR p_payment_method ILIKE '%transfer%' THEN
    v_cash_bank_account_id := v_accounts.bank_account_id;
  ELSE
    v_cash_bank_account_id := v_accounts.cash_account_id;
  END IF;
  
  IF v_cash_bank_account_id IS NULL THEN
    RAISE EXCEPTION 'حساب النقد/البنك غير موجود للشركة: %', p_company_id;
  END IF;
  
  -- إنشاء القيد
  INSERT INTO journal_entries (
    company_id,
    reference_type,
    reference_id,
    entry_date,
    description,
    status
  ) VALUES (
    p_company_id,
    'bill_payment',
    COALESCE(p_payment_id, p_bill_id),
    p_entry_date,
    COALESCE(p_description, 'قيد دفع فاتورة شراء: ' || v_bill.bill_number),
    'posted'
  ) RETURNING id INTO v_entry_id;
  
  -- إنشاء سطور القيد
  -- 1. AP (Debit)
  INSERT INTO journal_entry_lines (
    journal_entry_id,
    account_id,
    debit_amount,
    credit_amount,
    description
  ) VALUES (
    v_entry_id,
    v_accounts.ap_account_id,
    p_amount,
    0,
    'الذمم الدائنة'
  );
  
  -- 2. Cash/Bank (Credit)
  INSERT INTO journal_entry_lines (
    journal_entry_id,
    account_id,
    debit_amount,
    credit_amount,
    description
  ) VALUES (
    v_entry_id,
    v_cash_bank_account_id,
    0,
    p_amount,
    'النقد/البنك'
  );
  
  RETURN v_entry_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_booking_atomic(p_company_id uuid, p_branch_id uuid, p_service_id uuid, p_customer_id uuid, p_created_by uuid, p_booking_date date, p_start_time time without time zone, p_quantity numeric, p_staff_user_id uuid, p_discount_amount numeric, p_booking_source text, p_notes text, p_cost_center_id uuid, p_skip_schedule_check boolean, p_staff_user_ids uuid[])
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_booking_atomic(p_company_id uuid, p_branch_id uuid, p_service_id uuid, p_customer_id uuid, p_created_by uuid, p_booking_date date, p_start_time time without time zone, p_quantity numeric DEFAULT 1, p_staff_user_id uuid DEFAULT NULL::uuid, p_discount_amount numeric DEFAULT 0, p_booking_source text DEFAULT 'manual'::text, p_notes text DEFAULT NULL::text, p_cost_center_id uuid DEFAULT NULL::uuid, p_skip_schedule_check boolean DEFAULT false, p_staff_user_ids uuid[] DEFAULT NULL::uuid[])
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service       public.services;
  v_booking_id    UUID;
  v_booking_no    TEXT;
  v_end_time      TIME;
  v_totals        RECORD;
  v_staff_arr     UUID[];
  v_legacy_staff  UUID;
BEGIN
  v_service  := public.svc_assert_service_bookable(p_service_id, p_company_id);
  v_end_time := (p_start_time + (v_service.duration_minutes || ' minutes')::INTERVAL)::TIME;

  PERFORM public.bkg_validate_advance_booking(p_service_id, p_booking_date, p_start_time);

  SELECT * INTO v_totals
    FROM public.bkg_compute_totals(
      v_service.unit_price, p_quantity, p_discount_amount,
      v_service.tax_rate, v_service.commission_rate
    );

  v_booking_no := public.bkg_generate_booking_no(p_company_id);

  IF p_staff_user_ids IS NOT NULL AND array_length(p_staff_user_ids, 1) > 0 THEN
    v_staff_arr := p_staff_user_ids;
  ELSIF p_staff_user_id IS NOT NULL THEN
    v_staff_arr := ARRAY[p_staff_user_id];
  ELSE
    v_staff_arr := NULL;
  END IF;

  v_legacy_staff := CASE
    WHEN v_staff_arr IS NULL THEN NULL
    ELSE v_staff_arr[1]
  END;

  INSERT INTO public.bookings (
    company_id, branch_id, cost_center_id, booking_no, service_id, customer_id, staff_user_id,
    booking_date, start_time, end_time, duration_minutes, status,
    unit_price, quantity, discount_amount, tax_amount, total_amount, currency_code, commission_amount,
    payment_status, paid_amount, booking_source, notes, created_by, updated_by
  ) VALUES (
    p_company_id, p_branch_id, p_cost_center_id, v_booking_no, p_service_id, p_customer_id, v_legacy_staff,
    p_booking_date, p_start_time, v_end_time, v_service.duration_minutes, 'draft',
    v_service.unit_price, p_quantity, COALESCE(p_discount_amount, 0), v_totals.tax_amount, v_totals.total_amount,
    v_service.currency_code, v_totals.commission_amount,
    'unpaid', 0, p_booking_source, p_notes, p_created_by, p_created_by
  ) RETURNING id INTO v_booking_id;

  IF v_staff_arr IS NOT NULL THEN
    INSERT INTO public.booking_staff_assignments (booking_id, user_id, company_id, branch_id)
    SELECT v_booking_id, uid, p_company_id, p_branch_id
      FROM unnest(v_staff_arr) AS uid
    ON CONFLICT (booking_id, user_id) DO NOTHING;
  END IF;

  RETURN jsonb_build_object(
    'success',        true,
    'booking_id',     v_booking_id,
    'booking_no',     v_booking_no,
    'end_time',       v_end_time,
    'total_amount',   v_totals.total_amount,
    'staff_user_ids', COALESCE(v_staff_arr, ARRAY[]::uuid[])
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- create_branch_atomic(p_company_id uuid, p_name text, p_code text, p_address text, p_city text, p_phone text, p_email text, p_manager_name text, p_is_active boolean)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_branch_atomic(p_company_id uuid, p_name text, p_code text, p_address text, p_city text, p_phone text, p_email text, p_manager_name text, p_is_active boolean)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_branch_id UUID;
    v_cc_id UUID;
    v_wh_id UUID;
    v_result jsonb;
BEGIN
    -- 1. Create Branch
    INSERT INTO branches (
        company_id, name, branch_name, code, branch_code, address, city, phone, email, manager_name, is_active, is_main, is_head_office
    ) VALUES (
        p_company_id, p_name, p_name, p_code, p_code, p_address, p_city, p_phone, p_email, p_manager_name, COALESCE(p_is_active, true), false, false
    ) RETURNING id INTO v_branch_id;

    -- 2. Create Cost Center
    INSERT INTO cost_centers (
        company_id, branch_id, cost_center_name, cost_center_code, is_active
    ) VALUES (
        p_company_id, v_branch_id, 'مركز تكلفة - ' || p_name, 'CC-' || p_code, true
    ) RETURNING id INTO v_cc_id;

    -- 3. Create Warehouse — v3.74.37: dropped 'type' (column doesn't exist);
    --                     branch warehouses are simply not main.
    INSERT INTO warehouses (
        company_id, branch_id, name, is_main, is_active
    ) VALUES (
        p_company_id, v_branch_id, 'مستودع - ' || p_name, false, true
    ) RETURNING id INTO v_wh_id;

    -- 4. Update Branch with Defaults
    UPDATE branches
    SET default_cost_center_id = v_cc_id,
        default_warehouse_id = v_wh_id
    WHERE id = v_branch_id;

    v_result := jsonb_build_object(
        'success', true,
        'branch_id', v_branch_id,
        'branch_name', p_name,
        'cost_center_id', v_cc_id,
        'warehouse_id', v_wh_id
    );

    RETURN v_result;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to create branch infrastructure: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_cogs_journal_for_invoice(p_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_cogs_journal_for_invoice(p_invoice_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$ DECLARE v_invoice RECORD; v_item RECORD; v_journal_entry_id UUID; v_cogs_account_id UUID; v_inventory_account_id UUID; v_total_cogs NUMERIC := 0; v_item_cost NUMERIC; BEGIN SELECT * INTO v_invoice FROM invoices WHERE id = p_invoice_id; IF NOT FOUND THEN RAISE EXCEPTION 'Invoice not found: %', p_invoice_id; END IF; IF EXISTS (SELECT 1 FROM journal_entries WHERE reference_type = 'invoice_cogs' AND reference_id = p_invoice_id) THEN RETURN NULL; END IF; SELECT id INTO v_cogs_account_id FROM chart_of_accounts WHERE company_id = v_invoice.company_id AND (sub_type = 'cogs' OR sub_type = 'cost_of_goods_sold' OR account_name ILIKE '%cost of goods sold%' OR account_name ILIKE '%تكلفة البضاعة المباعة%' OR account_name LIKE '%COGS%') AND is_active = true LIMIT 1; SELECT id INTO v_inventory_account_id FROM chart_of_accounts WHERE company_id = v_invoice.company_id AND (sub_type = 'inventory' OR account_name ILIKE '%inventory%' OR account_name ILIKE '%مخزون%') AND is_active = true LIMIT 1; IF v_cogs_account_id IS NULL OR v_inventory_account_id IS NULL THEN RETURN NULL; END IF; FOR v_item IN SELECT ii.*, p.name as product_name FROM invoice_items ii JOIN products p ON p.id = ii.product_id WHERE ii.invoice_id = p_invoice_id AND p.item_type = 'product' LOOP v_item_cost := calculate_fifo_cost(v_item.product_id, v_invoice.warehouse_id, v_item.quantity); v_total_cogs := v_total_cogs + v_item_cost; END LOOP; IF v_total_cogs <= 0 THEN RETURN NULL; END IF; INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description, status, branch_id, cost_center_id, warehouse_id) VALUES (v_invoice.company_id, 'invoice_cogs', p_invoice_id, v_invoice.invoice_date, 'تكلفة البضاعة المباعة - فاتورة ' || v_invoice.invoice_number, 'posted', v_invoice.branch_id, v_invoice.cost_center_id, v_invoice.warehouse_id) RETURNING id INTO v_journal_entry_id; INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id) VALUES (v_journal_entry_id, v_cogs_account_id, v_total_cogs, 0, 'تكلفة البضاعة المباعة', v_invoice.branch_id, v_invoice.cost_center_id); INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id) VALUES (v_journal_entry_id, v_inventory_account_id, 0, v_total_cogs, 'تخفيض المخزون', v_invoice.branch_id, v_invoice.cost_center_id); UPDATE inventory_transactions SET journal_entry_id = v_journal_entry_id WHERE transaction_type = 'sale' AND reference_id = p_invoice_id AND journal_entry_id IS NULL; RETURN v_journal_entry_id; END; $function$
;

-- ---------------------------------------------------------------
-- create_company_atomic(p_user_id uuid, p_email text, p_company_name text, p_contact_name text, p_phone text, p_country text, p_city text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_company_atomic(p_user_id uuid, p_email text, p_company_name text, p_contact_name text, p_phone text, p_country text, p_city text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_company_id UUID;
    v_member_id UUID;
    v_branch_id UUID;
    v_cc_id UUID;
    v_wh_id UUID;
    v_result jsonb;
BEGIN
    -- 1. Create Company (v3.74.37: dropped subscription_plan + max_users)
    INSERT INTO companies (
        user_id, name, email, phone, country, city, subscription_status
    ) VALUES (
        p_user_id, p_company_name, p_email, p_phone, p_country, p_city, 'active'
    ) RETURNING id INTO v_company_id;

    -- 2. Create Company Member (Owner) — v3.74.37: dropped full_name
    INSERT INTO company_members (
        company_id, user_id, role, email
    ) VALUES (
        v_company_id, p_user_id, 'owner', p_email
    ) RETURNING id INTO v_member_id;

    -- 3. Create Main Branch
    INSERT INTO branches (
        company_id, name, branch_name, code, branch_code, email, phone, is_main, is_active, is_head_office
    ) VALUES (
        v_company_id, 'الفرع الرئيسي', 'الفرع الرئيسي', 'MAIN', 'MAIN', p_email, p_phone, true, true, true
    ) RETURNING id INTO v_branch_id;

    -- 4. Create Default Cost Center
    INSERT INTO cost_centers (
        company_id, branch_id, cost_center_name, cost_center_code, is_active
    ) VALUES (
        v_company_id, v_branch_id, 'مركز التكلفة الرئيسي', 'CC-MAIN', true
    ) RETURNING id INTO v_cc_id;

    -- 5. Create Default Warehouse — v3.74.37: type 'main' → is_main=true
    INSERT INTO warehouses (
        company_id, branch_id, name, is_main, is_active
    ) VALUES (
        v_company_id, v_branch_id, 'المستودع الرئيسي', true, true
    ) RETURNING id INTO v_wh_id;

    -- 6. Update Branch with Defaults
    UPDATE branches
    SET default_cost_center_id = v_cc_id,
        default_warehouse_id = v_wh_id
    WHERE id = v_branch_id;

    v_result := jsonb_build_object(
        'success', true,
        'company_id', v_company_id,
        'branch_id', v_branch_id,
        'cost_center_id', v_cc_id,
        'warehouse_id', v_wh_id
    );

    RETURN v_result;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to create company infrastructure: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_customer_debit_note(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_customer_id uuid, p_source_invoice_id uuid, p_debit_note_date date, p_reference_type character varying, p_reason text, p_items jsonb, p_notes text, p_currency_id uuid, p_exchange_rate numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_customer_debit_note(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_customer_id uuid, p_source_invoice_id uuid, p_debit_note_date date, p_reference_type character varying, p_reason text, p_items jsonb, p_notes text DEFAULT NULL::text, p_currency_id uuid DEFAULT NULL::uuid, p_exchange_rate numeric DEFAULT 1)
 RETURNS TABLE(debit_note_id uuid, debit_note_number character varying, total_amount numeric, journal_entry_id uuid, success boolean, message text)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_debit_note_id UUID;
  v_debit_note_number VARCHAR(50);
  v_journal_entry_id UUID;
  v_subtotal DECIMAL(15,2) := 0;
  v_tax_amount DECIMAL(15,2) := 0;
  v_total_amount DECIMAL(15,2) := 0;
  v_item JSONB;
  v_line_total DECIMAL(15,2);
  v_line_tax DECIMAL(15,2);
  v_ar_account_id UUID;
  v_revenue_account_id UUID;
  v_customer_name TEXT;
  v_invoice_number TEXT;
  v_original_currency VARCHAR(3);
BEGIN
  IF p_company_id IS NULL OR p_customer_id IS NULL OR p_source_invoice_id IS NULL THEN
    RETURN QUERY SELECT NULL::UUID, NULL::VARCHAR(50), 0::DECIMAL(15,2), NULL::UUID, FALSE, 
      'Missing required fields: company_id, customer_id, or source_invoice_id';
    RETURN;
  END IF;
  
  IF p_items IS NULL OR jsonb_array_length(p_items) = 0 THEN
    RETURN QUERY SELECT NULL::UUID, NULL::VARCHAR(50), 0::DECIMAL(15,2), NULL::UUID, FALSE, 
      'At least one item is required';
    RETURN;
  END IF;
  
  SELECT c.name INTO v_customer_name FROM customers c WHERE c.id = p_customer_id;
  SELECT i.invoice_number INTO v_invoice_number FROM invoices i WHERE i.id = p_source_invoice_id;
  
  IF v_customer_name IS NULL OR v_invoice_number IS NULL THEN
    RETURN QUERY SELECT NULL::UUID, NULL::VARCHAR(50), 0::DECIMAL(15,2), NULL::UUID, FALSE, 
      'Customer or invoice not found';
    RETURN;
  END IF;
  
  v_debit_note_number := generate_customer_debit_note_number(p_company_id);
  
  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    v_line_total := (v_item->>'quantity')::DECIMAL * (v_item->>'unit_price')::DECIMAL;
    v_line_tax := v_line_total * COALESCE((v_item->>'tax_rate')::DECIMAL, 0) / 100;
    v_subtotal := v_subtotal + v_line_total;
    v_tax_amount := v_tax_amount + v_line_tax;
  END LOOP;
  
  v_total_amount := v_subtotal + v_tax_amount;
  
  IF p_currency_id IS NULL THEN
    v_original_currency := 'EGP';
  ELSE
    SELECT code INTO v_original_currency FROM currencies WHERE id = p_currency_id;
  END IF;
  
  INSERT INTO customer_debit_notes (
    company_id, branch_id, cost_center_id, customer_id, debit_note_number, debit_note_date,
    source_invoice_id, subtotal, tax_amount, total_amount, applied_amount, currency_id,
    original_currency, original_subtotal, original_tax_amount, original_total_amount,
    exchange_rate, status, reference_type, reason, notes
  ) VALUES (
    p_company_id, p_branch_id, p_cost_center_id, p_customer_id, v_debit_note_number, p_debit_note_date,
    p_source_invoice_id, v_subtotal, v_tax_amount, v_total_amount, 0, p_currency_id,
    v_original_currency, v_subtotal, v_tax_amount, v_total_amount,
    p_exchange_rate, 'open', p_reference_type, p_reason, p_notes
  ) RETURNING id INTO v_debit_note_id;
  
  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    v_line_total := (v_item->>'quantity')::DECIMAL * (v_item->>'unit_price')::DECIMAL;
    INSERT INTO customer_debit_note_items (
      customer_debit_note_id, product_id, description, quantity, unit_price, tax_rate, line_total, item_type
    ) VALUES (
      v_debit_note_id, (v_item->>'product_id')::UUID, v_item->>'description',
      (v_item->>'quantity')::DECIMAL, (v_item->>'unit_price')::DECIMAL,
      COALESCE((v_item->>'tax_rate')::DECIMAL, 0), v_line_total, COALESCE(v_item->>'item_type', 'charge')
    );
  END LOOP;
  
  SELECT account_id INTO v_ar_account_id FROM profit_distribution_settings
  WHERE company_id = p_company_id AND setting_key = 'accounts_receivable_account';
  
  SELECT account_id INTO v_revenue_account_id FROM profit_distribution_settings
  WHERE company_id = p_company_id AND setting_key = 'sales_account';
  
  IF v_ar_account_id IS NOT NULL AND v_revenue_account_id IS NOT NULL THEN
    INSERT INTO journal_entries (
      company_id, branch_id, cost_center_id, reference_type, reference_id, entry_date, description, status
    ) VALUES (
      p_company_id, p_branch_id, p_cost_center_id, 'customer_debit', v_debit_note_id, p_debit_note_date,
      'Customer Debit Note ' || v_debit_note_number || ' - ' || v_customer_name || ' - Invoice ' || v_invoice_number, 'posted'
    ) RETURNING id INTO v_journal_entry_id;

    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
    VALUES (v_journal_entry_id, v_ar_account_id, v_total_amount * p_exchange_rate, 0, 'AR - Customer Debit Note ' || v_debit_note_number, p_branch_id, p_cost_center_id);

    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
    VALUES (v_journal_entry_id, v_revenue_account_id, 0, v_total_amount * p_exchange_rate, 'Revenue - Customer Debit Note ' || v_debit_note_number, p_branch_id, p_cost_center_id);

    UPDATE customer_debit_notes SET journal_entry_id = v_journal_entry_id WHERE id = v_debit_note_id;

    RETURN QUERY SELECT v_debit_note_id, v_debit_note_number, v_total_amount, v_journal_entry_id, TRUE,
      'Customer debit note created successfully with journal entry';
  ELSE
    RETURN QUERY SELECT v_debit_note_id, v_debit_note_number, v_total_amount, NULL::UUID, TRUE,
      'Customer debit note created successfully (no journal entry - accounts not configured)';
  END IF;

EXCEPTION
  WHEN OTHERS THEN
    RETURN QUERY SELECT NULL::UUID, NULL::VARCHAR(50), 0::DECIMAL(15,2), NULL::UUID, FALSE,
      'Error creating customer debit note: ' || SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_customer_debit_note(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_customer_id uuid, p_source_invoice_id uuid, p_debit_note_date date, p_reference_type character varying, p_reason text, p_items jsonb, p_notes text, p_currency_id uuid, p_exchange_rate numeric, p_created_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_customer_debit_note(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_customer_id uuid, p_source_invoice_id uuid, p_debit_note_date date, p_reference_type character varying, p_reason text, p_items jsonb, p_notes text DEFAULT NULL::text, p_currency_id uuid DEFAULT NULL::uuid, p_exchange_rate numeric DEFAULT 1, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS TABLE(debit_note_id uuid, debit_note_number character varying, total_amount numeric, approval_status character varying, success boolean, message text)
 LANGUAGE plpgsql
AS $function$ DECLARE v_debit_note_id UUID; v_debit_note_number VARCHAR(50); v_subtotal DECIMAL(15,2) := 0; v_tax_amount DECIMAL(15,2) := 0; v_total_amount DECIMAL(15,2) := 0; v_item JSONB; v_line_total DECIMAL(15,2); v_line_tax DECIMAL(15,2); v_customer_name TEXT; v_invoice_number TEXT; v_original_currency VARCHAR(3); v_approval_status VARCHAR(20) := 'draft'; BEGIN IF p_company_id IS NULL OR p_customer_id IS NULL OR p_source_invoice_id IS NULL THEN RETURN QUERY SELECT NULL::UUID, NULL::VARCHAR(50), 0::DECIMAL(15,2), NULL::VARCHAR(20), FALSE, 'Missing required fields: company_id, customer_id, or source_invoice_id'; RETURN; END IF; IF p_items IS NULL OR jsonb_array_length(p_items) = 0 THEN RETURN QUERY SELECT NULL::UUID, NULL::VARCHAR(50), 0::DECIMAL(15,2), NULL::VARCHAR(20), FALSE, 'At least one item is required'; RETURN; END IF; SELECT c.name INTO v_customer_name FROM customers c WHERE c.id = p_customer_id; SELECT i.invoice_number INTO v_invoice_number FROM invoices i WHERE i.id = p_source_invoice_id; IF v_customer_name IS NULL OR v_invoice_number IS NULL THEN RETURN QUERY SELECT NULL::UUID, NULL::VARCHAR(50), 0::DECIMAL(15,2), NULL::VARCHAR(20), FALSE, 'Customer or invoice not found'; RETURN; END IF; v_debit_note_number := generate_customer_debit_note_number(p_company_id); FOR v_item IN SELECT * FROM jsonb_array_elements(p_items) LOOP v_line_total := (v_item->>'quantity')::DECIMAL * (v_item->>'unit_price')::DECIMAL; v_line_tax := v_line_total * COALESCE((v_item->>'tax_rate')::DECIMAL, 0) / 100; v_subtotal := v_subtotal + v_line_total; v_tax_amount := v_tax_amount + v_line_tax; END LOOP; v_total_amount := v_subtotal + v_tax_amount; IF p_currency_id IS NULL THEN v_original_currency := 'EGP'; ELSE SELECT code INTO v_original_currency FROM currencies WHERE id = p_currency_id; END IF; INSERT INTO customer_debit_notes (company_id, branch_id, cost_center_id, customer_id, debit_note_number, debit_note_date, source_invoice_id, subtotal, tax_amount, total_amount, applied_amount, currency_id, original_currency, original_subtotal, original_tax_amount, original_total_amount, exchange_rate, status, approval_status, reference_type, reason, notes, created_by) VALUES (p_company_id, p_branch_id, p_cost_center_id, p_customer_id, v_debit_note_number, p_debit_note_date, p_source_invoice_id, v_subtotal, v_tax_amount, v_total_amount, 0, p_currency_id, v_original_currency, v_subtotal, v_tax_amount, v_total_amount, p_exchange_rate, 'open', 'draft', p_reference_type, p_reason, p_notes, p_created_by) RETURNING id INTO v_debit_note_id; FOR v_item IN SELECT * FROM jsonb_array_elements(p_items) LOOP v_line_total := (v_item->>'quantity')::DECIMAL * (v_item->>'unit_price')::DECIMAL; INSERT INTO customer_debit_note_items (customer_debit_note_id, product_id, description, quantity, unit_price, tax_rate, line_total, item_type) VALUES (v_debit_note_id, (v_item->>'product_id')::UUID, v_item->>'description', (v_item->>'quantity')::DECIMAL, (v_item->>'unit_price')::DECIMAL, COALESCE((v_item->>'tax_rate')::DECIMAL, 0), v_line_total, COALESCE(v_item->>'item_type', 'charge')); END LOOP; RETURN QUERY SELECT v_debit_note_id, v_debit_note_number, v_total_amount, v_approval_status, TRUE, 'Customer debit note created successfully as DRAFT. Submit for approval before applying.'; EXCEPTION WHEN OTHERS THEN RETURN QUERY SELECT NULL::UUID, NULL::VARCHAR(50), 0::DECIMAL(15,2), NULL::VARCHAR(20), FALSE, 'Error creating customer debit note: ' || SQLERRM; END; $function$
;

-- ---------------------------------------------------------------
-- create_default_branch_for_company()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_default_branch_for_company()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  INSERT INTO branches (company_id, name, code, branch_name, branch_code, is_main, is_head_office, is_active)
  VALUES (NEW.id, 'الفرع الرئيسي', 'MAIN', 'الفرع الرئيسي', 'MAIN', TRUE, TRUE, TRUE);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_default_cost_center_for_branch()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_default_cost_center_for_branch()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_new_cc_id UUID;
BEGIN
  INSERT INTO cost_centers (
    company_id, branch_id, cost_center_code, cost_center_name, is_main, is_active
  )
  VALUES (
    NEW.company_id,
    NEW.id,
    'CC-' || UPPER(COALESCE(NEW.code, COALESCE(NEW.branch_code, 'MAIN'))),
    'مركز التكلفة - ' || COALESCE(NEW.name, NEW.branch_name),
    COALESCE(NEW.is_main, NEW.is_head_office, FALSE),
    TRUE
  )
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_new_cc_id;

  -- v3.28.4 FIX: also propagate to branch.default_cost_center_id so that
  -- downstream triggers (e.g. create_main_warehouse + trg_warehouses_branch_scope)
  -- can read it.
  IF v_new_cc_id IS NOT NULL THEN
    UPDATE branches
    SET default_cost_center_id = v_new_cc_id
    WHERE id = NEW.id AND default_cost_center_id IS NULL;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_employee_on_company_member()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_employee_on_company_member()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
    emp_name TEXT;
    emp_email TEXT;
BEGIN
    -- Use NEW.email directly. Callback now always passes it.
    emp_email := NEW.email;

    -- Try to get name from a matching invitation first
    IF emp_email IS NOT NULL AND Trim(emp_email) <> '' THEN
        SELECT employee_name INTO emp_name
        FROM company_invitations
        WHERE email = emp_email AND company_id = NEW.company_id
        ORDER BY created_at DESC LIMIT 1;
    END IF;

    -- Fallback to email prefix
    IF (emp_name IS NULL OR Trim(emp_name) = '') AND emp_email IS NOT NULL AND Trim(emp_email) <> '' THEN
        emp_name := split_part(emp_email, '@', 1);
    END IF;

    -- Last resort: generic name based on user_id
    IF emp_name IS NULL OR Trim(emp_name) = '' THEN
        emp_name := 'Employee ' || substring(NEW.user_id::text, 1, 8);
    END IF;

    -- Avoid duplicate employee records
    IF NOT EXISTS (
        SELECT 1 FROM employees
        WHERE user_id = NEW.user_id AND company_id = NEW.company_id
    ) THEN
        INSERT INTO employees (
            company_id,
            user_id,
            full_name,
            email,
            joined_date,
            base_salary
        ) VALUES (
            NEW.company_id,
            NEW.user_id,
            emp_name,
            emp_email,
            now(),
            0
        );
    END IF;

    RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_fifo_lot_on_purchase()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_fifo_lot_on_purchase()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_unit_cost NUMERIC;
  v_bill_date DATE;
BEGIN
  -- فقط لحركات الشراء
  IF NEW.transaction_type NOT IN ('purchase', 'adjustment_in') THEN
    RETURN NEW;
  END IF;
  
  -- تجاهل الخدمات
  IF EXISTS (SELECT 1 FROM products WHERE id = NEW.product_id AND item_type = 'service') THEN
    RETURN NEW;
  END IF;
  
  -- الحصول على تكلفة الوحدة من الفاتورة
  IF NEW.transaction_type = 'purchase' AND NEW.reference_id IS NOT NULL THEN
    -- من bill_items
    SELECT bi.unit_price, b.bill_date
    INTO v_unit_cost, v_bill_date
    FROM bill_items bi
    JOIN bills b ON bi.bill_id = b.id
    WHERE bi.bill_id = NEW.reference_id 
      AND bi.product_id = NEW.product_id
    LIMIT 1;
  ELSE
    -- من products.cost_price (للتعديلات)
    SELECT cost_price INTO v_unit_cost FROM products WHERE id = NEW.product_id;
    v_bill_date := CURRENT_DATE;
  END IF;
  
  -- إنشاء دفعة جديدة
  INSERT INTO fifo_cost_lots (
    company_id,
    product_id,
    lot_date,
    lot_type,
    reference_type,
    reference_id,
    original_quantity,
    remaining_quantity,
    unit_cost,
    notes,
    branch_id,
    warehouse_id
  ) VALUES (
    NEW.company_id,
    NEW.product_id,
    v_bill_date,
    CASE 
      WHEN NEW.transaction_type = 'purchase' THEN 'purchase'
      ELSE 'adjustment'
    END,
    CASE 
      WHEN NEW.transaction_type = 'purchase' THEN 'bill'
      ELSE 'adjustment'
    END,
    NEW.reference_id,
    NEW.quantity_change,
    NEW.quantity_change,
    COALESCE(v_unit_cost, 0),
    NEW.notes,
    NEW.branch_id,
    NULL -- warehouse_id will be added later if needed
  );
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_financial_operation_trace(p_company_id uuid, p_source_entity text, p_source_id uuid, p_event_type text, p_actor_id uuid, p_idempotency_key text, p_request_hash text, p_metadata jsonb, p_audit_flags jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_financial_operation_trace(p_company_id uuid, p_source_entity text, p_source_id uuid, p_event_type text, p_actor_id uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text, p_request_hash text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb, p_audit_flags jsonb DEFAULT '[]'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_transaction_id UUID;
BEGIN
  INSERT INTO public.financial_operation_traces (
    company_id,
    source_entity,
    source_id,
    event_type,
    actor_id,
    idempotency_key,
    request_hash,
    metadata,
    audit_flags
  ) VALUES (
    p_company_id,
    p_source_entity,
    p_source_id,
    p_event_type,
    p_actor_id,
    p_idempotency_key,
    p_request_hash,
    COALESCE(p_metadata, '{}'::JSONB),
    COALESCE(p_audit_flags, '[]'::JSONB)
  )
  RETURNING transaction_id INTO v_transaction_id;

  RETURN v_transaction_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_generic_payment_entry(p_payment_id uuid, p_company_id uuid, p_entry_date date, p_amount numeric, p_payment_method text, p_customer_id uuid, p_supplier_id uuid, p_description text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_generic_payment_entry(p_payment_id uuid, p_company_id uuid, p_entry_date date, p_amount numeric, p_payment_method text, p_customer_id uuid, p_supplier_id uuid, p_description text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_entry_id UUID;
  v_accounts RECORD;
  v_cash_bank_account_id UUID;
  v_ar_ap_account_id UUID;
  v_reference_type TEXT;
BEGIN
  -- إيجاد الحسابات المطلوبة
  SELECT * INTO v_accounts FROM find_company_accounts(p_company_id);
  
  -- تحديد حساب النقد/البنك
  IF p_payment_method ILIKE '%bank%' OR p_payment_method ILIKE '%بنك%' OR p_payment_method ILIKE '%transfer%' THEN
    v_cash_bank_account_id := v_accounts.bank_account_id;
  ELSE
    v_cash_bank_account_id := v_accounts.cash_account_id;
  END IF;
  
  IF v_cash_bank_account_id IS NULL THEN
    RAISE EXCEPTION 'حساب النقد/البنك غير موجود للشركة: %', p_company_id;
  END IF;
  
  -- تحديد نوع القيد والحساب
  IF p_customer_id IS NOT NULL THEN
    v_reference_type := 'customer_payment';
    v_ar_ap_account_id := v_accounts.ar_account_id;
    IF v_ar_ap_account_id IS NULL THEN
      RAISE EXCEPTION 'حساب AR غير موجود للشركة: %', p_company_id;
    END IF;
  ELSIF p_supplier_id IS NOT NULL THEN
    v_reference_type := 'supplier_payment';
    v_ar_ap_account_id := v_accounts.ap_account_id;
    IF v_ar_ap_account_id IS NULL THEN
      RAISE EXCEPTION 'حساب AP غير موجود للشركة: %', p_company_id;
    END IF;
  ELSE
    RAISE EXCEPTION 'يجب تحديد عميل أو مورد للدفعة';
  END IF;
  
  -- إنشاء القيد
  INSERT INTO journal_entries (
    company_id,
    reference_type,
    reference_id,
    entry_date,
    description,
    status
  ) VALUES (
    p_company_id,
    v_reference_type,
    p_payment_id,
    p_entry_date,
    COALESCE(p_description, 'قيد دفعة عامة'),
    'posted'
  ) RETURNING id INTO v_entry_id;
  
  -- إنشاء سطور القيد
  IF p_customer_id IS NOT NULL THEN
    -- دفعة عميل: Cash/Bank (Debit) vs AR (Credit)
    INSERT INTO journal_entry_lines (
      journal_entry_id,
      account_id,
      debit_amount,
      credit_amount,
      description
    ) VALUES (
      v_entry_id,
      v_cash_bank_account_id,
      p_amount,
      0,
      'النقد/البنك'
    );
    
    INSERT INTO journal_entry_lines (
      journal_entry_id,
      account_id,
      debit_amount,
      credit_amount,
      description
    ) VALUES (
      v_entry_id,
      v_ar_ap_account_id,
      0,
      p_amount,
      'الذمم المدينة'
    );
  ELSE
    -- دفعة مورد: AP (Debit) vs Cash/Bank (Credit)
    INSERT INTO journal_entry_lines (
      journal_entry_id,
      account_id,
      debit_amount,
      credit_amount,
      description
    ) VALUES (
      v_entry_id,
      v_ar_ap_account_id,
      p_amount,
      0,
      'الذمم الدائنة'
    );
    
    INSERT INTO journal_entry_lines (
      journal_entry_id,
      account_id,
      debit_amount,
      credit_amount,
      description
    ) VALUES (
      v_entry_id,
      v_cash_bank_account_id,
      0,
      p_amount,
      'النقد/البنك'
    );
  END IF;
  
  RETURN v_entry_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_invoice_ar_revenue_entry(p_invoice_id uuid, p_company_id uuid, p_entry_date date, p_description text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_invoice_ar_revenue_entry(p_invoice_id uuid, p_company_id uuid, p_entry_date date, p_description text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_entry_id UUID;
  v_accounts RECORD;
  v_invoice RECORD;
  v_subtotal DECIMAL(15, 2);
  v_tax_amount DECIMAL(15, 2);
  v_shipping DECIMAL(15, 2);
  v_total DECIMAL(15, 2);
  v_adjustment DECIMAL(15, 2);
BEGIN
  -- جلب بيانات الفاتورة
  SELECT 
    subtotal, tax_amount, shipping, total_amount, invoice_number
  INTO v_invoice
  FROM invoices
  WHERE id = p_invoice_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'الفاتورة غير موجودة: %', p_invoice_id;
  END IF;
  
  v_subtotal := COALESCE(v_invoice.subtotal, 0);
  v_tax_amount := COALESCE(v_invoice.tax_amount, 0);
  v_shipping := COALESCE(v_invoice.shipping, 0);
  v_total := COALESCE(v_invoice.total_amount, 0);
  
  -- إيجاد الحسابات المطلوبة
  SELECT * INTO v_accounts FROM find_company_accounts(p_company_id);
  
  IF v_accounts.ar_account_id IS NULL OR v_accounts.revenue_account_id IS NULL THEN
    RAISE EXCEPTION 'حسابات AR أو Revenue غير موجودة للشركة: %', p_company_id;
  END IF;
  
  -- إنشاء القيد
  INSERT INTO journal_entries (
    company_id,
    reference_type,
    reference_id,
    entry_date,
    description,
    status
  ) VALUES (
    p_company_id,
    'invoice',
    p_invoice_id,
    p_entry_date,
    COALESCE(p_description, 'قيد فاتورة: ' || v_invoice.invoice_number),
    'posted'
  ) RETURNING id INTO v_entry_id;
  
  -- إنشاء سطور القيد
  -- 1. AR (Debit)
  INSERT INTO journal_entry_lines (
    journal_entry_id,
    account_id,
    debit_amount,
    credit_amount,
    description
  ) VALUES (
    v_entry_id,
    v_accounts.ar_account_id,
    v_total,
    0,
    'الذمم المدينة'
  );
  
  -- 2. Revenue (Credit)
  INSERT INTO journal_entry_lines (
    journal_entry_id,
    account_id,
    debit_amount,
    credit_amount,
    description
  ) VALUES (
    v_entry_id,
    v_accounts.revenue_account_id,
    0,
    v_subtotal,
    'إيرادات المبيعات'
  );
  
  -- 3. VAT Payable (Credit) - إن وجد
  IF v_tax_amount > 0 AND v_accounts.vat_payable_account_id IS NOT NULL THEN
    INSERT INTO journal_entry_lines (
      journal_entry_id,
      account_id,
      debit_amount,
      credit_amount,
      description
    ) VALUES (
      v_entry_id,
      v_accounts.vat_payable_account_id,
      0,
      v_tax_amount,
      'ضريبة القيمة المضافة'
    );
  END IF;
  
  -- 4. Shipping (Credit) - إن وجد
  IF v_shipping > 0 AND v_accounts.shipping_account_id IS NOT NULL THEN
    INSERT INTO journal_entry_lines (
      journal_entry_id,
      account_id,
      debit_amount,
      credit_amount,
      description
    ) VALUES (
      v_entry_id,
      v_accounts.shipping_account_id,
      0,
      v_shipping,
      'الشحن'
    );
  END IF;
  
  -- إذا لم يكن هناك حساب VAT أو Shipping، نضيف الفرق إلى Revenue
  IF (v_tax_amount > 0 AND v_accounts.vat_payable_account_id IS NULL) OR 
     (v_shipping > 0 AND v_accounts.shipping_account_id IS NULL) THEN
    v_adjustment := v_total - v_subtotal - 
      CASE WHEN v_accounts.vat_payable_account_id IS NOT NULL THEN v_tax_amount ELSE 0 END -
      CASE WHEN v_accounts.shipping_account_id IS NOT NULL THEN v_shipping ELSE 0 END;
    
    IF v_adjustment != 0 THEN
      UPDATE journal_entry_lines
      SET credit_amount = credit_amount + v_adjustment
      WHERE journal_entry_id = v_entry_id
      AND account_id = v_accounts.revenue_account_id;
    END IF;
  END IF;
  
  RETURN v_entry_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_invoice_payment_entry(p_invoice_id uuid, p_payment_id uuid, p_company_id uuid, p_entry_date date, p_amount numeric, p_payment_method text, p_description text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_invoice_payment_entry(p_invoice_id uuid, p_payment_id uuid, p_company_id uuid, p_entry_date date, p_amount numeric, p_payment_method text, p_description text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_entry_id UUID;
  v_accounts RECORD;
  v_invoice RECORD;
  v_cash_bank_account_id UUID;
BEGIN
  -- جلب بيانات الفاتورة
  SELECT invoice_number INTO v_invoice
  FROM invoices
  WHERE id = p_invoice_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'الفاتورة غير موجودة: %', p_invoice_id;
  END IF;
  
  -- إيجاد الحسابات المطلوبة
  SELECT * INTO v_accounts FROM find_company_accounts(p_company_id);
  
  IF v_accounts.ar_account_id IS NULL THEN
    RAISE EXCEPTION 'حساب AR غير موجود للشركة: %', p_company_id;
  END IF;
  
  -- تحديد حساب النقد/البنك
  IF p_payment_method ILIKE '%bank%' OR p_payment_method ILIKE '%بنك%' OR p_payment_method ILIKE '%transfer%' THEN
    v_cash_bank_account_id := v_accounts.bank_account_id;
  ELSE
    v_cash_bank_account_id := v_accounts.cash_account_id;
  END IF;
  
  IF v_cash_bank_account_id IS NULL THEN
    RAISE EXCEPTION 'حساب النقد/البنك غير موجود للشركة: %', p_company_id;
  END IF;
  
  -- إنشاء القيد
  INSERT INTO journal_entries (
    company_id,
    reference_type,
    reference_id,
    entry_date,
    description,
    status
  ) VALUES (
    p_company_id,
    'invoice_payment',
    COALESCE(p_payment_id, p_invoice_id),
    p_entry_date,
    COALESCE(p_description, 'قيد دفع فاتورة: ' || v_invoice.invoice_number),
    'posted'
  ) RETURNING id INTO v_entry_id;
  
  -- إنشاء سطور القيد
  -- 1. Cash/Bank (Debit)
  INSERT INTO journal_entry_lines (
    journal_entry_id,
    account_id,
    debit_amount,
    credit_amount,
    description
  ) VALUES (
    v_entry_id,
    v_cash_bank_account_id,
    p_amount,
    0,
    'النقد/البنك'
  );
  
  -- 2. AR (Credit)
  INSERT INTO journal_entry_lines (
    journal_entry_id,
    account_id,
    debit_amount,
    credit_amount,
    description
  ) VALUES (
    v_entry_id,
    v_accounts.ar_account_id,
    0,
    p_amount,
    'الذمم المدينة'
  );
  
  RETURN v_entry_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_journal_entry_atomic(p_company_id uuid, p_reference_type text, p_reference_id uuid, p_entry_date date, p_description text, p_branch_id uuid, p_cost_center_id uuid, p_warehouse_id uuid, p_lines jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_journal_entry_atomic(p_company_id uuid, p_reference_type text, p_reference_id uuid, p_entry_date date, p_description text, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_lines jsonb DEFAULT '[]'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_entry_id        UUID;
  v_total_debit     NUMERIC := 0;
  v_total_credit    NUMERIC := 0;
  v_line            JSONB;
  v_existing_id     UUID;
BEGIN
  -- 1. Guard: Duplicate check
  SELECT id INTO v_existing_id
  FROM journal_entries
  WHERE company_id = p_company_id
    AND reference_type = p_reference_type
    AND reference_id = p_reference_id
    AND (is_deleted IS NULL OR is_deleted = false)
  LIMIT 1;

  IF v_existing_id IS NOT NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'DUPLICATE_JE: Entry already exists for ' || p_reference_type || ':' || p_reference_id,
      'existing_id', v_existing_id
    );
  END IF;

  -- 2. Guard: Lines must exist and be balanced
  IF jsonb_array_length(p_lines) = 0 THEN
    RETURN jsonb_build_object('success', false, 'error', 'EMPTY_LINES: At least one line is required');
  END IF;

  FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines) LOOP
    v_total_debit  := v_total_debit  + COALESCE((v_line->>'debit_amount')::NUMERIC,  0);
    v_total_credit := v_total_credit + COALESCE((v_line->>'credit_amount')::NUMERIC, 0);
  END LOOP;

  IF ABS(v_total_debit - v_total_credit) > 0.01 THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'UNBALANCED_JE: Debit ' || v_total_debit || ' ≠ Credit ' || v_total_credit
    );
  END IF;

  -- 3. Allow direct-post within this atomic function
  PERFORM set_config('app.allow_direct_post', 'true', true);

  -- 4. Insert header as 'draft'
  INSERT INTO journal_entries (
    company_id, reference_type, reference_id, entry_date,
    description, branch_id, cost_center_id, warehouse_id, status
  )
  VALUES (
    p_company_id, p_reference_type, p_reference_id, p_entry_date,
    p_description, p_branch_id, p_cost_center_id, p_warehouse_id, 'draft'
  )
  RETURNING id INTO v_entry_id;

  -- 5. Insert all lines atomically (v3.23.0: now includes FX columns)
  INSERT INTO journal_entry_lines (
    journal_entry_id, account_id, debit_amount, credit_amount,
    description, branch_id, cost_center_id,
    original_debit, original_credit, original_currency, exchange_rate_used
  )
  SELECT
    v_entry_id,
    (ln->>'account_id')::UUID,
    COALESCE((ln->>'debit_amount')::NUMERIC,  0),
    COALESCE((ln->>'credit_amount')::NUMERIC, 0),
    ln->>'description',
    COALESCE((ln->>'branch_id')::UUID, p_branch_id),
    COALESCE((ln->>'cost_center_id')::UUID, p_cost_center_id),
    NULLIF(ln->>'original_debit', '')::NUMERIC,
    NULLIF(ln->>'original_credit', '')::NUMERIC,
    NULLIF(ln->>'original_currency', ''),
    COALESCE(NULLIF(ln->>'exchange_rate_used', '')::NUMERIC, 1)
  FROM jsonb_array_elements(p_lines) AS ln;

  -- 6. Update header to 'posted'
  UPDATE journal_entries SET status = 'posted' WHERE id = v_entry_id;

  -- 7. Reset session var
  PERFORM set_config('app.allow_direct_post', 'false', true);

  RETURN jsonb_build_object('success', true, 'entry_id', v_entry_id,
    'total_debit', v_total_debit, 'lines_count', jsonb_array_length(p_lines));

EXCEPTION WHEN OTHERS THEN
  PERFORM set_config('app.allow_direct_post', 'false', true);
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- create_main_warehouse()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_main_warehouse()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
    main_branch_id UUID;
BEGIN
    -- Get the main branch for this company
    SELECT id INTO main_branch_id FROM branches 
    WHERE company_id = NEW.id AND (is_main = TRUE OR is_head_office = TRUE)
    LIMIT 1;
    
    -- Create main warehouse
    INSERT INTO warehouses (company_id, branch_id, name, code, is_main, is_active)
    VALUES (NEW.id, main_branch_id, 'المخزن الرئيسي', 'MAIN', TRUE, TRUE);
    
    RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_manufacturing_bom_version_atomic(p_company_id uuid, p_bom_id uuid, p_created_by uuid, p_clone_from_version_id uuid, p_effective_from timestamp with time zone, p_effective_to timestamp with time zone, p_base_output_qty numeric, p_change_summary text, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_manufacturing_bom_version_atomic(p_company_id uuid, p_bom_id uuid, p_created_by uuid, p_clone_from_version_id uuid DEFAULT NULL::uuid, p_effective_from timestamp with time zone DEFAULT NULL::timestamp with time zone, p_effective_to timestamp with time zone DEFAULT NULL::timestamp with time zone, p_base_output_qty numeric DEFAULT 1, p_change_summary text DEFAULT NULL::text, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_bom RECORD;
  v_source_version RECORD;
  v_source_line RECORD;
  v_new_line_id UUID;
  v_new_version_id UUID;
  v_new_version_no INTEGER;
  v_cloned BOOLEAN := false;
BEGIN
  SELECT *
    INTO v_bom
    FROM public.manufacturing_boms
   WHERE id = p_bom_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing BOM not found or not in company. bom_id=%', p_bom_id;
  END IF;

  IF p_clone_from_version_id IS NOT NULL THEN
    SELECT *
      INTO v_source_version
      FROM public.manufacturing_bom_versions
     WHERE id = p_clone_from_version_id
       AND bom_id = p_bom_id
       AND company_id = p_company_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Clone source BOM version not found or does not belong to target BOM. bom_version_id=%', p_clone_from_version_id;
    END IF;

    v_cloned := true;
  END IF;

  SELECT COALESCE(MAX(version_no), 0) + 1
    INTO v_new_version_no
    FROM public.manufacturing_bom_versions
   WHERE bom_id = p_bom_id;

  INSERT INTO public.manufacturing_bom_versions (
    company_id,
    branch_id,
    bom_id,
    version_no,
    status,
    is_default,
    effective_from,
    effective_to,
    base_output_qty,
    change_summary,
    notes,
    created_by,
    updated_by
  ) VALUES (
    p_company_id,
    v_bom.branch_id,
    p_bom_id,
    v_new_version_no,
    'draft',
    false,
    p_effective_from,
    p_effective_to,
    COALESCE(p_base_output_qty, 1),
    p_change_summary,
    p_notes,
    p_created_by,
    p_created_by
  )
  RETURNING id INTO v_new_version_id;

  IF v_cloned THEN
    FOR v_source_line IN
      SELECT *
        FROM public.manufacturing_bom_lines
       WHERE bom_version_id = p_clone_from_version_id
       ORDER BY line_no
    LOOP
      INSERT INTO public.manufacturing_bom_lines (
        company_id,
        branch_id,
        bom_version_id,
        line_no,
        component_product_id,
        line_type,
        quantity_per,
        scrap_percent,
        issue_uom,
        is_optional,
        notes,
        created_by,
        updated_by
      ) VALUES (
        p_company_id,
        v_bom.branch_id,
        v_new_version_id,
        v_source_line.line_no,
        v_source_line.component_product_id,
        v_source_line.line_type,
        v_source_line.quantity_per,
        v_source_line.scrap_percent,
        v_source_line.issue_uom,
        v_source_line.is_optional,
        v_source_line.notes,
        p_created_by,
        p_created_by
      )
      RETURNING id INTO v_new_line_id;

      INSERT INTO public.manufacturing_bom_line_substitutes (
        company_id,
        branch_id,
        bom_line_id,
        substitute_product_id,
        substitute_quantity,
        priority,
        effective_from,
        effective_to,
        notes,
        created_by,
        updated_by
      )
      SELECT
        p_company_id,
        v_bom.branch_id,
        v_new_line_id,
        s.substitute_product_id,
        s.substitute_quantity,
        s.priority,
        s.effective_from,
        s.effective_to,
        s.notes,
        p_created_by,
        p_created_by
      FROM public.manufacturing_bom_line_substitutes s
      WHERE s.bom_line_id = v_source_line.id;
    END LOOP;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'bom_version_id', v_new_version_id,
    'version_no', v_new_version_no,
    'cloned', v_cloned
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- create_manufacturing_production_order_atomic(p_company_id uuid, p_branch_id uuid, p_created_by uuid, p_product_id uuid, p_bom_id uuid, p_bom_version_id uuid, p_routing_id uuid, p_routing_version_id uuid, p_issue_warehouse_id uuid, p_receipt_warehouse_id uuid, p_planned_quantity numeric, p_order_uom text, p_planned_start_at timestamp with time zone, p_planned_end_at timestamp with time zone, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_manufacturing_production_order_atomic(p_company_id uuid, p_branch_id uuid, p_created_by uuid, p_product_id uuid, p_bom_id uuid, p_bom_version_id uuid, p_routing_id uuid, p_routing_version_id uuid, p_issue_warehouse_id uuid DEFAULT NULL::uuid, p_receipt_warehouse_id uuid DEFAULT NULL::uuid, p_planned_quantity numeric DEFAULT 1, p_order_uom text DEFAULT NULL::text, p_planned_start_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_planned_end_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order_id UUID;
  v_order_no TEXT;
  v_routing_version RECORD;
  v_routing_operation RECORD;
  v_operation_count INTEGER := 0;
BEGIN
  IF p_planned_quantity IS NULL OR p_planned_quantity <= 0 THEN
    RAISE EXCEPTION 'planned_quantity must be greater than zero.';
  END IF;

  SELECT *
    INTO v_routing_version
    FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing routing version not found or not in company. routing_version_id=%', p_routing_version_id;
  END IF;

  v_order_no := public.mpo_generate_order_no(NOW());

  INSERT INTO public.manufacturing_production_orders (
    company_id,
    branch_id,
    order_no,
    product_id,
    bom_id,
    bom_version_id,
    routing_id,
    routing_version_id,
    issue_warehouse_id,
    receipt_warehouse_id,
    planned_quantity,
    order_uom,
    status,
    planned_start_at,
    planned_end_at,
    notes,
    created_by,
    updated_by
  ) VALUES (
    p_company_id,
    p_branch_id,
    v_order_no,
    p_product_id,
    p_bom_id,
    p_bom_version_id,
    p_routing_id,
    p_routing_version_id,
    p_issue_warehouse_id,
    p_receipt_warehouse_id,
    p_planned_quantity,
    p_order_uom,
    'draft',
    p_planned_start_at,
    p_planned_end_at,
    p_notes,
    p_created_by,
    p_created_by
  )
  RETURNING id INTO v_order_id;

  FOR v_routing_operation IN
    SELECT *
      FROM public.manufacturing_routing_operations
     WHERE routing_version_id = p_routing_version_id
     ORDER BY operation_no
  LOOP
    INSERT INTO public.manufacturing_production_order_operations (
      company_id,
      branch_id,
      production_order_id,
      routing_version_id,
      source_routing_operation_id,
      operation_no,
      operation_code,
      operation_name,
      work_center_id,
      status,
      planned_quantity,
      completed_quantity,
      setup_time_minutes,
      run_time_minutes_per_unit,
      queue_time_minutes,
      move_time_minutes,
      labor_time_minutes,
      machine_time_minutes,
      quality_checkpoint_required,
      instructions,
      created_by,
      updated_by
    ) VALUES (
      p_company_id,
      p_branch_id,
      v_order_id,
      p_routing_version_id,
      v_routing_operation.id,
      v_routing_operation.operation_no,
      v_routing_operation.operation_code,
      v_routing_operation.operation_name,
      v_routing_operation.work_center_id,
      'pending',
      p_planned_quantity,
      0,
      v_routing_operation.setup_time_minutes,
      v_routing_operation.run_time_minutes_per_unit,
      v_routing_operation.queue_time_minutes,
      v_routing_operation.move_time_minutes,
      v_routing_operation.labor_time_minutes,
      v_routing_operation.machine_time_minutes,
      v_routing_operation.quality_checkpoint_required,
      v_routing_operation.instructions,
      p_created_by,
      p_created_by
    );

    v_operation_count := v_operation_count + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', v_order_id,
    'order_no', v_order_no,
    'status', 'draft',
    'operation_count', v_operation_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- create_manufacturing_routing_version_atomic(p_company_id uuid, p_routing_id uuid, p_created_by uuid, p_clone_from_version_id uuid, p_effective_from timestamp with time zone, p_effective_to timestamp with time zone, p_change_summary text, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_manufacturing_routing_version_atomic(p_company_id uuid, p_routing_id uuid, p_created_by uuid, p_clone_from_version_id uuid DEFAULT NULL::uuid, p_effective_from timestamp with time zone DEFAULT NULL::timestamp with time zone, p_effective_to timestamp with time zone DEFAULT NULL::timestamp with time zone, p_change_summary text DEFAULT NULL::text, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_routing RECORD;
  v_source_version RECORD;
  v_source_operation RECORD;
  v_new_version_id UUID;
  v_new_version_no INTEGER;
  v_cloned BOOLEAN := false;
BEGIN
  SELECT *
    INTO v_routing
    FROM public.manufacturing_routings
   WHERE id = p_routing_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing routing not found or not in company. routing_id=%', p_routing_id;
  END IF;

  IF p_clone_from_version_id IS NOT NULL THEN
    SELECT *
      INTO v_source_version
      FROM public.manufacturing_routing_versions
     WHERE id = p_clone_from_version_id
       AND routing_id = p_routing_id
       AND company_id = p_company_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Clone source routing version not found or does not belong to target routing. routing_version_id=%', p_clone_from_version_id;
    END IF;

    v_cloned := true;
  END IF;

  SELECT COALESCE(MAX(version_no), 0) + 1
    INTO v_new_version_no
    FROM public.manufacturing_routing_versions
   WHERE routing_id = p_routing_id;

  INSERT INTO public.manufacturing_routing_versions (
    company_id,
    branch_id,
    routing_id,
    version_no,
    status,
    effective_from,
    effective_to,
    change_summary,
    notes,
    created_by,
    updated_by
  ) VALUES (
    p_company_id,
    v_routing.branch_id,
    p_routing_id,
    v_new_version_no,
    'draft',
    p_effective_from,
    p_effective_to,
    p_change_summary,
    p_notes,
    p_created_by,
    p_created_by
  )
  RETURNING id INTO v_new_version_id;

  IF v_cloned THEN
    FOR v_source_operation IN
      SELECT *
        FROM public.manufacturing_routing_operations
       WHERE routing_version_id = p_clone_from_version_id
       ORDER BY operation_no
    LOOP
      INSERT INTO public.manufacturing_routing_operations (
        company_id,
        branch_id,
        routing_version_id,
        operation_no,
        operation_code,
        operation_name,
        work_center_id,
        setup_time_minutes,
        run_time_minutes_per_unit,
        queue_time_minutes,
        move_time_minutes,
        labor_time_minutes,
        machine_time_minutes,
        quality_checkpoint_required,
        instructions,
        created_by,
        updated_by
      ) VALUES (
        p_company_id,
        v_routing.branch_id,
        v_new_version_id,
        v_source_operation.operation_no,
        v_source_operation.operation_code,
        v_source_operation.operation_name,
        v_source_operation.work_center_id,
        v_source_operation.setup_time_minutes,
        v_source_operation.run_time_minutes_per_unit,
        v_source_operation.queue_time_minutes,
        v_source_operation.move_time_minutes,
        v_source_operation.labor_time_minutes,
        v_source_operation.machine_time_minutes,
        v_source_operation.quality_checkpoint_required,
        v_source_operation.instructions,
        p_created_by,
        p_created_by
      );
    END LOOP;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'routing_version_id', v_new_version_id,
    'version_no', v_new_version_no,
    'cloned', v_cloned
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- create_missing_invoice_journals_safe(p_company_id uuid, p_limit integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_missing_invoice_journals_safe(p_company_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 20)
 RETURNS TABLE(invoice_id uuid, invoice_number text, fix_applied text, status text)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_invoice RECORD;
  v_journal_entry_id UUID;
  v_ar_account_id UUID;
  v_revenue_account_id UUID;
  v_vat_account_id UUID;
  v_processed INTEGER := 0;
BEGIN
  -- معالجة الفواتير مع LIMIT
  FOR v_invoice IN
    SELECT 
      i.id, i.company_id, i.invoice_number, i.invoice_date,
      i.subtotal, i.tax_amount, i.total_amount
    FROM invoices i
    WHERE i.status IN ('sent', 'partially_paid', 'paid')
      AND (p_company_id IS NULL OR i.company_id = p_company_id)
      AND NOT EXISTS (
        SELECT 1 FROM journal_entries je
        WHERE je.reference_type = 'invoice' AND je.reference_id = i.id
      )
    LIMIT p_limit
  LOOP
    -- الحصول على الحسابات
    SELECT id INTO v_ar_account_id
    FROM chart_of_accounts
    WHERE company_id = v_invoice.company_id
      AND (sub_type = 'accounts_receivable' OR account_name ILIKE '%ذمم%عملاء%')
    LIMIT 1;

    SELECT id INTO v_revenue_account_id
    FROM chart_of_accounts
    WHERE company_id = v_invoice.company_id
      AND (account_type = 'income' OR sub_type IN ('sales_revenue', 'revenue'))
    LIMIT 1;

    SELECT id INTO v_vat_account_id
    FROM chart_of_accounts
    WHERE company_id = v_invoice.company_id
      AND (sub_type = 'vat_payable' OR account_name ILIKE '%ضريبة%')
    LIMIT 1;

    IF v_ar_account_id IS NOT NULL AND v_revenue_account_id IS NOT NULL THEN
      -- إنشاء القيد
      INSERT INTO journal_entries (
        company_id, reference_type, reference_id, entry_date, description
      ) VALUES (
        v_invoice.company_id, 'invoice', v_invoice.id, v_invoice.invoice_date,
        'قيد فاتورة ' || v_invoice.invoice_number || ' - Safe auto-generated'
      ) RETURNING id INTO v_journal_entry_id;

      -- المدين: ذمم العملاء
      INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, debit_amount, credit_amount, description
      ) VALUES (
        v_journal_entry_id, v_ar_account_id, v_invoice.total_amount, 0,
        'ذمم عملاء - ' || v_invoice.invoice_number
      );

      -- الدائن: الإيرادات
      INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, debit_amount, credit_amount, description
      ) VALUES (
        v_journal_entry_id, v_revenue_account_id, 0, v_invoice.subtotal,
        'إيرادات - ' || v_invoice.invoice_number
      );

      -- الدائن: ضريبة
      IF v_vat_account_id IS NOT NULL AND v_invoice.tax_amount > 0 THEN
        INSERT INTO journal_entry_lines (
          journal_entry_id, account_id, debit_amount, credit_amount, description
        ) VALUES (
          v_journal_entry_id, v_vat_account_id, 0, v_invoice.tax_amount,
          'ضريبة - ' || v_invoice.invoice_number
        );
      END IF;

      v_processed := v_processed + 1;

      RETURN QUERY SELECT 
        v_invoice.id,
        v_invoice.invoice_number,
        'Created journal entry',
        'completed'::TEXT;
    ELSE
      RETURN QUERY SELECT 
        v_invoice.id,
        v_invoice.invoice_number,
        'Failed - accounts not found',
        'failed'::TEXT;
    END IF;
    
    -- خروج آمن
    IF v_processed >= p_limit THEN
      EXIT;
    END IF;
  END LOOP;
  
  RETURN;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_monthly_audit_snapshot(p_company_id uuid, p_snapshot_date date, p_created_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_monthly_audit_snapshot(p_company_id uuid, p_snapshot_date date DEFAULT CURRENT_DATE, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_snapshot_id      UUID;
  v_total_debits     NUMERIC := 0; v_total_credits    NUMERIC := 0;
  v_assets           NUMERIC := 0; v_liabilities      NUMERIC := 0;
  v_equity           NUMERIC := 0; v_net_income       NUMERIC := 0;
  v_gl_inventory     NUMERIC := 0; v_fifo_inventory   NUMERIC := 0;
  v_total_ar         NUMERIC := 0; v_total_ap         NUMERIC := 0;
  v_critical_fails   INTEGER := 0; v_warning_fails    INTEGER := 0;
BEGIN
  SELECT COALESCE(SUM(jel.debit_amount),0), COALESCE(SUM(jel.credit_amount),0)
  INTO v_total_debits, v_total_credits
  FROM journal_entry_lines jel JOIN journal_entries je ON je.id = jel.journal_entry_id
  WHERE je.company_id = p_company_id AND je.status = 'posted' AND je.entry_date <= p_snapshot_date;

  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount),0) INTO v_assets
  FROM journal_entry_lines jel JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted'
    AND je.entry_date <= p_snapshot_date AND coa.account_type = 'asset';

  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount),0) INTO v_liabilities
  FROM journal_entry_lines jel JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted'
    AND je.entry_date <= p_snapshot_date AND coa.account_type = 'liability';

  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount),0) INTO v_equity
  FROM journal_entry_lines jel JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted'
    AND je.entry_date <= p_snapshot_date AND coa.account_type = 'equity';

  SELECT COALESCE(SUM(CASE WHEN coa.account_type = 'income' THEN jel.credit_amount - jel.debit_amount
       WHEN coa.account_type = 'expense' THEN jel.debit_amount - jel.credit_amount ELSE 0 END), 0) INTO v_net_income
  FROM journal_entry_lines jel JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted'
    AND je.entry_date <= p_snapshot_date AND coa.account_type IN ('income','expense');

  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount),0) INTO v_gl_inventory
  FROM journal_entry_lines jel JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted' AND je.entry_date <= p_snapshot_date
    AND coa.account_type = 'asset' AND (coa.sub_type = 'inventory' OR coa.account_name ILIKE '%مخزون%');

  SELECT COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost),0) INTO v_fifo_inventory
  FROM fifo_cost_lots fcl JOIN products p ON p.id = fcl.product_id
  WHERE p.company_id = p_company_id AND fcl.remaining_quantity > 0;

  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount),0) INTO v_total_ar
  FROM journal_entry_lines jel JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted' AND je.entry_date <= p_snapshot_date
    AND coa.account_type = 'asset' AND (coa.sub_type IN ('accounts_receivable','ar') OR coa.account_name ILIKE '%العملاء%');

  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount),0) INTO v_total_ap
  FROM journal_entry_lines jel JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted' AND je.entry_date <= p_snapshot_date
    AND coa.account_type = 'liability' AND (coa.sub_type IN ('accounts_payable','ap') OR coa.account_name ILIKE '%الموردين%');

  SELECT COUNT(CASE WHEN severity = 'critical' AND NOT is_ok THEN 1 END),
         COUNT(CASE WHEN severity = 'warning'  AND NOT is_ok THEN 1 END)
  INTO v_critical_fails, v_warning_fails
  FROM daily_reconciliation_log WHERE company_id = p_company_id AND run_date = p_snapshot_date;

  INSERT INTO audit_snapshots (
    company_id, snapshot_date, snapshot_type,
    total_debits, total_credits, is_balanced,
    total_assets, total_liabilities, total_equity, net_income,
    gl_inventory_value, fifo_inventory_value, inventory_ok,
    total_ar, total_ap, critical_failures, warning_failures, snapshot_data, created_by
  ) VALUES (
    p_company_id, p_snapshot_date, 'monthly',
    v_total_debits, v_total_credits, ABS(v_total_debits - v_total_credits) < 0.01,
    v_assets, v_liabilities, v_equity, v_net_income,
    v_gl_inventory, v_fifo_inventory, ABS(v_gl_inventory - v_fifo_inventory) < 1,
    v_total_ar, v_total_ap, v_critical_fails, v_warning_fails,
    jsonb_build_object('run_at', NOW(), 'fifo_vs_gl_difference', ABS(v_gl_inventory - v_fifo_inventory)),
    p_created_by
  )
  ON CONFLICT (company_id, snapshot_date, snapshot_type) DO UPDATE SET
    total_debits=EXCLUDED.total_debits, total_credits=EXCLUDED.total_credits,
    is_balanced=EXCLUDED.is_balanced, net_income=EXCLUDED.net_income,
    gl_inventory_value=EXCLUDED.gl_inventory_value, fifo_inventory_value=EXCLUDED.fifo_inventory_value,
    inventory_ok=EXCLUDED.inventory_ok, total_ar=EXCLUDED.total_ar, total_ap=EXCLUDED.total_ap,
    critical_failures=EXCLUDED.critical_failures, warning_failures=EXCLUDED.warning_failures,
    snapshot_data=EXCLUDED.snapshot_data, created_at=NOW()
  RETURNING id INTO v_snapshot_id;
  RETURN v_snapshot_id;
END; $function$
;

-- ---------------------------------------------------------------
-- create_monthly_period(p_company_id uuid, p_year integer, p_month integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_monthly_period(p_company_id uuid, p_year integer, p_month integer)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_period_start DATE;
  v_period_end DATE;
  v_period_name TEXT;
  v_period_id UUID;
BEGIN
  -- حساب بداية ونهاية الشهر
  v_period_start := DATE(p_year || '-' || LPAD(p_month::TEXT, 2, '0') || '-01');
  v_period_end := (v_period_start + INTERVAL '1 month' - INTERVAL '1 day')::DATE;

  -- اسم الفترة
  v_period_name := TO_CHAR(v_period_start, 'Month YYYY', 'NLS_DATE_LANGUAGE=Arabic');

  -- إنشاء الفترة
  INSERT INTO accounting_periods (
    company_id,
    period_name,
    period_start,
    period_end,
    status
  ) VALUES (
    p_company_id,
    v_period_name,
    v_period_start,
    v_period_end,
    'open'
  ) RETURNING id INTO v_period_id;

  RETURN v_period_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_notification(p_company_id uuid, p_reference_type character varying, p_reference_id uuid, p_title character varying, p_message text, p_created_by uuid, p_branch_id uuid, p_cost_center_id uuid, p_warehouse_id uuid, p_assigned_to_role character varying, p_assigned_to_user uuid, p_priority character varying, p_event_key text, p_severity text, p_category text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_notification(p_company_id uuid, p_reference_type character varying, p_reference_id uuid, p_title character varying, p_message text, p_created_by uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_assigned_to_role character varying DEFAULT NULL::character varying, p_assigned_to_user uuid DEFAULT NULL::uuid, p_priority character varying DEFAULT 'normal'::character varying, p_event_key text DEFAULT NULL::text, p_severity text DEFAULT 'info'::text, p_category text DEFAULT 'system'::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_notification_id  uuid;
  v_existing_id      uuid;
  v_existing_status  text;
  v_existing_created timestamptz;
  c_race_window CONSTANT INTERVAL := '30 seconds';
BEGIN
  IF p_event_key IS NOT NULL THEN
    SELECT id, status, created_at
      INTO v_existing_id, v_existing_status, v_existing_created
    FROM notifications
    WHERE company_id = p_company_id
      AND event_key  = p_event_key
    ORDER BY created_at DESC
    LIMIT 1;

    IF v_existing_id IS NOT NULL THEN
      ----------------------------------------------------------
      -- Approvals: time-window safety net (covers workflows
      -- that forget to call archive_approval_notifications_…)
      ----------------------------------------------------------
      IF p_category = 'approvals' THEN
        IF v_existing_status = 'unread'
           AND v_existing_created > NOW() - c_race_window
        THEN
          RETURN v_existing_id;  -- race protection
        END IF;
        -- Stale predecessor: archive then insert fresh.
        UPDATE notifications
           SET status = 'archived'
         WHERE company_id = p_company_id
           AND event_key  = p_event_key
           AND status IN ('unread', 'read', 'actioned');

      ----------------------------------------------------------
      -- Non-approvals: original v3.74.16 behavior. Dedup
      -- against any non-archived row. NO auto-archive.
      ----------------------------------------------------------
      ELSE
        IF v_existing_status <> 'archived' THEN
          RETURN v_existing_id;
        END IF;
      END IF;
    END IF;
  END IF;

  INSERT INTO notifications (
    company_id, branch_id, cost_center_id, warehouse_id,
    reference_type, reference_id, created_by,
    assigned_to_role, assigned_to_user,
    title, message, priority, status, event_key, severity, category
  )
  VALUES (
    p_company_id, p_branch_id, p_cost_center_id, p_warehouse_id,
    p_reference_type, p_reference_id, p_created_by,
    p_assigned_to_role, p_assigned_to_user,
    p_title, p_message, p_priority, 'unread', p_event_key, p_severity, p_category
  )
  RETURNING id INTO v_notification_id;

  RETURN v_notification_id;

EXCEPTION
  WHEN unique_violation THEN
    SELECT id INTO v_existing_id
    FROM notifications
    WHERE company_id = p_company_id
      AND event_key  = p_event_key
      AND status     = 'unread'
    LIMIT 1;

    IF v_existing_id IS NOT NULL THEN
      RETURN v_existing_id;
    END IF;
    RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_notification(p_company_id uuid, p_reference_type character varying, p_reference_id uuid, p_title character varying, p_message text, p_created_by uuid, p_branch_id uuid, p_cost_center_id uuid, p_warehouse_id uuid, p_assigned_to_role character varying, p_assigned_to_user uuid, p_priority character varying, p_event_key text, p_severity text, p_category text, p_kind text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_notification(p_company_id uuid, p_reference_type character varying, p_reference_id uuid, p_title character varying, p_message text, p_created_by uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_assigned_to_role character varying DEFAULT NULL::character varying, p_assigned_to_user uuid DEFAULT NULL::uuid, p_priority character varying DEFAULT 'normal'::character varying, p_event_key text DEFAULT NULL::text, p_severity text DEFAULT 'info'::text, p_category text DEFAULT 'system'::text, p_kind text DEFAULT 'info'::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_notification_id  uuid;
  v_existing_id      uuid;
  v_existing_status  text;
  v_existing_created timestamptz;
  c_race_window CONSTANT INTERVAL := '30 seconds';
BEGIN
  IF p_event_key IS NOT NULL THEN
    SELECT id, status, created_at
      INTO v_existing_id, v_existing_status, v_existing_created
    FROM notifications
    WHERE company_id = p_company_id
      AND event_key  = p_event_key
      -- v3.74.607: same RECIPIENT only
      AND assigned_to_role IS NOT DISTINCT FROM p_assigned_to_role
      AND assigned_to_user IS NOT DISTINCT FROM p_assigned_to_user
    ORDER BY created_at DESC
    LIMIT 1;

    IF v_existing_id IS NOT NULL THEN
      IF p_category = 'approvals' THEN
        IF v_existing_status = 'unread'
           AND v_existing_created > NOW() - c_race_window
        THEN
          RETURN v_existing_id;  -- race protection
        END IF;
        UPDATE notifications
           SET status = 'archived'
         WHERE company_id = p_company_id
           AND event_key  = p_event_key
           -- v3.74.607: archive the SAME recipient's stale copy only
           AND assigned_to_role IS NOT DISTINCT FROM p_assigned_to_role
           AND assigned_to_user IS NOT DISTINCT FROM p_assigned_to_user
           AND status IN ('unread', 'read', 'actioned');
      ELSE
        IF v_existing_status <> 'archived' THEN
          RETURN v_existing_id;
        END IF;
      END IF;
    END IF;
  END IF;

  INSERT INTO notifications (
    company_id, branch_id, cost_center_id, warehouse_id,
    reference_type, reference_id, created_by,
    assigned_to_role, assigned_to_user,
    title, message, priority, status, event_key, severity, category, kind
  )
  VALUES (
    p_company_id, p_branch_id, p_cost_center_id, p_warehouse_id,
    p_reference_type, p_reference_id, p_created_by,
    p_assigned_to_role, p_assigned_to_user,
    p_title, p_message, p_priority, 'unread', p_event_key, p_severity, p_category,
    CASE WHEN p_kind IN ('action','info') THEN p_kind ELSE 'info' END
  )
  RETURNING id INTO v_notification_id;

  RETURN v_notification_id;

EXCEPTION
  WHEN unique_violation THEN
    SELECT id INTO v_existing_id
    FROM notifications
    WHERE company_id = p_company_id
      AND event_key  = p_event_key
      AND assigned_to_role IS NOT DISTINCT FROM p_assigned_to_role
      AND assigned_to_user IS NOT DISTINCT FROM p_assigned_to_user
      AND status     = 'unread'
    LIMIT 1;

    IF v_existing_id IS NOT NULL THEN
      RETURN v_existing_id;
    END IF;
    RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_opening_stock_fifo_lots(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_opening_stock_fifo_lots(p_company_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_product RECORD;
  v_lots_created INTEGER := 0;
BEGIN
  -- إنشاء دفعات من المخزون الافتتاحي
  FOR v_product IN
    SELECT
      id,
      quantity_on_hand,
      cost_price,
      name
    FROM products
    WHERE company_id = p_company_id
      AND item_type != 'service'
      AND quantity_on_hand > 0
      AND NOT EXISTS (
        SELECT 1 FROM fifo_cost_lots
        WHERE product_id = products.id
          AND lot_type = 'opening_stock'
      )
  LOOP
    INSERT INTO fifo_cost_lots (
      company_id,
      product_id,
      lot_date,
      lot_type,
      reference_type,
      reference_id,
      original_quantity,
      remaining_quantity,
      unit_cost,
      notes
    ) VALUES (
      p_company_id,
      v_product.id,
      CURRENT_DATE,
      'opening_stock',
      'opening_stock',
      NULL,
      v_product.quantity_on_hand,
      v_product.quantity_on_hand,
      v_product.cost_price,
      'Opening stock for ' || v_product.name
    );

    v_lots_created := v_lots_created + 1;
  END LOOP;

  RETURN v_lots_created;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_payment_correction_request(p_company_id uuid, p_payment_id uuid, p_reason text, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_payment_correction_request(p_company_id uuid, p_payment_id uuid, p_reason text, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_payment record;
  v_request_id uuid;
  v_invoice_id uuid;
  v_inv_number text;
BEGIN
  IF p_reason IS NULL OR LENGTH(TRIM(p_reason)) < 5 THEN
    RAISE EXCEPTION 'REASON_REQUIRED: السَّبَب مَطلوب (حَدّ أَدنى ٥ أَحرُف)';
  END IF;

  SELECT * INTO v_payment FROM payments WHERE id = p_payment_id AND company_id = p_company_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'PAYMENT_NOT_FOUND';
  END IF;

  IF v_payment.is_deleted = true THEN
    RAISE EXCEPTION 'PAYMENT_DELETED: الدَّفعَة مَحذوفَة';
  END IF;

  IF v_payment.voided_by_payment_id IS NOT NULL THEN
    RAISE EXCEPTION 'ALREADY_VOIDED: تَمَّ تَصحيح هذه الدَّفعَة مُسبَقاً';
  END IF;

  IF EXISTS (
    SELECT 1 FROM customer_refund_requests
    WHERE original_payment_id = p_payment_id
      AND status IN ('pending','approved')
  ) THEN
    RAISE EXCEPTION 'DUPLICATE_REQUEST: يوجَد طَلَب تَصحيح قائِم لِنَفس الدَّفعَة';
  END IF;

  -- v3.74.112 - resolve the source invoice for the workflow row:
  --   1) prefer the payment's own invoice_id (regular payments)
  --   2) for refunds / standalone payments, scan payment.notes for INV-XXX
  --      and look it up in invoices.invoice_number within the same company
  v_invoice_id := v_payment.invoice_id;

  IF v_invoice_id IS NULL AND v_payment.notes IS NOT NULL THEN
    v_inv_number := (regexp_match(v_payment.notes, 'INV-[0-9]+'))[1];
    IF v_inv_number IS NOT NULL THEN
      SELECT id INTO v_invoice_id
      FROM invoices
      WHERE company_id = p_company_id
        AND invoice_number = v_inv_number
      LIMIT 1;
    END IF;
  END IF;

  INSERT INTO customer_refund_requests (
    company_id, customer_id, invoice_id, source_type, amount,
    status, notes, requested_by, original_payment_id, metadata
  ) VALUES (
    p_company_id,
    v_payment.customer_id,
    v_invoice_id,
    'payment_correction',
    ABS(v_payment.amount),
    'pending',
    p_reason,
    p_user_id,
    p_payment_id,
    jsonb_build_object(
      'original_payment_id', p_payment_id,
      'original_amount', v_payment.amount,
      'original_payment_method', v_payment.payment_method,
      'original_account_id', v_payment.account_id,
      'original_payment_date', v_payment.payment_date,
      'source_invoice_id', v_invoice_id,
      'requested_at', NOW()
    )
  ) RETURNING id INTO v_request_id;

  RETURN jsonb_build_object('success', true, 'request_id', v_request_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- create_payment_correction_request(p_company_id uuid, p_payment_id uuid, p_reason text, p_user_id uuid, p_proposed_changes jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_payment_correction_request(p_company_id uuid, p_payment_id uuid, p_reason text, p_user_id uuid, p_proposed_changes jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_payment record;
  v_request_id uuid;
  v_invoice_id uuid;
  v_inv_number text;
BEGIN
  IF p_reason IS NULL OR LENGTH(TRIM(p_reason)) < 5 THEN
    RAISE EXCEPTION 'REASON_REQUIRED: السَّبَب مَطلوب (حَدّ أَدنى ٥ أَحرُف)';
  END IF;

  SELECT * INTO v_payment FROM payments WHERE id = p_payment_id AND company_id = p_company_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'PAYMENT_NOT_FOUND'; END IF;
  IF v_payment.is_deleted = true THEN RAISE EXCEPTION 'PAYMENT_DELETED'; END IF;
  IF v_payment.voided_by_payment_id IS NOT NULL THEN RAISE EXCEPTION 'ALREADY_VOIDED'; END IF;

  IF EXISTS (
    SELECT 1 FROM customer_refund_requests
    WHERE original_payment_id = p_payment_id AND status IN ('pending','approved')
  ) THEN
    RAISE EXCEPTION 'DUPLICATE_REQUEST';
  END IF;

  -- Resolve source invoice (works for refund payments too, see v3.74.112).
  v_invoice_id := v_payment.invoice_id;
  IF v_invoice_id IS NULL AND v_payment.notes IS NOT NULL THEN
    v_inv_number := (regexp_match(v_payment.notes, 'INV-[0-9]+'))[1];
    IF v_inv_number IS NOT NULL THEN
      SELECT id INTO v_invoice_id FROM invoices
      WHERE company_id = p_company_id AND invoice_number = v_inv_number LIMIT 1;
    END IF;
  END IF;

  INSERT INTO customer_refund_requests (
    company_id, customer_id, invoice_id, source_type, amount,
    status, notes, requested_by, original_payment_id, metadata
  ) VALUES (
    p_company_id,
    v_payment.customer_id,
    v_invoice_id,
    'payment_correction',
    ABS(v_payment.amount),
    'pending',
    p_reason,
    p_user_id,
    p_payment_id,
    jsonb_build_object(
      'original_payment_id',     p_payment_id,
      'original_amount',         v_payment.amount,
      'original_payment_method', v_payment.payment_method,
      'original_account_id',     v_payment.account_id,
      'original_payment_date',   v_payment.payment_date,
      'original_reference_number', v_payment.reference_number,
      'original_notes',          v_payment.notes,
      'source_invoice_id',       v_invoice_id,
      'proposed_changes',        COALESCE(p_proposed_changes, '{}'::jsonb),
      'requested_at',            NOW()
    )
  ) RETURNING id INTO v_request_id;

  RETURN jsonb_build_object('success', true, 'request_id', v_request_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- create_product_atomic(p_company_id uuid, p_sku text, p_name text, p_description text, p_unit_price numeric, p_cost_price numeric, p_unit text, p_quantity_on_hand numeric, p_reorder_level numeric, p_item_type text, p_income_account_id uuid, p_expense_account_id uuid, p_tax_code_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_cost_center_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_product_atomic(p_company_id uuid, p_sku text, p_name text, p_description text, p_unit_price numeric, p_cost_price numeric, p_unit text, p_quantity_on_hand numeric, p_reorder_level numeric, p_item_type text, p_income_account_id uuid, p_expense_account_id uuid, p_tax_code_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_cost_center_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_product_id  UUID;
    v_final_cc_id UUID := p_cost_center_id;
    v_final_wh_id UUID := p_warehouse_id;
    v_branch_record RECORD;
BEGIN
    -- 1. Fetch branch defaults if branch_id provided and cc/wh missing
    IF p_branch_id IS NOT NULL AND (p_cost_center_id IS NULL OR (p_item_type = 'product' AND p_warehouse_id IS NULL)) THEN
        SELECT default_cost_center_id, default_warehouse_id
        INTO v_branch_record
        FROM branches
        WHERE id = p_branch_id AND company_id = p_company_id;

        IF FOUND THEN
            IF p_cost_center_id IS NULL THEN
                v_final_cc_id := v_branch_record.default_cost_center_id;
            END IF;
            IF p_item_type = 'product' AND p_warehouse_id IS NULL THEN
                v_final_wh_id := v_branch_record.default_warehouse_id;
            END IF;
        END IF;
    END IF;

    -- 2. Services have no warehouse
    IF p_item_type = 'service' THEN
        v_final_wh_id := NULL;
    END IF;

    -- 3. Atomic insert
    INSERT INTO products (
        company_id, sku, name, description, unit_price, cost_price, unit,
        quantity_on_hand, reorder_level, item_type,
        income_account_id, expense_account_id, tax_code_id,
        branch_id, warehouse_id, cost_center_id
    ) VALUES (
        p_company_id, p_sku, p_name, p_description,
        p_unit_price, p_cost_price, p_unit,
        p_quantity_on_hand, p_reorder_level, p_item_type,
        p_income_account_id, p_expense_account_id, p_tax_code_id,
        p_branch_id, v_final_wh_id, v_final_cc_id
    ) RETURNING id INTO v_product_id;

    RETURN jsonb_build_object(
        'success', true,
        'product_id', v_product_id,
        'final_warehouse_id', v_final_wh_id,
        'final_cost_center_id', v_final_cc_id
    );
END;
$function$
;

-- ---------------------------------------------------------------
-- create_product_atomic(p_company_id uuid, p_sku text, p_name text, p_description text, p_unit_price numeric, p_cost_price numeric, p_unit text, p_quantity_on_hand numeric, p_reorder_level numeric, p_item_type text, p_income_account_id uuid, p_expense_account_id uuid, p_tax_code_id text, p_branch_id uuid, p_warehouse_id uuid, p_cost_center_id uuid, p_product_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_product_atomic(p_company_id uuid, p_sku text, p_name text, p_description text, p_unit_price numeric, p_cost_price numeric, p_unit text, p_quantity_on_hand numeric, p_reorder_level numeric, p_item_type text, p_income_account_id uuid, p_expense_account_id uuid, p_tax_code_id text, p_branch_id uuid, p_warehouse_id uuid, p_cost_center_id uuid, p_product_type text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_product_id UUID;
    v_final_cc_id UUID := p_cost_center_id;
    v_final_wh_id UUID := p_warehouse_id;
    v_final_tax_code_id UUID := NULLIF(BTRIM(COALESCE(p_tax_code_id, '')), '')::UUID;
    v_branch_record RECORD;
    v_final_product_type TEXT := NULLIF(BTRIM(COALESCE(p_product_type, '')), '');
BEGIN
    IF p_branch_id IS NOT NULL AND (p_cost_center_id IS NULL OR (p_item_type = 'product' AND p_warehouse_id IS NULL)) THEN
        SELECT default_cost_center_id, default_warehouse_id INTO v_branch_record
        FROM branches WHERE id = p_branch_id AND company_id = p_company_id;
        IF FOUND THEN
            IF p_cost_center_id IS NULL THEN v_final_cc_id := v_branch_record.default_cost_center_id; END IF;
            IF p_item_type = 'product' AND p_warehouse_id IS NULL THEN v_final_wh_id := v_branch_record.default_warehouse_id; END IF;
        END IF;
    END IF;

    IF p_item_type = 'service' THEN v_final_wh_id := NULL; END IF;

    IF v_final_product_type IS NULL THEN
        v_final_product_type := CASE WHEN p_item_type = 'service' THEN 'service' ELSE 'purchased' END;
    END IF;

    IF v_final_product_type NOT IN ('manufactured','raw_material','purchased','service') THEN
        RAISE EXCEPTION 'Invalid product_type: %', v_final_product_type;
    END IF;
    IF p_item_type = 'service' AND v_final_product_type <> 'service' THEN
        RAISE EXCEPTION 'item_type=service must use product_type=service';
    END IF;
    IF p_item_type <> 'service' AND v_final_product_type = 'service' THEN
        RAISE EXCEPTION 'product_type=service requires item_type=service';
    END IF;

    INSERT INTO products (
        company_id, sku, name, description, unit_price, cost_price, unit,
        quantity_on_hand, reorder_level, item_type, product_type,
        income_account_id, expense_account_id, tax_code_id,
        branch_id, warehouse_id, cost_center_id
    ) VALUES (
        p_company_id, p_sku, p_name, p_description, p_unit_price, p_cost_price, p_unit,
        p_quantity_on_hand, p_reorder_level, p_item_type, v_final_product_type,
        p_income_account_id, p_expense_account_id, v_final_tax_code_id,
        p_branch_id, v_final_wh_id, v_final_cc_id
    ) RETURNING id INTO v_product_id;

    RETURN jsonb_build_object(
        'success', true, 'product_id', v_product_id,
        'final_warehouse_id', v_final_wh_id,
        'final_cost_center_id', v_final_cc_id,
        'product_type', v_final_product_type
    );
EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION 'Failed to create product atomically: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_reversal_entry(p_original_entry_id uuid, p_reversal_date date, p_posted_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_reversal_entry(p_original_entry_id uuid, p_reversal_date date DEFAULT CURRENT_DATE, p_posted_by uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_orig RECORD;
  v_new_id UUID;
  v_line RECORD;
BEGIN
  SELECT id, company_id, entry_date, description, reference_type, reference_id,
         branch_id, cost_center_id, warehouse_id, status
  INTO v_orig
  FROM journal_entries
  WHERE id = p_original_entry_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Journal entry not found: %', p_original_entry_id;
  END IF;

  IF v_orig.status <> 'posted' THEN
    RAISE EXCEPTION 'Only posted entries can be reversed. Entry % has status %.', p_original_entry_id, v_orig.status;
  END IF;

  -- التحقق من قفل الفترة لتاريخ ال reversal
  IF public.check_fiscal_period_locked(v_orig.company_id, p_reversal_date) THEN
    RAISE EXCEPTION 'Cannot create reversal: fiscal period for date % is closed or locked.', p_reversal_date;
  END IF;

  -- السماح بالإضافة
  PERFORM set_config('app.allow_direct_post', 'true', true);

  INSERT INTO journal_entries (
    company_id, entry_date, description, reference_type, reference_id,
    branch_id, cost_center_id, warehouse_id, status,
    reversal_of_entry_id, is_closing_entry
  ) VALUES (
    v_orig.company_id,
    p_reversal_date,
    'Reversal: ' || COALESCE(v_orig.description, ''),
    'reversal',
    p_original_entry_id,
    v_orig.branch_id,
    v_orig.cost_center_id,
    v_orig.warehouse_id,
    'posted',
    p_original_entry_id,
    FALSE
  ) RETURNING id INTO v_new_id;

  -- نسخ السطور بعكس المدين والدائن
  FOR v_line IN
    SELECT account_id, debit_amount, credit_amount, description
    FROM journal_entry_lines
    WHERE journal_entry_id = p_original_entry_id
  LOOP
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
    VALUES (
      v_new_id,
      v_line.account_id,
      v_line.credit_amount,
      v_line.debit_amount,
      COALESCE(v_line.description, '') || ' (عكسي)'
    );
  END LOOP;

  PERFORM set_config('app.allow_direct_post', 'false', true);

  RETURN v_new_id;
EXCEPTION
  WHEN OTHERS THEN
    PERFORM set_config('app.allow_direct_post', 'false', true);
    RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_sales_invoice_atomic(p_invoice_data jsonb, p_invoice_items jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_sales_invoice_atomic(p_invoice_data jsonb, p_invoice_items jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_invoice_id UUID;
    v_item JSONB;
BEGIN
    INSERT INTO invoices (
        company_id, customer_id, invoice_date, due_date, subtotal, tax_amount, total_amount,
        discount_type, discount_value, discount_position, tax_inclusive, shipping, shipping_tax_rate,
        shipping_provider_id, adjustment, status, sales_order_id, branch_id, cost_center_id, warehouse_id,
        created_by_user_id, currency_code, exchange_rate, exchange_rate_used, exchange_rate_id, rate_source,
        base_currency_total, original_currency, original_total, original_subtotal, original_tax_amount,
        customer_name_snapshot, customer_email_snapshot, customer_phone_snapshot, customer_address_snapshot,
        customer_city_snapshot, customer_country_snapshot, customer_tax_id_snapshot, customer_governorate_snapshot,
        customer_detailed_address_snapshot
    )
    SELECT
        (p_invoice_data->>'company_id')::UUID,
        (p_invoice_data->>'customer_id')::UUID,
        (p_invoice_data->>'invoice_date')::DATE,
        (p_invoice_data->>'due_date')::DATE,
        (p_invoice_data->>'subtotal')::NUMERIC,
        (p_invoice_data->>'tax_amount')::NUMERIC,
        (p_invoice_data->>'total_amount')::NUMERIC,
        p_invoice_data->>'discount_type',
        (p_invoice_data->>'discount_value')::NUMERIC,
        p_invoice_data->>'discount_position',
        (p_invoice_data->>'tax_inclusive')::BOOLEAN,
        (p_invoice_data->>'shipping')::NUMERIC,
        (p_invoice_data->>'shipping_tax_rate')::NUMERIC,
        NULLIF(p_invoice_data->>'shipping_provider_id', '')::UUID,
        (p_invoice_data->>'adjustment')::NUMERIC,
        COALESCE(p_invoice_data->>'status', 'draft'),
        NULLIF(p_invoice_data->>'sales_order_id', '')::UUID,
        NULLIF(p_invoice_data->>'branch_id', '')::UUID,
        NULLIF(p_invoice_data->>'cost_center_id', '')::UUID,
        NULLIF(p_invoice_data->>'warehouse_id', '')::UUID,
        (p_invoice_data->>'created_by_user_id')::UUID,
        p_invoice_data->>'currency_code',
        (p_invoice_data->>'exchange_rate')::NUMERIC,
        (p_invoice_data->>'exchange_rate_used')::NUMERIC,
        NULLIF(p_invoice_data->>'exchange_rate_id', '')::UUID,
        p_invoice_data->>'rate_source',
        (p_invoice_data->>'base_currency_total')::NUMERIC,
        p_invoice_data->>'original_currency',
        (p_invoice_data->>'original_total')::NUMERIC,
        (p_invoice_data->>'original_subtotal')::NUMERIC,
        (p_invoice_data->>'original_tax_amount')::NUMERIC,
        p_invoice_data->>'customer_name_snapshot',
        p_invoice_data->>'customer_email_snapshot',
        p_invoice_data->>'customer_phone_snapshot',
        p_invoice_data->>'customer_address_snapshot',
        p_invoice_data->>'customer_city_snapshot',
        p_invoice_data->>'customer_country_snapshot',
        p_invoice_data->>'customer_tax_id_snapshot',
        p_invoice_data->>'customer_governorate_snapshot',
        p_invoice_data->>'customer_detailed_address_snapshot'
    RETURNING id INTO v_invoice_id;

    FOR v_item IN SELECT * FROM jsonb_array_elements(p_invoice_items) LOOP
        INSERT INTO invoice_items (
            invoice_id, product_id, quantity, unit_price, tax_rate,
            discount_percent, line_total, returned_quantity, item_type
        ) VALUES (
            v_invoice_id,
            (v_item->>'product_id')::UUID,
            (v_item->>'quantity')::INTEGER,
            (v_item->>'unit_price')::NUMERIC,
            (v_item->>'tax_rate')::NUMERIC,
            COALESCE((v_item->>'discount_percent')::NUMERIC, 0),
            (v_item->>'line_total')::NUMERIC,
            COALESCE((v_item->>'returned_quantity')::INTEGER, 0),
            COALESCE(v_item->>'item_type', 'product')
        );
    END LOOP;

    RETURN jsonb_build_object('success', true, 'invoice_id', v_invoice_id);

EXCEPTION WHEN OTHERS THEN
    RAISE EXCEPTION 'Invoice creation failed: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_sales_return_gl_reversal(p_company_id uuid, p_invoice_id uuid, p_return_amount numeric, p_return_request_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_sales_return_gl_reversal(p_company_id uuid, p_invoice_id uuid, p_return_amount numeric, p_return_request_id uuid, p_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_invoice            RECORD;
  v_journal_id         UUID;
  v_ar_account_id      UUID;
  v_revenue_account_id UUID;
  v_branch_id          UUID;
  v_cost_center_id     UUID;
BEGIN
  -- 1. Idempotency
  IF EXISTS (
    SELECT 1 FROM journal_entries
    WHERE company_id     = p_company_id
      AND reference_type = 'sales_return'
      AND reference_id   = p_return_request_id::TEXT
      AND (is_deleted IS NULL OR is_deleted = FALSE)
  ) THEN
    RETURN jsonb_build_object('success', true, 'idempotent', true);
  END IF;

  -- 2. Fetch invoice
  SELECT * INTO v_invoice FROM invoices WHERE id = p_invoice_id AND company_id = p_company_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'INVOICE_NOT_FOUND: Invoice % not found', p_invoice_id;
  END IF;

  v_branch_id      := v_invoice.branch_id;
  v_cost_center_id := v_invoice.cost_center_id;

  -- 3. Resolve AR account
  SELECT id INTO v_ar_account_id FROM chart_of_accounts
  WHERE company_id = p_company_id AND is_active = TRUE
    AND (sub_type = 'accounts_receivable' OR account_name ILIKE '%receivable%' OR account_name ILIKE '%الذمم المدين%')
  ORDER BY CASE WHEN sub_type = 'accounts_receivable' THEN 0 ELSE 1 END LIMIT 1;

  -- 4. Resolve Revenue account
  SELECT id INTO v_revenue_account_id FROM chart_of_accounts
  WHERE company_id = p_company_id AND is_active = TRUE
    AND (sub_type = 'sales_revenue' OR account_name ILIKE '%revenue%' OR account_name ILIKE '%المبيعات%' OR account_type = 'income')
  ORDER BY CASE WHEN sub_type = 'sales_revenue' THEN 0 ELSE 1 END LIMIT 1;

  IF v_ar_account_id IS NULL OR v_revenue_account_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'MISSING_GL_ACCOUNTS');
  END IF;

  -- 5. Create reversal journal entry
  PERFORM set_config('app.allow_direct_post', 'true', true);

  INSERT INTO journal_entries (
    company_id, branch_id, cost_center_id, reference_type, reference_id,
    entry_date, description, status, warehouse_id
  ) VALUES (
    p_company_id, v_branch_id, v_cost_center_id,
    'sales_return', p_return_request_id::TEXT,
    CURRENT_DATE,
    'قيد عكسي — مرتجع مبيعات للفاتورة ' || v_invoice.invoice_number,
    'draft', v_invoice.warehouse_id
  ) RETURNING id INTO v_journal_id;

  -- Dr: Sales Revenue
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
  VALUES (v_journal_id, v_revenue_account_id, p_return_amount, 0, 'عكس إيراد مرتجع — ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id);

  -- Cr: AR
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id)
  VALUES (v_journal_id, v_ar_account_id, 0, p_return_amount, 'تخفيض الذمة المدينة — مرتجع ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id);

  UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_id;
  PERFORM set_config('app.allow_direct_post', 'false', true);

  RETURN jsonb_build_object('success', true, 'journal_entry_id', v_journal_id, 'return_amount', p_return_amount);

EXCEPTION WHEN OTHERS THEN
  PERFORM set_config('app.allow_direct_post', 'false', true);
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- create_seat_licenses_for_purchase(p_company_id uuid, p_seats_count integer, p_billing_period text, p_billing_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_seat_licenses_for_purchase(p_company_id uuid, p_seats_count integer, p_billing_period text, p_billing_invoice_id uuid DEFAULT NULL::uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_period           text;
  v_purchased_at     timestamptz := NOW();
  v_expires_at       timestamptz;
  v_max_seat         int;
  v_next_seat        int;
  v_created          int := 0;
  v_existing_count   int;
  i                  int;
  v_new_ids          uuid[] := ARRAY[]::uuid[];
  v_new_id           uuid;
BEGIN
  IF p_company_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'company_id_required');
  END IF;
  IF p_seats_count IS NULL OR p_seats_count <= 0 THEN
    RETURN json_build_object('success', false, 'error', 'invalid_seats_count');
  END IF;

  v_period := CASE WHEN p_billing_period = 'annual' THEN 'annual' ELSE 'monthly' END;
  v_expires_at := CASE
    WHEN v_period = 'annual' THEN v_purchased_at + INTERVAL '1 year'
    ELSE                          v_purchased_at + INTERVAL '1 month'
  END;

  PERFORM pg_advisory_xact_lock(hashtext(p_company_id::text));

  IF p_billing_invoice_id IS NOT NULL THEN
    SELECT count(*) INTO v_existing_count
      FROM public.company_seat_licenses
     WHERE company_id = p_company_id
       AND billing_invoice_id = p_billing_invoice_id;

    IF v_existing_count > 0 THEN
      RETURN json_build_object(
        'success', true, 'idempotent', true,
        'created_count', 0, 'existing_count', v_existing_count,
        'invoice_id', p_billing_invoice_id
      );
    END IF;
  END IF;

  SELECT COALESCE(MAX(seat_number), 0) INTO v_max_seat
    FROM public.company_seat_licenses WHERE company_id = p_company_id;

  v_next_seat := v_max_seat + 1;

  FOR i IN 0..(p_seats_count - 1) LOOP
    INSERT INTO public.company_seat_licenses (
      company_id, seat_number, billing_period,
      purchased_at, expires_at, billing_invoice_id
    ) VALUES (
      p_company_id, v_next_seat + i, v_period,
      v_purchased_at, v_expires_at, p_billing_invoice_id
    )
    RETURNING id INTO v_new_id;
    v_new_ids := array_append(v_new_ids, v_new_id);
    v_created := v_created + 1;
  END LOOP;

  BEGIN
    INSERT INTO public.audit_logs (action, company_id, target_table, new_data)
    VALUES (
      'seat_licenses_created', p_company_id, 'company_seat_licenses',
      json_build_object(
        'count', v_created,
        'first_seat_number', v_next_seat,
        'last_seat_number',  v_next_seat + p_seats_count - 1,
        'billing_period',    v_period,
        'purchased_at',      v_purchased_at,
        'expires_at',        v_expires_at,
        'billing_invoice_id', p_billing_invoice_id,
        'license_ids',       v_new_ids
      )::jsonb
    );
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN json_build_object(
    'success', true, 'idempotent', false,
    'created_count', v_created,
    'first_seat', v_next_seat,
    'last_seat',  v_next_seat + p_seats_count - 1,
    'license_ids', to_json(v_new_ids),
    'billing_period', v_period,
    'purchased_at', v_purchased_at,
    'expires_at',   v_expires_at
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- create_service_atomic(p_company_id uuid, p_branch_id uuid, p_created_by uuid, p_product_catalog_id uuid, p_service_type text, p_duration_minutes integer, p_service_code text, p_description text, p_category text, p_tax_rate numeric, p_commission_rate numeric, p_capacity integer, p_buffer_minutes integer, p_advance_booking_days integer, p_min_advance_hours integer, p_cancel_before_hours integer, p_cost_center_id uuid, p_image_url text, p_color_code text, p_is_bookable boolean, p_requires_approval boolean, p_notes text, p_currency_code text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_service_atomic(p_company_id uuid, p_branch_id uuid, p_created_by uuid, p_product_catalog_id uuid, p_service_type text, p_duration_minutes integer, p_service_code text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_category text DEFAULT NULL::text, p_tax_rate numeric DEFAULT 0, p_commission_rate numeric DEFAULT 0, p_capacity integer DEFAULT 1, p_buffer_minutes integer DEFAULT 0, p_advance_booking_days integer DEFAULT 30, p_min_advance_hours integer DEFAULT 1, p_cancel_before_hours integer DEFAULT 24, p_cost_center_id uuid DEFAULT NULL::uuid, p_image_url text DEFAULT NULL::text, p_color_code text DEFAULT NULL::text, p_is_bookable boolean DEFAULT true, p_requires_approval boolean DEFAULT false, p_notes text DEFAULT NULL::text, p_currency_code text DEFAULT 'EGP'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service_id   UUID;
  v_service_code TEXT;
BEGIN
  IF p_product_catalog_id IS NULL THEN
    RAISE EXCEPTION 'product_catalog_id is required when creating a service'
      USING ERRCODE = 'P0001';
  END IF;

  IF NOT public.svc_is_valid_service_type(p_service_type) THEN
    RAISE EXCEPTION
      'Invalid service_type: %. Allowed: individual,group,hourly,session,daily',
      p_service_type
      USING ERRCODE = 'P0001';
  END IF;

  IF p_service_code IS NULL OR BTRIM(p_service_code) = '' THEN
    v_service_code := public.svc_generate_service_code(p_company_id);
  ELSE
    v_service_code := BTRIM(p_service_code);
  END IF;

  INSERT INTO public.services (
    company_id, branch_id, cost_center_id, service_code, service_name,
    description, category, service_type,
    unit_price, cost_price, tax_rate, currency_code, commission_rate,
    duration_minutes, capacity, buffer_minutes,
    advance_booking_days, min_advance_hours, cancel_before_hours,
    revenue_account_id, expense_account_id,
    image_url, color_code, is_bookable, is_active, requires_approval,
    notes, created_by, updated_by, product_catalog_id
  ) VALUES (
    p_company_id, p_branch_id, p_cost_center_id, v_service_code, NULL,
    p_description, p_category, p_service_type,
    0, 0, p_tax_rate, p_currency_code, p_commission_rate,
    p_duration_minutes, p_capacity, p_buffer_minutes,
    p_advance_booking_days, p_min_advance_hours, p_cancel_before_hours,
    NULL, NULL,
    p_image_url, p_color_code, p_is_bookable, true, p_requires_approval,
    p_notes, p_created_by, p_created_by, p_product_catalog_id
  ) RETURNING id INTO v_service_id;

  RETURN jsonb_build_object(
    'success',      true,
    'service_id',   v_service_id,
    'service_code', v_service_code
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- create_user_profile_on_signup()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_user_profile_on_signup()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_username TEXT;
BEGIN
  -- محاولة توليد username
  BEGIN
    v_username := generate_username_from_email(NEW.email);
  EXCEPTION WHEN OTHERS THEN
    v_username := NULL;
  END;

  -- إنشاء ملف المستخدم
  BEGIN
    INSERT INTO user_profiles (user_id, username, display_name)
    VALUES (
      NEW.id,
      v_username,
      COALESCE(NEW.raw_user_meta_data->>'full_name', SPLIT_PART(NEW.email, '@', 1))
    )
    ON CONFLICT (user_id) DO NOTHING;
  EXCEPTION WHEN unique_violation THEN
    INSERT INTO user_profiles (user_id, username, display_name)
    VALUES (NEW.id, NULL, SPLIT_PART(NEW.email, '@', 1))
    ON CONFLICT (user_id) DO NOTHING;
  WHEN OTHERS THEN
    RAISE WARNING 'Could not create user profile for %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_vendor_credit_from_bill_return(p_bill_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_vendor_credit_from_bill_return(p_bill_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_bill RECORD;
  v_vendor_credit_id UUID;
  v_credit_number TEXT;
  v_next_number INTEGER;
  v_company_prefix TEXT;
BEGIN
  -- Get bill details
  SELECT 
    b.id,
    b.company_id,
    b.branch_id,
    b.cost_center_id,
    b.supplier_id,
    b.returned_amount,
    b.bill_date,
    b.bill_number,
    b.status,
    b.return_status,
    c.name as company_name
  INTO v_bill
  FROM bills b
  INNER JOIN companies c ON c.id = b.company_id
  WHERE b.id = p_bill_id;

  -- Validation: Bill must exist
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Bill not found: %', p_bill_id;
  END IF;

  -- Validation: Bill must be Paid or Partially Paid or Fully Returned
  IF v_bill.status NOT IN ('paid', 'partially_paid', 'fully_returned') THEN
    RAISE NOTICE 'Bill % is not eligible (status: %). Skipping.', 
      v_bill.bill_number, v_bill.status;
    RETURN NULL;
  END IF;

  -- Validation: Must have returned amount
  IF v_bill.returned_amount IS NULL OR v_bill.returned_amount <= 0 THEN
    RAISE NOTICE 'Bill % has no returned amount. Skipping.', v_bill.bill_number;
    RETURN NULL;
  END IF;

  -- Check if Vendor Credit already exists for this bill
  SELECT id INTO v_vendor_credit_id
  FROM vendor_credits
  WHERE source_purchase_invoice_id = p_bill_id
    AND reference_type = 'bill_return'
  LIMIT 1;

  IF FOUND THEN
    RAISE NOTICE 'Vendor Credit already exists for bill %. Skipping.', v_bill.bill_number;
    RETURN v_vendor_credit_id;
  END IF;

  -- Generate credit number
  v_company_prefix := UPPER(LEFT(REGEXP_REPLACE(v_bill.company_name, '[^a-zA-Z]', '', 'g'), 3));
  IF v_company_prefix = '' THEN
    v_company_prefix := 'VC';
  END IF;

  -- Get next number for this company
  SELECT COALESCE(MAX(
    CASE 
      WHEN credit_number ~ '^[A-Z]+-VC-[0-9]+$' 
      THEN CAST(SUBSTRING(credit_number FROM '[0-9]+$') AS INTEGER)
      ELSE 0
    END
  ), 0) + 1
  INTO v_next_number
  FROM vendor_credits
  WHERE company_id = v_bill.company_id;

  v_credit_number := v_company_prefix || '-VC-' || LPAD(v_next_number::TEXT, 4, '0');

  -- Create Vendor Credit
  INSERT INTO vendor_credits (
    company_id,
    branch_id,
    cost_center_id,
    supplier_id,
    credit_number,
    credit_date,
    subtotal,
    tax_amount,
    total_amount,
    applied_amount,
    status,
    source_purchase_invoice_id,
    reference_type,
    reference_id,
    notes,
    created_at,
    updated_at
  ) VALUES (
    v_bill.company_id,
    v_bill.branch_id,
    v_bill.cost_center_id,
    v_bill.supplier_id,
    v_credit_number,
    v_bill.bill_date,
    v_bill.returned_amount,
    0,
    v_bill.returned_amount,
    0,
    'open',
    p_bill_id,
    'bill_return',
    p_bill_id,
    'Auto-generated from bill return: ' || v_bill.bill_number || 
      ' (Returned: ' || v_bill.returned_amount || ', Status: ' || COALESCE(v_bill.return_status, 'N/A') || ')',
    NOW(),
    NOW()
  ) RETURNING id INTO v_vendor_credit_id;

  RAISE NOTICE 'Created Vendor Credit % (ID: %) for bill % with amount %',
    v_credit_number, v_vendor_credit_id, v_bill.bill_number, v_bill.returned_amount;

  RETURN v_vendor_credit_id;

EXCEPTION
  WHEN OTHERS THEN
    RAISE WARNING 'Error creating vendor credit for bill %: %', p_bill_id, SQLERRM;
    RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_vendor_credits_for_all_returns()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_vendor_credits_for_all_returns()
 RETURNS TABLE(bill_id uuid, bill_number text, company_name text, returned_amount numeric, vendor_credit_id uuid, status text)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_bill RECORD;
  v_vc_id UUID;
  v_processed INTEGER := 0;
  v_created INTEGER := 0;
  v_skipped INTEGER := 0;
  v_errors INTEGER := 0;
BEGIN
  RAISE NOTICE '========================================';
  RAISE NOTICE 'Starting Vendor Credits Migration';
  RAISE NOTICE '========================================';

  -- Loop through all eligible bills
  FOR v_bill IN
    SELECT 
      b.id,
      b.bill_number,
      c.name as company_name,
      b.returned_amount,
      b.status,
      b.return_status
    FROM bills b
    INNER JOIN companies c ON c.id = b.company_id
    WHERE b.returned_amount > 0
      AND b.status IN ('paid', 'partially_paid', 'fully_returned')
    ORDER BY c.name, b.bill_number
  LOOP
    v_processed := v_processed + 1;
    
    BEGIN
      -- Create vendor credit
      v_vc_id := create_vendor_credit_from_bill_return(v_bill.id);
      
      IF v_vc_id IS NOT NULL THEN
        v_created := v_created + 1;
        
        RETURN QUERY SELECT 
          v_bill.id,
          v_bill.bill_number,
          v_bill.company_name,
          v_bill.returned_amount,
          v_vc_id,
          'created'::TEXT;
      ELSE
        v_skipped := v_skipped + 1;
        
        RETURN QUERY SELECT 
          v_bill.id,
          v_bill.bill_number,
          v_bill.company_name,
          v_bill.returned_amount,
          NULL::UUID,
          'skipped'::TEXT;
      END IF;
      
    EXCEPTION
      WHEN OTHERS THEN
        v_errors := v_errors + 1;
        
        RETURN QUERY SELECT 
          v_bill.id,
          v_bill.bill_number,
          v_bill.company_name,
          v_bill.returned_amount,
          NULL::UUID,
          ('error: ' || SQLERRM)::TEXT;
    END;
  END LOOP;

  RAISE NOTICE '========================================';
  RAISE NOTICE 'Migration Complete';
  RAISE NOTICE 'Processed: %', v_processed;
  RAISE NOTICE 'Created: %', v_created;
  RAISE NOTICE 'Skipped: %', v_skipped;
  RAISE NOTICE 'Errors: %', v_errors;
  RAISE NOTICE '========================================';

  RETURN;
END;
$function$
;

-- ---------------------------------------------------------------
-- create_vendor_payment_correction_request(p_company_id uuid, p_payment_id uuid, p_reason text, p_user_id uuid, p_proposed_changes jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_vendor_payment_correction_request(p_company_id uuid, p_payment_id uuid, p_reason text, p_user_id uuid, p_proposed_changes jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_payment record;
  v_request_id uuid;
  v_bill_id uuid;
  v_bill_number text;
BEGIN
  IF p_reason IS NULL OR LENGTH(TRIM(p_reason)) < 5 THEN
    RAISE EXCEPTION 'REASON_REQUIRED: السَّبَب مَطلوب (حَدّ أَدنى ٥ أَحرُف)';
  END IF;

  SELECT * INTO v_payment FROM payments
   WHERE id = p_payment_id AND company_id = p_company_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'PAYMENT_NOT_FOUND'; END IF;
  IF v_payment.is_deleted = true THEN RAISE EXCEPTION 'PAYMENT_DELETED'; END IF;
  IF v_payment.voided_by_payment_id IS NOT NULL THEN RAISE EXCEPTION 'ALREADY_VOIDED'; END IF;
  IF v_payment.supplier_id IS NULL THEN RAISE EXCEPTION 'NOT_VENDOR_PAYMENT'; END IF;

  IF EXISTS (
    SELECT 1 FROM vendor_payment_correction_requests
    WHERE original_payment_id = p_payment_id AND status IN ('pending','approved')
  ) THEN
    RAISE EXCEPTION 'DUPLICATE_REQUEST: يوجَد طَلَب تَصحيح قائِم لِنَفس الدَّفعَة';
  END IF;

  -- Resolve source bill: 1) p.bill_id, 2) scan notes for BILL-NNN
  v_bill_id := v_payment.bill_id;
  IF v_bill_id IS NULL AND v_payment.notes IS NOT NULL THEN
    v_bill_number := (regexp_match(v_payment.notes, 'BILL-[0-9]+'))[1];
    IF v_bill_number IS NOT NULL THEN
      SELECT id INTO v_bill_id FROM bills
       WHERE company_id = p_company_id AND bill_number = v_bill_number LIMIT 1;
    END IF;
  END IF;

  INSERT INTO vendor_payment_correction_requests (
    company_id, supplier_id, bill_id, source_type, amount,
    status, notes, requested_by, original_payment_id, metadata
  ) VALUES (
    p_company_id,
    v_payment.supplier_id,
    v_bill_id,
    'payment_correction',
    ABS(v_payment.amount),
    'pending',
    p_reason,
    p_user_id,
    p_payment_id,
    jsonb_build_object(
      'original_payment_id',      p_payment_id,
      'original_amount',          v_payment.amount,
      'original_payment_method',  v_payment.payment_method,
      'original_account_id',      v_payment.account_id,
      'original_payment_date',    v_payment.payment_date,
      'original_reference_number', v_payment.reference_number,
      'original_notes',           v_payment.notes,
      'source_bill_id',           v_bill_id,
      'proposed_changes',         COALESCE(p_proposed_changes, '{}'::jsonb),
      'requested_at',             NOW()
    )
  ) RETURNING id INTO v_request_id;

  RETURN jsonb_build_object('success', true, 'request_id', v_request_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- create_vendor_refund_request(p_company_id uuid, p_supplier_id uuid, p_amount numeric, p_currency text, p_exchange_rate numeric, p_base_amount numeric, p_receipt_account_id uuid, p_receipt_date date, p_notes text, p_branch_id uuid, p_cost_center_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.create_vendor_refund_request(p_company_id uuid, p_supplier_id uuid, p_amount numeric, p_currency text, p_exchange_rate numeric, p_base_amount numeric, p_receipt_account_id uuid, p_receipt_date date, p_notes text DEFAULT NULL::text, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id     UUID := auth.uid();
  v_user_role   TEXT;
  v_request_id  UUID;
BEGIN
  -- التحقق من العضوية
  SELECT role INTO v_user_role
  FROM public.company_members
  WHERE company_id = p_company_id AND user_id = v_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User is not a member of this company');
  END IF;

  -- التحقق من أن المبلغ موجب
  IF p_amount <= 0 OR p_base_amount <= 0 THEN
    RETURN jsonb_build_object('success', false, 'error', 'Amount must be positive');
  END IF;

  -- إنشاء الطلب
  INSERT INTO public.vendor_refund_requests (
    company_id, supplier_id, branch_id, cost_center_id,
    amount, currency, exchange_rate, base_amount,
    receipt_account_id, receipt_date, notes,
    status, created_by
  )
  VALUES (
    p_company_id, p_supplier_id, p_branch_id, p_cost_center_id,
    p_amount, p_currency, p_exchange_rate, p_base_amount,
    p_receipt_account_id, p_receipt_date, p_notes,
    'pending_approval', v_user_id
  )
  RETURNING id INTO v_request_id;

  -- سجل تدقيق
  INSERT INTO public.audit_logs (company_id, user_id, action, target_table, record_id, new_data, created_at)
  VALUES (
    p_company_id, v_user_id, 'INSERT', 'vendor_refund_requests', v_request_id,
    jsonb_build_object('supplier_id', p_supplier_id, 'amount', p_amount, 'currency', p_currency, 'status', 'pending_approval'),
    NOW()
  );

  RETURN jsonb_build_object('success', true, 'request_id', v_request_id);

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- cron_ensure_accounting_periods(p_months_ahead integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.cron_ensure_accounting_periods(p_months_ahead integer DEFAULT 3)
 RETURNS TABLE(total_companies integer, total_inserted integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_company RECORD;
  v_inserted int;
  v_total int := 0;
  v_companies int := 0;
BEGIN
  IF p_months_ahead IS NULL OR p_months_ahead < 1 THEN
    p_months_ahead := 3;
  END IF;

  FOR v_company IN SELECT id FROM companies LOOP
    v_companies := v_companies + 1;
    -- Always ensure at least the CURRENT month and the next (p_months_ahead - 1) months exist.
    -- seed_accounting_periods_for_company is idempotent and pre-checks overlap.
    v_inserted :=
      seed_accounting_periods_for_company(v_company.id, CURRENT_DATE, p_months_ahead);
    v_total := v_total + v_inserted;
  END LOOP;

  RETURN QUERY SELECT v_companies, v_total;
END;
$function$
;

-- ---------------------------------------------------------------
-- current_user_branch_id(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.current_user_branch_id(p_company_id uuid)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
  SELECT branch_id
  FROM public.company_members
  WHERE user_id = auth.uid() AND company_id = p_company_id
  LIMIT 1;
$function$
;

-- ---------------------------------------------------------------
-- current_user_record_visibility(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.current_user_record_visibility(p_company_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_role text;
  v_is_owner boolean;
BEGIN
  -- Company owner has full visibility
  SELECT EXISTS (
    SELECT 1 FROM public.companies WHERE id = p_company_id AND user_id = auth.uid()
  ) INTO v_is_owner;

  IF v_is_owner THEN
    RETURN 'company';
  END IF;

  SELECT role INTO v_role
  FROM public.company_members
  WHERE user_id = auth.uid() AND company_id = p_company_id
  LIMIT 1;

  IF v_role IS NULL THEN
    RETURN 'none';
  END IF;

  RETURN CASE
    WHEN v_role IN ('owner', 'admin')                                              THEN 'company'
    WHEN v_role IN ('manager', 'accountant', 'supervisor', 'store_manager',
                    'manufacturing_officer', 'purchasing_officer', 'hr_officer')   THEN 'branch'
    WHEN v_role = 'viewer'                                                         THEN 'company'
    ELSE 'own'  -- staff, employee, sales, booking_officer
  END;
END;
$function$
;

-- ---------------------------------------------------------------
-- current_user_resource_visibility(p_company_id uuid, p_resource text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.current_user_resource_visibility(p_company_id uuid, p_resource text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_role         text;
  v_is_owner     boolean;
  v_can_access   boolean;
BEGIN
  SELECT EXISTS (
    SELECT 1 FROM public.companies
    WHERE id = p_company_id AND user_id = auth.uid()
  ) INTO v_is_owner;

  IF v_is_owner THEN
    RETURN 'company';
  END IF;

  SELECT role INTO v_role
  FROM public.company_members
  WHERE user_id = auth.uid() AND company_id = p_company_id
  LIMIT 1;

  IF v_role IS NULL THEN
    RETURN 'none';
  END IF;

  -- v3.74.317: general_manager joins owner/admin at the company scope
  IF v_role IN ('owner', 'admin', 'general_manager') THEN
    RETURN 'company';
  END IF;

  SELECT can_access INTO v_can_access
  FROM public.company_role_permissions
  WHERE company_id = p_company_id
    AND role       = v_role
    AND resource   = p_resource
  LIMIT 1;

  IF v_can_access IS NOT TRUE THEN
    RETURN 'none';
  END IF;

  RETURN CASE
    WHEN v_role IN ('manager', 'accountant', 'supervisor', 'store_manager',
                    'manufacturing_officer', 'purchasing_officer', 'hr_officer')
      THEN 'branch'
    WHEN v_role = 'viewer' THEN 'company'
    ELSE 'own'
  END;
END;
$function$
;

-- ---------------------------------------------------------------
-- daily_billing_check()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.daily_billing_check()
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_now              timestamptz := NOW();
  v_reminders_7d     int := 0;
  v_reminders_3d     int := 0;
  v_reminders_1d     int := 0;
  v_marked_past_due  int := 0;
  v_suspended        int := 0;
  rec RECORD;
BEGIN
  -- (1) 7-day reminder
  FOR rec IN
    SELECT c.id, c.name, c.current_period_end
      FROM public.companies c
     WHERE c.subscription_status = 'active'
       AND c.current_period_end IS NOT NULL
       AND c.current_period_end BETWEEN v_now + interval '6 days' AND v_now + interval '8 days'
       AND c.reminder_7d_sent_at IS NULL
  LOOP
    PERFORM public.notify_company_billing_owner(
      rec.id,
      'اشتراكك سينتهى بعد ٧ أيام',
      'اشتراك شركة "' || rec.name || '" سينتهى فى ' || rec.current_period_end::date::text
      || '. جدّد الاشتراك من صفحة الفوترة لتجنّب توقف الخدمة.',
      'info', 'normal'
    );
    UPDATE public.companies SET reminder_7d_sent_at = v_now WHERE id = rec.id;
    v_reminders_7d := v_reminders_7d + 1;
  END LOOP;

  -- (2) 3-day reminder
  FOR rec IN
    SELECT c.id, c.name, c.current_period_end
      FROM public.companies c
     WHERE c.subscription_status = 'active'
       AND c.current_period_end IS NOT NULL
       AND c.current_period_end BETWEEN v_now + interval '2 days' AND v_now + interval '4 days'
       AND c.reminder_3d_sent_at IS NULL
  LOOP
    PERFORM public.notify_company_billing_owner(
      rec.id,
      'اشتراكك سينتهى بعد ٣ أيام',
      'باقى ٣ أيام على انتهاء اشتراك شركة "' || rec.name || '". '
      || 'إذا لم يتم التجديد ستدخل الشركة فى فترة سماح ثم يتم تعليقها.',
      'warning', 'high'
    );
    UPDATE public.companies SET reminder_3d_sent_at = v_now WHERE id = rec.id;
    v_reminders_3d := v_reminders_3d + 1;
  END LOOP;

  -- (3) 1-day reminder
  FOR rec IN
    SELECT c.id, c.name, c.current_period_end
      FROM public.companies c
     WHERE c.subscription_status = 'active'
       AND c.current_period_end IS NOT NULL
       AND c.current_period_end BETWEEN v_now AND v_now + interval '30 hours'
       AND c.reminder_1d_sent_at IS NULL
  LOOP
    PERFORM public.notify_company_billing_owner(
      rec.id,
      'اشتراكك سينتهى غداً',
      'اشتراك شركة "' || rec.name || '" سينتهى خلال ٢٤ ساعة. '
      || 'جدّد الآن لتجنّب دخول فترة السماح.',
      'error', 'high'
    );
    UPDATE public.companies SET reminder_1d_sent_at = v_now WHERE id = rec.id;
    v_reminders_1d := v_reminders_1d + 1;
  END LOOP;

  -- (4) Mark past_due
  FOR rec IN
    SELECT c.id, c.name, c.current_period_end
      FROM public.companies c
     WHERE c.subscription_status = 'active'
       AND c.current_period_end IS NOT NULL
       AND c.current_period_end < v_now
  LOOP
    UPDATE public.companies
       SET subscription_status = 'past_due',
           past_due_at         = v_now,
           reminder_7d_sent_at = NULL,
           reminder_3d_sent_at = NULL,
           reminder_1d_sent_at = NULL
     WHERE id = rec.id;
    PERFORM public.notify_company_billing_owner(
      rec.id,
      'اشتراكك انتهى — دخلت فترة السماح',
      'انتهى اشتراك شركة "' || rec.name || '" فى ' || rec.current_period_end::date::text
      || '. عندك فترة سماح للتجديد قبل تعليق الوصول.',
      'error', 'high'
    );
    v_marked_past_due := v_marked_past_due + 1;
  END LOOP;

  -- (5) Suspend after grace
  FOR rec IN
    SELECT c.id, c.name, c.past_due_at,
           COALESCE(sp.grace_period_days, 7) AS grace_days
      FROM public.companies c
      LEFT JOIN public.company_seats cs ON cs.company_id = c.id
      LEFT JOIN public.subscription_plans sp ON sp.id = cs.plan_id
     WHERE c.subscription_status = 'past_due'
       AND c.past_due_at IS NOT NULL
       AND c.past_due_at + (COALESCE(sp.grace_period_days, 7) || ' days')::interval < v_now
  LOOP
    PERFORM public.suspend_subscription(rec.id);
    PERFORM public.notify_company_billing_owner(
      rec.id,
      'تم تعليق الاشتراك',
      'تم تعليق اشتراك شركة "' || rec.name || '" بعد انتهاء فترة السماح. '
      || 'الوصول الآن للقراءة فقط. جدّد الاشتراك لاستعادة الوصول الكامل.',
      'error', 'high'
    );
    v_suspended := v_suspended + 1;
  END LOOP;

  RETURN json_build_object(
    'success', true,
    'ran_at', v_now,
    'reminders_7d', v_reminders_7d,
    'reminders_3d', v_reminders_3d,
    'reminders_1d', v_reminders_1d,
    'marked_past_due', v_marked_past_due,
    'suspended', v_suspended
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- deactivate_manufacturing_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_updated_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.deactivate_manufacturing_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_updated_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version RECORD;
BEGIN
  SELECT *
    INTO v_version
    FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing routing version not found or not in company. routing_version_id=%', p_routing_version_id;
  END IF;

  IF v_version.status NOT IN ('active', 'inactive') THEN
    RAISE EXCEPTION 'Only active or inactive routing versions can be deactivated. routing_version_id=%, status=%',
      p_routing_version_id, v_version.status;
  END IF;

  PERFORM 1
    FROM public.manufacturing_routing_versions
   WHERE routing_id = v_version.routing_id
   FOR UPDATE;

  UPDATE public.manufacturing_routing_versions
     SET status = 'inactive',
         updated_by = p_updated_by
   WHERE id = p_routing_version_id;

  RETURN jsonb_build_object(
    'success', true,
    'routing_version_id', p_routing_version_id,
    'previous_status', v_version.status,
    'status', 'inactive'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- decide_discount_approval(p_approval_id uuid, p_decision text, p_decision_note text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.decide_discount_approval(p_approval_id uuid, p_decision text, p_decision_note text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_approval public.discount_approvals;
BEGIN
  IF p_decision NOT IN ('approved', 'rejected') THEN
    RAISE EXCEPTION 'decision must be approved or rejected' USING ERRCODE = 'P0001';
  END IF;

  SELECT * INTO v_approval FROM public.discount_approvals WHERE id = p_approval_id FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Approval not found. approval_id=%', p_approval_id USING ERRCODE = 'P0001';
  END IF;

  IF NOT public.can_approve_discount(v_approval.company_id, auth.uid()) THEN
    RAISE EXCEPTION 'Not authorized to decide discount approvals' USING ERRCODE = 'P0001';
  END IF;

  IF v_approval.status <> 'pending' THEN
    RAISE EXCEPTION 'Approval already decided. Current status: %', v_approval.status USING ERRCODE = 'P0001';
  END IF;

  UPDATE public.discount_approvals SET
    status = p_decision::public.discount_approval_status,
    decided_by = auth.uid(),
    decided_at = NOW(),
    decision_note = p_decision_note
  WHERE id = p_approval_id;

  RETURN jsonb_build_object('success', true, 'approval_id', p_approval_id, 'status', p_decision, 'decided_at', NOW());
END;
$function$
;

-- ---------------------------------------------------------------
-- deduct_commission_advances_for_payroll(p_company_id uuid, p_employee_id uuid, p_payroll_run_id uuid, p_period_year integer, p_period_month integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.deduct_commission_advances_for_payroll(p_company_id uuid, p_employee_id uuid, p_payroll_run_id uuid, p_period_year integer, p_period_month integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_period_start DATE;
    v_period_end DATE;
    v_total_deducted DECIMAL(15,2) := 0;
    v_count INT := 0;
    v_already_deducted INT := 0;
BEGIN
    SET search_path = public, pg_temp;

    v_period_start := make_date(p_period_year, p_period_month, 1);
    v_period_end := (v_period_start + INTERVAL '1 month - 1 day')::DATE;

    -- التحقق من السلف المخصومة بالفعل
    SELECT COUNT(*) INTO v_already_deducted
    FROM commission_advance_payments
    WHERE company_id = p_company_id
    AND employee_id = p_employee_id
    AND payroll_run_id = p_payroll_run_id
    AND deducted_in_payroll = TRUE;

    IF v_already_deducted > 0 THEN
        RETURN jsonb_build_object(
            'success', TRUE,
            'message', 'السلف مخصومة بالفعل لهذا المرتب',
            'advances_deducted', 0,
            'total_deducted', 0,
            'already_deducted_count', v_already_deducted
        );
    END IF;

    WITH updated_advances AS (
        UPDATE commission_advance_payments
        SET deducted_in_payroll = TRUE,
            deducted_at = NOW(),
            payroll_run_id = p_payroll_run_id
        WHERE company_id = p_company_id
        AND employee_id = p_employee_id
        AND commission_period_start <= v_period_end
        AND commission_period_end >= v_period_start
        AND status = 'paid'
        AND deducted_in_payroll = FALSE
        RETURNING amount
    )
    SELECT COUNT(*), COALESCE(SUM(amount), 0)
    INTO v_count, v_total_deducted
    FROM updated_advances;

    RETURN jsonb_build_object(
        'success', TRUE,
        'advances_deducted', v_count,
        'total_deducted', v_total_deducted,
        'employee_id', p_employee_id,
        'payroll_run_id', p_payroll_run_id
    );
END;
$function$
;

-- ---------------------------------------------------------------
-- delete_duplicate_cogs_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.delete_duplicate_cogs_entries(p_company_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_deleted_count INTEGER := 0;
  v_duplicate RECORD;
BEGIN
  FOR v_duplicate IN
    SELECT reference_id, array_agg(id ORDER BY created_at) as entry_ids
    FROM journal_entries
    WHERE company_id = p_company_id AND reference_type = 'invoice_cogs'
    GROUP BY reference_id
    HAVING COUNT(*) > 1
  LOOP
    DELETE FROM journal_entry_lines
    WHERE journal_entry_id = ANY(v_duplicate.entry_ids[2:]);
    
    DELETE FROM journal_entries
    WHERE id = ANY(v_duplicate.entry_ids[2:]);
    
    v_deleted_count := v_deleted_count + array_length(v_duplicate.entry_ids, 1) - 1;
  END LOOP;

  RETURN v_deleted_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- delete_empty_journal_entries_safe(p_company_id uuid, p_limit integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.delete_empty_journal_entries_safe(p_company_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 100)
 RETURNS TABLE(deleted_count integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_deleted_count INTEGER := 0;
BEGIN
  -- حذف القيود الفارغة مع LIMIT
  WITH to_delete AS (
    SELECT je.id
    FROM journal_entries je
    WHERE (p_company_id IS NULL OR je.company_id = p_company_id)
      AND NOT EXISTS (
        SELECT 1 FROM journal_entry_lines jel 
        WHERE jel.journal_entry_id = je.id
      )
    LIMIT p_limit
  )
  DELETE FROM journal_entries
  WHERE id IN (SELECT id FROM to_delete);

  GET DIAGNOSTICS v_deleted_count = ROW_COUNT;

  RETURN QUERY SELECT v_deleted_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- delete_fixed_asset_completely(p_asset_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.delete_fixed_asset_completely(p_asset_id uuid)
 RETURNS TABLE(asset_name text, asset_code text, deleted_schedules integer, deleted_journals integer, deleted_lines integer, success boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_asset_id UUID;
  v_company_id UUID;
  v_asset_name TEXT;
  v_asset_code TEXT;
  v_deleted_schedules INTEGER := 0;
  v_deleted_journals INTEGER := 0;
  v_deleted_lines INTEGER := 0;
  v_journal_entry_ids UUID[];
  v_orphaned_journal_ids UUID[];
  v_orphaned_count INTEGER := 0;
BEGIN
  -- =====================================
  -- 1. العثور على الأصل
  -- =====================================
  SELECT fa.id, fa.company_id, fa.name, fa.asset_code
  INTO v_asset_id, v_company_id, v_asset_name, v_asset_code
  FROM fixed_assets fa
  WHERE fa.id = p_asset_id
  LIMIT 1;

  IF v_asset_id IS NULL THEN
    RAISE EXCEPTION 'Asset with ID % not found', p_asset_id;
  END IF;

  RAISE NOTICE '========================================';
  RAISE NOTICE 'Deleting Fixed Asset Completely';
  RAISE NOTICE 'حذف الأصل الثابت بالكامل';
  RAISE NOTICE '========================================';
  RAISE NOTICE 'Asset: % (Code: %, ID: %)', v_asset_name, v_asset_code, v_asset_id;
  RAISE NOTICE '';

  -- =====================================
  -- 2. جمع journal_entry_ids المرتبطة بالإهلاك
  -- =====================================
  SELECT ARRAY_AGG(DISTINCT ds.journal_entry_id)
  INTO v_journal_entry_ids
  FROM depreciation_schedules ds
  INNER JOIN journal_entries je ON ds.journal_entry_id = je.id
  WHERE ds.asset_id = v_asset_id
    AND ds.journal_entry_id IS NOT NULL
    AND je.reference_type = 'depreciation'
    AND je.reference_id = v_asset_id;

  -- جمع القيود المقطوعة (orphaned) للتنظيف
  SELECT ARRAY_AGG(DISTINCT ds.journal_entry_id), COUNT(DISTINCT ds.journal_entry_id)
  INTO v_orphaned_journal_ids, v_orphaned_count
  FROM depreciation_schedules ds
  LEFT JOIN journal_entries je ON ds.journal_entry_id = je.id
  WHERE ds.asset_id = v_asset_id
    AND ds.journal_entry_id IS NOT NULL
    AND (je.id IS NULL 
         OR je.reference_type != 'depreciation' 
         OR je.reference_id != v_asset_id);
  
  IF v_orphaned_count > 0 THEN
    RAISE WARNING '⚠ Found % orphaned journal entry references', v_orphaned_count;
  END IF;

  -- =====================================
  -- 3. حذف سطور القيود (journal_entry_lines)
  -- =====================================
  -- حذف سطور القيود للقيود التي تم التحقق منها
  IF v_journal_entry_ids IS NOT NULL AND array_length(v_journal_entry_ids, 1) > 0 THEN
    DELETE FROM journal_entry_lines
    WHERE journal_entry_id = ANY(v_journal_entry_ids);
    
    GET DIAGNOSTICS v_deleted_lines = ROW_COUNT;
    RAISE NOTICE '✓ Deleted % journal entry lines from verified depreciation entries', v_deleted_lines;
  END IF;

  -- حذف سطور القيود المقطوعة (orphaned) أيضاً
  IF v_orphaned_journal_ids IS NOT NULL AND array_length(v_orphaned_journal_ids, 1) > 0 THEN
    DECLARE
      v_orphaned_lines_deleted INTEGER;
    BEGIN
      DELETE FROM journal_entry_lines
      WHERE journal_entry_id = ANY(v_orphaned_journal_ids);
      
      GET DIAGNOSTICS v_orphaned_lines_deleted = ROW_COUNT;
      IF v_orphaned_lines_deleted > 0 THEN
        RAISE NOTICE '✓ Deleted % journal entry lines from orphaned entries', v_orphaned_lines_deleted;
        v_deleted_lines := v_deleted_lines + v_orphaned_lines_deleted;
      END IF;
    EXCEPTION
      WHEN OTHERS THEN
        RAISE WARNING '⚠ Error deleting orphaned journal entry lines: %', SQLERRM;
    END;
  END IF;

  -- =====================================
  -- 4. حذف القيود المحاسبية (journal_entries)
  -- =====================================
  IF v_journal_entry_ids IS NOT NULL AND array_length(v_journal_entry_ids, 1) > 0 THEN
    DELETE FROM journal_entries
    WHERE id = ANY(v_journal_entry_ids)
      AND reference_type = 'depreciation'
      AND reference_id = v_asset_id;
    
    GET DIAGNOSTICS v_deleted_journals = ROW_COUNT;
    RAISE NOTICE '✓ Deleted % verified depreciation journal entries', v_deleted_journals;
  END IF;

  -- =====================================
  -- 5. حذف جميع جداول الإهلاك
  -- =====================================
  DELETE FROM depreciation_schedules
  WHERE asset_id = v_asset_id;
  
  GET DIAGNOSTICS v_deleted_schedules = ROW_COUNT;
  RAISE NOTICE '✓ Deleted % depreciation schedules', v_deleted_schedules;

  -- =====================================
  -- 6. حذف الأصل نفسه
  -- =====================================
  DELETE FROM fixed_assets
  WHERE id = v_asset_id;

  RAISE NOTICE '✓ Deleted fixed asset: % (%)', v_asset_name, v_asset_code;

  -- =====================================
  -- 7. ملخص العملية
  -- =====================================
  RAISE NOTICE '';
  RAISE NOTICE '========================================';
  RAISE NOTICE 'Summary - ملخص العملية';
  RAISE NOTICE '========================================';
  RAISE NOTICE 'Asset: % (%)', v_asset_name, v_asset_code;
  RAISE NOTICE 'Deleted Depreciation Schedules: %', v_deleted_schedules;
  RAISE NOTICE 'Deleted Journal Entries: %', v_deleted_journals;
  RAISE NOTICE 'Deleted Journal Entry Lines: %', v_deleted_lines;
  RAISE NOTICE 'Deleted Fixed Asset: YES';
  RAISE NOTICE '========================================';
  RAISE NOTICE '';
  RAISE NOTICE '✓ Asset deleted completely!';

  -- Return results
  RETURN QUERY SELECT 
    v_asset_name,
    v_asset_code,
    v_deleted_schedules,
    v_deleted_journals,
    v_deleted_lines,
    TRUE as success;

EXCEPTION
  WHEN OTHERS THEN
    RAISE EXCEPTION 'Error deleting fixed asset: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- discount_approval_archive_notifications_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.discount_approval_archive_notifications_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Only fire on a real status transition.
  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  -- Only archive when leaving pending. New pending rows shouldn't
  -- archive anything (they were freshly inserted).
  IF OLD.status <> 'pending' THEN RETURN NEW; END IF;
  IF NEW.status NOT IN ('approved', 'rejected', 'cancelled') THEN RETURN NEW; END IF;

  UPDATE public.notifications
     SET status  = 'archived',
         read_at = COALESCE(read_at, NOW())
   WHERE reference_type = 'approval_request'
     AND reference_id   = NEW.id
     AND status         = 'unread';

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- discount_approval_cascade_notifications_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.discount_approval_cascade_notifications_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  DELETE FROM public.notifications
   WHERE reference_type = 'approval_request' AND reference_id = OLD.id;
  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- discount_approvals_touch_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.discount_approvals_touch_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- dispose_asset(p_asset_id uuid, p_disposal_date date, p_disposal_amount numeric, p_disposal_reason text, p_deposit_account_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.dispose_asset(p_asset_id uuid, p_disposal_date date, p_disposal_amount numeric, p_disposal_reason text, p_deposit_account_id uuid, p_user_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_asset RECORD;
  v_state JSONB;
  v_current_book_value DECIMAL;
  v_gain_loss DECIMAL;
  v_journal_id UUID;
  v_transaction_id UUID;
  v_company_id UUID;
  v_asset_account_id UUID;
  v_gain_loss_account_id UUID;
  v_base_ccy TEXT;
  v_role TEXT;
BEGIN
  SELECT * INTO v_asset FROM public.fixed_assets WHERE id = p_asset_id;
  IF v_asset IS NULL THEN RAISE EXCEPTION 'Asset not found'; END IF;
  IF v_asset.status = 'disposed' THEN RAISE EXCEPTION 'Asset already disposed'; END IF;

  v_company_id       := v_asset.company_id;
  v_asset_account_id := v_asset.asset_account_id;

  -- v3.74.565 — SoD
  SELECT role INTO v_role FROM company_members
   WHERE company_id = v_company_id AND user_id = p_user_id LIMIT 1;
  IF NOT (COALESCE(v_role,'') IN ('owner','general_manager','admin')) THEN
    IF v_asset.created_by = p_user_id THEN
      RAISE EXCEPTION 'SOD_VIOLATION: منشِئ الأصل لا يستطيع تسجيل التصرف — يحتاج مالك/مدير عام';
    END IF;
  END IF;

  -- v3.74.565 — period lock
  BEGIN
    PERFORM public.require_open_financial_period_db(v_company_id, p_disposal_date);
  EXCEPTION WHEN undefined_function THEN NULL; END;

  v_state := get_asset_current_state(p_asset_id);
  v_current_book_value := (v_state->>'book_value')::DECIMAL;
  v_gain_loss := p_disposal_amount - v_current_book_value;

  -- Gain/Loss account
  SELECT id INTO v_gain_loss_account_id FROM public.chart_of_accounts
   WHERE company_id = v_company_id
     AND (account_name ILIKE '%Gain%' OR account_name ILIKE '%Loss%' OR account_name ILIKE '%Disposal%'
          OR account_name ILIKE '%أرباح%بيع%' OR account_name ILIKE '%خسائر%بيع%' OR account_name ILIKE '%التصرف%')
   LIMIT 1;
  IF v_gain_loss_account_id IS NULL THEN
    SELECT id INTO v_gain_loss_account_id FROM public.chart_of_accounts
     WHERE company_id = v_company_id AND account_type = 'income' LIMIT 1;
    IF v_gain_loss_account_id IS NULL THEN
      SELECT id INTO v_gain_loss_account_id FROM public.chart_of_accounts
       WHERE company_id = v_company_id AND account_type = 'expense' LIMIT 1;
    END IF;
  END IF;

  SELECT base_currency INTO v_base_ccy FROM companies WHERE id = v_company_id;
  v_base_ccy := UPPER(COALESCE(v_base_ccy, 'EGP'));

  INSERT INTO public.journal_entries (
    company_id, branch_id, cost_center_id,
    entry_date, description, reference_type, reference_id,
    status
  ) VALUES (
    v_company_id, v_asset.branch_id, v_asset.cost_center_id,
    p_disposal_date,
    'تصرف فى أصل: ' || v_asset.name || ' — ' || COALESCE(p_disposal_reason, ''),
    'asset_disposal', p_asset_id,
    'draft'
  ) RETURNING id INTO v_journal_id;

  -- v3.74.565 — write IAS 21 columns
  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description,
    debit_amount, credit_amount,
    original_debit, original_credit, original_currency,
    exchange_rate_used, branch_id, cost_center_id
  )
  SELECT
    v_journal_id, p_deposit_account_id, 'متحصلات التصرف',
    p_disposal_amount, 0,
    p_disposal_amount, 0, v_base_ccy,
    1, v_asset.branch_id, v_asset.cost_center_id
  WHERE p_disposal_amount > 0
  UNION ALL
  SELECT
    v_journal_id, v_asset_account_id, 'استبعاد القيمة الدفترية',
    0, v_current_book_value,
    0, v_current_book_value, v_base_ccy,
    1, v_asset.branch_id, v_asset.cost_center_id
  UNION ALL
  SELECT
    v_journal_id, v_gain_loss_account_id, 'ربح تصرف',
    0, v_gain_loss,
    0, v_gain_loss, v_base_ccy,
    1, v_asset.branch_id, v_asset.cost_center_id
  WHERE v_gain_loss > 0
  UNION ALL
  SELECT
    v_journal_id, v_gain_loss_account_id, 'خسارة تصرف',
    ABS(v_gain_loss), 0,
    ABS(v_gain_loss), 0, v_base_ccy,
    1, v_asset.branch_id, v_asset.cost_center_id
  WHERE v_gain_loss < 0;

  UPDATE public.journal_entries
     SET status = 'posted', posted_by = p_user_id, posted_at = NOW()
   WHERE id = v_journal_id;

  INSERT INTO public.asset_transactions (
    company_id, asset_id, transaction_type, transaction_date, amount, reference_id, details, created_by
  ) VALUES (
    v_company_id, p_asset_id, 'disposal', p_disposal_date,
    -v_current_book_value, v_journal_id,
    jsonb_build_object(
      'disposal_amount', p_disposal_amount,
      'gain_loss', v_gain_loss,
      'book_value_at_disposal', v_current_book_value,
      'disposal_reason', p_disposal_reason
    ),
    p_user_id
  ) RETURNING id INTO v_transaction_id;

  -- v3.74.565 — persist the disposal metadata on the asset
  UPDATE public.fixed_assets
     SET status              = 'disposed',
         disposal_date       = p_disposal_date,
         disposal_amount     = p_disposal_amount,
         disposal_reason     = p_disposal_reason,
         disposal_journal_id = v_journal_id,
         book_value          = 0,
         updated_at          = NOW(),
         updated_by          = p_user_id
   WHERE id = p_asset_id;

  DELETE FROM public.depreciation_schedules
   WHERE asset_id = p_asset_id AND status = 'pending';

  RETURN v_transaction_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- distribute_dividends_atomic(p_company_id uuid, p_total_amount numeric, p_distribution_date date, p_shareholders jsonb, p_retained_earnings_account_id uuid, p_dividends_payable_account_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_fiscal_year integer, p_fiscal_period text, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.distribute_dividends_atomic(p_company_id uuid, p_total_amount numeric, p_distribution_date date, p_shareholders jsonb, p_retained_earnings_account_id uuid, p_dividends_payable_account_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_fiscal_year integer DEFAULT NULL::integer, p_fiscal_period text DEFAULT NULL::text, p_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_distribution_id UUID;
  v_journal_entry_id UUID;
  v_shareholder JSONB;
  v_available_retained_earnings DECIMAL;
BEGIN
  -- 1. Check retained earnings sufficiency
  v_available_retained_earnings := get_retained_earnings_balance(p_company_id);
  
  IF v_available_retained_earnings < p_total_amount THEN
    RAISE EXCEPTION 'Insufficient retained earnings. Available: %, Requested: %', 
      v_available_retained_earnings, p_total_amount;
  END IF;

  -- 2. Create distribution header
  INSERT INTO profit_distributions (
    company_id, distribution_date, total_profit, status,
    fiscal_year, fiscal_period, available_retained_earnings,
    branch_id, cost_center_id, approved_by, approved_at
  ) VALUES (
    p_company_id, p_distribution_date, p_total_amount, 'approved',
    p_fiscal_year, p_fiscal_period, v_available_retained_earnings,
    p_branch_id, p_cost_center_id, p_user_id, NOW()
  ) RETURNING id INTO v_distribution_id;

  -- 3. Create distribution lines for each shareholder
  FOR v_shareholder IN SELECT * FROM jsonb_array_elements(p_shareholders)
  LOOP
    INSERT INTO profit_distribution_lines (
      distribution_id, shareholder_id, percentage_at_distribution, amount, status, paid_amount
    ) VALUES (
      v_distribution_id,
      (v_shareholder->>'id')::UUID,
      (v_shareholder->>'percentage')::DECIMAL,
      (v_shareholder->>'amount')::DECIMAL,
      'pending',
      0
    );
  END LOOP;

  -- 4. Create journal entry
  INSERT INTO journal_entries (
    company_id, reference_type, reference_id, entry_date, description,
    branch_id, cost_center_id, status
  ) VALUES (
    p_company_id, 'profit_distribution', v_distribution_id, p_distribution_date,
    'توزيع أرباح - ' || p_total_amount::TEXT || ' - Dividend Declaration',
    p_branch_id, p_cost_center_id, 'posted'
  ) RETURNING id INTO v_journal_entry_id;

  -- 5. Create journal entry lines (Dr. Retained Earnings | Cr. Dividends Payable)
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
  VALUES
    (v_journal_entry_id, p_retained_earnings_account_id, p_total_amount, 0, 'من حـ/ الأرباح المحتجزة'),
    (v_journal_entry_id, p_dividends_payable_account_id, 0, p_total_amount, 'إلى حـ/ الأرباح الموزعة المستحقة');

  -- 6. Update distribution with journal entry link
  UPDATE profit_distributions SET journal_entry_id = v_journal_entry_id WHERE id = v_distribution_id;

  RETURN jsonb_build_object(
    'success', true,
    'distribution_id', v_distribution_id,
    'journal_entry_id', v_journal_entry_id,
    'available_retained_earnings', v_available_retained_earnings
  );

EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'Dividend distribution failed: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- emit_system_event_manual(p_company_id uuid, p_event_type character varying, p_reference_type character varying, p_reference_id uuid, p_user_id uuid, p_payload jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.emit_system_event_manual(p_company_id uuid, p_event_type character varying, p_reference_type character varying, p_reference_id uuid, p_user_id uuid DEFAULT NULL::uuid, p_payload jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_event_id UUID;
    v_event_key VARCHAR;
BEGIN
    -- unique enough for manual triggers
    v_event_key := p_reference_type || '.' || p_event_type || '.' || p_reference_id::text || '.' || extract(epoch from now())::int::text;
    
    INSERT INTO system_events (
        company_id, event_type, reference_type, reference_id, payload, user_id, event_key
    ) VALUES (
        p_company_id, p_event_type, p_reference_type, p_reference_id, p_payload, p_user_id, v_event_key
    ) RETURNING id INTO v_event_id;
    
    RETURN v_event_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- employee_branch_from_member_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.employee_branch_from_member_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_branch uuid;
begin
  if new.user_id is not null then
    select branch_id into v_branch
      from public.company_members
     where company_id = new.company_id and user_id = new.user_id
     limit 1;
    if found and v_branch is not null then
      new.branch_id := v_branch;
    end if;
  end if;
  return new;
end;
$function$
;

-- ---------------------------------------------------------------
-- enforce_branch_isolation()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_branch_isolation()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    IF auth.uid() IS NOT NULL THEN
        IF NOT public.is_branch_accessible(NEW.branch_id, auth.uid()) THEN
            RAISE EXCEPTION 'Access Denied: You cannot create or modify records for a branch you do not have permissions for.';
        END IF;
    END IF;
    RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- enforce_governance_on_insert()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_governance_on_insert()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_status TEXT;
  v_new_status TEXT;
  v_old_receipt_status TEXT;
  v_is_closed BOOLEAN;
  v_content_changed BOOLEAN;
  v_creator UUID;
  v_editor UUID;
  v_editor_name TEXT;
  v_editor_email TEXT;
  v_editor_display TEXT;
  v_change_summary TEXT;
  v_notice_owner TEXT;
  v_notice_gm TEXT;
BEGIN
  IF NEW.company_id IS NULL THEN
    RAISE EXCEPTION 'company_id cannot be NULL - ERP governance violation';
  END IF;
  IF TG_TABLE_NAME IN ('invoices','bills','sales_orders','purchase_orders','inventory_transactions','suppliers','customers') THEN
    IF NEW.branch_id IS NULL THEN RAISE EXCEPTION 'branch_id cannot be NULL for % - ERP governance violation', TG_TABLE_NAME; END IF;
  END IF;
  IF TG_TABLE_NAME IN ('invoices','bills','sales_orders','purchase_orders','inventory_transactions','suppliers','customers') THEN
    IF NEW.cost_center_id IS NULL THEN RAISE EXCEPTION 'cost_center_id cannot be NULL for % - ERP governance violation', TG_TABLE_NAME; END IF;
  END IF;
  IF TG_TABLE_NAME IN ('invoices','bills','sales_orders','purchase_orders','inventory_transactions') THEN
    IF NEW.warehouse_id IS NULL THEN RAISE EXCEPTION 'warehouse_id cannot be NULL for % - ERP governance violation', TG_TABLE_NAME; END IF;
  END IF;

  IF TG_TABLE_NAME = 'bills' AND TG_OP = 'UPDATE' THEN
    v_old_status := lower(coalesce(OLD.status, ''));
    v_new_status := lower(coalesce(NEW.status, ''));
    v_old_receipt_status := lower(coalesce(OLD.receipt_status, ''));
    v_is_closed := v_old_status IN ('paid','partially_paid','cancelled','voided','fully_returned');

    v_content_changed :=
      OLD.supplier_id        IS DISTINCT FROM NEW.supplier_id        OR
      OLD.bill_date          IS DISTINCT FROM NEW.bill_date          OR
      OLD.due_date           IS DISTINCT FROM NEW.due_date           OR
      OLD.subtotal           IS DISTINCT FROM NEW.subtotal           OR
      OLD.tax_amount         IS DISTINCT FROM NEW.tax_amount         OR
      OLD.total_amount       IS DISTINCT FROM NEW.total_amount       OR
      OLD.discount_type      IS DISTINCT FROM NEW.discount_type      OR
      OLD.discount_value     IS DISTINCT FROM NEW.discount_value     OR
      OLD.discount_position  IS DISTINCT FROM NEW.discount_position  OR
      OLD.tax_inclusive      IS DISTINCT FROM NEW.tax_inclusive      OR
      OLD.shipping           IS DISTINCT FROM NEW.shipping           OR
      OLD.shipping_tax_rate  IS DISTINCT FROM NEW.shipping_tax_rate  OR
      OLD.adjustment         IS DISTINCT FROM NEW.adjustment         OR
      OLD.branch_id          IS DISTINCT FROM NEW.branch_id          OR
      OLD.warehouse_id       IS DISTINCT FROM NEW.warehouse_id       OR
      OLD.cost_center_id     IS DISTINCT FROM NEW.cost_center_id;

    IF v_content_changed AND NOT v_is_closed
       AND (v_old_status <> 'draft' OR v_old_receipt_status = 'rejected') THEN
      NEW.status := 'pending_approval';
      NEW.approval_status := 'pending_approval';
      NEW.approved_by := NULL;
      NEW.approved_at := NULL;
      NEW.receipt_status := NULL;
      NEW.receipt_rejection_reason := NULL;

      v_creator := COALESCE(NEW.created_by_user_id, OLD.created_by_user_id);
      IF v_creator IS NULL THEN
        SELECT cm.user_id INTO v_creator FROM company_members cm
         WHERE cm.company_id = NEW.company_id AND cm.role IN ('owner','admin') LIMIT 1;
      END IF;
      IF v_creator IS NULL THEN
        RAISE EXCEPTION 'No creator user found for bill % in company % - cannot create governance notifications', NEW.id, NEW.company_id;
      END IF;

      -- v3.74.462 — resolve editor display name
      v_editor := COALESCE(NEW.last_edited_by_user_id, v_creator);
      BEGIN
        SELECT full_name INTO v_editor_name FROM public.employees WHERE user_id = v_editor LIMIT 1;
      EXCEPTION WHEN OTHERS THEN v_editor_name := NULL; END;
      BEGIN
        SELECT email INTO v_editor_email FROM auth.users WHERE id = v_editor LIMIT 1;
      EXCEPTION WHEN OTHERS THEN v_editor_email := NULL; END;
      v_editor_display := COALESCE(NULLIF(v_editor_name,''), NULLIF(v_editor_email,''), substr(v_editor::text,1,8));

      -- v3.74.462 — short change summary
      v_change_summary := '';
      IF OLD.total_amount IS DISTINCT FROM NEW.total_amount THEN
        v_change_summary := v_change_summary || format(' الإجمالى %s → %s،',
          to_char(COALESCE(OLD.total_amount,0),'FM999999990.00'),
          to_char(COALESCE(NEW.total_amount,0),'FM999999990.00'));
      END IF;
      IF OLD.shipping IS DISTINCT FROM NEW.shipping THEN
        v_change_summary := v_change_summary || format(' الشحن %s → %s،',
          to_char(COALESCE(OLD.shipping,0),'FM999999990.00'),
          to_char(COALESCE(NEW.shipping,0),'FM999999990.00'));
      END IF;
      IF OLD.discount_value IS DISTINCT FROM NEW.discount_value OR OLD.discount_type IS DISTINCT FROM NEW.discount_type THEN
        v_change_summary := v_change_summary || ' الخصم اتغيّر،';
      END IF;
      IF OLD.tax_inclusive IS DISTINCT FROM NEW.tax_inclusive THEN
        v_change_summary := v_change_summary || ' شاملة الضريبة اتغيّرت،';
      END IF;
      IF OLD.discount_position IS DISTINCT FROM NEW.discount_position THEN
        v_change_summary := v_change_summary || ' موضع الخصم اتغيّر،';
      END IF;
      v_change_summary := rtrim(v_change_summary, '،');

      v_notice_owner := format(
        'قام %s بتعديل فاتورة مشتريات رقم %s وتحتاج إلى إعادة اعتماد إداري.%s',
        v_editor_display, NEW.bill_number,
        CASE WHEN v_change_summary <> '' THEN E'\nالتغييرات:' || v_change_summary ELSE '' END
      );
      v_notice_gm := v_notice_owner;

      PERFORM create_notification(
        NEW.company_id, 'bill', NEW.id,
        'فاتورة مشتريات بانتظار الاعتماد الإداري',
        v_notice_owner,
        v_creator, NEW.branch_id, NEW.cost_center_id, NEW.warehouse_id,
        'owner', NULL, 'high',
        format('bill:%s:pending_approval_owner_after_edit', NEW.id),
        'warning', 'approvals'
      );
      PERFORM create_notification(
        NEW.company_id, 'bill', NEW.id,
        'فاتورة مشتريات بانتظار الاعتماد الإداري',
        v_notice_gm,
        v_creator, NEW.branch_id, NEW.cost_center_id, NEW.warehouse_id,
        'general_manager', NULL, 'high',
        format('bill:%s:pending_approval_gm_after_edit', NEW.id),
        'warning', 'approvals'
      );
    END IF;

    IF v_new_status = 'voided' AND v_old_status <> 'voided' THEN
      NEW.approval_status := NULL;
      NEW.approved_by := NULL;
      NEW.approved_at := NULL;
      NEW.receipt_status := NULL;
      NEW.receipt_rejection_reason := NULL;
    END IF;
  END IF;

  -- v3.74.462 — sales invoice mirror
  IF TG_TABLE_NAME = 'invoices' AND TG_OP = 'UPDATE' THEN
    v_old_status := lower(coalesce(OLD.status, ''));
    v_new_status := lower(coalesce(NEW.status, ''));
    v_is_closed := v_old_status IN ('paid','partially_paid','cancelled','voided','fully_returned');

    v_content_changed :=
      OLD.customer_id        IS DISTINCT FROM NEW.customer_id        OR
      OLD.subtotal           IS DISTINCT FROM NEW.subtotal           OR
      OLD.tax_amount         IS DISTINCT FROM NEW.tax_amount         OR
      OLD.total_amount       IS DISTINCT FROM NEW.total_amount       OR
      OLD.discount_type      IS DISTINCT FROM NEW.discount_type      OR
      OLD.discount_value     IS DISTINCT FROM NEW.discount_value     OR
      OLD.discount_position  IS DISTINCT FROM NEW.discount_position  OR
      OLD.tax_inclusive      IS DISTINCT FROM NEW.tax_inclusive      OR
      OLD.shipping           IS DISTINCT FROM NEW.shipping           OR
      OLD.shipping_tax_rate  IS DISTINCT FROM NEW.shipping_tax_rate  OR
      OLD.adjustment         IS DISTINCT FROM NEW.adjustment         OR
      OLD.branch_id          IS DISTINCT FROM NEW.branch_id          OR
      OLD.warehouse_id       IS DISTINCT FROM NEW.warehouse_id       OR
      OLD.cost_center_id     IS DISTINCT FROM NEW.cost_center_id;

    IF v_content_changed AND NOT v_is_closed
       AND v_old_status <> 'draft' THEN
      NEW.status := 'pending_approval';

      v_creator := COALESCE(NEW.created_by_user_id, OLD.created_by_user_id);
      IF v_creator IS NULL THEN
        SELECT cm.user_id INTO v_creator FROM company_members cm
         WHERE cm.company_id = NEW.company_id AND cm.role IN ('owner','admin') LIMIT 1;
      END IF;

      v_editor := COALESCE(NEW.last_edited_by_user_id, v_creator);
      BEGIN
        SELECT full_name INTO v_editor_name FROM public.employees WHERE user_id = v_editor LIMIT 1;
      EXCEPTION WHEN OTHERS THEN v_editor_name := NULL; END;
      BEGIN
        SELECT email INTO v_editor_email FROM auth.users WHERE id = v_editor LIMIT 1;
      EXCEPTION WHEN OTHERS THEN v_editor_email := NULL; END;
      v_editor_display := COALESCE(NULLIF(v_editor_name,''), NULLIF(v_editor_email,''), substr(v_editor::text,1,8));

      v_change_summary := '';
      IF OLD.total_amount IS DISTINCT FROM NEW.total_amount THEN
        v_change_summary := v_change_summary || format(' الإجمالى %s → %s،',
          to_char(COALESCE(OLD.total_amount,0),'FM999999990.00'),
          to_char(COALESCE(NEW.total_amount,0),'FM999999990.00'));
      END IF;
      IF OLD.shipping IS DISTINCT FROM NEW.shipping THEN
        v_change_summary := v_change_summary || format(' الشحن %s → %s،',
          to_char(COALESCE(OLD.shipping,0),'FM999999990.00'),
          to_char(COALESCE(NEW.shipping,0),'FM999999990.00'));
      END IF;
      IF OLD.discount_value IS DISTINCT FROM NEW.discount_value OR OLD.discount_type IS DISTINCT FROM NEW.discount_type THEN
        v_change_summary := v_change_summary || ' الخصم اتغيّر،';
      END IF;
      v_change_summary := rtrim(v_change_summary, '،');

      v_notice_owner := format(
        'قام %s بتعديل فاتورة مبيعات رقم %s وتحتاج إلى إعادة اعتماد إداري.%s',
        v_editor_display, NEW.invoice_number,
        CASE WHEN v_change_summary <> '' THEN E'\nالتغييرات:' || v_change_summary ELSE '' END
      );

      IF v_creator IS NOT NULL THEN
        PERFORM create_notification(
          NEW.company_id, 'invoice', NEW.id,
          'فاتورة مبيعات بانتظار الاعتماد الإداري',
          v_notice_owner,
          v_creator, NEW.branch_id, NEW.cost_center_id, NEW.warehouse_id,
          'owner', NULL, 'high',
          format('invoice:%s:pending_approval_owner_after_edit', NEW.id),
          'warning', 'approvals'
        );
        PERFORM create_notification(
          NEW.company_id, 'invoice', NEW.id,
          'فاتورة مبيعات بانتظار الاعتماد الإداري',
          v_notice_owner,
          v_creator, NEW.branch_id, NEW.cost_center_id, NEW.warehouse_id,
          'general_manager', NULL, 'high',
          format('invoice:%s:pending_approval_gm_after_edit', NEW.id),
          'warning', 'approvals'
        );
      END IF;
    END IF;

    IF v_new_status = 'voided' AND v_old_status <> 'voided' THEN
      NEW.approval_status := NULL;
      NEW.approved_by := NULL;
      NEW.approved_at := NULL;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- enforce_je_has_lines_on_post()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_je_has_lines_on_post()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status = 'posted' AND (OLD.status IS DISTINCT FROM 'posted') THEN
    IF NOT EXISTS (SELECT 1 FROM journal_entry_lines WHERE journal_entry_id = NEW.id) THEN
      RAISE EXCEPTION 'EMPTY_JE: Cannot post journal entry % with no lines', NEW.id;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- enforce_je_integrity()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_je_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_is_trusted_caller BOOLEAN;
BEGIN
  v_is_trusted_caller := (
    current_setting('app.allow_direct_post', true) IS NOT DISTINCT FROM 'true'
    AND current_user IN (SELECT rolname FROM pg_roles WHERE rolsuper=true OR rolname='postgres')
  );

  IF TG_OP = 'INSERT' AND NEW.status = 'posted' THEN
    IF v_is_trusted_caller IS NOT TRUE THEN
      BEGIN INSERT INTO financial_operation_log(company_id,operation,status,error_code,error_msg,payload)
        VALUES(NEW.company_id,'direct_post_attempt','blocked','DIRECT_POST_BLOCKED',
          'Blocked direct INSERT as posted by: '||current_user,
          jsonb_build_object('ref_type',NEW.reference_type,'ref_id',NEW.reference_id::TEXT,'caller',current_user));
      EXCEPTION WHEN OTHERS THEN NULL; END;
      RAISE EXCEPTION 'DIRECT_POST_BLOCKED: Use create_journal_entry_atomic(). [caller=%, flag=%]',
        current_user, COALESCE(current_setting('app.allow_direct_post',true),'null')
        USING HINT = 'Call create_journal_entry_atomic() or process_invoice_payment_atomic()';
    END IF;
  END IF;

  IF TG_OP = 'UPDATE' AND NEW.status = 'posted' AND OLD.status != 'posted' THEN
    IF v_is_trusted_caller IS NOT TRUE THEN
      IF NOT EXISTS (SELECT 1 FROM journal_entry_lines WHERE journal_entry_id = NEW.id) THEN
        BEGIN INSERT INTO financial_operation_log(company_id,operation,status,error_code,error_msg,payload)
          VALUES(NEW.company_id,'post_empty_je','blocked','EMPTY_JE_POST_BLOCKED',
            'Blocked posting JE with no lines',
            jsonb_build_object('je_id',NEW.id,'caller',current_user));
        EXCEPTION WHEN OTHERS THEN NULL; END;
        RAISE EXCEPTION 'EMPTY_JE: Cannot post journal entry % with no lines [caller=%]', NEW.id, current_user;
      END IF;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- enforce_journal_entry_balance()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_journal_entry_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_id    UUID;
  v_status      TEXT;
  v_total_debit NUMERIC(20, 6);
  v_total_credit NUMERIC(20, 6);
  v_line_count  INT;
  v_diff        NUMERIC(20, 6);
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_entry_id := OLD.journal_entry_id;
  ELSE
    v_entry_id := NEW.journal_entry_id;
  END IF;

  SELECT status INTO v_status FROM public.journal_entries WHERE id = v_entry_id;

  IF v_status IS DISTINCT FROM 'posted' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  SELECT
    COALESCE(SUM(debit_amount),  0),
    COALESCE(SUM(credit_amount), 0),
    COUNT(*)
    INTO v_total_debit, v_total_credit, v_line_count
    FROM public.journal_entry_lines
   WHERE journal_entry_id = v_entry_id;

  v_diff := ABS(v_total_debit - v_total_credit);

  IF v_diff > 0.01 THEN
    RAISE EXCEPTION 'ACCOUNTING_BALANCE_VIOLATION: Journal entry [%] debit=% credit=% diff=%',
      v_entry_id, ROUND(v_total_debit::NUMERIC,4), ROUND(v_total_credit::NUMERIC,4), ROUND(v_diff::NUMERIC,4);
  END IF;

  IF v_line_count < 2 THEN
    RAISE EXCEPTION 'ACCOUNTING_LINES_VIOLATION: Journal entry [%] has only % line(s).', v_entry_id, v_line_count;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- enforce_period_lock_header()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_period_lock_header()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry_date DATE;
  v_is_closing BOOLEAN;
  v_company_id UUID;
  v_fiscal_locked BOOLEAN;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_entry_date := OLD.entry_date;
    v_is_closing := OLD.is_closing_entry;
    v_company_id := OLD.company_id;
  ELSE
    v_entry_date := NEW.entry_date;
    v_is_closing := NEW.is_closing_entry;
    v_company_id := NEW.company_id;
  END IF;

  IF v_is_closing THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  -- التحقق من fiscal_periods (سنة/شهر)
  SELECT public.check_fiscal_period_locked(v_company_id, v_entry_date) INTO v_fiscal_locked;
  IF v_fiscal_locked THEN
    RAISE EXCEPTION 'Action blocked: Fiscal period %-% is CLOSED or LOCKED.', EXTRACT(YEAR FROM v_entry_date), EXTRACT(MONTH FROM v_entry_date);
  END IF;

  -- التحقق من accounting_periods (إن وُجدت)
  IF EXISTS (
    SELECT 1 FROM accounting_periods
    WHERE company_id = v_company_id
      AND v_entry_date BETWEEN period_start AND period_end
      AND (is_locked = TRUE OR status = 'closed')
  ) THEN
    RAISE EXCEPTION 'Action blocked: This accounting period is CLOSED or LOCKED. Date: %', v_entry_date;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- enforce_period_lock_lines()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_period_lock_lines()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_je_id UUID;
  v_period_locked BOOLEAN;
BEGIN
  v_je_id := CASE WHEN TG_OP = 'DELETE' THEN OLD.journal_entry_id ELSE NEW.journal_entry_id END;

  IF EXISTS (
    SELECT 1 
    FROM journal_entries je
    JOIN accounting_periods ap ON je.company_id = ap.company_id 
      AND je.entry_date BETWEEN ap.period_start AND ap.period_end
    WHERE je.id = v_je_id
      AND (ap.is_locked = TRUE OR ap.status = 'closed')
      AND je.is_closing_entry = FALSE
  ) THEN
      RAISE EXCEPTION 'Action blocked: Cannot modify lines of a Journal Entry in a CLOSED period.';
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- enforce_posted_entry_lines_no_edit()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_posted_entry_lines_no_edit()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_status TEXT;
  v_je_id UUID;
BEGIN
  v_je_id := CASE WHEN TG_OP = 'DELETE' THEN OLD.journal_entry_id ELSE NEW.journal_entry_id END;
  SELECT status INTO v_status FROM journal_entries WHERE id = v_je_id;

  IF v_status = 'posted' THEN
    -- ALLOW modifications if the application explicitly enables direct posting (e.g. within an RPC)
    IF current_setting('app.allow_direct_post', true) = 'true' THEN
      RETURN COALESCE(NEW, OLD);
    END IF;

    IF TG_OP = 'DELETE' THEN
      RAISE EXCEPTION 'Cannot modify lines of a posted journal entry. Use Reversal instead.';
    END IF;
    IF TG_OP = 'UPDATE' THEN
      RAISE EXCEPTION 'Cannot modify lines of a posted journal entry. Use Reversal instead.';
    END IF;
    IF TG_OP = 'INSERT' THEN
      RAISE EXCEPTION 'Cannot add lines to a posted journal entry. Use Reversal instead.';
    END IF;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- enforce_posted_entry_no_edit()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enforce_posted_entry_no_edit()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    IF OLD.status = 'posted' THEN
      IF coalesce(current_setting('app.allow_direct_post', true), '') = 'true' THEN
        RETURN OLD;
      END IF;
      RAISE EXCEPTION 'Cannot DELETE a posted journal entry. Use Reversal (create reversal entry) instead. Entry id: %', OLD.id;
    END IF;
    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF OLD.status = 'posted' THEN
      IF coalesce(current_setting('app.allow_direct_post', true), '') = 'true' THEN
        RETURN NEW;
      END IF;

      IF OLD.entry_date IS DISTINCT FROM NEW.entry_date
         OR OLD.description IS DISTINCT FROM NEW.description
         OR OLD.reference_type IS DISTINCT FROM NEW.reference_type
         OR OLD.reference_id IS DISTINCT FROM NEW.reference_id
         OR OLD.warehouse_id IS DISTINCT FROM NEW.warehouse_id
         OR OLD.status IS DISTINCT FROM NEW.status
      THEN
        RAISE EXCEPTION 'Cannot UPDATE a posted journal entry. Use Reversal (create reversal entry) instead. Entry id: %', OLD.id;
      END IF;

      IF OLD.branch_id IS DISTINCT FROM NEW.branch_id THEN
        IF OLD.branch_id IS NOT NULL OR NEW.branch_id IS NULL THEN
          RAISE EXCEPTION 'Cannot UPDATE a posted journal entry metadata fields (branch_id). Use Reversal instead. Entry id: %', OLD.id;
        END IF;
      END IF;

      IF OLD.cost_center_id IS DISTINCT FROM NEW.cost_center_id THEN
        IF OLD.cost_center_id IS NOT NULL OR NEW.cost_center_id IS NULL THEN
          RAISE EXCEPTION 'Cannot UPDATE a posted journal entry metadata fields (cost_center_id). Use Reversal instead. Entry id: %', OLD.id;
        END IF;
      END IF;
    END IF;
    RETURN NEW;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- enqueue_notification_outbox_event(p_event_id uuid, p_tenant_id uuid, p_event_type text, p_aggregate_type text, p_aggregate_id text, p_payload jsonb, p_context jsonb, p_idempotency_key text, p_correlation_id text, p_causation_event_id uuid, p_version integer, p_available_at timestamp with time zone, p_created_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.enqueue_notification_outbox_event(p_event_id uuid DEFAULT NULL::uuid, p_tenant_id uuid DEFAULT NULL::uuid, p_event_type text DEFAULT NULL::text, p_aggregate_type text DEFAULT NULL::text, p_aggregate_id text DEFAULT NULL::text, p_payload jsonb DEFAULT '{}'::jsonb, p_context jsonb DEFAULT '{}'::jsonb, p_idempotency_key text DEFAULT NULL::text, p_correlation_id text DEFAULT NULL::text, p_causation_event_id uuid DEFAULT NULL::uuid, p_version integer DEFAULT 1, p_available_at timestamp with time zone DEFAULT now(), p_created_by uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_event_id UUID := COALESCE(p_event_id, gen_random_uuid());
BEGIN
  IF p_tenant_id IS NULL THEN
    RAISE EXCEPTION 'NOTIFICATION_OUTBOX_TENANT_REQUIRED';
  END IF;

  IF p_event_type IS NULL OR btrim(p_event_type) = '' THEN
    RAISE EXCEPTION 'NOTIFICATION_OUTBOX_EVENT_TYPE_REQUIRED';
  END IF;

  IF p_aggregate_type IS NULL OR btrim(p_aggregate_type) = '' THEN
    RAISE EXCEPTION 'NOTIFICATION_OUTBOX_AGGREGATE_TYPE_REQUIRED';
  END IF;

  IF p_aggregate_id IS NULL OR btrim(p_aggregate_id) = '' THEN
    RAISE EXCEPTION 'NOTIFICATION_OUTBOX_AGGREGATE_ID_REQUIRED';
  END IF;

  IF jsonb_typeof(COALESCE(p_payload, '{}'::JSONB)) <> 'object' THEN
    RAISE EXCEPTION 'NOTIFICATION_OUTBOX_PAYLOAD_MUST_BE_OBJECT';
  END IF;

  IF jsonb_typeof(COALESCE(p_context, '{}'::JSONB)) <> 'object' THEN
    RAISE EXCEPTION 'NOTIFICATION_OUTBOX_CONTEXT_MUST_BE_OBJECT';
  END IF;

  INSERT INTO public.notification_outbox_events (
    event_id,
    tenant_id,
    event_type,
    aggregate_type,
    aggregate_id,
    payload,
    context,
    idempotency_key,
    correlation_id,
    causation_event_id,
    version,
    available_at,
    created_by
  ) VALUES (
    v_event_id,
    p_tenant_id,
    p_event_type,
    p_aggregate_type,
    p_aggregate_id,
    COALESCE(p_payload, '{}'::JSONB),
    COALESCE(p_context, '{}'::JSONB),
    p_idempotency_key,
    p_correlation_id,
    p_causation_event_id,
    COALESCE(p_version, 1),
    COALESCE(p_available_at, NOW()),
    p_created_by
  );

  RETURN v_event_id;
EXCEPTION
  WHEN unique_violation THEN
    IF p_idempotency_key IS NOT NULL THEN
      SELECT event_id
        INTO v_event_id
      FROM public.notification_outbox_events
      WHERE tenant_id = p_tenant_id
        AND idempotency_key = p_idempotency_key
      ORDER BY created_at DESC
      LIMIT 1;

      IF v_event_id IS NOT NULL THEN
        RETURN v_event_id;
      END IF;
    END IF;

    RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- ensure_branch_outlet(p_branch_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ensure_branch_outlet(p_branch_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_branch RECORD;
  v_id uuid;
  v_name text;
BEGIN
  SELECT id, company_id, name, COALESCE(is_active, true) AS is_active
  INTO v_branch FROM public.branches WHERE id = p_branch_id;
  IF NOT FOUND THEN RETURN NULL; END IF;

  v_name := 'منفذ بيع ' || v_branch.name;

  -- already-linked outlet for this branch?
  SELECT sp.id INTO v_id
  FROM public.shipping_providers sp
  JOIN public.branch_shipping_providers bsp ON bsp.shipping_provider_id = sp.id
  WHERE sp.company_id = v_branch.company_id
    AND sp.provider_code = 'branch_outlet'
    AND bsp.branch_id = p_branch_id
  LIMIT 1;

  -- adopt a manually-created outlet with the same name
  IF v_id IS NULL THEN
    SELECT id INTO v_id FROM public.shipping_providers
    WHERE company_id = v_branch.company_id
      AND provider_name = v_name
    LIMIT 1;
    IF v_id IS NOT NULL THEN
      UPDATE public.shipping_providers
         SET provider_code = 'branch_outlet', base_url = COALESCE(base_url, 'manual')
       WHERE id = v_id;
    END IF;
  END IF;

  IF v_id IS NULL THEN
    INSERT INTO public.shipping_providers
      (company_id, provider_name, provider_code, base_url, is_active)
    VALUES
      (v_branch.company_id, v_name, 'branch_outlet', 'manual', v_branch.is_active)
    RETURNING id INTO v_id;
  END IF;

  -- map strictly to its branch
  INSERT INTO public.branch_shipping_providers (branch_id, shipping_provider_id, is_active)
  SELECT p_branch_id, v_id, true
  WHERE NOT EXISTS (
    SELECT 1 FROM public.branch_shipping_providers bsp
    WHERE bsp.branch_id = p_branch_id AND bsp.shipping_provider_id = v_id
  );

  RETURN v_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- ensure_invoice_created_by()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ensure_invoice_created_by()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  -- إذا لم يكن created_by_user_id موجوداً
  IF NEW.created_by_user_id IS NULL THEN
    -- محاولة 1: من أمر البيع المرتبط
    IF NEW.sales_order_id IS NOT NULL THEN
      SELECT created_by_user_id INTO NEW.created_by_user_id
      FROM sales_orders
      WHERE id = NEW.sales_order_id
      LIMIT 1;
    END IF;
    
    -- محاولة 2: من المستخدم الحالي (auth.uid())
    IF NEW.created_by_user_id IS NULL THEN
      -- في Supabase، يمكن استخدام auth.uid() للحصول على المستخدم الحالي
      -- لكن في trigger، نستخدم auth.uid() مباشرة
      NEW.created_by_user_id := auth.uid();
    END IF;
    
    -- محاولة 3: من audit_logs (إذا كان موجوداً)
    IF NEW.created_by_user_id IS NULL THEN
      SELECT user_id INTO NEW.created_by_user_id
      FROM audit_logs
      WHERE target_table = 'invoices'
        AND action = 'INSERT'
        AND record_id = NEW.id
      ORDER BY created_at DESC
      LIMIT 1;
    END IF;
    
    -- محاولة 4: من owner/admin في الشركة (fallback أخير)
    IF NEW.created_by_user_id IS NULL THEN
      SELECT cm.user_id INTO NEW.created_by_user_id
      FROM company_members cm
      WHERE cm.company_id = NEW.company_id
        AND cm.role IN ('owner', 'admin')
      ORDER BY cm.role, cm.user_id
      LIMIT 1;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ensure_journal_entry_balanced()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ensure_journal_entry_balanced()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  total numeric;
BEGIN
  IF NEW.status = 'posted' AND (OLD.status IS DISTINCT FROM 'posted') THEN
    SELECT SUM(COALESCE(jel.debit_amount,0) - COALESCE(jel.credit_amount,0))
      INTO total
    FROM journal_entry_lines jel
    WHERE jel.journal_entry_id = NEW.id;

    IF COALESCE(total,0) <> 0 THEN
      RAISE EXCEPTION 'Cannot post journal_entry %: lines are not balanced (total = %).', NEW.id, total;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ensure_return_has_journal_entry()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ensure_return_has_journal_entry()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ BEGIN IF NEW.status = 'completed' AND NEW.journal_entry_id IS NULL THEN RAISE WARNING 'مرتجع مكتمل بدون قيد محاسبي: %', NEW.return_number; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- ensure_sales_order_created_by()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ensure_sales_order_created_by()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  -- إذا لم يكن created_by_user_id موجوداً
  IF NEW.created_by_user_id IS NULL THEN
    -- محاولة 1: من المستخدم الحالي (auth.uid())
    NEW.created_by_user_id := auth.uid();
    
    -- محاولة 2: من owner/admin في الشركة (fallback)
    IF NEW.created_by_user_id IS NULL THEN
      SELECT cm.user_id INTO NEW.created_by_user_id
      FROM company_members cm
      WHERE cm.company_id = NEW.company_id
        AND cm.role IN ('owner', 'admin')
      ORDER BY cm.role, cm.user_id
      LIMIT 1;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ensure_warehouse_cost_center_from_branch_default()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ensure_warehouse_cost_center_from_branch_default()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_default_cost_center_id UUID;
  v_cost_center_branch_id UUID;
BEGIN
  IF NEW.branch_id IS NULL THEN
    RAISE EXCEPTION 'warehouse.branch_id cannot be NULL - governance violation';
  END IF;

  IF NEW.cost_center_id IS NULL THEN
    SELECT default_cost_center_id
      INTO v_default_cost_center_id
      FROM public.branches
     WHERE id = NEW.branch_id
       AND company_id = NEW.company_id;

    NEW.cost_center_id := v_default_cost_center_id;
  END IF;

  IF NEW.cost_center_id IS NULL THEN
    RAISE EXCEPTION 'warehouse.cost_center_id cannot be NULL and branch has no default cost center. branch_id=%',
      NEW.branch_id;
  END IF;

  SELECT branch_id
    INTO v_cost_center_branch_id
    FROM public.cost_centers
   WHERE id = NEW.cost_center_id
     AND company_id = NEW.company_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'warehouse.cost_center_id must reference an existing company cost center. cost_center_id=%',
      NEW.cost_center_id;
  END IF;

  IF v_cost_center_branch_id IS DISTINCT FROM NEW.branch_id THEN
    RAISE EXCEPTION 'warehouse.cost_center_id must belong to warehouse.branch_id - governance violation';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- execute_customer_refund(p_refund_request_id uuid, p_account_id uuid, p_executed_by uuid, p_execution_date date, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.execute_customer_refund(p_refund_request_id uuid, p_account_id uuid, p_executed_by uuid, p_execution_date date DEFAULT CURRENT_DATE, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_req          RECORD;
  v_account      RECORD;
  v_ar_account   RECORD;
  v_je_id        UUID;
  v_entry_number TEXT;
BEGIN
  -- ─────────────────────────────────────────────
  -- 1. Fetch & validate the refund request
  -- ─────────────────────────────────────────────
  SELECT rr.*,
         c.name AS customer_name
  INTO   v_req
  FROM   customer_refund_requests rr
  JOIN   customers c ON c.id = rr.customer_id
  WHERE  rr.id = p_refund_request_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Refund request not found');
  END IF;

  IF v_req.status != 'approved' THEN
    RETURN jsonb_build_object('success', false,
      'error', 'Request must be in approved status before execution. Current: ' || v_req.status);
  END IF;

  -- Idempotency: already executed?
  IF EXISTS (
    SELECT 1 FROM journal_entries
    WHERE reference_type = 'customer_refund'
      AND reference_id   = p_refund_request_id
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'Refund already posted (idempotency guard)');
  END IF;

  -- ─────────────────────────────────────────────
  -- 2. Validate selected Cash/Bank account
  -- ─────────────────────────────────────────────
  SELECT id, account_code, account_name, sub_type, branch_id
  INTO   v_account
  FROM   chart_of_accounts
  WHERE  id         = p_account_id
    AND  company_id = v_req.company_id
    AND  sub_type   IN ('cash', 'bank')
    AND  is_active  = true;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid cash/bank account selected');
  END IF;

  -- ─────────────────────────────────────────────
  -- 3. Resolve Accounts Receivable account
  -- ─────────────────────────────────────────────
  -- Prefer account of same branch, fall back to global AR
  SELECT id INTO v_ar_account
  FROM   chart_of_accounts
  WHERE  company_id  = v_req.company_id
    AND  sub_type    = 'accounts_receivable'
    AND  is_active   = true
  ORDER BY (CASE WHEN branch_id IS NULL THEN 1 ELSE 0 END)  -- prefer non-null last
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'No Accounts Receivable account found in Chart of Accounts');
  END IF;

  -- ─────────────────────────────────────────────
  -- 4. Generate entry number
  -- ─────────────────────────────────────────────
  v_entry_number := 'REF-' || TO_CHAR(p_execution_date, 'YYYYMMDD') || '-' ||
                    LPAD(CAST(
                      (SELECT COUNT(*) + 1 FROM journal_entries
                       WHERE reference_type = 'customer_refund'
                         AND company_id = v_req.company_id)
                    AS TEXT), 4, '0');

  -- ─────────────────────────────────────────────
  -- 5. Create Journal Entry header
  -- ─────────────────────────────────────────────
  INSERT INTO journal_entries (
    company_id, reference_type, reference_id,
    entry_date, entry_number, description,
    status, branch_id,
    posted_at, posted_by
  ) VALUES (
    v_req.company_id,
    'customer_refund',
    p_refund_request_id,
    p_execution_date,
    v_entry_number,
    COALESCE(p_notes,
      'استرداد نقدي للعميل: ' || v_req.customer_name ||
      ' - طلب رقم: ' || p_refund_request_id::text
    ),
    'posted',
    v_account.branch_id,
    NOW(),
    p_executed_by
  ) RETURNING id INTO v_je_id;

  -- ─────────────────────────────────────────────
  -- 6. Create Journal Entry Lines
  -- Dr: Accounts Receivable (reduces what customer owes)
  -- Cr: Cash / Bank (reduces treasury)
  -- ─────────────────────────────────────────────
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
  VALUES
    -- Dr: AR (Customer Liability reduced)
    (v_je_id, v_ar_account.id, v_req.amount, 0,
     'Dr مديونية العميل - ' || v_req.customer_name),
    -- Cr: Cash/Bank
    (v_je_id, p_account_id, 0, v_req.amount,
     'Cr ' || v_account.account_name || ' - سداد استرداد');

  -- ─────────────────────────────────────────────
  -- 7. Mark refund request as executed
  -- ─────────────────────────────────────────────
  UPDATE customer_refund_requests SET
    status      = 'executed',
    executed_by = p_executed_by,
    executed_at = NOW(),
    notes       = COALESCE(p_notes, notes)
  WHERE id = p_refund_request_id;

  -- ─────────────────────────────────────────────
  -- 8. Return success with JE details
  -- ─────────────────────────────────────────────
  RETURN jsonb_build_object(
    'success',           true,
    'message',           'تم تنفيذ الاسترداد وترحيل القيد بنجاح',
    'journal_entry_id',  v_je_id,
    'entry_number',      v_entry_number,
    'amount',            v_req.amount,
    'debit_account',     v_ar_account.id,
    'credit_account',    p_account_id
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- execute_payment_correction(p_request_id uuid, p_company_id uuid, p_executor_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.execute_payment_correction(p_request_id uuid, p_company_id uuid, p_executor_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_req         record;
  v_original    record;
  v_orig_journal record;
  v_new_journal_id uuid := NULL;
  v_void_payment_id uuid;
  v_new_payment_id uuid := NULL;
  v_new_journal_post_id uuid := NULL;
  v_invoice     record;
  v_proposed    jsonb;
  v_new_amount  numeric;
  v_new_date    date;
  v_new_account uuid;
  v_new_method  text;
  v_new_ref     text;
  v_new_notes   text;
  v_ar_account  uuid;
  v_has_changes boolean;
  v_company_base_ccy text;
  v_has_orig_journal boolean;
  v_ledger_rec  record;
  v_ledger_undone int := 0;
  v_legacy_rolled int := 0;
  v_new_currency text;
  v_new_rate     numeric;
  v_new_base     numeric;
  v_orig_base    numeric;
  v_currency_changed    boolean;
  v_orig_currency_upper text;
BEGIN
  SELECT * INTO v_req FROM customer_refund_requests
  WHERE id = p_request_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'REQUEST_NOT_FOUND'; END IF;
  IF v_req.status <> 'approved' THEN RAISE EXCEPTION 'REQUEST_NOT_APPROVED'; END IF;
  IF v_req.source_type <> 'payment_correction' THEN RAISE EXCEPTION 'NOT_PAYMENT_CORRECTION'; END IF;
  IF v_req.original_payment_id IS NULL THEN RAISE EXCEPTION 'MISSING_ORIGINAL_PAYMENT'; END IF;

  SELECT * INTO v_original FROM payments WHERE id = v_req.original_payment_id FOR UPDATE;
  IF NOT FOUND OR v_original.voided_by_payment_id IS NOT NULL THEN
    RAISE EXCEPTION 'PAYMENT_ALREADY_VOIDED_OR_MISSING';
  END IF;

  -- v3.74.546 — load base ccy up front.
  SELECT base_currency INTO v_company_base_ccy FROM companies WHERE id = p_company_id;
  v_company_base_ccy := UPPER(COALESCE(v_company_base_ccy, 'EGP'));

  v_has_orig_journal := v_original.journal_entry_id IS NOT NULL;
  IF v_has_orig_journal THEN
    SELECT * INTO v_orig_journal FROM journal_entries WHERE id = v_original.journal_entry_id;
    IF v_orig_journal.id IS NULL THEN v_has_orig_journal := false; END IF;
  END IF;

  v_orig_base := COALESCE(v_original.base_currency_amount,
                          v_original.amount * COALESCE(NULLIF(v_original.exchange_rate, 0), 1));

  IF v_has_orig_journal THEN
    INSERT INTO journal_entries (
      company_id, branch_id, cost_center_id, reference_type, reference_id,
      entry_date, description, status
    ) VALUES (
      v_orig_journal.company_id, v_orig_journal.branch_id, v_orig_journal.cost_center_id,
      'payment_reversal', v_original.id, CURRENT_DATE,
      'تَصحيح / عَكس للدَّفعَة ' || COALESCE(v_original.reference_number, v_original.id::text) || ' — ' || COALESCE(v_req.notes, ''),
      'draft'
    ) RETURNING id INTO v_new_journal_id;

    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount,
      description, branch_id, cost_center_id, original_debit, original_credit, original_currency
    )
    SELECT v_new_journal_id, account_id, credit_amount, debit_amount,
           'عَكس قَيد — ' || COALESCE(description, ''), branch_id, cost_center_id,
           original_credit, original_debit, original_currency
    FROM journal_entry_lines WHERE journal_entry_id = v_original.journal_entry_id;

    UPDATE journal_entries SET status = 'posted' WHERE id = v_new_journal_id;
  END IF;

  INSERT INTO payments (
    company_id, customer_id, invoice_id, payment_date,
    amount, payment_method, reference_number, notes,
    account_id, journal_entry_id, branch_id, cost_center_id,
    currency_code, exchange_rate, base_currency_amount,
    original_currency, original_amount,
    status, created_by, voids_payment_id, void_reason, voided_at, voided_by, unallocated_amount
  ) VALUES (
    v_original.company_id, v_original.customer_id, v_original.invoice_id, CURRENT_DATE,
    -v_original.amount, v_original.payment_method,
    'VOID-' || COALESCE(v_original.reference_number, SUBSTRING(v_original.id::text FROM 1 FOR 8)),
    'تَصحيح: ' || COALESCE(v_req.notes, '') || ' — يُلغى الدَّفعَة الأَصلية' ||
      CASE WHEN v_has_orig_journal THEN '' ELSE ' (بدون عَكس قَيد - الأَصل بدون قَيد GL)' END,
    v_original.account_id, v_new_journal_id, v_original.branch_id, v_original.cost_center_id,
    v_original.currency_code, v_original.exchange_rate, -v_orig_base,
    v_original.original_currency, -v_original.original_amount,
    'approved', p_executor_id, v_original.id, v_req.notes, NOW(), p_executor_id, 0
  ) RETURNING id INTO v_void_payment_id;

  UPDATE payments SET
    voided_by_payment_id = v_void_payment_id, voided_at = NOW(),
    voided_by = p_executor_id, void_reason = v_req.notes
  WHERE id = v_original.id;

  IF v_original.invoice_id IS NOT NULL THEN
    SELECT * INTO v_invoice FROM invoices WHERE id = v_original.invoice_id FOR UPDATE;
    IF FOUND THEN
      UPDATE invoices SET
        paid_amount = GREATEST(0, COALESCE(paid_amount, 0) - v_orig_base),
        status = CASE
          WHEN GREATEST(0, COALESCE(paid_amount, 0) - v_orig_base) <= 0 THEN 'sent'
          WHEN GREATEST(0, COALESCE(paid_amount, 0) - v_orig_base)
               >= GREATEST(0, total_amount - COALESCE(returned_amount,0)) THEN 'paid'
          ELSE 'partially_paid' END,
        updated_at = NOW()
      WHERE id = v_invoice.id;
    END IF;
  END IF;

  FOR v_ledger_rec IN
    SELECT id, source_type, amount, description
    FROM customer_credit_ledger
    WHERE source_id = v_original.id
      AND customer_id = v_original.customer_id
  LOOP
    INSERT INTO customer_credit_ledger (
      company_id, customer_id, source_type, source_id, journal_entry_id, amount, description, created_by
    ) VALUES (
      v_original.company_id, v_original.customer_id, 'correction_reversal',
      p_request_id, v_new_journal_id, -v_ledger_rec.amount,
      'عَكس أَثَر "' || v_ledger_rec.source_type || '" على الرَّصيد بسَبَب تَصحيح الدَّفعَة — ' || COALESCE(v_req.notes, ''),
      p_executor_id
    );
    v_ledger_undone := v_ledger_undone + 1;

    IF v_ledger_rec.source_type = 'customer_refund' THEN
      UPDATE customer_credits cc
      SET used_amount = GREATEST(0, COALESCE(cc.used_amount, 0) - ABS(v_ledger_rec.amount)),
          status = CASE
            WHEN cc.applied_amount > 0
              AND cc.applied_amount < cc.amount
              AND GREATEST(0, COALESCE(cc.used_amount,0) - ABS(v_ledger_rec.amount)) = 0 THEN 'partially_used'
            WHEN cc.applied_amount = 0
              AND GREATEST(0, COALESCE(cc.used_amount,0) - ABS(v_ledger_rec.amount)) = 0 THEN 'active'
            ELSE cc.status
          END,
          updated_at = NOW()
      WHERE cc.customer_id = v_original.customer_id
        AND cc.company_id = v_original.company_id
        AND cc.used_amount > 0;
      GET DIAGNOSTICS v_legacy_rolled = ROW_COUNT;
    ELSIF v_ledger_rec.source_type = 'overpayment' THEN
      UPDATE customer_credits cc
      SET amount = GREATEST(0, COALESCE(cc.amount, 0) - ABS(v_ledger_rec.amount)),
          status = CASE
            WHEN GREATEST(0, COALESCE(cc.amount,0) - ABS(v_ledger_rec.amount))
                 <= COALESCE(cc.applied_amount,0) + COALESCE(cc.used_amount,0) THEN 'used'
            ELSE cc.status
          END,
          updated_at = NOW()
      WHERE cc.customer_id = v_original.customer_id
        AND cc.company_id = v_original.company_id
        AND cc.reference_id = v_original.id;
      GET DIAGNOSTICS v_legacy_rolled = ROW_COUNT;
    END IF;
  END LOOP;

  IF v_original.payment_method = 'customer_credit' AND v_ledger_undone = 0 THEN
    INSERT INTO customer_credit_ledger (
      company_id, customer_id, source_type, source_id, journal_entry_id, amount, description, created_by
    ) VALUES (
      v_original.company_id, v_original.customer_id, 'credit_applied',
      v_original.invoice_id, v_new_journal_id, v_original.amount,
      'إِلغاء تَطبيق رَصيد دائن — تَصحيح: ' || COALESCE(v_req.notes, ''), p_executor_id
    );
    v_ledger_undone := 1;
  END IF;

  v_proposed := COALESCE(v_req.metadata -> 'proposed_changes', '{}'::jsonb);
  v_has_changes := (v_proposed ? 'amount') OR (v_proposed ? 'payment_date') OR
                   (v_proposed ? 'account_id') OR (v_proposed ? 'payment_method') OR
                   (v_proposed ? 'reference_number') OR (v_proposed ? 'notes') OR
                   (v_proposed ? 'original_currency') OR (v_proposed ? 'exchange_rate');

  IF v_has_changes THEN
    v_new_amount := COALESCE((v_proposed->>'amount')::numeric, v_original.amount);
    v_new_date   := COALESCE((v_proposed->>'payment_date')::date, v_original.payment_date);
    v_new_account := COALESCE(NULLIF(v_proposed->>'account_id','')::uuid, v_original.account_id);
    v_new_method := COALESCE(NULLIF(v_proposed->>'payment_method',''), v_original.payment_method);
    v_new_ref    := COALESCE(NULLIF(v_proposed->>'reference_number',''), v_original.reference_number);
    v_new_notes  := COALESCE(NULLIF(v_proposed->>'notes',''), v_original.notes);

    -- v3.74.546 — new currency + rate logic (mirror of vendor side).
    v_new_currency := UPPER(COALESCE(NULLIF(v_proposed->>'original_currency',''),
                                     v_original.original_currency,
                                     v_original.currency_code, v_company_base_ccy));

    v_orig_currency_upper := UPPER(COALESCE(v_original.original_currency,
                                            v_original.currency_code,
                                            v_company_base_ccy));
    v_currency_changed := v_new_currency <> v_orig_currency_upper;

    IF v_new_currency = v_company_base_ccy THEN
      v_new_rate := 1;
    ELSIF v_proposed ? 'exchange_rate' AND
          (v_proposed->>'exchange_rate') IS NOT NULL AND
          (v_proposed->>'exchange_rate') <> '' THEN
      v_new_rate := (v_proposed->>'exchange_rate')::numeric;
      IF v_new_rate IS NULL OR v_new_rate <= 0 THEN v_new_rate := 1; END IF;
    ELSIF NOT v_currency_changed THEN
      v_new_rate := COALESCE(NULLIF(v_original.exchange_rate, 0), 1);
    ELSE
      v_new_rate := 1;
    END IF;

    v_new_base := ROUND(v_new_amount * v_new_rate, 4);

    IF v_original.invoice_id IS NOT NULL THEN
      SELECT id INTO v_ar_account FROM chart_of_accounts
      WHERE company_id = p_company_id AND is_active = true
        AND (sub_type = 'accounts_receivable'
             OR account_name ILIKE '%receivable%'
             OR account_name ILIKE '%الذمم المدينة%')
      ORDER BY CASE WHEN sub_type = 'accounts_receivable' THEN 0 ELSE 1 END LIMIT 1;
    END IF;

    INSERT INTO journal_entries (
      company_id, branch_id, cost_center_id, reference_type, reference_id,
      entry_date, description, status
    ) VALUES (
      v_original.company_id, v_original.branch_id, v_original.cost_center_id,
      'payment_correction_repost', p_request_id, v_new_date,
      'تَصحيح وَإِعادَة تَسجيل دَفعَة عَلى ' || COALESCE(v_original.reference_number, v_original.id::text),
      'draft'
    ) RETURNING id INTO v_new_journal_post_id;

    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount,
      description, branch_id, cost_center_id
    ) VALUES
      (v_new_journal_post_id, v_new_account, v_new_base, 0,
       'دَفعَة بَعد التَّصحيح', v_original.branch_id, v_original.cost_center_id);

    IF v_ar_account IS NOT NULL THEN
      INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, debit_amount, credit_amount,
        description, branch_id, cost_center_id
      ) VALUES (
        v_new_journal_post_id, v_ar_account, 0, v_new_base,
        'سَداد فاتورَة - تَصحيح', v_original.branch_id, v_original.cost_center_id
      );
    END IF;

    UPDATE journal_entries SET status = 'posted' WHERE id = v_new_journal_post_id;

    INSERT INTO payments (
      company_id, customer_id, invoice_id, payment_date,
      amount, payment_method, reference_number, notes,
      account_id, journal_entry_id, branch_id, cost_center_id,
      currency_code, exchange_rate, base_currency_amount,
      original_currency, original_amount,
      status, created_by, unallocated_amount
    ) VALUES (
      v_original.company_id, v_original.customer_id, v_original.invoice_id, v_new_date,
      v_new_amount, v_new_method,
      COALESCE(v_new_ref, 'CORR-' || SUBSTRING(p_request_id::text FROM 1 FOR 8)),
      'تَصحيح مُعتَمَد: ' || COALESCE(v_new_notes, ''),
      v_new_account, v_new_journal_post_id, v_original.branch_id, v_original.cost_center_id,
      v_new_currency, v_new_rate, v_new_base,
      v_new_currency, v_new_amount,
      'approved', p_executor_id, 0
    ) RETURNING id INTO v_new_payment_id;

    IF v_original.invoice_id IS NOT NULL THEN
      UPDATE invoices SET
        paid_amount = COALESCE(paid_amount, 0) + v_new_base,
        status = CASE
          WHEN COALESCE(paid_amount, 0) + v_new_base
               >= GREATEST(0, total_amount - COALESCE(returned_amount, 0)) THEN 'paid'
          ELSE 'partially_paid' END,
        updated_at = NOW()
      WHERE id = v_original.invoice_id;
    END IF;
  END IF;

  UPDATE customer_refund_requests SET
    status = 'executed',
    executed_by = p_executor_id,
    executed_at = NOW(),
    reversal_payment_id = v_void_payment_id,
    reversal_journal_entry_id = v_new_journal_id,
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'new_payment_id',       v_new_payment_id,
      'new_journal_entry_id', v_new_journal_post_id,
      'original_had_journal', v_has_orig_journal,
      'credit_ledger_undone', v_ledger_undone,
      'legacy_credits_rolled', v_legacy_rolled
    ),
    updated_at = NOW()
  WHERE id = p_request_id;

  RETURN jsonb_build_object(
    'success', true,
    'request_id', p_request_id,
    'original_payment_id', v_original.id,
    'reversal_payment_id', v_void_payment_id,
    'reversal_journal_entry_id', v_new_journal_id,
    'new_payment_id', v_new_payment_id,
    'new_journal_entry_id', v_new_journal_post_id,
    'original_had_journal', v_has_orig_journal,
    'credit_ledger_undone', v_ledger_undone,
    'legacy_credits_rolled', v_legacy_rolled
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- execute_permission_transfer(p_transfer_id uuid, p_mode text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.execute_permission_transfer(p_transfer_id uuid, p_mode text DEFAULT 'snapshot'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  t              record;
  v_branch       uuid;
  v_count        integer;
  v_total        integer := 0;
  v_cust_ids     uuid[]  := ARRAY[]::uuid[];
  v_so_ids       uuid[]  := ARRAY[]::uuid[];
  v_snap_cust    uuid[]  := ARRAY[]::uuid[];
  v_snap_so      uuid[]  := ARRAY[]::uuid[];
BEGIN
  IF p_mode NOT IN ('snapshot', 'dynamic') THEN
    RAISE EXCEPTION 'Invalid mode %, expected snapshot or dynamic', p_mode;
  END IF;

  SELECT * INTO t
  FROM public.permission_transfers
  WHERE id = p_transfer_id
  FOR UPDATE;

  IF t IS NULL THEN
    RAISE EXCEPTION 'Transfer % not found', p_transfer_id;
  END IF;

  IF t.status <> 'approved' THEN
    RAISE EXCEPTION 'Transfer % is in status %, must be approved before execution', p_transfer_id, t.status;
  END IF;

  IF t.transfer_data IS NOT NULL THEN
    v_branch := NULLIF(t.transfer_data ->> 'branch_id', '')::uuid;
    IF t.transfer_data ? 'snapshot_customer_ids' THEN
      SELECT array_agg((value #>> '{}')::uuid)
      INTO v_snap_cust
      FROM jsonb_array_elements(t.transfer_data -> 'snapshot_customer_ids');
    END IF;
    IF t.transfer_data ? 'snapshot_sales_order_ids' THEN
      SELECT array_agg((value #>> '{}')::uuid)
      INTO v_snap_so
      FROM jsonb_array_elements(t.transfer_data -> 'snapshot_sales_order_ids');
    END IF;
  END IF;

  -- customers
  IF t.resource_type = 'customers' OR t.resource_type = 'all' THEN
    IF p_mode = 'snapshot' AND v_snap_cust IS NOT NULL AND array_length(v_snap_cust, 1) > 0 THEN
      -- Just do the UPDATE. The follow-up SELECT array_agg captures
      -- which IDs actually moved (handles the case where a record was
      -- already manually re-assigned by another path between submit
      -- and approve).
      UPDATE public.customers
      SET created_by_user_id = t.to_user_id
      WHERE company_id = t.company_id
        AND created_by_user_id = t.from_user_id
        AND id = ANY(v_snap_cust);

      SELECT array_agg(id) INTO v_cust_ids
      FROM public.customers
      WHERE company_id = t.company_id
        AND created_by_user_id = t.to_user_id
        AND id = ANY(v_snap_cust);
    ELSE
      SELECT array_agg(id) INTO v_cust_ids
      FROM public.customers
      WHERE company_id = t.company_id
        AND created_by_user_id = t.from_user_id
        AND (v_branch IS NULL OR branch_id = v_branch);

      UPDATE public.customers
      SET created_by_user_id = t.to_user_id
      WHERE company_id = t.company_id
        AND created_by_user_id = t.from_user_id
        AND (v_branch IS NULL OR branch_id = v_branch);
    END IF;
    v_count := COALESCE(array_length(v_cust_ids, 1), 0);
    v_total := v_total + v_count;
  END IF;

  -- sales_orders
  IF t.resource_type = 'sales_orders' OR t.resource_type = 'all' THEN
    IF p_mode = 'snapshot' AND v_snap_so IS NOT NULL AND array_length(v_snap_so, 1) > 0 THEN
      UPDATE public.sales_orders
      SET created_by_user_id = t.to_user_id
      WHERE company_id = t.company_id
        AND created_by_user_id = t.from_user_id
        AND id = ANY(v_snap_so);
      SELECT array_agg(id) INTO v_so_ids
      FROM public.sales_orders
      WHERE company_id = t.company_id
        AND created_by_user_id = t.to_user_id
        AND id = ANY(v_snap_so);
    ELSE
      SELECT array_agg(id) INTO v_so_ids
      FROM public.sales_orders
      WHERE company_id = t.company_id
        AND created_by_user_id = t.from_user_id
        AND (v_branch IS NULL OR branch_id = v_branch);

      UPDATE public.sales_orders
      SET created_by_user_id = t.to_user_id
      WHERE company_id = t.company_id
        AND created_by_user_id = t.from_user_id
        AND (v_branch IS NULL OR branch_id = v_branch);
    END IF;
    v_count := COALESCE(array_length(v_so_ids, 1), 0);
    v_total := v_total + v_count;
  END IF;

  UPDATE public.permission_transfers
  SET status              = 'completed',
      records_transferred = v_total,
      completed_at        = now(),
      transfer_data       = COALESCE(transfer_data, '{}'::jsonb) || jsonb_build_object(
        'customer_ids',     COALESCE(to_jsonb(v_cust_ids), '[]'::jsonb),
        'sales_order_ids',  COALESCE(to_jsonb(v_so_ids),   '[]'::jsonb),
        'executed_at',      to_char(now(), 'YYYY-MM-DD"T"HH24:MI:SSOF'),
        'execution_mode',   p_mode
      )
  WHERE id = p_transfer_id;

  RETURN jsonb_build_object(
    'ok', true,
    'transfer_id', p_transfer_id,
    'mode', p_mode,
    'records_transferred', v_total,
    'customer_count',    COALESCE(array_length(v_cust_ids, 1), 0),
    'sales_order_count', COALESCE(array_length(v_so_ids, 1), 0)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- execute_recurring_journal_run(p_template_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.execute_recurring_journal_run(p_template_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_tmpl        record;
  v_je_id       uuid;
  v_role        text;
  v_new_due     date;
  v_line_count  integer := 0;
BEGIN
  SELECT * INTO v_tmpl FROM public.recurring_journal_templates WHERE id = p_template_id;
  IF NOT FOUND OR NOT v_tmpl.is_active THEN
    RAISE EXCEPTION 'TEMPLATE_NOT_ACTIVE';
  END IF;
  IF v_tmpl.end_date IS NOT NULL AND v_tmpl.next_due_date > v_tmpl.end_date THEN
    RAISE EXCEPTION 'TEMPLATE_ENDED';
  END IF;

  SELECT role INTO v_role FROM public.company_members
   WHERE company_id = v_tmpl.company_id AND user_id = p_user_id LIMIT 1;
  IF NOT (COALESCE(v_role,'') IN ('owner','general_manager','admin')) THEN
    RAISE EXCEPTION 'FORBIDDEN';
  END IF;

  PERFORM public.require_open_financial_period_db(v_tmpl.company_id, v_tmpl.next_due_date);

  INSERT INTO public.journal_entries (
    company_id, branch_id, cost_center_id,
    entry_date, description, reference_type, reference_id, status, created_by
  ) VALUES (
    v_tmpl.company_id, v_tmpl.branch_id, v_tmpl.cost_center_id,
    v_tmpl.next_due_date,
    'قيد دورى — ' || v_tmpl.template_name,
    'recurring_journal', p_template_id, 'draft', p_user_id
  ) RETURNING id INTO v_je_id;

  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description,
    debit_amount, credit_amount,
    original_debit, original_credit, original_currency, exchange_rate_used,
    branch_id, cost_center_id
  )
  SELECT v_je_id, l.account_id, COALESCE(l.description, v_tmpl.template_name),
         l.debit_amount, l.credit_amount,
         l.debit_amount, l.credit_amount,
         (SELECT UPPER(base_currency) FROM companies WHERE id = v_tmpl.company_id),
         1,
         v_tmpl.branch_id, v_tmpl.cost_center_id
    FROM public.recurring_journal_template_lines l
   WHERE l.template_id = p_template_id
   ORDER BY l.line_order;

  GET DIAGNOSTICS v_line_count = ROW_COUNT;
  IF v_line_count = 0 THEN
    DELETE FROM public.journal_entries WHERE id = v_je_id;
    RAISE EXCEPTION 'TEMPLATE_HAS_NO_LINES';
  END IF;

  UPDATE public.journal_entries
     SET status = 'posted', posted_by = p_user_id, posted_at = NOW()
   WHERE id = v_je_id;

  v_new_due := CASE v_tmpl.frequency
    WHEN 'daily'     THEN v_tmpl.next_due_date + INTERVAL '1 day'
    WHEN 'weekly'    THEN v_tmpl.next_due_date + INTERVAL '7 days'
    WHEN 'monthly'   THEN v_tmpl.next_due_date + INTERVAL '1 month'
    WHEN 'quarterly' THEN v_tmpl.next_due_date + INTERVAL '3 months'
    WHEN 'annually'  THEN v_tmpl.next_due_date + INTERVAL '1 year'
  END;

  UPDATE public.recurring_journal_templates
     SET next_due_date     = v_new_due,
         last_generated_at = NOW(),
         last_journal_id   = v_je_id,
         is_active         = CASE WHEN end_date IS NOT NULL AND v_new_due > end_date THEN false ELSE is_active END,
         updated_at        = NOW()
   WHERE id = p_template_id;

  RETURN jsonb_build_object('success', true, 'journal_id', v_je_id, 'next_due_date', v_new_due);
END;
$function$
;

-- ---------------------------------------------------------------
-- execute_sales_invoice_accounting(p_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.execute_sales_invoice_accounting(p_invoice_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_invoice            RECORD;
    v_company_id         UUID;
    v_branch_id          UUID;
    v_cost_center_id     UUID;
    v_ar_id              UUID;
    v_vat_id             UUID;
    v_default_revenue_id UUID;
    v_default_cogs_id    UUID;
    v_discount_id        UUID;
    v_revenue_je_id      UUID;
    v_cogs_je_id         UUID;
    v_item               RECORD;
    v_gross_revenue      NUMERIC := 0;
BEGIN
    SELECT * INTO v_invoice FROM invoices WHERE id = p_invoice_id;
    IF NOT FOUND THEN RETURN FALSE; END IF;

    v_company_id := v_invoice.company_id;
    v_branch_id  := v_invoice.branch_id;
    v_cost_center_id := v_invoice.cost_center_id;

    IF EXISTS (
        SELECT 1 FROM journal_entries
         WHERE reference_type = 'invoice' AND reference_id = p_invoice_id
           AND (is_deleted IS NULL OR is_deleted = false)
    ) THEN RETURN TRUE; END IF;

    SELECT id INTO v_ar_id FROM chart_of_accounts
     WHERE company_id = v_company_id AND is_active = true AND sub_type = 'accounts_receivable' LIMIT 1;
    SELECT id INTO v_default_revenue_id FROM chart_of_accounts
     WHERE company_id = v_company_id AND is_active = true
       AND (sub_type = 'sales_revenue' OR account_type = 'income')
     ORDER BY CASE WHEN sub_type = 'sales_revenue' THEN 0 ELSE 1 END LIMIT 1;
    SELECT id INTO v_default_cogs_id FROM chart_of_accounts
     WHERE company_id = v_company_id AND is_active = true
       AND (sub_type IN ('cost_of_goods_sold', 'cogs') OR account_code = '5000')
     ORDER BY CASE WHEN sub_type IN ('cost_of_goods_sold','cogs') THEN 0 ELSE 1 END LIMIT 1;
    SELECT id INTO v_vat_id FROM chart_of_accounts
     WHERE company_id = v_company_id AND is_active = true
       AND (sub_type IN ('vat_output','tax_payable') OR account_name ILIKE '%ضريبة%' OR account_name ILIKE '%vat%') LIMIT 1;
    SELECT id INTO v_discount_id FROM chart_of_accounts
     WHERE company_id = v_company_id AND is_active = true
       AND sub_type IN ('sales_discounts', 'sales_discount') LIMIT 1;

    IF v_ar_id IS NULL THEN
        RAISE EXCEPTION 'MISSING_AR_ACCOUNT: Accounts Receivable not configured for company %', v_company_id;
    END IF;
    IF v_default_revenue_id IS NULL THEN
        RAISE EXCEPTION 'MISSING_REVENUE_ACCOUNT: Sales Revenue not configured for company %', v_company_id;
    END IF;

    PERFORM set_config('app.allow_direct_post', 'true', true);

    INSERT INTO journal_entries (
        company_id, branch_id, reference_type, reference_id, entry_date,
        description, status, cost_center_id, warehouse_id
    ) VALUES (
        v_company_id, v_branch_id, 'invoice', p_invoice_id,
        COALESCE(v_invoice.invoice_date, CURRENT_DATE),
        'فاتورة مبيعات - ' || v_invoice.invoice_number,
        'draft', v_cost_center_id, v_invoice.warehouse_id
    ) RETURNING id INTO v_revenue_je_id;

    INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
    ) VALUES (
        v_revenue_je_id, v_ar_id, COALESCE(v_invoice.total_amount, 0), 0,
        'الذمم المدينة - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
    );

    IF COALESCE(v_invoice.discount_value, 0) > 0 AND v_discount_id IS NOT NULL THEN
        INSERT INTO journal_entry_lines (
            journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
        ) VALUES (
            v_revenue_je_id, v_discount_id, v_invoice.discount_value, 0,
            'خصم مبيعات - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
        );
    END IF;

    IF COALESCE(v_invoice.tax_amount, 0) > 0 AND v_vat_id IS NOT NULL THEN
        INSERT INTO journal_entry_lines (
            journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
        ) VALUES (
            v_revenue_je_id, v_vat_id, 0, v_invoice.tax_amount,
            'ضريبة القيمة المضافة - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
        );
    END IF;

    IF COALESCE(v_invoice.discount_value, 0) > 0 AND v_discount_id IS NOT NULL THEN
        v_gross_revenue := COALESCE(v_invoice.subtotal, 0);
        IF v_gross_revenue > 0 THEN
            INSERT INTO journal_entry_lines (
                journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
            ) VALUES (
                v_revenue_je_id, v_default_revenue_id, 0, v_gross_revenue,
                'إيرادات المبيعات - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
            );
        END IF;
    ELSE
        FOR v_item IN (
            SELECT COALESCE(p.income_account_id, v_default_revenue_id) as acc_id,
                   SUM(ii.line_total) as grouped_amount
              FROM invoice_items ii
              JOIN products p ON p.id = ii.product_id
             WHERE ii.invoice_id = p_invoice_id
             GROUP BY COALESCE(p.income_account_id, v_default_revenue_id)
             HAVING SUM(ii.line_total) > 0
        ) LOOP
            INSERT INTO journal_entry_lines (
                journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
            ) VALUES (
                v_revenue_je_id, v_item.acc_id, 0, v_item.grouped_amount,
                'إيرادات المبيعات - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
            );
        END LOOP;
    END IF;

    IF COALESCE(v_invoice.shipping, 0) > 0 THEN
        INSERT INTO journal_entry_lines (
            journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
        ) VALUES (
            v_revenue_je_id, v_default_revenue_id, 0, v_invoice.shipping,
            'إيرادات الشحن - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
        );
    END IF;

    IF COALESCE(v_invoice.adjustment, 0) != 0 THEN
        IF v_invoice.adjustment > 0 THEN
            INSERT INTO journal_entry_lines (
                journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
            ) VALUES (
                v_revenue_je_id, v_default_revenue_id, 0, v_invoice.adjustment,
                'تسويات - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
            );
        ELSE
            INSERT INTO journal_entry_lines (
                journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
            ) VALUES (
                v_revenue_je_id, v_default_revenue_id, ABS(v_invoice.adjustment), 0,
                'تسويات خصم - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
            );
        END IF;
    END IF;

    UPDATE journal_entries SET status = 'posted' WHERE id = v_revenue_je_id;

    FOR v_item IN (
        SELECT COALESCE(p.expense_account_id, v_default_cogs_id) as cogs_acc_id,
               (SELECT id FROM chart_of_accounts WHERE company_id = v_company_id AND is_active = true AND sub_type = 'inventory' LIMIT 1) as inv_acc_id,
               SUM(ii.quantity * COALESCE(p.cost_price, 0)) as grouped_cogs_amount
          FROM invoice_items ii JOIN products p ON p.id = ii.product_id
         WHERE ii.invoice_id = p_invoice_id AND p.item_type != 'service'
         GROUP BY COALESCE(p.expense_account_id, v_default_cogs_id)
         HAVING SUM(ii.quantity * COALESCE(p.cost_price, 0)) > 0
    ) LOOP
        IF v_cogs_je_id IS NULL THEN
            INSERT INTO journal_entries (
                company_id, branch_id, reference_type, reference_id, entry_date,
                description, status, cost_center_id, warehouse_id
            ) VALUES (
                v_company_id, v_branch_id, 'invoice_cogs', p_invoice_id,
                COALESCE(v_invoice.invoice_date, CURRENT_DATE),
                'تكلفة البضاعة المباعة - ' || v_invoice.invoice_number,
                'draft', v_cost_center_id, v_invoice.warehouse_id
            ) RETURNING id INTO v_cogs_je_id;
        END IF;
        INSERT INTO journal_entry_lines (
            journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
        ) VALUES (
            v_cogs_je_id, v_item.cogs_acc_id, v_item.grouped_cogs_amount, 0,
            'تكلفة مبيعات - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
        );
        IF v_item.inv_acc_id IS NOT NULL THEN
            INSERT INTO journal_entry_lines (
                journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id
            ) VALUES (
                v_cogs_je_id, v_item.inv_acc_id, 0, v_item.grouped_cogs_amount,
                'المخزون - ' || v_invoice.invoice_number, v_branch_id, v_cost_center_id
            );
        END IF;
    END LOOP;

    IF v_cogs_je_id IS NOT NULL THEN
        UPDATE journal_entries SET status = 'posted' WHERE id = v_cogs_je_id;
    END IF;

    PERFORM set_config('app.allow_direct_post', 'false', true);
    RETURN TRUE;
EXCEPTION WHEN OTHERS THEN
    PERFORM set_config('app.allow_direct_post', 'false', true);
    RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- execute_vendor_payment_correction(p_request_id uuid, p_company_id uuid, p_executor_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.execute_vendor_payment_correction(p_request_id uuid, p_company_id uuid, p_executor_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_req                 record;
  v_original            record;
  v_orig_journal        record;
  v_new_journal_id      uuid := NULL;
  v_void_payment_id     uuid;
  v_new_payment_id      uuid := NULL;
  v_new_journal_post_id uuid := NULL;
  v_bill                record;
  v_proposed            jsonb;
  v_new_amount          numeric;
  v_new_date            date;
  v_new_account         uuid;
  v_new_method          text;
  v_new_ref             text;
  v_new_notes           text;
  v_ap_account          uuid;
  v_has_changes         boolean;
  v_company_base_ccy    text;
  v_has_orig_journal    boolean;
  v_new_currency        text;
  v_new_rate            numeric;
  v_new_base            numeric;
  v_orig_base           numeric;
  v_currency_changed    boolean;
  v_orig_currency_upper text;
BEGIN
  SELECT * INTO v_req FROM vendor_payment_correction_requests
   WHERE id = p_request_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'REQUEST_NOT_FOUND'; END IF;
  IF v_req.status <> 'approved' THEN RAISE EXCEPTION 'REQUEST_NOT_APPROVED'; END IF;
  IF v_req.source_type <> 'payment_correction' THEN RAISE EXCEPTION 'NOT_PAYMENT_CORRECTION'; END IF;
  IF v_req.original_payment_id IS NULL THEN RAISE EXCEPTION 'MISSING_ORIGINAL_PAYMENT'; END IF;

  SELECT * INTO v_original FROM payments
   WHERE id = v_req.original_payment_id FOR UPDATE;
  IF NOT FOUND OR v_original.voided_by_payment_id IS NOT NULL THEN
    RAISE EXCEPTION 'PAYMENT_ALREADY_VOIDED_OR_MISSING';
  END IF;

  PERFORM set_config('app.correction_bypass', 'on', true);

  -- v3.74.546 — load base ccy up front so rate logic can see it.
  SELECT base_currency INTO v_company_base_ccy FROM companies WHERE id = p_company_id;
  v_company_base_ccy := UPPER(COALESCE(v_company_base_ccy, 'EGP'));

  v_has_orig_journal := v_original.journal_entry_id IS NOT NULL;
  IF v_has_orig_journal THEN
    SELECT * INTO v_orig_journal FROM journal_entries WHERE id = v_original.journal_entry_id;
    IF v_orig_journal.id IS NULL THEN v_has_orig_journal := false; END IF;
  END IF;

  v_orig_base := COALESCE(v_original.base_currency_amount,
                          v_original.amount * COALESCE(NULLIF(v_original.exchange_rate, 0), 1));

  IF v_has_orig_journal THEN
    INSERT INTO journal_entries (
      company_id, branch_id, cost_center_id, reference_type, reference_id,
      entry_date, description, status
    ) VALUES (
      v_orig_journal.company_id, v_orig_journal.branch_id, v_orig_journal.cost_center_id,
      'payment_reversal', v_original.id, CURRENT_DATE,
      'تَصحيح / عَكس لدَفعَة مُورِّد ' || COALESCE(v_original.reference_number, v_original.id::text) || ' — ' || COALESCE(v_req.notes, ''),
      'draft'
    ) RETURNING id INTO v_new_journal_id;

    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount,
      description, branch_id, cost_center_id, original_debit, original_credit, original_currency
    )
    SELECT v_new_journal_id, account_id, credit_amount, debit_amount,
           'عَكس قَيد — ' || COALESCE(description, ''), branch_id, cost_center_id,
           original_credit, original_debit, original_currency
    FROM journal_entry_lines WHERE journal_entry_id = v_original.journal_entry_id;

    UPDATE journal_entries SET status = 'posted' WHERE id = v_new_journal_id;
  END IF;

  INSERT INTO payments (
    company_id, supplier_id, bill_id, payment_date,
    amount, payment_method, reference_number, notes,
    account_id, journal_entry_id, branch_id, cost_center_id,
    currency_code, exchange_rate, base_currency_amount,
    original_currency, original_amount,
    status, created_by, voids_payment_id, void_reason, voided_at, voided_by, unallocated_amount
  ) VALUES (
    v_original.company_id, v_original.supplier_id, v_original.bill_id, CURRENT_DATE,
    -v_original.amount, v_original.payment_method,
    'VOID-' || COALESCE(v_original.reference_number, SUBSTRING(v_original.id::text FROM 1 FOR 8)),
    'تَصحيح: ' || COALESCE(v_req.notes, '') || ' — يُلغى الدَّفعَة الأَصلية لِلمُورِّد' ||
      CASE WHEN v_has_orig_journal THEN '' ELSE ' (بدون عَكس قَيد - الأَصل بدون قَيد GL)' END,
    v_original.account_id, v_new_journal_id, v_original.branch_id, v_original.cost_center_id,
    v_original.currency_code, v_original.exchange_rate, -v_orig_base,
    v_original.original_currency, -v_original.original_amount,
    'approved', p_executor_id, v_original.id, v_req.notes, NOW(), p_executor_id, 0
  ) RETURNING id INTO v_void_payment_id;

  UPDATE payments SET
    voided_by_payment_id = v_void_payment_id, voided_at = NOW(),
    voided_by = p_executor_id, void_reason = v_req.notes
  WHERE id = v_original.id;

  IF v_original.bill_id IS NOT NULL THEN
    SELECT * INTO v_bill FROM bills WHERE id = v_original.bill_id FOR UPDATE;
    IF FOUND THEN
      UPDATE bills SET
        paid_amount = GREATEST(0, COALESCE(paid_amount, 0) - v_orig_base),
        status = CASE
          WHEN GREATEST(0, COALESCE(paid_amount, 0) - v_orig_base) <= 0 THEN 'received'
          WHEN GREATEST(0, COALESCE(paid_amount, 0) - v_orig_base)
               >= GREATEST(0, total_amount - COALESCE(returned_amount,0)) THEN 'paid'
          ELSE 'partially_paid' END,
        updated_at = NOW()
      WHERE id = v_bill.id;
    END IF;
  END IF;

  v_proposed := COALESCE(v_req.metadata -> 'proposed_changes', '{}'::jsonb);
  v_has_changes := (v_proposed ? 'amount') OR (v_proposed ? 'payment_date') OR
                   (v_proposed ? 'account_id') OR (v_proposed ? 'payment_method') OR
                   (v_proposed ? 'reference_number') OR (v_proposed ? 'notes') OR
                   (v_proposed ? 'original_currency') OR (v_proposed ? 'exchange_rate');

  IF v_has_changes THEN
    v_new_amount  := COALESCE((v_proposed->>'amount')::numeric, v_original.amount);
    v_new_date    := COALESCE((v_proposed->>'payment_date')::date, v_original.payment_date);
    v_new_account := COALESCE(NULLIF(v_proposed->>'account_id','')::uuid, v_original.account_id);
    v_new_method  := COALESCE(NULLIF(v_proposed->>'payment_method',''), v_original.payment_method);
    v_new_ref     := COALESCE(NULLIF(v_proposed->>'reference_number',''), v_original.reference_number);
    v_new_notes   := COALESCE(NULLIF(v_proposed->>'notes',''), v_original.notes);

    -- v3.74.546 — new currency + rate logic (see file header).
    v_new_currency := UPPER(COALESCE(NULLIF(v_proposed->>'original_currency',''),
                                     v_original.original_currency,
                                     v_original.currency_code, v_company_base_ccy));

    v_orig_currency_upper := UPPER(COALESCE(v_original.original_currency,
                                            v_original.currency_code,
                                            v_company_base_ccy));
    v_currency_changed := v_new_currency <> v_orig_currency_upper;

    IF v_new_currency = v_company_base_ccy THEN
      -- Base ccy → parity, ignoring any inherited rate.
      v_new_rate := 1;
    ELSIF v_proposed ? 'exchange_rate' AND
          (v_proposed->>'exchange_rate') IS NOT NULL AND
          (v_proposed->>'exchange_rate') <> '' THEN
      v_new_rate := (v_proposed->>'exchange_rate')::numeric;
      IF v_new_rate IS NULL OR v_new_rate <= 0 THEN v_new_rate := 1; END IF;
    ELSIF NOT v_currency_changed THEN
      -- Same currency → keep the original rate (it still applies).
      v_new_rate := COALESCE(NULLIF(v_original.exchange_rate, 0), 1);
    ELSE
      -- Currency changed but no rate provided → parity (safest default).
      v_new_rate := 1;
    END IF;

    v_new_base := ROUND(v_new_amount * v_new_rate, 4);

    IF v_original.bill_id IS NOT NULL THEN
      SELECT id INTO v_ap_account FROM chart_of_accounts
       WHERE company_id = p_company_id AND is_active = true
         AND (sub_type = 'accounts_payable'
              OR account_code = '2110'
              OR account_name ILIKE '%payable%'
              OR account_name ILIKE '%الموردين%'
              OR account_name ILIKE '%الذمم الدائنة%')
       ORDER BY CASE WHEN account_code = '2110' THEN 0
                     WHEN sub_type = 'accounts_payable' THEN 1
                     ELSE 2 END LIMIT 1;
    END IF;

    INSERT INTO journal_entries (
      company_id, branch_id, cost_center_id, reference_type, reference_id,
      entry_date, description, status
    ) VALUES (
      v_original.company_id, v_original.branch_id, v_original.cost_center_id,
      'payment_correction_repost', p_request_id, v_new_date,
      'تَصحيح وَإِعادَة تَسجيل دَفعَة مُورِّد عَلى ' || COALESCE(v_original.reference_number, v_original.id::text),
      'draft'
    ) RETURNING id INTO v_new_journal_post_id;

    IF v_ap_account IS NOT NULL THEN
      INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, debit_amount, credit_amount,
        description, branch_id, cost_center_id
      ) VALUES (
        v_new_journal_post_id, v_ap_account, v_new_base, 0,
        'سَداد فاتورَة مُورِّد - تَصحيح', v_original.branch_id, v_original.cost_center_id
      );
    END IF;

    INSERT INTO journal_entry_lines (
      journal_entry_id, account_id, debit_amount, credit_amount,
      description, branch_id, cost_center_id
    ) VALUES
      (v_new_journal_post_id, v_new_account, 0, v_new_base,
       'دَفعَة بَعد التَّصحيح', v_original.branch_id, v_original.cost_center_id);

    UPDATE journal_entries SET status = 'posted' WHERE id = v_new_journal_post_id;

    INSERT INTO payments (
      company_id, supplier_id, bill_id, payment_date,
      amount, payment_method, reference_number, notes,
      account_id, journal_entry_id, branch_id, cost_center_id,
      currency_code, exchange_rate, base_currency_amount,
      original_currency, original_amount,
      status, created_by, unallocated_amount
    ) VALUES (
      v_original.company_id, v_original.supplier_id, v_original.bill_id, v_new_date,
      v_new_amount, v_new_method,
      COALESCE(v_new_ref, 'CORR-' || SUBSTRING(p_request_id::text FROM 1 FOR 8)),
      'تَصحيح مُعتَمَد: ' || COALESCE(v_new_notes, ''),
      v_new_account, v_new_journal_post_id, v_original.branch_id, v_original.cost_center_id,
      v_new_currency, v_new_rate, v_new_base,
      v_new_currency, v_new_amount,
      'approved', p_executor_id, 0
    ) RETURNING id INTO v_new_payment_id;

    IF v_original.bill_id IS NOT NULL THEN
      UPDATE bills SET
        paid_amount = COALESCE(paid_amount, 0) + v_new_base,
        status = CASE
          WHEN COALESCE(paid_amount, 0) + v_new_base
               >= GREATEST(0, total_amount - COALESCE(returned_amount, 0)) THEN 'paid'
          ELSE 'partially_paid' END,
        updated_at = NOW()
      WHERE id = v_original.bill_id;
    END IF;
  END IF;

  UPDATE vendor_payment_correction_requests SET
    status = 'executed',
    executed_by = p_executor_id,
    executed_at = NOW(),
    reversal_payment_id = v_void_payment_id,
    reversal_journal_entry_id = v_new_journal_id,
    metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object(
      'new_payment_id',       v_new_payment_id,
      'new_journal_entry_id', v_new_journal_post_id,
      'original_had_journal', v_has_orig_journal
    ),
    updated_at = NOW()
  WHERE id = p_request_id;

  RETURN jsonb_build_object(
    'success', true,
    'request_id', p_request_id,
    'original_payment_id', v_original.id,
    'reversal_payment_id', v_void_payment_id,
    'reversal_journal_entry_id', v_new_journal_id,
    'new_payment_id', v_new_payment_id,
    'new_journal_entry_id', v_new_journal_post_id,
    'original_had_journal', v_has_orig_journal
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- expense_sod_guard()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.expense_sod_guard()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.approved_by IS NOT NULL AND NEW.created_by IS NOT NULL
     AND NEW.approved_by = NEW.created_by THEN
    RAISE EXCEPTION 'SoD violation: مُعتَمِد المَصروف لا يَجوز أَن يَكون هو نَفسه مُنشِئ المَصروف.'
      USING ERRCODE = 'check_violation';
  END IF;
  IF NEW.paid_by IS NOT NULL AND NEW.approved_by IS NOT NULL
     AND NEW.paid_by = NEW.approved_by THEN
    RAISE EXCEPTION 'SoD violation: مُنَفِّذ الصَّرف لا يَجوز أَن يَكون هو نَفسه مُعتَمِد المَصروف.'
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- expenses_mark_paid_when_journal_added()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.expenses_mark_paid_when_journal_added()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- We only act on the specific transition that creates the inconsistency.
  -- Two conditions:
  --   1. journal_entry_id just became non-null (NULL → not NULL)
  --   2. the current row is still flagged as merely 'approved'
  --      (so an admin who intentionally un-paid the expense and reposted
  --       the journal won't have their status overridden).
  IF (TG_OP = 'UPDATE'
      AND OLD.journal_entry_id IS NULL
      AND NEW.journal_entry_id IS NOT NULL
      AND NEW.status = 'approved')
  OR (TG_OP = 'INSERT'
      AND NEW.journal_entry_id IS NOT NULL
      AND NEW.status = 'approved')
  THEN
    NEW.status                 := 'paid';
    NEW.paid_at                := COALESCE(NEW.paid_at, NEW.approved_at, now());
    NEW.paid_by                := COALESCE(NEW.paid_by, NEW.approved_by);
    NEW.last_status_changed_at := now();
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- expire_permission_shares()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.expire_permission_shares()
 RETURNS TABLE(expired_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_count integer;
BEGIN
  UPDATE public.permission_sharing
  SET is_active = false,
      notes = COALESCE(notes, '') ||
              CASE WHEN COALESCE(notes,'') = '' THEN '' ELSE E'\n' END ||
              '[auto-expired v3.70.0 on ' ||
              to_char(now(), 'YYYY-MM-DD HH24:MI:SS') || ']'
  WHERE is_active = true
    AND expires_at IS NOT NULL
    AND expires_at < now();

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN QUERY SELECT v_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- export_public_routines()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.export_public_routines()
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(string_agg(
    format(
      E'-- ---------------------------------------------------------------\n-- %s(%s)\n-- ---------------------------------------------------------------\n%s;\n',
      p.proname,
      pg_get_function_identity_arguments(p.oid),
      pg_get_functiondef(p.oid)
    ),
    E'\n' ORDER BY p.proname, p.oid
  ), '')
  FROM pg_proc p
  JOIN pg_namespace n ON n.oid = p.pronamespace
  WHERE n.nspname = 'public' AND p.prokind IN ('f','p');
$function$
;

-- ---------------------------------------------------------------
-- fill_customer_credit_fx_from_source()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fill_customer_credit_fx_from_source()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_currency text;
  v_rate numeric(18,8);
  v_rate_id uuid;
  v_amount_base numeric;
BEGIN
  -- Skip when caller has already filled the columns (any non-default value).
  IF NEW.original_currency IS NOT NULL
     AND NEW.original_currency <> ''
     AND NEW.original_currency <> 'EGP' THEN
    -- Caller specified a non-base currency explicitly; trust it.
    NEW.exchange_rate_used := COALESCE(NEW.exchange_rate_used, 1);
    NEW.original_amount := COALESCE(NEW.original_amount, NEW.amount);
    RETURN NEW;
  END IF;

  -- Detect by reference_type.
  IF NEW.reference_type IN ('payment', 'overpayment', 'customer_payment') THEN
    SELECT currency_code, exchange_rate, exchange_rate_id
    INTO v_currency, v_rate, v_rate_id
    FROM payments WHERE id = NEW.reference_id;
  ELSIF NEW.reference_type IN ('sales_return', 'refund') THEN
    SELECT original_currency, exchange_rate_used, exchange_rate_id
    INTO v_currency, v_rate, v_rate_id
    FROM sales_returns WHERE id = NEW.reference_id;
  END IF;

  v_currency := COALESCE(v_currency, 'EGP');
  v_rate := COALESCE(NULLIF(v_rate, 0), 1);

  NEW.original_currency := COALESCE(NEW.original_currency, v_currency);
  NEW.exchange_rate_used := COALESCE(NEW.exchange_rate_used, v_rate);
  NEW.exchange_rate_id := COALESCE(NEW.exchange_rate_id, v_rate_id);
  NEW.original_amount := COALESCE(
    NEW.original_amount,
    CASE WHEN v_currency = 'EGP' THEN NEW.amount
         ELSE ROUND(NEW.amount / NULLIF(v_rate, 0), 4) END
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- fill_customer_credit_ledger_fx_from_source()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fill_customer_credit_ledger_fx_from_source()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_currency text;
  v_rate numeric(18,8);
  v_rate_id uuid;
BEGIN
  IF NEW.original_currency IS NOT NULL
     AND NEW.original_currency <> ''
     AND NEW.original_currency <> 'EGP' THEN
    NEW.exchange_rate_used := COALESCE(NEW.exchange_rate_used, 1);
    NEW.original_amount := COALESCE(NEW.original_amount, NEW.amount);
    RETURN NEW;
  END IF;

  SELECT original_currency, exchange_rate_used, exchange_rate_id
  INTO v_currency, v_rate, v_rate_id
  FROM customer_credits WHERE id = NEW.source_id;

  v_currency := COALESCE(v_currency, 'EGP');
  v_rate := COALESCE(NULLIF(v_rate, 0), 1);

  NEW.original_currency := COALESCE(NEW.original_currency, v_currency);
  NEW.exchange_rate_used := COALESCE(NEW.exchange_rate_used, v_rate);
  NEW.exchange_rate_id := COALESCE(NEW.exchange_rate_id, v_rate_id);
  NEW.original_amount := COALESCE(
    NEW.original_amount,
    CASE WHEN v_currency = 'EGP' THEN NEW.amount
         ELSE ROUND(NEW.amount / NULLIF(v_rate, 0), 4) END
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- fill_vendor_credit_fx_from_source()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fill_vendor_credit_fx_from_source()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_currency text;
  v_rate numeric(18,8);
  v_rate_id uuid;
BEGIN
  IF NEW.original_currency IS NOT NULL
     AND NEW.original_currency <> ''
     AND NEW.original_currency <> 'EGP' THEN
    NEW.exchange_rate_used := COALESCE(NEW.exchange_rate_used, 1);
    NEW.original_total_amount := COALESCE(NEW.original_total_amount, NEW.total_amount);
    NEW.original_subtotal := COALESCE(NEW.original_subtotal, NEW.subtotal);
    NEW.original_tax_amount := COALESCE(NEW.original_tax_amount, NEW.tax_amount);
    RETURN NEW;
  END IF;

  IF NEW.source_purchase_return_id IS NOT NULL THEN
    SELECT original_currency, exchange_rate_used, exchange_rate_id
    INTO v_currency, v_rate, v_rate_id
    FROM purchase_returns WHERE id = NEW.source_purchase_return_id;
  END IF;
  IF v_currency IS NULL AND NEW.bill_id IS NOT NULL THEN
    SELECT currency_code, exchange_rate, NULL::uuid
    INTO v_currency, v_rate, v_rate_id
    FROM bills WHERE id = NEW.bill_id;
  END IF;

  v_currency := COALESCE(v_currency, 'EGP');
  v_rate := COALESCE(NULLIF(v_rate, 0), 1);

  NEW.original_currency := COALESCE(NEW.original_currency, v_currency);
  NEW.exchange_rate_used := COALESCE(NEW.exchange_rate_used, v_rate);
  NEW.exchange_rate_id := COALESCE(NEW.exchange_rate_id, v_rate_id);
  NEW.original_subtotal := COALESCE(NEW.original_subtotal,
    CASE WHEN v_currency = 'EGP' THEN NEW.subtotal
         ELSE ROUND(NEW.subtotal / NULLIF(v_rate, 0), 4) END);
  NEW.original_tax_amount := COALESCE(NEW.original_tax_amount,
    CASE WHEN v_currency = 'EGP' THEN NEW.tax_amount
         ELSE ROUND(NEW.tax_amount / NULLIF(v_rate, 0), 4) END);
  NEW.original_total_amount := COALESCE(NEW.original_total_amount,
    CASE WHEN v_currency = 'EGP' THEN NEW.total_amount
         ELSE ROUND(NEW.total_amount / NULLIF(v_rate, 0), 4) END);

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- find_company_accounts(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.find_company_accounts(p_company_id uuid)
 RETURNS TABLE(ar_account_id uuid, ap_account_id uuid, revenue_account_id uuid, expense_account_id uuid, cash_account_id uuid, bank_account_id uuid, vat_payable_account_id uuid, shipping_account_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    -- AR (Accounts Receivable)
    (SELECT id FROM chart_of_accounts 
     WHERE company_id = p_company_id 
     AND sub_type = 'accounts_receivable' 
     AND is_active = true 
     LIMIT 1) as ar_account_id,
    
    -- AP (Accounts Payable)
    (SELECT id FROM chart_of_accounts 
     WHERE company_id = p_company_id 
     AND sub_type = 'accounts_payable' 
     AND is_active = true 
     LIMIT 1) as ap_account_id,
    
    -- Revenue
    (SELECT id FROM chart_of_accounts 
     WHERE company_id = p_company_id 
     AND account_type = 'income' 
     AND is_active = true 
     ORDER BY account_code 
     LIMIT 1) as revenue_account_id,
    
    -- Expense
    (SELECT id FROM chart_of_accounts 
     WHERE company_id = p_company_id 
     AND account_type = 'expense' 
     AND is_active = true 
     ORDER BY account_code 
     LIMIT 1) as expense_account_id,
    
    -- Cash
    (SELECT id FROM chart_of_accounts 
     WHERE company_id = p_company_id 
     AND sub_type = 'cash' 
     AND is_active = true 
     LIMIT 1) as cash_account_id,
    
    -- Bank
    (SELECT id FROM chart_of_accounts 
     WHERE company_id = p_company_id 
     AND sub_type IN ('bank', 'checking', 'savings') 
     AND is_active = true 
     LIMIT 1) as bank_account_id,
    
    -- VAT Payable
    (SELECT id FROM chart_of_accounts 
     WHERE company_id = p_company_id 
     AND (account_name ILIKE '%vat%' OR account_name ILIKE '%ضريبة%' OR account_name ILIKE '%tax%')
     AND account_type = 'liability'
     AND is_active = true 
     LIMIT 1) as vat_payable_account_id,
    
    -- Shipping
    (SELECT id FROM chart_of_accounts 
     WHERE company_id = p_company_id 
     AND (account_name ILIKE '%shipping%' OR account_name ILIKE '%شحن%' OR account_name ILIKE '%freight%')
     AND is_active = true 
     LIMIT 1) as shipping_account_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- find_duplicate_journal_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.find_duplicate_journal_entries(p_company_id uuid)
 RETURNS TABLE(reference_type text, reference_id uuid, count bigint)
 LANGUAGE plpgsql
AS $function$ BEGIN RETURN QUERY SELECT je.reference_type::TEXT, je.reference_id, COUNT(*)::BIGINT as count FROM journal_entries je WHERE je.company_id = p_company_id AND (je.is_deleted IS NULL OR je.is_deleted = false) AND je.reference_type IN ('invoice', 'invoice_cogs', 'bill', 'expense') GROUP BY je.reference_type, je.reference_id HAVING COUNT(*) > 1; END; $function$
;

-- ---------------------------------------------------------------
-- find_payment_account(p_company_id uuid, p_account_name_pattern text, p_account_code_pattern text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.find_payment_account(p_company_id uuid, p_account_name_pattern text, p_account_code_pattern text)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_account_id UUID;
BEGIN
    -- البحث أولاً بالكود إذا كان موجوداً
    IF p_account_code_pattern IS NOT NULL THEN
        SELECT id INTO v_account_id
        FROM chart_of_accounts
        WHERE company_id = p_company_id
          AND account_code = p_account_code_pattern
          AND (account_type = 'asset' OR account_type IS NULL)
        LIMIT 1;
        
        IF v_account_id IS NOT NULL THEN
            RETURN v_account_id;
        END IF;
    END IF;
    
    -- البحث بالاسم
    SELECT id INTO v_account_id
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND (
          account_name ILIKE '%' || p_account_name_pattern || '%'
          OR account_name ILIKE '%' || REPLACE(p_account_name_pattern, ' ', '%') || '%'
      )
      AND (account_type = 'asset' OR account_type IS NULL)
    ORDER BY 
        CASE 
            WHEN account_name ILIKE '%' || p_account_name_pattern || '%' THEN 1
            ELSE 2
        END,
        account_code
    LIMIT 1;
    
    RETURN v_account_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- find_unbalanced_journal_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.find_unbalanced_journal_entries(p_company_id uuid)
 RETURNS TABLE(journal_entry_id uuid, entry_number text, entry_date date, reference_type text, total_debit numeric, total_credit numeric, difference numeric)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT
    je.id                                                  AS journal_entry_id,
    je.entry_number,
    je.entry_date,
    je.reference_type,
    ROUND(COALESCE(SUM(jel.debit_amount),  0)::NUMERIC, 4) AS total_debit,
    ROUND(COALESCE(SUM(jel.credit_amount), 0)::NUMERIC, 4) AS total_credit,
    ROUND(ABS(
      COALESCE(SUM(jel.debit_amount),  0) -
      COALESCE(SUM(jel.credit_amount), 0)
    )::NUMERIC, 4)                                         AS difference
  FROM public.journal_entries je
  LEFT JOIN public.journal_entry_lines jel
         ON jel.journal_entry_id = je.id
  WHERE je.company_id = p_company_id
    AND je.status     = 'posted'
    AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
    AND je.deleted_at IS NULL
  GROUP BY je.id, je.entry_number, je.entry_date, je.reference_type
  HAVING ABS(
    COALESCE(SUM(jel.debit_amount),  0) -
    COALESCE(SUM(jel.credit_amount), 0)
  ) > 0.01
  ORDER BY difference DESC;
$function$
;

-- ---------------------------------------------------------------
-- find_user_by_login(p_login text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.find_user_by_login(p_login text)
 RETURNS TABLE(user_id uuid, email text, username text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    u.id AS user_id,
    u.email::TEXT,
    up.username
  FROM auth.users u
  LEFT JOIN user_profiles up ON u.id = up.user_id
  WHERE
    LOWER(u.email) = LOWER(p_login) OR
    LOWER(up.username) = LOWER(p_login)
  LIMIT 1;
END;
$function$
;

-- ---------------------------------------------------------------
-- fix_accrual_accounting_data(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fix_accrual_accounting_data(p_company_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_result TEXT := '';
  v_count INTEGER := 0;
BEGIN
  v_result := 'بدء إصلاح البيانات لتطبيق أساس الاستحقاق...' || E'\n';

  -- التحقق من وجود الحسابات الأساسية
  IF NOT EXISTS (
    SELECT 1 FROM chart_of_accounts 
    WHERE company_id = p_company_id AND sub_type = 'accounts_receivable'
  ) THEN
    v_result := v_result || '❌ حساب العملاء غير موجود' || E'\n';
    RETURN v_result || 'يرجى إنشاء الحسابات الأساسية أولاً';
  END IF;

  -- عد الفواتير المرسلة بدون قيود محاسبية
  SELECT COUNT(*) INTO v_count
  FROM invoices i
  WHERE i.company_id = p_company_id
    AND i.status != 'draft'
    AND NOT EXISTS (
      SELECT 1 FROM journal_entries je 
      WHERE je.reference_type = 'invoice' 
        AND je.reference_id = i.id
        AND je.company_id = p_company_id
    );

  v_result := v_result || 'عدد الفواتير التي تحتاج إصلاح: ' || v_count || E'\n';
  v_result := v_result || '✅ النظام جاهز للعمل على أساس الاستحقاق' || E'\n';
  v_result := v_result || 'تم الانتهاء من فحص البيانات بنجاح!';

  RETURN v_result;
END;
$function$
;

-- ---------------------------------------------------------------
-- fix_all_historical_cogs()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fix_all_historical_cogs()
 RETURNS TABLE(comp_id uuid, fixed_invoices integer, total_cogs_amount numeric, status text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  company_record RECORD;
  invoice_record RECORD;
  item_record RECORD;
  v_cogs_amount NUMERIC;
  v_inventory_account_id UUID;
  v_cogs_account_id UUID;
  v_journal_entry_id UUID;
  fixed_count INTEGER := 0;
  total_cogs NUMERIC := 0;
BEGIN
  FOR company_record IN SELECT DISTINCT c.id, c.name FROM companies c LOOP
    SELECT coa.id INTO v_inventory_account_id FROM chart_of_accounts coa
    WHERE coa.company_id = company_record.id AND coa.sub_type = 'inventory' 
    AND (coa.parent_id IS NOT NULL OR coa.level > 1) LIMIT 1;

    SELECT coa.id INTO v_cogs_account_id FROM chart_of_accounts coa
    WHERE coa.company_id = company_record.id 
    AND (coa.sub_type = 'cost_of_goods_sold' OR coa.sub_type = 'cogs' OR coa.account_code = '5000')
    AND (coa.parent_id IS NOT NULL OR coa.level > 1) LIMIT 1;

    IF v_inventory_account_id IS NULL OR v_cogs_account_id IS NULL THEN CONTINUE; END IF;

    FOR invoice_record IN 
      SELECT i.id, i.invoice_number, i.invoice_date FROM invoices i
      WHERE i.company_id = company_record.id AND i.status IN ('partially_paid', 'paid')
        AND NOT EXISTS (SELECT 1 FROM journal_entries je WHERE je.reference_id = i.id AND je.reference_type = 'invoice_cogs')
    LOOP
      v_cogs_amount := 0;
      
      FOR item_record IN
        SELECT ii.quantity, p.cost_price FROM invoice_items ii
        JOIN products p ON ii.product_id = p.id WHERE ii.invoice_id = invoice_record.id
          AND p.item_type != 'service' AND COALESCE(p.cost_price, 0) > 0
      LOOP
        v_cogs_amount := v_cogs_amount + (item_record.quantity * COALESCE(item_record.cost_price, 0));
      END LOOP;

      IF v_cogs_amount > 0 THEN
        INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description) VALUES (
          company_record.id, 'invoice_cogs', invoice_record.id, invoice_record.invoice_date,
          'COGS Fix - ' || invoice_record.invoice_number
        ) RETURNING id INTO v_journal_entry_id;

        INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
        (v_journal_entry_id, v_cogs_account_id, v_cogs_amount, 0, 'COGS'),
        (v_journal_entry_id, v_inventory_account_id, 0, v_cogs_amount, 'Inventory');

        UPDATE inventory_transactions SET journal_entry_id = v_journal_entry_id
        WHERE reference_id = invoice_record.id AND transaction_type = 'sale' AND journal_entry_id IS NULL;

        fixed_count := fixed_count + 1;
        total_cogs := total_cogs + v_cogs_amount;
      END IF;
    END LOOP;

    RETURN QUERY SELECT company_record.id, fixed_count, total_cogs, 
      CASE WHEN fixed_count > 0 THEN 'Fixed' ELSE 'No Fix Needed' END;
    
    fixed_count := 0; total_cogs := 0;
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- fix_cogs_clean()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fix_cogs_clean()
 RETURNS TABLE(invoice_id uuid, invoice_number text, correct_cogs numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  invoice_record RECORD;
  v_cogs_amount NUMERIC;
  v_inventory_account_id UUID;
  v_cogs_account_id UUID;
  v_journal_entry_id UUID;
BEGIN
  FOR invoice_record IN 
    SELECT i.id, i.invoice_number, i.invoice_date, i.company_id
    FROM invoices i
    WHERE i.status IN ('partially_paid', 'paid')
      AND NOT EXISTS (SELECT 1 FROM journal_entries je WHERE je.reference_id = i.id AND je.reference_type = 'invoice_cogs')
  LOOP
    SELECT coa.id INTO v_inventory_account_id FROM chart_of_accounts coa
    WHERE coa.company_id = invoice_record.company_id AND coa.sub_type = 'inventory' LIMIT 1;

    SELECT coa.id INTO v_cogs_account_id FROM chart_of_accounts coa
    WHERE coa.company_id = invoice_record.company_id AND (coa.sub_type = 'cogs' OR coa.account_code = '5000') LIMIT 1;

    IF v_inventory_account_id IS NULL OR v_cogs_account_id IS NULL THEN CONTINUE; END IF;

    SELECT SUM(ii.quantity * COALESCE(p.cost_price, 0)) INTO v_cogs_amount
    FROM invoice_items ii
    JOIN products p ON ii.product_id = p.id
    WHERE ii.invoice_id = invoice_record.id AND p.item_type != 'service';

    IF COALESCE(v_cogs_amount, 0) > 0 THEN
      INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description) 
      VALUES (invoice_record.company_id, 'invoice_cogs', invoice_record.id, invoice_record.invoice_date, 'COGS - ' || invoice_record.invoice_number) 
      RETURNING id INTO v_journal_entry_id;

      INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
      (v_journal_entry_id, v_cogs_account_id, v_cogs_amount, 0, 'COGS'),
      (v_journal_entry_id, v_inventory_account_id, 0, v_cogs_amount, 'Inventory');

      RETURN QUERY SELECT invoice_record.id, invoice_record.invoice_number, v_cogs_amount;
    END IF;
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- fix_historical_cogs(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fix_historical_cogs(p_company_id uuid)
 RETURNS TABLE(invoice_id uuid, invoice_number text, cogs_amount numeric, journal_entry_id uuid, status text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_transaction RECORD;
  v_product_cost NUMERIC;
  v_cogs_amount NUMERIC;
  v_inventory_account_id UUID;
  v_cogs_account_id UUID;
  v_journal_entry_id UUID;
  v_invoice_number TEXT;
  v_invoice_date DATE;
  v_existing_cogs UUID;
BEGIN
  -- الحصول على حسابات المخزون و COGS
  SELECT id INTO v_inventory_account_id 
  FROM chart_of_accounts 
  WHERE company_id = p_company_id 
    AND sub_type = 'inventory' 
    AND (parent_id IS NOT NULL OR level > 1)
  LIMIT 1;

  SELECT id INTO v_cogs_account_id 
  FROM chart_of_accounts 
  WHERE company_id = p_company_id 
    AND (sub_type = 'cost_of_goods_sold' OR sub_type = 'cogs' OR account_code = '5000')
    AND (parent_id IS NOT NULL OR level > 1)
  LIMIT 1;

  -- إذا لم نجد الحسابات، نتوقف
  IF v_inventory_account_id IS NULL OR v_cogs_account_id IS NULL THEN
    RAISE EXCEPTION 'COGS accounts not found for company %', p_company_id;
  END IF;

  -- معالجة جميع معاملات البيع التي ليس لها قيد COGS
  FOR v_transaction IN 
    SELECT 
      it.id,
      it.product_id,
      it.quantity_change,
      it.reference_id,
      it.branch_id,
      it.cost_center_id,
      p.cost_price,
      p.item_type
    FROM inventory_transactions it
    JOIN products p ON it.product_id = p.id
    WHERE it.company_id = p_company_id
      AND it.transaction_type = 'sale'
      AND p.item_type != 'service'
      AND it.journal_entry_id IS NULL -- ليس لها قيد COGS
    ORDER BY it.created_at
  LOOP
    -- حساب قيمة COGS
    v_cogs_amount := ABS(v_transaction.quantity_change) * COALESCE(v_transaction.cost_price, 0);
    
    -- تجاهل إذا كانت التكلفة = 0
    IF v_cogs_amount = 0 THEN
      CONTINUE;
    END IF;

    -- التحقق من عدم وجود قيد COGS سابق
    SELECT id INTO v_existing_cogs
    FROM journal_entries
    WHERE company_id = p_company_id
      AND reference_type = 'invoice_cogs'
      AND reference_id = v_transaction.reference_id
    LIMIT 1;

    IF v_existing_cogs IS NOT NULL THEN
      -- قيد موجود بالفعل، نتخطى
      CONTINUE;
    END IF;

    -- الحصول على معلومات الفاتورة
    SELECT invoice_number, invoice_date 
    INTO v_invoice_number, v_invoice_date
    FROM invoices 
    WHERE id = v_transaction.reference_id;

    -- إنشاء قيد COGS
    INSERT INTO journal_entries (
      company_id,
      reference_type,
      reference_id,
      entry_date,
      description,
      branch_id,
      cost_center_id
    ) VALUES (
      p_company_id,
      'invoice_cogs',
      v_transaction.reference_id,
      COALESCE(v_invoice_date, CURRENT_DATE),
      'تكلفة البضاعة المباعة (تصحيح) - ' || COALESCE(v_invoice_number, 'فاتورة'),
      v_transaction.branch_id,
      v_transaction.cost_center_id
    ) RETURNING id INTO v_journal_entry_id;

    -- سطور القيد
    INSERT INTO journal_entry_lines (
      journal_entry_id,
      account_id,
      debit_amount,
      credit_amount,
      description
    ) VALUES 
    (
      v_journal_entry_id,
      v_cogs_account_id,
      v_cogs_amount,
      0,
      'تكلفة البضاعة المباعة'
    ),
    (
      v_journal_entry_id,
      v_inventory_account_id,
      0,
      v_cogs_amount,
      'خصم من المخزون'
    );

    -- تحديث حركة المخزون لربطها بالقيد
    UPDATE inventory_transactions
    SET journal_entry_id = v_journal_entry_id
    WHERE id = v_transaction.id;

    -- إرجاع النتيجة
    RETURN QUERY SELECT 
      v_transaction.reference_id,
      v_invoice_number,
      v_cogs_amount,
      v_journal_entry_id,
      'created'::TEXT;
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- fix_missing_cogs_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fix_missing_cogs_entries(p_company_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_fixed_count INTEGER := 0;
  v_invoice RECORD;
  v_cogs_amount NUMERIC;
  v_inventory_account_id UUID;
  v_cogs_account_id UUID;
  v_journal_entry_id UUID;
BEGIN
  SELECT id INTO v_inventory_account_id 
  FROM chart_of_accounts 
  WHERE company_id = p_company_id 
    AND sub_type = 'inventory' 
    AND (parent_id IS NOT NULL OR level > 1)
  LIMIT 1;

  SELECT id INTO v_cogs_account_id 
  FROM chart_of_accounts 
  WHERE company_id = p_company_id 
    AND sub_type IN ('cost_of_goods_sold', 'cogs')
    AND (parent_id IS NOT NULL OR level > 1)
  LIMIT 1;

  IF v_inventory_account_id IS NULL OR v_cogs_account_id IS NULL THEN
    RAISE EXCEPTION 'لم يتم العثور على حسابات المخزون أو COGS';
  END IF;

  FOR v_invoice IN
    SELECT 
      i.id,
      i.invoice_number,
      i.invoice_date,
      i.branch_id,
      COALESCE((
        SELECT SUM(ii.quantity * p.cost_price)
        FROM invoice_items ii
        JOIN products p ON ii.product_id = p.id
        WHERE ii.invoice_id = i.id AND p.item_type != 'service'
      ), 0) as cogs_amount
    FROM invoices i
    WHERE i.company_id = p_company_id
      AND i.status NOT IN ('draft', 'cancelled')
      AND NOT EXISTS(
        SELECT 1 FROM journal_entries je 
        WHERE je.reference_type = 'invoice_cogs' AND je.reference_id = i.id
      )
  LOOP
    IF v_invoice.cogs_amount > 0 THEN
      INSERT INTO journal_entries (
        company_id, reference_type, reference_id, entry_date, description,
        branch_id, status
      ) VALUES (
        p_company_id, 'invoice_cogs', v_invoice.id, v_invoice.invoice_date,
        'تكلفة البضاعة المباعة - ' || v_invoice.invoice_number,
        v_invoice.branch_id, 'posted'
      ) RETURNING id INTO v_journal_entry_id;

      INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
      VALUES 
      (v_journal_entry_id, v_cogs_account_id, v_invoice.cogs_amount, 0, 'تكلفة البضاعة المباعة'),
      (v_journal_entry_id, v_inventory_account_id, 0, v_invoice.cogs_amount, 'خصم من المخزون');

      v_fixed_count := v_fixed_count + 1;
    END IF;
  END LOOP;

  RETURN v_fixed_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- fix_unbalanced_journal_entries_safe(p_company_id uuid, p_limit integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fix_unbalanced_journal_entries_safe(p_company_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 50)
 RETURNS TABLE(journal_entry_id uuid, issue text, fix_applied text, status text)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_entry RECORD;
  v_difference DECIMAL(15, 2);
  v_suspense_account_id UUID;
  v_processed INTEGER := 0;
BEGIN
  -- الحصول على حساب التسوية
  SELECT id INTO v_suspense_account_id
  FROM chart_of_accounts
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
    AND (account_name ILIKE '%تسوية%' OR account_name ILIKE '%suspense%')
  LIMIT 1;

  -- معالجة القيود غير المتوازنة مع LIMIT
  FOR v_entry IN
    SELECT 
      je.id,
      je.company_id,
      COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0) AS difference
    FROM journal_entries je
    LEFT JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE (p_company_id IS NULL OR je.company_id = p_company_id)
    GROUP BY je.id, je.company_id
    HAVING ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) > 0.01
    LIMIT p_limit -- حد آمن
  LOOP
    v_difference := v_entry.difference;
    
    -- إنشاء حساب التسوية إذا لم يكن موجوداً
    IF v_suspense_account_id IS NULL THEN
      INSERT INTO chart_of_accounts (
        company_id, account_code, account_name, account_type, 
        sub_type, description, is_active
      ) VALUES (
        v_entry.company_id, '9999', 'حساب التسوية - Suspense Account', 'asset',
        'other_current_asset', 'حساب مؤقت لتسوية القيود غير المتوازنة', true
      ) RETURNING id INTO v_suspense_account_id;
    END IF;

    -- إضافة سطر تسوية
    IF v_difference > 0 THEN
      INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, credit_amount, debit_amount, description
      ) VALUES (
        v_entry.id, v_suspense_account_id, v_difference, 0,
        'تسوية تلقائية آمنة - Safe auto adjustment'
      );
    ELSE
      INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, debit_amount, credit_amount, description
      ) VALUES (
        v_entry.id, v_suspense_account_id, ABS(v_difference), 0,
        'تسوية تلقائية آمنة - Safe auto adjustment'
      );
    END IF;

    v_processed := v_processed + 1;

    RETURN QUERY SELECT 
      v_entry.id,
      'Unbalanced by ' || v_difference,
      'Added adjustment line',
      'completed'::TEXT;
      
    -- خروج آمن بعد المعالجة
    IF v_processed >= p_limit THEN
      EXIT;
    END IF;
  END LOOP;
  
  RETURN;
END;
$function$
;

-- ---------------------------------------------------------------
-- fix_wrong_return_account_entries(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fix_wrong_return_account_entries(p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ DECLARE v_fixed_count INTEGER := 0; v_ar_account_id UUID; BEGIN SELECT id INTO v_ar_account_id FROM chart_of_accounts WHERE company_id = p_company_id AND sub_type = 'accounts_receivable' LIMIT 1; IF v_ar_account_id IS NULL THEN RETURN jsonb_build_object('success', false, 'error', 'AR account not found'); END IF; UPDATE journal_entry_lines jel SET account_id = v_ar_account_id, description = 'إلغاء الذمم المدينة - مرتجع' WHERE jel.journal_entry_id IN ( SELECT je.id FROM journal_entries je JOIN invoices i ON je.reference_id = i.id JOIN journal_entry_lines jel2 ON jel2.journal_entry_id = je.id JOIN chart_of_accounts ca ON jel2.account_id = ca.id WHERE je.company_id = p_company_id AND je.reference_type = 'sales_return' AND i.paid_amount = 0 AND ca.sub_type = 'customer_credit' AND jel2.credit_amount > 0 ) AND jel.credit_amount > 0; GET DIAGNOSTICS v_fixed_count = ROW_COUNT; RETURN jsonb_build_object('success', true, 'fixed_count', v_fixed_count); END; $function$
;

-- ---------------------------------------------------------------
-- fn_check_journal_balance()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_check_journal_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  total_debit DECIMAL(15,2);
  total_credit DECIMAL(15,2);
  diff DECIMAL(15,2);
BEGIN
  -- حساب إجمالي المدين والدائن للقيد
  SELECT 
    COALESCE(SUM(debit_amount), 0),
    COALESCE(SUM(credit_amount), 0)
  INTO total_debit, total_credit
  FROM journal_entry_lines
  WHERE journal_entry_id = NEW.journal_entry_id;
  
  diff := ABS(total_debit - total_credit);
  
  -- السماح بفرق بسيط للتقريب
  IF diff > 0.01 AND total_debit > 0 AND total_credit > 0 THEN
    RAISE WARNING 'تحذير: القيد % غير متوازن - مدين: %, دائن: %, الفرق: %', 
      NEW.journal_entry_id, total_debit, total_credit, diff;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- fn_recalc_bill_paid_status(p_bill_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_recalc_bill_paid_status(p_bill_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total NUMERIC;
  v_returned NUMERIC;
  v_paid NUMERIC;
  v_net NUMERIC;
  v_new_status TEXT;
  v_bill_currency TEXT;
  v_bill_rate NUMERIC;
BEGIN
  SELECT
    COALESCE(b.total_amount, 0),
    COALESCE(b.returned_amount, 0),
    UPPER(COALESCE(b.currency_code, '')),
    COALESCE(NULLIF(b.exchange_rate, 0), 1)
  INTO v_total, v_returned, v_bill_currency, v_bill_rate
  FROM bills b WHERE b.id = p_bill_id;

  v_paid := COALESCE(
    (SELECT SUM(
      pa.allocated_amount *
      CASE
        WHEN v_bill_currency = '' OR UPPER(COALESCE(p.currency_code, '')) = '' THEN 1
        WHEN UPPER(p.currency_code) = v_bill_currency THEN 1
        ELSE COALESCE(NULLIF(p.exchange_rate, 0), 1) / v_bill_rate
      END
     )
     FROM payment_allocations pa
     JOIN payments p ON p.id = pa.payment_id
     WHERE pa.bill_id = p_bill_id
       AND p.status = 'approved'
       AND COALESCE(p.is_deleted, false) = false
       AND p.voided_at IS NULL
       AND p.voids_payment_id IS NULL
    ), 0
  )
  +
  COALESCE(
    (SELECT SUM(
      p2.amount *
      CASE
        WHEN v_bill_currency = '' OR UPPER(COALESCE(p2.currency_code, '')) = '' THEN 1
        WHEN UPPER(p2.currency_code) = v_bill_currency THEN 1
        ELSE COALESCE(NULLIF(p2.exchange_rate, 0), 1) / v_bill_rate
      END
     )
     FROM payments p2
     WHERE p2.bill_id = p_bill_id
       AND p2.status = 'approved'
       AND COALESCE(p2.is_deleted, false) = false
       AND p2.voided_at IS NULL
       AND p2.voids_payment_id IS NULL
       AND NOT EXISTS (
         SELECT 1 FROM payment_allocations pa2
         WHERE pa2.payment_id = p2.id AND pa2.bill_id = p_bill_id
       )
    ), 0
  );

  v_paid := ROUND(v_paid::numeric, 4);
  v_net := GREATEST(v_total - v_returned, 0);

  v_new_status := CASE
    WHEN v_paid <= 0 THEN 'received'
    WHEN v_paid >= v_net - 0.01 THEN 'paid'
    ELSE 'partially_paid'
  END;

  UPDATE public.bills
  SET paid_amount = v_paid, status = v_new_status, updated_at = NOW()
  WHERE id = p_bill_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- fn_recalc_invoice_paid_status(p_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_recalc_invoice_paid_status(p_invoice_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total          NUMERIC;
  v_returned       NUMERIC;
  v_paid           NUMERIC;
  v_net            NUMERIC;
  v_new_status     TEXT;
  v_inv_currency   TEXT;
  v_inv_rate       NUMERIC;
BEGIN
  SELECT
    COALESCE(i.total_amount, 0),
    COALESCE(i.returned_amount, 0),
    UPPER(COALESCE(i.currency_code, '')),
    COALESCE(NULLIF(i.exchange_rate, 0), 1)
  INTO v_total, v_returned, v_inv_currency, v_inv_rate
  FROM invoices i WHERE i.id = p_invoice_id;

  v_paid := COALESCE(
    (SELECT SUM(
      pa.allocated_amount *
      CASE
        WHEN v_inv_currency = '' OR UPPER(COALESCE(p.currency_code, '')) = '' THEN 1
        WHEN UPPER(p.currency_code) = v_inv_currency THEN 1
        ELSE COALESCE(NULLIF(p.exchange_rate, 0), 1) / v_inv_rate
      END
     )
     FROM payment_allocations pa
     JOIN payments p ON p.id = pa.payment_id
     WHERE pa.invoice_id = p_invoice_id
       AND p.status = 'approved'
       AND COALESCE(p.is_deleted, false) = false
       AND p.voided_at IS NULL
       AND p.voids_payment_id IS NULL
    ), 0
  )
  +
  COALESCE(
    (SELECT SUM(
      p2.amount *
      CASE
        WHEN v_inv_currency = '' OR UPPER(COALESCE(p2.currency_code, '')) = '' THEN 1
        WHEN UPPER(p2.currency_code) = v_inv_currency THEN 1
        ELSE COALESCE(NULLIF(p2.exchange_rate, 0), 1) / v_inv_rate
      END
     )
     FROM payments p2
     WHERE p2.invoice_id = p_invoice_id
       AND p2.status = 'approved'
       AND COALESCE(p2.is_deleted, false) = false
       AND p2.voided_at IS NULL
       AND p2.voids_payment_id IS NULL
       AND NOT EXISTS (
         SELECT 1 FROM payment_allocations pa2
         WHERE pa2.payment_id = p2.id AND pa2.invoice_id = p_invoice_id
       )
    ), 0
  );

  v_paid := ROUND(v_paid::numeric, 4);
  v_net  := GREATEST(v_total - v_returned, 0);

  v_new_status := CASE
    WHEN v_paid <= 0 THEN 'sent'
    WHEN v_paid >= v_net - 0.01 THEN 'paid'
    ELSE 'partially_paid'
  END;

  UPDATE public.invoices
  SET paid_amount = v_paid, status = v_new_status, updated_at = NOW()
  WHERE id = p_invoice_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- fn_user_company_ids()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_user_company_ids()
 RETURNS SETOF uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT DISTINCT company_id
  FROM company_members
  WHERE user_id = auth.uid();
$function$
;

-- ---------------------------------------------------------------
-- fn_validate_normal_balance()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.fn_validate_normal_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_is_contra BOOLEAN := false;
BEGIN
  -- Detect contra accounts via sub_type. These have a normal balance
  -- opposite to their parent account_type by design (IFRS-compliant).
  IF LOWER(COALESCE(NEW.sub_type, '')) = ANY (ARRAY[
    'allowance_doubtful',         -- 1131: contra-asset
    'accumulated_depreciation',   -- 1290: contra-asset
    'accumulated_amortization',   -- 1390: contra-asset
    'sales_returns',              -- 4110: contra-income
    'sales_discounts',            -- 4120: contra-income
    'purchase_returns',           -- 5120: contra-expense
    'purchase_discounts'          -- 5130: contra-expense
  ]) THEN
    v_is_contra := true;
  END IF;

  -- Legacy escape hatches kept for backward compatibility with rows
  -- that may have been created before sub_type was used:
  --   - 125x codes (historic accumulated-depreciation prefix)
  --   - any account whose name contains the Arabic or English word
  --     for "depreciation" or "amortization"
  IF NOT v_is_contra THEN
    IF NEW.account_code LIKE '125%'
       OR NEW.account_name ILIKE '%إهلاك%'
       OR NEW.account_name ILIKE '%إطفاء%'
       OR NEW.account_name ILIKE '%depreciation%'
       OR NEW.account_name ILIKE '%amortization%'
       OR NEW.account_name ILIKE '%مخصص%'   -- "provision/allowance"
       OR NEW.account_name ILIKE '%مردودات%' -- "returns" (sales/purchase)
       OR NEW.account_name ILIKE '%خصم%'    -- "discounts"
    THEN
      v_is_contra := true;
    END IF;
  END IF;

  IF v_is_contra THEN
    RETURN NEW;
  END IF;

  -- Normal accounts: enforce the IFRS natural balance rule.
  IF NEW.account_type IN ('asset', 'expense') AND NEW.normal_balance != 'debit' THEN
    RAISE EXCEPTION 'خطأ محاسبي: حسابات % يجب أن تكون طبيعتها debit', NEW.account_type;
  END IF;

  IF NEW.account_type IN ('liability', 'equity', 'income') AND NEW.normal_balance != 'credit' THEN
    RAISE EXCEPTION 'خطأ محاسبي: حسابات % يجب أن تكون طبيعتها credit', NEW.account_type;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- force_delete_all_depreciation_schedules(p_asset_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.force_delete_all_depreciation_schedules(p_asset_id uuid)
 RETURNS TABLE(deleted_schedules integer, deleted_journals integer, deleted_lines integer, asset_name text, asset_code text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_asset_id UUID;
  v_company_id UUID;
  v_asset_name TEXT;
  v_asset_code TEXT;
  v_deleted_schedules INTEGER := 0;
  v_deleted_journals INTEGER := 0;
  v_deleted_lines INTEGER := 0;
  v_pending_count INTEGER := 0;
  v_approved_count INTEGER := 0;
  v_posted_count INTEGER := 0;
  v_journal_entry_ids UUID[];
  v_orphaned_journal_ids UUID[];
  v_orphaned_count INTEGER := 0;
BEGIN
  -- =====================================
  -- 1. العثور على الأصل
  -- =====================================
  SELECT fa.id, fa.company_id, fa.name, fa.asset_code
  INTO v_asset_id, v_company_id, v_asset_name, v_asset_code
  FROM fixed_assets fa
  WHERE fa.id = p_asset_id
  LIMIT 1;

  IF v_asset_id IS NULL THEN
    RAISE EXCEPTION 'Asset with ID % not found', p_asset_id;
  END IF;

  RAISE NOTICE '✓ Found asset: % (Code: %, ID: %)', v_asset_name, v_asset_code, v_asset_id;

  -- =====================================
  -- 2. التحقق من جداول الإهلاك الموجودة
  -- =====================================
  SELECT COUNT(*) INTO v_pending_count
  FROM depreciation_schedules
  WHERE asset_id = v_asset_id AND status = 'pending';

  SELECT COUNT(*) INTO v_approved_count
  FROM depreciation_schedules
  WHERE asset_id = v_asset_id AND status = 'approved';

  SELECT COUNT(*) INTO v_posted_count
  FROM depreciation_schedules
  WHERE asset_id = v_asset_id AND status = 'posted';

  RAISE NOTICE '';
  RAISE NOTICE 'Current Depreciation Schedules:';
  RAISE NOTICE '  - Pending: %', v_pending_count;
  RAISE NOTICE '  - Approved: %', v_approved_count;
  RAISE NOTICE '  - Posted: %', v_posted_count;
  RAISE NOTICE '  - Total: %', (v_pending_count + v_approved_count + v_posted_count);

  -- =====================================
  -- 3. جمع journal_entry_ids المرتبطة بالإهلاك (مع التحقق من صحتها)
  -- =====================================
  -- جمع فقط القيود التي تتوافق مع قيود الإهلاك الفعلية
  -- هذا يمنع حذف سطور قيود غير متعلقة بالإهلاك
  SELECT ARRAY_AGG(DISTINCT ds.journal_entry_id)
  INTO v_journal_entry_ids
  FROM depreciation_schedules ds
  INNER JOIN journal_entries je ON ds.journal_entry_id = je.id
  WHERE ds.asset_id = v_asset_id
    AND ds.journal_entry_id IS NOT NULL
    AND je.reference_type = 'depreciation'
    AND je.reference_id = v_asset_id;

  -- جمع القيود المقطوعة (orphaned) للتنظيف
  SELECT ARRAY_AGG(DISTINCT ds.journal_entry_id), COUNT(DISTINCT ds.journal_entry_id)
  INTO v_orphaned_journal_ids, v_orphaned_count
  FROM depreciation_schedules ds
  LEFT JOIN journal_entries je ON ds.journal_entry_id = je.id
  WHERE ds.asset_id = v_asset_id
    AND ds.journal_entry_id IS NOT NULL
    AND (je.id IS NULL 
         OR je.reference_type != 'depreciation' 
         OR je.reference_id != v_asset_id);
  
  IF v_orphaned_count > 0 THEN
    RAISE WARNING '⚠ Found % orphaned journal entry references in depreciation schedules', v_orphaned_count;
    RAISE WARNING '⚠ These will be cleaned up (lines deleted, entries remain if not depreciation-related).';
  END IF;

  IF v_journal_entry_ids IS NOT NULL AND array_length(v_journal_entry_ids, 1) > 0 THEN
    RAISE NOTICE '✓ Found % verified depreciation journal entries', array_length(v_journal_entry_ids, 1);
  ELSE
    RAISE NOTICE '✓ No verified depreciation journal entries found';
  END IF;

  -- =====================================
  -- 4. حذف سطور القيود (journal_entry_lines) المرتبطة بالإهلاك
  -- =====================================
  -- حذف سطور القيود للقيود التي تم التحقق منها
  IF v_journal_entry_ids IS NOT NULL AND array_length(v_journal_entry_ids, 1) > 0 THEN
    DELETE FROM journal_entry_lines
    WHERE journal_entry_id = ANY(v_journal_entry_ids);
    
    GET DIAGNOSTICS v_deleted_lines = ROW_COUNT;
    RAISE NOTICE '✓ Deleted % journal entry lines from verified depreciation entries', v_deleted_lines;
  END IF;

  -- حذف سطور القيود المقطوعة (orphaned) أيضاً
  IF v_orphaned_journal_ids IS NOT NULL AND array_length(v_orphaned_journal_ids, 1) > 0 THEN
    DECLARE
      v_orphaned_lines_deleted INTEGER;
    BEGIN
      DELETE FROM journal_entry_lines
      WHERE journal_entry_id = ANY(v_orphaned_journal_ids);
      
      GET DIAGNOSTICS v_orphaned_lines_deleted = ROW_COUNT;
      IF v_orphaned_lines_deleted > 0 THEN
        RAISE NOTICE '✓ Deleted % journal entry lines from orphaned entries', v_orphaned_lines_deleted;
        v_deleted_lines := v_deleted_lines + v_orphaned_lines_deleted;
      END IF;
    EXCEPTION
      WHEN OTHERS THEN
        RAISE WARNING '⚠ Error deleting orphaned journal entry lines: %', SQLERRM;
    END;
  END IF;

  -- =====================================
  -- 5. حذف القيود المحاسبية (journal_entries) المرتبطة بالإهلاك
  -- =====================================
  -- حذف القيود التي تم التحقق منها مع فلاتر دفاعية إضافية
  -- الفلاتر الدفاعية تمنع حذف قيود غير متوقعة في حالة race conditions
  IF v_journal_entry_ids IS NOT NULL AND array_length(v_journal_entry_ids, 1) > 0 THEN
    DELETE FROM journal_entries
    WHERE id = ANY(v_journal_entry_ids)
      AND reference_type = 'depreciation'
      AND reference_id = v_asset_id;
    
    GET DIAGNOSTICS v_deleted_journals = ROW_COUNT;
    RAISE NOTICE '✓ Deleted % verified depreciation journal entries', v_deleted_journals;
    
    -- التحقق من أن عدد القيود المحذوفة يطابق العدد المتوقع
    IF v_deleted_journals != array_length(v_journal_entry_ids, 1) THEN
      RAISE WARNING '⚠ Expected to delete % journal entries, but deleted %. Please verify manually.', 
        array_length(v_journal_entry_ids, 1), v_deleted_journals;
    END IF;
  END IF;

  -- =====================================
  -- 6. حذف جميع جداول الإهلاك (بجميع الحالات)
  -- =====================================
  DELETE FROM depreciation_schedules
  WHERE asset_id = v_asset_id;
  
  GET DIAGNOSTICS v_deleted_schedules = ROW_COUNT;
  
  RAISE NOTICE '';
  RAISE NOTICE '✓ Deleted % depreciation schedules (ALL statuses)', v_deleted_schedules;

  -- =====================================
  -- 7. إعادة تعيين قيم الأصل
  -- =====================================
  UPDATE fixed_assets
  SET
    accumulated_depreciation = 0,
    book_value = purchase_cost,
    status = CASE 
      WHEN status = 'fully_depreciated' THEN 'active'
      ELSE status
    END,
    updated_at = CURRENT_TIMESTAMP
  WHERE id = v_asset_id;

  RAISE NOTICE '✓ Reset asset values: accumulated_depreciation = 0, book_value = purchase_cost';

  -- =====================================
  -- 8. ملخص العملية
  -- =====================================
  RAISE NOTICE '';
  RAISE NOTICE '========================================';
  RAISE NOTICE 'Summary - ملخص العملية';
  RAISE NOTICE '========================================';
  RAISE NOTICE 'Asset: % (%)', v_asset_name, v_asset_code;
  RAISE NOTICE 'Deleted Depreciation Schedules: %', v_deleted_schedules;
  RAISE NOTICE 'Deleted Journal Entries: %', v_deleted_journals;
  RAISE NOTICE 'Deleted Journal Entry Lines: %', v_deleted_lines;
  RAISE NOTICE 'Asset Status: Reset to initial values';
  RAISE NOTICE '========================================';
  RAISE NOTICE '';
  RAISE NOTICE '✓ All depreciation data deleted successfully!';
  RAISE NOTICE '';
  RAISE NOTICE 'Next Step: Use generate_depreciation_schedule() function';
  RAISE NOTICE '          to regenerate using the enhanced monthly depreciation system.';

  -- Return results
  RETURN QUERY SELECT 
    v_deleted_schedules,
    v_deleted_journals,
    v_deleted_lines,
    v_asset_name,
    v_asset_code;

EXCEPTION
  WHEN OTHERS THEN
    RAISE EXCEPTION 'Error deleting depreciation: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- gate_direct_sales_returns()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.gate_direct_sales_returns()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_role text;
BEGIN
  -- server-side executions (request-cycle RPCs, service role) pass
  IF v_uid IS NULL THEN RETURN NEW; END IF;

  SELECT cm.role INTO v_role
  FROM public.company_members cm
  WHERE cm.company_id = NEW.company_id AND cm.user_id = v_uid
  LIMIT 1;

  IF v_role IS NULL THEN
    RAISE EXCEPTION 'RETURN_FORBIDDEN: لست عضواً فى هذه الشركة';
  END IF;

  IF v_role NOT IN ('owner','general_manager') THEN
    RAISE EXCEPTION 'RETURN_FORBIDDEN: المرتجع المباشر من صفحة الفاتورة متاح للمالك والمدير العام فقط — استخدم دورة "طلب مرتجع مبيعات" (اعتماد إدارى ثم استلام مخزنى)';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- generate_accounting_audit_report(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.generate_accounting_audit_report(p_company_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(category text, issue_type text, issue_count bigint, details jsonb)
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    '1. المصدر الوحيد للأرصدة'::TEXT AS category,
    'قيود غير متوازنة'::TEXT AS issue_type,
    COUNT(*)::BIGINT AS issue_count,
    jsonb_agg(jsonb_build_object(
      'journal_entry_id', id,
      'entry_date', entry_date,
      'reference_type', reference_type,
      'difference', difference
    )) AS details
  FROM v_unbalanced_journal_entries
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '2. فواتير البيع'::TEXT,
    'فواتير بدون قيود'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'invoice_id', id,
      'invoice_number', invoice_number,
      'invoice_date', invoice_date,
      'total_amount', total_amount
    ))
  FROM v_invoices_without_journal_entries
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '2. فواتير البيع'::TEXT,
    'فواتير بدون حركات مخزون'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'invoice_id', id,
      'invoice_number', invoice_number
    ))
  FROM v_invoices_without_inventory_transactions
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '2. فواتير البيع'::TEXT AS category,
    'قيود فواتير غير صحيحة'::TEXT AS issue_type,
    COUNT(*)::BIGINT AS issue_count,
    jsonb_agg(jsonb_build_object(
      'journal_entry_id', v_inv.journal_entry_id,
      'invoice_id', v_inv.invoice_id,
      'invoice_number', v_inv.invoice_number,
      'issue_detail', v_inv.issue_type
    )) AS details
  FROM v_invalid_sales_invoice_journals v_inv
  WHERE (p_company_id IS NULL OR v_inv.company_id = p_company_id)
  GROUP BY 1, 2
  
  UNION ALL
  
  SELECT 
    '3. فواتير الشراء'::TEXT,
    'فواتير بدون قيود'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'bill_id', id,
      'bill_number', bill_number,
      'total_amount', total_amount
    ))
  FROM v_bills_without_journal_entries
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '3. فواتير الشراء'::TEXT AS category,
    'قيود فواتير غير صحيحة'::TEXT AS issue_type,
    COUNT(*)::BIGINT AS issue_count,
    jsonb_agg(jsonb_build_object(
      'journal_entry_id', v_bill.journal_entry_id,
      'bill_id', v_bill.bill_id,
      'bill_number', v_bill.bill_number,
      'issue_detail', v_bill.issue_type
    )) AS details
  FROM v_invalid_bill_journals v_bill
  WHERE (p_company_id IS NULL OR v_bill.company_id = p_company_id)
  GROUP BY 1, 2
  
  UNION ALL
  
  SELECT 
    '4. المرتجعات'::TEXT,
    'مرتجعات بيع بدون قيود'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'return_id', id,
      'return_number', return_number
    ))
  FROM v_sales_returns_without_journals
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '4. المرتجعات'::TEXT,
    'مرتجعات شراء بدون قيود'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'credit_id', id,
      'credit_number', credit_number
    ))
  FROM v_purchase_returns_without_journals
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '5. المدفوعات'::TEXT,
    'مدفوعات عملاء بدون قيود'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'payment_id', id,
      'invoice_number', invoice_number,
      'amount', amount
    ))
  FROM v_customer_payments_without_journals
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '5. المدفوعات'::TEXT,
    'مدفوعات موردين بدون قيود'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'payment_id', id,
      'bill_number', bill_number,
      'amount', amount
    ))
  FROM v_supplier_payments_without_journals
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '6. الهالك'::TEXT,
    'هالك بدون قيود'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'write_off_id', id,
      'write_off_number', write_off_number,
      'total_cost', total_cost
    ))
  FROM v_write_offs_without_journals
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '6. الهالك'::TEXT AS category,
    'قيود هالك غير صحيحة'::TEXT AS issue_type,
    COUNT(*)::BIGINT AS issue_count,
    jsonb_agg(jsonb_build_object(
      'journal_entry_id', v_wo.journal_entry_id,
      'write_off_number', v_wo.write_off_number,
      'issue_detail', v_wo.issue_type
    )) AS details
  FROM v_invalid_write_off_journals v_wo
  WHERE (p_company_id IS NULL OR v_wo.company_id = p_company_id)
  GROUP BY 1, 2
  
  UNION ALL
  
  SELECT 
    '7. الضرائب'::TEXT,
    'خلط VAT Output/Input'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'account_id', account_id,
      'account_name', account_name,
      'account_code', account_code,
      'journal_count', journal_count
    ))
  FROM v_mixed_vat_accounts
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '8. التكامل المحاسبي'::TEXT,
    'قيود بدون سطور'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'journal_entry_id', id,
      'reference_type', reference_type
    ))
  FROM v_journal_entries_without_lines
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '8. التكامل المحاسبي'::TEXT,
    'قيود مكررة'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'reference_type', reference_type,
      'reference_id', reference_id,
      'entry_count', entry_count,
      'journal_entry_ids', journal_entry_ids
    ))
  FROM v_duplicate_journal_entries
  WHERE (p_company_id IS NULL OR company_id = p_company_id)
  
  UNION ALL
  
  SELECT 
    '8. التكامل المحاسبي'::TEXT,
    'معاملات بدون قيود'::TEXT,
    COUNT(*)::BIGINT,
    jsonb_agg(jsonb_build_object(
      'transaction_type', transaction_type,
      'transaction_id', transaction_id,
      'transaction_number', transaction_number
    ))
  FROM v_transactions_without_journals
  WHERE (p_company_id IS NULL OR company_id = p_company_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- generate_customer_debit_note_number(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.generate_customer_debit_note_number(p_company_id uuid)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$ DECLARE v_prefix VARCHAR(10); v_next_number INTEGER; v_debit_number VARCHAR(50); BEGIN SELECT UPPER(LEFT(name, 3)) INTO v_prefix FROM companies WHERE id = p_company_id; SELECT COALESCE(MAX(CAST(SUBSTRING(debit_note_number FROM '[0-9]+$') AS INTEGER)), 0) + 1 INTO v_next_number FROM customer_debit_notes WHERE company_id = p_company_id AND debit_note_number ~ (v_prefix || '-DN-[0-9]+$'); v_debit_number := v_prefix || '-DN-' || LPAD(v_next_number::TEXT, 4, '0'); RETURN v_debit_number; END; $function$
;

-- ---------------------------------------------------------------
-- generate_depreciation_schedule(p_asset_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.generate_depreciation_schedule(p_asset_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_asset RECORD;
  v_period INTEGER := 1;
  v_current_date DATE;
  v_depreciation DECIMAL(15, 2);
  v_accumulated DECIMAL(15, 2) := 0;
  v_book_value DECIMAL(15, 2);
  v_periods_count INTEGER := 0;
  v_depreciable_base DECIMAL(15, 2);
  v_monthly_depreciation DECIMAL(15, 2);
  v_last_period_depreciation DECIMAL(15, 2);
  v_remaining_months INTEGER;
BEGIN
  -- جلب بيانات الأصل
  SELECT * INTO v_asset FROM fixed_assets WHERE id = p_asset_id;

  IF v_asset IS NULL THEN
    RAISE EXCEPTION 'Asset not found: %', p_asset_id;
  END IF;

  -- التحقق من صحة البيانات
  IF v_asset.useful_life_months IS NULL OR v_asset.useful_life_months <= 0 THEN
    RAISE EXCEPTION 'Invalid useful life months: %. Must be greater than 0', v_asset.useful_life_months;
  END IF;

  IF v_asset.purchase_cost IS NULL OR v_asset.purchase_cost <= 0 THEN
    RAISE EXCEPTION 'Invalid purchase cost: %. Must be greater than 0', v_asset.purchase_cost;
  END IF;

  IF v_asset.salvage_value IS NULL OR v_asset.salvage_value < 0 THEN
    RAISE EXCEPTION 'Invalid salvage value: %. Must be greater than or equal to 0', v_asset.salvage_value;
  END IF;

  IF v_asset.salvage_value >= v_asset.purchase_cost THEN
    RAISE EXCEPTION 'Salvage value (%) cannot be greater than or equal to purchase cost (%)', 
      v_asset.salvage_value, v_asset.purchase_cost;
  END IF;

  -- حذف الجدول القديم (فقط الفترات غير المرحلة)
  DELETE FROM depreciation_schedules
  WHERE asset_id = p_asset_id AND status IN ('pending', 'approved');

  -- تهيئة القيم
  v_book_value := v_asset.purchase_cost;
  v_depreciable_base := v_asset.purchase_cost - v_asset.salvage_value;
  
  -- تحديد تاريخ البداية (بداية الشهر)
  v_current_date := DATE_TRUNC('month', v_asset.depreciation_start_date)::DATE;

  -- حساب الإهلاك الشهري للطريقة الخطية (للاستخدام في التحقق)
  IF v_asset.depreciation_method = 'straight_line' THEN
    v_monthly_depreciation := ROUND(v_depreciable_base / v_asset.useful_life_months, 2);
  END IF;

  -- إنشاء جدول الإهلاك
  WHILE v_period <= v_asset.useful_life_months LOOP
    -- حساب الإهلاك حسب الطريقة
    IF v_asset.depreciation_method = 'straight_line' THEN
      -- طريقة القسط الثابت: توزيع منتظم على جميع الفترات
      v_depreciation := v_monthly_depreciation;
      
      -- في الفترة الأخيرة، تأكد من أن الإهلاك المتبقي يصل بالضبط إلى salvage_value
      v_remaining_months := v_asset.useful_life_months - v_period + 1;
      IF v_remaining_months = 1 THEN
        -- الفترة الأخيرة: استخدم القيمة المتبقية بالضبط
        v_depreciation := v_book_value - v_asset.salvage_value;
      END IF;
      
    ELSIF v_asset.depreciation_method = 'declining_balance' THEN
      -- طريقة القسط المتناقص
      v_depreciation := calc_declining_balance_depreciation(
        v_book_value,
        v_asset.salvage_value,
        v_asset.declining_balance_rate,
        v_asset.useful_life_months,
        v_period
      );
    ELSE
      -- افتراضي: طريقة القسط الثابت
      v_depreciation := v_monthly_depreciation;
    END IF;

    -- التأكد من عدم تجاوز القيمة المتبقية
    IF (v_book_value - v_depreciation) < v_asset.salvage_value THEN
      v_depreciation := GREATEST(v_book_value - v_asset.salvage_value, 0);
    END IF;

    -- التأكد من أن الإهلاك غير سالب
    IF v_depreciation < 0 THEN
      v_depreciation := 0;
    END IF;

    -- تحديث القيم
    v_accumulated := v_accumulated + v_depreciation;
    v_book_value := v_asset.purchase_cost - v_accumulated;

    -- التأكد من أن book_value لا يقل عن salvage_value
    IF v_book_value < v_asset.salvage_value THEN
      v_book_value := v_asset.salvage_value;
      v_accumulated := v_asset.purchase_cost - v_asset.salvage_value;
    END IF;

    -- إدراج فترة الإهلاك (بداية كل شهر)
    INSERT INTO depreciation_schedules (
      company_id, asset_id, period_number, period_date,
      depreciation_amount, accumulated_depreciation, book_value, status
    ) VALUES (
      v_asset.company_id, p_asset_id, v_period, v_current_date,
      ROUND(v_depreciation, 2), ROUND(v_accumulated, 2), ROUND(v_book_value, 2), 'pending'
    );

    v_periods_count := v_periods_count + 1;
    v_period := v_period + 1;
    
    -- الانتقال إلى بداية الشهر التالي
    v_current_date := (v_current_date + INTERVAL '1 month')::DATE;
    v_current_date := DATE_TRUNC('month', v_current_date)::DATE;
    
    -- إيقاف إذا وصلنا إلى salvage_value
    IF v_book_value <= v_asset.salvage_value THEN
      EXIT;
    END IF;
  END LOOP;

  -- التحقق النهائي من دقة الإهلاك
  IF v_asset.depreciation_method = 'straight_line' THEN
    -- في طريقة القسط الثابت، يجب أن يكون book_value النهائي = salvage_value
    IF ABS(v_book_value - v_asset.salvage_value) > 0.01 THEN
      RAISE WARNING 'Final book value (%) does not match salvage value (%). Difference: %', 
        v_book_value, v_asset.salvage_value, ABS(v_book_value - v_asset.salvage_value);
    END IF;
  END IF;

  RETURN v_periods_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- generate_expense_number(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.generate_expense_number(p_company_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_lock_key BIGINT;
  v_max_number INTEGER;
  v_number TEXT;
BEGIN
  -- 🔒 إنشاء lock key فريد لكل شركة (استخدام hashtext للحصول على رقم من UUID)
  v_lock_key := hashtext(p_company_id::TEXT);
  
  -- 🔒 الحصول على قفل حصري لهذه الشركة (ينتظر حتى يتم تحرير القفل)
  PERFORM pg_advisory_xact_lock(v_lock_key);
  
  -- 🔍 الحصول على أكبر رقم موجود
  SELECT COALESCE(
    MAX(
      CAST(
        SUBSTRING(expense_number FROM 'EXP-([0-9]+)') AS INTEGER
      )
    ),
    0
  ) INTO v_max_number
  FROM expenses
  WHERE company_id = p_company_id
    AND expense_number ~ '^EXP-[0-9]+$';
  
  -- ✅ توليد الرقم التالي
  v_number := 'EXP-' || LPAD((v_max_number + 1)::TEXT, 4, '0');
  
  -- 🔓 القفل سيتم تحريره تلقائياً عند انتهاء Transaction
  RETURN v_number;
END;
$function$
;

-- ---------------------------------------------------------------
-- generate_invoice_number()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.generate_invoice_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year TEXT;
  v_seq INTEGER;
BEGIN
  IF NEW.invoice_number IS NULL OR NEW.invoice_number = '' THEN
    v_year := to_char(now(), 'YYYY');
    SELECT COALESCE(MAX(CAST(SUBSTRING(invoice_number FROM '[0-9]+$') AS INTEGER)), 0) + 1
    INTO v_seq
    FROM billing_invoices
    WHERE invoice_number LIKE 'INV-' || v_year || '-%';
    NEW.invoice_number := 'INV-' || v_year || '-' || LPAD(v_seq::TEXT, 6, '0');
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- generate_username_from_email(p_email text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.generate_username_from_email(p_email text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_base TEXT;
  v_username TEXT;
  v_counter INTEGER := 0;
BEGIN
  v_base := LOWER(SPLIT_PART(p_email, '@', 1));
  v_base := REGEXP_REPLACE(v_base, '[^a-z0-9_]', '', 'g');
  IF LENGTH(v_base) > 25 THEN
    v_base := LEFT(v_base, 25);
  END IF;
  IF LENGTH(v_base) < 3 THEN
    v_base := v_base || 'user';
  END IF;
  v_username := v_base;
  WHILE EXISTS (SELECT 1 FROM user_profiles WHERE username = v_username) LOOP
    v_counter := v_counter + 1;
    v_username := v_base || v_counter::TEXT;
    IF v_counter > 1000 THEN
      v_username := v_base || EXTRACT(EPOCH FROM now())::BIGINT::TEXT;
      EXIT;
    END IF;
  END LOOP;
  RETURN v_username;
END;
$function$
;

-- ---------------------------------------------------------------
-- generate_write_off_number(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.generate_write_off_number(p_company_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_count INTEGER;
  v_year TEXT;
BEGIN
  v_year := TO_CHAR(CURRENT_DATE, 'YYYY');
  SELECT COUNT(*) + 1 INTO v_count
  FROM inventory_write_offs
  WHERE company_id = p_company_id
  AND EXTRACT(YEAR FROM write_off_date) = EXTRACT(YEAR FROM CURRENT_DATE);

  RETURN 'WO-' || v_year || '-' || LPAD(v_count::TEXT, 4, '0');
END;
$function$
;

-- ---------------------------------------------------------------
-- get_account_balance(p_company_id uuid, p_account_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_account_balance(p_company_id uuid, p_account_id uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_opening_balance DECIMAL(15, 2);
    v_debit_total DECIMAL(15, 2);
    v_credit_total DECIMAL(15, 2);
    v_account_type TEXT;
    v_normal_balance TEXT;
    v_balance DECIMAL(15, 2);
BEGIN
    -- جلب الرصيد الافتتاحي ونوع الحساب
    SELECT 
        COALESCE(opening_balance, 0),
        account_type,
        COALESCE(normal_balance, 
            CASE 
                WHEN account_type IN ('asset', 'expense') THEN 'debit'
                ELSE 'credit'
            END
        )
    INTO v_opening_balance, v_account_type, v_normal_balance
    FROM chart_of_accounts
    WHERE id = p_account_id AND company_id = p_company_id;
    
    IF NOT FOUND THEN
        RETURN 0;
    END IF;
    
    -- حساب إجمالي المدين والدائن من القيود
    SELECT 
        COALESCE(SUM(debit_amount), 0),
        COALESCE(SUM(credit_amount), 0)
    INTO v_debit_total, v_credit_total
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.journal_entry_id
    WHERE jel.account_id = p_account_id
      AND je.company_id = p_company_id
      AND je.entry_date <= p_as_of_date;
    
    -- حساب الرصيد حسب الطبيعة المحاسبية
    IF v_normal_balance = 'debit' THEN
        v_balance := v_opening_balance + (v_debit_total - v_credit_total);
    ELSE
        v_balance := v_opening_balance + (v_credit_total - v_debit_total);
    END IF;
    
    RETURN v_balance;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_account_branch_cost_center(p_account_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_account_branch_cost_center(p_account_id uuid)
 RETURNS TABLE(branch_id uuid, cost_center_id uuid, branch_name text, cost_center_name text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    coa.branch_id,
    coa.cost_center_id,
    b.name AS branch_name,
    cc.name AS cost_center_name
  FROM chart_of_accounts coa
  LEFT JOIN branches b ON b.id = coa.branch_id
  LEFT JOIN cost_centers cc ON cc.id = coa.cost_center_id
  WHERE coa.id = p_account_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_activity_summary(p_company_id uuid, p_days integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_activity_summary(p_company_id uuid, p_days integer DEFAULT 7)
 RETURNS TABLE(user_id uuid, user_email text, user_name text, total_actions bigint, inserts bigint, updates bigint, deletes bigint, last_action timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    al.user_id,
    al.user_email,
    al.user_name,
    COUNT(*) as total_actions,
    COUNT(*) FILTER (WHERE al.action = 'INSERT') as inserts,
    COUNT(*) FILTER (WHERE al.action = 'UPDATE') as updates,
    COUNT(*) FILTER (WHERE al.action = 'DELETE') as deletes,
    MAX(al.created_at) as last_action
  FROM audit_logs al
  WHERE al.company_id = p_company_id
    AND al.created_at >= NOW() - (p_days || ' days')::INTERVAL
  GROUP BY al.user_id, al.user_email, al.user_name
  ORDER BY total_actions DESC;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_approval_history(p_company_id uuid, p_reference_type text, p_reference_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_approval_history(p_company_id uuid, p_reference_type text, p_reference_id uuid)
 RETURNS TABLE(id uuid, cycle_no integer, action text, actor_id uuid, actor_role text, reason text, snapshot_data jsonb, created_at timestamp with time zone)
 LANGUAGE sql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT id, cycle_no, action, actor_id, actor_role, reason, snapshot_data, created_at
    FROM public.approval_history
   WHERE company_id     = p_company_id
     AND reference_type = p_reference_type
     AND reference_id   = p_reference_id
   ORDER BY created_at ASC, cycle_no ASC;
$function$
;

-- ---------------------------------------------------------------
-- get_ar_reconciliation_report(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_ar_reconciliation_report(p_company_id uuid)
 RETURNS TABLE(source text, total_outstanding numeric, invoice_count bigint, note text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT
    'GL (journal_entry_lines)'::TEXT AS source,
    ROUND(SUM(GREATEST(0,
      COALESCE(d.amount, 0) - COALESCE(pc.amount, 0) - COALESCE(rc.amount, 0)
    )), 2) AS total_outstanding,
    COUNT(i.id) AS invoice_count,
    'مصدر الحقيقة الرسمي - يستخدم في ميزان المراجعة'::TEXT AS note
  FROM invoices i
  LEFT JOIN (
    SELECT je.reference_id::TEXT AS reference_id, SUM(jel.debit_amount) AS amount
    FROM journal_entries je JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    JOIN chart_of_accounts coa ON coa.id = jel.account_id
    WHERE je.company_id = p_company_id AND je.status = 'posted'
      AND je.reference_type = 'invoice'
      AND (je.is_deleted IS NULL OR je.is_deleted = false)
      AND (coa.sub_type = 'accounts_receivable' OR coa.account_name ILIKE '%receivable%')
    GROUP BY je.reference_id
  ) d ON d.reference_id = i.id::TEXT
  LEFT JOIN (
    SELECT je.reference_id::TEXT AS reference_id, SUM(jel.credit_amount) AS amount
    FROM journal_entries je JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    JOIN chart_of_accounts coa ON coa.id = jel.account_id
    WHERE je.company_id = p_company_id AND je.status = 'posted'
      AND je.reference_type = 'invoice_payment'
      AND (je.is_deleted IS NULL OR je.is_deleted = false)
      AND (coa.sub_type = 'accounts_receivable' OR coa.account_name ILIKE '%receivable%')
    GROUP BY je.reference_id
  ) pc ON pc.reference_id = i.id::TEXT
  LEFT JOIN (
    SELECT sr.invoice_id::TEXT AS invoice_id, SUM(jel.credit_amount) AS amount
    FROM journal_entries je JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    JOIN chart_of_accounts coa ON coa.id = jel.account_id
    JOIN sales_returns sr ON je.reference_id = sr.id
    WHERE je.company_id = p_company_id AND je.status = 'posted'
      AND je.reference_type = 'sales_return'
      AND (je.is_deleted IS NULL OR je.is_deleted = false)
      AND (coa.sub_type = 'accounts_receivable' OR coa.account_name ILIKE '%receivable%')
    GROUP BY sr.invoice_id
  ) rc ON rc.invoice_id = i.id::TEXT
  WHERE i.company_id = p_company_id
    AND i.status NOT IN ('draft', 'cancelled', 'fully_returned')
    AND (i.is_deleted IS NULL OR i.is_deleted = false)
    AND COALESCE(d.amount, 0) > 0

  UNION ALL

  SELECT
    'Operational (invoices table)'::TEXT AS source,
    ROUND(SUM(GREATEST(0,
      i.total_amount
      - COALESCE(i.paid_amount, 0)
      - COALESCE(i.returned_amount, 0)
    )), 2) AS total_outstanding,
    COUNT(i.id) AS invoice_count,
    'تقديري تشغيلي - قد يختلف عن GL عند وجود أخطاء'::TEXT AS note
  FROM invoices i
  WHERE i.company_id = p_company_id
    AND i.status IN ('sent', 'partially_paid')
    AND (i.is_deleted IS NULL OR i.is_deleted = false);
$function$
;

-- ---------------------------------------------------------------
-- get_asset_current_state(p_asset_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_asset_current_state(p_asset_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_asset RECORD;
  v_last_schedule RECORD;
  v_cutoff_date DATE;
  v_current_book_value DECIMAL;
  v_elapsed_months INTEGER;
  v_remaining_life INTEGER;
  v_transaction RECORD;
BEGIN
  -- Get Asset
  SELECT * INTO v_asset FROM public.fixed_assets WHERE id = p_asset_id;
  
  -- Calculate elapsed months/count FIRST
  SELECT COUNT(*) INTO v_elapsed_months 
  FROM public.depreciation_schedules 
  WHERE asset_id = p_asset_id AND status = 'posted';

  IF v_elapsed_months > 0 THEN
    -- Get Last Posted Schedule
    SELECT * INTO v_last_schedule 
    FROM public.depreciation_schedules 
    WHERE asset_id = p_asset_id AND status = 'posted'
    ORDER BY period_date DESC 
    LIMIT 1;
    
    v_cutoff_date := v_last_schedule.period_date;
    v_current_book_value := v_last_schedule.book_value;
    v_remaining_life := GREATEST(0, v_asset.useful_life_months - v_elapsed_months);
  ELSE
    -- No posted schedules yet, start from scratch
    v_cutoff_date := v_asset.depreciation_start_date - INTERVAL '1 day'; -- Start from day before first depreciation
    v_current_book_value := v_asset.purchase_cost;
    v_remaining_life := v_asset.useful_life_months;
  END IF;

  -- Adjust for any "mid-cycle" transactions that happened AFTER the last posted schedule
  -- e.g. An "Addition" or "Revaluation" that hasn't been depreciated yet
  FOR v_transaction IN 
    SELECT * FROM public.asset_transactions 
    WHERE asset_id = p_asset_id 
      AND transaction_date > v_cutoff_date 
      AND transaction_type IN ('addition', 'revaluation', 'adjustment')
  LOOP
    v_current_book_value := v_current_book_value + v_transaction.amount;
  END LOOP;

  RETURN jsonb_build_object(
    'book_value', v_current_book_value,
    'remaining_life_months', v_remaining_life,
    'cutoff_date', v_cutoff_date,
    'posted_count', COALESCE(v_elapsed_months, 0)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_audit_trail_report(p_company_id uuid, p_start_date timestamp with time zone, p_end_date timestamp with time zone, p_table_name text, p_action text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_audit_trail_report(p_company_id uuid, p_start_date timestamp with time zone DEFAULT (now() - '30 days'::interval), p_end_date timestamp with time zone DEFAULT now(), p_table_name text DEFAULT NULL::text, p_action text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, user_name text, user_email text, action text, target_table text, record_identifier text, changed_fields text[], created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    al.id,
    al.user_name,
    al.user_email,
    al.action,
    al.target_table,
    al.record_identifier,
    al.changed_fields,
    al.created_at
  FROM audit_logs al
  WHERE al.company_id = p_company_id
    AND al.created_at >= p_start_date
    AND al.created_at <= p_end_date
    AND (p_table_name IS NULL OR al.target_table = p_table_name)
    AND (p_action IS NULL OR al.action = p_action)
  ORDER BY al.created_at DESC;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_available_inventory_quantity(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_cost_center_id uuid, p_product_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_available_inventory_quantity(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_cost_center_id uuid, p_product_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_available_qty INTEGER := 0;
  v_transaction_count INTEGER := 0;
  v_final_branch_id UUID;
  v_final_cost_center_id UUID;
  v_warehouse_branch_id UUID;
  v_branch_default_cost_center_id UUID;
BEGIN
  -- ✅ الخطوة 1: تحديد branch_id النهائي
  -- إذا تم تمرير warehouse_id، نجلب branch_id منه
  IF p_warehouse_id IS NOT NULL THEN
    SELECT branch_id INTO v_warehouse_branch_id
    FROM warehouses
    WHERE id = p_warehouse_id AND company_id = p_company_id;
    
    -- استخدام branch_id من warehouse إذا كان متوفراً ولم يتم تمرير branch_id
    IF v_warehouse_branch_id IS NOT NULL THEN
      v_final_branch_id := COALESCE(p_branch_id, v_warehouse_branch_id);
    ELSE
      v_final_branch_id := p_branch_id;
    END IF;
  ELSE
    v_final_branch_id := p_branch_id;
  END IF;

  -- ✅ الخطوة 2: تحديد cost_center_id النهائي
  -- إذا كان branch_id محدداً ولم يكن cost_center_id محدداً، نجلب default_cost_center_id من branch
  IF v_final_branch_id IS NOT NULL AND p_cost_center_id IS NULL THEN
    SELECT default_cost_center_id INTO v_branch_default_cost_center_id
    FROM branches
    WHERE id = v_final_branch_id AND company_id = p_company_id;
    
    v_final_cost_center_id := v_branch_default_cost_center_id;
  ELSE
    v_final_cost_center_id := p_cost_center_id;
  END IF;

  -- ✅ الخطوة 3: حساب الرصيد المتاح من inventory_transactions
  -- نستخدم المعايير الصحيحة: company_id, branch_id, warehouse_id, cost_center_id, product_id
  -- الحل المحسّن: نحاول بالمعايير الصارمة أولاً، ثم بالمعايير المرنة
  
  -- المحاولة 1: البحث بالمعايير الصارمة (warehouse + branch + cost_center)
  SELECT COALESCE(SUM(quantity_change), 0), COUNT(*) INTO v_available_qty, v_transaction_count
  FROM inventory_transactions
  WHERE company_id = p_company_id
    AND product_id = p_product_id
    AND (p_warehouse_id IS NULL OR warehouse_id = p_warehouse_id)
    AND (v_final_branch_id IS NULL OR branch_id = v_final_branch_id)
    AND (v_final_cost_center_id IS NULL OR cost_center_id = v_final_cost_center_id)
    AND (is_deleted IS NULL OR is_deleted = false);

  -- المحاولة 2: إذا لم توجد transactions بالمعايير الصارمة، نجرب بدون cost_center_id
  -- هذا يحل مشكلة cost_center_id mismatch
  IF v_transaction_count = 0 AND p_warehouse_id IS NOT NULL AND v_final_branch_id IS NOT NULL THEN
    SELECT COALESCE(SUM(quantity_change), 0), COUNT(*) INTO v_available_qty, v_transaction_count
    FROM inventory_transactions
    WHERE company_id = p_company_id
      AND product_id = p_product_id
      AND warehouse_id = p_warehouse_id
      AND branch_id = v_final_branch_id
      AND (is_deleted IS NULL OR is_deleted = false);
  END IF;

  -- المحاولة 3: إذا لم توجد transactions، نجرب بدون branch_id أيضاً (فقط warehouse)
  -- هذا يحل مشكلة branch_id mismatch
  IF v_transaction_count = 0 AND p_warehouse_id IS NOT NULL THEN
    SELECT COALESCE(SUM(quantity_change), 0), COUNT(*) INTO v_available_qty, v_transaction_count
    FROM inventory_transactions
    WHERE company_id = p_company_id
      AND product_id = p_product_id
      AND warehouse_id = p_warehouse_id
      AND (is_deleted IS NULL OR is_deleted = false);
  END IF;

  -- ✅ الخطوة 4: إذا لم توجد transactions في المخزن المحدد، نرجع 0
  -- ⚠️ لا نستخدم quantity_on_hand لأنه الرصيد الإجمالي في جميع المخازن، وليس في المخزن المحدد
  -- إذا لم توجد transactions في المخزن المحدد، فهذا يعني أن الرصيد = 0 في هذا المخزن
  IF v_transaction_count = 0 THEN
    RETURN 0;
  END IF;
  
  -- ✅ الخطوة 5: إذا كانت هناك transactions، استخدم المجموع المحسوب
  RETURN GREATEST(0, v_available_qty);
END;
$function$
;

-- ---------------------------------------------------------------
-- get_available_return_quantity(p_invoice_id uuid, p_product_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_available_return_quantity(p_invoice_id uuid, p_product_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_sold_qty NUMERIC := 0;
  v_returned_qty NUMERIC := 0;
  v_available_qty NUMERIC;
BEGIN
  -- الكمية المباعة (من حركات البيع)
  SELECT COALESCE(ABS(SUM(quantity_change)), 0)
  INTO v_sold_qty
  FROM inventory_transactions
  WHERE reference_id = p_invoice_id
    AND product_id = p_product_id
    AND transaction_type = 'sale';

  -- الكمية المرتجعة سابقاً
  SELECT COALESCE(SUM(quantity_change), 0)
  INTO v_returned_qty
  FROM inventory_transactions
  WHERE reference_id = p_invoice_id
    AND product_id = p_product_id
    AND transaction_type = 'sale_return';

  v_available_qty := v_sold_qty - v_returned_qty;
  
  RETURN GREATEST(v_available_qty, 0);
END;
$function$
;

-- ---------------------------------------------------------------
-- get_balance_sheet(p_company_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_balance_sheet(p_company_id uuid, p_as_of_date date)
 RETURNS TABLE(section text, account_id uuid, account_code text, account_name text, balance numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    coa.account_type as section,
    coa.id as account_id,
    coa.code as account_code,
    coa.name as account_name,
    CASE 
      WHEN coa.account_type = 'Asset' THEN 
        (COALESCE(coa.opening_balance, 0) + COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0))
      WHEN coa.account_type IN ('Liability', 'Equity') THEN 
        (COALESCE(coa.opening_balance, 0) + COALESCE(SUM(jel.credit_amount - jel.debit_amount), 0))
      ELSE 0
    END as balance
  FROM public.chart_of_accounts coa
  LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
  LEFT JOIN public.journal_entries je ON jel.journal_entry_id = je.id
  WHERE coa.company_id = p_company_id
    AND coa.account_type IN ('Asset', 'Liability', 'Equity')
    AND coa.is_active = TRUE
    AND (je.id IS NULL OR (
      je.entry_date <= p_as_of_date
      AND je.status = 'posted'
    ))
  GROUP BY coa.id, coa.code, coa.name, coa.account_type, coa.opening_balance
  HAVING (COALESCE(coa.opening_balance, 0) + COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)) != 0
  ORDER BY 
    CASE coa.account_type
      WHEN 'Asset' THEN 1
      WHEN 'Liability' THEN 2
      WHEN 'Equity' THEN 3
    END,
    coa.code;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_bill_effective_outstanding(p_bill_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_bill_effective_outstanding(p_bill_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_total          numeric := 0;
  v_paid           numeric := 0;
  v_returned       numeric := 0;
  v_pending_pr     numeric := 0;
  v_pending_pay    numeric := 0;
  v_company_id     uuid;
BEGIN
  IF p_bill_id IS NULL THEN RETURN 0; END IF;

  SELECT company_id, COALESCE(total_amount, 0), COALESCE(paid_amount, 0),
         COALESCE(returned_amount, 0)
    INTO v_company_id, v_total, v_paid, v_returned
    FROM public.bills WHERE id = p_bill_id;
  IF NOT FOUND THEN RETURN 0; END IF;

  SELECT COALESCE(SUM(pr.total_amount), 0) INTO v_pending_pr
    FROM public.purchase_returns pr
   WHERE pr.bill_id = p_bill_id
     AND pr.workflow_status IN (
       'pending_admin_approval', 'pending_approval',
       'pending_warehouse',      'partial_approval'
     );

  -- v3.74.559 — pending payment allocations (sum in base ccy).
  -- Covers both:
  --   * legacy shape (payments.bill_id set, no allocations row)
  --   * modern shape (payment_allocations row)
  -- Uses base_currency_amount so FC payments contribute their EGP
  -- equivalent (matches how paid_amount is stored).
  SELECT COALESCE(SUM(
           COALESCE(p.base_currency_amount,
                    p.amount * COALESCE(NULLIF(p.exchange_rate, 0), 1))
         ), 0) INTO v_pending_pay
    FROM public.payments p
   WHERE p.status = 'pending_approval'
     AND p.voided_at IS NULL
     AND p.voids_payment_id IS NULL
     AND (
       p.bill_id = p_bill_id OR
       EXISTS (
         SELECT 1 FROM public.payment_allocations pa
          WHERE pa.payment_id = p.id AND pa.bill_id = p_bill_id
       )
     );

  RETURN GREATEST(v_total - v_paid - v_returned - v_pending_pr - v_pending_pay, 0);
END;
$function$
;

-- ---------------------------------------------------------------
-- get_bills_payload(p_company_id uuid, p_bill_ids uuid[])
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_bills_payload(p_company_id uuid, p_bill_ids uuid[])
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  IF p_bill_ids IS NULL OR array_length(p_bill_ids, 1) = 0 THEN
    RETURN jsonb_build_object(
      'payments', '[]'::jsonb,
      'items', '[]'::jsonb,
      'returned_by_item', '[]'::jsonb,
      'open_vc_by_bill', '{}'::jsonb
    );
  END IF;

  RETURN (
    WITH
    payments_agg AS (
      SELECT jsonb_agg(jsonb_build_object(
        'id', id, 'bill_id', bill_id, 'amount', amount, 'status', status,
        'currency_code', currency_code, 'exchange_rate', exchange_rate,
        'base_currency_amount', base_currency_amount
      )) AS rows
      FROM payments
      WHERE company_id = p_company_id
        AND bill_id = ANY(p_bill_ids)
        AND status = 'approved'
    ),
    items_agg AS (
      SELECT jsonb_agg(jsonb_build_object(
        'bill_id', bi.bill_id, 'quantity', bi.quantity,
        'product_id', bi.product_id, 'returned_quantity', bi.returned_quantity,
        'products', jsonb_build_object('name', p.name)
      )) AS rows
      FROM bill_items bi
      LEFT JOIN products p ON p.id = bi.product_id
      WHERE bi.bill_id = ANY(p_bill_ids)
    ),
    returns_agg AS (
      SELECT jsonb_agg(jsonb_build_object(
        'bill_id', vc.bill_id, 'product_id', vci.product_id, 'quantity', vci.quantity
      )) AS rows
      FROM vendor_credits vc
      JOIN vendor_credit_items vci ON vci.vendor_credit_id = vc.id
      WHERE vc.bill_id = ANY(p_bill_ids)
    ),
    -- Open vendor-credit balance per bill (v3.74.175 logic).
    open_vc AS (
      SELECT jsonb_object_agg(bill_id, open_balance) AS map
      FROM (
        SELECT bill_id,
          SUM(GREATEST(COALESCE(total_amount,0) - COALESCE(applied_amount,0), 0)) AS open_balance
        FROM vendor_credits
        WHERE bill_id = ANY(p_bill_ids) AND status = 'open'
        GROUP BY bill_id
      ) agg
    )
    SELECT jsonb_build_object(
      'payments', COALESCE((SELECT rows FROM payments_agg), '[]'::jsonb),
      'items', COALESCE((SELECT rows FROM items_agg), '[]'::jsonb),
      'returned_by_item', COALESCE((SELECT rows FROM returns_agg), '[]'::jsonb),
      'open_vc_by_bill', COALESCE((SELECT map FROM open_vc), '{}'::jsonb)
    )
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_booking_line_additions(p_booking_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_booking_line_additions(p_booking_id uuid)
 RETURNS TABLE(kind text, product_id uuid, quantity numeric, unit_price numeric, discount_percent numeric, tax_rate numeric, auto_deduct_inventory boolean, price_handling text, bundle_item_id uuid, extra_item_id uuid, description text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH booking AS (
    SELECT b.id AS booking_id, b.company_id, b.quantity AS booking_qty,
           s.product_catalog_id AS parent_product_id
      FROM public.bookings b
      JOIN public.services s ON s.id = b.service_id
     WHERE b.id = p_booking_id
  ),
  mandatory AS (
    SELECT 'bundle_mandatory'::text AS kind,
           pbi.child_product_id     AS product_id,
           (pbi.quantity * bk.booking_qty)::numeric AS quantity,
           CASE COALESCE(pbi.price_handling,'included')
             WHEN 'included'  THEN 0
             WHEN 'free_gift' THEN 0
             ELSE COALESCE(p.unit_price, 0)
           END AS unit_price,
           0::numeric AS discount_percent,
           0::numeric AS tax_rate,
           COALESCE(pbi.auto_deduct_inventory, false) AS auto_deduct_inventory,
           COALESCE(pbi.price_handling,'included') AS price_handling,
           pbi.id AS bundle_item_id,
           NULL::uuid AS extra_item_id,
           p.name AS description
      FROM booking bk
      JOIN public.product_bundle_items pbi
        ON pbi.parent_product_id = bk.parent_product_id
       AND pbi.company_id = bk.company_id
      JOIN public.products p ON p.id = pbi.child_product_id
     WHERE COALESCE(pbi.is_optional, false) = false
  ),
  optional AS (
    SELECT 'bundle_optional'::text AS kind,
           pbi.child_product_id    AS product_id,
           COALESCE(bbs.quantity_override, pbi.quantity * bk.booking_qty)::numeric AS quantity,
           CASE COALESCE(pbi.price_handling,'included')
             WHEN 'included'  THEN 0
             WHEN 'free_gift' THEN 0
             ELSE COALESCE(p.unit_price, 0)
           END AS unit_price,
           0::numeric AS discount_percent,
           0::numeric AS tax_rate,
           COALESCE(pbi.auto_deduct_inventory, false) AS auto_deduct_inventory,
           COALESCE(pbi.price_handling,'included') AS price_handling,
           pbi.id AS bundle_item_id,
           NULL::uuid AS extra_item_id,
           p.name AS description
      FROM booking bk
      JOIN public.booking_bundle_selections bbs
        ON bbs.booking_id = bk.booking_id
      JOIN public.product_bundle_items pbi
        ON pbi.id = bbs.bundle_item_id
      JOIN public.products p ON p.id = pbi.child_product_id
  ),
  extras AS (
    SELECT 'extra'::text AS kind,
           bei.product_id,
           bei.quantity,
           bei.unit_price,
           bei.discount_percent,
           bei.tax_rate,
           -- v3.74.578: sale products are dispatched via the warehouse
           -- cycle, NOT consumed at execution.
           false::boolean AS auto_deduct_inventory,
           'added'::text AS price_handling,
           NULL::uuid AS bundle_item_id,
           bei.id AS extra_item_id,
           COALESCE(bei.notes, p.name) AS description
      FROM public.booking_extra_items bei
      JOIN public.products p ON p.id = bei.product_id
     WHERE bei.booking_id = p_booking_id
  )
  SELECT * FROM mandatory
  UNION ALL SELECT * FROM optional
  UNION ALL SELECT * FROM extras;
$function$
;

-- ---------------------------------------------------------------
-- get_branch_outlet(p_branch_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_branch_outlet(p_branch_id uuid)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT sp.id
  FROM public.shipping_providers sp
  JOIN public.branch_shipping_providers bsp ON bsp.shipping_provider_id = sp.id
  WHERE sp.provider_code = 'branch_outlet'
    AND bsp.branch_id = p_branch_id
  LIMIT 1;
$function$
;

-- ---------------------------------------------------------------
-- get_closing_preview(p_company_id uuid, p_fiscal_year integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_closing_preview(p_company_id uuid, p_fiscal_year integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_revenue_total  NUMERIC(20,4) := 0;
  v_expense_total  NUMERIC(20,4) := 0;
  v_revenue_lines  JSONB := '[]'::JSONB;
  v_expense_lines  JSONB := '[]'::JSONB;
  v_already_closed BOOLEAN := FALSE;
  v_account        RECORD;
BEGIN
  SELECT TRUE INTO v_already_closed
    FROM public.fiscal_year_closings
   WHERE company_id = p_company_id
     AND fiscal_year = p_fiscal_year
     AND status = 'posted';

  FOR v_account IN
    SELECT
      coa.id,
      coa.account_code,
      coa.account_name,
      COALESCE(SUM(jel.credit_amount), 0) - COALESCE(SUM(jel.debit_amount), 0) AS net_balance
    FROM public.chart_of_accounts coa
    LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
    LEFT JOIN public.journal_entries je
           ON je.id = jel.journal_entry_id
          AND je.company_id = p_company_id
          AND EXTRACT(YEAR FROM je.entry_date) = p_fiscal_year
          AND je.status = 'posted'
          AND COALESCE(je.is_closing_entry, FALSE) = FALSE
    WHERE coa.company_id = p_company_id
      AND coa.account_type IN ('income', 'revenue')
    GROUP BY coa.id, coa.account_code, coa.account_name
    HAVING COALESCE(SUM(jel.credit_amount), 0) - COALESCE(SUM(jel.debit_amount), 0) <> 0
    ORDER BY coa.account_code
  LOOP
    v_revenue_total := v_revenue_total + v_account.net_balance;
    v_revenue_lines := v_revenue_lines || jsonb_build_object(
      'id',           v_account.id,
      'account_code', v_account.account_code,
      'account_name', v_account.account_name,
      'balance',      v_account.net_balance
    );
  END LOOP;

  FOR v_account IN
    SELECT
      coa.id,
      coa.account_code,
      coa.account_name,
      COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0) AS net_balance
    FROM public.chart_of_accounts coa
    LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
    LEFT JOIN public.journal_entries je
           ON je.id = jel.journal_entry_id
          AND je.company_id = p_company_id
          AND EXTRACT(YEAR FROM je.entry_date) = p_fiscal_year
          AND je.status = 'posted'
          AND COALESCE(je.is_closing_entry, FALSE) = FALSE
    WHERE coa.company_id = p_company_id
      AND coa.account_type = 'expense'
    GROUP BY coa.id, coa.account_code, coa.account_name
    HAVING COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0) <> 0
    ORDER BY coa.account_code
  LOOP
    v_expense_total := v_expense_total + v_account.net_balance;
    v_expense_lines := v_expense_lines || jsonb_build_object(
      'id',           v_account.id,
      'account_code', v_account.account_code,
      'account_name', v_account.account_name,
      'balance',      v_account.net_balance
    );
  END LOOP;

  RETURN jsonb_build_object(
    'fiscal_year',      p_fiscal_year,
    'already_closed',   COALESCE(v_already_closed, FALSE),
    'total_revenue',    v_revenue_total,
    'total_expenses',   v_expense_total,
    'net_income',       v_revenue_total - v_expense_total,
    'revenue_accounts', v_revenue_lines,
    'expense_accounts', v_expense_lines
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_customer_credit_balance(p_company_id uuid, p_customer_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_customer_credit_balance(p_company_id uuid, p_customer_id uuid)
 RETURNS numeric
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  SELECT COALESCE(SUM(amount), 0)
  FROM public.customer_credit_ledger
  WHERE company_id  = p_company_id
    AND customer_id = p_customer_id;
$function$
;

-- ---------------------------------------------------------------
-- get_customer_credit_effective_balance(p_customer_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_customer_credit_effective_balance(p_customer_id uuid, p_company_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_available   numeric := 0;
  v_pending_ref numeric := 0;
BEGIN
  IF p_customer_id IS NULL OR p_company_id IS NULL THEN RETURN 0; END IF;

  SELECT COALESCE(SUM(GREATEST(
           COALESCE(amount, 0)
           - COALESCE(applied_amount, 0)
           - COALESCE(used_amount, 0), 0)), 0)
    INTO v_available
    FROM public.customer_credits
   WHERE customer_id = p_customer_id
     AND company_id  = p_company_id
     AND LOWER(COALESCE(status, '')) IN ('active','partially_used');

  -- Pending customer refund requests (source_type='refund' path) that
  -- would consume the credit once executed.
  SELECT COALESCE(SUM(amount), 0) INTO v_pending_ref
    FROM public.customer_refund_requests
   WHERE customer_id = p_customer_id
     AND company_id  = p_company_id
     AND LOWER(COALESCE(status, '')) IN ('pending', 'approved');

  RETURN GREATEST(v_available - v_pending_ref, 0);
END;
$function$
;

-- ---------------------------------------------------------------
-- get_customer_overall_credit_balance(p_company_id uuid, p_customer_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_customer_overall_credit_balance(p_company_id uuid, p_customer_id uuid)
 RETURNS numeric
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  -- الـ ledger هو المَصدَر المُوَحَّد بَعد v3.74.76
  -- (customer_credits → ledger مُتَزامِنان عَبر trg_sync_customer_credit_to_ledger)
  SELECT COALESCE(SUM(amount), 0)
  FROM public.customer_credit_ledger
  WHERE company_id  = p_company_id
    AND customer_id = p_customer_id;
$function$
;

-- ---------------------------------------------------------------
-- get_customers_overview(p_company_id uuid, p_branch_filter uuid, p_employee_filter uuid, p_cost_center_filter uuid, p_shared_grantor_ids uuid[], p_search text, p_invoice_filter text, p_page integer, p_page_size integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_customers_overview(p_company_id uuid, p_branch_filter uuid DEFAULT NULL::uuid, p_employee_filter uuid DEFAULT NULL::uuid, p_cost_center_filter uuid DEFAULT NULL::uuid, p_shared_grantor_ids uuid[] DEFAULT NULL::uuid[], p_search text DEFAULT NULL::text, p_invoice_filter text DEFAULT 'all'::text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 50)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_offset integer := GREATEST(0, (COALESCE(p_page, 1) - 1)) * COALESCE(p_page_size, 50);
  v_limit  integer := LEAST(GREATEST(COALESCE(p_page_size, 50), 1), 500);
  v_search text := NULLIF(TRIM(COALESCE(p_search, '')), '');
BEGIN
  RETURN (
    WITH base AS (
      SELECT c.*
      FROM customers c
      WHERE c.company_id = p_company_id
        AND (p_branch_filter IS NULL OR c.branch_id = p_branch_filter)
        AND (
              p_employee_filter IS NULL
           OR c.created_by_user_id = p_employee_filter
           OR (p_shared_grantor_ids IS NOT NULL AND c.created_by_user_id = ANY(p_shared_grantor_ids))
        )
        AND (p_cost_center_filter IS NULL OR c.cost_center_id = p_cost_center_filter)
        AND (
             v_search IS NULL
             OR c.name  ILIKE '%' || v_search || '%'
             OR c.email ILIKE '%' || v_search || '%'
             OR c.phone ILIKE '%' || v_search || '%'
             OR COALESCE(c.tax_id,'') ILIKE '%' || v_search || '%'
        )
    ),
    advance_per_cust AS (
      SELECT customer_id,
             COALESCE(SUM(COALESCE(base_currency_amount, amount)), 0) AS adv
      FROM payments
      WHERE company_id = p_company_id AND customer_id IS NOT NULL AND invoice_id IS NULL
      GROUP BY customer_id
    ),
    applied_per_cust AS (
      SELECT customer_id, COALESCE(SUM(amount_applied), 0) AS app
      FROM advance_applications
      WHERE company_id = p_company_id
      GROUP BY customer_id
    ),
    credits_per_cust AS (
      SELECT customer_id,
        COALESCE(SUM(CASE
          WHEN status IN ('active', 'partially_used')
            THEN GREATEST(amount - COALESCE(used_amount, 0) - COALESCE(applied_amount, 0), 0)
          ELSE 0
        END), 0) AS available,
        COALESCE(SUM(COALESCE(used_amount, 0) + COALESCE(applied_amount, 0)), 0) AS disbursed
      FROM customer_credits
      WHERE company_id = p_company_id
      GROUP BY customer_id
    ),
    inv_agg AS (
      SELECT customer_id,
        -- v3.74.258 — only living invoices contribute to receivables.
        -- Cancelled / fully_returned / draft don't represent an actual
        -- amount owed by the customer.
        COALESCE(SUM(
          CASE WHEN COALESCE(status,'') IN ('cancelled','fully_returned','draft')
               THEN 0
               ELSE GREATEST(
                 COALESCE(total_amount,0) - COALESCE(paid_amount,0) - COALESCE(returned_amount,0),
                 0
               )
          END
        ), 0) AS receivables,
        COUNT(*) FILTER (WHERE COALESCE(status,'') NOT IN ('draft','cancelled')) AS any_invoices,
        COUNT(*) FILTER (WHERE COALESCE(status,'') IN ('sent','partially_paid','paid','partially_returned')) AS active_invoices
      FROM invoices
      WHERE company_id = p_company_id AND customer_id IS NOT NULL
      GROUP BY customer_id
    ),
    enriched AS (
      SELECT
        b.id, b.name, b.email, b.phone, b.address, b.governorate, b.city,
        b.country, b.detailed_address, b.tax_id, b.credit_limit, b.payment_terms,
        b.created_by_user_id, b.branch_id, b.cost_center_id, b.created_at,
        jsonb_build_object('name', br.name) AS branches,
        COALESCE(a.adv, 0)        AS advance,
        COALESCE(ap.app, 0)       AS applied,
        COALESCE(cr.available, 0) AS available_credits,
        COALESCE(cr.disbursed, 0) AS disbursed_credits,
        COALESCE(iv.receivables, 0) AS receivables,
        COALESCE(iv.active_invoices, 0) > 0 AS has_active_invoices,
        COALESCE(iv.any_invoices, 0)    > 0 AS has_any_invoices
      FROM base b
      LEFT JOIN advance_per_cust a   ON a.customer_id = b.id
      LEFT JOIN applied_per_cust ap  ON ap.customer_id = b.id
      LEFT JOIN credits_per_cust cr  ON cr.customer_id = b.id
      LEFT JOIN inv_agg iv           ON iv.customer_id = b.id
      LEFT JOIN branches br          ON br.id = b.branch_id
    ),
    filtered AS (
      SELECT * FROM enriched
      WHERE CASE COALESCE(p_invoice_filter, 'all')
              WHEN 'with_invoices'    THEN has_any_invoices
              WHEN 'without_invoices' THEN NOT has_any_invoices
              ELSE TRUE
            END
    )
    SELECT jsonb_build_object(
      'total', (SELECT COUNT(*) FROM filtered),
      'page',  COALESCE(p_page, 1),
      'page_size', v_limit,
      'rows', COALESCE(
        (SELECT jsonb_agg(to_jsonb(p))
         FROM (SELECT * FROM filtered ORDER BY name ASC NULLS LAST, created_at DESC LIMIT v_limit OFFSET v_offset) p),
        '[]'::jsonb)
    )
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_dashboard_kpis(p_company_id uuid, p_from_date date, p_to_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_dashboard_kpis(p_company_id uuid, p_from_date date, p_to_date date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  WITH
  invoice_stats AS (
    SELECT
      ROUND(COALESCE(SUM(CASE WHEN status IN ('paid','partially_paid') THEN paid_amount ELSE 0 END), 0)::NUMERIC, 2) AS paid_amount,
      ROUND(COALESCE(SUM(CASE WHEN status IN ('sent','partially_paid') THEN total_amount - paid_amount ELSE 0 END), 0)::NUMERIC, 2) AS receivables,
      COUNT(*) FILTER (WHERE status NOT IN ('draft','cancelled')) AS invoice_count
    FROM public.invoices
    WHERE company_id = p_company_id
      AND invoice_date BETWEEN p_from_date AND p_to_date
      AND (is_deleted IS NULL OR is_deleted = FALSE)
  ),
  bill_stats AS (
    SELECT
      ROUND(COALESCE(SUM(CASE WHEN status NOT IN ('draft','cancelled') THEN total_amount ELSE 0 END), 0)::NUMERIC, 2) AS total_purchases,
      COUNT(*) FILTER (WHERE status NOT IN ('draft','cancelled')) AS bill_count
    FROM public.bills
    WHERE company_id = p_company_id
      AND bill_date BETWEEN p_from_date AND p_to_date
  ),
  gl_stats AS (
    SELECT
      ROUND(COALESCE(SUM(CASE WHEN coa.account_type IN ('income','revenue') THEN jel.credit_amount - jel.debit_amount ELSE 0 END), 0)::NUMERIC, 2) AS gl_revenue,
      ROUND(COALESCE(SUM(CASE WHEN coa.account_type = 'expense' THEN jel.debit_amount - jel.credit_amount ELSE 0 END), 0)::NUMERIC, 2) AS gl_expenses
    FROM public.journal_entry_lines jel
    JOIN public.journal_entries je ON je.id = jel.journal_entry_id
    JOIN public.chart_of_accounts coa ON coa.id = jel.account_id
    WHERE je.company_id = p_company_id
      AND je.status = 'posted'
      AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
      AND je.deleted_at IS NULL
      AND je.entry_date BETWEEN p_from_date AND p_to_date
  )
  SELECT jsonb_build_object(
    'revenue',       i.paid_amount,
    'receivables',   i.receivables,
    'invoice_count', i.invoice_count,
    'purchases',     b.total_purchases,
    'bill_count',    b.bill_count,
    'gl_revenue',    g.gl_revenue,
    'gl_expenses',   g.gl_expenses,
    'gl_net_profit', g.gl_revenue - g.gl_expenses,
    'from_date',     p_from_date,
    'to_date',       p_to_date
  )
  FROM invoice_stats i, bill_stats b, gl_stats g;
$function$
;

-- ---------------------------------------------------------------
-- get_effective_available_stock(p_company_id uuid, p_warehouse_id uuid, p_product_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_effective_available_stock(p_company_id uuid, p_warehouse_id uuid, p_product_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_stock          numeric := 0;
  v_pending_pr     numeric := 0;
  v_pending_inv    numeric := 0;
  v_pending_xfer   numeric := 0;
  v_pending_wo     numeric := 0;
  v_pending_mi     numeric := 0;
BEGIN
  IF p_company_id IS NULL OR p_warehouse_id IS NULL OR p_product_id IS NULL THEN
    RETURN 0;
  END IF;

  SELECT COALESCE(SUM(quantity_change), 0) INTO v_stock
    FROM public.inventory_transactions
   WHERE company_id = p_company_id
     AND warehouse_id = p_warehouse_id
     AND product_id = p_product_id
     AND (is_deleted IS NULL OR is_deleted = false);

  SELECT COALESCE(SUM(pri.quantity), 0) INTO v_pending_pr
    FROM public.purchase_return_items pri
    JOIN public.purchase_returns pr ON pr.id = pri.purchase_return_id
   WHERE pr.company_id = p_company_id
     AND pri.product_id = p_product_id
     AND COALESCE(pri.warehouse_id, pr.warehouse_id) = p_warehouse_id
     AND pr.workflow_status IN (
       'pending_admin_approval', 'pending_approval',
       'pending_warehouse',      'partial_approval'
     );

  SELECT COALESCE(SUM(ii.quantity), 0) INTO v_pending_inv
    FROM public.invoice_items ii
    JOIN public.invoices i ON i.id = ii.invoice_id
   WHERE i.company_id = p_company_id
     AND ii.product_id = p_product_id
     AND i.warehouse_id = p_warehouse_id
     AND i.warehouse_status = 'pending'
     AND i.status IN ('sent', 'partially_paid', 'paid');

  SELECT COALESCE(SUM(iti.quantity_sent), 0) INTO v_pending_xfer
    FROM public.inventory_transfer_items iti
    JOIN public.inventory_transfers it ON it.id = iti.transfer_id
   WHERE it.company_id = p_company_id
     AND iti.product_id = p_product_id
     AND it.source_warehouse_id = p_warehouse_id
     AND (it.deleted_at IS NULL)
     AND LOWER(COALESCE(it.status, '')) IN ('pending', 'approved', 'in_transit');

  SELECT COALESCE(SUM(woi.quantity), 0) INTO v_pending_wo
    FROM public.inventory_write_off_items woi
    JOIN public.inventory_write_offs wo ON wo.id = woi.write_off_id
   WHERE wo.company_id = p_company_id
     AND woi.product_id = p_product_id
     AND wo.warehouse_id = p_warehouse_id
     AND LOWER(COALESCE(wo.status, '')) IN ('pending', 'pending_approval', 'draft');

  -- v3.74.563 — pending manufacturing material issues
  -- Sum BOM component qty × remaining production qty × (1+scrap%)
  BEGIN
    SELECT COALESCE(SUM(
             bl.quantity_per
             * GREATEST(COALESCE(po.planned_quantity,0) - COALESCE(po.completed_quantity,0), 0)
             * (1 + COALESCE(bl.scrap_percent,0)/100)
           ), 0)
      INTO v_pending_mi
      FROM public.manufacturing_material_issue_approvals mmia
      JOIN public.manufacturing_production_orders po
        ON po.id = mmia.production_order_id
      JOIN public.manufacturing_bom_lines bl
        ON bl.bom_version_id = po.bom_version_id
     WHERE mmia.company_id = p_company_id
       AND mmia.warehouse_id = p_warehouse_id
       AND bl.component_product_id = p_product_id
       AND LOWER(COALESCE(mmia.status,'')) IN (
         'pending','pending_admin_approval','pending_approval',
         'pending_warehouse','approved','partial_approval'
       );
  EXCEPTION WHEN OTHERS THEN
    v_pending_mi := 0;
  END;

  RETURN v_stock - v_pending_pr - v_pending_inv - v_pending_xfer - v_pending_wo - v_pending_mi;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_employee_available_commission(p_company_id uuid, p_employee_id uuid, p_period_start date, p_period_end date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_employee_available_commission(p_company_id uuid, p_employee_id uuid, p_period_start date DEFAULT NULL::date, p_period_end date DEFAULT NULL::date)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_total_earned DECIMAL(15,2) := 0;
    v_total_advance_paid DECIMAL(15,2) := 0;
    v_available DECIMAL(15,2) := 0;
    v_period_start DATE;
    v_period_end DATE;
BEGIN
    SET search_path = public, pg_temp;

    v_period_start := COALESCE(p_period_start, date_trunc('month', CURRENT_DATE)::DATE);
    v_period_end := COALESCE(p_period_end, (date_trunc('month', CURRENT_DATE) + INTERVAL '1 month - 1 day')::DATE);

    SELECT COALESCE(SUM(
        CASE
            WHEN COALESCE(is_clawback, FALSE) = FALSE THEN amount
            WHEN COALESCE(is_clawback, FALSE) = TRUE THEN -amount
            ELSE 0
        END
    ), 0)
    INTO v_total_earned
    FROM commission_ledger
    WHERE company_id = p_company_id
    AND employee_id = p_employee_id
    AND transaction_date BETWEEN v_period_start AND v_period_end;

    SELECT COALESCE(SUM(amount), 0)
    INTO v_total_advance_paid
    FROM commission_advance_payments
    WHERE company_id = p_company_id
    AND employee_id = p_employee_id
    AND commission_period_start <= v_period_end
    AND commission_period_end >= v_period_start
    AND status = 'paid'
    AND deducted_in_payroll = FALSE;

    v_available := GREATEST(v_total_earned - v_total_advance_paid, 0);

    RETURN jsonb_build_object(
        'employee_id', p_employee_id,
        'period_start', v_period_start,
        'period_end', v_period_end,
        'total_earned', v_total_earned,
        'total_advance_paid', v_total_advance_paid,
        'available_amount', v_available
    );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_employee_commission_summary_for_payroll(p_company_id uuid, p_employee_id uuid, p_period_year integer, p_period_month integer, p_payroll_run_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_employee_commission_summary_for_payroll(p_company_id uuid, p_employee_id uuid, p_period_year integer, p_period_month integer, p_payroll_run_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_period_start DATE;
    v_period_end DATE;
    v_total_earned DECIMAL(15,2) := 0;
    v_total_clawbacks DECIMAL(15,2) := 0;
    v_net_earned DECIMAL(15,2) := 0;
    v_advance_paid DECIMAL(15,2) := 0;
    v_advance_already_deducted DECIMAL(15,2) := 0;
    v_net_payable DECIMAL(15,2) := 0;
BEGIN
    SET search_path = public, pg_temp;

    v_period_start := make_date(p_period_year, p_period_month, 1);
    v_period_end := (v_period_start + INTERVAL '1 month - 1 day')::DATE;

    SELECT
        COALESCE(SUM(CASE WHEN COALESCE(is_clawback, FALSE) = FALSE THEN amount ELSE 0 END), 0),
        COALESCE(SUM(CASE WHEN COALESCE(is_clawback, FALSE) = TRUE THEN amount ELSE 0 END), 0)
    INTO v_total_earned, v_total_clawbacks
    FROM commission_ledger
    WHERE company_id = p_company_id
    AND employee_id = p_employee_id
    AND transaction_date BETWEEN v_period_start AND v_period_end;

    v_net_earned := v_total_earned - v_total_clawbacks;

    -- السلف غير المخصومة
    SELECT COALESCE(SUM(amount), 0)
    INTO v_advance_paid
    FROM commission_advance_payments
    WHERE company_id = p_company_id
    AND employee_id = p_employee_id
    AND commission_period_start <= v_period_end
    AND commission_period_end >= v_period_start
    AND status = 'paid'
    AND deducted_in_payroll = FALSE;

    -- السلف المخصومة لهذا المرتب (لإعادة الحساب)
    IF p_payroll_run_id IS NOT NULL THEN
        SELECT COALESCE(SUM(amount), 0)
        INTO v_advance_already_deducted
        FROM commission_advance_payments
        WHERE company_id = p_company_id
        AND employee_id = p_employee_id
        AND commission_period_start <= v_period_end
        AND commission_period_end >= v_period_start
        AND status = 'paid'
        AND deducted_in_payroll = TRUE
        AND payroll_run_id = p_payroll_run_id;

        v_advance_paid := v_advance_paid + v_advance_already_deducted;
    END IF;

    v_net_payable := GREATEST(v_net_earned - v_advance_paid, 0);

    RETURN jsonb_build_object(
        'employee_id', p_employee_id,
        'period_year', p_period_year,
        'period_month', p_period_month,
        'total_earned', v_total_earned,
        'total_clawbacks', v_total_clawbacks,
        'net_earned', v_net_earned,
        'advance_paid', v_advance_paid,
        'advance_already_deducted', v_advance_already_deducted,
        'net_payable_in_salary', v_net_payable
    );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_enhanced_accounts_payable(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_supplier_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_enhanced_accounts_payable(p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_supplier_id uuid DEFAULT NULL::uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(supplier_id uuid, supplier_name text, bill_id uuid, bill_number text, bill_date date, due_date date, original_amount numeric, paid_amount numeric, returned_amount numeric, balance numeric, days_overdue integer, aging_bucket text, branch_id uuid, cost_center_id uuid)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        b.supplier_id,
        s.name as supplier_name,
        b.id as bill_id,
        b.bill_number,
        b.bill_date,
        b.due_date,
        b.total_amount as original_amount,
        COALESCE(b.paid_amount, 0) as paid_amount,
        COALESCE(b.returned_amount, 0) as returned_amount,
        (b.total_amount - COALESCE(b.paid_amount, 0)) as balance,
        CASE 
            WHEN b.due_date IS NULL THEN 0
            ELSE GREATEST(0, p_as_of_date - b.due_date)
        END as days_overdue,
        CASE 
            WHEN b.due_date IS NULL OR p_as_of_date <= b.due_date THEN 'Current'
            WHEN p_as_of_date - b.due_date <= 30 THEN '1-30 Days'
            WHEN p_as_of_date - b.due_date <= 60 THEN '31-60 Days'
            WHEN p_as_of_date - b.due_date <= 90 THEN '61-90 Days'
            ELSE '90+ Days'
        END as aging_bucket,
        b.branch_id,
        b.cost_center_id
    FROM bills b
    JOIN suppliers s ON b.supplier_id = s.id
    WHERE b.company_id = p_company_id
    AND b.status IN ('sent', 'partially_paid') -- فقط الفواتير المرسلة وغير المدفوعة بالكامل
    AND b.bill_date <= p_as_of_date
    AND (b.total_amount - COALESCE(b.paid_amount, 0)) > 0.01 -- فقط الفواتير التي لها رصيد
    AND (p_branch_id IS NULL OR b.branch_id = p_branch_id)
    AND (p_cost_center_id IS NULL OR b.cost_center_id = p_cost_center_id)
    AND (p_supplier_id IS NULL OR b.supplier_id = p_supplier_id)
    ORDER BY s.name, b.bill_date;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_enhanced_accounts_receivable(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_customer_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_enhanced_accounts_receivable(p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_customer_id uuid DEFAULT NULL::uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(customer_id uuid, customer_name text, invoice_id uuid, invoice_number text, invoice_date date, due_date date, original_amount numeric, paid_amount numeric, returned_amount numeric, balance numeric, days_overdue integer, aging_bucket text, branch_id uuid, cost_center_id uuid)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        i.customer_id,
        c.name as customer_name,
        i.id as invoice_id,
        i.invoice_number,
        i.invoice_date,
        i.due_date,
        i.total_amount as original_amount,
        COALESCE(i.paid_amount, 0) as paid_amount,
        COALESCE(i.returned_amount, 0) as returned_amount,
        (i.total_amount - COALESCE(i.paid_amount, 0)) as balance,
        CASE 
            WHEN i.due_date IS NULL THEN 0
            ELSE GREATEST(0, p_as_of_date - i.due_date)
        END as days_overdue,
        CASE 
            WHEN i.due_date IS NULL OR p_as_of_date <= i.due_date THEN 'Current'
            WHEN p_as_of_date - i.due_date <= 30 THEN '1-30 Days'
            WHEN p_as_of_date - i.due_date <= 60 THEN '31-60 Days'
            WHEN p_as_of_date - i.due_date <= 90 THEN '61-90 Days'
            ELSE '90+ Days'
        END as aging_bucket,
        i.branch_id,
        i.cost_center_id
    FROM invoices i
    JOIN customers c ON i.customer_id = c.id
    WHERE i.company_id = p_company_id
    AND i.status IN ('sent', 'partially_paid') -- فقط الفواتير المرسلة وغير المدفوعة بالكامل
    AND i.invoice_date <= p_as_of_date
    AND (i.total_amount - COALESCE(i.paid_amount, 0)) > 0.01 -- فقط الفواتير التي لها رصيد
    AND (p_branch_id IS NULL OR i.branch_id = p_branch_id)
    AND (p_cost_center_id IS NULL OR i.cost_center_id = p_cost_center_id)
    AND (p_customer_id IS NULL OR i.customer_id = p_customer_id)
    ORDER BY c.name, i.invoice_date;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_enhanced_balance_sheet(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_enhanced_balance_sheet(p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(account_id uuid, account_code text, account_name text, account_type text, sub_type text, balance numeric, branch_id uuid, cost_center_id uuid)
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- التحقق من صحة المعاملات
    IF p_company_id IS NULL THEN
        RAISE EXCEPTION 'Company ID is required';
    END IF;
    
    RETURN QUERY
    SELECT 
        coa.id as account_id,
        coa.account_code,
        coa.account_name,
        coa.account_type,
        coa.sub_type,
        COALESCE(SUM(
            CASE 
                WHEN coa.account_type IN ('asset', 'expense') THEN 
                    jel.debit_amount - jel.credit_amount
                ELSE 
                    jel.credit_amount - jel.debit_amount
            END
        ), 0) as balance,
        jel.branch_id,
        jel.cost_center_id
    FROM chart_of_accounts coa
    LEFT JOIN journal_entry_lines jel ON coa.id = jel.account_id
    LEFT JOIN journal_entries je ON jel.journal_entry_id = je.id
    WHERE coa.company_id = p_company_id
    AND coa.account_type IN ('asset', 'liability', 'equity')
    AND (je.entry_date IS NULL OR je.entry_date <= p_as_of_date)
    AND (p_branch_id IS NULL OR jel.branch_id = p_branch_id OR jel.branch_id IS NULL)
    AND (p_cost_center_id IS NULL OR jel.cost_center_id = p_cost_center_id OR jel.cost_center_id IS NULL)
    GROUP BY coa.id, coa.account_code, coa.account_name, coa.account_type, coa.sub_type, jel.branch_id, jel.cost_center_id
    HAVING ABS(COALESCE(SUM(
        CASE 
            WHEN coa.account_type IN ('asset', 'expense') THEN 
                jel.debit_amount - jel.credit_amount
            ELSE 
                jel.credit_amount - jel.debit_amount
        END
    ), 0)) >= 0.01
    ORDER BY coa.account_type, coa.account_code;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_enhanced_income_statement(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_from_date date, p_to_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_enhanced_income_statement(p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_from_date date DEFAULT (date_trunc('year'::text, (CURRENT_DATE)::timestamp with time zone))::date, p_to_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(account_id uuid, account_code text, account_name text, account_type text, sub_type text, amount numeric, branch_id uuid, cost_center_id uuid)
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- التحقق من صحة المعاملات
    IF p_company_id IS NULL THEN
        RAISE EXCEPTION 'Company ID is required';
    END IF;

    IF p_from_date > p_to_date THEN
        RAISE EXCEPTION 'From date cannot be after to date';
    END IF;

    RETURN QUERY
    SELECT
        coa.id as account_id,
        coa.account_code,
        coa.account_name,
        coa.account_type,
        coa.sub_type,
        COALESCE(SUM(
            CASE
                WHEN coa.account_type = 'income' THEN
                    jel.credit_amount - jel.debit_amount
                WHEN coa.account_type = 'expense' THEN
                    jel.debit_amount - jel.credit_amount
                ELSE 0
            END
        ), 0) as amount,
        jel.branch_id,
        jel.cost_center_id
    FROM chart_of_accounts coa
    LEFT JOIN journal_entry_lines jel ON coa.id = jel.account_id
    LEFT JOIN journal_entries je ON jel.journal_entry_id = je.id
    WHERE coa.company_id = p_company_id
    AND coa.account_type IN ('income', 'expense')
    -- ✅ تم إزالة استبعاد COGS - يجب أن يظهر في قائمة الدخل
    AND je.entry_date BETWEEN p_from_date AND p_to_date
    AND (p_branch_id IS NULL OR jel.branch_id = p_branch_id OR jel.branch_id IS NULL)
    AND (p_cost_center_id IS NULL OR jel.cost_center_id = p_cost_center_id OR jel.cost_center_id IS NULL)
    GROUP BY coa.id, coa.account_code, coa.account_name, coa.account_type, coa.sub_type, jel.branch_id, jel.cost_center_id
    HAVING ABS(COALESCE(SUM(
        CASE 
            WHEN coa.account_type = 'income' THEN 
                jel.credit_amount - jel.debit_amount
            WHEN coa.account_type = 'expense' THEN 
                jel.debit_amount - jel.credit_amount
            ELSE 0
        END
    ), 0)) >= 0.01
    ORDER BY coa.account_type DESC, coa.account_code;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_enhanced_inventory_report(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_warehouse_id uuid, p_product_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_enhanced_inventory_report(p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_product_id uuid DEFAULT NULL::uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(product_id uuid, product_name text, product_code text, warehouse_id uuid, warehouse_name text, opening_quantity numeric, in_quantity numeric, out_quantity numeric, closing_quantity numeric, unit_cost numeric, total_value numeric, branch_id uuid, cost_center_id uuid)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        p.id as product_id,
        p.name as product_name,
        p.product_code,
        COALESCE(it.warehouse_id, w.id) as warehouse_id,
        COALESCE(w.name, 'Default') as warehouse_name,
        -- الكمية الافتتاحية (حركات قبل تاريخ البداية)
        COALESCE(SUM(
            CASE WHEN it.transaction_date < DATE_TRUNC('year', p_as_of_date) 
            THEN it.quantity_change ELSE 0 END
        ), 0) as opening_quantity,
        -- الكميات الداخلة
        COALESCE(SUM(
            CASE WHEN it.transaction_date BETWEEN DATE_TRUNC('year', p_as_of_date) AND p_as_of_date 
            AND it.quantity_change > 0 
            THEN it.quantity_change ELSE 0 END
        ), 0) as in_quantity,
        -- الكميات الخارجة
        COALESCE(SUM(
            CASE WHEN it.transaction_date BETWEEN DATE_TRUNC('year', p_as_of_date) AND p_as_of_date 
            AND it.quantity_change < 0 
            THEN ABS(it.quantity_change) ELSE 0 END
        ), 0) as out_quantity,
        -- الكمية الختامية
        COALESCE(SUM(
            CASE WHEN it.transaction_date <= p_as_of_date 
            THEN it.quantity_change ELSE 0 END
        ), 0) as closing_quantity,
        p.cost_price as unit_cost,
        -- القيمة الإجمالية
        COALESCE(SUM(
            CASE WHEN it.transaction_date <= p_as_of_date 
            THEN it.quantity_change ELSE 0 END
        ), 0) * p.cost_price as total_value,
        it.branch_id,
        it.cost_center_id
    FROM products p
    LEFT JOIN inventory_transactions it ON p.id = it.product_id
    LEFT JOIN warehouses w ON it.warehouse_id = w.id OR (it.warehouse_id IS NULL AND w.company_id = p_company_id)
    WHERE p.company_id = p_company_id
    AND (p_branch_id IS NULL OR it.branch_id = p_branch_id OR it.branch_id IS NULL)
    AND (p_cost_center_id IS NULL OR it.cost_center_id = p_cost_center_id OR it.cost_center_id IS NULL)
    AND (p_warehouse_id IS NULL OR it.warehouse_id = p_warehouse_id OR it.warehouse_id IS NULL)
    AND (p_product_id IS NULL OR p.id = p_product_id)
    GROUP BY p.id, p.name, p.product_code, p.cost_price, it.warehouse_id, w.id, w.name, it.branch_id, it.cost_center_id
    HAVING COALESCE(SUM(
        CASE WHEN it.transaction_date <= p_as_of_date 
        THEN it.quantity_change ELSE 0 END
    ), 0) != 0 -- فقط المنتجات التي لها كمية
    ORDER BY p.name, w.name;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_enhanced_purchases_report(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_supplier_id uuid, p_created_by_user_id uuid, p_from_date date, p_to_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_enhanced_purchases_report(p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_supplier_id uuid DEFAULT NULL::uuid, p_created_by_user_id uuid DEFAULT NULL::uuid, p_from_date date DEFAULT (date_trunc('month'::text, (CURRENT_DATE)::timestamp with time zone))::date, p_to_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(bill_id uuid, bill_number text, bill_date date, supplier_id uuid, supplier_name text, subtotal numeric, tax_amount numeric, total_amount numeric, paid_amount numeric, status text, created_by_user_id uuid, branch_id uuid, cost_center_id uuid)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        b.id as bill_id,
        b.bill_number,
        b.bill_date,
        b.supplier_id,
        s.name as supplier_name,
        b.subtotal,
        b.tax_amount,
        b.total_amount,
        COALESCE(b.paid_amount, 0) as paid_amount,
        b.status,
        po.created_by_user_id, -- من أمر الشراء المرتبط
        b.branch_id,
        b.cost_center_id
    FROM bills b
    JOIN suppliers s ON b.supplier_id = s.id
    LEFT JOIN purchase_orders po ON b.purchase_order_id = po.id
    WHERE b.company_id = p_company_id
    AND b.status IN ('sent', 'paid', 'partially_paid') -- فقط الفواتير المستلمة (لا مسودات)
    AND b.bill_date BETWEEN p_from_date AND p_to_date
    AND (p_branch_id IS NULL OR b.branch_id = p_branch_id)
    AND (p_cost_center_id IS NULL OR b.cost_center_id = p_cost_center_id)
    AND (p_supplier_id IS NULL OR b.supplier_id = p_supplier_id)
    AND (p_created_by_user_id IS NULL OR po.created_by_user_id = p_created_by_user_id)
    ORDER BY b.bill_date DESC, b.bill_number;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_enhanced_sales_report(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_customer_id uuid, p_created_by_user_id uuid, p_from_date date, p_to_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_enhanced_sales_report(p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_customer_id uuid DEFAULT NULL::uuid, p_created_by_user_id uuid DEFAULT NULL::uuid, p_from_date date DEFAULT (date_trunc('month'::text, (CURRENT_DATE)::timestamp with time zone))::date, p_to_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(invoice_id uuid, invoice_number text, invoice_date date, customer_id uuid, customer_name text, subtotal numeric, tax_amount numeric, total_amount numeric, paid_amount numeric, status text, created_by_user_id uuid, branch_id uuid, cost_center_id uuid)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT 
        i.id as invoice_id,
        i.invoice_number,
        i.invoice_date,
        i.customer_id,
        c.name as customer_name,
        i.subtotal,
        i.tax_amount,
        i.total_amount,
        COALESCE(i.paid_amount, 0) as paid_amount,
        i.status,
        so.created_by_user_id, -- من أمر البيع المرتبط
        i.branch_id,
        i.cost_center_id
    FROM invoices i
    JOIN customers c ON i.customer_id = c.id
    LEFT JOIN sales_orders so ON i.sales_order_id = so.id
    WHERE i.company_id = p_company_id
    AND i.status IN ('sent', 'paid', 'partially_paid') -- فقط الفواتير المرسلة (لا مسودات)
    AND i.invoice_date BETWEEN p_from_date AND p_to_date
    AND (p_branch_id IS NULL OR i.branch_id = p_branch_id)
    AND (p_cost_center_id IS NULL OR i.cost_center_id = p_cost_center_id)
    AND (p_customer_id IS NULL OR i.customer_id = p_customer_id)
    AND (p_created_by_user_id IS NULL OR so.created_by_user_id = p_created_by_user_id)
    ORDER BY i.invoice_date DESC, i.invoice_number;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_expired_seat_license_ids(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_expired_seat_license_ids(p_company_id uuid)
 RETURNS uuid[]
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(array_agg(id ORDER BY seat_number), ARRAY[]::uuid[])
    FROM public.company_seat_licenses
   WHERE company_id = p_company_id AND expires_at <= NOW();
$function$
;

-- ---------------------------------------------------------------
-- get_financial_summary(p_company_id uuid, p_start_date date, p_end_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_financial_summary(p_company_id uuid, p_start_date date, p_end_date date)
 RETURNS TABLE(total_revenue numeric, total_cogs numeric, gross_profit numeric, total_expenses numeric, net_income numeric, total_assets numeric, total_liabilities numeric, total_equity numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_revenue DECIMAL(15,2);
  v_cogs DECIMAL(15,2);
  v_expenses DECIMAL(15,2);
  v_assets DECIMAL(15,2);
  v_liabilities DECIMAL(15,2);
  v_equity DECIMAL(15,2);
BEGIN
  -- Revenue
  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount), 0) INTO v_revenue
  FROM journal_entry_lines jel
  JOIN journal_entries je ON jel.journal_entry_id = je.id
  JOIN chart_of_accounts coa ON jel.account_id = coa.id
  WHERE je.company_id = p_company_id
    AND coa.account_type = 'Revenue'
    AND je.entry_date BETWEEN p_start_date AND p_end_date
    AND je.status = 'posted';

  -- COGS
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0) INTO v_cogs
  FROM journal_entry_lines jel
  JOIN journal_entries je ON jel.journal_entry_id = je.id
  JOIN chart_of_accounts coa ON jel.account_id = coa.id
  WHERE je.company_id = p_company_id
    AND coa.account_type = 'COGS'
    AND je.entry_date BETWEEN p_start_date AND p_end_date
    AND je.status = 'posted';

  -- Expenses
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0) INTO v_expenses
  FROM journal_entry_lines jel
  JOIN journal_entries je ON jel.journal_entry_id = je.id
  JOIN chart_of_accounts coa ON jel.account_id = coa.id
  WHERE je.company_id = p_company_id
    AND coa.account_type = 'Expense'
    AND je.entry_date BETWEEN p_start_date AND p_end_date
    AND je.status = 'posted';

  -- Assets (as of end date)
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0) INTO v_assets
  FROM journal_entry_lines jel
  JOIN journal_entries je ON jel.journal_entry_id = je.id
  JOIN chart_of_accounts coa ON jel.account_id = coa.id
  WHERE je.company_id = p_company_id
    AND coa.account_type = 'Asset'
    AND je.entry_date <= p_end_date
    AND je.status = 'posted';

  -- Liabilities
  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount), 0) INTO v_liabilities
  FROM journal_entry_lines jel
  JOIN journal_entries je ON jel.journal_entry_id = je.id
  JOIN chart_of_accounts coa ON jel.account_id = coa.id
  WHERE je.company_id = p_company_id
    AND coa.account_type = 'Liability'
    AND je.entry_date <= p_end_date
    AND je.status = 'posted';

  -- Equity
  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount), 0) INTO v_equity
  FROM journal_entry_lines jel
  JOIN journal_entries je ON jel.journal_entry_id = je.id
  JOIN chart_of_accounts coa ON jel.account_id = coa.id
  WHERE je.company_id = p_company_id
    AND coa.account_type = 'Equity'
    AND je.entry_date <= p_end_date
    AND je.status = 'posted';

  RETURN QUERY SELECT 
    v_revenue,
    v_cogs,
    v_revenue - v_cogs as gross_profit,
    v_expenses,
    v_revenue - v_cogs - v_expenses as net_income,
    v_assets,
    v_liabilities,
    v_equity;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_gl_account_summary(p_company_id uuid, p_from_date date, p_to_date date, p_account_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_gl_account_summary(p_company_id uuid, p_from_date date DEFAULT '0001-01-01'::date, p_to_date date DEFAULT '9999-12-31'::date, p_account_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(account_id uuid, account_code text, account_name text, account_type text, sub_type text, opening_balance numeric, total_debit numeric, total_credit numeric, closing_balance numeric, transaction_count bigint)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  WITH period_movements AS (
    SELECT
      jel.account_id,
      ROUND(SUM(jel.debit_amount)::NUMERIC,  2) AS period_debit,
      ROUND(SUM(jel.credit_amount)::NUMERIC, 2) AS period_credit,
      COUNT(*) AS txn_count
    FROM public.journal_entry_lines jel
    JOIN public.journal_entries je ON je.id = jel.journal_entry_id
    WHERE je.company_id = p_company_id
      AND je.status = 'posted'
      AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
      AND je.deleted_at IS NULL
      AND je.entry_date BETWEEN p_from_date AND p_to_date
      AND (p_account_id IS NULL OR jel.account_id = p_account_id)
    GROUP BY jel.account_id
  ),
  pre_period_movements AS (
    SELECT
      jel.account_id,
      ROUND(SUM(jel.debit_amount - jel.credit_amount)::NUMERIC, 2) AS pre_net
    FROM public.journal_entry_lines jel
    JOIN public.journal_entries je ON je.id = jel.journal_entry_id
    WHERE je.company_id = p_company_id
      AND je.status = 'posted'
      AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
      AND je.deleted_at IS NULL
      AND je.entry_date < p_from_date
      AND (p_account_id IS NULL OR jel.account_id = p_account_id)
    GROUP BY jel.account_id
  )
  SELECT
    coa.id                                                               AS account_id,
    coa.account_code,
    coa.account_name,
    coa.account_type,
    coa.sub_type,
    ROUND((COALESCE(coa.opening_balance, 0) + COALESCE(pp.pre_net, 0))::NUMERIC, 2) AS opening_balance,
    COALESCE(pm.period_debit,  0)                                        AS total_debit,
    COALESCE(pm.period_credit, 0)                                        AS total_credit,
    ROUND((
      COALESCE(coa.opening_balance, 0)
      + COALESCE(pp.pre_net, 0)
      + COALESCE(pm.period_debit,  0)
      - COALESCE(pm.period_credit, 0)
    )::NUMERIC, 2)                                                       AS closing_balance,
    COALESCE(pm.txn_count, 0)                                           AS transaction_count
  FROM public.chart_of_accounts coa
  LEFT JOIN period_movements    pm ON pm.account_id = coa.id
  LEFT JOIN pre_period_movements pp ON pp.account_id = coa.id
  WHERE coa.company_id = p_company_id
    AND coa.is_active = TRUE
    AND (p_account_id IS NULL OR coa.id = p_account_id)
    AND (
      COALESCE(pm.txn_count, 0) > 0
      OR ABS(COALESCE(coa.opening_balance, 0) + COALESCE(pp.pre_net, 0)) >= 0.01
    )
  ORDER BY coa.account_code;
$function$
;

-- ---------------------------------------------------------------
-- get_gl_ar_balance_per_invoice(p_company_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_gl_ar_balance_per_invoice(p_company_id uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(invoice_id text, customer_id uuid, invoice_number text, invoice_date date, due_date date, ar_debit numeric, ar_credit numeric, outstanding numeric)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  WITH ar_accounts AS (
    SELECT id
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND is_active  = true
      AND (
        sub_type      = 'accounts_receivable'
        OR account_name ILIKE '%receivable%'
        OR account_name ILIKE '%الذمم المدين%'
      )
  ),
  ar_debits AS (
    SELECT
      je.reference_id::TEXT AS invoice_id,
      SUM(jel.debit_amount) AS amount
    FROM journal_entries je
    JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE je.company_id     = p_company_id
      AND je.status         = 'posted'
      AND je.reference_type = 'invoice'
      AND je.entry_date    <= p_as_of_date
      AND (je.is_deleted IS NULL OR je.is_deleted = false)
      AND je.deleted_at IS NULL
      AND jel.account_id IN (SELECT id FROM ar_accounts)
    GROUP BY je.reference_id
  ),
  ar_payment_credits AS (
    SELECT
      je.reference_id::TEXT AS invoice_id,
      SUM(jel.credit_amount) AS amount
    FROM journal_entries je
    JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE je.company_id     = p_company_id
      AND je.status         = 'posted'
      AND je.reference_type = 'invoice_payment'
      AND je.entry_date    <= p_as_of_date
      AND (je.is_deleted IS NULL OR je.is_deleted = false)
      AND je.deleted_at IS NULL
      AND jel.account_id IN (SELECT id FROM ar_accounts)
    GROUP BY je.reference_id
  ),
  ar_return_credits AS (
    SELECT
      sr.invoice_id::TEXT AS invoice_id,
      SUM(jel.credit_amount) AS amount
    FROM journal_entries je
    JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    JOIN sales_returns sr ON je.reference_id = sr.id
    WHERE je.company_id     = p_company_id
      AND je.status         = 'posted'
      AND je.reference_type = 'sales_return'
      AND je.entry_date    <= p_as_of_date
      AND (je.is_deleted IS NULL OR je.is_deleted = false)
      AND je.deleted_at IS NULL
      AND jel.account_id IN (SELECT id FROM ar_accounts)
    GROUP BY sr.invoice_id
  )

  SELECT
    i.id::TEXT                                       AS invoice_id,
    i.customer_id,
    i.invoice_number,
    i.invoice_date,
    i.due_date,
    COALESCE(d.amount, 0)                            AS ar_debit,
    COALESCE(pc.amount, 0) + COALESCE(rc.amount, 0) AS ar_credit,
    GREATEST(0,
      COALESCE(d.amount, 0)
      - COALESCE(pc.amount, 0)
      - COALESCE(rc.amount, 0)
    )                                                AS outstanding
  FROM invoices i
  LEFT JOIN ar_debits         d  ON d.invoice_id  = i.id::TEXT
  LEFT JOIN ar_payment_credits pc ON pc.invoice_id = i.id::TEXT
  LEFT JOIN ar_return_credits  rc ON rc.invoice_id = i.id::TEXT
  WHERE i.company_id = p_company_id
    AND i.status NOT IN ('draft', 'cancelled', 'fully_returned')
    AND (i.is_deleted IS NULL OR i.is_deleted = false)
    AND COALESCE(d.amount, 0) > 0
  ORDER BY i.due_date ASC NULLS LAST;
$function$
;

-- ---------------------------------------------------------------
-- get_gl_transactions_paginated(p_company_id uuid, p_account_id uuid, p_from_date date, p_to_date date, p_page integer, p_page_size integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_gl_transactions_paginated(p_company_id uuid, p_account_id uuid, p_from_date date DEFAULT '0001-01-01'::date, p_to_date date DEFAULT '9999-12-31'::date, p_page integer DEFAULT 1, p_page_size integer DEFAULT 50)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_offset         INT;
  v_total_count    BIGINT := 0;
  v_opening_bal    NUMERIC(15,2) := 0;
  v_page_opening   NUMERIC(15,2) := 0;
  v_account_info   JSONB;
  v_transactions   JSONB;
BEGIN
  p_page      := GREATEST(1, p_page);
  p_page_size := LEAST(200, GREATEST(10, p_page_size));
  v_offset    := (p_page - 1) * p_page_size;

  -- معلومات الحساب
  SELECT jsonb_build_object(
    'id',       coa.id,
    'code',     coa.account_code,
    'name',     coa.account_name,
    'type',     coa.account_type,
    'sub_type', coa.sub_type
  ) INTO v_account_info
  FROM public.chart_of_accounts coa
  WHERE coa.id = p_account_id AND coa.company_id = p_company_id;

  IF v_account_info IS NULL THEN
    RAISE EXCEPTION 'ACCOUNT_NOT_FOUND: %', p_account_id;
  END IF;

  -- الرصيد الافتتاحي: opening_balance + حركات قبل فترة الطلب
  SELECT ROUND((
    COALESCE((
      SELECT opening_balance FROM public.chart_of_accounts
      WHERE id = p_account_id AND company_id = p_company_id
    ), 0) +
    COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)
  )::NUMERIC, 2) INTO v_opening_bal
  FROM public.journal_entry_lines jel
  JOIN public.journal_entries je ON je.id = jel.journal_entry_id
  WHERE jel.account_id = p_account_id
    AND je.company_id = p_company_id
    AND je.status = 'posted'
    AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
    AND je.deleted_at IS NULL
    AND je.entry_date < p_from_date;

  -- إجمالي عدد السطور في الفترة
  SELECT COUNT(*) INTO v_total_count
  FROM public.journal_entry_lines jel
  JOIN public.journal_entries je ON je.id = jel.journal_entry_id
  WHERE jel.account_id = p_account_id
    AND je.company_id = p_company_id
    AND je.status = 'posted'
    AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
    AND je.deleted_at IS NULL
    AND je.entry_date BETWEEN p_from_date AND p_to_date;

  -- الرصيد عند بداية الصفحة الحالية (مجموع كل السطور قبل OFFSET)
  SELECT ROUND((
    v_opening_bal +
    COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)
  )::NUMERIC, 2) INTO v_page_opening
  FROM (
    SELECT jel.debit_amount, jel.credit_amount
    FROM public.journal_entry_lines jel
    JOIN public.journal_entries je ON je.id = jel.journal_entry_id
    WHERE jel.account_id = p_account_id
      AND je.company_id = p_company_id
      AND je.status = 'posted'
      AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
      AND je.deleted_at IS NULL
      AND je.entry_date BETWEEN p_from_date AND p_to_date
    ORDER BY je.entry_date, je.entry_number, jel.id
    LIMIT v_offset
  ) pre_page;

  -- جلب سطور الصفحة المطلوبة
  SELECT jsonb_agg(row_data ORDER BY row_data->>'date', row_data->>'entry_number') INTO v_transactions
  FROM (
    SELECT jsonb_build_object(
      'line_id',       jel.id,
      'date',          je.entry_date,
      'entry_number',  COALESCE(je.entry_number, 'JE-' || LEFT(je.id::TEXT, 8)),
      'description',   COALESCE(jel.description, je.description, ''),
      'reference_type', je.reference_type,
      'debit',         ROUND(COALESCE(jel.debit_amount,  0)::NUMERIC, 2),
      'credit',        ROUND(COALESCE(jel.credit_amount, 0)::NUMERIC, 2)
    ) AS row_data
    FROM public.journal_entry_lines jel
    JOIN public.journal_entries je ON je.id = jel.journal_entry_id
    WHERE jel.account_id = p_account_id
      AND je.company_id = p_company_id
      AND je.status = 'posted'
      AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
      AND je.deleted_at IS NULL
      AND je.entry_date BETWEEN p_from_date AND p_to_date
    ORDER BY je.entry_date, je.entry_number, jel.id
    LIMIT p_page_size OFFSET v_offset
  ) page_rows;

  RETURN jsonb_build_object(
    'account',         v_account_info,
    'opening_balance', v_opening_bal,
    'page_opening_balance', COALESCE(v_page_opening, v_opening_bal),
    'transactions',    COALESCE(v_transactions, '[]'::JSONB),
    'pagination', jsonb_build_object(
      'page',      p_page,
      'page_size', p_page_size,
      'total',     v_total_count,
      'pages',     CEIL(v_total_count::NUMERIC / p_page_size),
      'has_next',  v_offset + p_page_size < v_total_count,
      'has_prev',  p_page > 1
    ),
    'period', jsonb_build_object('from', p_from_date, 'to', p_to_date)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_income_statement(p_company_id uuid, p_start_date date, p_end_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_income_statement(p_company_id uuid, p_start_date date, p_end_date date)
 RETURNS TABLE(section text, account_id uuid, account_code text, account_name text, amount numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    coa.account_type as section,
    coa.id as account_id,
    coa.code as account_code,
    coa.name as account_name,
    CASE 
      WHEN coa.account_type = 'Revenue' THEN 
        (COALESCE(coa.opening_balance, 0) + COALESCE(SUM(jel.credit_amount - jel.debit_amount), 0))
      WHEN coa.account_type IN ('Expense', 'COGS') THEN 
        (COALESCE(coa.opening_balance, 0) + COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0))
      ELSE 0
    END as amount
  FROM public.chart_of_accounts coa
  LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
  LEFT JOIN public.journal_entries je ON jel.journal_entry_id = je.id
  WHERE coa.company_id = p_company_id
    AND coa.account_type IN ('Revenue', 'Expense', 'COGS')
    AND coa.is_active = TRUE
    AND (je.id IS NULL OR (
      je.entry_date BETWEEN p_start_date AND p_end_date
      AND je.status = 'posted'
    ))
  GROUP BY coa.id, coa.code, coa.name, coa.account_type, coa.opening_balance
  HAVING (COALESCE(coa.opening_balance, 0) + SUM(jel.debit_amount)) != 0 OR (COALESCE(coa.opening_balance, 0) + SUM(jel.credit_amount)) != 0
  ORDER BY 
    CASE coa.account_type
      WHEN 'Revenue' THEN 1
      WHEN 'COGS' THEN 2
      WHEN 'Expense' THEN 3
    END,
    coa.code;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_inventory_available_balance(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_cost_center_id uuid, p_product_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_inventory_available_balance(p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_product_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(company_id uuid, branch_id uuid, warehouse_id uuid, cost_center_id uuid, product_id uuid, available_quantity integer, transaction_count bigint)
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    iab.company_id,
    iab.branch_id,
    iab.warehouse_id,
    iab.cost_center_id,
    iab.product_id,
    iab.available_quantity,
    iab.transaction_count
  FROM inventory_available_balance iab
  WHERE iab.company_id = p_company_id  -- ⚠️ فحص أمان إلزامي
    AND (p_branch_id IS NULL OR iab.branch_id = p_branch_id)
    AND (p_warehouse_id IS NULL OR iab.warehouse_id = p_warehouse_id)
    AND (p_cost_center_id IS NULL OR iab.cost_center_id = p_cost_center_id)
    AND (p_product_id IS NULL OR iab.product_id = p_product_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- get_inventory_reservation_balances()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_inventory_reservation_balances()
 RETURNS TABLE(company_id uuid, branch_id uuid, warehouse_id uuid, product_id uuid, on_hand_quantity numeric, reserved_quantity numeric, free_quantity numeric, shortage_quantity numeric, open_reservation_count bigint, open_allocation_count bigint, last_inventory_transaction_at timestamp with time zone, last_reservation_activity_at timestamp with time zone)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  WITH inventory_buckets AS (
    SELECT
      it.company_id,
      it.branch_id,
      it.warehouse_id,
      it.product_id,
      COALESCE(SUM(it.quantity_change), 0)::NUMERIC(18,4) AS on_hand_quantity,
      MAX(it.created_at) AS last_inventory_transaction_at
    FROM public.inventory_transactions it
    WHERE COALESCE(it.is_deleted, false) = false
    GROUP BY
      it.company_id,
      it.branch_id,
      it.warehouse_id,
      it.product_id
  ),
  open_allocations AS (
    SELECT
      a.company_id,
      a.branch_id,
      a.warehouse_id,
      a.product_id,
      a.reservation_id,
      a.id AS allocation_id,
      GREATEST(a.allocated_qty - a.consumed_qty - a.released_qty, 0)::NUMERIC(18,4) AS open_reserved_quantity,
      a.updated_at
    FROM public.inventory_reservation_allocations a
    WHERE GREATEST(a.allocated_qty - a.consumed_qty - a.released_qty, 0) > 0
  ),
  reservation_buckets AS (
    SELECT
      oa.company_id,
      oa.branch_id,
      oa.warehouse_id,
      oa.product_id,
      COALESCE(SUM(oa.open_reserved_quantity), 0)::NUMERIC(18,4) AS reserved_quantity,
      COUNT(DISTINCT oa.reservation_id)::BIGINT AS open_reservation_count,
      COUNT(*)::BIGINT AS open_allocation_count,
      MAX(oa.updated_at) AS last_reservation_activity_at
    FROM open_allocations oa
    GROUP BY
      oa.company_id,
      oa.branch_id,
      oa.warehouse_id,
      oa.product_id
  )
  SELECT
    COALESCE(i.company_id, r.company_id) AS company_id,
    COALESCE(i.branch_id, r.branch_id) AS branch_id,
    COALESCE(i.warehouse_id, r.warehouse_id) AS warehouse_id,
    COALESCE(i.product_id, r.product_id) AS product_id,
    COALESCE(i.on_hand_quantity, 0)::NUMERIC(18,4) AS on_hand_quantity,
    COALESCE(r.reserved_quantity, 0)::NUMERIC(18,4) AS reserved_quantity,
    GREATEST(COALESCE(i.on_hand_quantity, 0) - COALESCE(r.reserved_quantity, 0), 0)::NUMERIC(18,4) AS free_quantity,
    GREATEST(COALESCE(r.reserved_quantity, 0) - COALESCE(i.on_hand_quantity, 0), 0)::NUMERIC(18,4) AS shortage_quantity,
    COALESCE(r.open_reservation_count, 0)::BIGINT AS open_reservation_count,
    COALESCE(r.open_allocation_count, 0)::BIGINT AS open_allocation_count,
    i.last_inventory_transaction_at,
    r.last_reservation_activity_at
  FROM inventory_buckets i
  FULL OUTER JOIN reservation_buckets r
    ON r.company_id = i.company_id
   AND r.branch_id = i.branch_id
   AND r.warehouse_id = i.warehouse_id
   AND r.product_id = i.product_id
  WHERE COALESCE(i.company_id, r.company_id) IS NOT NULL;
$function$
;

-- ---------------------------------------------------------------
-- get_inventory_reservation_snapshot(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_inventory_reservation_snapshot(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid)
 RETURNS TABLE(company_id uuid, branch_id uuid, warehouse_id uuid, product_id uuid, on_hand_quantity numeric, reserved_quantity numeric, free_quantity numeric, shortage_quantity numeric, open_reservation_count bigint, open_allocation_count bigint, last_inventory_transaction_at timestamp with time zone, last_reservation_activity_at timestamp with time zone)
 LANGUAGE sql
 STABLE
 SET search_path TO 'public', 'pg_temp'
AS $function$
  WITH balance AS (
    SELECT *
    FROM public.get_inventory_reservation_balances()
    WHERE company_id = p_company_id
      AND branch_id = p_branch_id
      AND warehouse_id = p_warehouse_id
      AND product_id = p_product_id
  )
  SELECT
    p_company_id AS company_id,
    p_branch_id AS branch_id,
    p_warehouse_id AS warehouse_id,
    p_product_id AS product_id,
    COALESCE((SELECT b.on_hand_quantity FROM balance b), 0)::NUMERIC(18,4) AS on_hand_quantity,
    COALESCE((SELECT b.reserved_quantity FROM balance b), 0)::NUMERIC(18,4) AS reserved_quantity,
    COALESCE((SELECT b.free_quantity FROM balance b), 0)::NUMERIC(18,4) AS free_quantity,
    COALESCE((SELECT b.shortage_quantity FROM balance b), 0)::NUMERIC(18,4) AS shortage_quantity,
    COALESCE((SELECT b.open_reservation_count FROM balance b), 0)::BIGINT AS open_reservation_count,
    COALESCE((SELECT b.open_allocation_count FROM balance b), 0)::BIGINT AS open_allocation_count,
    (SELECT b.last_inventory_transaction_at FROM balance b) AS last_inventory_transaction_at,
    (SELECT b.last_reservation_activity_at FROM balance b) AS last_reservation_activity_at;
$function$
;

-- ---------------------------------------------------------------
-- get_invoice_effective_outstanding(p_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_invoice_effective_outstanding(p_invoice_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_total        numeric := 0;
  v_paid         numeric := 0;
  v_returned     numeric := 0;
  v_pending_sr   numeric := 0;
  v_pending_pay  numeric := 0;
BEGIN
  IF p_invoice_id IS NULL THEN RETURN 0; END IF;

  SELECT COALESCE(total_amount, 0), COALESCE(paid_amount, 0),
         COALESCE(returned_amount, 0)
    INTO v_total, v_paid, v_returned
    FROM public.invoices WHERE id = p_invoice_id;
  IF NOT FOUND THEN RETURN 0; END IF;

  BEGIN
    SELECT COALESCE(SUM(srr.total_return_amount), 0) INTO v_pending_sr
      FROM public.sales_return_requests srr
     WHERE srr.invoice_id = p_invoice_id
       AND LOWER(COALESCE(srr.status, '')) IN (
         'pending', 'approved', 'partial_approval', 'pending_warehouse'
       );
  EXCEPTION WHEN undefined_table OR undefined_column THEN v_pending_sr := 0; END;

  SELECT COALESCE(SUM(
           COALESCE(p.base_currency_amount,
                    p.amount * COALESCE(NULLIF(p.exchange_rate, 0), 1))
         ), 0) INTO v_pending_pay
    FROM public.payments p
   WHERE p.status = 'pending_approval'
     AND p.voided_at IS NULL
     AND p.voids_payment_id IS NULL
     AND (
       p.invoice_id = p_invoice_id OR
       EXISTS (
         SELECT 1 FROM public.payment_allocations pa
          WHERE pa.payment_id = p.id AND pa.invoice_id = p_invoice_id
       )
     );

  RETURN GREATEST(v_total - v_paid - v_returned - v_pending_sr - v_pending_pay, 0);
END;
$function$
;

-- ---------------------------------------------------------------
-- get_invoice_source(p_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_invoice_source(p_invoice_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_company_id uuid;
  v_sales_order_id uuid;
  v_booking_id uuid;
  v_booking_no text;
  v_so_number text;
BEGIN
  SELECT company_id, sales_order_id INTO v_company_id, v_sales_order_id
  FROM public.invoices WHERE id = p_invoice_id;
  IF NOT FOUND THEN RETURN NULL; END IF;

  IF auth.uid() IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.company_members cm
    WHERE cm.company_id = v_company_id AND cm.user_id = auth.uid()
  ) THEN
    RETURN NULL;
  END IF;

  SELECT b.id, b.booking_no INTO v_booking_id, v_booking_no
  FROM public.bookings b WHERE b.invoice_id = p_invoice_id LIMIT 1;

  IF v_sales_order_id IS NOT NULL THEN
    SELECT so.so_number INTO v_so_number
    FROM public.sales_orders so WHERE so.id = v_sales_order_id;
  END IF;

  RETURN jsonb_build_object(
    'booking_id',     v_booking_id,
    'booking_no',     v_booking_no,
    'sales_order_id', v_sales_order_id,
    'so_number',      v_so_number
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_invoices_payload(p_company_id uuid, p_invoice_ids uuid[])
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_invoices_payload(p_company_id uuid, p_invoice_ids uuid[])
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  IF p_invoice_ids IS NULL OR array_length(p_invoice_ids, 1) = 0 THEN
    RETURN jsonb_build_object(
      'payments', '[]'::jsonb,
      'items', '[]'::jsonb,
      'returned_by_item', '[]'::jsonb,
      'invoice_to_employee', '{}'::jsonb,
      'active_return_requests', '{}'::jsonb
    );
  END IF;

  RETURN (
    WITH
    payments_agg AS (
      SELECT jsonb_agg(jsonb_build_object(
        'id', id, 'invoice_id', invoice_id, 'amount', amount,
        'currency_code', currency_code, 'exchange_rate', exchange_rate,
        'base_currency_amount', base_currency_amount
      )) AS rows
      FROM payments
      WHERE company_id = p_company_id AND invoice_id = ANY(p_invoice_ids)
    ),
    items_agg AS (
      SELECT jsonb_agg(jsonb_build_object(
        'invoice_id', ii.invoice_id, 'quantity', ii.quantity,
        'product_id', ii.product_id, 'returned_quantity', ii.returned_quantity,
        'products', jsonb_build_object('name', p.name)
      )) AS rows
      FROM invoice_items ii
      LEFT JOIN products p ON p.id = ii.product_id
      WHERE ii.invoice_id = ANY(p_invoice_ids)
    ),
    returns_agg AS (
      SELECT jsonb_agg(jsonb_build_object(
        'invoice_id', sr.invoice_id, 'product_id', sri.product_id, 'quantity', sri.quantity
      )) AS rows
      FROM sales_returns sr
      JOIN sales_return_items sri ON sri.sales_return_id = sr.id
      WHERE sr.invoice_id = ANY(p_invoice_ids)
    ),
    emp_map AS (
      SELECT jsonb_object_agg(
        i.id, COALESCE(so.created_by_user_id, i.created_by_user_id)
      ) FILTER (WHERE COALESCE(so.created_by_user_id, i.created_by_user_id) IS NOT NULL) AS map
      FROM invoices i
      LEFT JOIN sales_orders so ON so.id = i.sales_order_id
      WHERE i.id = ANY(p_invoice_ids)
    ),
    active_returns AS (
      SELECT jsonb_object_agg(
        invoice_id, jsonb_build_object('id', id, 'status', status)
      ) AS map
      FROM (
        SELECT DISTINCT ON (invoice_id) id, invoice_id, status, created_at
        FROM sales_return_requests
        WHERE company_id = p_company_id
          AND invoice_id = ANY(p_invoice_ids)
          AND status IN ('pending_approval_level_1','pending_warehouse_approval','pending')
        ORDER BY invoice_id, created_at DESC
      ) latest
    )
    SELECT jsonb_build_object(
      'payments', COALESCE((SELECT rows FROM payments_agg), '[]'::jsonb),
      'items', COALESCE((SELECT rows FROM items_agg), '[]'::jsonb),
      'returned_by_item', COALESCE((SELECT rows FROM returns_agg), '[]'::jsonb),
      'invoice_to_employee', COALESCE((SELECT map FROM emp_map), '{}'::jsonb),
      'active_return_requests', COALESCE((SELECT map FROM active_returns), '{}'::jsonb)
    )
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_journal_entry_id_for_bill_receipt(p_company_id uuid, p_bill_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_journal_entry_id_for_bill_receipt(p_company_id uuid, p_bill_id uuid)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT je.id
  FROM public.journal_entries je
  WHERE je.company_id = p_company_id
    AND je.reference_id = p_bill_id
  ORDER BY je.created_at DESC NULLS LAST
  LIMIT 1;
$function$
;

-- ---------------------------------------------------------------
-- get_notification_escalation_level(p_notification_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_notification_escalation_level(p_notification_id uuid)
 RETURNS integer
 LANGUAGE sql
 STABLE
AS $function$
