  FROM notification_escalations
  WHERE original_notification_id = p_notification_id;
$function$
;

-- ---------------------------------------------------------------
-- get_or_create_fx_account(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_or_create_fx_account(p_company_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_id uuid;
  v_expense_parent_id uuid;
BEGIN
  SELECT id INTO v_id
  FROM chart_of_accounts
  WHERE company_id = p_company_id
    AND sub_type = 'fx_gain_loss'
    AND COALESCE(is_active, true)
  LIMIT 1;

  IF v_id IS NOT NULL THEN
    RETURN v_id;
  END IF;

  SELECT id INTO v_expense_parent_id
  FROM chart_of_accounts
  WHERE company_id = p_company_id
    AND (account_type = 'expense' OR account_type = 'other')
    AND COALESCE(is_active, true)
  ORDER BY CASE WHEN account_type = 'expense' THEN 0 ELSE 1 END
  LIMIT 1;

  -- v3.74.37: aligned to real chart_of_accounts columns.
  INSERT INTO chart_of_accounts (
    company_id, parent_id, account_type, sub_type,
    account_code, account_name, normal_balance,
    is_active, description
  ) VALUES (
    p_company_id, v_expense_parent_id, 'expense', 'fx_gain_loss',
    'FX-001', 'فروق أسعار العملات الأجنبية', 'debit',
    true, 'FX Gain/Loss'
  ) RETURNING id INTO v_id;

  RETURN v_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_pending_approvals_count(p_company_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_pending_approvals_count(p_company_id uuid, p_user_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_role        text;
  v_bom_count   integer := 0;
  v_rv_count    integer := 0;
  v_po_count    integer := 0;
  v_mi_count    integer := 0;
BEGIN
  -- التحقق من الدور
  SELECT role INTO v_role
  FROM public.company_members
  WHERE company_id = p_company_id
    AND user_id    = p_user_id
  LIMIT 1;

  -- يُعيد 0 لغير الأدوار الإدارية العليا
  IF v_role NOT IN ('admin', 'owner', 'general_manager', 'manager') THEN
    RETURN 0;
  END IF;

  -- BOM versions بانتظار الاعتماد
  SELECT COUNT(*) INTO v_bom_count
  FROM public.manufacturing_bom_versions
  WHERE company_id = p_company_id
    AND status     = 'pending_approval';

  -- Routing versions بانتظار الاعتماد
  -- Note: approval_status column from migration 20260515000200 may not exist yet
  -- Fall back to status column which always exists
  SELECT COUNT(*) INTO v_rv_count
  FROM public.manufacturing_routing_versions
  WHERE company_id = p_company_id
    AND status     = 'pending_approval';

  -- Production orders بانتظار الاعتماد (uses status column, NOT approval_status)
  SELECT COUNT(*) INTO v_po_count
  FROM public.manufacturing_production_orders
  WHERE company_id = p_company_id
    AND status     = 'pending_approval';

  -- Material issues — Stage 1 فقط (انتظار موافقة الإدارة)
  SELECT COUNT(*) INTO v_mi_count
  FROM public.manufacturing_material_issue_approvals
  WHERE company_id = p_company_id
    AND status     = 'pending';

  RETURN v_bom_count + v_rv_count + v_po_count + v_mi_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_pending_dispatch_count(p_company_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_pending_dispatch_count(p_company_id uuid, p_user_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_role            text;
  v_warehouse_id    uuid;
  v_dispatch_count  integer := 0;
BEGIN
  SELECT role, warehouse_id
  INTO   v_role, v_warehouse_id
  FROM   public.company_members
  WHERE  company_id = p_company_id
    AND  user_id    = p_user_id
  LIMIT 1;

  IF v_role NOT IN ('store_manager', 'warehouse_manager', 'admin', 'owner', 'general_manager', 'manager') THEN
    RETURN 0;
  END IF;

  IF v_role IN ('store_manager', 'warehouse_manager') AND v_warehouse_id IS NOT NULL THEN
    -- مسؤول المخزن يرى مخزنه فقط
    SELECT COUNT(*) INTO v_dispatch_count
    FROM public.manufacturing_material_issue_approvals
    WHERE company_id   = p_company_id
      AND status       = 'management_approved'
      AND warehouse_id = v_warehouse_id;
  ELSE
    -- الإدارة ترى الكل
    SELECT COUNT(*) INTO v_dispatch_count
    FROM public.manufacturing_material_issue_approvals
    WHERE company_id = p_company_id
      AND status     = 'management_approved';
  END IF;

  RETURN v_dispatch_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_pending_dividends(p_company_id uuid, p_shareholder_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_pending_dividends(p_company_id uuid, p_shareholder_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(distribution_id uuid, distribution_date date, line_id uuid, shareholder_id uuid, shareholder_name text, total_amount numeric, paid_amount numeric, remaining_amount numeric, status text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    pd.id as distribution_id,
    pd.distribution_date,
    pdl.id as line_id,
    pdl.shareholder_id,
    s.name as shareholder_name,
    pdl.amount as total_amount,
    COALESCE(pdl.paid_amount, 0) as paid_amount,
    (pdl.amount - COALESCE(pdl.paid_amount, 0)) as remaining_amount,
    pdl.status
  FROM profit_distributions pd
  JOIN profit_distribution_lines pdl ON pdl.distribution_id = pd.id
  JOIN shareholders s ON s.id = pdl.shareholder_id
  WHERE pd.company_id = p_company_id
    AND pd.status IN ('approved', 'partially_paid')
    AND pdl.status IN ('pending', 'partially_paid')
    AND (p_shareholder_id IS NULL OR pdl.shareholder_id = p_shareholder_id)
  ORDER BY pd.distribution_date DESC;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_permission_stats(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_permission_stats(p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_active_sharing INTEGER;
  v_total_transfers INTEGER;
  v_branch_access INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_active_sharing FROM permission_sharing 
  WHERE company_id = p_company_id AND is_active = TRUE;
  
  SELECT COUNT(*) INTO v_total_transfers FROM permission_transfers 
  WHERE company_id = p_company_id;
  
  SELECT COUNT(*) INTO v_branch_access FROM user_branch_access 
  WHERE company_id = p_company_id AND is_active = TRUE;
  
  RETURN jsonb_build_object(
    'active_sharing', v_active_sharing,
    'total_transfers', v_total_transfers,
    'branch_access', v_branch_access
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_privileged_manager_user_ids(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_privileged_manager_user_ids(p_company_id uuid)
 RETURNS TABLE(user_id uuid)
 LANGUAGE sql
