-- ---------------------------------------------------------------
-- get_reconciliation_status(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_reconciliation_status(p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_result JSONB; v_last_run DATE; v_critical INTEGER; v_warnings INTEGER;
BEGIN
  SELECT MAX(run_date) INTO v_last_run FROM daily_reconciliation_log WHERE company_id = p_company_id;
  SELECT COUNT(CASE WHEN severity='critical' AND NOT is_ok THEN 1 END),
         COUNT(CASE WHEN severity='warning' AND NOT is_ok THEN 1 END)
  INTO v_critical, v_warnings
  FROM daily_reconciliation_log WHERE company_id = p_company_id AND run_date = v_last_run;
  SELECT jsonb_build_object('last_run_date',v_last_run,'critical_failures',v_critical,'warning_failures',v_warnings,'is_healthy',v_critical=0,
    'checks', jsonb_agg(jsonb_build_object('check_name',check_name,'is_ok',is_ok,'severity',severity,'gl_value',gl_value,'operational_value',operational_value,'difference',difference,'message',message) ORDER BY severity DESC, is_ok ASC))
  INTO v_result FROM daily_reconciliation_log WHERE company_id = p_company_id AND run_date = v_last_run;
  RETURN COALESCE(v_result, jsonb_build_object('error','No reconciliation data found','last_run_date',NULL));
END; $function$
;

-- ---------------------------------------------------------------
-- get_related_audit_logs(p_log_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_related_audit_logs(p_log_id uuid)
 RETURNS TABLE(id uuid, action text, target_table text, record_id uuid, record_identifier text, created_at timestamp with time zone, relation_type text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_log RECORD;
BEGIN
  -- Get the original log
  SELECT * INTO v_log FROM audit_logs al WHERE al.id = p_log_id;
  IF NOT FOUND THEN RETURN; END IF;
  
  -- Return logs with the same batch_id (if exists)
  IF v_log.batch_id IS NOT NULL THEN
    RETURN QUERY
    SELECT al.id, al.action, al.target_table, al.record_id,
           al.record_identifier, al.created_at, 'batch'::TEXT as relation_type
    FROM audit_logs al
    WHERE al.batch_id = v_log.batch_id
      AND al.id != p_log_id
    ORDER BY al.created_at DESC
    LIMIT 50;
  ELSE
    -- Simple search: same user within 5 seconds, limited results
    RETURN QUERY
    SELECT al.id, al.action, al.target_table, al.record_id,
           al.record_identifier, al.created_at, 'related'::TEXT as relation_type
    FROM audit_logs al
    WHERE al.company_id = v_log.company_id
      AND al.user_id = v_log.user_id
      AND al.id != p_log_id
      AND al.created_at BETWEEN v_log.created_at - INTERVAL '5 seconds'
                            AND v_log.created_at + INTERVAL '5 seconds'
    ORDER BY al.created_at DESC
    LIMIT 50;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_retained_earnings_balance(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_retained_earnings_balance(p_company_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_re  DECIMAL := 0;
    v_inc DECIMAL := 0;
      v_exp DECIMAL := 0;
      BEGIN
        SELECT COALESCE(SUM(jel.credit_amount) - SUM(jel.debit_amount), 0)
            INTO v_re
              FROM journal_entry_lines jel
                JOIN journal_entries je ON je.id = jel.journal_entry_id
                  JOIN chart_of_accounts coa ON coa.id = jel.account_id
                    WHERE coa.company_id = p_company_id
                        AND coa.account_type = 'equity'
                            AND (coa.sub_type = 'retained_earnings' OR coa.account_code = '3200')
                                AND je.company_id = p_company_id
                                    AND COALESCE(je.status, 'posted') NOT IN ('cancelled', 'draft');
                                      SELECT COALESCE(SUM(jel.credit_amount) - SUM(jel.debit_amount), 0)
                                          INTO v_inc
                                            FROM journal_entry_lines jel
                                              JOIN journal_entries je ON je.id = jel.journal_entry_id
                                                JOIN chart_of_accounts coa ON coa.id = jel.account_id
                                                  WHERE coa.company_id = p_company_id
                                                      AND coa.account_type IN ('income', 'revenue')
                                                          AND je.company_id = p_company_id
                                                              AND je.status = 'posted';
                                                                SELECT COALESCE(SUM(jel.debit_amount) - SUM(jel.credit_amount), 0)
                                                                    INTO v_exp
                                                                      FROM journal_entry_lines jel
                                                                        JOIN journal_entries je ON je.id = jel.journal_entry_id
                                                                          JOIN chart_of_accounts coa ON coa.id = jel.account_id
                                                                            WHERE coa.company_id = p_company_id
                                                                                AND coa.account_type = 'expense'
                                                                                    AND je.company_id = p_company_id
                                                                                        AND je.status = 'posted';
                                                                                          RETURN v_re + (v_inc - v_exp);
                                                                                          END;
                                                                                          $function$
;

-- ---------------------------------------------------------------
-- get_seat_status(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_seat_status(p_company_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_total_paid_seats  INTEGER := 0;
  v_owner_id          UUID;
  v_active_members    INTEGER := 0;
  v_pending_invites   INTEGER := 0;
  v_available         INTEGER := 0;
  v_sub_status        TEXT    := 'free';
  v_price_per_seat    INTEGER := 500;
  v_can_invite        BOOLEAN := false;
  v_is_suspended      BOOLEAN := false;
  v_license_count     INTEGER := 0;
  v_empty_active      INTEGER := 0;
  v_expired_count     INTEGER := 0;
  v_active_count      INTEGER := 0;
BEGIN
  SELECT user_id, subscription_status INTO v_owner_id, v_sub_status
  FROM companies WHERE id = p_company_id;
  IF NOT FOUND THEN RETURN json_build_object('error', 'Company not found'); END IF;

  SELECT COALESCE(total_paid_seats, 0), COALESCE(price_per_seat_egp, 500)
  INTO v_total_paid_seats, v_price_per_seat
  FROM company_seats WHERE company_id = p_company_id;

  SELECT COUNT(*) INTO v_active_members
  FROM company_members WHERE company_id = p_company_id AND user_id != v_owner_id;

  SELECT COUNT(*) INTO v_pending_invites
  FROM company_invitations
  WHERE company_id = p_company_id AND accepted = FALSE AND seat_reserved = TRUE
    AND expires_at > now() AND COALESCE(status, 'pending') = 'pending';

  SELECT COUNT(*) INTO v_license_count
    FROM public.company_seat_licenses WHERE company_id = p_company_id;

  IF v_license_count > 0 THEN
    SELECT COUNT(*) INTO v_empty_active FROM public.company_seat_licenses
     WHERE company_id = p_company_id AND assigned_user_id IS NULL AND expires_at > NOW();
    SELECT COUNT(*) INTO v_expired_count FROM public.company_seat_licenses
     WHERE company_id = p_company_id AND expires_at <= NOW();
    SELECT COUNT(*) INTO v_active_count  FROM public.company_seat_licenses
     WHERE company_id = p_company_id AND expires_at > NOW();
    v_available := GREATEST(0, v_empty_active - v_pending_invites);
  ELSE
    v_available     := GREATEST(0, v_total_paid_seats - v_active_members - v_pending_invites);
    v_expired_count := 0;
    v_active_count  := v_total_paid_seats;
  END IF;

  IF v_sub_status = 'payment_failed' THEN
    v_can_invite := v_available > 0; v_is_suspended := true;
  ELSIF v_sub_status = 'free' THEN v_can_invite := false;
  ELSE v_can_invite := v_available > 0; END IF;

  RETURN json_build_object(
    'total_paid_seats', v_total_paid_seats,
    'used_seats', v_active_members,
    'reserved_seats', v_pending_invites,
    'available_seats', v_available,
    'can_invite', v_can_invite,
    'owner_id', v_owner_id,
    'subscription_status', COALESCE(v_sub_status, 'free'),
    'is_suspended', v_is_suspended,
    'price_per_seat_egp', v_price_per_seat,
    'license_count', v_license_count,
    'empty_active', v_empty_active,
    'expired_seat_count', v_expired_count,
    'active_seat_count', v_active_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_service_consumables(p_service_id uuid, p_booking_qty numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_service_consumables(p_service_id uuid, p_booking_qty numeric DEFAULT 1)
 RETURNS TABLE(product_id uuid, product_name text, qty_per_service numeric, qty_needed numeric, track_inventory boolean)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT sp.product_id, p.name, sp.quantity_per_service,
         sp.quantity_per_service * COALESCE(p_booking_qty, 1),
         COALESCE(p.track_inventory, false)
    FROM public.service_products sp
    JOIN public.products p ON p.id = sp.product_id
   WHERE sp.service_id = p_service_id
   ORDER BY p.name;
$function$
;

-- ---------------------------------------------------------------
-- get_suppliers_overview(p_company_id uuid, p_branch_filter uuid, p_search text, p_page integer, p_page_size integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_suppliers_overview(p_company_id uuid, p_branch_filter uuid DEFAULT NULL::uuid, p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_page_size integer DEFAULT 50)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  v_offset integer := GREATEST(0, (COALESCE(p_page, 1) - 1)) * COALESCE(p_page_size, 50);
  v_limit  integer := LEAST(GREATEST(COALESCE(p_page_size, 50), 1), 500);
  v_search text := NULLIF(TRIM(COALESCE(p_search, '')), '');
BEGIN
  RETURN (
    WITH base AS (
      SELECT s.*
      FROM suppliers s
      WHERE s.company_id = p_company_id
        AND (p_branch_filter IS NULL OR s.branch_id = p_branch_filter)
        AND (
             v_search IS NULL
             OR s.name  ILIKE '%' || v_search || '%'
             OR COALESCE(s.email,'') ILIKE '%' || v_search || '%'
             OR COALESCE(s.phone,'') ILIKE '%' || v_search || '%'
             OR COALESCE(s.tax_id,'') ILIKE '%' || v_search || '%'
        )
    ),
    -- v3.26.3: payables and bill overpayments come from the same scan of bills.
    -- Drafts / cancelled / fully_returned are pre-GL or terminal and contribute
    -- nothing to either column.
    bill_agg AS (
      SELECT supplier_id,
        COALESCE(SUM(GREATEST(
          GREATEST(COALESCE(total_amount,0) - COALESCE(returned_amount,0), 0)
            - COALESCE(paid_amount,0), 0
        )), 0) AS payables,
        COALESCE(SUM(GREATEST(
          COALESCE(paid_amount,0) - COALESCE(total_amount,0), 0
        )), 0) AS overpayments
      FROM bills
      WHERE company_id = p_company_id
        AND COALESCE(status,'') NOT IN ('draft','cancelled','fully_returned')
      GROUP BY supplier_id
    ),
    credit_agg AS (
      SELECT supplier_id,
        COALESCE(SUM(GREATEST(
          COALESCE(total_amount,0) - COALESCE(applied_amount,0), 0
        )), 0) AS open_credits
      FROM vendor_credits
      WHERE company_id = p_company_id
        AND COALESCE(status,'') = 'open'
      GROUP BY supplier_id
    ),
    -- v3.74.158 advance payments: supplier paid in advance, no bill yet.
    -- Prefer unallocated_amount when populated; fall back to amount for
    -- legacy rows.
    advance_agg AS (
      SELECT supplier_id,
        COALESCE(SUM(
          CASE
            WHEN unallocated_amount IS NOT NULL
              THEN GREATEST(COALESCE(unallocated_amount, 0), 0)
            ELSE GREATEST(ABS(COALESCE(amount, 0)), 0)
          END
        ), 0) AS advances
      FROM payments
      WHERE company_id = p_company_id
        AND supplier_id IS NOT NULL
        AND bill_id IS NULL
        AND invoice_id IS NULL
        AND COALESCE(status, '') = 'approved'
        AND COALESCE(is_deleted, false) = false
      GROUP BY supplier_id
    ),
    enriched AS (
      SELECT
        b.*,
        jsonb_build_object('branch_name', br.branch_name) AS branches,
        COALESCE(ba.payables, 0)     AS payables,
        COALESCE(ba.overpayments, 0) AS bill_overpayments,
        COALESCE(ca.open_credits, 0) AS open_credits,
        COALESCE(av.advances, 0)     AS advances
      FROM base b
      LEFT JOIN bill_agg ba    ON ba.supplier_id = b.id
      LEFT JOIN credit_agg ca  ON ca.supplier_id = b.id
      LEFT JOIN advance_agg av ON av.supplier_id = b.id
      LEFT JOIN branches br    ON br.id = b.branch_id
    )
    SELECT jsonb_build_object(
      'total', (SELECT COUNT(*) FROM enriched),
      'page',  COALESCE(p_page, 1),
      'page_size', v_limit,
      'rows', COALESCE(
        (SELECT jsonb_agg(to_jsonb(p))
         FROM (SELECT * FROM enriched ORDER BY name ASC NULLS LAST, created_at DESC LIMIT v_limit OFFSET v_offset) p),
        '[]'::jsonb)
    )
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_transfer_scope_counts(p_transfer_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_transfer_scope_counts(p_transfer_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  t           record;
  v_branch    uuid;
  v_snap_c    integer := 0;
  v_snap_so   integer := 0;
  v_curr_c    integer := 0;
  v_curr_so   integer := 0;
BEGIN
  SELECT * INTO t FROM public.permission_transfers WHERE id = p_transfer_id;
  IF t IS NULL THEN RETURN NULL; END IF;

  IF t.transfer_data IS NOT NULL THEN
    v_branch := NULLIF(t.transfer_data ->> 'branch_id','')::uuid;
    v_snap_c := COALESCE(jsonb_array_length(t.transfer_data -> 'snapshot_customer_ids'), 0);
    v_snap_so := COALESCE(jsonb_array_length(t.transfer_data -> 'snapshot_sales_order_ids'), 0);
  END IF;

  IF t.resource_type = 'customers' OR t.resource_type = 'all' THEN
    SELECT count(*)::int INTO v_curr_c
    FROM public.customers
    WHERE company_id = t.company_id
      AND created_by_user_id = t.from_user_id
      AND (v_branch IS NULL OR branch_id = v_branch);
  END IF;

  IF t.resource_type = 'sales_orders' OR t.resource_type = 'all' THEN
    SELECT count(*)::int INTO v_curr_so
    FROM public.sales_orders
    WHERE company_id = t.company_id
      AND created_by_user_id = t.from_user_id
      AND (v_branch IS NULL OR branch_id = v_branch);
  END IF;

  RETURN jsonb_build_object(
    'snapshot_customers',    v_snap_c,
    'snapshot_sales_orders', v_snap_so,
    'snapshot_total',        v_snap_c + v_snap_so,
    'current_customers',     v_curr_c,
    'current_sales_orders',  v_curr_so,
    'current_total',         v_curr_c + v_curr_so,
    'has_drift',             (v_snap_c + v_snap_so) <> (v_curr_c + v_curr_so),
    'resource_type',         t.resource_type,
    'branch_id',             v_branch
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_trial_balance(p_company_id uuid, p_start_date date, p_end_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_trial_balance(p_company_id uuid, p_start_date date, p_end_date date)
 RETURNS TABLE(account_id uuid, account_code text, account_name text, account_type text, total_debit numeric, total_credit numeric, balance numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    coa.id as account_id,
    coa.code as account_code,
    coa.name as account_name,
    coa.account_type,
    COALESCE(SUM(jel.debit_amount), 0) as total_debit,
    COALESCE(SUM(jel.credit_amount), 0) as total_credit,
    (COALESCE(coa.opening_balance, 0) + COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)) as balance
  FROM public.chart_of_accounts coa
  LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
  LEFT JOIN public.journal_entries je ON jel.journal_entry_id = je.id
  WHERE coa.company_id = p_company_id
    AND coa.is_active = TRUE
    AND (je.id IS NULL OR (
      je.entry_date BETWEEN p_start_date AND p_end_date
      AND je.status = 'posted'
    ))
  GROUP BY coa.id, coa.code, coa.name, coa.account_type, coa.opening_balance
  HAVING (COALESCE(coa.opening_balance, 0) + COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)) != 0 OR COUNT(jel.id) > 0
  ORDER BY coa.code;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_trial_balance(p_company_id uuid, p_start_date date, p_end_date date, p_branch_id uuid, p_cost_center_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_trial_balance(p_company_id uuid, p_start_date date, p_end_date date, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(account_id uuid, account_code text, account_name text, account_type text, total_debit numeric, total_credit numeric, balance numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    coa.id as account_id,
    coa.code as account_code,
    coa.name as account_name,
    coa.account_type,
    COALESCE(SUM(jel.debit_amount), 0) as total_debit,
    COALESCE(SUM(jel.credit_amount), 0) as total_credit,
    COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0) as balance
  FROM public.chart_of_accounts coa
  LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
  LEFT JOIN public.journal_entries je ON jel.journal_entry_id = je.id
  WHERE coa.company_id = p_company_id
    AND coa.is_active = TRUE
    AND (je.id IS NULL OR (
      je.entry_date BETWEEN p_start_date AND p_end_date
      AND je.status = 'posted'
      AND (p_branch_id IS NULL OR je.branch_id = p_branch_id)
      AND (p_cost_center_id IS NULL OR jel.cost_center_id = p_cost_center_id)
    ))
  GROUP BY coa.id, coa.code, coa.name, coa.account_type
  HAVING SUM(jel.debit_amount - jel.credit_amount) != 0 OR COUNT(jel.id) > 0
  ORDER BY coa.code;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_trial_balance(p_company_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_trial_balance(p_company_id uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(account_code text, account_name text, account_type text, debit_balance numeric, credit_balance numeric)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
  WITH account_balances AS (
    SELECT
      coa.id,
      coa.account_code,
      coa.account_name,
      coa.account_type,
      ROUND((
        COALESCE(coa.opening_balance, 0) +
        COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)
      )::NUMERIC, 2) AS net_balance
    FROM public.chart_of_accounts coa
    LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
    LEFT JOIN public.journal_entries je ON je.id = jel.journal_entry_id
      AND je.company_id = p_company_id
      AND je.status = 'posted'
      AND (je.is_deleted IS NULL OR je.is_deleted = FALSE)
      AND je.deleted_at IS NULL
      AND je.entry_date <= p_as_of_date
    WHERE coa.company_id = p_company_id
      AND coa.is_active = TRUE
    GROUP BY coa.id, coa.account_code, coa.account_name, coa.account_type, coa.opening_balance
    HAVING ABS(COALESCE(coa.opening_balance, 0) + COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)) >= 0.01
  )
  SELECT
    account_code,
    account_name,
    account_type,
    CASE WHEN net_balance > 0 THEN ROUND(net_balance, 2) ELSE 0 END AS debit_balance,
    CASE WHEN net_balance < 0 THEN ROUND(ABS(net_balance), 2) ELSE 0 END AS credit_balance
  FROM account_balances
  ORDER BY account_code;
$function$
;

-- ---------------------------------------------------------------
-- get_unprocessed_attendance_logs(p_company_id uuid, p_batch_size integer, p_worker_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_unprocessed_attendance_logs(p_company_id uuid, p_batch_size integer, p_worker_id uuid)
 RETURNS SETOF attendance_raw_logs
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
    RETURN QUERY
    UPDATE public.attendance_raw_logs
    SET processing_lock_id = p_worker_id,
        locked_at = NOW()
    WHERE id IN (
        SELECT id
        FROM public.attendance_raw_logs
        WHERE company_id = p_company_id 
          AND is_processed = false
          AND (processing_lock_id IS NULL OR locked_at < NOW() - INTERVAL '15 minutes') -- recover dead locks
        ORDER BY log_time ASC
        LIMIT p_batch_size
        FOR UPDATE SKIP LOCKED -- ⚡ CRITICAL FOR HIGH CONCURRENCY
    )
    RETURNING *;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_unread_notification_count(p_user_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_unread_notification_count(p_user_id uuid, p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_role VARCHAR(50);
  v_count INTEGER;
BEGIN
  -- Get user role
  SELECT cm.role INTO v_user_role
  FROM company_members cm
  WHERE cm.user_id = p_user_id
    AND cm.company_id = p_company_id
  LIMIT 1;

  -- Count unread notifications
  SELECT COUNT(*) INTO v_count
  FROM notifications n
  WHERE n.company_id = p_company_id
    AND n.status = 'unread'
    AND (
      n.assigned_to_user = p_user_id
      OR (
        n.assigned_to_user IS NULL
        AND (
          n.assigned_to_role = v_user_role
          OR n.assigned_to_role IS NULL
          OR v_user_role IN ('owner', 'admin', 'general_manager')
        )
      )
    )
    AND (p_branch_id IS NULL OR n.branch_id = p_branch_id OR n.branch_id IS NULL)
    AND (p_warehouse_id IS NULL OR n.warehouse_id = p_warehouse_id OR n.warehouse_id IS NULL)
    AND (n.expires_at IS NULL OR n.expires_at > NOW());

  RETURN COALESCE(v_count, 0);
END;
$function$
;

-- ---------------------------------------------------------------
-- get_user_approval_badges(p_user_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_user_approval_badges(p_user_id uuid, p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_role         text;
  v_branch_id    uuid;
  v_warehouse_id uuid;
  v_result       jsonb := '{}'::jsonb;
  v_n            int;
  v_is_admin     boolean;
BEGIN
  IF p_user_id IS NULL OR p_company_id IS NULL THEN RETURN '{}'::jsonb; END IF;
  SELECT role, branch_id, warehouse_id INTO v_role, v_branch_id, v_warehouse_id
  FROM company_members WHERE user_id = p_user_id AND company_id = p_company_id;
  IF v_role IS NULL THEN RETURN '{}'::jsonb; END IF;
  v_is_admin := v_role IN ('owner','admin');

  IF v_is_admin OR v_role IN ('general_manager','manager','accountant') THEN
    SELECT count(*) INTO v_n FROM sales_return_requests
    WHERE company_id = p_company_id
      AND status IN ('pending','pending_approval_level_1')
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_role IN ('manager','accountant') AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('sales_return_request_l1', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('store_manager','warehouse_manager','general_manager') THEN
    SELECT count(*) INTO v_n FROM sales_return_requests
    WHERE company_id = p_company_id AND status = 'pending_warehouse_approval'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_warehouse_id IS NOT NULL AND warehouse_id = v_warehouse_id)
           OR (v_warehouse_id IS NULL AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('sales_return_request_warehouse', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','manager','accountant') THEN
    SELECT count(*) INTO v_n FROM customer_debit_notes
    WHERE company_id = p_company_id AND approval_status = 'pending_approval'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_role IN ('manager','accountant') AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('customer_debit_note', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','accountant') THEN
    SELECT count(*) INTO v_n FROM customer_refund_requests
    WHERE company_id = p_company_id AND status = 'pending';
    v_result := v_result || jsonb_build_object('customer_refund_request', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','manager','purchasing_officer') THEN
    SELECT count(*) INTO v_n FROM purchase_requests
    WHERE company_id = p_company_id AND status = 'pending_approval'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_role IN ('manager','purchasing_officer') AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('purchase_request', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','manager','accountant') THEN
    SELECT count(*) INTO v_n FROM purchase_returns
    WHERE company_id = p_company_id AND workflow_status = 'pending_admin_approval'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_role IN ('manager','accountant') AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('purchase_return_admin', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('store_manager','warehouse_manager','general_manager') THEN
    SELECT count(*) INTO v_n FROM purchase_returns
    WHERE company_id = p_company_id AND workflow_status = 'pending_warehouse'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_warehouse_id IS NOT NULL AND warehouse_id = v_warehouse_id)
           OR (v_warehouse_id IS NULL AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('purchase_return_warehouse', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','accountant') THEN
    SELECT count(*) INTO v_n FROM vendor_refund_requests
    WHERE company_id = p_company_id AND status = 'pending_approval'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('vendor_refund_request', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('store_manager','warehouse_manager','general_manager') THEN
    SELECT count(*) INTO v_n FROM bills
    WHERE company_id = p_company_id AND receipt_status = 'pending'
      AND COALESCE(status,'') NOT IN ('cancelled','draft')
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_warehouse_id IS NOT NULL AND warehouse_id = v_warehouse_id)
           OR (v_warehouse_id IS NULL AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('bill_receipt', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('store_manager','warehouse_manager','general_manager') THEN
    SELECT count(*) INTO v_n FROM invoices
    WHERE company_id = p_company_id
      AND warehouse_status = 'pending'
      AND status IN ('sent','paid','partially_paid')
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_warehouse_id IS NOT NULL AND warehouse_id = v_warehouse_id)
           OR (v_warehouse_id IS NULL AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('dispatch_approval', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('store_manager','warehouse_manager','general_manager','manager','accountant') THEN
    SELECT count(*) INTO v_n FROM inventory_transfers
    WHERE company_id = p_company_id AND status IN ('pending_approval','pending','in_transit')
      AND (
        v_is_admin OR v_role = 'general_manager'
        OR (v_role IN ('manager','accountant') AND status = 'pending_approval' AND v_branch_id IS NOT NULL
            AND (source_branch_id = v_branch_id OR destination_branch_id = v_branch_id))
        OR (v_role IN ('store_manager','warehouse_manager') AND status = 'pending'
            AND v_warehouse_id IS NOT NULL AND source_warehouse_id = v_warehouse_id)
        OR (v_role IN ('store_manager','warehouse_manager') AND status = 'in_transit'
            AND v_warehouse_id IS NOT NULL AND destination_warehouse_id = v_warehouse_id)
      );
    v_result := v_result || jsonb_build_object('inventory_transfer', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('manager','general_manager','store_manager','warehouse_manager') THEN
    SELECT count(*) INTO v_n FROM inventory_write_offs
    WHERE company_id = p_company_id AND status = 'pending'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_role = 'manager' AND v_branch_id IS NOT NULL AND branch_id = v_branch_id)
           OR (v_role IN ('store_manager','warehouse_manager') AND v_warehouse_id IS NOT NULL AND warehouse_id = v_warehouse_id));
    v_result := v_result || jsonb_build_object('inventory_write_off', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','manager','accountant') THEN
    SELECT count(*) INTO v_n FROM expenses
    WHERE company_id = p_company_id AND status = 'pending_approval'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_role IN ('manager','accountant') AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('expense', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','manager','accountant') THEN
    SELECT count(*) INTO v_n FROM payments
    WHERE company_id = p_company_id AND status = 'pending_approval'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_role IN ('manager','accountant') AND v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('payment_approval', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','accountant') THEN
    SELECT count(*) INTO v_n FROM bank_voucher_requests
    WHERE company_id = p_company_id AND status = 'pending'
      AND (v_is_admin OR v_role = 'general_manager'
           OR (v_branch_id IS NOT NULL AND branch_id = v_branch_id));
    v_result := v_result || jsonb_build_object('bank_voucher_request', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('manufacturing_officer','manager','general_manager') THEN
    SELECT count(*) INTO v_n FROM manufacturing_material_issue_approvals
    WHERE company_id = p_company_id AND status = 'pending'
      AND (v_is_admin OR v_role IN ('general_manager','manager','manufacturing_officer'));
    v_result := v_result || jsonb_build_object('mfg_material_issue', v_n);
    SELECT count(*) INTO v_n FROM manufacturing_product_receive_approvals
    WHERE company_id = p_company_id AND status = 'pending';
    v_result := v_result || jsonb_build_object('mfg_product_receive', v_n);
  END IF;

  IF v_is_admin OR v_role IN ('general_manager','manager') THEN
    SELECT count(*) INTO v_n FROM permission_transfers
    WHERE company_id = p_company_id AND status = 'pending'
      AND transferred_by IS DISTINCT FROM p_user_id;
    v_result := v_result || jsonb_build_object('permission_transfer', v_n);
  END IF;

  -- v3.74.373 - discount approvals badge. Only owner/admin/general_manager
  -- are approvers per the owner's governance decision.
  IF v_is_admin OR v_role = 'general_manager' THEN
    SELECT count(*) INTO v_n FROM discount_approvals
    WHERE company_id = p_company_id AND status = 'pending';
    v_result := v_result || jsonb_build_object('discount_approval', v_n);
  END IF;

  RETURN v_result;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_user_company_ids()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_user_company_ids()
 RETURNS SETOF uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
AS $function$
  SELECT company_id FROM public.company_members WHERE user_id = auth.uid()
  UNION
  SELECT id FROM public.companies WHERE user_id = auth.uid();
$function$
;

-- ---------------------------------------------------------------
-- get_user_company_status(p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_user_company_status(p_user_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_company_id        uuid;
  v_owner_id          uuid;
  v_status            text;
  v_legacy_seat_num   int;
  v_paid_seats        int;
  v_is_owner          boolean;
  v_license_seat_num  int;
  v_license_expires   timestamptz;
  v_seat_suspended    boolean;
  v_company_suspended boolean;
BEGIN
  SELECT cm.company_id, cm.seat_number INTO v_company_id, v_legacy_seat_num
  FROM company_members cm WHERE cm.user_id = p_user_id LIMIT 1;

  IF v_company_id IS NULL THEN
    RETURN json_build_object(
      'has_company', false, 'is_owner', false, 'is_suspended', false,
      'is_company_suspended', false, 'is_seat_suspended', false
    );
  END IF;

  SELECT c.user_id, c.subscription_status INTO v_owner_id, v_status
  FROM companies c WHERE c.id = v_company_id;

  SELECT COALESCE(cs.total_paid_seats, 0) INTO v_paid_seats
  FROM company_seats cs WHERE cs.company_id = v_company_id;
  v_paid_seats := COALESCE(v_paid_seats, 0);

  v_is_owner := (v_owner_id = p_user_id);

  SELECT csl.seat_number, csl.expires_at
    INTO v_license_seat_num, v_license_expires
    FROM company_seat_licenses csl
   WHERE csl.assigned_user_id = p_user_id
   LIMIT 1;

  -- subscription_status kept for legacy callers but no longer gates.
  v_company_suspended := (v_status = 'payment_failed');

  IF v_is_owner THEN
    v_seat_suspended := false;
  ELSIF v_license_expires IS NULL THEN
    v_seat_suspended := true;
  ELSE
    v_seat_suspended := (v_license_expires <= NOW());
  END IF;

  RETURN json_build_object(
    'has_company', true, 'company_id', v_company_id, 'is_owner', v_is_owner,
    'subscription_status', COALESCE(v_status, 'free'),
    'seat_number', COALESCE(v_license_seat_num, v_legacy_seat_num),
    'paid_seats', v_paid_seats,
    'seat_expires_at', v_license_expires,
    'is_company_suspended', v_company_suspended,
    'is_seat_suspended', v_seat_suspended,
    -- v3.74.379 fix - access depends on the seat license only. The
    -- old "(NOT is_owner AND (company_suspended OR seat_suspended))"
    -- gated allowed users out when their company's last renewal
    -- failed even though the seat they paid for was still valid.
    'is_suspended', (NOT v_is_owner AND v_seat_suspended)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- get_user_dependencies(p_company_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_user_dependencies(p_company_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_result JSONB := '{}'::JSONB;
    v_count INT;
    v_total INT := 0;
BEGIN
    -- Check Invoices
    SELECT count(*) INTO v_count FROM invoices WHERE company_id = p_company_id AND created_by_user_id = p_user_id;
    IF v_count > 0 THEN v_result := jsonb_set(v_result, '{invoices}', to_jsonb(v_count)); v_total := v_total + v_count; END IF;
    
    -- Check Sales Orders
    SELECT count(*) INTO v_count FROM sales_orders WHERE company_id = p_company_id AND created_by_user_id = p_user_id;
    IF v_count > 0 THEN v_result := jsonb_set(v_result, '{sales_orders}', to_jsonb(v_count)); v_total := v_total + v_count; END IF;

    -- Check Purchase Orders
    SELECT count(*) INTO v_count FROM purchase_orders WHERE company_id = p_company_id AND created_by_user_id = p_user_id;
    IF v_count > 0 THEN v_result := jsonb_set(v_result, '{purchase_orders}', to_jsonb(v_count)); v_total := v_total + v_count; END IF;

    -- Check Bills
    SELECT count(*) INTO v_count FROM bills WHERE company_id = p_company_id AND (created_by_user_id = p_user_id OR created_by = p_user_id);
    IF v_count > 0 THEN v_result := jsonb_set(v_result, '{bills}', to_jsonb(v_count)); v_total := v_total + v_count; END IF;

    -- Check Customers
    SELECT count(*) INTO v_count FROM customers WHERE company_id = p_company_id AND created_by_user_id = p_user_id;
    IF v_count > 0 THEN v_result := jsonb_set(v_result, '{customers}', to_jsonb(v_count)); v_total := v_total + v_count; END IF;

    -- Check Suppliers
    SELECT count(*) INTO v_count FROM suppliers WHERE company_id = p_company_id AND created_by_user_id = p_user_id;
    IF v_count > 0 THEN v_result := jsonb_set(v_result, '{suppliers}', to_jsonb(v_count)); v_total := v_total + v_count; END IF;

    -- Check Journal Entries
    SELECT count(*) INTO v_count FROM journal_entries WHERE company_id = p_company_id AND posted_by = p_user_id;
    IF v_count > 0 THEN v_result := jsonb_set(v_result, '{journal_entries}', to_jsonb(v_count)); v_total := v_total + v_count; END IF;
    
    -- Expose total for easy checking
    v_result := jsonb_set(v_result, '{total}', to_jsonb(v_total));

    RETURN v_result;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_user_display_currency(p_user_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_user_display_currency(p_user_id uuid, p_company_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_is_owner BOOLEAN;
  v_preferred_currency TEXT;
  v_sync_enabled BOOLEAN;
  v_company_currency TEXT;
BEGIN
  SELECT (user_id = p_user_id) INTO v_is_owner
  FROM companies
  WHERE id = p_company_id;

  SELECT COALESCE(base_currency, currency, 'EGP') INTO v_company_currency
  FROM companies
  WHERE id = p_company_id;

  IF v_is_owner THEN
    SELECT preferred_currency INTO v_preferred_currency
    FROM company_members
    WHERE user_id = p_user_id AND company_id = p_company_id;
    
    RETURN COALESCE(v_preferred_currency, v_company_currency);
  END IF;

  SELECT preferred_currency, COALESCE(currency_sync_enabled, TRUE)
  INTO v_preferred_currency, v_sync_enabled
  FROM company_members
  WHERE user_id = p_user_id AND company_id = p_company_id;

  IF v_sync_enabled THEN
    RETURN v_company_currency;
  END IF;

  RETURN COALESCE(v_preferred_currency, v_company_currency);
END;
$function$
;

-- ---------------------------------------------------------------
-- get_user_notifications(p_user_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_status character varying, p_severity character varying, p_category character varying, p_search_query text, p_priority character varying, p_reference_type character varying)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.get_user_notifications(p_user_id uuid, p_company_id uuid, p_branch_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_status character varying DEFAULT NULL::character varying, p_severity character varying DEFAULT NULL::character varying, p_category character varying DEFAULT NULL::character varying, p_search_query text DEFAULT NULL::text, p_priority character varying DEFAULT NULL::character varying, p_reference_type character varying DEFAULT NULL::character varying)
 RETURNS TABLE(id uuid, reference_type character varying, reference_id uuid, title character varying, message text, priority character varying, status character varying, created_at timestamp with time zone, branch_name character varying, warehouse_name character varying, severity character varying, category character varying, event_key text, branch_id uuid, warehouse_id uuid, assigned_to_user uuid, assigned_to_role character varying)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_role VARCHAR(50);
  v_role_norm  TEXT;
  v_exec_bypass BOOLEAN;
BEGIN
  SELECT cm.role INTO v_user_role
  FROM company_members cm
  WHERE cm.user_id = p_user_id
    AND cm.company_id = p_company_id
  LIMIT 1;

  v_role_norm := lower(trim(coalesce(v_user_role::text, '')));
  v_exec_bypass := v_role_norm IN (
    'owner',
    'admin',
    'general_manager',
    'gm',
    'super_admin',
    'superadmin',
    'generalmanager'
  );

  RETURN QUERY
  SELECT
    n.id,
    n.reference_type,
    n.reference_id,
    n.title,
    n.message,
    n.priority,
    COALESCE(nus.status, n.status, 'unread')::VARCHAR AS status,
    n.created_at,
    b.name::VARCHAR(255) AS branch_name,
    w.name::VARCHAR(255) AS warehouse_name,
    COALESCE(n.severity, 'info')::VARCHAR AS severity,
    COALESCE(n.category, 'system')::VARCHAR AS category,
    n.event_key::TEXT,
    n.branch_id,
    n.warehouse_id,
    n.assigned_to_user,
    n.assigned_to_role
  FROM notifications n
  LEFT JOIN branches b ON (n.branch_id = b.id AND b.company_id = p_company_id)
  LEFT JOIN warehouses w ON (n.warehouse_id = w.id AND w.company_id = p_company_id)
  LEFT JOIN notification_user_states nus ON (n.id = nus.notification_id AND nus.user_id = p_user_id)
  WHERE n.company_id = p_company_id
    AND (
      n.assigned_to_user = p_user_id
      OR (
        n.assigned_to_user IS NULL
        AND (
          n.assigned_to_role = v_user_role
          OR n.assigned_to_role IS NULL
          OR (n.assigned_to_role = 'admin' AND v_user_role = 'owner')
        )
      )
    )
    AND (
      v_exec_bypass
      OR (p_branch_id IS NULL OR n.branch_id = p_branch_id OR n.branch_id IS NULL)
    )
    AND (
      v_exec_bypass
      OR (p_warehouse_id IS NULL OR n.warehouse_id = p_warehouse_id OR n.warehouse_id IS NULL)
    )
    AND (
      (p_status IS NULL AND COALESCE(nus.status, n.status, 'unread') != 'archived')
      OR (p_status IS NOT NULL AND COALESCE(nus.status, n.status, 'unread') = p_status)
    )
    AND (p_severity IS NULL OR COALESCE(n.severity, 'info') = p_severity)
    AND (p_category IS NULL OR COALESCE(n.category, 'system') = p_category)
    AND (p_priority IS NULL OR n.priority = p_priority)
    AND (p_reference_type IS NULL OR n.reference_type = p_reference_type)
    AND (
      p_search_query IS NULL
      OR p_search_query = ''
      OR n.title ILIKE '%' || p_search_query || '%'
      OR n.message ILIKE '%' || p_search_query || '%'
      OR n.reference_id::text ILIKE '%' || p_search_query || '%'
    )
    AND (n.expires_at IS NULL OR n.expires_at > NOW())
  ORDER BY
    CASE n.priority
      WHEN 'urgent' THEN 1
      WHEN 'high' THEN 2
      WHEN 'normal' THEN 3
      WHEN 'low' THEN 4
    END,
    n.created_at DESC;
END;
$function$
;

-- ---------------------------------------------------------------
-- get_user_record_counts(p_company_id uuid, p_user_id uuid)
