       WHERE company_id = p_company_id AND created_by_user_id = p_user_id),
    'sales_orders',
      (SELECT count(*)::int FROM public.sales_orders
       WHERE company_id = p_company_id AND created_by_user_id = p_user_id),
    'bookings',
