-- ---------------------------------------------------------------
-- handle_invoice_cancellation_reversal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.handle_invoice_cancellation_reversal()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_original_je  RECORD;
  v_reversal_id  UUID;
BEGIN
  -- Only fire when sent → cancelled
  IF NOT (OLD.status = 'sent' AND NEW.status = 'cancelled') THEN
    RETURN NEW;
  END IF;

  PERFORM set_config('app.allow_direct_post', 'true', true);

  BEGIN
    -- Find and reverse all JEs linked to this invoice (revenue + cogs)
    FOR v_original_je IN
      SELECT je.id, je.reference_type, je.description
      FROM journal_entries je
      WHERE je.company_id = NEW.company_id
        AND je.reference_id = NEW.id
        AND je.reference_type IN ('invoice', 'invoice_cogs')
        AND (je.is_deleted IS NULL OR je.is_deleted = false)
    LOOP
      -- Create reversal JE as draft
      INSERT INTO journal_entries (
        company_id, branch_id, reference_type, reference_id,
        entry_date, description, status
      ) VALUES (
        NEW.company_id, NEW.branch_id,
        v_original_je.reference_type || '_reversal',
        NEW.id,
        CURRENT_DATE,
        '[إلغاء] ' || v_original_je.description,
        'draft'
      ) RETURNING id INTO v_reversal_id;

      -- Mirror all lines with debit↔credit swapped
      INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id
      )
      SELECT
        v_reversal_id,
        jel.account_id,
        jel.credit_amount,   -- swap: original credit → reversal debit
        jel.debit_amount,    -- swap: original debit  → reversal credit
        '[عكس] ' || jel.description,
        jel.branch_id
      FROM journal_entry_lines jel
      WHERE jel.journal_entry_id = v_original_je.id;

      -- Post the reversal
      UPDATE journal_entries SET status = 'posted' WHERE id = v_reversal_id;
    END LOOP;

  EXCEPTION WHEN OTHERS THEN
    PERFORM set_config('app.allow_direct_post', 'false', true);
    RAISE WARNING 'Cancellation reversal failed for invoice %: %', NEW.invoice_number, SQLERRM;
    -- Don't block the cancellation, just warn
  END;

  PERFORM set_config('app.allow_direct_post', 'false', true);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- handle_invoice_sent_accrual()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.handle_invoice_sent_accrual()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_item RECORD;
  v_product RECORD;
BEGIN
  -- Only fire when status changes from 'draft' → 'sent'
  IF NOT (OLD.status = 'draft' AND NEW.status = 'sent') THEN
    RETURN NEW;
  END IF;

  -- ✅ 1. القيود المحاسبية (موجودة مسبقاً)
  PERFORM execute_sales_invoice_accounting(NEW.id);

  -- ✅ 2. خصم المخزون لكل بند من `invoice_items` (للمنتجات فقط)
  FOR v_item IN (
    SELECT 
      ii.product_id,
      ii.quantity,
      ii.unit_price,
      p.cost_price,
      p.item_type,
      p.name as product_name
    FROM invoice_items ii
    JOIN products p ON p.id = ii.product_id
    WHERE ii.invoice_id = NEW.id
      AND p.item_type != 'service'
      AND p.item_type IS NOT NULL
      AND ii.quantity > 0
  )
  LOOP
    -- إدراج حركة خصم مخزون (quantity negative = خصم)
    INSERT INTO inventory_transactions (
      company_id,
      product_id,
      transaction_type,
      quantity_change,
      reference_id,
      reference_type,
      notes,
      branch_id,
      cost_center_id,
      warehouse_id,
      unit_cost,
      total_cost,
      from_location_type,
      from_location_id,
      to_location_type,
      to_location_id,
      shipping_provider_id
    ) VALUES (
      NEW.company_id,
      v_item.product_id,
      'sale',
      -(v_item.quantity),   -- سالب = خصم
      NEW.id,
      'invoice',
      'مبيعات - فاتورة ' || NEW.invoice_number,
      NEW.branch_id,
      NEW.cost_center_id,
      NEW.warehouse_id,
      COALESCE(v_item.cost_price, 0),
      COALESCE(v_item.cost_price, 0) * v_item.quantity,
      'warehouse',
      NEW.warehouse_id,
      CASE 
        WHEN NEW.shipping_provider_id IS NOT NULL THEN 'third_party'
        ELSE 'customer'
      END,
      COALESCE(NEW.shipping_provider_id, NEW.customer_id)::UUID,
      NEW.shipping_provider_id
    );
  END LOOP;

  -- ✅ 3. إنشاء/تحديث سجلات third_party_inventory مع customer_id
  FOR v_item IN (
    SELECT 
      ii.product_id,
      ii.quantity,
      ii.unit_price,
      COALESCE(p.cost_price, ii.unit_price * 0.7) as unit_cost,
      p.item_type
    FROM invoice_items ii
    JOIN products p ON p.id = ii.product_id
    WHERE ii.invoice_id = NEW.id
      AND p.item_type != 'service'
      AND ii.quantity > 0
  )
  LOOP
    -- إدراج إذا لم يكن موجوداً، تحديث إذا كان موجوداً
    INSERT INTO third_party_inventory (
      company_id,
      invoice_id,
      product_id,
      quantity,
      unit_cost,
      shipping_provider_id,
      status,
      cleared_quantity,
      returned_quantity,
      branch_id,
      cost_center_id,
      warehouse_id,
      customer_id,
      sales_order_id,
      tracking_type,
      payment_status,
      delivery_status
    ) VALUES (
      NEW.company_id,
      NEW.id,
      v_item.product_id,
      v_item.quantity,
      v_item.unit_cost,
      NEW.shipping_provider_id,
      'open',
      0,
      0,
      NEW.branch_id,
      NEW.cost_center_id,
      NEW.warehouse_id,
      NEW.customer_id,
      NEW.sales_order_id,
      CASE WHEN NEW.shipping_provider_id IS NOT NULL THEN 'shipping_company' ELSE 'customer_direct' END,
      'unpaid',
      'with_customer'
    )
    ON CONFLICT (invoice_id, product_id) 
    DO UPDATE SET
      quantity = EXCLUDED.quantity,
      customer_id = EXCLUDED.customer_id,
      tracking_type = EXCLUDED.tracking_type,
      payment_status = 'unpaid',
      delivery_status = 'with_customer',
      updated_at = NOW();
  END LOOP;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- لا نوقف العملية إذا فشل المخزون أو third_party_inventory
  RAISE WARNING 'handle_invoice_sent_accrual error: %', SQLERRM;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- has_shared_access(p_company_id uuid, p_resource_type text, p_created_by_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.has_shared_access(p_company_id uuid, p_resource_type text, p_created_by_user_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
  SELECT EXISTS (
    SELECT 1
    FROM public.permission_sharing ps
    WHERE ps.company_id          = p_company_id
      AND ps.grantee_user_id     = auth.uid()
      AND ps.grantor_user_id     = p_created_by_user_id
      AND ps.is_active           = true
      AND (ps.expires_at IS NULL OR ps.expires_at > now())
      AND (ps.resource_type      = 'all' OR ps.resource_type = p_resource_type)
  );
$function$
;

