-- ---------------------------------------------------------------
-- ic_accounting_equation(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_accounting_equation(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_assets numeric; v_liab numeric; v_equity numeric; v_diff numeric;
BEGIN
  SELECT
    COALESCE(SUM(CASE WHEN coa.account_type='asset'      THEN jel.debit_amount - jel.credit_amount END), 0),
    COALESCE(SUM(CASE WHEN coa.account_type='liability'  THEN jel.credit_amount - jel.debit_amount END), 0),
    -- 'income' is what the DB uses (not 'revenue'). Plus equity and expense.
    COALESCE(SUM(CASE WHEN coa.account_type IN ('equity','income','revenue','expense')
                        THEN jel.credit_amount - jel.debit_amount END), 0)
  INTO v_assets, v_liab, v_equity
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id AND je.status='posted'
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id;

  v_diff := ROUND(v_assets - (v_liab + v_equity), 2);
  IF ABS(v_diff) > 0.10 THEN
    severity := CASE WHEN ABS(v_diff) > 100 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object('assets', v_assets, 'liabilities', v_liab,
      'equity_plus_pnl', v_equity, 'difference', v_diff,
      'hint','Accounting equation broken: Assets != Liabilities + (Equity + Revenue - Expenses).');
    RETURN NEXT;
  END IF;
EXCEPTION WHEN undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_ap_balance(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_ap_balance(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_bill_net numeric; v_acct_net numeric; v_diff numeric;
BEGIN
  -- v3.74.135 — count only bills that have crossed the GL boundary
  -- (confirm-receipt onward). draft / pending_approval / sent /
  -- rejected / voided / cancelled are pre-GL and stay excluded.
  SELECT COALESCE(SUM(GREATEST(0, total_amount - COALESCE(paid_amount,0) - COALESCE(returned_amount,0))),0)
    INTO v_bill_net FROM bills
  WHERE company_id = p_company_id
    AND COALESCE(status,'') IN ('received','partially_paid','paid','partially_returned','fully_returned');

  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount),0) INTO v_acct_net
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id=jel.journal_entry_id AND je.status='posted'
  JOIN chart_of_accounts coa ON coa.id=jel.account_id
  WHERE coa.company_id=p_company_id AND coa.account_code='2110'
    AND COALESCE(je.reference_type,'') NOT IN
        ('fx_period_end_revaluation','fx_revaluation','fx_ar_revaluation','fx_ap_revaluation');

  v_diff := ROUND(v_bill_net - v_acct_net, 2);
  IF ABS(v_diff) > 0.10 THEN
    severity := CASE WHEN ABS(v_diff)>100 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object('bill_remaining',v_bill_net,'account_2110',v_acct_net,
      'difference',v_diff,
      'hint','AP ledger (excluding FX revaluation) does not match outstanding bills.');
    RETURN NEXT;
  END IF;
END $function$
;

-- ---------------------------------------------------------------
-- ic_ar_balance(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_ar_balance(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_invoice_net numeric;
  v_acct_net    numeric;
  v_diff        numeric;
BEGIN
  -- v3.74.309: superseding v3.74.307.
  -- The previous fix excluded approval_status='pending' invoices on the
  -- assumption that the AR journal entry is posted at warehouse approval.
  -- In practice, this codebase posts the revenue/AR journal the moment
  -- the invoice transitions to status='sent' (via the legacy auto-post
  -- trigger), regardless of approval_status. That created a -10 phantom
  -- drift on sent-but-not-approved invoices.
  --
  -- This version compares only what is actually booked: invoices with a
  -- posted invoice journal entry. Anything in 'draft', 'invoiced' (the
  -- pre-send staging state on some flows), or 'cancelled' simply has no
  -- AR debit yet, so excluding by EXISTS is the most accurate filter
  -- and is independent of which workflow column the project happens to
  -- be using.
  SELECT COALESCE(SUM(GREATEST(0, i.total_amount - COALESCE(i.paid_amount,0) - COALESCE(i.returned_amount,0))),0)
    INTO v_invoice_net
  FROM invoices i
  WHERE i.company_id = p_company_id
    AND i.status NOT IN ('draft','cancelled')
    AND EXISTS (
      SELECT 1
      FROM journal_entries je
      WHERE je.company_id     = i.company_id
        AND je.reference_type = 'invoice'
        AND je.reference_id   = i.id
        AND je.status         = 'posted'
        AND (je.is_deleted IS NULL OR je.is_deleted = false)
    );

  -- v3.74.98: exclude FX revaluation entries — they adjust EGP value of AR
  -- balances without representing new invoices, so they don't belong in
  -- the comparison.
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount),0) INTO v_acct_net
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id=jel.journal_entry_id AND je.status='posted'
  JOIN chart_of_accounts coa ON coa.id=jel.account_id
  WHERE coa.company_id=p_company_id AND coa.account_code='1130'
    AND COALESCE(je.reference_type,'') NOT IN
        ('fx_period_end_revaluation','fx_revaluation','fx_ar_revaluation','fx_ap_revaluation');

  v_diff := ROUND(v_invoice_net - v_acct_net, 2);
  IF ABS(v_diff) > 0.10 THEN
    severity := CASE WHEN ABS(v_diff)>100 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object(
      'invoice_remaining', v_invoice_net,
      'account_1130',      v_acct_net,
      'difference',        v_diff,
      'hint',              'AR ledger (excluding FX revaluation) does not match outstanding invoices.'
    );
    RETURN NEXT;
  END IF;
END $function$
;

-- ---------------------------------------------------------------
-- ic_backup_stale(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_backup_stale(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_last_success timestamptz;
  v_company_created timestamptz;
BEGIN
  SELECT MAX(created_at) INTO v_last_success
  FROM backup_history
  WHERE company_id = p_company_id
    AND status IN ('success','completed','succeeded');

  -- v3.74.240 — fetch the company creation timestamp so brand-new tenants
  -- aren't flagged before the first daily cron has had a chance to run.
  SELECT created_at INTO v_company_created
  FROM companies
  WHERE id = p_company_id;

  IF v_last_success IS NULL THEN
    -- Grace period: skip the warning entirely for companies <48h old.
    IF v_company_created IS NOT NULL
       AND v_company_created > NOW() - INTERVAL '48 hours' THEN
      RETURN;
    END IF;

    severity := 'high';
    detail := jsonb_build_object(
      'last_success', NULL,
      'hint','No successful backup ever recorded for this company. Data at risk.'
    );
    RETURN NEXT;
  ELSIF v_last_success < NOW() - INTERVAL '7 days' THEN
    severity := CASE WHEN v_last_success < NOW() - INTERVAL '30 days' THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object(
      'last_success', v_last_success,
      'days_ago', EXTRACT(DAY FROM (NOW() - v_last_success)),
      'hint','Last successful backup is older than 7 days. Cron may be failing silently.'
    );
    RETURN NEXT;
  END IF;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_bank_recon_pending(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_bank_recon_pending(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT br.id, br.statement_date, br.statement_balance, br.cleared_total, br.difference,
           coa.account_code, coa.account_name
    FROM bank_reconciliations br
    LEFT JOIN chart_of_accounts coa ON coa.id = br.account_id
    WHERE br.company_id = p_company_id
      AND ABS(COALESCE(br.difference, 0)) > 0.10
      AND br.statement_date < CURRENT_DATE - INTERVAL '30 days'
    ORDER BY br.statement_date DESC
    LIMIT 20
  LOOP
    severity := CASE WHEN ABS(r.difference) > 1000 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object('reconciliation_id', r.id, 'statement_date', r.statement_date,
      'account_code', r.account_code, 'account_name', r.account_name,
      'statement_balance', r.statement_balance, 'cleared_total', r.cleared_total,
      'difference', r.difference,
      'hint','Bank reconciliation has unresolved difference > 30 days. Investigate uncleared transactions.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_bank_transfer_unbalanced(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_bank_transfer_unbalanced(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT je.id, je.entry_date, je.description,
           COUNT(DISTINCT coa.id) FILTER (WHERE coa.sub_type IN ('cash','bank')) AS cash_bank_lines
    FROM journal_entries je
    JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    JOIN chart_of_accounts coa ON coa.id = jel.account_id
    WHERE je.company_id = p_company_id
      AND je.status = 'posted'
      AND je.reference_type IN ('bank_transfer','cash_transfer','internal_transfer')
    GROUP BY je.id, je.entry_date, je.description
    HAVING COUNT(DISTINCT coa.id) FILTER (WHERE coa.sub_type IN ('cash','bank')) < 2
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('journal_id', r.id, 'entry_date', r.entry_date,
      'description', r.description, 'cash_bank_lines', r.cash_bank_lines,
      'hint','Bank/cash transfer journal touches < 2 cash/bank accounts. One side missing.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_bonus_invoice_orphan(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_bonus_invoice_orphan(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT ub.id, ub.invoice_id, ub.bonus_amount, ub.status, ub.user_id
    FROM user_bonuses ub
    WHERE ub.company_id = p_company_id
      AND ub.invoice_id IS NOT NULL
      AND ub.reversed_at IS NULL
      AND NOT EXISTS (SELECT 1 FROM invoices WHERE id = ub.invoice_id)
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('bonus_id', r.id, 'invoice_id', r.invoice_id,
      'bonus_amount', r.bonus_amount, 'status', r.status, 'user_id', r.user_id,
      'hint','Sales bonus row references a non-existent invoice. Bonus should have been reversed when invoice was deleted.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_bonus_reversal_pending(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_bonus_reversal_pending(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT sr.id, sr.return_number, sr.total_amount, sr.invoice_id
    FROM sales_returns sr
    WHERE sr.company_id = p_company_id
      AND COALESCE(sr.status,'') IN ('approved','approved_completed','completed','posted')
      AND EXISTS (
        -- original invoice had a sales bonus
        SELECT 1 FROM user_bonuses ub
        WHERE ub.reference_type = 'invoice' AND ub.reference_id = sr.invoice_id
          AND ub.company_id = sr.company_id AND COALESCE(ub.amount, 0) > 0
      )
      AND NOT EXISTS (
        -- no reversal row for this return
        SELECT 1 FROM user_bonuses ub
        WHERE ub.reference_type = 'sales_return' AND ub.reference_id = sr.id
      )
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('return_id', r.id, 'return_number', r.return_number,
      'invoice_id', r.invoice_id, 'return_amount', r.total_amount,
      'hint','Approved sales return on an invoice that had a sales bonus, but no reversal bonus row exists.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_booking_no_invoice(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_booking_no_invoice(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT id, total_amount, status
    FROM bookings
    WHERE company_id = p_company_id
      AND status IN ('completed','closed','fulfilled')
      AND COALESCE(total_amount, 0) > 0
      AND invoice_id IS NULL
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('booking_id', r.id, 'total_amount', r.total_amount,
      'status', r.status,
      'hint','Completed booking without an invoice link. Revenue may not be booked.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_branch_isolation(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_branch_isolation(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT je.id, je.branch_id, je.reference_type, b.company_id AS branch_company
    FROM journal_entries je
    JOIN branches b ON b.id = je.branch_id
    WHERE je.company_id = p_company_id
      AND je.branch_id IS NOT NULL
      AND b.company_id <> je.company_id
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('journal_id', r.id, 'journal_company', p_company_id,
      'branch_id', r.branch_id, 'branch_company', r.branch_company,
      'hint','Journal entry references a branch belonging to a different company.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_branch_no_warehouse(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_branch_no_warehouse(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT b.id, b.name
    FROM branches b
    WHERE b.company_id = p_company_id
      AND COALESCE(b.is_active, true) = true
      AND NOT EXISTS (
        SELECT 1 FROM warehouses w
        WHERE w.branch_id = b.id AND w.company_id = b.company_id
          AND COALESCE(w.is_active, true) = true
      )
    LIMIT 10
  LOOP
    severity := 'low';
    detail := jsonb_build_object('branch_id', r.id, 'branch_name', r.name,
      'hint','Active branch without any active warehouse. Branch cannot fulfill sales.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_closed_period_mutations(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_closed_period_mutations(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT je.id, je.entry_date, je.reference_type, je.reference_id, je.description,
           ap.period_name, ap.status AS period_status, ap.is_locked
    FROM journal_entries je
    JOIN accounting_periods ap ON ap.company_id = je.company_id
      AND je.entry_date BETWEEN ap.period_start AND ap.period_end
    WHERE je.company_id = p_company_id
      AND je.status = 'posted'
      AND (ap.status = 'closed' OR ap.is_locked = true)
      AND je.created_at > ap.closed_at
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('journal_id', r.id, 'entry_date', r.entry_date,
      'reference_type', r.reference_type, 'reference_id', r.reference_id,
      'period_name', r.period_name, 'period_status', r.period_status,
      'hint','Posted journal in a closed accounting period. Should require unlock + audit trail.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_cogs_balance(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_cogs_balance(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_cogs_tx     numeric;
  v_acct_net    numeric;
  v_diff        numeric;
BEGIN
  SELECT COALESCE(SUM(total_cost), 0)
    INTO v_cogs_tx
    FROM cogs_transactions
   WHERE company_id = p_company_id;

  -- v3.74.264: restrict to journal entries created by the COGS engine.
  -- Manual postings to COGS accounts (e.g. ad-hoc expenses categorised
  -- as cost of goods) are accounting-valid but NOT part of the FIFO
  -- sub-ledger, so they must not appear in this reconciliation.
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)
    INTO v_acct_net
    FROM journal_entry_lines jel
    JOIN journal_entries je
      ON je.id = jel.journal_entry_id
     AND je.status = 'posted'
     AND je.reference_type IN ('invoice_cogs', 'invoice_cogs_reversal', 'sale_return_cogs')
    JOIN chart_of_accounts coa
      ON coa.id = jel.account_id
   WHERE coa.company_id = p_company_id
     AND coa.sub_type IN ('cost_of_goods_sold', 'cogs');

  v_diff := ROUND(v_cogs_tx - v_acct_net, 2);

  IF ABS(v_diff) > 0.50 THEN
    severity := CASE WHEN ABS(v_diff) > 500 THEN 'high' ELSE 'medium' END;
    detail   := jsonb_build_object(
      'cogs_transactions_total', v_cogs_tx,
      'cogs_engine_gl_net',      v_acct_net,
      'difference',              v_diff,
      'hint',                    'COGS sub-ledger and engine GL diverged.'
    );
    RETURN NEXT;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- ic_company_no_owner(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_company_no_owner(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_owner_count integer;
BEGIN
  SELECT COUNT(*) INTO v_owner_count
  FROM company_members
  WHERE company_id = p_company_id AND role = 'owner';

  IF v_owner_count = 0 THEN
    severity := 'high';
    detail := jsonb_build_object('owner_count', 0,
      'hint','Company has no member with role=owner. Critical actions (billing, suspension) have nobody to receive them.');
    RETURN NEXT;
  END IF;
END $function$
;

-- ---------------------------------------------------------------
-- ic_credit_without_journal(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_credit_without_journal(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT cc.id, cc.credit_number, cc.amount, cc.reference_type, cc.reference_id, cc.customer_id
    FROM customer_credits cc
    WHERE cc.company_id=p_company_id AND cc.status='active'
      AND cc.reference_type IN ('overpayment','invoice_overpayment')
      AND NOT EXISTS (
        SELECT 1 FROM journal_entries je
        WHERE je.company_id=cc.company_id AND je.status='posted'
          AND je.reference_type='credit_from_overpayment'
          AND je.reference_id=cc.reference_id
      )
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('credit_id',r.id,'credit_number',r.credit_number,
      'amount',r.amount,'reference_type',r.reference_type,'reference_id',r.reference_id,
      'customer_id',r.customer_id,
      'hint','customer_credit row without matching credit_from_overpayment journal.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_customer_credit(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_customer_credit(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_cc_net numeric; v_acct_net numeric; v_diff numeric;
BEGIN
  SELECT COALESCE(SUM(amount - COALESCE(used_amount,0) - COALESCE(applied_amount,0)),0) INTO v_cc_net
  FROM customer_credits
  WHERE company_id = p_company_id
    AND status IN ('active', 'partially_used');

  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount),0) INTO v_acct_net
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id AND je.status = 'posted'
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE coa.company_id = p_company_id
    AND (coa.account_code = '2155' OR coa.sub_type IN ('customer_credit','customer_advance'));

  v_diff := ROUND(v_cc_net - v_acct_net, 2);
  IF ABS(v_diff) > 0.01 THEN
    severity := CASE WHEN ABS(v_diff) > 1 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object(
      'customer_credits', v_cc_net,
      'account_2155', v_acct_net,
      'difference', v_diff,
      'hint', 'customer_credits without matching journal.'
    );
    RETURN NEXT;
  END IF;
END
$function$
;

-- ---------------------------------------------------------------
-- ic_customer_duplicate_phone(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_customer_duplicate_phone(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT phone, COUNT(*) AS n, ARRAY_AGG(id ORDER BY created_at) AS customer_ids,
           ARRAY_AGG(name ORDER BY created_at) AS names
    FROM customers
    WHERE company_id = p_company_id
      AND phone IS NOT NULL
      AND TRIM(phone) <> ''
      AND COALESCE(is_deleted, false) = false
    GROUP BY phone
    HAVING COUNT(*) > 1
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('phone', r.phone, 'customer_count', r.n,
      'customer_ids', r.customer_ids, 'customer_names', r.names,
      'hint','Multiple customers share the same phone number. Merge or correct one.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_duplicate_journals(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_duplicate_journals(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT reference_type, reference_id, COUNT(*) AS n,
           ARRAY_AGG(id ORDER BY created_at) AS journal_ids,
           SUM(COALESCE(
             (SELECT SUM(jel.debit_amount) FROM journal_entry_lines jel WHERE jel.journal_entry_id = je.id),
             0
           )) AS total_debit
    FROM journal_entries je
    WHERE company_id = p_company_id
      AND status = 'posted'
      AND reference_type IS NOT NULL
      AND reference_id IS NOT NULL
    GROUP BY reference_type, reference_id
    HAVING COUNT(*) > 1
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('reference_type', r.reference_type,
      'reference_id', r.reference_id, 'duplicate_count', r.n,
      'journal_ids', r.journal_ids, 'total_debit_sum', r.total_debit,
      'hint','Two or more posted journals reference the same row. Double-booking.');
    RETURN NEXT;
  END LOOP;
END $function$
;

