-- ---------------------------------------------------------------
-- ic_fifo_lot_integrity(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_fifo_lot_integrity(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT fl.id, fl.product_id, fl.lot_date, fl.original_quantity, fl.remaining_quantity,
           COALESCE(SUM(flc.quantity_consumed),0) AS consumed_sum
    FROM fifo_cost_lots fl
    LEFT JOIN fifo_lot_consumptions flc ON flc.lot_id=fl.id
    WHERE fl.company_id=p_company_id
    GROUP BY fl.id, fl.product_id, fl.lot_date, fl.original_quantity, fl.remaining_quantity
    HAVING ABS(fl.remaining_quantity - (fl.original_quantity - COALESCE(SUM(flc.quantity_consumed),0))) > 0.001
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('lot_id',r.id,'product_id',r.product_id,
      'original_quantity',r.original_quantity,'remaining_quantity',r.remaining_quantity,
      'consumed_sum',r.consumed_sum,
      'expected_remaining',ROUND(r.original_quantity - r.consumed_sum, 3),
      'hint','FIFO lot remaining_quantity drifted from original - consumed. Audit FIFO consumption flow.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_financial_op_no_audit(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_financial_op_no_audit(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_count integer;
BEGIN
  SELECT COUNT(*) INTO v_count
  FROM invoices i
  WHERE i.company_id = p_company_id
    AND i.created_at > NOW() - INTERVAL '30 days'
    AND i.status NOT IN ('draft','cancelled')
    AND NOT EXISTS (
      SELECT 1 FROM audit_logs al
      WHERE al.company_id = i.company_id
        AND al.entity_type = 'invoices'
        AND al.entity_id = i.id::text
    );

  IF v_count > 5 THEN
    severity := CASE WHEN v_count > 50 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object('invoices_without_audit', v_count,
      'period','last 30 days',
      'hint','Multiple financial operations (invoices) have no audit_logs entry. Audit trail gap.');
    RETURN NEXT;
  END IF;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_fx_amount_accuracy(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_fx_amount_accuracy(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT p.id, p.amount, p.base_currency_amount, p.exchange_rate, p.original_amount,
           p.original_currency, p.currency_code, p.invoice_id,
           ROUND(p.base_currency_amount
                 - (COALESCE(p.original_amount, p.amount) * COALESCE(p.exchange_rate, 1)), 2) AS diff
    FROM payments p
    WHERE p.company_id = p_company_id
      AND p.is_deleted = false
      AND p.base_currency_amount IS NOT NULL
      AND p.exchange_rate IS NOT NULL
      AND p.exchange_rate > 0
      AND COALESCE(p.original_currency, 'EGP') <> 'EGP'
      AND ABS(p.base_currency_amount
              - (COALESCE(p.original_amount, p.amount) * p.exchange_rate)) > 0.05
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('payment_id', r.id, 'amount', r.amount,
      'base_currency_amount', r.base_currency_amount, 'exchange_rate', r.exchange_rate,
      'original_amount', r.original_amount, 'original_currency', r.original_currency,
      'difference', r.diff,
      'hint','base_currency_amount diverges from (original_amount × exchange_rate). FX conversion error.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_fx_draft_stale(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_fx_draft_stale(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT je.id, je.reference_type, je.entry_date, je.description, je.created_at,
           COALESCE(SUM(jel.debit_amount), 0) AS total_debit
    FROM journal_entries je
    LEFT JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE je.company_id = p_company_id
      AND je.status = 'draft'
      AND je.reference_type IN ('fx_period_end_revaluation','fx_revaluation','fx_ar_revaluation','fx_ap_revaluation')
      AND je.created_at < NOW() - INTERVAL '7 days'
    GROUP BY je.id, je.reference_type, je.entry_date, je.description, je.created_at
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('journal_id', r.id, 'reference_type', r.reference_type,
      'entry_date', r.entry_date, 'created_at', r.created_at, 'total_debit', r.total_debit,
      'description', r.description,
      'hint','FX revaluation draft journal > 7 days old. Either post or delete; do not leave hanging.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_inventory_cost_drift(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_inventory_cost_drift(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT it.id, it.product_id, it.transaction_type, it.unit_cost AS tx_cost,
           p.name AS product_name,
           AVG(flc.unit_cost) AS avg_fifo_cost
    FROM inventory_transactions it
    LEFT JOIN products p ON p.id = it.product_id
    LEFT JOIN fifo_lot_consumptions flc ON flc.reference_id = it.reference_id
      AND flc.reference_type = it.reference_type
      AND flc.product_id = it.product_id
    WHERE it.company_id = p_company_id
      AND it.transaction_type = 'sale'
      AND it.unit_cost IS NOT NULL
      AND it.unit_cost > 0
    GROUP BY it.id, it.product_id, it.transaction_type, it.unit_cost, p.name
    HAVING ABS(it.unit_cost - COALESCE(AVG(flc.unit_cost), it.unit_cost)) > 0.10
      AND AVG(flc.unit_cost) IS NOT NULL
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('transaction_id', r.id, 'product_id', r.product_id,
      'product_name', r.product_name, 'tx_unit_cost', r.tx_cost, 'fifo_avg_cost', ROUND(r.avg_fifo_cost, 4),
      'hint','inventory_transactions.unit_cost diverges from the underlying FIFO consumption average.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_inventory_gl_vs_fifo(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_inventory_gl_vs_fifo(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_gl_inventory numeric;
  v_fifo_remaining numeric;
  v_diff numeric;
BEGIN
  -- GL 1140 net
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)
  INTO v_gl_inventory
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id AND je.status='posted'
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE coa.company_id = p_company_id
    AND (coa.account_code = '1140' OR coa.sub_type = 'inventory');

  -- FIFO remaining value
  SELECT COALESCE(SUM(remaining_quantity * unit_cost), 0)
  INTO v_fifo_remaining
  FROM fifo_cost_lots
  WHERE company_id = p_company_id;

  v_diff := ROUND(v_gl_inventory - v_fifo_remaining, 2);

  -- Tolerance: max(5 EGP, 1% of FIFO value)
  IF ABS(v_diff) > GREATEST(5, v_fifo_remaining * 0.01) THEN
    severity := CASE WHEN ABS(v_diff) > 500 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object(
      'gl_inventory_1140', v_gl_inventory,
      'fifo_remaining_value', v_fifo_remaining,
      'difference', v_diff,
      'hint','GL 1140 diverges from FIFO remaining value. Possible causes: production_issue/production_receipt not journaled, transfer-in cost mismatch, or COGS journal missing.');
    RETURN NEXT;
  END IF;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_inventory_valuation_drift(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_inventory_valuation_drift(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_acct_net numeric; v_stock_value numeric; v_diff numeric;
BEGIN
  -- Inventory GL account net
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0) INTO v_acct_net
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id=jel.journal_entry_id AND je.status='posted'
  JOIN chart_of_accounts coa ON coa.id=jel.account_id
  WHERE coa.company_id=p_company_id
    AND (coa.account_code='1140' OR coa.sub_type='inventory');

  -- Physical stock × cost_price (only for goods, not services)
  SELECT COALESCE(SUM(stock_qty * cost), 0) INTO v_stock_value
  FROM (
    SELECT it.product_id,
           SUM(it.quantity_change) AS stock_qty,
           COALESCE(p.cost_price, 0) AS cost
    FROM inventory_transactions it
    LEFT JOIN products p ON p.id = it.product_id
    WHERE it.company_id = p_company_id
      AND COALESCE(p.item_type,'goods') <> 'service'
    GROUP BY it.product_id, p.cost_price
  ) sub;

  v_diff := ROUND(v_acct_net - v_stock_value, 2);
  -- Tolerance: 5 EGP or 1% of stock_value, whichever larger
  IF ABS(v_diff) > GREATEST(5, v_stock_value * 0.01) THEN
    severity := CASE WHEN ABS(v_diff) > 500 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object('account_1140', v_acct_net,
      'stock_at_cost', v_stock_value, 'difference', v_diff,
      'hint','Inventory GL account diverges from SUM(stock × cost_price). FIFO vs cost_price snapshot drift.');
    RETURN NEXT;
  END IF;
END $function$
;

