-- ---------------------------------------------------------------
-- ic_manufacturing_consumption(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_manufacturing_consumption(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  -- production runs that have no material_consumption_entries
  FOR r IN
    SELECT po.id, po.order_number
    FROM production_orders po
    WHERE po.company_id=p_company_id
      AND po.status IN ('completed','closed')
      AND NOT EXISTS (
        SELECT 1 FROM material_consumption_entries mce WHERE mce.production_order_id=po.id
      )
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('production_order_id',r.id,'order_number',r.order_number,
      'hint','Completed production order without any material consumption recorded.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table THEN
  -- manufacturing tables not present in this deployment — skip silently
  RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_negative_assets(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_negative_assets(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT coa.id, coa.account_code, coa.account_name, coa.sub_type,
           COALESCE(SUM(jel.debit_amount - jel.credit_amount),0) AS net
    FROM chart_of_accounts coa
    LEFT JOIN journal_entry_lines jel ON jel.account_id=coa.id
    LEFT JOIN journal_entries je ON je.id=jel.journal_entry_id AND je.status='posted'
    WHERE coa.company_id=p_company_id AND coa.is_active=true
      AND coa.sub_type IN ('cash','bank','inventory','accounts_receivable')
    GROUP BY coa.id, coa.account_code, coa.account_name, coa.sub_type
    HAVING COALESCE(SUM(jel.debit_amount - jel.credit_amount),0) < -0.10
    LIMIT 20
  LOOP
    severity := CASE WHEN r.sub_type='inventory' OR ABS(r.net)>1000 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object('account_id',r.id,'account_code',r.account_code,
      'account_name',r.account_name,'sub_type',r.sub_type,'net_balance',ROUND(r.net,2),
      'hint','Asset account has negative balance.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_negative_stock(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_negative_stock(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT it.product_id, it.warehouse_id, p.name AS product_name, w.name AS warehouse_name,
           SUM(it.quantity_change) AS balance
    FROM inventory_transactions it
    LEFT JOIN products p ON p.id=it.product_id
    LEFT JOIN warehouses w ON w.id=it.warehouse_id
    WHERE it.company_id=p_company_id
    GROUP BY it.product_id, it.warehouse_id, p.name, w.name
    HAVING SUM(it.quantity_change) < -0.001
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('product_id',r.product_id,'product_name',r.product_name,
      'warehouse_id',r.warehouse_id,'warehouse_name',r.warehouse_name,
      'balance',ROUND(r.balance,3),
      'hint','Negative stock balance — sale or transfer was approved without enough on hand.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_orphaned_journals(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_orphaned_journals(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    -- invoice refs
    SELECT je.id, je.reference_type, je.reference_id, je.description FROM journal_entries je
    WHERE je.company_id=p_company_id AND je.status='posted' AND je.reference_type='invoice'
      AND je.reference_id IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM invoices WHERE id=je.reference_id)
    UNION ALL
    -- bill refs
    SELECT je.id, je.reference_type, je.reference_id, je.description FROM journal_entries je
    WHERE je.company_id=p_company_id AND je.status='posted' AND je.reference_type='bill'
      AND je.reference_id IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM bills WHERE id=je.reference_id)
    UNION ALL
    -- sales_return refs
    SELECT je.id, je.reference_type, je.reference_id, je.description FROM journal_entries je
    WHERE je.company_id=p_company_id AND je.status='posted' AND je.reference_type='sales_return'
      AND je.reference_id IS NOT NULL
      AND NOT EXISTS (SELECT 1 FROM sales_returns WHERE id=je.reference_id)
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('journal_id',r.id,'reference_type',r.reference_type,
      'reference_id',r.reference_id,'description',r.description,
      'hint','Journal references a row that no longer exists.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_overpaid_no_credit(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_overpaid_no_credit(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT i.id, i.invoice_number, i.total_amount, i.paid_amount, i.customer_id,
           ROUND(i.paid_amount - i.total_amount, 2) AS overpay
    FROM invoices i
    WHERE i.company_id=p_company_id
      AND i.status NOT IN ('draft','cancelled')
      AND COALESCE(i.returned_amount,0) < 0.01
      AND COALESCE(i.paid_amount,0) > COALESCE(i.total_amount,0) + 0.01
      AND NOT EXISTS (
        SELECT 1 FROM customer_credits cc
        WHERE cc.company_id=i.company_id AND cc.customer_id=i.customer_id
          AND cc.reference_type IN ('invoice_overpayment','overpayment')
          AND (cc.reference_id=i.id
               OR cc.reference_id IN (SELECT p.id FROM payments p WHERE p.invoice_id=i.id))
      )
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('invoice_id',r.id,'invoice_number',r.invoice_number,
      'total',r.total_amount,'paid',r.paid_amount,'overpay',r.overpay,
      'hint','Overpaid invoice without customer_credit row — overpayment trigger may have missed.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_payment_double_allocation(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_payment_double_allocation(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  -- Real double-count detection: paid_amount exceeds the sum of actual payments
  -- by more than the sum could justify, with the surplus matching an advance_application entry.
  FOR r IN
    WITH payment_sum AS (
      SELECT p.invoice_id,
             SUM(COALESCE(p.base_currency_amount, p.amount, 0)) AS pay_total
      FROM payments p
      WHERE p.company_id = p_company_id AND p.is_deleted = false AND p.invoice_id IS NOT NULL
        AND COALESCE(p.amount, 0) > 0
      GROUP BY p.invoice_id
    ),
    aa_sum AS (
      SELECT aa.invoice_id, SUM(COALESCE(aa.amount_applied, 0)) AS aa_total
      FROM advance_applications aa
      WHERE aa.company_id = p_company_id
      GROUP BY aa.invoice_id
    )
    SELECT i.id, i.invoice_number, i.paid_amount,
           COALESCE(ps.pay_total, 0) AS payments_sum,
           COALESCE(aas.aa_total, 0) AS aa_sum,
           ROUND(COALESCE(i.paid_amount,0)
                 - GREATEST(COALESCE(ps.pay_total,0), COALESCE(aas.aa_total,0)), 2) AS over_count
    FROM invoices i
    LEFT JOIN payment_sum ps ON ps.invoice_id = i.id
    LEFT JOIN aa_sum aas ON aas.invoice_id = i.id
    WHERE i.company_id = p_company_id
      -- both sources have entries
      AND ps.pay_total IS NOT NULL AND aas.aa_total IS NOT NULL
      -- and paid_amount exceeds the larger of the two by more than 0.50
      -- (the larger is what should be reflected; smaller is a mirror entry)
      AND COALESCE(i.paid_amount,0) > GREATEST(COALESCE(ps.pay_total,0), COALESCE(aas.aa_total,0)) + 0.50
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('invoice_id', r.id, 'invoice_number', r.invoice_number,
      'paid_amount', r.paid_amount, 'payments_sum', r.payments_sum, 'aa_sum', r.aa_sum,
      'over_count', r.over_count,
      'hint','invoice.paid_amount exceeds both payment-sum AND advance_applications-sum. Likely double-booked.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_payment_no_journal(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_payment_no_journal(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT p.id, p.payment_date, p.amount, p.invoice_id, p.customer_id, p.status
    FROM payments p
    WHERE p.company_id = p_company_id
      AND p.is_deleted = false
      AND COALESCE(p.status,'approved') = 'approved'
      AND p.journal_entry_id IS NULL
      AND COALESCE(p.amount, 0) > 0
      AND p.voids_payment_id IS NULL          -- v3.74.118 - skip void payments
      AND p.voided_by_payment_id IS NULL      -- skip historical (already-voided) rows
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('payment_id', r.id, 'payment_date', r.payment_date,
      'amount', r.amount, 'invoice_id', r.invoice_id, 'status', r.status,
      'hint','Approved payment with no journal_entry_id. Cash/AR ledger not updated.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_perm_shares_expired(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_perm_shares_expired(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT ps.id, ps.expires_at, ps.is_active, ps.grantor_user_id, ps.grantee_user_id, ps.resource_type
    FROM permission_sharing ps
    WHERE ps.company_id = p_company_id
      AND ps.is_active = true
      AND ps.expires_at IS NOT NULL
      AND ps.expires_at < NOW() - INTERVAL '1 day'
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('share_id', r.id, 'expires_at', r.expires_at,
      'grantor_user_id', r.grantor_user_id, 'grantee_user_id', r.grantee_user_id,
      'resource_type', r.resource_type,
      'hint','Permission share is past its expiry but still marked active. Cron may have missed it.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_return_chain(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_return_chain(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  -- approved sales_returns without inventory_transactions
  FOR r IN
    SELECT sr.id, sr.return_number, sr.total_amount, sr.invoice_id
    FROM sales_returns sr
    WHERE sr.company_id=p_company_id
      AND COALESCE(sr.status,'') IN ('approved','approved_completed','completed','posted')
      AND NOT EXISTS (
        SELECT 1 FROM inventory_transactions it
        WHERE it.reference_type='sales_return' AND it.reference_id=sr.id
      )
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('return_id',r.id,'return_number',r.return_number,
      'total_amount',r.total_amount,'invoice_id',r.invoice_id,
      'hint','Approved sales return without an inventory transaction. Stock was not restored.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_return_exceeds_invoice(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_return_exceeds_invoice(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT i.id AS invoice_id, i.invoice_number, i.total_amount,
           COALESCE(SUM(sr.total_amount), 0) AS returns_sum,
           ROUND(COALESCE(SUM(sr.total_amount),0) - COALESCE(i.total_amount,0), 2) AS over
    FROM invoices i
    JOIN sales_returns sr ON sr.invoice_id = i.id AND sr.company_id = i.company_id
    WHERE i.company_id = p_company_id
      AND COALESCE(sr.status,'') IN ('approved','approved_completed','completed','posted')
    GROUP BY i.id, i.invoice_number, i.total_amount
    HAVING COALESCE(SUM(sr.total_amount),0) > COALESCE(i.total_amount,0) + 0.10
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('invoice_id', r.invoice_id, 'invoice_number', r.invoice_number,
      'invoice_total', r.total_amount, 'returns_sum', r.returns_sum, 'over_amount', r.over,
      'hint','Approved sales returns sum exceeds original invoice total. Either data error or over-refund.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_return_total_mismatch(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_return_total_mismatch(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT sr.id, sr.total_amount AS header_total,
           COALESCE(SUM(sri.line_total), 0) AS items_sum,
           ROUND(sr.total_amount - COALESCE(SUM(sri.line_total),0), 2) AS diff
    FROM sales_returns sr
    LEFT JOIN sales_return_items sri ON sri.sales_return_id = sr.id
    WHERE sr.company_id = p_company_id
    GROUP BY sr.id, sr.total_amount
    HAVING ABS(sr.total_amount - COALESCE(SUM(sri.line_total),0)) > 0.10
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('return_id', r.id,
      'header_total', r.header_total, 'items_sum', r.items_sum, 'difference', r.diff,
      'hint','Sales return header total does not match sum of line items.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_sales_return_no_journal(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_sales_return_no_journal(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT sr.id, sr.return_number, sr.total_amount
    FROM sales_returns sr
    WHERE sr.company_id = p_company_id
      AND COALESCE(sr.status,'') IN ('approved','approved_completed','completed','posted')
      AND COALESCE(sr.total_amount, 0) > 0
      AND NOT EXISTS (
        SELECT 1 FROM journal_entries je
        WHERE je.company_id = sr.company_id AND je.status='posted'
          AND je.reference_type = 'sales_return' AND je.reference_id = sr.id
      )
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('return_id', r.id, 'return_number', r.return_number,
      'total_amount', r.total_amount,
      'hint','Approved sales return without an accounting journal entry. AR / revenue / cogs not adjusted.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_set_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ic_stale_approvals(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_stale_approvals(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  -- pending expenses
  FOR r IN
    SELECT id, expense_number, total_amount, created_at
    FROM expenses
    WHERE company_id=p_company_id
      AND status IN ('pending','pending_approval','submitted')
      AND created_at < NOW() - INTERVAL '7 days'
    LIMIT 10
  LOOP
    severity := 'low';
    detail := jsonb_build_object('type','expense','id',r.id,'number',r.expense_number,
      'amount',r.total_amount,'created_at',r.created_at,
      'hint','Expense pending > 7 days.');
    RETURN NEXT;
  END LOOP;

  -- pending sales return requests
  FOR r IN
    SELECT id, request_number, total_amount, created_at
    FROM sales_return_requests
    WHERE company_id=p_company_id
      AND status IN ('pending','pending_approval','submitted')
      AND created_at < NOW() - INTERVAL '7 days'
    LIMIT 10
  LOOP
    severity := 'low';
    detail := jsonb_build_object('type','sales_return_request','id',r.id,
      'number',r.request_number,'amount',r.total_amount,'created_at',r.created_at,
      'hint','Sales return request pending > 7 days.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table OR undefined_column THEN
  RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_stale_critical_notifications(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_stale_critical_notifications(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_count integer;
BEGIN
  SELECT COUNT(*) INTO v_count
  FROM notifications n
  WHERE n.company_id = p_company_id
    AND n.priority IN ('critical','high')
    AND n.read_at IS NULL
    AND n.created_at < NOW() - INTERVAL '30 days'
    -- v3.74.215 — exclude notifications whose source workflow is resolved.
    AND CASE n.reference_type
      WHEN 'purchase_order' THEN EXISTS (
        SELECT 1 FROM purchase_orders po
        WHERE po.id = n.reference_id
          AND COALESCE(po.status, '') IN ('draft', 'pending_approval', 'pending_director', 'pending_manager', 'sent_to_supplier')
      )
      WHEN 'bill' THEN EXISTS (
        SELECT 1 FROM bills b
        WHERE b.id = n.reference_id
          AND COALESCE(b.status, '') IN ('draft', 'pending_approval', 'received')
          AND COALESCE(b.paid_amount, 0) < COALESCE(b.total_amount, 0)
      )
      WHEN 'invoice' THEN EXISTS (
        SELECT 1 FROM invoices i
        WHERE i.id = n.reference_id
          AND COALESCE(i.status, '') IN ('draft', 'sent', 'partially_paid')
          AND COALESCE(i.approval_status, '') IN ('pending', '')
      )
      WHEN 'stock_transfer' THEN EXISTS (
        SELECT 1 FROM inventory_transfers t
        WHERE t.id = n.reference_id
          AND COALESCE(t.status, '') IN ('draft', 'pending_approval', 'in_transit')
      )
      WHEN 'payment_approval' THEN EXISTS (
        SELECT 1 FROM payments p
        WHERE p.id = n.reference_id
          AND COALESCE(p.status, '') IN ('pending_approval', 'pending_manager', 'pending_director')
      )
      WHEN 'expense' THEN EXISTS (
        SELECT 1 FROM expenses e
        WHERE e.id = n.reference_id
          AND COALESCE(e.status, '') IN ('draft', 'pending_approval')
      )
      ELSE TRUE  -- unknown reference_type → keep legacy behaviour
    END;

  IF v_count > 0 THEN
    severity := 'low';
    detail := jsonb_build_object(
      'unread_critical_count', v_count,
      'hint','Critical or high-priority notifications unread > 30 days, and the underlying workflow is still pending action.'
    );
    RETURN NEXT;
  END IF;
EXCEPTION WHEN undefined_table OR undefined_column THEN
  -- One of the joined tables doesn't exist (custom deployments).
  -- Fall back to the legacy check so we still flag something.
  SELECT COUNT(*) INTO v_count
  FROM notifications
  WHERE company_id = p_company_id
    AND priority IN ('critical','high')
    AND read_at IS NULL
    AND created_at < NOW() - INTERVAL '30 days';
  IF v_count > 0 THEN
    severity := 'low';
    detail := jsonb_build_object('unread_critical_count', v_count,
      'hint','Critical or high-priority notifications unread > 30 days. Decisions may have been missed.');
    RETURN NEXT;
  END IF;
END
$function$
;

-- ---------------------------------------------------------------
-- ic_stale_transfers(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_stale_transfers(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT id, transfer_number, transfer_date, status,
           source_warehouse_id, destination_warehouse_id
    FROM inventory_transfers
    WHERE company_id=p_company_id
      AND status IN ('in_transit','pending_receipt')
      AND transfer_date < CURRENT_DATE - INTERVAL '30 days'
    LIMIT 20
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('transfer_id',r.id,'transfer_number',r.transfer_number,
      'transfer_date',r.transfer_date,'status',r.status,
      'hint','Transfer has been in transit > 30 days. Likely needs manual closure.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_subscription_past_due(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_subscription_past_due(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT id, status, current_period_end, plan_id
    FROM subscriptions
    WHERE company_id = p_company_id
      AND status IN ('past_due','active')
      AND current_period_end IS NOT NULL
      AND current_period_end < CURRENT_DATE - INTERVAL '14 days'
    LIMIT 5
  LOOP
    severity := 'high';
    detail := jsonb_build_object('subscription_id', r.id, 'status', r.status,
      'current_period_end', r.current_period_end, 'plan_id', r.plan_id,
      'hint','Subscription past_due > 14 days. Suspension cron may have missed it.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- ic_tax_accuracy(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_tax_accuracy(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    WITH item_tax AS (
      SELECT ii.invoice_id,
             SUM(COALESCE(ii.quantity, 0) * COALESCE(ii.unit_price, 0)
                 * COALESCE(ii.tax_rate, 0) / 100.0) AS expected_tax
      FROM invoice_items ii
      GROUP BY ii.invoice_id
    )
    SELECT i.id, i.invoice_number, i.tax_amount AS stored_tax, it.expected_tax,
           ROUND(COALESCE(i.tax_amount,0) - COALESCE(it.expected_tax,0), 2) AS diff
    FROM invoices i
    JOIN item_tax it ON it.invoice_id = i.id
    WHERE i.company_id = p_company_id
      AND i.status NOT IN ('draft','cancelled')
      AND ABS(COALESCE(i.tax_amount,0) - COALESCE(it.expected_tax,0)) > 1.00
    LIMIT 20
  LOOP
    severity := CASE WHEN ABS(r.diff) > 100 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object('invoice_id', r.id, 'invoice_number', r.invoice_number,
      'stored_tax', r.stored_tax, 'expected_tax', r.expected_tax, 'difference', r.diff,
      'hint','Invoice tax_amount diverges from sum of line tax (qty*price*rate/100).');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_trial_balance(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_trial_balance(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_dr numeric; v_cr numeric;
BEGIN
  SELECT COALESCE(SUM(jel.debit_amount),0), COALESCE(SUM(jel.credit_amount),0) INTO v_dr, v_cr
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id=jel.journal_entry_id AND je.status='posted'
  WHERE je.company_id=p_company_id;

  IF ABS(v_dr - v_cr) > 0.01 THEN
    severity := 'high';
    detail := jsonb_build_object('total_debits',v_dr,'total_credits',v_cr,'difference',ROUND(v_dr-v_cr,2),
      'hint','Trial balance is out of equilibrium.');
    RETURN NEXT;
  END IF;
END $function$
;

-- ---------------------------------------------------------------
-- ic_unbalanced_journals(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_unbalanced_journals(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT je.id, je.entry_date, je.reference_type, je.reference_id, je.description,
           SUM(jel.debit_amount) AS dr, SUM(jel.credit_amount) AS cr
    FROM journal_entries je
    JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE je.company_id = p_company_id AND je.status = 'posted'
    GROUP BY je.id, je.entry_date, je.reference_type, je.reference_id, je.description
    HAVING ABS(SUM(jel.debit_amount) - SUM(jel.credit_amount)) > 0.01
    LIMIT 20
  LOOP
    severity := 'high';
    detail := jsonb_build_object('journal_id', r.id, 'entry_date', r.entry_date,
      'reference_type', r.reference_type, 'reference_id', r.reference_id,
      'description', r.description,
      'total_debit', r.dr, 'total_credit', r.cr,
      'difference', ROUND(r.dr - r.cr, 2),
      'hint','Posted journal with unbalanced lines. Should have been blocked by trigger.');
    RETURN NEXT;
  END LOOP;
END $function$
;

-- ---------------------------------------------------------------
-- ic_user_can_access_company(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_user_can_access_company(p_company_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
AS $function$
  SELECT EXISTS (
    SELECT 1
    FROM public.company_members cm
    WHERE cm.company_id = p_company_id
      AND cm.user_id = auth.uid()
  )
  OR EXISTS (
    SELECT 1
    FROM public.companies c
    WHERE c.id = p_company_id
      AND c.user_id = auth.uid()
  );
$function$
;

-- ---------------------------------------------------------------
-- ic_user_can_access_consolidation_group(p_consolidation_group_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_user_can_access_consolidation_group(p_consolidation_group_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
AS $function$
  SELECT EXISTS (
    SELECT 1
    FROM public.consolidation_group_members cgm
    JOIN public.company_legal_entity_map clem
      ON clem.legal_entity_id = cgm.legal_entity_id
     AND clem.status = 'active'
     AND clem.effective_to IS NULL
    WHERE cgm.consolidation_group_id = p_consolidation_group_id
      AND (cgm.effective_to IS NULL OR cgm.effective_to >= CURRENT_DATE)
      AND public.ic_user_can_access_company(clem.company_id)
  );
$function$
;

-- ---------------------------------------------------------------
-- ic_user_can_access_legal_entity(p_legal_entity_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_user_can_access_legal_entity(p_legal_entity_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
AS $function$
  SELECT EXISTS (
    SELECT 1
    FROM public.company_legal_entity_map clem
    WHERE clem.legal_entity_id = p_legal_entity_id
      AND clem.status = 'active'
      AND clem.effective_to IS NULL
      AND public.ic_user_can_access_company(clem.company_id)
  );
$function$
;

-- ---------------------------------------------------------------
-- ic_user_can_manage_company(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_user_can_manage_company(p_company_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
AS $function$
  SELECT EXISTS (
    SELECT 1
    FROM public.company_members cm
    WHERE cm.company_id = p_company_id
      AND cm.user_id = auth.uid()
      AND lower(cm.role) IN ('owner', 'admin', 'general_manager', 'manager')
  )
  OR EXISTS (
    SELECT 1
    FROM public.companies c
    WHERE c.id = p_company_id
      AND c.user_id = auth.uid()
  );
$function$
;

-- ---------------------------------------------------------------
-- ic_validate_elimination_dry_run_only()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_validate_elimination_dry_run_only()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_run_type TEXT;
BEGIN
  SELECT run_type
    INTO v_run_type
  FROM public.consolidation_runs
  WHERE id = NEW.consolidation_run_id;

  IF v_run_type IS NULL THEN
    RAISE EXCEPTION 'CONSOLIDATION_RUN_MISSING: consolidation run not found';
  END IF;

  IF v_run_type <> 'dry_run' THEN
    RAISE EXCEPTION 'ELIMINATION_DRY_RUN_REQUIRED: elimination entries are locked to dry_run runs during Phase 2A.3';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ic_validate_intercompany_document_integrity()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_validate_intercompany_document_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  tx RECORD;
BEGIN
  SELECT id, seller_company_id, buyer_company_id, transaction_currency
    INTO tx
  FROM public.intercompany_transactions
  WHERE id = NEW.intercompany_transaction_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'INTERCOMPANY_TRANSACTION_MISSING: parent transaction not found';
  END IF;

  IF NEW.side = 'seller' AND NEW.company_id <> tx.seller_company_id THEN
    RAISE EXCEPTION 'INTERCOMPANY_DOCUMENT_PAIR_MISMATCH: seller-side document must reference seller company';
  END IF;

  IF NEW.side = 'buyer' AND NEW.company_id <> tx.buyer_company_id THEN
    RAISE EXCEPTION 'INTERCOMPANY_DOCUMENT_PAIR_MISMATCH: buyer-side document must reference buyer company';
  END IF;

  IF NEW.transaction_currency IS NOT NULL
     AND tx.transaction_currency IS NOT NULL
     AND NEW.transaction_currency <> tx.transaction_currency THEN
    RAISE EXCEPTION 'INTERCOMPANY_DOCUMENT_CURRENCY_MISMATCH: document currency must match transaction currency';
  END IF;

  IF (
    NEW.locked_exchange_rate IS NOT NULL
    OR NULLIF(BTRIM(COALESCE(NEW.rate_source, '')), '') IS NOT NULL
    OR NEW.locked_rate_timestamp IS NOT NULL
  ) THEN
    IF NEW.locked_exchange_rate IS NULL
       OR NULLIF(BTRIM(COALESCE(NEW.rate_source, '')), '') IS NULL
       OR NEW.locked_rate_timestamp IS NULL THEN
      RAISE EXCEPTION 'INTERCOMPANY_DOCUMENT_RATE_LOCK_INCOMPLETE: locked_exchange_rate, rate_source, and locked_rate_timestamp are required together';
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ic_validate_intercompany_transaction_integrity()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_validate_intercompany_transaction_integrity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  rel RECORD;
BEGIN
  IF NEW.seller_company_id = NEW.buyer_company_id THEN
    RAISE EXCEPTION 'INTERCOMPANY_PAIR_INVALID: seller_company_id and buyer_company_id must differ';
  END IF;

  IF NEW.intercompany_relationship_id IS NOT NULL THEN
    SELECT *
      INTO rel
    FROM public.intercompany_relationships
    WHERE id = NEW.intercompany_relationship_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'INTERCOMPANY_RELATIONSHIP_MISSING: intercompany relationship not found';
    END IF;

    IF rel.seller_company_id <> NEW.seller_company_id
       OR rel.buyer_company_id <> NEW.buyer_company_id THEN
      RAISE EXCEPTION 'INTERCOMPANY_RELATIONSHIP_PAIR_MISMATCH: relationship pair does not match transaction pair';
    END IF;

    IF rel.seller_legal_entity_id <> NEW.seller_legal_entity_id
       OR rel.buyer_legal_entity_id <> NEW.buyer_legal_entity_id THEN
      RAISE EXCEPTION 'INTERCOMPANY_RELATIONSHIP_ENTITY_MISMATCH: legal entity pair does not match relationship';
    END IF;

    IF rel.relationship_status NOT IN ('draft', 'active') THEN
      RAISE EXCEPTION 'INTERCOMPANY_RELATIONSHIP_INACTIVE: relationship is not active';
    END IF;

    IF NEW.transaction_date < rel.effective_from
       OR (rel.effective_to IS NOT NULL AND NEW.transaction_date > rel.effective_to) THEN
      RAISE EXCEPTION 'INTERCOMPANY_RELATIONSHIP_OUTSIDE_EFFECTIVE_RANGE: transaction_date is outside relationship validity';
    END IF;
  END IF;

  IF (
    NEW.seller_exchange_rate IS NOT NULL
    OR NULLIF(BTRIM(COALESCE(NEW.seller_rate_source, '')), '') IS NOT NULL
    OR NEW.seller_rate_timestamp IS NOT NULL
  ) THEN
    IF NEW.seller_exchange_rate IS NULL
       OR NULLIF(BTRIM(COALESCE(NEW.seller_rate_source, '')), '') IS NULL
       OR NEW.seller_rate_timestamp IS NULL THEN
      RAISE EXCEPTION 'INTERCOMPANY_SELLER_RATE_LOCK_INCOMPLETE: exchange_rate, rate_source, and rate_timestamp are required together';
    END IF;
  END IF;

  IF (
    NEW.buyer_exchange_rate IS NOT NULL
    OR NULLIF(BTRIM(COALESCE(NEW.buyer_rate_source, '')), '') IS NOT NULL
    OR NEW.buyer_rate_timestamp IS NOT NULL
  ) THEN
    IF NEW.buyer_exchange_rate IS NULL
       OR NULLIF(BTRIM(COALESCE(NEW.buyer_rate_source, '')), '') IS NULL
       OR NEW.buyer_rate_timestamp IS NULL THEN
      RAISE EXCEPTION 'INTERCOMPANY_BUYER_RATE_LOCK_INCOMPLETE: exchange_rate, rate_source, and rate_timestamp are required together';
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ic_vendor_credit(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_vendor_credit(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_vc_net numeric; v_acct_net numeric; v_diff numeric;
BEGIN
  SELECT COALESCE(SUM(total_amount - COALESCE(applied_amount,0)),0) INTO v_vc_net
  FROM vendor_credits WHERE company_id=p_company_id AND status='active';

  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount),0) INTO v_acct_net
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id=jel.journal_entry_id AND je.status='posted'
  JOIN chart_of_accounts coa ON coa.id=jel.account_id
  WHERE coa.company_id=p_company_id
    AND (coa.sub_type IN ('vendor_credit','supplier_advance','prepaid_supplier') OR coa.account_code='2150');

  v_diff := ROUND(v_vc_net - v_acct_net, 2);
  IF ABS(v_diff) > 0.10 THEN
    severity := CASE WHEN ABS(v_diff)>100 THEN 'high' ELSE 'medium' END;
    detail := jsonb_build_object('vendor_credits_remaining',v_vc_net,'account_vendor_credit',v_acct_net,'difference',v_diff,
      'hint','Vendor credit table out of sync with chart of accounts.');
    RETURN NEXT;
  END IF;
END $function$
;

-- ---------------------------------------------------------------
-- ic_workflow_stuck(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ic_workflow_stuck(p_company_id uuid)
 RETURNS TABLE(severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE r record;
BEGIN
  -- expenses
  FOR r IN
    SELECT 'expense' AS kind, id, amount, status, created_at
    FROM expenses
    WHERE company_id = p_company_id
      AND status IN ('pending','pending_approval','submitted')
      AND created_at < NOW() - INTERVAL '30 days'
    LIMIT 10
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('type', r.kind, 'id', r.id,
      'amount', r.amount, 'status', r.status, 'created_at', r.created_at,
      'hint','Approval workflow stuck > 30 days. Needs manual escalation or close.');
    RETURN NEXT;
  END LOOP;

  -- sales return requests
  FOR r IN
    SELECT 'sales_return_request' AS kind, id, total_amount AS amount, status, created_at
    FROM sales_return_requests
    WHERE company_id = p_company_id
      AND status IN ('pending','pending_approval','submitted','pending_review')
      AND created_at < NOW() - INTERVAL '30 days'
    LIMIT 10
  LOOP
    severity := 'medium';
    detail := jsonb_build_object('type', r.kind, 'id', r.id,
      'amount', r.amount, 'status', r.status, 'created_at', r.created_at,
      'hint','Approval workflow stuck > 30 days.');
    RETURN NEXT;
  END LOOP;
EXCEPTION WHEN undefined_table OR undefined_column THEN RETURN;
END $function$
;

-- ---------------------------------------------------------------
-- increase_seats(p_company_id uuid, p_seats_count integer, p_paymob_txn_id text, p_amount_egp integer, p_performed_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.increase_seats(p_company_id uuid, p_seats_count integer, p_paymob_txn_id text, p_amount_egp integer DEFAULT NULL::integer, p_performed_by uuid DEFAULT NULL::uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_existing_txn_id UUID;
BEGIN
  -- Idempotency check: has this paymob transaction been processed before?
  SELECT id INTO v_existing_txn_id
  FROM seat_transactions
  WHERE paymob_transaction_id = p_paymob_txn_id;

  IF FOUND THEN
    RETURN json_build_object('success', TRUE, 'idempotent', TRUE, 'message', 'already_processed');
  END IF;

  -- Upsert company_seats
  INSERT INTO company_seats(company_id, total_paid_seats, status)
  VALUES (p_company_id, p_seats_count, 'active')
  ON CONFLICT (company_id)
  DO UPDATE SET
    total_paid_seats = company_seats.total_paid_seats + EXCLUDED.total_paid_seats,
    updated_at = now();

  -- Update subscription status on company
  UPDATE companies
  SET subscription_status = 'active',
      current_period_start = now(),
      current_period_end = (now() + INTERVAL '1 month')
  WHERE id = p_company_id;

  -- Log the transaction
  INSERT INTO seat_transactions(
    company_id, transaction_type, seats_delta,
    paymob_transaction_id, amount_egp, performed_by, metadata
  )
  VALUES (
    p_company_id, 'purchase', p_seats_count,
    p_paymob_txn_id, p_amount_egp, p_performed_by,
    json_build_object('source', 'paymob_webhook')
  );

  RETURN json_build_object('success', TRUE, 'idempotent', FALSE, 'new_seats', p_seats_count);
END;
$function$
;

-- ---------------------------------------------------------------
-- increase_seats(p_company_id uuid, p_seats_count integer, p_paymob_txn_id text, p_amount_egp integer, p_performed_by uuid, p_billing_period text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.increase_seats(p_company_id uuid, p_seats_count integer, p_paymob_txn_id text, p_amount_egp integer DEFAULT NULL::integer, p_performed_by uuid DEFAULT NULL::uuid, p_billing_period text DEFAULT 'monthly'::text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_existing_txn_id UUID;
  v_reactivation json;
BEGIN
  -- Idempotency check
  SELECT id INTO v_existing_txn_id
  FROM seat_transactions
  WHERE paymob_transaction_id = p_paymob_txn_id;

  IF FOUND THEN
    RETURN json_build_object('success', TRUE, 'idempotent', TRUE, 'message', 'already_processed');
  END IF;

  -- Upsert company_seats
  INSERT INTO company_seats(company_id, total_paid_seats, status)
  VALUES (p_company_id, p_seats_count, 'active')
  ON CONFLICT (company_id)
  DO UPDATE SET
    total_paid_seats = company_seats.total_paid_seats + EXCLUDED.total_paid_seats,
    updated_at = now();

  -- Reactivate/extend subscription
  v_reactivation := reactivate_after_payment(p_company_id, p_billing_period);

  -- Log the transaction
  INSERT INTO seat_transactions(
    company_id, transaction_type, seats_delta,
    paymob_transaction_id, amount_egp, performed_by, metadata
  )
  VALUES (
    p_company_id, 'purchase', p_seats_count,
    p_paymob_txn_id, p_amount_egp, p_performed_by,
    json_build_object('source', 'paymob_webhook', 'billing_period', p_billing_period)
  );

  RETURN json_build_object(
    'success', TRUE,
    'idempotent', FALSE,
    'new_seats', p_seats_count,
    'reactivation', v_reactivation
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- increment_usage_metric(p_company_id uuid, p_metric text, p_period text, p_amount numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.increment_usage_metric(p_company_id uuid, p_metric text, p_period text, p_amount numeric DEFAULT 1)
 RETURNS void
 LANGUAGE sql
 SECURITY DEFINER
AS $function$
  INSERT INTO usage_metrics (company_id, metric, period, value, updated_at)
  VALUES (p_company_id, p_metric, p_period, p_amount, now())
  ON CONFLICT (company_id, metric, period)
  DO UPDATE SET
    value = usage_metrics.value + EXCLUDED.value,
    updated_at = now();
$function$
;

-- ---------------------------------------------------------------
-- inherit_branch_cost_center_for_journal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.inherit_branch_cost_center_for_journal()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_branch_id UUID; v_cost_center_id UUID; BEGIN IF NEW.branch_id IS NULL OR NEW.cost_center_id IS NULL THEN IF NEW.reference_type = 'invoice' OR NEW.reference_type = 'invoice_payment' OR NEW.reference_type = 'sale_return' THEN SELECT branch_id, cost_center_id INTO v_branch_id, v_cost_center_id FROM invoices WHERE id = NEW.reference_id; ELSIF NEW.reference_type = 'bill' OR NEW.reference_type = 'bill_payment' OR NEW.reference_type = 'purchase_return' THEN SELECT branch_id, cost_center_id INTO v_branch_id, v_cost_center_id FROM bills WHERE id = NEW.reference_id; ELSIF NEW.reference_type = 'payment' THEN SELECT branch_id, cost_center_id INTO v_branch_id, v_cost_center_id FROM payments WHERE id = NEW.reference_id; END IF; NEW.branch_id := COALESCE(NEW.branch_id, v_branch_id); NEW.cost_center_id := COALESCE(NEW.cost_center_id, v_cost_center_id); IF NEW.branch_id IS NULL THEN SELECT b.id INTO v_branch_id FROM branches b WHERE b.company_id = NEW.company_id AND b.is_main = true LIMIT 1; NEW.branch_id := v_branch_id; END IF; IF NEW.cost_center_id IS NULL AND NEW.branch_id IS NOT NULL THEN SELECT cc.id INTO v_cost_center_id FROM cost_centers cc WHERE cc.branch_id = NEW.branch_id AND cc.is_main = true LIMIT 1; IF v_cost_center_id IS NULL THEN SELECT cc.id INTO v_cost_center_id FROM cost_centers cc WHERE cc.branch_id = NEW.branch_id LIMIT 1; END IF; NEW.cost_center_id := v_cost_center_id; END IF; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- inherit_branch_warehouse_for_inventory()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.inherit_branch_warehouse_for_inventory()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_branch_id UUID; v_warehouse_id UUID; BEGIN IF NEW.branch_id IS NULL OR NEW.warehouse_id IS NULL THEN IF NEW.transaction_type IN ('sale', 'sale_return') THEN SELECT branch_id, warehouse_id INTO v_branch_id, v_warehouse_id FROM invoices WHERE id = NEW.reference_id; ELSIF NEW.transaction_type IN ('purchase', 'purchase_return') THEN SELECT branch_id, warehouse_id INTO v_branch_id, v_warehouse_id FROM bills WHERE id = NEW.reference_id; END IF; IF NEW.branch_id IS NULL AND v_branch_id IS NOT NULL THEN NEW.branch_id := v_branch_id; END IF; IF NEW.warehouse_id IS NULL AND v_warehouse_id IS NOT NULL THEN NEW.warehouse_id := v_warehouse_id; END IF; IF NEW.branch_id IS NULL OR NEW.warehouse_id IS NULL THEN SELECT b.id, w.id INTO v_branch_id, v_warehouse_id FROM branches b LEFT JOIN warehouses w ON w.branch_id = b.id AND w.is_main = true WHERE b.company_id = NEW.company_id AND b.is_main = true LIMIT 1; NEW.branch_id := COALESCE(NEW.branch_id, v_branch_id); NEW.warehouse_id := COALESCE(NEW.warehouse_id, v_warehouse_id); END IF; END IF; RETURN NEW; END; $function$
;

