-- ---------------------------------------------------------------
-- insert_user_security_event(p_user_id uuid, p_company_id uuid, p_event_type text, p_event_data jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.insert_user_security_event(p_user_id uuid, p_company_id uuid, p_event_type text, p_event_data jsonb DEFAULT NULL::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_id uuid;
BEGIN
  INSERT INTO user_security_events (user_id, company_id, event_type, event_data, created_at)
  VALUES (p_user_id, p_company_id, p_event_type, p_event_data, clock_timestamp())
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- inv_block_post_unapproved_discount_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.inv_block_post_unapproved_discount_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_approval_state text;
  v_approval_type  text;
BEGIN
  IF current_setting('app.skip_discount_approval', true) = 'booking' THEN
    RETURN NEW;
  END IF;

  IF COALESCE(OLD.status, '') <> 'draft' THEN
    RETURN NEW;
  END IF;
  IF NEW.status NOT IN ('sent', 'posted', 'paid', 'partially_paid') THEN
    RETURN NEW;
  END IF;

  IF NEW.discount_value IS NULL OR NEW.discount_value <= 0 THEN
    RETURN NEW;
  END IF;

  SELECT status, discount_type
    INTO v_approval_state, v_approval_type
    FROM public.discount_approvals
   WHERE document_type = 'sales_invoice'
     AND document_id   = NEW.id
     AND discount_value = NEW.discount_value
     AND COALESCE(discount_type, 'amount') = COALESCE(NEW.discount_type, 'amount')
   ORDER BY requested_at DESC
   LIMIT 1;

  IF NOT FOUND THEN
    RAISE EXCEPTION
      'الخصم المطبق على الفاتورة يتطلب اعتماد المالك / المدير العام قبل الترحيل. اطلب الاعتماد من صندوق الموافقات.'
      USING ERRCODE = 'P0001';
  END IF;

  IF v_approval_state <> 'approved' THEN
    RAISE EXCEPTION
      'الخصم على الفاتورة منتظر اعتماد الإدارة (الحالة الحالية: %). لا يمكن ترحيل الفاتورة قبل الاعتماد.',
      v_approval_state
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- inv_request_discount_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.inv_request_discount_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_last_id uuid; v_last_status text; v_last_value numeric; v_last_type text;
  v_party_name text; v_requester uuid;
  v_so_disc_status text; v_so_disc_value numeric; v_so_disc_type text;
  v_supersedes uuid; v_items_snap jsonb;
BEGIN
  IF COALESCE(current_setting('app.skip_discount_approval', true), '') <> '' THEN RETURN NEW; END IF;
  IF COALESCE(current_setting('app.amendment_inserted', true), '') = '1' THEN
    PERFORM set_config('app.amendment_inserted', '', true); RETURN NEW;
  END IF;
  IF NEW.discount_value IS NULL OR NEW.discount_value <= 0 THEN RETURN NEW; END IF;
  IF NEW.status <> 'draft' THEN RETURN NEW; END IF;
  IF TG_OP='UPDATE'
     AND COALESCE(OLD.discount_value, 0) = NEW.discount_value
     AND COALESCE(OLD.discount_type, '') = COALESCE(NEW.discount_type, '')
     AND COALESCE(OLD.discount_position, '') = COALESCE(NEW.discount_position, '')
     AND COALESCE(OLD.tax_inclusive, false) = COALESCE(NEW.tax_inclusive, false) THEN
    RETURN NEW;
  END IF;
  IF NEW.sales_order_id IS NOT NULL THEN
    SELECT status, discount_value, discount_type INTO v_so_disc_status, v_so_disc_value, v_so_disc_type
      FROM public.discount_approvals
     WHERE document_type='sales_order' AND document_id=NEW.sales_order_id
     ORDER BY requested_at DESC LIMIT 1;
    IF FOUND THEN
      IF v_so_disc_status='rejected' THEN
        RAISE EXCEPTION 'تم رفض اعتماد خصم طلب المبيعات المرتبط — لا يمكن حفظ فاتورة بنفس الخصم.' USING ERRCODE='P0001';
      END IF;
      IF TG_OP='INSERT' AND v_so_disc_status='approved'
         AND v_so_disc_value = NEW.discount_value
         AND COALESCE(v_so_disc_type,'amount') = COALESCE(NEW.discount_type,'amount') THEN
        RETURN NEW;
      END IF;
    END IF;
  END IF;
  SELECT id, status, discount_value, discount_type INTO v_last_id, v_last_status, v_last_value, v_last_type
    FROM public.discount_approvals
   WHERE document_type='sales_invoice' AND document_id=NEW.id
   ORDER BY requested_at DESC LIMIT 1;
  IF FOUND AND v_last_status IN ('pending','approved')
     AND v_last_value = NEW.discount_value
     AND COALESCE(v_last_type,'') = COALESCE(NEW.discount_type,'amount') THEN
    RETURN NEW;
  END IF;
  IF FOUND AND v_last_status='pending' THEN
    UPDATE public.discount_approvals
       SET status='cancelled',
           decision_note = COALESCE(decision_note, 'Superseded by amended discount on the sales invoice.'),
           updated_at = NOW()
     WHERE id = v_last_id;
  END IF;
  BEGIN SELECT name INTO v_party_name FROM public.customers WHERE id = NEW.customer_id;
  EXCEPTION WHEN OTHERS THEN v_party_name := NULL; END;
  v_requester := COALESCE(NEW.last_edited_by_user_id, NEW.created_by_user_id, NEW.created_by);
  IF v_requester IS NULL THEN
    RAISE EXCEPTION 'Cannot open discount approval — no requester recorded on invoice %.', NEW.id USING ERRCODE='P0001';
  END IF;
  BEGIN v_supersedes := NULLIF(current_setting('app.superseded_approval_id', true), '')::uuid;
  EXCEPTION WHEN OTHERS THEN v_supersedes := NULL; END;
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'product_id', ii.product_id, 'product_name', p.name,
    'quantity', ii.quantity, 'unit_price', ii.unit_price,
    'discount_percent', ii.discount_percent,
    'tax_rate', ii.tax_rate, 'total', ii.line_total
  )), '[]'::jsonb) INTO v_items_snap
    FROM public.invoice_items ii LEFT JOIN public.products p ON p.id = ii.product_id
   WHERE ii.invoice_id = NEW.id;
  INSERT INTO public.discount_approvals (
    company_id, document_type, document_id, document_no,
    discount_value, discount_type, document_total, party_name,
    reason, status, requested_by, requested_at,
    supersedes_approval_id, items_snapshot,
    shipping_snapshot, adjustment_snapshot,
    tax_amount_snapshot, subtotal_snapshot
  ) VALUES (
    NEW.company_id, 'sales_invoice', NEW.id, NEW.invoice_number,
    NEW.discount_value, COALESCE(NEW.discount_type, 'amount'),
    NEW.total_amount, v_party_name,
    NULL, 'pending', v_requester, NOW(),
    v_supersedes, v_items_snap,
    NEW.shipping, NEW.adjustment,
    NEW.tax_amount, NEW.subtotal
  );
  PERFORM set_config('app.superseded_approval_id', '', true);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- invoice_amendment_reset_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.invoice_amendment_reset_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_material_change boolean := false;
  v_baseline_id uuid; v_baseline_type text;
  v_party_name text; v_requester uuid; v_items_snap jsonb;
BEGIN
  IF NEW.status <> 'draft' AND NEW.status <> 'pending_approval' THEN RETURN NEW; END IF;
  IF COALESCE(current_setting('app.skip_discount_approval', true), '') <> '' THEN RETURN NEW; END IF;

  IF   COALESCE(OLD.shipping, 0)          IS DISTINCT FROM COALESCE(NEW.shipping, 0)
    OR COALESCE(OLD.shipping_tax_rate, 0) IS DISTINCT FROM COALESCE(NEW.shipping_tax_rate, 0)
    OR COALESCE(OLD.adjustment, 0)        IS DISTINCT FROM COALESCE(NEW.adjustment, 0)
    OR COALESCE(OLD.tax_amount, 0)        IS DISTINCT FROM COALESCE(NEW.tax_amount, 0)
    OR COALESCE(OLD.subtotal, 0)          IS DISTINCT FROM COALESCE(NEW.subtotal, 0)
    OR COALESCE(OLD.total_amount, 0)      IS DISTINCT FROM COALESCE(NEW.total_amount, 0)
    OR COALESCE(OLD.currency_code, '')    IS DISTINCT FROM COALESCE(NEW.currency_code, '')
    OR COALESCE(OLD.exchange_rate, 1)     IS DISTINCT FROM COALESCE(NEW.exchange_rate, 1)
    OR COALESCE(OLD.discount_position,'') IS DISTINCT FROM COALESCE(NEW.discount_position,'')
    OR COALESCE(OLD.tax_inclusive, false) IS DISTINCT FROM COALESCE(NEW.tax_inclusive, false)
    OR COALESCE(OLD.discount_value, 0)    IS DISTINCT FROM COALESCE(NEW.discount_value, 0)
    OR COALESCE(OLD.discount_type, '')    IS DISTINCT FROM COALESCE(NEW.discount_type, '')
    OR COALESCE(OLD.customer_id::text, '')IS DISTINCT FROM COALESCE(NEW.customer_id::text, '') THEN
    v_material_change := true;
  END IF;
  IF NOT v_material_change THEN RETURN NEW; END IF;

  SELECT id, 'sales_invoice' INTO v_baseline_id, v_baseline_type
    FROM public.discount_approvals
   WHERE document_type='sales_invoice' AND document_id=NEW.id
     AND status IN ('approved','pending','rejected')
   ORDER BY requested_at DESC LIMIT 1;
  IF v_baseline_id IS NULL AND NEW.sales_order_id IS NOT NULL THEN
    SELECT id, 'sales_order' INTO v_baseline_id, v_baseline_type
      FROM public.discount_approvals
     WHERE document_type='sales_order' AND document_id=NEW.sales_order_id
       AND status='approved'
     ORDER BY requested_at DESC LIMIT 1;
  END IF;

  UPDATE public.discount_approvals
     SET status='cancelled',
         decision_note = COALESCE(decision_note,
           'Superseded by material amendment on the sales invoice.'),
         updated_at = NOW()
   WHERE document_type='sales_invoice' AND document_id=NEW.id
     AND status IN ('approved','pending');

  BEGIN
    SELECT name INTO v_party_name FROM public.customers WHERE id = NEW.customer_id;
  EXCEPTION WHEN OTHERS THEN v_party_name := NULL; END;
  -- v3.74.601: invoices carries created_by_user_id ONLY (the previous
  -- COALESCE referenced bills-only columns and crashed with 42703).
  v_requester := NEW.created_by_user_id;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'product_id', ii.product_id,
    'product_name', COALESCE(p.name, ii.description),
    'description', ii.description,
    'item_type', ii.item_type,
    'quantity', ii.quantity, 'unit_price', ii.unit_price,
    'discount_percent', ii.discount_percent,
    'tax_rate', ii.tax_rate, 'total', ii.line_total
  )), '[]'::jsonb) INTO v_items_snap
    FROM public.invoice_items ii
    LEFT JOIN public.products p ON p.id = ii.product_id
   WHERE ii.invoice_id = NEW.id;

  IF v_requester IS NOT NULL THEN
    INSERT INTO public.discount_approvals (
      company_id, document_type, document_id, document_no,
      discount_value, discount_type, document_total, party_name,
      reason, status, requested_by, requested_at,
      supersedes_approval_id, items_snapshot,
      shipping_snapshot, adjustment_snapshot,
      tax_amount_snapshot, subtotal_snapshot,
      shipping_tax_rate_snapshot, discount_position_snapshot,
      tax_inclusive_snapshot, supplier_name_snapshot
    ) VALUES (
      NEW.company_id, 'sales_invoice', NEW.id, NEW.invoice_number,
      COALESCE(NEW.discount_value, 0), COALESCE(NEW.discount_type, 'amount'),
      NEW.total_amount, v_party_name,
      'تعديل على الفاتورة يستدعى إعادة اعتماد', 'pending', v_requester, NOW(),
      v_baseline_id, v_items_snap,
      NEW.shipping, NEW.adjustment,
      NEW.tax_amount, NEW.subtotal,
      NEW.shipping_tax_rate, NEW.discount_position,
      NEW.tax_inclusive, v_party_name
    );
    PERFORM set_config('app.amendment_inserted', '1', true);
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- invoice_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.invoice_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_customer_name text; v_currency text;
BEGIN
  v_currency := COALESCE(NEW.currency_code, 'EGP');
  BEGIN
    SELECT name INTO v_customer_name FROM public.customers WHERE id = NEW.customer_id;
  EXCEPTION WHEN OTHERS THEN v_customer_name := NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'invoice', NEW.id, NEW.created_by_user_id,
      'نشاط فرعك: تم إنشاء فاتورة مبيعات',
      'تم إنشاء فاتورة ' || NEW.invoice_number ||
      CASE WHEN v_customer_name IS NOT NULL THEN ' للعميل ' || v_customer_name ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency || ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status IN ('paid', 'partially_paid', 'voided') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'invoice', NEW.id, NULL,
      'نشاط فرعك: تغيّرت حالة فاتورة مبيعات',
      'فاتورة ' || NEW.invoice_number ||
      CASE WHEN v_customer_name IS NOT NULL THEN ' للعميل ' || v_customer_name ELSE '' END ||
      ' أصبحت الحالة "' || NEW.status || '".'
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- invoice_item_amendment_reset_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.invoice_item_amendment_reset_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_invoice_id uuid; v_items jsonb; v_inv RECORD; v_customer text;
BEGIN
  v_invoice_id := COALESCE(NEW.invoice_id, OLD.invoice_id);
  SELECT * INTO v_inv FROM public.invoices WHERE id = v_invoice_id;
  IF NOT FOUND THEN RETURN COALESCE(NEW, OLD); END IF;
  IF v_inv.status NOT IN ('draft','pending_approval') THEN RETURN COALESCE(NEW, OLD); END IF;
  IF COALESCE(current_setting('app.skip_discount_approval', true), '') <> '' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'product_id', ii.product_id,
    'product_name', COALESCE(p.name, ii.description),
    'description', ii.description,
    'item_type', ii.item_type,
    'quantity', ii.quantity, 'unit_price', ii.unit_price,
    'discount_percent', ii.discount_percent,
    'tax_rate', ii.tax_rate, 'total', ii.line_total
  )), '[]'::jsonb) INTO v_items
    FROM public.invoice_items ii LEFT JOIN public.products p ON p.id=ii.product_id
   WHERE ii.invoice_id = v_invoice_id;
  SELECT name INTO v_customer FROM public.customers WHERE id = v_inv.customer_id;

  UPDATE public.discount_approvals
     SET items_snapshot            = v_items,
         document_total            = v_inv.total_amount,
         subtotal_snapshot         = v_inv.subtotal,
         shipping_snapshot         = v_inv.shipping,
         adjustment_snapshot       = v_inv.adjustment,
         tax_amount_snapshot       = v_inv.tax_amount,
         shipping_tax_rate_snapshot= v_inv.shipping_tax_rate,
         discount_position_snapshot= v_inv.discount_position,
         tax_inclusive_snapshot    = v_inv.tax_inclusive,
         supplier_name_snapshot    = v_customer,
         discount_value            = COALESCE(v_inv.discount_value, 0),
         discount_type             = COALESCE(v_inv.discount_type, 'amount'),
         updated_at                = NOW()
   WHERE document_type='sales_invoice' AND document_id=v_invoice_id AND status='pending';
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- invoice_item_protect_posted_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.invoice_item_protect_posted_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_invoice_status text;
  v_invoice_id uuid;
BEGIN
  v_invoice_id := COALESCE(NEW.invoice_id, OLD.invoice_id);
  SELECT status INTO v_invoice_status FROM public.invoices WHERE id = v_invoice_id;
  IF NOT FOUND THEN RETURN COALESCE(NEW, OLD); END IF;
  IF v_invoice_status IN ('draft', 'voided', 'cancelled', 'pending_approval', 'rejected') THEN
    RETURN COALESCE(NEW, OLD);
  END IF;
  IF COALESCE(current_setting('app.skip_po_lock', true), '') <> '' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;
  RAISE EXCEPTION 'لا يمكن تعديل بنود فاتورة منشورة. اعمل void للفاتورة أولاً.'
    USING ERRCODE = 'P0001';
END;
$function$
;

-- ---------------------------------------------------------------
-- invoice_notify_accountant_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.invoice_notify_accountant_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_customer_name text; v_currency text; v_actor uuid; v_accountant uuid;
  v_branch_count int; v_so_no text;
BEGIN
  v_actor    := NEW.created_by_user_id;
  v_currency := COALESCE(NEW.currency_code, 'EGP');

  BEGIN
    SELECT name INTO v_customer_name FROM public.customers WHERE id = NEW.customer_id;
  EXCEPTION WHEN OTHERS THEN v_customer_name := NULL; END;

  BEGIN
    IF NEW.sales_order_id IS NOT NULL THEN
      SELECT so_number INTO v_so_no FROM public.sales_orders WHERE id = NEW.sales_order_id;
    END IF;
  EXCEPTION WHEN OTHERS THEN v_so_no := NULL; END;

  SELECT COUNT(*) INTO v_branch_count
    FROM public.company_members
   WHERE company_id = NEW.company_id
     AND role       = 'accountant'
     AND branch_id  = NEW.branch_id
     AND user_id    IS NOT NULL;

  FOR v_accountant IN
    SELECT user_id FROM public.company_members
     WHERE company_id = NEW.company_id
       AND role       = 'accountant'
       AND user_id    IS NOT NULL
       AND ((v_branch_count > 0 AND branch_id = NEW.branch_id)
             OR (v_branch_count = 0))
       AND (v_actor IS NULL OR user_id <> v_actor)
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      NEW.company_id, 'invoice', NEW.id, v_actor,
      v_accountant,
      'فاتورة مبيعات جديدة تحتاج إجراء',
      'فاتورة ' || NEW.invoice_number ||
      CASE WHEN v_customer_name IS NOT NULL THEN ' للعميل ' || v_customer_name ELSE '' END ||
      CASE WHEN v_so_no IS NOT NULL THEN ' (من طلب مبيعات ' || v_so_no || ')' ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency ||
      ' — راجع الفاتورة وتابع التحصيل.',
      'high', 'info', 'accountant_action', 'in_app', NOW()
    );
  END LOOP;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- invoice_protect_posted_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.invoice_protect_posted_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF COALESCE(OLD.status, '') IN ('draft', 'voided', 'cancelled', 'pending_approval', 'rejected') THEN
    RETURN NEW;
  END IF;
  IF NEW.status IS DISTINCT FROM OLD.status THEN RETURN NEW; END IF;
  IF NEW.discount_value    IS DISTINCT FROM OLD.discount_value
     OR NEW.discount_type     IS DISTINCT FROM OLD.discount_type
     OR NEW.discount_position IS DISTINCT FROM OLD.discount_position
     OR NEW.tax_inclusive     IS DISTINCT FROM OLD.tax_inclusive
     OR NEW.exchange_rate     IS DISTINCT FROM OLD.exchange_rate
     OR NEW.subtotal          IS DISTINCT FROM OLD.subtotal
     OR NEW.total_amount      IS DISTINCT FROM OLD.total_amount
     OR NEW.tax_amount        IS DISTINCT FROM OLD.tax_amount
     OR NEW.shipping          IS DISTINCT FROM OLD.shipping THEN
    RAISE EXCEPTION 'لا يمكن تعديل الخصم أو الإجماليات على فاتورة منشورة. اعمل void للفاتورة أولاً.'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_format_reservation_number(p_sequence_value bigint, p_reference_ts timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_format_reservation_number(p_sequence_value bigint, p_reference_ts timestamp with time zone)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  RETURN 'RSV-' ||
    TO_CHAR(TIMEZONE('UTC', p_reference_ts), 'YYYYMM') ||
    '-' ||
    CASE
      WHEN p_sequence_value < 1000000 THEN LPAD(p_sequence_value::TEXT, 6, '0')
      ELSE p_sequence_value::TEXT
    END;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_generate_reservation_number(p_reference_ts timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_generate_reservation_number(p_reference_ts timestamp with time zone DEFAULT now())
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_sequence_value BIGINT;
  v_reference_ts   TIMESTAMPTZ := COALESCE(p_reference_ts, NOW());
BEGIN
  v_sequence_value := nextval('public.inventory_reservation_number_seq');
  RETURN public.ir_format_reservation_number(v_sequence_value, v_reference_ts);
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_guard_allocation_parent_terminal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_guard_allocation_parent_terminal()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_status TEXT;
  v_new_status TEXT;
BEGIN
  IF TG_OP IN ('UPDATE', 'DELETE') AND OLD.reservation_id IS NOT NULL THEN
    SELECT status
      INTO v_old_status
      FROM public.inventory_reservations
     WHERE id = OLD.reservation_id;

    IF v_old_status IS NOT NULL AND public.ir_is_terminal_reservation_status(v_old_status) THEN
      RAISE EXCEPTION 'inventory_reservation_allocations cannot be modified when parent reservation is terminal. reservation_id=%, status=%', OLD.reservation_id, v_old_status;
    END IF;
  END IF;

  IF TG_OP IN ('INSERT', 'UPDATE') AND NEW.reservation_id IS NOT NULL THEN
    SELECT status
      INTO v_new_status
      FROM public.inventory_reservations
     WHERE id = NEW.reservation_id;

    IF v_new_status IS NOT NULL AND public.ir_is_terminal_reservation_status(v_new_status) THEN
      RAISE EXCEPTION 'inventory_reservation_allocations cannot target a terminal reservation. reservation_id=%, status=%', NEW.reservation_id, v_new_status;
    END IF;
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_guard_consumption_immutable()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_guard_consumption_immutable()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  RAISE EXCEPTION 'inventory_reservation_consumptions is immutable. UPDATE and DELETE are not allowed.';
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_guard_consumption_parent_terminal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_guard_consumption_parent_terminal()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_parent_status TEXT;
BEGIN
  SELECT status
    INTO v_parent_status
    FROM public.inventory_reservations
   WHERE id = NEW.reservation_id;

  IF v_parent_status IS NOT NULL AND public.ir_is_terminal_reservation_status(v_parent_status) THEN
    RAISE EXCEPTION 'inventory_reservation_consumptions cannot be inserted when parent reservation is terminal. reservation_id=%, status=%', NEW.reservation_id, v_parent_status;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_guard_line_parent_terminal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_guard_line_parent_terminal()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_status TEXT;
  v_new_status TEXT;
BEGIN
  IF TG_OP IN ('UPDATE', 'DELETE') AND OLD.reservation_id IS NOT NULL THEN
    SELECT status
      INTO v_old_status
      FROM public.inventory_reservations
     WHERE id = OLD.reservation_id;

    IF v_old_status IS NOT NULL AND public.ir_is_terminal_reservation_status(v_old_status) THEN
      RAISE EXCEPTION 'inventory_reservation_lines cannot be modified when parent reservation is terminal. reservation_id=%, status=%', OLD.reservation_id, v_old_status;
    END IF;
  END IF;

  IF TG_OP IN ('INSERT', 'UPDATE') AND NEW.reservation_id IS NOT NULL THEN
    SELECT status
      INTO v_new_status
      FROM public.inventory_reservations
     WHERE id = NEW.reservation_id;

    IF v_new_status IS NOT NULL AND public.ir_is_terminal_reservation_status(v_new_status) THEN
      RAISE EXCEPTION 'inventory_reservation_lines cannot target a terminal reservation. reservation_id=%, status=%', NEW.reservation_id, v_new_status;
    END IF;
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_guard_reservation_number()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_guard_reservation_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_number TEXT;
  v_new_number TEXT;
BEGIN
  v_new_number := NULLIF(BTRIM(COALESCE(NEW.reservation_number, '')), '');

  IF TG_OP = 'INSERT' THEN
    IF v_new_number IS NULL THEN
      NEW.reservation_number := public.ir_generate_reservation_number(COALESCE(NEW.created_at, NOW()));
    ELSE
      NEW.reservation_number := v_new_number;
    END IF;
    RETURN NEW;
  END IF;

  v_old_number := NULLIF(BTRIM(COALESCE(OLD.reservation_number, '')), '');

  IF v_old_number IS NOT NULL AND v_new_number IS DISTINCT FROM v_old_number THEN
    RAISE EXCEPTION 'inventory_reservations.reservation_number is immutable once assigned.';
  END IF;

  IF v_new_number IS NULL THEN
    IF v_old_number IS NOT NULL THEN
      NEW.reservation_number := v_old_number;
    ELSE
      NEW.reservation_number := public.ir_generate_reservation_number(
        COALESCE(NEW.created_at, OLD.created_at, NOW())
      );
    END IF;
  ELSE
    NEW.reservation_number := v_new_number;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_guard_reservation_terminal_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_guard_reservation_terminal_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF public.ir_is_terminal_reservation_status(OLD.status) THEN
    RAISE EXCEPTION 'inventory_reservations terminal records are immutable. status=%', OLD.status;
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_is_terminal_reservation_status(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_is_terminal_reservation_status(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('consumed', 'released', 'cancelled', 'expired', 'closed');
$function$
;

-- ---------------------------------------------------------------
-- ir_refresh_allocation_consumed_from_consumptions()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_refresh_allocation_consumed_from_consumptions()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.ir_refresh_allocation_from_consumptions(NEW.reservation_allocation_id);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_refresh_allocation_from_consumptions(p_allocation_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_refresh_allocation_from_consumptions(p_allocation_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_consumed_qty NUMERIC(18,4) := 0;
  v_allocated_qty NUMERIC(18,4);
  v_released_qty NUMERIC(18,4);
  v_new_status TEXT;
BEGIN
  IF p_allocation_id IS NULL THEN
    RETURN;
  END IF;

  SELECT
    COALESCE(SUM(quantity), 0)::NUMERIC(18,4)
    INTO v_consumed_qty
    FROM public.inventory_reservation_consumptions
   WHERE reservation_allocation_id = p_allocation_id;

  SELECT
    allocated_qty,
    released_qty
    INTO v_allocated_qty,
         v_released_qty
    FROM public.inventory_reservation_allocations
   WHERE id = p_allocation_id;

  IF NOT FOUND THEN
    RETURN;
  END IF;

  v_new_status := CASE
    WHEN (v_allocated_qty - v_consumed_qty - v_released_qty) > 0 THEN 'active'
    WHEN v_consumed_qty > 0 THEN 'consumed'
    ELSE 'active'
  END;

  UPDATE public.inventory_reservation_allocations
     SET consumed_qty = v_consumed_qty,
         status = v_new_status
   WHERE id = p_allocation_id
     AND (
       consumed_qty IS DISTINCT FROM v_consumed_qty OR
       status IS DISTINCT FROM v_new_status
     );
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_refresh_header_totals(p_reservation_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_refresh_header_totals(p_reservation_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_requested_qty NUMERIC(18,4) := 0;
  v_reserved_qty  NUMERIC(18,4) := 0;
  v_consumed_qty  NUMERIC(18,4) := 0;
  v_released_qty  NUMERIC(18,4) := 0;
BEGIN
  IF p_reservation_id IS NULL THEN
    RETURN;
  END IF;

  SELECT
    COALESCE(SUM(requested_qty), 0)::NUMERIC(18,4),
    COALESCE(SUM(reserved_qty), 0)::NUMERIC(18,4),
    COALESCE(SUM(consumed_qty), 0)::NUMERIC(18,4),
    COALESCE(SUM(released_qty), 0)::NUMERIC(18,4)
    INTO v_requested_qty,
         v_reserved_qty,
         v_consumed_qty,
         v_released_qty
    FROM public.inventory_reservation_lines
   WHERE reservation_id = p_reservation_id;

  UPDATE public.inventory_reservations
     SET requested_qty = v_requested_qty,
         reserved_qty = v_reserved_qty,
         consumed_qty = v_consumed_qty,
         released_qty = v_released_qty
   WHERE id = p_reservation_id
     AND (
       requested_qty IS DISTINCT FROM v_requested_qty OR
       reserved_qty IS DISTINCT FROM v_reserved_qty OR
       consumed_qty IS DISTINCT FROM v_consumed_qty OR
       released_qty IS DISTINCT FROM v_released_qty
     );
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_refresh_header_totals_from_lines()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_refresh_header_totals_from_lines()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM public.ir_refresh_header_totals(OLD.reservation_id);
    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' AND OLD.reservation_id IS DISTINCT FROM NEW.reservation_id THEN
    PERFORM public.ir_refresh_header_totals(OLD.reservation_id);
  END IF;

  PERFORM public.ir_refresh_header_totals(NEW.reservation_id);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_refresh_line_totals(p_reservation_line_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_refresh_line_totals(p_reservation_line_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_reserved_qty NUMERIC(18,4) := 0;
  v_consumed_qty NUMERIC(18,4) := 0;
  v_released_qty NUMERIC(18,4) := 0;
BEGIN
  IF p_reservation_line_id IS NULL THEN
    RETURN;
  END IF;

  SELECT
    COALESCE(SUM(GREATEST(allocated_qty - consumed_qty - released_qty, 0)), 0)::NUMERIC(18,4),
    COALESCE(SUM(consumed_qty), 0)::NUMERIC(18,4),
    COALESCE(SUM(released_qty), 0)::NUMERIC(18,4)
    INTO v_reserved_qty,
         v_consumed_qty,
         v_released_qty
    FROM public.inventory_reservation_allocations
   WHERE reservation_line_id = p_reservation_line_id;

  UPDATE public.inventory_reservation_lines
     SET reserved_qty = v_reserved_qty,
         consumed_qty = v_consumed_qty,
         released_qty = v_released_qty
   WHERE id = p_reservation_line_id
     AND (
       reserved_qty IS DISTINCT FROM v_reserved_qty OR
       consumed_qty IS DISTINCT FROM v_consumed_qty OR
       released_qty IS DISTINCT FROM v_released_qty
     );
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_refresh_line_totals_from_allocations()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_refresh_line_totals_from_allocations()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM public.ir_refresh_line_totals(OLD.reservation_line_id);
    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' AND OLD.reservation_line_id IS DISTINCT FROM NEW.reservation_line_id THEN
    PERFORM public.ir_refresh_line_totals(OLD.reservation_line_id);
  END IF;

  PERFORM public.ir_refresh_line_totals(NEW.reservation_line_id);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- ir_set_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.ir_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- is_branch_accessible(p_branch_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.is_branch_accessible(p_branch_id uuid, p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_role TEXT;
    v_user_branch UUID;
BEGIN
    IF p_branch_id IS NULL THEN
        RETURN TRUE;
    END IF;

    -- Get user role and branch in the associated company
    SELECT role, branch_id INTO v_role, v_user_branch
    FROM public.company_members
    WHERE user_id = p_user_id 
    AND company_id = (SELECT company_id FROM public.branches WHERE id = p_branch_id);

    IF v_role IN ('super_admin', 'admin', 'owner', 'manager', 'general_manager') THEN
        RETURN TRUE;
    END IF;

    RETURN v_user_branch = p_branch_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- is_company_member(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.is_company_member(p_company_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN EXISTS (
    SELECT 1 FROM company_members cm
    WHERE cm.company_id = p_company_id
    AND cm.user_id = auth.uid()
  ) OR EXISTS (
    SELECT 1 FROM companies c
    WHERE c.id = p_company_id
    AND c.user_id = auth.uid()
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- is_owner_or_admin(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.is_owner_or_admin(p_company_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN EXISTS (
    SELECT 1 FROM companies c WHERE c.id = p_company_id AND c.user_id = auth.uid()
  ) OR EXISTS (
    SELECT 1 FROM company_members cm
    WHERE cm.company_id = p_company_id
    AND cm.user_id = auth.uid()
    AND cm.role IN ('owner', 'admin')
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- is_shipping_provider_allowed_for_branch(p_branch_id uuid, p_shipping_provider_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.is_shipping_provider_allowed_for_branch(p_branch_id uuid, p_shipping_provider_id uuid, p_company_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_provider_has_mapping BOOLEAN;
BEGIN
  IF p_shipping_provider_id IS NULL THEN RETURN TRUE; END IF;
  IF p_branch_id IS NULL THEN RETURN FALSE; END IF;

  -- v3.74.597: semantics are PER PROVIDER now (was: per company).
  SELECT EXISTS (
    SELECT 1 FROM public.branch_shipping_providers bsp
    WHERE bsp.shipping_provider_id = p_shipping_provider_id
  ) INTO v_provider_has_mapping;

  -- unmapped provider = global (visible/usable by all branches)
  IF NOT v_provider_has_mapping THEN RETURN TRUE; END IF;

  RETURN EXISTS (
    SELECT 1 FROM public.branch_shipping_providers bsp
    JOIN public.branches b ON b.id = bsp.branch_id
    WHERE bsp.branch_id = p_branch_id
      AND bsp.shipping_provider_id = p_shipping_provider_id
      AND b.company_id = p_company_id
      AND (bsp.is_active IS NULL OR bsp.is_active = TRUE)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- issue_manufacturing_production_order_materials_atomic(p_company_id uuid, p_production_order_id uuid, p_posted_by uuid, p_lines jsonb, p_posted_at timestamp with time zone, p_notes text, p_command_key text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.issue_manufacturing_production_order_materials_atomic(p_company_id uuid, p_production_order_id uuid, p_posted_by uuid, p_lines jsonb, p_posted_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_notes text DEFAULT NULL::text, p_command_key text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order RECORD;
  v_issue_warehouse RECORD;
  v_sync_result JSONB;
  v_posted_at TIMESTAMPTZ := COALESCE(p_posted_at, NOW());
  v_issue_event_id UUID := gen_random_uuid();
  v_existing_issue_event_id UUID;
  v_issue_event_number TEXT := NULLIF(BTRIM(COALESCE(p_command_key, '')), '');
  v_auto_started_order BOOLEAN := false;
  v_active_reservation RECORD;
  v_line JSONB;
  v_line_no INTEGER := 0;
  v_requirement RECORD;
  v_reservation_line RECORD;
  v_active_allocation_id UUID;
  v_active_allocation_status TEXT;
  v_requested_allocation_id UUID;
  v_issued_qty NUMERIC(18,4);
  v_already_issued_qty NUMERIC(18,4);
  v_remaining_requirement_qty NUMERIC(18,4);
  v_open_alloc_qty NUMERIC(18,4);
  v_needed_top_up_qty NUMERIC(18,4);
  v_free_qty NUMERIC(18,4);
  v_issue_line_id UUID;
  v_inventory_transaction_id UUID;
  v_inventory_total_cost NUMERIC(18,4);
  v_inventory_unit_cost NUMERIC(18,4);
  v_fifo_lot RECORD;
  v_remaining_fifo_qty NUMERIC(18,4);
  v_fifo_consume_qty NUMERIC(18,4);
  v_total_issued_qty NUMERIC(18,4) := 0;
  v_total_issued_cost NUMERIC(18,4) := 0;
  v_reservation_status TEXT;
BEGIN
  IF p_lines IS NULL OR jsonb_typeof(p_lines) <> 'array' OR jsonb_array_length(p_lines) = 0 THEN
    RAISE EXCEPTION 'Material issue requires a non-empty lines array.';
  END IF;

  IF EXISTS (
    SELECT 1
      FROM (
        SELECT NULLIF(line->>'material_requirement_id', '')::UUID AS material_requirement_id
          FROM jsonb_array_elements(p_lines) AS line
      ) dup
     GROUP BY material_requirement_id
    HAVING COUNT(*) > 1
  ) THEN
    RAISE EXCEPTION 'Duplicate material_requirement_id values are not allowed in a single issue command.';
  END IF;

  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order not found or not in company. production_order_id=%', p_production_order_id;
  END IF;

  IF v_order.status NOT IN ('released', 'in_progress') THEN
    RAISE EXCEPTION 'Material issue is allowed only for released or in-progress production orders. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  END IF;

  IF v_issue_event_number IS NOT NULL THEN
    SELECT id
      INTO v_existing_issue_event_id
      FROM public.production_order_issue_events
     WHERE company_id = p_company_id
       AND production_order_id = p_production_order_id
       AND event_number = v_issue_event_number
     ORDER BY created_at DESC
     LIMIT 1
     FOR UPDATE;

    IF FOUND THEN
      RETURN jsonb_build_object(
        'success', true,
        'idempotent', true,
        'production_order_id', p_production_order_id,
        'issue_event_id', v_existing_issue_event_id
      );
    END IF;
  END IF;

  v_sync_result := public.mpoe_sync_materials_internal(
    p_company_id,
    p_production_order_id,
    p_posted_by
  );

  IF v_order.status = 'released' THEN
    PERFORM public.start_manufacturing_production_order_atomic(
      p_company_id,
      p_production_order_id,
      p_posted_by,
      v_posted_at
    );
    v_auto_started_order := true;
  END IF;

  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  SELECT w.*
    INTO v_issue_warehouse
    FROM public.warehouses w
   WHERE w.id = v_order.issue_warehouse_id;

  IF NOT FOUND OR v_issue_warehouse.cost_center_id IS NULL THEN
    RAISE EXCEPTION 'Issue warehouse/cost center context not ready for material issue. production_order_id=%', p_production_order_id;
  END IF;

  SELECT *
    INTO v_active_reservation
    FROM public.inventory_reservations
   WHERE company_id = p_company_id
     AND source_type = 'production_order'
     AND source_id = p_production_order_id
     AND status NOT IN ('consumed', 'released', 'cancelled', 'expired', 'closed')
   ORDER BY created_at DESC
   LIMIT 1
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Open production reservation not found after material sync. production_order_id=%', p_production_order_id;
  END IF;

  INSERT INTO public.production_order_issue_events (
    id,
    company_id,
    branch_id,
    production_order_id,
    warehouse_id,
    cost_center_id,
    event_number,
    issue_mode,
    posted_at,
    posted_by,
    notes
  ) VALUES (
    v_issue_event_id,
    v_order.company_id,
    v_issue_warehouse.branch_id,
    v_order.id,
    v_order.issue_warehouse_id,
    v_issue_warehouse.cost_center_id,
    v_issue_event_number,
    'manual',
    v_posted_at,
    p_posted_by,
    p_notes
  );

  FOR v_line IN
    SELECT value
      FROM jsonb_array_elements(p_lines)
  LOOP
    v_line_no := v_line_no + 1;
    v_issue_line_id := gen_random_uuid();
    v_inventory_total_cost := 0;
    v_inventory_unit_cost := 0;

    v_issued_qty := public.mpoe_round_qty((v_line->>'issued_qty')::NUMERIC);
    v_requested_allocation_id := NULLIF(v_line->>'reservation_allocation_id', '')::UUID;

    IF v_issued_qty <= 0 THEN
      RAISE EXCEPTION 'issued_qty must be greater than zero for production issue lines. production_order_id=%',
        p_production_order_id;
    END IF;

    SELECT *
      INTO v_requirement
      FROM public.production_order_material_requirements
     WHERE id = NULLIF(v_line->>'material_requirement_id', '')::UUID
       AND production_order_id = p_production_order_id
     FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Material requirement not found for production issue. production_order_id=%, material_requirement_id=%',
        p_production_order_id, v_line->>'material_requirement_id';
    END IF;

    PERFORM public.mpoe_lock_inventory_bucket(
      p_company_id,
      v_requirement.warehouse_id,
      v_requirement.product_id
    );

    SELECT COALESCE(SUM(issued_qty), 0)::NUMERIC(18,4)
      INTO v_already_issued_qty
      FROM public.production_order_issue_lines
     WHERE material_requirement_id = v_requirement.id;

    v_remaining_requirement_qty := GREATEST(
      v_requirement.gross_required_qty - COALESCE(v_already_issued_qty, 0),
      0
    )::NUMERIC(18,4);

    IF v_issued_qty > v_remaining_requirement_qty THEN
      RAISE EXCEPTION 'Issued quantity exceeds remaining allowed requirement quantity. production_order_id=%, material_requirement_id=%, remaining_qty=%, requested_qty=%',
        p_production_order_id, v_requirement.id, v_remaining_requirement_qty, v_issued_qty;
    END IF;

    SELECT *
      INTO v_reservation_line
      FROM public.inventory_reservation_lines
     WHERE reservation_id = v_active_reservation.id
       AND source_line_id = v_requirement.id
     FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Reservation line not found for material requirement issue. production_order_id=%, reservation_id=%, material_requirement_id=%',
        p_production_order_id, v_active_reservation.id, v_requirement.id;
    END IF;

    IF v_requested_allocation_id IS NOT NULL THEN
      SELECT
        a.id,
        a.status,
        GREATEST(a.allocated_qty - a.consumed_qty - a.released_qty, 0)::NUMERIC(18,4)
        INTO v_active_allocation_id,
             v_active_allocation_status,
             v_open_alloc_qty
        FROM public.inventory_reservation_allocations a
       WHERE a.id = v_requested_allocation_id
         AND a.reservation_id = v_active_reservation.id
         AND a.reservation_line_id = v_reservation_line.id
       FOR UPDATE;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Requested reservation allocation not found for material issue. reservation_allocation_id=%',
          v_requested_allocation_id;
      END IF;

      IF v_active_allocation_status <> 'active' THEN
        RAISE EXCEPTION 'Requested reservation allocation must be active for material issue. reservation_allocation_id=%, status=%',
          v_requested_allocation_id, v_active_allocation_status;
      END IF;
    ELSE
      SELECT
        a.id,
        a.status,
        GREATEST(a.allocated_qty - a.consumed_qty - a.released_qty, 0)::NUMERIC(18,4)
        INTO v_active_allocation_id,
             v_active_allocation_status,
             v_open_alloc_qty
        FROM public.inventory_reservation_allocations a
       WHERE a.reservation_line_id = v_reservation_line.id
         AND a.warehouse_id = v_requirement.warehouse_id
         AND a.status = 'active'
       FOR UPDATE;

      IF NOT FOUND THEN
        v_active_allocation_id := NULL;
        v_active_allocation_status := NULL;
        v_open_alloc_qty := 0;
      END IF;
    END IF;

    IF v_open_alloc_qty < v_issued_qty THEN
      v_needed_top_up_qty := (v_issued_qty - v_open_alloc_qty)::NUMERIC(18,4);

      SELECT free_quantity
        INTO v_free_qty
        FROM public.get_inventory_reservation_snapshot(
          p_company_id,
          v_requirement.branch_id,
          v_requirement.warehouse_id,
          v_requirement.product_id
        );

      IF COALESCE(v_free_qty, 0) < v_needed_top_up_qty THEN
        RAISE EXCEPTION 'Insufficient free stock to reserve and issue requested material quantity. production_order_id=%, material_requirement_id=%, free_qty=%, requested_top_up=%',
          p_production_order_id, v_requirement.id, COALESCE(v_free_qty, 0), v_needed_top_up_qty;
      END IF;

      IF v_active_allocation_id IS NULL THEN
        INSERT INTO public.inventory_reservation_allocations (
          company_id,
          branch_id,
          warehouse_id,
          cost_center_id,
          reservation_id,
          reservation_line_id,
          product_id,
          allocated_qty,
          status,
          created_by,
          updated_by
        ) VALUES (
          v_requirement.company_id,
          v_requirement.branch_id,
          v_requirement.warehouse_id,
          v_requirement.cost_center_id,
          v_active_reservation.id,
          v_reservation_line.id,
          v_requirement.product_id,
          v_needed_top_up_qty,
          'active',
          p_posted_by,
          p_posted_by
        )
        RETURNING id,
                  status,
                  GREATEST(allocated_qty - consumed_qty - released_qty, 0)::NUMERIC(18,4)
             INTO v_active_allocation_id,
                  v_active_allocation_status,
                  v_open_alloc_qty;
      ELSE
        UPDATE public.inventory_reservation_allocations
           SET allocated_qty = allocated_qty + v_needed_top_up_qty,
               updated_by = p_posted_by
         WHERE id = v_active_allocation_id
         RETURNING id,
                   status,
                   GREATEST(allocated_qty - consumed_qty - released_qty, 0)::NUMERIC(18,4)
              INTO v_active_allocation_id,
                   v_active_allocation_status,
                   v_open_alloc_qty;
      END IF;
    END IF;

    IF v_open_alloc_qty < v_issued_qty THEN
      RAISE EXCEPTION 'Reservation allocation open quantity is insufficient for material issue. production_order_id=%, material_requirement_id=%, open_qty=%, requested_qty=%',
        p_production_order_id, v_requirement.id, v_open_alloc_qty, v_issued_qty;
    END IF;

    v_remaining_fifo_qty := v_issued_qty;

    FOR v_fifo_lot IN
      SELECT *
        FROM public.fifo_cost_lots
       WHERE company_id = p_company_id
         AND product_id = v_requirement.product_id
         AND COALESCE(branch_id, v_requirement.branch_id) = v_requirement.branch_id
         AND COALESCE(warehouse_id, v_requirement.warehouse_id) = v_requirement.warehouse_id
         AND remaining_quantity > 0
       ORDER BY lot_date ASC, created_at ASC, id ASC
       FOR UPDATE
    LOOP
      EXIT WHEN v_remaining_fifo_qty <= 0;

      v_fifo_consume_qty := LEAST(v_fifo_lot.remaining_quantity, v_remaining_fifo_qty)::NUMERIC(18,4);
      v_inventory_total_cost := v_inventory_total_cost + public.mpoe_round_qty(v_fifo_consume_qty * v_fifo_lot.unit_cost);
      v_remaining_fifo_qty := public.mpoe_round_qty(v_remaining_fifo_qty - v_fifo_consume_qty);
    END LOOP;

    IF v_remaining_fifo_qty > 0 THEN
      RAISE EXCEPTION 'Insufficient FIFO stock layers for production issue. production_order_id=%, material_requirement_id=%, missing_qty=%',
        p_production_order_id, v_requirement.id, v_remaining_fifo_qty;
    END IF;

    v_inventory_unit_cost := CASE
      WHEN v_issued_qty > 0 THEN public.mpoe_round_qty(v_inventory_total_cost / v_issued_qty)
      ELSE 0
    END;

    INSERT INTO public.inventory_transactions (
      company_id,
      product_id,
      transaction_type,
      quantity_change,
      unit_cost,
      total_cost,
      reference_id,
      reference_type,
      notes,
      branch_id,
      cost_center_id,
      warehouse_id
    ) VALUES (
      p_company_id,
      v_requirement.product_id,
      'production_issue',
      -v_issued_qty,
      v_inventory_unit_cost,
      v_inventory_total_cost,
      v_issue_line_id,
      'production_issue_line',
      COALESCE(NULLIF(BTRIM(COALESCE(v_line->>'notes', '')), ''), p_notes),
      v_requirement.branch_id,
      v_requirement.cost_center_id,
      v_requirement.warehouse_id
    )
    RETURNING id INTO v_inventory_transaction_id;

    INSERT INTO public.production_order_issue_lines (
      id,
      company_id,
      branch_id,
      issue_event_id,
      production_order_id,
      material_requirement_id,
      line_no,
      warehouse_id,
      cost_center_id,
      product_id,
      reservation_allocation_id,
      inventory_transaction_id,
      issued_qty,
      issue_uom,
      notes
    ) VALUES (
      v_issue_line_id,
      v_requirement.company_id,
      v_requirement.branch_id,
      v_issue_event_id,
      p_production_order_id,
      v_requirement.id,
      v_line_no,
      v_requirement.warehouse_id,
      v_requirement.cost_center_id,
      v_requirement.product_id,
      v_active_allocation_id,
      v_inventory_transaction_id,
      v_issued_qty,
      v_requirement.issue_uom,
      NULLIF(BTRIM(COALESCE(v_line->>'notes', '')), '')
    );

    v_remaining_fifo_qty := v_issued_qty;

    FOR v_fifo_lot IN
      SELECT *
        FROM public.fifo_cost_lots
       WHERE company_id = p_company_id
         AND product_id = v_requirement.product_id
         AND COALESCE(branch_id, v_requirement.branch_id) = v_requirement.branch_id
         AND COALESCE(warehouse_id, v_requirement.warehouse_id) = v_requirement.warehouse_id
         AND remaining_quantity > 0
       ORDER BY lot_date ASC, created_at ASC, id ASC
       FOR UPDATE
    LOOP
      EXIT WHEN v_remaining_fifo_qty <= 0;

      v_fifo_consume_qty := LEAST(v_fifo_lot.remaining_quantity, v_remaining_fifo_qty)::NUMERIC(18,4);

      INSERT INTO public.fifo_lot_consumptions (
        company_id,
        lot_id,
        product_id,
        consumption_type,
        reference_type,
        reference_id,
        quantity_consumed,
        unit_cost,
        total_cost,
        consumption_date,
        notes,
        created_at
      ) VALUES (
        p_company_id,
        v_fifo_lot.id,
        v_fifo_lot.product_id,
        'production_issue',
        'production_issue_line',
        v_issue_line_id,
        v_fifo_consume_qty,
        v_fifo_lot.unit_cost,
        public.mpoe_round_qty(v_fifo_consume_qty * v_fifo_lot.unit_cost),
        v_posted_at::DATE,
        COALESCE(NULLIF(BTRIM(COALESCE(v_line->>'notes', '')), ''), p_notes),
        v_posted_at
      );

      UPDATE public.fifo_cost_lots
         SET remaining_quantity = remaining_quantity - v_fifo_consume_qty
       WHERE id = v_fifo_lot.id;

      IF EXISTS (
        SELECT 1
          FROM public.fifo_cost_lots
         WHERE id = v_fifo_lot.id
           AND remaining_quantity < 0
      ) THEN
        RAISE EXCEPTION 'FIFO lot quantity cannot be negative after production issue. lot_id=%', v_fifo_lot.id;
      END IF;

      v_remaining_fifo_qty := public.mpoe_round_qty(v_remaining_fifo_qty - v_fifo_consume_qty);
    END LOOP;

    INSERT INTO public.inventory_reservation_consumptions (
      company_id,
      branch_id,
      warehouse_id,
      cost_center_id,
      reservation_id,
      reservation_line_id,
      reservation_allocation_id,
      product_id,
      inventory_transaction_id,
      source_event_type,
      source_event_id,
      quantity,
      created_by
    ) VALUES (
      p_company_id,
      v_requirement.branch_id,
      v_requirement.warehouse_id,
      v_requirement.cost_center_id,
      v_active_reservation.id,
      v_reservation_line.id,
      v_active_allocation_id,
      v_requirement.product_id,
      v_inventory_transaction_id,
      'production_issue',
      v_issue_line_id,
      v_issued_qty,
      p_posted_by
    );

    v_total_issued_qty := v_total_issued_qty + v_issued_qty;
    v_total_issued_cost := v_total_issued_cost + v_inventory_total_cost;
  END LOOP;

  PERFORM public.mpoe_refresh_open_reservation_status(v_active_reservation.id, p_posted_by);

  SELECT status
    INTO v_reservation_status
    FROM public.inventory_reservations
   WHERE id = v_active_reservation.id;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', p_production_order_id,
    'issue_event_id', v_issue_event_id,
    'line_count', jsonb_array_length(p_lines),
    'total_issued_qty', v_total_issued_qty,
    'total_issued_cost', v_total_issued_cost,
    'reservation_id', v_active_reservation.id,
    'reservation_status', v_reservation_status,
    'auto_started_order', v_auto_started_order,
    'sync_result', v_sync_result
  );
END;
$function$
;

