-- ---------------------------------------------------------------
-- link_existing_bank_accounts_to_main_branch()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.link_existing_bank_accounts_to_main_branch()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_count INTEGER := 0;
BEGIN
  UPDATE chart_of_accounts coa
  SET branch_id = (
    SELECT b.id FROM branches b 
    WHERE b.company_id = coa.company_id 
    AND b.is_main = TRUE 
    LIMIT 1
  )
  WHERE coa.branch_id IS NULL
  AND coa.sub_type IN ('cash', 'bank')
  AND EXISTS (
    SELECT 1 FROM branches b 
    WHERE b.company_id = coa.company_id 
    AND b.is_main = TRUE
  );
  
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$function$
;

-- ---------------------------------------------------------------
-- link_financial_operation_trace(p_transaction_id uuid, p_entity_type text, p_entity_id uuid, p_link_role text, p_reference_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.link_financial_operation_trace(p_transaction_id uuid, p_entity_type text, p_entity_id uuid, p_link_role text DEFAULT NULL::text, p_reference_type text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF p_transaction_id IS NULL OR p_entity_id IS NULL THEN
    RETURN;
  END IF;

  INSERT INTO public.financial_operation_trace_links (
    transaction_id,
    entity_type,
    entity_id,
    link_role,
    reference_type
  ) VALUES (
    p_transaction_id,
    p_entity_type,
    p_entity_id,
    p_link_role,
    p_reference_type
  )
  ON CONFLICT (transaction_id, entity_type, entity_id) DO NOTHING;
END;
$function$
;

-- ---------------------------------------------------------------
-- lock_purchase_return_on_status()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.lock_purchase_return_on_status()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status IN ('approved', 'sent_to_vendor') THEN
    NEW.is_locked := true;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mark_notification_as_read(p_notification_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mark_notification_as_read(p_notification_id uuid, p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- إدراج حالة جديدة أو تحديث الحالة الحالية للمستخدم
  INSERT INTO notification_user_states (notification_id, user_id, status, read_at, updated_at)
  VALUES (p_notification_id, p_user_id, 'read', NOW(), NOW())
  ON CONFLICT (notification_id, user_id)
  DO UPDATE SET 
    status = CASE WHEN notification_user_states.status = 'unread' THEN 'read' ELSE notification_user_states.status END,
    read_at = COALESCE(notification_user_states.read_at, NOW()),
    updated_at = NOW();

  RETURN TRUE;
END;
$function$
;

-- ---------------------------------------------------------------
-- mark_subscription_past_due(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mark_subscription_past_due(p_company_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_status text;
BEGIN
  SELECT subscription_status INTO v_status
  FROM companies WHERE id = p_company_id FOR UPDATE;

  IF v_status IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'company_not_found');
  END IF;

  IF v_status != 'active' THEN
    RETURN json_build_object('success', true, 'idempotent', true, 'current_status', v_status);
  END IF;

  UPDATE companies
  SET subscription_status = 'past_due',
      renewal_reminder_sent_at = NULL
  WHERE id = p_company_id;

  BEGIN
    INSERT INTO audit_logs(action, company_id, target_table, new_data)
    VALUES (
      'subscription_past_due',
      p_company_id,
      'companies',
      json_build_object('previous_status', v_status, 'reason', 'period_end_passed')::jsonb
    );
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN json_build_object('success', true, 'transitioned', true);
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_assert_bom_version_structure_editable(p_bom_version_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_assert_bom_version_structure_editable(p_bom_version_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_status TEXT;
BEGIN
  SELECT status
    INTO v_status
    FROM public.manufacturing_bom_versions
   WHERE id = p_bom_version_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'manufacturing_bom_versions record not found. bom_version_id=%', p_bom_version_id;
  END IF;

  IF NOT public.mb_is_bom_version_structure_editable(v_status) THEN
    RAISE EXCEPTION 'manufacturing_bom_versions structure is not editable in current status. bom_version_id=%, status=%', p_bom_version_id, v_status;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_guard_bom_deleteability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_guard_bom_deleteability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_blocking_version_id UUID;
  v_blocking_status TEXT;
BEGIN
  SELECT v.id, v.status
    INTO v_blocking_version_id, v_blocking_status
    FROM public.manufacturing_bom_versions v
   WHERE v.bom_id = OLD.id
     AND NOT public.mb_is_bom_version_structure_editable(v.status)
   ORDER BY v.version_no
   LIMIT 1;

  IF v_blocking_version_id IS NOT NULL THEN
    RAISE EXCEPTION 'manufacturing_boms cannot be deleted when it has non-editable versions. bom_id=%, blocking_version_id=%, blocking_status=%',
      OLD.id, v_blocking_version_id, v_blocking_status;
  END IF;

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_guard_bom_identity_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_guard_bom_identity_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.company_id IS DISTINCT FROM NEW.company_id
     OR OLD.branch_id IS DISTINCT FROM NEW.branch_id
     OR OLD.product_id IS DISTINCT FROM NEW.product_id
     OR OLD.bom_usage IS DISTINCT FROM NEW.bom_usage THEN
    RAISE EXCEPTION 'manufacturing_boms identity fields are immutable after creation. bom_id=%', OLD.id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_guard_bom_line_parent_editability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_guard_bom_line_parent_editability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM public.mb_assert_bom_version_structure_editable(OLD.bom_version_id);
    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    PERFORM public.mb_assert_bom_version_structure_editable(OLD.bom_version_id);

    IF OLD.bom_version_id IS DISTINCT FROM NEW.bom_version_id THEN
      PERFORM public.mb_assert_bom_version_structure_editable(NEW.bom_version_id);
    END IF;

    RETURN NEW;
  END IF;

  PERFORM public.mb_assert_bom_version_structure_editable(NEW.bom_version_id);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_guard_bom_substitute_parent_editability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_guard_bom_substitute_parent_editability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old_bom_version_id UUID;
  v_new_bom_version_id UUID;
BEGIN
  IF TG_OP IN ('UPDATE', 'DELETE') THEN
    SELECT l.bom_version_id
      INTO v_old_bom_version_id
      FROM public.manufacturing_bom_lines l
     WHERE l.id = OLD.bom_line_id;

    IF v_old_bom_version_id IS NULL THEN
      RAISE EXCEPTION 'Parent BOM line not found for substitute editability validation. bom_line_id=%', OLD.bom_line_id;
    END IF;

    PERFORM public.mb_assert_bom_version_structure_editable(v_old_bom_version_id);
  END IF;

  IF TG_OP IN ('INSERT', 'UPDATE') THEN
    SELECT l.bom_version_id
      INTO v_new_bom_version_id
      FROM public.manufacturing_bom_lines l
     WHERE l.id = NEW.bom_line_id;

    IF v_new_bom_version_id IS NULL THEN
      RAISE EXCEPTION 'Parent BOM line not found for substitute editability validation. bom_line_id=%', NEW.bom_line_id;
    END IF;

    IF TG_OP = 'INSERT' OR v_new_bom_version_id IS DISTINCT FROM v_old_bom_version_id THEN
      PERFORM public.mb_assert_bom_version_structure_editable(v_new_bom_version_id);
    END IF;

    RETURN NEW;
  END IF;

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_guard_bom_version_deleteability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_guard_bom_version_deleteability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NOT public.mb_is_bom_version_structure_editable(OLD.status) THEN
    RAISE EXCEPTION 'manufacturing_bom_versions cannot be deleted in current status. bom_version_id=%, status=%',
      OLD.id, OLD.status;
  END IF;

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_guard_bom_version_update()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_guard_bom_version_update()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_header_changed BOOLEAN;
BEGIN
  IF OLD.company_id IS DISTINCT FROM NEW.company_id
     OR OLD.branch_id IS DISTINCT FROM NEW.branch_id
     OR OLD.bom_id IS DISTINCT FROM NEW.bom_id
     OR OLD.version_no IS DISTINCT FROM NEW.version_no THEN
    RAISE EXCEPTION 'manufacturing_bom_versions identity fields are immutable after creation. bom_version_id=%', OLD.id;
  END IF;

  IF NOT public.mb_is_bom_version_transition_allowed(OLD.status, NEW.status) THEN
    RAISE EXCEPTION 'Invalid manufacturing_bom_versions status transition. bom_version_id=%, old_status=%, new_status=%',
      OLD.id, OLD.status, NEW.status;
  END IF;

  v_header_changed :=
       OLD.effective_from IS DISTINCT FROM NEW.effective_from
    OR OLD.effective_to IS DISTINCT FROM NEW.effective_to
    OR OLD.base_output_qty IS DISTINCT FROM NEW.base_output_qty
    OR OLD.change_summary IS DISTINCT FROM NEW.change_summary
    OR OLD.notes IS DISTINCT FROM NEW.notes;

  IF OLD.status = 'pending_approval' THEN
    IF NEW.status = OLD.status THEN
      RAISE EXCEPTION 'Pending approval BOM versions are locked for editing. bom_version_id=%', OLD.id;
    END IF;

    IF v_header_changed OR OLD.is_default IS DISTINCT FROM NEW.is_default THEN
      RAISE EXCEPTION 'Pending approval BOM versions cannot change header fields or default flag. bom_version_id=%', OLD.id;
    END IF;
  ELSIF OLD.status = 'approved' THEN
    IF NEW.status = OLD.status THEN
      IF v_header_changed THEN
        RAISE EXCEPTION 'Approved BOM versions cannot modify header fields. bom_version_id=%', OLD.id;
      END IF;
    ELSE
      IF v_header_changed THEN
        RAISE EXCEPTION 'Approved BOM versions cannot modify header fields during status transition. bom_version_id=%', OLD.id;
      END IF;
    END IF;
  ELSIF OLD.status IN ('superseded', 'archived') THEN
    RAISE EXCEPTION 'Locked BOM versions cannot be updated. bom_version_id=%, status=%', OLD.id, OLD.status;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_is_bom_input_product_type_allowed(p_product_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_is_bom_input_product_type_allowed(p_product_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(BTRIM(p_product_type), '') = 'raw_material';
$function$
;

-- ---------------------------------------------------------------
-- mb_is_bom_output_product_type_allowed(p_product_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_is_bom_output_product_type_allowed(p_product_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(BTRIM(p_product_type), '') = 'manufactured';
$function$
;

-- ---------------------------------------------------------------
-- mb_is_bom_version_locked(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_is_bom_version_locked(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('pending_approval', 'approved', 'superseded', 'archived');
$function$
;

-- ---------------------------------------------------------------
-- mb_is_bom_version_structure_editable(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_is_bom_version_structure_editable(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('draft', 'rejected');
$function$
;

-- ---------------------------------------------------------------
-- mb_is_bom_version_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_is_bom_version_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_old_status, '')
    WHEN 'draft' THEN COALESCE(p_new_status, '') IN ('draft', 'pending_approval', 'archived')
    WHEN 'pending_approval' THEN COALESCE(p_new_status, '') IN ('pending_approval', 'approved', 'rejected')
    WHEN 'approved' THEN COALESCE(p_new_status, '') IN ('approved', 'superseded', 'archived')
    WHEN 'rejected' THEN COALESCE(p_new_status, '') IN ('rejected', 'pending_approval', 'archived')
    WHEN 'superseded' THEN COALESCE(p_new_status, '') IN ('superseded', 'archived')
    WHEN 'archived' THEN COALESCE(p_new_status, '') IN ('archived')
    ELSE false
  END;
$function$
;

