-- ---------------------------------------------------------------
-- mb_validate_bom_line_context(p_bom_version_id uuid, p_company_id uuid, p_branch_id uuid, p_component_product_id uuid, p_line_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_validate_bom_line_context(p_bom_version_id uuid, p_company_id uuid, p_branch_id uuid, p_component_product_id uuid, p_line_type text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_version_company_id UUID;
  v_version_branch_id UUID;
  v_owner_product_id UUID;
  v_component_company_id UUID;
  v_component_item_type TEXT;
  v_component_product_type TEXT;
  v_effective_component_product_type TEXT;
BEGIN
  SELECT
    v.company_id,
    v.branch_id,
    b.product_id
    INTO v_version_company_id,
         v_version_branch_id,
         v_owner_product_id
    FROM public.manufacturing_bom_versions v
    JOIN public.manufacturing_boms b
      ON b.id = v.bom_id
   WHERE v.id = p_bom_version_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'manufacturing_bom_versions record not found for BOM line validation. bom_version_id=%', p_bom_version_id;
  END IF;

  IF v_version_company_id IS DISTINCT FROM p_company_id OR v_version_branch_id IS DISTINCT FROM p_branch_id THEN
    RAISE EXCEPTION 'BOM line company/branch must match BOM version. bom_version_id=%, line_company_id=%, line_branch_id=%',
      p_bom_version_id, p_company_id, p_branch_id;
  END IF;

  SELECT company_id, item_type, product_type
    INTO v_component_company_id, v_component_item_type, v_component_product_type
    FROM public.products
   WHERE id = p_component_product_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Component product not found for BOM line validation. product_id=%', p_component_product_id;
  END IF;

  IF v_component_company_id IS DISTINCT FROM p_company_id THEN
    RAISE EXCEPTION 'Component product must belong to the same company as the BOM line. product_id=%, company_id=%',
      p_component_product_id, p_company_id;
  END IF;

  v_effective_component_product_type := COALESCE(NULLIF(BTRIM(v_component_product_type), ''), 'purchased');

  IF COALESCE(v_component_item_type, 'product') = 'service' THEN
    v_effective_component_product_type := 'service';
  END IF;

  IF COALESCE(p_line_type, '') = 'component' THEN
    IF NOT public.mb_is_bom_input_product_type_allowed(v_effective_component_product_type) THEN
      RAISE EXCEPTION 'Component product_type is not eligible for BOM quantity logic. Component lines must use raw_material products. product_id=%, product_type=%',
        p_component_product_id, v_effective_component_product_type;
    END IF;

    IF p_component_product_id = v_owner_product_id THEN
      RAISE EXCEPTION 'Owner product cannot be used as a direct component in the same BOM version. bom_version_id=%, product_id=%',
        p_bom_version_id, p_component_product_id;
    END IF;
  ELSE
    IF NOT public.mb_is_bom_output_product_type_allowed(v_effective_component_product_type) THEN
      RAISE EXCEPTION 'BOM output line product_type must be manufactured. product_id=%, product_type=%, line_type=%',
        p_component_product_id, v_effective_component_product_type, p_line_type;
    END IF;

    IF p_component_product_id = v_owner_product_id THEN
      RAISE EXCEPTION 'Owner product is already the primary BOM output and cannot be repeated as a co/by product. bom_version_id=%, product_id=%',
        p_bom_version_id, p_component_product_id;
    END IF;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_validate_bom_substitute_context(p_bom_line_id uuid, p_company_id uuid, p_branch_id uuid, p_substitute_product_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_validate_bom_substitute_context(p_bom_line_id uuid, p_company_id uuid, p_branch_id uuid, p_substitute_product_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_line_company_id UUID;
  v_line_branch_id UUID;
  v_line_type TEXT;
  v_component_product_id UUID;
  v_substitute_company_id UUID;
  v_substitute_item_type TEXT;
  v_substitute_product_type TEXT;
  v_effective_substitute_product_type TEXT;
BEGIN
  SELECT
    l.company_id,
    l.branch_id,
    l.line_type,
    l.component_product_id
    INTO v_line_company_id,
         v_line_branch_id,
         v_line_type,
         v_component_product_id
    FROM public.manufacturing_bom_lines l
   WHERE l.id = p_bom_line_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'manufacturing_bom_lines record not found for substitute validation. bom_line_id=%', p_bom_line_id;
  END IF;

  IF v_line_company_id IS DISTINCT FROM p_company_id OR v_line_branch_id IS DISTINCT FROM p_branch_id THEN
    RAISE EXCEPTION 'BOM substitute company/branch must match parent BOM line. bom_line_id=%, substitute_company_id=%, substitute_branch_id=%',
      p_bom_line_id, p_company_id, p_branch_id;
  END IF;

  IF COALESCE(v_line_type, '') <> 'component' THEN
    RAISE EXCEPTION 'BOM substitutes are allowed only for component lines. bom_line_id=%, line_type=%', p_bom_line_id, v_line_type;
  END IF;

  SELECT company_id, item_type, product_type
    INTO v_substitute_company_id, v_substitute_item_type, v_substitute_product_type
    FROM public.products
   WHERE id = p_substitute_product_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Substitute product not found for BOM substitute validation. product_id=%', p_substitute_product_id;
  END IF;

  IF v_substitute_company_id IS DISTINCT FROM p_company_id THEN
    RAISE EXCEPTION 'Substitute product must belong to the same company as the BOM line. product_id=%, company_id=%',
      p_substitute_product_id, p_company_id;
  END IF;

  v_effective_substitute_product_type := COALESCE(NULLIF(BTRIM(v_substitute_product_type), ''), 'purchased');

  IF COALESCE(v_substitute_item_type, 'product') = 'service' THEN
    v_effective_substitute_product_type := 'service';
  END IF;

  IF NOT public.mb_is_bom_input_product_type_allowed(v_effective_substitute_product_type) THEN
    RAISE EXCEPTION 'Substitute product_type is not eligible for BOM quantity logic. Substitute products must use raw_material products. product_id=%, product_type=%',
      p_substitute_product_id, v_effective_substitute_product_type;
  END IF;

  IF p_substitute_product_id = v_component_product_id THEN
    RAISE EXCEPTION 'Substitute product cannot be the same as the primary component product. bom_line_id=%, product_id=%',
      p_bom_line_id, p_substitute_product_id;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mb_validate_bom_version_effective_window(p_bom_id uuid, p_version_id uuid, p_status text, p_effective_from timestamp with time zone, p_effective_to timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mb_validate_bom_version_effective_window(p_bom_id uuid, p_version_id uuid, p_status text, p_effective_from timestamp with time zone, p_effective_to timestamp with time zone)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_conflict_id UUID;
  v_conflict_version_no INTEGER;
BEGIN
  IF COALESCE(p_status, '') <> 'approved' THEN
    RETURN;
  END IF;

  IF p_effective_from IS NULL THEN
    RAISE EXCEPTION 'Approved BOM version requires effective_from. bom_id=%, version_id=%', p_bom_id, p_version_id;
  END IF;

  SELECT v.id, v.version_no
    INTO v_conflict_id, v_conflict_version_no
    FROM public.manufacturing_bom_versions v
   WHERE v.bom_id = p_bom_id
     AND (p_version_id IS NULL OR v.id <> p_version_id)
     AND v.status = 'approved'
     AND COALESCE(v.effective_to, 'infinity'::timestamptz) > p_effective_from
     AND COALESCE(p_effective_to, 'infinity'::timestamptz) > v.effective_from
   ORDER BY v.version_no
   LIMIT 1;

  IF v_conflict_id IS NOT NULL THEN
    RAISE EXCEPTION 'Approved BOM version effective window overlaps another approved version. bom_id=%, conflicting_version_id=%, conflicting_version_no=%',
      p_bom_id, v_conflict_id, v_conflict_version_no;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- member_branch_to_employee_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.member_branch_to_employee_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  if new.branch_id is distinct from coalesce(old.branch_id, null) and new.branch_id is not null then
    update public.employees
       set branch_id = new.branch_id
     where company_id = new.company_id
       and user_id = new.user_id
       and (branch_id is distinct from new.branch_id);
  end if;
  return new;
end;
$function$
;

-- ---------------------------------------------------------------
-- merge_duplicate_accounts_safe(p_company_id uuid, p_account_code text, p_keep_account_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.merge_duplicate_accounts_safe(p_company_id uuid, p_account_code text, p_keep_account_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(merged_count integer, journal_entry_id uuid, total_amount numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_keep_account_id UUID;
    v_merge_account_id UUID;
    v_balance DECIMAL(15, 2);
    v_journal_entry_id UUID;
    v_total_amount DECIMAL(15, 2) := 0;
    v_merged_count INTEGER := 0;
    v_account_type TEXT;
    v_normal_balance TEXT;
    v_account_name TEXT;
BEGIN
    -- تحديد الحساب الذي سيتم الاحتفاظ به
    IF p_keep_account_id IS NOT NULL THEN
        v_keep_account_id := p_keep_account_id;
    ELSE
        -- اختيار الحساب الأقدم أو الأكثر استخداماً
        SELECT id INTO v_keep_account_id
        FROM chart_of_accounts
        WHERE company_id = p_company_id
          AND account_code = p_account_code
          AND is_active = true
        ORDER BY created_at ASC, 
                 (SELECT COUNT(*) FROM journal_entry_lines WHERE account_id = chart_of_accounts.id) DESC
        LIMIT 1;
    END IF;
    
    IF v_keep_account_id IS NULL THEN
        RAISE EXCEPTION 'لم يتم العثور على حساب للكود: %', p_account_code;
    END IF;
    
    -- جلب معلومات الحساب المحتفظ به
    SELECT account_type, normal_balance, account_name
    INTO v_account_type, v_normal_balance, v_account_name
    FROM chart_of_accounts
    WHERE id = v_keep_account_id;
    
    -- دمج جميع الحسابات المكررة الأخرى
    FOR v_merge_account_id IN 
        SELECT id 
        FROM chart_of_accounts
        WHERE company_id = p_company_id
          AND account_code = p_account_code
          AND is_active = true
          AND id != v_keep_account_id
    LOOP
        -- حساب رصيد الحساب المراد دمجه
        v_balance := get_account_balance(p_company_id, v_merge_account_id);
        
        IF ABS(v_balance) > 0.01 THEN
            -- إنشاء قيد إعادة تصنيف لتحويل الرصيد
            INSERT INTO journal_entries (
                company_id,
                entry_date,
                description,
                reference_type,
                reference_id
            ) VALUES (
                p_company_id,
                CURRENT_DATE,
                format('إعادة تصنيف: دمج حساب %s إلى %s', 
                    (SELECT account_name FROM chart_of_accounts WHERE id = v_merge_account_id),
                    v_account_name),
                'coa_restructure',
                v_merge_account_id::TEXT
            )
            RETURNING id INTO v_journal_entry_id;
            
            -- إنشاء قيود الإعادة التصنيف
            IF v_normal_balance = 'debit' THEN
                IF v_balance > 0 THEN
                    -- رصيد مدين: خصم من الحساب الجديد وائتمان من القديم
                    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
                    VALUES (v_journal_entry_id, v_keep_account_id, ABS(v_balance), 0, 
                        format('نقل رصيد من %s', (SELECT account_name FROM chart_of_accounts WHERE id = v_merge_account_id)));
                    
                    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
                    VALUES (v_journal_entry_id, v_merge_account_id, 0, ABS(v_balance), 
                        format('نقل رصيد إلى %s', v_account_name));
                ELSE
                    -- رصيد دائن: عكس القيود
                    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
                    VALUES (v_journal_entry_id, v_keep_account_id, 0, ABS(v_balance), 
                        format('نقل رصيد من %s', (SELECT account_name FROM chart_of_accounts WHERE id = v_merge_account_id)));
                    
                    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
                    VALUES (v_journal_entry_id, v_merge_account_id, ABS(v_balance), 0, 
                        format('نقل رصيد إلى %s', v_account_name));
                END IF;
            ELSE
                -- نفس المنطق للحسابات الدائنة
                IF v_balance > 0 THEN
                    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
                    VALUES (v_journal_entry_id, v_keep_account_id, 0, ABS(v_balance), 
                        format('نقل رصيد من %s', (SELECT account_name FROM chart_of_accounts WHERE id = v_merge_account_id)));
                    
                    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
                    VALUES (v_journal_entry_id, v_merge_account_id, ABS(v_balance), 0, 
                        format('نقل رصيد إلى %s', v_account_name));
                ELSE
                    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
                    VALUES (v_journal_entry_id, v_keep_account_id, ABS(v_balance), 0, 
                        format('نقل رصيد من %s', (SELECT account_name FROM chart_of_accounts WHERE id = v_merge_account_id)));
                    
                    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
                    VALUES (v_journal_entry_id, v_merge_account_id, 0, ABS(v_balance), 
                        format('نقل رصيد إلى %s', v_account_name));
                END IF;
            END IF;
            
            -- تحديث جميع القيود المحاسبية لاستخدام الحساب الجديد
            UPDATE journal_entry_lines
            SET account_id = v_keep_account_id
            WHERE account_id = v_merge_account_id;
            
            -- تسجيل العملية
            INSERT INTO coa_restructure_log (
                company_id, operation_type, source_account_id, target_account_id,
                journal_entry_id, amount, description
            ) VALUES (
                p_company_id, 'merge', v_merge_account_id, v_keep_account_id,
                v_journal_entry_id, ABS(v_balance),
                format('دمج حساب %s إلى %s', 
                    (SELECT account_name FROM chart_of_accounts WHERE id = v_merge_account_id),
                    v_account_name)
            );
            
            v_total_amount := v_total_amount + ABS(v_balance);
            v_merged_count := v_merged_count + 1;
        ELSE
            -- لا يوجد رصيد: تحديث القيود فقط
            UPDATE journal_entry_lines
            SET account_id = v_keep_account_id
            WHERE account_id = v_merge_account_id;
            
            v_merged_count := v_merged_count + 1;
        END IF;
        
        -- تعطيل الحساب المدمج
        UPDATE chart_of_accounts
        SET is_active = false,
            account_code = account_code || '_MERGED_' || gen_random_uuid()::TEXT
        WHERE id = v_merge_account_id;
    END LOOP;
    
    RETURN QUERY SELECT v_merged_count, v_journal_entry_id, v_total_amount;
END;
$function$
;

-- ---------------------------------------------------------------
-- migrate_existing_purchases_to_fifo()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.migrate_existing_purchases_to_fifo()
 RETURNS TABLE(products_migrated integer, lots_created integer, total_value numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_products_count INTEGER := 0;
  v_lots_count INTEGER := 0;
  v_total_value NUMERIC := 0;
  v_purchase RECORD;
BEGIN
  -- حذف الدفعات الموجودة (إن وجدت)
  DELETE FROM fifo_lot_consumptions;
  DELETE FROM fifo_cost_lots;

  -- إنشاء دفعات من المشتريات الموجودة
  FOR v_purchase IN
    SELECT
      it.company_id,
      it.product_id,
      it.quantity_change,
      it.reference_id,
      it.branch_id,
      it.created_at::DATE as purchase_date,
      bi.unit_price,
      b.bill_date,
      p.name as product_name
    FROM inventory_transactions it
    JOIN bill_items bi ON bi.bill_id = it.reference_id AND bi.product_id = it.product_id
    JOIN bills b ON b.id = it.reference_id
    JOIN products p ON p.id = it.product_id
    WHERE it.transaction_type = 'purchase'
      AND p.item_type != 'service'
      AND it.quantity_change > 0
    ORDER BY b.bill_date ASC, it.created_at ASC
  LOOP
    -- إنشاء دفعة
    INSERT INTO fifo_cost_lots (
      company_id,
      product_id,
      lot_date,
      lot_type,
      reference_type,
      reference_id,
      original_quantity,
      remaining_quantity,
      unit_cost,
      notes,
      branch_id
    ) VALUES (
      v_purchase.company_id,
      v_purchase.product_id,
      v_purchase.bill_date,
      'purchase',
      'bill',
      v_purchase.reference_id,
      v_purchase.quantity_change,
      v_purchase.quantity_change, -- في البداية، كل الكمية متبقية
      v_purchase.unit_price,
      'Migrated from existing purchase',
      v_purchase.branch_id
    );

    v_lots_count := v_lots_count + 1;
    v_total_value := v_total_value + (v_purchase.quantity_change * v_purchase.unit_price);
  END LOOP;

  -- حساب عدد المنتجات
  SELECT COUNT(DISTINCT product_id) INTO v_products_count FROM fifo_cost_lots;

  products_migrated := v_products_count;
  lots_created := v_lots_count;
  total_value := v_total_value;

  RETURN NEXT;

  RAISE NOTICE 'Migration completed: % products, % lots, total value: %',
    v_products_count, v_lots_count, v_total_value;
END;
$function$
;

-- ---------------------------------------------------------------
-- mmia_sod_guard()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mmia_sod_guard()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.approved_by IS NOT NULL AND NEW.requested_by IS NOT NULL
     AND NEW.approved_by = NEW.requested_by THEN
    RAISE EXCEPTION 'SoD violation: مُعتَمِد طَلَب صَرف المَواد لا يَجوز أَن يَكون هو نَفسه مُقَدِّم الطَّلَب.'
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_assert_manufactured_owner_product(p_product_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_assert_manufactured_owner_product(p_product_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_product_type TEXT;
BEGIN
  SELECT product_type
    INTO v_product_type
    FROM public.products
   WHERE id = p_product_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'products record not found for production order owner validation. product_id=%', p_product_id;
  END IF;

  IF COALESCE(v_product_type, '') = '' THEN
    RAISE EXCEPTION 'Owner product must have product_type assigned before production order usage. product_id=%', p_product_id;
  END IF;

  IF v_product_type <> 'manufactured' THEN
    RAISE EXCEPTION 'Production order owner product must be manufactured. product_id=%, product_type=%', p_product_id, v_product_type;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_assert_order_editable(p_production_order_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_assert_order_editable(p_production_order_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_status TEXT;
BEGIN
  SELECT status
    INTO v_status
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'manufacturing_production_orders record not found. production_order_id=%', p_production_order_id;
  END IF;

  IF NOT public.mpo_is_order_editable(v_status) THEN
    RAISE EXCEPTION 'manufacturing_production_orders record is not editable in current status. production_order_id=%, status=%',
      p_production_order_id, v_status;
  END IF;
END;
$function$
;

