-- ---------------------------------------------------------------
-- mpo_assert_order_release_ready(p_production_order_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_assert_order_release_ready(p_production_order_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_order public.manufacturing_production_orders%ROWTYPE;
  v_operation_count INTEGER;
BEGIN
  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'manufacturing_production_orders record not found. production_order_id=%', p_production_order_id;
  END IF;

  IF NOT public.mpo_is_order_releasable(v_order.status) THEN
    RAISE EXCEPTION 'Only draft production orders can be released. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  END IF;

  IF v_order.issue_warehouse_id IS NULL OR v_order.receipt_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'Production order release requires issue and receipt warehouses. production_order_id=%', p_production_order_id;
  END IF;

  PERFORM public.mpo_validate_production_order_context(
    v_order.company_id,
    v_order.branch_id,
    v_order.product_id,
    v_order.bom_id,
    v_order.bom_version_id,
    v_order.routing_id,
    v_order.routing_version_id,
    v_order.issue_warehouse_id,
    v_order.receipt_warehouse_id
  );

  SELECT COUNT(*)
    INTO v_operation_count
    FROM public.manufacturing_production_order_operations
   WHERE production_order_id = p_production_order_id;

  IF COALESCE(v_operation_count, 0) <= 0 THEN
    RAISE EXCEPTION 'Production order release requires at least one operation snapshot. production_order_id=%', p_production_order_id;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_format_order_no(p_sequence_value bigint, p_reference_ts timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_format_order_no(p_sequence_value bigint, p_reference_ts timestamp with time zone)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  RETURN 'MPO-' ||
    TO_CHAR(TIMEZONE('UTC', p_reference_ts), 'YYYYMM') ||
    '-' ||
    CASE
      WHEN p_sequence_value < 1000000 THEN LPAD(p_sequence_value::TEXT, 6, '0')
      ELSE p_sequence_value::TEXT
    END;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_generate_order_no(p_reference_ts timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_generate_order_no(p_reference_ts timestamp with time zone DEFAULT now())
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_sequence_value BIGINT;
  v_reference_ts   TIMESTAMPTZ := COALESCE(p_reference_ts, NOW());
BEGIN
  v_sequence_value := nextval('public.manufacturing_production_order_number_seq');
  RETURN public.mpo_format_order_no(v_sequence_value, v_reference_ts);
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_guard_production_order_approval_transition()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_guard_production_order_approval_transition()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF OLD.approval_status IS DISTINCT FROM NEW.approval_status THEN
    IF NOT public.mpo_is_order_approval_transition_allowed(OLD.approval_status, NEW.approval_status) THEN
      RAISE EXCEPTION
        'انتقال غير مسموح لحالة اعتماد أمر الإنتاج. production_order_id=%, القديم=%, الجديد=%',
        OLD.id, OLD.approval_status, NEW.approval_status USING ERRCODE = 'P0001';
    END IF;
  END IF;

  -- Activation gate: status='released' requires approval_status='approved'.
  IF NEW.status = 'released' AND OLD.status = 'draft'
     AND COALESCE(NEW.approval_status, 'draft') <> 'approved' THEN
    RAISE EXCEPTION
      'لا يمكن إصدار أمر الإنتاج قبل اعتماده. أرسله للاعتماد أولاً وانتظر موافقة المالك / المدير العام.'
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_guard_production_order_header_editability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_guard_production_order_header_editability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.status = 'draft' THEN
    RETURN NEW;
  END IF;

  IF public.mpo_is_order_terminal(OLD.status) THEN
    IF OLD.product_receive_approval_status IS DISTINCT FROM NEW.product_receive_approval_status
       AND OLD.company_id IS NOT DISTINCT FROM NEW.company_id
       AND OLD.branch_id IS NOT DISTINCT FROM NEW.branch_id
       AND OLD.order_no IS NOT DISTINCT FROM NEW.order_no
       AND OLD.product_id IS NOT DISTINCT FROM NEW.product_id
       AND OLD.bom_id IS NOT DISTINCT FROM NEW.bom_id
       AND OLD.bom_version_id IS NOT DISTINCT FROM NEW.bom_version_id
       AND OLD.routing_id IS NOT DISTINCT FROM NEW.routing_id
       AND OLD.routing_version_id IS NOT DISTINCT FROM NEW.routing_version_id
       AND OLD.issue_warehouse_id IS NOT DISTINCT FROM NEW.issue_warehouse_id
       AND OLD.receipt_warehouse_id IS NOT DISTINCT FROM NEW.receipt_warehouse_id
       AND OLD.planned_quantity IS NOT DISTINCT FROM NEW.planned_quantity
       AND OLD.completed_quantity IS NOT DISTINCT FROM NEW.completed_quantity
       AND OLD.order_uom IS NOT DISTINCT FROM NEW.order_uom
       AND OLD.status IS NOT DISTINCT FROM NEW.status
       AND OLD.planned_start_at IS NOT DISTINCT FROM NEW.planned_start_at
       AND OLD.planned_end_at IS NOT DISTINCT FROM NEW.planned_end_at
       AND OLD.released_at IS NOT DISTINCT FROM NEW.released_at
       AND OLD.released_by IS NOT DISTINCT FROM NEW.released_by
       AND OLD.started_at IS NOT DISTINCT FROM NEW.started_at
       AND OLD.started_by IS NOT DISTINCT FROM NEW.started_by
       AND OLD.completed_at IS NOT DISTINCT FROM NEW.completed_at
       AND OLD.completed_by IS NOT DISTINCT FROM NEW.completed_by
       AND OLD.cancelled_at IS NOT DISTINCT FROM NEW.cancelled_at
       AND OLD.cancelled_by IS NOT DISTINCT FROM NEW.cancelled_by
       AND OLD.cancellation_reason IS NOT DISTINCT FROM NEW.cancellation_reason
       AND OLD.notes IS NOT DISTINCT FROM NEW.notes
       AND OLD.created_by IS NOT DISTINCT FROM NEW.created_by
       AND OLD.updated_by IS NOT DISTINCT FROM NEW.updated_by
       AND OLD.created_at IS NOT DISTINCT FROM NEW.created_at THEN
      RETURN NEW;
    END IF;

    RAISE EXCEPTION 'Terminal production orders cannot be updated. production_order_id=%, status=%', OLD.id, OLD.status;
  END IF;

  IF OLD.product_id IS DISTINCT FROM NEW.product_id
     OR OLD.bom_id IS DISTINCT FROM NEW.bom_id
     OR OLD.bom_version_id IS DISTINCT FROM NEW.bom_version_id
     OR OLD.routing_id IS DISTINCT FROM NEW.routing_id
     OR OLD.routing_version_id IS DISTINCT FROM NEW.routing_version_id
     OR OLD.issue_warehouse_id IS DISTINCT FROM NEW.issue_warehouse_id
     OR OLD.receipt_warehouse_id IS DISTINCT FROM NEW.receipt_warehouse_id
     OR OLD.planned_quantity IS DISTINCT FROM NEW.planned_quantity
     OR OLD.order_uom IS DISTINCT FROM NEW.order_uom
     OR OLD.planned_start_at IS DISTINCT FROM NEW.planned_start_at
     OR OLD.planned_end_at IS DISTINCT FROM NEW.planned_end_at
     OR OLD.notes IS DISTINCT FROM NEW.notes THEN
    RAISE EXCEPTION 'Production order header is frozen after leaving draft. production_order_id=%, status=%',
      OLD.id, OLD.status;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_guard_production_order_identity_immutability()
