$function$
;

-- ---------------------------------------------------------------
-- mpo_guard_production_order_operation_identity_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_guard_production_order_operation_identity_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
