-- ---------------------------------------------------------------
-- mpo_guard_production_order_operation_status_transition()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_guard_production_order_operation_status_transition()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NOT public.mpo_is_operation_transition_allowed(OLD.status, NEW.status) THEN
    RAISE EXCEPTION 'Invalid manufacturing_production_order_operations status transition. production_order_operation_id=%, old_status=%, new_status=%',
      OLD.id, OLD.status, NEW.status;
  END IF;

  IF OLD.status IS DISTINCT FROM NEW.status THEN
    PERFORM public.mpo_assert_order_execution_open(OLD.production_order_id);
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_guard_production_order_operation_write_scope()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_guard_production_order_operation_write_scope()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_order_status TEXT;
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM public.mpo_assert_order_editable(OLD.production_order_id);
    RETURN OLD;
  END IF;

  SELECT status
    INTO v_order_status
    FROM public.manufacturing_production_orders
   WHERE id = COALESCE(NEW.production_order_id, OLD.production_order_id);

  IF NOT FOUND THEN
    RAISE EXCEPTION 'manufacturing_production_orders record not found for production order operation write scope. production_order_id=%',
      COALESCE(NEW.production_order_id, OLD.production_order_id);
  END IF;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.mpo_assert_order_editable(NEW.production_order_id);
    RETURN NEW;
  END IF;

  IF v_order_status = 'draft' THEN
    IF OLD.status IS DISTINCT FROM NEW.status
       OR OLD.completed_quantity IS DISTINCT FROM NEW.completed_quantity
       OR OLD.actual_start_at IS DISTINCT FROM NEW.actual_start_at
       OR OLD.started_by IS DISTINCT FROM NEW.started_by
       OR OLD.actual_end_at IS DISTINCT FROM NEW.actual_end_at
       OR OLD.completed_by IS DISTINCT FROM NEW.completed_by
       OR OLD.last_progress_at IS DISTINCT FROM NEW.last_progress_at THEN
      RAISE EXCEPTION 'Production order operation execution fields cannot change while the parent order is draft. production_order_operation_id=%',
        OLD.id;
    END IF;

    RETURN NEW;
  END IF;

  IF public.mpo_is_order_execution_open(v_order_status) THEN
    PERFORM public.mpo_assert_order_execution_open(OLD.production_order_id);

    IF OLD.routing_version_id IS DISTINCT FROM NEW.routing_version_id
       OR OLD.source_routing_operation_id IS DISTINCT FROM NEW.source_routing_operation_id
       OR OLD.operation_no IS DISTINCT FROM NEW.operation_no
       OR OLD.operation_code IS DISTINCT FROM NEW.operation_code
       OR OLD.operation_name IS DISTINCT FROM NEW.operation_name
       OR OLD.work_center_id IS DISTINCT FROM NEW.work_center_id
       OR OLD.planned_quantity IS DISTINCT FROM NEW.planned_quantity
       OR OLD.setup_time_minutes IS DISTINCT FROM NEW.setup_time_minutes
       OR OLD.run_time_minutes_per_unit IS DISTINCT FROM NEW.run_time_minutes_per_unit
       OR OLD.queue_time_minutes IS DISTINCT FROM NEW.queue_time_minutes
       OR OLD.move_time_minutes IS DISTINCT FROM NEW.move_time_minutes
       OR OLD.labor_time_minutes IS DISTINCT FROM NEW.labor_time_minutes
       OR OLD.machine_time_minutes IS DISTINCT FROM NEW.machine_time_minutes
       OR OLD.quality_checkpoint_required IS DISTINCT FROM NEW.quality_checkpoint_required
       OR OLD.instructions IS DISTINCT FROM NEW.instructions
       OR OLD.planned_start_at IS DISTINCT FROM NEW.planned_start_at
       OR OLD.planned_end_at IS DISTINCT FROM NEW.planned_end_at THEN
      RAISE EXCEPTION 'Production order operation snapshot structure is frozen after release. production_order_operation_id=%, order_status=%',
        OLD.id, v_order_status;
    END IF;

    RETURN NEW;
  END IF;

  RAISE EXCEPTION 'Production order operations cannot be updated when the parent order is terminal. production_order_operation_id=%, order_status=%',
    OLD.id, v_order_status;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_guard_production_order_status_transition()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_guard_production_order_status_transition()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NOT public.mpo_is_order_transition_allowed(OLD.status, NEW.status) THEN
    RAISE EXCEPTION 'Invalid manufacturing_production_orders status transition. production_order_id=%, old_status=%, new_status=%',
      OLD.id, OLD.status, NEW.status;
  END IF;

  IF OLD.status = 'draft' AND NEW.status = 'released' THEN
    IF OLD.product_id IS DISTINCT FROM NEW.product_id
       OR OLD.bom_id IS DISTINCT FROM NEW.bom_id
       OR OLD.bom_version_id IS DISTINCT FROM NEW.bom_version_id
       OR OLD.routing_id IS DISTINCT FROM NEW.routing_id
       OR OLD.routing_version_id IS DISTINCT FROM NEW.routing_version_id
       OR OLD.issue_warehouse_id IS DISTINCT FROM NEW.issue_warehouse_id
       OR OLD.receipt_warehouse_id IS DISTINCT FROM NEW.receipt_warehouse_id THEN
      RAISE EXCEPTION 'Production order release must use already-persisted header/source values. Save order changes before releasing. production_order_id=%', OLD.id;
    END IF;

    PERFORM public.mpo_assert_order_release_ready(OLD.id);
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_operation_completed(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_operation_completed(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'completed';
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_operation_in_progress(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_operation_in_progress(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'in_progress';
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_operation_open(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_operation_open(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('pending', 'ready', 'in_progress');
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_operation_ready(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_operation_ready(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'ready';
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_operation_terminal(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_operation_terminal(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('completed', 'cancelled');
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_operation_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_operation_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_old_status, '')
    WHEN 'pending' THEN COALESCE(p_new_status, '') IN ('pending', 'ready', 'cancelled')
    WHEN 'ready' THEN COALESCE(p_new_status, '') IN ('ready', 'in_progress', 'completed', 'cancelled')
    WHEN 'in_progress' THEN COALESCE(p_new_status, '') IN ('in_progress', 'completed')
    WHEN 'completed' THEN COALESCE(p_new_status, '') IN ('completed')
    WHEN 'cancelled' THEN COALESCE(p_new_status, '') IN ('cancelled')
    ELSE false
  END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_order_approval_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_order_approval_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_old_status, '')
    WHEN 'draft'             THEN COALESCE(p_new_status, '') IN ('draft', 'pending_approval')
    WHEN 'pending_approval'  THEN COALESCE(p_new_status, '') IN ('pending_approval', 'approved', 'rejected')
    WHEN 'approved'          THEN COALESCE(p_new_status, '') IN ('approved')
    WHEN 'rejected'          THEN COALESCE(p_new_status, '') IN ('rejected', 'pending_approval')
    ELSE false
  END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_order_editable(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_order_editable(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'draft';
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_order_execution_open(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_order_execution_open(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('released', 'in_progress');
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_order_releasable(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_order_releasable(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'draft';
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_order_terminal(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_order_terminal(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('completed', 'cancelled');
$function$
;

-- ---------------------------------------------------------------
-- mpo_is_order_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_is_order_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_old_status, '')
    WHEN 'draft' THEN COALESCE(p_new_status, '') IN ('draft', 'released', 'cancelled')
    WHEN 'released' THEN COALESCE(p_new_status, '') IN ('released', 'in_progress', 'cancelled')
    WHEN 'in_progress' THEN COALESCE(p_new_status, '') IN ('in_progress', 'completed')
    WHEN 'completed' THEN COALESCE(p_new_status, '') IN ('completed')
    WHEN 'cancelled' THEN COALESCE(p_new_status, '') IN ('cancelled')
    ELSE false
  END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_set_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpo_trg_validate_production_order_context()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpo_trg_validate_production_order_context()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.mpo_validate_production_order_context(
    NEW.company_id,
    NEW.branch_id,
    NEW.product_id,
    NEW.bom_id,
    NEW.bom_version_id,
    NEW.routing_id,
    NEW.routing_version_id,
    NEW.issue_warehouse_id,
    NEW.receipt_warehouse_id
  );

  RETURN NEW;
END;
$function$
;

