;

-- ---------------------------------------------------------------
-- mpoe_assert_material_requirements_snapshot_absent(p_production_order_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpoe_assert_material_requirements_snapshot_absent(p_production_order_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_requirement_count INTEGER;
BEGIN
  SELECT COUNT(*)
    INTO v_requirement_count
    FROM public.production_order_material_requirements
   WHERE production_order_id = p_production_order_id;

  IF COALESCE(v_requirement_count, 0) > 0 THEN
    RAISE EXCEPTION 'Production order material requirements snapshot already exists and cannot be recreated in v1. production_order_id=%',
      p_production_order_id;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpoe_assert_material_requirements_snapshot_exists(p_production_order_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpoe_assert_material_requirements_snapshot_exists(p_production_order_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_requirement_count INTEGER;
BEGIN
  SELECT COUNT(*)
    INTO v_requirement_count
    FROM public.production_order_material_requirements
   WHERE production_order_id = p_production_order_id;

  IF COALESCE(v_requirement_count, 0) <= 0 THEN
    RAISE EXCEPTION 'Production order requires a material requirements snapshot before inventory execution. production_order_id=%',
      p_production_order_id;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpoe_assert_material_requirements_snapshot_frozen(p_production_order_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpoe_assert_material_requirements_snapshot_frozen(p_production_order_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_status TEXT;
BEGIN
  SELECT status
    INTO v_status
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'manufacturing_production_orders record not found for material requirements snapshot validation. production_order_id=%',
      p_production_order_id;
  END IF;

  IF v_status = 'draft' THEN
    RAISE EXCEPTION 'Draft production orders do not have a frozen material requirements snapshot. production_order_id=%',
      p_production_order_id;
  END IF;

  PERFORM public.mpoe_assert_material_requirements_snapshot_exists(p_production_order_id);
END;
$function$
;

