-- ---------------------------------------------------------------
-- mpoe_compute_open_reservation_status(p_requested_qty numeric, p_reserved_qty numeric, p_consumed_qty numeric, p_released_qty numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpoe_compute_open_reservation_status(p_requested_qty numeric, p_reserved_qty numeric, p_consumed_qty numeric, p_released_qty numeric)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN COALESCE(p_requested_qty, 0) <= 0 THEN 'active'
    WHEN COALESCE(p_consumed_qty, 0) >= COALESCE(p_requested_qty, 0)
      AND COALESCE(p_released_qty, 0) = 0 THEN 'consumed'
    WHEN COALESCE(p_consumed_qty, 0) > 0 THEN 'partially_consumed'
    WHEN COALESCE(p_reserved_qty, 0) >= COALESCE(p_requested_qty, 0) THEN 'fully_reserved'
    WHEN COALESCE(p_reserved_qty, 0) > 0 THEN 'partially_reserved'
    ELSE 'active'
  END;
$function$
;

-- ---------------------------------------------------------------
-- mpoe_guard_issue_event_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpoe_guard_issue_event_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.mpoe_assert_issue_event_mutation_forbidden(
    OLD.id,
    TG_OP
  );

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpoe_guard_issue_event_insert()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpoe_guard_issue_event_insert()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.mpoe_assert_issue_execution_ready(NEW.production_order_id);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mpoe_guard_issue_line_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mpoe_guard_issue_line_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.mpoe_assert_issue_line_mutation_forbidden(
    OLD.id,
    TG_OP
  );

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  RETURN NEW;
END;
$function$
;

