-- ---------------------------------------------------------------
-- mr_guard_routing_identity_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_guard_routing_identity_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.company_id IS DISTINCT FROM NEW.company_id
     OR OLD.branch_id IS DISTINCT FROM NEW.branch_id
     OR OLD.product_id IS DISTINCT FROM NEW.product_id
     OR OLD.routing_usage IS DISTINCT FROM NEW.routing_usage THEN
    RAISE EXCEPTION 'manufacturing_routings identity fields are immutable after creation. routing_id=%', OLD.id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mr_guard_routing_operation_identity_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_guard_routing_operation_identity_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.company_id IS DISTINCT FROM NEW.company_id
     OR OLD.branch_id IS DISTINCT FROM NEW.branch_id
     OR OLD.routing_version_id IS DISTINCT FROM NEW.routing_version_id THEN
    RAISE EXCEPTION 'manufacturing_routing_operations identity fields are immutable after creation. routing_operation_id=%', OLD.id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mr_guard_routing_operation_parent_editability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_guard_routing_operation_parent_editability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM public.mr_assert_routing_version_structure_editable(OLD.routing_version_id);
    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    PERFORM public.mr_assert_routing_version_structure_editable(OLD.routing_version_id);

    IF OLD.routing_version_id IS DISTINCT FROM NEW.routing_version_id THEN
      PERFORM public.mr_assert_routing_version_structure_editable(NEW.routing_version_id);
    END IF;

    RETURN NEW;
  END IF;

  PERFORM public.mr_assert_routing_version_structure_editable(NEW.routing_version_id);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mr_guard_routing_version_approval_transition()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_guard_routing_version_approval_transition()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF OLD.approval_status IS DISTINCT FROM NEW.approval_status THEN
    IF NOT public.mr_is_routing_version_approval_transition_allowed(OLD.approval_status, NEW.approval_status) THEN
      RAISE EXCEPTION
        'انتقال غير مسموح لحالة اعتماد مسار التصنيع. routing_version_id=%, القديم=%, الجديد=%',
        OLD.id, OLD.approval_status, NEW.approval_status USING ERRCODE = 'P0001';
    END IF;
  END IF;

  -- Activation gate: cannot move status → 'active' unless approved.
  IF NEW.status = 'active' AND OLD.status <> 'active'
     AND COALESCE(NEW.approval_status, 'draft') <> 'approved' THEN
    RAISE EXCEPTION
      'لا يمكن تفعيل نسخة مسار التصنيع قبل اعتمادها. أرسلها للاعتماد أولاً وانتظر موافقة المالك / المدير العام.'
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mr_guard_routing_version_update()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_guard_routing_version_update()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_header_changed BOOLEAN;
BEGIN
  IF OLD.company_id IS DISTINCT FROM NEW.company_id
     OR OLD.branch_id IS DISTINCT FROM NEW.branch_id
     OR OLD.routing_id IS DISTINCT FROM NEW.routing_id
     OR OLD.version_no IS DISTINCT FROM NEW.version_no THEN
    RAISE EXCEPTION 'manufacturing_routing_versions identity fields are immutable after creation. routing_version_id=%', OLD.id;
  END IF;

  IF NOT public.mr_is_routing_version_transition_allowed(OLD.status, NEW.status) THEN
    RAISE EXCEPTION 'Invalid manufacturing_routing_versions status transition. routing_version_id=%, old_status=%, new_status=%',
      OLD.id, OLD.status, NEW.status;
  END IF;

  v_header_changed :=
       OLD.effective_from IS DISTINCT FROM NEW.effective_from
    OR OLD.effective_to IS DISTINCT FROM NEW.effective_to
    OR OLD.change_summary IS DISTINCT FROM NEW.change_summary
    OR OLD.notes IS DISTINCT FROM NEW.notes;

  IF OLD.status = 'archived' THEN
    RAISE EXCEPTION 'Archived routing versions cannot be updated. routing_version_id=%', OLD.id;
  END IF;

  IF public.mr_is_routing_version_locked(OLD.status) AND v_header_changed THEN
    RAISE EXCEPTION 'Locked routing versions cannot modify header fields. routing_version_id=%, status=%',
      OLD.id, OLD.status;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mr_is_routing_version_approval_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_is_routing_version_approval_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_old_status, '')
    WHEN 'draft'             THEN COALESCE(p_new_status, '') IN ('draft', 'pending_approval')
    WHEN 'pending_approval'  THEN COALESCE(p_new_status, '') IN ('pending_approval', 'approved', 'rejected')
    WHEN 'approved'          THEN COALESCE(p_new_status, '') IN ('approved')
    WHEN 'rejected'          THEN COALESCE(p_new_status, '') IN ('rejected', 'pending_approval')
    ELSE false
  END;
$function$
;

-- ---------------------------------------------------------------
-- mr_is_routing_version_locked(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_is_routing_version_locked(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('active', 'inactive', 'archived');
$function$
;

-- ---------------------------------------------------------------
-- mr_is_routing_version_operational(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_is_routing_version_operational(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'active';
$function$
;

-- ---------------------------------------------------------------
-- mr_is_routing_version_structure_editable(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_is_routing_version_structure_editable(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'draft';
$function$
;

-- ---------------------------------------------------------------
-- mr_is_routing_version_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mr_is_routing_version_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_old_status, '')
    WHEN 'draft' THEN COALESCE(p_new_status, '') IN ('draft', 'active', 'archived')
    WHEN 'active' THEN COALESCE(p_new_status, '') IN ('active', 'inactive', 'archived')
    WHEN 'inactive' THEN COALESCE(p_new_status, '') IN ('inactive', 'active', 'archived')
    WHEN 'archived' THEN COALESCE(p_new_status, '') IN ('archived')
    ELSE false
  END;
$function$
;

