-- ---------------------------------------------------------------
-- mrp_assert_warehouse_resolution_present(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_context text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_assert_warehouse_resolution_present(p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_context text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_warehouse_company_id UUID;
  v_warehouse_branch_id UUID;
BEGIN
  IF p_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'MRP rows must be warehouse-resolved. context=%', p_context;
  END IF;

  SELECT company_id, branch_id
    INTO v_warehouse_company_id, v_warehouse_branch_id
    FROM public.warehouses
   WHERE id = p_warehouse_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'warehouses record not found for MRP validation. warehouse_id=%, context=%',
      p_warehouse_id, p_context;
  END IF;

  IF v_warehouse_company_id IS DISTINCT FROM p_company_id OR v_warehouse_branch_id IS DISTINCT FROM p_branch_id THEN
    RAISE EXCEPTION 'MRP warehouse must belong to the same company/branch. warehouse_id=%, company_id=%, branch_id=%, context=%',
      p_warehouse_id, p_company_id, p_branch_id, p_context;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_guard_run_identity_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_guard_run_identity_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.company_id IS DISTINCT FROM NEW.company_id
     OR OLD.branch_id IS DISTINCT FROM NEW.branch_id
     OR OLD.run_scope IS DISTINCT FROM NEW.run_scope
     OR OLD.warehouse_id IS DISTINCT FROM NEW.warehouse_id
     OR OLD.run_mode IS DISTINCT FROM NEW.run_mode
     OR OLD.as_of_at IS DISTINCT FROM NEW.as_of_at
     OR OLD.started_at IS DISTINCT FROM NEW.started_at
     OR OLD.created_by IS DISTINCT FROM NEW.created_by
     OR OLD.created_at IS DISTINCT FROM NEW.created_at THEN
    RAISE EXCEPTION 'mrp_runs identity and scope fields are immutable after creation. run_id=%', OLD.id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_guard_run_row_write_scope()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_guard_run_row_write_scope()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_run_id UUID;
BEGIN
  v_run_id := COALESCE(NEW.run_id, OLD.run_id);

  PERFORM public.mrp_assert_run_running(v_run_id);

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_guard_run_status_transition()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_guard_run_status_transition()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NOT public.mrp_is_run_transition_allowed(OLD.status, NEW.status) THEN
    RAISE EXCEPTION 'Invalid mrp_runs status transition. run_id=%, old_status=%, new_status=%',
      OLD.id, OLD.status, NEW.status;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_guard_run_terminal_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_guard_run_terminal_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF public.mrp_is_run_terminal(OLD.status) THEN
    RAISE EXCEPTION 'Terminal mrp_runs records cannot be updated. run_id=%, status=%',
      OLD.id, OLD.status;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_production_demand_eligible_product_type(p_product_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_production_demand_eligible_product_type(p_product_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT public.mrp_is_supported_product_type(p_product_type);
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_reorder_demand_eligible_product_type(p_product_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_reorder_demand_eligible_product_type(p_product_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_product_type, '') IN ('raw_material', 'purchased');
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_run_running(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_run_running(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'running';
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_run_terminal(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_run_terminal(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') IN ('completed', 'failed');
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_run_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_run_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_old_status, '')
    WHEN 'running' THEN COALESCE(p_new_status, '') IN ('running', 'completed', 'failed')
    WHEN 'completed' THEN COALESCE(p_new_status, '') IN ('completed')
    WHEN 'failed' THEN COALESCE(p_new_status, '') IN ('failed')
    ELSE false
  END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_sales_demand_eligible_product_type(p_product_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_sales_demand_eligible_product_type(p_product_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT public.mrp_is_supported_product_type(p_product_type);
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_suggestion_type_eligible(p_product_type text, p_suggestion_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_suggestion_type_eligible(p_product_type text, p_suggestion_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_suggestion_type, '')
    WHEN 'production' THEN COALESCE(p_product_type, '') = 'manufactured'
    WHEN 'purchase' THEN COALESCE(p_product_type, '') IN ('raw_material', 'purchased')
    ELSE false
  END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_supply_source_eligible(p_product_type text, p_supply_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_supply_source_eligible(p_product_type text, p_supply_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE COALESCE(p_supply_type, '')
    WHEN 'free_stock' THEN public.mrp_is_supported_product_type(p_product_type)
    WHEN 'purchase_incoming' THEN COALESCE(p_product_type, '') IN ('raw_material', 'purchased')
    WHEN 'production_incoming' THEN COALESCE(p_product_type, '') = 'manufactured'
    ELSE false
  END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_is_supported_product_type(p_product_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_is_supported_product_type(p_product_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_product_type, '') IN ('manufactured', 'raw_material', 'purchased');
$function$
;

