-- ---------------------------------------------------------------
-- mrp_validate_demand_row_context(p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text, p_demand_type text, p_source_type text, p_source_id uuid, p_source_line_id uuid, p_original_qty numeric, p_covered_qty numeric, p_uncovered_qty numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_demand_row_context(p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text, p_demand_type text, p_source_type text, p_source_id uuid, p_source_line_id uuid, p_original_qty numeric, p_covered_qty numeric, p_uncovered_qty numeric)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_requirement_company_id UUID;
  v_requirement_branch_id UUID;
  v_requirement_order_id UUID;
  v_requirement_warehouse_id UUID;
  v_requirement_product_id UUID;
BEGIN
  PERFORM public.mrp_assert_run_running(p_run_id);

  PERFORM public.mrp_validate_run_row_context(
    p_run_id,
    p_company_id,
    p_branch_id,
    p_warehouse_id,
    'mrp_demand_rows'
  );

  PERFORM public.mrp_validate_product_snapshot(
    p_product_id,
    p_product_type,
    'mrp_demand_rows'
  );

  PERFORM public.mrp_validate_source_pointer(
    p_source_type,
    p_source_id,
    'mrp_demand_rows'
  );

  IF p_original_qty IS NULL OR p_original_qty <= 0 THEN
    RAISE EXCEPTION 'MRP demand original_qty must be > 0. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_covered_qty IS NULL OR p_covered_qty < 0 OR p_uncovered_qty IS NULL OR p_uncovered_qty < 0 THEN
    RAISE EXCEPTION 'MRP demand covered/uncovered quantities must be non-negative. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_covered_qty > p_original_qty OR p_uncovered_qty > p_original_qty THEN
    RAISE EXCEPTION 'MRP demand covered/uncovered quantities cannot exceed original_qty. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_covered_qty + p_uncovered_qty IS DISTINCT FROM p_original_qty THEN
    RAISE EXCEPTION 'MRP demand covered_qty + uncovered_qty must equal original_qty. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  CASE COALESCE(p_demand_type, '')
    WHEN 'sales' THEN
      PERFORM public.mrp_assert_sales_demand_eligible(p_product_id, p_product_type);

      IF p_source_type <> 'sales_order' THEN
        RAISE EXCEPTION 'Sales demand rows must use source_type=sales_order. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

      IF p_source_line_id IS NULL THEN
        RAISE EXCEPTION 'Sales demand rows require source_line_id. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

    WHEN 'production_component' THEN
      PERFORM public.mrp_assert_production_demand_eligible(p_product_id, p_product_type);

      IF p_source_type <> 'production_order' THEN
        RAISE EXCEPTION 'Production component demand rows must use source_type=production_order. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

      IF p_source_line_id IS NULL THEN
        RAISE EXCEPTION 'Production component demand rows require source_line_id. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

      SELECT company_id, branch_id, production_order_id, warehouse_id, product_id
        INTO v_requirement_company_id, v_requirement_branch_id, v_requirement_order_id, v_requirement_warehouse_id, v_requirement_product_id
        FROM public.production_order_material_requirements
       WHERE id = p_source_line_id;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'production_order_material_requirements record not found for MRP production demand validation. source_line_id=%',
          p_source_line_id;
      END IF;

      IF v_requirement_company_id IS DISTINCT FROM p_company_id
         OR v_requirement_branch_id IS DISTINCT FROM p_branch_id
         OR v_requirement_order_id IS DISTINCT FROM p_source_id
         OR v_requirement_warehouse_id IS DISTINCT FROM p_warehouse_id
         OR v_requirement_product_id IS DISTINCT FROM p_product_id THEN
        RAISE EXCEPTION 'MRP production demand row must match the linked material requirement context. source_id=%, source_line_id=%, product_id=%, run_id=%',
          p_source_id, p_source_line_id, p_product_id, p_run_id;
      END IF;

    WHEN 'reorder' THEN
      PERFORM public.mrp_assert_reorder_demand_eligible(p_product_id, p_product_type);

      IF p_source_type <> 'reorder_policy' THEN
        RAISE EXCEPTION 'Reorder demand rows must use source_type=reorder_policy. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

      IF p_source_id IS DISTINCT FROM p_product_id THEN
        RAISE EXCEPTION 'Reorder demand rows must use product_id as source_id. product_id=%, source_id=%, run_id=%',
          p_product_id, p_source_id, p_run_id;
      END IF;

      IF p_source_line_id IS NOT NULL THEN
        RAISE EXCEPTION 'Reorder demand rows must not use source_line_id. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

    ELSE
      RAISE EXCEPTION 'Unsupported MRP demand_type. demand_type=%', p_demand_type;
  END CASE;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_validate_net_row_context(p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text, p_total_demand_qty numeric, p_sales_demand_qty numeric, p_production_demand_qty numeric, p_reorder_demand_qty numeric, p_free_stock_qty numeric, p_incoming_purchase_qty numeric, p_incoming_production_qty numeric, p_total_supply_qty numeric, p_reorder_level_qty numeric, p_projected_after_committed_qty numeric, p_net_required_qty numeric, p_suggested_action text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_net_row_context(p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text, p_total_demand_qty numeric, p_sales_demand_qty numeric, p_production_demand_qty numeric, p_reorder_demand_qty numeric, p_free_stock_qty numeric, p_incoming_purchase_qty numeric, p_incoming_production_qty numeric, p_total_supply_qty numeric, p_reorder_level_qty numeric, p_projected_after_committed_qty numeric, p_net_required_qty numeric, p_suggested_action text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.mrp_assert_run_running(p_run_id);

  PERFORM public.mrp_validate_run_row_context(
    p_run_id,
    p_company_id,
    p_branch_id,
    p_warehouse_id,
    'mrp_net_rows'
  );

  PERFORM public.mrp_validate_product_snapshot(
    p_product_id,
    p_product_type,
    'mrp_net_rows'
  );

  IF p_total_demand_qty IS NULL OR p_total_demand_qty < 0
     OR p_sales_demand_qty IS NULL OR p_sales_demand_qty < 0
     OR p_production_demand_qty IS NULL OR p_production_demand_qty < 0
     OR p_reorder_demand_qty IS NULL OR p_reorder_demand_qty < 0 THEN
    RAISE EXCEPTION 'MRP net demand quantities must be non-negative. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_free_stock_qty IS NULL OR p_free_stock_qty < 0
     OR p_incoming_purchase_qty IS NULL OR p_incoming_purchase_qty < 0
     OR p_incoming_production_qty IS NULL OR p_incoming_production_qty < 0
     OR p_total_supply_qty IS NULL OR p_total_supply_qty < 0
     OR p_reorder_level_qty IS NULL OR p_reorder_level_qty < 0
     OR p_net_required_qty IS NULL OR p_net_required_qty < 0 THEN
    RAISE EXCEPTION 'MRP net supply/reorder/net-required quantities must be non-negative. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_projected_after_committed_qty IS NULL THEN
    RAISE EXCEPTION 'MRP projected_after_committed_qty is required. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_total_demand_qty IS DISTINCT FROM (p_sales_demand_qty + p_production_demand_qty + p_reorder_demand_qty) THEN
    RAISE EXCEPTION 'MRP total_demand_qty must equal sales + production + reorder. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_total_supply_qty IS DISTINCT FROM (p_free_stock_qty + p_incoming_purchase_qty + p_incoming_production_qty) THEN
    RAISE EXCEPTION 'MRP total_supply_qty must equal free_stock + incoming_purchase + incoming_production. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_reorder_demand_qty > 0 THEN
    PERFORM public.mrp_assert_reorder_demand_eligible(
      p_product_id,
      p_product_type
    );
  END IF;

  IF p_suggested_action IS NOT NULL AND p_suggested_action <> 'none' THEN
    PERFORM public.mrp_assert_suggestion_eligibility(
      p_product_id,
      p_product_type,
      p_suggested_action
    );
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_validate_net_row_link(p_net_row_id uuid, p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_net_row_link(p_net_row_id uuid, p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_run_id UUID;
  v_company_id UUID;
  v_branch_id UUID;
  v_warehouse_id UUID;
  v_product_id UUID;
  v_product_type TEXT;
BEGIN
  SELECT run_id, company_id, branch_id, warehouse_id, product_id, product_type
    INTO v_run_id, v_company_id, v_branch_id, v_warehouse_id, v_product_id, v_product_type
    FROM public.mrp_net_rows
   WHERE id = p_net_row_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'mrp_net_rows record not found for suggestion validation. net_row_id=%',
      p_net_row_id;
  END IF;

  IF v_run_id IS DISTINCT FROM p_run_id
     OR v_company_id IS DISTINCT FROM p_company_id
     OR v_branch_id IS DISTINCT FROM p_branch_id
     OR v_warehouse_id IS DISTINCT FROM p_warehouse_id
     OR v_product_id IS DISTINCT FROM p_product_id
     OR v_product_type IS DISTINCT FROM p_product_type THEN
    RAISE EXCEPTION 'MRP suggestion must match the linked net row grain and product snapshot. net_row_id=%, run_id=%, company_id=%, branch_id=%, warehouse_id=%, product_id=%',
      p_net_row_id, p_run_id, p_company_id, p_branch_id, p_warehouse_id, p_product_id;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_validate_product_snapshot(p_product_id uuid, p_product_type text, p_context text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_product_snapshot(p_product_id uuid, p_product_type text, p_context text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_current_product_type TEXT;
BEGIN
  IF NULLIF(BTRIM(COALESCE(p_product_type, '')), '') IS NULL THEN
    RAISE EXCEPTION 'MRP product_type snapshot is required. product_id=%, context=%',
      p_product_id, p_context;
  END IF;

  SELECT product_type
    INTO v_current_product_type
    FROM public.products
   WHERE id = p_product_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'products record not found for MRP validation. product_id=%, context=%',
      p_product_id, p_context;
  END IF;

  IF NOT public.mrp_is_supported_product_type(v_current_product_type) THEN
    RAISE EXCEPTION 'MRP only supports manufactured/raw_material/purchased products. product_id=%, product_type=%, context=%',
      p_product_id, v_current_product_type, p_context;
  END IF;

  IF p_product_type IS DISTINCT FROM v_current_product_type THEN
    RAISE EXCEPTION 'MRP product_type snapshot must match products.product_type. product_id=%, snapshot_product_type=%, current_product_type=%, context=%',
      p_product_id, p_product_type, v_current_product_type, p_context;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_validate_run_row_context(p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_context text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_run_row_context(p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_context text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_run_company_id UUID;
  v_run_branch_id UUID;
  v_run_scope TEXT;
  v_run_warehouse_id UUID;
BEGIN
  SELECT company_id, branch_id, run_scope, warehouse_id
    INTO v_run_company_id, v_run_branch_id, v_run_scope, v_run_warehouse_id
    FROM public.mrp_runs
   WHERE id = p_run_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'mrp_runs record not found for row validation. run_id=%, context=%', p_run_id, p_context;
  END IF;

  IF v_run_company_id IS DISTINCT FROM p_company_id OR v_run_branch_id IS DISTINCT FROM p_branch_id THEN
    RAISE EXCEPTION 'MRP row company/branch must match the parent run. run_id=%, company_id=%, branch_id=%, context=%',
      p_run_id, p_company_id, p_branch_id, p_context;
  END IF;

  PERFORM public.mrp_assert_warehouse_resolution_present(
    p_company_id,
    p_branch_id,
    p_warehouse_id,
    p_context
  );

  IF COALESCE(v_run_scope, '') = 'warehouse_filtered' AND v_run_warehouse_id IS DISTINCT FROM p_warehouse_id THEN
    RAISE EXCEPTION 'MRP row warehouse_id must match the warehouse-filtered run scope. run_id=%, run_warehouse_id=%, row_warehouse_id=%, context=%',
      p_run_id, v_run_warehouse_id, p_warehouse_id, p_context;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_validate_run_scope_context(p_company_id uuid, p_branch_id uuid, p_run_scope text, p_warehouse_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_run_scope_context(p_company_id uuid, p_branch_id uuid, p_run_scope text, p_warehouse_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  CASE COALESCE(p_run_scope, '')
    WHEN 'branch' THEN
      IF p_warehouse_id IS NOT NULL THEN
        RAISE EXCEPTION 'MRP branch-scoped runs must not have warehouse_id. company_id=%, branch_id=%',
          p_company_id, p_branch_id;
      END IF;

    WHEN 'warehouse_filtered' THEN
      PERFORM public.mrp_assert_warehouse_resolution_present(
        p_company_id,
        p_branch_id,
        p_warehouse_id,
        'mrp_runs'
      );

    ELSE
      RAISE EXCEPTION 'Unsupported MRP run_scope. run_scope=%', p_run_scope;
  END CASE;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_validate_source_pointer(p_source_type text, p_source_id uuid, p_context text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_source_pointer(p_source_type text, p_source_id uuid, p_context text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NULLIF(BTRIM(COALESCE(p_source_type, '')), '') IS NULL THEN
    RAISE EXCEPTION 'MRP source_type is required. context=%', p_context;
  END IF;

  IF p_source_id IS NULL THEN
    RAISE EXCEPTION 'MRP source_id is required. context=%', p_context;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_validate_suggestion_context(p_run_id uuid, p_net_row_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text, p_suggestion_type text, p_suggested_qty numeric, p_reason_code text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_suggestion_context(p_run_id uuid, p_net_row_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text, p_suggestion_type text, p_suggested_qty numeric, p_reason_code text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_net_required_qty NUMERIC;
  v_net_suggested_action TEXT;
BEGIN
  PERFORM public.mrp_assert_run_running(p_run_id);

  PERFORM public.mrp_validate_run_row_context(
    p_run_id,
    p_company_id,
    p_branch_id,
    p_warehouse_id,
    'mrp_suggestions'
  );

  PERFORM public.mrp_validate_product_snapshot(
    p_product_id,
    p_product_type,
    'mrp_suggestions'
  );

  PERFORM public.mrp_validate_net_row_link(
    p_net_row_id,
    p_run_id,
    p_company_id,
    p_branch_id,
    p_warehouse_id,
    p_product_id,
    p_product_type
  );

  PERFORM public.mrp_assert_suggestion_eligibility(
    p_product_id,
    p_product_type,
    p_suggestion_type
  );

  IF p_suggested_qty IS NULL OR p_suggested_qty <= 0 THEN
    RAISE EXCEPTION 'MRP suggested_qty must be > 0. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF COALESCE(p_reason_code, '') NOT IN ('sales_shortage', 'production_shortage', 'reorder_shortage', 'mixed') THEN
    RAISE EXCEPTION 'Unsupported MRP reason_code. reason_code=%', p_reason_code;
  END IF;

  SELECT net_required_qty, suggested_action
    INTO v_net_required_qty, v_net_suggested_action
    FROM public.mrp_net_rows
   WHERE id = p_net_row_id;

  IF v_net_required_qty IS NULL OR v_net_required_qty <= 0 THEN
    RAISE EXCEPTION 'MRP suggestions require a linked net row with positive net_required_qty. net_row_id=%',
      p_net_row_id;
  END IF;

  IF v_net_suggested_action IS NOT NULL
     AND v_net_suggested_action <> 'none'
     AND v_net_suggested_action IS DISTINCT FROM p_suggestion_type THEN
    RAISE EXCEPTION 'MRP suggestion_type must match mrp_net_rows.suggested_action when present. net_row_id=%, suggested_action=%, suggestion_type=%',
      p_net_row_id, v_net_suggested_action, p_suggestion_type;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mrp_validate_supply_row_context(p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text, p_supply_type text, p_source_type text, p_source_id uuid, p_source_line_id uuid, p_original_qty numeric, p_available_qty numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mrp_validate_supply_row_context(p_run_id uuid, p_company_id uuid, p_branch_id uuid, p_warehouse_id uuid, p_product_id uuid, p_product_type text, p_supply_type text, p_source_type text, p_source_id uuid, p_source_line_id uuid, p_original_qty numeric, p_available_qty numeric)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_order_company_id UUID;
  v_order_branch_id UUID;
  v_order_receipt_warehouse_id UUID;
  v_order_product_id UUID;
BEGIN
  PERFORM public.mrp_assert_run_running(p_run_id);

  PERFORM public.mrp_validate_run_row_context(
    p_run_id,
    p_company_id,
    p_branch_id,
    p_warehouse_id,
    'mrp_supply_rows'
  );

  PERFORM public.mrp_validate_product_snapshot(
    p_product_id,
    p_product_type,
    'mrp_supply_rows'
  );

  PERFORM public.mrp_validate_source_pointer(
    p_source_type,
    p_source_id,
    'mrp_supply_rows'
  );

  IF p_original_qty IS NULL OR p_original_qty < 0 THEN
    RAISE EXCEPTION 'MRP supply original_qty must be non-negative. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_available_qty IS NULL OR p_available_qty < 0 THEN
    RAISE EXCEPTION 'MRP supply available_qty must be non-negative. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  IF p_available_qty > p_original_qty THEN
    RAISE EXCEPTION 'MRP supply available_qty cannot exceed original_qty. product_id=%, run_id=%',
      p_product_id, p_run_id;
  END IF;

  PERFORM public.mrp_assert_supply_source_eligibility(
    p_product_id,
    p_product_type,
    p_supply_type
  );

  CASE COALESCE(p_supply_type, '')
    WHEN 'free_stock' THEN
      IF p_source_type <> 'inventory_free_stock' THEN
        RAISE EXCEPTION 'Free-stock supply rows must use source_type=inventory_free_stock. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

      IF p_source_id IS DISTINCT FROM p_product_id THEN
        RAISE EXCEPTION 'Free-stock supply rows must use product_id as source_id. product_id=%, source_id=%, run_id=%',
          p_product_id, p_source_id, p_run_id;
      END IF;

      IF p_source_line_id IS NOT NULL THEN
        RAISE EXCEPTION 'Free-stock supply rows must not use source_line_id. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

    WHEN 'purchase_incoming' THEN
      IF p_source_type <> 'purchase_order' THEN
        RAISE EXCEPTION 'Purchase-incoming supply rows must use source_type=purchase_order. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

      IF p_source_line_id IS NULL THEN
        RAISE EXCEPTION 'Purchase-incoming supply rows require source_line_id. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

    WHEN 'production_incoming' THEN
      IF p_source_type <> 'production_order' THEN
        RAISE EXCEPTION 'Production-incoming supply rows must use source_type=production_order. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

      IF p_source_line_id IS NOT NULL THEN
        RAISE EXCEPTION 'Production-incoming supply rows must not use source_line_id in v1. product_id=%, run_id=%',
          p_product_id, p_run_id;
      END IF;

      SELECT company_id, branch_id, receipt_warehouse_id, product_id
        INTO v_order_company_id, v_order_branch_id, v_order_receipt_warehouse_id, v_order_product_id
        FROM public.manufacturing_production_orders
       WHERE id = p_source_id;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'manufacturing_production_orders record not found for MRP production supply validation. source_id=%',
          p_source_id;
      END IF;

      IF v_order_company_id IS DISTINCT FROM p_company_id
         OR v_order_branch_id IS DISTINCT FROM p_branch_id
         OR v_order_receipt_warehouse_id IS DISTINCT FROM p_warehouse_id
         OR v_order_product_id IS DISTINCT FROM p_product_id THEN
        RAISE EXCEPTION 'MRP production supply row must match the linked production order context. source_id=%, product_id=%, run_id=%',
          p_source_id, p_product_id, p_run_id;
      END IF;

    ELSE
      RAISE EXCEPTION 'Unsupported MRP supply_type. supply_type=%', p_supply_type;
  END CASE;
END;
$function$
;

-- ---------------------------------------------------------------
-- mwc_assert_work_center_operational(p_work_center_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_assert_work_center_operational(p_work_center_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_status TEXT;
BEGIN
  SELECT status
    INTO v_status
    FROM public.manufacturing_work_centers
   WHERE id = p_work_center_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'manufacturing_work_centers record not found. work_center_id=%', p_work_center_id;
  END IF;

  IF NOT public.mwc_is_work_center_operational(v_status) THEN
    RAISE EXCEPTION 'manufacturing_work_centers record is not operational. work_center_id=%, status=%', p_work_center_id, v_status;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mwc_guard_work_center_identity_immutability()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_guard_work_center_identity_immutability()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.company_id IS DISTINCT FROM NEW.company_id
     OR OLD.branch_id IS DISTINCT FROM NEW.branch_id THEN
    RAISE EXCEPTION 'manufacturing_work_centers identity fields are immutable after creation. work_center_id=%', OLD.id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mwc_guard_work_center_status_transition()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_guard_work_center_status_transition()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NOT public.mwc_is_work_center_transition_allowed(OLD.status, NEW.status) THEN
    RAISE EXCEPTION 'Invalid manufacturing_work_centers status transition. work_center_id=%, old_status=%, new_status=%',
      OLD.id, OLD.status, NEW.status;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mwc_is_work_center_blocked(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_is_work_center_blocked(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'blocked';
$function$
;

-- ---------------------------------------------------------------
-- mwc_is_work_center_operational(p_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_is_work_center_operational(p_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_status, '') = 'active';
$function$
;

-- ---------------------------------------------------------------
-- mwc_is_work_center_transition_allowed(p_old_status text, p_new_status text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_is_work_center_transition_allowed(p_old_status text, p_new_status text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(p_old_status, '') IN ('active', 'inactive', 'blocked')
     AND COALESCE(p_new_status, '') IN ('active', 'inactive', 'blocked');
$function$
;

-- ---------------------------------------------------------------
-- mwc_set_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mwc_trg_validate_work_center_context()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_trg_validate_work_center_context()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.mwc_validate_work_center_context(
    NEW.company_id,
    NEW.branch_id,
    NEW.cost_center_id,
    NEW.capacity_uom,
    NEW.nominal_capacity_per_hour,
    NEW.available_hours_per_day,
    NEW.parallel_capacity,
    NEW.efficiency_percent
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- mwc_validate_work_center_capacity_context(p_capacity_uom text, p_nominal_capacity_per_hour numeric, p_available_hours_per_day numeric, p_parallel_capacity integer, p_efficiency_percent numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_validate_work_center_capacity_context(p_capacity_uom text, p_nominal_capacity_per_hour numeric, p_available_hours_per_day numeric, p_parallel_capacity integer, p_efficiency_percent numeric)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF (p_capacity_uom IS NULL) <> (p_nominal_capacity_per_hour IS NULL) THEN
    RAISE EXCEPTION 'capacity_uom and nominal_capacity_per_hour must both be null or both be provided.';
  END IF;

  IF p_capacity_uom IS NOT NULL AND BTRIM(p_capacity_uom) = '' THEN
    RAISE EXCEPTION 'capacity_uom cannot be blank when provided.';
  END IF;

  IF p_nominal_capacity_per_hour IS NOT NULL AND p_nominal_capacity_per_hour <= 0 THEN
    RAISE EXCEPTION 'nominal_capacity_per_hour must be positive when provided.';
  END IF;

  IF p_available_hours_per_day IS NOT NULL AND p_available_hours_per_day <= 0 THEN
    RAISE EXCEPTION 'available_hours_per_day must be positive when provided.';
  END IF;

  IF p_parallel_capacity IS NULL OR p_parallel_capacity <= 0 THEN
    RAISE EXCEPTION 'parallel_capacity must be greater than zero.';
  END IF;

  IF p_efficiency_percent IS NULL OR p_efficiency_percent <= 0 OR p_efficiency_percent > 100 THEN
    RAISE EXCEPTION 'efficiency_percent must be greater than zero and less than or equal to 100.';
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- mwc_validate_work_center_context(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_capacity_uom text, p_nominal_capacity_per_hour numeric, p_available_hours_per_day numeric, p_parallel_capacity integer, p_efficiency_percent numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_validate_work_center_context(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_capacity_uom text, p_nominal_capacity_per_hour numeric, p_available_hours_per_day numeric, p_parallel_capacity integer, p_efficiency_percent numeric)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.mwc_validate_work_center_cost_center_context(
    p_company_id,
    p_branch_id,
    p_cost_center_id
  );

  PERFORM public.mwc_validate_work_center_capacity_context(
    p_capacity_uom,
    p_nominal_capacity_per_hour,
    p_available_hours_per_day,
    p_parallel_capacity,
    p_efficiency_percent
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- mwc_validate_work_center_cost_center_context(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.mwc_validate_work_center_cost_center_context(p_company_id uuid, p_branch_id uuid, p_cost_center_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cost_center_company_id UUID;
  v_cost_center_branch_id UUID;
BEGIN
  IF p_cost_center_id IS NULL THEN
    RETURN;
  END IF;

  SELECT company_id, branch_id
    INTO v_cost_center_company_id, v_cost_center_branch_id
    FROM public.cost_centers
   WHERE id = p_cost_center_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Referenced cost center not found. cost_center_id=%', p_cost_center_id;
  END IF;

  IF v_cost_center_company_id IS DISTINCT FROM p_company_id THEN
    RAISE EXCEPTION 'Cost center must belong to the same company as the work center. cost_center_id=%, company_id=%',
      p_cost_center_id, p_company_id;
  END IF;

  IF v_cost_center_branch_id IS DISTINCT FROM p_branch_id THEN
    RAISE EXCEPTION 'Cost center must belong to the same branch as the work center. cost_center_id=%, cost_center_branch_id=%, work_center_branch_id=%',
      p_cost_center_id, v_cost_center_branch_id, p_branch_id;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- next_lot_number(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.next_lot_number(p_company_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE v_next bigint;
BEGIN
  INSERT INTO public.lot_number_counters (company_id, last_value)
  VALUES (p_company_id, 1)
  ON CONFLICT (company_id) DO UPDATE
    SET last_value = lot_number_counters.last_value + 1
  RETURNING last_value INTO v_next;
  RETURN 'L' || TO_CHAR(NOW(), 'YYMM') || '-' || LPAD(v_next::text, 4, '0');
END;
$function$
;

-- ---------------------------------------------------------------
-- no_show_booking_atomic(p_company_id uuid, p_booking_id uuid, p_updated_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.no_show_booking_atomic(p_company_id uuid, p_booking_id uuid, p_updated_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_booking public.bookings;
BEGIN
  SELECT * INTO v_booking FROM public.bookings WHERE id = p_booking_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Booking not found. booking_id=%', p_booking_id USING ERRCODE='P0001'; END IF;
  IF v_booking.status NOT IN ('confirmed') THEN RAISE EXCEPTION 'Only confirmed bookings can be marked no-show. Current status: %. booking_id=%', v_booking.status, p_booking_id USING ERRCODE='P0001'; END IF;
  UPDATE public.bookings SET status='no_show', notes=COALESCE(p_notes,notes), updated_by=p_updated_by WHERE id=p_booking_id;
  RETURN jsonb_build_object('success',true,'booking_id',p_booking_id,'status','no_show');
END; $function$
;

-- ---------------------------------------------------------------
-- normalize_booking_payment_status()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.normalize_booking_payment_status()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.payment_status = 'partially_paid' THEN
    NEW.payment_status := 'partial';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- normalize_phone(phone text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.normalize_phone(phone text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$ BEGIN IF phone IS NULL OR phone = '' THEN RETURN NULL; END IF; RETURN regexp_replace(regexp_replace(phone, '^\+?2?0?', ''), '[^0-9]', '', 'g'); END; $function$
;

-- ---------------------------------------------------------------
-- notif_complete_actions()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notif_complete_actions()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE public.notifications
     SET status = 'actioned',
         actioned_at = COALESCE(actioned_at, NOW())
   WHERE company_id = NEW.company_id
     AND reference_id = NEW.id
     AND kind = 'action'
     AND status IN ('unread','read');
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- notification_outbox_from_financial_trace()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notification_outbox_from_financial_trace()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_context JSONB;
BEGIN
  IF NEW.event_type <> 'bill_receipt_posting' THEN
    RETURN NEW;
  END IF;

  v_context := jsonb_strip_nulls(jsonb_build_object(
    'actorId', NEW.actor_id,
    'branchId', NEW.metadata ->> 'branch_id',
    'warehouseId', NEW.metadata ->> 'warehouse_id',
    'costCenterId', NEW.metadata ->> 'cost_center_id',
    'uiSurface', NEW.metadata ->> 'ui_surface',
    'requestHash', NEW.request_hash,
    'correlationId', NEW.transaction_id::TEXT,
    'metadata', jsonb_build_object(
      'sourceEntity', NEW.source_entity,
      'sourceId', NEW.source_id,
      'traceId', NEW.transaction_id
    )
  ));

  PERFORM public.enqueue_notification_outbox_event(
    p_tenant_id         => NEW.company_id,
    p_event_type        => 'procurement.bill_receipt_posted',
    p_aggregate_type    => 'bill',
    p_aggregate_id      => NEW.source_id::TEXT,
    p_payload           => jsonb_strip_nulls(jsonb_build_object(
      'trace_id', NEW.transaction_id,
      'source_entity', NEW.source_entity,
      'source_id', NEW.source_id,
      'financial_event_type', NEW.event_type,
      'metadata', COALESCE(NEW.metadata, '{}'::JSONB),
      'audit_flags', COALESCE(NEW.audit_flags, '[]'::JSONB),
      'replay_payload', COALESCE(NEW.metadata -> 'normalized_replay_payload', '{}'::JSONB),
      'replay_payload_version', NEW.metadata ->> 'replay_payload_version',
      'replay_eligibility', NEW.metadata ->> 'replay_eligibility',
      'created_at', NEW.created_at
    )),
    p_context           => v_context,
    p_idempotency_key   => COALESCE(NEW.idempotency_key, 'bill_receipt_posting:' || NEW.source_id::TEXT || ':' || NEW.transaction_id::TEXT),
    p_correlation_id    => NEW.transaction_id::TEXT,
    p_causation_event_id=> NULL,
    p_version           => 1,
    p_available_at      => NEW.created_at,
    p_created_by        => NEW.actor_id
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- notification_outbox_from_replay_commit_intent()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notification_outbox_from_replay_commit_intent()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.enqueue_notification_outbox_event(
    p_tenant_id         => NEW.company_id,
    p_event_type        => 'governance.replay_commit_intent_issued',
    p_aggregate_type    => 'financial_replay_commit_intent',
    p_aggregate_id      => NEW.id::TEXT,
    p_payload           => jsonb_strip_nulls(jsonb_build_object(
      'intent_id', NEW.id,
      'source_trace_id', NEW.source_trace_id,
      'event_type', NEW.event_type,
      'payload_version', NEW.payload_version,
      'preview_result_hash', NEW.preview_result_hash,
      'preview_hash_algorithm', NEW.preview_hash_algorithm,
      'status', NEW.status,
      'intent_scope', COALESCE(NEW.intent_scope, '{}'::JSONB),
      'execution_envelope', COALESCE(NEW.execution_envelope, '{}'::JSONB),
      'execution_switch', COALESCE(NEW.execution_switch, '{}'::JSONB),
      'stability_snapshot', COALESCE(NEW.stability_snapshot, '{}'::JSONB),
      'token_hint', NEW.token_hint,
      'approved_at', NEW.approved_at,
      'expires_at', NEW.expires_at
    )),
    p_context           => jsonb_strip_nulls(jsonb_build_object(
      'actorId', COALESCE(NEW.approved_by, NEW.created_by),
      'uiSurface', COALESCE(NEW.execution_switch ->> 'ui_surface', NEW.intent_scope ->> 'ui_surface'),
      'correlationId', NEW.source_trace_id::TEXT,
      'metadata', jsonb_build_object(
        'sourceTraceId', NEW.source_trace_id,
        'eventType', NEW.event_type
      )
    )),
    p_idempotency_key   => 'replay_commit_intent:' || NEW.id::TEXT,
    p_correlation_id    => NEW.source_trace_id::TEXT,
    p_causation_event_id=> NULL,
    p_version           => 1,
    p_available_at      => NEW.created_at,
    p_created_by        => COALESCE(NEW.created_by, NEW.approved_by)
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- notification_outbox_from_replay_execution()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notification_outbox_from_replay_execution()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_causation_event_id UUID;
BEGIN
  SELECT event_id
    INTO v_causation_event_id
  FROM public.notification_outbox_events
  WHERE tenant_id = NEW.company_id
    AND idempotency_key = 'replay_commit_intent:' || NEW.commit_intent_id::TEXT
  ORDER BY created_at DESC
  LIMIT 1;

  PERFORM public.enqueue_notification_outbox_event(
    p_tenant_id         => NEW.company_id,
    p_event_type        => 'governance.replay_execution_activated',
    p_aggregate_type    => 'financial_replay_execution',
    p_aggregate_id      => NEW.id::TEXT,
    p_payload           => jsonb_strip_nulls(jsonb_build_object(
      'execution_id', NEW.id,
      'commit_intent_id', NEW.commit_intent_id,
      'source_trace_id', NEW.source_trace_id,
      'event_type', NEW.event_type,
      'payload_version', NEW.payload_version,
      'preview_result_hash', NEW.preview_result_hash,
      'preview_hash_algorithm', NEW.preview_hash_algorithm,
      'execution_mode', NEW.execution_mode,
      'status', NEW.status,
      'financial_writes_performed', NEW.financial_writes_performed,
      'write_guard', COALESCE(NEW.write_guard, '{}'::JSONB),
      'execution_metadata', COALESCE(NEW.execution_metadata, '{}'::JSONB),
      'result_summary', COALESCE(NEW.result_summary, '{}'::JSONB),
      'token_hint', NEW.token_hint,
      'executed_at', NEW.executed_at
    )),
    p_context           => jsonb_strip_nulls(jsonb_build_object(
      'actorId', NEW.executed_by,
      'uiSurface', NEW.execution_metadata ->> 'ui_surface',
      'correlationId', NEW.source_trace_id::TEXT,
      'metadata', jsonb_build_object(
        'sourceTraceId', NEW.source_trace_id,
        'eventType', NEW.event_type,
        'commitIntentId', NEW.commit_intent_id
      )
    )),
    p_idempotency_key   => 'replay_execution_activation:' || NEW.id::TEXT,
    p_correlation_id    => NEW.source_trace_id::TEXT,
    p_causation_event_id=> v_causation_event_id,
    p_version           => 1,
    p_available_at      => NEW.created_at,
    p_created_by        => NEW.executed_by
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- notification_outbox_set_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notification_outbox_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- notification_supersede_older_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notification_supersede_older_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.category NOT IN ('approvals', 'accountant_action', 'branch_activity') THEN
    RETURN NEW;
  END IF;
  IF NEW.reference_id IS NULL THEN RETURN NEW; END IF;

  IF NEW.assigned_to_user IS NOT NULL THEN
    UPDATE public.notifications
       SET status  = 'archived',
           read_at = COALESCE(read_at, NOW())
     WHERE id             <> NEW.id
       AND company_id     = NEW.company_id
       AND category       IN ('approvals', 'accountant_action', 'branch_activity')
       AND reference_type = NEW.reference_type
       AND reference_id   = NEW.reference_id
       AND assigned_to_user = NEW.assigned_to_user
       AND status         = 'unread'
       AND created_at     < NEW.created_at;

    -- When a targeted accountant_action arrives, the generic approvals
    -- broadcast about the same document becomes noise — archive it.
    IF NEW.category = 'accountant_action' THEN
      UPDATE public.notifications
         SET status  = 'archived',
             read_at = COALESCE(read_at, NOW())
       WHERE company_id     = NEW.company_id
         AND category       = 'approvals'
         AND reference_type = NEW.reference_type
         AND reference_id   = NEW.reference_id
         AND assigned_to_user IS NULL
         AND status         = 'unread';
    END IF;
  ELSE
    UPDATE public.notifications
       SET status  = 'archived',
           read_at = COALESCE(read_at, NOW())
     WHERE id             <> NEW.id
       AND company_id     = NEW.company_id
       AND category       = NEW.category
       AND reference_type = NEW.reference_type
       AND reference_id   = NEW.reference_id
       AND assigned_to_user IS NULL
       AND status         = 'unread'
       AND created_at     < NEW.created_at;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- notify_branch_manager(p_company_id uuid, p_branch_id uuid, p_reference_type text, p_reference_id uuid, p_actor_id uuid, p_title text, p_message text, p_severity text, p_priority text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notify_branch_manager(p_company_id uuid, p_branch_id uuid, p_reference_type text, p_reference_id uuid, p_actor_id uuid, p_title text, p_message text, p_severity text DEFAULT 'info'::text, p_priority text DEFAULT 'normal'::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_manager_id uuid;
  v_actor uuid;
BEGIN
  IF p_branch_id IS NULL THEN RETURN; END IF;

  v_actor := p_actor_id;
  IF v_actor IS NULL THEN
    v_actor := auth.uid();
  END IF;
  IF v_actor IS NULL THEN
    SELECT user_id INTO v_actor
    FROM public.company_members
    WHERE company_id = p_company_id AND role = 'owner' AND user_id IS NOT NULL
    LIMIT 1;
  END IF;
  -- Absolute last resort: skip the notify instead of failing the whole
  -- caller transaction. A missing notification is better than a rolled-
  -- back financial UPDATE.
  IF v_actor IS NULL THEN RETURN; END IF;

  FOR v_manager_id IN
    SELECT user_id FROM public.company_members
     WHERE company_id = p_company_id
       AND branch_id  = p_branch_id
       AND role       = 'manager'
       AND user_id    IS NOT NULL
       AND user_id <> v_actor
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      p_company_id, p_reference_type, p_reference_id, v_actor,
      v_manager_id, p_title, p_message,
      p_priority, p_severity, 'branch_activity', 'in_app', NOW()
    );
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- notify_company_billing_owner(p_company_id uuid, p_title text, p_message text, p_severity text, p_priority text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notify_company_billing_owner(p_company_id uuid, p_title text, p_message text, p_severity text DEFAULT 'warning'::text, p_priority text DEFAULT 'high'::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_owner uuid;
  v_creator uuid;
BEGIN
  -- Use the company owner as the "creator" for system billing pings.
  SELECT user_id INTO v_creator FROM public.companies WHERE id = p_company_id;

  FOR v_owner IN
    SELECT DISTINCT u FROM (
      SELECT user_id AS u FROM public.companies WHERE id = p_company_id
      UNION
      SELECT user_id FROM public.company_members
       WHERE company_id = p_company_id
         AND role IN ('owner', 'general_manager', 'admin')
    ) owners
    WHERE u IS NOT NULL
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      p_company_id, 'subscription', p_company_id, COALESCE(v_creator, v_owner),
      v_owner, p_title, p_message,
      p_priority, p_severity, 'billing', 'in_app', NOW()
    );
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- notify_discount_decision_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.notify_discount_decision_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_title text;
  v_severity text;
  v_priority text;
  v_msg text;
  v_doc_label text;
  v_kind_ar text;
  v_is_amendment boolean;
BEGIN
  IF OLD.status = NEW.status THEN RETURN NEW; END IF;
  IF NEW.status NOT IN ('approved','rejected') THEN RETURN NEW; END IF;
  IF NEW.requested_by IS NULL THEN RETURN NEW; END IF;

  v_doc_label := CASE NEW.document_type
    WHEN 'purchase_order'   THEN 'أمر الشراء '
    WHEN 'sales_order'      THEN 'طلب المبيعات '
    WHEN 'purchase_invoice' THEN 'فاتورة المشتريات '
    WHEN 'sales_invoice'    THEN 'فاتورة المبيعات '
    WHEN 'booking'          THEN 'الحجز '
    ELSE 'المستند '
  END || COALESCE(NEW.document_no, '');

  -- v3.74.494 — pick the right noun. supersedes_approval_id is set
  -- only when the row was opened by an amendment trigger, which is the
  -- catch-all path for edits to shipping / quantities / tax / etc.
  -- Fresh discount requests (no supersedes) still say "الخصم".
  v_is_amendment := NEW.supersedes_approval_id IS NOT NULL;
  v_kind_ar := CASE WHEN v_is_amendment THEN 'التعديل' ELSE 'الخصم' END;

  IF NEW.status = 'approved' THEN
    v_title := 'تم اعتماد ' || v_kind_ar;
    v_severity := 'info';
    v_priority := 'normal';
    v_msg := 'تم اعتماد ' || v_kind_ar || ' على ' || v_doc_label || '. يمكنك المتابعة.';
  ELSE
    v_title := 'تم رفض ' || v_kind_ar;
    v_severity := 'error';
    v_priority := 'high';
    v_msg := 'تم رفض ' || v_kind_ar || ' على ' || v_doc_label || '.' ||
      CASE WHEN NEW.decision_note IS NOT NULL AND TRIM(NEW.decision_note) <> ''
           THEN ' السبب: ' || NEW.decision_note
           ELSE ''
      END ||
      -- v3.74.494 — hint text differs. Amendments need a re-edit;
      -- fresh discount requests may keep or remove the discount.
      CASE WHEN v_is_amendment
           THEN ' عدّل الفاتورة لفتح دورة اعتماد جديدة.'
           ELSE ' عدّل المستند (احذف الخصم أو غيّره) لفتح دورة موافقة جديدة.'
      END;
  END IF;

  INSERT INTO public.notifications (
    company_id, reference_type, reference_id, created_by,
    assigned_to_user, title, message,
    priority, severity, category, channel, created_at
  ) VALUES (
    NEW.company_id,
    CASE NEW.document_type::text
      WHEN 'purchase_order'   THEN 'purchase_order'
      WHEN 'sales_order'      THEN 'sales_order'
      WHEN 'purchase_invoice' THEN 'bill'
      WHEN 'sales_invoice'    THEN 'invoice'
      WHEN 'booking'          THEN 'booking'
      ELSE NEW.document_type::text
    END,
    NEW.document_id,
    COALESCE(NEW.decided_by, NEW.requested_by),
    NEW.requested_by,
    v_title, v_msg,
    v_priority, v_severity, 'approvals', 'in_app', NOW()
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- pay_commission_advance(p_company_id uuid, p_employee_id uuid, p_amount numeric, p_payment_account_id uuid, p_payment_date date, p_period_start date, p_period_end date, p_user_id uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.pay_commission_advance(p_company_id uuid, p_employee_id uuid, p_amount numeric, p_payment_account_id uuid, p_payment_date date, p_period_start date, p_period_end date, p_user_id uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
    v_total_earned DECIMAL(15,2) := 0;
    v_total_advance_paid DECIMAL(15,2) := 0;
    v_available_amount DECIMAL(15,2);
    v_advance_id UUID;
    v_journal_id UUID;
    v_ref_number TEXT;
    v_employee_name TEXT;
    v_commission_liability_account UUID;
    v_fiscal_year_id UUID;
    v_lock_key BIGINT;
BEGIN
    SET search_path = public, pg_temp;

    v_lock_key := ('x' || substr(md5(p_company_id::TEXT || p_employee_id::TEXT), 1, 15))::BIT(60)::BIGINT;

    IF NOT pg_try_advisory_xact_lock(v_lock_key) THEN
        RAISE EXCEPTION 'عملية صرف أخرى قيد التنفيذ لهذا الموظف.';
    END IF;

    IF p_amount <= 0 THEN
        RAISE EXCEPTION 'المبلغ يجب أن يكون أكبر من صفر';
    END IF;

    SELECT COALESCE(SUM(
        CASE
            WHEN COALESCE(is_clawback, FALSE) = FALSE THEN amount
            WHEN COALESCE(is_clawback, FALSE) = TRUE THEN -amount
            ELSE 0
        END
    ), 0)
    INTO v_total_earned
    FROM commission_ledger
    WHERE company_id = p_company_id
    AND employee_id = p_employee_id
    AND transaction_date BETWEEN p_period_start AND p_period_end
    FOR SHARE;

    SELECT COALESCE(SUM(amount), 0)
    INTO v_total_advance_paid
    FROM commission_advance_payments
    WHERE company_id = p_company_id
    AND employee_id = p_employee_id
    AND commission_period_start <= p_period_end
    AND commission_period_end >= p_period_start
    AND status = 'paid'
    AND deducted_in_payroll = FALSE
    FOR UPDATE;

    v_available_amount := GREATEST(v_total_earned - v_total_advance_paid, 0);

    IF p_amount > v_available_amount THEN
        RAISE EXCEPTION 'المبلغ المطلوب (%) أكبر من الرصيد المتاح (%)', p_amount, v_available_amount;
    END IF;

    SELECT full_name INTO v_employee_name FROM employees WHERE id = p_employee_id;
    IF v_employee_name IS NULL THEN
        RAISE EXCEPTION 'الموظف غير موجود';
    END IF;

    SELECT id INTO v_commission_liability_account
    FROM chart_of_accounts
    WHERE company_id = p_company_id
    AND (account_code LIKE '%2150%' OR account_name ILIKE '%commission%payable%' OR account_name ILIKE '%عمولات مستحقة%')
    AND account_type = 'liability'
    LIMIT 1;

    IF v_commission_liability_account IS NULL THEN
        SELECT id INTO v_commission_liability_account
        FROM chart_of_accounts
        WHERE company_id = p_company_id
        AND account_type = 'liability'
        AND (account_code LIKE '%2100%' OR sub_type = 'accrued_expenses')
        LIMIT 1;
    END IF;

    IF v_commission_liability_account IS NULL THEN
        RAISE EXCEPTION 'لم يتم العثور على حساب العمولات المستحقة. يرجى إنشاء حساب التزامات للعمولات أولاً.';
    END IF;

    IF NOT EXISTS (SELECT 1 FROM chart_of_accounts WHERE id = p_payment_account_id AND company_id = p_company_id) THEN
        RAISE EXCEPTION 'حساب الدفع غير صالح';
    END IF;

    -- Business rule: must have an active fiscal year for the payment
    -- date. The id is no longer stored on the JE row, but the check
    -- itself stays as a guard.
    SELECT id INTO v_fiscal_year_id
    FROM fiscal_years
    WHERE company_id = p_company_id
    AND start_date <= p_payment_date
    AND end_date >= p_payment_date
    AND status = 'active'
    LIMIT 1;

    IF v_fiscal_year_id IS NULL THEN
        RAISE EXCEPTION 'لا توجد سنة مالية نشطة للتاريخ المحدد';
    END IF;

    v_ref_number := 'ADV-COM-' || TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS') || '-' || SUBSTR(gen_random_uuid()::TEXT, 1, 4);

    -- v3.74.38: dropped fiscal_year_id + posted; renamed created_by → posted_by; added posted_at
    INSERT INTO journal_entries (
        company_id, entry_date, description,
        reference_type, posted_by, posted_at, status
    ) VALUES (
        p_company_id, p_payment_date,
        'صرف سلفة عمولات - ' || v_employee_name || ' - ' || v_ref_number,
        'commission_advance', p_user_id, NOW(), 'posted'
    ) RETURNING id INTO v_journal_id;

    -- v3.74.38: debit/credit → debit_amount/credit_amount
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
    VALUES (v_journal_id, v_commission_liability_account, p_amount, 0, 'صرف سلفة عمولات - ' || v_employee_name);

    INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
    VALUES (v_journal_id, p_payment_account_id, 0, p_amount, 'صرف سلفة عمولات - ' || v_employee_name);

    INSERT INTO commission_advance_payments (
        company_id, employee_id, amount, payment_date,
        commission_period_start, commission_period_end,
        reference_number, notes, status,
        journal_entry_id, payment_account_id, created_by
    ) VALUES (
        p_company_id, p_employee_id, p_amount, p_payment_date,
        p_period_start, p_period_end,
        v_ref_number, p_notes, 'paid',
        v_journal_id, p_payment_account_id, p_user_id
    ) RETURNING id INTO v_advance_id;

    RETURN jsonb_build_object(
        'success', TRUE,
        'advance_id', v_advance_id,
        'reference_number', v_ref_number,
        'amount', p_amount,
        'journal_entry_id', v_journal_id,
        'employee_name', v_employee_name,
        'remaining_available', v_available_amount - p_amount
    );
EXCEPTION WHEN OTHERS THEN
    RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- pay_commission_run_atomic(p_commission_run_id uuid, p_payable_account_id uuid, p_bank_account_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.pay_commission_run_atomic(p_commission_run_id uuid, p_payable_account_id uuid, p_bank_account_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
    v_run RECORD;
    v_journal_id UUID;
BEGIN
    SELECT * INTO v_run FROM commission_runs WHERE id = p_commission_run_id;
    
    IF v_run IS NULL THEN
        RAISE EXCEPTION 'Commission run not found';
    END IF;
    
    -- Idempotency check
    IF v_run.status = 'paid' THEN
        RETURN jsonb_build_object('success', TRUE, 'message', 'Already paid', 'payment_journal_id', v_run.payment_journal_id);
    END IF;
    
    PERFORM validate_commission_run_transition(p_commission_run_id, 'paid');
    PERFORM validate_transaction_period(v_run.company_id, CURRENT_DATE);
    
    INSERT INTO journal_entries (
        company_id, entry_date, description, reference_type, reference_id,
        status, posted_by, posted_at
    ) VALUES (
        v_run.company_id, CURRENT_DATE,
        'Commission Payment - ' || v_run.period_start || ' to ' || v_run.period_end,
        'commission_payment', p_commission_run_id, 'posted', p_user_id, NOW()
    ) RETURNING id INTO v_journal_id;
    
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, description, debit_amount, credit_amount)
    VALUES (v_journal_id, p_payable_account_id, 'Commission Payable', v_run.net_commission, 0);
    
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, description, debit_amount, credit_amount)
    VALUES (v_journal_id, p_bank_account_id, 'Bank Payment', 0, v_run.net_commission);
    
    UPDATE commission_runs
    SET status = 'paid', payment_journal_id = v_journal_id, paid_by = p_user_id, paid_at = NOW()
    WHERE id = p_commission_run_id;
    
    UPDATE commission_ledger SET status = 'paid' WHERE commission_run_id = p_commission_run_id;
    
    RETURN jsonb_build_object('success', TRUE, 'payment_journal_id', v_journal_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- pay_dividend_atomic(p_company_id uuid, p_distribution_line_id uuid, p_amount numeric, p_payment_date date, p_payment_account_id uuid, p_dividends_payable_account_id uuid, p_payment_method text, p_reference_number text, p_branch_id uuid, p_cost_center_id uuid, p_user_id uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.pay_dividend_atomic(p_company_id uuid, p_distribution_line_id uuid, p_amount numeric, p_payment_date date, p_payment_account_id uuid, p_dividends_payable_account_id uuid, p_payment_method text DEFAULT 'cash'::text, p_reference_number text DEFAULT NULL::text, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_user_id uuid DEFAULT NULL::uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_line RECORD;
  v_payment_id UUID;
  v_journal_id UUID;
  v_new_paid DECIMAL;
  v_new_status TEXT;
BEGIN
  -- 1. Validate Period Locking (STRICT)
  PERFORM validate_transaction_period(p_company_id, p_payment_date);

  -- Get Line
  SELECT * INTO v_line FROM public.profit_distribution_lines WHERE id = p_distribution_line_id;
  IF v_line IS NULL THEN RAISE EXCEPTION 'Distribution line not found'; END IF;

  -- Validate Amount
  IF p_amount > (v_line.amount - v_line.paid_amount) THEN
    RAISE EXCEPTION 'Payment amount exceeds remaining payable balance';
  END IF;

  -- 2. Insert Payment
  INSERT INTO public.dividend_payments (
    company_id, distribution_line_id, shareholder_id, payment_date, amount, 
    payment_method, reference_number, notes, created_by
  ) VALUES (
    p_company_id, p_distribution_line_id, v_line.shareholder_id, p_payment_date, p_amount,
    p_payment_method, p_reference_number, p_notes, p_user_id
  ) RETURNING id INTO v_payment_id;

  -- 3. Create Journal Entry
  -- DR Dividends Payable (Liability Decrease)
  -- CR Bank/Cash (Asset Decrease)
  
  INSERT INTO public.journal_entries (
    company_id, entry_date, description, reference_type, reference_id, 
    status, branch_id, cost_center_id, posted_by, posted_at
  ) VALUES (
    p_company_id, p_payment_date, 'Dividend Payment - ' || p_payment_date, 'dividend_payment', v_payment_id,
    'posted', p_branch_id, p_cost_center_id, p_user_id, NOW()
  ) RETURNING id INTO v_journal_id;
  
  -- Update Payment with JE ID
  UPDATE public.dividend_payments SET journal_entry_id = v_journal_id WHERE id = v_payment_id;

  -- Insert Lines
  -- Debit Payable
  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount, branch_id, cost_center_id
  ) VALUES (
    v_journal_id, p_dividends_payable_account_id, 'Dividend Payment', p_amount, 0, p_branch_id, p_cost_center_id
  );

  -- Credit Bank
  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount, branch_id, cost_center_id
  ) VALUES (
    v_journal_id, p_payment_account_id, 'Cash Outflow', 0, p_amount, p_branch_id, p_cost_center_id
  );

  -- 4. Update Line Status
  v_new_paid := v_line.paid_amount + p_amount;
  v_new_status := CASE 
    WHEN v_new_paid >= v_line.amount THEN 'paid'
    ELSE 'partially_paid' 
  END;

  UPDATE public.profit_distribution_lines
  SET paid_amount = v_new_paid,
      status = v_new_status
  WHERE id = p_distribution_line_id;

  RETURN jsonb_build_object('payment_id', v_payment_id, 'journal_entry_id', v_journal_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- payment_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.payment_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_supplier_name text;
  v_currency text;
  v_bill_no text;
  v_is_supplier boolean;
BEGIN
  v_is_supplier := NEW.supplier_id IS NOT NULL OR NEW.bill_id IS NOT NULL;
  IF NOT v_is_supplier THEN RETURN NEW; END IF;

  v_currency := COALESCE(NEW.currency_code, 'EGP');
  BEGIN
    IF NEW.supplier_id IS NOT NULL THEN
      SELECT name INTO v_supplier_name FROM public.suppliers WHERE id = NEW.supplier_id;
    END IF;
    IF NEW.bill_id IS NOT NULL THEN
      SELECT bill_number INTO v_bill_no FROM public.bills WHERE id = NEW.bill_id;
    END IF;
  EXCEPTION WHEN OTHERS THEN NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'payment', NEW.id, COALESCE(NEW.created_by_user_id, NEW.created_by),
      'نشاط فرعك: تم إنشاء دفعة مورد',
      'تم إنشاء دفعة بقيمة ' || NEW.amount::text || ' ' || v_currency ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' للمورد ' || v_supplier_name ELSE '' END ||
      CASE WHEN v_bill_no IS NOT NULL THEN ' على فاتورة ' || v_bill_no ELSE '' END ||
      ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status IN ('approved', 'rejected', 'posted', 'paid') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'payment', NEW.id,
      CASE WHEN NEW.status = 'rejected' THEN NEW.rejected_by ELSE NEW.approved_by END,
      'نشاط فرعك: تغيّرت حالة دفعة مورد',
      'دفعة بقيمة ' || NEW.amount::text || ' ' || v_currency ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' للمورد ' || v_supplier_name ELSE '' END ||
      CASE WHEN v_bill_no IS NOT NULL THEN ' على فاتورة ' || v_bill_no ELSE '' END ||
      ' أصبحت الحالة "' || NEW.status || '".'
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- payment_customer_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.payment_customer_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_customer_name text; v_currency text; v_invoice_no text;
  v_is_customer boolean;
BEGIN
  v_is_customer := NEW.customer_id IS NOT NULL OR NEW.invoice_id IS NOT NULL;
  IF NOT v_is_customer THEN RETURN NEW; END IF;
  IF NEW.supplier_id IS NOT NULL OR NEW.bill_id IS NOT NULL THEN
    -- Ambiguous; let the supplier trigger handle it.
    RETURN NEW;
  END IF;

  v_currency := COALESCE(NEW.currency_code, 'EGP');
  BEGIN
    IF NEW.customer_id IS NOT NULL THEN
      SELECT name INTO v_customer_name FROM public.customers WHERE id = NEW.customer_id;
    END IF;
    IF NEW.invoice_id IS NOT NULL THEN
      SELECT invoice_number INTO v_invoice_no FROM public.invoices WHERE id = NEW.invoice_id;
    END IF;
  EXCEPTION WHEN OTHERS THEN NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'payment', NEW.id, COALESCE(NEW.created_by_user_id, NEW.created_by),
      'نشاط فرعك: تم تحصيل دفعة من عميل',
      'دفعة بقيمة ' || NEW.amount::text || ' ' || v_currency ||
      CASE WHEN v_customer_name IS NOT NULL THEN ' من العميل ' || v_customer_name ELSE '' END ||
      CASE WHEN v_invoice_no IS NOT NULL THEN ' على فاتورة ' || v_invoice_no ELSE '' END ||
      ' فى فرعك.'
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- payment_supplier_approval_insert_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.payment_supplier_approval_insert_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_is_supplier_payment boolean;
  v_creator_role text;
  v_bypass text;
BEGIN
  v_is_supplier_payment := NEW.supplier_id IS NOT NULL OR NEW.bill_id IS NOT NULL;
  IF NOT v_is_supplier_payment THEN
    RETURN NEW;
  END IF;

  -- v3.74.544 — correction RPCs set this GUC transaction-local before
  -- inserting the VOID row + replacement. Both rows are already
  -- approved as part of the correction workflow so the governance
  -- rule is satisfied through the request, not the direct insert.
  BEGIN
    v_bypass := current_setting('app.correction_bypass', true);
  EXCEPTION WHEN OTHERS THEN
    v_bypass := NULL;
  END;
  IF v_bypass = 'on' THEN
    RETURN NEW;
  END IF;

  IF NEW.created_by_user_id IS NOT NULL THEN
    SELECT role INTO v_creator_role
      FROM public.company_members
     WHERE company_id = NEW.company_id
       AND user_id    = NEW.created_by_user_id
     LIMIT 1;
  END IF;

  IF v_creator_role IN ('owner', 'general_manager') THEN
    IF NEW.status = 'approved' THEN
      IF NEW.approved_by IS NULL THEN NEW.approved_by := NEW.created_by_user_id; END IF;
      IF NEW.approved_at IS NULL THEN NEW.approved_at := NOW(); END IF;
    END IF;
    RETURN NEW;
  END IF;

  IF NEW.status NOT IN ('draft', 'pending_approval') THEN
    RAISE EXCEPTION
      'دفع المورد يحتاج اعتماد المالك / المدير العام. لا يجوز إنشاء دفعة بحالة "%" مباشرة. ابدأ بحالة pending_approval.', NEW.status
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- payment_supplier_approval_update_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.payment_supplier_approval_update_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_is_supplier_payment boolean;
BEGIN
  v_is_supplier_payment := NEW.supplier_id IS NOT NULL OR NEW.bill_id IS NOT NULL;
  IF NOT v_is_supplier_payment THEN
    RETURN NEW;
  END IF;
  IF NEW.status = OLD.status THEN
    RETURN NEW;
  END IF;

  IF NEW.status IN ('approved', 'posted', 'paid', 'partially_paid')
     AND (NEW.approved_by IS NULL OR NEW.approved_at IS NULL) THEN
    RAISE EXCEPTION
      'لا يمكن تحويل دفعة المورد إلى حالة "%" بدون تسجيل المعتمد (approved_by + approved_at). استخدم RPC الاعتماد.', NEW.status
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- payment_supplier_notify_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.payment_supplier_notify_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_is_supplier_payment boolean;
  v_supplier_name text;
  v_requester uuid;
  v_approver_id uuid;
  v_currency text;
  v_bill_no text;
BEGIN
  v_is_supplier_payment := NEW.supplier_id IS NOT NULL OR NEW.bill_id IS NOT NULL;
  IF NOT v_is_supplier_payment THEN RETURN NEW; END IF;

  -- Only fire when entering pending_approval.
  IF TG_OP = 'UPDATE' AND OLD.status = NEW.status THEN RETURN NEW; END IF;
  IF NEW.status <> 'pending_approval' THEN RETURN NEW; END IF;

  v_requester := COALESCE(NEW.created_by_user_id, NEW.created_by);
  v_currency  := COALESCE(NEW.currency_code, 'EGP');

  BEGIN
    IF NEW.supplier_id IS NOT NULL THEN
      SELECT name INTO v_supplier_name FROM public.suppliers WHERE id = NEW.supplier_id;
    END IF;
    IF NEW.bill_id IS NOT NULL THEN
      SELECT bill_number INTO v_bill_no FROM public.bills WHERE id = NEW.bill_id;
    END IF;
  EXCEPTION WHEN OTHERS THEN NULL; END;

  FOR v_approver_id IN
    SELECT DISTINCT u FROM (
      SELECT user_id AS u FROM public.companies WHERE id = NEW.company_id
      UNION
      SELECT user_id FROM public.company_members
       WHERE company_id = NEW.company_id
         AND role IN ('owner', 'general_manager')
    ) approvers
    WHERE u IS NOT NULL AND (v_requester IS NULL OR u <> v_requester)
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      NEW.company_id, 'approval_request', NEW.id, v_requester,
      v_approver_id,
      'طلب اعتماد دفعة مورد',
      'دفعة بقيمة ' || NEW.amount::text || ' ' || v_currency ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' للمورد ' || v_supplier_name ELSE '' END ||
      CASE WHEN v_bill_no IS NOT NULL THEN ' على فاتورة ' || v_bill_no ELSE '' END ||
      ' — يحتاج اعتمادك من صندوق الموافقات قبل الترحيل.',
      'high', 'warning', 'approvals', 'in_app', NOW()
    );
  END LOOP;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- perform_annual_closing_atomic(p_company_id uuid, p_fiscal_year integer, p_closing_date date, p_retained_earnings_account_id uuid, p_user_id uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.perform_annual_closing_atomic(p_company_id uuid, p_fiscal_year integer, p_closing_date date, p_retained_earnings_account_id uuid, p_user_id uuid DEFAULT NULL::uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_revenue_total  NUMERIC(20,4) := 0;
  v_expense_total  NUMERIC(20,4) := 0;
  v_net_income     NUMERIC(20,4) := 0;
  v_je_id          UUID;
  v_closing_id     UUID;
  v_lines          JSONB[] := ARRAY[]::JSONB[];
  v_account        RECORD;
  v_affected_count INTEGER := 0;
BEGIN
  IF EXISTS (
    SELECT 1 FROM public.fiscal_year_closings
     WHERE company_id = p_company_id
       AND fiscal_year = p_fiscal_year
       AND status = 'posted'
  ) THEN
    RAISE EXCEPTION 'السنة المالية % مقفلة بالفعل', p_fiscal_year;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.chart_of_accounts
     WHERE id = p_retained_earnings_account_id
       AND company_id = p_company_id
  ) THEN
    RAISE EXCEPTION 'حساب الأرباح المحتجزة غير موجود';
  END IF;

  IF NOT EXISTS (
    SELECT 1
      FROM public.journal_entry_lines jel
      JOIN public.journal_entries je ON je.id = jel.journal_entry_id
      JOIN public.chart_of_accounts coa ON coa.id = jel.account_id
     WHERE je.company_id = p_company_id
       AND EXTRACT(YEAR FROM je.entry_date) = p_fiscal_year
       AND je.status = 'posted'
       AND COALESCE(je.is_closing_entry, FALSE) = FALSE
       AND coa.account_type IN ('income', 'revenue', 'expense')
  ) THEN
    RAISE EXCEPTION 'لا توجد حركات إيرادات أو مصروفات لهذه السنة المالية';
  END IF;

  FOR v_account IN
    SELECT
      coa.id, coa.account_code, coa.account_name,
      COALESCE(SUM(jel.credit_amount), 0) - COALESCE(SUM(jel.debit_amount), 0) AS net_balance
    FROM public.chart_of_accounts coa
    LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
    LEFT JOIN public.journal_entries je
           ON je.id = jel.journal_entry_id
          AND je.company_id = p_company_id
          AND EXTRACT(YEAR FROM je.entry_date) = p_fiscal_year
          AND je.status = 'posted'
          AND COALESCE(je.is_closing_entry, FALSE) = FALSE
    WHERE coa.company_id = p_company_id AND coa.account_type IN ('income', 'revenue')
    GROUP BY coa.id, coa.account_code, coa.account_name
    HAVING COALESCE(SUM(jel.credit_amount), 0) - COALESCE(SUM(jel.debit_amount), 0) > 0
  LOOP
    v_revenue_total := v_revenue_total + v_account.net_balance;
    v_lines := array_append(v_lines, jsonb_build_object(
      'account_id', v_account.id,
      'debit_amount', v_account.net_balance,
      'credit_amount', 0,
      'description', 'إقفال حساب إيرادات: ' || v_account.account_name || ' - السنة المالية ' || p_fiscal_year
    ));
    v_affected_count := v_affected_count + 1;
  END LOOP;

  FOR v_account IN
    SELECT
      coa.id, coa.account_code, coa.account_name,
      COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0) AS net_balance
    FROM public.chart_of_accounts coa
    LEFT JOIN public.journal_entry_lines jel ON jel.account_id = coa.id
    LEFT JOIN public.journal_entries je
           ON je.id = jel.journal_entry_id
          AND je.company_id = p_company_id
          AND EXTRACT(YEAR FROM je.entry_date) = p_fiscal_year
          AND je.status = 'posted'
          AND COALESCE(je.is_closing_entry, FALSE) = FALSE
    WHERE coa.company_id = p_company_id AND coa.account_type = 'expense'
    GROUP BY coa.id, coa.account_code, coa.account_name
    HAVING COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0) > 0
  LOOP
    v_expense_total := v_expense_total + v_account.net_balance;
    v_lines := array_append(v_lines, jsonb_build_object(
      'account_id', v_account.id,
      'debit_amount', 0,
      'credit_amount', v_account.net_balance,
      'description', 'إقفال حساب مصروفات: ' || v_account.account_name || ' - السنة المالية ' || p_fiscal_year
    ));
    v_affected_count := v_affected_count + 1;
  END LOOP;

  v_net_income := v_revenue_total - v_expense_total;

  IF v_net_income > 0 THEN
    v_lines := array_append(v_lines, jsonb_build_object(
      'account_id', p_retained_earnings_account_id,
      'debit_amount', 0,
      'credit_amount', v_net_income,
      'description', 'صافي ربح السنة المالية ' || p_fiscal_year || ' - أرباح محتجزة'
    ));
  ELSIF v_net_income < 0 THEN
    v_lines := array_append(v_lines, jsonb_build_object(
      'account_id', p_retained_earnings_account_id,
      'debit_amount', ABS(v_net_income),
      'credit_amount', 0,
      'description', 'صافي خسارة السنة المالية ' || p_fiscal_year || ' - أرباح محتجزة'
    ));
  END IF;

  -- v3.74.38: created_by → posted_by; added posted_at for completeness
  INSERT INTO public.journal_entries (
    company_id, entry_date, description, reference_type, status, is_closing_entry, posted_by, posted_at
  ) VALUES (
    p_company_id, p_closing_date,
    'قيد الإقفال السنوي - السنة المالية ' || p_fiscal_year,
    'annual_closing', 'posted', TRUE, p_user_id, NOW()
  ) RETURNING id INTO v_je_id;

  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, debit_amount, credit_amount, description
  )
  SELECT v_je_id,
    (line->>'account_id')::UUID,
    (line->>'debit_amount')::NUMERIC,
    (line->>'credit_amount')::NUMERIC,
    line->>'description'
  FROM unnest(v_lines) AS line;

  INSERT INTO public.fiscal_year_closings (
    company_id, fiscal_year, closing_date, total_revenue, total_expenses,
    net_income, status, journal_entry_id, retained_earnings_account_id, created_by, notes
  ) VALUES (
    p_company_id, p_fiscal_year, p_closing_date, v_revenue_total, v_expense_total,
    v_net_income, 'posted', v_je_id, p_retained_earnings_account_id, p_user_id, p_notes
  ) RETURNING id INTO v_closing_id;

  UPDATE public.accounting_periods
     SET status = 'closed', is_locked = TRUE, closed_at = NOW(), closed_by = p_user_id
   WHERE company_id = p_company_id
     AND EXTRACT(YEAR FROM period_start) = p_fiscal_year
     AND status <> 'closed';

  RETURN jsonb_build_object(
    'success', TRUE,
    'closing_id', v_closing_id,
    'journal_entry_id', v_je_id,
    'fiscal_year', p_fiscal_year,
    'total_revenue', v_revenue_total,
    'total_expenses', v_expense_total,
    'net_income', v_net_income,
    'accounts_closed', v_affected_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- po_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.po_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_supplier_name text;
  v_currency text;
BEGIN
  v_currency := COALESCE(NEW.currency, 'EGP');
  BEGIN
    SELECT name INTO v_supplier_name FROM public.suppliers WHERE id = NEW.supplier_id;
  EXCEPTION WHEN OTHERS THEN v_supplier_name := NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'purchase_order', NEW.id, NEW.created_by_user_id,
      'نشاط فرعك: تم إنشاء أمر شراء',
      'تم إنشاء أمر شراء ' || NEW.po_number ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' للمورد ' || v_supplier_name ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency || ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status IN ('approved', 'rejected') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'purchase_order', NEW.id,
      CASE NEW.status WHEN 'approved' THEN NEW.approved_by ELSE NEW.rejected_by END,
      'نشاط فرعك: ' ||
        (CASE NEW.status WHEN 'approved' THEN 'تم اعتماد أمر شراء' ELSE 'تم رفض أمر شراء' END),
      'أمر الشراء ' || NEW.po_number ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' للمورد ' || v_supplier_name ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency || ' ' ||
      (CASE NEW.status WHEN 'approved' THEN 'تم اعتماده' ELSE 'تم رفضه' END) || ' فى فرعك.'
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- po_cancel_discount_on_status_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.po_cancel_discount_on_status_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.status IN ('rejected', 'cancelled')
     AND OLD.status IS DISTINCT FROM NEW.status THEN
    UPDATE public.discount_approvals
       SET status = 'cancelled',
           decision_note = COALESCE(
             decision_note,
             CASE NEW.status
               WHEN 'rejected'  THEN 'تم رفض أمر الشراء — لم تعد الموافقة على الخصم لازمة.'
               WHEN 'cancelled' THEN 'تم إلغاء أمر الشراء — لم تعد الموافقة على الخصم لازمة.'
             END
           ),
           updated_at = NOW()
     WHERE document_type = 'purchase_order'
       AND document_id   = NEW.id
       AND status        = 'pending';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- po_evaluate_discount_approval(p_po_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.po_evaluate_discount_approval(p_po_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_po record;
  v_subtotal numeric := 0;
  v_line_discount_amt numeric := 0;
  v_doc_discount_amt numeric := 0;
  v_total_discount_amt numeric := 0;
  v_last_id uuid;
  v_last_status text;
  v_last_value numeric;
  v_party_name text;
  v_requester uuid;
  v_approver_id uuid;
  v_currency text;
  v_new_approval_id uuid;
BEGIN
  SELECT * INTO v_po FROM public.purchase_orders WHERE id = p_po_id;
  IF NOT FOUND THEN RETURN; END IF;
  -- Only act while the PO is editable / awaiting approval.
  IF v_po.status NOT IN ('draft', 'pending_approval') THEN RETURN; END IF;

  -- Pull subtotal and line-discount total from items.
  SELECT
    COALESCE(SUM(quantity * unit_price), 0),
    COALESCE(SUM(quantity * unit_price * COALESCE(discount_percent, 0) / 100.0), 0)
  INTO v_subtotal, v_line_discount_amt
  FROM public.purchase_order_items
  WHERE purchase_order_id = p_po_id;

  -- Document-level discount in amount terms.
  IF COALESCE(v_po.discount_value, 0) > 0 THEN
    IF COALESCE(v_po.discount_type, 'amount') = 'percent' THEN
      -- Percent applies to the subtotal AFTER line discounts.
      v_doc_discount_amt := GREATEST(v_subtotal - v_line_discount_amt, 0) * v_po.discount_value / 100.0;
    ELSE
      v_doc_discount_amt := v_po.discount_value;
    END IF;
  END IF;

  v_total_discount_amt := ROUND(v_line_discount_amt + v_doc_discount_amt, 2);

  -- What's the latest approval row for this PO?
  SELECT id, status, discount_value
    INTO v_last_id, v_last_status, v_last_value
    FROM public.discount_approvals
   WHERE document_type = 'purchase_order' AND document_id = p_po_id
   ORDER BY requested_at DESC LIMIT 1;

  -- (1) No effective discount → cancel any pending request.
  IF v_total_discount_amt <= 0 THEN
    IF FOUND AND v_last_status = 'pending' THEN
      UPDATE public.discount_approvals
         SET status = 'cancelled',
             decision_note = COALESCE(decision_note, 'Discount removed from the purchase order.'),
             updated_at = NOW()
       WHERE id = v_last_id;
    END IF;
    RETURN;
  END IF;

  -- (2) Same effective discount already pending/approved → nothing to do.
  IF FOUND AND v_last_status IN ('pending', 'approved')
     AND v_last_value = v_total_discount_amt THEN
    RETURN;
  END IF;

  -- (3) Different discount or fresh: cancel any existing pending, then
  --     open a new pending row.
  IF FOUND AND v_last_status = 'pending' THEN
    UPDATE public.discount_approvals
       SET status = 'cancelled',
           decision_note = COALESCE(decision_note, 'Superseded by amended aggregated discount.'),
           updated_at = NOW()
     WHERE id = v_last_id;
  END IF;

  BEGIN
    SELECT name INTO v_party_name FROM public.suppliers WHERE id = v_po.supplier_id;
  EXCEPTION WHEN OTHERS THEN v_party_name := NULL; END;

  v_requester := v_po.created_by_user_id;
  -- If no requester recorded, we silently skip. Approve gate will block
  -- the PO anyway (no approved row = no approval).
  IF v_requester IS NULL THEN RETURN; END IF;

  v_currency := COALESCE(v_po.currency, 'EGP');

  INSERT INTO public.discount_approvals (
    company_id, document_type, document_id, document_no,
    discount_value, discount_type, document_total, party_name,
    reason, status, requested_by, requested_at
  ) VALUES (
    v_po.company_id, 'purchase_order', v_po.id, v_po.po_number,
    v_total_discount_amt, 'amount',
    v_po.total_amount, v_party_name,
    NULL, 'pending', v_requester, NOW()
  ) RETURNING id INTO v_new_approval_id;

  FOR v_approver_id IN
    SELECT DISTINCT u FROM (
      SELECT user_id AS u FROM public.companies WHERE id = v_po.company_id
      UNION
      SELECT user_id FROM public.company_members
       WHERE company_id = v_po.company_id
         AND role IN ('owner', 'general_manager', 'admin')
    ) approvers
    WHERE u IS NOT NULL AND u <> v_requester
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      v_po.company_id, 'approval_request', v_new_approval_id, v_requester,
      v_approver_id,
      'طلب موافقة على خصم أمر شراء',
      'أمر شراء ' || v_po.po_number || ' للمورد ' || COALESCE(v_party_name, 'غير محدد') ||
      ' بإجمالى خصم ' || v_total_discount_amt::text || ' ' || v_currency ||
      ' (مجمَّع: خصم البنود + خصم المستند) — يحتاج اعتمادك من صندوق الموافقات',
      'high', 'warning', 'approvals', 'in_app', NOW()
    );
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- po_item_evaluate_discount_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.po_item_evaluate_discount_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM public.po_evaluate_discount_approval(OLD.purchase_order_id);
    RETURN OLD;
  ELSE
    PERFORM public.po_evaluate_discount_approval(NEW.purchase_order_id);
    RETURN NEW;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- po_item_protect_approved_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.po_item_protect_approved_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_po_status text;
  v_po_id     uuid;
BEGIN
  v_po_id := COALESCE(NEW.purchase_order_id, OLD.purchase_order_id);
  SELECT status INTO v_po_status FROM public.purchase_orders WHERE id = v_po_id;
  IF NOT FOUND THEN RETURN COALESCE(NEW, OLD); END IF;

  IF v_po_status IN ('approved', 'sent_to_vendor', 'received') THEN
    -- Allow the bypass token (used by void/recreate flows).
    IF COALESCE(current_setting('app.skip_po_lock', true), '') <> '' THEN
      RETURN COALESCE(NEW, OLD);
    END IF;
    RAISE EXCEPTION
      'لا يمكن تعديل بنود أمر شراء معتمد. اعمل void للفاتورة المرتبطة لإعادة فتح الدورة.'
      USING ERRCODE = 'P0001';
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- po_protect_approved_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.po_protect_approved_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Only guard the post-approval lifecycle.
  IF OLD.status NOT IN ('approved', 'sent_to_vendor', 'received') THEN
    RETURN NEW;
  END IF;
  -- If status itself is changing, this is a legitimate workflow
  -- transition (e.g. void_bill_atomic moves us back to pending_approval).
  IF NEW.status IS DISTINCT FROM OLD.status THEN
    RETURN NEW;
  END IF;

  IF NEW.discount_value     IS DISTINCT FROM OLD.discount_value
     OR NEW.discount_type    IS DISTINCT FROM OLD.discount_type
     OR NEW.discount_position IS DISTINCT FROM OLD.discount_position
     OR NEW.tax_inclusive    IS DISTINCT FROM OLD.tax_inclusive
     OR NEW.exchange_rate    IS DISTINCT FROM OLD.exchange_rate
     OR NEW.subtotal         IS DISTINCT FROM OLD.subtotal
     OR NEW.total_amount     IS DISTINCT FROM OLD.total_amount
     OR NEW.tax_amount       IS DISTINCT FROM OLD.tax_amount
     OR NEW.shipping         IS DISTINCT FROM OLD.shipping THEN
    RAISE EXCEPTION
      'لا يمكن تعديل الخصم أو الإجماليات على أمر شراء معتمد. اعمل void للفاتورة المرتبطة لإعادة فتح الدورة.'
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- po_request_discount_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.po_request_discount_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.po_evaluate_discount_approval(NEW.id);
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_accounting_event(p_event_type text, p_company_id uuid, p_items jsonb, p_inventory_transactions jsonb, p_cogs_transactions jsonb, p_fifo_consumptions jsonb, p_journal_entries jsonb, p_payments jsonb, p_sales_returns jsonb, p_sales_return_items jsonb, p_update_source jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_accounting_event(p_event_type text, p_company_id uuid, p_items jsonb DEFAULT NULL::jsonb, p_inventory_transactions jsonb DEFAULT NULL::jsonb, p_cogs_transactions jsonb DEFAULT NULL::jsonb, p_fifo_consumptions jsonb DEFAULT NULL::jsonb, p_journal_entries jsonb DEFAULT NULL::jsonb, p_payments jsonb DEFAULT NULL::jsonb, p_sales_returns jsonb DEFAULT NULL::jsonb, p_sales_return_items jsonb DEFAULT NULL::jsonb, p_update_source jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  -- v3.74.39: delegate to the canonical 12-param overload with
  -- customer_credits = NULL. The canonical overload was made
  -- column-correct + SECURITY DEFINER in v3.74.31 → v3.74.33.
  RETURN public.post_accounting_event(
    p_event_type             := p_event_type,
    p_company_id             := p_company_id,
    p_items                  := p_items,
    p_inventory_transactions := p_inventory_transactions,
    p_cogs_transactions      := p_cogs_transactions,
    p_fifo_consumptions      := p_fifo_consumptions,
    p_journal_entries        := p_journal_entries,
    p_payments               := p_payments,
    p_sales_returns          := p_sales_returns,
    p_sales_return_items     := p_sales_return_items,
    p_customer_credits       := NULL::jsonb,
    p_update_source          := p_update_source
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- post_accounting_event(p_event_type text, p_company_id uuid, p_items jsonb, p_inventory_transactions jsonb, p_cogs_transactions jsonb, p_fifo_consumptions jsonb, p_journal_entries jsonb, p_payments jsonb, p_sales_returns jsonb, p_sales_return_items jsonb, p_customer_credits jsonb, p_update_source jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_accounting_event(p_event_type text, p_company_id uuid, p_items jsonb DEFAULT NULL::jsonb, p_inventory_transactions jsonb DEFAULT NULL::jsonb, p_cogs_transactions jsonb DEFAULT NULL::jsonb, p_fifo_consumptions jsonb DEFAULT NULL::jsonb, p_journal_entries jsonb DEFAULT NULL::jsonb, p_payments jsonb DEFAULT NULL::jsonb, p_sales_returns jsonb DEFAULT NULL::jsonb, p_sales_return_items jsonb DEFAULT NULL::jsonb, p_customer_credits jsonb DEFAULT NULL::jsonb, p_update_source jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_journal_ids UUID[] := ARRAY[]::UUID[];
  v_cogs_ids    UUID[] := ARRAY[]::UUID[];
  v_inv_ids     UUID[] := ARRAY[]::UUID[];
  v_payment_ids UUID[] := ARRAY[]::UUID[];
  v_return_ids  UUID[] := ARRAY[]::UUID[];
  v_credit_ids  UUID[] := ARRAY[]::UUID[];
  v_inv  JSONB; v_fifo JSONB; v_cogs JSONB; v_je JSONB;
  v_pay  JSONB; v_sr JSONB; v_sri JSONB; v_cc JSONB; v_je_line JSONB;
  v_current_journal_id UUID;
  v_inserted_id        UUID;
BEGIN
  IF p_payments IS NOT NULL AND jsonb_array_length(p_payments) > 0 THEN
    FOR v_pay IN SELECT * FROM jsonb_array_elements(p_payments) LOOP
      -- v3.74.32: column is reference_number, not reference
      INSERT INTO payments (
        id, company_id, branch_id, cost_center_id, warehouse_id,
        invoice_id, customer_id, supplier_id,
        amount, payment_date, payment_method,
        reference_number, notes, created_by_user_id
      ) VALUES (
        COALESCE((v_pay->>'id')::UUID, gen_random_uuid()),
        (v_pay->>'company_id')::UUID, (v_pay->>'branch_id')::UUID,
        (v_pay->>'cost_center_id')::UUID, (v_pay->>'warehouse_id')::UUID,
        (v_pay->>'invoice_id')::UUID, (v_pay->>'customer_id')::UUID,
        (v_pay->>'supplier_id')::UUID, (v_pay->>'amount')::NUMERIC,
        (v_pay->>'payment_date')::DATE, v_pay->>'payment_method',
        COALESCE(v_pay->>'reference_number', v_pay->>'reference'),
        v_pay->>'notes',
        (v_pay->>'created_by_user_id')::UUID
      ) RETURNING id INTO v_inserted_id;
      v_payment_ids := array_append(v_payment_ids, v_inserted_id);
    END LOOP;
  END IF;

  IF p_sales_returns IS NOT NULL AND jsonb_array_length(p_sales_returns) > 0 THEN
    FOR v_sr IN SELECT * FROM jsonb_array_elements(p_sales_returns) LOOP
      INSERT INTO sales_returns (
        id, company_id, customer_id, invoice_id,
        branch_id, warehouse_id, cost_center_id,
        return_number, return_date,
        subtotal, tax_amount, total_amount,
        refund_amount, refund_method, status, reason, notes
      ) VALUES (
        COALESCE((v_sr->>'id')::UUID, gen_random_uuid()),
        (v_sr->>'company_id')::UUID, (v_sr->>'customer_id')::UUID,
        (v_sr->>'invoice_id')::UUID, (v_sr->>'branch_id')::UUID,
        (v_sr->>'warehouse_id')::UUID, (v_sr->>'cost_center_id')::UUID,
        v_sr->>'return_number', (v_sr->>'return_date')::DATE,
        (v_sr->>'subtotal')::NUMERIC, (v_sr->>'tax_amount')::NUMERIC,
        (v_sr->>'total_amount')::NUMERIC, (v_sr->>'refund_amount')::NUMERIC,
        v_sr->>'refund_method', v_sr->>'status',
        v_sr->>'reason', v_sr->>'notes'
      ) RETURNING id INTO v_inserted_id;
      v_return_ids := array_append(v_return_ids, v_inserted_id);
    END LOOP;
  END IF;

  IF p_sales_return_items IS NOT NULL AND jsonb_array_length(p_sales_return_items) > 0 THEN
    FOR v_sri IN SELECT * FROM jsonb_array_elements(p_sales_return_items) LOOP
      INSERT INTO sales_return_items (
        sales_return_id, product_id, quantity,
        unit_price, tax_rate, discount_percent, line_total
      ) VALUES (
        (v_sri->>'sales_return_id')::UUID, (v_sri->>'product_id')::UUID,
        (v_sri->>'quantity')::NUMERIC, (v_sri->>'unit_price')::NUMERIC,
        (v_sri->>'tax_rate')::NUMERIC, (v_sri->>'discount_percent')::NUMERIC,
        (v_sri->>'line_total')::NUMERIC
      );
    END LOOP;
  END IF;

  IF p_customer_credits IS NOT NULL AND jsonb_array_length(p_customer_credits) > 0 THEN
    FOR v_cc IN SELECT * FROM jsonb_array_elements(p_customer_credits) LOOP
      INSERT INTO customer_credits (
        company_id, customer_id, credit_number, credit_date,
        amount, used_amount, reference_type, reference_id, status, notes
      ) VALUES (
        (v_cc->>'company_id')::UUID, (v_cc->>'customer_id')::UUID,
        v_cc->>'credit_number', (v_cc->>'credit_date')::DATE,
        (v_cc->>'amount')::NUMERIC, 0,
        v_cc->>'reference_type', (v_cc->>'reference_id')::UUID,
        v_cc->>'status', v_cc->>'notes'
      ) RETURNING id INTO v_inserted_id;
      v_credit_ids := array_append(v_credit_ids, v_inserted_id);
    END LOOP;
  END IF;

  IF p_inventory_transactions IS NOT NULL AND jsonb_array_length(p_inventory_transactions) > 0 THEN
    FOR v_inv IN SELECT * FROM jsonb_array_elements(p_inventory_transactions) LOOP
      -- v3.74.32: dropped transaction_date (column does not exist;
      --          created_at defaults to NOW())
      INSERT INTO inventory_transactions (
        company_id, branch_id, warehouse_id, cost_center_id,
        product_id, transaction_type, quantity_change,
        reference_type, reference_id, notes
      ) VALUES (
        (v_inv->>'company_id')::UUID, (v_inv->>'branch_id')::UUID,
        (v_inv->>'warehouse_id')::UUID, (v_inv->>'cost_center_id')::UUID,
        (v_inv->>'product_id')::UUID, v_inv->>'transaction_type',
        (v_inv->>'quantity_change')::NUMERIC, v_inv->>'reference_type',
        (v_inv->>'reference_id')::UUID, v_inv->>'notes'
      );
    END LOOP;
  END IF;

  IF p_fifo_consumptions IS NOT NULL AND jsonb_array_length(p_fifo_consumptions) > 0 THEN
    FOR v_fifo IN SELECT * FROM jsonb_array_elements(p_fifo_consumptions) LOOP
      -- v3.74.32: added required product_id and consumption_type;
      --          tolerate either consumption_date OR consumed_at in the
      --          payload for backward compatibility with both prep
      --          shapes.
      INSERT INTO fifo_lot_consumptions (
        company_id, lot_id, product_id, consumption_type,
        reference_type, reference_id,
        quantity_consumed, unit_cost, total_cost,
        consumption_date, created_at
      ) VALUES (
        (v_fifo->>'company_id')::UUID, (v_fifo->>'lot_id')::UUID,
        (v_fifo->>'product_id')::UUID,
        COALESCE(v_fifo->>'consumption_type', 'sale'),
        v_fifo->>'reference_type', (v_fifo->>'reference_id')::UUID,
        (v_fifo->>'quantity_consumed')::NUMERIC, (v_fifo->>'unit_cost')::NUMERIC,
        (v_fifo->>'total_cost')::NUMERIC,
        COALESCE((v_fifo->>'consumption_date')::DATE, CURRENT_DATE),
        COALESCE((v_fifo->>'consumed_at')::TIMESTAMPTZ, NOW())
      );
      UPDATE fifo_cost_lots
      SET remaining_quantity = remaining_quantity - (v_fifo->>'quantity_consumed')::NUMERIC
      WHERE id = (v_fifo->>'lot_id')::UUID;
      IF EXISTS (
        SELECT 1 FROM fifo_cost_lots
        WHERE id = (v_fifo->>'lot_id')::UUID AND remaining_quantity < 0
      ) THEN
        RAISE EXCEPTION 'Governance Violation: FIFO Lot quantity cannot be negative (Lot ID: %)', (v_fifo->>'lot_id');
      END IF;
    END LOOP;
  END IF;

  IF p_cogs_transactions IS NOT NULL AND jsonb_array_length(p_cogs_transactions) > 0 THEN
    FOR v_cogs IN SELECT * FROM jsonb_array_elements(p_cogs_transactions) LOOP
      INSERT INTO cogs_transactions (
        company_id, branch_id, cost_center_id, warehouse_id,
        product_id, source_type, source_id,
        quantity, unit_cost, total_cost, transaction_date, notes
      ) VALUES (
        (v_cogs->>'company_id')::UUID, (v_cogs->>'branch_id')::UUID,
        (v_cogs->>'cost_center_id')::UUID, (v_cogs->>'warehouse_id')::UUID,
        (v_cogs->>'product_id')::UUID, v_cogs->>'source_type',
        (v_cogs->>'source_id')::UUID, (v_cogs->>'quantity')::NUMERIC,
        (v_cogs->>'unit_cost')::NUMERIC, (v_cogs->>'total_cost')::NUMERIC,
        (v_cogs->>'transaction_date')::DATE, v_cogs->>'notes'
      );
    END LOOP;
  END IF;

  IF p_journal_entries IS NOT NULL AND jsonb_array_length(p_journal_entries) > 0 THEN
    PERFORM set_config('app.allow_direct_post', 'true', true);
    FOR v_je IN SELECT * FROM jsonb_array_elements(p_journal_entries) LOOP
      INSERT INTO journal_entries (
        id, company_id, reference_type, reference_id,
        entry_date, description, branch_id, cost_center_id, status
      ) VALUES (
        COALESCE((v_je->>'id')::UUID, gen_random_uuid()),
        (v_je->>'company_id')::UUID, v_je->>'reference_type',
        (v_je->>'reference_id')::UUID, (v_je->>'entry_date')::DATE,
        v_je->>'description', (v_je->>'branch_id')::UUID,
        (v_je->>'cost_center_id')::UUID, 'posted'
      ) RETURNING id INTO v_current_journal_id;
      v_journal_ids := array_append(v_journal_ids, v_current_journal_id);
      IF v_je->'lines' IS NOT NULL AND jsonb_array_length(v_je->'lines') > 0 THEN
        FOR v_je_line IN SELECT * FROM jsonb_array_elements(v_je->'lines') LOOP
          INSERT INTO journal_entry_lines (
            journal_entry_id, account_id,
            debit_amount, credit_amount,
            description, branch_id, cost_center_id
          ) VALUES (
            v_current_journal_id, (v_je_line->>'account_id')::UUID,
            (v_je_line->>'debit_amount')::NUMERIC,
            (v_je_line->>'credit_amount')::NUMERIC,
            v_je_line->>'description', (v_je_line->>'branch_id')::UUID,
            (v_je_line->>'cost_center_id')::UUID
          );
        END LOOP;
      END IF;
    END LOOP;
    PERFORM set_config('app.allow_direct_post', 'false', true);
  END IF;

  IF p_update_source IS NOT NULL THEN
    IF p_event_type = 'invoice_posting' THEN
      UPDATE invoices SET status = p_update_source->>'status', updated_at = NOW()
       WHERE id = (p_update_source->>'id')::UUID;
    END IF;
    IF p_event_type = 'return' THEN
      IF p_update_source->>'invoice_id' IS NOT NULL THEN
        UPDATE invoices SET status = p_update_source->>'status',
            returned_amount = (p_update_source->>'returned_amount')::NUMERIC,
            return_status = p_update_source->>'return_status',
            updated_at = NOW()
         WHERE id = (p_update_source->>'invoice_id')::UUID;
      END IF;
      IF p_update_source->>'sales_order_id' IS NOT NULL THEN
        UPDATE sales_orders SET status = p_update_source->>'status',
            returned_amount = (p_update_source->>'returned_amount')::NUMERIC,
            return_status = p_update_source->>'return_status',
            updated_at = NOW()
         WHERE id = (p_update_source->>'sales_order_id')::UUID;
      END IF;
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'success',           true,
    'payment_ids',       v_payment_ids,
    'journal_entry_ids', v_journal_ids,
    'return_ids',        v_return_ids,
    'credit_ids',        v_credit_ids
  );
EXCEPTION WHEN OTHERS THEN
  PERFORM set_config('app.allow_direct_post', 'false', true);
  RAISE EXCEPTION 'Transaction Failed: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_accounting_event_v2(p_event_type text, p_company_id uuid, p_items jsonb, p_inventory_transactions jsonb, p_cogs_transactions jsonb, p_fifo_consumptions jsonb, p_journal_entries jsonb, p_payments jsonb, p_sales_returns jsonb, p_sales_return_items jsonb, p_customer_credits jsonb, p_update_source jsonb, p_source_entity text, p_source_id uuid, p_effective_date date, p_actor_id uuid, p_idempotency_key text, p_request_hash text, p_third_party_inventory_records jsonb, p_customer_credit_ledger_entries jsonb, p_trace_metadata jsonb, p_audit_flags jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_accounting_event_v2(p_event_type text, p_company_id uuid, p_items jsonb DEFAULT NULL::jsonb, p_inventory_transactions jsonb DEFAULT NULL::jsonb, p_cogs_transactions jsonb DEFAULT NULL::jsonb, p_fifo_consumptions jsonb DEFAULT NULL::jsonb, p_journal_entries jsonb DEFAULT NULL::jsonb, p_payments jsonb DEFAULT NULL::jsonb, p_sales_returns jsonb DEFAULT NULL::jsonb, p_sales_return_items jsonb DEFAULT NULL::jsonb, p_customer_credits jsonb DEFAULT NULL::jsonb, p_update_source jsonb DEFAULT NULL::jsonb, p_source_entity text DEFAULT NULL::text, p_source_id uuid DEFAULT NULL::uuid, p_effective_date date DEFAULT NULL::date, p_actor_id uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text, p_request_hash text DEFAULT NULL::text, p_third_party_inventory_records jsonb DEFAULT NULL::jsonb, p_customer_credit_ledger_entries jsonb DEFAULT NULL::jsonb, p_trace_metadata jsonb DEFAULT '{}'::jsonb, p_audit_flags jsonb DEFAULT '[]'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_idempotency_result JSONB;
  v_result             JSONB;
  v_effective_date     DATE;
  v_source_entity      TEXT;
  v_source_id          UUID;
  v_transaction_id     UUID;
  v_payment_id_text    TEXT;
  v_journal_id_text    TEXT;
  v_return_id_text     TEXT;
  v_credit_ledger      JSONB;
  v_tpi_record         JSONB;
  v_inserted_id        UUID;
  v_third_party_ids    UUID[] := ARRAY[]::UUID[];
  v_credit_ledger_ids  UUID[] := ARRAY[]::UUID[];
BEGIN
  v_effective_date := COALESCE(
    p_effective_date,
    CASE
      WHEN p_journal_entries IS NOT NULL AND jsonb_typeof(p_journal_entries) = 'array' AND jsonb_array_length(p_journal_entries) > 0
      THEN (p_journal_entries->0->>'entry_date')::DATE
      ELSE NULL
    END,
    CASE
      WHEN p_payments IS NOT NULL AND jsonb_typeof(p_payments) = 'array' AND jsonb_array_length(p_payments) > 0
      THEN (p_payments->0->>'payment_date')::DATE
      ELSE NULL
    END,
    CASE
      WHEN p_sales_returns IS NOT NULL AND jsonb_typeof(p_sales_returns) = 'array' AND jsonb_array_length(p_sales_returns) > 0
      THEN (p_sales_returns->0->>'return_date')::DATE
      ELSE NULL
    END,
    CURRENT_DATE
  );

  PERFORM public.require_open_financial_period_db(p_company_id, v_effective_date);
  PERFORM public.assert_journal_entries_balanced_v2(p_journal_entries);

  IF p_idempotency_key IS NOT NULL THEN
    v_idempotency_result := public.check_and_claim_idempotency_key(
      p_idempotency_key,
      p_company_id,
      'financial_' || p_event_type || '_v2',
      p_request_hash,
      p_actor_id
    );

    IF v_idempotency_result IS NOT NULL AND COALESCE(v_idempotency_result->>'cached', 'false') = 'true' THEN
      RETURN COALESCE(v_idempotency_result->'response', jsonb_build_object('success', true))
        || jsonb_build_object('cached', true, 'idempotent', true);
    END IF;
  END IF;

  v_result := public.post_accounting_event(
    p_event_type,
    p_company_id,
    p_items,
    p_inventory_transactions,
    p_cogs_transactions,
    p_fifo_consumptions,
    p_journal_entries,
    p_payments,
    p_sales_returns,
    p_sales_return_items,
    p_customer_credits,
    p_update_source
  );

  IF p_third_party_inventory_records IS NOT NULL
     AND jsonb_typeof(p_third_party_inventory_records) = 'array'
     AND jsonb_array_length(p_third_party_inventory_records) > 0 THEN
    FOR v_tpi_record IN SELECT * FROM jsonb_array_elements(p_third_party_inventory_records)
    LOOP
      INSERT INTO public.third_party_inventory (
        company_id,
        shipping_provider_id,
        product_id,
        invoice_id,
        quantity,
        unit_cost,
        total_cost,
        status,
        branch_id,
        cost_center_id,
        warehouse_id,
        customer_id,
        sales_order_id,
        notes
      ) VALUES (
        (v_tpi_record->>'company_id')::UUID,
        (v_tpi_record->>'shipping_provider_id')::UUID,
        (v_tpi_record->>'product_id')::UUID,
        (v_tpi_record->>'invoice_id')::UUID,
        (v_tpi_record->>'quantity')::NUMERIC,
        (v_tpi_record->>'unit_cost')::NUMERIC,
        (v_tpi_record->>'total_cost')::NUMERIC,
        COALESCE(v_tpi_record->>'status', 'open'),
        (v_tpi_record->>'branch_id')::UUID,
        (v_tpi_record->>'cost_center_id')::UUID,
        (v_tpi_record->>'warehouse_id')::UUID,
        (v_tpi_record->>'customer_id')::UUID,
        (v_tpi_record->>'sales_order_id')::UUID,
        v_tpi_record->>'notes'
      )
      RETURNING id INTO v_inserted_id;

      v_third_party_ids := array_append(v_third_party_ids, v_inserted_id);
    END LOOP;
  END IF;

  IF p_customer_credit_ledger_entries IS NOT NULL
     AND jsonb_typeof(p_customer_credit_ledger_entries) = 'array'
     AND jsonb_array_length(p_customer_credit_ledger_entries) > 0 THEN
    FOR v_credit_ledger IN SELECT * FROM jsonb_array_elements(p_customer_credit_ledger_entries)
    LOOP
      INSERT INTO public.customer_credit_ledger (
        company_id,
        customer_id,
        source_type,
        source_id,
        journal_entry_id,
        amount,
        description,
        created_by
      ) VALUES (
        (v_credit_ledger->>'company_id')::UUID,
        (v_credit_ledger->>'customer_id')::UUID,
        v_credit_ledger->>'source_type',
        (v_credit_ledger->>'source_id')::UUID,
        (v_credit_ledger->>'journal_entry_id')::UUID,
        (v_credit_ledger->>'amount')::NUMERIC,
        v_credit_ledger->>'description',
        (v_credit_ledger->>'created_by')::UUID
      )
      RETURNING id INTO v_inserted_id;

      v_credit_ledger_ids := array_append(v_credit_ledger_ids, v_inserted_id);
    END LOOP;
  END IF;

  IF p_update_source IS NOT NULL AND p_event_type = 'warehouse_approval' THEN
    UPDATE public.invoices
    SET
      warehouse_status = COALESCE(p_update_source->>'warehouse_status', warehouse_status),
      status = COALESCE(p_update_source->>'status', status),
      updated_at = NOW()
    WHERE id = (p_update_source->>'invoice_id')::UUID;
  END IF;

  v_source_entity := COALESCE(p_source_entity, 'financial_event');
  v_source_id := COALESCE(
    p_source_id,
    CASE WHEN p_update_source ? 'invoice_id' THEN (p_update_source->>'invoice_id')::UUID ELSE NULL END,
    CASE WHEN p_update_source ? 'id' THEN (p_update_source->>'id')::UUID ELSE NULL END,
    CASE
      WHEN p_sales_returns IS NOT NULL AND jsonb_typeof(p_sales_returns) = 'array' AND jsonb_array_length(p_sales_returns) > 0
      THEN (p_sales_returns->0->>'id')::UUID
      ELSE NULL
    END,
    CASE
      WHEN p_payments IS NOT NULL AND jsonb_typeof(p_payments) = 'array' AND jsonb_array_length(p_payments) > 0
      THEN (p_payments->0->>'invoice_id')::UUID
      ELSE NULL
    END
  );

  IF v_source_id IS NOT NULL THEN
    v_transaction_id := public.create_financial_operation_trace(
      p_company_id,
      v_source_entity,
      v_source_id,
      p_event_type,
      p_actor_id,
      p_idempotency_key,
      p_request_hash,
      COALESCE(p_trace_metadata, '{}'::JSONB),
      COALESCE(p_audit_flags, '[]'::JSONB)
    );

    PERFORM public.link_financial_operation_trace(
      v_transaction_id,
      v_source_entity,
      v_source_id,
      'source',
      p_event_type
    );

    IF COALESCE(jsonb_typeof(v_result->'payment_ids'), 'null') = 'array' THEN
      FOR v_payment_id_text IN SELECT * FROM jsonb_array_elements_text(v_result->'payment_ids')
      LOOP
        PERFORM public.link_financial_operation_trace(
          v_transaction_id,
          'payment',
          v_payment_id_text::UUID,
          'payment',
          p_event_type
        );
      END LOOP;
    END IF;

    IF COALESCE(jsonb_typeof(v_result->'journal_entry_ids'), 'null') = 'array' THEN
      FOR v_journal_id_text IN SELECT * FROM jsonb_array_elements_text(v_result->'journal_entry_ids')
      LOOP
        PERFORM public.link_financial_operation_trace(
          v_transaction_id,
          'journal_entry',
          v_journal_id_text::UUID,
          'journal_entry',
          p_event_type
        );
      END LOOP;
    END IF;

    IF COALESCE(jsonb_typeof(v_result->'return_ids'), 'null') = 'array' THEN
      FOR v_return_id_text IN SELECT * FROM jsonb_array_elements_text(v_result->'return_ids')
      LOOP
        PERFORM public.link_financial_operation_trace(
          v_transaction_id,
          'sales_return',
          v_return_id_text::UUID,
          'sales_return',
          p_event_type
        );
      END LOOP;
    END IF;

    IF COALESCE(array_length(v_third_party_ids, 1), 0) > 0 THEN
      FOREACH v_inserted_id IN ARRAY v_third_party_ids
      LOOP
        PERFORM public.link_financial_operation_trace(
          v_transaction_id,
          'third_party_inventory',
          v_inserted_id,
          'third_party_inventory',
          p_event_type
        );
      END LOOP;
    END IF;

    IF COALESCE(array_length(v_credit_ledger_ids, 1), 0) > 0 THEN
      FOREACH v_inserted_id IN ARRAY v_credit_ledger_ids
      LOOP
        PERFORM public.link_financial_operation_trace(
          v_transaction_id,
          'customer_credit_ledger',
          v_inserted_id,
          'customer_credit_ledger',
          p_event_type
        );
      END LOOP;
    END IF;
  END IF;

  v_result := v_result
    || jsonb_build_object(
      'transaction_id', v_transaction_id,
      'source_entity', v_source_entity,
      'source_id', v_source_id,
      'event_type', p_event_type,
      'third_party_inventory_ids', to_jsonb(COALESCE(v_third_party_ids, ARRAY[]::UUID[])),
      'customer_credit_ledger_ids', to_jsonb(COALESCE(v_credit_ledger_ids, ARRAY[]::UUID[]))
    );

  IF p_idempotency_key IS NOT NULL THEN
    PERFORM public.complete_idempotency_key(
      p_idempotency_key,
      p_company_id,
      'financial_' || p_event_type || '_v2',
      v_result,
      TRUE
    );
  END IF;

  RETURN v_result;

EXCEPTION
  WHEN OTHERS THEN
    IF p_idempotency_key IS NOT NULL THEN
      BEGIN
        PERFORM public.complete_idempotency_key(
          p_idempotency_key,
          p_company_id,
          'financial_' || p_event_type || '_v2',
          jsonb_build_object(
            'success', false,
            'error', SQLERRM,
            'event_type', p_event_type
          ),
          FALSE
        );
      EXCEPTION WHEN OTHERS THEN
        NULL;
      END;
    END IF;
    RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_bank_voucher(p_request_id uuid, p_posted_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_bank_voucher(p_request_id uuid, p_posted_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_req RECORD;
    v_journal_id UUID;
    v_reference_type TEXT;
BEGIN
    SELECT * INTO v_req FROM public.bank_voucher_requests WHERE id = p_request_id FOR UPDATE;

    IF v_req IS NULL THEN
        RAISE EXCEPTION 'Request not found';
    END IF;

    IF v_req.status != 'approved' THEN
        RAISE EXCEPTION 'Request must be approved before posting. Current status: %', v_req.status;
    END IF;

    PERFORM validate_transaction_period(v_req.company_id, v_req.entry_date);

    v_reference_type := CASE WHEN v_req.voucher_type = 'deposit' THEN 'bank_deposit' ELSE 'cash_withdrawal' END;

    INSERT INTO public.journal_entries (
        company_id, branch_id, entry_date, description, reference_type, reference_id, status, cost_center_id, posted_by
    ) VALUES (
        v_req.company_id, v_req.branch_id, v_req.entry_date,
        COALESCE(v_req.description, '') || CASE WHEN v_req.reference_number IS NOT NULL THEN ' | المرجع: ' || v_req.reference_number ELSE '' END,
        v_reference_type, v_req.id,
        'posted', v_req.cost_center_id, p_posted_by
    ) RETURNING id INTO v_journal_id;

    -- v3.74.39: dropped rate_source from journal_entry_lines INSERT
    -- (column doesn't exist on jel).
    IF v_req.voucher_type = 'deposit' THEN
        INSERT INTO public.journal_entry_lines (
            journal_entry_id, account_id, debit_amount, credit_amount, description,
            original_debit, original_credit, original_currency, exchange_rate_used, exchange_rate_id,
            branch_id, cost_center_id
        ) VALUES
        (v_journal_id, v_req.account_id, v_req.base_amount, 0, 'إيداع', v_req.amount, 0, v_req.currency, v_req.exchange_rate, v_req.exchange_rate_id, v_req.branch_id, v_req.cost_center_id),
        (v_journal_id, v_req.counter_id, 0, v_req.base_amount, 'مقابل الإيداع', 0, v_req.amount, v_req.currency, v_req.exchange_rate, v_req.exchange_rate_id, v_req.branch_id, v_req.cost_center_id);
    ELSE
        INSERT INTO public.journal_entry_lines (
            journal_entry_id, account_id, debit_amount, credit_amount, description,
            original_debit, original_credit, original_currency, exchange_rate_used, exchange_rate_id,
            branch_id, cost_center_id
        ) VALUES
        (v_journal_id, v_req.counter_id, v_req.base_amount, 0, 'مقابل السحب', v_req.amount, 0, v_req.currency, v_req.exchange_rate, v_req.exchange_rate_id, v_req.branch_id, v_req.cost_center_id),
        (v_journal_id, v_req.account_id, 0, v_req.base_amount, 'سحب', 0, v_req.amount, v_req.currency, v_req.exchange_rate, v_req.exchange_rate_id, v_req.branch_id, v_req.cost_center_id);
    END IF;

    UPDATE public.bank_voucher_requests SET
        status = 'posted',
        posted_by = p_posted_by,
        posted_at = NOW(),
        journal_entry_id = v_journal_id
    WHERE id = p_request_id;

    RETURN jsonb_build_object('success', true, 'journal_entry_id', v_journal_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- post_bill_receipt_atomic(p_company_id uuid, p_bill_id uuid, p_bill_update jsonb, p_journal_entry jsonb, p_inventory_transactions jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_bill_receipt_atomic(p_company_id uuid, p_bill_id uuid, p_bill_update jsonb DEFAULT NULL::jsonb, p_journal_entry jsonb DEFAULT NULL::jsonb, p_inventory_transactions jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_result JSONB := '{}'::JSONB;
  v_journal_entry_id UUID;
  v_bill_exists BOOLEAN := FALSE;
BEGIN
  PERFORM set_config('app.allow_direct_post', 'true', true);

  SELECT EXISTS (
    SELECT 1
    FROM public.bills
    WHERE id = p_bill_id
      AND company_id = p_company_id
  )
  INTO v_bill_exists;

  IF NOT v_bill_exists THEN
    RAISE EXCEPTION 'Bill not found or does not belong to company';
  END IF;

  IF p_journal_entry IS NOT NULL THEN
    INSERT INTO public.journal_entries (
      company_id,
      branch_id,
      cost_center_id,
      entry_date,
      description,
      reference_type,
      reference_id,
      status
    ) VALUES (
      p_company_id,
      NULLIF(p_journal_entry->>'branch_id', '')::UUID,
      NULLIF(p_journal_entry->>'cost_center_id', '')::UUID,
      COALESCE(NULLIF(p_journal_entry->>'entry_date', '')::DATE, CURRENT_DATE),
      p_journal_entry->>'description',
      COALESCE(NULLIF(p_journal_entry->>'reference_type', ''), 'bill'),
      COALESCE(NULLIF(p_journal_entry->>'reference_id', '')::UUID, p_bill_id),
      COALESCE(NULLIF(p_journal_entry->>'status', ''), 'posted')
    )
    RETURNING id INTO v_journal_entry_id;

    IF p_journal_entry->'lines' IS NOT NULL THEN
      INSERT INTO public.journal_entry_lines (
        journal_entry_id,
        account_id,
        description,
        debit_amount,
        credit_amount,
        branch_id,
        cost_center_id
      )
      SELECT
        v_journal_entry_id,
        (line->>'account_id')::UUID,
        line->>'description',
        COALESCE((line->>'debit_amount')::NUMERIC, 0),
        COALESCE((line->>'credit_amount')::NUMERIC, 0),
        NULLIF(line->>'branch_id', '')::UUID,
        NULLIF(line->>'cost_center_id', '')::UUID
      FROM jsonb_array_elements(p_journal_entry->'lines') AS line;
    END IF;

    v_result := jsonb_set(v_result, '{journal_entry_id}', to_jsonb(v_journal_entry_id), true);
  END IF;

  IF p_inventory_transactions IS NOT NULL AND jsonb_array_length(p_inventory_transactions) > 0 THEN
    INSERT INTO public.inventory_transactions (
      company_id,
      product_id,
      transaction_type,
      quantity_change,
      unit_cost,
      total_cost,
      reference_id,
      reference_type,
      journal_entry_id,
      notes,
      branch_id,
      cost_center_id,
      warehouse_id,
      original_currency,
      original_unit_cost,
      original_total_cost,
      exchange_rate_used
    )
    SELECT
      p_company_id,
      NULLIF(tx->>'product_id', '')::UUID,
      tx->>'transaction_type',
      COALESCE((tx->>'quantity_change')::INTEGER, 0),
      NULLIF(tx->>'unit_cost', '')::NUMERIC,
      NULLIF(tx->>'total_cost', '')::NUMERIC,
      COALESCE(NULLIF(tx->>'reference_id', '')::UUID, p_bill_id),
      COALESCE(NULLIF(tx->>'reference_type', ''), 'bill'),
      COALESCE(NULLIF(tx->>'journal_entry_id', '')::UUID, v_journal_entry_id),
      tx->>'notes',
      NULLIF(tx->>'branch_id', '')::UUID,
      NULLIF(tx->>'cost_center_id', '')::UUID,
      NULLIF(tx->>'warehouse_id', '')::UUID,
      NULLIF(tx->>'original_currency', ''),
      NULLIF(tx->>'original_unit_cost', '')::NUMERIC,
      NULLIF(tx->>'original_total_cost', '')::NUMERIC,
      COALESCE(NULLIF(tx->>'exchange_rate_used', '')::NUMERIC, 1)
    FROM jsonb_array_elements(p_inventory_transactions) AS tx;

    v_result := jsonb_set(
      v_result,
      '{inventory_transaction_count}',
      to_jsonb(COALESCE(jsonb_array_length(p_inventory_transactions), 0)),
      true
    );
  END IF;

  IF p_bill_update IS NOT NULL THEN
    UPDATE public.bills
    SET
      status = COALESCE(NULLIF(p_bill_update->>'status', ''), status),
      receipt_status = COALESCE(NULLIF(p_bill_update->>'receipt_status', ''), receipt_status),
      received_by = COALESCE(NULLIF(p_bill_update->>'received_by', '')::UUID, received_by),
      received_at = COALESCE(NULLIF(p_bill_update->>'received_at', '')::TIMESTAMPTZ, received_at),
      updated_at = NOW()
    WHERE id = p_bill_id
      AND company_id = p_company_id;
  END IF;

  PERFORM set_config('app.allow_direct_post', 'false', true);
  RETURN v_result;
EXCEPTION WHEN OTHERS THEN
  PERFORM set_config('app.allow_direct_post', 'false', true);
  RAISE EXCEPTION 'Bill receipt posting failed: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_commission_atomic(p_commission_id uuid, p_expense_account_id uuid, p_payable_account_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_commission_atomic(p_commission_id uuid, p_expense_account_id uuid, p_payable_account_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_comm RECORD;
  v_journal_id UUID;
BEGIN
  -- 1. Get Commission & Validate
  SELECT * INTO v_comm FROM public.employee_commissions WHERE id = p_commission_id;
  IF v_comm IS NULL THEN RAISE EXCEPTION 'Commission Record not found'; END IF;
  
  IF v_comm.status != 'approved' THEN
    RAISE EXCEPTION 'Commission must be Approved before Posting';
  END IF;

  -- 2. Validate Period Locking (Use End Date as Accrual Date)
  PERFORM validate_transaction_period(v_comm.company_id, v_comm.period_end);

  -- 3. Create Journal Entry
  INSERT INTO public.journal_entries (
    company_id, entry_date, description, reference_type, reference_id, 
    status, posted_by, posted_at
  ) VALUES (
    v_comm.company_id, v_comm.period_end, 'Sales Commission Accrual - ' || v_comm.period_end, 
    'commission_accrual', p_commission_id, 'posted', p_user_id, NOW()
  ) RETURNING id INTO v_journal_id;

  -- Update Record
  UPDATE public.employee_commissions 
  SET journal_entry_id = v_journal_id, status = 'posted' 
  WHERE id = p_commission_id;

  -- 4. Lines
  -- Dr Commission Expense
  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount, cost_center_id
  ) VALUES (
    v_journal_id, p_expense_account_id, 'Commission Exp - ' || (SELECT name FROM employees WHERE id = v_comm.employee_id),
    v_comm.commission_amount, 0, (SELECT cost_center_id FROM employees WHERE id = v_comm.employee_id)
  );

  -- Cr Commission Payable
  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount
  ) VALUES (
    v_journal_id, p_payable_account_id, 'Commission Payable', 0, v_comm.commission_amount
  );
  
  -- 5. Ledger (Already populated during calculation? Or here? Let's assume Ledger tracks detail, so header post just locks it).
  -- Ideally Ledger is populated at Calculation time.
  
  RETURN jsonb_build_object('success', true, 'journal_entry_id', v_journal_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- post_commission_run_atomic(p_commission_run_id uuid, p_expense_account_id uuid, p_payable_account_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_commission_run_atomic(p_commission_run_id uuid, p_expense_account_id uuid, p_payable_account_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
    v_run RECORD;
    v_journal_id UUID;
    v_total_commission DECIMAL(15,2) := 0;
    v_total_clawbacks DECIMAL(15,2) := 0;
    v_net_commission DECIMAL(15,2) := 0;
BEGIN
    SELECT * INTO v_run FROM commission_runs WHERE id = p_commission_run_id;
    
    IF v_run IS NULL THEN
        RAISE EXCEPTION 'Commission run not found';
    END IF;
    
    -- Idempotency check
    IF v_run.status = 'posted' OR v_run.status = 'paid' THEN
        RETURN jsonb_build_object(
            'success', TRUE,
            'message', 'Already posted',
            'journal_entry_id', v_run.journal_entry_id,
            'net_commission', v_run.net_commission
        );
    END IF;
    
    PERFORM validate_commission_run_transition(p_commission_run_id, 'posted');
    PERFORM validate_transaction_period(v_run.company_id, v_run.period_end);
    
    SELECT 
        COALESCE(SUM(amount) FILTER (WHERE is_clawback = FALSE), 0),
        COALESCE(SUM(ABS(amount)) FILTER (WHERE is_clawback = TRUE), 0),
        COALESCE(SUM(amount), 0)
    INTO v_total_commission, v_total_clawbacks, v_net_commission
    FROM commission_ledger
    WHERE commission_run_id = p_commission_run_id;
    
    INSERT INTO journal_entries (
        company_id, entry_date, description, reference_type, reference_id,
        status, posted_by, posted_at
    ) VALUES (
        v_run.company_id, v_run.period_end,
        'Sales Commission Accrual - ' || v_run.period_start || ' to ' || v_run.period_end,
        'commission_run', p_commission_run_id, 'posted', p_user_id, NOW()
    ) RETURNING id INTO v_journal_id;
    
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, description, debit_amount, credit_amount)
    VALUES (v_journal_id, p_expense_account_id, 'Commission Expense', v_net_commission, 0);
    
    INSERT INTO journal_entry_lines (journal_entry_id, account_id, description, debit_amount, credit_amount)
    VALUES (v_journal_id, p_payable_account_id, 'Commission Payable', 0, v_net_commission);
    
    UPDATE commission_runs
    SET status = 'posted', journal_entry_id = v_journal_id, posted_by = p_user_id, posted_at = NOW(),
        total_commission = v_total_commission, total_clawbacks = v_total_clawbacks, net_commission = v_net_commission
    WHERE id = p_commission_run_id;
    
    UPDATE commission_ledger
    SET status = 'posted', journal_entry_id = v_journal_id
    WHERE commission_run_id = p_commission_run_id;
    
    RETURN jsonb_build_object('success', TRUE, 'journal_entry_id', v_journal_id, 'net_commission', v_net_commission);
END;
$function$
;

-- ---------------------------------------------------------------
-- post_depreciation(p_schedule_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_depreciation(p_schedule_id uuid, p_user_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_schedule_id UUID;
  v_asset_id UUID;
  v_period_number INTEGER;
  v_period_date DATE;
  v_depreciation_amount DECIMAL(15,2);
  v_accumulated_depreciation DECIMAL(15,2);
  v_book_value DECIMAL(15,2);
  v_status TEXT;
  v_asset_company_id UUID;
  v_asset_name TEXT;
  v_asset_depreciation_expense_account_id UUID;
  v_asset_accumulated_depreciation_account_id UUID;
  v_asset_salvage_value DECIMAL(15,2);
  v_asset_branch_id UUID;
  v_asset_cost_center_id UUID;
  v_journal_id UUID;
  v_base_ccy TEXT;
BEGIN
  SELECT id, asset_id, period_number, period_date,
         depreciation_amount, accumulated_depreciation, book_value, status
    INTO v_schedule_id, v_asset_id, v_period_number, v_period_date,
         v_depreciation_amount, v_accumulated_depreciation, v_book_value, v_status
    FROM depreciation_schedules WHERE id = p_schedule_id;

  IF v_schedule_id IS NULL THEN RAISE EXCEPTION 'Depreciation schedule not found'; END IF;
  IF v_status = 'posted' THEN RAISE EXCEPTION 'Already posted'; END IF;

  SELECT company_id, name, depreciation_expense_account_id,
         accumulated_depreciation_account_id, salvage_value,
         branch_id, cost_center_id
    INTO v_asset_company_id, v_asset_name,
         v_asset_depreciation_expense_account_id,
         v_asset_accumulated_depreciation_account_id, v_asset_salvage_value,
         v_asset_branch_id, v_asset_cost_center_id
    FROM fixed_assets WHERE id = v_asset_id;

  IF v_asset_company_id IS NULL THEN RAISE EXCEPTION 'Asset not found'; END IF;
  IF v_asset_depreciation_expense_account_id IS NULL THEN RAISE EXCEPTION 'Depreciation expense account missing'; END IF;
  IF v_asset_accumulated_depreciation_account_id IS NULL THEN RAISE EXCEPTION 'Accumulated depreciation account missing'; END IF;

  -- v3.74.564 — financial period lock
  BEGIN
    PERFORM public.require_open_financial_period_db(v_asset_company_id, v_period_date);
  EXCEPTION WHEN undefined_function THEN NULL; END;

  SELECT base_currency INTO v_base_ccy FROM companies WHERE id = v_asset_company_id;
  v_base_ccy := UPPER(COALESCE(v_base_ccy, 'EGP'));

  INSERT INTO journal_entries (
    company_id, branch_id, cost_center_id,
    entry_date, description, reference_type, reference_id, status
  ) VALUES (
    v_asset_company_id, v_asset_branch_id, v_asset_cost_center_id,
    v_period_date,
    'إهلاك أصل: ' || v_asset_name || ' - فترة ' || v_period_number,
    'depreciation', v_asset_id, 'draft'
  ) RETURNING id INTO v_journal_id;

  -- v3.74.564 — write IAS 21 columns too
  INSERT INTO journal_entry_lines (
    journal_entry_id, account_id, description,
    debit_amount, credit_amount,
    original_debit, original_credit, original_currency,
    exchange_rate_used,
    branch_id, cost_center_id
  ) VALUES (
    v_journal_id, v_asset_depreciation_expense_account_id,
    'مصروف إهلاك: ' || v_asset_name,
    v_depreciation_amount, 0,
    v_depreciation_amount, 0, v_base_ccy,
    1,
    v_asset_branch_id, v_asset_cost_center_id
  ), (
    v_journal_id, v_asset_accumulated_depreciation_account_id,
    'مجمع إهلاك: ' || v_asset_name,
    0, v_depreciation_amount,
    0, v_depreciation_amount, v_base_ccy,
    1,
    v_asset_branch_id, v_asset_cost_center_id
  );

  -- v3.74.564 — post explicitly (triggers balance check)
  UPDATE journal_entries SET status = 'posted' WHERE id = v_journal_id;

  UPDATE depreciation_schedules
     SET status = 'posted', journal_entry_id = v_journal_id,
         posted_by = p_user_id, posted_at = CURRENT_TIMESTAMP
   WHERE id = p_schedule_id;

  UPDATE fixed_assets
     SET accumulated_depreciation = v_accumulated_depreciation,
         book_value = v_book_value,
         status = CASE WHEN v_book_value <= v_asset_salvage_value THEN 'fully_depreciated' ELSE 'active' END,
         updated_at = CURRENT_TIMESTAMP, updated_by = p_user_id
   WHERE id = v_asset_id;

  RETURN v_journal_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_invoice_atomic_v2(p_company_id uuid, p_invoice_id uuid, p_inventory_transactions jsonb, p_cogs_transactions jsonb, p_fifo_consumptions jsonb, p_journal_entries jsonb, p_update_source jsonb, p_effective_date date, p_actor_id uuid, p_idempotency_key text, p_request_hash text, p_trace_metadata jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_invoice_atomic_v2(p_company_id uuid, p_invoice_id uuid, p_inventory_transactions jsonb DEFAULT NULL::jsonb, p_cogs_transactions jsonb DEFAULT NULL::jsonb, p_fifo_consumptions jsonb DEFAULT NULL::jsonb, p_journal_entries jsonb DEFAULT NULL::jsonb, p_update_source jsonb DEFAULT NULL::jsonb, p_effective_date date DEFAULT NULL::date, p_actor_id uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text, p_request_hash text DEFAULT NULL::text, p_trace_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  RETURN public.post_accounting_event_v2(
    p_event_type             => 'invoice_posting',
    p_company_id             => p_company_id,
    p_inventory_transactions => p_inventory_transactions,
    p_cogs_transactions      => p_cogs_transactions,
    p_fifo_consumptions      => p_fifo_consumptions,
    p_journal_entries        => p_journal_entries,
    p_update_source          => p_update_source,
    p_source_entity          => 'invoice',
    p_source_id              => p_invoice_id,
    p_effective_date         => p_effective_date,
    p_actor_id               => p_actor_id,
    p_idempotency_key        => p_idempotency_key,
    p_request_hash           => p_request_hash,
    p_trace_metadata         => p_trace_metadata
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- post_manual_journal_draft(p_journal_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_manual_journal_draft(p_journal_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_je   record;
  v_role text;
BEGIN
  SELECT * INTO v_je FROM public.journal_entries WHERE id = p_journal_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'JOURNAL_NOT_FOUND'; END IF;
  IF v_je.status <> 'draft' THEN RAISE EXCEPTION 'NOT_DRAFT: status=%', v_je.status; END IF;
  IF v_je.reference_type <> 'manual_entry' THEN RAISE EXCEPTION 'NOT_MANUAL_ENTRY'; END IF;

  SELECT role INTO v_role FROM public.company_members
   WHERE company_id = v_je.company_id AND user_id = p_user_id LIMIT 1;
  IF NOT (COALESCE(v_role,'') IN ('owner','general_manager','admin')) THEN
    RAISE EXCEPTION 'FORBIDDEN: يحتاج مالك/مدير عام/مشرف';
  END IF;

  IF v_je.created_by IS NOT NULL AND v_je.created_by = p_user_id
     AND COALESCE(v_role,'') NOT IN ('owner','general_manager') THEN
    RAISE EXCEPTION 'SOD_VIOLATION: منشِئ القَيد لا يَستَطيع نَشرَه';
  END IF;

  PERFORM public.require_open_financial_period_db(v_je.company_id, v_je.entry_date);

  UPDATE public.journal_entries
     SET status = 'posted', posted_by = p_user_id, posted_at = NOW()
   WHERE id = p_journal_id;

  RETURN jsonb_build_object('success', true, 'journal_id', p_journal_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- post_payroll_atomic(p_company_id uuid, p_payroll_run_id uuid, p_payment_account_id uuid, p_expense_account_id uuid, p_payment_date date, p_year integer, p_month integer, p_created_by uuid, p_idempotency_key text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_payroll_atomic(p_company_id uuid, p_payroll_run_id uuid, p_payment_account_id uuid, p_expense_account_id uuid, p_payment_date date, p_year integer, p_month integer, p_created_by uuid, p_idempotency_key text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_total              NUMERIC(15,2) := 0;
  v_entry_id           UUID;
  v_period_locked      BOOLEAN := FALSE;
  v_period_name        TEXT;
  v_existing_entry     UUID;
  v_idempotency_result JSONB;
  v_description        TEXT;
BEGIN
  IF p_idempotency_key IS NOT NULL THEN
    v_idempotency_result := public.check_and_claim_idempotency_key(
      p_idempotency_key, p_company_id, 'payroll_pay', NULL, p_created_by);
    IF v_idempotency_result IS NOT NULL AND (v_idempotency_result->>'cached')::BOOLEAN THEN
      RETURN v_idempotency_result->'response';
    END IF;
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.accounting_periods
    WHERE company_id = p_company_id
      AND p_payment_date BETWEEN period_start AND period_end
      AND (is_locked = TRUE OR status IN ('closed','locked'))
  ) INTO v_period_locked;

  IF v_period_locked THEN
    SELECT period_name INTO v_period_name FROM public.accounting_periods
    WHERE company_id = p_company_id
      AND p_payment_date BETWEEN period_start AND period_end
      AND (is_locked = TRUE OR status IN ('closed','locked')) LIMIT 1;
    IF p_idempotency_key IS NOT NULL THEN
      PERFORM public.complete_idempotency_key(p_idempotency_key, p_company_id, 'payroll_pay',
        jsonb_build_object('error','PERIOD_LOCKED','period',v_period_name), FALSE);
    END IF;
    RAISE EXCEPTION 'PERIOD_LOCKED: الفترة "%" مقفلة', COALESCE(v_period_name, p_payment_date::TEXT)
      USING ERRCODE = 'P0002';
  END IF;

  SELECT id INTO v_existing_entry FROM public.journal_entries
  WHERE company_id = p_company_id AND reference_type = 'payroll_payment'
    AND reference_id = p_payroll_run_id
    AND (is_deleted IS NULL OR is_deleted = FALSE) AND deleted_at IS NULL LIMIT 1;

  IF v_existing_entry IS NOT NULL THEN
    IF p_idempotency_key IS NOT NULL THEN
      PERFORM public.complete_idempotency_key(p_idempotency_key, p_company_id, 'payroll_pay',
        jsonb_build_object('ok',TRUE,'entry_id',v_existing_entry,'idempotent',TRUE), TRUE);
    END IF;
    RETURN jsonb_build_object('ok',TRUE,'entry_id',v_existing_entry,
      'message','تم صرف هذه الدفعة مسبقاً','idempotent',TRUE);
  END IF;

  SELECT COALESCE(SUM(net_salary), 0) INTO v_total
  FROM public.payslips WHERE company_id = p_company_id AND payroll_run_id = p_payroll_run_id;

  IF v_total <= 0 THEN
    IF p_idempotency_key IS NOT NULL THEN
      PERFORM public.complete_idempotency_key(p_idempotency_key, p_company_id, 'payroll_pay',
        jsonb_build_object('error','NO_PAYSLIPS'), FALSE);
    END IF;
    RAISE EXCEPTION 'NO_PAYSLIPS: لا توجد كشوف مرتبات للصرف' USING ERRCODE = 'P0003';
  END IF;

  v_description := format('صرف مرتبات %s-%s', p_year, LPAD(p_month::TEXT,2,'0'));
  INSERT INTO public.journal_entries
    (company_id, entry_date, description, reference_type, reference_id, status, posted_by, posted_at)
  VALUES (p_company_id, p_payment_date, v_description, 'payroll_payment', p_payroll_run_id, 'posted', p_created_by, NOW())
  RETURNING id INTO v_entry_id;

  INSERT INTO public.journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
  VALUES
    (v_entry_id, p_expense_account_id, v_total, 0,      'مرتبات موظفين - 6110'),
    (v_entry_id, p_payment_account_id, 0,       v_total, 'صرف من الحساب');

  -- v3.74.40: removed the broken `UPDATE payroll_runs SET status='paid',
  -- updated_at=NOW()` — neither column exists on payroll_runs. The
  -- journal entry remains the record-of-truth for the payment; if
  -- status tracking is needed later, expand the payroll_runs schema
  -- first.

  IF p_idempotency_key IS NOT NULL THEN
    PERFORM public.complete_idempotency_key(p_idempotency_key, p_company_id, 'payroll_pay',
      jsonb_build_object('ok',TRUE,'entry_id',v_entry_id,'total',v_total), TRUE);
  END IF;

  RETURN jsonb_build_object('ok',TRUE,'entry_id',v_entry_id,'total',v_total,'description',v_description);

EXCEPTION WHEN OTHERS THEN
  IF p_idempotency_key IS NOT NULL THEN
    BEGIN
      PERFORM public.complete_idempotency_key(p_idempotency_key, p_company_id, 'payroll_pay',
        jsonb_build_object('error', SQLERRM), FALSE);
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END IF;
  RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_payroll_run_atomic(p_payroll_run_id uuid, p_expense_account_id uuid, p_payable_account_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_payroll_run_atomic(p_payroll_run_id uuid, p_expense_account_id uuid, p_payable_account_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_run RECORD;
  v_company_id UUID;
  v_journal_id UUID;
  v_item RECORD;
  v_employee_cost_center UUID;
BEGIN
  -- 1. Get Run Info & Validate Status
  SELECT * INTO v_run FROM public.payroll_runs WHERE id = p_payroll_run_id;
  
  IF v_run IS NULL THEN RAISE EXCEPTION 'Payroll Run not found'; END IF;
  v_company_id := v_run.company_id;
  
  IF v_run.status != 'approved' THEN
    RAISE EXCEPTION 'Payroll Run must be Approved before Posting (Current Status: %)', v_run.status;
  END IF;

  -- 2. Validate Period Locking (STRICT)
  PERFORM validate_transaction_period(v_company_id, v_run.pay_date);

  -- 3. Create Journal Entry Header
  INSERT INTO public.journal_entries (
    company_id, entry_date, description, reference_type, reference_id, 
    status, posted_by, posted_at
  ) VALUES (
    v_company_id, v_run.pay_date, 'Payroll Run - ' || v_run.period_start || ' to ' || v_run.period_end, 
    'payroll_run', p_payroll_run_id, 'posted', p_user_id, NOW()
  ) RETURNING id INTO v_journal_id;
  
  -- Update Run
  UPDATE public.payroll_runs 
  SET journal_entry_id = v_journal_id, status = 'posted', posted_by = p_user_id 
  WHERE id = p_payroll_run_id;

  -- 4. Insert Journal Lines (Aggregated by Cost Center logic is ideal, but for now 1 line per item is safer for detail)
  -- Or better: 
  -- Debit Salaries Expense (Grouped by Employee Cost Center)
  -- Credit Payroll Payable (Total)

  FOR v_item IN SELECT * FROM public.payroll_items WHERE payroll_run_id = p_payroll_run_id
  LOOP
     -- Debit Expense
     INSERT INTO public.journal_entry_lines (
       journal_entry_id, account_id, description, debit_amount, credit_amount, 
       branch_id, cost_center_id
     ) VALUES (
       v_journal_id, p_expense_account_id, 
       COALESCE(v_item.component_name, 'Basic Salary') || ' - ' || (SELECT name FROM employees WHERE id = v_item.employee_id),
       CASE WHEN v_item.type = 'earning' THEN v_item.amount ELSE 0 END, -- Expense
       CASE WHEN v_item.type = 'deduction' THEN 0 ELSE 0 END, -- Deductions usually credit an asset/liability, simpler model: assume NET PAYABLE logic for now, or expense reduction? Standard: Deductions are Credits to Liability/Asset.
       NULL, v_item.cost_center_id
     );
     
     -- Handle Deduction: If Type is Deduction, we Credit the Expense? Or Credit a specific liability? 
     -- SIMPLIFICATION: For this atomic function, let's assume all items are Expenses (Earnings). 
     -- Deductions need a separate mapping account. 
     -- For V1: We debit Expense for Earnings. We Don't handle Deductions logic deeply here to keep SQL simple. Assumes 'Net Pay' model.
     
     -- 5. Insert into Ledger
     INSERT INTO public.payroll_ledger (
        company_id, employee_id, payroll_run_id, transaction_date, 
        period_start, period_end, category, amount, journal_entry_id
     ) VALUES (
        v_company_id, v_item.employee_id, p_payroll_run_id, v_run.pay_date,
        v_run.period_start, v_run.period_end, v_item.type, v_item.amount, v_journal_id
     );
  END LOOP;

  -- Credit Payable (Total Net)
  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount
  ) VALUES (
    v_journal_id, p_payable_account_id, 'Net Payroll Payable', 0, v_run.total_net
  );

  RETURN jsonb_build_object('success', true, 'journal_entry_id', v_journal_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- post_production_issue_journal_entry()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_production_issue_journal_entry()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_inventory_account uuid;
  v_wip_account uuid;
  v_cost numeric;
  v_je_id uuid;
  v_event RECORD;
BEGIN
  -- Resolve the cost actually consumed from FIFO for this issue line.
  SELECT COALESCE(SUM(total_cost), 0)
  INTO v_cost
  FROM fifo_lot_consumptions
  WHERE company_id = NEW.company_id
    AND reference_id = NEW.id
    AND reference_type IN ('production_issue_line', 'production_issue');

  -- Fallback if FIFO consumption rows are not in place yet (defensive only).
  IF v_cost IS NULL OR v_cost <= 0 THEN
    SELECT COALESCE(p.cost_price, 0) * COALESCE(NEW.issued_qty, 0)
    INTO v_cost FROM products p WHERE p.id = NEW.product_id;
  END IF;

  IF v_cost IS NULL OR v_cost <= 0 THEN RETURN NEW; END IF;

  SELECT id INTO v_inventory_account FROM chart_of_accounts
   WHERE company_id = NEW.company_id AND sub_type = 'inventory' AND COALESCE(is_active, true) LIMIT 1;
  SELECT id INTO v_wip_account FROM chart_of_accounts
   WHERE company_id = NEW.company_id AND sub_type IN ('work_in_process', 'wip')
     AND COALESCE(is_active, true) LIMIT 1;
  IF v_inventory_account IS NULL OR v_wip_account IS NULL THEN RETURN NEW; END IF;

  SELECT id, posted_at, event_number INTO v_event
  FROM production_order_issue_events WHERE id = NEW.issue_event_id;

  v_je_id := public._production_get_or_create_je(
    NEW.company_id, NEW.branch_id, NEW.cost_center_id,
    'production_issue', NEW.issue_event_id,
    COALESCE(v_event.posted_at::date, CURRENT_DATE),
    'صرف إنتاج ' || COALESCE(v_event.event_number, NEW.issue_event_id::text)
  );

  PERFORM set_config('app.allow_direct_post', 'true', true);
  INSERT INTO journal_entry_lines (
    journal_entry_id, account_id, debit_amount, credit_amount,
    description, branch_id, cost_center_id
  ) VALUES (
    v_je_id, v_wip_account, v_cost, 0,
    'تكلفة خامات لإنتاج تحت التشغيل', NEW.branch_id, NEW.cost_center_id
  );
  INSERT INTO journal_entry_lines (
    journal_entry_id, account_id, debit_amount, credit_amount,
    description, branch_id, cost_center_id
  ) VALUES (
    v_je_id, v_inventory_account, 0, v_cost,
    'صرف خامات للإنتاج', NEW.branch_id, NEW.cost_center_id
  );
  PERFORM set_config('app.allow_direct_post', 'false', true);

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_production_receipt_journal_entry()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_production_receipt_journal_entry()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_inventory_account uuid;
  v_wip_account uuid;
  v_cost numeric;
  v_je_id uuid;
  v_event RECORD;
BEGIN
  SELECT (COALESCE(unit_cost, 0) * COALESCE(NEW.received_qty, 0))
  INTO v_cost
  FROM fifo_cost_lots WHERE id = NEW.fifo_cost_lot_id;

  IF v_cost IS NULL OR v_cost <= 0 THEN RETURN NEW; END IF;

  SELECT id INTO v_inventory_account FROM chart_of_accounts
   WHERE company_id = NEW.company_id AND sub_type = 'inventory' AND COALESCE(is_active, true) LIMIT 1;
  SELECT id INTO v_wip_account FROM chart_of_accounts
   WHERE company_id = NEW.company_id AND sub_type IN ('work_in_process', 'wip')
     AND COALESCE(is_active, true) LIMIT 1;
  IF v_inventory_account IS NULL OR v_wip_account IS NULL THEN RETURN NEW; END IF;

  SELECT id, posted_at, event_number INTO v_event
  FROM production_order_receipt_events WHERE id = NEW.receipt_event_id;

  v_je_id := public._production_get_or_create_je(
    NEW.company_id, NEW.branch_id, NEW.cost_center_id,
    'production_receipt', NEW.receipt_event_id,
    COALESCE(v_event.posted_at::date, CURRENT_DATE),
    'إنتاج تام ' || COALESCE(v_event.event_number, NEW.receipt_event_id::text)
  );

  PERFORM set_config('app.allow_direct_post', 'true', true);
  INSERT INTO journal_entry_lines (
    journal_entry_id, account_id, debit_amount, credit_amount,
    description, branch_id, cost_center_id
  ) VALUES (
    v_je_id, v_inventory_account, v_cost, 0,
    'استلام إنتاج تام في المخزون', NEW.branch_id, NEW.cost_center_id
  );
  INSERT INTO journal_entry_lines (
    journal_entry_id, account_id, debit_amount, credit_amount,
    description, branch_id, cost_center_id
  ) VALUES (
    v_je_id, v_wip_account, 0, v_cost,
    'إقفال تكلفة الإنتاج تحت التشغيل', NEW.branch_id, NEW.cost_center_id
  );
  PERFORM set_config('app.allow_direct_post', 'false', true);

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_purchase_transaction(p_transaction_type text, p_company_id uuid, p_bill_id uuid, p_bill_data jsonb, p_bill_items jsonb, p_bill_update jsonb, p_journal_entry jsonb, p_inventory_transactions jsonb, p_purchase_return jsonb, p_vendor_credit jsonb, p_vendor_credit_items jsonb, p_update_source jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_purchase_transaction(p_transaction_type text, p_company_id uuid, p_bill_id uuid DEFAULT NULL::uuid, p_bill_data jsonb DEFAULT NULL::jsonb, p_bill_items jsonb DEFAULT NULL::jsonb, p_bill_update jsonb DEFAULT NULL::jsonb, p_journal_entry jsonb DEFAULT NULL::jsonb, p_inventory_transactions jsonb DEFAULT NULL::jsonb, p_purchase_return jsonb DEFAULT NULL::jsonb, p_vendor_credit jsonb DEFAULT NULL::jsonb, p_vendor_credit_items jsonb DEFAULT NULL::jsonb, p_update_source jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_result              JSONB := '{}';
  v_je_id               UUID;
  v_bill_id             UUID;
  v_pr_id               UUID;
  v_vc_id               UUID;
  item_update           JSONB;
  inv_tx                JSONB;
  v_bill_exists         BOOLEAN;
BEGIN
  -- Allow direct journal_entry INSERT as posted (bypass enforce_je_integrity trigger)
  PERFORM set_config('app.allow_direct_post', 'true', true);

  -- ── POST_BILL (Receipt Approval - Inventory + Journal) ───────────────────────
  IF p_transaction_type = 'post_bill' THEN

    IF p_bill_id IS NOT NULL THEN
      SELECT EXISTS(SELECT 1 FROM bills WHERE id = p_bill_id AND company_id = p_company_id) INTO v_bill_exists;
      IF NOT v_bill_exists THEN
        RAISE EXCEPTION 'Bill not found or does not belong to company';
      END IF;
    END IF;

    -- A. Insert Inventory Transactions
    IF p_inventory_transactions IS NOT NULL AND jsonb_array_length(p_inventory_transactions) > 0 THEN
      INSERT INTO inventory_transactions (
        company_id, branch_id, warehouse_id, cost_center_id,
        product_id, transaction_type, quantity_change,
        unit_cost, total_cost, reference_id, reference_type,
        journal_entry_id, notes, transaction_date
      )
      SELECT
        p_company_id,
        NULLIF(t->>'branch_id', '')::UUID,
        NULLIF(t->>'warehouse_id', '')::UUID,
        NULLIF(t->>'cost_center_id', '')::UUID,
        NULLIF(t->>'product_id', '')::UUID,
        t->>'transaction_type',
        COALESCE((t->>'quantity_change')::NUMERIC, 0),
        NULLIF(t->>'unit_cost', '')::NUMERIC,
        NULLIF(t->>'total_cost', '')::NUMERIC,
        COALESCE(NULLIF(t->>'reference_id', '')::UUID, p_bill_id),
        COALESCE(NULLIF(t->>'reference_type', ''), 'bill'),
        NULLIF(t->>'journal_entry_id', '')::UUID,
        t->>'notes',
        COALESCE(NULLIF(t->>'transaction_date', '')::DATE, CURRENT_DATE)
      FROM jsonb_array_elements(p_inventory_transactions) AS t;
    END IF;

    -- B. Insert Journal Entry
    IF p_journal_entry IS NOT NULL THEN
      INSERT INTO journal_entries (
        company_id, branch_id, cost_center_id,
        entry_date, description, reference_type, reference_id,
        status
      ) VALUES (
        p_company_id,
        NULLIF(p_journal_entry->>'branch_id', '')::UUID,
        NULLIF(p_journal_entry->>'cost_center_id', '')::UUID,
        COALESCE(NULLIF(p_journal_entry->>'entry_date', '')::DATE, CURRENT_DATE),
        p_journal_entry->>'description',
        COALESCE(NULLIF(p_journal_entry->>'reference_type', ''), 'bill'),
        COALESCE(NULLIF(p_journal_entry->>'reference_id', '')::UUID, p_bill_id),
        COALESCE(NULLIF(p_journal_entry->>'status', ''), 'posted')
      ) RETURNING id INTO v_je_id;

      IF p_journal_entry->'lines' IS NOT NULL THEN
        INSERT INTO journal_entry_lines (
          journal_entry_id, account_id, description,
          debit_amount, credit_amount,
          branch_id, cost_center_id
        )
        SELECT
          v_je_id,
          (l->>'account_id')::UUID,
          l->>'description',
          COALESCE((l->>'debit_amount')::NUMERIC, 0),
          COALESCE((l->>'credit_amount')::NUMERIC, 0),
          NULLIF(l->>'branch_id', '')::UUID,
          NULLIF(l->>'cost_center_id', '')::UUID
        FROM jsonb_array_elements(p_journal_entry->'lines') AS l;
      END IF;

      v_result := jsonb_set(v_result, '{journal_entry_id}', to_jsonb(v_je_id));
      UPDATE bills SET updated_at = NOW() WHERE id = p_bill_id;
    END IF;

    -- C. Update Bill Status (MODIFIED to include receipt fields)
    IF p_bill_update IS NOT NULL AND p_bill_id IS NOT NULL THEN
      UPDATE bills
      SET
        status = COALESCE(NULLIF(p_bill_update->>'status', ''), status),
        receipt_status = COALESCE(NULLIF(p_bill_update->>'receipt_status', ''), receipt_status),
        received_by = COALESCE(NULLIF(p_bill_update->>'received_by', '')::uuid, received_by),
        received_at = COALESCE(NULLIF(p_bill_update->>'received_at', '')::timestamptz, received_at),
        updated_at = NOW()
      WHERE id = p_bill_id;
    END IF;

  -- ── BILL CREATION ─────────────────────────────────────────────────────────
  ELSIF p_transaction_type = 'bill' THEN

    INSERT INTO bills (
      company_id, supplier_id, branch_id, cost_center_id, warehouse_id,
      bill_number, bill_date, due_date, status,
      subtotal, tax_amount, total_amount, paid_amount, notes
    )
    SELECT
      p_company_id,
      (p_bill_data->>'supplier_id')::UUID,
      NULLIF(p_bill_data->>'branch_id', '')::UUID,
      NULLIF(p_bill_data->>'cost_center_id', '')::UUID,
      NULLIF(p_bill_data->>'warehouse_id', '')::UUID,
      p_bill_data->>'bill_number',
      (p_bill_data->>'bill_date')::DATE,
      NULLIF(p_bill_data->>'due_date', '')::DATE,
      COALESCE(NULLIF(p_bill_data->>'status', ''), 'draft'),
      COALESCE((p_bill_data->>'subtotal')::NUMERIC, 0),
      COALESCE((p_bill_data->>'tax_amount')::NUMERIC, 0),
      COALESCE((p_bill_data->>'total_amount')::NUMERIC, 0),
      0, p_bill_data->>'notes'
    RETURNING id INTO v_bill_id;

    v_result := jsonb_set(v_result, '{bill_id}', to_jsonb(v_bill_id));

    IF p_bill_items IS NOT NULL THEN
      INSERT INTO bill_items (
        bill_id, product_id, description, quantity, unit_price,
        tax_rate, discount_percent, line_total
      )
      SELECT v_bill_id,
        NULLIF(bi->>'product_id', '')::UUID, bi->>'description',
        COALESCE((bi->>'quantity')::NUMERIC, 0), COALESCE((bi->>'unit_price')::NUMERIC, 0),
        COALESCE((bi->>'tax_rate')::NUMERIC, 0), COALESCE((bi->>'discount_percent')::NUMERIC, 0),
        COALESCE((bi->>'line_total')::NUMERIC, 0)
      FROM jsonb_array_elements(p_bill_items) AS bi;
    END IF;

    IF p_journal_entry IS NOT NULL THEN
      INSERT INTO journal_entries (
        company_id, branch_id, cost_center_id,
        entry_date, description, reference_id, reference_type, status
      ) VALUES (
        p_company_id,
        NULLIF(p_journal_entry->>'branch_id', '')::UUID,
        NULLIF(p_journal_entry->>'cost_center_id', '')::UUID,
        (p_journal_entry->>'entry_date')::DATE,
        p_journal_entry->>'description',
        v_bill_id, 'bill',
        COALESCE(NULLIF(p_journal_entry->>'status', ''), 'posted')
      ) RETURNING id INTO v_je_id;

      IF p_journal_entry->'lines' IS NOT NULL THEN
        INSERT INTO journal_entry_lines (
          journal_entry_id, account_id, description, debit_amount, credit_amount
        )
        SELECT v_je_id, (jl->>'account_id')::UUID, jl->>'description',
          COALESCE((jl->>'debit_amount')::NUMERIC, 0), COALESCE((jl->>'credit_amount')::NUMERIC, 0)
        FROM jsonb_array_elements(p_journal_entry->'lines') AS jl;
      END IF;

      UPDATE bills SET updated_at = NOW() WHERE id = v_bill_id;
      v_result := jsonb_set(v_result, '{journal_entry_id}', to_jsonb(v_je_id));
    END IF;

    IF p_inventory_transactions IS NOT NULL THEN
      INSERT INTO inventory_transactions (
        company_id, product_id, transaction_type, quantity_change,
        reference_id, reference_type, journal_entry_id, notes,
        branch_id, cost_center_id, warehouse_id, transaction_date
      )
      SELECT p_company_id, NULLIF(inv_tx->>'product_id', '')::UUID,
        inv_tx->>'transaction_type', COALESCE((inv_tx->>'quantity_change')::NUMERIC, 0),
        v_bill_id, 'bill', v_je_id, inv_tx->>'notes',
        NULLIF(inv_tx->>'branch_id', '')::UUID, NULLIF(inv_tx->>'cost_center_id', '')::UUID,
        NULLIF(inv_tx->>'warehouse_id', '')::UUID,
        COALESCE((inv_tx->>'transaction_date')::DATE, CURRENT_DATE)
      FROM jsonb_array_elements(p_inventory_transactions) AS inv_tx;
    END IF;

  -- ── PURCHASE RETURN ──────────────────────────────────────────────────────
  ELSIF p_transaction_type = 'purchase_return' THEN

    IF p_journal_entry IS NOT NULL THEN
      INSERT INTO journal_entries (
        company_id, branch_id, cost_center_id,
        entry_date, description, reference_id, reference_type, status
      ) VALUES (
        p_company_id,
        NULLIF(p_journal_entry->>'branch_id', '')::UUID,
        NULLIF(p_journal_entry->>'cost_center_id', '')::UUID,
        (p_journal_entry->>'entry_date')::DATE,
        p_journal_entry->>'description',
        p_bill_id, 'purchase_return',
        COALESCE(NULLIF(p_journal_entry->>'status', ''), 'posted')
      ) RETURNING id INTO v_je_id;

      IF p_journal_entry->'lines' IS NOT NULL THEN
        INSERT INTO journal_entry_lines (
          journal_entry_id, account_id, description, debit_amount, credit_amount
        )
        SELECT v_je_id, (jl->>'account_id')::UUID, jl->>'description',
          COALESCE((jl->>'debit_amount')::NUMERIC, 0), COALESCE((jl->>'credit_amount')::NUMERIC, 0)
        FROM jsonb_array_elements(p_journal_entry->'lines') AS jl;
      END IF;

      v_result := jsonb_set(v_result, '{journal_entry_id}', to_jsonb(v_je_id));
    END IF;

    IF p_purchase_return IS NOT NULL THEN
      INSERT INTO purchase_returns (
        company_id, supplier_id, bill_id, journal_entry_id,
        return_number, return_date, status, subtotal, tax_amount, total_amount,
        settlement_method, reason, notes, branch_id, cost_center_id, warehouse_id
      ) VALUES (
        p_company_id, NULLIF(p_purchase_return->>'supplier_id', '')::UUID,
        p_bill_id, v_je_id, p_purchase_return->>'return_number',
        (p_purchase_return->>'return_date')::DATE,
        COALESCE(NULLIF(p_purchase_return->>'status', ''), 'completed'),
        COALESCE((p_purchase_return->>'subtotal')::NUMERIC, 0),
        COALESCE((p_purchase_return->>'tax_amount')::NUMERIC, 0),
        COALESCE((p_purchase_return->>'total_amount')::NUMERIC, 0),
        p_purchase_return->>'settlement_method', p_purchase_return->>'reason',
        p_purchase_return->>'notes',
        NULLIF(p_purchase_return->>'branch_id', '')::UUID,
        NULLIF(p_purchase_return->>'cost_center_id', '')::UUID,
        NULLIF(p_purchase_return->>'warehouse_id', '')::UUID
      ) RETURNING id INTO v_pr_id;

      v_result := jsonb_set(v_result, '{purchase_return_id}', to_jsonb(v_pr_id));
      IF v_je_id IS NOT NULL THEN
        UPDATE journal_entries SET reference_id = v_pr_id WHERE id = v_je_id;
      END IF;
    END IF;

    IF p_vendor_credit IS NOT NULL THEN
      INSERT INTO vendor_credits (
        company_id, supplier_id, bill_id,
        source_purchase_return_id, source_purchase_invoice_id, journal_entry_id,
        credit_number, credit_date, status,
        subtotal, tax_amount, total_amount, applied_amount,
        branch_id, cost_center_id, warehouse_id, notes
      ) VALUES (
        p_company_id, NULLIF(p_vendor_credit->>'supplier_id', '')::UUID,
        p_bill_id, v_pr_id, p_bill_id, v_je_id,
        p_vendor_credit->>'credit_number',
        COALESCE((p_vendor_credit->>'credit_date')::DATE, CURRENT_DATE), 'open',
        COALESCE((p_vendor_credit->>'subtotal')::NUMERIC, 0),
        COALESCE((p_vendor_credit->>'tax_amount')::NUMERIC, 0),
        COALESCE((p_vendor_credit->>'total_amount')::NUMERIC, 0), 0,
        NULLIF(p_vendor_credit->>'branch_id', '')::UUID,
        NULLIF(p_vendor_credit->>'cost_center_id', '')::UUID,
        NULLIF(p_vendor_credit->>'warehouse_id', '')::UUID, p_vendor_credit->>'notes'
      ) RETURNING id INTO v_vc_id;

      IF p_vendor_credit_items IS NOT NULL THEN
        INSERT INTO vendor_credit_items (
          vendor_credit_id, product_id, description,
          quantity, unit_price, tax_rate, discount_percent, line_total
        )
        SELECT v_vc_id, NULLIF(vci->>'product_id', '')::UUID, vci->>'description',
          COALESCE((vci->>'quantity')::NUMERIC, 0), COALESCE((vci->>'unit_price')::NUMERIC, 0),
          COALESCE((vci->>'tax_rate')::NUMERIC, 0), COALESCE((vci->>'discount_percent')::NUMERIC, 0),
          COALESCE((vci->>'line_total')::NUMERIC, 0)
        FROM jsonb_array_elements(p_vendor_credit_items) AS vci;
      END IF;

      v_result := jsonb_set(v_result, '{vendor_credit_id}', to_jsonb(v_vc_id));
    END IF;

    IF p_inventory_transactions IS NOT NULL THEN
      INSERT INTO inventory_transactions (
        company_id, product_id, transaction_type, quantity_change,
        reference_id, reference_type, journal_entry_id, notes,
        branch_id, cost_center_id, warehouse_id, transaction_date
      )
      SELECT p_company_id, NULLIF(inv_tx->>'product_id', '')::UUID,
        inv_tx->>'transaction_type', COALESCE((inv_tx->>'quantity_change')::NUMERIC, 0),
        COALESCE(v_pr_id, p_bill_id), 'purchase_return', v_je_id, inv_tx->>'notes',
        NULLIF(inv_tx->>'branch_id', '')::UUID, NULLIF(inv_tx->>'cost_center_id', '')::UUID,
        NULLIF(inv_tx->>'warehouse_id', '')::UUID,
        COALESCE((inv_tx->>'transaction_date')::DATE, CURRENT_DATE)
      FROM jsonb_array_elements(p_inventory_transactions) AS inv_tx;
    END IF;

    IF p_bill_update IS NOT NULL AND p_bill_id IS NOT NULL THEN
      UPDATE bills
      SET
        returned_amount = COALESCE(NULLIF(p_bill_update->>'returned_amount', '')::NUMERIC, returned_amount),
        return_status = COALESCE(NULLIF(p_bill_update->>'return_status', ''), return_status),
        status = COALESCE(NULLIF(p_bill_update->>'status', ''), status),
        updated_at = NOW()
      WHERE id = p_bill_id;
    END IF;

    IF p_update_source->'bill_items_update' IS NOT NULL THEN
      FOR item_update IN
        SELECT * FROM jsonb_array_elements(p_update_source->'bill_items_update')
      LOOP
        UPDATE bill_items
        SET returned_quantity = COALESCE(returned_quantity, 0)
                              + COALESCE((item_update->>'returned_quantity')::NUMERIC, 0)
        WHERE id = (item_update->>'id')::UUID;
      END LOOP;
    END IF;

  END IF;

  RETURN v_result;

EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'Transaction failed: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- post_purchase_transaction(p_transaction_type text, p_company_id uuid, p_bill_data jsonb, p_bill_items jsonb, p_journal_entry jsonb, p_inventory_transactions jsonb, p_bill_id uuid, p_purchase_return jsonb, p_return_items jsonb, p_vendor_credit jsonb, p_vendor_credit_items jsonb, p_bill_update jsonb, p_update_source jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.post_purchase_transaction(p_transaction_type text, p_company_id uuid, p_bill_data jsonb DEFAULT NULL::jsonb, p_bill_items jsonb DEFAULT NULL::jsonb, p_journal_entry jsonb DEFAULT NULL::jsonb, p_inventory_transactions jsonb DEFAULT NULL::jsonb, p_bill_id uuid DEFAULT NULL::uuid, p_purchase_return jsonb DEFAULT NULL::jsonb, p_return_items jsonb DEFAULT NULL::jsonb, p_vendor_credit jsonb DEFAULT NULL::jsonb, p_vendor_credit_items jsonb DEFAULT NULL::jsonb, p_bill_update jsonb DEFAULT NULL::jsonb, p_update_source jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result              JSONB := '{}';
  v_je_id               UUID;
  v_bill_id             UUID;
  v_pr_id               UUID;
  v_vc_id               UUID;
  item_update           JSONB;
  inv_tx                JSONB;
  v_bill_exists         BOOLEAN;
BEGIN
  -- Allow direct journal_entry INSERT as posted (bypass enforce_je_integrity trigger)
  PERFORM set_config('app.allow_direct_post', 'true', true);

  -- ── POST_BILL (Receipt Approval - Inventory + Journal) ───────────────────────
  IF p_transaction_type = 'post_bill' THEN

    IF p_bill_id IS NOT NULL THEN
      SELECT EXISTS(SELECT 1 FROM bills WHERE id = p_bill_id AND company_id = p_company_id) INTO v_bill_exists;
      IF NOT v_bill_exists THEN
        RAISE EXCEPTION 'Bill not found or does not belong to company';
      END IF;
    END IF;

    -- A. Insert Inventory Transactions
    IF p_inventory_transactions IS NOT NULL AND jsonb_array_length(p_inventory_transactions) > 0 THEN
      INSERT INTO inventory_transactions (
        company_id, branch_id, warehouse_id, cost_center_id,
        product_id, transaction_type, quantity_change,
        unit_cost, total_cost, reference_id, reference_type,
        journal_entry_id, notes, transaction_date
      )
      SELECT
        p_company_id,
        NULLIF(t->>'branch_id', '')::UUID,
        NULLIF(t->>'warehouse_id', '')::UUID,
        NULLIF(t->>'cost_center_id', '')::UUID,
        NULLIF(t->>'product_id', '')::UUID,
        t->>'transaction_type',
        COALESCE((t->>'quantity_change')::NUMERIC, 0),
        NULLIF(t->>'unit_cost', '')::NUMERIC,
        NULLIF(t->>'total_cost', '')::NUMERIC,
        COALESCE(NULLIF(t->>'reference_id', '')::UUID, p_bill_id),
        COALESCE(NULLIF(t->>'reference_type', ''), 'bill'),
        NULLIF(t->>'journal_entry_id', '')::UUID,
        t->>'notes',
        COALESCE(NULLIF(t->>'transaction_date', '')::DATE, CURRENT_DATE)
      FROM jsonb_array_elements(p_inventory_transactions) AS t;
    END IF;

    -- B. Insert Journal Entry
    IF p_journal_entry IS NOT NULL THEN
      -- ✅ Check if journal entry already exists for this bill to prevent DUPLICATE_JOURNAL_VIOLATION
      SELECT id INTO v_je_id 
      FROM journal_entries 
      WHERE reference_id = p_bill_id 
        AND reference_type = COALESCE(NULLIF(p_journal_entry->>'reference_type', ''), 'bill')
        AND company_id = p_company_id
        AND (is_deleted IS NULL OR is_deleted = false)
      LIMIT 1;

      -- ✅ Only insert if it doesn't exist
      IF v_je_id IS NULL THEN
        INSERT INTO journal_entries (
          company_id, branch_id, cost_center_id,
          entry_date, description, reference_type, reference_id,
          status
        ) VALUES (
          p_company_id,
          NULLIF(p_journal_entry->>'branch_id', '')::UUID,
          NULLIF(p_journal_entry->>'cost_center_id', '')::UUID,
          COALESCE(NULLIF(p_journal_entry->>'entry_date', '')::DATE, CURRENT_DATE),
          p_journal_entry->>'description',
          COALESCE(NULLIF(p_journal_entry->>'reference_type', ''), 'bill'),
          COALESCE(NULLIF(p_journal_entry->>'reference_id', '')::UUID, p_bill_id),
          COALESCE(NULLIF(p_journal_entry->>'status', ''), 'posted')
        ) RETURNING id INTO v_je_id;

        IF p_journal_entry->'lines' IS NOT NULL THEN
          INSERT INTO journal_entry_lines (
            journal_entry_id, account_id, description,
            debit_amount, credit_amount,
            branch_id, cost_center_id
          )
          SELECT
            v_je_id,
            (l->>'account_id')::UUID,
            l->>'description',
            COALESCE((l->>'debit_amount')::NUMERIC, 0),
            COALESCE((l->>'credit_amount')::NUMERIC, 0),
            NULLIF(l->>'branch_id', '')::UUID,
            NULLIF(l->>'cost_center_id', '')::UUID
          FROM jsonb_array_elements(p_journal_entry->'lines') AS l;
        END IF;
      END IF;

      v_result := jsonb_set(v_result, '{journal_entry_id}', to_jsonb(v_je_id));
      UPDATE bills SET updated_at = NOW() WHERE id = p_bill_id;
    END IF;

    -- C. Update Bill Status (MODIFIED to include receipt fields)
    IF p_bill_update IS NOT NULL AND p_bill_id IS NOT NULL THEN
      UPDATE bills
      SET
        status = COALESCE(NULLIF(p_bill_update->>'status', ''), status),
        receipt_status = COALESCE(NULLIF(p_bill_update->>'receipt_status', ''), receipt_status),
        received_by = COALESCE(NULLIF(p_bill_update->>'received_by', '')::uuid, received_by),
        received_at = COALESCE(NULLIF(p_bill_update->>'received_at', '')::timestamptz, received_at),
        updated_at = NOW()
      WHERE id = p_bill_id;
    END IF;

  -- ── BILL CREATION ─────────────────────────────────────────────────────────
  ELSIF p_transaction_type = 'bill' THEN

    INSERT INTO bills (
      company_id, supplier_id, branch_id, cost_center_id, warehouse_id,
      bill_number, bill_date, due_date, status,
      subtotal, tax_amount, total_amount, paid_amount, notes
    )
    SELECT
      p_company_id,
      (p_bill_data->>'supplier_id')::UUID,
      NULLIF(p_bill_data->>'branch_id', '')::UUID,
      NULLIF(p_bill_data->>'cost_center_id', '')::UUID,
      NULLIF(p_bill_data->>'warehouse_id', '')::UUID,
      p_bill_data->>'bill_number',
      (p_bill_data->>'bill_date')::DATE,
      NULLIF(p_bill_data->>'due_date', '')::DATE,
      COALESCE(NULLIF(p_bill_data->>'status', ''), 'draft'),
      COALESCE((p_bill_data->>'subtotal')::NUMERIC, 0),
      COALESCE((p_bill_data->>'tax_amount')::NUMERIC, 0),
      COALESCE((p_bill_data->>'total_amount')::NUMERIC, 0),
      0, p_bill_data->>'notes'
    RETURNING id INTO v_bill_id;

    v_result := jsonb_set(v_result, '{bill_id}', to_jsonb(v_bill_id));

    IF p_bill_items IS NOT NULL THEN
      INSERT INTO bill_items (
        bill_id, product_id, description, quantity, unit_price,
        tax_rate, discount_percent, line_total
      )
      SELECT v_bill_id,
        NULLIF(bi->>'product_id', '')::UUID, bi->>'description',
        COALESCE((bi->>'quantity')::NUMERIC, 0), COALESCE((bi->>'unit_price')::NUMERIC, 0),
        COALESCE((bi->>'tax_rate')::NUMERIC, 0), COALESCE((bi->>'discount_percent')::NUMERIC, 0),
        COALESCE((bi->>'line_total')::NUMERIC, 0)
      FROM jsonb_array_elements(p_bill_items) AS bi;
    END IF;

    IF p_journal_entry IS NOT NULL THEN
      INSERT INTO journal_entries (
        company_id, branch_id, cost_center_id,
        entry_date, description, reference_id, reference_type, status
      ) VALUES (
        p_company_id,
        NULLIF(p_journal_entry->>'branch_id', '')::UUID,
        NULLIF(p_journal_entry->>'cost_center_id', '')::UUID,
        (p_journal_entry->>'entry_date')::DATE,
        p_journal_entry->>'description',
        v_bill_id, 'bill',
        COALESCE(NULLIF(p_journal_entry->>'status', ''), 'posted')
      ) RETURNING id INTO v_je_id;

      IF p_journal_entry->'lines' IS NOT NULL THEN
        INSERT INTO journal_entry_lines (
          journal_entry_id, account_id, description, debit_amount, credit_amount
        )
        SELECT v_je_id, (jl->>'account_id')::UUID, jl->>'description',
          COALESCE((jl->>'debit_amount')::NUMERIC, 0), COALESCE((jl->>'credit_amount')::NUMERIC, 0)
        FROM jsonb_array_elements(p_journal_entry->'lines') AS jl;
      END IF;

      UPDATE bills SET updated_at = NOW() WHERE id = v_bill_id;
      v_result := jsonb_set(v_result, '{journal_entry_id}', to_jsonb(v_je_id));
    END IF;

    IF p_inventory_transactions IS NOT NULL THEN
      INSERT INTO inventory_transactions (
        company_id, product_id, transaction_type, quantity_change,
        reference_id, reference_type, journal_entry_id, notes,
        branch_id, cost_center_id, warehouse_id, transaction_date
      )
      SELECT p_company_id, NULLIF(inv_tx->>'product_id', '')::UUID,
        inv_tx->>'transaction_type', COALESCE((inv_tx->>'quantity_change')::NUMERIC, 0),
        v_bill_id, 'bill', v_je_id, inv_tx->>'notes',
        NULLIF(inv_tx->>'branch_id', '')::UUID, NULLIF(inv_tx->>'cost_center_id', '')::UUID,
        NULLIF(inv_tx->>'warehouse_id', '')::UUID,
        COALESCE((inv_tx->>'transaction_date')::DATE, CURRENT_DATE)
      FROM jsonb_array_elements(p_inventory_transactions) AS inv_tx;
    END IF;

  -- ── PURCHASE RETURN ──────────────────────────────────────────────────────
  ELSIF p_transaction_type = 'purchase_return' THEN

    IF p_journal_entry IS NOT NULL THEN
      INSERT INTO journal_entries (
        company_id, branch_id, cost_center_id,
        entry_date, description, reference_id, reference_type, status
      ) VALUES (
        p_company_id,
        NULLIF(p_journal_entry->>'branch_id', '')::UUID,
        NULLIF(p_journal_entry->>'cost_center_id', '')::UUID,
        (p_journal_entry->>'entry_date')::DATE,
        p_journal_entry->>'description',
        p_bill_id, 'purchase_return',
        COALESCE(NULLIF(p_journal_entry->>'status', ''), 'posted')
      ) RETURNING id INTO v_je_id;

      IF p_journal_entry->'lines' IS NOT NULL THEN
        INSERT INTO journal_entry_lines (
          journal_entry_id, account_id, description, debit_amount, credit_amount
        )
        SELECT v_je_id, (jl->>'account_id')::UUID, jl->>'description',
          COALESCE((jl->>'debit_amount')::NUMERIC, 0), COALESCE((jl->>'credit_amount')::NUMERIC, 0)
        FROM jsonb_array_elements(p_journal_entry->'lines') AS jl;
      END IF;

      v_result := jsonb_set(v_result, '{journal_entry_id}', to_jsonb(v_je_id));
    END IF;

    IF p_purchase_return IS NOT NULL THEN
      INSERT INTO purchase_returns (
        company_id, supplier_id, bill_id, journal_entry_id,
        return_number, return_date, status, subtotal, tax_amount, total_amount,
        settlement_method, reason, notes, branch_id, cost_center_id, warehouse_id
      ) VALUES (
        p_company_id, NULLIF(p_purchase_return->>'supplier_id', '')::UUID,
        p_bill_id, v_je_id, p_purchase_return->>'return_number',
        (p_purchase_return->>'return_date')::DATE,
        COALESCE(NULLIF(p_purchase_return->>'status', ''), 'completed'),
        COALESCE((p_purchase_return->>'subtotal')::NUMERIC, 0),
        COALESCE((p_purchase_return->>'tax_amount')::NUMERIC, 0),
        COALESCE((p_purchase_return->>'total_amount')::NUMERIC, 0),
        p_purchase_return->>'settlement_method', p_purchase_return->>'reason',
        p_purchase_return->>'notes',
        NULLIF(p_purchase_return->>'branch_id', '')::UUID,
        NULLIF(p_purchase_return->>'cost_center_id', '')::UUID,
        NULLIF(p_purchase_return->>'warehouse_id', '')::UUID
      ) RETURNING id INTO v_pr_id;

      v_result := jsonb_set(v_result, '{purchase_return_id}', to_jsonb(v_pr_id));
      IF v_je_id IS NOT NULL THEN
        UPDATE journal_entries SET reference_id = v_pr_id WHERE id = v_je_id;
      END IF;
    END IF;

    IF p_vendor_credit IS NOT NULL THEN
      INSERT INTO vendor_credits (
        company_id, supplier_id, bill_id,
        source_purchase_return_id, source_purchase_invoice_id, journal_entry_id,
        credit_number, credit_date, status,
        subtotal, tax_amount, total_amount, applied_amount,
        branch_id, cost_center_id, warehouse_id, notes
      ) VALUES (
        p_company_id, NULLIF(p_vendor_credit->>'supplier_id', '')::UUID,
        p_bill_id, v_pr_id, p_bill_id, v_je_id,
        p_vendor_credit->>'credit_number',
        COALESCE((p_vendor_credit->>'credit_date')::DATE, CURRENT_DATE), 'open',
        COALESCE((p_vendor_credit->>'subtotal')::NUMERIC, 0),
        COALESCE((p_vendor_credit->>'tax_amount')::NUMERIC, 0),
        COALESCE((p_vendor_credit->>'total_amount')::NUMERIC, 0), 0,
        NULLIF(p_vendor_credit->>'branch_id', '')::UUID,
        NULLIF(p_vendor_credit->>'cost_center_id', '')::UUID,
        NULLIF(p_vendor_credit->>'warehouse_id', '')::UUID, p_vendor_credit->>'notes'
      ) RETURNING id INTO v_vc_id;

      IF p_vendor_credit_items IS NOT NULL THEN
        INSERT INTO vendor_credit_items (
          vendor_credit_id, product_id, description,
          quantity, unit_price, tax_rate, discount_percent, line_total
        )
        SELECT v_vc_id, NULLIF(vci->>'product_id', '')::UUID, vci->>'description',
          COALESCE((vci->>'quantity')::NUMERIC, 0), COALESCE((vci->>'unit_price')::NUMERIC, 0),
          COALESCE((vci->>'tax_rate')::NUMERIC, 0), COALESCE((vci->>'discount_percent')::NUMERIC, 0),
          COALESCE((vci->>'line_total')::NUMERIC, 0)
        FROM jsonb_array_elements(p_vendor_credit_items) AS vci;
      END IF;

      v_result := jsonb_set(v_result, '{vendor_credit_id}', to_jsonb(v_vc_id));
    END IF;

    IF p_inventory_transactions IS NOT NULL THEN
      INSERT INTO inventory_transactions (
        company_id, product_id, transaction_type, quantity_change,
        reference_id, reference_type, journal_entry_id, notes,
        branch_id, cost_center_id, warehouse_id, transaction_date
      )
      SELECT p_company_id, NULLIF(inv_tx->>'product_id', '')::UUID,
        inv_tx->>'transaction_type', COALESCE((inv_tx->>'quantity_change')::NUMERIC, 0),
        COALESCE(v_pr_id, p_bill_id), 'purchase_return', v_je_id, inv_tx->>'notes',
        NULLIF(inv_tx->>'branch_id', '')::UUID, NULLIF(inv_tx->>'cost_center_id', '')::UUID,
        NULLIF(inv_tx->>'warehouse_id', '')::UUID,
        COALESCE((inv_tx->>'transaction_date')::DATE, CURRENT_DATE)
      FROM jsonb_array_elements(p_inventory_transactions) AS inv_tx;
    END IF;

    IF p_bill_update IS NOT NULL AND p_bill_id IS NOT NULL THEN
      UPDATE bills
      SET
        returned_amount = COALESCE(NULLIF(p_bill_update->>'returned_amount', '')::NUMERIC, returned_amount),
        return_status = COALESCE(NULLIF(p_bill_update->>'return_status', ''), return_status),
        status = COALESCE(NULLIF(p_bill_update->>'status', ''), status),
        updated_at = NOW()
      WHERE id = p_bill_id;
    END IF;

    IF p_update_source->'bill_items_update' IS NOT NULL THEN
      FOR item_update IN
        SELECT * FROM jsonb_array_elements(p_update_source->'bill_items_update')
      LOOP
        UPDATE bill_items
        SET returned_quantity = COALESCE(returned_quantity, 0)
                              + COALESCE((item_update->>'returned_quantity')::NUMERIC, 0)
        WHERE id = (item_update->>'id')::UUID;
      END LOOP;
    END IF;

  END IF;

  RETURN v_result;

EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'Transaction failed: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_audit_log_modification()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_audit_log_modification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  RAISE EXCEPTION 'system_audit_log is immutable. UPDATE and DELETE are not allowed.';
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_bill_deletion_with_vendor_credit()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_bill_deletion_with_vendor_credit()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_vc_count INTEGER;
BEGIN
  -- Check if bill has associated vendor credits
  SELECT COUNT(*) INTO v_vc_count
  FROM vendor_credits
  WHERE source_purchase_invoice_id = OLD.id;

  IF v_vc_count > 0 THEN
    RAISE EXCEPTION 'Cannot delete Bill % because it has % associated Vendor Credit(s). Delete or cancel the Vendor Credits first.',
      OLD.bill_number, v_vc_count;
  END IF;

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_bill_overpayment()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_bill_overpayment()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_bill_total NUMERIC;
  v_bill_returned NUMERIC;
  v_pending_returns NUMERIC;
  v_current_paid NUMERIC;
  v_net_available NUMERIC;
  v_alloc RECORD;
  v_bill_currency TEXT;
  v_bill_rate NUMERIC;
  v_alloc_in_bill_currency NUMERIC;
BEGIN
  IF COALESCE(NEW.status, 'approved') = 'pending_approval' THEN RETURN NEW; END IF;
  IF NEW.status IN ('rejected', 'cancelled') THEN RETURN NEW; END IF;

  IF NEW.bill_id IS NOT NULL THEN
    SELECT COALESCE(b.total_amount, 0), COALESCE(b.returned_amount, 0)
    INTO v_bill_total, v_bill_returned
    FROM bills b WHERE id = NEW.bill_id;

    SELECT COALESCE(SUM(pr.total_amount), 0)
    INTO v_pending_returns
    FROM purchase_returns pr
    WHERE pr.bill_id = NEW.bill_id
      AND pr.status IN ('pending_approval', 'pending_warehouse');

    SELECT COALESCE(SUM(pa.allocated_amount), 0)
    INTO v_current_paid
    FROM payment_allocations pa
    JOIN payments p ON p.id = pa.payment_id
    WHERE pa.bill_id = NEW.bill_id
      AND p.status = 'approved'
      AND COALESCE(p.is_deleted, false) = false
      AND p.voided_at IS NULL
      AND p.voids_payment_id IS NULL
      AND p.id != COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::uuid);

    v_net_available := GREATEST(v_bill_total - v_bill_returned - v_pending_returns, 0);

    IF (v_current_paid + NEW.amount) > v_net_available + 0.01 THEN
      RAISE EXCEPTION 'OVERPAYMENT_BLOCKED: دفعة % تتجاوز المتبقى الصافى % (إجمالى=%، مرتجع=%، مرتجعات معلقة=%، مدفوع سابق=%)',
        NEW.amount, v_net_available - v_current_paid,
        v_bill_total, v_bill_returned, v_pending_returns, v_current_paid
        USING ERRCODE = 'P0001';
    END IF;

    RETURN NEW;
  END IF;

  FOR v_alloc IN
    SELECT pa.bill_id, pa.allocated_amount
    FROM payment_allocations pa
    WHERE pa.payment_id = NEW.id
      AND pa.bill_id IS NOT NULL
  LOOP
    SELECT COALESCE(b.total_amount, 0),
           COALESCE(b.returned_amount, 0),
           UPPER(COALESCE(b.currency_code, 'EGP')),
           COALESCE(NULLIF(b.exchange_rate, 0), 1)
    INTO v_bill_total, v_bill_returned, v_bill_currency, v_bill_rate
    FROM bills b WHERE id = v_alloc.bill_id;

    SELECT COALESCE(SUM(pr.total_amount), 0)
    INTO v_pending_returns
    FROM purchase_returns pr
    WHERE pr.bill_id = v_alloc.bill_id
      AND pr.status IN ('pending_approval', 'pending_warehouse');

    SELECT COALESCE(SUM(
      pa2.allocated_amount *
      CASE
        WHEN v_bill_currency = '' OR UPPER(COALESCE(p2.currency_code, '')) = '' THEN 1
        WHEN UPPER(COALESCE(p2.currency_code, '')) = v_bill_currency THEN 1
        ELSE COALESCE(NULLIF(p2.exchange_rate, 0), 1) / v_bill_rate
      END
    ), 0)
    INTO v_current_paid
    FROM payment_allocations pa2
    JOIN payments p2 ON p2.id = pa2.payment_id
    WHERE pa2.bill_id = v_alloc.bill_id
      AND p2.status = 'approved'
      AND COALESCE(p2.is_deleted, false) = false
      AND p2.voided_at IS NULL
      AND p2.voids_payment_id IS NULL
      AND p2.id != NEW.id;

    v_alloc_in_bill_currency := v_alloc.allocated_amount *
      CASE
        WHEN v_bill_currency = '' OR UPPER(COALESCE(NEW.currency_code, '')) = '' THEN 1
        WHEN UPPER(COALESCE(NEW.currency_code, '')) = v_bill_currency THEN 1
        ELSE COALESCE(NULLIF(NEW.exchange_rate, 0), 1) / v_bill_rate
      END;

    v_net_available := GREATEST(v_bill_total - v_bill_returned - v_pending_returns, 0);

    IF (v_current_paid + v_alloc_in_bill_currency) > v_net_available + 0.01 THEN
      RAISE EXCEPTION 'OVERPAYMENT_BLOCKED: تخصيص دفعة % (بعملة الفاتورة) يتجاوز المتبقى الصافى % على الفاتورة % (إجمالى=%، مرتجع=%، مرتجعات معلقة=%، مدفوع سابق=%)',
        v_alloc_in_bill_currency,
        v_net_available - v_current_paid,
        v_alloc.bill_id,
        v_bill_total, v_bill_returned, v_pending_returns, v_current_paid
        USING ERRCODE = 'P0001';
    END IF;
  END LOOP;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_critical_account_changes()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_critical_account_changes()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  has_transactions BOOLEAN;
BEGIN
  SELECT EXISTS (
    SELECT 1 FROM journal_entry_lines WHERE account_id = OLD.id LIMIT 1
  ) INTO has_transactions;

  IF TG_OP = 'DELETE' THEN
    IF OLD.is_system THEN
      RAISE EXCEPTION 'Cannot delete a system account.';
    END IF;

    IF has_transactions THEN
      -- استبدال الحذف بالأرشفة: تحديث السجل ثم إلغاء الحذف
      UPDATE chart_of_accounts
      SET is_archived = TRUE, is_active = FALSE, updated_at = NOW()
      WHERE id = OLD.id;
      RETURN NULL; -- إلغاء عملية الحذف
    END IF;

    RETURN OLD;
  END IF;

  IF TG_OP = 'UPDATE' THEN
    IF OLD.account_type IS DISTINCT FROM NEW.account_type AND has_transactions THEN
      RAISE EXCEPTION 'Cannot change account type of % because it has transactions. This would corrupt historical financial statements.', OLD.account_name;
    END IF;

    IF OLD.is_system THEN
      IF OLD.account_code IS DISTINCT FROM NEW.account_code THEN
        RAISE EXCEPTION 'Cannot change account code of a system account.';
      END IF;
      IF OLD.account_type IS DISTINCT FROM NEW.account_type THEN
        RAISE EXCEPTION 'Cannot change account type of a system account.';
      END IF;
    END IF;

    -- منع إعادة تفعيل حساب مُؤرشف له قيود (اختياري: يمكن السماح بالقراءة فقط)
    IF OLD.is_archived = TRUE AND NEW.is_archived = FALSE AND has_transactions THEN
      RAISE EXCEPTION 'Cannot unarchive account with existing transactions. Account: %', OLD.account_name;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_customer_debit_item_deletion()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_customer_debit_item_deletion()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_journal_entry_id UUID; v_debit_note_number VARCHAR(50); BEGIN SELECT journal_entry_id, debit_note_number INTO v_journal_entry_id, v_debit_note_number FROM customer_debit_notes WHERE id = OLD.customer_debit_note_id; IF v_journal_entry_id IS NOT NULL THEN RAISE EXCEPTION 'Cannot delete item from customer debit note % - it has a posted journal entry', v_debit_note_number; END IF; RETURN OLD; END; $function$
;

-- ---------------------------------------------------------------
-- prevent_customer_debit_note_deletion()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_customer_debit_note_deletion()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ BEGIN IF OLD.applied_amount > 0 THEN RAISE EXCEPTION 'Cannot delete customer debit note - it has been applied'; END IF; IF OLD.approval_status IN ('approved', 'pending_approval') THEN RAISE EXCEPTION 'Cannot delete customer debit note - it is approved or pending'; END IF; RETURN OLD; END; $function$
;

-- ---------------------------------------------------------------
-- prevent_customer_debit_note_modification()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_customer_debit_note_modification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ BEGIN IF OLD.approval_status = 'approved' AND (NEW.total_amount != OLD.total_amount OR NEW.customer_id != OLD.customer_id OR NEW.source_invoice_id != OLD.source_invoice_id OR NEW.reference_type != OLD.reference_type) THEN RAISE EXCEPTION 'Cannot modify approved customer debit note % (only draft/pending can be modified)', OLD.debit_note_number; END IF; IF OLD.applied_amount > 0 AND (NEW.total_amount < OLD.total_amount OR NEW.customer_id != OLD.customer_id) THEN RAISE EXCEPTION 'Cannot modify customer debit note % - it has been applied (%.2f applied)', OLD.debit_note_number, OLD.applied_amount; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- prevent_direct_debit_application()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_direct_debit_application()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ BEGIN IF current_setting('application.name', TRUE) != 'apply_customer_debit_note' THEN RAISE NOTICE 'Direct INSERT into customer_debit_note_applications is discouraged. Use apply_customer_debit_note() function instead.'; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- prevent_duplicate_cogs_entries()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_duplicate_cogs_entries()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_existing_count INTEGER;
BEGIN
  IF NEW.reference_type = 'invoice_cogs' THEN
    SELECT COUNT(*) INTO v_existing_count
    FROM journal_entries
    WHERE company_id = NEW.company_id
      AND reference_type = 'invoice_cogs'
      AND reference_id = NEW.reference_id;
    
    IF v_existing_count > 0 THEN
      RAISE EXCEPTION 'قيد COGS موجود مسبقاً لهذه الفاتورة. لا يمكن إنشاء قيد مكرر.';
    END IF;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_duplicate_customer_phone()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_duplicate_customer_phone()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE normalized_phone text; existing_count int; existing_name text; BEGIN normalized_phone := normalize_phone(NEW.phone); IF normalized_phone IS NULL OR normalized_phone = '' THEN RETURN NEW; END IF; SELECT COUNT(*), MAX(name) INTO existing_count, existing_name FROM customers WHERE company_id = NEW.company_id AND normalize_phone(phone) = normalized_phone AND id != COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::uuid); IF existing_count > 0 THEN RAISE EXCEPTION 'DUPLICATE_PHONE: العميل مسجل مسبقاً بنفس رقم الهاتف (%)', existing_name; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- prevent_duplicate_inventory_transactions()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_duplicate_inventory_transactions()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  existing_count INTEGER;
BEGIN
  -- السماح بعدة حركات مرتجع لنفس المنتج والفاتورة (المرتجعات الجزئية)
  IF NEW.transaction_type IN ('sale_return', 'purchase_return') THEN
    RETURN NEW;
  END IF;

  IF NEW.reference_id IS NOT NULL AND NEW.product_id IS NOT NULL THEN
    SELECT COUNT(*) INTO existing_count
    FROM inventory_transactions
    WHERE reference_id = NEW.reference_id
      AND product_id = NEW.product_id
      AND transaction_type = NEW.transaction_type
      AND (is_deleted = false OR is_deleted IS NULL)
      AND id != COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::uuid);

    IF existing_count > 0 THEN
      RAISE EXCEPTION 'يوجد حركة مخزون سابقة لنفس المنتج والفاتورة. reference_id: %, product_id: %, type: %',
        NEW.reference_id, NEW.product_id, NEW.transaction_type;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_duplicate_journal_entry_v2()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_duplicate_journal_entry_v2()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count INT;
BEGIN
  IF NEW.reference_type IS NULL OR NEW.reference_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Payment journals are naturally one-per-payment, not one-per-invoice.
  -- Multiple payments on the same invoice create multiple valid journals.
  IF NEW.reference_type IN ('invoice_payment', 'bill_payment') THEN
    RETURN NEW;
  END IF;

  SELECT COUNT(*)
    INTO v_count
    FROM public.journal_entries
   WHERE company_id     = NEW.company_id
     AND reference_type = NEW.reference_type
     AND reference_id   = NEW.reference_id
     AND (is_deleted IS NULL OR is_deleted = FALSE)
     AND deleted_at IS NULL;

  IF v_count > 0 THEN
    RAISE EXCEPTION
      'DUPLICATE_JOURNAL_VIOLATION: A journal entry with '
      'reference_type=[%] and reference_id=[%] already exists '
      'for company [%]. '
      'Duplicate accounting entries are not permitted. '
      'Use a reversal entry to correct an existing posted entry.',
      NEW.reference_type, NEW.reference_id, NEW.company_id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_inventory_for_cancelled()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_inventory_for_cancelled()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  invoice_status TEXT;
  bill_status TEXT;
  po_status TEXT;
BEGIN
  -- إذا كانت الحركة مرتبطة بفاتورة بيع
  IF NEW.transaction_type IN ('sale', 'sale_reversal') AND NEW.reference_id IS NOT NULL THEN
    SELECT status INTO invoice_status
    FROM invoices
    WHERE id = NEW.reference_id;

    -- إذا كانت الفاتورة ملغاة، منع إنشاء الحركة
    IF invoice_status = 'cancelled' THEN
      RAISE EXCEPTION 'لا يمكن إنشاء حركة مخزون لفاتورة ملغاة (invoice_id: %)', NEW.reference_id;
    END IF;
  END IF;

  -- إذا كانت الحركة مرتبطة بفاتورة شراء
  IF NEW.transaction_type IN ('purchase', 'purchase_reversal') AND NEW.reference_id IS NOT NULL THEN
    SELECT status INTO bill_status
    FROM bills
    WHERE id = NEW.reference_id;

    -- إذا كانت الفاتورة ملغاة، منع إنشاء الحركة
    IF bill_status = 'cancelled' THEN
      RAISE EXCEPTION 'لا يمكن إنشاء حركة مخزون لفاتورة شراء ملغاة (bill_id: %)', NEW.reference_id;
    END IF;
  END IF;

  -- إذا كانت الحركة مرتبطة بأمر شراء
  IF NEW.transaction_type IN ('purchase', 'purchase_reversal') AND NEW.reference_id IS NOT NULL THEN
    -- التحقق من وجود أمر شراء بهذا ID
    SELECT status INTO po_status
    FROM purchase_orders
    WHERE id = NEW.reference_id;

    -- إذا كان أمر الشراء ملغى، منع إنشاء الحركة
    IF po_status = 'cancelled' THEN
      RAISE EXCEPTION 'لا يمكن إنشاء حركة مخزون لأمر شراء ملغى (purchase_order_id: %)', NEW.reference_id;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_inventory_in_closed_period()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_inventory_in_closed_period()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_transaction_date DATE;
  v_invoice_date DATE;
  v_po_date DATE;
BEGIN
  -- محاولة الحصول على تاريخ من المرجع
  IF NEW.reference_id IS NOT NULL THEN
    -- التحقق من الفواتير
    SELECT invoice_date INTO v_invoice_date
    FROM invoices
    WHERE id = NEW.reference_id
    LIMIT 1;

    IF v_invoice_date IS NOT NULL THEN
      v_transaction_date := v_invoice_date;
    ELSE
      -- التحقق من أوامر الشراء
      SELECT po_date INTO v_po_date
      FROM purchase_orders
      WHERE id = NEW.reference_id
      LIMIT 1;

      IF v_po_date IS NOT NULL THEN
        v_transaction_date := v_po_date;
      ELSE
        -- استخدام تاريخ الإنشاء كبديل
        v_transaction_date := NEW.created_at::DATE;
      END IF;
    END IF;
  ELSE
    -- استخدام تاريخ الإنشاء
    v_transaction_date := COALESCE(NEW.created_at::DATE, CURRENT_DATE);
  END IF;

  -- التحقق من حالة الفترة
  PERFORM can_modify_transaction(
    NEW.company_id,
    v_transaction_date,
    'إنشاء/تعديل حركات مخزون'
  );

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_inventory_on_draft_invoice()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_inventory_on_draft_invoice()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE invoice_status TEXT; bill_status TEXT; BEGIN IF NEW.transaction_type = 'sale' AND NEW.reference_id IS NOT NULL THEN SELECT status INTO invoice_status FROM invoices WHERE id = NEW.reference_id; IF invoice_status = 'draft' THEN RAISE EXCEPTION 'النمط المحاسبي: لا يمكن إنشاء حركة مخزون لفاتورة مبيعات مسودة DRAFT'; END IF; END IF; IF NEW.transaction_type = 'purchase' AND NEW.reference_id IS NOT NULL THEN SELECT status INTO bill_status FROM bills WHERE id = NEW.reference_id; IF bill_status = 'draft' THEN RAISE EXCEPTION 'النمط المحاسبي: لا يمكن إنشاء حركة مخزون لفاتورة شراء مسودة DRAFT'; END IF; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- prevent_invoice_edit_after_journal()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_invoice_edit_after_journal()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE has_journal BOOLEAN;
BEGIN
  SELECT EXISTS (SELECT 1 FROM journal_entries WHERE reference_type IN ('invoice', 'invoice_payment', 'invoice_cogs', 'invoice_cogs_reversal') AND reference_id = NEW.id) INTO has_journal;
  IF has_journal THEN
    IF (OLD.invoice_number IS DISTINCT FROM NEW.invoice_number OR OLD.customer_id IS DISTINCT FROM NEW.customer_id OR OLD.invoice_date IS DISTINCT FROM NEW.invoice_date OR OLD.due_date IS DISTINCT FROM NEW.due_date OR OLD.discount_type IS DISTINCT FROM NEW.discount_type OR OLD.discount_value IS DISTINCT FROM NEW.discount_value OR OLD.shipping IS DISTINCT FROM NEW.shipping OR OLD.adjustment IS DISTINCT FROM NEW.adjustment) THEN
      RAISE EXCEPTION 'لا يمكن تعديل البيانات الأساسية للفاتورة بعد إنشاء قيود محاسبية';
    END IF;
    IF (NEW.subtotal > OLD.subtotal OR NEW.tax_amount > OLD.tax_amount OR NEW.total_amount > OLD.total_amount) THEN
      RAISE EXCEPTION 'لا يمكن زيادة قيم الفاتورة بعد إنشاء قيود محاسبية';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

