-- ---------------------------------------------------------------
-- prevent_journal_on_sent_invoice()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_journal_on_sent_invoice()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  invoice_status TEXT;
  bill_status TEXT;
BEGIN
  IF NEW.reference_type = 'invoice_cogs' THEN
    RETURN NEW;
  END IF;
  IF NEW.reference_type = 'invoice_cogs_reversal' THEN
    RETURN NEW;
  END IF;
  IF NEW.reference_type = 'invoice' AND NEW.reference_id IS NOT NULL THEN
    SELECT status INTO invoice_status FROM invoices WHERE id = NEW.reference_id;
    IF invoice_status = 'sent' THEN
      RAISE EXCEPTION 'النمط المحاسبي: لا يمكن إنشاء قيد إيراد لفاتورة مبيعات بحالة SENT. قيود الإيراد تُنشأ فقط عند الدفع (PAID)';
    END IF;
  END IF;
  IF NEW.reference_type = 'bill' AND NEW.reference_id IS NOT NULL THEN
    SELECT status INTO bill_status FROM bills WHERE id = NEW.reference_id;
    IF bill_status IN ('sent', 'received') THEN
      RAISE EXCEPTION 'النمط المحاسبي: لا يمكن إنشاء قيد لفاتورة شراء بحالة SENT/RECEIVED. القيود تُنشأ فقط عند الدفع (PAID)';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_linked_inventory_modification()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_linked_inventory_modification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    journal_status TEXT;
BEGIN
    -- Linked to a journal? Check if it's posted.
    IF OLD.journal_entry_id IS NOT NULL THEN
        SELECT status INTO journal_status
          FROM public.journal_entries
         WHERE id = OLD.journal_entry_id;

        IF journal_status = 'posted' THEN
            RAISE EXCEPTION 'Cannot modify/delete inventory transaction linked to a posted journal (ID: %).',
                OLD.journal_entry_id;
        END IF;
    END IF;

    -- Canonical pattern: return OLD on DELETE, NEW on UPDATE.
    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    ELSE
        RETURN NEW;
    END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_negative_branch_inventory()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_negative_branch_inventory()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_tracked       boolean;
    v_product_name  text;
    v_branch_name   text;
    v_current_qty   numeric;
    v_new_balance   numeric;
BEGIN
    IF NEW.quantity_change >= 0 THEN
        RETURN NEW;
    END IF;

    IF NEW.branch_id IS NULL THEN
        RETURN NEW;
    END IF;

    -- Lock the product row to serialize concurrent outflows on the
    -- same SKU. Any other transaction trying to deduct the same
    -- product will wait here, so we never race on the SUM.
    SELECT track_inventory, name
      INTO v_tracked, v_product_name
      FROM public.products
     WHERE id = NEW.product_id
     FOR UPDATE;

    IF NOT COALESCE(v_tracked, false) THEN
        RETURN NEW;
    END IF;

    SELECT COALESCE(SUM(quantity_change), 0)
      INTO v_current_qty
      FROM public.inventory_transactions
     WHERE company_id  = NEW.company_id
       AND product_id  = NEW.product_id
       AND branch_id   = NEW.branch_id
       AND COALESCE(warehouse_id::text, '') = COALESCE(NEW.warehouse_id::text, '')
       AND COALESCE(is_deleted, false) = false;

    v_new_balance := v_current_qty + NEW.quantity_change;

    IF v_new_balance < 0 THEN
        SELECT branch_name INTO v_branch_name
          FROM public.branches
         WHERE id = NEW.branch_id;

        RAISE EXCEPTION USING
          MESSAGE = format(
            'لا يُمكِن خَصم %s من المُنتَج "%s" بالفَرع "%s" — الرَّصيد الحالى %s. // Insufficient inventory: cannot deduct %s units of "%s" from branch "%s" (current balance %s).',
            abs(NEW.quantity_change), v_product_name, COALESCE(v_branch_name, NEW.branch_id::text), v_current_qty,
            abs(NEW.quantity_change), v_product_name, COALESCE(v_branch_name, NEW.branch_id::text), v_current_qty
          ),
          ERRCODE = 'check_violation',
          HINT = 'تَأَكَّد من أَنَّ المَخزون مُتاح فى الفَرع المُختار قَبل تَأكيد العَمَلية أَو حَوِّل من فَرع آخَر أَولاً.';
    END IF;

    RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_negative_payment_invoice_link()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_negative_payment_invoice_link()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NEW.amount < 0 AND NEW.invoice_id IS NOT NULL THEN
    NEW.invoice_id := NULL;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_paid_invoice_items_modification()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_paid_invoice_items_modification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  inv_status TEXT;
  allowed_fields TEXT[] := ARRAY['returned_quantity', 'updated_at', 'is_deleted', 'deleted_at', 'deleted_by'];
  old_val JSONB;
  new_val JSONB;
  key TEXT;
BEGIN
  -- جلب حالة الفاتورة
  SELECT status INTO inv_status FROM invoices WHERE id = COALESCE(NEW.invoice_id, OLD.invoice_id);
  
  -- فقط للفواتير المدفوعة
  IF inv_status IN ('paid', 'partially_paid') THEN
    IF TG_OP = 'DELETE' THEN
      RAISE EXCEPTION 'لا يمكن حذف بنود الفاتورة المدفوعة. يرجى إنشاء مرتجع بدلاً من ذلك.';
    ELSIF TG_OP = 'INSERT' THEN
      RAISE EXCEPTION 'لا يمكن إضافة بنود للفاتورة المدفوعة. يرجى إنشاء فاتورة جديدة أو إشعار دائن.';
    ELSIF TG_OP = 'UPDATE' THEN
      old_val := to_jsonb(OLD);
      new_val := to_jsonb(NEW);
      
      FOR key IN SELECT jsonb_object_keys(new_val)
      LOOP
        IF key = ANY(allowed_fields) THEN
          CONTINUE;
        END IF;
        
        IF (old_val->key)::text IS DISTINCT FROM (new_val->key)::text THEN
          RAISE EXCEPTION 'لا يمكن تعديل بنود الفاتورة المدفوعة. الحقل: %. يرجى إنشاء مرتجع.', key;
        END IF;
      END LOOP;
    END IF;
  END IF;
  
  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_paid_invoice_modification()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_paid_invoice_modification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  allowed_fields TEXT[] := ARRAY[
    'paid_amount',
    'original_paid',
    'display_paid',
    'status', 'returned_amount', 'return_status',
    'notes', 'internal_notes', 'attachments', 'updated_at',
    'is_deleted', 'deleted_at', 'deleted_by',
    'warehouse_status', 'approval_status',
    'approved_by', 'approval_date', 'approval_reason',
    'rejected_by', 'rejection_date', 'rejection_reason',
    'shipping_provider_id', 'tracking_number', 'shipped_at', 'delivered_at',
    'current_approval_role', 'workflow_state',
    'bonus_calculated', 'bonus_calculated_at', 'commission_amount',
    -- v3.74.257 — pre-shipment refund audit columns. The executor sets
    -- these in the same UPDATE as paid_amount=0 / status='cancelled'.
    'pre_shipment_refund_at', 'pre_shipment_refund_by',
    'pre_shipment_refund_amount', 'pre_shipment_refund_mode',
    'pre_shipment_refund_reason', 'pre_shipment_refund_je_id'
  ];
  old_val JSONB;
  new_val JSONB;
  key TEXT;
BEGIN
  IF OLD.status IN ('paid', 'partially_paid') THEN
    old_val := to_jsonb(OLD);
    new_val := to_jsonb(NEW);

    FOR key IN SELECT jsonb_object_keys(new_val)
    LOOP
      IF key = ANY(allowed_fields) THEN
        CONTINUE;
      END IF;

      IF (old_val->key)::text IS DISTINCT FROM (new_val->key)::text THEN
        RAISE EXCEPTION 'لا يمكن تعديل الفاتورة المدفوعة. الحقل المعدل: %. يرجى إنشاء مرتجع أو إشعار دائن بدلاً من ذلك.', key;
      END IF;
    END LOOP;
  END IF;

  RETURN NEW;
END;
$function$
;

