-- prevent_payment_in_closed_period()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_payment_in_closed_period()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- التحقق من حالة الفترة
  PERFORM can_modify_transaction(
    NEW.company_id,
    NEW.payment_date,
    'إنشاء/تعديل مدفوعات'
  );

  RETURN NEW;
