-- ---------------------------------------------------------------
-- prevent_posted_je_lines_deletion()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_posted_je_lines_deletion()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
  DECLARE v_je_status TEXT;
  BEGIN
    IF current_setting('app.allow_direct_post', true) = 'true' OR
       current_setting('app.allow_je_line_delete', true) = 'true' THEN
      RETURN OLD;
    END IF;
    SELECT status INTO v_je_status FROM journal_entries WHERE id = OLD.journal_entry_id;
    IF v_je_status = 'posted' THEN
      RAISE EXCEPTION 'POSTED_JE_LINES_IMMUTABLE: Cannot delete lines from posted journal entry %', OLD.journal_entry_id
        USING HINT = 'Reverse the journal entry instead of deleting its lines';
    END IF;
    RETURN OLD;
  END;
  $function$
;

-- ---------------------------------------------------------------
-- prevent_posted_journal_modification()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_posted_journal_modification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Administrative bypass
  IF current_setting('app.allow_direct_post', true) = 'true' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  IF OLD.status = 'posted' THEN
    IF TG_OP = 'DELETE' THEN
      RAISE EXCEPTION 'Cannot delete a posted journal entry (ID: %). Create a reversal entry instead.', OLD.id;
    ELSIF TG_OP = 'UPDATE' THEN
      IF OLD.entry_date IS DISTINCT FROM NEW.entry_date
         OR OLD.description IS DISTINCT FROM NEW.description
         OR OLD.reference_type IS DISTINCT FROM NEW.reference_type
         OR OLD.reference_id IS DISTINCT FROM NEW.reference_id
         OR OLD.warehouse_id IS DISTINCT FROM NEW.warehouse_id
         OR OLD.status IS DISTINCT FROM NEW.status
      THEN
        RAISE EXCEPTION 'Cannot modify a posted journal entry (ID: %). Create a reversal entry instead.', OLD.id;
      END IF;
      IF OLD.branch_id IS DISTINCT FROM NEW.branch_id THEN
        IF OLD.branch_id IS NOT NULL OR NEW.branch_id IS NULL THEN
          RAISE EXCEPTION 'Cannot modify a posted journal entry (metadata branch_id) (ID: %). Create a reversal entry instead.', OLD.id;
        END IF;
      END IF;
      IF OLD.cost_center_id IS DISTINCT FROM NEW.cost_center_id THEN
        IF OLD.cost_center_id IS NOT NULL OR NEW.cost_center_id IS NULL THEN
          RAISE EXCEPTION 'Cannot modify a posted journal entry (metadata cost_center_id) (ID: %). Create a reversal entry instead.', OLD.id;
        END IF;
      END IF;
      RETURN NEW;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_posted_line_modification()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_posted_line_modification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
  DECLARE
    v_entry_id UUID;
    v_status   TEXT;
  BEGIN
    IF current_setting('app.allow_direct_post', true) = 'true' THEN
      RETURN COALESCE(NEW, OLD);
    END IF;
    IF TG_OP = 'DELETE' THEN v_entry_id := OLD.journal_entry_id;
    ELSE v_entry_id := NEW.journal_entry_id; END IF;
    SELECT status INTO v_status FROM public.journal_entries WHERE id = v_entry_id;
    IF v_status = 'posted' THEN
      RAISE EXCEPTION 'IMMUTABILITY_VIOLATION: Cannot % line of posted entry [%].', TG_OP, v_entry_id;
    END IF;
    RETURN COALESCE(NEW, OLD);
  END;
  $function$
;

-- ---------------------------------------------------------------
-- prevent_return_creating_overpay()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_return_creating_overpay()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_bill_total NUMERIC;
  v_bill_returned NUMERIC;
  v_other_pending_returns NUMERIC;
  v_approved_paid NUMERIC;
  v_pending_payment NUMERIC;
  v_net_after_this_return NUMERIC;
  v_bill_currency TEXT;
  v_bill_rate NUMERIC;
BEGIN
  IF NEW.bill_id IS NULL THEN RETURN NEW; END IF;
  IF NEW.workflow_status NOT IN ('confirmed', 'completed') THEN RETURN NEW; END IF;
  IF TG_OP = 'UPDATE' AND OLD.workflow_status IS NOT DISTINCT FROM NEW.workflow_status THEN
    RETURN NEW;
  END IF;

  SELECT COALESCE(b.total_amount, 0),
         COALESCE(b.returned_amount, 0),
         UPPER(COALESCE(b.currency_code, 'EGP')),
         COALESCE(NULLIF(b.exchange_rate, 0), 1)
  INTO v_bill_total, v_bill_returned, v_bill_currency, v_bill_rate
  FROM bills b WHERE id = NEW.bill_id;

  SELECT COALESCE(SUM(pr.total_amount), 0)
  INTO v_other_pending_returns
  FROM purchase_returns pr
  WHERE pr.bill_id = NEW.bill_id
    AND pr.status IN ('pending_approval', 'pending_warehouse')
    AND pr.id != NEW.id;

  SELECT COALESCE(SUM(
    pa.allocated_amount *
    CASE
      WHEN UPPER(COALESCE(p.currency_code, '')) = v_bill_currency THEN 1
      WHEN UPPER(COALESCE(p.currency_code, '')) = '' THEN 1
      ELSE COALESCE(NULLIF(p.exchange_rate, 0), 1) / v_bill_rate
    END
  ), 0)
  INTO v_approved_paid
  FROM payment_allocations pa
  JOIN payments p ON p.id = pa.payment_id
  WHERE pa.bill_id = NEW.bill_id
    AND p.status = 'approved'
    AND COALESCE(p.is_deleted, false) = false
    AND p.voided_at IS NULL
    AND p.voids_payment_id IS NULL
    AND NOT EXISTS (
      SELECT 1 FROM vendor_payment_correction_requests v
      WHERE v.original_payment_id = p.id AND v.status = 'executed'
    );

  SELECT COALESCE(SUM(
    pa.allocated_amount *
    CASE
      WHEN UPPER(COALESCE(p.currency_code, '')) = v_bill_currency THEN 1
      WHEN UPPER(COALESCE(p.currency_code, '')) = '' THEN 1
      ELSE COALESCE(NULLIF(p.exchange_rate, 0), 1) / v_bill_rate
    END
  ), 0)
  INTO v_pending_payment
  FROM payment_allocations pa
  JOIN payments p ON p.id = pa.payment_id
  WHERE pa.bill_id = NEW.bill_id
    AND p.status = 'pending_approval'
    AND COALESCE(p.is_deleted, false) = false
    AND p.voided_at IS NULL
    AND p.voids_payment_id IS NULL
    AND NOT EXISTS (
      SELECT 1 FROM vendor_payment_correction_requests v
      WHERE v.original_payment_id = p.id AND v.status = 'executed'
    );

  v_net_after_this_return := v_bill_total
                             - v_bill_returned
                             - COALESCE(NEW.total_amount, 0)
                             - v_other_pending_returns;

  IF (v_approved_paid + v_pending_payment) > v_net_after_this_return + 0.01 THEN
    RAISE EXCEPTION 'RETURN_WOULD_CAUSE_OVERPAY: اعتماد المرتجع % يخفض صافى الفاتورة إلى % بينما المدفوع المعتمد % + المعلق % = % — ارفض أو عدّل الدفعة المعلقة أولاً ثم أكد الإخراج',
      COALESCE(NEW.total_amount, 0),
      ROUND(v_net_after_this_return, 2),
      ROUND(v_approved_paid, 2),
      ROUND(v_pending_payment, 2),
      ROUND(v_approved_paid + v_pending_payment, 2)
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- prevent_vendor_credit_deletion()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.prevent_vendor_credit_deletion()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Allow deletion only if status is 'draft' or 'cancelled'
  IF OLD.status NOT IN ('draft', 'cancelled') THEN
    RAISE EXCEPTION 'Cannot delete Vendor Credit % (%). Only draft or cancelled credits can be deleted.',
      OLD.credit_number, OLD.status;
  END IF;
  
  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_customer_payment_allocation(p_company_id uuid, p_customer_id uuid, p_payment_amount numeric, p_payment_date date, p_payment_method character varying, p_account_id uuid, p_branch_id uuid, p_currency_code character varying, p_exchange_rate numeric, p_base_currency_amount numeric, p_reference_number character varying, p_notes character varying, p_allocations jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_customer_payment_allocation(p_company_id uuid, p_customer_id uuid, p_payment_amount numeric, p_payment_date date, p_payment_method character varying, p_account_id uuid, p_branch_id uuid, p_currency_code character varying, p_exchange_rate numeric, p_base_currency_amount numeric, p_reference_number character varying DEFAULT NULL::character varying, p_notes character varying DEFAULT NULL::character varying, p_allocations jsonb DEFAULT NULL::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_payment_id        UUID;
  v_status            VARCHAR := 'pending_approval';
  v_user_id           UUID := auth.uid();
  v_user_role         VARCHAR;
  v_alloc_record      JSONB;
  v_total_allocated   NUMERIC := 0;
  v_invoice_id        UUID;
  v_inv_total         NUMERIC;
  v_inv_paid          NUMERIC;
  v_inv_net           NUMERIC;
  v_inv_rate          NUMERIC;
  v_inv_branch_id     UUID;
  v_inv_customer_id   UUID;
  v_inv_number        VARCHAR;

  -- FX GL accounts
  v_fx_gain_id        UUID;
  v_fx_loss_id        UUID;
  v_ar_id             UUID;
  v_fx_amount         NUMERIC;
  v_fx_description    VARCHAR;
  v_fx_journal_id     UUID;
  v_alloc_amount      NUMERIC;
BEGIN
  -- ✅ Allow direct posting within this SECURITY DEFINER function
  PERFORM set_config('app.allow_direct_post', 'true', true);

  -- Validate user membership
  SELECT role INTO v_user_role
  FROM company_members
  WHERE user_id = v_user_id AND company_id = p_company_id;

  IF v_user_role IS NULL THEN
    RAISE EXCEPTION 'Unauthorized: User is not a member of this company';
  END IF;

  -- Privileged roles auto-approve
  IF v_user_role IN ('owner', 'admin', 'general_manager') THEN
    v_status := 'approved';
  END IF;

  -- Validate total allocations <= payment amount
  IF p_allocations IS NOT NULL AND jsonb_array_length(p_allocations) > 0 THEN
    SELECT SUM((alloc->>'amount')::numeric)
    INTO v_total_allocated
    FROM jsonb_array_elements(p_allocations) AS alloc;

    IF v_total_allocated > p_payment_amount + 0.01 THEN
      RAISE EXCEPTION 'ALLOCATION_EXCEEDS_PAYMENT: Total allocations (%) exceed payment amount (%)',
        v_total_allocated, p_payment_amount;
    END IF;
  END IF;

  -- Create Payment record
  INSERT INTO payments (
    company_id, customer_id,
    payment_date, amount, payment_method, account_id,
    branch_id, currency_code, exchange_rate, base_currency_amount,
    reference_number, notes,
    status, created_by, unallocated_amount
  ) VALUES (
    p_company_id, p_customer_id,
    p_payment_date, p_payment_amount, p_payment_method, p_account_id,
    p_branch_id, p_currency_code, p_exchange_rate, p_base_currency_amount,
    p_reference_number, p_notes,
    v_status, v_user_id, p_payment_amount
  ) RETURNING id INTO v_payment_id;

  IF v_status = 'approved' THEN
    UPDATE payments SET approved_by = v_user_id, approved_at = NOW()
    WHERE id = v_payment_id;
  END IF;

  -- Resolve FX GL accounts
  SELECT id INTO v_fx_gain_id
  FROM chart_of_accounts
  WHERE company_id = p_company_id
    AND (account_code LIKE '4200%' OR account_name ILIKE '%أرباح فروق صرف%'
         OR account_name ILIKE '%fx gain%' OR account_name ILIKE '%exchange gain%')
  LIMIT 1;

  SELECT id INTO v_fx_loss_id
  FROM chart_of_accounts
  WHERE company_id = p_company_id
    AND (account_code LIKE '5200%' OR account_name ILIKE '%خسائر فروق صرف%'
         OR account_name ILIKE '%fx loss%' OR account_name ILIKE '%exchange loss%')
  LIMIT 1;

  SELECT id INTO v_ar_id
  FROM chart_of_accounts
  WHERE company_id = p_company_id
    AND (account_code LIKE '1200%' OR account_name ILIKE '%ذمم مدينة%'
         OR account_name ILIKE '%accounts receivable%' OR account_name ILIKE '%عملاء%')
  ORDER BY account_code
  LIMIT 1;

  -- Process Allocations
  v_total_allocated := 0;

  IF p_allocations IS NOT NULL AND jsonb_array_length(p_allocations) > 0 THEN
    FOR v_alloc_record IN SELECT * FROM jsonb_array_elements(p_allocations)
    LOOP
      v_invoice_id   := (v_alloc_record->>'invoice_id')::uuid;
      v_alloc_amount := (v_alloc_record->>'amount')::numeric;

      SELECT
        COALESCE(total_amount, 0),
        COALESCE(paid_amount, 0),
        COALESCE(exchange_rate, 1),
        branch_id,
        customer_id,
        invoice_number
      INTO v_inv_total, v_inv_paid, v_inv_rate, v_inv_branch_id, v_inv_customer_id, v_inv_number
      FROM invoices
      WHERE id = v_invoice_id AND company_id = p_company_id AND customer_id = p_customer_id;

      IF NOT FOUND THEN
        RAISE EXCEPTION 'Invoice % does not belong to this customer/company', v_invoice_id;
      END IF;

      v_inv_net := GREATEST(v_inv_total - v_inv_paid, 0);
      IF v_alloc_amount > v_inv_net + 0.01 THEN
        RAISE EXCEPTION 'OVERPAYMENT_BLOCKED: Allocation of % exceeds outstanding % on invoice %',
          v_alloc_amount, v_inv_net, v_invoice_id;
      END IF;

      INSERT INTO payment_allocations (payment_id, invoice_id, allocated_amount, company_id)
      VALUES (v_payment_id, v_invoice_id, v_alloc_amount, p_company_id)
      ON CONFLICT DO NOTHING;

      v_total_allocated := v_total_allocated + v_alloc_amount;

      -- FX Gain/Loss Journal (only if approved and rates differ)
      IF v_status = 'approved'
         AND v_inv_rate IS NOT NULL
         AND p_exchange_rate IS NOT NULL
         AND ABS(v_inv_rate - p_exchange_rate) > 0.0001
         AND v_fx_gain_id IS NOT NULL
         AND v_fx_loss_id IS NOT NULL
         AND v_ar_id IS NOT NULL
      THEN
        v_fx_amount := v_alloc_amount * (p_exchange_rate - v_inv_rate);
        v_fx_description := format('فرق صرف محقق - فاتورة %s', v_inv_number);

        IF ABS(v_fx_amount) >= 0.01 THEN
          -- Insert FX journal entry as 'draft' first, then update to 'posted'
          -- This satisfies enforce_je_integrity which requires lines before posting
          INSERT INTO journal_entries (
            company_id, reference_type, reference_id, entry_date,
            description, branch_id, status
          ) VALUES (
            p_company_id, 'fx_gain_loss', v_payment_id, p_payment_date,
            v_fx_description, COALESCE(v_inv_branch_id, p_branch_id), 'draft'
          ) RETURNING id INTO v_fx_journal_id;

          IF v_fx_amount > 0 THEN
            -- FX GAIN: Dr. AR / Cr. FX Gain
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id)
            VALUES
              (v_fx_journal_id, v_ar_id,      ABS(v_fx_amount), 0,               v_fx_description, COALESCE(v_inv_branch_id, p_branch_id)),
              (v_fx_journal_id, v_fx_gain_id, 0,               ABS(v_fx_amount), v_fx_description, COALESCE(v_inv_branch_id, p_branch_id));
          ELSE
            -- FX LOSS: Dr. FX Loss / Cr. AR
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id)
            VALUES
              (v_fx_journal_id, v_fx_loss_id, ABS(v_fx_amount), 0,               v_fx_description, COALESCE(v_inv_branch_id, p_branch_id)),
              (v_fx_journal_id, v_ar_id,      0,               ABS(v_fx_amount), v_fx_description, COALESCE(v_inv_branch_id, p_branch_id));
          END IF;

          -- Now post the journal entry (lines exist, enforce_je_integrity will pass)
          UPDATE journal_entries SET status = 'posted' WHERE id = v_fx_journal_id;
        END IF;
      END IF;

    END LOOP;
  END IF;

  -- Update unallocated remainder
  UPDATE payments
  SET unallocated_amount = p_payment_amount - v_total_allocated
  WHERE id = v_payment_id;

  RETURN v_payment_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_goods_receipt_atomic(p_grn_id uuid, p_user_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_goods_receipt_atomic(p_grn_id uuid, p_user_id uuid, p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_grn RECORD;
  v_user_role TEXT;
  v_item RECORD;
  v_inventory_tx_id UUID;
  v_po_status TEXT;
BEGIN
  SELECT role INTO v_user_role
  FROM company_members
  WHERE company_id = p_company_id AND user_id = p_user_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User is not a member of this company');
  END IF;
  
  SELECT * INTO v_grn
  FROM goods_receipts
  WHERE id = p_grn_id AND company_id = p_company_id AND status = 'draft'
  FOR UPDATE;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'GRN not found or not in draft status');
  END IF;
  
  IF v_grn.warehouse_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Warehouse is required');
  END IF;
  
  FOR v_item IN 
    SELECT * FROM goods_receipt_items
    WHERE goods_receipt_id = p_grn_id
      AND quantity_accepted > 0
      AND item_type = 'product'
  LOOP
    INSERT INTO inventory_transactions (
      company_id, branch_id, warehouse_id, cost_center_id, product_id,
      transaction_type, quantity_change, reference_id, reference_type, notes, transaction_date
    )
    VALUES (
      p_company_id, v_grn.branch_id, v_grn.warehouse_id, v_grn.cost_center_id, v_item.product_id,
      'purchase', v_item.quantity_accepted, p_grn_id, 'goods_receipt',
      'Goods receipt ' || v_grn.grn_number, v_grn.receipt_date
    )
    RETURNING id INTO v_inventory_tx_id;
  END LOOP;
  
  IF v_grn.total_quantity_rejected > 0 THEN
    v_po_status := 'partially_received';
  ELSE
    v_po_status := 'received';
  END IF;
  
  UPDATE goods_receipts
  SET status = v_po_status, received_by = p_user_id, received_at = NOW(), updated_at = NOW()
  WHERE id = p_grn_id;
  
  IF v_grn.purchase_order_id IS NOT NULL THEN
    UPDATE purchase_orders
    SET 
      status = CASE 
        WHEN EXISTS (
          SELECT 1 FROM goods_receipt_items gri
          JOIN purchase_order_items poi ON gri.purchase_order_item_id = poi.id
          WHERE gri.goods_receipt_id = p_grn_id AND poi.quantity > gri.quantity_accepted
        ) THEN 'partially_received'
        ELSE 'received'
      END,
      goods_receipt_id = p_grn_id,
      updated_at = NOW()
    WHERE id = v_grn.purchase_order_id;
  END IF;
  
  INSERT INTO audit_logs (
    company_id, user_id, action, entity_type, entity_id, old_values, new_values, created_at
  )
  VALUES (
    p_company_id, p_user_id, 'goods_receipt_processed', 'goods_receipt', p_grn_id,
    jsonb_build_object('status', 'draft'),
    jsonb_build_object('status', v_po_status),
    NOW()
  );
  
  RETURN jsonb_build_object('success', true, 'grn_id', p_grn_id, 'status', v_po_status);
  
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- process_invoice_payment_atomic(p_invoice_id uuid, p_company_id uuid, p_customer_id uuid, p_amount numeric, p_payment_date date, p_payment_method text, p_reference_number text, p_notes text, p_account_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_warehouse_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_invoice_payment_atomic(p_invoice_id uuid, p_company_id uuid, p_customer_id uuid, p_amount numeric, p_payment_date date, p_payment_method text, p_reference_number text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_account_id uuid DEFAULT NULL::uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_invoice              RECORD;
  v_payment_id           UUID;
  v_branch_id            UUID;
  v_new_paid_amount      NUMERIC;
  v_new_status           TEXT;
  v_net_invoice_amount   NUMERIC;
BEGIN
  -- ✅ Lock invoice row to prevent race conditions
  SELECT * INTO v_invoice FROM invoices
  WHERE id = p_invoice_id AND company_id = p_company_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'INVOICE_NOT_FOUND: Invoice % not found for company %',
      p_invoice_id, p_company_id;
  END IF;

  -- ✅ Guard: Cannot pay a draft invoice — must be sent first
  IF v_invoice.status = 'draft' THEN
    RAISE EXCEPTION 'PAYMENT_ON_DRAFT: Cannot record payment for a draft invoice (%). Please send the invoice first.',
      v_invoice.invoice_number;
  END IF;

  -- ✅ Guard: Cannot pay a cancelled or fully returned invoice
  IF v_invoice.status IN ('cancelled', 'fully_returned') THEN
    RAISE EXCEPTION 'PAYMENT_BLOCKED: Invoice % has status %. Payment not allowed.',
      v_invoice.invoice_number, v_invoice.status;
  END IF;

  -- ✅ Guard: Duplicate payment check
  IF EXISTS (
    SELECT 1 FROM payments
    WHERE invoice_id = p_invoice_id
      AND amount = p_amount
      AND payment_date = p_payment_date
      AND COALESCE(reference_number, '') = COALESCE(p_reference_number, '')
      AND COALESCE(is_deleted, false) = false
  ) THEN
    RAISE EXCEPTION 'DUPLICATE_PAYMENT: A payment of % on % already exists for invoice %',
      p_amount, p_payment_date, p_invoice_id;
  END IF;

  -- ✅ Resolve branch
  v_branch_id := COALESCE(p_branch_id, v_invoice.branch_id);
  IF v_branch_id IS NULL THEN
    SELECT id INTO v_branch_id FROM branches
    WHERE company_id = p_company_id AND is_active = true
    ORDER BY is_main DESC NULLS LAST, name LIMIT 1;
  END IF;
  IF v_branch_id IS NULL THEN
    RAISE EXCEPTION 'NO_BRANCH: No active branch for company %', p_company_id;
  END IF;

  -- ✅ Insert the payment record
  -- Note: auto_create_payment_journal trigger will AUTOMATICALLY create
  --       DR: Cash/Bank / CR: Accounts Receivable entry
  INSERT INTO payments (
    company_id, customer_id, invoice_id, payment_date, amount,
    payment_method, reference_number, notes,
    account_id, branch_id, cost_center_id, warehouse_id
  ) VALUES (
    p_company_id, p_customer_id, p_invoice_id, p_payment_date, p_amount,
    p_payment_method,
    p_reference_number,
    COALESCE(p_notes, 'دفعة على الفاتورة ' || v_invoice.invoice_number),
    p_account_id, v_branch_id, p_cost_center_id, p_warehouse_id
  ) RETURNING id INTO v_payment_id;

  -- ================================================================
  -- IMPORTANT: Revenue JE is NOT created here anymore.
  -- It was created when invoice was changed to 'sent' via
  -- trg_invoice_sent_accrual → handle_invoice_sent_accrual()
  --
  -- At payment time, the accounting is simply:
  --   DR: Cash/Bank / CR: Accounts Receivable
  -- This is handled by auto_create_payment_journal trigger on payments.
  -- ================================================================

  -- ✅ Check if Revenue JE exists (warn if missing — should not happen with new trigger)
  IF NOT EXISTS (
    SELECT 1 FROM journal_entries
    WHERE company_id = p_company_id
      AND reference_type = 'invoice'
      AND reference_id = p_invoice_id
      AND (is_deleted IS NULL OR is_deleted = false)
  ) THEN
    RAISE WARNING 'WARNING: No Revenue JE found for invoice % at payment time. Invoice may not have been properly sent.',
      v_invoice.invoice_number;
  END IF;

  -- ✅ Update invoice: paid_amount + status
  v_new_paid_amount    := COALESCE(v_invoice.paid_amount, 0) + p_amount;
  v_net_invoice_amount := GREATEST(0, v_invoice.total_amount - COALESCE(v_invoice.returned_amount, 0));
  v_new_status         := CASE
    WHEN v_new_paid_amount >= v_net_invoice_amount THEN 'paid'
    ELSE 'partially_paid'
  END;

  PERFORM set_config('app.skip_je_check', 'true', true);
  UPDATE invoices
  SET paid_amount = v_new_paid_amount,
      status      = v_new_status,
      updated_at  = NOW()
  WHERE id = p_invoice_id;
  PERFORM set_config('app.skip_je_check', 'false', true);

  -- ✅ Audit log
  BEGIN
    INSERT INTO audit_logs (
      company_id, user_id, action, target_table, record_id,
      record_identifier, old_data, new_data
    ) VALUES (
      p_company_id, p_user_id, 'INSERT', 'payments', v_payment_id,
      v_invoice.invoice_number,
      jsonb_build_object('status', v_invoice.status, 'paid_amount', v_invoice.paid_amount),
      jsonb_build_object(
        'status', v_new_status,
        'paid_amount', v_new_paid_amount,
        'payment_id', v_payment_id,
        'accounting_model', 'accrual_cash_settlement'
      )
    );
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  RETURN jsonb_build_object(
    'success',                 true,
    'payment_id',              v_payment_id,
    'new_paid_amount',         v_new_paid_amount,
    'new_status',              v_new_status,
    'net_invoice_amount',      v_net_invoice_amount,
    'remaining',               GREATEST(0, v_net_invoice_amount - v_new_paid_amount),
    'invoice_journal_created', false,   -- Revenue already existed from send-time
    'accounting_model',        'accrual_basis'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- process_invoice_payment_atomic_v2(p_invoice_id uuid, p_company_id uuid, p_customer_id uuid, p_amount numeric, p_payment_date date, p_payment_method text, p_reference_number text, p_notes text, p_account_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_warehouse_id uuid, p_user_id uuid, p_idempotency_key text, p_request_hash text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_invoice_payment_atomic_v2(p_invoice_id uuid, p_company_id uuid, p_customer_id uuid, p_amount numeric, p_payment_date date, p_payment_method text, p_reference_number text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_account_id uuid DEFAULT NULL::uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_user_id uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text, p_request_hash text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_invoice             RECORD;
  v_payment_id          UUID;
  v_branch_id           UUID;
  v_new_paid_amount     NUMERIC;
  v_new_status          TEXT;
  v_net_invoice_amount  NUMERIC;
  v_idempotency_result  JSONB;
  v_transaction_id      UUID;
  v_payment_journal_id  UUID;
  v_result              JSONB;
BEGIN
  PERFORM public.require_open_financial_period_db(p_company_id, p_payment_date);

  IF p_idempotency_key IS NOT NULL THEN
    v_idempotency_result := public.check_and_claim_idempotency_key(
      p_idempotency_key,
      p_company_id,
      'invoice_payment_v2',
      p_request_hash,
      p_user_id
    );

    IF v_idempotency_result IS NOT NULL AND COALESCE(v_idempotency_result->>'cached', 'false') = 'true' THEN
      RETURN COALESCE(v_idempotency_result->'response', jsonb_build_object('success', true))
        || jsonb_build_object('cached', true, 'idempotent', true);
    END IF;
  END IF;

  SELECT *
  INTO v_invoice
  FROM public.invoices
  WHERE id = p_invoice_id
    AND company_id = p_company_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'INVOICE_NOT_FOUND: Invoice % not found for company %',
      p_invoice_id, p_company_id
      USING ERRCODE = 'P0001';
  END IF;

  IF EXISTS (
    SELECT 1
    FROM public.payments
    WHERE invoice_id = p_invoice_id
      AND amount = p_amount
      AND payment_date = p_payment_date
      AND COALESCE(reference_number, '') = COALESCE(p_reference_number, '')
      AND COALESCE(is_deleted, FALSE) = FALSE
  ) THEN
    RAISE EXCEPTION
      'DUPLICATE_PAYMENT: A payment of % on % with reference [%] already exists for invoice %',
      p_amount, p_payment_date, COALESCE(p_reference_number, ''), p_invoice_id
      USING ERRCODE = 'P0001';
  END IF;

  v_branch_id := COALESCE(p_branch_id, v_invoice.branch_id);

  IF v_branch_id IS NULL THEN
    SELECT id
    INTO v_branch_id
    FROM public.branches
    WHERE company_id = p_company_id
      AND is_active = TRUE
    ORDER BY is_main DESC NULLS LAST, name
    LIMIT 1;
  END IF;

  IF v_branch_id IS NULL THEN
    RAISE EXCEPTION 'NO_BRANCH: No active branch found for company %. Create at least one branch.', p_company_id
      USING ERRCODE = 'P0001';
  END IF;

  INSERT INTO public.payments (
    company_id,
    customer_id,
    invoice_id,
    payment_date,
    amount,
    payment_method,
    reference_number,
    notes,
    account_id,
    branch_id,
    cost_center_id,
    warehouse_id
  ) VALUES (
    p_company_id,
    p_customer_id,
    p_invoice_id,
    p_payment_date,
    p_amount,
    p_payment_method,
    p_reference_number,
    COALESCE(p_notes, 'دفعة على الفاتورة ' || v_invoice.invoice_number),
    p_account_id,
    v_branch_id,
    p_cost_center_id,
    p_warehouse_id
  )
  RETURNING id INTO v_payment_id;

  SELECT journal_entry_id
  INTO v_payment_journal_id
  FROM public.payments
  WHERE id = v_payment_id;

  v_new_paid_amount := COALESCE(v_invoice.paid_amount, 0) + p_amount;

  v_net_invoice_amount := CASE
    WHEN COALESCE(v_invoice.returned_amount, 0) > 0
         AND v_invoice.total_amount < COALESCE(v_invoice.returned_amount, 0)
      THEN v_invoice.total_amount
    ELSE GREATEST(0, v_invoice.total_amount - COALESCE(v_invoice.returned_amount, 0))
  END;

  v_new_status := CASE
    WHEN v_new_paid_amount >= v_net_invoice_amount THEN 'paid'
    ELSE 'partially_paid'
  END;

  UPDATE public.invoices
  SET
    paid_amount = v_new_paid_amount,
    status = v_new_status,
    updated_at = NOW()
  WHERE id = p_invoice_id;

  v_transaction_id := public.create_financial_operation_trace(
    p_company_id,
    'invoice',
    p_invoice_id,
    'invoice_payment',
    p_user_id,
    p_idempotency_key,
    p_request_hash,
    jsonb_build_object(
      'payment_id', v_payment_id,
      'payment_method', p_payment_method
    ),
    '[]'::JSONB
  );

  PERFORM public.link_financial_operation_trace(v_transaction_id, 'invoice', p_invoice_id, 'source', 'invoice_payment');
  PERFORM public.link_financial_operation_trace(v_transaction_id, 'payment', v_payment_id, 'payment', 'invoice_payment');

  IF v_payment_journal_id IS NOT NULL THEN
    PERFORM public.link_financial_operation_trace(v_transaction_id, 'journal_entry', v_payment_journal_id, 'journal_entry', 'invoice_payment');
  END IF;

  v_result := jsonb_build_object(
    'success', true,
    'payment_id', v_payment_id,
    'journal_entry_id', v_payment_journal_id,
    'new_paid_amount', v_new_paid_amount,
    'new_status', v_new_status,
    'net_invoice_amount', v_net_invoice_amount,
    'remaining', GREATEST(0, v_net_invoice_amount - v_new_paid_amount),
    'invoice_journal_created', false,
    'transaction_id', v_transaction_id,
    'source_entity', 'invoice',
    'source_id', p_invoice_id,
    'event_type', 'invoice_payment'
  );

  IF p_idempotency_key IS NOT NULL THEN
    PERFORM public.complete_idempotency_key(
      p_idempotency_key,
      p_company_id,
      'invoice_payment_v2',
      v_result,
      TRUE
    );
  END IF;

  RETURN v_result;

EXCEPTION
  WHEN OTHERS THEN
    IF p_idempotency_key IS NOT NULL THEN
      BEGIN
        PERFORM public.complete_idempotency_key(
          p_idempotency_key,
          p_company_id,
          'invoice_payment_v2',
          jsonb_build_object(
            'success', false,
            'error', SQLERRM,
            'source_entity', 'invoice',
            'source_id', p_invoice_id,
            'event_type', 'invoice_payment'
          ),
          FALSE
        );
      EXCEPTION WHEN OTHERS THEN
        NULL;
      END;
    END IF;
    RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_invoice_payment_atomic_v2(p_invoice_id uuid, p_company_id uuid, p_customer_id uuid, p_amount numeric, p_payment_date date, p_payment_method text, p_reference_number text, p_notes text, p_account_id uuid, p_branch_id uuid, p_cost_center_id uuid, p_warehouse_id uuid, p_user_id uuid, p_idempotency_key text, p_request_hash text, p_payment_currency text, p_exchange_rate numeric, p_original_amount numeric, p_exchange_rate_id uuid, p_rate_source text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_invoice_payment_atomic_v2(p_invoice_id uuid, p_company_id uuid, p_customer_id uuid, p_amount numeric, p_payment_date date, p_payment_method text, p_reference_number text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_account_id uuid DEFAULT NULL::uuid, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_user_id uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text, p_request_hash text DEFAULT NULL::text, p_payment_currency text DEFAULT NULL::text, p_exchange_rate numeric DEFAULT NULL::numeric, p_original_amount numeric DEFAULT NULL::numeric, p_exchange_rate_id uuid DEFAULT NULL::uuid, p_rate_source text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_invoice             RECORD;
  v_payment_id          UUID;
  v_branch_id           UUID;
  v_new_paid_amount     NUMERIC;
  v_new_status          TEXT;
  v_net_invoice_amount  NUMERIC;
  v_idempotency_result  JSONB;
  v_transaction_id      UUID;
  v_payment_journal_id  UUID;
  v_result              JSONB;
  v_base_ccy            TEXT;
  v_pay_ccy             TEXT;
  v_pay_rate            NUMERIC;
  v_pay_orig_amount     NUMERIC;
  v_ref_no              TEXT;
BEGIN
  PERFORM public.require_open_financial_period_db(p_company_id, p_payment_date);

  IF p_idempotency_key IS NOT NULL THEN
    v_idempotency_result := public.check_and_claim_idempotency_key(
      p_idempotency_key, p_company_id, 'invoice_payment_v2', p_request_hash, p_user_id);
    IF v_idempotency_result IS NOT NULL AND COALESCE(v_idempotency_result->>'cached', 'false') = 'true' THEN
      RETURN COALESCE(v_idempotency_result->'response', jsonb_build_object('success', true))
        || jsonb_build_object('cached', true, 'idempotent', true);
    END IF;
  END IF;

  SELECT * INTO v_invoice FROM public.invoices
  WHERE id = p_invoice_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'INVOICE_NOT_FOUND: Invoice % not found for company %', p_invoice_id, p_company_id
      USING ERRCODE = 'P0001';
  END IF;

  IF EXISTS (
    SELECT 1 FROM public.payments
    WHERE invoice_id = p_invoice_id AND amount = p_amount AND payment_date = p_payment_date
      AND COALESCE(reference_number, '') = COALESCE(p_reference_number, '')
      AND COALESCE(is_deleted, FALSE) = FALSE
  ) THEN
    RAISE EXCEPTION 'DUPLICATE_PAYMENT: A payment of % on % with reference [%] already exists for invoice %',
      p_amount, p_payment_date, COALESCE(p_reference_number, ''), p_invoice_id
      USING ERRCODE = 'P0001';
  END IF;

  v_branch_id := COALESCE(p_branch_id, v_invoice.branch_id);
  IF v_branch_id IS NULL THEN
    SELECT id INTO v_branch_id FROM public.branches
    WHERE company_id = p_company_id AND is_active = TRUE
    ORDER BY is_main DESC NULLS LAST, name LIMIT 1;
  END IF;
  IF v_branch_id IS NULL THEN
    RAISE EXCEPTION 'NO_BRANCH: No active branch found for company %. Create at least one branch.', p_company_id
      USING ERRCODE = 'P0001';
  END IF;

  -- v3.74.219 — resolve FX context
  SELECT base_currency INTO v_base_ccy FROM companies WHERE id = p_company_id;
  v_base_ccy := UPPER(COALESCE(v_base_ccy, 'EGP'));
  v_pay_ccy := UPPER(COALESCE(p_payment_currency, v_base_ccy));
  v_pay_rate := COALESCE(NULLIF(p_exchange_rate, 0), 1);
  v_pay_orig_amount := COALESCE(p_original_amount,
    CASE WHEN v_pay_ccy = v_base_ccy THEN p_amount ELSE p_amount / NULLIF(v_pay_rate, 0) END);

  -- v3.74.219 — auto-generate reference_number if caller didn't provide one
  v_ref_no := COALESCE(NULLIF(TRIM(p_reference_number), ''),
    'TXN-' || COALESCE(v_invoice.invoice_number, SUBSTRING(p_invoice_id::text FROM 1 FOR 8))
    || '-' || to_char(NOW(), 'YYYYMMDDHH24MISS'));

  INSERT INTO public.payments (
    company_id, customer_id, invoice_id, payment_date, amount, payment_method,
    reference_number, notes, account_id, branch_id, cost_center_id, warehouse_id,
    -- v3.74.219 — FX context now persisted on the row
    currency_code, exchange_rate, exchange_rate_used, base_currency_amount,
    original_amount, original_currency, exchange_rate_id, rate_source,
    -- v3.74.219 — creator + approver from p_user_id
    created_by, created_by_user_id, approved_by, approved_at, status
  ) VALUES (
    p_company_id, p_customer_id, p_invoice_id, p_payment_date, p_amount, p_payment_method,
    v_ref_no, COALESCE(p_notes, 'دفعة على الفاتورة ' || v_invoice.invoice_number),
    p_account_id, v_branch_id, p_cost_center_id, p_warehouse_id,
    v_pay_ccy, v_pay_rate, v_pay_rate, p_amount,
    v_pay_orig_amount, v_pay_ccy, p_exchange_rate_id, COALESCE(p_rate_source, 'manual'),
    p_user_id, p_user_id, p_user_id, NOW(), 'approved'
  ) RETURNING id INTO v_payment_id;

  SELECT journal_entry_id INTO v_payment_journal_id FROM public.payments WHERE id = v_payment_id;

  v_new_paid_amount := COALESCE(v_invoice.paid_amount, 0) + p_amount;
  v_net_invoice_amount := CASE
    WHEN COALESCE(v_invoice.returned_amount, 0) > 0 AND v_invoice.total_amount < COALESCE(v_invoice.returned_amount, 0)
      THEN v_invoice.total_amount
    ELSE GREATEST(0, v_invoice.total_amount - COALESCE(v_invoice.returned_amount, 0))
  END;
  v_new_status := CASE WHEN v_new_paid_amount >= v_net_invoice_amount THEN 'paid' ELSE 'partially_paid' END;

  UPDATE public.invoices
  SET paid_amount = v_new_paid_amount, status = v_new_status, updated_at = NOW()
  WHERE id = p_invoice_id;

  v_transaction_id := public.create_financial_operation_trace(
    p_company_id, 'invoice', p_invoice_id, 'invoice_payment',
    p_user_id, p_idempotency_key, p_request_hash,
    jsonb_build_object('payment_id', v_payment_id, 'payment_method', p_payment_method,
                       'currency_code', v_pay_ccy, 'exchange_rate', v_pay_rate),
    '[]'::JSONB
  );
  PERFORM public.link_financial_operation_trace(v_transaction_id, 'invoice', p_invoice_id, 'source', 'invoice_payment');
  PERFORM public.link_financial_operation_trace(v_transaction_id, 'payment', v_payment_id, 'payment', 'invoice_payment');
  IF v_payment_journal_id IS NOT NULL THEN
    PERFORM public.link_financial_operation_trace(v_transaction_id, 'journal_entry', v_payment_journal_id, 'journal_entry', 'invoice_payment');
  END IF;

  v_result := jsonb_build_object(
    'success', true, 'payment_id', v_payment_id,
    'journal_entry_id', v_payment_journal_id,
    'new_paid_amount', v_new_paid_amount, 'new_status', v_new_status,
    'net_invoice_amount', v_net_invoice_amount,
    'remaining', GREATEST(0, v_net_invoice_amount - v_new_paid_amount),
    'invoice_journal_created', false,
    'transaction_id', v_transaction_id,
    'source_entity', 'invoice', 'source_id', p_invoice_id,
    'event_type', 'invoice_payment',
    'currency_code', v_pay_ccy, 'exchange_rate', v_pay_rate
  );

  IF p_idempotency_key IS NOT NULL THEN
    PERFORM public.complete_idempotency_key(p_idempotency_key, p_company_id, 'invoice_payment_v2', v_result, TRUE);
  END IF;

  RETURN v_result;

EXCEPTION WHEN OTHERS THEN
  IF p_idempotency_key IS NOT NULL THEN
    BEGIN
      PERFORM public.complete_idempotency_key(p_idempotency_key, p_company_id, 'invoice_payment_v2',
        jsonb_build_object('success', false, 'error', SQLERRM,
                           'source_entity', 'invoice', 'source_id', p_invoice_id,
                           'event_type', 'invoice_payment'),
        FALSE);
    EXCEPTION WHEN OTHERS THEN NULL; END;
  END IF;
  RAISE;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_invoice_return_in_tpi(p_invoice_id uuid, p_return_items jsonb, p_return_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_invoice_return_in_tpi(p_invoice_id uuid, p_return_items jsonb, p_return_type text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_item JSONB;
  v_product_id UUID;
  v_return_qty NUMERIC;
  v_tpi RECORD;
BEGIN
  IF p_return_type = 'full' THEN
    -- مرتجع كامل: تحديث جميع البنود
    UPDATE third_party_inventory
    SET
      returned_quantity = quantity,
      status = 'returned',
      delivery_status = 'returned',
      payment_status = CASE WHEN payment_status = 'paid' THEN 'paid' ELSE 'unpaid' END,
      updated_at = NOW()
    WHERE invoice_id = p_invoice_id;

  ELSE
    -- مرتجع جزئي: تحديث البنود المحددة فقط
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_return_items)
    LOOP
      v_product_id := (v_item->>'product_id')::UUID;
      v_return_qty := (v_item->>'quantity')::NUMERIC;

      SELECT * INTO v_tpi 
      FROM third_party_inventory 
      WHERE invoice_id = p_invoice_id AND product_id = v_product_id;

      IF FOUND THEN
        UPDATE third_party_inventory
        SET
          returned_quantity = LEAST(returned_quantity + v_return_qty, quantity),
          status = CASE 
            WHEN (returned_quantity + v_return_qty) >= quantity THEN 'returned'
            ELSE 'partial'
          END,
          delivery_status = CASE 
            WHEN (returned_quantity + v_return_qty) >= quantity THEN 'returned'
            ELSE 'partially_returned'
          END,
          updated_at = NOW()
        WHERE invoice_id = p_invoice_id AND product_id = v_product_id;
      END IF;
    END LOOP;
  END IF;

  RETURN jsonb_build_object('success', true);
EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'PROCESS_RETURN_TPI_FAILED: %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_payment_approval_stage(p_payment_id uuid, p_action character varying, p_rejection_reason character varying)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_payment_approval_stage(p_payment_id uuid, p_action character varying, p_rejection_reason character varying DEFAULT NULL::character varying)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_payment RECORD;
  v_user_role VARCHAR;
  v_user_id UUID := auth.uid();
  v_next_status VARCHAR;
BEGIN
  -- Get payment
  SELECT * INTO v_payment FROM payments WHERE id = p_payment_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Payment not found'; END IF;

  -- Get user role in the company
  SELECT role INTO v_user_role FROM company_members 
  WHERE user_id = v_user_id AND company_id = v_payment.company_id;

  IF v_user_role IS NULL THEN RAISE EXCEPTION 'Unauthorized'; END IF;

  IF p_action = 'REJECT' THEN
    UPDATE payments SET 
      status = 'rejected', 
      rejection_reason = p_rejection_reason,
      rejected_by = v_user_id,
      rejected_at = NOW()
    WHERE id = p_payment_id;
    RETURN;
  END IF;

  IF p_action = 'APPROVE' THEN
    -- Configurable Hierarchy: Accountant -> Manager -> Owner/Admin/GM
    IF v_payment.status = 'pending_approval' THEN
        IF v_user_role IN ('owner', 'admin', 'general_manager') THEN
            v_next_status := 'approved';
        ELSIF v_user_role IN ('manager') THEN
            v_next_status := 'pending_director';
        ELSE
            RAISE EXCEPTION 'Role % cannot approve this stage', v_user_role;
        END IF;
    ELSIF v_payment.status = 'pending_manager' THEN
        IF v_user_role IN ('manager', 'owner', 'admin', 'general_manager') THEN
             v_next_status := 'pending_director';
        ELSE
             RAISE EXCEPTION 'Role % cannot approve manager stage', v_user_role;
        END IF;
    ELSIF v_payment.status = 'pending_director' THEN
        IF v_user_role IN ('owner', 'admin', 'general_manager') THEN
             v_next_status := 'approved';
        ELSE
             RAISE EXCEPTION 'Role % cannot approve director stage', v_user_role;
        END IF;
    ELSE
        RAISE EXCEPTION 'Payment is in status %, cannot approve', v_payment.status;
    END IF;

    -- Execute stage update
    UPDATE payments SET 
      status = v_next_status,
      approved_by = CASE WHEN v_next_status = 'approved' THEN v_user_id ELSE approved_by END,
      approved_at = CASE WHEN v_next_status = 'approved' THEN NOW() ELSE approved_at END,
      current_approval_role = CASE WHEN v_next_status = 'approved' THEN NULL ELSE 'director' END
    WHERE id = p_payment_id;
    
    RETURN;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_purchase_return_atomic(p_company_id uuid, p_supplier_id uuid, p_bill_id uuid, p_purchase_return jsonb, p_return_items jsonb, p_journal_entry jsonb, p_journal_lines jsonb, p_vendor_credit jsonb, p_vendor_credit_items jsonb, p_bill_update jsonb, p_workflow_status text, p_created_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_purchase_return_atomic(p_company_id uuid, p_supplier_id uuid, p_bill_id uuid, p_purchase_return jsonb, p_return_items jsonb, p_journal_entry jsonb DEFAULT NULL::jsonb, p_journal_lines jsonb DEFAULT NULL::jsonb, p_vendor_credit jsonb DEFAULT NULL::jsonb, p_vendor_credit_items jsonb DEFAULT NULL::jsonb, p_bill_update jsonb DEFAULT NULL::jsonb, p_workflow_status text DEFAULT 'pending_admin_approval'::text, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_pr_id           UUID;
  v_je_id           UUID;
  v_vc_id           UUID;
  v_item            JSONB;
  v_bill_item       RECORD;
  v_current_stock   NUMERIC;
  v_requested_qty   NUMERIC;
  v_product_id      UUID;
  v_bill_item_id    UUID;
  v_warehouse_id    UUID;
  v_branch_id       UUID;
  v_cost_center_id  UUID;
  v_is_pending      BOOLEAN;
  v_je_status       TEXT;
  v_result          JSONB := '{}';
  v_refund_account_id UUID;
BEGIN
  v_warehouse_id   := NULLIF(p_purchase_return->>'warehouse_id', '')::UUID;
  v_branch_id      := NULLIF(p_purchase_return->>'branch_id', '')::UUID;
  v_cost_center_id := NULLIF(p_purchase_return->>'cost_center_id', '')::UUID;
  v_refund_account_id := NULLIF(p_purchase_return->>'refund_account_id', '')::UUID;

  v_is_pending := p_workflow_status IN ('pending_admin_approval', 'pending_approval', 'pending_warehouse');
  v_je_status := CASE WHEN v_is_pending THEN 'draft' ELSE 'posted' END;

  IF p_bill_id IS NULL THEN
    RAISE EXCEPTION 'Bill ID is required to create a purchase return';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM bills WHERE id = p_bill_id AND company_id = p_company_id) THEN
    RAISE EXCEPTION 'Bill not found or does not belong to company: %', p_bill_id;
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_return_items) LOOP
    v_bill_item_id  := NULLIF(v_item->>'bill_item_id', '')::UUID;
    v_product_id    := NULLIF(v_item->>'product_id', '')::UUID;
    v_requested_qty := COALESCE((v_item->>'quantity')::NUMERIC, 0);
    IF v_requested_qty <= 0 THEN CONTINUE; END IF;

    IF v_bill_item_id IS NOT NULL AND NOT v_is_pending THEN
      SELECT id, quantity, COALESCE(returned_quantity, 0) AS returned_quantity
      INTO v_bill_item FROM bill_items WHERE id = v_bill_item_id FOR UPDATE;
      IF NOT FOUND THEN
        RAISE EXCEPTION 'Bill item not found: %', v_bill_item_id;
      END IF;
      IF (v_bill_item.returned_quantity + v_requested_qty) > v_bill_item.quantity THEN
        RAISE EXCEPTION 'Cannot return % units. Available: %',
          v_requested_qty, (v_bill_item.quantity - v_bill_item.returned_quantity);
      END IF;
    END IF;

    IF v_product_id IS NOT NULL AND v_warehouse_id IS NOT NULL AND NOT v_is_pending THEN
      PERFORM pg_advisory_xact_lock(
        hashtext(p_company_id::text || v_product_id::text || v_warehouse_id::text));
      SELECT COALESCE(SUM(quantity_change), 0) INTO v_current_stock
      FROM inventory_transactions
      WHERE company_id = p_company_id AND product_id = v_product_id
        AND warehouse_id = v_warehouse_id
        AND COALESCE(is_deleted, false) = false;
      IF v_current_stock < v_requested_qty THEN
        RAISE EXCEPTION 'Insufficient stock for product %. Available: %, Requested: %',
          v_product_id, v_current_stock, v_requested_qty;
      END IF;
    END IF;
  END LOOP;

  IF p_journal_entry IS NOT NULL THEN
    INSERT INTO journal_entries (
      company_id, branch_id, cost_center_id, reference_type, reference_id,
      entry_date, description, status
    ) VALUES (
      p_company_id, v_branch_id, v_cost_center_id,
      'purchase_return', NULL,
      (p_journal_entry->>'entry_date')::DATE,
      p_journal_entry->>'description',
      v_je_status
    ) RETURNING id INTO v_je_id;

    IF p_journal_lines IS NOT NULL AND jsonb_array_length(p_journal_lines) > 0 THEN
      INSERT INTO journal_entry_lines (
        journal_entry_id, account_id, debit_amount, credit_amount,
        description, branch_id, cost_center_id
      )
      SELECT v_je_id, (l->>'account_id')::UUID,
        COALESCE((l->>'debit_amount')::NUMERIC, 0),
        COALESCE((l->>'credit_amount')::NUMERIC, 0),
        l->>'description', v_branch_id, v_cost_center_id
      FROM jsonb_array_elements(p_journal_lines) AS l;
    END IF;
    v_result := jsonb_set(v_result, '{journal_entry_id}', to_jsonb(v_je_id));
  END IF;

  -- v3.74.173: persist refund_account_id on the row.
  INSERT INTO purchase_returns (
    company_id, supplier_id, bill_id, journal_entry_id,
    return_number, return_date, status, workflow_status, created_by,
    subtotal, tax_amount, total_amount,
    settlement_method, reason, notes,
    branch_id, cost_center_id, warehouse_id,
    original_currency, original_subtotal, original_tax_amount, original_total_amount,
    exchange_rate_used, exchange_rate_id,
    refund_account_id
  ) VALUES (
    p_company_id, p_supplier_id, p_bill_id, v_je_id,
    p_purchase_return->>'return_number',
    (p_purchase_return->>'return_date')::DATE,
    CASE WHEN v_is_pending THEN 'pending_approval' ELSE 'completed' END,
    COALESCE(NULLIF(p_workflow_status, ''), 'pending_admin_approval'),
    p_created_by,
    COALESCE((p_purchase_return->>'subtotal')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'tax_amount')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'total_amount')::NUMERIC, 0),
    p_purchase_return->>'settlement_method',
    p_purchase_return->>'reason',
    p_purchase_return->>'notes',
    v_branch_id, v_cost_center_id, v_warehouse_id,
    COALESCE(NULLIF(p_purchase_return->>'original_currency', ''), 'EGP'),
    COALESCE((p_purchase_return->>'original_subtotal')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'original_tax_amount')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'original_total_amount')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'exchange_rate_used')::NUMERIC, 1),
    NULLIF(p_purchase_return->>'exchange_rate_id', '')::UUID,
    v_refund_account_id
  ) RETURNING id INTO v_pr_id;

  v_result := jsonb_set(v_result, '{purchase_return_id}', to_jsonb(v_pr_id));

  IF v_je_id IS NOT NULL THEN
    UPDATE journal_entries SET reference_id = v_pr_id WHERE id = v_je_id;
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_return_items) LOOP
    v_product_id    := NULLIF(v_item->>'product_id', '')::UUID;
    v_bill_item_id  := NULLIF(v_item->>'bill_item_id', '')::UUID;
    v_requested_qty := COALESCE((v_item->>'quantity')::NUMERIC, 0);
    IF v_requested_qty <= 0 THEN CONTINUE; END IF;

    INSERT INTO purchase_return_items (
      purchase_return_id, bill_item_id, product_id,
      description, quantity, unit_price, tax_rate, discount_percent, line_total
    ) VALUES (
      v_pr_id, v_bill_item_id, v_product_id,
      v_item->>'description', v_requested_qty,
      COALESCE((v_item->>'unit_price')::NUMERIC, 0),
      COALESCE((v_item->>'tax_rate')::NUMERIC, 0),
      COALESCE((v_item->>'discount_percent')::NUMERIC, 0),
      COALESCE((v_item->>'line_total')::NUMERIC, 0)
    );

    IF NOT v_is_pending THEN
      IF v_bill_item_id IS NOT NULL THEN
        UPDATE bill_items
        SET returned_quantity = COALESCE(returned_quantity, 0) + v_requested_qty
        WHERE id = v_bill_item_id;
      END IF;
      IF v_product_id IS NOT NULL THEN
        INSERT INTO inventory_transactions (
          company_id, product_id, transaction_type, quantity_change,
          reference_id, reference_type, journal_entry_id, notes,
          branch_id, cost_center_id, warehouse_id
        ) VALUES (
          p_company_id, v_product_id, 'purchase_return', -v_requested_qty,
          v_pr_id, 'purchase_return', v_je_id,
          'مرتجع مشتريات ' || COALESCE(p_purchase_return->>'return_number', ''),
          v_branch_id, v_cost_center_id, v_warehouse_id
        );
      END IF;
    END IF;
  END LOOP;

  IF p_vendor_credit IS NOT NULL AND NOT v_is_pending THEN
    IF EXISTS (SELECT 1 FROM vendor_credits WHERE source_purchase_return_id = v_pr_id) THEN
      RAISE EXCEPTION 'Vendor Credit already exists for this purchase return';
    END IF;
    INSERT INTO vendor_credits (
      company_id, supplier_id, bill_id,
      source_purchase_return_id, source_purchase_invoice_id, journal_entry_id,
      credit_number, credit_date, status,
      subtotal, tax_amount, total_amount, applied_amount,
      branch_id, cost_center_id, notes
    ) VALUES (
      p_company_id, p_supplier_id, p_bill_id,
      v_pr_id, p_bill_id, v_je_id,
      p_vendor_credit->>'credit_number',
      COALESCE((p_vendor_credit->>'credit_date')::DATE, CURRENT_DATE),
      'open',
      COALESCE((p_vendor_credit->>'subtotal')::NUMERIC, 0),
      COALESCE((p_vendor_credit->>'tax_amount')::NUMERIC, 0),
      COALESCE((p_vendor_credit->>'total_amount')::NUMERIC, 0),
      0, v_branch_id, v_cost_center_id,
      p_vendor_credit->>'notes'
    ) RETURNING id INTO v_vc_id;

    IF p_vendor_credit_items IS NOT NULL AND jsonb_array_length(p_vendor_credit_items) > 0 THEN
      INSERT INTO vendor_credit_items (
        vendor_credit_id, product_id, description,
        quantity, unit_price, tax_rate, discount_percent, line_total
      )
      SELECT v_vc_id,
        NULLIF(vci->>'product_id', '')::UUID, vci->>'description',
        COALESCE((vci->>'quantity')::NUMERIC, 0),
        COALESCE((vci->>'unit_price')::NUMERIC, 0),
        COALESCE((vci->>'tax_rate')::NUMERIC, 0),
        COALESCE((vci->>'discount_percent')::NUMERIC, 0),
        COALESCE((vci->>'line_total')::NUMERIC, 0)
      FROM jsonb_array_elements(p_vendor_credit_items) AS vci;
    END IF;
    v_result := jsonb_set(v_result, '{vendor_credit_id}', to_jsonb(v_vc_id));
  END IF;

  IF p_bill_update IS NOT NULL AND p_bill_id IS NOT NULL AND NOT v_is_pending THEN
    UPDATE bills SET
      returned_amount = COALESCE(NULLIF(p_bill_update->>'returned_amount', '')::NUMERIC, returned_amount),
      return_status   = COALESCE(NULLIF(p_bill_update->>'return_status', ''), return_status),
      status          = COALESCE(NULLIF(p_bill_update->>'status', ''), status),
      total_amount    = CASE
        WHEN (p_bill_update->>'total_amount') IS NOT NULL AND (p_bill_update->>'total_amount') != ''
        THEN (p_bill_update->>'total_amount')::NUMERIC ELSE total_amount END,
      updated_at = NOW()
    WHERE id = p_bill_id;
  END IF;

  RETURN v_result;
EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'Purchase return failed (rolled back): %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_purchase_return_multi_warehouse(p_company_id uuid, p_supplier_id uuid, p_bill_id uuid, p_purchase_return jsonb, p_warehouse_groups jsonb, p_bill_update jsonb, p_created_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_purchase_return_multi_warehouse(p_company_id uuid, p_supplier_id uuid, p_bill_id uuid, p_purchase_return jsonb, p_warehouse_groups jsonb, p_bill_update jsonb DEFAULT NULL::jsonb, p_created_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_pr_id          UUID;
  v_group          JSONB;
  v_alloc_id       UUID;
  v_je_id          UUID;
  v_item           JSONB;
  v_product_id     UUID;
  v_bill_item_id   UUID;
  v_requested_qty  NUMERIC;
  v_warehouse_id   UUID;
  v_branch_id      UUID;
  v_cost_center_id UUID;
  v_alloc_ids      UUID[] := ARRAY[]::UUID[];
  v_result         JSONB := '{}';
  v_group_count    INT;
  v_qty_check      RECORD;
BEGIN
  IF p_bill_id IS NULL THEN
    RAISE EXCEPTION 'Bill ID is required to create a purchase return';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM bills WHERE id = p_bill_id AND company_id = p_company_id) THEN
    RAISE EXCEPTION 'Bill not found or does not belong to company: %', p_bill_id;
  END IF;

  v_group_count := jsonb_array_length(p_warehouse_groups);
  IF v_group_count < 2 THEN
    RAISE EXCEPTION 'Multi-warehouse function requires at least 2 warehouse groups.';
  END IF;

  FOR v_group IN SELECT * FROM jsonb_array_elements(p_warehouse_groups) LOOP
    v_warehouse_id   := NULLIF(v_group->>'warehouse_id', '')::UUID;
    v_branch_id      := NULLIF(v_group->>'branch_id', '')::UUID;
    v_cost_center_id := NULLIF(v_group->>'cost_center_id', '')::UUID;

    FOR v_item IN SELECT * FROM jsonb_array_elements(v_group->'items') LOOP
      v_bill_item_id  := NULLIF(v_item->>'bill_item_id', '')::UUID;
      v_product_id    := NULLIF(v_item->>'product_id', '')::UUID;
      v_requested_qty := COALESCE((v_item->>'quantity')::NUMERIC, 0);
      IF v_requested_qty <= 0 THEN CONTINUE; END IF;
      IF v_bill_item_id IS NOT NULL THEN
        PERFORM id FROM bill_items WHERE id = v_bill_item_id FOR UPDATE;
      END IF;
      IF v_product_id IS NOT NULL AND v_warehouse_id IS NOT NULL THEN
        PERFORM pg_advisory_xact_lock(
          hashtext(p_company_id::text || v_product_id::text || v_warehouse_id::text)
        );
      END IF;
    END LOOP;
  END LOOP;

  WITH item_totals AS (
    SELECT
      NULLIF(itm->>'bill_item_id', '')::UUID AS bill_item_id,
      SUM((itm->>'quantity')::NUMERIC) AS total_qty
    FROM jsonb_array_elements(p_warehouse_groups) AS grp,
         jsonb_array_elements(grp->'items') AS itm
    WHERE (itm->>'quantity')::NUMERIC > 0
      AND (itm->>'bill_item_id') IS NOT NULL
    GROUP BY NULLIF(itm->>'bill_item_id', '')::UUID
  )
  SELECT bi.id, bi.quantity, COALESCE(bi.returned_quantity, 0) AS returned_quantity,
         it.total_qty
  INTO v_qty_check
  FROM item_totals it
  JOIN bill_items bi ON bi.id = it.bill_item_id
  WHERE it.total_qty > (bi.quantity - COALESCE(bi.returned_quantity, 0))
  LIMIT 1;

  IF FOUND THEN
    RAISE EXCEPTION 'Return quantity (%) exceeds available quantity (%) for bill item %',
      v_qty_check.total_qty,
      (v_qty_check.quantity - v_qty_check.returned_quantity),
      v_qty_check.id;
  END IF;

  INSERT INTO purchase_returns (
    company_id, supplier_id, bill_id,
    return_number, return_date, status, workflow_status, created_by,
    subtotal, tax_amount, total_amount,
    settlement_method, reason, notes,
    branch_id, cost_center_id, warehouse_id,
    original_currency, original_subtotal, original_tax_amount, original_total_amount,
    exchange_rate_used, exchange_rate_id
  ) VALUES (
    p_company_id, p_supplier_id, p_bill_id,
    p_purchase_return->>'return_number',
    (p_purchase_return->>'return_date')::DATE,
    COALESCE(NULLIF(p_purchase_return->>'status', ''), 'completed'),
    'pending_approval',
    p_created_by,
    COALESCE((p_purchase_return->>'subtotal')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'tax_amount')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'total_amount')::NUMERIC, 0),
    p_purchase_return->>'settlement_method',
    p_purchase_return->>'reason',
    p_purchase_return->>'notes',
    NULL, NULL, NULL,
    COALESCE(NULLIF(p_purchase_return->>'original_currency', ''), 'EGP'),
    COALESCE((p_purchase_return->>'original_subtotal')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'original_tax_amount')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'original_total_amount')::NUMERIC, 0),
    COALESCE((p_purchase_return->>'exchange_rate_used')::NUMERIC, 1),
    NULLIF(p_purchase_return->>'exchange_rate_id', '')::UUID
  ) RETURNING id INTO v_pr_id;

  v_result := jsonb_set(v_result, '{purchase_return_id}', to_jsonb(v_pr_id));

  FOR v_group IN SELECT * FROM jsonb_array_elements(p_warehouse_groups) LOOP
    v_warehouse_id   := NULLIF(v_group->>'warehouse_id', '')::UUID;
    v_branch_id      := NULLIF(v_group->>'branch_id', '')::UUID;
    v_cost_center_id := NULLIF(v_group->>'cost_center_id', '')::UUID;
    v_je_id          := NULL;

    IF (v_group->'journal_entry') IS NOT NULL THEN
      INSERT INTO journal_entries (
        company_id, branch_id, cost_center_id,
        reference_type, reference_id,
        entry_date, description, status
      ) VALUES (
        p_company_id, v_branch_id, v_cost_center_id,
        'purchase_return', v_pr_id,
        (v_group->'journal_entry'->>'entry_date')::DATE,
        v_group->'journal_entry'->>'description',
        'draft'
      ) RETURNING id INTO v_je_id;

      IF (v_group->'journal_lines') IS NOT NULL
         AND jsonb_array_length(v_group->'journal_lines') > 0 THEN
        INSERT INTO journal_entry_lines (
          journal_entry_id, account_id, debit_amount, credit_amount, description,
          branch_id, cost_center_id,
          original_debit, original_credit, original_currency,
          exchange_rate_used, exchange_rate_id
        )
        SELECT
          v_je_id,
          (l->>'account_id')::UUID,
          COALESCE((l->>'debit_amount')::NUMERIC, 0),
          COALESCE((l->>'credit_amount')::NUMERIC, 0),
          l->>'description',
          v_branch_id, v_cost_center_id,
          COALESCE((l->>'original_debit')::NUMERIC, 0),
          COALESCE((l->>'original_credit')::NUMERIC, 0),
          COALESCE(NULLIF(l->>'original_currency', ''), 'EGP'),
          COALESCE((l->>'exchange_rate_used')::NUMERIC, 1),
          NULLIF(l->>'exchange_rate_id', '')::UUID
        FROM jsonb_array_elements(v_group->'journal_lines') AS l;
      END IF;
    END IF;

    INSERT INTO purchase_return_warehouse_allocations (
      company_id, purchase_return_id, warehouse_id, branch_id, cost_center_id,
      journal_entry_id, workflow_status,
      subtotal, tax_amount, total_amount
    ) VALUES (
      p_company_id, v_pr_id, v_warehouse_id, v_branch_id, v_cost_center_id,
      v_je_id, 'pending_approval',
      COALESCE((v_group->>'subtotal')::NUMERIC, 0),
      COALESCE((v_group->>'tax_amount')::NUMERIC, 0),
      COALESCE((v_group->>'total_amount')::NUMERIC, 0)
    ) RETURNING id INTO v_alloc_id;

    v_alloc_ids := array_append(v_alloc_ids, v_alloc_id);

    FOR v_item IN SELECT * FROM jsonb_array_elements(v_group->'items') LOOP
      v_product_id    := NULLIF(v_item->>'product_id', '')::UUID;
      v_bill_item_id  := NULLIF(v_item->>'bill_item_id', '')::UUID;
      v_requested_qty := COALESCE((v_item->>'quantity')::NUMERIC, 0);
      IF v_requested_qty <= 0 THEN CONTINUE; END IF;
      INSERT INTO purchase_return_items (
        purchase_return_id, bill_item_id, product_id,
        description, quantity, unit_price, tax_rate, discount_percent, line_total,
        warehouse_id, warehouse_allocation_id
      ) VALUES (
        v_pr_id, v_bill_item_id, v_product_id,
        v_item->>'description', v_requested_qty,
        COALESCE((v_item->>'unit_price')::NUMERIC, 0),
        COALESCE((v_item->>'tax_rate')::NUMERIC, 0),
        COALESCE((v_item->>'discount_percent')::NUMERIC, 0),
        COALESCE((v_item->>'line_total')::NUMERIC, 0),
        v_warehouse_id, v_alloc_id
      );
    END LOOP;
  END LOOP;

  v_result := jsonb_set(v_result, '{allocation_ids}', to_jsonb(v_alloc_ids));
  RETURN v_result;

EXCEPTION WHEN OTHERS THEN
  RAISE EXCEPTION 'Multi-warehouse purchase return failed (rolled back): %', SQLERRM;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_sales_return_atomic_v2(p_company_id uuid, p_invoice_id uuid, p_sales_return_request_id uuid, p_sales_returns jsonb, p_sales_return_items jsonb, p_inventory_transactions jsonb, p_cogs_transactions jsonb, p_fifo_consumptions jsonb, p_journal_entries jsonb, p_customer_credits jsonb, p_customer_credit_ledger_entries jsonb, p_update_source jsonb, p_effective_date date, p_actor_id uuid, p_idempotency_key text, p_request_hash text, p_trace_metadata jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_sales_return_atomic_v2(p_company_id uuid, p_invoice_id uuid, p_sales_return_request_id uuid DEFAULT NULL::uuid, p_sales_returns jsonb DEFAULT NULL::jsonb, p_sales_return_items jsonb DEFAULT NULL::jsonb, p_inventory_transactions jsonb DEFAULT NULL::jsonb, p_cogs_transactions jsonb DEFAULT NULL::jsonb, p_fifo_consumptions jsonb DEFAULT NULL::jsonb, p_journal_entries jsonb DEFAULT NULL::jsonb, p_customer_credits jsonb DEFAULT NULL::jsonb, p_customer_credit_ledger_entries jsonb DEFAULT NULL::jsonb, p_update_source jsonb DEFAULT NULL::jsonb, p_effective_date date DEFAULT NULL::date, p_actor_id uuid DEFAULT NULL::uuid, p_idempotency_key text DEFAULT NULL::text, p_request_hash text DEFAULT NULL::text, p_trace_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result JSONB;
  v_sales_return_id UUID;
  v_journal_entry_id UUID;
BEGIN
  v_result := public.post_accounting_event_v2(
    p_event_type                     => 'return',
    p_company_id                     => p_company_id,
    p_inventory_transactions         => p_inventory_transactions,
    p_cogs_transactions              => p_cogs_transactions,
    p_fifo_consumptions              => p_fifo_consumptions,
    p_journal_entries                => p_journal_entries,
    p_sales_returns                  => p_sales_returns,
    p_sales_return_items             => p_sales_return_items,
    p_customer_credits               => p_customer_credits,
    p_customer_credit_ledger_entries => p_customer_credit_ledger_entries,
    p_update_source                  => p_update_source,
    p_source_entity                  => 'invoice',
    p_source_id                      => p_invoice_id,
    p_effective_date                 => p_effective_date,
    p_actor_id                       => p_actor_id,
    p_idempotency_key                => p_idempotency_key,
    p_request_hash                   => p_request_hash,
    p_trace_metadata                 => p_trace_metadata
  );

  v_sales_return_id := NULLIF(v_result->'return_ids'->>0, '')::UUID;
  v_journal_entry_id := NULLIF(v_result->'journal_entry_ids'->>0, '')::UUID;

  IF p_sales_return_request_id IS NOT NULL THEN
    UPDATE public.sales_return_requests
    SET
      status = 'approved_completed',
      reviewed_by = COALESCE(reviewed_by, level_1_reviewed_by, p_actor_id),
      reviewed_at = COALESCE(reviewed_at, level_1_reviewed_at, NOW()),
      level_1_reviewed_by = COALESCE(level_1_reviewed_by, reviewed_by, p_actor_id),
      level_1_reviewed_at = COALESCE(level_1_reviewed_at, reviewed_at, NOW()),
      warehouse_reviewed_by = p_actor_id,
      warehouse_reviewed_at = NOW(),
      executed_by = p_actor_id,
      executed_at = NOW(),
      executed_sales_return_id = COALESCE(executed_sales_return_id, v_sales_return_id),
      executed_journal_entry_id = COALESCE(executed_journal_entry_id, v_journal_entry_id)
    WHERE id = p_sales_return_request_id
      AND company_id = p_company_id;

    PERFORM public.link_financial_operation_trace(
      (v_result->>'transaction_id')::UUID,
      'sales_return_request',
      p_sales_return_request_id,
      'approval_request',
      'return'
    );
  END IF;

  RETURN v_result;
END;
$function$
;

-- ---------------------------------------------------------------
-- process_supplier_payment_allocation(p_company_id uuid, p_supplier_id uuid, p_payment_amount numeric, p_payment_date date, p_payment_method character varying, p_account_id uuid, p_branch_id uuid, p_currency_code character varying, p_exchange_rate numeric, p_base_currency_amount numeric, p_allocations jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.process_supplier_payment_allocation(p_company_id uuid, p_supplier_id uuid, p_payment_amount numeric, p_payment_date date, p_payment_method character varying, p_account_id uuid, p_branch_id uuid, p_currency_code character varying, p_exchange_rate numeric, p_base_currency_amount numeric, p_allocations jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_payment_id UUID;
  v_status VARCHAR := 'pending_approval';
  v_user_id UUID := auth.uid();
  v_user_role VARCHAR;
  v_alloc_record JSONB;
  v_total_allocated NUMERIC := 0;
BEGIN
  -- Validate user
  SELECT role INTO v_user_role FROM company_members WHERE user_id = v_user_id AND company_id = p_company_id;
  IF v_user_role IS NULL THEN RAISE EXCEPTION 'Unauthorized'; END IF;

  -- Privileged users bypass approval
  IF v_user_role IN ('owner', 'admin', 'general_manager') THEN
    v_status := 'approved';
  END IF;

  -- Create Payment
  INSERT INTO payments (
    company_id, supplier_id, payment_date, amount, payment_method, account_id, branch_id,
    currency_code, exchange_rate, base_currency_amount,
    status, created_by,
    unallocated_amount
  ) VALUES (
    p_company_id, p_supplier_id, p_payment_date, p_payment_amount, p_payment_method, p_account_id, p_branch_id,
    p_currency_code, p_exchange_rate, p_base_currency_amount,
    v_status, v_user_id,
    p_payment_amount -- Initially full amount unallocated
  ) RETURNING id INTO v_payment_id;

  -- Auto-Approve logic fields (if privileged)
  IF v_status = 'approved' THEN
    UPDATE payments SET approved_by = v_user_id, approved_at = NOW() WHERE id = v_payment_id;
  END IF;

  -- Process Allocations from JSON Array
  IF p_allocations IS NOT NULL AND jsonb_array_length(p_allocations) > 0 THEN
    FOR v_alloc_record IN SELECT * FROM jsonb_array_elements(p_allocations)
    LOOP
      INSERT INTO payment_allocations (payment_id, bill_id, allocated_amount, company_id)
      VALUES (
        v_payment_id, 
        (v_alloc_record->>'bill_id')::uuid, 
        (v_alloc_record->>'amount')::numeric,
        p_company_id
      );
      v_total_allocated := v_total_allocated + (v_alloc_record->>'amount')::numeric;
    END LOOP;
  END IF;

  -- Update unallocated amount
  UPDATE payments SET unallocated_amount = p_payment_amount - v_total_allocated WHERE id = v_payment_id;

  RETURN v_payment_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- product_receive_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.product_receive_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order_no text;
  v_product_name text;
BEGIN
  BEGIN
    SELECT order_no, (SELECT name FROM public.products WHERE id = po.product_id)
      INTO v_order_no, v_product_name
      FROM public.manufacturing_production_orders po
     WHERE po.id = NEW.production_order_id;
  EXCEPTION WHEN OTHERS THEN NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'manufacturing_product_receive', NEW.id, NEW.requested_by,
      'نشاط فرعك: طلب استلام منتج نهائى',
      'طلب استلام كمية ' || NEW.proposed_quantity::text
      || CASE WHEN v_product_name IS NOT NULL THEN ' من المنتج ' || v_product_name ELSE '' END
      || CASE WHEN v_order_no IS NOT NULL THEN ' (أمر إنتاج ' || v_order_no || ')' ELSE '' END
      || ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status IN ('approved', 'rejected') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'manufacturing_product_receive', NEW.id,
      CASE WHEN NEW.status = 'rejected' THEN NEW.rejected_by ELSE NEW.approved_by END,
      'نشاط فرعك: تغيّرت حالة طلب استلام منتج',
      'طلب استلام'
      || CASE WHEN v_product_name IS NOT NULL THEN ' للمنتج ' || v_product_name ELSE '' END
      || CASE WHEN v_order_no IS NOT NULL THEN ' (أمر إنتاج ' || v_order_no || ')' ELSE '' END
      || CASE NEW.status WHEN 'approved' THEN ' تم اعتماده.' WHEN 'rejected' THEN ' تم رفضه.' ELSE '' END
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- product_receive_notify_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.product_receive_notify_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order_no text;
  v_product_name text;
  v_requester uuid;
  v_approver_id uuid;
BEGIN
  IF TG_OP = 'UPDATE' AND OLD.status = NEW.status THEN RETURN NEW; END IF;
  IF NEW.status <> 'pending' THEN RETURN NEW; END IF;

  v_requester := NEW.requested_by;

  BEGIN
    SELECT order_no, (SELECT name FROM public.products WHERE id = po.product_id)
      INTO v_order_no, v_product_name
      FROM public.manufacturing_production_orders po
     WHERE po.id = NEW.production_order_id;
  EXCEPTION WHEN OTHERS THEN NULL; END;

  FOR v_approver_id IN
    SELECT DISTINCT u FROM (
      SELECT user_id AS u FROM public.companies WHERE id = NEW.company_id
      UNION
      SELECT user_id FROM public.company_members
       WHERE company_id = NEW.company_id
         AND role IN ('owner', 'general_manager')
    ) approvers
    WHERE u IS NOT NULL AND (v_requester IS NULL OR u <> v_requester)
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      NEW.company_id, 'approval_request', NEW.id, v_requester,
      v_approver_id,
      'طلب اعتماد استلام منتج نهائى',
      'استلام كمية ' || NEW.proposed_quantity::text
      || CASE WHEN v_product_name IS NOT NULL THEN ' من المنتج ' || v_product_name ELSE '' END
      || CASE WHEN v_order_no IS NOT NULL THEN ' (أمر إنتاج ' || v_order_no || ')' ELSE '' END
      || ' — يحتاج اعتمادك من صندوق الموافقات.',
      'high', 'warning', 'approvals', 'in_app', NOW()
    );
  END LOOP;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- production_order_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.production_order_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_product_name text;
BEGIN
  BEGIN
    SELECT name INTO v_product_name FROM public.products WHERE id = NEW.product_id;
  EXCEPTION WHEN OTHERS THEN v_product_name := NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'manufacturing_production_order', NEW.id, NEW.created_by,
      'نشاط فرعك: تم إنشاء أمر إنتاج',
      'أمر إنتاج ' || NEW.order_no
      || CASE WHEN v_product_name IS NOT NULL THEN ' للمنتج ' || v_product_name ELSE '' END
      || ' بكمية ' || NEW.planned_quantity::text || ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.approval_status = OLD.approval_status THEN RETURN NEW; END IF;
  IF NEW.approval_status IN ('approved', 'rejected') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'manufacturing_production_order', NEW.id,
      CASE WHEN NEW.approval_status = 'rejected' THEN NEW.rejected_by ELSE NEW.approved_by END,
      'نشاط فرعك: تغيّرت حالة اعتماد أمر إنتاج',
      'أمر إنتاج ' || NEW.order_no
      || CASE WHEN v_product_name IS NOT NULL THEN ' للمنتج ' || v_product_name ELSE '' END
      || CASE NEW.approval_status WHEN 'approved' THEN ' تم اعتماده.' WHEN 'rejected' THEN ' تم رفضه.' ELSE '' END
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- production_order_notify_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.production_order_notify_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_product_name text;
  v_requester uuid;
  v_approver_id uuid;
BEGIN
  IF TG_OP = 'UPDATE' AND OLD.approval_status = NEW.approval_status THEN RETURN NEW; END IF;
  IF NEW.approval_status <> 'pending_approval' THEN RETURN NEW; END IF;

  v_requester := COALESCE(NEW.submitted_by, NEW.created_by);

  BEGIN
    SELECT name INTO v_product_name FROM public.products WHERE id = NEW.product_id;
  EXCEPTION WHEN OTHERS THEN v_product_name := NULL; END;

  FOR v_approver_id IN
    SELECT DISTINCT u FROM (
      SELECT user_id AS u FROM public.companies WHERE id = NEW.company_id
      UNION
      SELECT user_id FROM public.company_members
       WHERE company_id = NEW.company_id
         AND role IN ('owner', 'general_manager')
    ) approvers
    WHERE u IS NOT NULL AND (v_requester IS NULL OR u <> v_requester)
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      NEW.company_id, 'approval_request', NEW.id, v_requester,
      v_approver_id,
      'طلب اعتماد أمر إنتاج',
      'أمر إنتاج ' || NEW.order_no
      || CASE WHEN v_product_name IS NOT NULL THEN ' للمنتج ' || v_product_name ELSE '' END
      || ' بكمية ' || NEW.planned_quantity::text
      || ' — يحتاج اعتمادك من صندوق الموافقات.',
      'high', 'warning', 'approvals', 'in_app', NOW()
    );
  END LOOP;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- protect_branch_outlets()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.protect_branch_outlets()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  IF OLD.provider_code = 'branch_outlet' THEN
    RAISE EXCEPTION 'OUTLET_PROTECTED: منافذ بيع الفروع تُنشأ وتُدار تلقائياً ولا تُحذف — يمكن تعطيلها فقط (تتعطل تلقائياً مع تعطيل الفرع)';
  END IF;
  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- protect_customer_branch_id()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.protect_customer_branch_id()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  user_role TEXT;
  allowed_roles TEXT[] := ARRAY['owner', 'admin', 'general_manager', 'gm', 'super_admin', 'superadmin', 'generalmanager'];
BEGIN
  -- السماح بالإدخال الجديد (INSERT)
  IF TG_OP = 'INSERT' THEN
    RETURN NEW;
  END IF;

  -- التحقق من تغيير branch_id
  IF TG_OP = 'UPDATE' THEN
    -- إذا لم يتغير branch_id، نسمح بالتحديث
    IF OLD.branch_id IS NOT DISTINCT FROM NEW.branch_id THEN
      RETURN NEW;
    END IF;

    -- جلب دور المستخدم الحالي
    SELECT role INTO user_role
    FROM company_members
    WHERE user_id = auth.uid()
      AND company_id = NEW.company_id
    LIMIT 1;

    -- تطبيع الدور
    user_role := LOWER(TRIM(REPLACE(COALESCE(user_role, 'staff'), ' ', '_')));

    -- التحقق من الصلاحية
    IF user_role = ANY(allowed_roles) THEN
      -- 🔐 تسجيل التغيير في Audit Log (v3.74.36: aligned to real columns)
      INSERT INTO audit_logs (
        company_id,
        user_id,
        action,
        entity,
        entity_id,
        old_data,
        new_data,
        metadata
      ) VALUES (
        NEW.company_id,
        auth.uid(),
        'customer_branch_changed_by_trigger',
        'customer',
        NEW.id,
        jsonb_build_object('branch_id', OLD.branch_id, 'customer_name', OLD.name),
        jsonb_build_object('branch_id', NEW.branch_id, 'customer_name', NEW.name),
        jsonb_build_object(
          'changed_by_role', user_role,
          'changed_at', NOW(),
          'trigger_name', 'protect_customer_branch_id'
        )
      );

      RETURN NEW;
    ELSE
      -- 🚫 رفض التغيير للمستخدمين غير المصرح لهم
      RAISE EXCEPTION 'GOVERNANCE_VIOLATION: Cannot change customer branch_id. Only Owner or General Manager can modify branch assignment. Your role: %', user_role;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- protect_paid_invoice_revenue_je()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.protect_paid_invoice_revenue_je()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE v_invoice_status TEXT;
BEGIN
  IF NEW.is_deleted = true AND OLD.is_deleted IS DISTINCT FROM true
     AND OLD.reference_type = 'invoice' AND OLD.status = 'posted' THEN
    IF current_setting('app.skip_je_check', true) = 'true' THEN RETURN NEW; END IF;
    SELECT status INTO v_invoice_status
    FROM invoices WHERE id = OLD.reference_id;  -- UUID = UUID ✅
    IF v_invoice_status = 'paid' THEN
      RAISE EXCEPTION 'PAID_INVOICE_JE_PROTECTED: Cannot delete revenue JE % — invoice is paid.',
        OLD.entry_number
        USING HINT = 'Create a credit note or sales return instead.';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- purchase_return_approval_insert_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.purchase_return_approval_insert_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_role text;
BEGIN
  IF NEW.created_by IS NOT NULL THEN
    SELECT role INTO v_role FROM public.company_members
     WHERE company_id = NEW.company_id AND user_id = NEW.created_by LIMIT 1;
  END IF;
  IF v_role IN ('owner', 'general_manager') THEN
    IF NEW.status IN ('approved', 'sent_to_vendor') THEN
      IF NEW.approved_by IS NULL THEN NEW.approved_by := NEW.created_by; END IF;
      IF NEW.approved_at IS NULL THEN NEW.approved_at := NOW(); END IF;
    END IF;
    RETURN NEW;
  END IF;
  IF NEW.status IS NOT NULL AND NEW.status NOT IN ('draft', 'pending_approval') THEN
    RAISE EXCEPTION
      'مرتجع المشتريات يحتاج اعتماد المالك / المدير العام. لا يجوز إنشاء مرتجع بحالة "%" مباشرة. ابدأ بحالة pending_approval.', NEW.status
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- purchase_return_approval_update_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.purchase_return_approval_update_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status IN ('approved', 'sent_to_vendor')
     AND (NEW.approved_by IS NULL OR NEW.approved_at IS NULL) THEN
    RAISE EXCEPTION
      'لا يمكن تحويل مرتجع المشتريات إلى حالة "%" بدون تسجيل المعتمد. استخدم RPC approve_purchase_return_atomic.', NEW.status
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- purchase_return_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.purchase_return_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_supplier_name text;
  v_currency text;
BEGIN
  v_currency := COALESCE(NEW.original_currency, 'EGP');
  BEGIN
    SELECT name INTO v_supplier_name FROM public.suppliers WHERE id = NEW.supplier_id;
  EXCEPTION WHEN OTHERS THEN v_supplier_name := NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'purchase_return', NEW.id, NEW.created_by,
      'نشاط فرعك: تم إنشاء مرتجع مشتريات',
      'تم إنشاء مرتجع ' || NEW.return_number ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' للمورد ' || v_supplier_name ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency || ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status IN ('approved', 'rejected', 'sent_to_vendor') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'purchase_return', NEW.id,
      CASE WHEN NEW.status = 'rejected' THEN NEW.rejected_by ELSE NEW.approved_by END,
      'نشاط فرعك: تغيّرت حالة مرتجع مشتريات',
      'المرتجع ' || NEW.return_number ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' للمورد ' || v_supplier_name ELSE '' END ||
      ' أصبحت الحالة "' || NEW.status || '".'
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- purchase_return_notify_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.purchase_return_notify_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_supplier_name text; v_requester uuid; v_approver_id uuid; v_currency text;
BEGIN
  IF TG_OP = 'UPDATE' AND OLD.status = NEW.status THEN RETURN NEW; END IF;
  IF NEW.status <> 'pending_approval' THEN RETURN NEW; END IF;
  v_requester := NEW.created_by;
  v_currency  := COALESCE(NEW.original_currency, 'EGP');
  BEGIN
    SELECT name INTO v_supplier_name FROM public.suppliers WHERE id = NEW.supplier_id;
  EXCEPTION WHEN OTHERS THEN v_supplier_name := NULL; END;

  FOR v_approver_id IN
    SELECT DISTINCT u FROM (
      SELECT user_id AS u FROM public.companies WHERE id = NEW.company_id
      UNION
      SELECT user_id FROM public.company_members
       WHERE company_id = NEW.company_id
         AND role IN ('owner', 'general_manager')
    ) approvers
    WHERE u IS NOT NULL AND (v_requester IS NULL OR u <> v_requester)
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      NEW.company_id, 'approval_request', NEW.id, v_requester,
      v_approver_id,
      'طلب اعتماد مرتجع مشتريات',
      'مرتجع ' || NEW.return_number ||
      CASE WHEN v_supplier_name IS NOT NULL THEN ' للمورد ' || v_supplier_name ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency ||
      ' — يحتاج اعتمادك من صندوق الموافقات.',
      'high', 'warning', 'approvals', 'in_app', NOW()
    );
  END LOOP;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- rate_booking_atomic(p_company_id uuid, p_booking_id uuid, p_updated_by uuid, p_rating integer, p_feedback text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.rate_booking_atomic(p_company_id uuid, p_booking_id uuid, p_updated_by uuid, p_rating integer, p_feedback text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_booking public.bookings;
BEGIN
  IF p_rating NOT BETWEEN 1 AND 5 THEN RAISE EXCEPTION 'Rating must be between 1 and 5. Got: %', p_rating USING ERRCODE='P0001'; END IF;
  SELECT * INTO v_booking FROM public.bookings WHERE id = p_booking_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Booking not found. booking_id=%', p_booking_id USING ERRCODE='P0001'; END IF;
  IF v_booking.status <> 'completed' THEN RAISE EXCEPTION 'Only completed bookings can be rated. Current status: %. booking_id=%', v_booking.status, p_booking_id USING ERRCODE='P0001'; END IF;
  UPDATE public.bookings SET rating=p_rating, feedback=p_feedback, updated_by=p_updated_by WHERE id=p_booking_id;
  RETURN jsonb_build_object('success',true,'booking_id',p_booking_id,'rating',p_rating);
END; $function$
;

-- ---------------------------------------------------------------
-- reactivate_after_payment(p_company_id uuid, p_billing_period text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reactivate_after_payment(p_company_id uuid, p_billing_period text DEFAULT 'monthly'::text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_old_status text;
  v_interval interval;
BEGIN
  SELECT subscription_status INTO v_old_status
  FROM companies WHERE id = p_company_id FOR UPDATE;

  IF v_old_status IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'company_not_found');
  END IF;

  v_interval := CASE WHEN p_billing_period = 'annual' THEN INTERVAL '12 months' ELSE INTERVAL '1 month' END;

  UPDATE companies
  SET subscription_status = 'active',
      current_period_start = now(),
      current_period_end = now() + v_interval,
      suspended_at = NULL,
      reactivated_at = CASE WHEN v_old_status IN ('past_due', 'payment_failed') THEN now() ELSE reactivated_at END,
      renewal_reminder_sent_at = NULL
  WHERE id = p_company_id;

  UPDATE company_seats
  SET status = 'active', updated_at = now()
  WHERE company_id = p_company_id AND status = 'suspended';

  BEGIN
    INSERT INTO audit_logs(action, company_id, target_table, new_data)
    VALUES (
      'subscription_reactivated',
      p_company_id,
      'companies',
      json_build_object(
        'previous_status', v_old_status,
        'new_period_end', (now() + v_interval),
        'billing_period', p_billing_period
      )::jsonb
    );
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN json_build_object(
    'success', true,
    'previous_status', v_old_status,
    'was_reactivated', v_old_status IN ('past_due', 'payment_failed', 'canceled')
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- reactivate_company_subscription(p_company_id uuid, p_performed_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reactivate_company_subscription(p_company_id uuid, p_performed_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_status text;
  v_new_period_end timestamptz;
  v_active_seats int;
BEGIN
  SELECT subscription_status INTO v_status FROM public.companies WHERE id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'company_not_found');
  END IF;

  SELECT count(*), MAX(expires_at) INTO v_active_seats, v_new_period_end
    FROM public.company_seat_licenses
   WHERE company_id = p_company_id
     AND expires_at > NOW();

  IF v_active_seats = 0 THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'no_active_seats',
      'message', 'لا توجد مقاعد فعّالة. جدّد المقاعد أولاً.'
    );
  END IF;

  UPDATE public.companies
     SET subscription_status  = 'active',
         suspended_at         = NULL,
         reactivated_at       = NOW(),
         past_due_at          = NULL,
         current_period_start = COALESCE(current_period_start, NOW()),
         current_period_end   = GREATEST(COALESCE(current_period_end, NOW()), v_new_period_end),
         reminder_7d_sent_at  = NULL,
         reminder_3d_sent_at  = NULL,
         reminder_1d_sent_at  = NULL
   WHERE id = p_company_id;

  UPDATE public.company_seats
     SET status = 'active',
         updated_at = NOW()
   WHERE company_id = p_company_id
     AND status <> 'active';

  IF v_status IN ('past_due', 'payment_failed') THEN
    PERFORM public.notify_company_billing_owner(
      p_company_id,
      'تم إعادة تفعيل الاشتراك',
      'تم إعادة تفعيل اشتراك شركتك بنجاح. جميع الأعضاء يستطيعون الوصول الآن.',
      'info', 'high'
    );
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'active_seats', v_active_seats,
    'new_period_end', v_new_period_end,
    'previous_status', v_status
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- reassign_user_data_and_remove(p_company_id uuid, p_old_user_id uuid, p_new_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reassign_user_data_and_remove(p_company_id uuid, p_old_user_id uuid, p_new_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_old_role TEXT;
    v_is_target_active BOOLEAN;
BEGIN
    -- Validate old user
    SELECT role INTO v_old_role FROM company_members WHERE company_id = p_company_id AND user_id = p_old_user_id;
    IF v_old_role = 'owner' THEN
        RAISE EXCEPTION 'Cannot reassign and delete the company owner.';
    END IF;
    IF v_old_role IS NULL THEN
        RAISE EXCEPTION 'Source user is not a member of this company.';
    END IF;

    -- Validate new user
    SELECT TRUE INTO v_is_target_active FROM company_members WHERE company_id = p_company_id AND user_id = p_new_user_id;
    IF v_is_target_active IS NULL THEN
        RAISE EXCEPTION 'Target user is not a member of this company.';
    END IF;

    -- ===========================================
    -- REASSIGNMENTS: Change ownership / audit trails
    -- ===========================================
    
    -- Main Entities
    UPDATE invoices SET created_by_user_id = p_new_user_id WHERE company_id = p_company_id AND created_by_user_id = p_old_user_id;
    UPDATE sales_orders SET created_by_user_id = p_new_user_id WHERE company_id = p_company_id AND created_by_user_id = p_old_user_id;
    UPDATE purchase_orders SET created_by_user_id = p_new_user_id WHERE company_id = p_company_id AND created_by_user_id = p_old_user_id;
    UPDATE bills SET created_by_user_id = p_new_user_id WHERE company_id = p_company_id AND created_by_user_id = p_old_user_id;
    UPDATE bills SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE bills SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    UPDATE bills SET rejected_by = p_new_user_id WHERE company_id = p_company_id AND rejected_by = p_old_user_id;
    UPDATE bills SET received_by = p_new_user_id WHERE company_id = p_company_id AND received_by = p_old_user_id;
    UPDATE customers SET created_by_user_id = p_new_user_id WHERE company_id = p_company_id AND created_by_user_id = p_old_user_id;
    UPDATE suppliers SET created_by_user_id = p_new_user_id WHERE company_id = p_company_id AND created_by_user_id = p_old_user_id;

    -- Financials & Ledger
    UPDATE journal_entries SET posted_by = p_new_user_id WHERE company_id = p_company_id AND posted_by = p_old_user_id;
    UPDATE expenses SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE expenses SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    UPDATE expenses SET rejected_by = p_new_user_id WHERE company_id = p_company_id AND rejected_by = p_old_user_id;
    UPDATE expenses SET paid_by = p_new_user_id WHERE company_id = p_company_id AND paid_by = p_old_user_id;
    UPDATE vendor_credits SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE customer_credit_ledger SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE dividend_payments SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE profit_distributions SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    UPDATE shareholder_drawings SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE shareholder_drawings SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    UPDATE shareholder_drawings SET rejected_by = p_new_user_id WHERE company_id = p_company_id AND rejected_by = p_old_user_id;
    UPDATE commission_advance_payments SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE credit_notes SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE credit_notes SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    
    -- Inventory & Operations
    UPDATE inventory_transfers SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE inventory_transfers SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    UPDATE inventory_transfers SET rejected_by = p_new_user_id WHERE company_id = p_company_id AND rejected_by = p_old_user_id;
    UPDATE inventory_transfers SET received_by = p_new_user_id WHERE company_id = p_company_id AND received_by = p_old_user_id;
    UPDATE inventory_write_offs SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE inventory_write_offs SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    UPDATE inventory_write_offs SET rejected_by = p_new_user_id WHERE company_id = p_company_id AND rejected_by = p_old_user_id;
    UPDATE inventory_write_offs SET cancelled_by = p_new_user_id WHERE company_id = p_company_id AND cancelled_by = p_old_user_id;
    UPDATE shipments SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE asset_transactions SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE fixed_assets SET employee_id = p_new_user_id WHERE company_id = p_company_id AND employee_id = p_old_user_id;
    UPDATE fixed_assets SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE fixed_assets SET updated_by = p_new_user_id WHERE company_id = p_company_id AND updated_by = p_old_user_id;
    UPDATE cogs_transactions SET created_by_user_id = p_new_user_id WHERE company_id = p_company_id AND created_by_user_id = p_old_user_id;

    -- Approvals, Planning & Miscellaneous
    UPDATE approval_workflows SET requested_by = p_new_user_id WHERE company_id = p_company_id AND requested_by = p_old_user_id;
    UPDATE approval_workflows SET approver_id = p_new_user_id WHERE company_id = p_company_id AND approver_id = p_old_user_id;
    UPDATE approval_workflows SET rejected_by = p_new_user_id WHERE company_id = p_company_id AND rejected_by = p_old_user_id;
    UPDATE approval_workflows SET executed_by = p_new_user_id WHERE company_id = p_company_id AND executed_by = p_old_user_id;
    UPDATE system_audit_log SET user_id = p_new_user_id WHERE company_id = p_company_id AND user_id = p_old_user_id;
    UPDATE notifications SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE notifications SET assigned_to_user = p_new_user_id WHERE company_id = p_company_id AND assigned_to_user = p_old_user_id;
    UPDATE fiscal_periods SET closed_by = p_new_user_id WHERE company_id = p_company_id AND closed_by = p_old_user_id;
    UPDATE fiscal_periods SET reopened_by = p_new_user_id WHERE company_id = p_company_id AND reopened_by = p_old_user_id;
    UPDATE budgets SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE budgets SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    UPDATE commission_runs SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE commission_runs SET reviewed_by = p_new_user_id WHERE company_id = p_company_id AND reviewed_by = p_old_user_id;
    UPDATE commission_runs SET approved_by = p_new_user_id WHERE company_id = p_company_id AND approved_by = p_old_user_id;
    UPDATE commission_runs SET posted_by = p_new_user_id WHERE company_id = p_company_id AND posted_by = p_old_user_id;
    UPDATE commission_runs SET paid_by = p_new_user_id WHERE company_id = p_company_id AND paid_by = p_old_user_id;
    UPDATE exchange_rate_log SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE shipping_providers SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE shareholder_percentage_history SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    UPDATE restore_queue SET user_id = p_new_user_id WHERE company_id = p_company_id AND user_id = p_old_user_id;

    -- HR / Employees constraint detaching
    UPDATE employees SET user_id = NULL WHERE company_id = p_company_id AND user_id = p_old_user_id;

    -- ===========================================
    -- DELETIONS: Remove access records for old user
    -- ===========================================
    
    DELETE FROM user_branch_access WHERE company_id = p_company_id AND user_id = p_old_user_id;
    UPDATE user_branch_access SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    
    DELETE FROM user_branch_cost_center WHERE company_id = p_company_id AND user_id = p_old_user_id;
    DELETE FROM permission_sharing WHERE company_id = p_company_id AND grantee_user_id = p_old_user_id;
    
    UPDATE permission_sharing SET grantor_user_id = p_new_user_id WHERE company_id = p_company_id AND grantor_user_id = p_old_user_id;
    UPDATE permission_sharing SET created_by = p_new_user_id WHERE company_id = p_company_id AND created_by = p_old_user_id;
    
    DELETE FROM permission_transfers WHERE company_id = p_company_id AND to_user_id = p_old_user_id;
    UPDATE permission_transfers SET from_user_id = p_new_user_id WHERE company_id = p_company_id AND from_user_id = p_old_user_id;
    UPDATE permission_transfers SET transferred_by = p_new_user_id WHERE company_id = p_company_id AND transferred_by = p_old_user_id;

    DELETE FROM user_security_events WHERE user_id = p_old_user_id;

    -- Finally delete company membership
    DELETE FROM company_members WHERE company_id = p_company_id AND user_id = p_old_user_id;

    RETURN jsonb_build_object('ok', true, 'message', 'User data reassigned and access removed successfully');
END;
$function$
;

-- ---------------------------------------------------------------
-- recalc_bill_on_allocation_change()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recalc_bill_on_allocation_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN 
    PERFORM fn_recalc_bill_paid_status(OLD.bill_id);
  ELSE 
    PERFORM fn_recalc_bill_paid_status(NEW.bill_id);
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- recalc_bill_on_payment_change()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recalc_bill_on_payment_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_payment_id UUID;
  v_bill_id    UUID;
BEGIN
  -- Determine which payment changed
  v_payment_id := COALESCE(NEW.id, OLD.id);

  -- Recalc all bills linked via payment_allocations (new engine)
  FOR v_bill_id IN
    SELECT DISTINCT pa.bill_id
    FROM payment_allocations pa
    WHERE pa.payment_id = v_payment_id
      AND pa.bill_id IS NOT NULL
  LOOP
    PERFORM fn_recalc_bill_paid_status(v_bill_id);
  END LOOP;

  -- Fallback: Also handle legacy payments that use payments.bill_id directly
  DECLARE
    v_legacy_bill UUID;
  BEGIN
    v_legacy_bill := CASE
      WHEN TG_OP = 'DELETE' THEN OLD.bill_id
      ELSE COALESCE(NEW.bill_id, OLD.bill_id)
    END;
    IF v_legacy_bill IS NOT NULL THEN
      PERFORM fn_recalc_bill_paid_status(v_legacy_bill);
    END IF;
  END;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- recalc_bills_for_payment()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recalc_bills_for_payment()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_bill_id UUID;
BEGIN
  FOR v_bill_id IN 
    SELECT DISTINCT pa.bill_id FROM payment_allocations pa WHERE pa.payment_id = COALESCE(NEW.id, OLD.id)
    UNION
    SELECT COALESCE(NEW.bill_id, OLD.bill_id) WHERE COALESCE(NEW.bill_id, OLD.bill_id) IS NOT NULL
  LOOP
    IF v_bill_id IS NOT NULL THEN
      PERFORM fn_recalc_bill_paid_status(v_bill_id);
    END IF;
  END LOOP;
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- recalc_invoice_on_allocation_change()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recalc_invoice_on_allocation_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    IF OLD.invoice_id IS NOT NULL THEN
      PERFORM fn_recalc_invoice_paid_status(OLD.invoice_id);
    END IF;
  ELSE
    IF NEW.invoice_id IS NOT NULL THEN
      PERFORM fn_recalc_invoice_paid_status(NEW.invoice_id);
    END IF;
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- recalc_invoices_for_payment()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recalc_invoices_for_payment()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_payment_id UUID;
  v_invoice_id UUID;
BEGIN
  v_payment_id := COALESCE(NEW.id, OLD.id);

  FOR v_invoice_id IN
    SELECT DISTINCT pa.invoice_id FROM payment_allocations pa
    WHERE pa.payment_id = v_payment_id
      AND pa.invoice_id IS NOT NULL
    UNION
    SELECT OLD.invoice_id WHERE OLD.invoice_id IS NOT NULL
  LOOP
    IF v_invoice_id IS NOT NULL THEN
      PERFORM fn_recalc_invoice_paid_status(v_invoice_id);
    END IF;
  END LOOP;
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- recalculate_asset_depreciation(p_asset_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recalculate_asset_depreciation(p_asset_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_asset RECORD;
  v_total_posted_depreciation DECIMAL(15, 2);
  v_calculated_accumulated DECIMAL(15, 2);
  v_calculated_book_value DECIMAL(15, 2);
  v_new_status TEXT;
BEGIN
  -- جلب بيانات الأصل
  SELECT * INTO v_asset FROM fixed_assets WHERE id = p_asset_id;
  
  IF v_asset IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Asset not found'
    );
  END IF;

  -- حساب إجمالي الإهلاك من الجداول المرحلة فقط
  SELECT COALESCE(SUM(depreciation_amount), 0)
  INTO v_total_posted_depreciation
  FROM depreciation_schedules
  WHERE asset_id = p_asset_id
    AND status = 'posted';

  -- حساب مجمع الإهلاك والقيمة الدفترية
  v_calculated_accumulated := v_total_posted_depreciation;
  v_calculated_book_value := v_asset.purchase_cost - v_calculated_accumulated;

  -- التأكد من أن book_value لا يقل عن salvage_value
  IF v_calculated_book_value < v_asset.salvage_value THEN
    v_calculated_book_value := v_asset.salvage_value;
    v_calculated_accumulated := v_asset.purchase_cost - v_asset.salvage_value;
  END IF;

  -- تحديث status فقط إذا كانت الحالة active أو fully_depreciated
  -- منع الكتابة على الحالات التشغيلية (suspended, sold, disposed)
  IF v_asset.status = 'active' OR v_asset.status = 'fully_depreciated' THEN
    v_new_status := CASE
      WHEN v_calculated_book_value <= v_asset.salvage_value THEN 'fully_depreciated'
      ELSE 'active'
    END;
  ELSE
    -- الاحتفاظ بالحالة الحالية للأصول المشغلة
    v_new_status := v_asset.status;
  END IF;

  -- تحديث الأصل
  UPDATE fixed_assets
  SET
    accumulated_depreciation = ROUND(v_calculated_accumulated, 2),
    book_value = ROUND(v_calculated_book_value, 2),
    status = v_new_status,
    updated_at = CURRENT_TIMESTAMP
  WHERE id = p_asset_id;

  RETURN jsonb_build_object(
    'success', true,
    'asset_id', p_asset_id,
    'old_accumulated_depreciation', v_asset.accumulated_depreciation,
    'new_accumulated_depreciation', v_calculated_accumulated,
    'old_book_value', v_asset.book_value,
    'new_book_value', v_calculated_book_value,
    'old_status', v_asset.status,
    'new_status', v_new_status
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- recalculate_cogs()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recalculate_cogs()
 RETURNS TABLE(invoice_number text, old_cogs numeric, new_cogs numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  invoice_record RECORD;
  v_cogs_amount NUMERIC;
  v_inventory_account_id UUID;
  v_cogs_account_id UUID;
  v_journal_entry_id UUID;
BEGIN
  FOR invoice_record IN 
    SELECT i.id, i.invoice_number, i.invoice_date, i.company_id
    FROM invoices i
    WHERE i.status IN ('partially_paid', 'paid')
  LOOP
    SELECT coa.id INTO v_inventory_account_id FROM chart_of_accounts coa
    WHERE coa.company_id = invoice_record.company_id AND coa.sub_type = 'inventory' LIMIT 1;

    SELECT coa.id INTO v_cogs_account_id FROM chart_of_accounts coa
    WHERE coa.company_id = invoice_record.company_id AND (coa.sub_type = 'cogs' OR coa.account_code = '5000') LIMIT 1;

    IF v_inventory_account_id IS NULL OR v_cogs_account_id IS NULL THEN CONTINUE; END IF;

    -- حساب COGS بالأسعار المصححة
    SELECT SUM(ii.quantity * COALESCE(p.cost_price, 0)) INTO v_cogs_amount
    FROM invoice_items ii
    JOIN products p ON ii.product_id = p.id
    WHERE ii.invoice_id = invoice_record.id AND p.item_type != 'service';

    IF COALESCE(v_cogs_amount, 0) > 0 THEN
      INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description) 
      VALUES (invoice_record.company_id, 'invoice_cogs', invoice_record.id, invoice_record.invoice_date, 'COGS - ' || invoice_record.invoice_number) 
      RETURNING id INTO v_journal_entry_id;

      INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
      (v_journal_entry_id, v_cogs_account_id, v_cogs_amount, 0, 'COGS'),
      (v_journal_entry_id, v_inventory_account_id, 0, v_cogs_amount, 'Inventory');

      RETURN QUERY SELECT invoice_record.invoice_number, 10000.0, v_cogs_amount;
    END IF;
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- receipt_manufacturing_production_order_output_atomic(p_company_id uuid, p_production_order_id uuid, p_posted_by uuid, p_received_qty numeric, p_posted_at timestamp with time zone, p_notes text, p_command_key text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.receipt_manufacturing_production_order_output_atomic(p_company_id uuid, p_production_order_id uuid, p_posted_by uuid, p_received_qty numeric, p_posted_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_notes text DEFAULT NULL::text, p_command_key text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order RECORD;
  v_receipt_warehouse RECORD;
  v_posted_at TIMESTAMPTZ := COALESCE(p_posted_at, NOW());
  v_receipt_event_id UUID := gen_random_uuid();
  v_existing_receipt_event_id UUID;
  v_receipt_event_number TEXT := NULLIF(BTRIM(COALESCE(p_command_key, '')), '');
  v_received_qty NUMERIC(18,4) := public.mpoe_round_qty(p_received_qty);
  v_receipt_line_id UUID := gen_random_uuid();
  v_inventory_transaction_id UUID;
  v_fifo_cost_lot_id UUID;
  v_already_received_qty NUMERIC(18,4);
  v_remaining_receivable_qty NUMERIC(18,4);
  v_total_issued_cost NUMERIC(18,4);
  v_total_receipted_cost NUMERIC(18,4);
  v_receipt_total_cost NUMERIC(18,4);
  v_receipt_unit_cost NUMERIC(18,4);
BEGIN
  IF v_received_qty <= 0 THEN
    RAISE EXCEPTION 'received_qty must be greater than zero.';
  END IF;

  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order not found or not in company. production_order_id=%', p_production_order_id;
  END IF;

  IF v_order.status <> 'in_progress' THEN
    RAISE EXCEPTION 'Finished-goods receipt is allowed only when the production order is in progress. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  END IF;

  IF v_receipt_event_number IS NOT NULL THEN
    SELECT id
      INTO v_existing_receipt_event_id
      FROM public.production_order_receipt_events
     WHERE company_id = p_company_id
       AND production_order_id = p_production_order_id
       AND event_number = v_receipt_event_number
     ORDER BY created_at DESC
     LIMIT 1
     FOR UPDATE;

    IF FOUND THEN
      RETURN jsonb_build_object(
        'success', true,
        'idempotent', true,
        'production_order_id', p_production_order_id,
        'receipt_event_id', v_existing_receipt_event_id
      );
    END IF;
  END IF;

  PERFORM public.mpoe_assert_receipt_execution_ready(p_production_order_id);

  SELECT w.*
    INTO v_receipt_warehouse
    FROM public.warehouses w
   WHERE w.id = v_order.receipt_warehouse_id;

  IF NOT FOUND OR v_receipt_warehouse.cost_center_id IS NULL THEN
    RAISE EXCEPTION 'Receipt warehouse/cost center context not ready for finished-goods receipt. production_order_id=%',
      p_production_order_id;
  END IF;

  PERFORM public.mpoe_lock_inventory_bucket(
    p_company_id,
    v_order.receipt_warehouse_id,
    v_order.product_id
  );

  SELECT COALESCE(SUM(received_qty), 0)::NUMERIC(18,4)
    INTO v_already_received_qty
    FROM public.production_order_receipt_lines
   WHERE production_order_id = p_production_order_id;

  v_remaining_receivable_qty := GREATEST(v_order.planned_quantity - COALESCE(v_already_received_qty, 0), 0)::NUMERIC(18,4);

  IF v_received_qty > v_remaining_receivable_qty THEN
    RAISE EXCEPTION 'Received quantity exceeds remaining receivable quantity. production_order_id=%, remaining_qty=%, requested_qty=%',
      p_production_order_id, v_remaining_receivable_qty, v_received_qty;
  END IF;

  SELECT COALESCE(SUM(it.total_cost), 0)::NUMERIC(18,4)
    INTO v_total_issued_cost
    FROM public.production_order_issue_lines l
    JOIN public.inventory_transactions it ON it.id = l.inventory_transaction_id
   WHERE l.production_order_id = p_production_order_id;

  SELECT COALESCE(SUM(it.total_cost), 0)::NUMERIC(18,4)
    INTO v_total_receipted_cost
    FROM public.production_order_receipt_lines l
    JOIN public.inventory_transactions it ON it.id = l.inventory_transaction_id
   WHERE l.production_order_id = p_production_order_id;

  IF v_remaining_receivable_qty = v_received_qty THEN
    v_receipt_total_cost := GREATEST(v_total_issued_cost - v_total_receipted_cost, 0)::NUMERIC(18,4);
  ELSE
    v_receipt_total_cost := public.mpoe_round_qty(
      (COALESCE(v_total_issued_cost, 0) / v_order.planned_quantity) * v_received_qty
    );
  END IF;

  v_receipt_unit_cost := CASE
    WHEN v_received_qty > 0 THEN public.mpoe_round_qty(v_receipt_total_cost / v_received_qty)
    ELSE 0
  END;

  INSERT INTO public.production_order_receipt_events (
    id,
    company_id,
    branch_id,
    production_order_id,
    warehouse_id,
    cost_center_id,
    event_number,
    receipt_mode,
    posted_at,
    posted_by,
    notes
  ) VALUES (
    v_receipt_event_id,
    v_order.company_id,
    v_order.branch_id,
    v_order.id,
    v_order.receipt_warehouse_id,
    v_receipt_warehouse.cost_center_id,
    v_receipt_event_number,
    'manual',
    v_posted_at,
    p_posted_by,
    p_notes
  );

  INSERT INTO public.inventory_transactions (
    company_id,
    product_id,
    transaction_type,
    quantity_change,
    unit_cost,
    total_cost,
    reference_id,
    reference_type,
    notes,
    branch_id,
    cost_center_id,
    warehouse_id
  ) VALUES (
    p_company_id,
    v_order.product_id,
    'production_receipt',
    v_received_qty,
    v_receipt_unit_cost,
    v_receipt_total_cost,
    v_receipt_line_id,
    'production_receipt_line',
    p_notes,
    v_order.branch_id,
    v_receipt_warehouse.cost_center_id,
    v_order.receipt_warehouse_id
  )
  RETURNING id INTO v_inventory_transaction_id;

  INSERT INTO public.fifo_cost_lots (
    company_id,
    product_id,
    lot_date,
    lot_type,
    original_quantity,
    remaining_quantity,
    unit_cost,
    reference_type,
    reference_id,
    branch_id,
    warehouse_id,
    notes
  ) VALUES (
    p_company_id,
    v_order.product_id,
    v_posted_at::DATE,
    'production',
    v_received_qty,
    v_received_qty,
    v_receipt_unit_cost,
    'production_receipt_line',
    v_receipt_line_id,
    v_order.branch_id,
    v_order.receipt_warehouse_id,
    p_notes
  )
  RETURNING id INTO v_fifo_cost_lot_id;

  INSERT INTO public.production_order_receipt_lines (
    id,
    company_id,
    branch_id,
    receipt_event_id,
    production_order_id,
    line_no,
    warehouse_id,
    cost_center_id,
    product_id,
    output_type,
    inventory_transaction_id,
    fifo_cost_lot_id,
    received_qty,
    receipt_uom,
    notes
  ) VALUES (
    v_receipt_line_id,
    v_order.company_id,
    v_order.branch_id,
    v_receipt_event_id,
    v_order.id,
    1,
    v_order.receipt_warehouse_id,
    v_receipt_warehouse.cost_center_id,
    v_order.product_id,
    'main_output',
    v_inventory_transaction_id,
    v_fifo_cost_lot_id,
    v_received_qty,
    v_order.order_uom,
    p_notes
  );

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', p_production_order_id,
    'receipt_event_id', v_receipt_event_id,
    'received_qty', v_received_qty,
    'total_cost', v_receipt_total_cost,
    'unit_cost', v_receipt_unit_cost,
    'fifo_cost_lot_id', v_fifo_cost_lot_id
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- reclassify_account_safe(p_company_id uuid, p_source_account_id uuid, p_target_account_id uuid, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reclassify_account_safe(p_company_id uuid, p_source_account_id uuid, p_target_account_id uuid, p_reason text DEFAULT 'إعادة تصنيف وفق معايير Zoho Books'::text)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_balance DECIMAL(15, 2);
    v_journal_entry_id UUID;
    v_source_account_type TEXT;
    v_target_account_type TEXT;
    v_source_normal_balance TEXT;
    v_target_normal_balance TEXT;
    v_source_name TEXT;
    v_target_name TEXT;
BEGIN
    -- التحقق من وجود الحسابات
    SELECT account_type, normal_balance, account_name
    INTO v_source_account_type, v_source_normal_balance, v_source_name
    FROM chart_of_accounts
    WHERE id = p_source_account_id AND company_id = p_company_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'الحساب المصدر غير موجود: %', p_source_account_id;
    END IF;
    
    SELECT account_type, normal_balance, account_name
    INTO v_target_account_type, v_target_normal_balance, v_target_name
    FROM chart_of_accounts
    WHERE id = p_target_account_id AND company_id = p_company_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'الحساب الهدف غير موجود: %', p_target_account_id;
    END IF;
    
    -- حساب الرصيد الحالي
    v_balance := get_account_balance(p_company_id, p_source_account_id);
    
    IF ABS(v_balance) < 0.01 THEN
        -- لا يوجد رصيد: تحديث القيود فقط
        UPDATE journal_entry_lines
        SET account_id = p_target_account_id
        WHERE account_id = p_source_account_id;
        
        -- تسجيل العملية
        INSERT INTO coa_restructure_log (
            company_id, operation_type, source_account_id, target_account_id,
            amount, description
        ) VALUES (
            p_company_id, 'reclassify', p_source_account_id, p_target_account_id,
            0, p_reason
        );
        
        RETURN NULL;
    END IF;
    
    -- إنشاء قيد إعادة التصنيف
    INSERT INTO journal_entries (
        company_id,
        entry_date,
        description,
        reference_type,
        reference_id
    ) VALUES (
        p_company_id,
        CURRENT_DATE,
        format('%s: نقل من %s إلى %s', p_reason, v_source_name, v_target_name),
        'coa_reclassify',
        p_source_account_id::TEXT
    )
    RETURNING id INTO v_journal_entry_id;
    
    -- إنشاء قيود الإعادة التصنيف
    -- المنطق: نقل الرصيد من الحساب القديم إلى الجديد
    IF v_source_normal_balance = 'debit' AND v_target_normal_balance = 'debit' THEN
        -- كلاهما مدين: نفس المنطق
        IF v_balance > 0 THEN
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
            VALUES (v_journal_entry_id, p_target_account_id, ABS(v_balance), 0, 
                format('نقل رصيد من %s', v_source_name));
            
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
            VALUES (v_journal_entry_id, p_source_account_id, 0, ABS(v_balance), 
                format('نقل رصيد إلى %s', v_target_name));
        ELSE
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
            VALUES (v_journal_entry_id, p_target_account_id, 0, ABS(v_balance), 
                format('نقل رصيد من %s', v_source_name));
            
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
            VALUES (v_journal_entry_id, p_source_account_id, ABS(v_balance), 0, 
                format('نقل رصيد إلى %s', v_target_name));
        END IF;
    ELSIF v_source_normal_balance = 'credit' AND v_target_normal_balance = 'credit' THEN
        -- كلاهما دائن: نفس المنطق
        IF v_balance > 0 THEN
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
            VALUES (v_journal_entry_id, p_target_account_id, 0, ABS(v_balance), 
                format('نقل رصيد من %s', v_source_name));
            
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
            VALUES (v_journal_entry_id, p_source_account_id, ABS(v_balance), 0, 
                format('نقل رصيد إلى %s', v_target_name));
        ELSE
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
            VALUES (v_journal_entry_id, p_target_account_id, ABS(v_balance), 0, 
                format('نقل رصيد من %s', v_source_name));
            
            INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
            VALUES (v_journal_entry_id, p_source_account_id, 0, ABS(v_balance), 
                format('نقل رصيد إلى %s', v_target_name));
        END IF;
    ELSE
        -- تغيير الطبيعة: يحتاج معالجة خاصة
        RAISE EXCEPTION 'إعادة التصنيف بين حسابات بطبائع مختلفة غير مدعومة حالياً';
    END IF;
    
    -- تحديث جميع القيود المحاسبية
    UPDATE journal_entry_lines
    SET account_id = p_target_account_id
    WHERE account_id = p_source_account_id;
    
    -- تسجيل العملية
    INSERT INTO coa_restructure_log (
        company_id, operation_type, source_account_id, target_account_id,
        journal_entry_id, amount, description
    ) VALUES (
        p_company_id, 'reclassify', p_source_account_id, p_target_account_id,
        v_journal_entry_id, ABS(v_balance), p_reason
    );
    
    -- تعطيل الحساب القديم
    UPDATE chart_of_accounts
    SET is_active = false,
        account_code = account_code || '_RECLASSIFIED_' || gen_random_uuid()::TEXT
    WHERE id = p_source_account_id;
    
    RETURN v_journal_entry_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- recompute_account_balances_for_date(target_company uuid, target_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recompute_account_balances_for_date(target_company uuid, target_date date)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  BEGIN
    DELETE FROM account_balances WHERE company_id = target_company AND balance_date = target_date;
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;
  BEGIN
    INSERT INTO account_balances (company_id, account_id, balance_date, debit_balance, credit_balance)
    SELECT je.company_id, l.account_id, target_date,
           COALESCE(SUM(l.debit_amount), 0) AS debit_balance,
           COALESCE(SUM(l.credit_amount), 0) AS credit_balance
    FROM journal_entry_lines l
    INNER JOIN journal_entries je ON je.id = l.journal_entry_id
    WHERE je.company_id = target_company AND je.entry_date <= target_date AND COALESCE(je.is_deleted, FALSE) = FALSE
    GROUP BY je.company_id, l.account_id;
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;
END;
$function$
;

-- ---------------------------------------------------------------
-- recompute_on_journal_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recompute_on_journal_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  tgt_company UUID := OLD.company_id;
  tgt_date DATE := OLD.entry_date;
BEGIN
  PERFORM recompute_account_balances_for_date(tgt_company, tgt_date);
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- recompute_on_journal_soft_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recompute_on_journal_soft_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NEW.is_deleted = TRUE AND COALESCE(OLD.is_deleted, FALSE) = FALSE THEN
    PERFORM recompute_account_balances_for_date(OLD.company_id, OLD.entry_date);
  END IF;
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- recompute_on_line_change()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recompute_on_line_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  comp_id UUID;
  entry_dt DATE;
  je_id UUID;
BEGIN
  IF TG_OP = 'INSERT' THEN
    je_id := NEW.journal_entry_id;
  ELSIF TG_OP = 'UPDATE' THEN
    je_id := COALESCE(NEW.journal_entry_id, OLD.journal_entry_id);
  ELSE
    je_id := OLD.journal_entry_id;
  END IF;

  SELECT company_id, entry_date INTO comp_id, entry_dt FROM journal_entries WHERE id = je_id;
  IF comp_id IS NULL OR entry_dt IS NULL THEN
    RETURN NULL;
  END IF;

  PERFORM recompute_account_balances_for_date(comp_id, entry_dt);
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- reconcile_fifo_vs_gl(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reconcile_fifo_vs_gl(p_company_id uuid)
 RETURNS TABLE(product_id uuid, product_name text, fifo_value numeric, gl_inventory_value numeric, difference numeric, status text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_total_gl_inventory NUMERIC := 0;
  v_total_fifo         NUMERIC := 0;
BEGIN
  -- Get total GL inventory value for this company
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0)
  INTO v_total_gl_inventory
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id
    AND je.status = 'posted'
    AND coa.account_type = 'asset'
    AND (coa.sub_type = 'inventory' OR coa.account_name ILIKE '%مخزون%');

  -- Get total FIFO value
  SELECT COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost), 0)
  INTO v_total_fifo
  FROM fifo_cost_lots fcl
  JOIN products p ON p.id = fcl.product_id
  WHERE p.company_id = p_company_id AND fcl.remaining_quantity > 0;

  -- Return per-product FIFO breakdown vs total GL (GL is per company, not per product in GL)
  RETURN QUERY
  SELECT
    p.id::UUID as product_id,
    p.name::TEXT as product_name,
    COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost), 0)::NUMERIC as fifo_value,
    -- Proportional GL allocation (since GL doesn't track per-product)
    CASE WHEN v_total_fifo > 0
      THEN ROUND((COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost), 0) / v_total_fifo) * v_total_gl_inventory, 4)
      ELSE 0 END::NUMERIC as gl_inventory_value,
    CASE WHEN v_total_fifo > 0
      THEN COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost), 0) -
           ROUND((COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost), 0) / v_total_fifo) * v_total_gl_inventory, 4)
      ELSE COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost), 0) END::NUMERIC as difference,
    CASE
      WHEN ABS(v_total_gl_inventory - v_total_fifo) < 1 THEN 'OK'
      WHEN ABS(v_total_gl_inventory - v_total_fifo) > v_total_gl_inventory * 0.05 THEN 'CRITICAL'
      ELSE 'WARNING'
    END::TEXT as status
  FROM products p
  LEFT JOIN fifo_cost_lots fcl ON fcl.product_id = p.id AND fcl.remaining_quantity > 0
  WHERE p.company_id = p_company_id
  GROUP BY p.id, p.name
  HAVING COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost), 0) > 0
  ORDER BY fifo_value DESC;
END; $function$
;

-- ---------------------------------------------------------------
-- record_approval_action(p_company_id uuid, p_reference_type text, p_reference_id uuid, p_cycle_no integer, p_action text, p_actor_id uuid, p_actor_role text, p_reason text, p_snapshot_data jsonb, p_branch_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.record_approval_action(p_company_id uuid, p_reference_type text, p_reference_id uuid, p_cycle_no integer, p_action text, p_actor_id uuid, p_actor_role text, p_reason text DEFAULT NULL::text, p_snapshot_data jsonb DEFAULT NULL::jsonb, p_branch_id uuid DEFAULT NULL::uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_id uuid;
BEGIN
  INSERT INTO public.approval_history (
    company_id, reference_type, reference_id, cycle_no, action,
    actor_id, actor_role, reason, snapshot_data, branch_id
  ) VALUES (
    p_company_id, p_reference_type, p_reference_id, GREATEST(p_cycle_no, 1), p_action,
    p_actor_id, p_actor_role, p_reason, p_snapshot_data, p_branch_id
  )
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- record_financial_replay_execution_activation(p_company_id uuid, p_intent_id uuid, p_token_hash text, p_actor_id uuid, p_preview_result_hash text, p_write_guard jsonb, p_execution_metadata jsonb, p_result_summary jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.record_financial_replay_execution_activation(p_company_id uuid, p_intent_id uuid, p_token_hash text, p_actor_id uuid, p_preview_result_hash text, p_write_guard jsonb DEFAULT '{}'::jsonb, p_execution_metadata jsonb DEFAULT '{}'::jsonb, p_result_summary jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_intent public.financial_replay_commit_intents%ROWTYPE;
  v_execution_id UUID;
  v_now TIMESTAMPTZ := NOW();
BEGIN
  SELECT *
    INTO v_intent
  FROM public.financial_replay_commit_intents
  WHERE id = p_intent_id
    AND company_id = p_company_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'REPLAY_COMMIT_INTENT_NOT_FOUND';
  END IF;

  IF v_intent.status <> 'issued' THEN
    RAISE EXCEPTION 'REPLAY_COMMIT_INTENT_NOT_ACTIVE';
  END IF;

  IF v_intent.expires_at <= v_now THEN
    UPDATE public.financial_replay_commit_intents
    SET status = 'expired',
        updated_at = v_now
    WHERE id = v_intent.id;

    RAISE EXCEPTION 'REPLAY_COMMIT_INTENT_EXPIRED';
  END IF;

  IF v_intent.token_hash <> p_token_hash THEN
    RAISE EXCEPTION 'REPLAY_COMMIT_TOKEN_INVALID';
  END IF;

  IF v_intent.preview_result_hash <> p_preview_result_hash THEN
    RAISE EXCEPTION 'REPLAY_COMMIT_PREVIEW_HASH_MISMATCH';
  END IF;

  UPDATE public.financial_replay_commit_intents
  SET status = 'consumed',
      consumed_by = p_actor_id,
      consumed_at = v_now,
      updated_at = v_now
  WHERE id = v_intent.id;

  INSERT INTO public.financial_replay_executions (
    company_id,
    commit_intent_id,
    source_trace_id,
    event_type,
    payload_version,
    preview_result_hash,
    preview_hash_algorithm,
    execution_mode,
    status,
    financial_writes_performed,
    write_guard,
    execution_metadata,
    result_summary,
    token_hint,
    executed_by,
    executed_at
  )
  VALUES (
    v_intent.company_id,
    v_intent.id,
    v_intent.source_trace_id,
    v_intent.event_type,
    v_intent.payload_version,
    v_intent.preview_result_hash,
    v_intent.preview_hash_algorithm,
    'controlled_single_path',
    'validated',
    FALSE,
    COALESCE(p_write_guard, '{}'::JSONB),
    COALESCE(p_execution_metadata, '{}'::JSONB),
    COALESCE(p_result_summary, '{}'::JSONB),
    v_intent.token_hint,
    p_actor_id,
    v_now
  )
  RETURNING id INTO v_execution_id;

  RETURN jsonb_build_object(
    'execution_id', v_execution_id,
    'intent_id', v_intent.id,
    'status', 'validated',
    'consumed_at', v_now,
    'financial_writes_performed', FALSE
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- record_payment(p_invoice_id uuid, p_amount numeric, p_payment_date date, p_account_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.record_payment(p_invoice_id uuid, p_amount numeric, p_payment_date date, p_account_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company_id UUID;
  v_ar_id UUID;
  v_journal_id UUID;
BEGIN
  SELECT company_id INTO v_company_id FROM invoices WHERE id = p_invoice_id;
  SELECT id INTO v_ar_id FROM chart_of_accounts WHERE company_id = v_company_id AND sub_type = 'accounts_receivable' LIMIT 1;

  INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description)
  VALUES (v_company_id, 'payment', p_invoice_id, p_payment_date, 'Payment received')
  RETURNING id INTO v_journal_id;

  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description) VALUES 
  (v_journal_id, p_account_id, p_amount, 0, 'Cash/Bank'),
  (v_journal_id, v_ar_id, 0, p_amount, 'Accounts Receivable');

  RETURN v_journal_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- record_payment(p_invoice_id uuid, p_amount numeric, p_payment_date date, p_account_id uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.record_payment(p_invoice_id uuid, p_amount numeric, p_payment_date date, p_account_id uuid, p_notes text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- ⚠️ DEPRECATED: This function is no longer the canonical payment JE creator.  
  -- Use process_invoice_payment_atomic() instead.
  -- This stub prevents breaking existing calls while logging a warning.
  RAISE WARNING 'DEPRECATED: record_payment() called for invoice %. Use process_invoice_payment_atomic() instead.', p_invoice_id;
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- record_shareholder_drawing_atomic(p_company_id uuid, p_shareholder_id uuid, p_amount numeric, p_drawing_date date, p_payment_account_id uuid, p_drawings_account_id uuid, p_description text, p_branch_id uuid, p_cost_center_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.record_shareholder_drawing_atomic(p_company_id uuid, p_shareholder_id uuid, p_amount numeric, p_drawing_date date, p_payment_account_id uuid, p_drawings_account_id uuid, p_description text DEFAULT NULL::text, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid, p_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_drawing_id UUID;
  v_journal_id UUID;
BEGIN
  -- 1. Validate Period Locking (STRICT)
  PERFORM validate_transaction_period(p_company_id, p_drawing_date);

  -- 2. Insert Drawing
  INSERT INTO public.shareholder_drawings (
    company_id, shareholder_id, drawing_date, amount, description, status, created_by
  ) VALUES (
    p_company_id, p_shareholder_id, p_drawing_date, p_amount, p_description, 'posted', p_user_id
  ) RETURNING id INTO v_drawing_id;

  -- 3. Create Journal Entry
  -- DR Drawings (Equity Contra - Increases)
  -- CR Bank/Cash (Asset Decrease)
  
  INSERT INTO public.journal_entries (
    company_id, entry_date, description, reference_type, reference_id, 
    status, branch_id, cost_center_id, posted_by, posted_at
  ) VALUES (
    p_company_id, p_drawing_date, 'Shareholder Drawing - ' || p_drawing_date, 'shareholder_drawing', v_drawing_id,
    'posted', p_branch_id, p_cost_center_id, p_user_id, NOW()
  ) RETURNING id INTO v_journal_id;
  
  -- Update Drawing with JE ID
  UPDATE public.shareholder_drawings SET journal_entry_id = v_journal_id WHERE id = v_drawing_id;

  -- Insert Lines
  -- Debit Drawings
  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount, branch_id, cost_center_id
  ) VALUES (
    v_journal_id, p_drawings_account_id, 'Shareholder Withdrawal', p_amount, 0, p_branch_id, p_cost_center_id
  );

  -- Credit Bank
  INSERT INTO public.journal_entry_lines (
    journal_entry_id, account_id, description, debit_amount, credit_amount, branch_id, cost_center_id
  ) VALUES (
    v_journal_id, p_payment_account_id, 'Cash Outflow', 0, p_amount, p_branch_id, p_cost_center_id
  );

  RETURN jsonb_build_object('drawing_id', v_drawing_id, 'journal_entry_id', v_journal_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- recurring_template_balance_check_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.recurring_template_balance_check_trg()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_debit  numeric;
  v_credit numeric;
BEGIN
  IF TG_OP = 'DELETE' THEN RETURN OLD; END IF;
  SELECT COALESCE(SUM(debit_amount),0), COALESCE(SUM(credit_amount),0)
    INTO v_debit, v_credit
    FROM public.recurring_journal_template_lines
   WHERE template_id = NEW.template_id;
  -- Rows exist (INSERT/UPDATE fires per row)
  IF v_debit <> v_credit AND (v_debit + v_credit) > 0 THEN
    RAISE EXCEPTION 'Recurring template must balance: debit % vs credit %', v_debit, v_credit
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END; $function$
;

