-- ---------------------------------------------------------------
-- regenerate_asset_schedules(p_asset_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.regenerate_asset_schedules(p_asset_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_asset RECORD;
  v_state JSONB;
  v_book_value DECIMAL;
  v_remaining_life INTEGER;
  v_posted_count INTEGER;
  v_cutoff_date DATE;
  v_next_date DATE;
  v_period INTEGER;
  v_monthly_depreciation DECIMAL;
  v_accumulated DECIMAL;
  v_final_salvage_value DECIMAL;
BEGIN
  -- Get Asset
  SELECT * INTO v_asset FROM public.fixed_assets WHERE id = p_asset_id;
  
  -- 1. Clear future (pending) schedules
  DELETE FROM public.depreciation_schedules 
  WHERE asset_id = p_asset_id AND status = 'pending';

  -- 2. Get Current State
  v_state := get_asset_current_state(p_asset_id);
  v_book_value := (v_state->>'book_value')::DECIMAL;
  v_remaining_life := (v_state->>'remaining_life_months')::INTEGER;
  v_posted_count := (v_state->>'posted_count')::INTEGER;
  v_cutoff_date := (v_state->>'cutoff_date')::DATE;
  
  -- Init loop variables
  v_next_date := v_cutoff_date + INTERVAL '1 month';
  
  -- Get current accumulated from asset or calculate
  v_accumulated := v_asset.purchase_cost - v_book_value; 

  -- If no remaining life or fully depreciated, stop
  IF v_remaining_life <= 0 OR v_book_value <= v_asset.salvage_value THEN
    RETURN TRUE; 
  END IF;

  -- 3. Loop to generate schedules
  FOR i IN 1..v_remaining_life LOOP
  
    -- Calculate Depreciation Amount (Straight Line for now)
    v_monthly_depreciation := (v_book_value - v_asset.salvage_value) / (v_remaining_life - i + 1);
    
    -- Rounding
    v_monthly_depreciation := ROUND(v_monthly_depreciation, 2);
    
    -- Last month adjustment
    IF i = v_remaining_life THEN
        v_monthly_depreciation := v_book_value - v_asset.salvage_value;
    END IF;
    
    -- prevent negative
    IF v_monthly_depreciation < 0 THEN v_monthly_depreciation := 0; END IF;

    -- Update running totals
    v_accumulated := v_accumulated + v_monthly_depreciation;
    v_book_value := v_book_value - v_monthly_depreciation;
    
    -- Insert Schedule
    INSERT INTO public.depreciation_schedules (
      company_id,
      asset_id, 
      period_number, 
      period_date,
      depreciation_amount,
      accumulated_depreciation,
      book_value,
      status
    ) VALUES (
      v_asset.company_id,
      p_asset_id,
      v_posted_count + i, -- Continue numbering consecutively from last posted
      v_next_date,
      v_monthly_depreciation,
      v_accumulated,
      v_book_value,
      'pending'
    );
    
    v_next_date := v_next_date + INTERVAL '1 month';
    
  END LOOP;

  RETURN TRUE;
END;
$function$
;

-- ---------------------------------------------------------------
-- regenerate_manufacturing_production_order_operations_atomic(p_company_id uuid, p_production_order_id uuid, p_updated_by uuid, p_product_id uuid, p_bom_id uuid, p_bom_version_id uuid, p_routing_id uuid, p_routing_version_id uuid, p_issue_warehouse_id uuid, p_receipt_warehouse_id uuid, p_planned_quantity numeric, p_order_uom text, p_planned_start_at timestamp with time zone, p_planned_end_at timestamp with time zone, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.regenerate_manufacturing_production_order_operations_atomic(p_company_id uuid, p_production_order_id uuid, p_updated_by uuid, p_product_id uuid, p_bom_id uuid, p_bom_version_id uuid, p_routing_id uuid, p_routing_version_id uuid, p_issue_warehouse_id uuid, p_receipt_warehouse_id uuid, p_planned_quantity numeric, p_order_uom text, p_planned_start_at timestamp with time zone, p_planned_end_at timestamp with time zone, p_notes text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order RECORD;
  v_routing_version RECORD;
  v_routing_operation RECORD;
  v_operation_count INTEGER := 0;
BEGIN
  IF p_planned_quantity IS NULL OR p_planned_quantity <= 0 THEN
    RAISE EXCEPTION 'planned_quantity must be greater than zero.';
  END IF;

  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order not found or not in company. production_order_id=%', p_production_order_id;
  END IF;

  IF v_order.status <> 'draft' THEN
    RAISE EXCEPTION 'Only draft production orders can regenerate operation snapshots. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  END IF;

  SELECT *
    INTO v_routing_version
    FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing routing version not found or not in company. routing_version_id=%', p_routing_version_id;
  END IF;

  UPDATE public.manufacturing_production_orders
     SET product_id = p_product_id,
         bom_id = p_bom_id,
         bom_version_id = p_bom_version_id,
         routing_id = p_routing_id,
         routing_version_id = p_routing_version_id,
         issue_warehouse_id = p_issue_warehouse_id,
         receipt_warehouse_id = p_receipt_warehouse_id,
         planned_quantity = p_planned_quantity,
         order_uom = p_order_uom,
         planned_start_at = p_planned_start_at,
         planned_end_at = p_planned_end_at,
         notes = p_notes,
         updated_by = p_updated_by
   WHERE id = p_production_order_id;

  DELETE FROM public.manufacturing_production_order_operations
   WHERE production_order_id = p_production_order_id;

  FOR v_routing_operation IN
    SELECT *
      FROM public.manufacturing_routing_operations
     WHERE routing_version_id = p_routing_version_id
     ORDER BY operation_no
  LOOP
    INSERT INTO public.manufacturing_production_order_operations (
      company_id,
      branch_id,
      production_order_id,
      routing_version_id,
      source_routing_operation_id,
      operation_no,
      operation_code,
      operation_name,
      work_center_id,
      status,
      planned_quantity,
      completed_quantity,
      setup_time_minutes,
      run_time_minutes_per_unit,
      queue_time_minutes,
      move_time_minutes,
      labor_time_minutes,
      machine_time_minutes,
      quality_checkpoint_required,
      instructions,
      created_by,
      updated_by
    ) VALUES (
      p_company_id,
      v_order.branch_id,
      p_production_order_id,
      p_routing_version_id,
      v_routing_operation.id,
      v_routing_operation.operation_no,
      v_routing_operation.operation_code,
      v_routing_operation.operation_name,
      v_routing_operation.work_center_id,
      'pending',
      p_planned_quantity,
      0,
      v_routing_operation.setup_time_minutes,
      v_routing_operation.run_time_minutes_per_unit,
      v_routing_operation.queue_time_minutes,
      v_routing_operation.move_time_minutes,
      v_routing_operation.labor_time_minutes,
      v_routing_operation.machine_time_minutes,
      v_routing_operation.quality_checkpoint_required,
      v_routing_operation.instructions,
      p_updated_by,
      p_updated_by
    );

    v_operation_count := v_operation_count + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', p_production_order_id,
    'routing_version_id', p_routing_version_id,
    'planned_quantity', p_planned_quantity,
    'operation_count', v_operation_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- register_asset_addition(p_asset_id uuid, p_amount numeric, p_date date, p_description text, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.register_asset_addition(p_asset_id uuid, p_amount numeric, p_date date, p_description text, p_user_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_asset RECORD;
  v_journal_id UUID;
  v_transaction_id UUID;
BEGIN
  SELECT * INTO v_asset FROM fixed_assets WHERE id = p_asset_id;
  
  -- 1. Create Journal Entry (Debit Asset, Credit Bank/Payable)
  -- For simplicity, assuming Bank (1110) for now. Ideally pass contra-account.
  -- This part should ideally reuse a shared "create_journal" function if available, or be explicit.
  
  INSERT INTO journal_entries (
    company_id, entry_date, description, reference_type, reference_id
  ) VALUES (
    v_asset.company_id, p_date, 'Additions to Asset: ' || v_asset.name || ' - ' || p_description, 'asset_addition', p_asset_id
  ) RETURNING id INTO v_journal_id;
  
  -- DEBIT: Asset Account
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, description, debit_amount, credit_amount)
  VALUES (v_journal_id, v_asset.asset_account_id, 'Addition: ' || v_asset.name, p_amount, 0);
  
  -- CREDIT: Bank/Cash (Hardcoded for prototype, should be parameter)
  -- Finding a safe default '1110'
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, description, debit_amount, credit_amount)
  SELECT v_journal_id, id, 'Payment for Addition', 0, p_amount
  FROM chart_of_accounts WHERE company_id = v_asset.company_id AND account_code = '1110' LIMIT 1;
  
  -- 2. Create Asset Transaction
  INSERT INTO asset_transactions (
    company_id, asset_id, transaction_type, transaction_date, amount, reference_id, reference_type, details, created_by
  ) VALUES (
    v_asset.company_id, p_asset_id, 'addition', p_date, p_amount, v_journal_id, 'journal_entry', 
    jsonb_build_object('description', p_description), p_user_id
  ) RETURNING id INTO v_transaction_id;
  
  -- 3. Update Asset Header (Book Value matches instantly for display, but regeneration fixes schedule)
  UPDATE fixed_assets 
  SET purchase_cost = purchase_cost + p_amount,
      book_value = book_value + p_amount,
      updated_at = NOW()
  WHERE id = p_asset_id;
  
  -- 4. Regenerate Schedules
  PERFORM regenerate_asset_schedules(p_asset_id);
  
  RETURN v_transaction_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- reject_bank_voucher(p_request_id uuid, p_rejected_by uuid, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reject_bank_voucher(p_request_id uuid, p_rejected_by uuid, p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_req RECORD;
BEGIN
    SELECT * INTO v_req FROM public.bank_voucher_requests WHERE id = p_request_id FOR UPDATE;

    IF v_req IS NULL THEN
        RAISE EXCEPTION 'Request not found';
    END IF;

    IF v_req.status != 'pending' THEN
        RAISE EXCEPTION 'Request is already %', v_req.status;
    END IF;

    UPDATE public.bank_voucher_requests SET
        status = 'rejected',
        reviewed_by = p_rejected_by,
        reviewed_at = NOW(),
        rejection_reason = p_reason
    WHERE id = p_request_id;

    RETURN jsonb_build_object('success', true);
END;
$function$
;

-- ---------------------------------------------------------------
-- reject_customer_debit_note(p_debit_note_id uuid, p_rejected_by uuid, p_rejection_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reject_customer_debit_note(p_debit_note_id uuid, p_rejected_by uuid, p_rejection_reason text)
 RETURNS TABLE(success boolean, message text)
 LANGUAGE plpgsql
AS $function$ DECLARE v_debit_note RECORD; BEGIN SELECT * INTO v_debit_note FROM customer_debit_notes WHERE id = p_debit_note_id; IF NOT FOUND THEN RETURN QUERY SELECT FALSE, 'Debit note not found'; RETURN; END IF; IF v_debit_note.applied_amount > 0 THEN RETURN QUERY SELECT FALSE, 'Cannot reject debit note - it has been applied'; RETURN; END IF; UPDATE customer_debit_notes SET approval_status = 'rejected', rejection_reason = p_rejection_reason, updated_at = NOW() WHERE id = p_debit_note_id; RETURN QUERY SELECT TRUE, 'Debit note rejected'; END; $function$
;

-- ---------------------------------------------------------------
-- reject_manufacturing_bom_version_atomic(p_company_id uuid, p_bom_version_id uuid, p_rejected_by uuid, p_rejection_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reject_manufacturing_bom_version_atomic(p_company_id uuid, p_bom_version_id uuid, p_rejected_by uuid, p_rejection_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version RECORD;
BEGIN
  IF p_rejection_reason IS NULL OR BTRIM(p_rejection_reason) = '' THEN
    RAISE EXCEPTION 'Rejection reason is required.';
  END IF;

  SELECT * INTO v_version
    FROM public.manufacturing_bom_versions
   WHERE id = p_bom_version_id AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'BOM version not found. bom_version_id=%', p_bom_version_id;
  END IF;

  IF v_version.status <> 'pending_approval' THEN
    RAISE EXCEPTION 'Only pending_approval versions can be rejected. status=%', v_version.status;
  END IF;

  UPDATE public.manufacturing_bom_versions
     SET status           = 'rejected',
         is_default       = false,
         approved_by      = NULL,
         approved_at      = NULL,
         rejected_by      = p_rejected_by,
         rejected_at      = NOW(),
         rejection_reason = p_rejection_reason,
         updated_by       = p_rejected_by
   WHERE id = p_bom_version_id;

  RETURN jsonb_build_object(
    'success',        true,
    'bom_version_id', p_bom_version_id,
    'status',         'rejected'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- reject_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_rejected_by uuid, p_rejection_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reject_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_rejected_by uuid, p_rejection_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_po record;
BEGIN
  IF p_rejection_reason IS NULL OR TRIM(p_rejection_reason) = '' THEN
    RETURN jsonb_build_object('success', false, 'error', 'سبب الرفض مطلوب');
  END IF;
  SELECT role INTO v_role FROM public.company_members
   WHERE company_id = p_company_id AND user_id = p_rejected_by;
  IF NOT FOUND OR v_role NOT IN ('owner', 'general_manager') THEN
    RETURN jsonb_build_object('success', false,
      'error', 'صلاحية رفض أوامر الإنتاج محصورة بالمالك والمدير العام');
  END IF;

  SELECT * INTO v_po FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'أمر الإنتاج غير موجود');
  END IF;
  IF v_po.approval_status <> 'pending_approval' THEN
    RETURN jsonb_build_object('success', false, 'error', 'الأمر ليس بانتظار الاعتماد');
  END IF;

  UPDATE public.manufacturing_production_orders
     SET approval_status  = 'rejected',
         rejected_by      = p_rejected_by,
         rejected_at      = NOW(),
         rejection_reason = p_rejection_reason
   WHERE id = p_production_order_id;

  RETURN jsonb_build_object('success', true, 'approval_status', 'rejected');
END;
$function$
;

-- ---------------------------------------------------------------
-- reject_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_rejected_by uuid, p_rejection_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reject_routing_version_atomic(p_company_id uuid, p_routing_version_id uuid, p_rejected_by uuid, p_rejection_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_rv record;
BEGIN
  IF p_rejection_reason IS NULL OR TRIM(p_rejection_reason) = '' THEN
    RETURN jsonb_build_object('success', false, 'error', 'سبب الرفض مطلوب');
  END IF;

  SELECT role INTO v_role FROM public.company_members
   WHERE company_id = p_company_id AND user_id = p_rejected_by;
  IF NOT FOUND OR v_role NOT IN ('owner', 'general_manager') THEN
    RETURN jsonb_build_object('success', false,
      'error', 'صلاحية رفض مسارات التصنيع محصورة بالمالك والمدير العام');
  END IF;

  SELECT * INTO v_rv FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'النسخة غير موجودة');
  END IF;
  IF v_rv.approval_status <> 'pending_approval' THEN
    RETURN jsonb_build_object('success', false, 'error', 'النسخة ليست بانتظار الاعتماد');
  END IF;

  UPDATE public.manufacturing_routing_versions
     SET approval_status  = 'rejected',
         rejected_by      = p_rejected_by,
         rejected_at      = NOW(),
         rejection_reason = p_rejection_reason
   WHERE id = p_routing_version_id;

  RETURN jsonb_build_object('success', true, 'approval_status', 'rejected');
END;
$function$
;

-- ---------------------------------------------------------------
-- reject_sales_delivery(p_invoice_id uuid, p_confirmed_by uuid, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reject_sales_delivery(p_invoice_id uuid, p_confirmed_by uuid, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_invoice       RECORD;
  v_credit_amount NUMERIC := 0;
  v_decision_at   TIMESTAMPTZ := NOW();
BEGIN
  SELECT *
  INTO v_invoice
  FROM public.invoices
  WHERE id = p_invoice_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invoice not found');
  END IF;

  IF v_invoice.warehouse_status != 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Delivery already processed');
  END IF;

  IF v_invoice.status NOT IN ('sent', 'paid', 'partially_paid') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invoice must be posted (sent/paid) before warehouse action');
  END IF;

  IF COALESCE(v_invoice.paid_amount, 0) = 0 THEN
    UPDATE public.invoices
    SET
      status = 'draft',
      warehouse_status = 'rejected',
      approval_status = 'rejected',
      approval_reason = NULLIF(p_notes, ''),
      approved_by = NULL,
      approval_date = v_decision_at,
      rejected_by = p_confirmed_by,
      rejected_at = v_decision_at,
      warehouse_rejection_reason = p_notes,
      warehouse_rejected_at = v_decision_at
    WHERE id = p_invoice_id;

    RETURN jsonb_build_object(
      'success',           true,
      'message',           'Invoice reverted to draft due to warehouse rejection (no payment existed)',
      'reverted_to_draft', true,
      'credit_created',    false,
      'credit_amount',     0
    );
  END IF;

  v_credit_amount := COALESCE(v_invoice.paid_amount, 0);

  UPDATE public.invoices
  SET
    warehouse_status = 'rejected',
    approval_status = 'rejected',
    approval_reason = NULLIF(p_notes, ''),
    approved_by = NULL,
    approval_date = v_decision_at,
    rejected_by = p_confirmed_by,
    rejected_at = v_decision_at,
    warehouse_rejection_reason = p_notes,
    warehouse_rejected_at = v_decision_at
  WHERE id = p_invoice_id;

  INSERT INTO public.customer_credit_ledger (
    company_id,
    customer_id,
    amount,
    source_type,
    source_id,
    description,
    created_by
  )
  SELECT
    v_invoice.company_id,
    v_invoice.customer_id,
    v_credit_amount,
    'delivery_rejection',
    p_invoice_id,
    COALESCE(
      p_notes,
      'تحويل دفعة بسبب رفض التسليم من المخزن للفاتورة رقم: ' || v_invoice.invoice_number
    ),
    p_confirmed_by
  WHERE NOT EXISTS (
    SELECT 1
    FROM public.customer_credit_ledger
    WHERE source_type = 'delivery_rejection'
      AND source_id = p_invoice_id
  );

  RETURN jsonb_build_object(
    'success',           true,
    'message',           'Delivery rejected and payment converted to customer credit',
    'reverted_to_draft', false,
    'credit_created',    true,
    'credit_amount',     v_credit_amount
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- reject_supplier_payment(p_payment_id uuid, p_rejector_id uuid, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reject_supplier_payment(p_payment_id uuid, p_rejector_id uuid, p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_payment RECORD;
  v_member  RECORD;
BEGIN
  IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
    RAISE EXCEPTION 'REASON_REQUIRED: rejection_reason is mandatory';
  END IF;

  SELECT * INTO v_payment FROM payments WHERE id = p_payment_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Payment not found'; END IF;
  IF v_payment.status != 'pending_approval' THEN
    RAISE EXCEPTION 'Payment is not pending approval. Current status: %', v_payment.status;
  END IF;

  SELECT role INTO v_member
  FROM company_members
  WHERE user_id = p_rejector_id AND company_id = v_payment.company_id;
  IF NOT FOUND OR v_member.role NOT IN ('owner', 'admin', 'general_manager') THEN
    RAISE EXCEPTION 'UNAUTHORIZED: Only owner/admin/general_manager can reject payments';
  END IF;

  UPDATE payments SET
    status = 'rejected',
    rejected_by = p_rejector_id,
    rejected_at = NOW(),
    rejection_reason = p_reason,
    updated_at = NOW()
  WHERE id = p_payment_id;

  -- Notify creator
  IF v_payment.created_by IS NOT NULL THEN
    INSERT INTO notifications (
      company_id, branch_id, reference_type, reference_id,
      created_by, assigned_to_user,
      title, message, priority, status, event_key
    ) VALUES (
      v_payment.company_id, v_payment.branch_id,
      'supplier_payment_rejected', p_payment_id,
      p_rejector_id, v_payment.created_by,
      'تم رفض طلب الدفع',
      'تم رفض دفعة المورد بمبلغ ' || v_payment.amount || '. السبب: ' || p_reason,
      'high', 'unread',
      'payment_rejected_' || p_payment_id::text
    );
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'payment_id', p_payment_id,
    'status', 'rejected',
    'rejected_by', p_rejector_id,
    'rejection_reason', p_reason
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- reject_warehouse_return(p_purchase_return_id uuid, p_rejected_by uuid, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reject_warehouse_return(p_purchase_return_id uuid, p_rejected_by uuid, p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_pr RECORD;
BEGIN
  IF p_reason IS NULL OR TRIM(p_reason) = '' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Warehouse rejection reason is required');
  END IF;

  SELECT * INTO v_pr
  FROM purchase_returns
  WHERE id = p_purchase_return_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Purchase return not found');
  END IF;

  IF v_pr.workflow_status NOT IN ('pending_warehouse', 'pending_approval') THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', format(
        'Cannot reject: return is not pending warehouse confirmation. Current status: %s',
        v_pr.workflow_status
      )
    );
  END IF;

  UPDATE purchase_returns
  SET
    workflow_status            = 'warehouse_rejected',
    warehouse_rejection_reason = p_reason,
    warehouse_rejected_by      = p_rejected_by,
    warehouse_rejected_at      = NOW(),
    is_locked                  = false,
    updated_at                 = NOW()
  WHERE id = p_purchase_return_id;

  INSERT INTO audit_logs (
    company_id, user_id, action, target_table, record_id, old_data, new_data, created_at
  ) VALUES (
    v_pr.company_id, p_rejected_by,
    'WAREHOUSE_REJECT',
    'purchase_returns',
    p_purchase_return_id,
    jsonb_build_object('workflow_status', v_pr.workflow_status),
    jsonb_build_object('workflow_status', 'warehouse_rejected', 'reason', p_reason),
    NOW()
  );

  RETURN jsonb_build_object(
    'success',          true,
    'pr_id',            p_purchase_return_id,
    'workflow_status',  'warehouse_rejected',
    'created_by',       v_pr.created_by
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- release_manufacturing_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_updated_by uuid, p_released_at timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.release_manufacturing_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_updated_by uuid, p_released_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order RECORD;
  v_released_at TIMESTAMPTZ := COALESCE(p_released_at, NOW());
BEGIN
  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order not found or not in company. production_order_id=%', p_production_order_id;
  END IF;

  UPDATE public.manufacturing_production_orders
     SET status = 'released',
         released_at = v_released_at,
         released_by = p_updated_by,
         updated_by = p_updated_by
   WHERE id = p_production_order_id;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', p_production_order_id,
    'previous_status', v_order.status,
    'status', 'released',
    'released_at', v_released_at
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- release_seat(p_company_id uuid, p_invite_id uuid, p_by_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.release_seat(p_company_id uuid, p_invite_id uuid, p_by_user_id uuid DEFAULT NULL::uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE company_invitations
  SET seat_reserved = FALSE,
      status = 'cancelled',
      cancelled_at = now()
  WHERE id = p_invite_id AND company_id = p_company_id;

  INSERT INTO seat_transactions(company_id, transaction_type, seats_delta, performed_by, metadata)
  VALUES (p_company_id, 'release', 0, p_by_user_id, json_build_object('invite_id', p_invite_id));

  RETURN json_build_object('success', TRUE);
END;
$function$
;

-- ---------------------------------------------------------------
-- remove_booking_bundle_selection(p_company_id uuid, p_booking_id uuid, p_bundle_item_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.remove_booking_bundle_selection(p_company_id uuid, p_booking_id uuid, p_bundle_item_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.assert_booking_editable_for_bundle(p_booking_id);
  PERFORM public.assert_booking_addons_permission(p_company_id, p_booking_id);
  DELETE FROM public.booking_bundle_selections
   WHERE booking_id = p_booking_id
     AND bundle_item_id = p_bundle_item_id
     AND company_id = p_company_id;
  IF EXISTS (SELECT 1 FROM public.bookings WHERE id = p_booking_id AND status = 'completed') THEN
    PERFORM public.resync_booking_invoice(p_company_id, p_booking_id, auth.uid());
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- remove_booking_extra_item(p_company_id uuid, p_booking_id uuid, p_extra_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.remove_booking_extra_item(p_company_id uuid, p_booking_id uuid, p_extra_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.assert_booking_editable_for_bundle(p_booking_id);
  PERFORM public.assert_booking_addons_permission(p_company_id, p_booking_id);
  DELETE FROM public.booking_extra_items
   WHERE id = p_extra_id
     AND booking_id = p_booking_id
     AND company_id = p_company_id;
  IF EXISTS (SELECT 1 FROM public.bookings WHERE id = p_booking_id AND status = 'completed') THEN
    PERFORM public.resync_booking_invoice(p_company_id, p_booking_id, auth.uid());
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- remove_cancelled_invoice_sale_transactions(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.remove_cancelled_invoice_sale_transactions(p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ DECLARE v_deleted_count INTEGER := 0; BEGIN DELETE FROM inventory_transactions it WHERE it.company_id = p_company_id AND it.transaction_type = 'sale' AND (it.is_deleted IS NULL OR it.is_deleted = false) AND EXISTS ( SELECT 1 FROM invoices i WHERE i.id = it.reference_id AND i.status = 'cancelled' AND i.return_status = 'full' ); GET DIAGNOSTICS v_deleted_count = ROW_COUNT; PERFORM sync_all_stock_quantities(p_company_id); RETURN jsonb_build_object('success', true, 'deleted_count', v_deleted_count); END; $function$
;

-- ---------------------------------------------------------------
-- renew_seat_licenses(p_company_id uuid, p_seat_license_ids uuid[], p_billing_period text, p_billing_invoice_id uuid, p_performed_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.renew_seat_licenses(p_company_id uuid, p_seat_license_ids uuid[], p_billing_period text, p_billing_invoice_id uuid DEFAULT NULL::uuid, p_performed_by uuid DEFAULT NULL::uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_period         text;
  v_now            timestamptz := NOW();
  v_interval       interval;
  v_renewed_ids    uuid[] := ARRAY[]::uuid[];
  v_renewed_count  int := 0;
  v_existing_count int;
  v_match_count    int;
  v_target_count   int;
  rec              RECORD;
  v_new_expires    timestamptz;
BEGIN
  IF p_company_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'company_id_required');
  END IF;
  IF p_seat_license_ids IS NULL OR array_length(p_seat_license_ids, 1) IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'no_seats_specified');
  END IF;

  v_period := CASE WHEN p_billing_period = 'annual' THEN 'annual' ELSE 'monthly' END;
  v_interval := CASE
    WHEN v_period = 'annual' THEN INTERVAL '1 year'
    ELSE                          INTERVAL '1 month'
  END;
  v_target_count := array_length(p_seat_license_ids, 1);

  PERFORM pg_advisory_xact_lock(hashtext(p_company_id::text));

  IF p_billing_invoice_id IS NOT NULL THEN
    SELECT count(*) INTO v_existing_count
      FROM public.company_seat_licenses
     WHERE company_id = p_company_id
       AND id = ANY(p_seat_license_ids)
       AND last_renewal_invoice_id = p_billing_invoice_id;
    IF v_existing_count > 0 THEN
      RETURN json_build_object(
        'success', true, 'idempotent', true,
        'renewed_count', 0, 'matched_count', v_existing_count,
        'invoice_id', p_billing_invoice_id
      );
    END IF;
  END IF;

  SELECT count(*) INTO v_match_count
    FROM public.company_seat_licenses
   WHERE company_id = p_company_id AND id = ANY(p_seat_license_ids);
  IF v_match_count = 0 THEN
    RETURN json_build_object('success', false, 'error', 'no_matching_licenses');
  END IF;

  FOR rec IN
    SELECT id, seat_number, expires_at
      FROM public.company_seat_licenses
     WHERE company_id = p_company_id AND id = ANY(p_seat_license_ids)
     ORDER BY seat_number
  LOOP
    v_new_expires := CASE
      WHEN rec.expires_at <= v_now THEN v_now + v_interval
      ELSE                              rec.expires_at + v_interval
    END;

    UPDATE public.company_seat_licenses
       SET expires_at              = v_new_expires,
           billing_period          = v_period,
           last_renewed_at         = v_now,
           last_renewal_invoice_id = p_billing_invoice_id,
           updated_at              = v_now
     WHERE id = rec.id;

    v_renewed_ids := array_append(v_renewed_ids, rec.id);
    v_renewed_count := v_renewed_count + 1;
  END LOOP;

  BEGIN
    INSERT INTO public.audit_logs (action, company_id, target_table, new_data, user_id)
    VALUES (
      'seat_licenses_renewed', p_company_id, 'company_seat_licenses',
      json_build_object(
        'license_ids', v_renewed_ids,
        'count', v_renewed_count,
        'billing_period', v_period,
        'billing_invoice_id', p_billing_invoice_id,
        'renewed_at', v_now,
        'performed_by', p_performed_by,
        'requested_count', v_target_count,
        'unmatched_count', v_target_count - v_match_count
      )::jsonb,
      p_performed_by
    );
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN json_build_object(
    'success', true, 'idempotent', false,
    'renewed_count', v_renewed_count,
    'license_ids', to_json(v_renewed_ids),
    'billing_period', v_period,
    'requested', v_target_count,
    'unmatched', v_target_count - v_match_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- reopen_commission_advances_on_payroll_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reopen_commission_advances_on_payroll_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_temp'
AS $function$
BEGIN
    UPDATE commission_advance_payments
    SET deducted_in_payroll = FALSE,
        deducted_at = NULL,
        payroll_run_id = NULL
    WHERE payroll_run_id = OLD.id;
    RETURN OLD;
END;
