;

-- ---------------------------------------------------------------
-- reopen_fiscal_period(p_company_id uuid, p_year smallint, p_month smallint, p_reopened_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reopen_fiscal_period(p_company_id uuid, p_year smallint, p_month smallint, p_reopened_by uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_id UUID;
  v_before RECORD;
  v_after RECORD;
BEGIN
  SELECT id INTO v_id FROM public.fiscal_periods
  WHERE company_id = p_company_id AND year = p_year AND month = p_month;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Fiscal period %-% not found for company.', p_year, p_month;
  END IF;

  SELECT * INTO v_before FROM public.fiscal_periods WHERE id = v_id;

  UPDATE public.fiscal_periods
  SET status = 'open', reopened_at = NOW(), reopened_by = p_reopened_by, closed_at = NULL, closed_by = NULL, updated_at = NOW()
  WHERE id = v_id
  RETURNING * INTO v_after;

  PERFORM public.system_audit_log_insert(
    p_reopened_by, p_company_id, 'reopen_period', 'fiscal_period', v_id::TEXT,
    to_jsonb(v_before), to_jsonb(v_after), jsonb_build_object('year', p_year, 'month', p_month)
  );
  RETURN v_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- request_discount_approval(p_company_id uuid, p_document_type text, p_document_id uuid, p_discount_value numeric, p_discount_type text, p_document_no text, p_document_total numeric, p_party_name text, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.request_discount_approval(p_company_id uuid, p_document_type text, p_document_id uuid, p_discount_value numeric, p_discount_type text, p_document_no text DEFAULT NULL::text, p_document_total numeric DEFAULT NULL::numeric, p_party_name text DEFAULT NULL::text, p_reason text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_approval_id UUID;
BEGIN
  IF p_discount_value IS NULL OR p_discount_value <= 0 THEN
    RAISE EXCEPTION 'discount_value must be > 0' USING ERRCODE = 'P0001';
  END IF;
  IF p_discount_type NOT IN ('percent', 'amount') THEN
    RAISE EXCEPTION 'discount_type must be percent or amount' USING ERRCODE = 'P0001';
  END IF;
  IF p_document_type NOT IN ('sales_invoice', 'purchase_invoice', 'booking') THEN
    RAISE EXCEPTION 'Unknown document_type: %', p_document_type USING ERRCODE = 'P0001';
  END IF;

  INSERT INTO public.discount_approvals (
    company_id, document_type, document_id, document_no,
    discount_value, discount_type, document_total,
    party_name, reason, status, requested_by
  ) VALUES (
    p_company_id, p_document_type::public.discount_document_type, p_document_id, p_document_no,
    p_discount_value, p_discount_type, p_document_total,
    p_party_name, p_reason, 'pending', auth.uid()
  )
  RETURNING id INTO v_approval_id;

  RETURN v_approval_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- require_open_financial_period_db(p_company_id uuid, p_effective_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.require_open_financial_period_db(p_company_id uuid, p_effective_date date)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_period RECORD;
BEGIN
  SELECT
    id,
    period_name,
    status,
    is_locked
  INTO v_period
  FROM public.accounting_periods
  WHERE company_id = p_company_id
    AND p_effective_date BETWEEN period_start AND period_end
  ORDER BY period_start DESC
  LIMIT 1;

  -- v3.74.242 — auto-seed for back-dated entries within 24 months.
  IF NOT FOUND THEN
    IF p_effective_date >= (CURRENT_DATE - INTERVAL '24 months')::date
       AND p_effective_date <= (CURRENT_DATE + INTERVAL '12 months')::date THEN
      PERFORM public.seed_accounting_periods_for_company(
        p_company_id,
        date_trunc('month', p_effective_date)::date,
        1
      );
      SELECT
        id,
        period_name,
        status,
        is_locked
      INTO v_period
      FROM public.accounting_periods
      WHERE company_id = p_company_id
        AND p_effective_date BETWEEN period_start AND period_end
      ORDER BY period_start DESC
      LIMIT 1;
    END IF;
  END IF;

  IF NOT FOUND THEN
    RAISE EXCEPTION
      'NO_ACTIVE_FINANCIAL_PERIOD: No accounting period covers date % for company %',
      p_effective_date, p_company_id
      USING ERRCODE = 'P0001';
  END IF;

  IF COALESCE(v_period.is_locked, FALSE) OR COALESCE(v_period.status, 'open') IN ('closed', 'locked', 'audit_lock') THEN
    RAISE EXCEPTION
      'FINANCIAL_PERIOD_LOCKED: Period [%] is [%] for date %',
      COALESCE(v_period.period_name, v_period.id::TEXT),
      COALESCE(v_period.status, CASE WHEN v_period.is_locked THEN 'locked' ELSE 'open' END),
      p_effective_date
      USING ERRCODE = 'P0001';
  END IF;

  RETURN v_period.id;
END;
$function$
;

-- ---------------------------------------------------------------
-- require_revenue_je_before_paid()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.require_revenue_je_before_paid()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  IF NEW.status = 'paid' AND OLD.status NOT IN ('paid','cancelled','fully_returned') THEN
    IF current_setting('app.skip_je_check', true) = 'true' THEN RETURN NEW; END IF;
    IF NOT EXISTS (
      SELECT 1 FROM journal_entries je
      WHERE je.reference_type='invoice' AND je.reference_id=NEW.id
        AND je.status='posted' AND (je.is_deleted IS NULL OR je.is_deleted=false)
    ) THEN
      BEGIN INSERT INTO financial_operation_log(company_id,operation,status,error_code,error_msg,payload)
        VALUES(NEW.company_id,'invoice_paid_no_je','blocked','INVOICE_REQUIRES_REVENUE_JE',
          'Blocked: invoice '||NEW.invoice_number||' → paid without revenue JE',
          jsonb_build_object('invoice_id',NEW.id,'invoice_number',NEW.invoice_number,
            'from_status',OLD.status,'caller',current_user));
      EXCEPTION WHEN OTHERS THEN NULL; END;
      RAISE EXCEPTION 'INVOICE_REQUIRES_REVENUE_JE: Cannot set invoice % to paid — no active revenue JE.',
        NEW.invoice_number
        USING HINT = 'Post the invoice first to create the revenue journal entry.';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- reserve_seat(p_company_id uuid, p_invite_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reserve_seat(p_company_id uuid, p_invite_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_status JSON;
  v_available INTEGER;
  v_seat_number INTEGER;
BEGIN
  -- Lock the company_seats row to prevent race condition
  PERFORM pg_advisory_xact_lock(hashtext(p_company_id::TEXT));

  -- Check current availability
  SELECT get_seat_status(p_company_id) INTO v_status;
  v_available := (v_status->>'available_seats')::INTEGER;

  IF v_available <= 0 THEN
    RETURN json_build_object('success', FALSE, 'error', 'no_seats_available');
  END IF;

  -- Assign the next available seat_number for this company
  v_seat_number := assign_next_seat_number(p_company_id);

  -- Mark the invitation as having a reserved seat + store its seat_number
  UPDATE company_invitations
  SET seat_reserved = TRUE,
      status = 'pending',
      seat_number = v_seat_number
  WHERE id = p_invite_id AND company_id = p_company_id;

  -- Log the reservation
  INSERT INTO seat_transactions(company_id, transaction_type, seats_delta, metadata)
  VALUES (
    p_company_id,
    'reserve',
    0,
    json_build_object('invite_id', p_invite_id, 'seat_number', v_seat_number)
  );

  RETURN json_build_object('success', TRUE, 'seat_number', v_seat_number);
END;
$function$
;

-- ---------------------------------------------------------------
-- restore_company_backup(p_queue_id uuid, p_dry_run boolean)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.restore_company_backup(p_queue_id uuid, p_dry_run boolean DEFAULT true)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_queue_record restore_queue%ROWTYPE;
  v_backup_data JSONB;
  v_metadata JSONB;
  v_data JSONB;
  v_table_name TEXT;
  v_rows JSONB;
  v_company_id UUID;
  v_user_id UUID;
  v_ip_address TEXT;
  v_report JSONB := '{}'::JSONB;
  v_start_time TIMESTAMPTZ;
  v_end_time TIMESTAMPTZ;
  v_duration_ms INT;
  v_error_msg TEXT;
  v_total_records INT := 0;
  v_has_company_id BOOLEAN;
  v_audit_log_id UUID;
  
  -- Validation Variables
  v_before_counts JSONB := '{}'::JSONB;
  v_after_counts JSONB := '{}'::JSONB;
  v_balance_check RECORD;
  v_orphan_check INT;
  
  -- Cursor
  c_tables TEXT[] := ARRAY[
    'branches', 'warehouses', 'cost_centers',
    'chart_of_accounts',
    'account_balances',
    'customers', 'suppliers', 'employees', 'shareholders',
    'company_members',
    'products', 'services', 
    'sales_orders', 'purchase_orders',
    'invoices', 'bills',
    'sales_order_items', 'purchase_order_items', 'invoice_items', 'bill_items',
    'sales_returns', 'purchase_returns', 'sales_return_items', 'purchase_return_items',
    'customer_debit_notes', 'customer_debit_note_items', 'customer_credits', 'customer_credit_applications',
    'supplier_debit_notes', 'vendor_credits',
    'inventory_transactions',
    'inventory_write_offs',
    'fixed_assets', 'asset_transactions', 'depreciation_schedules',
    'journal_entries', 'journal_entry_lines',
    'payments',
    'bank_accounts', 'bank_transactions', 'bank_reconciliations',
    'payroll_runs', 'payslips', 'user_bonuses'
  ];
  
  -- Temp record for loops
  r_record RECORD;
  i INT;
  j INT;
  r_batch RECORD;
  v_row_json JSONB;
  v_use_batches BOOLEAN := FALSE;

BEGIN
  v_start_time := NOW();
  
  -- A. Fetch & Lock
  SELECT * INTO v_queue_record FROM restore_queue WHERE id = p_queue_id FOR UPDATE;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Queue record not found');
  END IF;

  v_company_id := v_queue_record.company_id;
  v_user_id := v_queue_record.user_id;
  v_ip_address := v_queue_record.ip_address;
  
  -- B. Data Source
  v_backup_data := v_queue_record.backup_data;
  
  IF v_backup_data IS NOT NULL THEN
     v_metadata := v_backup_data->'metadata';
     v_data := v_backup_data->'data';
     v_use_batches := FALSE;
  ELSE
     PERFORM 1 FROM restore_batches WHERE queue_id = p_queue_id;
     IF FOUND THEN
        v_use_batches := TRUE;
        IF v_backup_data IS NOT NULL THEN
            v_metadata := v_backup_data->'metadata';
        END IF;
     ELSE
        RETURN jsonb_build_object('success', false, 'error', 'No backup data or batches found');
     END IF;
  END IF;
  
  -- D. DRY RUN INIT
  IF p_dry_run THEN
    v_report := jsonb_build_object(
      'status', 'DRY_RUN',
      'valid', true,
      'metadata', v_metadata
    );
  END IF;

  -- =========================================================
  -- CORE LOGIC
  -- =========================================================
  BEGIN
    -- 1. Snapshot Before Counts & Global RLS Disable
    FOR i IN 1 .. array_length(c_tables, 1) LOOP
       v_table_name := c_tables[i];
       PERFORM 1 FROM information_schema.tables WHERE table_name = v_table_name;
       IF FOUND THEN
           EXECUTE format('ALTER TABLE %I DISABLE ROW LEVEL SECURITY', v_table_name);
           
           PERFORM 1 FROM information_schema.columns WHERE table_name = v_table_name AND column_name = 'company_id';
           IF FOUND THEN
               EXECUTE format('SELECT count(*) FROM %I WHERE company_id = $1', v_table_name) 
               INTO r_record 
               USING v_company_id;
               v_before_counts := jsonb_set(v_before_counts, ARRAY[v_table_name], to_jsonb(r_record));
           END IF;
       END IF;
    END LOOP;

    -- 2. Aggressive Cleanup (Reverse Order)
    FOR i IN REVERSE array_length(c_tables, 1)..1 LOOP
      v_table_name := c_tables[i];
      PERFORM 1 FROM information_schema.tables WHERE table_name = v_table_name;
      IF FOUND THEN
        PERFORM 1 FROM information_schema.columns WHERE table_name = v_table_name AND column_name = 'company_id';
        v_has_company_id := FOUND;
        
        EXECUTE format('ALTER TABLE %I DISABLE TRIGGER USER', v_table_name);
        
        IF v_table_name = 'account_balances' THEN
             EXECUTE 'DELETE FROM account_balances USING chart_of_accounts WHERE account_balances.account_id = chart_of_accounts.id AND chart_of_accounts.company_id = $1' USING v_company_id;
        END IF;
        
        IF v_table_name = 'journal_entry_lines' THEN
             EXECUTE 'DELETE FROM journal_entry_lines USING journal_entries WHERE journal_entry_lines.journal_entry_id = journal_entries.id AND journal_entries.company_id = $1' USING v_company_id;
             EXECUTE 'DELETE FROM journal_entry_lines USING chart_of_accounts WHERE journal_entry_lines.account_id = chart_of_accounts.id AND chart_of_accounts.company_id = $1' USING v_company_id;
        END IF;
        
        IF v_has_company_id THEN
            EXECUTE format('DELETE FROM %I WHERE company_id = $1', v_table_name) USING v_company_id;
        END IF;
        
        EXECUTE format('ALTER TABLE %I ENABLE TRIGGER USER', v_table_name);
      END IF;
    END LOOP;

    -- 3. Restore Data
    FOR i IN 1 .. array_length(c_tables, 1) LOOP
      v_table_name := c_tables[i];
      IF v_use_batches THEN
         FOR r_batch IN SELECT data FROM restore_batches WHERE queue_id = p_queue_id AND table_name = v_table_name ORDER BY batch_index LOOP
             v_rows := r_batch.data;
             IF v_rows IS NOT NULL AND jsonb_array_length(v_rows) > 0 THEN
                 FOR j IN 0 .. jsonb_array_length(v_rows) - 1 LOOP
                     v_row_json := v_rows->j;
                     v_row_json := jsonb_set(v_row_json, '{company_id}', to_jsonb(v_company_id));
                     BEGIN
                        EXECUTE format('INSERT INTO %I SELECT * FROM jsonb_populate_record(NULL::%I, $1)', v_table_name, v_table_name) USING v_row_json;
                     EXCEPTION WHEN OTHERS THEN
                        RAISE EXCEPTION 'Error inserting into %: %', v_table_name, SQLERRM;
                     END;
                 END LOOP;
                 v_total_records := v_total_records + jsonb_array_length(v_rows);
             END IF;
         END LOOP;
      ELSE
         IF v_data ? v_table_name THEN
             v_rows := v_data->v_table_name;
             IF v_rows IS NOT NULL AND jsonb_array_length(v_rows) > 0 THEN
                 FOR j IN 0 .. jsonb_array_length(v_rows) - 1 LOOP
                     v_row_json := v_rows->j;
                     v_row_json := jsonb_set(v_row_json, '{company_id}', to_jsonb(v_company_id));
                     EXECUTE format('INSERT INTO %I SELECT * FROM jsonb_populate_record(NULL::%I, $1)', v_table_name, v_table_name) USING v_row_json;
                 END LOOP;
                 v_total_records := v_total_records + jsonb_array_length(v_rows);
             END IF;
         END IF;
      END IF;
    END LOOP;

    -- 4. Post-Restore Integrity Checks
    PERFORM 1 FROM journal_entries WHERE company_id = v_company_id;
    IF FOUND THEN
        SELECT 
          COALESCE(SUM(debit_amount), 0) as total_debit, 
          COALESCE(SUM(credit_amount), 0) as total_credit 
        INTO v_balance_check
        FROM journal_entry_lines 
        WHERE journal_entry_id IN (SELECT id FROM journal_entries WHERE company_id = v_company_id);
        
        IF v_balance_check.total_debit != v_balance_check.total_credit THEN
          RAISE EXCEPTION 'Financial Integrity Failed: Debits (%) != Credits (%)', v_balance_check.total_debit, v_balance_check.total_credit;
        END IF;
    END IF;

    -- 5. Capture After Counts
    FOR i IN 1 .. array_length(c_tables, 1) LOOP
       v_table_name := c_tables[i];
       PERFORM 1 FROM information_schema.tables WHERE table_name = v_table_name;
       IF FOUND THEN
           PERFORM 1 FROM information_schema.columns WHERE table_name = v_table_name AND column_name = 'company_id';
           IF FOUND THEN
               EXECUTE format('SELECT count(*) FROM %I WHERE company_id = $1', v_table_name) 
               INTO r_record 
               USING v_company_id;
               v_after_counts := jsonb_set(v_after_counts, ARRAY[v_table_name], to_jsonb(r_record));
           END IF;
       END IF;
    END LOOP;
    
    -- 6. RE-ENABLE RLS GLOBAL
    FOR i IN 1 .. array_length(c_tables, 1) LOOP
       v_table_name := c_tables[i];
       PERFORM 1 FROM information_schema.tables WHERE table_name = v_table_name;
       IF FOUND THEN
           EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', v_table_name);
       END IF;
    END LOOP;

    -- 7. DECISION & AUDIT LOGGING
    v_end_time := NOW();
    v_duration_ms := EXTRACT(MILLISECOND FROM (v_end_time - v_start_time));
    
    IF p_dry_run THEN
       -- Log DRY RUN
       v_audit_log_id := create_audit_log(
         v_company_id,
         v_user_id,
         'SETTINGS',
         'restore_queue',
         p_queue_id,
         'Backup Restore Dry Run',
         NULL,
         jsonb_build_object(
           'mode', 'DRY_RUN',
           'total_records', v_total_records,
           'duration_ms', v_duration_ms,
           'counts_before', v_before_counts,
           'counts_expected', v_after_counts
         ),
         NULL,
         NULL,
         format('Dry run completed successfully. %s records would be restored.', v_total_records)
       );
       
       RAISE EXCEPTION 'DRY_RUN_COMPLETED'; 
    ELSE
       -- Log SUCCESSFUL RESTORE
       v_audit_log_id := create_audit_log(
         v_company_id,
         v_user_id,
         'SETTINGS',
         'restore_queue',
         p_queue_id,
         'Backup Restore',
         v_before_counts,
         v_after_counts,
         NULL,
         NULL,
         format('Backup restored successfully. %s records restored in %s ms.', v_total_records, v_duration_ms)
       );
       
       v_report := jsonb_build_object(
          'success', true,
          'mode', 'RESTORE',
          'counts_before', v_before_counts,
          'counts_after', v_after_counts,
          'financial_status', 'BALANCED',
          'message', 'Restore completed successfully.',
          'summary', jsonb_build_object('totalRecords', v_total_records),
          'audit_log_id', v_audit_log_id
       );
    END IF;

  EXCEPTION
    WHEN OTHERS THEN
       v_error_msg := SQLERRM;
       v_end_time := NOW();
       v_duration_ms := EXTRACT(MILLISECOND FROM (v_end_time - v_start_time));
       
       IF v_error_msg = 'DRY_RUN_COMPLETED' THEN
          v_report := jsonb_build_object(
             'success', true,
             'mode', 'DRY_RUN',
             'counts_before', v_before_counts,
             'counts_expected', v_after_counts,
             'financial_status', 'BALANCED',
             'message', 'Dry Run Successful. Data is valid.',
             'summary', jsonb_build_object('totalRecords', v_total_records),
             'audit_log_id', v_audit_log_id
          );
          v_error_msg := NULL;
       ELSE
          -- Log FAILED RESTORE
          BEGIN
            v_audit_log_id := create_audit_log(
              v_company_id,
              v_user_id,
              'SETTINGS',
              'restore_queue',
              p_queue_id,
              'Backup Restore Failed',
              NULL,
              jsonb_build_object(
                'error', v_error_msg,
                'duration_ms', v_duration_ms,
                'mode', CASE WHEN p_dry_run THEN 'DRY_RUN' ELSE 'RESTORE' END
              ),
              NULL,
              NULL,
              format('Restore failed: %s', v_error_msg)
            );
          EXCEPTION WHEN OTHERS THEN
            -- Ignore audit log errors during failure handling
          END;
          
          v_report := jsonb_build_object(
             'success', false,
             'mode', CASE WHEN p_dry_run THEN 'DRY_RUN' ELSE 'RESTORE' END,
             'error', v_error_msg,
             'audit_log_id', v_audit_log_id
          );
       END IF;
  END;

  RETURN v_report;
END;
$function$
;

-- ---------------------------------------------------------------
-- restructure_coa_zoho_books(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.restructure_coa_zoho_books(p_company_id uuid)
 RETURNS TABLE(step text, accounts_processed integer, journal_entries_created integer, total_amount numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_duplicate_code TEXT;
    v_source_account_id UUID;
    v_target_account_id UUID;
    v_merged_count INTEGER;
    v_journal_entry_id UUID;
    v_total_amount DECIMAL(15, 2);
    v_step_count INTEGER := 0;
    v_journal_count INTEGER := 0;
    
    -- حسابات Zoho Books القياسية
    v_ar_account_id UUID;
    v_ap_account_id UUID;
    v_inventory_account_id UUID;
    v_cogs_account_id UUID;
    v_revenue_account_id UUID;
    v_expense_account_id UUID;
BEGIN
    RAISE NOTICE '========================================';
    RAISE NOTICE '🚀 بدء إعادة هيكلة الشجرة المحاسبية';
    RAISE NOTICE 'الشركة: %', p_company_id;
    RAISE NOTICE '========================================';
    
    -- الخطوة 1: العثور على الحسابات القياسية أو إنشاؤها
    RAISE NOTICE '📋 الخطوة 1: التحقق من الحسابات القياسية';
    
    -- Accounts Receivable (1130 أو 1100)
    SELECT id INTO v_ar_account_id
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND is_active = true
      AND (
        account_code IN ('1130', '1100')
        OR sub_type = 'accounts_receivable'
      )
    ORDER BY 
        CASE WHEN account_code = '1130' THEN 1
             WHEN account_code = '1100' THEN 2
             ELSE 3 END,
        created_at ASC
    LIMIT 1;
    
    -- Accounts Payable (2110)
    SELECT id INTO v_ap_account_id
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND is_active = true
      AND (
        account_code = '2110'
        OR sub_type = 'accounts_payable'
      )
    ORDER BY 
        CASE WHEN account_code = '2110' THEN 1 ELSE 2 END,
        created_at ASC
    LIMIT 1;
    
    -- Inventory (1140 أو 1200)
    SELECT id INTO v_inventory_account_id
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND is_active = true
      AND (
        account_code IN ('1140', '1200')
        OR sub_type = 'inventory'
      )
    ORDER BY 
        CASE WHEN account_code = '1140' THEN 1
             WHEN account_code = '1200' THEN 2
             ELSE 3 END,
        created_at ASC
    LIMIT 1;
    
    -- COGS (5100)
    SELECT id INTO v_cogs_account_id
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND is_active = true
      AND (
        account_code = '5100'
        OR sub_type = 'cogs'
      )
    ORDER BY 
        CASE WHEN account_code = '5100' THEN 1 ELSE 2 END,
        created_at ASC
    LIMIT 1;
    
    -- Revenue (4100)
    SELECT id INTO v_revenue_account_id
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND is_active = true
      AND (
        account_code = '4100'
        OR sub_type = 'sales_revenue'
      )
    ORDER BY 
        CASE WHEN account_code = '4100' THEN 1 ELSE 2 END,
        created_at ASC
    LIMIT 1;
    
    -- الخطوة 2: دمج الحسابات المكررة
    RAISE NOTICE '📋 الخطوة 2: دمج الحسابات المكررة';
    
    FOR v_duplicate_code IN 
        SELECT account_code
        FROM chart_of_accounts
        WHERE company_id = p_company_id
          AND is_active = true
        GROUP BY account_code
        HAVING COUNT(*) > 1
    LOOP
        SELECT * INTO v_merged_count, v_journal_entry_id, v_total_amount
        FROM merge_duplicate_accounts_safe(p_company_id, v_duplicate_code);
        
        v_step_count := v_step_count + v_merged_count;
        IF v_journal_entry_id IS NOT NULL THEN
            v_journal_count := v_journal_count + 1;
        END IF;
        
        RAISE NOTICE '✅ تم دمج % حسابات للكود %', v_merged_count, v_duplicate_code;
    END LOOP;
    
    RETURN QUERY SELECT 'merge_duplicates'::TEXT, v_step_count, v_journal_count, v_total_amount;
    v_step_count := 0;
    v_journal_count := 0;
    v_total_amount := 0;
    
    -- الخطوة 3: إعادة تصنيف COGS
    RAISE NOTICE '📋 الخطوة 3: إعادة تصنيف COGS';
    
    IF v_cogs_account_id IS NOT NULL THEN
        FOR v_source_account_id IN
            SELECT id
            FROM chart_of_accounts
            WHERE company_id = p_company_id
              AND is_active = true
              AND account_type = 'expense'
              AND (
                account_name ILIKE '%تكلفة%'
                OR account_name ILIKE '%cost%'
                OR account_name ILIKE '%cogs%'
              )
              AND id != v_cogs_account_id
              AND sub_type != 'cogs'
        LOOP
            v_journal_entry_id := reclassify_account_safe(
                p_company_id,
                v_source_account_id,
                v_cogs_account_id,
                'إعادة تصنيف COGS وفق Zoho Books'
            );
            
            v_step_count := v_step_count + 1;
            IF v_journal_entry_id IS NOT NULL THEN
                v_journal_count := v_journal_count + 1;
            END IF;
        END LOOP;
    END IF;
    
    RETURN QUERY SELECT 'reclassify_cogs'::TEXT, v_step_count, v_journal_count, v_total_amount;
    v_step_count := 0;
    v_journal_count := 0;
    
    -- الخطوة 4: إعادة تصنيف Inventory
    RAISE NOTICE '📋 الخطوة 4: إعادة تصنيف Inventory';
    
    IF v_inventory_account_id IS NOT NULL THEN
        FOR v_source_account_id IN
            SELECT id
            FROM chart_of_accounts
            WHERE company_id = p_company_id
              AND is_active = true
              AND account_type = 'asset'
              AND (
                account_name ILIKE '%مخزون%'
                OR account_name ILIKE '%inventory%'
                OR account_name ILIKE '%stock%'
              )
              AND id != v_inventory_account_id
              AND sub_type != 'inventory'
        LOOP
            v_journal_entry_id := reclassify_account_safe(
                p_company_id,
                v_source_account_id,
                v_inventory_account_id,
                'إعادة تصنيف Inventory وفق Zoho Books'
            );
            
            v_step_count := v_step_count + 1;
            IF v_journal_entry_id IS NOT NULL THEN
                v_journal_count := v_journal_count + 1;
            END IF;
        END LOOP;
    END IF;
    
    RETURN QUERY SELECT 'reclassify_inventory'::TEXT, v_step_count, v_journal_count, v_total_amount;
    v_step_count := 0;
    v_journal_count := 0;
    
    -- الخطوة 5: إعادة تصنيف Expenses
    RAISE NOTICE '📋 الخطوة 5: إعادة تصنيف Expenses';
    
    -- البحث عن حساب مصروفات تشغيلية قياسي (5200)
    SELECT id INTO v_expense_account_id
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND is_active = true
      AND (
        account_code = '5200'
        OR sub_type = 'operating_expenses'
      )
    ORDER BY 
        CASE WHEN account_code = '5200' THEN 1 ELSE 2 END,
        created_at ASC
    LIMIT 1;
    
    IF v_expense_account_id IS NOT NULL THEN
        -- دمج المصروفات المكررة في حساب واحد (اختياري)
        -- يمكن تخصيص هذا حسب الحاجة
        RAISE NOTICE '✅ حساب المصروفات موجود: %', v_expense_account_id;
    END IF;
    
    RETURN QUERY SELECT 'reclassify_expenses'::TEXT, v_step_count, v_journal_count, v_total_amount;
    
    RAISE NOTICE '========================================';
    RAISE NOTICE '✅ اكتملت إعادة الهيكلة بنجاح';
    RAISE NOTICE '========================================';
END;
$function$
;

-- ---------------------------------------------------------------
-- resubmit_purchase_return(p_return_id uuid, p_user_id uuid, p_purchase_return jsonb, p_return_items jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.resubmit_purchase_return(p_return_id uuid, p_user_id uuid, p_purchase_return jsonb, p_return_items jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_pr       RECORD;
  v_item     JSONB;
BEGIN
  -- Load and lock the return
  SELECT * INTO v_pr
  FROM purchase_returns
  WHERE id = p_return_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Purchase return not found');
  END IF;

  -- Only the creator or admin can resubmit
  IF v_pr.created_by != p_user_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'Only the creator can resubmit this return');
  END IF;

  -- Only allow resubmission from rejected states
  IF v_pr.workflow_status NOT IN ('rejected', 'warehouse_rejected') THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', format(
        'Cannot resubmit: return is not in a rejected state. Current status: %s',
        v_pr.workflow_status
      )
    );
  END IF;

  -- Update the return record with new data, reset workflow
  UPDATE purchase_returns SET
    reason             = COALESCE(NULLIF(p_purchase_return->>'reason', ''), reason),
    notes              = COALESCE(NULLIF(p_purchase_return->>'notes', ''), notes),
    settlement_method  = COALESCE(NULLIF(p_purchase_return->>'settlement_method', ''), settlement_method),
    return_date        = COALESCE(NULLIF(p_purchase_return->>'return_date', '')::DATE, return_date),
    subtotal           = COALESCE(NULLIF(p_purchase_return->>'subtotal', '')::NUMERIC, subtotal),
    tax_amount         = COALESCE(NULLIF(p_purchase_return->>'tax_amount', '')::NUMERIC, tax_amount),
    total_amount       = COALESCE(NULLIF(p_purchase_return->>'total_amount', '')::NUMERIC, total_amount),
    original_subtotal  = COALESCE(NULLIF(p_purchase_return->>'original_subtotal', '')::NUMERIC, original_subtotal),
    original_tax_amount= COALESCE(NULLIF(p_purchase_return->>'original_tax_amount', '')::NUMERIC, original_tax_amount),
    original_total_amount = COALESCE(NULLIF(p_purchase_return->>'original_total_amount', '')::NUMERIC, original_total_amount),
    -- Reset workflow
    status             = 'pending_approval',
    workflow_status    = 'pending_admin_approval',
    is_locked          = false,
    rejected_by        = NULL,
    rejected_at        = NULL,
    rejection_reason   = NULL,
    warehouse_rejected_by     = NULL,
    warehouse_rejected_at     = NULL,
    warehouse_rejection_reason = NULL,
    updated_at         = NOW()
  WHERE id = p_return_id;

  -- Replace return items
  DELETE FROM purchase_return_items WHERE purchase_return_id = p_return_id;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_return_items) LOOP
    INSERT INTO purchase_return_items (
      purchase_return_id, bill_item_id, product_id,
      description, quantity, unit_price, tax_rate, discount_percent, line_total
    ) VALUES (
      p_return_id,
      NULLIF(v_item->>'bill_item_id', '')::UUID,
      NULLIF(v_item->>'product_id', '')::UUID,
      v_item->>'description',
      COALESCE((v_item->>'quantity')::NUMERIC, 0),
      COALESCE((v_item->>'unit_price')::NUMERIC, 0),
      COALESCE((v_item->>'tax_rate')::NUMERIC, 0),
      COALESCE((v_item->>'discount_percent')::NUMERIC, 0),
      COALESCE((v_item->>'line_total')::NUMERIC, 0)
    );
  END LOOP;

  -- Audit log
  INSERT INTO audit_logs (
    company_id, user_id, action, target_table, record_id, old_data, new_data, created_at
  ) VALUES (
    v_pr.company_id, p_user_id,
    'SUBMIT',
    'purchase_returns',
    p_return_id,
    jsonb_build_object('workflow_status', v_pr.workflow_status, 'status', v_pr.status),
    jsonb_build_object('workflow_status', 'pending_admin_approval', 'status', 'pending_approval'),
    NOW()
  );

  RETURN jsonb_build_object(
    'success',         true,
    'purchase_return_id', p_return_id,
    'workflow_status', 'pending_admin_approval',
    'company_id',      v_pr.company_id,
    'bill_id',         v_pr.bill_id
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- resync_booking_invoice(p_company_id uuid, p_booking_id uuid, p_actor uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.resync_booking_invoice(p_company_id uuid, p_booking_id uuid, p_actor uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_booking public.bookings; v_service public.services; v_invoice public.invoices;
  v_service_subtotal NUMERIC; v_addon_total NUMERIC := 0; v_new_total NUMERIC;
  v_goods int := 0; v_lines int := 0; v_deducted int := 0;
  v_actor uuid := COALESCE(auth.uid(), p_actor);
  v_role text;
  con RECORD;
BEGIN
  PERFORM set_config('app.skip_discount_approval', 'booking_resync', true);

  SELECT * INTO v_booking FROM public.bookings
  WHERE id = p_booking_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'BOOKING_NOT_FOUND'; END IF;
  IF v_booking.status <> 'completed' OR v_booking.invoice_id IS NULL THEN
    RETURN jsonb_build_object('success', true, 'skipped', 'booking_not_completed');
  END IF;

  SELECT * INTO v_invoice FROM public.invoices WHERE id = v_booking.invoice_id FOR UPDATE;
  IF v_invoice.status <> 'draft' THEN
    RAISE EXCEPTION 'INVOICE_NOT_DRAFT: الفاتورة معتمدة — أى تعديل يتم عبر مرتجع المبيعات';
  END IF;

  SELECT * INTO v_service FROM public.services WHERE id = v_booking.service_id;

  v_service_subtotal := COALESCE(v_booking.unit_price, 0) * COALESCE(v_booking.quantity, 1);
  SELECT COALESCE(SUM((unit_price * quantity) * (1 - COALESCE(discount_percent,0)/100)), 0)
    INTO v_addon_total
    FROM public.get_booking_line_additions(p_booking_id)
   WHERE unit_price > 0;
  v_new_total := v_service_subtotal + v_addon_total
               - COALESCE(v_booking.discount_amount, 0)
               + COALESCE(v_booking.tax_amount, 0);

  DELETE FROM public.invoice_items WHERE invoice_id = v_invoice.id;
  DELETE FROM public.inventory_transactions
   WHERE company_id = p_company_id
     AND reference_type = 'booking_invoice'
     AND reference_id = v_invoice.id;

  IF v_service.product_catalog_id IS NOT NULL THEN
    INSERT INTO public.invoice_items (
      invoice_id, product_id, quantity, unit_price, tax_rate,
      discount_percent, line_total, returned_quantity, item_type
    ) VALUES (
      v_invoice.id, v_service.product_catalog_id, v_booking.quantity, v_booking.unit_price,
      COALESCE(v_service.tax_rate, 0), 0, v_service_subtotal, 0, 'service'
    );
    v_lines := v_lines + 1;
  END IF;

  FOR con IN SELECT * FROM public.get_booking_line_additions(p_booking_id) LOOP
    INSERT INTO public.invoice_items (
      invoice_id, product_id, quantity, unit_price, tax_rate,
      discount_percent, line_total, returned_quantity, item_type
    ) VALUES (
      v_invoice.id, con.product_id, con.quantity, con.unit_price,
      con.tax_rate, con.discount_percent,
      con.unit_price * con.quantity * (1 - COALESCE(con.discount_percent,0)/100),
      0,
      CASE WHEN con.kind = 'extra' THEN 'product' ELSE 'service' END
    );
    v_lines := v_lines + 1;
    IF con.kind = 'extra' THEN v_goods := v_goods + 1; END IF;

    IF con.kind <> 'extra' AND con.auto_deduct_inventory AND con.quantity > 0 THEN
      INSERT INTO public.inventory_transactions (
        company_id, branch_id, warehouse_id, cost_center_id,
        product_id, transaction_type, quantity_change,
        reference_type, reference_id, notes
      ) VALUES (
        p_company_id, v_booking.branch_id, v_invoice.warehouse_id, v_invoice.cost_center_id,
        con.product_id, 'service_consumption', -(CEIL(con.quantity)::int),
        'booking_invoice', v_invoice.id,
        con.kind || ' — ' || COALESCE(con.description,'') || ' — حجز ' || v_booking.booking_no || ' (مزامنة تعديل)'
      );
      v_deducted := v_deducted + 1;
    END IF;
  END LOOP;

  UPDATE public.invoices
     SET subtotal = v_service_subtotal + v_addon_total,
         total_amount = v_new_total,
         warehouse_status = CASE WHEN v_goods > 0 THEN 'pending' ELSE 'approved' END,
         updated_at = NOW()
   WHERE id = v_invoice.id;

  UPDATE public.bookings
     SET total_amount = v_new_total,
         payment_status = CASE WHEN COALESCE(paid_amount,0) >= v_new_total THEN 'paid'
                               WHEN COALESCE(paid_amount,0) > 0 THEN 'partially_paid'
                               ELSE 'unpaid' END,
         updated_by = v_actor, updated_at = NOW()
   WHERE id = p_booking_id;

  -- v3.74.602b: accountant deep-links to the INVOICE (their workspace)
  BEGIN
    PERFORM public.create_notification(
      p_company_id, 'invoice', v_invoice.id,
      'تعديل فاتورة حجز ' || v_booking.booking_no,
      'عدّل الموظف المنفذ إضافات أمر الحجز ' || v_booking.booking_no ||
      ' — تمت مزامنة الفاتورة ' || v_invoice.invoice_number ||
      ' (الإجمالى الجديد: ' || TO_CHAR(v_new_total, 'FM999999990.00') || '). برجاء مراجعتها واستكمال الدورة.',
      v_actor, v_booking.branch_id, NULL, NULL,
      'accountant', NULL, 'high',
      'booking_resync_acct:' || v_invoice.id || ':' || TO_CHAR(NOW(), 'YYYYMMDDHH24MI'),
      'warning', 'sales', 'action');
  EXCEPTION WHEN OTHERS THEN NULL; END;

  FOR v_role IN SELECT unnest(ARRAY['owner','general_manager','manager']) LOOP
    BEGIN
      PERFORM public.create_notification(
        p_company_id, 'booking', p_booking_id,
        'للعلم: تعديل بعد التنفيذ على حجز ' || v_booking.booking_no,
        'تم تعديل إضافات أمر الحجز ' || v_booking.booking_no || ' بعد التنفيذ وقبل اعتماد الفاتورة ' ||
        v_invoice.invoice_number || '. الإجمالى الجديد: ' || TO_CHAR(v_new_total, 'FM999999990.00') || '.',
        v_actor, v_booking.branch_id, NULL, NULL,
        v_role, NULL, 'normal',
        'booking_resync_' || v_role || ':' || v_invoice.id || ':' || TO_CHAR(NOW(), 'YYYYMMDDHH24MI'),
        'info', 'sales', 'info');
    EXCEPTION WHEN OTHERS THEN NULL; END;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true, 'invoice_id', v_invoice.id, 'new_total', v_new_total,
    'lines', v_lines, 'goods_lines', v_goods, 'consumption_rows', v_deducted
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- revalue_asset(p_asset_id uuid, p_new_value numeric, p_date date, p_reason text, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.revalue_asset(p_asset_id uuid, p_new_value numeric, p_date date, p_reason text, p_user_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_asset RECORD;
  v_current_book_value DECIMAL;
  v_diff DECIMAL;
  v_transaction_id UUID;
BEGIN
  SELECT * INTO v_asset FROM fixed_assets WHERE id = p_asset_id;
  
  -- Get current BV from DB or calc? Trust DB for now.
  v_current_book_value := v_asset.book_value;
  v_diff := p_new_value - v_current_book_value;
  
  IF v_diff = 0 THEN RETURN NULL; END IF;
  
  -- 1. Create Asset Transaction
  INSERT INTO asset_transactions (
    company_id, asset_id, transaction_type, transaction_date, amount, details, created_by
  ) VALUES (
    v_asset.company_id, p_asset_id, 'revaluation', p_date, v_diff, 
    jsonb_build_object('reason', p_reason, 'old_value', v_current_book_value, 'new_value', p_new_value), p_user_id
  ) RETURNING id INTO v_transaction_id;
  
  -- 2. Update Asset
  UPDATE fixed_assets 
  SET book_value = p_new_value,
      -- Usually we don't change purchase_cost in Revaluation model, we adjust a specific "Revaluation Reserve"
      -- But for simplicity in this system, we might just track book_value changes.
      -- Let's NOT change purchase_cost to keep historical cost, but change book_value.
      updated_at = NOW()
  WHERE id = p_asset_id;
  
  -- 3. Regenerate Schedules (Depreciation will now stand on new Book Value)
  PERFORM regenerate_asset_schedules(p_asset_id);
  
  RETURN v_transaction_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- reverse_bonuses_on_booking_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reverse_bonuses_on_booking_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE public.user_bonuses
     SET status = 'reversed',
         reversed_at = NOW(),
         reversal_reason = COALESCE(reversal_reason, '') ||
           CASE WHEN COALESCE(reversal_reason,'') = '' THEN '' ELSE ' | ' END ||
           'عكس آلى: حُذف الحجز المصدر ' || COALESCE(OLD.booking_no, OLD.id::text),
         updated_at = NOW()
   WHERE booking_id = OLD.id
     AND invoice_id IS NULL
     AND reversed_at IS NULL
     AND paid_at IS NULL
     AND payroll_run_id IS NULL;
  RETURN OLD;
END;
$function$
;

