-- ---------------------------------------------------------------
-- reverse_cogs_journal_for_return(p_invoice_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reverse_cogs_journal_for_return(p_invoice_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$ DECLARE v_original_cogs_entry RECORD; v_invoice RECORD; v_new_journal_entry_id UUID; BEGIN SELECT * INTO v_invoice FROM invoices WHERE id = p_invoice_id; IF NOT FOUND THEN RAISE EXCEPTION 'Invoice not found: %', p_invoice_id; END IF; SELECT je.* INTO v_original_cogs_entry FROM journal_entries je WHERE je.reference_type = 'invoice_cogs' AND je.reference_id = p_invoice_id LIMIT 1; IF NOT FOUND THEN RETURN NULL; END IF; IF EXISTS (SELECT 1 FROM journal_entries WHERE reference_type = 'sales_return_cogs' AND reference_id = p_invoice_id) THEN RETURN NULL; END IF; INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description, status, branch_id, cost_center_id, warehouse_id) VALUES (v_invoice.company_id, 'sales_return_cogs', p_invoice_id, CURRENT_DATE, 'عكس تكلفة البضاعة المباعة - مرتجع فاتورة ' || v_invoice.invoice_number, 'posted', v_invoice.branch_id, v_invoice.cost_center_id, v_invoice.warehouse_id) RETURNING id INTO v_new_journal_entry_id; INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description, branch_id, cost_center_id) SELECT v_new_journal_entry_id, account_id, credit_amount, debit_amount, 'عكس: ' || description, branch_id, cost_center_id FROM journal_entry_lines WHERE journal_entry_id = v_original_cogs_entry.id; UPDATE inventory_transactions SET journal_entry_id = v_new_journal_entry_id WHERE transaction_type = 'sale_return' AND reference_id = p_invoice_id AND journal_entry_id IS NULL; RETURN v_new_journal_entry_id; END; $function$
;

-- ---------------------------------------------------------------
-- reverse_fifo_consumption(p_reference_type text, p_reference_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reverse_fifo_consumption(p_reference_type text, p_reference_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_consumption RECORD;
BEGIN
  -- الحصول على جميع الاستهلاكات المرتبطة بهذا المرجع
  FOR v_consumption IN
    SELECT lot_id, quantity_consumed
    FROM fifo_lot_consumptions
    WHERE reference_type = p_reference_type
      AND reference_id = p_reference_id
    ORDER BY created_at DESC -- عكس الترتيب (LIFO للعكس)
  LOOP
    -- إرجاع الكمية للدفعة
    UPDATE fifo_cost_lots
    SET remaining_quantity = remaining_quantity + v_consumption.quantity_consumed,
        updated_at = CURRENT_TIMESTAMP
    WHERE id = v_consumption.lot_id;
  END LOOP;

  -- حذف سجلات الاستهلاك
  DELETE FROM fifo_lot_consumptions
  WHERE reference_type = p_reference_type
    AND reference_id = p_reference_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- reverse_journal_entry(p_journal_id uuid, p_reason text, p_user_id uuid, p_entry_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.reverse_journal_entry(p_journal_id uuid, p_reason text, p_user_id uuid, p_entry_date date DEFAULT NULL::date)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_orig            record;
  v_new_je_id       uuid;
  v_effective_date  date := COALESCE(p_entry_date, CURRENT_DATE);
  v_role            text;
BEGIN
  IF p_reason IS NULL OR LENGTH(TRIM(p_reason)) < 5 THEN
    RAISE EXCEPTION 'REASON_REQUIRED: السَّبَب مَطلوب (٥ أَحرُف)';
  END IF;

  SELECT * INTO v_orig FROM journal_entries WHERE id = p_journal_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'JOURNAL_NOT_FOUND'; END IF;
  IF v_orig.status <> 'posted' THEN
    RAISE EXCEPTION 'NOT_POSTED: يُمكِن عَكس القُيود المَنشورة فَقَط';
  END IF;
  IF COALESCE(v_orig.is_deleted, false) THEN
    RAISE EXCEPTION 'JOURNAL_DELETED';
  END IF;
  IF v_orig.deleted_at IS NOT NULL THEN
    RAISE EXCEPTION 'JOURNAL_DELETED';
  END IF;

  -- SoD check
  SELECT role INTO v_role FROM company_members
   WHERE company_id = v_orig.company_id AND user_id = p_user_id LIMIT 1;
  IF NOT (COALESCE(v_role,'') IN ('owner','general_manager')) THEN
    IF v_orig.created_by IS NOT NULL AND v_orig.created_by = p_user_id THEN
      RAISE EXCEPTION 'SOD_VIOLATION: مُنشِئ القَيد لا يَستَطيع عَكسَه — يَحتاج مالِك أَو مُدير عام';
    END IF;
  END IF;

  -- Financial period lock on the reversal date
  PERFORM public.require_open_financial_period_db(v_orig.company_id, v_effective_date);

  -- Check for existing reversal
  IF EXISTS (
    SELECT 1 FROM journal_entries
     WHERE company_id = v_orig.company_id
       AND (metadata->>'reversal_of') = p_journal_id::text
       AND status = 'posted'
  ) THEN
    RAISE EXCEPTION 'ALREADY_REVERSED: يوجَد قَيد عَكسِى مَنشور لِنَفس القَيد';
  END IF;

  INSERT INTO journal_entries (
    company_id, branch_id, cost_center_id,
    reference_type, reference_id,
    entry_date, description, status,
    created_by,
    metadata
  ) VALUES (
    v_orig.company_id, v_orig.branch_id, v_orig.cost_center_id,
    'journal_reversal', v_orig.id,
    v_effective_date,
    'عَكس قَيد — ' || COALESCE(v_orig.description, v_orig.id::text) || ' — السَّبَب: ' || p_reason,
    'draft',
    jsonb_build_object(
      'reversal_of', v_orig.id,
      'reversal_reason', p_reason,
      'reversed_by', p_user_id,
      'reversed_at', NOW()
    )
  ) RETURNING id INTO v_new_je_id;

  -- Copy lines with swapped debit/credit + swapped originals
  INSERT INTO journal_entry_lines (
    journal_entry_id, account_id,
    debit_amount, credit_amount,
    description, branch_id, cost_center_id,
    original_debit, original_credit, original_currency,
    exchange_rate_used
  )
  SELECT v_new_je_id, account_id,
         credit_amount, debit_amount,
         'عَكس — ' || COALESCE(description, ''), branch_id, cost_center_id,
         original_credit, original_debit, original_currency,
         exchange_rate_used
    FROM journal_entry_lines
   WHERE journal_entry_id = v_orig.id;

  -- Post it (this triggers the balance check + governance triggers)
  UPDATE journal_entries SET status = 'posted' WHERE id = v_new_je_id;

  -- Stamp original with a link
  UPDATE journal_entries
     SET metadata = COALESCE(metadata,'{}'::jsonb) || jsonb_build_object(
           'reversed_by_entry', v_new_je_id,
           'reversed_at',       NOW(),
           'reversal_reason',   p_reason
         )
   WHERE id = v_orig.id;

  RETURN jsonb_build_object(
    'success', true,
    'original_journal_id', v_orig.id,
    'reversal_journal_id', v_new_je_id,
    'entry_date',          v_effective_date
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- revert_audit_log(p_log_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.revert_audit_log(p_log_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_log RECORD;
  v_result JSONB;
  v_company_role TEXT;
  v_sql TEXT;
  v_column_info RECORD;
  v_cast_expr TEXT;
BEGIN
  -- جلب سجل المراجعة
  SELECT * INTO v_log FROM audit_logs WHERE id = p_log_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'السجل غير موجود');
  END IF;

  -- التحقق من صلاحية المالك
  SELECT role INTO v_company_role
  FROM company_members
  WHERE company_id = v_log.company_id AND user_id = p_user_id;

  IF v_company_role != 'owner' THEN
    RETURN jsonb_build_object('success', false, 'error', 'غير مصرح - المالك فقط يمكنه التراجع');
  END IF;

  -- تنفيذ التراجع حسب نوع العملية
  CASE v_log.action
    WHEN 'INSERT' THEN
      -- إذا كانت العملية إضافة، نحذف السجل
      EXECUTE format('DELETE FROM %I WHERE id = $1', v_log.target_table)
      USING v_log.record_id;
      v_result := jsonb_build_object(
        'success', true,
        'message', 'تم حذف السجل المضاف',
        'action', 'DELETE',
        'record_id', v_log.record_id
      );

    WHEN 'UPDATE' THEN
      -- إذا كانت العملية تعديل، نرجع البيانات القديمة
      IF v_log.old_data IS NOT NULL THEN
        -- بناء استعلام التحديث مع تحديد نوع البيانات الصحيح من الجدول
        SELECT string_agg(
          format('%I = ($1->>%L)::%s', 
            key, 
            key,
            COALESCE(
              (SELECT data_type 
               FROM information_schema.columns 
               WHERE table_name = v_log.target_table 
               AND column_name = key),
              CASE
                WHEN jsonb_typeof(v_log.old_data->key) = 'number' THEN 'numeric'
                WHEN jsonb_typeof(v_log.old_data->key) = 'boolean' THEN 'boolean'
                WHEN v_log.old_data->>key ~ '^\d{4}-\d{2}-\d{2}' THEN 'timestamp with time zone'
                ELSE 'text'
              END
            )
          ), ', ')
        INTO v_sql
        FROM jsonb_object_keys(v_log.old_data) AS key
        WHERE key NOT IN ('id', 'created_at', 'company_id', 'updated_at');

        IF v_sql IS NOT NULL THEN
          EXECUTE format('UPDATE %I SET %s WHERE id = $2', v_log.target_table, v_sql)
          USING v_log.old_data, v_log.record_id;
        END IF;

        v_result := jsonb_build_object(
          'success', true,
          'message', 'تم استرجاع البيانات السابقة',
          'action', 'REVERT_UPDATE',
          'record_id', v_log.record_id
        );
      ELSE
        v_result := jsonb_build_object('success', false, 'error', 'لا توجد بيانات سابقة للاسترجاع');
      END IF;

    WHEN 'DELETE' THEN
      -- إذا كانت العملية حذف، نعيد إدراج السجل
      IF v_log.old_data IS NOT NULL THEN
        EXECUTE format(
          'INSERT INTO %I SELECT * FROM jsonb_populate_record(null::%I, $1)',
          v_log.target_table, v_log.target_table
        ) USING v_log.old_data;

        v_result := jsonb_build_object(
          'success', true,
          'message', 'تم استعادة السجل المحذوف',
          'action', 'RESTORE',
          'record_id', v_log.record_id
        );
      ELSE
        v_result := jsonb_build_object('success', false, 'error', 'لا توجد بيانات للاستعادة');
      END IF;

    ELSE
      v_result := jsonb_build_object('success', false, 'error', 'نوع العملية غير معروف');
  END CASE;

  -- تسجيل عملية التراجع
  IF (v_result->>'success')::boolean THEN
    INSERT INTO audit_logs (
      company_id, user_id, action, target_table, record_id,
      record_identifier, old_data, new_data
    ) VALUES (
      v_log.company_id, p_user_id, 'REVERT', v_log.target_table, v_log.record_id,
      'تراجع عن: ' || COALESCE(v_log.record_identifier, ''),
      v_log.new_data, v_log.old_data
    );
  END IF;

  RETURN v_result;
EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- revert_batch_operations(p_log_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.revert_batch_operations(p_log_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_log RECORD;
  v_related RECORD;
  v_company_role TEXT;
  v_reverted_count INT := 0;
  v_errors TEXT[] := ARRAY[]::TEXT[];
  v_result JSONB;
  v_batch_id UUID;
BEGIN
  -- جلب السجل الأصلي
  SELECT * INTO v_log FROM audit_logs WHERE id = p_log_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'السجل غير موجود');
  END IF;

  -- التحقق من صلاحية المالك
  SELECT role INTO v_company_role
  FROM company_members
  WHERE company_id = v_log.company_id AND user_id = p_user_id;

  IF v_company_role != 'owner' THEN
    RETURN jsonb_build_object('success', false, 'error', 'غير مصرح - المالك فقط');
  END IF;

  -- إنشاء batch_id جديد لعملية التراجع
  v_batch_id := gen_random_uuid();

  -- التراجع عن جميع السجلات المرتبطة بترتيب عكسي
  FOR v_related IN
    SELECT * FROM get_related_audit_logs(p_log_id) ORDER BY created_at DESC
  LOOP
    BEGIN
      -- تنفيذ التراجع حسب نوع العملية
      CASE v_related.action
        WHEN 'INSERT' THEN
          EXECUTE format('DELETE FROM %I WHERE id = $1', v_related.target_table)
          USING v_related.record_id;
          v_reverted_count := v_reverted_count + 1;

        WHEN 'UPDATE' THEN
          -- استعادة البيانات القديمة
          DECLARE
            v_old_data JSONB;
            v_sql TEXT;
          BEGIN
            SELECT old_data INTO v_old_data FROM audit_logs WHERE id = v_related.id;
            IF v_old_data IS NOT NULL THEN
              SELECT string_agg(
                format('%I = ($1->>%L)::%s', key, key,
                  COALESCE(
                    (SELECT data_type FROM information_schema.columns
                     WHERE table_name = v_related.target_table AND column_name = key),
                    'text'
                  )
                ), ', ')
              INTO v_sql
              FROM jsonb_object_keys(v_old_data) AS key
              WHERE key NOT IN ('id', 'created_at', 'company_id', 'updated_at');

              IF v_sql IS NOT NULL THEN
                EXECUTE format('UPDATE %I SET %s WHERE id = $2', v_related.target_table, v_sql)
                USING v_old_data, v_related.record_id;
                v_reverted_count := v_reverted_count + 1;
              END IF;
            END IF;
          END;

        WHEN 'DELETE' THEN
          -- استعادة السجل المحذوف
          DECLARE
            v_old_data JSONB;
          BEGIN
            SELECT old_data INTO v_old_data FROM audit_logs WHERE id = v_related.id;
            IF v_old_data IS NOT NULL THEN
              EXECUTE format(
                'INSERT INTO %I SELECT * FROM jsonb_populate_record(null::%I, $1)',
                v_related.target_table, v_related.target_table
              ) USING v_old_data;
              v_reverted_count := v_reverted_count + 1;
            END IF;
          END;

        ELSE
          NULL; -- تخطي REVERT وغيرها
      END CASE;

    EXCEPTION WHEN OTHERS THEN
      v_errors := array_append(v_errors, v_related.target_table || ': ' || SQLERRM);
    END;
  END LOOP;

  -- تسجيل عملية التراجع الشامل
  INSERT INTO audit_logs (
    company_id, user_id, action, target_table, record_id,
    record_identifier, batch_id, old_data
  ) VALUES (
    v_log.company_id, p_user_id, 'REVERT', 'batch_revert', p_log_id,
    'تراجع شامل: ' || v_reverted_count || ' عملية',
    v_batch_id,
    jsonb_build_object('original_log_id', p_log_id, 'reverted_count', v_reverted_count)
  );

  -- إرجاع النتيجة
  IF array_length(v_errors, 1) > 0 THEN
    RETURN jsonb_build_object(
      'success', true,
      'partial', true,
      'message', 'تم التراجع عن ' || v_reverted_count || ' عملية مع بعض الأخطاء',
      'reverted_count', v_reverted_count,
      'errors', to_jsonb(v_errors)
    );
  ELSE
    RETURN jsonb_build_object(
      'success', true,
      'message', 'تم التراجع الشامل عن ' || v_reverted_count || ' عملية بنجاح',
      'reverted_count', v_reverted_count
    );
  END IF;

EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- route_system_events_to_notifications()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.route_system_events_to_notifications()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_role VARCHAR;
    v_title VARCHAR;
    v_message VARCHAR;
    v_user_locale VARCHAR := 'ar';
    v_notification_count INT := 0;
    v_admin_roles VARCHAR[] := ARRAY['admin', 'owner', 'general_manager'];
BEGIN
    IF NEW.reference_type = 'purchase_return' THEN

        -- Event: Pending Admin Approval
        IF NEW.event_type = 'purchase_return.pending_approval' THEN
            v_title := 'طلب اعتماد مرتجع - Pending Return Approval';
            v_message := 'مرتجع جديد ' || (NEW.payload->>'return_number') || ' بحاجة لاعتماد الإدارة.';

            FOREACH v_role IN ARRAY v_admin_roles LOOP
                INSERT INTO notifications (
                    company_id, created_by, assigned_to_role, title, message,
                    reference_type, reference_id, priority, category, event_key
                ) VALUES (
                    NEW.company_id, NEW.user_id, v_role, v_title, v_message,
                    'purchase_return', NEW.reference_id, 'high', 'approvals',
                    NEW.event_key || '.' || v_role
                ) ON CONFLICT (event_key) DO NOTHING;
            END LOOP;

        -- Event: Approved (Requires Warehouse Execution)
        ELSIF NEW.event_type = 'purchase_return.approved' THEN
            v_title := 'مطلوب استلام مخزني للمرتجع - Warehouse Action Required';
            v_message := 'تمت الموافقة على المرتجع ' || (NEW.payload->>'return_number') || '. يرجى اعتماد المخزن وتسليم البضاعة للمورد.';

            INSERT INTO notifications (
                company_id, created_by, assigned_to_role, title, message,
                reference_type, reference_id, priority, category, event_key
            ) VALUES (
                NEW.company_id, NEW.user_id, 'store_manager', v_title, v_message,
                'purchase_return', NEW.reference_id, 'high', 'inventory',
                NEW.event_key || '.store_manager'
            ) ON CONFLICT (event_key) DO NOTHING;

            -- Also notify the creator (target user)
            INSERT INTO notifications (
                company_id, created_by, assigned_to_user, title, message,
                reference_type, reference_id, priority, category, event_key
            )
            SELECT
                NEW.company_id, NEW.user_id, created_by, 'تمت الموافقة الدفترية على المرتجع - PR Approved', 'تمت الموافقة على المرتجع ' || (NEW.payload->>'return_number'),
                'purchase_return', NEW.reference_id, 'normal', 'approvals',
                NEW.event_key || '.creator'
            FROM purchase_returns WHERE id = NEW.reference_id
            ON CONFLICT (event_key) DO NOTHING;

        -- Event: Rejected
        ELSIF NEW.event_type = 'purchase_return.rejected' THEN
            v_title := 'تم رفض المرتجع - Purchase Return Rejected';
            v_message := 'تم رفض المرتجع ' || (NEW.payload->>'return_number') || ' بسبب: ' || COALESCE(NEW.payload->>'notes', 'بدون سبب');

            INSERT INTO notifications (
                company_id, created_by, assigned_to_user, title, message,
                reference_type, reference_id, priority, category, event_key
            )
            SELECT
                NEW.company_id, NEW.user_id, created_by, v_title, v_message,
                'purchase_return', NEW.reference_id, 'high', 'approvals',
                NEW.event_key || '.creator'
            FROM purchase_returns WHERE id = NEW.reference_id
            ON CONFLICT (event_key) DO NOTHING;

        -- Event: Completed (Warehouse Executed)
        ELSIF NEW.event_type = 'purchase_return.completed' THEN
            v_title := 'اكتمل إرجاع المخزون - PR Completed';
            v_message := 'تم اعتماد استلام المخزن بالكامل للمرتجع ' || (NEW.payload->>'return_number') || ' وتم خصم المخزون والقيود و Vendor credit بنجاح.';

            FOREACH v_role IN ARRAY v_admin_roles LOOP
                INSERT INTO notifications (
                    company_id, created_by, assigned_to_role, title, message,
                    reference_type, reference_id, priority, category, event_key
                ) VALUES (
                    NEW.company_id, NEW.user_id, v_role, v_title, v_message,
                    'purchase_return', NEW.reference_id, 'normal', 'inventory',
                    NEW.event_key || '.' || v_role
                ) ON CONFLICT (event_key) DO NOTHING;
            END LOOP;

            INSERT INTO notifications (
                company_id, created_by, assigned_to_user, title, message,
                reference_type, reference_id, priority, category, event_key
            )
            SELECT
                NEW.company_id, NEW.user_id, created_by, v_title, 'لقد اكتمل المرتجع فعلياً في المستودع ' || (NEW.payload->>'return_number'),
                'purchase_return', NEW.reference_id, 'normal', 'inventory',
                NEW.event_key || '.creator'
            FROM purchase_returns WHERE id = NEW.reference_id
            ON CONFLICT (event_key) DO NOTHING;

        END IF;

        NEW.status := 'processed';
        NEW.processed_at := NOW();

    END IF;

    RETURN NEW;
EXCEPTION WHEN OTHERS THEN
    NEW.status := 'failed';
    NEW.error_message := SQLERRM;
    RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- routing_version_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.routing_version_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_routing_name text;
BEGIN
  BEGIN
    SELECT routing_name INTO v_routing_name FROM public.manufacturing_routings WHERE id = NEW.routing_id;
  EXCEPTION WHEN OTHERS THEN v_routing_name := NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'manufacturing_routing_version', NEW.id, NEW.created_by,
      'نشاط فرعك: تم إنشاء نسخة مسار تصنيع',
      'إصدار ' || NEW.version_no::text || ' من مسار '
      || COALESCE(v_routing_name, '—') || ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.approval_status = OLD.approval_status THEN RETURN NEW; END IF;
  IF NEW.approval_status IN ('approved', 'rejected') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'manufacturing_routing_version', NEW.id,
      CASE WHEN NEW.approval_status = 'rejected' THEN NEW.rejected_by ELSE NEW.approved_by END,
      'نشاط فرعك: تغيّرت حالة اعتماد مسار تصنيع',
      'إصدار ' || NEW.version_no::text || ' من ' || COALESCE(v_routing_name, '—')
      || CASE NEW.approval_status WHEN 'approved' THEN ' تم اعتماده.' WHEN 'rejected' THEN ' تم رفضه.' ELSE '' END
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- routing_version_notify_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.routing_version_notify_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_routing_name text;
  v_requester uuid;
  v_approver_id uuid;
BEGIN
  IF TG_OP = 'UPDATE' AND OLD.approval_status = NEW.approval_status THEN RETURN NEW; END IF;
  IF NEW.approval_status <> 'pending_approval' THEN RETURN NEW; END IF;

  v_requester := COALESCE(NEW.submitted_by, NEW.created_by);

  BEGIN
    SELECT routing_name INTO v_routing_name FROM public.manufacturing_routings WHERE id = NEW.routing_id;
  EXCEPTION WHEN OTHERS THEN v_routing_name := NULL; END;

  FOR v_approver_id IN
    SELECT DISTINCT u FROM (
      SELECT user_id AS u FROM public.companies WHERE id = NEW.company_id
      UNION
      SELECT user_id FROM public.company_members
       WHERE company_id = NEW.company_id
         AND role IN ('owner', 'general_manager')
    ) approvers
    WHERE u IS NOT NULL AND (v_requester IS NULL OR u <> v_requester)
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      NEW.company_id, 'approval_request', NEW.id, v_requester,
      v_approver_id,
      'طلب اعتماد مسار تصنيع',
      'نسخة (إصدار ' || NEW.version_no::text || ') من مسار '
      || COALESCE(v_routing_name, 'بدون اسم')
      || ' — يحتاج اعتمادك من صندوق الموافقات.',
      'high', 'warning', 'approvals', 'in_app', NOW()
    );
  END LOOP;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- run_all_critical_tests()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.run_all_critical_tests()
 RETURNS TABLE(test_name text, result text)
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    'Invoice Edit Protection'::TEXT,
    test_prevent_invoice_edit_after_journal()::TEXT
  UNION ALL
  SELECT 
    'Journal Entry Balance'::TEXT,
    test_journal_entry_balance()::TEXT
  UNION ALL
  SELECT 
    'Customer Deletion Protection'::TEXT,
    test_prevent_customer_deletion_with_invoices()::TEXT
  UNION ALL
  SELECT 
    'Accounting Period Lock'::TEXT,
    test_accounting_period_lock()::TEXT
  UNION ALL
  SELECT 
    'Audit Trail System'::TEXT,
    test_audit_trail()::TEXT;
END;
$function$
;

-- ---------------------------------------------------------------
-- run_all_integrity_checks(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.run_all_integrity_checks(p_company_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(cmp_id uuid, check_code text, category text, name_ar text, name_en text, severity text, detail jsonb)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_company  RECORD;
  v_def_code text;
  v_def_fn   text;
  v_def_cat  text;
  v_def_ar   text;
  v_def_en   text;
  v_def_sev  text;
  v_sql      text;
  v_row      record;
BEGIN
  FOR v_company IN
    SELECT c.id FROM companies c WHERE (p_company_id IS NULL OR c.id = p_company_id)
  LOOP
    FOR v_def_code, v_def_fn, v_def_cat, v_def_ar, v_def_en, v_def_sev IN
      SELECT d.code, d.fn_name, d.category, d.name_ar, d.name_en, d.severity_default
      FROM integrity_check_definitions d WHERE d.active = true
    LOOP
      v_sql := format('SELECT severity, detail FROM %I($1)', v_def_fn);
      BEGIN
        FOR v_row IN EXECUTE v_sql USING v_company.id LOOP
          cmp_id     := v_company.id;
          check_code := v_def_code;
          category   := v_def_cat;
          name_ar    := v_def_ar;
          name_en    := v_def_en;
          severity   := COALESCE(v_row.severity, v_def_sev);
          detail     := v_row.detail;
          RETURN NEXT;
        END LOOP;
      EXCEPTION WHEN OTHERS THEN
        cmp_id     := v_company.id;
        check_code := v_def_code;
        category   := v_def_cat;
        name_ar    := v_def_ar;
        name_en    := v_def_en;
        severity   := 'high';
        detail     := jsonb_build_object('error', SQLERRM,
          'hint','Check function raised an exception.');
        RETURN NEXT;
      END;
    END LOOP;
  END LOOP;
END;
$function$
;

-- ---------------------------------------------------------------
-- run_daily_income_query(p_account_ids uuid[], p_company_id uuid, p_date date, p_branch_id uuid, p_cost_center_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.run_daily_income_query(p_account_ids uuid[], p_company_id uuid, p_date date, p_branch_id uuid DEFAULT NULL::uuid, p_cost_center_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(account_id uuid, debit_amount numeric, credit_amount numeric, branch_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  RETURN QUERY
    SELECT
      jel.account_id,
      jel.debit_amount,
      jel.credit_amount,
      je.branch_id
    FROM journal_entry_lines jel
    INNER JOIN journal_entries je ON je.id = jel.journal_entry_id
    WHERE jel.account_id = ANY(p_account_ids)
      AND je.company_id = p_company_id
      AND je.status = 'posted'
      AND je.entry_date = p_date
      AND (p_branch_id IS NULL OR je.branch_id = p_branch_id)
      AND (p_cost_center_id IS NULL OR je.cost_center_id = p_cost_center_id);
END;
$function$
;

-- ---------------------------------------------------------------
-- run_daily_reconciliation(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.run_daily_reconciliation(p_company_id uuid)
 RETURNS TABLE(check_name text, gl_value numeric, operational_value numeric, difference numeric, severity text, is_ok boolean, message text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_gl_inventory    NUMERIC := 0;
  v_fifo_inventory  NUMERIC := 0;
  v_gl_ar           NUMERIC := 0;
  v_op_ar           NUMERIC := 0;
  v_gl_ap           NUMERIC := 0;
  v_op_ap           NUMERIC := 0;
  v_gl_cash         NUMERIC := 0;
  v_op_cash         NUMERIC := 0;
  v_unbalanced      INTEGER := 0;
  v_run_date        DATE    := CURRENT_DATE;
  v_sev             TEXT;
  v_ok              BOOLEAN;
  v_msg             TEXT;
  v_diff            NUMERIC;
BEGIN
  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0) INTO v_gl_inventory
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted'
    AND coa.account_type = 'asset'
    AND (coa.sub_type = 'inventory' OR coa.account_name ILIKE '%مخزون%');

  SELECT COALESCE(SUM(fcl.remaining_quantity * fcl.unit_cost), 0) INTO v_fifo_inventory
  FROM fifo_cost_lots fcl
  JOIN products p ON p.id = fcl.product_id
  WHERE p.company_id = p_company_id AND fcl.remaining_quantity > 0;

  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0) INTO v_gl_ar
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted'
    AND coa.account_type = 'asset'
    AND (coa.sub_type IN ('accounts_receivable','ar') OR coa.account_name ILIKE '%العملاء%');

  SELECT COALESCE(SUM(GREATEST(i.total_amount - COALESCE(i.paid_amount,0) - COALESCE(i.returned_amount,0), 0)), 0)
  INTO v_op_ar FROM invoices i
  WHERE i.company_id = p_company_id AND i.status NOT IN ('cancelled','draft');

  SELECT COALESCE(SUM(jel.credit_amount - jel.debit_amount), 0) INTO v_gl_ap
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted'
    AND coa.account_type = 'liability'
    AND (coa.sub_type IN ('accounts_payable','ap') OR coa.account_name ILIKE '%الموردين%');

  SELECT COALESCE(SUM(GREATEST(b.total_amount - COALESCE(b.paid_amount,0), 0)), 0)
  INTO v_op_ap FROM bills b
  WHERE b.company_id = p_company_id AND b.status NOT IN ('cancelled','draft');

  SELECT COALESCE(SUM(jel.debit_amount - jel.credit_amount), 0) INTO v_gl_cash
  FROM journal_entry_lines jel
  JOIN journal_entries je ON je.id = jel.journal_entry_id
  JOIN chart_of_accounts coa ON coa.id = jel.account_id
  WHERE je.company_id = p_company_id AND je.status = 'posted'
    AND coa.account_type = 'asset'
    AND (coa.sub_type IN ('cash','bank') OR coa.account_name ILIKE '%بنك%' OR coa.account_name ILIKE '%صندوق%');

  SELECT COALESCE(SUM(ba.balance), 0) INTO v_op_cash
  FROM bank_accounts ba WHERE ba.company_id = p_company_id;

  SELECT COUNT(*) INTO v_unbalanced
  FROM (
    SELECT je.id FROM journal_entries je
    JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE je.company_id = p_company_id AND je.status = 'posted'
    GROUP BY je.id
    HAVING ABS(SUM(jel.debit_amount) - SUM(jel.credit_amount)) > 0.01
  ) sub;

  DELETE FROM daily_reconciliation_log WHERE company_id = p_company_id AND run_date = v_run_date;

  v_diff := ABS(v_gl_inventory - v_fifo_inventory);
  v_ok   := v_diff < 1;
  v_sev  := CASE WHEN v_ok THEN 'ok' WHEN v_diff > v_gl_inventory * 0.05 THEN 'critical' ELSE 'warning' END;
  v_msg  := CASE WHEN v_ok THEN 'GL Inventory = FIFO' ELSE 'تضارب: GL='||v_gl_inventory||' FIFO='||v_fifo_inventory||' فارق='||v_diff END;
  INSERT INTO daily_reconciliation_log(company_id,run_date,check_name,gl_value,operational_value,difference,is_ok,severity,message)
  VALUES(p_company_id,v_run_date,'GL vs FIFO Inventory',v_gl_inventory,v_fifo_inventory,v_diff,v_ok,v_sev,v_msg);
  RETURN QUERY VALUES('GL vs FIFO Inventory',v_gl_inventory,v_fifo_inventory,v_diff,v_sev,v_ok,v_msg);

  v_diff := ABS(v_gl_ar - v_op_ar);
  v_ok   := v_diff < 1;
  v_sev  := CASE WHEN v_ok THEN 'ok' WHEN v_diff > 10 THEN 'critical' ELSE 'warning' END;
  v_msg  := CASE WHEN v_ok THEN 'GL AR = Operational AR' ELSE 'تضارب AR: GL='||v_gl_ar||' Op='||v_op_ar END;
  INSERT INTO daily_reconciliation_log(company_id,run_date,check_name,gl_value,operational_value,difference,is_ok,severity,message)
  VALUES(p_company_id,v_run_date,'GL AR vs Operational',v_gl_ar,v_op_ar,v_diff,v_ok,v_sev,v_msg);
  RETURN QUERY VALUES('GL AR vs Operational',v_gl_ar,v_op_ar,v_diff,v_sev,v_ok,v_msg);

  v_diff := ABS(v_gl_ap - v_op_ap);
  v_ok   := v_diff < 1;
  v_sev  := CASE WHEN v_ok THEN 'ok' WHEN v_diff > 10 THEN 'critical' ELSE 'warning' END;
  v_msg  := CASE WHEN v_ok THEN 'GL AP = Operational AP' ELSE 'تضارب AP: GL='||v_gl_ap||' Op='||v_op_ap END;
  INSERT INTO daily_reconciliation_log(company_id,run_date,check_name,gl_value,operational_value,difference,is_ok,severity,message)
  VALUES(p_company_id,v_run_date,'GL AP vs Operational',v_gl_ap,v_op_ap,v_diff,v_ok,v_sev,v_msg);
  RETURN QUERY VALUES('GL AP vs Operational',v_gl_ap,v_op_ap,v_diff,v_sev,v_ok,v_msg);

  v_diff := ABS(v_gl_cash - v_op_cash);
  v_ok   := v_diff < 1;
  v_sev  := CASE WHEN v_ok THEN 'ok' WHEN v_diff > 10 THEN 'critical' ELSE 'warning' END;
  v_msg  := CASE WHEN v_ok THEN 'GL Cash = Bank Accounts' ELSE 'تضارب نقد: GL='||v_gl_cash||' Bank='||v_op_cash END;
  INSERT INTO daily_reconciliation_log(company_id,run_date,check_name,gl_value,operational_value,difference,is_ok,severity,message)
  VALUES(p_company_id,v_run_date,'GL Cash vs Bank',v_gl_cash,v_op_cash,v_diff,v_ok,v_sev,v_msg);
  RETURN QUERY VALUES('GL Cash vs Bank',v_gl_cash,v_op_cash,v_diff,v_sev,v_ok,v_msg);

  v_ok  := v_unbalanced = 0;
  v_sev := CASE WHEN v_ok THEN 'ok' ELSE 'critical' END;
  v_msg := CASE WHEN v_ok THEN 'لا توجد قيود غير متوازنة' ELSE v_unbalanced||' قيد غير متوازن!' END;
  INSERT INTO daily_reconciliation_log(company_id,run_date,check_name,gl_value,operational_value,difference,is_ok,severity,message)
  VALUES(p_company_id,v_run_date,'Unbalanced Journal Entries',0,v_unbalanced,v_unbalanced,v_ok,v_sev,v_msg);
  RETURN QUERY VALUES('Unbalanced Journal Entries',0::NUMERIC,v_unbalanced::NUMERIC,v_unbalanced::NUMERIC,v_sev,v_ok,v_msg);
END;
$function$
;

-- ---------------------------------------------------------------
-- run_fx_revaluation(p_company_id uuid, p_revaluation_date date, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.run_fx_revaluation(p_company_id uuid, p_revaluation_date date, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_base_ccy      text;
  v_role          text;
  v_journal_id    uuid;
  v_line          record;
  v_fx_gain_acct  uuid;
  v_fx_loss_acct  uuid;
  v_total_delta   numeric := 0;
  v_lines_added   integer := 0;
BEGIN
  -- SoD
  SELECT role INTO v_role FROM public.company_members
   WHERE company_id = p_company_id AND user_id = p_user_id LIMIT 1;
  IF NOT (COALESCE(v_role,'') IN ('owner','general_manager','admin')) THEN
    RAISE EXCEPTION 'SOD: FX revaluation limited to owner/general_manager/admin';
  END IF;

  -- Period lock
  BEGIN
    PERFORM public.require_open_financial_period_db(p_company_id, p_revaluation_date);
  EXCEPTION WHEN undefined_function THEN NULL; END;

  SELECT UPPER(base_currency) INTO v_base_ccy
    FROM public.companies WHERE id = p_company_id;
  v_base_ccy := COALESCE(v_base_ccy, 'EGP');

  -- Locate P&L accounts (Arabic + English name match)
  SELECT id INTO v_fx_gain_acct FROM public.chart_of_accounts
   WHERE company_id = p_company_id AND is_active = true
     AND (account_name ILIKE '%FX%gain%' OR account_name ILIKE '%unrealized%gain%'
          OR account_name ILIKE '%أرباح%عملة%' OR account_name ILIKE '%أرباح%صرف%')
   LIMIT 1;
  SELECT id INTO v_fx_loss_acct FROM public.chart_of_accounts
   WHERE company_id = p_company_id AND is_active = true
     AND (account_name ILIKE '%FX%loss%' OR account_name ILIKE '%unrealized%loss%'
          OR account_name ILIKE '%خسائر%عملة%' OR account_name ILIKE '%خسائر%صرف%')
   LIMIT 1;
  IF v_fx_gain_acct IS NULL THEN v_fx_gain_acct := v_fx_loss_acct; END IF;
  IF v_fx_loss_acct IS NULL THEN v_fx_loss_acct := v_fx_gain_acct; END IF;
  IF v_fx_gain_acct IS NULL THEN
    RAISE EXCEPTION 'FX Gain/Loss account not found. Please create one in the CoA (name containing "أرباح عملة" or "FX gain" or "خسائر عملة" or "FX loss").';
  END IF;

  -- Draft header
  INSERT INTO public.journal_entries (
    company_id, entry_date, description, reference_type, reference_id, status
  ) VALUES (
    p_company_id, p_revaluation_date,
    'إعادة تقييم أرصدة العملات الأجنبية — ' || p_revaluation_date::text,
    'fx_revaluation', p_company_id, 'draft'
  ) RETURNING id INTO v_journal_id;

  -- For each FC account, compute delta and add revaluation lines
  FOR v_line IN
    WITH bal AS (
      SELECT jel.account_id,
             SUM(COALESCE(jel.original_debit,0) - COALESCE(jel.original_credit,0)) AS native_balance,
             SUM(COALESCE(jel.debit_amount,0)   - COALESCE(jel.credit_amount,0))   AS current_base,
             MAX(COALESCE(jel.original_currency, '')) AS ccy
      FROM public.journal_entry_lines jel
      JOIN public.journal_entries je ON je.id = jel.journal_entry_id
     WHERE je.company_id = p_company_id
       AND je.status = 'posted'
       AND (je.is_deleted IS NULL OR je.is_deleted = false)
       AND je.deleted_at IS NULL
       AND je.entry_date <= p_revaluation_date
      GROUP BY jel.account_id
    )
    SELECT bal.account_id, bal.native_balance, bal.current_base, bal.ccy,
           coa.account_type, coa.sub_type, coa.account_name,
           coa.branch_id, coa.cost_center_id
      FROM bal
      JOIN public.chart_of_accounts coa ON coa.id = bal.account_id
     WHERE bal.ccy <> '' AND UPPER(bal.ccy) <> v_base_ccy
       -- monetary only: exclude fixed assets, equity, revenue, expense
       AND coa.account_type IN ('asset','liability')
       AND coa.sub_type IN ('cash','bank','accounts_receivable','accounts_payable',
                            'other_current_asset','other_current_liability')
  LOOP
    DECLARE
      v_rate         numeric := 1;
      v_target_base  numeric;
      v_delta        numeric;
      v_gl_acct      uuid;
    BEGIN
      -- Closing rate (most recent up to revaluation date)
      SELECT rate INTO v_rate FROM public.exchange_rates
       WHERE company_id = p_company_id
         AND UPPER(COALESCE(from_currency, '')) = UPPER(v_line.ccy)
         AND UPPER(COALESCE(to_currency, ''))   = v_base_ccy
         AND rate_date <= p_revaluation_date
         AND (is_active IS NULL OR is_active = true)
       ORDER BY rate_date DESC LIMIT 1;
      IF v_rate IS NULL OR v_rate = 0 THEN v_rate := 1; END IF;

      v_target_base := ROUND(v_line.native_balance * v_rate, 4);
      v_delta       := v_target_base - v_line.current_base;

      IF ABS(v_delta) < 0.01 THEN CONTINUE; END IF;

      -- Book the delta on the FC account, opposite side to GL/loss.
      -- Gain: net asset increased (or liability decreased) → DR asset
      -- and CR gain, or DR liability and CR gain.
      IF v_delta > 0 THEN
        v_gl_acct := v_fx_gain_acct;
        INSERT INTO public.journal_entry_lines (
          journal_entry_id, account_id, description,
          debit_amount, credit_amount,
          original_debit, original_credit, original_currency,
          exchange_rate_used, branch_id, cost_center_id
        ) VALUES
          (v_journal_id, v_line.account_id, 'FX reval — ' || v_line.account_name,
           v_delta, 0, 0, 0, v_base_ccy, v_rate, v_line.branch_id, v_line.cost_center_id),
          (v_journal_id, v_gl_acct, 'FX revaluation gain — ' || v_line.account_name,
           0, v_delta, 0, 0, v_base_ccy, 1, v_line.branch_id, v_line.cost_center_id);
      ELSE
        v_gl_acct := v_fx_loss_acct;
        INSERT INTO public.journal_entry_lines (
          journal_entry_id, account_id, description,
          debit_amount, credit_amount,
          original_debit, original_credit, original_currency,
          exchange_rate_used, branch_id, cost_center_id
        ) VALUES
          (v_journal_id, v_gl_acct, 'FX revaluation loss — ' || v_line.account_name,
           ABS(v_delta), 0, 0, 0, v_base_ccy, 1, v_line.branch_id, v_line.cost_center_id),
          (v_journal_id, v_line.account_id, 'FX reval — ' || v_line.account_name,
           0, ABS(v_delta), 0, 0, v_base_ccy, v_rate, v_line.branch_id, v_line.cost_center_id);
      END IF;

      v_lines_added := v_lines_added + 1;
      v_total_delta := v_total_delta + v_delta;
    END;
  END LOOP;

  IF v_lines_added = 0 THEN
    DELETE FROM public.journal_entries WHERE id = v_journal_id;
    RETURN jsonb_build_object(
      'success', true,
      'message', 'No revaluation needed — balances already match closing rates.',
      'lines_added', 0
    );
  END IF;

  UPDATE public.journal_entries
     SET status = 'posted', posted_by = p_user_id, posted_at = NOW()
   WHERE id = v_journal_id;

  RETURN jsonb_build_object(
    'success', true,
    'journal_id', v_journal_id,
    'accounts_revalued', v_lines_added,
    'total_delta_base_ccy', ROUND(v_total_delta, 2)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- run_integrity_check()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.run_integrity_check()
 RETURNS TABLE(check_type text, company_id uuid, record_id uuid, identifier text, severity text, description text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE v_alert RECORD;
BEGIN
  -- Clear resolved alerts older than 7 days
  UPDATE system_integrity_alerts
  SET resolved = true, resolved_at = NOW()
  WHERE resolved = false
    AND NOT EXISTS (
      SELECT 1 FROM v_erp_integrity_monitor m
      WHERE m.company_id = system_integrity_alerts.company_id
        AND m.check_type = system_integrity_alerts.alert_type
        AND m.record_id  = system_integrity_alerts.record_id
    );

  -- Insert new alerts from the monitor view
  INSERT INTO system_integrity_alerts (company_id, alert_type, record_id, identifier, severity, description)
  SELECT
    m.company_id,
    m.check_type,
    m.record_id,
    m.identifier,
    CASE
      WHEN m.check_type IN ('unbalanced_je','empty_posted_je') THEN 'critical'
      WHEN m.check_type IN ('stock_mismatch','bill_status_mismatch') THEN 'warning'
      ELSE 'info'
    END,
    m.issue_description
  FROM v_erp_integrity_monitor m
  WHERE NOT EXISTS (
    SELECT 1 FROM system_integrity_alerts sa
    WHERE sa.company_id  = m.company_id
      AND sa.alert_type  = m.check_type
      AND sa.record_id   = m.record_id
      AND sa.resolved    = false
  )
  ON CONFLICT DO NOTHING;

  -- Return current open alerts
  RETURN QUERY
  SELECT sa.alert_type, sa.company_id, sa.record_id, sa.identifier, sa.severity, sa.description
  FROM system_integrity_alerts sa
  WHERE sa.resolved = false
  ORDER BY sa.severity DESC, sa.created_at DESC;
END;
$function$
;

-- ---------------------------------------------------------------
-- run_negative_security_tests()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.run_negative_security_tests()
 RETURNS TABLE(test_id text, scenario text, target text, outcome text, err_code text, err_msg text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_inv_id UUID; v_inv_num TEXT;
  v_paid_je_id UUID; v_je_num TEXT;
  v_co_id UUID; v_draft_je_id UUID;
BEGIN
  SELECT i.id, i.invoice_number INTO v_inv_id, v_inv_num
  FROM invoices i
  WHERE i.status='sent' AND (i.is_deleted IS NULL OR i.is_deleted=false)
    AND NOT EXISTS (SELECT 1 FROM journal_entries je
      WHERE je.reference_type='invoice' AND je.reference_id=i.id
        AND je.status='posted' AND (je.is_deleted IS NULL OR je.is_deleted=false))
  LIMIT 1;

  SELECT je.id, je.entry_number INTO v_paid_je_id, v_je_num
  FROM invoices i
  JOIN journal_entries je ON je.reference_type='invoice' AND je.reference_id=i.id
    AND je.status='posted' AND (je.is_deleted IS NULL OR je.is_deleted=false)
  WHERE i.status='paid' AND (i.is_deleted IS NULL OR i.is_deleted=false)
  LIMIT 1;

  SELECT id INTO v_co_id FROM companies LIMIT 1;

  -- NT1: Force invoice to paid without revenue JE
  BEGIN
    IF v_inv_id IS NOT NULL THEN
      UPDATE invoices SET status='paid' WHERE id=v_inv_id;
      test_id:='NT1'; scenario:='Force invoice.status=paid without revenue JE'; target:=v_inv_num;
      outcome:='❌ FAIL'; err_code:='NONE'; err_msg:='TRIGGER DID NOT FIRE — attack succeeded';
      RETURN NEXT;
    ELSE
      test_id:='NT1'; scenario:='Force invoice.status=paid without revenue JE'; target:='no unposted invoice';
      outcome:='⚠️ SKIPPED'; err_code:='N/A'; err_msg:='No suitable test invoice found';
      RETURN NEXT;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    test_id:='NT1'; scenario:='Force invoice.status=paid without revenue JE';
    target:=COALESCE(v_inv_num,'N/A');
    outcome:='✅ BLOCKED'; err_code:=SQLSTATE; err_msg:=LEFT(SQLERRM,180);
    RETURN NEXT;
  END;

  -- NT2: Soft-delete revenue JE of a paid invoice
  BEGIN
    IF v_paid_je_id IS NOT NULL THEN
      UPDATE journal_entries SET is_deleted=true WHERE id=v_paid_je_id;
      test_id:='NT2'; scenario:='Soft-delete revenue JE of paid invoice'; target:=v_je_num;
      outcome:='❌ FAIL'; err_code:='NONE'; err_msg:='TRIGGER DID NOT FIRE';
      RETURN NEXT;
    ELSE
      test_id:='NT2'; scenario:='Soft-delete revenue JE of paid invoice'; target:='no paid+JE found';
      outcome:='⚠️ SKIPPED'; err_code:='N/A'; err_msg:='No paid invoice with active JE found';
      RETURN NEXT;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    test_id:='NT2'; scenario:='Soft-delete revenue JE of paid invoice';
    target:=COALESCE(v_je_num,'N/A');
    outcome:='✅ BLOCKED'; err_code:=SQLSTATE; err_msg:=LEFT(SQLERRM,180);
    RETURN NEXT;
  END;

  -- NT3: Direct INSERT journal_entry as posted (bypassing atomic RPC)
  BEGIN
    INSERT INTO journal_entries(company_id,reference_type,reference_id,entry_date,description,status)
    VALUES(v_co_id,'manual',gen_random_uuid(),CURRENT_DATE,'ATTACK: direct insert posted','posted');
    test_id:='NT3'; scenario:='Direct INSERT journal_entry as posted without atomic RPC'; target:='direct INSERT';
    outcome:='❌ FAIL'; err_code:='NONE'; err_msg:='TRIGGER DID NOT FIRE';
    RETURN NEXT;
  EXCEPTION WHEN OTHERS THEN
    test_id:='NT3'; scenario:='Direct INSERT journal_entry as posted without atomic RPC'; target:='direct INSERT';
    outcome:='✅ BLOCKED'; err_code:=SQLSTATE; err_msg:=LEFT(SQLERRM,180);
    RETURN NEXT;
  END;

  -- NT4: Post JE with no lines (INSERT draft then UPDATE to posted)
  BEGIN
    INSERT INTO journal_entries(company_id,reference_type,reference_id,entry_date,description,status)
    VALUES(v_co_id,'manual',gen_random_uuid(),CURRENT_DATE,'ATTACK: post empty JE','draft')
    RETURNING id INTO v_draft_je_id;

    UPDATE journal_entries SET status='posted' WHERE id=v_draft_je_id;
    test_id:='NT4'; scenario:='Post JE with zero lines'; target:=v_draft_je_id::TEXT;
    outcome:='❌ FAIL'; err_code:='NONE'; err_msg:='TRIGGER DID NOT FIRE';
    RETURN NEXT;
  EXCEPTION WHEN OTHERS THEN
    test_id:='NT4'; scenario:='Post JE with zero lines'; target:=COALESCE(v_draft_je_id::TEXT,'N/A');
    outcome:='✅ BLOCKED'; err_code:=SQLSTATE; err_msg:=LEFT(SQLERRM,180);
    RETURN NEXT;
  END;

  -- NT5: Call critical function (restore_company_backup) — 
  -- authenticated role cannot call it (we simulate by checking ACL)
  BEGIN
    test_id:='NT5'; scenario:='authenticated calling restore_company_backup';
    target:='restore_company_backup';
    outcome:= CASE
      WHEN NOT EXISTS (
        SELECT 1 FROM pg_proc p
        WHERE p.proname='restore_company_backup'
          AND array_to_string(p.proacl,'|') LIKE '%authenticated=X%'
      ) THEN '✅ BLOCKED — authenticated has no EXECUTE'
      ELSE '❌ FAIL — authenticated still has EXECUTE'
    END;
    err_code:='ACL_CHECK'; err_msg:='Verified via pg_proc.proacl';
    RETURN NEXT;
  END;
END;
$function$
;

-- ---------------------------------------------------------------
-- safe_delete_payment_journals()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.safe_delete_payment_journals()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_je RECORD;
BEGIN
  -- Soft-delete all journal entries linked to this payment
  -- to avoid NO ACTION FK violations from child tables
  FOR v_je IN 
    SELECT id FROM journal_entries
    WHERE reference_id = OLD.id 
      AND company_id = OLD.company_id
      AND (is_deleted IS NULL OR is_deleted = FALSE)
  LOOP
    BEGIN
      -- Try to soft-delete by nullifying reference (won't trigger enforce_posted_entry_no_edit for drafts)
      UPDATE journal_entries
      SET is_deleted = TRUE, deleted_at = NOW()
      WHERE id = v_je.id AND status != 'posted';
    EXCEPTION WHEN OTHERS THEN
      NULL; -- Skip posted entries - leave them as orphaned history
    END;
  END LOOP;

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- sales_return_approval_insert_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sales_return_approval_insert_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_role text;
BEGIN
  IF NEW.created_by_user_id IS NOT NULL THEN
    SELECT role INTO v_role FROM public.company_members
     WHERE company_id = NEW.company_id AND user_id = NEW.created_by_user_id LIMIT 1;
  END IF;
  IF v_role IN ('owner', 'general_manager') THEN
    IF NEW.status = 'approved' THEN
      IF NEW.approved_by IS NULL THEN NEW.approved_by := NEW.created_by_user_id; END IF;
      IF NEW.approved_at IS NULL THEN NEW.approved_at := NOW(); END IF;
    END IF;
    RETURN NEW;
  END IF;
  IF NEW.status IS NOT NULL AND NEW.status NOT IN ('draft', 'pending_approval') THEN
    RAISE EXCEPTION
      'مرتجع المبيعات يحتاج اعتماد المالك / المدير العام. لا يجوز إنشاء مرتجع بحالة "%" مباشرة. ابدأ بحالة pending_approval.', NEW.status
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sales_return_approval_update_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sales_return_approval_update_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status = 'approved' AND (NEW.approved_by IS NULL OR NEW.approved_at IS NULL) THEN
    RAISE EXCEPTION
      'لا يمكن تحويل مرتجع المبيعات إلى حالة "approved" بدون تسجيل المعتمد. استخدم RPC approve_sales_return_atomic.'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sales_return_branch_manager_notify_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sales_return_branch_manager_notify_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_customer_name text; v_currency text;
BEGIN
  v_currency := COALESCE(NEW.original_currency, 'EGP');
  BEGIN
    SELECT name INTO v_customer_name FROM public.customers WHERE id = NEW.customer_id;
  EXCEPTION WHEN OTHERS THEN v_customer_name := NULL; END;

  IF TG_OP = 'INSERT' THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'sales_return', NEW.id, NEW.created_by_user_id,
      'نشاط فرعك: تم إنشاء مرتجع مبيعات',
      'تم إنشاء مرتجع ' || NEW.return_number ||
      CASE WHEN v_customer_name IS NOT NULL THEN ' للعميل ' || v_customer_name ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency || ' فى فرعك.'
    );
    RETURN NEW;
  END IF;

  IF NEW.status = OLD.status THEN RETURN NEW; END IF;
  IF NEW.status IN ('approved', 'rejected') THEN
    PERFORM public.notify_branch_manager(
      NEW.company_id, NEW.branch_id,
      'sales_return', NEW.id,
      CASE WHEN NEW.status='rejected' THEN NEW.rejected_by ELSE NEW.approved_by END,
      'نشاط فرعك: تغيّرت حالة مرتجع مبيعات',
      'المرتجع ' || NEW.return_number ||
      CASE WHEN v_customer_name IS NOT NULL THEN ' للعميل ' || v_customer_name ELSE '' END ||
      ' أصبحت الحالة "' || NEW.status || '".'
    );
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sales_return_notify_approval_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sales_return_notify_approval_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_customer_name text; v_requester uuid; v_approver_id uuid; v_currency text;
BEGIN
  IF TG_OP = 'UPDATE' AND OLD.status = NEW.status THEN RETURN NEW; END IF;
  IF NEW.status <> 'pending_approval' THEN RETURN NEW; END IF;
  v_requester := NEW.created_by_user_id;
  v_currency  := COALESCE(NEW.original_currency, 'EGP');
  BEGIN
    SELECT name INTO v_customer_name FROM public.customers WHERE id = NEW.customer_id;
  EXCEPTION WHEN OTHERS THEN v_customer_name := NULL; END;

  FOR v_approver_id IN
    SELECT DISTINCT u FROM (
      SELECT user_id AS u FROM public.companies WHERE id = NEW.company_id
      UNION
      SELECT user_id FROM public.company_members
       WHERE company_id = NEW.company_id
         AND role IN ('owner', 'general_manager')
    ) approvers
    WHERE u IS NOT NULL AND (v_requester IS NULL OR u <> v_requester)
  LOOP
    INSERT INTO public.notifications (
      company_id, reference_type, reference_id, created_by,
      assigned_to_user, title, message,
      priority, severity, category, channel, created_at
    ) VALUES (
      NEW.company_id, 'approval_request', NEW.id, v_requester,
      v_approver_id,
      'طلب اعتماد مرتجع مبيعات',
      'مرتجع ' || NEW.return_number ||
      CASE WHEN v_customer_name IS NOT NULL THEN ' للعميل ' || v_customer_name ELSE '' END ||
      ' بقيمة ' || NEW.total_amount::text || ' ' || v_currency ||
      ' — يحتاج اعتمادك من صندوق الموافقات.',
      'high', 'warning', 'approvals', 'in_app', NOW()
    );
  END LOOP;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- search_audit_trail(p_company_id uuid, p_search_term text, p_limit integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.search_audit_trail(p_company_id uuid, p_search_term text, p_limit integer DEFAULT 100)
 RETURNS TABLE(id uuid, user_name text, action text, target_table text, record_identifier text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  RETURN QUERY
  SELECT
    al.id,
    al.user_name,
    al.action,
    al.target_table,
    al.record_identifier,
    al.created_at
  FROM audit_logs al
  WHERE al.company_id = p_company_id
    AND (
      al.record_identifier ILIKE '%' || p_search_term || '%' OR
      al.user_name ILIKE '%' || p_search_term || '%' OR
      al.user_email ILIKE '%' || p_search_term || '%' OR
      al.target_table ILIKE '%' || p_search_term || '%'
    )
  ORDER BY al.created_at DESC
  LIMIT p_limit;
END;
$function$
;

-- ---------------------------------------------------------------
-- seed_accounting_periods_for_company(p_company_id uuid, p_start_date date, p_months integer)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.seed_accounting_periods_for_company(p_company_id uuid, p_start_date date DEFAULT CURRENT_DATE, p_months integer DEFAULT 12)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_inserted int := 0;
  v_first_month date;
  v_i int;
  v_month_start date;
  v_month_end date;
  v_name text;
  v_exists boolean;
BEGIN
  IF p_company_id IS NULL THEN
    RAISE EXCEPTION 'p_company_id is required';
  END IF;
  IF p_months IS NULL OR p_months < 1 THEN
    p_months := 12;
  END IF;

  v_first_month := date_trunc('month', p_start_date)::date;

  FOR v_i IN 0 .. (p_months - 1) LOOP
    v_month_start := (v_first_month + (v_i || ' months')::interval)::date;
    v_month_end   := (v_month_start + interval '1 month' - interval '1 day')::date;

    -- Pre-check: skip if any existing period overlaps this month for this company.
    SELECT EXISTS(
      SELECT 1 FROM accounting_periods
      WHERE company_id = p_company_id
        AND daterange(period_start, period_end, '[]') &&
            daterange(v_month_start, v_month_end, '[]')
    ) INTO v_exists;

    IF v_exists THEN
      CONTINUE;
    END IF;

    v_name :=
      _arabic_month_name(EXTRACT(MONTH FROM v_month_start)::int)
      || ' '
      || _to_arabic_indic_digits(EXTRACT(YEAR FROM v_month_start)::text);

    INSERT INTO accounting_periods (
      company_id, period_name, period_start, period_end, status, is_locked
    )
    VALUES (
      p_company_id, v_name, v_month_start, v_month_end, 'open', false
    );

    v_inserted := v_inserted + 1;
  END LOOP;

  RETURN v_inserted;
END;
$function$
;

