-- ---------------------------------------------------------------
-- set_default_branch_for_document()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.set_default_branch_for_document()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_branch_id UUID; v_cost_center_id UUID; v_warehouse_id UUID; BEGIN IF NEW.branch_id IS NULL THEN SELECT b.id INTO v_branch_id FROM branches b WHERE b.company_id = NEW.company_id AND b.is_main = true LIMIT 1; NEW.branch_id := v_branch_id; END IF; IF NEW.cost_center_id IS NULL AND NEW.branch_id IS NOT NULL THEN SELECT cc.id INTO v_cost_center_id FROM cost_centers cc WHERE cc.branch_id = NEW.branch_id AND cc.is_main = true LIMIT 1; IF v_cost_center_id IS NULL THEN SELECT cc.id INTO v_cost_center_id FROM cost_centers cc WHERE cc.branch_id = NEW.branch_id LIMIT 1; END IF; NEW.cost_center_id := v_cost_center_id; END IF; IF NEW.warehouse_id IS NULL AND NEW.branch_id IS NOT NULL THEN SELECT w.id INTO v_warehouse_id FROM warehouses w WHERE w.branch_id = NEW.branch_id AND w.is_main = true LIMIT 1; IF v_warehouse_id IS NULL THEN SELECT w.id INTO v_warehouse_id FROM warehouses w WHERE w.company_id = NEW.company_id AND w.is_main = true LIMIT 1; END IF; NEW.warehouse_id := v_warehouse_id; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- set_default_manufacturing_bom_version_atomic(p_company_id uuid, p_bom_version_id uuid, p_updated_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.set_default_manufacturing_bom_version_atomic(p_company_id uuid, p_bom_version_id uuid, p_updated_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version RECORD;
  v_previous_default UUID;
BEGIN
  SELECT *
    INTO v_version
    FROM public.manufacturing_bom_versions
   WHERE id = p_bom_version_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing BOM version not found or not in company. bom_version_id=%', p_bom_version_id;
  END IF;

  IF v_version.status <> 'approved' THEN
    RAISE EXCEPTION 'Only approved BOM versions can be set as default. bom_version_id=%, status=%',
      p_bom_version_id, v_version.status;
  END IF;

  SELECT id
    INTO v_previous_default
    FROM public.manufacturing_bom_versions
   WHERE bom_id = v_version.bom_id
     AND is_default = true
   ORDER BY version_no DESC
   LIMIT 1;

  PERFORM 1
    FROM public.manufacturing_bom_versions
   WHERE bom_id = v_version.bom_id
   FOR UPDATE;

  UPDATE public.manufacturing_bom_versions
     SET is_default = false,
         updated_by = p_updated_by
   WHERE bom_id = v_version.bom_id
     AND is_default = true
     AND id <> p_bom_version_id;

  UPDATE public.manufacturing_bom_versions
     SET is_default = true,
         updated_by = p_updated_by
   WHERE id = p_bom_version_id;

  RETURN jsonb_build_object(
    'success', true,
    'bom_version_id', p_bom_version_id,
    'previous_default_version_id', v_previous_default,
    'status', v_version.status
  );
END;
$function$
;

