-- ---------------------------------------------------------------
-- split_fifo_lot(p_company_id uuid, p_lot_id uuid, p_splits jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.split_fifo_lot(p_company_id uuid, p_lot_id uuid, p_splits jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_role text; v_member_branch uuid;
  v_lot public.fifo_cost_lots;
  v_sum numeric := 0;
  v_item jsonb;
  v_qty numeric;
  v_first boolean := true;
  v_created int := 0;
  v_numbers text[] := '{}';
  v_new_id uuid;
BEGIN
  -- role gate (mirror of update_lot_expiry v3.74.580)
  IF v_uid IS NOT NULL THEN
    SELECT cm.role, cm.branch_id INTO v_role, v_member_branch
    FROM public.company_members cm
    WHERE cm.company_id = p_company_id AND cm.user_id = v_uid LIMIT 1;
    IF v_role IS NULL THEN
      RAISE EXCEPTION 'LOT_SPLIT_FORBIDDEN: لست عضواً فى هذه الشركة';
    END IF;
    IF v_role NOT IN ('owner','admin','general_manager','store_manager','warehouse_manager') THEN
      RAISE EXCEPTION 'LOT_SPLIT_FORBIDDEN: تقسيم الدفعات متاح للإدارة ومسئولى المخازن فقط';
    END IF;
  END IF;

  SELECT * INTO v_lot FROM public.fifo_cost_lots
  WHERE id = p_lot_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'LOT_NOT_FOUND'; END IF;

  IF v_uid IS NOT NULL AND v_role IN ('store_manager','warehouse_manager')
     AND v_member_branch IS NOT NULL
     AND v_lot.branch_id IS DISTINCT FROM v_member_branch THEN
    RAISE EXCEPTION 'LOT_SPLIT_FORBIDDEN: الدفعة خارج نطاق فرعك';
  END IF;

  -- only untouched lots can be split (no consumptions yet)
  IF v_lot.remaining_quantity <> v_lot.original_quantity
     OR EXISTS (SELECT 1 FROM public.fifo_lot_consumptions c WHERE c.lot_id = p_lot_id) THEN
    RAISE EXCEPTION 'LOT_SPLIT_NOT_ALLOWED: لا يمكن تقسيم دفعة بدأ الصرف منها — قسّمها فور الاستلام';
  END IF;

  IF p_splits IS NULL OR jsonb_typeof(p_splits) <> 'array' OR jsonb_array_length(p_splits) < 2 THEN
    RAISE EXCEPTION 'LOT_SPLIT_INVALID: التقسيم يحتاج سطرين على الأقل';
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_splits) LOOP
    v_qty := COALESCE((v_item->>'quantity')::numeric, 0);
    IF v_qty <= 0 THEN RAISE EXCEPTION 'LOT_SPLIT_INVALID: كل سطر يجب أن يحمل كمية موجبة'; END IF;
    v_sum := v_sum + v_qty;
  END LOOP;
  IF v_sum <> v_lot.original_quantity THEN
    RAISE EXCEPTION 'LOT_SPLIT_INVALID: مجموع الكميات (%) لا يساوى كمية الدفعة (%)', v_sum, v_lot.original_quantity;
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_splits) LOOP
    v_qty := (v_item->>'quantity')::numeric;
    IF v_first THEN
      -- first split keeps the original row (and its lot_number)
      UPDATE public.fifo_cost_lots
         SET original_quantity = v_qty,
             remaining_quantity = v_qty,
             expiry_date = COALESCE((v_item->>'expiry_date')::date, expiry_date),
             updated_at = NOW()
       WHERE id = p_lot_id;
      v_numbers := array_append(v_numbers, v_lot.lot_number);
      v_first := false;
    ELSE
      INSERT INTO public.fifo_cost_lots (
        company_id, product_id, lot_date, lot_type, reference_type, reference_id,
        original_quantity, remaining_quantity, unit_cost, notes,
        branch_id, warehouse_id, purchase_date, expiry_date
      ) VALUES (
        v_lot.company_id, v_lot.product_id, v_lot.lot_date, v_lot.lot_type,
        v_lot.reference_type, v_lot.reference_id,
        v_qty, v_qty, v_lot.unit_cost,
        COALESCE(v_lot.notes,'') || ' (مقسمة من ' || COALESCE(v_lot.lot_number,'?') || ')',
        v_lot.branch_id, v_lot.warehouse_id, v_lot.purchase_date,
        (v_item->>'expiry_date')::date
      ) RETURNING id INTO v_new_id;
      v_created := v_created + 1;
      v_numbers := array_append(v_numbers,
        (SELECT lot_number FROM public.fifo_cost_lots WHERE id = v_new_id));
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true, 'lots_created', v_created + 1,
    'lot_numbers', to_jsonb(v_numbers)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- start_booking_atomic(p_company_id uuid, p_booking_id uuid, p_started_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.start_booking_atomic(p_company_id uuid, p_booking_id uuid, p_started_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_booking public.bookings;
BEGIN
  SELECT * INTO v_booking FROM public.bookings WHERE id = p_booking_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Booking not found. booking_id=%', p_booking_id USING ERRCODE='P0001'; END IF;
  IF v_booking.status <> 'confirmed' THEN RAISE EXCEPTION 'Booking must be confirmed before starting. Current status: %. booking_id=%', v_booking.status, p_booking_id USING ERRCODE='P0001'; END IF;
  UPDATE public.bookings SET status='in_progress', started_by=p_started_by, started_at=NOW(), updated_by=p_started_by WHERE id=p_booking_id;
  RETURN jsonb_build_object('success',true,'booking_id',p_booking_id,'status','in_progress');
END; $function$
;

-- ---------------------------------------------------------------
-- start_manufacturing_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_started_by uuid, p_started_at timestamp with time zone)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.start_manufacturing_production_order_atomic(p_company_id uuid, p_production_order_id uuid, p_started_by uuid, p_started_at timestamp with time zone DEFAULT NULL::timestamp with time zone)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_order RECORD;
  v_started_at TIMESTAMPTZ := COALESCE(p_started_at, NOW());
  v_primed_operation_id UUID;
BEGIN
  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order not found or not in company. production_order_id=%', p_production_order_id;
  END IF;

  IF v_order.status NOT IN ('released', 'in_progress') THEN
    RAISE EXCEPTION 'Only released or in-progress production orders can be started. production_order_id=%, status=%',
      p_production_order_id, v_order.status;
  END IF;

  IF v_order.status = 'released' THEN
    UPDATE public.manufacturing_production_orders
       SET status = 'in_progress',
           started_at = COALESCE(started_at, v_started_at),
           started_by = COALESCE(started_by, p_started_by),
           updated_by = p_started_by
     WHERE id = p_production_order_id;

    IF NOT EXISTS (
      SELECT 1
        FROM public.manufacturing_production_order_operations
       WHERE production_order_id = p_production_order_id
         AND status IN ('ready', 'in_progress', 'completed')
    ) THEN
      SELECT id
        INTO v_primed_operation_id
        FROM public.manufacturing_production_order_operations
       WHERE production_order_id = p_production_order_id
         AND status = 'pending'
       ORDER BY operation_no
       LIMIT 1;

      IF v_primed_operation_id IS NOT NULL THEN
        UPDATE public.manufacturing_production_order_operations
           SET status = 'ready',
               updated_by = p_started_by
         WHERE id = v_primed_operation_id;
      END IF;
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', p_production_order_id,
    'previous_status', v_order.status,
    'status', CASE WHEN v_order.status = 'released' THEN 'in_progress' ELSE v_order.status END,
    'primed_operation_id', v_primed_operation_id,
    'started_at', COALESCE(v_order.started_at, v_started_at)
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- strict_word_similarity(text, text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.strict_word_similarity(text, text)
 RETURNS real
 LANGUAGE c
