-- ---------------------------------------------------------------
-- submit_debit_note_for_approval(p_debit_note_id uuid, p_submitted_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.submit_debit_note_for_approval(p_debit_note_id uuid, p_submitted_by uuid)
 RETURNS TABLE(success boolean, message text, requires_owner_approval boolean)
 LANGUAGE plpgsql
AS $function$ DECLARE v_debit_note RECORD; v_requires_owner BOOLEAN := FALSE; BEGIN SELECT * INTO v_debit_note FROM customer_debit_notes WHERE id = p_debit_note_id; IF NOT FOUND THEN RETURN QUERY SELECT FALSE, 'Debit note not found', FALSE; RETURN; END IF; IF v_debit_note.approval_status != 'draft' THEN RETURN QUERY SELECT FALSE, 'Debit note is not in draft status', FALSE; RETURN; END IF; IF v_debit_note.reference_type IN ('penalty', 'correction') THEN v_requires_owner := TRUE; END IF; UPDATE customer_debit_notes SET approval_status = 'pending_approval', updated_at = NOW() WHERE id = p_debit_note_id; RETURN QUERY SELECT TRUE, 'Debit note submitted for approval', v_requires_owner; END; $function$
;

-- ---------------------------------------------------------------
-- submit_manufacturing_bom_version_for_approval_atomic(p_company_id uuid, p_bom_version_id uuid, p_submitted_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.submit_manufacturing_bom_version_for_approval_atomic(p_company_id uuid, p_bom_version_id uuid, p_submitted_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version   RECORD;
  v_line_count INTEGER;
BEGIN
  SELECT * INTO v_version
    FROM public.manufacturing_bom_versions
   WHERE id = p_bom_version_id AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'BOM version not found. bom_version_id=%', p_bom_version_id;
  END IF;

  IF v_version.status NOT IN ('draft', 'rejected') THEN
    RAISE EXCEPTION 'Only draft or rejected versions can be submitted. current status=%', v_version.status;
  END IF;

  SELECT COUNT(*) INTO v_line_count
    FROM public.manufacturing_bom_lines
   WHERE bom_version_id = p_bom_version_id;

  IF v_line_count <= 0 THEN
    RAISE EXCEPTION 'BOM version must have at least one line. bom_version_id=%', p_bom_version_id;
  END IF;

  UPDATE public.manufacturing_bom_versions
     SET status           = 'pending_approval',
         submitted_by     = p_submitted_by,
         submitted_at     = NOW(),
         approved_by      = NULL,
         approved_at      = NULL,
         rejected_by      = NULL,
         rejected_at      = NULL,
         rejection_reason = NULL,
         updated_by       = p_submitted_by
   WHERE id = p_bom_version_id;

  RETURN jsonb_build_object(
    'success',        true,
    'bom_version_id', p_bom_version_id,
    'status',         'pending_approval'
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- submit_production_order_for_approval_atomic(p_company_id uuid, p_production_order_id uuid, p_submitted_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.submit_production_order_for_approval_atomic(p_company_id uuid, p_production_order_id uuid, p_submitted_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_po record;
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.company_members
     WHERE company_id = p_company_id AND user_id = p_submitted_by
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'المستخدم ليس عضواً فى هذه الشركة');
  END IF;

  SELECT * INTO v_po FROM public.manufacturing_production_orders
   WHERE id = p_production_order_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'أمر الإنتاج غير موجود');
  END IF;
  IF COALESCE(v_po.approval_status, 'draft') NOT IN ('draft', 'rejected') THEN
    RETURN jsonb_build_object('success', false,
      'error', 'لا يمكن إرسال هذا الأمر للاعتماد. الحالة الحالية: ' || v_po.approval_status);
  END IF;

  UPDATE public.manufacturing_production_orders
     SET approval_status = 'pending_approval',
         submitted_by    = p_submitted_by,
         submitted_at    = NOW()
   WHERE id = p_production_order_id;

  RETURN jsonb_build_object('success', true, 'approval_status', 'pending_approval');
END;
$function$
;

-- ---------------------------------------------------------------
-- submit_routing_version_for_approval_atomic(p_company_id uuid, p_routing_version_id uuid, p_submitted_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.submit_routing_version_for_approval_atomic(p_company_id uuid, p_routing_version_id uuid, p_submitted_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_rv record;
BEGIN
  IF NOT EXISTS (
