     WHERE company_id = p_company_id AND user_id = p_submitted_by
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'المستخدم ليس عضواً فى هذه الشركة');
  END IF;

  SELECT * INTO v_rv FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id AND company_id = p_company_id FOR UPDATE;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'النسخة غير موجودة');
  END IF;
  IF COALESCE(v_rv.approval_status, 'draft') NOT IN ('draft', 'rejected') THEN
