-- ---------------------------------------------------------------
-- suggest_fix_for_unbalanced_entry(p_journal_entry_id uuid, p_account_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.suggest_fix_for_unbalanced_entry(p_journal_entry_id uuid, p_account_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(journal_entry_id uuid, current_debit numeric, current_credit numeric, difference numeric, suggested_debit numeric, suggested_credit numeric, account_suggestion uuid)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_debit DECIMAL;
  v_credit DECIMAL;
  v_diff DECIMAL;
  v_account UUID;
BEGIN
  -- حساب المبالغ الحالية
  SELECT 
    COALESCE(SUM(debit_amount), 0),
    COALESCE(SUM(credit_amount), 0)
  INTO v_debit, v_credit
  FROM journal_entry_lines
  WHERE journal_entry_id = p_journal_entry_id;

  v_diff := ABS(v_debit - v_credit);

  -- إذا كان هناك حساب محدد، استخدمه
  -- وإلا، ابحث عن حساب مناسب
  IF p_account_id IS NOT NULL THEN
    v_account := p_account_id;
  ELSE
    -- البحث عن حساب مصروف أو تكلفة كاقتراح
    SELECT id INTO v_account
    FROM chart_of_accounts
    WHERE account_type IN ('Expense', 'Cost of Goods Sold')
    LIMIT 1;
  END IF;

  RETURN QUERY
  SELECT 
    p_journal_entry_id,
    v_debit,
    v_credit,
    v_diff,
    CASE WHEN v_credit > v_debit THEN v_diff ELSE 0 END as suggested_debit,
    CASE WHEN v_debit > v_credit THEN v_diff ELSE 0 END as suggested_credit,
    v_account;
END;
$function$
;

-- ---------------------------------------------------------------
-- suspend_subscription(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.suspend_subscription(p_company_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_status text;
BEGIN
  SELECT subscription_status INTO v_status
  FROM companies WHERE id = p_company_id FOR UPDATE;

  IF v_status IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'company_not_found');
  END IF;

  IF v_status = 'payment_failed' THEN
    RETURN json_build_object('success', true, 'idempotent', true);
  END IF;

  UPDATE companies
  SET subscription_status = 'payment_failed',
      suspended_at = now()
  WHERE id = p_company_id;

  UPDATE company_seats
  SET status = 'suspended', updated_at = now()
  WHERE company_id = p_company_id;

  -- Audit log — non-blocking
  BEGIN
    INSERT INTO audit_logs(action, company_id, target_table, new_data)
    VALUES (
      'subscription_suspended',
      p_company_id,
      'companies',
      json_build_object('previous_status', v_status, 'reason', 'grace_period_exceeded')::jsonb
    );
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN json_build_object('success', true, 'suspended', true);
END;
$function$
;

-- ---------------------------------------------------------------
-- svc_assert_service_accessible(p_service_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_assert_service_accessible(p_service_id uuid, p_company_id uuid)
 RETURNS services
 LANGUAGE plpgsql
AS $function$
DECLARE v_service public.services;
BEGIN
  SELECT * INTO v_service FROM public.services WHERE id = p_service_id AND company_id = p_company_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Service not found or not accessible. service_id=%, company_id=%', p_service_id, p_company_id USING ERRCODE = 'P0001';
  END IF;
  RETURN v_service;
END; $function$
;

-- ---------------------------------------------------------------
-- svc_assert_service_bookable(p_service_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_assert_service_bookable(p_service_id uuid, p_company_id uuid)
 RETURNS services
 LANGUAGE plpgsql
AS $function$
DECLARE v_service public.services;
BEGIN
  v_service := public.svc_assert_service_accessible(p_service_id, p_company_id);
  IF NOT v_service.is_active THEN
    RAISE EXCEPTION 'Service is not active. service_id=%', p_service_id USING ERRCODE = 'P0001';
  END IF;
  IF NOT v_service.is_bookable THEN
    RAISE EXCEPTION 'Service is not open for booking. service_id=%', p_service_id USING ERRCODE = 'P0001';
  END IF;
  RETURN v_service;
END; $function$
;

-- ---------------------------------------------------------------
-- svc_generate_service_code(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_generate_service_code(p_company_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_next INTEGER;
BEGIN
  SELECT COALESCE(
    MAX(
      CASE
        WHEN service_code ~ '^SVC-[0-9]+$'
        THEN CAST(SPLIT_PART(service_code, '-', 2) AS INTEGER)
        ELSE 0
      END
    ), 0
  ) + 1
  INTO v_next
  FROM public.services
  WHERE company_id = p_company_id;

  RETURN 'SVC-' || LPAD(v_next::TEXT, 4, '0');
END;
$function$
;

-- ---------------------------------------------------------------
-- svc_guard_service_code_immutable()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_guard_service_code_immutable()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.service_code IS DISTINCT FROM OLD.service_code THEN
    RAISE EXCEPTION 'service_code is immutable after creation. service_id=%', OLD.id USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END; $function$
;

-- ---------------------------------------------------------------
-- svc_inherit_pricing_from_product()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_inherit_pricing_from_product()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_product RECORD;
BEGIN
  IF NEW.product_catalog_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT name, unit_price, cost_price, income_account_id, expense_account_id
  INTO v_product
  FROM public.products
  WHERE id          = NEW.product_catalog_id
    AND company_id  = NEW.company_id
    AND item_type   = 'service';

  IF NOT FOUND THEN
    RAISE EXCEPTION
      'product_catalog_id (%) must reference a product with item_type=service in company (%).',
      NEW.product_catalog_id, NEW.company_id
      USING ERRCODE = 'P0001';
  END IF;

  NEW.service_name        := v_product.name;
  NEW.unit_price          := COALESCE(v_product.unit_price, 0);
  NEW.cost_price          := COALESCE(v_product.cost_price, 0);
  NEW.revenue_account_id  := v_product.income_account_id;
  NEW.expense_account_id  := v_product.expense_account_id;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- svc_is_valid_service_type(p_type text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_is_valid_service_type(p_type text)
 RETURNS boolean
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT COALESCE(BTRIM(p_type), '') IN ('individual','group','hourly','session','daily');
$function$
;

-- ---------------------------------------------------------------
-- svc_set_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN NEW.updated_at := NOW(); RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- svc_sync_from_product()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_sync_from_product()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.item_type IS DISTINCT FROM 'service' THEN
    RETURN NEW;
  END IF;

  IF OLD.name               IS NOT DISTINCT FROM NEW.name
     AND OLD.unit_price         IS NOT DISTINCT FROM NEW.unit_price
     AND OLD.cost_price         IS NOT DISTINCT FROM NEW.cost_price
     AND OLD.income_account_id  IS NOT DISTINCT FROM NEW.income_account_id
     AND OLD.expense_account_id IS NOT DISTINCT FROM NEW.expense_account_id
  THEN
    RETURN NEW;
  END IF;

  UPDATE public.services
     SET service_name       = NEW.name,
         unit_price         = COALESCE(NEW.unit_price, 0),
         cost_price         = COALESCE(NEW.cost_price, 0),
         revenue_account_id = NEW.income_account_id,
         expense_account_id = NEW.expense_account_id,
         updated_at         = NOW()
   WHERE product_catalog_id = NEW.id
     AND company_id         = NEW.company_id;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- svc_trg_validate_schedule()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_trg_validate_schedule()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_exclude_id uuid;
BEGIN
  IF TG_OP = 'UPDATE' THEN
    v_exclude_id := OLD.id;
  ELSE
    -- INSERT path: if there is already a row with the same
    -- (service_id, day_of_week) the UPSERT will turn this into an
    -- update of that row, so treat it as "self" for overlap purposes.
    SELECT id
      INTO v_exclude_id
      FROM public.service_schedules
     WHERE service_id  = NEW.service_id
       AND day_of_week = NEW.day_of_week
     LIMIT 1;
  END IF;

  PERFORM public.svc_validate_schedule_no_overlap(
    NEW.service_id,
    NEW.day_of_week,
    NEW.start_time,
    NEW.end_time,
    v_exclude_id
  );
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- svc_validate_product_catalog_company()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_validate_product_catalog_company()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.product_catalog_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF NOT EXISTS (
    SELECT 1
      FROM public.products
     WHERE id          = NEW.product_catalog_id
       AND company_id  = NEW.company_id
       AND item_type   = 'service'
  ) THEN
    RAISE EXCEPTION
      'product_catalog_id (%) must reference a product with item_type=''service'' in the same company (%). '
      'Check that the product exists, belongs to company_id=%, and has item_type=''service''.',
      NEW.product_catalog_id, NEW.company_id, NEW.company_id
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- svc_validate_schedule_no_overlap(p_service_id uuid, p_day_of_week integer, p_start_time time without time zone, p_end_time time without time zone, p_exclude_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.svc_validate_schedule_no_overlap(p_service_id uuid, p_day_of_week integer, p_start_time time without time zone, p_end_time time without time zone, p_exclude_id uuid DEFAULT NULL::uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE v_conflict_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_conflict_count FROM public.service_schedules
   WHERE service_id = p_service_id AND day_of_week = p_day_of_week AND is_active = true
     AND id IS DISTINCT FROM p_exclude_id
     AND (start_time, end_time) OVERLAPS (p_start_time, p_end_time);
  IF v_conflict_count > 0 THEN
    RAISE EXCEPTION 'Schedule slot overlaps an existing active slot for this service on day %. service_id=%', p_day_of_week, p_service_id USING ERRCODE = 'P0001';
  END IF;
END; $function$
;

-- ---------------------------------------------------------------
-- swap_seat_numbers(p_company_id uuid, p_seat_a integer, p_seat_b integer, p_actor_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.swap_seat_numbers(p_company_id uuid, p_seat_a integer, p_seat_b integer, p_actor_user_id uuid DEFAULT NULL::uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_owner_id        uuid;
  v_license_a_id    uuid;
  v_license_b_id    uuid;
  v_user_before_a   uuid;
  v_user_before_b   uuid;
BEGIN
  SELECT user_id INTO v_owner_id FROM public.companies WHERE id = p_company_id;
  IF v_owner_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'company_not_found');
  END IF;

  IF p_seat_a = 0 OR p_seat_b = 0 THEN
    RETURN json_build_object('success', false, 'error', 'cannot_swap_owner_seat');
  END IF;

  IF p_seat_a = p_seat_b THEN
    RETURN json_build_object('success', true, 'no_op', true);
  END IF;

  PERFORM pg_advisory_xact_lock(hashtext(p_company_id::text));

  SELECT id, assigned_user_id INTO v_license_a_id, v_user_before_a
    FROM public.company_seat_licenses
   WHERE company_id = p_company_id AND seat_number = p_seat_a
   LIMIT 1;

  SELECT id, assigned_user_id INTO v_license_b_id, v_user_before_b
    FROM public.company_seat_licenses
   WHERE company_id = p_company_id AND seat_number = p_seat_b
   LIMIT 1;

  IF v_license_a_id IS NULL OR v_license_b_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'license_not_found');
  END IF;

  IF v_user_before_a IS NULL AND v_user_before_b IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'both_seats_empty');
  END IF;

  UPDATE public.company_seat_licenses
     SET assigned_user_id = NULL, assigned_at = NULL, updated_at = NOW()
   WHERE id = v_license_a_id;

  UPDATE public.company_seat_licenses
     SET assigned_user_id = v_user_before_a,
         assigned_at      = CASE WHEN v_user_before_a IS NOT NULL THEN NOW() ELSE NULL END,
         updated_at       = NOW()
   WHERE id = v_license_b_id;

  UPDATE public.company_seat_licenses
     SET assigned_user_id = v_user_before_b,
         assigned_at      = CASE WHEN v_user_before_b IS NOT NULL THEN NOW() ELSE NULL END,
         updated_at       = NOW()
   WHERE id = v_license_a_id;

  IF v_user_before_a IS NOT NULL THEN
    UPDATE public.company_members SET seat_number = p_seat_b
     WHERE company_id = p_company_id AND user_id = v_user_before_a;
  END IF;
  IF v_user_before_b IS NOT NULL THEN
    UPDATE public.company_members SET seat_number = p_seat_a
     WHERE company_id = p_company_id AND user_id = v_user_before_b;
  END IF;

  BEGIN
    INSERT INTO public.audit_logs (
      action, company_id, target_table, new_data, user_id
    ) VALUES (
      'seat_swap', p_company_id, 'company_seat_licenses',
      json_build_object(
        'seat_a', p_seat_a, 'seat_b', p_seat_b,
        'license_a_id', v_license_a_id, 'license_b_id', v_license_b_id,
        'user_on_a_before', v_user_before_a, 'user_on_b_before', v_user_before_b,
        'user_on_a_after',  v_user_before_b, 'user_on_b_after',  v_user_before_a,
        'performed_by', p_actor_user_id, 'performed_at', NOW()
      )::jsonb,
      p_actor_user_id
    );
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN json_build_object('success', true,
    'swapped', json_build_object(
      'a', p_seat_a, 'b', p_seat_b,
      'user_on_a', v_user_before_b, 'user_on_b', v_user_before_a
    )
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_all_companies_chart_of_accounts()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_all_companies_chart_of_accounts()
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_company_record RECORD;
    v_result JSON;
    v_results JSON[] := ARRAY[]::JSON[];
    v_total_changes INTEGER := 0;
    v_total_added INTEGER := 0;
    v_total_linked INTEGER := 0;
    v_success_count INTEGER := 0;
    v_error_count INTEGER := 0;
BEGIN
    -- Loop through all companies
    FOR v_company_record IN SELECT id, name FROM companies ORDER BY name LOOP
        RAISE NOTICE 'Syncing chart of accounts for company: %', v_company_record.name;

        -- تنفيذ التوحيد للشركة
        v_result := sync_company_chart_of_accounts(v_company_record.id);

        -- تجميع النتائج
        v_results := array_append(v_results, json_build_object(
            'company_id', v_company_record.id,
            'company_name', v_company_record.name,
            'result', v_result
        ));

        -- تحديث المجاميع
        IF (v_result->>'success')::BOOLEAN = true THEN
            v_success_count := v_success_count + 1;
            v_total_changes := v_total_changes + (v_result->>'total_changes')::INTEGER;
            v_total_added := v_total_added + (v_result->>'accounts_added')::INTEGER;
            v_total_linked := v_total_linked + (v_result->>'accounts_linked')::INTEGER;
        ELSE
            v_error_count := v_error_count + 1;
        END IF;
    END LOOP;

    -- إرجاع التقرير النهائي
    RETURN json_build_object(
        'success', true,
        'total_companies', array_length(v_results, 1),
        'successful_syncs', v_success_count,
        'failed_syncs', v_error_count,
        'total_changes', v_total_changes,
        'total_accounts_added', v_total_added,
        'total_accounts_linked', v_total_linked,
        'company_results', v_results,
        'message', format('تم توحيد %s شركة: %s ناجحة، %s فاشلة، %s تغيير إجمالي',
                         array_length(v_results, 1), v_success_count, v_error_count, v_total_changes)
    );

EXCEPTION WHEN OTHERS THEN
    RETURN json_build_object(
        'success', false,
        'error', SQLERRM,
        'error_detail', SQLSTATE
    );
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_all_stock_quantities(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_all_stock_quantities(p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$ DECLARE v_fixed_count INTEGER := 0; BEGIN UPDATE products p SET quantity_on_hand = ( SELECT COALESCE(SUM(it.quantity_change), 0) FROM inventory_transactions it WHERE it.product_id = p.id AND (it.is_deleted IS NULL OR it.is_deleted = false) ) WHERE p.company_id = p_company_id AND p.quantity_on_hand != ( SELECT COALESCE(SUM(it.quantity_change), 0) FROM inventory_transactions it WHERE it.product_id = p.id AND (it.is_deleted IS NULL OR it.is_deleted = false) ); GET DIAGNOSTICS v_fixed_count = ROW_COUNT; RETURN jsonb_build_object('success', true, 'fixed_count', v_fixed_count); END; $function$
;

-- ---------------------------------------------------------------
-- sync_bill_status_on_discount_decision_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_bill_status_on_discount_decision_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.document_type = 'purchase_invoice'
     AND NEW.status IN ('approved','rejected')
     AND (OLD.status IS DISTINCT FROM NEW.status) THEN

    IF NEW.status = 'approved' THEN
      -- Owner approved the amendment. Return the bill to draft so
      -- the accountant can post it (posting = normal draft flow).
      -- v3.74.500: refresh the approved baselines from the bill's
      -- current amounts so the re-approval trigger stops firing.
      UPDATE public.bills
         SET status = 'draft',
             approval_status = 'approved',
             approved_by = NEW.decided_by,
             approved_at = NEW.decided_at,
             original_total = total_amount,
             original_subtotal = subtotal,
             original_tax_amount = tax_amount,
             updated_at = NOW()
       WHERE id = NEW.document_id
         AND status = 'pending_approval';
    ELSIF NEW.status = 'rejected' THEN
      -- Owner rejected the amendment. Bill stays pending; accountant
      -- must re-edit to re-submit.
      UPDATE public.bills
         SET approval_status = 'rejected',
             receipt_rejection_reason = NEW.decision_note,
             updated_at = NOW()
       WHERE id = NEW.document_id
         AND status = 'pending_approval';
    END IF;

  ELSIF NEW.document_type = 'sales_invoice'
        AND NEW.status IN ('approved','rejected')
        AND (OLD.status IS DISTINCT FROM NEW.status) THEN

    IF NEW.status = 'approved' THEN
      UPDATE public.invoices
         SET status = 'draft',
             updated_at = NOW()
       WHERE id = NEW.document_id
         AND status = 'pending_approval';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_bill_to_purchase_order_safe()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_bill_to_purchase_order_safe()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  po_record RECORD;
  v_new_status text;
BEGIN
  IF NEW.purchase_order_id IS NULL THEN RETURN NEW; END IF;
  SELECT * INTO po_record FROM purchase_orders WHERE id = NEW.purchase_order_id;
  IF po_record IS NULL THEN RETURN NEW; END IF;
  IF NEW.status IN ('paid', 'partially_paid') THEN
    v_new_status := 'billed';
  ELSE
    v_new_status := po_record.status;
  END IF;
  IF COALESCE(po_record.returned_amount, 0) = COALESCE(NEW.returned_amount, 0)
     AND COALESCE(po_record.return_status, '') = COALESCE(NEW.return_status, '')
     AND po_record.status = v_new_status THEN
    RETURN NEW;
  END IF;
  UPDATE purchase_orders
     SET returned_amount = NEW.returned_amount,
         return_status   = NEW.return_status,
         status          = v_new_status,
         updated_at      = NOW()
   WHERE id = NEW.purchase_order_id;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_booking_from_invoice_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_booking_from_invoice_trg()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.paid_amount IS NOT DISTINCT FROM OLD.paid_amount
     AND NEW.status IS NOT DISTINCT FROM OLD.status
     AND NEW.returned_amount IS NOT DISTINCT FROM OLD.returned_amount THEN
    RETURN NEW;
  END IF;

  UPDATE public.bookings
     SET paid_amount = LEAST(COALESCE(NEW.paid_amount, 0), total_amount),
         payment_status = CASE
           WHEN COALESCE(NEW.paid_amount, 0) <= 0 THEN 'unpaid'
           WHEN COALESCE(NEW.paid_amount, 0) >= total_amount THEN 'paid'
           ELSE 'partial'
         END,
         updated_at = NOW()
   WHERE invoice_id = NEW.id;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_company_chart_of_accounts(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_company_chart_of_accounts(p_company_id uuid)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_template_record RECORD;
    v_existing_account RECORD;
    v_parent_id UUID;
    v_new_account_id UUID;
    v_changes_count INTEGER := 0;
    v_accounts_added INTEGER := 0;
    v_accounts_linked INTEGER := 0;
    v_accounts_updated INTEGER := 0;
    v_result JSON;
    v_has_journal_entries BOOLEAN := FALSE;
BEGIN
    -- Loop through template accounts
    FOR v_template_record IN SELECT * FROM chart_of_accounts_template ORDER BY level, account_code LOOP

        -- التحقق من وجود الحساب
        SELECT * INTO v_existing_account
        FROM chart_of_accounts
        WHERE company_id = p_company_id AND account_code = v_template_record.account_code;

        IF v_existing_account IS NULL THEN
            -- الحساب غير موجود - إضافته

            -- البحث عن parent_id إذا كان مطلوباً
            IF v_template_record.parent_code IS NOT NULL THEN
                SELECT id INTO v_parent_id
                FROM chart_of_accounts
                WHERE company_id = p_company_id AND account_code = v_template_record.parent_code;

                -- إذا لم يوجد parent، نبحث عن أي حساب مناسب
                IF v_parent_id IS NULL THEN
                    SELECT id INTO v_parent_id
                    FROM chart_of_accounts
                    WHERE company_id = p_company_id
                      AND account_type = v_template_record.account_type
                      AND level = v_template_record.level - 1
                      AND account_code LIKE substring(v_template_record.account_code, 1, length(v_template_record.account_code) - 1) || '%'
                    LIMIT 1;
                END IF;
            END IF;

            -- إدراج الحساب الجديد
            INSERT INTO chart_of_accounts (
                company_id, account_code, account_name, account_type, normal_balance,
                sub_type, parent_id, level, is_active
            ) VALUES (
                p_company_id,
                v_template_record.account_code,
                v_template_record.account_name,
                v_template_record.account_type,
                v_template_record.normal_balance,
                v_template_record.sub_type,
                v_parent_id,
                v_template_record.level,
                true
            ) RETURNING id INTO v_new_account_id;

            v_accounts_added := v_accounts_added + 1;
            v_changes_count := v_changes_count + 1;

            -- تسجيل في audit_logs
            INSERT INTO audit_logs (
                company_id, action, target_table, record_id, old_data, new_data, reason
            ) VALUES (
                p_company_id,
                'INSERT',
                'chart_of_accounts',
                v_new_account_id,
                NULL,
                json_build_object(
                    'account_code', v_template_record.account_code,
                    'account_name', v_template_record.account_name,
                    'account_type', v_template_record.account_type
                ),
                'Chart of accounts sync: added missing account from template'
            );

        ELSE
            -- الحساب موجود - التحقق من الربط والتصنيف والاسم

            -- التحقق من وجود قيود محاسبية
            SELECT EXISTS(
                SELECT 1 FROM journal_entry_lines
                WHERE account_id = v_existing_account.id
                LIMIT 1
            ) INTO v_has_journal_entries;

            -- تحديث الاسم إذا لم يكن هناك قيود محاسبية وكان الاسم مختلف
            IF NOT v_has_journal_entries AND v_existing_account.account_name != v_template_record.account_name THEN
                UPDATE chart_of_accounts
                SET account_name = v_template_record.account_name,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = v_existing_account.id;

                v_accounts_updated := v_accounts_updated + 1;
                v_changes_count := v_changes_count + 1;

                -- تسجيل في audit_logs
                INSERT INTO audit_logs (
                    company_id, action, target_table, record_id, old_data, new_data, reason
                ) VALUES (
                    p_company_id,
                    'UPDATE',
                    'chart_of_accounts',
                    v_existing_account.id,
                    json_build_object('account_name', v_existing_account.account_name),
                    json_build_object('account_name', v_template_record.account_name),
                    'Chart of accounts sync: updated account name (no journal entries)'
                );
            END IF;

            -- البحث عن parent_id الصحيح
            v_parent_id := NULL;
            IF v_template_record.parent_code IS NOT NULL THEN
                SELECT id INTO v_parent_id
                FROM chart_of_accounts
                WHERE company_id = p_company_id AND account_code = v_template_record.parent_code;
            END IF;

            -- تحديث parent_id إذا كان فارغاً أو خاطئاً
            IF (v_existing_account.parent_id IS NULL OR v_existing_account.parent_id != v_parent_id) AND v_parent_id IS NOT NULL THEN
                UPDATE chart_of_accounts
                SET parent_id = v_parent_id,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = v_existing_account.id;

                v_accounts_linked := v_accounts_linked + 1;
                v_changes_count := v_changes_count + 1;

                -- تسجيل في audit_logs
                INSERT INTO audit_logs (
                    company_id, action, target_table, record_id, old_data, new_data, reason
                ) VALUES (
                    p_company_id,
                    'UPDATE',
                    'chart_of_accounts',
                    v_existing_account.id,
                    json_build_object('parent_id', v_existing_account.parent_id),
                    json_build_object('parent_id', v_parent_id),
                    'Chart of accounts sync: linked to correct parent'
                );
            END IF;

            -- تحديث sub_type إذا كان فارغاً ومطلوب
            IF v_existing_account.sub_type IS NULL AND v_template_record.sub_type IS NOT NULL THEN
                UPDATE chart_of_accounts
                SET sub_type = v_template_record.sub_type,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = v_existing_account.id;

                v_changes_count := v_changes_count + 1;

                -- تسجيل في audit_logs
                INSERT INTO audit_logs (
                    company_id, action, target_table, record_id, old_data, new_data, reason
                ) VALUES (
                    p_company_id,
                    'UPDATE',
                    'chart_of_accounts',
                    v_existing_account.id,
                    json_build_object('sub_type', v_existing_account.sub_type),
                    json_build_object('sub_type', v_template_record.sub_type),
                    'Chart of accounts sync: updated sub_type'
                );
            END IF;
        END IF;
    END LOOP;

    -- إرجاع تقرير العملية
    v_result := json_build_object(
        'success', true,
        'company_id', p_company_id,
        'total_changes', v_changes_count,
        'accounts_added', v_accounts_added,
        'accounts_linked', v_accounts_linked,
        'accounts_updated', v_accounts_updated,
        'message', format('تم توحيد الشجرة المحاسبية: %s تغيير (%s مضاف، %s مربوط، %s محدث)',
                         v_changes_count, v_accounts_added, v_accounts_linked, v_accounts_updated)
    );

    RETURN v_result;

EXCEPTION WHEN OTHERS THEN
    -- في حالة الخطأ، نعيد JSON مع تفاصيل الخطأ
    RETURN json_build_object(
        'success', false,
        'company_id', p_company_id,
        'error', SQLERRM,
        'error_detail', SQLSTATE
    );
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_company_member_seat_number_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_company_member_seat_number_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    IF OLD.assigned_user_id IS NOT NULL THEN
      UPDATE public.company_members
         SET seat_number = NULL
       WHERE company_id  = OLD.company_id
         AND user_id     = OLD.assigned_user_id
         AND seat_number = OLD.seat_number;
    END IF;
    RETURN OLD;
  END IF;

  -- INSERT or UPDATE
  -- If the old assignment changed, clear the old member's seat_number
  IF TG_OP = 'UPDATE'
     AND OLD.assigned_user_id IS NOT NULL
     AND OLD.assigned_user_id IS DISTINCT FROM NEW.assigned_user_id THEN
    UPDATE public.company_members
       SET seat_number = NULL
     WHERE company_id  = OLD.company_id
       AND user_id     = OLD.assigned_user_id
       AND seat_number = OLD.seat_number;
  END IF;

  -- Set the new member's seat_number to NEW.seat_number
  IF NEW.assigned_user_id IS NOT NULL THEN
    UPDATE public.company_members
       SET seat_number = NEW.seat_number
     WHERE company_id = NEW.company_id
       AND user_id    = NEW.assigned_user_id
       AND (seat_number IS NULL OR seat_number IS DISTINCT FROM NEW.seat_number);
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_customer_credit_to_ledger()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_customer_credit_to_ledger()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_remaining   numeric;
  v_source_type text;
BEGIN
  v_remaining := NEW.amount - COALESCE(NEW.used_amount, 0) - COALESCE(NEW.applied_amount, 0);

  IF NEW.status <> 'active' OR v_remaining <= 0.01 THEN
    RETURN NEW;
  END IF;

  v_source_type := CASE
    WHEN NEW.reference_type IN ('overpayment', 'manual_credit') THEN NEW.reference_type
    ELSE 'sales_return'
  END;

  IF NOT EXISTS (
    SELECT 1 FROM public.customer_credit_ledger
    WHERE company_id  = NEW.company_id
      AND customer_id = NEW.customer_id
      AND source_id   = NEW.id
  ) THEN
    INSERT INTO public.customer_credit_ledger (
      company_id, customer_id, source_type, source_id,
      amount, description, created_by
    ) VALUES (
      NEW.company_id, NEW.customer_id,
      v_source_type,
      NEW.id,
      v_remaining,
      COALESCE(NEW.notes, 'Auto-mirrored from customer_credits ' || COALESCE(NEW.credit_number, NEW.id::text)),
      NULL
    );
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_customer_debit_note_applied_amount()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_customer_debit_note_applied_amount()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total_applied DECIMAL(15,2);
BEGIN
  -- Calculate total applied amount for this debit note
  SELECT COALESCE(SUM(amount_applied), 0)
  INTO v_total_applied
  FROM customer_debit_note_applications
  WHERE customer_debit_note_id = COALESCE(NEW.customer_debit_note_id, OLD.customer_debit_note_id);
  
  -- Update the debit note's applied_amount
  UPDATE customer_debit_notes
  SET applied_amount = v_total_applied
  WHERE id = COALESCE(NEW.customer_debit_note_id, OLD.customer_debit_note_id);
  
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_display_totals_from_total()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_display_totals_from_total()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Base-currency rows only. FX rows store the localised total in
  -- display_/original_ and need explicit values from the caller.
  IF NEW.exchange_rate IS NULL OR NEW.exchange_rate = 1 THEN
    IF NEW.total_amount IS DISTINCT FROM OLD.total_amount THEN
      NEW.display_total := NEW.total_amount;
      NEW.original_total := NEW.total_amount;
    END IF;
    IF NEW.subtotal IS DISTINCT FROM OLD.subtotal THEN
      NEW.display_subtotal := NEW.subtotal;
      NEW.original_subtotal := NEW.subtotal;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_document_paid_amount()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_document_paid_amount()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_invoice_id UUID;
  v_bill_id    UUID;
BEGIN
  v_invoice_id := COALESCE(NEW.invoice_id, OLD.invoice_id);
  v_bill_id    := COALESCE(NEW.bill_id,    OLD.bill_id);

  IF v_bill_id IS NOT NULL THEN
    PERFORM public.fn_recalc_bill_paid_status(v_bill_id);
  END IF;

  IF v_invoice_id IS NOT NULL THEN
    -- Use the invoice-side helper if it exists; fall back to the
    -- untouched sync for invoices to avoid disturbing the sales flow
    -- until the customer-side FX is retested.
    IF EXISTS (
      SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = 'public' AND p.proname = 'fn_recalc_invoice_paid_status'
    ) THEN
      PERFORM public.fn_recalc_invoice_paid_status(v_invoice_id);
    ELSE
      DECLARE v_new_paid NUMERIC;
      BEGIN
        SELECT COALESCE(SUM(p.amount), 0) INTO v_new_paid
        FROM payments p
        WHERE p.invoice_id = v_invoice_id
          AND p.status = 'approved'
          AND (p.is_deleted IS NULL OR p.is_deleted = false);
        UPDATE invoices
        SET paid_amount = GREATEST(v_new_paid, 0), updated_at = NOW()
        WHERE id = v_invoice_id;
      END;
    END IF;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_employee_user_id_from_member()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_employee_user_id_from_member()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP = 'DELETE' THEN
    IF OLD.employee_id IS NOT NULL THEN
      UPDATE public.employees SET user_id = NULL
       WHERE id = OLD.employee_id AND user_id = OLD.user_id;
    END IF;
    RETURN OLD;
  END IF;

  IF NEW.employee_id IS NOT NULL THEN
    UPDATE public.employees SET user_id = NEW.user_id
     WHERE id = NEW.employee_id
       AND company_id = NEW.company_id
       AND user_id IS DISTINCT FROM NEW.user_id;
  END IF;

  IF TG_OP = 'UPDATE'
     AND OLD.employee_id IS NOT NULL
     AND (NEW.employee_id IS NULL OR NEW.employee_id <> OLD.employee_id) THEN
    UPDATE public.employees SET user_id = NULL
     WHERE id = OLD.employee_id AND user_id = OLD.user_id;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_invited_users_currency()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_invited_users_currency()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.base_currency IS DISTINCT FROM NEW.base_currency THEN
    UPDATE company_members
    SET preferred_currency = NEW.base_currency
    WHERE company_id = NEW.id
      AND user_id != NEW.user_id
      AND COALESCE(currency_sync_enabled, TRUE) = TRUE;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_invoice_to_sales_order()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_invoice_to_sales_order()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ BEGIN IF NEW.sales_order_id IS NOT NULL THEN UPDATE sales_orders SET subtotal = NEW.subtotal, tax_amount = NEW.tax_amount, total = NEW.total_amount, returned_amount = NEW.returned_amount, return_status = NEW.return_status, status = CASE WHEN NEW.status = 'fully_returned' THEN 'fully_returned' WHEN NEW.status = 'partially_returned' THEN 'partially_returned' WHEN NEW.status = 'paid' THEN 'paid' WHEN NEW.status = 'partially_paid' THEN 'partially_paid' WHEN NEW.status = 'sent' THEN 'sent' ELSE status END, updated_at = NOW() WHERE id = NEW.sales_order_id; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- sync_invoice_to_sales_order_safe()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_invoice_to_sales_order_safe()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  so_record RECORD;
BEGIN
  IF NEW.sales_order_id IS NULL THEN RETURN NEW; END IF;
  SELECT * INTO so_record FROM sales_orders WHERE id = NEW.sales_order_id;
  IF so_record IS NULL THEN RETURN NEW; END IF;
  IF COALESCE(so_record.returned_amount, 0) = COALESCE(NEW.returned_amount, 0)
     AND COALESCE(so_record.return_status, '') = COALESCE(NEW.return_status, '')
     AND so_record.status = NEW.status THEN
    RETURN NEW;
  END IF;
  UPDATE sales_orders
     SET returned_amount = NEW.returned_amount,
         return_status   = NEW.return_status,
         status          = NEW.status,
         updated_at      = NOW()
   WHERE id = NEW.sales_order_id;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_invoice_warehouse_from_items_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_invoice_warehouse_from_items_trg()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_invoice_id uuid := COALESCE(NEW.invoice_id, OLD.invoice_id);
  v_inv record;
  v_goods integer;
BEGIN
  SELECT id, status, warehouse_status INTO v_inv
  FROM public.invoices WHERE id = v_invoice_id;
  IF v_inv.id IS NULL THEN RETURN COALESCE(NEW, OLD); END IF;

  -- Only self-correct while the document is still a draft; after posting
  -- the warehouse flow owns this column.
  IF v_inv.status <> 'draft' THEN RETURN COALESCE(NEW, OLD); END IF;

  SELECT COUNT(*) INTO v_goods
    FROM public.invoice_items
   WHERE invoice_id = v_invoice_id
     AND COALESCE(item_type, 'product') NOT IN ('service');

  IF v_goods = 0 AND COALESCE(v_inv.warehouse_status,'') = 'pending' THEN
    UPDATE public.invoices SET warehouse_status = 'approved', updated_at = NOW()
     WHERE id = v_invoice_id;
  ELSIF v_goods > 0 AND COALESCE(v_inv.warehouse_status,'') = 'approved' THEN
    UPDATE public.invoices SET warehouse_status = 'pending', updated_at = NOW()
     WHERE id = v_invoice_id;
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_legacy_customer_payment_allocation()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_legacy_customer_payment_allocation()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- v3.74.545 — skip VOID rows and non-positive payments (see the
  -- vendor mirror for the full rationale).
  IF NEW.voids_payment_id IS NOT NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.amount IS NULL OR NEW.amount <= 0 THEN
    RETURN NEW;
  END IF;

  IF NEW.invoice_id IS NOT NULL AND NEW.customer_id IS NOT NULL THEN
    INSERT INTO payment_allocations (payment_id, invoice_id, allocated_amount, company_id, created_at)
    VALUES (NEW.id, NEW.invoice_id, NEW.amount, NEW.company_id, NEW.created_at)
    ON CONFLICT DO NOTHING;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_legacy_payment_allocation()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_legacy_payment_allocation()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- v3.74.545 — VOID rows and zero/negative payments must not create
  -- allocations. bills.paid_amount reversal is handled by the
  -- correction RPC directly; allocations for VOID rows would break
  -- the CHECK (allocated_amount > 0) constraint and are semantically
  -- meaningless (an allocation of "how much of this payment paid a
  -- bill" cannot be negative).
  IF NEW.voids_payment_id IS NOT NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.amount IS NULL OR NEW.amount <= 0 THEN
    RETURN NEW;
  END IF;

  IF NEW.bill_id IS NOT NULL THEN
    INSERT INTO payment_allocations (payment_id, bill_id, allocated_amount, company_id, created_at)
    VALUES (NEW.id, NEW.bill_id, NEW.amount, NEW.company_id, NEW.created_at)
    ON CONFLICT ON CONSTRAINT payment_allocations_unique_per_doc
    DO UPDATE SET allocated_amount = EXCLUDED.allocated_amount;
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- sync_legacy_payment_unallocated()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.sync_legacy_payment_unallocated()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.bill_id IS NOT NULL THEN
    NEW.unallocated_amount := 0;
  END IF;
  RETURN NEW;
END;
$function$
;

