-- ---------------------------------------------------------------
-- transactional_document_delete_gate_trg()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.transactional_document_delete_gate_trg()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_doc_type text;
  v_disc_doc_type text;
  v_ar_label text;
BEGIN
  IF TG_TABLE_NAME = 'purchase_orders' THEN
    v_doc_type := 'purchase_order';  v_disc_doc_type := 'purchase_order';  v_ar_label := 'أمر الشراء';
  ELSIF TG_TABLE_NAME = 'sales_orders' THEN
    v_doc_type := 'sales_order';     v_disc_doc_type := 'sales_order';     v_ar_label := 'طلب المبيعات';
  ELSIF TG_TABLE_NAME = 'bills' THEN
    v_doc_type := 'bill';            v_disc_doc_type := 'purchase_invoice'; v_ar_label := 'فاتورة المورد';
  ELSIF TG_TABLE_NAME = 'invoices' THEN
    v_doc_type := 'invoice';         v_disc_doc_type := 'sales_invoice';   v_ar_label := 'فاتورة العميل';
  ELSE
    RETURN OLD;
  END IF;

  -- Only draft can be deleted. Anything else must be voided/cancelled.
  IF COALESCE(OLD.status, 'draft') <> 'draft' THEN
    RAISE EXCEPTION
      'لا يمكن حذف % بحالة "%". استخدم "إلغاء" أو "void" بدلاً من الحذف للحفاظ على سجل التدقيق.',
      v_ar_label, OLD.status USING ERRCODE = 'P0001';
  END IF;

  -- Draft delete is allowed. Cascade-clean any hanging discount
  -- approvals and notifications for this doc BEFORE the DELETE runs
  -- so no orphans are left behind.
  DELETE FROM public.discount_approvals
   WHERE document_type = v_disc_doc_type AND document_id = OLD.id;

  DELETE FROM public.notifications
   WHERE (reference_type = v_doc_type AND reference_id = OLD.id)
      OR (reference_type = 'approval_request'
          AND reference_id IN (
            SELECT id FROM public.discount_approvals
             WHERE document_type = v_disc_doc_type AND document_id = OLD.id
          ));

  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- transfer_records_ownership(p_company_id uuid, p_from_user_id uuid, p_to_user_id uuid, p_resource_type text, p_transferred_by uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.transfer_records_ownership(p_company_id uuid, p_from_user_id uuid, p_to_user_id uuid, p_resource_type text, p_transferred_by uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_customers_count INTEGER := 0;
  v_orders_count INTEGER := 0;
  v_transfer_id UUID;
BEGIN
  INSERT INTO permission_transfers (company_id, from_user_id, to_user_id, resource_type, transferred_by, status)
  VALUES (p_company_id, p_from_user_id, p_to_user_id, p_resource_type, p_transferred_by, 'pending')
  RETURNING id INTO v_transfer_id;
  
  IF p_resource_type IN ('customers', 'all') THEN
    UPDATE customers SET created_by_user_id = p_to_user_id 
    WHERE company_id = p_company_id AND created_by_user_id = p_from_user_id;
    GET DIAGNOSTICS v_customers_count = ROW_COUNT;
  END IF;
  
  IF p_resource_type IN ('sales_orders', 'all') THEN
    UPDATE sales_orders SET created_by_user_id = p_to_user_id 
    WHERE company_id = p_company_id AND created_by_user_id = p_from_user_id;
    GET DIAGNOSTICS v_orders_count = ROW_COUNT;
  END IF;
  
  UPDATE permission_transfers SET 
    status = 'completed',
    records_transferred = v_customers_count + v_orders_count,
    transfer_data = jsonb_build_object('customers', v_customers_count, 'sales_orders', v_orders_count)
  WHERE id = v_transfer_id;
  
  RETURN jsonb_build_object(
    'success', TRUE,
    'transfer_id', v_transfer_id,
    'customers_transferred', v_customers_count,
    'orders_transferred', v_orders_count,
    'total_transferred', v_customers_count + v_orders_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- transition_purchase_return_state(p_pr_id uuid, p_company_id uuid, p_user_id uuid, p_new_state character varying, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.transition_purchase_return_state(p_pr_id uuid, p_company_id uuid, p_user_id uuid, p_new_state character varying, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_old_status varchar;
  v_old_workflow varchar;
  v_pr_number varchar;
  v_payload jsonb;
  v_event_key varchar;
  v_audit_action text;
  v_effective_state varchar;
BEGIN
  SELECT status, workflow_status, return_number
  INTO v_old_status, v_old_workflow, v_pr_number
  FROM purchase_returns
  WHERE id = p_pr_id AND company_id = p_company_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Purchase return not found or access denied';
  END IF;

  v_effective_state := COALESCE(NULLIF(v_old_workflow, ''), v_old_status);

  IF p_new_state = 'approved' THEN
    IF COALESCE(v_old_workflow, v_old_status) NOT IN ('pending_admin_approval', 'pending_approval') THEN
      RAISE EXCEPTION
        'Invalid transition: Cannot approve a purchase return in status % / workflow_status %',
        v_old_status, v_old_workflow;
    END IF;

  ELSIF p_new_state = 'rejected' THEN
    IF COALESCE(v_old_workflow, v_old_status) NOT IN ('pending_admin_approval', 'pending_approval') THEN
      RAISE EXCEPTION
        'Invalid transition: Cannot reject a purchase return in status % / workflow_status %',
        v_old_status, v_old_workflow;
    END IF;

  ELSIF p_new_state = 'completed' THEN
    IF v_old_status NOT IN ('approved', 'partially_returned', 'pending_warehouse')
       AND v_effective_state NOT IN ('pending_warehouse', 'pending_approval', 'approved', 'partially_returned')
    THEN
      RAISE EXCEPTION
        'Invalid transition: Cannot complete a purchase return in status % / workflow_status %',
        v_old_status, v_old_workflow;
    END IF;

  ELSIF p_new_state = 'closed' THEN
    IF COALESCE(v_old_workflow, v_old_status) NOT IN ('completed', 'returned') THEN
      RAISE EXCEPTION
        'Invalid transition: Cannot close a purchase return in status % / workflow_status %',
        v_old_status, v_old_workflow;
    END IF;

  ELSE
    RAISE EXCEPTION 'Invalid new state: %', p_new_state;
  END IF;

  v_audit_action := CASE trim(lower(p_new_state::text))
    WHEN 'completed' THEN 'CONFIRM'
    WHEN 'approved' THEN 'APPROVE'
    WHEN 'rejected' THEN 'REJECT'
    WHEN 'closed' THEN 'CLOSE'
    ELSE 'UPDATE'
  END;

  UPDATE purchase_returns
  SET
    status = p_new_state,
    workflow_status = p_new_state,
    updated_at = NOW(),
    notes = CASE WHEN p_notes IS NOT NULL THEN p_notes ELSE notes END,
    approved_by = CASE WHEN p_new_state = 'approved' THEN p_user_id ELSE approved_by END,
    approved_at = CASE WHEN p_new_state = 'approved' THEN NOW() ELSE approved_at END,
    rejected_by = CASE WHEN p_new_state = 'rejected' THEN p_user_id ELSE rejected_by END,
    rejected_at = CASE WHEN p_new_state = 'rejected' THEN NOW() ELSE rejected_at END
  WHERE id = p_pr_id;

  v_payload := jsonb_build_object(
    'return_id', p_pr_id,
    'return_number', v_pr_number,
    'old_status', v_old_status,
    'old_workflow_status', v_old_workflow,
    'new_state', p_new_state,
    'notes', p_notes
  );
  v_event_key := 'purchase_return.' || p_new_state || '.' || p_pr_id::text;

  INSERT INTO system_events (
    company_id, event_type, reference_type, reference_id, payload, user_id, event_key
  ) VALUES (
    p_company_id,
    'purchase_return.' || p_new_state,
    'purchase_return',
    p_pr_id,
    v_payload,
    p_user_id,
    v_event_key
  )
  ON CONFLICT (event_key) DO NOTHING;

  INSERT INTO audit_logs (
    company_id, user_id, action, target_table, record_id, old_data, new_data, created_at
  ) VALUES (
    p_company_id,
    p_user_id,
    v_audit_action,
    'purchase_returns',
    p_pr_id,
    jsonb_build_object('status', v_old_status, 'workflow_status', v_old_workflow),
    jsonb_build_object(
      'from_status', v_old_status,
      'from_workflow_status', v_old_workflow,
      'to_state', p_new_state,
      'notes', p_notes,
      'transitioned_at', NOW()
    ),
    NOW()
  );

  RETURN jsonb_build_object(
    'success', true,
    'old_status', v_old_status,
    'old_workflow_status', v_old_workflow,
    'new_state', p_new_state
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- trg_auto_seed_role_permissions()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trg_auto_seed_role_permissions()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
begin
  perform public.seed_default_role_permissions(new.id);
  -- v3.74.508 add-on grants
  perform public.seed_purchasing_officer_returns_permissions(new.id);
  -- v3.74.581 reports access matrix
  perform public.seed_reports_access_v581(new.id);
  -- v3.74.597: branch outlets are created by the branches INSERT
  -- trigger (the auto main branch included) — pickup seeding removed.
  return new;
end;
$function$
;

-- ---------------------------------------------------------------
-- trg_prevent_bill_modification()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trg_prevent_bill_modification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Only protect bills that are received or paid in some form
    IF OLD.receipt_status = 'received' OR OLD.status IN ('paid', 'partially_paid') THEN
        -- Prevent changing the total_amount
        IF NEW.total_amount IS DISTINCT FROM OLD.total_amount THEN
            RAISE EXCEPTION 'Enterprise Constraint Failed: Cannot modify total_amount of a received or paid bill (Bill %). Only returned_amount can be modified.', OLD.bill_number;
        END IF;
    END IF;
    RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- trg_seed_accounting_periods_on_company_insert()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trg_seed_accounting_periods_on_company_insert()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM seed_accounting_periods_for_company(NEW.id, CURRENT_DATE, 12);
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Do not block company creation if seeding hits an unexpected condition.
  RAISE NOTICE 'seed_accounting_periods_for_company failed for %: %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- trg_seed_company_accounts()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trg_seed_company_accounts()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Skeleton via the historical hardcoded path (creates ~31 accounts and
  -- bootstraps the parent_id hierarchy 1000/2000/3000/4000/5000).
  PERFORM public.seed_default_chart_of_accounts(NEW.id, 'ar');

  -- Then fill in anything the template carries that the skeleton skipped.
  -- sync_company_chart_of_accounts is idempotent — it only INSERTs rows
  -- that don't already exist (matched on (company_id, account_code)),
  -- so calling it right after the skeleton is safe.
  PERFORM public.sync_company_chart_of_accounts(NEW.id);

  RETURN NEW;
END;
$function$
;

