-- ---------------------------------------------------------------
-- trigger_refresh_gl_mv()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trigger_refresh_gl_mv()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- نُحدِّث فقط عند تغيير الحالة إلى posted (أو تحديث قيد posted)
  IF (TG_OP = 'INSERT' AND NEW.status = 'posted')
  OR (TG_OP = 'UPDATE' AND (OLD.status != 'posted' AND NEW.status = 'posted'))
  THEN
    -- تحديث غير متزامن لتجنب إبطاء العمليات الأصلية
    PERFORM pg_notify('refresh_gl_mv', NEW.company_id::text);
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- trigger_user_security_event_allowed_branches_changed()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trigger_user_security_event_allowed_branches_changed()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  -- ✅ عند INSERT: إدراج حدث allowed_branches_changed
  IF TG_OP = 'INSERT' THEN
    PERFORM insert_user_security_event(
      NEW.user_id,
      NEW.company_id,
      'allowed_branches_changed',
      jsonb_build_object(
        'action', 'added',
        'branch_id', NEW.branch_id,
        'is_active', NEW.is_active,
        'changed_by', auth.uid(),
        'changed_at', NOW()
      )
    );
    
    -- ✅ أيضاً إدراج حدث access_changed
    PERFORM insert_user_security_event(
      NEW.user_id,
      NEW.company_id,
      'access_changed',
      jsonb_build_object(
        'reason', 'allowed_branches_changed',
        'action', 'added',
        'branch_id', NEW.branch_id,
        'changed_by', auth.uid(),
        'changed_at', NOW()
      )
    );
    
    RETURN NEW;
  END IF;
  
  -- ✅ عند UPDATE: فقط إذا تغير is_active أو branch_id
  IF TG_OP = 'UPDATE' THEN
    IF (OLD.is_active IS DISTINCT FROM NEW.is_active) OR (OLD.branch_id IS DISTINCT FROM NEW.branch_id) THEN
      PERFORM insert_user_security_event(
        NEW.user_id,
        NEW.company_id,
        'allowed_branches_changed',
        jsonb_build_object(
          'action', 'updated',
          'old_branch_id', OLD.branch_id,
          'new_branch_id', NEW.branch_id,
          'old_is_active', OLD.is_active,
          'new_is_active', NEW.is_active,
          'changed_by', auth.uid(),
          'changed_at', NOW()
        )
      );
      
      -- ✅ أيضاً إدراج حدث access_changed
      PERFORM insert_user_security_event(
        NEW.user_id,
        NEW.company_id,
        'access_changed',
        jsonb_build_object(
          'reason', 'allowed_branches_changed',
          'action', 'updated',
          'branch_id', NEW.branch_id,
          'changed_by', auth.uid(),
          'changed_at', NOW()
        )
      );
    END IF;
    
    RETURN NEW;
  END IF;
  
  -- ✅ عند DELETE: إدراج حدث allowed_branches_changed
  IF TG_OP = 'DELETE' THEN
    PERFORM insert_user_security_event(
      OLD.user_id,
      OLD.company_id,
      'allowed_branches_changed',
      jsonb_build_object(
        'action', 'removed',
        'branch_id', OLD.branch_id,
        'changed_by', auth.uid(),
        'changed_at', NOW()
      )
    );
    
    -- ✅ أيضاً إدراج حدث access_changed
    PERFORM insert_user_security_event(
      OLD.user_id,
      OLD.company_id,
      'access_changed',
      jsonb_build_object(
        'reason', 'allowed_branches_changed',
        'action', 'removed',
        'branch_id', OLD.branch_id,
        'changed_by', auth.uid(),
        'changed_at', NOW()
      )
    );
    
    RETURN OLD;
  END IF;
  
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- trigger_user_security_event_branch_changed()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trigger_user_security_event_branch_changed()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  -- ✅ فقط إذا تغير branch_id فعلياً
  IF OLD.branch_id IS DISTINCT FROM NEW.branch_id THEN
    -- ✅ إدراج حدث branch_changed
    PERFORM insert_user_security_event(
      NEW.user_id,
      NEW.company_id,
      'branch_changed',
      jsonb_build_object(
        'old_branch_id', OLD.branch_id,
        'new_branch_id', NEW.branch_id,
        'changed_by', auth.uid(),
        'changed_at', NOW()
      )
    );
    
    -- ✅ أيضاً إدراج حدث access_changed (لأن تغيير branch يؤثر على الصلاحيات)
    PERFORM insert_user_security_event(
      NEW.user_id,
      NEW.company_id,
      'access_changed',
      jsonb_build_object(
        'reason', 'branch_changed',
        'old_branch_id', OLD.branch_id,
        'new_branch_id', NEW.branch_id,
        'changed_by', auth.uid(),
        'changed_at', NOW()
      )
    );
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- trigger_user_security_event_permissions_changed()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trigger_user_security_event_permissions_changed()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_affected_users UUID[];
BEGIN
  -- ✅ جلب جميع المستخدمين الذين لديهم هذا الدور في هذه الشركة
  SELECT ARRAY_AGG(user_id)
  INTO v_affected_users
  FROM company_members
  WHERE company_id = COALESCE(NEW.company_id, OLD.company_id)
    AND role = COALESCE(NEW.role, OLD.role);
  
  -- ✅ إدراج حدث access_changed لكل مستخدم متأثر
  IF v_affected_users IS NOT NULL THEN
    FOR i IN 1..array_length(v_affected_users, 1) LOOP
      PERFORM insert_user_security_event(
        v_affected_users[i],
        COALESCE(NEW.company_id, OLD.company_id),
        'access_changed',
        jsonb_build_object(
          'reason', 'role_permissions_changed',
          'role', COALESCE(NEW.role, OLD.role),
          'resource', COALESCE(NEW.resource, OLD.resource),
          'changed_by', auth.uid(),
          'changed_at', NOW()
        )
      );
    END LOOP;
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$function$
;

