-- ---------------------------------------------------------------
-- trigger_validate_bill_matching()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.trigger_validate_bill_matching()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_bill RECORD;
  v_validation_result JSONB;
BEGIN
  SELECT * INTO v_bill FROM bills WHERE id = NEW.bill_id;
  
  IF v_bill.purchase_order_id IS NOT NULL OR v_bill.goods_receipt_id IS NOT NULL THEN
    SELECT validate_three_way_matching(NEW.bill_id, v_bill.company_id) INTO v_validation_result;
    RAISE NOTICE 'Three-way matching validation for bill %: %', NEW.bill_id, v_validation_result;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- unlock_accounting_period(p_period_id uuid, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.unlock_accounting_period(p_period_id uuid, p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_period RECORD;
  v_user_role TEXT;
BEGIN
  -- جلب بيانات الفترة
  SELECT * INTO v_period
  FROM accounting_periods
  WHERE id = p_period_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'الفترة غير موجودة'
    );
  END IF;

  -- التحقق من أن المستخدم مالك
  SELECT role INTO v_user_role
  FROM company_members
  WHERE company_id = v_period.company_id
    AND user_id = p_user_id;

  IF v_user_role != 'owner' THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'غير مصرح - المالك فقط يمكنه فتح الفترة'
    );
  END IF;

  -- فتح الفترة
  UPDATE accounting_periods
  SET
    status = 'open',
    closed_by = NULL,
    closed_at = NULL,
    updated_at = NOW()
  WHERE id = p_period_id;

  RETURN jsonb_build_object(
    'success', true,
    'message', 'تم فتح الفترة بنجاح',
    'period_id', p_period_id
  );
END;
$function$
;

