-- ---------------------------------------------------------------
-- update_bill_on_credit_application()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_bill_on_credit_application()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  ap_account UUID;
  vc_liability UUID;
  je_id UUID;
  vc_record RECORD;
  bill_record RECORD;
BEGIN
  -- Get vendor credit info
  SELECT * INTO vc_record FROM vendor_credits WHERE id = NEW.vendor_credit_id;
  SELECT * INTO bill_record FROM bills WHERE id = NEW.bill_id;

  -- Find AP account
  SELECT id INTO ap_account FROM chart_of_accounts
  WHERE company_id = NEW.company_id
    AND (sub_type = 'accounts_payable' OR account_name ILIKE '%payable%')
  LIMIT 1;

  IF ap_account IS NULL THEN
    RETURN NEW;
  END IF;

  -- Create journal entry for the application
  INSERT INTO journal_entries (company_id, reference_type, reference_id, entry_date, description)
  VALUES (NEW.company_id, 'vendor_credit_application', NEW.id, NEW.applied_date,
    'تطبيق إشعار دائن ' || vc_record.credit_number || ' على فاتورة ' || bill_record.bill_number)
  RETURNING id INTO je_id;

  -- Debit: Vendor Credit Liability (reduce what supplier owes us)
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
  VALUES (je_id, ap_account, 0, NEW.amount_applied, 'تسوية إشعار دائن');

  -- Credit: Accounts Payable (reduce what we owe supplier)
  INSERT INTO journal_entry_lines (journal_entry_id, account_id, debit_amount, credit_amount, description)
  VALUES (je_id, ap_account, NEW.amount_applied, 0, 'تسوية ذمم دائنة');

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_bill_on_journal_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_bill_on_journal_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  bill_uuid UUID;
  ref_type TEXT;
  pay_amount DECIMAL(15,2);
BEGIN
  ref_type := OLD.reference_type;
  bill_uuid := OLD.reference_id;
  
  IF bill_uuid IS NULL THEN
    RETURN NULL;
  END IF;
  
  -- Handle bill payment reversal
  IF ref_type = 'bill_payment' THEN
    SELECT COALESCE(SUM(credit_amount), 0) INTO pay_amount
    FROM journal_entry_lines WHERE journal_entry_id = OLD.id AND credit_amount > 0;
    
    UPDATE bills 
    SET paid_amount = GREATEST(0, paid_amount - pay_amount),
        status = CASE 
          WHEN GREATEST(0, paid_amount - pay_amount) <= 0 THEN 'sent'
          WHEN GREATEST(0, paid_amount - pay_amount) < total_amount THEN 'partially_paid'
          ELSE status
        END
    WHERE id = bill_uuid;
  END IF;
  
  -- Handle bill reversal (return)
  IF ref_type = 'bill_reversal' OR ref_type = 'vendor_credit' THEN
    UPDATE bills 
    SET return_status = NULL,
        returned_amount = 0
    WHERE id = bill_uuid;
  END IF;
  
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_capital_contribution_amount(p_contribution_id uuid, p_new_amount numeric, p_new_date date, p_new_notes text, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_capital_contribution_amount(p_contribution_id uuid, p_new_amount numeric, p_new_date date DEFAULT NULL::date, p_new_notes text DEFAULT NULL::text, p_user_id uuid DEFAULT NULL::uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_contribution capital_contributions%ROWTYPE;
  v_je           journal_entries%ROWTYPE;
  v_debit_id     uuid;
  v_credit_id    uuid;
  v_final_dr     numeric;
  v_final_cr     numeric;
BEGIN
  IF p_new_amount IS NULL OR p_new_amount <= 0 THEN
    RAISE EXCEPTION 'Invalid amount: must be a positive number';
  END IF;

  SELECT * INTO v_contribution
  FROM capital_contributions
  WHERE id = p_contribution_id
  FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Contribution not found: %', p_contribution_id;
  END IF;

  PERFORM set_config('app.allow_direct_post', 'true', true);

  SELECT * INTO v_je
  FROM journal_entries
  WHERE company_id     = v_contribution.company_id
    AND reference_type = 'capital_contribution'
    AND reference_id   = p_contribution_id
  ORDER BY created_at DESC NULLS LAST
  LIMIT 1;

  IF v_je.id IS NULL THEN
    RAISE EXCEPTION 'Linked journal entry not found for contribution %', p_contribution_id;
  END IF;

  SELECT id INTO v_debit_id
  FROM journal_entry_lines
  WHERE journal_entry_id = v_je.id AND COALESCE(debit_amount, 0) > 0
  ORDER BY id LIMIT 1;

  SELECT id INTO v_credit_id
  FROM journal_entry_lines
  WHERE journal_entry_id = v_je.id AND COALESCE(credit_amount, 0) > 0
  ORDER BY id LIMIT 1;

  IF v_debit_id IS NULL OR v_credit_id IS NULL THEN
    RAISE EXCEPTION 'Journal lines are malformed (missing debit or credit line). JE id: %', v_je.id;
  END IF;

  UPDATE journal_entry_lines SET debit_amount  = p_new_amount WHERE id = v_debit_id;
  UPDATE journal_entry_lines SET credit_amount = p_new_amount WHERE id = v_credit_id;

  UPDATE journal_entries
     SET entry_date            = COALESCE(p_new_date, entry_date),
         original_total_debit  = p_new_amount,
         original_total_credit = p_new_amount,
         updated_at            = now()
   WHERE id = v_je.id;

  UPDATE capital_contributions
     SET amount            = p_new_amount,
         contribution_date = COALESCE(p_new_date, contribution_date),
         notes             = COALESCE(p_new_notes, notes),
         original_amount   = COALESCE(original_amount, v_contribution.amount),
         last_edited_at    = now(),
         last_edited_by    = COALESCE(p_user_id, last_edited_by)
   WHERE id = p_contribution_id;

  -- Final balance check (audit guarantee). The trigger let us through
  -- temporary imbalance; we MUST end the transaction balanced.
  SELECT COALESCE(SUM(debit_amount), 0),
         COALESCE(SUM(credit_amount), 0)
    INTO v_final_dr, v_final_cr
    FROM journal_entry_lines
   WHERE journal_entry_id = v_je.id;

  IF ABS(v_final_dr - v_final_cr) > 0.01 THEN
    RAISE EXCEPTION 'Post-edit imbalance: Dr=%, Cr=%, diff=%',
      v_final_dr, v_final_cr, ABS(v_final_dr - v_final_cr);
  END IF;

  RETURN json_build_object(
    'success',         true,
    'id',              p_contribution_id,
    'journal_entry_id', v_je.id,
    'new_amount',      p_new_amount,
    'new_date',        COALESCE(p_new_date, v_je.entry_date)
  );
END;
$function$
;

