-- ---------------------------------------------------------------
-- update_customer_debit_note_status()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_customer_debit_note_status()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Update status based on applied_amount vs total_amount
  IF NEW.applied_amount >= NEW.total_amount THEN
    NEW.status := 'applied';
  ELSIF NEW.applied_amount > 0 THEN
    NEW.status := 'partially_applied';
  ELSE
    NEW.status := 'open';
  END IF;
  
  -- Update timestamp
  NEW.updated_at := NOW();
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_expenses_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_expenses_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_grn_totals()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_grn_totals()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE goods_receipts
  SET 
    total_quantity_received = (SELECT COALESCE(SUM(quantity_received), 0) FROM goods_receipt_items WHERE goods_receipt_id = NEW.goods_receipt_id),
    total_quantity_accepted = (SELECT COALESCE(SUM(quantity_accepted), 0) FROM goods_receipt_items WHERE goods_receipt_id = NEW.goods_receipt_id),
    total_quantity_rejected = (SELECT COALESCE(SUM(quantity_rejected), 0) FROM goods_receipt_items WHERE goods_receipt_id = NEW.goods_receipt_id),
    updated_at = NOW()
  WHERE id = NEW.goods_receipt_id;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_invoice_after_return(p_invoice_id uuid, p_returned_amount numeric, p_return_status text, p_new_status text, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_invoice_after_return(p_invoice_id uuid, p_returned_amount numeric, p_return_status text, p_new_status text, p_notes text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_result JSON;
  v_old_returned_amount NUMERIC;
  v_total_amount NUMERIC;
BEGIN
  -- التحقق من وجود الفاتورة
  SELECT returned_amount, total_amount
  INTO v_old_returned_amount, v_total_amount
  FROM invoices
  WHERE id = p_invoice_id;

  IF NOT FOUND THEN
    RETURN json_build_object(
      'success', false,
      'error', 'Invoice not found'
    );
  END IF;

  -- التحقق من عدم تجاوز المبلغ المرتجع للإجمالي
  IF p_returned_amount > v_total_amount THEN
    RETURN json_build_object(
      'success', false,
      'error', 'Returned amount cannot exceed total amount'
    );
  END IF;

  -- تحديث الفاتورة (تجاوز قيد القيود المحاسبية)
  UPDATE invoices
  SET 
    returned_amount = p_returned_amount,
    return_status = p_return_status,
    status = p_new_status,
    notes = COALESCE(notes, '') || E'\n' || p_notes,
    updated_at = NOW()
  WHERE id = p_invoice_id;

  -- إرجاع النتيجة
  RETURN json_build_object(
    'success', true,
    'invoice_id', p_invoice_id,
    'old_returned_amount', v_old_returned_amount,
    'new_returned_amount', p_returned_amount
  );

EXCEPTION
  WHEN OTHERS THEN
    RETURN json_build_object(
      'success', false,
      'error', SQLERRM
    );
END;
$function$
;

-- ---------------------------------------------------------------
-- update_invoice_on_journal_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_invoice_on_journal_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  inv_id UUID;
  ref_type TEXT;
  pay_amount DECIMAL(15,2);
BEGIN
  ref_type := OLD.reference_type;
  inv_id := OLD.reference_id;
  
  IF inv_id IS NULL THEN
    RETURN NULL;
  END IF;
  
  -- Handle invoice payment reversal
  IF ref_type = 'invoice_payment' THEN
    -- Get the payment amount from journal lines (debit to cash/bank)
    SELECT COALESCE(SUM(debit_amount), 0) INTO pay_amount
    FROM journal_entry_lines WHERE journal_entry_id = OLD.id AND debit_amount > 0;
    
    -- Update invoice paid_amount and status
    UPDATE invoices 
    SET paid_amount = GREATEST(0, paid_amount - pay_amount),
        status = CASE 
          WHEN GREATEST(0, paid_amount - pay_amount) <= 0 THEN 'sent'
          WHEN GREATEST(0, paid_amount - pay_amount) < total_amount THEN 'partially_paid'
          ELSE status
        END
    WHERE id = inv_id;
  END IF;
  
  -- Handle invoice reversal (return)
  IF ref_type = 'invoice_reversal' OR ref_type = 'credit_note' THEN
    -- Reset return status
    UPDATE invoices 
    SET return_status = NULL,
        returned_amount = 0
    WHERE id = inv_id;
  END IF;
  
  RETURN NULL;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_invoice_on_payment_delete()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_invoice_on_payment_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_invoice_id UUID;
  v_total_payments NUMERIC;
  v_invoice_total NUMERIC;
  v_new_status TEXT;
BEGIN
  -- Only process if payment was linked to an invoice
  IF OLD.invoice_id IS NOT NULL THEN
    v_invoice_id := OLD.invoice_id;
    
    -- Get sum of remaining payments for this invoice
    SELECT COALESCE(SUM(amount), 0) INTO v_total_payments
    FROM payments
    WHERE invoice_id = v_invoice_id AND id != OLD.id;
    
    -- Get invoice total
    SELECT total_amount INTO v_invoice_total
    FROM invoices
    WHERE id = v_invoice_id;
    
    -- Determine new status
    IF v_total_payments <= 0 THEN
      v_new_status := 'sent';
    ELSIF v_total_payments >= v_invoice_total THEN
      v_new_status := 'paid';
    ELSE
      v_new_status := 'partially_paid';
    END IF;
    
    -- Update invoice
    UPDATE invoices
    SET paid_amount = v_total_payments,
        status = v_new_status
    WHERE id = v_invoice_id;
    
    RAISE NOTICE 'Invoice % updated: paid_amount=%, status=%', v_invoice_id, v_total_payments, v_new_status;
  END IF;
  
  RETURN OLD;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_invoice_on_payment_insert()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_invoice_on_payment_insert()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_total_payments NUMERIC;
  v_invoice_total NUMERIC;
  v_current_paid NUMERIC;
  v_new_status TEXT;
BEGIN
  -- Only process if payment is linked to an invoice
  IF NEW.invoice_id IS NOT NULL THEN
    -- Get sum of all payments for this invoice
    SELECT COALESCE(SUM(amount), 0) INTO v_total_payments
    FROM payments
    WHERE invoice_id = NEW.invoice_id;
    
    -- Get invoice total and current paid amount
    SELECT total_amount, COALESCE(paid_amount, 0) INTO v_invoice_total, v_current_paid
    FROM invoices
    WHERE id = NEW.invoice_id;
    
    -- Only update if there's a mismatch (to avoid conflicts with app code)
    IF v_current_paid != v_total_payments THEN
      -- Determine new status
      IF v_total_payments <= 0 THEN
        v_new_status := 'sent';
      ELSIF v_total_payments >= v_invoice_total THEN
        v_new_status := 'paid';
      ELSE
        v_new_status := 'partially_paid';
      END IF;
      
      -- Update invoice
      UPDATE invoices
      SET paid_amount = v_total_payments,
          status = v_new_status
      WHERE id = NEW.invoice_id;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$function$
;

