-- ---------------------------------------------------------------
-- update_lot_expiry(p_company_id uuid, p_lot_id uuid, p_expiry_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_lot_expiry(p_company_id uuid, p_lot_id uuid, p_expiry_date date)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_role text; v_member_branch uuid; v_lot_branch uuid;
BEGIN
  IF v_uid IS NOT NULL THEN
    SELECT cm.role, cm.branch_id INTO v_role, v_member_branch
    FROM public.company_members cm
    WHERE cm.company_id = p_company_id AND cm.user_id = v_uid
    LIMIT 1;
    IF v_role IS NULL THEN
      RAISE EXCEPTION 'EXPIRY_FORBIDDEN: لست عضواً فى هذه الشركة';
    END IF;
    IF v_role NOT IN ('owner','admin','general_manager','store_manager','warehouse_manager') THEN
      RAISE EXCEPTION 'EXPIRY_FORBIDDEN: تعديل صلاحية الدفعات متاح للإدارة ومسئولى المخازن فقط';
    END IF;
    IF v_role IN ('store_manager','warehouse_manager') AND v_member_branch IS NOT NULL THEN
      SELECT branch_id INTO v_lot_branch FROM public.fifo_cost_lots
      WHERE id = p_lot_id AND company_id = p_company_id;
      IF v_lot_branch IS DISTINCT FROM v_member_branch THEN
        RAISE EXCEPTION 'EXPIRY_FORBIDDEN: الدفعة خارج نطاق فرعك';
      END IF;
    END IF;
  END IF;

  UPDATE public.fifo_cost_lots
     SET expiry_date = p_expiry_date, updated_at = NOW()
   WHERE id = p_lot_id AND company_id = p_company_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'LOT_NOT_FOUND'; END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_manufacturing_bom_structure_atomic(p_company_id uuid, p_bom_version_id uuid, p_updated_by uuid, p_lines jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_manufacturing_bom_structure_atomic(p_company_id uuid, p_bom_version_id uuid, p_updated_by uuid, p_lines jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version RECORD;
  v_line JSONB;
  v_substitute JSONB;
  v_new_line_id UUID;
  v_line_count INTEGER := 0;
  v_substitute_count INTEGER := 0;
BEGIN
  IF p_lines IS NULL OR jsonb_typeof(p_lines) <> 'array' THEN
    RAISE EXCEPTION 'BOM structure payload must be a JSON array of lines.';
  END IF;

  SELECT *
    INTO v_version
    FROM public.manufacturing_bom_versions
   WHERE id = p_bom_version_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing BOM version not found or not in company. bom_version_id=%', p_bom_version_id;
  END IF;

  DELETE FROM public.manufacturing_bom_line_substitutes
   WHERE bom_line_id IN (
     SELECT id
       FROM public.manufacturing_bom_lines
      WHERE bom_version_id = p_bom_version_id
   );

  DELETE FROM public.manufacturing_bom_lines
   WHERE bom_version_id = p_bom_version_id;

  FOR v_line IN
    SELECT value
      FROM jsonb_array_elements(p_lines)
  LOOP
    INSERT INTO public.manufacturing_bom_lines (
      company_id,
      branch_id,
      bom_version_id,
      line_no,
      component_product_id,
      line_type,
      quantity_per,
      scrap_percent,
      issue_uom,
      is_optional,
      notes,
      created_by,
      updated_by
    ) VALUES (
      p_company_id,
      v_version.branch_id,
      p_bom_version_id,
      (v_line->>'line_no')::INTEGER,
      NULLIF(v_line->>'component_product_id', '')::UUID,
      COALESCE(NULLIF(v_line->>'line_type', ''), 'component'),
      (v_line->>'quantity_per')::NUMERIC,
      COALESCE((v_line->>'scrap_percent')::NUMERIC, 0),
      NULLIF(v_line->>'issue_uom', ''),
      COALESCE((v_line->>'is_optional')::BOOLEAN, false),
      NULLIF(v_line->>'notes', ''),
      p_updated_by,
      p_updated_by
    )
    RETURNING id INTO v_new_line_id;

    v_line_count := v_line_count + 1;

    IF jsonb_typeof(v_line->'substitutes') = 'array' THEN
      FOR v_substitute IN
        SELECT value
          FROM jsonb_array_elements(v_line->'substitutes')
      LOOP
        INSERT INTO public.manufacturing_bom_line_substitutes (
          company_id,
          branch_id,
          bom_line_id,
          substitute_product_id,
          substitute_quantity,
          priority,
          effective_from,
          effective_to,
          notes,
          created_by,
          updated_by
        ) VALUES (
          p_company_id,
          v_version.branch_id,
          v_new_line_id,
          NULLIF(v_substitute->>'substitute_product_id', '')::UUID,
          (v_substitute->>'substitute_quantity')::NUMERIC,
          COALESCE((v_substitute->>'priority')::INTEGER, 1),
          NULLIF(v_substitute->>'effective_from', '')::TIMESTAMPTZ,
          NULLIF(v_substitute->>'effective_to', '')::TIMESTAMPTZ,
          NULLIF(v_substitute->>'notes', ''),
          p_updated_by,
          p_updated_by
        );

        v_substitute_count := v_substitute_count + 1;
      END LOOP;
    END IF;
  END LOOP;

  UPDATE public.manufacturing_bom_versions
     SET updated_by = p_updated_by
   WHERE id = p_bom_version_id;

  RETURN jsonb_build_object(
    'success', true,
    'bom_version_id', p_bom_version_id,
    'line_count', v_line_count,
    'substitute_count', v_substitute_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- update_manufacturing_production_order_operation_progress_atomic(p_company_id uuid, p_production_order_operation_id uuid, p_updated_by uuid, p_status text, p_completed_quantity numeric, p_actual_start_at timestamp with time zone, p_actual_end_at timestamp with time zone, p_notes text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_manufacturing_production_order_operation_progress_atomic(p_company_id uuid, p_production_order_operation_id uuid, p_updated_by uuid, p_status text DEFAULT NULL::text, p_completed_quantity numeric DEFAULT NULL::numeric, p_actual_start_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_actual_end_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_notes text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_operation RECORD;
  v_order RECORD;
  v_new_status TEXT;
  v_new_completed_quantity NUMERIC;
  v_new_actual_start_at TIMESTAMPTZ;
  v_new_actual_end_at TIMESTAMPTZ;
  v_new_notes TEXT;
  v_started_by UUID;
  v_completed_by UUID;
  v_auto_started_order BOOLEAN := false;
BEGIN
  SELECT *
    INTO v_operation
    FROM public.manufacturing_production_order_operations
   WHERE id = p_production_order_operation_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing production order operation not found or not in company. production_order_operation_id=%',
      p_production_order_operation_id;
  END IF;

  SELECT *
    INTO v_order
    FROM public.manufacturing_production_orders
   WHERE id = v_operation.production_order_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Parent manufacturing production order not found or not in company. production_order_id=%',
      v_operation.production_order_id;
  END IF;

  v_new_completed_quantity := COALESCE(p_completed_quantity, v_operation.completed_quantity);
  v_new_actual_start_at := COALESCE(p_actual_start_at, v_operation.actual_start_at);
  v_new_actual_end_at := COALESCE(p_actual_end_at, v_operation.actual_end_at);
  v_new_notes := p_notes;

  IF p_status IS NOT NULL THEN
    v_new_status := p_status;
  ELSIF v_new_completed_quantity >= v_operation.planned_quantity AND v_new_actual_end_at IS NOT NULL THEN
    v_new_status := 'completed';
  ELSIF v_new_completed_quantity > v_operation.completed_quantity
     OR v_new_actual_start_at IS NOT NULL
     OR v_new_actual_end_at IS NOT NULL THEN
    v_new_status := CASE
      WHEN v_operation.status IN ('pending', 'ready', 'in_progress') THEN 'in_progress'
      ELSE v_operation.status
    END;
  ELSE
    v_new_status := v_operation.status;
  END IF;

  IF v_new_status = 'completed' THEN
    IF v_new_completed_quantity IS DISTINCT FROM v_operation.planned_quantity THEN
      RAISE EXCEPTION 'Completed production order operations must have completed_quantity equal to planned_quantity. production_order_operation_id=%',
        p_production_order_operation_id;
    END IF;

    IF v_new_actual_end_at IS NULL THEN
      v_new_actual_end_at := NOW();
    END IF;
  END IF;

  IF v_new_status IN ('in_progress', 'completed') AND v_new_actual_start_at IS NULL THEN
    v_new_actual_start_at := NOW();
  END IF;

  IF v_order.status = 'released'
     AND (
       v_new_status IN ('in_progress', 'completed')
       OR v_new_completed_quantity > 0
       OR v_new_actual_start_at IS NOT NULL
       OR v_new_actual_end_at IS NOT NULL
     ) THEN
    UPDATE public.manufacturing_production_orders
       SET status = 'in_progress',
           started_at = COALESCE(started_at, v_new_actual_start_at, NOW()),
           started_by = COALESCE(started_by, p_updated_by),
           updated_by = p_updated_by
     WHERE id = v_order.id;

    v_auto_started_order := true;
  END IF;

  v_started_by := CASE
    WHEN v_new_actual_start_at IS NOT NULL THEN COALESCE(v_operation.started_by, p_updated_by)
    ELSE v_operation.started_by
  END;

  v_completed_by := CASE
    WHEN v_new_status = 'completed' OR v_new_actual_end_at IS NOT NULL THEN COALESCE(v_operation.completed_by, p_updated_by)
    ELSE v_operation.completed_by
  END;

  UPDATE public.manufacturing_production_order_operations
     SET status = v_new_status,
         completed_quantity = v_new_completed_quantity,
         actual_start_at = v_new_actual_start_at,
         started_by = v_started_by,
         actual_end_at = v_new_actual_end_at,
         completed_by = v_completed_by,
         last_progress_at = NOW(),
         notes = v_new_notes,
         updated_by = p_updated_by
   WHERE id = p_production_order_operation_id;

  RETURN jsonb_build_object(
    'success', true,
    'production_order_id', v_order.id,
    'production_order_operation_id', p_production_order_operation_id,
    'previous_status', v_operation.status,
    'status', v_new_status,
    'completed_quantity', v_new_completed_quantity,
    'auto_started_order', v_auto_started_order
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- update_manufacturing_routing_operations_atomic(p_company_id uuid, p_routing_version_id uuid, p_updated_by uuid, p_operations jsonb)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_manufacturing_routing_operations_atomic(p_company_id uuid, p_routing_version_id uuid, p_updated_by uuid, p_operations jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_version RECORD;
  v_operation JSONB;
  v_operation_count INTEGER := 0;
BEGIN
  IF p_operations IS NULL OR jsonb_typeof(p_operations) <> 'array' THEN
    RAISE EXCEPTION 'Routing operations payload must be a JSON array.';
  END IF;

  SELECT *
    INTO v_version
    FROM public.manufacturing_routing_versions
   WHERE id = p_routing_version_id
     AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manufacturing routing version not found or not in company. routing_version_id=%', p_routing_version_id;
  END IF;

  DELETE FROM public.manufacturing_routing_operations
   WHERE routing_version_id = p_routing_version_id;

  FOR v_operation IN
    SELECT value
      FROM jsonb_array_elements(p_operations)
  LOOP
    INSERT INTO public.manufacturing_routing_operations (
      company_id,
      branch_id,
      routing_version_id,
      operation_no,
      operation_code,
      operation_name,
      work_center_id,
      setup_time_minutes,
      run_time_minutes_per_unit,
      queue_time_minutes,
      move_time_minutes,
      labor_time_minutes,
      machine_time_minutes,
      quality_checkpoint_required,
      instructions,
      created_by,
      updated_by
    ) VALUES (
      p_company_id,
      v_version.branch_id,
      p_routing_version_id,
      (v_operation->>'operation_no')::INTEGER,
      NULLIF(v_operation->>'operation_code', ''),
      NULLIF(v_operation->>'operation_name', ''),
      NULLIF(v_operation->>'work_center_id', '')::UUID,
      COALESCE((v_operation->>'setup_time_minutes')::NUMERIC, 0),
      COALESCE((v_operation->>'run_time_minutes_per_unit')::NUMERIC, 0),
      COALESCE((v_operation->>'queue_time_minutes')::NUMERIC, 0),
      COALESCE((v_operation->>'move_time_minutes')::NUMERIC, 0),
      COALESCE((v_operation->>'labor_time_minutes')::NUMERIC, 0),
      COALESCE((v_operation->>'machine_time_minutes')::NUMERIC, 0),
      COALESCE((v_operation->>'quality_checkpoint_required')::BOOLEAN, false),
      NULLIF(v_operation->>'instructions', ''),
      p_updated_by,
      p_updated_by
    );

    v_operation_count := v_operation_count + 1;
  END LOOP;

  UPDATE public.manufacturing_routing_versions
     SET updated_by = p_updated_by
   WHERE id = p_routing_version_id;

  RETURN jsonb_build_object(
    'success', true,
    'routing_version_id', p_routing_version_id,
    'operation_count', v_operation_count
  );
END;
$function$
;

-- ---------------------------------------------------------------
-- update_notification_status(p_notification_id uuid, p_status character varying, p_user_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_notification_status(p_notification_id uuid, p_status character varying, p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- إدراج حالة جديدة أو تحديث الحالة الحالية للمستخدم
  INSERT INTO notification_user_states (notification_id, user_id, status, read_at, actioned_at, updated_at)
  VALUES (
    p_notification_id, 
    p_user_id, 
    p_status,
    CASE WHEN p_status IN ('read', 'archived', 'actioned') THEN NOW() ELSE NULL END,
    CASE WHEN p_status = 'actioned' THEN NOW() ELSE NULL END,
    NOW()
  )
  ON CONFLICT (notification_id, user_id)
  DO UPDATE SET 
    status = p_status,
    read_at = CASE WHEN p_status IN ('read', 'archived', 'actioned') THEN COALESCE(notification_user_states.read_at, NOW()) ELSE notification_user_states.read_at END,
    actioned_at = CASE WHEN p_status = 'actioned' THEN COALESCE(notification_user_states.actioned_at, NOW()) ELSE notification_user_states.actioned_at END,
    updated_at = NOW();

  RETURN TRUE;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_onboarding_updated_at()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_onboarding_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = now();
  -- Auto-complete when all steps done
  IF (NEW.steps->>'company_created')::boolean
    AND (NEW.steps->>'branch_added')::boolean
    AND (NEW.steps->>'first_product')::boolean
    AND (NEW.steps->>'first_invoice')::boolean
    AND (NEW.steps->>'first_purchase_order')::boolean
    AND NEW.completed_at IS NULL
  THEN
    NEW.completed_at = now();
  END IF;
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_product_quantity()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_product_quantity()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ BEGIN IF TG_OP = 'INSERT' THEN UPDATE products SET quantity_on_hand = COALESCE(quantity_on_hand, 0) + NEW.quantity_change WHERE id = NEW.product_id; ELSIF TG_OP = 'UPDATE' THEN IF OLD.is_deleted = false AND NEW.is_deleted = true THEN UPDATE products SET quantity_on_hand = COALESCE(quantity_on_hand, 0) - OLD.quantity_change WHERE id = OLD.product_id; ELSIF OLD.is_deleted = true AND NEW.is_deleted = false THEN UPDATE products SET quantity_on_hand = COALESCE(quantity_on_hand, 0) + NEW.quantity_change WHERE id = NEW.product_id; ELSIF OLD.quantity_change != NEW.quantity_change THEN UPDATE products SET quantity_on_hand = COALESCE(quantity_on_hand, 0) - OLD.quantity_change + NEW.quantity_change WHERE id = NEW.product_id; END IF; ELSIF TG_OP = 'DELETE' THEN IF OLD.is_deleted = false THEN UPDATE products SET quantity_on_hand = COALESCE(quantity_on_hand, 0) - OLD.quantity_change WHERE id = OLD.product_id; END IF; RETURN OLD; END IF; RETURN NEW; END; $function$
;

