-- ---------------------------------------------------------------
-- update_service_atomic(p_company_id uuid, p_service_id uuid, p_updated_by uuid, p_description text, p_category text, p_service_type text, p_tax_rate numeric, p_commission_rate numeric, p_duration_minutes integer, p_capacity integer, p_buffer_minutes integer, p_advance_booking_days integer, p_min_advance_hours integer, p_cancel_before_hours integer, p_cost_center_id uuid, p_image_url text, p_color_code text, p_currency_code text, p_is_bookable boolean, p_requires_approval boolean, p_notes text, p_product_catalog_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_service_atomic(p_company_id uuid, p_service_id uuid, p_updated_by uuid, p_description text DEFAULT NULL::text, p_category text DEFAULT NULL::text, p_service_type text DEFAULT NULL::text, p_tax_rate numeric DEFAULT NULL::numeric, p_commission_rate numeric DEFAULT NULL::numeric, p_duration_minutes integer DEFAULT NULL::integer, p_capacity integer DEFAULT NULL::integer, p_buffer_minutes integer DEFAULT NULL::integer, p_advance_booking_days integer DEFAULT NULL::integer, p_min_advance_hours integer DEFAULT NULL::integer, p_cancel_before_hours integer DEFAULT NULL::integer, p_cost_center_id uuid DEFAULT NULL::uuid, p_image_url text DEFAULT NULL::text, p_color_code text DEFAULT NULL::text, p_currency_code text DEFAULT NULL::text, p_is_bookable boolean DEFAULT NULL::boolean, p_requires_approval boolean DEFAULT NULL::boolean, p_notes text DEFAULT NULL::text, p_product_catalog_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_service public.services;
BEGIN
  SELECT * INTO v_service
    FROM public.services
   WHERE id = p_service_id AND company_id = p_company_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Service not found or not accessible. service_id=%', p_service_id
      USING ERRCODE = 'P0001';
  END IF;

  IF p_service_type IS NOT NULL AND NOT public.svc_is_valid_service_type(p_service_type) THEN
    RAISE EXCEPTION 'Invalid service_type: %', p_service_type
      USING ERRCODE = 'P0001';
  END IF;

  UPDATE public.services SET
    description          = COALESCE(p_description,          description),
    category             = COALESCE(p_category,             category),
    service_type         = COALESCE(p_service_type,         service_type),
    tax_rate             = COALESCE(p_tax_rate,             tax_rate),
    commission_rate      = COALESCE(p_commission_rate,      commission_rate),
    duration_minutes     = COALESCE(p_duration_minutes,     duration_minutes),
    capacity             = COALESCE(p_capacity,             capacity),
    buffer_minutes       = COALESCE(p_buffer_minutes,       buffer_minutes),
    advance_booking_days = COALESCE(p_advance_booking_days, advance_booking_days),
    min_advance_hours    = COALESCE(p_min_advance_hours,    min_advance_hours),
    cancel_before_hours  = COALESCE(p_cancel_before_hours,  cancel_before_hours),
    cost_center_id       = COALESCE(p_cost_center_id,       cost_center_id),
    image_url            = COALESCE(p_image_url,            image_url),
    color_code           = COALESCE(p_color_code,           color_code),
    currency_code        = COALESCE(p_currency_code,        currency_code),
    is_bookable          = COALESCE(p_is_bookable,          is_bookable),
    requires_approval    = COALESCE(p_requires_approval,    requires_approval),
    notes                = COALESCE(p_notes,                notes),
    product_catalog_id   = COALESCE(p_product_catalog_id,   product_catalog_id),
    updated_by           = p_updated_by,
    updated_at           = NOW()
  WHERE id = p_service_id AND company_id = p_company_id;

  RETURN jsonb_build_object(
    'success',    true,
    'service_id', p_service_id
  );
END;
$function$
;

