-- ---------------------------------------------------------------
-- update_third_party_on_payment(p_invoice_id uuid, p_new_status text, p_paid_amount numeric, p_net_invoice_amount numeric)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_third_party_on_payment(p_invoice_id uuid, p_new_status text, p_paid_amount numeric, p_net_invoice_amount numeric)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF p_new_status = 'paid' THEN
    -- دفع كامل: البضاعة تُعتبر مُسلَّمة ومدفوعة
    UPDATE third_party_inventory
    SET 
      cleared_quantity = quantity,
      cleared_at = NOW(),
      status = 'cleared',
      payment_status = 'paid',
      delivery_status = 'delivered',
      updated_at = NOW()
    WHERE invoice_id = p_invoice_id
      AND delivery_status != 'returned';

  ELSIF p_new_status = 'partially_paid' THEN
    -- دفع جزئي: تحديث حالة الدفع فقط
    UPDATE third_party_inventory
    SET
      payment_status = 'partially_paid',
      updated_at = NOW()
    WHERE invoice_id = p_invoice_id
      AND delivery_status != 'returned'
      AND delivery_status != 'delivered';
  END IF;
END;
$function$
;

