-- ---------------------------------------------------------------
-- update_user_currency_preference(p_user_id uuid, p_company_id uuid, p_currency text, p_sync_enabled boolean)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_user_currency_preference(p_user_id uuid, p_company_id uuid, p_currency text, p_sync_enabled boolean DEFAULT true)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_is_owner BOOLEAN;
  v_result JSONB;
BEGIN
  SELECT (user_id = p_user_id) INTO v_is_owner
  FROM companies
  WHERE id = p_company_id;

  UPDATE company_members
  SET 
    preferred_currency = p_currency,
    currency_sync_enabled = CASE 
      WHEN v_is_owner THEN FALSE
      ELSE p_sync_enabled
    END
  WHERE user_id = p_user_id AND company_id = p_company_id;

  SELECT jsonb_build_object(
    'success', TRUE,
    'currency', p_currency,
    'sync_enabled', CASE WHEN v_is_owner THEN FALSE ELSE p_sync_enabled END,
    'is_owner', v_is_owner
  ) INTO v_result;

  RETURN v_result;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_username(p_user_id uuid, p_new_username text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_username(p_user_id uuid, p_new_username text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_check JSONB;
  v_clean TEXT;
BEGIN
  v_clean := LOWER(TRIM(p_new_username));
  v_check := check_username_available(v_clean, p_user_id);
  IF NOT (v_check->>'available')::BOOLEAN THEN
    RETURN v_check;
  END IF;
  UPDATE user_profiles SET username = v_clean, updated_at = now()
  WHERE user_id = p_user_id;
  RETURN jsonb_build_object('success', true, 'username', v_clean);
END;
$function$
;

-- ---------------------------------------------------------------
-- update_vendor_credit_on_application()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_vendor_credit_on_application()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total_applied DECIMAL(15,2);
  v_vendor_credit_id UUID;
BEGIN
  -- تحديد vendor_credit_id بناءً على نوع العملية
  IF TG_OP = 'DELETE' THEN
    v_vendor_credit_id := OLD.vendor_credit_id;
  ELSE
    v_vendor_credit_id := NEW.vendor_credit_id;
  END IF;
  
  -- حساب إجمالي المبلغ المطبق من جدول vendor_credit_applications
  SELECT COALESCE(SUM(amount_applied), 0)
  INTO v_total_applied
  FROM vendor_credit_applications
  WHERE vendor_credit_id = v_vendor_credit_id;
  
  -- تحديث vendor_credit
  UPDATE vendor_credits
  SET applied_amount = v_total_applied
  WHERE id = v_vendor_credit_id;
  
  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$function$
;

-- ---------------------------------------------------------------
-- update_vendor_credit_status()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.update_vendor_credit_status()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- تحديث حالة vendor_credit بناءً على المبلغ المطبق
  IF NEW.applied_amount >= NEW.total_amount THEN
    NEW.status = 'closed';
  ELSIF NEW.applied_amount > 0 THEN
    NEW.status = 'applied';
  ELSE
    NEW.status = 'open';
  END IF;
  
  RETURN NEW;
END;
$function$
;

