-- ---------------------------------------------------------------
-- validate_accrual_accounting_implementation(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_accrual_accounting_implementation(p_company_id uuid)
 RETURNS TABLE(test_name text, status text, details text, recommendation text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
BEGIN
  -- اختبار 1: وجود الحسابات الأساسية
  RETURN QUERY
  SELECT 
    'Basic Accounts Test'::TEXT,
    CASE 
      WHEN EXISTS (
        SELECT 1 FROM chart_of_accounts 
        WHERE company_id = p_company_id AND sub_type = 'accounts_receivable'
      ) THEN 'PASS'::TEXT
      ELSE 'FAIL'::TEXT
    END,
    'Checking for required chart of accounts'::TEXT,
    'Create basic accounts: AR, AP, Revenue, Inventory, COGS'::TEXT;

  -- اختبار 2: Trial Balance متزن
  RETURN QUERY
  SELECT 
    'Trial Balance Test'::TEXT,
    CASE 
      WHEN ABS(
        COALESCE((SELECT SUM(debit_amount) FROM journal_entry_lines jel
         JOIN journal_entries je ON jel.journal_entry_id = je.id
         WHERE je.company_id = p_company_id), 0) -
        COALESCE((SELECT SUM(credit_amount) FROM journal_entry_lines jel
         JOIN journal_entries je ON jel.journal_entry_id = je.id
         WHERE je.company_id = p_company_id), 0)
      ) < 0.01 THEN 'PASS'::TEXT
      ELSE 'FAIL'::TEXT
    END,
    'Total debits: ' || 
    COALESCE((SELECT SUM(debit_amount) FROM journal_entry_lines jel
     JOIN journal_entries je ON jel.journal_entry_id = je.id
     WHERE je.company_id = p_company_id), 0)::TEXT ||
    ', Total credits: ' ||
    COALESCE((SELECT SUM(credit_amount) FROM journal_entry_lines jel
     JOIN journal_entries je ON jel.journal_entry_id = je.id
     WHERE je.company_id = p_company_id), 0)::TEXT,
    'All journal entries must be balanced'::TEXT;

  -- اختبار 3: الإيراد مسجل
  RETURN QUERY
  SELECT 
    'Revenue Recognition Test'::TEXT,
    CASE 
      WHEN EXISTS (
        SELECT 1 FROM journal_entries je
        WHERE je.company_id = p_company_id AND je.reference_type = 'invoice'
      ) THEN 'PASS'::TEXT
      ELSE 'FAIL'::TEXT
    END,
    'Invoice journals: ' || 
    COALESCE((SELECT COUNT(*) FROM journal_entries WHERE company_id = p_company_id AND reference_type = 'invoice'), 0)::TEXT,
    'Revenue should be recorded when invoice is issued'::TEXT;

END;
$function$
;

-- ---------------------------------------------------------------
-- validate_booking_staff_from_service()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_booking_staff_from_service()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  -- Only when the staff or the service actually changes.
  IF TG_OP = 'UPDATE'
     AND NEW.staff_user_id IS NOT DISTINCT FROM OLD.staff_user_id
     AND NEW.service_id    IS NOT DISTINCT FROM OLD.service_id THEN
    RETURN NEW;
  END IF;

  IF NEW.staff_user_id IS NULL OR NEW.service_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Rule applies only when the service has registered staff at all.
  IF EXISTS (SELECT 1 FROM public.service_staff ss WHERE ss.service_id = NEW.service_id) THEN
    IF NOT EXISTS (
      SELECT 1 FROM public.service_staff ss
      WHERE ss.service_id = NEW.service_id
        AND ss.employee_user_id = NEW.staff_user_id
        AND (ss.branch_id IS NULL OR ss.branch_id = NEW.branch_id)
    ) THEN
      RAISE EXCEPTION 'STAFF_NOT_ON_SERVICE: الموظف المختار غير مسجل ضمن موظفى هذه الخدمة فى هذا الفرع';
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- validate_cogs_amount()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_cogs_amount()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_invoice_total NUMERIC;
  v_cogs_total NUMERIC;
BEGIN
  -- Only check for COGS entries
  IF NEW.reference_type != 'invoice_cogs' THEN
    RETURN NEW;
  END IF;
  
  -- Get invoice total
  SELECT total_amount INTO v_invoice_total
  FROM invoices
  WHERE id = NEW.reference_id;
  
  -- Get COGS total from journal entry lines
  SELECT SUM(credit_amount) INTO v_cogs_total
  FROM journal_entry_lines
  WHERE journal_entry_id = NEW.id;
  
  -- COGS should not exceed invoice total (sanity check)
  IF v_cogs_total > v_invoice_total * 2 THEN
    RAISE WARNING 'COGS amount (%) seems too high for invoice total (%). Invoice: %',
      v_cogs_total, v_invoice_total, NEW.reference_id;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- validate_customer_debit_application()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_customer_debit_application()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_total_amount DECIMAL(15,2); v_current_applied DECIMAL(15,2); v_new_total DECIMAL(15,2); BEGIN SELECT total_amount, applied_amount INTO v_total_amount, v_current_applied FROM customer_debit_notes WHERE id = NEW.customer_debit_note_id; SELECT COALESCE(SUM(amount_applied), 0) INTO v_new_total FROM customer_debit_note_applications WHERE customer_debit_note_id = NEW.customer_debit_note_id AND id != COALESCE(NEW.id, '00000000-0000-0000-0000-000000000000'::UUID); v_new_total := v_new_total + NEW.amount_applied; IF v_new_total > v_total_amount THEN RAISE EXCEPTION 'Cannot apply %.2f - would exceed debit note total of %.2f (%.2f already applied)', NEW.amount_applied, v_total_amount, v_current_applied; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- validate_depreciation_schedule(p_asset_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_depreciation_schedule(p_asset_id uuid)
 RETURNS TABLE(is_valid boolean, errors text[])
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_asset RECORD;
  v_schedules RECORD;
  v_errors TEXT[] := ARRAY[]::TEXT[];
  v_expected_periods INTEGER;
  v_actual_periods INTEGER;
  v_total_depreciation DECIMAL(15, 2) := 0;
  v_expected_total DECIMAL(15, 2);
  v_last_period_date DATE;
  v_current_period_date DATE;
BEGIN
  -- جلب بيانات الأصل
  SELECT * INTO v_asset FROM fixed_assets WHERE id = p_asset_id;

  IF v_asset IS NULL THEN
    RETURN QUERY SELECT FALSE, ARRAY['Asset not found']::TEXT[];
    RETURN;
  END IF;

  -- التحقق من عدد الفترات
  SELECT COUNT(*) INTO v_actual_periods
  FROM depreciation_schedules
  WHERE asset_id = p_asset_id AND status != 'cancelled';

  v_expected_periods := v_asset.useful_life_months;

  IF v_actual_periods != v_expected_periods THEN
    v_errors := array_append(v_errors, 
      format('Expected %s periods, but found %s', v_expected_periods, v_actual_periods));
  END IF;

  -- التحقق من توزيع الفترات الشهرية
  SELECT MAX(period_date) INTO v_last_period_date
  FROM depreciation_schedules
  WHERE asset_id = p_asset_id AND status != 'cancelled';

  v_current_period_date := DATE_TRUNC('month', v_asset.depreciation_start_date)::DATE;
  
  FOR v_schedules IN
    SELECT period_number, period_date
    FROM depreciation_schedules
    WHERE asset_id = p_asset_id AND status != 'cancelled'
    ORDER BY period_number
  LOOP
    -- التحقق من أن تاريخ الفترة هو بداية الشهر
    IF DATE_TRUNC('month', v_schedules.period_date)::DATE != v_schedules.period_date THEN
      v_errors := array_append(v_errors, 
        format('Period %s date (%) is not at the start of the month', 
          v_schedules.period_number, v_schedules.period_date));
    END IF;

    -- التحقق من تسلسل الفترات
    IF v_schedules.period_date != v_current_period_date THEN
      v_errors := array_append(v_errors, 
        format('Period %s date (%) does not match expected date (%)', 
          v_schedules.period_number, v_schedules.period_date, v_current_period_date));
    END IF;

    v_current_period_date := (v_current_period_date + INTERVAL '1 month')::DATE;
    v_current_period_date := DATE_TRUNC('month', v_current_period_date)::DATE;
  END LOOP;

  -- التحقق من إجمالي الإهلاك
  SELECT SUM(depreciation_amount) INTO v_total_depreciation
  FROM depreciation_schedules
  WHERE asset_id = p_asset_id AND status != 'cancelled';

  v_expected_total := v_asset.purchase_cost - v_asset.salvage_value;

  IF ABS(v_total_depreciation - v_expected_total) > 0.01 THEN
    v_errors := array_append(v_errors, 
      format('Total depreciation (%) does not match expected (%). Difference: %', 
        v_total_depreciation, v_expected_total, ABS(v_total_depreciation - v_expected_total)));
  END IF;

  RETURN QUERY SELECT (array_length(v_errors, 1) IS NULL), v_errors;
END;
$function$
;

-- ---------------------------------------------------------------
-- validate_journal_entry_balance()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_journal_entry_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total_debit NUMERIC;
  v_total_credit NUMERIC;
BEGIN
  SELECT 
    COALESCE(SUM(debit_amount), 0),
    COALESCE(SUM(credit_amount), 0)
  INTO v_total_debit, v_total_credit
  FROM journal_entry_lines
  WHERE journal_entry_id = NEW.journal_entry_id;
  
  v_total_debit := v_total_debit + COALESCE(NEW.debit_amount, 0);
  v_total_credit := v_total_credit + COALESCE(NEW.credit_amount, 0);
  
  IF ABS(v_total_debit - v_total_credit) > 0.01 THEN
    RAISE WARNING 'تحذير: القيد غير متوازن. المدين: %, الدائن: %', v_total_debit, v_total_credit;
  END IF;
  
  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- validate_product_branch_isolation()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_product_branch_isolation()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$ DECLARE v_pb UUID; v_db UUID; v_tn TEXT := TG_TABLE_NAME; v_p UUID; BEGIN IF NEW.product_id IS NULL THEN RETURN NEW; END IF; CASE v_tn WHEN 'purchase_order_items' THEN v_p := NEW.purchase_order_id; SELECT branch_id INTO v_db FROM purchase_orders WHERE id = v_p; WHEN 'bill_items' THEN v_p := NEW.bill_id; SELECT branch_id INTO v_db FROM bills WHERE id = v_p; WHEN 'sales_order_items' THEN v_p := NEW.sales_order_id; SELECT branch_id INTO v_db FROM sales_orders WHERE id = v_p; WHEN 'invoice_items' THEN v_p := NEW.invoice_id; SELECT branch_id INTO v_db FROM invoices WHERE id = v_p; WHEN 'purchase_return_items' THEN v_p := NEW.purchase_return_id; SELECT branch_id INTO v_db FROM purchase_returns WHERE id = v_p; WHEN 'vendor_credit_items' THEN v_p := NEW.vendor_credit_id; SELECT branch_id INTO v_db FROM vendor_credits WHERE id = v_p; ELSE RETURN NEW; END CASE; IF v_db IS NULL THEN RETURN NEW; END IF; SELECT branch_id INTO v_pb FROM products WHERE id = NEW.product_id; IF v_pb IS NOT NULL AND v_pb != v_db THEN RAISE EXCEPTION 'Branch Isolation Violation'; END IF; RETURN NEW; END; $function$
;

-- ---------------------------------------------------------------
-- validate_reports_integrity(p_company_id uuid, p_as_of_date date)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_reports_integrity(p_company_id uuid, p_as_of_date date DEFAULT CURRENT_DATE)
 RETURNS TABLE(check_name text, status text, expected_value numeric, actual_value numeric, difference numeric, is_critical boolean)
 LANGUAGE plpgsql
AS $function$
DECLARE
    total_debits NUMERIC;
    total_credits NUMERIC;
    balance_sheet_assets NUMERIC;
    balance_sheet_liab_equity NUMERIC;
BEGIN
    -- التحقق من توازن القيود
    SELECT 
        COALESCE(SUM(jel.debit_amount), 0),
        COALESCE(SUM(jel.credit_amount), 0)
    INTO total_debits, total_credits
    FROM journal_entry_lines jel
    JOIN journal_entries je ON jel.journal_entry_id = je.id
    WHERE je.company_id = p_company_id
    AND je.entry_date <= p_as_of_date;
    
    RETURN QUERY SELECT 
        'Journal Entries Balance'::TEXT,
        CASE WHEN ABS(total_debits - total_credits) < 0.01 THEN 'OK' ELSE 'ERROR' END::TEXT,
        total_debits,
        total_credits,
        total_debits - total_credits,
        ABS(total_debits - total_credits) >= 0.01;
    
    -- التحقق من توازن الميزانية
    SELECT 
        COALESCE(SUM(CASE WHEN account_type = 'asset' THEN balance ELSE 0 END), 0),
        COALESCE(SUM(CASE WHEN account_type IN ('liability', 'equity') THEN balance ELSE 0 END), 0)
    INTO balance_sheet_assets, balance_sheet_liab_equity
    FROM get_enhanced_balance_sheet(p_company_id, NULL, NULL, p_as_of_date);
    
    RETURN QUERY SELECT 
        'Balance Sheet Balance'::TEXT,
        CASE WHEN ABS(balance_sheet_assets - balance_sheet_liab_equity) < 0.01 THEN 'OK' ELSE 'ERROR' END::TEXT,
        balance_sheet_assets,
        balance_sheet_liab_equity,
        balance_sheet_assets - balance_sheet_liab_equity,
        ABS(balance_sheet_assets - balance_sheet_liab_equity) >= 0.01;
END;
$function$
;

-- ---------------------------------------------------------------
-- validate_three_way_matching(p_bill_id uuid, p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_three_way_matching(p_bill_id uuid, p_company_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_bill            RECORD;
  v_po              RECORD;
  v_has_po          BOOLEAN := FALSE;
  v_bill_item       RECORD;
  v_po_item         RECORD;
  v_has_po_item     BOOLEAN;
  v_exception_id    UUID;
  v_exceptions      JSONB := '[]'::JSONB;
  v_exception       JSONB;
  v_price_tolerance NUMERIC(12,2) := 0.01;
BEGIN
  -- ① Load bill
  SELECT * INTO v_bill FROM bills WHERE id = p_bill_id AND company_id = p_company_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Bill not found');
  END IF;

  -- ② Load linked PO (FOUND is reliable; record-level IS NOT NULL is not)
  IF v_bill.purchase_order_id IS NOT NULL THEN
    SELECT * INTO v_po FROM purchase_orders WHERE id = v_bill.purchase_order_id;
    v_has_po := FOUND;
  END IF;

  -- ③ Wipe only the unresolved exceptions for this bill (keep resolved ones
  --    as audit trail)
  DELETE FROM matching_exceptions
  WHERE bill_id = p_bill_id
    AND company_id = p_company_id
    AND resolved = false;

  -- ④ Re-validate each bill item against the PO line. This project uses
  --    bills.receipt_status='received' instead of a separate goods_receipts
  --    table, so the bill's own quantities ARE the received quantities once
  --    the warehouse approves them.
  FOR v_bill_item IN
    SELECT * FROM bill_items
    WHERE bill_id = p_bill_id AND product_id IS NOT NULL
  LOOP
    v_has_po_item := FALSE;

    IF v_has_po THEN
      SELECT * INTO v_po_item FROM purchase_order_items
      WHERE purchase_order_id = v_bill.purchase_order_id
        AND product_id = v_bill_item.product_id
      LIMIT 1;
      v_has_po_item := FOUND;
    END IF;

    -- Price mismatch (bill price ≠ PO price beyond tolerance)
    IF v_has_po_item
       AND v_bill_item.unit_price IS NOT NULL
       AND v_po_item.unit_price IS NOT NULL
       AND ABS(v_bill_item.unit_price - v_po_item.unit_price) > v_price_tolerance
    THEN
      INSERT INTO matching_exceptions (
        company_id, purchase_order_id, bill_id, product_id,
        exception_type, po_price, bill_price, severity, description
      )
      VALUES (
        p_company_id,
        v_bill.purchase_order_id,
        p_bill_id,
        v_bill_item.product_id,
        'price_mismatch',
        v_po_item.unit_price,
        v_bill_item.unit_price,
        'warning',
        'Bill price (' || v_bill_item.unit_price ||
          ') differs from PO price (' || v_po_item.unit_price || ')'
      )
      RETURNING id INTO v_exception_id;

      v_exception := jsonb_build_object(
        'id',         v_exception_id,
        'type',       'price_mismatch',
        'product_id', v_bill_item.product_id,
        'message',    'Bill price differs from PO price',
        'po_price',   v_po_item.unit_price,
        'bill_price', v_bill_item.unit_price
      );
      v_exceptions := v_exceptions || v_exception;
    END IF;

    -- Quantity mismatch (bill qty > PO qty, i.e. over-receipt)
    IF v_has_po_item
       AND v_bill_item.quantity IS NOT NULL
       AND v_po_item.quantity IS NOT NULL
       AND v_bill_item.quantity > v_po_item.quantity
    THEN
      INSERT INTO matching_exceptions (
        company_id, purchase_order_id, bill_id, product_id,
        exception_type, po_quantity, bill_quantity, severity, description
      )
      VALUES (
        p_company_id,
        v_bill.purchase_order_id,
        p_bill_id,
        v_bill_item.product_id,
        'quantity_mismatch',
        v_po_item.quantity,
        v_bill_item.quantity,
        'error',
        'Bill quantity (' || v_bill_item.quantity ||
          ') exceeds PO quantity (' || v_po_item.quantity || ')'
      )
      RETURNING id INTO v_exception_id;

      v_exception := jsonb_build_object(
        'id',         v_exception_id,
        'type',       'quantity_mismatch',
        'product_id', v_bill_item.product_id,
        'message',    'Bill quantity exceeds PO quantity',
        'po_qty',     v_po_item.quantity,
        'bill_qty',   v_bill_item.quantity
      );
      v_exceptions := v_exceptions || v_exception;
    END IF;
  END LOOP;

  -- ⑤ Return result (no missing_grn check anymore — this project uses
  --    integrated receipt approval on the bill itself)
  RETURN jsonb_build_object(
    'success',          true,
    'has_exceptions',   jsonb_array_length(v_exceptions) > 0,
    'exceptions',       v_exceptions,
    'exceptions_count', jsonb_array_length(v_exceptions)
  );

EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- validate_vendor_credit()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_vendor_credit()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Ensure company_id is set
  IF NEW.company_id IS NULL THEN
    RAISE EXCEPTION 'company_id is required for Vendor Credit';
  END IF;

  -- Ensure branch_id is set
  IF NEW.branch_id IS NULL THEN
    RAISE EXCEPTION 'branch_id is required for Vendor Credit';
  END IF;

  -- Ensure supplier_id is set
  IF NEW.supplier_id IS NULL THEN
    RAISE EXCEPTION 'supplier_id is required for Vendor Credit';
  END IF;

  -- If reference_type is 'bill_return', ensure source_purchase_invoice_id is set
  IF NEW.reference_type = 'bill_return' AND NEW.source_purchase_invoice_id IS NULL THEN
    RAISE EXCEPTION 'source_purchase_invoice_id is required when reference_type is bill_return';
  END IF;

  -- If reference_type is set, ensure reference_id is set
  IF NEW.reference_type IS NOT NULL AND NEW.reference_id IS NULL THEN
    RAISE EXCEPTION 'reference_id is required when reference_type is set';
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- validate_write_off_approval()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_write_off_approval()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_item RECORD;
  v_warehouse_id UUID;
  v_branch_id UUID;
  v_cost_center_id UUID;
  v_available_qty INTEGER;
BEGIN
  -- التحقق فقط عند تغيير الحالة إلى 'approved'
  IF NEW.status = 'approved' AND (OLD.status IS NULL OR OLD.status != 'approved') THEN
    
    -- جلب warehouse_id و branch_id
    v_warehouse_id := NEW.warehouse_id;
    
    -- ✅ جلب branch_id من warehouse
    IF v_warehouse_id IS NOT NULL THEN
      SELECT branch_id INTO v_branch_id 
      FROM warehouses 
      WHERE id = v_warehouse_id AND company_id = NEW.company_id;
    END IF;

    -- ✅ جلب cost_center_id من branch (الحل الجذري)
    IF v_branch_id IS NOT NULL THEN
      SELECT default_cost_center_id INTO v_cost_center_id
      FROM branches
      WHERE id = v_branch_id AND company_id = NEW.company_id;
    END IF;

    -- التحقق من جميع العناصر
    FOR v_item IN SELECT * FROM inventory_write_off_items WHERE write_off_id = NEW.id LOOP
      v_available_qty := get_available_inventory_quantity(
        NEW.company_id,
        v_branch_id,
        v_warehouse_id,
        v_cost_center_id,
        v_item.product_id
      );

      -- 🧾 Governance Rule: منع الاعتماد إذا الرصيد غير كافٍ
      IF v_available_qty <= 0 THEN
        RAISE EXCEPTION 'لا يمكن اعتماد الإهلاك: الرصيد المتاح = 0 للمنتج (product_id: %, warehouse_id: %, branch_id: %, cost_center_id: %)',
          v_item.product_id, v_warehouse_id, v_branch_id, v_cost_center_id;
      END IF;

      IF v_available_qty < v_item.quantity THEN
        RAISE EXCEPTION 'لا يمكن اعتماد الإهلاك: الرصيد المتاح (%) < الكمية المطلوبة (%) للمنتج (product_id: %, warehouse_id: %, branch_id: %, cost_center_id: %)',
          v_available_qty, v_item.quantity, v_item.product_id, v_warehouse_id, v_branch_id, v_cost_center_id;
      END IF;
    END LOOP;
  END IF;

  RETURN NEW;
END;
$function$
;

-- ---------------------------------------------------------------
-- validate_write_off_items()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.validate_write_off_items()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_write_off RECORD;
  v_warehouse_id UUID;
  v_branch_id UUID;
  v_cost_center_id UUID;
  v_available_qty INTEGER;
  v_item_quantity INTEGER;
BEGIN
  -- جلب بيانات الإهلاك
  SELECT * INTO v_write_off FROM inventory_write_offs WHERE id = NEW.write_off_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'إهلاك غير موجود: %', NEW.write_off_id;
  END IF;

  -- جلب warehouse_id و branch_id من الإهلاك
  v_warehouse_id := v_write_off.warehouse_id;
  
  -- ✅ جلب branch_id من warehouse
  IF v_warehouse_id IS NOT NULL THEN
    SELECT branch_id INTO v_branch_id 
    FROM warehouses 
    WHERE id = v_warehouse_id AND company_id = v_write_off.company_id;
  END IF;

  -- ✅ جلب cost_center_id من branch (الحل الجذري)
  IF v_branch_id IS NOT NULL THEN
    SELECT default_cost_center_id INTO v_cost_center_id
    FROM branches
    WHERE id = v_branch_id AND company_id = v_write_off.company_id;
  END IF;

  -- حساب الرصيد المتاح (مع cost_center_id الصحيح)
  v_available_qty := get_available_inventory_quantity(
    v_write_off.company_id,
    v_branch_id,
    v_warehouse_id,
    v_cost_center_id,
    NEW.product_id
  );

  -- جلب الكمية المطلوبة (من السجل الجديد أو المحدث)
  IF TG_OP = 'INSERT' THEN
    v_item_quantity := NEW.quantity;
  ELSE -- UPDATE
    v_item_quantity := NEW.quantity;
  END IF;

  -- 🧾 Governance Rule: منع الإدخال/التحديث إذا الرصيد غير كافٍ
  -- ملاحظة: هذا التحقق في Insert فقط - في Update نتحقق عند Approve
  -- لأن المستخدم قد يكون يعدل الكمية قبل الاعتماد
  IF TG_OP = 'INSERT' AND v_available_qty < v_item_quantity THEN
    RAISE EXCEPTION 'الرصيد المتاح غير كافٍ: الرصيد المتاح = %, المطلوب = % (company_id: %, warehouse_id: %, branch_id: %, cost_center_id: %, product_id: %)',
      v_available_qty, v_item_quantity, v_write_off.company_id, v_warehouse_id, v_branch_id, v_cost_center_id, NEW.product_id;
  END IF;

  RETURN NEW;
END;
$function$
;

