-- ---------------------------------------------------------------
-- verify_all_journal_entries_balanced()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.verify_all_journal_entries_balanced()
 RETURNS TABLE(journal_entry_id uuid, entry_date date, description text, total_debit numeric, total_credit numeric, difference numeric)
 LANGUAGE plpgsql
AS $function$ BEGIN RETURN QUERY SELECT je.id, je.entry_date, je.description, COALESCE(SUM(jel.debit_amount), 0) as total_debit, COALESCE(SUM(jel.credit_amount), 0) as total_credit, COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0) as difference FROM journal_entries je LEFT JOIN journal_entry_lines jel ON jel.journal_entry_id = je.id GROUP BY je.id, je.entry_date, je.description HAVING ABS(COALESCE(SUM(jel.debit_amount), 0) - COALESCE(SUM(jel.credit_amount), 0)) > 0.01 ORDER BY je.entry_date DESC; END; $function$
;

-- ---------------------------------------------------------------
-- verify_coa_restructure(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.verify_coa_restructure(p_company_id uuid)
 RETURNS TABLE(check_type text, status text, details text, count integer, amount numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- 1. التحقق من عدم وجود حسابات مكررة نشطة
    RETURN QUERY
    SELECT 
        'duplicate_accounts'::TEXT,
        CASE WHEN COUNT(*) = 0 THEN '✅ PASS' ELSE '❌ FAIL' END,
        format('حسابات مكررة: %s', COUNT(*)),
        COUNT(*)::INTEGER,
        0::DECIMAL(15, 2)
    FROM (
        SELECT account_code, COUNT(*) as cnt
        FROM chart_of_accounts
        WHERE company_id = p_company_id AND is_active = true
        GROUP BY account_code
        HAVING COUNT(*) > 1
    ) duplicates;
    
    -- 2. التحقق من توازن القيود
    RETURN QUERY
    SELECT 
        'journal_balance'::TEXT,
        CASE WHEN ABS(COALESCE(SUM(debit_amount - credit_amount), 0)) < 0.01 
             THEN '✅ PASS' ELSE '❌ FAIL' END,
        format('الفرق: %s', ABS(COALESCE(SUM(debit_amount - credit_amount), 0))),
        0::INTEGER,
        ABS(COALESCE(SUM(debit_amount - credit_amount), 0))
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.journal_entry_id
    WHERE je.company_id = p_company_id;
    
    -- 3. التحقق من وجود الحسابات القياسية
    RETURN QUERY
    SELECT 
        'standard_accounts'::TEXT,
        CASE WHEN COUNT(*) >= 6 THEN '✅ PASS' ELSE '⚠️ WARNING' END,
        format('حسابات قياسية موجودة: %s/6', COUNT(*)),
        COUNT(*)::INTEGER,
        0::DECIMAL(15, 2)
    FROM chart_of_accounts
    WHERE company_id = p_company_id
      AND is_active = true
      AND (
        account_code IN ('1130', '1100', '2110', '1140', '1200', '5100', '4100', '5200')
        OR sub_type IN ('accounts_receivable', 'accounts_payable', 'inventory', 'cogs', 'sales_revenue', 'operating_expenses')
      );
    
    -- 4. التحقق من سجل التغييرات
    RETURN QUERY
    SELECT 
        'restructure_log'::TEXT,
        '✅ INFO'::TEXT,
        format('عمليات مسجلة: %s', COUNT(*)),
        COUNT(*)::INTEGER,
        COALESCE(SUM(log.amount), 0)
    FROM coa_restructure_log log
    WHERE log.company_id = p_company_id;
END;
$function$
;

-- ---------------------------------------------------------------
-- verify_cogs_entries_for_sales(p_company_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.verify_cogs_entries_for_sales(p_company_id uuid)
 RETURNS TABLE(invoice_id uuid, invoice_number text, invoice_date date, has_cogs_entry boolean, expected_cogs numeric, actual_cogs numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT 
    i.id as invoice_id,
    i.invoice_number,
    i.invoice_date,
    EXISTS(
      SELECT 1 FROM journal_entries je 
      WHERE je.reference_type = 'invoice_cogs' AND je.reference_id = i.id
    ) as has_cogs_entry,
    COALESCE((
      SELECT SUM(ii.quantity * p.cost_price)
      FROM invoice_items ii
      JOIN products p ON ii.product_id = p.id
      WHERE ii.invoice_id = i.id AND p.item_type != 'service'
    ), 0) as expected_cogs,
    COALESCE((
      SELECT SUM(jel.debit_amount)
      FROM journal_entries je
      JOIN journal_entry_lines jel ON je.id = jel.journal_entry_id
      JOIN chart_of_accounts coa ON jel.account_id = coa.id
      WHERE je.reference_type = 'invoice_cogs' 
        AND je.reference_id = i.id
        AND coa.sub_type IN ('cost_of_goods_sold', 'cogs')
    ), 0) as actual_cogs
  FROM invoices i
  WHERE i.company_id = p_company_id
    AND i.status NOT IN ('draft', 'cancelled')
  ORDER BY i.invoice_date DESC;
END;
$function$
;

-- ---------------------------------------------------------------
-- verify_depreciation_deleted(p_asset_id uuid)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.verify_depreciation_deleted(p_asset_id uuid)
 RETURNS TABLE(remaining_schedules integer, remaining_journals integer, remaining_lines integer, asset_name text, asset_code text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_catalog'
AS $function$
DECLARE
  v_asset_id UUID;
  v_asset_name TEXT;
  v_asset_code TEXT;
  v_remaining_schedules INTEGER;
  v_remaining_journals INTEGER;
  v_remaining_lines INTEGER;
BEGIN
  SELECT fa.id, fa.name, fa.asset_code
  INTO v_asset_id, v_asset_name, v_asset_code
  FROM fixed_assets fa
  WHERE fa.id = p_asset_id
  LIMIT 1;

  IF v_asset_id IS NULL THEN
    RAISE EXCEPTION 'Asset with ID % not found', p_asset_id;
  END IF;

    -- التحقق من جداول الإهلاك المتبقية
    SELECT COUNT(*) INTO v_remaining_schedules
    FROM depreciation_schedules
    WHERE asset_id = v_asset_id;

    -- التحقق من القيود المتبقية
    SELECT COUNT(*) INTO v_remaining_journals
    FROM journal_entries
    WHERE reference_type = 'depreciation'
      AND reference_id = v_asset_id;

    -- التحقق من سطور القيود المتبقية
    SELECT COUNT(*) INTO v_remaining_lines
    FROM journal_entry_lines jel
    INNER JOIN journal_entries je ON jel.journal_entry_id = je.id
    WHERE je.reference_type = 'depreciation'
      AND je.reference_id = v_asset_id;

    -- Return results
    RETURN QUERY SELECT 
      v_remaining_schedules,
      v_remaining_journals,
      v_remaining_lines,
      v_asset_name,
      v_asset_code;
END;
$function$
;

-- ---------------------------------------------------------------
-- verify_inventory_journal_links()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.verify_inventory_journal_links()
 RETURNS TABLE(transaction_id uuid, product_id uuid, transaction_type text, quantity_change integer, reference_id uuid, has_journal_link boolean)
 LANGUAGE plpgsql
AS $function$ BEGIN RETURN QUERY SELECT it.id, it.product_id, it.transaction_type, it.quantity_change::INTEGER, it.reference_id, (it.journal_entry_id IS NOT NULL) as has_journal_link FROM inventory_transactions it WHERE it.transaction_type IN ('sale', 'purchase', 'write_off', 'sale_return') ORDER BY it.created_at DESC; END; $function$
;

-- ---------------------------------------------------------------
-- verify_invoices_have_cogs()
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.verify_invoices_have_cogs()
 RETURNS TABLE(invoice_id uuid, invoice_number text, invoice_date date, status text, has_inventory_items boolean, has_cogs_entry boolean)
 LANGUAGE plpgsql
AS $function$ BEGIN RETURN QUERY SELECT i.id, i.invoice_number, i.invoice_date, i.status, EXISTS (SELECT 1 FROM invoice_items ii JOIN products p ON p.id = ii.product_id WHERE ii.invoice_id = i.id AND p.item_type = 'product') as has_inventory_items, EXISTS (SELECT 1 FROM journal_entries je WHERE je.reference_type = 'invoice_cogs' AND je.reference_id = i.id) as has_cogs_entry FROM invoices i WHERE i.status IN ('sent', 'paid') ORDER BY i.invoice_date DESC; END; $function$
;

-- ---------------------------------------------------------------
-- void_bill_atomic(p_bill_id uuid, p_user_id uuid, p_company_id uuid, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.void_bill_atomic(p_bill_id uuid, p_user_id uuid, p_company_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_bill RECORD;
    v_user_role TEXT;
    v_user_branch UUID;
    v_payments_count INT;
BEGIN
    SELECT role, branch_id INTO v_user_role, v_user_branch
    FROM public.company_members WHERE company_id = p_company_id AND user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'User is not a member of this company');
    END IF;

    -- Same permission gate as bill delete: owner, admin, general_manager, accountant.
    IF v_user_role NOT IN ('owner', 'admin', 'general_manager', 'accountant') THEN
        RETURN jsonb_build_object('success', false,
          'error', 'صلاحية إلغاء الفواتير محصورة بالمالك والمدير العام والمحاسب');
    END IF;

    SELECT * INTO v_bill FROM public.bills
     WHERE id = p_bill_id AND company_id = p_company_id FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Bill not found');
    END IF;

    IF LOWER(COALESCE(v_bill.status, '')) <> 'draft' THEN
        RETURN jsonb_build_object('success', false,
          'error', 'لا يمكن إلغاء فاتورة بعد ترحيلها. هذه العملية متاحة فقط للمسودات.');
    END IF;

    SELECT COUNT(*) INTO v_payments_count FROM public.payments WHERE bill_id = p_bill_id;
    IF v_payments_count > 0 THEN
        RETURN jsonb_build_object('success', false,
          'error', 'لا يمكن إلغاء فاتورة لها مدفوعات. الغ المدفوعات أولاً.');
    END IF;

    UPDATE public.bills
       SET status = 'voided',
           voided_by = p_user_id,
           voided_at = NOW(),
           voided_reason = COALESCE(NULLIF(TRIM(p_reason), ''), 'إلغاء بواسطة المستخدم'),
           updated_at = NOW()
     WHERE id = p_bill_id;

    UPDATE public.discount_approvals
       SET status = 'cancelled',
           decision_note = COALESCE(decision_note, '') || ' [v3.74.402: cancelled with bill void]',
           updated_at = NOW()
     WHERE document_type = 'purchase_invoice'
       AND document_id = p_bill_id
       AND status = 'pending';

    IF v_bill.purchase_order_id IS NOT NULL THEN
        UPDATE public.purchase_orders
           SET bill_id = NULL,
               status = 'pending_approval',
               approved_by = NULL,
               approved_at = NULL,
               updated_at = NOW()
         WHERE id = v_bill.purchase_order_id;
    END IF;

    INSERT INTO public.audit_logs (
        company_id, user_id, action, target_table, record_id, old_data, new_data, created_at, reason, branch_id
    ) VALUES (
        p_company_id, p_user_id, 'VOID', 'bills', p_bill_id,
        jsonb_build_object('status', v_bill.status, 'bill_number', v_bill.bill_number),
        jsonb_build_object('status', 'voided', 'voided_reason', p_reason),
        NOW(), p_reason, v_bill.branch_id
    );

    RETURN jsonb_build_object(
        'success', true,
        'bill_id', p_bill_id,
        'status', 'voided',
        'purchase_order_id', v_bill.purchase_order_id,
        'purchase_order_unblocked', v_bill.purchase_order_id IS NOT NULL
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

-- ---------------------------------------------------------------
-- void_invoice_atomic(p_invoice_id uuid, p_user_id uuid, p_company_id uuid, p_reason text)
-- ---------------------------------------------------------------
CREATE OR REPLACE FUNCTION public.void_invoice_atomic(p_invoice_id uuid, p_user_id uuid, p_company_id uuid, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_invoice RECORD;
    v_user_role TEXT;
    v_user_branch UUID;
    v_payments_count INT;
    v_je_count INT;
    v_inv_tx_count INT;
BEGIN
    SELECT role, branch_id INTO v_user_role, v_user_branch
    FROM public.company_members WHERE company_id = p_company_id AND user_id = p_user_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'User is not a member of this company');
    END IF;

    IF v_user_role NOT IN ('owner', 'admin', 'general_manager', 'accountant') THEN
        RETURN jsonb_build_object('success', false,
          'error', 'صلاحية إلغاء الفواتير محصورة بالمالك والمدير العام والمحاسب');
    END IF;

    SELECT * INTO v_invoice FROM public.invoices
     WHERE id = p_invoice_id AND company_id = p_company_id FOR UPDATE;

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Invoice not found');
    END IF;

    IF LOWER(COALESCE(v_invoice.status, '')) <> 'draft' THEN
        RETURN jsonb_build_object('success', false,
          'error', 'لا يمكن إلغاء فاتورة بعد ترحيلها. هذه العملية متاحة فقط للمسودات.');
    END IF;

    SELECT COUNT(*) INTO v_payments_count FROM public.payments WHERE invoice_id = p_invoice_id;
    IF v_payments_count > 0 THEN
        RETURN jsonb_build_object('success', false,
          'error', 'لا يمكن إلغاء فاتورة لها مدفوعات. الغ المدفوعات أولاً.');
    END IF;

    SELECT COUNT(*) INTO v_je_count FROM public.journal_entries WHERE reference_id = p_invoice_id;
    IF v_je_count > 0 THEN
        RETURN jsonb_build_object('success', false,
          'error', 'لا يمكن إلغاء فاتورة لها قيود محاسبية مرحّلة.');
    END IF;

    SELECT COUNT(*) INTO v_inv_tx_count FROM public.inventory_transactions WHERE reference_id = p_invoice_id;
    IF v_inv_tx_count > 0 THEN
        RETURN jsonb_build_object('success', false,
          'error', 'لا يمكن إلغاء فاتورة لها حركات مخزون. استخدم المرتجع بدلاً من الإلغاء.');
    END IF;

    UPDATE public.invoices
       SET status = 'voided',
           voided_by = p_user_id,
           voided_at = NOW(),
           voided_reason = COALESCE(NULLIF(TRIM(p_reason), ''), 'إلغاء بواسطة المستخدم'),
           updated_at = NOW()
     WHERE id = p_invoice_id;

    UPDATE public.discount_approvals
       SET status = 'cancelled',
           decision_note = COALESCE(decision_note, '') || ' [v3.74.406: cancelled with invoice void]',
           updated_at = NOW()
     WHERE document_type = 'sales_invoice'
       AND document_id = p_invoice_id
       AND status = 'pending';

    IF v_invoice.sales_order_id IS NOT NULL THEN
        UPDATE public.sales_orders
           SET invoice_id = NULL,
               updated_at = NOW()
         WHERE id = v_invoice.sales_order_id;
    END IF;

    INSERT INTO public.audit_logs (
        company_id, user_id, action, target_table, record_id, old_data, new_data, created_at, reason, branch_id
    ) VALUES (
        p_company_id, p_user_id, 'VOID', 'invoices', p_invoice_id,
        jsonb_build_object('status', v_invoice.status, 'invoice_number', v_invoice.invoice_number),
        jsonb_build_object('status', 'voided', 'voided_reason', p_reason),
        NOW(), p_reason, v_invoice.branch_id
    );

    RETURN jsonb_build_object(
        'success', true,
        'invoice_id', p_invoice_id,
        'status', 'voided',
        'sales_order_id', v_invoice.sales_order_id,
        'sales_order_unblocked', v_invoice.sales_order_id IS NOT NULL
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$function$
;

